"""
stroke_engine.py — Natural painting primitives.

Architecture
============
  PaintCanvas      — cairo surface + numpy wetness / thickness maps + linen texture
  BrushProfile     — physical tool descriptor (bristle count, distribution, stiffness…)
  PressureProfile  — within-stroke and per-pass pressure variation
  PaintLoad        — cross-stroke paint charge and depletion model
  BrushTip         — legacy tip descriptor (auto-converted to BrushProfile at render)
  mix_paint()      — subtractive (pigment) color mixing in sqrt-space
  Painter          — high-level layered painting API

Brush system v2
===============
  Each stroke is decomposed into N individual bristle sub-strokes with
  seeded-deterministic deviation.  The aggregate produces ragged organic
  edges, visible bristle tracks, and natural dry-brush effects as paint
  depletes — impossible with the old polygon fill approach.

  Named presets:
    BRUSH_PRESETS     — BrushProfile instances by name
    TECHNIQUE_PRESETS — brush + pressure + load combos for known styles

Tool operations
===============
  deposit    — apply_stroke() / apply_knife_stroke() — adds new paint
  manipulate — smear() (finger tool) — moves existing paint
  remove     — apply_knife_stroke(scrape=True) — lifts paint to lower layer

Workflow
========
  p = Painter(800, 1000, edge_treatment="full_coverage")
  p.tone_ground(TERRE_VERTE)
  p.underpainting(reference, stroke_size=55)
  p.block_in(reference,      stroke_size=38)
  p.build_form(reference,    stroke_size=16)
  p.place_lights(reference,  stroke_size=6)
  p.canvas.sheen_pass()
  p.glaze(WARM_AMBER, opacity=0.10)
  p.save("out.png")
"""

import math, random, colorsys
from dataclasses import dataclass, field
from typing import List, Tuple, Optional, Union

import numpy as np
import cairo
from PIL import Image, ImageFilter
from scipy import ndimage
from noise import pnoise2
from art_utils import Composition

Color = Tuple[float, float, float]

# ─────────────────────────────────────────────────────────────────────────────
# Guided filter — edge-preserving error map smoothing
# ─────────────────────────────────────────────────────────────────────────────

def guided_filter(
    src: np.ndarray,
    guide: np.ndarray,
    radius: int,
    eps: float = 0.01,
) -> np.ndarray:
    """
    Fast box-filter guided filter (He et al. 2013).

    Unlike isotropic Gaussian blur, a guided filter preserves edges in the
    guide image when smoothing `src`.  Applying this to the error map with
    the reference luminance as guide concentrates strokes *inside* meaningful
    zones rather than smearing across object boundaries.

    Parameters
    ----------
    src    : (H, W) float32 array to smooth — the raw error map.
    guide  : (H, W) float32 array that defines edges — typically luma(reference).
    radius : Box half-width in pixels.  Corresponds to Gaussian sigma × ~1.5.
    eps    : Regularisation that controls how strongly edges in `guide` are
             preserved.  Smaller = sharper edge preservation.
    """
    from scipy.ndimage import uniform_filter

    def _mean(x: np.ndarray) -> np.ndarray:
        return uniform_filter(x.astype(np.float64), 2 * radius + 1).astype(np.float32)

    mean_I  = _mean(guide)
    mean_p  = _mean(src)
    mean_Ip = _mean(guide * src)
    mean_II = _mean(guide * guide)

    cov_Ip = mean_Ip - mean_I * mean_p
    var_I  = mean_II - mean_I * mean_I

    a = cov_Ip / (var_I + eps)
    b = mean_p - a * mean_I

    mean_a = _mean(a)
    mean_b = _mean(b)

    return np.clip(mean_a * guide + mean_b, 0.0, None).astype(np.float32)


# ─────────────────────────────────────────────────────────────────────────────
# Color mixing — subtractive (pigment) model
# ─────────────────────────────────────────────────────────────────────────────

def mix_paint(c1: Color, c2: Color, t: float) -> Color:
    """
    Subtractive pigment mixing via sqrt-space blend.
    Unlike linear RGB averaging (which gives muddy midpoints),
    this approximates how physical paint pigments combine.
    """
    t = max(0.0, min(1.0, t))
    return tuple(math.sqrt((1 - t) * c1[i] ** 2 + t * c2[i] ** 2)
                 for i in range(3))


def jitter(c: Color, amount: float = 0.035, rng=None) -> Color:
    """Organic per-stroke color variation."""
    r = rng or random
    return tuple(max(0.0, min(1.0, c[i] + r.uniform(-amount, amount)))
                 for i in range(3))


def complement(c: Color) -> Color:
    """
    Return the chromatic complement of a colour by rotating hue 180° in HSV.

    Seurat's divisionism relies on simultaneous contrast: placing a colour
    beside its complement makes both appear more vivid.  This gives the
    luminous shimmer that physical pigment mixing cannot achieve.

    Unlike a naive (1-r, 1-g, 1-b) inversion this preserves saturation and
    value, so the complement dot is the same 'brightness' as the primary.
    """
    h, s, v = colorsys.rgb_to_hsv(*c)
    h_comp = (h + 0.5) % 1.0
    return colorsys.hsv_to_rgb(h_comp, s, v)


def snap_to_harmony(
    c: Color,
    palette: List[Color],
    snap_strength: float = 0.35,
) -> Color:
    """
    Soft-constrain a sampled colour toward the nearest colour in `palette`.

    Rather than hard-replacing the colour (which kills local variation), this
    lerps `snap_strength` of the way toward the closest palette entry.  The
    result retains per-pixel reference sampling while gently steering adjacent
    strokes into harmonious hue relationships.

    Parameters
    ----------
    c            : Sampled colour to constrain.
    palette      : List of (R, G, B) harmony colours from Palette.harmony().
    snap_strength: 0 = no snapping (identity); 1 = hard snap to palette.
                   0.25–0.40 gives subtle cohesion without killing variation.
    """
    if not palette or snap_strength < 1e-6:
        return c

    # Find nearest palette entry by Euclidean distance in RGB space
    best = min(palette, key=lambda p: sum((c[i] - p[i]) ** 2 for i in range(3)))
    t    = max(0.0, min(1.0, snap_strength))
    return tuple(c[i] + t * (best[i] - c[i]) for i in range(3))


def temp_shift(c: Color, warmth: float) -> Color:
    """
    Shift a colour toward warm (positive) or cool (negative).
    Warm: boost R, damp B.  Cool: boost B, damp R.
    Models the painter's warm-light / cool-shadow convention.
    """
    r, g, b = c
    if warmth > 0:
        return (min(1.0, r + warmth * 0.12),
                g,
                max(0.0, b - warmth * 0.08))
    else:
        w = -warmth
        return (max(0.0, r - w * 0.08),
                g,
                min(1.0, b + w * 0.12))


# ─────────────────────────────────────────────────────────────────────────────
# Canvas texture — linen grain via layered Perlin noise
# ─────────────────────────────────────────────────────────────────────────────

def make_linen_texture(w: int, h: int) -> np.ndarray:
    """
    Returns a (H, W) float32 array in [0.72, 1.0] representing linen weave.
    Two scales: coarse warp/weft threads + fine surface grain.
    """
    tex = np.zeros((h, w), dtype=np.float32)
    inv_w, inv_h = 1.0 / w, 1.0 / h
    for y in range(h):
        for x in range(w):
            # Coarse thread weave
            coarse = pnoise2(x * inv_w * 28, y * inv_h * 28,
                             octaves=2, persistence=0.5)
            # Fine surface grain
            fine = pnoise2(x * inv_w * 120, y * inv_h * 120,
                           octaves=3, persistence=0.4)
            tex[y, x] = coarse * 0.65 + fine * 0.35

    # Normalise to [0.72, 1.0]
    lo, hi = tex.min(), tex.max()
    tex = (tex - lo) / (hi - lo + 1e-8)
    return (0.72 + 0.28 * tex).astype(np.float32)


def make_cold_press_texture(w: int, h: int) -> np.ndarray:
    """
    Returns a (H, W) float32 array in [0.68, 1.0] representing cold-press
    watercolor paper texture.

    Cold-press (NOT) watercolor paper has a distinct character compared to
    woven linen canvas:

    1. **Large irregular tooth** — the paper surface has a rough, random grain
       formed by pressing the wet pulp sheet into a felt (the 'cold press').
       Two scales: coarse bumps (2–5mm) and medium mid-grain.

    2. **Horizontal laid lines** — the wire mesh of the papermaking mould
       leaves faint horizontal parallel striations spaced ~1mm apart.
       These are subtle but visible when paint pools in the valleys.

    3. **Chain lines** — thicker vertical wires are spaced every ~25mm,
       creating a barely perceptible vertical grid of slightly lower relief.

    Unlike linen, the cold-press surface absorbs water non-uniformly —
    higher areas resist first washes while low areas trap pigment.  This is
    the source of the characteristic blooms and cauliflowers of watercolor.

    The watercolor pipeline uses this texture in `tone_ground()` so the paper
    surface shows through in the untouched highlight areas.
    """
    tex = np.zeros((h, w), dtype=np.float32)
    inv_w, inv_h = 1.0 / w, 1.0 / h

    # ── Stage 1: Coarse irregular grain ──────────────────────────────────────
    # Two overlapping Perlin octave bands for paper bumps.
    for y in range(h):
        for x in range(w):
            coarse = pnoise2(x * inv_w * 18, y * inv_h * 18,
                             octaves=3, persistence=0.55)
            medium = pnoise2(x * inv_w * 55, y * inv_h * 55,
                             octaves=2, persistence=0.45)
            tex[y, x] = coarse * 0.55 + medium * 0.45

    # Normalise Perlin output to [0, 1]
    lo, hi = tex.min(), tex.max()
    tex = (tex - lo) / (hi - lo + 1e-8)

    # ── Stage 2: Horizontal laid lines ────────────────────────────────────────
    # Spaced ~1mm at 96 dpi ≈ every 3.8 pixels.  Subtle — only a 3% darkening
    # in the laid-line valleys so they appear as faint ribbing under wash.
    laid_period = max(3, round(h * 0.0035))          # ~0.35 % of canvas height
    ys = np.arange(h)
    laid = 0.03 * (0.5 - 0.5 * np.cos(2 * math.pi * ys / laid_period))
    tex -= laid[:, np.newaxis]                        # slight dip in laid valleys

    # ── Stage 3: Chain lines ──────────────────────────────────────────────────
    # Much wider spacing (~25mm at 96 dpi ≈ every 94px) and very faint (1%).
    chain_period = max(60, round(w * 0.12))
    xs = np.arange(w)
    chain = 0.01 * (0.5 - 0.5 * np.cos(2 * math.pi * xs / chain_period))
    tex -= chain[np.newaxis, :]

    # Re-normalise to [0.68, 1.0] — same range as linen texture
    lo, hi = tex.min(), tex.max()
    tex = (tex - lo) / (hi - lo + 1e-8)
    return (0.68 + 0.32 * tex).astype(np.float32)


# ─────────────────────────────────────────────────────────────────────────────
# BrushTip — normalised alpha mask for stamp-style edge texture
# ─────────────────────────────────────────────────────────────────────────────

class BrushTip:
    ROUND   = "round"
    FILBERT = "filbert"     # rounded-corner flat — most versatile
    FLAT    = "flat"

    def __init__(self, kind: str = FILBERT, bristle_noise: float = 0.06):
        self.kind = kind
        self.bristle_noise = bristle_noise

    def edge_softness(self, t_along: float) -> float:
        """
        Edge opacity modifier as a function of position along stroke (0-1).
        Tapers both tips; filbert and round taper more than flat.
        """
        if self.kind == BrushTip.FLAT:
            # Flat brush: sharp sides, only tiny taper at very ends
            return math.sin(min(t_along, 1 - t_along) * math.pi / 0.15) \
                   if t_along < 0.15 or t_along > 0.85 else 1.0
        else:
            # Round / filbert: smooth bell
            return math.sin(t_along * math.pi)


# ─────────────────────────────────────────────────────────────────────────────
# BrushProfile — physical tool properties driving bristle simulation
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class BrushProfile:
    """
    Describes the physical contact surface of a painting tool.

    Replaces BrushTip as the authoritative tool descriptor.  BrushTip instances
    are silently converted to BrushProfile at render time so all existing call
    sites receive bristle simulation without modification.

    Fields
    ------
    name            : Human-readable label (used in debug/logging).
    tool_type       : "brush" | "knife" | "finger" | "sponge"
    bristle_count   : Number of simulated bristles; 0 for knives/fingers.
    distribution    : How bristles are arranged across the ferrule:
                      "linear"  — evenly spaced (flat/bright brushes)
                      "oval"    — Gaussian cluster, denser at centre (filbert)
                      "radial"  — even angular spread (round brushes)
                      "arc"     — wide fan (fan/hake brushes)
    stiffness       : 0.0 (soft sable) to 1.0 (stiff hog bristle).
                      Drives per-bristle path deviation; low = more flex.
    spread          : Base fan-width multiplier relative to nominal stroke width.
                      1.0 = bristles exactly fill the stated width.
    pressure_spread : Additional spread gained at maximum pressure.
    load_capacity   : Relative paint charge compared to a standard brush (1.0).
    edge_sharpness  : For knives only — 0.0 = soft scrape, 1.0 = crisp edge.
    """
    name:             str
    tool_type:        str   = "brush"
    bristle_count:    int   = 14
    distribution:     str   = "oval"
    stiffness:        float = 0.5
    spread:           float = 1.0
    pressure_spread:  float = 0.2
    load_capacity:    float = 1.0
    edge_sharpness:   float = 0.0

    @classmethod
    def from_brush_tip(cls, tip: 'BrushTip') -> 'BrushProfile':
        """
        Convert a legacy BrushTip to the equivalent BrushProfile.

        bristle_noise maps to stiffness: noise=0 → loose/soft bristles,
        noise=0.25 → stiff hog-like bristles with heavy deviation.
        """
        stiffness = max(0.05, min(1.0, 0.1 + tip.bristle_noise * 3.6))
        if tip.kind == BrushTip.FLAT:
            return cls("hog_flat",    "brush", 16, "linear", stiffness, 1.00, 0.25, 1.00)
        elif tip.kind == BrushTip.FILBERT:
            return cls("hog_filbert", "brush", 14, "oval",   stiffness, 0.90, 0.20, 0.95)
        else:  # ROUND
            return cls("round_sable", "brush", 10, "radial", stiffness, 0.50, 0.15, 0.70)


