# ─────────────────────────────────────────────────────────────────────────────
# PressureProfile — within-stroke and per-pass pressure control
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class PressureProfile:
    """
    Controls how hard the painter presses at each point along a stroke and
    across strokes in a pass.

    Profile types
    -------------
    even        — Constant pressure throughout (filling, glazing).
    press_lift  — Heavy at start, taper off as stroke ends; the most natural
                  alla prima mark; models the brush leaving the canvas.
    lift_press  — Light touch building to full pressure mid-stroke; used for
                  building form without disturbing the underlying layer at entry.
    stab        — Immediate full pressure, released sharply; Cézanne comma
                  strokes, impasto dabs.
    feather     — Very light throughout; final blending, sfumato, glazing.

    Parameters
    ----------
    base_pressure : 0.0–1.0 default for this pass.
    variance      : Per-stroke random ± variation around base_pressure.
    """
    profile_type:  str   = "press_lift"
    base_pressure: float = 1.0
    variance:      float = 0.0

    def at(self, t: float) -> float:
        """Pressure in [0, 1] at normalised position t along a single stroke."""
        t = max(0.0, min(1.0, t))
        bp = self.base_pressure
        if self.profile_type == "even":
            return bp
        elif self.profile_type == "press_lift":
            return bp * (1.0 - t * 0.55)
        elif self.profile_type == "lift_press":
            return bp * (0.40 + t * 0.60)
        elif self.profile_type == "stab":
            return bp * math.exp(-t * 5.0)
        elif self.profile_type == "feather":
            return bp * 0.30
        return bp


# ─────────────────────────────────────────────────────────────────────────────
# PaintLoad — cross-stroke paint charge and depletion
# ─────────────────────────────────────────────────────────────────────────────

class PaintLoad:
    """
    Tracks paint charge on the brush across multiple strokes.

    A freshly loaded brush (load=1.0) deposits opaque, tightly bundled marks.
    As paint depletes, coverage thins and bristles spread — producing natural
    dry-brush texture automatically without any special-casing.

    Reload modes
    ------------
    every_stroke  — Reload after every stroke (alla prima / Sargent style).
    every_n       — Reload every N strokes; controlled gradation.
    threshold     — Reload when load drops below reload_threshold fraction.
    never         — Full depletion cycle; brush runs completely dry (Wyeth-style
                    dry brush, long texture runs).

    Usage guidance
    --------------
    - Pair ``every_stroke`` with press_lift pressure for bold alla prima work.
    - Pair ``threshold=0.15`` with even pressure for medium dry-brush sequences.
    - Pair ``never`` with long stroke_size for broken texture effects.
    - Do not use ``never`` for glazing passes; paint runs out almost immediately.
    """

    # Pixels of stroke travel that deplete one full load at neutral pressure.
    _PIXELS_PER_FULL_LOAD = 1200.0

    def __init__(
        self,
        capacity:         float = 1.0,
        reload_mode:      str   = "every_stroke",
        reload_n:         int   = 1,
        reload_threshold: float = 0.20,
    ):
        self.capacity         = capacity
        self.reload_mode      = reload_mode
        self.reload_n         = reload_n
        self.reload_threshold = reload_threshold
        self.current_load     = capacity
        self._stroke_count    = 0

    def deplete(self, stroke_length: float, pressure: float = 1.0):
        """Reduce load by distance × pressure, then reload if the mode requires it."""
        rate = pressure / self._PIXELS_PER_FULL_LOAD
        self.current_load = max(0.0, self.current_load - stroke_length * rate * self.capacity)
        self._stroke_count += 1

        if self.reload_mode == "every_stroke":
            self.current_load = self.capacity
        elif self.reload_mode == "every_n":
            if self._stroke_count % max(1, self.reload_n) == 0:
                self.current_load = self.capacity
        elif self.reload_mode == "threshold":
            if self.current_load < self.reload_threshold * self.capacity:
                self.current_load = self.capacity

    @property
    def coverage(self) -> float:
        """Alpha multiplier: 1.0 when full, ~0.05 at near-empty."""
        t = self.current_load / (self.capacity + 1e-9)
        return max(0.05, t ** 0.5)

    @property
    def bristle_spread_bonus(self) -> float:
        """Extra lateral spread as load depletes: 0.0 full → 0.4 empty."""
        t = 1.0 - self.current_load / (self.capacity + 1e-9)
        return t * 0.4


# ── Technique presets ─────────────────────────────────────────────────────────
# Named combinations of BrushProfile + PressureProfile + PaintLoad that
# correspond to recognised oil painting approaches.

def _technique(brush_key: str, profile_type: str = "press_lift",
               base_pressure: float = 1.0, reload_mode: str = "every_stroke",
               reload_n: int = 1, reload_threshold: float = 0.20
               ) -> dict:
    """Return a dict of kwargs for _place_strokes."""
    return {
        "brush_profile":    BRUSH_PRESETS[brush_key],
        "pressure_profile": PressureProfile(profile_type, base_pressure),
        "paint_load":       PaintLoad(reload_mode=reload_mode, reload_n=reload_n,
                                      reload_threshold=reload_threshold),
    }

TECHNIQUE_PRESETS: dict = {
    # Alla prima (Sargent / Sorolla): reload every stroke, heavy press_lift.
    # Deposit ratio ~90%.  Each mark is fresh and confident.
    "alla_prima":  _technique("hog_filbert", "press_lift",  1.0,  "every_stroke"),

    # Glazing: thin transparent layers over dry paint.
    # Deposit ratio ~70%, very low load capacity.
    "glazing":     _technique("round_sable", "feather",     0.55, "every_stroke"),

    # Dry brush: long runs between reloads; broken texture is the goal.
    # Deposit ratio ~85%.  Load depletes within 2–3 strokes.
    "dry_brush":   _technique("dry_brush",   "even",        0.85, "threshold",
                               reload_threshold=0.08),

    # Impasto: maximum load, stab pressure, knife or hog flat.
    # Deposit ratio ~95%.
    "impasto":     _technique("hog_flat",    "stab",        1.0,  "every_stroke"),

    # Blending pass (dry fan): manipulate only — no load, feather pressure.
    # Use PaintCanvas.smear() or apply_stroke with opacity near zero instead.
    "blending":    _technique("fan",         "feather",     0.25, "every_stroke"),
}


# ─────────────────────────────────────────────────────────────────────────────
# Stroke geometry helpers
# ─────────────────────────────────────────────────────────────────────────────

def catmull_rom(pts: List[Tuple], steps: int = 6) -> List[Tuple]:
    """Smooth a point list with Catmull-Rom interpolation."""
    if len(pts) < 2:
        return pts
    out = []
    n = len(pts)
    for i in range(n - 1):
        p0 = pts[max(i - 1, 0)]
        p1 = pts[i]
        p2 = pts[i + 1]
        p3 = pts[min(i + 2, n - 1)]
        for s in range(steps):
            t = s / steps
            t2, t3 = t * t, t * t * t
            x = 0.5 * ((2 * p1[0]) +
                       (-p0[0] + p2[0]) * t +
                       (2 * p0[0] - 5 * p1[0] + 4 * p2[0] - p3[0]) * t2 +
                       (-p0[0] + 3 * p1[0] - 3 * p2[0] + p3[0]) * t3)
            y = 0.5 * ((2 * p1[1]) +
                       (-p0[1] + p2[1]) * t +
                       (2 * p0[1] - 5 * p1[1] + 4 * p2[1] - p3[1]) * t2 +
                       (-p0[1] + 3 * p1[1] - 3 * p2[1] + p3[1]) * t3)
            out.append((x, y))
    out.append(pts[-1])
    return out


def build_stroke_outline(pts: List[Tuple], widths: List[float]
                         ) -> Tuple[List[Tuple], List[Tuple]]:
    """
    Offset a centre-line into left / right boundary polygons.
    Returns (left_side, right_side) each as a list of (x, y).
    """
    left, right = [], []
    n = len(pts)
    for i in range(n):
        if i == 0:
            dx, dy = pts[1][0] - pts[0][0], pts[1][1] - pts[0][1]
        elif i == n - 1:
            dx, dy = pts[-1][0] - pts[-2][0], pts[-1][1] - pts[-2][1]
        else:
            dx, dy = pts[i+1][0] - pts[i-1][0], pts[i+1][1] - pts[i-1][1]

        mag = math.hypot(dx, dy) or 1e-6
        px, py = -dy / mag, dx / mag       # perpendicular (left normal)
        hw = widths[i] / 2.0
        left.append( (pts[i][0] + px * hw, pts[i][1] + py * hw))
        right.append((pts[i][0] - px * hw, pts[i][1] - py * hw))
    return left, right


def width_profile(n: int, tip_frac: float = 0.18) -> List[float]:
    """Bell-shaped width envelope: narrow at both tips, full in middle."""
    out = []
    for i in range(n):
        t = i / max(n - 1, 1)
        if t < tip_frac:
            v = t / tip_frac
        elif t > 1 - tip_frac:
            v = (1 - t) / tip_frac
        else:
            v = 1.0
        out.append(max(0.05, v))
    return out


def stroke_path(origin: Tuple, angle: float, length: float,
                curve: float = 0.0, n: int = 7) -> List[Tuple]:
    """
    Generate a gently curved centre-line.
    curve: radians of total arc over the stroke length.
    """
    pts = [origin]
    x, y = origin
    a = angle
    step = length / n
    da = curve / n
    for _ in range(n):
        a += da
        x += math.cos(a) * step
        y += math.sin(a) * step
        pts.append((x, y))
    return pts


# ─────────────────────────────────────────────────────────────────────────────
# Bristle simulation helpers
# ─────────────────────────────────────────────────────────────────────────────

def _bristle_offsets(
    profile: BrushProfile,
    rng: random.Random,
) -> List[Tuple[float, float]]:
    """
    Compute (lateral_fraction, deviation_amplitude) for each bristle.

    lateral_fraction  : -1 (far left) to +1 (far right) of nominal half-width.
    deviation_amplitude: signed scale of per-step path wander (bristle flex).

    Seeded via the caller's RNG so results are deterministic per stroke.
    """
    n   = profile.bristle_count
    s   = profile.stiffness
    spd = profile.spread
    out = []

    for i in range(n):
        dist = profile.distribution
        if dist == "linear":
            # Evenly spaced chisel edge; outer bristles deviate more.
            lat = (i / (n - 1) * 2.0 - 1.0) * spd if n > 1 else 0.0
            dev = s * (0.5 + abs(lat / max(spd, 1e-6)) * 0.5)
        elif dist == "oval":
            # Gaussian cluster denser at centre.
            lat = max(-spd, min(spd, rng.gauss(0.0, spd * 0.38)))
            dev = s * 0.6
        elif dist == "radial":
            # Even angular spread for round/rigger brushes.
            lat = math.sin(i * 2.0 * math.pi / max(n, 1)) * spd * 0.8
            dev = s * 0.4
        elif dist == "arc":
            # Wide fan: bristles splay beyond nominal width.
            lat = (i / (n - 1) * 2.0 - 1.0) * spd if n > 1 else 0.0
            dev = s * 0.2
        else:
            lat = rng.uniform(-spd, spd)
            dev = s * 0.5

        out.append((lat, dev))

    return out


def _bristle_path(
    pts:          List[Tuple],
    scaled_widths: List[float],
    lat_fraction: float,
    dev_amplitude: float,
    rng:          random.Random,
) -> List[Tuple]:
    """
    Compute the world-space path for one bristle.

    The bristle sits at lat_fraction × half-width perpendicular to the stroke
    center-line and accumulates a small longitudinal wander (dev_amplitude)
    at each step — modelling bristle flex under paint drag.

    At the tips, scaled_widths is small, so bristles naturally converge toward
    the center.  Taper is thus geometric rather than requiring per-segment alpha.
    """
    n   = len(pts)
    out = []
    cum = 0.0   # cumulative longitudinal deviation

    for i in range(n):
        if i == 0:
            dx, dy = pts[1][0] - pts[0][0],   pts[1][1] - pts[0][1]
        elif i == n - 1:
            dx, dy = pts[-1][0] - pts[-2][0], pts[-1][1] - pts[-2][1]
        else:
            dx, dy = pts[i+1][0] - pts[i-1][0], pts[i+1][1] - pts[i-1][1]

        mag = math.hypot(dx, dy) or 1e-6
        px, py = -dy / mag, dx / mag   # perpendicular (left normal)
        fx, fy =  dx / mag, dy / mag   # forward

        hw  = scaled_widths[i] * 0.5
        lat = lat_fraction * hw

        cum += dev_amplitude * rng.gauss(0.0, 0.4)
        cum *= 0.82  # decay prevents unbounded drift

        out.append((pts[i][0] + px * lat + fx * cum,
                    pts[i][1] + py * lat + fy * cum))

    return out


def _tip_taper(distribution: str, t: float) -> float:
    """
    Alpha taper factor at normalised position t (0 = stroke start, 1 = end).

    For flat/linear brushes the taper is minimal and sharp (chisel edge).
    For oval/radial the taper follows a full sin bell.
    """
    if distribution == "linear":
        # Sharp taper only at the outermost 12% of each end.
        margin = t if t < 0.5 else (1.0 - t)
        if margin < 0.12:
            return math.sin(margin / 0.12 * math.pi * 0.5)
        return 1.0
    else:
        return math.sin(max(0.0, min(1.0, t)) * math.pi)


# ─────────────────────────────────────────────────────────────────────────────
# PaintCanvas
# ─────────────────────────────────────────────────────────────────────────────

class PaintCanvas:
    """
    The painting surface.

    Cairo ImageSurface is the master pixel store.
    A numpy wetness map tracks which regions have fresh paint
    so wet-on-wet blending can be simulated.
    """

    def __init__(self, width: int, height: int):
        self.w, self.h = width, height
        self.surface = cairo.ImageSurface(cairo.FORMAT_ARGB32, width, height)
        self.ctx     = cairo.Context(self.surface)
        self.ctx.set_antialias(cairo.ANTIALIAS_BEST)

        # Wetness: 1.0 = fresh paint, decays between layers
        self.wetness = np.zeros((height, width), dtype=np.float32)

        # Impasto thickness: accumulated per-pixel paint height [0, 1].
        # Driven by load and pressure; used by the sheen pass.
        self.thickness_map = np.zeros((height, width), dtype=np.float32)

        # Linen texture (built once)
        print("  Weaving linen texture…")
        self.texture = make_linen_texture(width, height)

    # ── Ground ────────────────────────────────────────────────────────────────

    def tone(self, color: Color, texture_strength: float = 0.07):
        """
        Prime the canvas with a toned ground.
        The texture modulates the ground colour so the linen weave shows through.
        """
        r, g, b = color
        # Build BGRA array with texture variation
        tex = self.texture
        arr = np.zeros((self.h, self.w, 4), dtype=np.uint8)
        arr[:, :, 0] = np.clip((b * (1 - texture_strength + texture_strength * tex)) * 255, 0, 255)
        arr[:, :, 1] = np.clip((g * (1 - texture_strength + texture_strength * tex)) * 255, 0, 255)
        arr[:, :, 2] = np.clip((r * (1 - texture_strength + texture_strength * tex)) * 255, 0, 255)
        arr[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(arr.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.ctx.set_source_surface(tmp, 0, 0)
        self.ctx.paint()
        self.wetness[:] = 0.0

    # ── Stroke application ────────────────────────────────────────────────────

    def _sample_color(self, x: int, y: int) -> Color:
        """Read canvas colour at pixel (x, y) — fast single-pixel read."""
        x = max(0, min(self.w - 1, x))
        y = max(0, min(self.h - 1, y))
        buf  = self.surface.get_data()
        off  = (y * self.w + x) * 4
        b, g, r, _ = buf[off], buf[off+1], buf[off+2], buf[off+3]
        return r / 255.0, g / 255.0, b / 255.0

    def apply_stroke(self,
                     pts:              List[Tuple],
                     widths:           List[float],
                     color:            Color,
                     tip:              Union[BrushTip, BrushProfile],
                     opacity:          float = 0.82,
                     wet_blend:        float = 0.22,
                     jitter_amt:       float = 0.03,
                     rng=None,
                     region_mask:      Optional[np.ndarray] = None,
                     pressure_profile: Optional[PressureProfile] = None,
                     paint_load:       Optional[PaintLoad]       = None):
        """
        Place one brush stroke on the canvas using bristle simulation.

        Each stroke is decomposed into N individual bristle sub-strokes whose
        paths deviate deterministically from the centre-line (seeded from stroke
        origin + angle).  The emergent bundle produces ragged, organic edges and
        visible bristle tracks — impossible with the old polygon fill approach.

        Accepts either a legacy BrushTip (auto-converted to BrushProfile) or a
        BrushProfile directly.  All existing call sites continue to work without
        modification.

        New optional parameters
        -----------------------
        pressure_profile : PressureProfile controlling within-stroke pressure.
                           Defaults to press_lift when None.
        paint_load       : PaintLoad tracking charge across strokes.  When None,
                           each stroke behaves as if fully loaded (reload_mode
                           = every_stroke).
        """
        if len(pts) < 2:
            return

        # ── Convert legacy BrushTip → BrushProfile ───────────────────────────
        profile: BrushProfile = (
            tip if isinstance(tip, BrushProfile)
            else BrushProfile.from_brush_tip(tip)
        )

        # ── Smooth centre-line ────────────────────────────────────────────────
        pts = catmull_rom(pts, steps=5)
        orig_n = len(widths)
        new_n  = len(pts)
        if new_n != orig_n:
            widths = [widths[int(i * (orig_n - 1) / max(new_n - 1, 1))]
                      for i in range(new_n)]

        # ── Wet blending (sampled at stroke midpoint for colour) ─────────────
        # Colour is blended once at the midpoint — sampling per-segment would
        # be prohibitively slow.  Wetness IS sampled at start, mid, and end so
        # the gradient can modulate edge softness along the stroke length.
        def _wet(pt: Tuple) -> float:
            return float(self.wetness[max(0, min(self.h-1, int(pt[1]))),
                                      max(0, min(self.w-1, int(pt[0])))])

        wet_start  = _wet(pts[0])
        wet_mid_pt = pts[len(pts) // 2]
        wet_mid    = _wet(wet_mid_pt)
        wet_end    = _wet(pts[-1])

        canvas_col = self._sample_color(int(wet_mid_pt[0]), int(wet_mid_pt[1]))
        blend_t    = wet_blend * wet_mid
        paint_col  = mix_paint(color, canvas_col, blend_t)
        paint_col  = jitter(paint_col, jitter_amt, rng)
        pr, pg, pb = paint_col

        # ── Width profile (bell curve — tips narrower) ────────────────────────
        wp            = width_profile(len(pts))
        scaled_widths = [wp[i] * widths[i] for i in range(len(pts))]

        # ── Deterministic bristle RNG seeded from stroke geometry ─────────────
        # Seeding from (origin, angle) means re-rendering the same pass yields
        # identical bristle patterns — important for iterative development.
        origin       = pts[0]
        stroke_angle = math.atan2(pts[-1][1] - origin[1],
                                  pts[-1][0] - origin[0])
        seed         = int(abs(origin[0] * 1373 + origin[1] * 7919
                                + stroke_angle * 10007)) % (2 ** 31)
        bristle_rng  = random.Random(seed)

        # ── Load and spread modifiers ─────────────────────────────────────────
        load_coverage = paint_load.coverage            if paint_load else 1.0
        spread_bonus  = paint_load.bristle_spread_bonus if paint_load else 0.0

        # Effective spread including depletion-driven splay.
        eff_profile = BrushProfile(
            name=profile.name, tool_type=profile.tool_type,
            bristle_count=profile.bristle_count,
            distribution=profile.distribution,
            stiffness=profile.stiffness,
            spread=profile.spread + spread_bonus,
            pressure_spread=profile.pressure_spread,
            load_capacity=profile.load_capacity,
            edge_sharpness=profile.edge_sharpness,
        )

        # ── Generate bristle layout ───────────────────────────────────────────
        bristles = _bristle_offsets(eff_profile, bristle_rng)
        n_b      = max(len(bristles), 1)

        # Per-bristle line width: overlap slightly so bundle reads as solid.
        # Outer bristles are naturally thinner (scale down with abs(lat)).
        base_bristle_w = max(0.6, scaled_widths[len(scaled_widths) // 2] / n_b * 2.2)

        # ── Collect all bristle points for bbox (wetness + thickness update) ──
        all_pts: List[Tuple] = []

        # ── Render each bristle ───────────────────────────────────────────────
        n_pts = len(pts)

        for lat_frac, dev_amp in bristles:
            b_pts = _bristle_path(pts, scaled_widths, lat_frac, dev_amp, bristle_rng)
            all_pts.extend(b_pts)

            # Per-bristle width varies with lateral distance from centre.
            b_w = max(0.5, base_bristle_w * (1.0 - abs(lat_frac) * 0.25))

            n_seg = len(b_pts) - 1
            for i in range(n_seg):
                # Region mask guard (per-segment).
                if region_mask is not None:
                    seg_cx = int((b_pts[i][0] + b_pts[i+1][0]) * 0.5)
                    seg_cy = int((b_pts[i][1] + b_pts[i+1][1]) * 0.5)
                    seg_cx = max(0, min(self.w - 1, seg_cx))
                    seg_cy = max(0, min(self.h - 1, seg_cy))
                    if region_mask[seg_cy, seg_cx] < 0.5:
                        continue

                t_along = (i + 0.5) / max(n_seg, 1)

                # Pressure taper along stroke length.
                pressure = (pressure_profile.at(t_along)
                            if pressure_profile else
                            max(0.1, 1.0 - t_along * 0.55))  # default press_lift

                # Geometric taper at tips (from narrowing width profile + alpha).
                taper = _tip_taper(eff_profile.distribution, t_along)

                # ── Wetness gradient (3.3) ────────────────────────────────────
                # Interpolate wetness along the stroke: start→mid→end.
                # Wet paint spreads more, reads as softer and slightly more
                # translucent; drier paint sits harder and more opaque.
                if t_along <= 0.5:
                    wet_t = wet_start + (wet_mid - wet_start) * (t_along * 2.0)
                else:
                    wet_t = wet_mid + (wet_end - wet_mid) * ((t_along - 0.5) * 2.0)

                # Wet paint softens alpha slightly at edges (0–12% reduction).
                wet_softness = 1.0 - wet_t * 0.12

                # Wet paint widens the bristle slightly (paint flows laterally).
                wet_width_bonus = 1.0 + wet_t * 0.10

                seg_alpha = opacity * pressure * load_coverage * taper * wet_softness
                if seg_alpha < 0.015:
                    continue

                self.ctx.move_to(*b_pts[i])
                self.ctx.line_to(*b_pts[i + 1])
                self.ctx.set_line_width(b_w * max(0.4, pressure) * wet_width_bonus)
                self.ctx.set_line_cap(cairo.LINE_CAP_ROUND)
                self.ctx.set_source_rgba(pr, pg, pb, seg_alpha)
                self.ctx.stroke()

        # ── Update wetness in bbox ────────────────────────────────────────────
        if all_pts:
            all_x  = [int(p[0]) for p in all_pts]
            all_y  = [int(p[1]) for p in all_pts]
            bx0 = max(0,       min(all_x))
            bx1 = min(self.w,  max(all_x) + 1)
            by0 = max(0,       min(all_y))
            by1 = min(self.h,  max(all_y) + 1)
            self.wetness[by0:by1, bx0:bx1] = np.minimum(
                1.0, self.wetness[by0:by1, bx0:bx1] + 0.35)

            # Thickness: proportional to load × average pressure.
            avg_pressure = (pressure_profile.base_pressure
                            if pressure_profile else 0.7)
            thickness_add = load_coverage * avg_pressure * 0.08
            self.thickness_map[by0:by1, bx0:bx1] = np.minimum(
                1.0, self.thickness_map[by0:by1, bx0:bx1] + thickness_add)

        # ── Deplete paint load for next stroke ────────────────────────────────
        if paint_load:
            stroke_px = sum(
                math.hypot(pts[i+1][0] - pts[i][0], pts[i+1][1] - pts[i][1])
                for i in range(len(pts) - 1)
            )
            avg_p = (pressure_profile.base_pressure
                     if pressure_profile else 0.7)
            paint_load.deplete(stroke_px, avg_p)

    # ── Knife tool ────────────────────────────────────────────────────────────

    def apply_knife_stroke(self,
                           pts:         List[Tuple],
                           widths:      List[float],
                           color:       Color,
                           profile:     BrushProfile,
                           opacity:     float = 0.96,
                           scrape:      bool  = False,
                           wet_blend:   float = 0.08,
                           jitter_amt:  float = 0.01,
                           rng=None,
                           region_mask: Optional[np.ndarray] = None):
        """
        Deposit or scrape paint using a rigid painting knife.

        A knife has no bristles.  In deposit mode it lays a flat slab of
        paint with crisp lateral edges, a subtle blade-texture micro-grain,
        and a slightly thicker ridge at the trailing edge (where the blade
        lifts off).  In scrape mode it removes paint, revealing the layer
        beneath.

        Usage guidance
        --------------
        Deposit: impasto highlights, bold colour statements, textured
                 foregrounds.  Follow with no brush strokes on the same
                 area; let the knife mark stand.
        Scrape : corrective lightening, creating texture contrast by
                 revealing a lower layer.  Use sparingly — once or twice
                 per passage.

        Do not use for fine detail.  Knife marks are large, confident
        statements — they read as such at normal viewing distance.
        """
        if len(pts) < 2:
            return

        pts   = catmull_rom(pts, steps=5)
        orig_n = len(widths)
        new_n  = len(pts)
        if new_n != orig_n:
            widths = [widths[int(i * (orig_n - 1) / max(new_n - 1, 1))]
                      for i in range(new_n)]

        # Wet blend (sampled at midpoint).
        mid       = pts[len(pts) // 2]
        mx, my    = int(mid[0]), int(mid[1])
        canvas_c  = self._sample_color(mx, my)
        wet_at    = float(self.wetness[max(0, min(self.h-1, my)),
                                       max(0, min(self.w-1, mx))])
        if not scrape:
            blend_t   = wet_blend * wet_at
            paint_col = mix_paint(color, canvas_c, blend_t)
            paint_col = jitter(paint_col, jitter_amt, rng)
        else:
            # Scrape: blend heavily toward canvas colour (lifting paint).
            paint_col = mix_paint(canvas_c, (1.0, 1.0, 1.0), 0.15)
        pr, pg, pb = paint_col

        # Width profile — flat brush keeps near-full width almost to the tips.
        wp            = width_profile(len(pts), tip_frac=0.06)
        scaled_widths = [wp[i] * widths[i] for i in range(len(pts))]
        left, right   = build_stroke_outline(pts, scaled_widths)

        rng_ = rng or random
        n_seg = len(pts) - 1

        for i in range(n_seg):
            if region_mask is not None:
                seg_cx = int((pts[i][0] + pts[i+1][0]) * 0.5)
                seg_cy = int((pts[i][1] + pts[i+1][1]) * 0.5)
                seg_cx = max(0, min(self.w - 1, seg_cx))
                seg_cy = max(0, min(self.h - 1, seg_cy))
                if region_mask[seg_cy, seg_cx] < 0.5:
                    continue

            t_mid = (i + 0.5) / max(n_seg, 1)

            # Knife taper: sharp rectangular body, tiny roll-off at very ends.
            if t_mid < 0.05 or t_mid > 0.95:
                margin = t_mid if t_mid < 0.5 else (1.0 - t_mid)
                alpha  = opacity * math.sin(margin / 0.05 * math.pi * 0.5)
            else:
                alpha = opacity

            if scrape:
                alpha *= 0.5 + wet_at * 0.5  # scrape more effective on wet paint

            i0 = min(i, len(left) - 1)
            i1 = min(i + 1, len(left) - 1)
            quad = [left[i0], left[i1], right[i1], right[i0]]

            self.ctx.move_to(*quad[0])
            for p in quad[1:]:
                self.ctx.line_to(*p)
            self.ctx.close_path()
            self.ctx.set_source_rgba(pr, pg, pb, alpha)
            self.ctx.fill()

            # Micro-grain texture: faint parallel lines along stroke direction.
            if not scrape and i % 2 == 0:
                dx = pts[min(i+1, n_seg)][0] - pts[i][0]
                dy = pts[min(i+1, n_seg)][1] - pts[i][1]
                mag = math.hypot(dx, dy) or 1e-6
                for k in range(3):
                    kf   = (k - 1) * 0.28
                    px_  = -dy / mag * kf * scaled_widths[i0]
                    py_  =  dx / mag * kf * scaled_widths[i0]
                    self.ctx.move_to(left[i0][0]  + px_, left[i0][1]  + py_)
                    self.ctx.line_to(left[i1][0]  + px_, left[i1][1]  + py_)
                    self.ctx.set_line_width(0.4)
                    self.ctx.set_source_rgba(pr * 0.92, pg * 0.92, pb * 0.92,
                                             alpha * 0.18)
                    self.ctx.stroke()

        # Trailing-edge paint pileup: darker ridge along the final segments.
        if not scrape and n_seg > 2:
            ridge_start = max(0, n_seg - max(2, n_seg // 8))
            for i in range(ridge_start, n_seg):
                for side in (left, right):
                    i0 = min(i, len(side) - 1)
                    i1 = min(i + 1, len(side) - 1)
                    self.ctx.move_to(*side[i0])
                    self.ctx.line_to(*side[i1])
                    self.ctx.set_line_width(1.2)
                    self.ctx.set_source_rgba(pr * 0.78, pg * 0.78, pb * 0.78,
                                             opacity * 0.55)
                    self.ctx.stroke()

        # Update wetness + thickness.
        all_x = [int(p[0]) for p in left + right]
        all_y = [int(p[1]) for p in left + right]
        bx0 = max(0,      min(all_x))
        bx1 = min(self.w, max(all_x) + 1)
        by0 = max(0,      min(all_y))
        by1 = min(self.h, max(all_y) + 1)
        self.wetness[by0:by1, bx0:bx1] = np.minimum(
            1.0, self.wetness[by0:by1, bx0:bx1] + (0.50 if not scrape else 0.0))
        if not scrape:
            self.thickness_map[by0:by1, bx0:bx1] = np.minimum(
                1.0, self.thickness_map[by0:by1, bx0:bx1] + 0.25)

    # ── Finger / smear tool ───────────────────────────────────────────────────

    def smear(self,
              pts:         List[Tuple],
              radius:      float = 8.0,
              strength:    float = 0.40,
              region_mask: Optional[np.ndarray] = None):
        """
        Soft Gaussian smear of existing canvas colour along a path.

        Models a painter's finger dragged across wet paint.  No new colour is
        added; the tool only blends neighbouring pixels.

        Usage guidance
        --------------
        - Use to soften transitions between two wet areas (sky-to-horizon,
          shadow-to-light edge).
        - Apply after a brush pass to unify adjacent strokes into a smooth
          tonal field.
        - Limit to 1–3 passes over any one area; heavy use destroys texture
          and reads as muddy, overworked paint.
        - Do not use on impasto or knife marks; the raised texture is the
          point of those marks.
        - Only effective on wet paint; on dry areas the smear has minimal
          visible impact (models real physics).

        Parameters
        ----------
        pts      : Centre-line of the smear path.
        radius   : Gaussian blur radius in pixels.  Larger = softer blend.
        strength : [0, 1] blend fraction toward the smeared result.
                   0.0 = no effect; 1.0 = full replacement.
        """
        if len(pts) < 1 or strength < 0.01:
            return

        pts     = catmull_rom(pts, steps=4) if len(pts) > 1 else pts
        radius  = max(1.0, radius)
        sigma   = radius * 0.45

        # Read current canvas as float RGB.
        buf = np.frombuffer(self.surface.get_data(), dtype=np.uint8).copy()
        arr = buf.reshape(self.h, self.w, 4)
        rgb = arr[:, :, [2, 1, 0]].astype(np.float32) / 255.0

        # Gaussian blur of the full canvas — blurred version is the "smear target".
        from scipy.ndimage import gaussian_filter
        blurred = gaussian_filter(rgb, sigma=[sigma, sigma, 0])

        # For each point along path, blend a disc-shaped region toward blurred.
        r_int = max(1, int(radius))
        for pt in pts[::max(1, len(pts) // 20)]:
            px, py = int(pt[0]), int(pt[1])
            if not (0 <= px < self.w and 0 <= py < self.h):
                continue
            if region_mask is not None:
                if region_mask[py, px] < 0.5:
                    continue

            # Wetness gate: smear effect scales with local wetness.
            local_wet = float(self.wetness[py, px])
            eff_str   = strength * (0.25 + local_wet * 0.75)

            y0 = max(0,       py - r_int)
            y1 = min(self.h,  py + r_int + 1)
            x0 = max(0,       px - r_int)
            x1 = min(self.w,  px + r_int + 1)

            ys, xs = np.mgrid[y0:y1, x0:x1]
            dist2  = (ys - py) ** 2 + (xs - px) ** 2
            weight = np.exp(-dist2 / (2 * sigma ** 2))[..., np.newaxis]
            weight = weight * eff_str

            rgb[y0:y1, x0:x1] = np.clip(
                rgb[y0:y1, x0:x1] * (1 - weight) +
                blurred[y0:y1, x0:x1] * weight,
                0.0, 1.0,
            )

        # Write back.
        out = arr.copy()
        out[:, :, 0] = np.clip(rgb[:, :, 2] * 255, 0, 255).astype(np.uint8)
        out[:, :, 1] = np.clip(rgb[:, :, 1] * 255, 0, 255).astype(np.uint8)
        out[:, :, 2] = np.clip(rgb[:, :, 0] * 255, 0, 255).astype(np.uint8)
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(out.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.ctx.set_source_surface(tmp, 0, 0)
        self.ctx.paint()

    # ── Sheen pass (wet paint highlight) ─────────────────────────────────────

    def sheen_pass(self, light_angle: float = 2.36, strength: float = 0.35):
        """
        Composite a specular sheen over raised impasto edges.

        Finds high-gradient regions of the thickness_map and adds a directional
        highlight — simulating raking light catching the edges of thick paint
        strokes.  Called after all painting passes, before vignette.

        Usage guidance
        --------------
        - strength 0.20–0.40 is natural for oil; higher reads as very wet /
          varnished.
        - light_angle matches the Painter's light_pos convention where
          applicable; default ~135° (upper-left) matches studio lighting.

        Parameters
        ----------
        light_angle : Direction of raking light in radians.
        strength    : Peak highlight opacity added at raised edges.
        """
        if self.thickness_map.max() < 0.01:
            return

        lx = math.cos(light_angle)
        ly = math.sin(light_angle)

        # Gradient of thickness map along light direction.
        from scipy.ndimage import sobel
        gx = sobel(self.thickness_map, axis=1).astype(np.float32)
        gy = sobel(self.thickness_map, axis=0).astype(np.float32)
        directional = (gx * lx + gy * ly)
        directional = np.clip(directional, 0.0, None)

        # Normalise to [0, 1].
        peak = directional.max()
        if peak < 1e-6:
            return
        highlight = (directional / peak * strength).astype(np.float32)

        # ── Tinted highlight (3.2) ────────────────────────────────────────────
        # Rather than adding pure white, the highlight is tinted from the
        # local paint colour.  Real specular highlights on oil paint pick up a
        # warm, slightly desaturated version of the surrounding colour —
        # pure white reads as plastic.
        #
        # Formula: highlight_colour = local_colour × 0.35 + white × 0.65
        # Then brightened by ×1.25 so the result is noticeably lighter than
        # the paint body.
        buf = np.frombuffer(self.surface.get_data(), dtype=np.uint8).copy()
        arr = buf.reshape(self.h, self.w, 4).astype(np.float32)

        # BGRA channel layout: 0=B, 1=G, 2=R, 3=A
        b_f = arr[:, :, 0] / 255.0
        g_f = arr[:, :, 1] / 255.0
        r_f = arr[:, :, 2] / 255.0

        # Tint: mix local colour with white, then brighten.
        tint_r = np.clip(r_f * 0.35 + 0.65, 0.0, 1.0) * 1.25
        tint_g = np.clip(g_f * 0.35 + 0.65, 0.0, 1.0) * 1.25
        tint_b = np.clip(b_f * 0.35 + 0.65, 0.0, 1.0) * 1.25

        arr[:, :, 2] = np.clip((r_f + highlight * tint_r) * 255, 0, 255)
        arr[:, :, 1] = np.clip((g_f + highlight * tint_g) * 255, 0, 255)
        arr[:, :, 0] = np.clip((b_f + highlight * tint_b) * 255, 0, 255)

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(arr.astype(np.uint8).tobytes()),
            cairo.FORMAT_ARGB32, self.w, self.h)
        self.ctx.set_source_surface(tmp, 0, 0)
        self.ctx.paint()

    # ── Phase 2 tools ─────────────────────────────────────────────────────────

    def fan_blend(self,
                  pts:         List[Tuple],
                  width:       float = 30.0,
                  strength:    float = 0.45,
                  n_passes:    int   = 1,
                  region_mask: Optional[np.ndarray] = None):
        """
        Dry fan-brush blend along a path — pure manipulation, no new paint.

        Models a fan brush with zero load dragged lightly across wet strokes.
        Merges neighbouring colours with a soft directional Gaussian, producing
        smooth tonal transitions without adding any colour of its own.

        Usage guidance
        --------------
        - Apply after a brush pass to soften edges that should not remain as
          distinct marks (sky gradients, shadow-to-light on skin, background).
        - Run parallel to the dominant stroke direction for smooth blends;
          perpendicular for a more diffuse, all-over merge.
        - 1–2 passes maximum per area.  More passes destroy surface texture and
          read as overworked, muddy paint.
        - Do NOT use after a knife pass or on impasto areas; the raised texture
          is the point of those marks — blending flattens them.
        - Only meaningfully effective while the underlying paint is wet.

        Parameters
        ----------
        pts      : Centre-line of the blend path.
        width    : Blend radius in pixels; wider = softer, less directional.
        strength : [0, 1] blend fraction toward smeared average per pass.
        n_passes : Number of sweeps.  Keep ≤ 2.
        """
        # Fan blend is the smear tool running at lower strength with a wider
        # radius and a directional orientation bias.  We reuse smear() with
        # a sigma that makes it explicitly directional.
        if len(pts) < 1 or strength < 0.01:
            return
        sigma_lat = max(1.0, width * 0.5)
        sigma_fwd = max(1.0, width * 0.12)   # much tighter along stroke direction

        pts_s = catmull_rom(pts, steps=4) if len(pts) > 1 else list(pts)

        buf = np.frombuffer(self.surface.get_data(), dtype=np.uint8).copy()
        arr = buf.reshape(self.h, self.w, 4)
        rgb = arr[:, :, [2, 1, 0]].astype(np.float32) / 255.0

        from scipy.ndimage import gaussian_filter

        for _ in range(n_passes):
            blurred = gaussian_filter(rgb, sigma=[sigma_lat, sigma_lat, 0])
            for pt in pts_s[::max(1, len(pts_s) // 24)]:
                px, py = int(pt[0]), int(pt[1])
                if not (0 <= px < self.w and 0 <= py < self.h):
                    continue
                if region_mask is not None and region_mask[py, px] < 0.5:
                    continue
                local_wet = float(self.wetness[py, px])
                eff = strength * (0.15 + local_wet * 0.85)
                r_int = max(1, int(sigma_lat))
                y0 = max(0,      py - r_int); y1 = min(self.h, py + r_int + 1)
                x0 = max(0,      px - r_int); x1 = min(self.w, px + r_int + 1)
                ys, xs = np.mgrid[y0:y1, x0:x1]
                w2d = np.exp(-((ys-py)**2 / (2*sigma_lat**2) +
                               (xs-px)**2 / (2*sigma_lat**2)))[..., np.newaxis] * eff
                rgb[y0:y1, x0:x1] = np.clip(
                    rgb[y0:y1, x0:x1] * (1 - w2d) + blurred[y0:y1, x0:x1] * w2d,
                    0.0, 1.0)

        out = arr.copy()
        out[:, :, 0] = np.clip(rgb[:, :, 2] * 255, 0, 255).astype(np.uint8)
        out[:, :, 1] = np.clip(rgb[:, :, 1] * 255, 0, 255).astype(np.uint8)
        out[:, :, 2] = np.clip(rgb[:, :, 0] * 255, 0, 255).astype(np.uint8)
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(out.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.ctx.set_source_surface(tmp, 0, 0)
        self.ctx.paint()

    def rag(self,
            pts:         List[Tuple],
            width:       float = 40.0,
            mode:        str   = "drag",
            strength:    float = 0.40,
            region_mask: Optional[np.ndarray] = None):
        """
        Rag / cloth — spread or lift existing paint along a path.

        Two modes:

        drag (manipulate)
            Spreads wet paint thinly across a larger area, reducing local
            opacity and adding a faint cloth-grain directional texture.
            Classic use: establishing large tonal areas in the underpainting
            and block-in stages; creating soft atmospheric backgrounds.

        wipe (remove)
            Lifts paint toward the underlying layer.  Proportional to
            strength and local wetness.  Light wipe = subtle lightening;
            heavy wipe = back toward ground colour.
            Classic use: corrections, carving light areas into a dark ground.

        Usage guidance
        --------------
        - Drag is most effective in early stages (underpainting, block-in)
          before fine marks are placed.
        - Wipe is a correction tool; use deliberately, not habitually.
        - Do NOT rag over freshly knifed impasto — it flattens the texture.
        - A rag-drag pass followed by a fresh brush pass is a classic sequence
          for building soft, unified backgrounds.
        - Like all manipulation tools: only works on wet paint.

        Parameters
        ----------
        pts      : Centre-line of the rag path.
        width    : Coverage radius in pixels.
        mode     : "drag" (spread/thin) or "wipe" (lift toward ground).
        strength : [0, 1] effect intensity per step.
        """
        if len(pts) < 1 or strength < 0.01:
            return
        pts_s = catmull_rom(pts, steps=4) if len(pts) > 1 else list(pts)
        sigma = max(2.0, width * 0.35)

        buf = np.frombuffer(self.surface.get_data(), dtype=np.uint8).copy()
        arr = buf.reshape(self.h, self.w, 4)
        rgb = arr[:, :, [2, 1, 0]].astype(np.float32) / 255.0

        from scipy.ndimage import gaussian_filter, uniform_filter

        if mode == "drag":
            # Spread + lighten: blend toward a locally averaged, slightly brighter value.
            spread = gaussian_filter(rgb, sigma=[sigma, sigma, 0])
            # Cloth-grain texture: alternate strength along stroke to suggest weave.
            for idx, pt in enumerate(pts_s[::max(1, len(pts_s)//20)]):
                px, py = int(pt[0]), int(pt[1])
                if not (0 <= px < self.w and 0 <= py < self.h):
                    continue
                if region_mask is not None and region_mask[py, px] < 0.5:
                    continue
                local_wet = float(self.wetness[py, px])
                grain = 1.0 + 0.08 * math.sin(idx * 2.3)   # cloth weave oscillation
                eff = strength * grain * (0.20 + local_wet * 0.80)
                r_int = max(1, int(sigma))
                y0 = max(0,      py - r_int); y1 = min(self.h, py + r_int + 1)
                x0 = max(0,      px - r_int); x1 = min(self.w, px + r_int + 1)
                ys, xs = np.mgrid[y0:y1, x0:x1]
                w2d = np.exp(-((ys-py)**2 + (xs-px)**2)/(2*sigma**2))[..., np.newaxis] * eff
                rgb[y0:y1, x0:x1] = np.clip(
                    rgb[y0:y1, x0:x1] * (1 - w2d) + spread[y0:y1, x0:x1] * w2d,
                    0.0, 1.0)
        else:  # wipe
            # Lift toward a lighter ground estimate.
            # Approximate the "ground" as a mildly brightened and desaturated local average.
            ground = gaussian_filter(rgb, sigma=[sigma * 2, sigma * 2, 0])
            ground = np.clip(ground * 1.18, 0.0, 1.0)   # wipe reveals a lighter layer
            for pt in pts_s[::max(1, len(pts_s)//20)]:
                px, py = int(pt[0]), int(pt[1])
                if not (0 <= px < self.w and 0 <= py < self.h):
                    continue
                if region_mask is not None and region_mask[py, px] < 0.5:
                    continue
                local_wet = float(self.wetness[py, px])
                eff = strength * (0.10 + local_wet * 0.90)  # wipe much weaker on dry paint
                r_int = max(1, int(sigma))
                y0 = max(0,      py - r_int); y1 = min(self.h, py + r_int + 1)
                x0 = max(0,      px - r_int); x1 = min(self.w, px + r_int + 1)
                ys, xs = np.mgrid[y0:y1, x0:x1]
                w2d = np.exp(-((ys-py)**2 + (xs-px)**2)/(2*sigma**2))[..., np.newaxis] * eff
                rgb[y0:y1, x0:x1] = np.clip(
                    rgb[y0:y1, x0:x1] * (1 - w2d) + ground[y0:y1, x0:x1] * w2d,
                    0.0, 1.0)

        out = arr.copy()
        out[:, :, 0] = np.clip(rgb[:, :, 2] * 255, 0, 255).astype(np.uint8)
        out[:, :, 1] = np.clip(rgb[:, :, 1] * 255, 0, 255).astype(np.uint8)
        out[:, :, 2] = np.clip(rgb[:, :, 0] * 255, 0, 255).astype(np.uint8)
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(out.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.ctx.set_source_surface(tmp, 0, 0)
        self.ctx.paint()

    def sponge_stamp(self,
                     pts:          List[Tuple],
                     color:        Color,
                     width:        float = 24.0,
                     opacity:      float = 0.55,
                     cell_density: float = 0.50,
                     wet_blend:    float = 0.18,
                     jitter_amt:   float = 0.05,
                     rng=None,
                     region_mask:  Optional[np.ndarray] = None):
        """
        Sponge — stamp irregular cellular texture along a path (deposit).

        A Voronoi-cell mask gives each stamp naturally porous, organic edges.
        Consecutive stamps are rotated and scaled slightly to prevent visible
        tiling.

        Usage guidance
        --------------
        - Use for foliage masses, clouds, rough stone, porous or mossy surfaces.
        - Do NOT use for smooth surfaces, skin, or any area needing directional
          structure.
        - Best applied in two passes: a lighter first pass for colour, a slightly
          heavier second pass for density.
        - Sponge followed by a dry-brush stroke over the top is effective for
          foliage that still reads as painterly rather than stamped.

        Parameters
        ----------
        pts          : Stamp positions along path (stamps placed at intervals).
        color        : Base paint colour for the stamps.
        width        : Stamp diameter in pixels.
        opacity      : Peak opacity at stamp centre.
        cell_density : [0, 1] — 0 = large open holes (sea sponge);
                       1 = fine dense texture (foam sponge).
        wet_blend    : Blend fraction with underlying wet paint.
        """
        if len(pts) < 1:
            return
        rng_ = rng or self._rng_for_stamps

        pts_s = catmull_rom(pts, steps=3) if len(pts) > 1 else list(pts)
        stride = max(1, int(width * 0.55))   # spacing between stamps

        for idx, pt in enumerate(pts_s[::stride]):
            px, py = int(pt[0]), int(pt[1])
            if not (0 <= px < self.w and 0 <= py < self.h):
                continue
            if region_mask is not None and region_mask[py, px] < 0.5:
                continue

            # Wet blend at stamp centre.
            canvas_c = self._sample_color(px, py)
            wet_at   = float(self.wetness[py, px])
            paint_c  = mix_paint(color, canvas_c, wet_blend * wet_at)
            paint_c  = jitter(paint_c, jitter_amt, rng_)
            pr, pg, pb = paint_c

            # Build a Voronoi-cell mask in a local patch.
            r_int = max(3, int(width * 0.5))
            patch_sz = r_int * 2 + 1
            n_cells  = max(3, int(cell_density * 18 + 4))
            seed_pts = [(rng_.uniform(0, patch_sz), rng_.uniform(0, patch_sz))
                        for _ in range(n_cells)]

            ys_loc, xs_loc = np.mgrid[0:patch_sz, 0:patch_sz]
            # Distance to nearest Voronoi seed.
            dists = np.stack([
                np.hypot(xs_loc - sx, ys_loc - sy) for sx, sy in seed_pts
            ], axis=0)
            nearest = dists.min(axis=0)
            second  = np.sort(dists, axis=0)[1]
            # Voronoi edge = where distance to nearest ≈ distance to second-nearest.
            edge_dist = second - nearest
            # Mask: high alpha AWAY from cell edges (cells fill, edges are holes).
            cell_mask = np.clip(edge_dist / (width * 0.12 + 1e-6), 0.0, 1.0)
            # Radial falloff so stamp fades at its boundary.
            cy_loc, cx_loc = r_int, r_int
            radial = np.clip(
                1.0 - np.hypot(xs_loc - cx_loc, ys_loc - cy_loc) / (r_int + 1e-6),
                0.0, 1.0)
            alpha_mask = (cell_mask * radial * opacity).astype(np.float32)

            # Paint each pixel in the patch.
            y0 = max(0,      py - r_int); y1 = min(self.h, py + r_int + 1)
            x0 = max(0,      px - r_int); x1 = min(self.w, px + r_int + 1)
            ly0 = y0 - (py - r_int); ly1 = ly0 + (y1 - y0)
            lx0 = x0 - (px - r_int); lx1 = lx0 + (x1 - x0)

            a_slice = alpha_mask[ly0:ly1, lx0:lx1]
            if a_slice.max() < 0.02:
                continue

            # Render as a semi-transparent ARGB patch.
            patch_rgba = np.zeros((y1-y0, x1-x0, 4), dtype=np.uint8)
            patch_rgba[:, :, 0] = np.clip(pb * 255, 0, 255)
            patch_rgba[:, :, 1] = np.clip(pg * 255, 0, 255)
            patch_rgba[:, :, 2] = np.clip(pr * 255, 0, 255)
            patch_rgba[:, :, 3] = np.clip(a_slice * 255, 0, 255).astype(np.uint8)

            tmp_surf = cairo.ImageSurface.create_for_data(
                bytearray(patch_rgba.tobytes()),
                cairo.FORMAT_ARGB32, x1-x0, y1-y0)
            self.ctx.set_source_surface(tmp_surf, x0, y0)
            self.ctx.paint()

            # Wetness update.
            self.wetness[y0:y1, x0:x1] = np.minimum(
                1.0, self.wetness[y0:y1, x0:x1] + 0.20 * a_slice)

    @property
    def _rng_for_stamps(self):
        """Fallback RNG for tools that aren't passed an explicit rng."""
        if not hasattr(self, '_default_rng'):
            self._default_rng = random.Random(42)
        return self._default_rng

    def spatter(self,
                origin:      Tuple[float, float],
                color:       Color,
                angle:       float = 0.0,
                spread:      float = 0.40,
                reach:       float = 80.0,
                dot_size:    float = 2.5,
                dot_count:   int   = 60,
                opacity:     float = 0.75,
                jitter_amt:  float = 0.06,
                wet_blend:   float = 0.08,
                rng=None,
                region_mask: Optional[np.ndarray] = None):
        """
        Spatter — Poisson-distributed paint dots fired from an origin point.

        Models a toothbrush or stiff brush flicked toward the canvas.  Dots are
        Poisson-spaced within a directional cone so they never clump.  Size
        grows slightly with distance from the source (coarser spread at reach).

        Usage guidance
        --------------
        - Use as a *texture accent*, not a primary mark.  Spatter reads as
          natural randomness; overuse reads as chaos.
        - Apply over dry or near-dry paint only — wet paint causes dots to bleed
          into each other, losing the characteristic distinct drop texture.
        - `dot_count` should be low enough that individual dots are visible at
          normal viewing distance; 30–80 is a typical range.
        - Good uses: soil, rock texture, foliage edge texture, water droplets,
          sand, splashed colour accents.

        Parameters
        ----------
        origin     : (x, y) source point.
        color      : Base paint colour.
        angle      : Direction of spray in radians (0 = right).
        spread     : Half-angle of the cone in radians (π = full hemisphere).
        reach      : Maximum travel distance in pixels.
        dot_size   : Base dot radius in pixels; actual size varies ± 40%.
        dot_count  : Total number of dots to attempt.
        opacity    : Per-dot alpha at full reach; closer dots are stronger.
        wet_blend  : Blend fraction with underlying wet paint.
        """
        rng_ = rng or self._rng_for_stamps
        ox, oy = origin

        # Poisson-disk sampling in the cone.
        min_sep = dot_size * 2.2
        placed: List[Tuple[float, float]] = []

        attempts = 0
        while len(placed) < dot_count and attempts < dot_count * 20:
            attempts += 1
            # Random polar coords in the cone.
            r   = rng_.uniform(reach * 0.05, reach)
            phi = rng_.uniform(angle - spread, angle + spread)
            cx  = ox + math.cos(phi) * r
            cy  = oy + math.sin(phi) * r

            if not (0 <= cx < self.w and 0 <= cy < self.h):
                continue
            if region_mask is not None:
                ix, iy = int(cx), int(cy)
                if region_mask[max(0,min(self.h-1,iy)), max(0,min(self.w-1,ix))] < 0.5:
                    continue

            # Poisson spacing check.
            too_close = any(math.hypot(cx-px, cy-py) < min_sep for px, py in placed)
            if too_close:
                continue

            placed.append((cx, cy))

            # Dot properties.
            dist_frac = r / max(reach, 1.0)
            dot_r   = dot_size * rng_.uniform(0.6, 1.4) * (0.7 + dist_frac * 0.6)
            dot_r   = max(0.5, dot_r)
            dot_a   = opacity * (1.0 - dist_frac * 0.45) * rng_.uniform(0.7, 1.0)
            if dot_a < 0.05:
                continue

            # Wet blend at dot centre.
            canvas_c = self._sample_color(int(cx), int(cy))
            wet_at   = float(self.wetness[max(0, min(self.h-1, int(cy))),
                                          max(0, min(self.w-1, int(cx)))])
            paint_c  = mix_paint(color, canvas_c, wet_blend * wet_at)
            paint_c  = jitter(paint_c, jitter_amt, rng_)

            self.ctx.arc(cx, cy, dot_r, 0, 2 * math.pi)
            self.ctx.set_source_rgba(*paint_c, dot_a)
            self.ctx.fill()

    def sgraffito(self,
                  pts:           List[Tuple],
                  scratch_depth: float = 0.70,
                  width:         float = 1.2,
                  region_mask:   Optional[np.ndarray] = None):
        """
        Sgraffito — scratch through wet paint to reveal the layer beneath.

        Draws a hard-edged line that reduces local paint opacity, exposing the
        colour of whatever was painted earlier.  On a linen-toned ground this
        typically produces a warm ochre or grey-green highlight.

        Usage guidance
        --------------
        - Use for bright highlights scratched into dark wet passages: specular
          light on water, windows in a night scene, grasses in a dark foreground.
        - Use for fine linear texture: branches against sky, fur direction marks,
          hair highlight lines.
        - Finishing technique only — apply at the very end of a pass.
        - Use sparingly: 3–5 scratches per passage maximum.  More becomes
          decorative rather than structural.
        - Only effective on wet or semi-wet paint.  On fully dry paint the
          scratch has no visible effect (models real physics).
        - ``scratch_depth`` 0.3–0.5 gives subtle texture; 0.7–1.0 gives a
          clear bright line.

        Parameters
        ----------
        pts           : Path of the scratch.
        scratch_depth : [0, 1] — 0 = slight lightening; 1 = full reveal to
                        ground (near-transparent).
        width         : Scratch line width in pixels.  Keep narrow (0.8–2.5).
        """
        if len(pts) < 2 or scratch_depth < 0.01:
            return

        pts_s = catmull_rom(pts, steps=6)

        # Sgraffito blends toward a transparent/ground state.
        # We achieve this by painting the scratch line with a
        # "destination-out" composite over a copy of the pre-scratch surface,
        # then re-compositing at reduced opacity.
        # Simpler approach: paint with the per-pixel canvas colour sampled at
        # the scratch, brightened slightly (the layer beneath).
        for i in range(len(pts_s) - 1):
            seg_cx = int((pts_s[i][0] + pts_s[i+1][0]) * 0.5)
            seg_cy = int((pts_s[i][1] + pts_s[i+1][1]) * 0.5)
            seg_cx = max(0, min(self.w-1, seg_cx))
            seg_cy = max(0, min(self.h-1, seg_cy))

            if region_mask is not None and region_mask[seg_cy, seg_cx] < 0.5:
                continue

            # Scale effect with wetness at that point.
            local_wet = float(self.wetness[seg_cy, seg_cx])
            eff_alpha = scratch_depth * (0.15 + local_wet * 0.85)

            # Reveal colour: sample what is painted and push toward the ground.
            # We approximate the ground as a desaturated, lightened version of
            # the current colour (since the actual ground may be buried).
            cur = self._sample_color(seg_cx, seg_cy)
            reveal = tuple(min(1.0, c * 0.55 + 0.45) for c in cur)

            self.ctx.move_to(*pts_s[i])
            self.ctx.line_to(*pts_s[i+1])
            self.ctx.set_line_width(width)
            self.ctx.set_line_cap(cairo.LINE_CAP_ROUND)
            self.ctx.set_source_rgba(*reveal, eff_alpha)
            self.ctx.stroke()

    def comb_drag(self,
                  pts:          List[Tuple],
                  width:        float = 30.0,
                  tine_count:   int   = 8,
                  tine_spacing: float = 0.0,
                  groove_depth: float = 0.55,
                  region_mask:  Optional[np.ndarray] = None):
        """
        Comb / texture drag — draw a rigid comb through wet paint.

        Produces parallel grooves running along the drag direction.  Each groove
        partially exposes the layer beneath by rendering a thin dark-then-light
        alternation.  Classic uses: wood grain, hair masses, calm water
        reflections, grass fields.

        Usage guidance
        --------------
        - Drag in one consistent direction per passage.  Crossing directions
          produces a crosshatch that reads as fabric or woven texture rather
          than organic grain — only use that intentionally.
        - Works only on wet paint; apply immediately after a brush or knife pass.
        - Coarse combs (wide tine_spacing) for large structural features (planks,
          coarse hair); fine combs (tight spacing) for hair, fur, grass.
        - Do NOT comb over impasto knife marks — the tines skip over the raised
          texture and the effect is lost.

        Parameters
        ----------
        pts          : Centre-line of the drag path.
        width        : Total comb width in pixels.
        tine_count   : Number of tines (grooves).  4–16 is typical.
        tine_spacing : Override spacing between tine centres in pixels.
                       0 = auto-derive from width / tine_count.
        groove_depth : [0, 1] how strongly each groove darkens then lightens.
        """
        if len(pts) < 2 or groove_depth < 0.01:
            return

        pts_s = catmull_rom(pts, steps=5)
        spacing = tine_spacing if tine_spacing > 0 else width / max(tine_count, 1)

        half_w = width * 0.5
        offsets = [
            -half_w + spacing * (i + 0.5)
            for i in range(tine_count)
        ]

        n = len(pts_s)
        for lat in offsets:
            # Build tine path (parallel offset from centre-line).
            tine_pts = []
            for i in range(n):
                if i == 0:
                    dx, dy = pts_s[1][0]-pts_s[0][0], pts_s[1][1]-pts_s[0][1]
                elif i == n-1:
                    dx, dy = pts_s[-1][0]-pts_s[-2][0], pts_s[-1][1]-pts_s[-2][1]
                else:
                    dx, dy = pts_s[i+1][0]-pts_s[i-1][0], pts_s[i+1][1]-pts_s[i-1][1]
                mag = math.hypot(dx, dy) or 1e-6
                px_, py_ = -dy/mag, dx/mag
                tine_pts.append((pts_s[i][0] + px_*lat, pts_s[i][1] + py_*lat))

            for i in range(len(tine_pts) - 1):
                seg_cx = int((tine_pts[i][0] + tine_pts[i+1][0]) * 0.5)
                seg_cy = int((tine_pts[i][1] + tine_pts[i+1][1]) * 0.5)
                seg_cx = max(0, min(self.w-1, seg_cx))
                seg_cy = max(0, min(self.h-1, seg_cy))

                if region_mask is not None and region_mask[seg_cy, seg_cx] < 0.5:
                    continue

                local_wet = float(self.wetness[seg_cy, seg_cx])
                eff = groove_depth * (0.10 + local_wet * 0.90)

                cur = self._sample_color(seg_cx, seg_cy)

                # Dark pass (groove displaces paint inward → darker).
                dark_col = tuple(max(0.0, c * (1.0 - eff * 0.6)) for c in cur)
                self.ctx.move_to(*tine_pts[i])
                self.ctx.line_to(*tine_pts[i+1])
                self.ctx.set_line_width(max(0.8, spacing * 0.30))
                self.ctx.set_line_cap(cairo.LINE_CAP_ROUND)
                self.ctx.set_source_rgba(*dark_col, eff * 0.8)
                self.ctx.stroke()

                # Light pass (paint piles on groove edges → lighter flanks).
                light_col = tuple(min(1.0, c * (1.0 + eff * 0.35)) for c in cur)
                for sign in (-1.0, 1.0):
                    dx = tine_pts[i+1][0] - tine_pts[i][0]
                    dy = tine_pts[i+1][1] - tine_pts[i][1]
                    mag = math.hypot(dx, dy) or 1e-6
                    off = sign * spacing * 0.28
                    px_, py_ = -dy/mag * off, dx/mag * off
                    self.ctx.move_to(tine_pts[i][0]+px_,   tine_pts[i][1]+py_)
                    self.ctx.line_to(tine_pts[i+1][0]+px_, tine_pts[i+1][1]+py_)
                    self.ctx.set_line_width(max(0.5, spacing * 0.18))
                    self.ctx.set_source_rgba(*light_col, eff * 0.45)
                    self.ctx.stroke()

    # ── Post-processing ───────────────────────────────────────────────────────

    def dry(self, amount: float = 0.55):
        """
        Simulate paint drying between layers.

        Reduces both wetness and thickness.  Wetness drops quickly (paint
        surface dries); thickness decays much more slowly (the physical paint
        body settles but does not disappear).

        Parameters
        ----------
        amount : [0, 1] drying fraction.  0.55 = typical between-pass dry.
                 0.90 = near-complete dry (underpainting stage).
                 1.00 = fully dry (no wet-on-wet blending in next pass).
        """
        self.wetness *= (1.0 - amount)
        # Thickness decays at 20 % of the wetness rate — impasto marks retain
        # their physical relief long after the surface dries.
        self.thickness_map *= (1.0 - amount * 0.20)

    # ── Phase 4 — Watercolour physics ─────────────────────────────────────────

    def diffuse_wet(self, passes: int = 1, strength: float = 0.50):
        """
        Bleed wet paint outward — watercolour wet-into-wet diffusion.

        Simulates water carrying pigment across wet regions.  Very wet areas
        receive a wider diffusion radius; barely-wet areas barely bleed.

        Call immediately after placing strokes, before granulate() and
        dry_edges().

        Usage guidance
        --------------
        - One pass at strength 0.35–0.55 gives natural soft-edged washes.
        - Two passes at strength 0.60+ give the heavy bloom of wet-on-wet.
        - Do NOT call on a dry canvas — wetness gates the effect completely.
        - Not needed for oil painting; oil does not bleed this way.

        Parameters
        ----------
        passes   : Number of diffusion sweeps.  1 = subtle; 2 = heavy bloom.
        strength : [0, 1] blend fraction toward the diffused result per pass.
        """
        if self.wetness.max() < 0.10:
            return

        from scipy.ndimage import gaussian_filter

        buf = np.frombuffer(self.surface.get_data(), dtype=np.uint8).copy()
        arr = buf.reshape(self.h, self.w, 4)
        rgb = arr[:, :, [2, 1, 0]].astype(np.float32) / 255.0

        for _ in range(passes):
            # Multi-scale diffusion: very wet → wide blur, barely wet → fine blur.
            # Three wetness bands drive three Gaussian radii.
            for threshold, sigma in [(0.70, 3.5), (0.40, 2.0), (0.15, 1.0)]:
                mask = np.clip(
                    (self.wetness - threshold) / (1.0 - threshold + 1e-6),
                    0.0, 1.0,
                )
                if mask.max() < 0.01:
                    continue
                blurred = gaussian_filter(rgb, sigma=[sigma, sigma, 0])
                m3d     = (mask * strength)[..., np.newaxis]
                rgb     = rgb * (1.0 - m3d) + blurred * m3d

        out = arr.copy()
        out[:, :, 0] = np.clip(rgb[:, :, 2] * 255, 0, 255).astype(np.uint8)
        out[:, :, 1] = np.clip(rgb[:, :, 1] * 255, 0, 255).astype(np.uint8)
        out[:, :, 2] = np.clip(rgb[:, :, 0] * 255, 0, 255).astype(np.uint8)
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(out.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.ctx.set_source_surface(tmp, 0, 0)
        self.ctx.paint()

    def dry_edges(self, darkening: float = 0.88, edge_width: int = 2):
        """
        Concentrate pigment at the boundary of drying wet regions.

        As watercolour dries, receding water carries dissolved pigment to the
        drying front, depositing a darker, crisper ring — the characteristic
        hard edge (cauliflower / bloom / backrun).

        Call just before dry() so the effect is applied while paint is still
        wet.  The darkening is modulated by local wetness: pixels that are
        barely wet produce a faint edge; very wet pixels produce the full ring.

        Usage guidance
        --------------
        - darkening 0.85–0.92 is natural (8–15 % darker at the edge).
        - edge_width 1–2 for fine-grained paper; 3–4 for large washes.
        - Call once per drying cycle.  Repeated calls stack and over-darken.
        - Not needed for oil painting.

        Parameters
        ----------
        darkening  : Multiplier for edge pixels — 1.0 = no effect, 0.80 = strong.
        edge_width : Pixel width of the darkened ring.
        """
        from scipy.ndimage import binary_dilation, binary_erosion

        wet_mask = self.wetness > 0.25
        if not wet_mask.any():
            return

        struct  = np.ones((3, 3), dtype=bool)
        dilated = binary_dilation(wet_mask, structure=struct,
                                  iterations=edge_width)
        eroded  = binary_erosion(wet_mask, structure=struct,
                                 iterations=max(1, edge_width - 1))
        # Edge band: the ring just outside (or just inside) the wet boundary.
        edge    = (dilated & ~eroded).astype(np.float32)

        # Weight by local wetness so the effect is strongest where wetter.
        edge   *= np.clip(self.wetness, 0.0, 1.0)

        if edge.max() < 0.01:
            return

        buf = np.frombuffer(self.surface.get_data(), dtype=np.uint8).copy()
        arr = buf.reshape(self.h, self.w, 4).astype(np.float32)

        dark_factor = 1.0 - edge * (1.0 - darkening)
        arr[:, :, 0] = np.clip(arr[:, :, 0] * dark_factor, 0, 255)
        arr[:, :, 1] = np.clip(arr[:, :, 1] * dark_factor, 0, 255)
        arr[:, :, 2] = np.clip(arr[:, :, 2] * dark_factor, 0, 255)

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(arr.astype(np.uint8).tobytes()),
            cairo.FORMAT_ARGB32, self.w, self.h)
        self.ctx.set_source_surface(tmp, 0, 0)
        self.ctx.paint()

    def granulate(self, strength: float = 0.22, pigment_weight: float = 1.0):
        """
        Simulate pigment granulation into paper / canvas texture.

        Paper valleys accumulate pigment (darker, denser where the texture
        dips); surface peaks resist the wash (slightly lighter where the
        texture rises).  Effect is gated by local wetness — dry areas do not
        granulate because the water that carries pigment is gone.

        Naturally more visible on cold-press watercolour paper (deeper tooth)
        than on linen canvas, but both surfaces produce the effect at scale.

        Usage guidance
        --------------
        - strength 0.15–0.25 is natural; above 0.40 reads as exaggerated.
        - Call after diffuse_wet() so bleeding has already spread the pigment
          before it settles into the texture.
        - Earth pigments (raw umber, burnt sienna, ultramarine) granulate more
          strongly in real life.  Use pigment_weight 1.2–1.5 for those hues
          and 0.6–0.8 for synthetic pigments (cadmium, phthalo).
        - Not needed for oil painting; oil pigment does not granulate.

        Parameters
        ----------
        strength       : [0, 1] maximum darkening / lightening amplitude.
        pigment_weight : Multiplier for the effect — use to differentiate
                         granulating pigments (> 1) from smooth ones (< 1).
        """
        if self.wetness.max() < 0.10 or strength < 0.01:
            return

        # Normalise texture to [-1, 1] centred at its midpoint.
        t_min, t_max = float(self.texture.min()), float(self.texture.max())
        mid      = (t_min + t_max) * 0.5
        t_range  = (t_max - t_min) * 0.5 + 1e-6
        tex_norm = (self.texture - mid) / t_range   # -1 (valley) to +1 (peak)

        # Valleys darken (pigment pools); peaks lighten slightly (pigment skims).
        valley_dark = np.clip(-tex_norm, 0.0, 1.0) * strength * pigment_weight
        peak_light  = np.clip( tex_norm, 0.0, 1.0) * strength * 0.45 * pigment_weight

        wet_w      = np.clip(self.wetness, 0.0, 1.0)
        modulation = 1.0 - valley_dark * wet_w + peak_light * wet_w

        buf = np.frombuffer(self.surface.get_data(), dtype=np.uint8).copy()
        arr = buf.reshape(self.h, self.w, 4).astype(np.float32)

        arr[:, :, 0] = np.clip(arr[:, :, 0] * modulation, 0, 255)
        arr[:, :, 1] = np.clip(arr[:, :, 1] * modulation, 0, 255)
        arr[:, :, 2] = np.clip(arr[:, :, 2] * modulation, 0, 255)

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(arr.astype(np.uint8).tobytes()),
            cairo.FORMAT_ARGB32, self.w, self.h)
        self.ctx.set_source_surface(tmp, 0, 0)
        self.ctx.paint()

    def watercolor_dry(self,
                       amount:             float = 0.55,
                       diffuse_strength:   float = 0.40,
                       diffuse_passes:     int   = 1,
                       granulate_strength: float = 0.22,
                       pigment_weight:     float = 1.0,
                       edge_darkening:     float = 0.88,
                       edge_width:         int   = 2):
        """
        Watercolour drying sequence — one call for physically correct drying.

        Runs diffusion, granulation, and edge concentration in the correct
        physical order, then reduces wetness.  Use in place of dry() for all
        watercolour painting passes.

        Physical sequence
        -----------------
        1. diffuse_wet()  — wet paint bleeds while still fluid
        2. granulate()    — pigment settles into paper texture
        3. dry_edges()    — pigment concentrates at the receding drying front
        4. dry()          — wetness reduced

        Usage guidance
        --------------
        - For a light first wash: diffuse_strength=0.30, granulate_strength=0.15,
          edge_darkening=0.92 (subtle bleed, faint granulation, light edge).
        - For a heavy wet-on-wet bloom: diffuse_strength=0.60, diffuse_passes=2,
          granulate_strength=0.25, edge_darkening=0.84 (heavy bleed, strong ring).
        - amount matches dry() — 0.55 typical, 0.90 near-complete.
        - Do NOT use for oil painting passes; use dry() instead.

        Parameters
        ----------
        amount             : Drying fraction passed to dry() [0, 1].
        diffuse_strength   : Bleeding intensity [0, 1].
        diffuse_passes     : Diffusion sweep count.  1–2.
        granulate_strength : Texture granulation depth [0, 1].
        pigment_weight     : Granulation multiplier (earth pigments > 1).
        edge_darkening     : Pigment ring darkness multiplier (0.80–0.95).
        edge_width         : Pixel width of the darkened edge band.
        """
        self.diffuse_wet(passes=diffuse_passes, strength=diffuse_strength)
        self.granulate(strength=granulate_strength, pigment_weight=pigment_weight)
        self.dry_edges(darkening=edge_darkening, edge_width=edge_width)
        self.dry(amount)

    def glaze(self, color: Color, opacity: float = 0.10):
        """Transparent colour wash over entire canvas (final warmth / tone)."""
        self.ctx.rectangle(0, 0, self.w, self.h)
        self.ctx.set_source_rgba(*color, opacity)
        self.ctx.fill()

    def vignette(self, strength: float = 0.55):
        grad = cairo.RadialGradient(
            self.w/2, self.h/2, min(self.w, self.h) * 0.30,
            self.w/2, self.h/2, max(self.w, self.h) * 0.78)
        grad.add_color_stop_rgba(0, 0, 0, 0, 0)
        grad.add_color_stop_rgba(1, 0, 0, 0, strength)
        self.ctx.rectangle(0, 0, self.w, self.h)
        self.ctx.set_source(grad)
        self.ctx.fill()

    def crackle(self, density: float = 0.028):
        """
        Simulate aged varnish crackle — a fine dark network across the surface.
        Adds enormous period authenticity.
        """
        buf = np.frombuffer(self.surface.get_data(), dtype=np.uint8).reshape(
            self.h, self.w, 4).copy()

        for y in range(0, self.h, 3):
            for x in range(0, self.w, 3):
                n = abs(pnoise2(x / 12.0, y / 12.0, octaves=5))
                if n > 0.44:
                    fade = min(1.0, (n - 0.44) / 0.06) * density
                    buf[y, x, :3] = np.clip(
                        buf[y, x, :3].astype(float) * (1 - fade), 0, 255).astype(np.uint8)

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.ctx.set_source_surface(tmp, 0, 0)
        self.ctx.paint()

    # ── Output ────────────────────────────────────────────────────────────────

    def to_pil(self) -> Image.Image:
        buf  = self.surface.get_data()
        arr  = np.frombuffer(buf, dtype=np.uint8).reshape(self.h, self.w, 4).copy()
        rgb  = arr[:, :, [2, 1, 0]]          # BGRA → RGB
        return Image.fromarray(rgb, "RGB")

    def save(self, path: str):
        self.to_pil().save(path)
        print(f"  Saved: {path}")


# ─────────────────────────────────────────────────────────────────────────────
# Flow field — stroke directions from image gradient
# ─────────────────────────────────────────────────────────────────────────────

def flow_field(img_arr: np.ndarray) -> np.ndarray:
    """
    Compute stroke direction angles (radians) from image gradient.
    Strokes run PERPENDICULAR to the gradient so they follow colour contours,
    which is how painters naturally work along the form.
    """
    if img_arr.ndim == 3:
        gray = (0.299 * img_arr[:,:,0] +
                0.587 * img_arr[:,:,1] +
                0.114 * img_arr[:,:,2]).astype(np.float32)
    else:
        gray = img_arr.astype(np.float32)

    # Sobel gradient
    gx = ndimage.sobel(gray, axis=1)
    gy = ndimage.sobel(gray, axis=0)

    # Perpendicular to gradient = follow colour contour
    angles = np.arctan2(gx, -gy)

    # Smooth the field so strokes don't jitter randomly
    angles = ndimage.gaussian_filter(angles, sigma=4.0)
    return angles


# ─────────────────────────────────────────────────────────────────────────────
# Region mask helpers
# ─────────────────────────────────────────────────────────────────────────────

def ellipse_mask(w: int, h: int,
                 cx: float, cy: float,
                 rx: float, ry: float,
                 feather: float = 0.25) -> np.ndarray:
    """
    Soft elliptical mask.  Values are 1 inside, fall to 0 at the feathered edge.
    cx, cy, rx, ry are in pixels.  feather: fraction of radius for soft edge.
    """
    ys, xs = np.mgrid[0:h, 0:w]
    d = np.sqrt(((xs - cx) / (rx + 1e-6))**2 + ((ys - cy) / (ry + 1e-6))**2)
    inner = 1.0 - feather
    mask  = np.clip((1.0 - d) / feather, 0.0, 1.0)
    mask  = np.where(d < inner, 1.0, mask)
    return mask.astype(np.float32)


def spherical_flow(w: int, h: int,
                   cx: float, cy: float,
                   rx: float, ry: float) -> np.ndarray:
    """
    Flow field whose strokes follow the surface of a sphere centred at (cx, cy).
    Strokes are tangent to latitude circles — they curve around the face
    rather than following colour edges.

    This is what painters do: on a face they work 'around' the form,
    not in arbitrary directions dictated by the flat image.
    """
    ys, xs = np.mgrid[0:h, 0:w]
    # Normalised vector from centre
    dx = (xs - cx) / (rx + 1e-6)
    dy = (ys - cy) / (ry + 1e-6)
    # Tangent = perpendicular to radial = rotate 90°
    # At top of sphere: strokes go horizontal.
    # At sides: strokes go vertical.
    angles = np.arctan2(dx, -dy)          # tangent direction
    # Smooth so there are no discontinuities
    angles = ndimage.gaussian_filter(angles, sigma=6.0)
    return angles.astype(np.float32)


def anatomy_flow_field(w: int, h: int,
                       cx: float, cy: float,
                       rx: float, ry: float,
                       gradient_fallback: Optional[np.ndarray] = None) -> np.ndarray:
    """
    Anatomy-aware stroke flow field for portrait faces.

    Unlike ``spherical_flow()`` which treats the face as a featureless sphere,
    this field encodes the **major anatomical planes** that trained portrait
    painters follow instinctively when building form:

      ┌─────────────────────────────────────────────────────────────────┐
      │  Forehead (ny < -0.45)                                          │
      │    → Near-horizontal strokes with a gentle outward spread.      │
      │      The forehead is a broad, near-flat plane; painters run      │
      │      strokes across it rather than up-down.                     │
      │  Brow ridge / upper cheek (ny ∈ [-0.45, -0.10])                │
      │    → Diagonal strokes curving outward from the nose bridge,      │
      │      following the supraorbital arc and zygoma.                 │
      │  Eye socket zone (|nx| < 0.55, ny ∈ [-0.35, 0.10])            │
      │    → Orbital circle tangent — strokes orbit the eye socket.     │
      │  Nose bridge / axis (|nx| < 0.22, ny ∈ [-0.15, 0.55])         │
      │    → Near-vertical strokes running down the nasal planes.        │
      │  Cheeks (|nx| > 0.25, ny ∈ [-0.10, 0.50])                     │
      │    → Diagonal strokes following the cheekbone toward the jaw.   │
      │  Philtrum / upper lip (ny ∈ [0.30, 0.60])                     │
      │    → Near-horizontal strokes, slightly converging at centre.    │
      │  Chin / mandible (ny > 0.55)                                   │
      │    → Downward-curving strokes following jaw contour outward.    │
      └─────────────────────────────────────────────────────────────────┘

    Parameters
    ----------
    w, h              : canvas dimensions.
    cx, cy            : face centre pixel coordinates.
    rx, ry            : face ellipse radii in pixels.
    gradient_fallback : optional pre-computed ``flow_field()`` array.
                        Used to blend in a gradient-driven direction for
                        pixels outside the face ellipse (d > 1.4).

    Returns
    -------
    (H, W) float32 ndarray of stroke angles in radians.
    """
    ys, xs = np.mgrid[0:h, 0:w]

    # Normalised face-relative coordinates in [-1, 1] space.
    nx = (xs - cx) / (rx + 1e-6)          # -1 = left ear, +1 = right ear
    ny = (ys - cy) / (ry + 1e-6)          # -1 = hairline, +1 = chin
    d  = np.sqrt(nx ** 2 + ny ** 2)       # distance from face centre, norm.

    # ── Zone angles (one per anatomical region) ───────────────────────────────

    # Forehead: near-horizontal, slight upward bow at centre, outward spread.
    ang_forehead = np.arctan2(nx * 0.18, np.ones_like(nx))

    # Brow / upper cheek: supraorbital arc; diagonal following cheekbone slope.
    ang_brow = np.arctan2(nx * 0.6, -np.ones_like(nx) * 0.3)

    # Eye socket orbit: strokes circle the socket like latitude lines on a small
    # sphere.  Tangent to the orbital ring = (-dy_orbit, dx_orbit) where
    # the orbit centre is at (0, -0.20) in normalised space.
    orb_dx = nx
    orb_dy = ny + 0.20
    ang_orbit = np.arctan2(orb_dx, -orb_dy)

    # Nose axis: near-vertical, slight inward lean toward centre line.
    ang_nose = np.arctan2(nx * 0.10, np.ones_like(nx) * 0.9)

    # Cheeks: diagonal toward jaw; steepens further from centre.
    ang_cheek = np.arctan2(
        np.sign(nx) * 0.55 + nx * 0.35,
        np.ones_like(ny) * 0.7 + ny * 0.20,
    )

    # Philtrum / lip: horizontal strokes with gentle convergence at midline.
    ang_lip = np.arctan2(nx * (-0.12), np.ones_like(nx))

    # Chin / mandible: downward-curving strokes that fan outward from the chin.
    ang_chin = np.arctan2(
        np.sign(nx) * 0.40 + nx * 0.30,
        np.ones_like(ny) * 0.85,
    )

    # ── Blend weights per zone (smooth, overlapping) ──────────────────────────

    def smooth_step(a: float, b: float, arr: np.ndarray) -> np.ndarray:
        """Smoothstep ramp 0→1 over the interval [a, b]."""
        t = np.clip((arr - a) / (b - a + 1e-9), 0.0, 1.0).astype(np.float32)
        return t * t * (3 - 2 * t)

    # ny-based zone weights (vertical anatomy)
    w_forehead = smooth_step(-0.55, -0.30, -ny)              # top: large weight
    w_brow     = (smooth_step(0.25, 0.55, -ny) *
                  smooth_step(0.35, 0.65, -ny + 0.2))        # upper face
    w_orbit    = (smooth_step(-0.05, 0.25, -ny) *
                  smooth_step(0.35, 0.10, np.abs(nx) - 0.1)) # eye zone (central)
    w_nose     = (smooth_step(-0.20, 0.05, ny) *
                  smooth_step(0.60, 0.25, ny) *
                  smooth_step(0.22, 0.0, np.abs(nx)))         # nose (centre)
    w_cheek    = (smooth_step(0.0, 0.30, ny) *
                  smooth_step(0.60, 0.35, ny) *
                  smooth_step(0.25, 0.55, np.abs(nx)))        # cheeks (sides)
    w_lip      = smooth_step(0.22, 0.45, ny)                  # lower-mid face
    w_chin     = smooth_step(0.50, 0.75, ny)                  # bottom

    # Stack and normalise (each pixel belongs partly to multiple zones).
    total = w_forehead + w_brow + w_orbit + w_nose + w_cheek + w_lip + w_chin + 1e-9

    # Weighted blend of angles using sin/cos to avoid wrap discontinuity.
    def _blend(weights_list, angles_list):
        sin_sum = np.zeros((h, w), dtype=np.float32)
        cos_sum = np.zeros((h, w), dtype=np.float32)
        for ww, aa in zip(weights_list, angles_list):
            sin_sum += ww * np.sin(aa)
            cos_sum += ww * np.cos(aa)
        return np.arctan2(sin_sum, cos_sum)

    blended = _blend(
        [w_forehead, w_brow, w_orbit, w_nose, w_cheek, w_lip, w_chin],
        [ang_forehead, ang_brow, ang_orbit, ang_nose, ang_cheek, ang_lip, ang_chin],
    )
    blended = blended / total  # normalise is implicitly in arctan2 result,
                                # but rescale influences for cleaner output
    blended = _blend(
        [w_forehead, w_brow, w_orbit, w_nose, w_cheek, w_lip, w_chin],
        [ang_forehead, ang_brow, ang_orbit, ang_nose, ang_cheek, ang_lip, ang_chin],
    )

    # ── Blend to fallback outside the face ellipse ────────────────────────────
    if gradient_fallback is not None:
        # Smooth transition: anatomy field fully active inside d < 0.9,
        # fades to gradient fallback between d = 0.9 and d = 1.4.
        inside  = np.clip(1.0 - (d - 0.90) / 0.50, 0.0, 1.0).astype(np.float32)
        outside = 1.0 - inside
        sin_b = inside * np.sin(blended) + outside * np.sin(gradient_fallback)
        cos_b = inside * np.cos(blended) + outside * np.cos(gradient_fallback)
        blended = np.arctan2(sin_b, cos_b).astype(np.float32)

    # Final smooth to remove any numerical noise from the zone blending.
    blended = ndimage.gaussian_filter(blended, sigma=3.5)
    return blended.astype(np.float32)


# ─────────────────────────────────────────────────────────────────────────────
# Painter — high-level layered API
# ─────────────────────────────────────────────────────────────────────────────

class Painter:
    """
    Thinks in painting layers, not geometric shapes.

    Each method corresponds to a real stage in oil painting practice.
    """

    def __init__(self, width: int, height: int, seed: int = 7,
                 edge_treatment: str = "natural_border"):
        """
        Parameters
        ----------
        width, height  : Canvas dimensions in pixels.
        seed           : RNG seed for reproducibility.  Change to generate
                         compositionally different paintings from the same
                         reference.  Use PipelineSpec.seed to drive this from
                         the session level.
        edge_treatment : How to handle canvas edges.

                         "natural_border"  — Ground colour visible at edges;
                           appropriate for plein air studies, academic figure
                           work, and sketches.  Current default behaviour.

                         "full_coverage"   — Dedicated edge pass after each
                           painting stage ensures the entire canvas surface is
                           painted.  Use for finished gallery-ready works.

                         "overpainting"    — Post-pass that targets
                           undersampled edge regions and fills them with
                           outward-biased strokes.  Aggressive — use only
                           when a painting must fill edge-to-edge.
        """
        self.canvas         = PaintCanvas(width, height)
        self.rng            = np.random.default_rng(seed)
        self._rng_py        = random.Random(seed)
        self.w, self.h      = width, height
        self.edge_treatment = edge_treatment
        # Figure mask: (H, W) float32 — 1.0=figure, 0.0=background.
        # Set via set_figure_mask() before painting.
        self._figure_mask: Optional[np.ndarray] = None
        # Normal map: (H, W, 3) float32 in [-1, 1], world-space normals.
        # Set via set_normal_map() before toon passes.
        self._normal_map: Optional[np.ndarray] = None
        # Composition weight map: (H, W) float32 — relative stroke placement bias.
        # Built via _build_composition_map() and stored here so _place_strokes()
        # picks it up automatically without requiring every call site to pass it.
        self._comp_map: Optional[np.ndarray] = None

    # ── Mask management ───────────────────────────────────────────────────────

    def set_figure_mask(self, mask_source):
        """
        Load the figure silhouette mask.

        mask_source — path to a grayscale PNG (white=figure, black=background),
                      a PIL Image, or a (H, W) numpy array.

        Once set, ALL stroke passes automatically constrain themselves to the
        figure region.  Background pixels are sealed first with
        seal_background() before any figure strokes are placed.
        """
        if isinstance(mask_source, str):
            from PIL import Image as _PILImage
            img = _PILImage.open(mask_source).convert("L").resize(
                (self.w, self.h), _PILImage.NEAREST)
            arr = np.array(img, dtype=np.float32) / 255.0
        elif isinstance(mask_source, np.ndarray):
            arr = mask_source.astype(np.float32)
            if arr.max() > 1.0:
                arr /= 255.0
        else:
            arr = np.array(mask_source.convert("L"), dtype=np.float32) / 255.0
        # Hard threshold: 1 = figure, 0 = background
        self._figure_mask = (arr > 0.5).astype(np.float32)

    def set_normal_map(self, source):
        """Load world-normal map (H, W, 3) float32 in [-1, 1] range.

        source — path to the normal PNG written by blender_bridge (encoded as
                 (N+1)/2 → RGB), a PIL Image, or a (H, W, 3) numpy array.

        Decodes the PNG encoding: pixel = (N + 1) / 2  →  N = pixel * 2 - 1.
        Result is stored as self._normal_map with shape (H, W, 3), dtype float32,
        values in [-1, 1], resized to match the painter dimensions.
        """
        if isinstance(source, str):
            from PIL import Image as _PILImage
            img = _PILImage.open(source).convert("RGB").resize(
                (self.w, self.h), _PILImage.BILINEAR)
            arr = np.array(img, dtype=np.float32) / 255.0
        elif isinstance(source, np.ndarray):
            arr = source.astype(np.float32)
            if arr.max() > 1.0:
                arr = arr / 255.0
        else:
            # PIL Image
            img = source.convert("RGB").resize((self.w, self.h))
            arr = np.array(img, dtype=np.float32) / 255.0

        # Decode from [0, 1] encoding to [-1, 1] world normals
        self._normal_map = arr * 2.0 - 1.0

    def set_substrate(self, kind: str = "linen"):
        """
        Replace the canvas texture with the chosen substrate.

        Parameters
        ----------
        kind : str
            "linen"       — woven linen canvas (default; already set at init).
            "cold_press"  — cold-press watercolor paper with laid lines, chain
                            lines, and irregular paper tooth.  Use before the
                            watercolor_wash_pass() to get authentic paper grain
                            showing through untouched highlight areas.

        Why this matters
        ----------------
        The canvas texture modulates every `tone_ground()` call so the physical
        surface "shows through" the paint layer.  Linen weave on a watercolor
        painting looks wrong — the texture grid is too regular and too coarse.
        Cold-press paper has a distinctly different character: random coarse tooth
        plus faint horizontal laid lines from the paper mould wire.  Switching
        substrate before the watercolor passes ensures that the highlight areas
        (where no pigment is placed) display authentic paper surface rather than
        linen.
        """
        w, h = self.w, self.h
        if kind == "cold_press":
            print("  Stretching cold-press watercolor paper…")
            self.canvas.texture = make_cold_press_texture(w, h)
        else:
            print("  Weaving linen texture…")
            self.canvas.texture = make_linen_texture(w, h)

    def toon_contour_mask(self, light_dir, shadow_thresh=0.10, contour_thresh=0.25):
        """Compute toon shading masks from the loaded normal map.

        Parameters
        ----------
        light_dir       : (3,) array-like — world-space light direction (normalised)
        shadow_thresh   : dot(N, L) threshold below which a pixel is in shadow
        contour_thresh  : |dot(N, camera)| threshold for silhouette/contour pixels

        Returns
        -------
        shadow_mask   : (H, W) float32 — 1.0 where dot(N, L) < shadow_thresh
        light_mask    : (H, W) float32 — 1.0 where dot(N, L) >= shadow_thresh
        contour_mask  : (H, W) float32 — 1.0 where |dot(N, camera)| < contour_thresh

        All masks have feathered edges via a small Gaussian blur so stroke
        placement transitions look painted rather than hard-cut.
        """
        if self._normal_map is None:
            h, w = self.h, self.w
            ones  = np.zeros((h, w), dtype=np.float32)
            return ones, np.ones((h, w), dtype=np.float32), ones

        N = self._normal_map  # (H, W, 3)

        # Normalise light direction
        L = np.array(light_dir, dtype=np.float32)
        L_len = np.sqrt((L * L).sum()) + 1e-9
        L = L / L_len

        # Dot product: N · L for each pixel
        NdotL = (N * L[np.newaxis, np.newaxis, :]).sum(axis=2)  # (H, W)

        # Camera direction: in Blender convention the camera looks along -Y.
        # The "camera normal" for contour detection is the view direction (0, -1, 0).
        cam_dir = np.array([0.0, -1.0, 0.0], dtype=np.float32)
        NdotC = np.abs((N * cam_dir[np.newaxis, np.newaxis, :]).sum(axis=2))

        # Binary masks with feathering (Gaussian blur for soft edges)
        shadow_raw   = (NdotL < shadow_thresh).astype(np.float32)
        contour_raw  = (NdotC < contour_thresh).astype(np.float32)

        shadow_mask  = ndimage.gaussian_filter(shadow_raw,  sigma=1.5).astype(np.float32)
        contour_mask = ndimage.gaussian_filter(contour_raw, sigma=1.0).astype(np.float32)
        light_mask   = 1.0 - shadow_mask

        # Clip to [0, 1] after blur
        shadow_mask  = np.clip(shadow_mask,  0.0, 1.0)
        light_mask   = np.clip(light_mask,   0.0, 1.0)
        contour_mask = np.clip(contour_mask, 0.0, 1.0)

        return shadow_mask, light_mask, contour_mask

    def toon_paint(self, reference, light_direction, shadow_color=(0.12, 0.08, 0.04),
                   light_color=(0.92, 0.80, 0.65), ink_color=(0.05, 0.03, 0.02),
                   n_strokes=800, stroke_size=8):
        """Cel-shading paint pass using the loaded normal map.

        Three sub-passes:
          1. Shadow region — flat dark strokes (shadow_color)
          2. Light region  — flat warm strokes (light_color)
          3. Contour lines — thin dark ink strokes (ink_color) along contour dir

        All passes respect self._figure_mask if set.
        Uses BrushTip.FLAT for solid coverage.

        Parameters
        ----------
        reference       : reference image (PIL Image or ndarray, not used for colour
                          — pass for error-map weighting within each region)
        light_direction : (3,) world-space light direction (normalised)
        shadow_color    : fixed RGB tuple for shadow strokes
        light_color     : fixed RGB tuple for lit-area strokes
        ink_color       : fixed RGB tuple for contour strokes
        n_strokes       : total strokes (split ~1/3 shadow, 1/3 light, 1/4 contour)
        stroke_size     : base stroke width in pixels
        """
        print(f"Toon paint pass ({n_strokes} strokes, size={stroke_size}px)…")
        ref = self._prep(reference)

        shadow_mask, light_mask, contour_mask = self.toon_contour_mask(light_direction)

        # Apply figure mask to all region masks
        if self._figure_mask is not None:
            shadow_mask  = shadow_mask  * self._figure_mask
            light_mask   = light_mask   * self._figure_mask
            contour_mask = contour_mask * self._figure_mask

        tip_flat = BrushTip(BrushTip.FLAT)

        # ── Shadow pass ───────────────────────────────────────────────────────
        shadow_n = n_strokes // 3
        if shadow_mask.sum() > 1.0:
            self._place_strokes(
                ref, stroke_size, shadow_n,
                opacity=0.95, wet_blend=0.04, jitter_amt=0.015,
                curvature=0.03, tip=tip_flat,
                stroke_mask=shadow_mask,
                override_color=shadow_color,
            )

        # ── Light pass ────────────────────────────────────────────────────────
        light_n = n_strokes // 3
        if light_mask.sum() > 1.0:
            self._place_strokes(
                ref, stroke_size, light_n,
                opacity=0.90, wet_blend=0.04, jitter_amt=0.015,
                curvature=0.03, tip=tip_flat,
                stroke_mask=light_mask,
                override_color=light_color,
            )

        # ── Contour / ink pass ────────────────────────────────────────────────
        # Thin strokes oriented along the contour (tangent to the silhouette
        # edge), giving the appearance of hand-drawn ink outlines.
        contour_n = n_strokes // 4
        if contour_mask.sum() > 1.0:
            self._place_strokes(
                ref, max(2, stroke_size // 3), contour_n,
                opacity=0.98, wet_blend=0.02, jitter_amt=0.008,
                curvature=0.05, tip=tip_flat,
                stroke_mask=contour_mask,
                override_color=ink_color,
            )

    def seal_background(self, reference):
        """
        Before any figure strokes, lock the background by copying reference
        pixels directly onto the canvas for every non-figure pixel.

        Why: error-driven stroke sampling would otherwise place large strokes
        near the figure/background boundary that carry figure colours into the
        dark background.  Sealing prevents this entirely — the background
        pixels are already 'correct' and carry no painterly error signal.

        Also applies a tiny linen-texture modulation so the background reads
        as painted rather than photographic.
        """
        if self._figure_mask is None:
            return

        print("  Sealing background…")
        ref = Painter._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32)   # 0-255 range

        bg = self._figure_mask < 0.5               # (H, W) bool

        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(self.h, self.w, 4).copy()

        tex = self.canvas.texture                  # (H, W) float32 in ~[0,1]
        strength = 0.06                            # subtle texture modulation
        mod = 1.0 - strength + strength * tex      # e.g. 0.94 … 1.00

        # Write reference colour into background pixels with texture modulation.
        # Cairo uses BGRA byte order.
        buf[bg, 2] = np.clip(rarr[bg, 0] * mod[bg], 0, 255).astype(np.uint8)  # R
        buf[bg, 1] = np.clip(rarr[bg, 1] * mod[bg], 0, 255).astype(np.uint8)  # G
        buf[bg, 0] = np.clip(rarr[bg, 2] * mod[bg], 0, 255).astype(np.uint8)  # B
        buf[bg, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

    def background_pass(self, reference, n_strokes: int = 60,
                        stroke_size: float = 55):
        """
        Optional atmospheric background strokes (placed ONLY in background).

        A small number of large, dark, loosely directional strokes give the
        background painterly texture without contaminating the figure region.
        Painted before any figure strokes.
        """
        if self._figure_mask is None:
            return

        print(f"  Background pass ({n_strokes} strokes  size={stroke_size:.0f}px)…")
        ref   = self._prep(reference)
        bg_mask = 1.0 - self._figure_mask          # (H, W): 1=bg, 0=figure
        self._place_strokes(ref, stroke_size, n_strokes,
                            opacity=0.55, wet_blend=0.08,
                            jitter_amt=0.015, curvature=0.05,
                            tip=BrushTip(BrushTip.FLAT),
                            stroke_mask=bg_mask)

    # ── Layer methods ─────────────────────────────────────────────────────────

    def tone_ground(self, color: Color, texture_strength: float = 0.07):
        """
        Step 1 — Toned ground.
        Eliminates the white canvas; sets the mid-tone temperature.
        Traditionally: raw umber, terre verte, or warm ochre.
        """
        print("Toning ground…")
        self.canvas.tone(color, texture_strength)

    def underpainting(self, reference: Union[np.ndarray, Image.Image],
                      stroke_size: float = 52,
                      n_strokes:   int   = 150,
                      dry_amount:  float = 0.90):
        """
        Step 2 — Dead-colour underpainting.
        Value structure only, desaturated toward raw umber.
        Establishes light/dark composition before colour is introduced.

        dry_amount — canvas.dry() factor before painting.  Higher = faster dry
                     = harder edges between this pass and the next.  Use
                     Painter._drying_curve() to compute from pass position.
        """
        print(f"Underpainting  ({n_strokes} strokes  size={stroke_size:.0f}px)…")
        ref = self._prep(reference)
        gray_ref = self._to_value(ref, warm_tint=(0.42, 0.32, 0.18))
        self.canvas.dry(dry_amount)
        self._place_strokes(gray_ref, stroke_size, n_strokes,
                            opacity=0.60, wet_blend=0.12,
                            jitter_amt=0.02, curvature=0.04,
                            tip=BrushTip(BrushTip.FLAT),
                            stroke_mask=self._figure_mask)

    def block_in(self, reference: Union[np.ndarray, Image.Image],
                 stroke_size: float = 36,
                 n_strokes:   int   = 300,
                 dry_amount:  float = 0.65):
        """
        Step 3 — Block-in.
        Large confident strokes establishing main colour masses.
        Painters work boldly here; no detail yet.

        dry_amount — see underpainting() for description.
        """
        print(f"Blocking in    ({n_strokes} strokes  size={stroke_size:.0f}px)…")
        ref = self._prep(reference)
        self.canvas.dry(dry_amount)
        self._place_strokes(ref, stroke_size, n_strokes,
                            opacity=0.72, wet_blend=0.28,
                            jitter_amt=0.045, curvature=0.07,
                            tip=BrushTip(BrushTip.FILBERT),
                            stroke_mask=self._figure_mask)

    def build_form(self, reference: Union[np.ndarray, Image.Image],
                   stroke_size: float = 15,
                   n_strokes:   int   = 700,
                   dry_amount:  float = 0.55):
        """
        Step 4 — Form building.
        Medium directional strokes that follow surface curvature.
        This is the most labour-intensive stage.
        Stroke direction follows image gradient contours (Hertzmann 1998).

        dry_amount — see underpainting() for description.  Lower values here
                     (0.45–0.60) keep the surface wet so form strokes blend
                     naturally into the block-in layer underneath.
        """
        print(f"Building form  ({n_strokes} strokes  size={stroke_size:.0f}px)…")
        ref = self._prep(reference)
        self.canvas.dry(dry_amount)
        self._place_strokes(ref, stroke_size, n_strokes,
                            opacity=0.78, wet_blend=0.22,
                            jitter_amt=0.038, curvature=0.10,
                            tip=BrushTip(BrushTip.FILBERT),
                            stroke_mask=self._figure_mask,
                            complexity_scale=True)

    def place_lights(self, reference: Union[np.ndarray, Image.Image],
                     stroke_size: float = 6,
                     n_strokes:   int   = 500):
        """
        Step 5 — Lights placed last (impasto highlights).
        Small, opaque, bright strokes concentrated in high-luminance areas.
        In oil painting these are always the FINAL marks — never painted over.
        """
        print(f"Placing lights ({n_strokes} strokes  size={stroke_size:.0f}px)…")
        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        lum  = (0.299*rarr[:,:,0] + 0.587*rarr[:,:,1] + 0.114*rarr[:,:,2])
        # Bias toward VERY bright regions only (impasto highlights on nose tip,
        # forehead, cheekbone).  Power=4.5 (was 2.2) ensures only true specular
        # peaks qualify — moderately-lit hair (~0.4–0.6 lum) gets near-zero weight
        # and won't receive bright white strokes.  Also gate by figure mask.
        weight = np.power(lum, 4.5)
        if self._figure_mask is not None:
            weight *= self._figure_mask
        weight /= weight.sum() + 1e-9

        angles = flow_field(rarr)
        h, w   = ref.shape[:2]

        positions = self.rng.choice(h * w, size=n_strokes,
                                    p=weight.flatten(), replace=True)
        tip = BrushTip(BrushTip.ROUND)

        self.canvas.dry(0.8)
        for pos in positions:
            py, px = int(pos // w), int(pos % w)
            margin = max(4, int(stroke_size * 2))
            px = int(np.clip(px, margin, w - margin))
            py = int(np.clip(py, margin, h - margin))

            col = tuple(float(rarr[py, px, c]) for c in range(3))
            col = tuple(min(1.0, v * 1.18) for v in col)  # impasto: brighter
            col = jitter(col, 0.025, self._rng_py)

            a = float(angles[py, px]) + self._rng_py.uniform(-0.2, 0.2)
            length = stroke_size * self._rng_py.uniform(1.3, 2.4)
            start = (px - math.cos(a)*length*0.5,
                     py - math.sin(a)*length*0.5)
            pts = stroke_path(start, a, length,
                              curve=self._rng_py.uniform(-0.04, 0.04),
                              n=max(3, int(length / 3)))
            ws  = [stroke_size * self._rng_py.uniform(0.7, 1.0)] * len(pts)

            self.canvas.apply_stroke(pts, ws, col, tip,
                                     opacity=0.88, wet_blend=0.08,
                                     jitter_amt=0.02, rng=self._rng_py,
                                     region_mask=self._figure_mask)

    def pointillist_pass(self,
                         reference:       Union[np.ndarray, Image.Image],
                         n_dots:          int   = 6000,
                         dot_size:        float = 4.0,
                         chromatic_split: bool  = True,
                         split_ratio:     float = 0.30,
                         split_radius:    float = 2.5):
        """
        Divisionist dot pass — Seurat / Signac pointillism technique.

        Inspired by Georges Seurat's *A Sunday on La Grande Jatte* (1884–86)
        and the discoveries of Hilma af Klint, who also explored pure-colour
        fields and spiritual resonance in pigment placement.

        Each placement samples the reference colour at that pixel and places a
        small round dot.  When chromatic_split=True an additional tiny dot of
        the **complementary colour** (hue-rotated 180°) is offset by
        split_radius×dot_size pixels.  This mirrors Seurat's use of
        simultaneous contrast (Chevreul's law): adjacent complementary dots
        intensify each other optically in the viewer's eye, creating a
        luminosity impossible with physically mixed paint.

        Parameters
        ----------
        reference       : PIL Image or ndarray reference to sample colour from.
        n_dots          : Total number of primary dots placed.
        dot_size        : Radius of each dot in pixels.
        chromatic_split : Enable the complementary-dot shimmer technique.
        split_ratio     : Opacity of the complementary dot (0–1).
                          0.25–0.40 gives subtle vibration; >0.50 is vivid.
        split_radius    : Offset of complementary dot as a multiple of dot_size.
                          Seurat kept dots very close (~1.5–3 radii apart).

        Notes
        -----
        Unlike the brush-stroke passes this method does NOT use wet-on-wet
        blending (wet_blend is forced to 0.0 per Seurat's dry-on-dry method).
        The canvas should be toned first; any underpainting is visible between
        the sparsely-placed dots, just as the gessoed linen showed through in
        La Grande Jatte.
        """
        print(f"Pointillist pass  ({n_dots} dots  size={dot_size:.1f}px"
              + (" + complement)" if chromatic_split else ")") + "…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        # Error-weighted sampling so dots concentrate where canvas diverges most
        # from the reference (same principle as _place_strokes but adapted for dots).
        cbuf = np.frombuffer(self.canvas.surface.get_data(),
                             dtype=np.uint8).reshape(h, w, 4).copy()
        carr = cbuf[:, :, [2, 1, 0]].astype(np.float32) / 255.0
        err  = np.mean(np.abs(carr - rarr), axis=2).astype(np.float32)
        # Mild smoothing so dot placement isn't hyper-concentrated at single pixels.
        err  = ndimage.gaussian_filter(err, sigma=dot_size * 0.6)

        # Mask to figure only when available; else paint everywhere.
        region = self._figure_mask
        if region is not None:
            err = err * region

        err_flat = err.flatten()
        total    = err_flat.sum()
        if total < 1e-9:
            # Fallback to uniform sampling if canvas already closely matches reference.
            prob = np.ones(h * w, dtype=np.float32) / (h * w)
            if region is not None:
                prob *= region.flatten()
                prob /= prob.sum() + 1e-9
        else:
            prob = err_flat / total

        positions = self.rng.choice(h * w, size=n_dots, p=prob, replace=True)

        tip_round = BrushTip(BrushTip.ROUND, bristle_noise=0.0)
        margin = max(int(dot_size) + 1, 3)

        for pos in positions:
            py, px = int(pos // w), int(pos % w)
            px = int(np.clip(px, margin, w - margin))
            py = int(np.clip(py, margin, h - margin))

            # Sample reference colour at this pixel.
            primary = tuple(float(rarr[py, px, c]) for c in range(3))
            primary = jitter(primary, 0.025, self._rng_py)

            # Place a tiny round dot: two-point stroke (centre → centre + 1px).
            # The degenerate stroke collapses to a circle thanks to round tip caps.
            pts = [(float(px), float(py)), (float(px) + 0.5, float(py))]
            ws  = [dot_size, dot_size]

            self.canvas.apply_stroke(
                pts, ws, primary, tip_round,
                opacity=0.92, wet_blend=0.0,    # zero wet blending — Seurat's method
                jitter_amt=0.018, rng=self._rng_py,
                region_mask=region,
            )

            # ── Complementary dot (divisionist shimmer) ───────────────────────
            if chromatic_split:
                comp_col = complement(primary)
                comp_col = jitter(comp_col, 0.02, self._rng_py)

                # Offset in a random direction so the complement dot doesn't
                # simply overlay the primary — Seurat kept them visually distinct.
                angle = self._rng_py.uniform(0, 2 * math.pi)
                offset = dot_size * split_radius
                cx = int(np.clip(px + math.cos(angle) * offset, margin, w - margin))
                cy = int(np.clip(py + math.sin(angle) * offset, margin, h - margin))

                # Check region mask at complement position too.
                if region is not None and region[cy, cx] < 0.5:
                    continue

                comp_pts = [(float(cx), float(cy)), (float(cx) + 0.5, float(cy))]
                comp_ws  = [dot_size * 0.70, dot_size * 0.70]   # slightly smaller

                self.canvas.apply_stroke(
                    comp_pts, comp_ws, comp_col, tip_round,
                    opacity=split_ratio, wet_blend=0.0,
                    jitter_amt=0.015, rng=self._rng_py,
                    region_mask=region,
                )

    def luminous_glow_pass(self,
                           reference:    Union[np.ndarray, Image.Image],
                           n_rings:      int   = 9,
                           max_radius:   float = 0.55,
                           core_color:   Color = (0.98, 0.94, 0.72),
                           haze_color:   Color = (0.50, 0.62, 0.80),
                           core_opacity: float = 0.22,
                           haze_opacity: float = 0.10):
        """
        Atmospheric luminosity pass — inspired by J.M.W. Turner.

        Turner's late work dissolves solid form into radiant light.  His vortex
        compositions place the light source at the centre of a whirlpool of
        colour: burning white-yellow at the core, fading through warm amber and
        cool blue-grey to near-darkness at the periphery.

        This pass locates the brightest region in the reference image (the
        'sun' or primary light source) and overlays a series of concentric,
        semi-transparent radial gradients — each ring slightly larger and
        cooler than the last.  The accumulation creates the luminous aureole
        that is impossible to achieve with a single flat brush stroke.

        Unlike the stroke passes this is a post-processing compositing step:
        it does NOT use the wetness map or figure mask, because atmospheric
        light halos cross all boundaries (figure, background, edge).  Call it
        LAST, just before any final vignette or crackle.

        Parameters
        ----------
        reference    : PIL Image or ndarray — used only to locate the brightest
                       pixel (the light source centre).
        n_rings      : Number of glow rings to stack.  More rings = smoother
                       aureole.  9–12 is a good range; too many reads as foggy.
        max_radius   : Radius of the outermost ring as a fraction of the shorter
                       canvas dimension (0.55 = half the canvas width).
        core_color   : RGB of the innermost glow (hottest — near white-yellow).
        haze_color   : RGB of the outermost ring (cool atmospheric blue-grey).
        core_opacity : Alpha of the first (innermost) ring per layer.
        haze_opacity : Alpha of the last (outermost) ring per layer.

        Notes
        -----
        Turner frequently painted with a near-white cream ground and built up
        transparent warm glazes from the centre outward.  The cool blue-grey at
        the edges reflects his study of Goethe's colour theory: warm colours
        advance (light), cool colours recede (shadow/atmosphere).

        Famous works to study:
          *Light and Colour (Goethe's Theory)* (1843) — purest vortex composition.
          *Snow Storm — Steam-Boat* (1842) — ship dissolving in white tornado.
          *The Fighting Temeraire* (1839) — sunset aureole across calm water.
        """
        print(f"Luminous glow pass  ({n_rings} rings  max_r={max_radius:.2f})…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        # ── Locate brightest point (light source centre) ──────────────────────
        # Luminance map: weight toward warm bright pixels (matches incandescent
        # light sources which are warm rather than blue-white).
        lum = (0.40 * rarr[:, :, 0] +   # boosted red weight — warm bias
               0.50 * rarr[:, :, 1] +   # green
               0.10 * rarr[:, :, 2])    # suppressed blue
        lum = ndimage.gaussian_filter(lum, sigma=max(3.0, min(w, h) * 0.02))
        flat_idx = int(np.argmax(lum))
        src_y    = flat_idx // w
        src_x    = flat_idx %  w

        # ── Ring geometry ─────────────────────────────────────────────────────
        short_side  = min(w, h)
        outer_r     = max_radius * short_side

        # Rings grow non-linearly (quadratic) so the core is dense and the halo
        # thins out gracefully toward the edges — matching Turner's actual light.
        ring_radii = [outer_r * ((i + 1) / n_rings) ** 1.6
                      for i in range(n_rings)]

        # ── Draw concentric radial gradients ─────────────────────────────────
        for i, r in enumerate(ring_radii):
            t = i / max(n_rings - 1, 1)           # 0.0 = innermost, 1.0 = outermost

            # Colour: lerp from core (warm) to haze (cool)
            rc = core_color[0] + (haze_color[0] - core_color[0]) * t
            gc = core_color[1] + (haze_color[1] - core_color[1]) * t
            bc = core_color[2] + (haze_color[2] - core_color[2]) * t

            # Opacity: lerp between core and haze opacities, then halve for each
            # successive ring so they don't simply overdrive brightness.
            ring_opacity = core_opacity + (haze_opacity - core_opacity) * t
            # Thin inner rings need higher opacity; outer rings accumulate via
            # multiple layers so they're kept light individually.
            ring_opacity *= max(0.30, 1.0 - t * 0.55)

            # Inner edge fully transparent → outer edge at ring_opacity (annular).
            # Using two concentric radial gradients stacked gives a true ring
            # rather than a filled disk, which better matches Turner's swirling
            # diffuse bands of colour.
            inner_r = r * 0.0 if i == 0 else ring_radii[i - 1] * 0.65

            grad = cairo.RadialGradient(
                src_x, src_y, inner_r,
                src_x, src_y, r,
            )
            grad.add_color_stop_rgba(0.0, rc, gc, bc, 0.0)            # centre → transparent
            grad.add_color_stop_rgba(0.45, rc, gc, bc, ring_opacity)  # peak opacity
            grad.add_color_stop_rgba(1.0, rc, gc, bc, 0.0)            # fade to transparent

            self.canvas.ctx.rectangle(0, 0, w, h)
            self.canvas.ctx.set_source(grad)
            self.canvas.ctx.fill()

        # ── Thin warm core bloom (Vermeer 'pearls' at the light source) ───────
        # A final very small, very opaque bright dot at the exact light centre
        # gives the pin-sharp 'sun disc' visible in Turner's works through haze.
        bloom_r = max(3.0, short_side * 0.012)
        bloom   = cairo.RadialGradient(src_x, src_y, 0, src_x, src_y, bloom_r)
        bloom.add_color_stop_rgba(0.0, 1.0, 0.97, 0.88, 0.55)
        bloom.add_color_stop_rgba(1.0, 1.0, 0.97, 0.88, 0.0)
        self.canvas.ctx.arc(src_x, src_y, bloom_r, 0, 2 * math.pi)
        self.canvas.ctx.set_source(bloom)
        self.canvas.ctx.fill()

    def woodblock_pass(self,
                       reference:         Union[np.ndarray, Image.Image],
                       n_colors:          int   = 8,
                       bokashi_color:     Color = (0.15, 0.38, 0.72),
                       bokashi_strength:  float = 0.42,
                       bokashi_vertical:  bool  = True,
                       contour_weight:    float = 0.30,
                       contour_thickness: float = 2.5,
                       ink_color:         Color = (0.06, 0.04, 0.10)):
        """
        Ukiyo-e woodblock print technique — inspired by Katsushika Hokusai.

        Traditional ukiyo-e prints are built from three separate carved wood
        blocks printed in register:

          1. **Keyblock (Kento)** — the ink outline, printed in near-black or
             deep indigo.  Defines all major forms and figure silhouettes.
          2. **Colour blocks** — each flat colour region has its own block.
             The colours are pure, unshaded, with no tonal modelling.
          3. **Bokashi** — a soft graduated wash, produced by rubbing damp
             pigment from the edge of the block inward.  Typically Prussian
             blue in sky, water, and distant background areas.

        This pass replicates the full three-stage process:

          Stage 1 — Flat colour quantisation:
            The reference is reduced to ``n_colors`` dominant pigments via
            median-cut quantisation.  Each pixel is then painted with its
            nearest palette colour, creating the flat blocked-out regions
            characteristic of all ukiyo-e work.

          Stage 2 — Bokashi gradient:
            A soft directional gradient (default: Prussian blue, top → bottom,
            or left → right in landscape works) is overlaid at reduced opacity
            in the background zone, recreating the graduated atmospheric wash
            that makes Hokusai's skies and seas luminous.

          Stage 3 — Ink contour lines (keyblock):
            Thin dark strokes are placed along value boundaries (detected via
            Sobel gradient magnitude).  These mimic the carved contour lines
            that give ukiyo-e its distinctive graphic clarity.

        Parameters
        ----------
        reference         : Reference image (PIL Image or ndarray).
        n_colors          : Palette size for flat colour quantisation (6–12).
        bokashi_color     : Colour of the directional wash (default: Prussian blue).
        bokashi_strength  : Maximum opacity of the bokashi gradient (0–1).
                            0.30–0.50 reads as subtle; >0.60 reads as deep sky.
        bokashi_vertical  : True = top-to-bottom fade (sky); False = left-right.
        contour_weight    : Weight of contour detection in stroke placement
                            (0 = ignore value edges, 1 = contours only).
        contour_thickness : Width of ink keyblock lines in pixels.
        ink_color         : Colour of the keyblock outline strokes.

        Notes
        -----
        Unlike oil painting passes this method does NOT use the wetness map
        (ukiyo-e pigment is water-based and dries instantly).  wet_blend is
        forced to 0.0 throughout.

        Famous Hokusai works to study:
          *The Great Wave off Kanagawa* (c. 1831) — defining bokashi
          *Fine Wind, Clear Morning (Red Fuji)* (c. 1831) — flat colour + sky
          *The Dream of the Fisherman's Wife* (1814) — keyblock mastery
        """
        print(f"Woodblock pass  (n_colors={n_colors}  bokashi={bokashi_strength:.2f}"
              + f"  contour_w={contour_weight:.2f})…")

        ref  = self._prep(reference)
        h, w = ref.shape[:2]

        # ── Stage 1: Flat colour quantisation ────────────────────────────────
        # Reduce the reference to n_colors representative pigments and fill
        # each pixel with its nearest palette colour — no tonal blending.
        print("  Stage 1: flat colour quantisation…")
        pil_ref = Image.fromarray(ref[:, :, :3])

        # Quantise using PIL's median-cut algorithm to find dominant pigments.
        quantized_pil = pil_ref.quantize(colors=n_colors,
                                         method=Image.Quantize.MEDIANCUT,
                                         dither=Image.Dither.NONE)
        # Convert back to RGB so each pixel holds its palette colour.
        flat_rgb = np.array(quantized_pil.convert("RGB"), dtype=np.uint8)

        # Write the flat-colour image to the canvas surface.
        # Cairo stores BGRA; we build that directly.
        flat_bgra = np.dstack([flat_rgb[:, :, 2],   # B
                               flat_rgb[:, :, 1],   # G
                               flat_rgb[:, :, 0],   # R
                               np.full((h, w), 255, dtype=np.uint8)])
        flat_bytes = bytearray(flat_bgra.astype(np.uint8).tobytes())
        flat_surf  = cairo.ImageSurface.create_for_data(
            flat_bytes, cairo.FORMAT_ARGB32, w, h)
        self.canvas.ctx.set_source_surface(flat_surf, 0, 0)
        self.canvas.ctx.paint()

        # ── Stage 2: Bokashi gradient ──────────────────────────────────────────
        # Apply a soft directional colour wash over the background zone only.
        # In Hokusai's prints this is typically a graduated Prussian-blue sky
        # running from dark at the top to pale cream at the horizon.
        print("  Stage 2: bokashi gradient…")
        br, bg, bb = bokashi_color

        if bokashi_vertical:
            # Vertical: dark at top (y=0), fades to transparent at mid-canvas.
            grad = cairo.LinearGradient(0, 0, 0, h * 0.65)
        else:
            # Horizontal: left to right (e.g. for wave / water direction).
            grad = cairo.LinearGradient(0, 0, w * 0.65, 0)

        grad.add_color_stop_rgba(0.0, br, bg, bb, bokashi_strength)
        grad.add_color_stop_rgba(0.55, br, bg, bb, bokashi_strength * 0.25)
        grad.add_color_stop_rgba(1.0, br, bg, bb, 0.0)

        # Apply only in background zone if mask is available; otherwise full canvas.
        if self._figure_mask is not None:
            # Background is where figure_mask < 0.5.
            # Build a temporary mask surface to clip the gradient.
            bg_mask = (self._figure_mask < 0.5).astype(np.uint8) * 255
            mask_rgba = np.dstack([bg_mask, bg_mask, bg_mask,
                                   bg_mask]).astype(np.uint8)
            mask_bytes = bytearray(mask_rgba.tobytes())
            mask_surf  = cairo.ImageSurface.create_for_data(
                mask_bytes, cairo.FORMAT_ARGB32, w, h)

            # Paint gradient, then mask it by multiplying alpha with the bg mask.
            # Simpler approach: just fill, but skip figure pixels.
            # We'll use a full-canvas fill and let the very light opacity do the work
            # (the figure already has flat colour from Stage 1 which is opaque).
            self.canvas.ctx.rectangle(0, 0, w, h)
            self.canvas.ctx.set_source(grad)
            self.canvas.ctx.fill()
        else:
            self.canvas.ctx.rectangle(0, 0, w, h)
            self.canvas.ctx.set_source(grad)
            self.canvas.ctx.fill()

        # ── Stage 3: Ink contour lines (keyblock) ─────────────────────────────
        # Thin dark strokes placed along value boundaries, replicating the carved
        # contour lines that give ukiyo-e its graphic clarity.
        print("  Stage 3: ink keyblock contours…")
        rarr   = ref[:, :, :3].astype(np.float32) / 255.0
        lum    = (0.299 * rarr[:,:,0] + 0.587 * rarr[:,:,1]
                  + 0.114 * rarr[:,:,2]).astype(np.float32)
        gx     = ndimage.sobel(lum, axis=1)
        gy     = ndimage.sobel(lum, axis=0)
        # Contour strength map: strong at sharp value edges (lines / silhouettes).
        edge_mag = np.sqrt(gx**2 + gy**2).astype(np.float32)
        if edge_mag.max() > 1e-9:
            edge_mag /= edge_mag.max()

        # Smooth lightly so contour placement isn't hyper-jittery.
        edge_mag = ndimage.gaussian_filter(edge_mag, sigma=contour_thickness * 0.4)

        # Contour strokes respect figure mask if present.
        if self._figure_mask is not None:
            edge_mag = edge_mag * self._figure_mask

        prob = edge_mag.flatten() * contour_weight
        # Also add a small uniform component so every feature region can receive
        # contour lines even if its gradient is very soft (e.g. coloured areas
        # within the figure that share similar value to their neighbours).
        if self._figure_mask is not None:
            uniform = self._figure_mask.flatten() * (1.0 - contour_weight)
        else:
            uniform = np.ones(h * w, dtype=np.float32) * (1.0 - contour_weight)
        prob = prob + uniform
        total = prob.sum()
        if total < 1e-9:
            return
        prob /= total

        # Contour direction: tangent to the edge gradient (perpendicular to normal).
        contour_angles = np.arctan2(gx, -gy)     # follow the contour line direction
        contour_angles = ndimage.gaussian_filter(contour_angles, sigma=2.0)

        # Stroke count proportional to canvas area so large canvases get enough lines.
        n_contour = max(400, int(w * h / 600))

        tip_flat = BrushTip(BrushTip.FLAT, bristle_noise=0.0)
        positions = self._rng_py.choices(range(h * w),
                                          weights=prob.tolist(), k=n_contour)
        ir, ig, ib = ink_color
        margin = max(3, int(contour_thickness * 2))

        for pos in positions:
            py, px = int(pos // w), int(pos % w)
            px = max(margin, min(w - margin, px))
            py = max(margin, min(h - margin, py))

            a  = float(contour_angles[py, px])
            # Short crisp strokes — keyblock lines are typically 10–25px long.
            L  = self._rng_py.uniform(8.0, 22.0)
            start = (px - math.cos(a) * L * 0.5,
                     py - math.sin(a) * L * 0.5)
            n_pts = max(3, int(L / 4))
            pts   = stroke_path(start, a, L, curve=0.0, n=n_pts)
            ws    = [contour_thickness] * len(pts)

            self.canvas.apply_stroke(
                pts, ws, ink_color, tip_flat,
                opacity=0.94, wet_blend=0.0,
                jitter_amt=0.008, rng=self._rng_py,
                region_mask=self._figure_mask,
            )

    def watercolor_wash_pass(self,
                             reference:      Union[np.ndarray, Image.Image],
                             n_washes:       int   = 6,
                             wash_opacity:   float = 0.28,
                             drag_strokes:   int   = 180,
                             drag_size:      float = 22.0,
                             dark_strokes:   int   = 320,
                             dark_opacity:   float = 0.72,
                             paper_threshold: float = 0.82,
                             bloom_prob:     float = 0.18):
        """
        Transparent watercolour technique — inspired by John Singer Sargent.

        Watercolour is fundamentally different from oil: pigment is suspended
        in water and behaves according to the moisture state of the paper.
        There is no white paint — the highest lights are bare paper.  This
        pass replicates the four stages of Sargent's watercolour method:

          Stage 1 — Wet-into-wet foundation washes:
            Large, nearly-transparent sweeps of diluted pigment applied to
            pre-wetted paper.  Colours bleed and merge at their boundaries,
            producing the soft lost-edge quality of sky, water, and shadow
            masses.  Simulated via very large strokes with high wet_blend and
            low opacity.

          Stage 2 — 'Sargent drag' (dry-brush sparkle):
            A heavily-loaded flat brush dragged rapidly across the PEAKS of
            dry rough-surface paper.  The brush skips the hollows, leaving
            channels of bare cream paper that read as sparkling water,
            sunlit foliage, or sunlit stucco.
            Simulated by short, high-opacity flat strokes placed ONLY in
            mid-luminance areas (avoiding the very darkest shadows and the
            reserved bright lights), with a broken-edge quality from
            high bristle_noise in the BrushTip.

          Stage 3 — Hard-edge blooms:
            When a second wet stroke meets the drying edge of an earlier
            wash a backrun forms: the advancing waterfront pushes pigment
            outward, creating a hard 'cauliflower' edge.  Simulated by
            occasionally placing a narrow dark fringe stroke just outside
            a wash boundary (detected from the reference gradient).

          Stage 4 — Dark accent strokes (charged loaded brush):
            The final crisp darks are the last marks placed — a fully-loaded
            brush on dry paper leaves clean, transparent, high-intensity
            colour.  These are the marks that define shadow edges, figure
            outlines, and the deepest recesses.

        Paper preservation:
            Any pixel whose reference luminance exceeds *paper_threshold* is
            left as bare cream paper — NO pigment is placed there.  This is
            the most important rule of watercolour: you cannot paint light
            back once it is covered, so the artist plans and protects the
            white areas from the start.

        Parameters
        ----------
        reference        : PIL Image or ndarray — the target reference.
        n_washes         : Number of large wet-into-wet wash strokes.
                           6–10 is typical; more reads as overworked.
        wash_opacity     : Alpha of each wash stroke (keep low: 0.18–0.35).
        drag_strokes     : Number of 'Sargent drag' dry-brush strokes.
        drag_size        : Width of each drag stroke in pixels.
        dark_strokes     : Number of final dark-accent strokes.
        dark_opacity     : Opacity of dark accent strokes (0.55–0.85).
        paper_threshold  : Luminance above which pixels are left as bare paper.
        bloom_prob       : Probability (0–1) that a wash boundary gets a hard
                          bloom fringe stroke (cauliflower effect).

        Notes
        -----
        Sargent famously said that a watercolour should be finished before the
        first wash dries — speed is everything.  His *Muddy Alligators* (1917)
        and *Santa Maria della Salute* (1904) show a 'Sargent drag' sky
        applied in a single confident pass.

        Famous works to study:
          *Muddy Alligators* (1917) — wet-into-wet + loaded dark strokes.
          *Santa Maria della Salute* (1904) — 'drag' sky, hard blooms on water.
          *Boat Deck, Meteor* (1902) — reserve whites + dark accent calligraphy.
        """
        print(f"Watercolour wash pass  ({n_washes} washes  {drag_strokes} drag  "
              f"{dark_strokes} darks)…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        # ── Luminance map: used throughout for paper-preservation gating ─────────
        lum = (0.299 * rarr[:, :, 0] +
               0.587 * rarr[:, :, 1] +
               0.114 * rarr[:, :, 2])                        # (H, W) in [0, 1]

        # Paper-preservation mask: 0.0 where we must leave bare paper, 1.0 elsewhere.
        # Applied to stroke probability so no pigment lands on the lightest areas.
        paper_mask = (lum < paper_threshold).astype(np.float32)
        paper_mask = ndimage.gaussian_filter(paper_mask, sigma=3.5)  # feather the edge
        paper_mask = np.clip(paper_mask, 0.0, 1.0)

        # Also respect the figure mask if one is loaded.
        effective_mask = paper_mask
        if self._figure_mask is not None:
            effective_mask = paper_mask * self._figure_mask

        # ── Gradient for bloom detection ─────────────────────────────────────────
        gx = ndimage.sobel(lum, axis=1).astype(np.float32)
        gy = ndimage.sobel(lum, axis=0).astype(np.float32)
        grad_mag = np.sqrt(gx ** 2 + gy ** 2)
        if grad_mag.max() > 1e-9:
            grad_mag /= grad_mag.max()

        # ── Stage 1: Wet-into-wet foundation washes ──────────────────────────────
        # Large, very transparent, high-blending strokes that lay in the broad
        # colour and tonal masses.  The wetness allows colours to flow together
        # at their boundaries — this is the 'lost edge' quality of watercolour.
        print("  Stage 1: wet-into-wet washes…")
        tip_filbert = BrushTip(BrushTip.FILBERT, bristle_noise=0.04)

        # Sample from mid-dark regions (avoid bare-paper zones).
        wash_weight = (1.0 - lum) * effective_mask
        wash_total  = wash_weight.sum()
        if wash_total > 1e-9:
            wash_weight /= wash_total
            wash_positions = self.rng.choice(h * w, size=n_washes,
                                             p=wash_weight.flatten(), replace=True)
        else:
            wash_positions = self.rng.integers(0, h * w, size=n_washes)

        wash_stroke_size = min(w, h) * 0.18    # ~18% of the shorter canvas dimension

        for pos in wash_positions:
            py, px = int(pos // w), int(pos % w)
            margin = max(20, int(wash_stroke_size))
            px = int(np.clip(px, margin, w - margin))
            py = int(np.clip(py, margin, h - margin))

            # Colour: sample a patch and take the mean — washes are flat tones.
            pw = max(4, int(wash_stroke_size * 0.3))
            patch = rarr[max(0, py-pw):py+pw+1, max(0, px-pw):px+pw+1, :]
            col   = tuple(float(np.mean(patch[:, :, c])) for c in range(3))
            # Dilute toward white (water lightens pigment in wash state).
            col = tuple(min(1.0, v * 0.85 + 0.15) for v in col)
            col = jitter(col, 0.04, self._rng_py)

            a      = self._rng_py.uniform(0, 2 * math.pi)
            length = wash_stroke_size * self._rng_py.uniform(1.8, 3.5)
            start  = (px - math.cos(a) * length * 0.5,
                      py - math.sin(a) * length * 0.5)
            pts    = stroke_path(start, a, length,
                                 curve=self._rng_py.uniform(-0.08, 0.08),
                                 n=max(5, int(length / 14)))
            ws     = [wash_stroke_size * self._rng_py.uniform(1.0, 2.2)] * len(pts)

            self.canvas.apply_stroke(
                pts, ws, col, tip_filbert,
                opacity=wash_opacity,
                wet_blend=0.68,          # very high: washes bleed into each other
                jitter_amt=0.025,
                rng=self._rng_py,
                region_mask=effective_mask,
            )

            # ── Hard bloom (backrun / cauliflower edge) ───────────────────────
            # Occasionally add a narrow fringe of concentrated pigment along the
            # leading edge of the wash — this is the hard water-mark that forms
            # when a wet stroke dries.  Its colour is a darker, slightly shifted
            # version of the wash colour.
            if self._rng_py.random() < bloom_prob and len(pts) >= 2:
                # Bloom colour: darker, slightly cooler than the parent wash.
                b_col = tuple(max(0.0, v - self._rng_py.uniform(0.08, 0.18))
                              for v in col)
                # Bloom trace runs along the wash boundary: pick the last quarter
                # of the stroke path as the 'leading edge' and draw a thin line.
                split    = max(1, len(pts) * 3 // 4)
                b_pts    = pts[split:]
                b_ws     = [max(1.5, ws[0] * 0.12)] * len(b_pts)
                if len(b_pts) >= 2:
                    self.canvas.apply_stroke(
                        b_pts, b_ws, b_col,
                        BrushTip(BrushTip.FLAT, bristle_noise=0.0),
                        opacity=min(0.85, dark_opacity * 0.70),
                        wet_blend=0.0,       # hard bloom = no wet blending
                        jitter_amt=0.012,
                        rng=self._rng_py,
                        region_mask=effective_mask,
                    )

        # ── Stage 2: Sargent drag (dry-brush sparkle pass) ───────────────────────
        # A loaded flat brush drawn rapidly across the PEAKS of rough dry paper.
        # The bristles skip the hollow valleys of the paper grain, leaving thin
        # channels of bare cream paper that become sparkling light on water, etc.
        # We simulate this with short, fast flat-brush strokes using high bristle_noise
        # placed only in mid-luminance areas (not in the protected lights or the
        # deepest darks).
        print("  Stage 2: Sargent drag…")
        drag_tip = BrushTip(BrushTip.FLAT, bristle_noise=0.18)   # high bristle noise → broken coverage

        # Mid-luminance target: 0.35 ≤ lum < paper_threshold.
        # This is where sunlit texture is: not the deepest shadows, not the paper-white lights.
        drag_mask = ((lum >= 0.32) & (lum < paper_threshold)).astype(np.float32)
        if self._figure_mask is not None:
            drag_mask = drag_mask * self._figure_mask
        drag_weight = drag_mask * (lum - 0.32)     # favour brighter end of the range
        drag_total  = drag_weight.sum()

        if drag_total > 1e-9:
            drag_weight /= drag_total
            drag_positions = self.rng.choice(h * w, size=drag_strokes,
                                              p=drag_weight.flatten(), replace=True)

            for pos in drag_positions:
                py, px = int(pos // w), int(pos % w)
                margin = max(4, int(drag_size))
                px = int(np.clip(px, margin, w - margin))
                py = int(np.clip(py, margin, h - margin))

                # Sample lightened reference colour — drag picks up light pigment.
                col = tuple(float(rarr[py, px, c]) for c in range(3))
                col = tuple(min(1.0, v * 1.12) for v in col)   # slightly lighter
                col = jitter(col, 0.03, self._rng_py)

                # Direction: predominantly horizontal or a gentle diagonal —
                # Sargent worked with confident directional strokes, not random.
                base_angle = self._rng_py.choice([0.0, math.pi / 8, -math.pi / 8,
                                                   math.pi / 6, math.pi * 0.9])
                a      = base_angle + self._rng_py.uniform(-0.12, 0.12)
                length = drag_size * self._rng_py.uniform(2.5, 5.0)   # long confident stroke
                start  = (px - math.cos(a) * length * 0.5,
                          py - math.sin(a) * length * 0.5)
                pts    = stroke_path(start, a, length, curve=0.0,
                                     n=max(4, int(length / 8)))
                ws     = [drag_size * self._rng_py.uniform(0.8, 1.4)] * len(pts)

                self.canvas.apply_stroke(
                    pts, ws, col, drag_tip,
                    opacity=0.55,       # moderate — drag is not fully opaque
                    wet_blend=0.04,     # nearly dry surface — almost no blending
                    jitter_amt=0.025,
                    rng=self._rng_py,
                    region_mask=effective_mask,
                )

        # ── Stage 3: Dark accent strokes (loaded charged brush on dry paper) ─────
        # The final crisp darks are placed last on completely dry paper.  A
        # fully-loaded brush on dry paper gives transparent, luminous, clean
        # dark marks — much more vivid than overworking wet-into-wet.
        # These define shadow edges, cast shadows, and the deepest recesses.
        print("  Stage 3: dark accent strokes…")
        tip_round = BrushTip(BrushTip.ROUND, bristle_noise=0.02)

        dark_weight = (1.0 - lum) ** 2.5          # strongly prefer the darkest areas
        dark_weight *= effective_mask
        dark_weight += grad_mag * effective_mask * 0.4   # and value edges
        dark_weight  = dark_weight.flatten()
        dark_total   = dark_weight.sum()

        if dark_total > 1e-9:
            dark_weight /= dark_total
            dark_positions = self.rng.choice(h * w, size=dark_strokes,
                                              p=dark_weight, replace=True)

            angles = flow_field(rarr)   # strokes follow the colour contour
            dark_size = max(3.0, drag_size * 0.30)   # smaller, crisper than washes
            dark_load = PaintLoad(reload_mode='every_stroke')

            for pos in dark_positions:
                py, px = int(pos // w), int(pos % w)
                margin = max(4, int(dark_size * 2))
                px = int(np.clip(px, margin, w - margin))
                py = int(np.clip(py, margin, h - margin))

                col = tuple(float(rarr[py, px, c]) for c in range(3))
                # Darken the sampled colour — loaded pigment on dry paper is deep
                # and transparent.  The colour is rich, not muddy: multiply lightly.
                col = tuple(max(0.0, v * 0.75) for v in col)
                col = jitter(col, 0.02, self._rng_py)

                a      = float(angles[py, px]) + self._rng_py.uniform(-0.25, 0.25)
                length = dark_size * self._rng_py.uniform(2.0, 5.0)
                start  = (px - math.cos(a) * length * 0.5,
                          py - math.sin(a) * length * 0.5)
                pts    = stroke_path(start, a, length,
                                     curve=self._rng_py.uniform(-0.08, 0.08),
                                     n=max(3, int(length / 5)))
                ws     = [dark_size * self._rng_py.uniform(0.6, 1.2)] * len(pts)

                self.canvas.apply_stroke(
                    pts, ws, col, tip_round,
                    opacity=dark_opacity,
                    wet_blend=0.03,     # dry surface — no blending
                    jitter_amt=0.018,
                    rng=self._rng_py,
                    region_mask=effective_mask,
                    paint_load=dark_load,
                )

        # ── Stage 4: Drying — diffuse wet edges and granulate paper surface ───────
        print("  Stage 4: watercolour drying…")
        self.canvas.watercolor_dry(
            amount=0.55,
            diffuse_strength=0.25,
            diffuse_passes=1,
            granulate_strength=0.18,
        )

    def flat_plane_pass(self,
                        reference:       Union[np.ndarray, Image.Image],
                        n_planes:        int   = 5,
                        strokes_per_plane: int = 500,
                        stroke_size:     float = 11.0,
                        plane_opacity:   float = 0.80,
                        border_strokes:  int   = 300,
                        border_size:     float = 4.0,
                        border_opacity:  float = 0.88,
                        black_color:     Color = (0.06, 0.05, 0.06),
                        wet_blend:       float = 0.12):
        """
        Flat value-plane pass — inspired by Édouard Manet.

        Manet's revolutionary technique broke with academic chiaroscuro by
        rendering forms as a small number of discrete tonal planes separated
        by visible (but not hard) boundaries.  Where a Renaissance painter
        would smoothly graduate from highlight to shadow through hundreds of
        nuanced mid-tones, Manet laid down 3–5 flat patches of colour and
        left the boundary visible.  Olympia (1863) looks like a playing card
        at arm's length — and that flatness is the radical act.

        Algorithm
        ---------
        1. **Value quantisation** — Convert the reference to luminance.
           Cluster pixels into ``n_planes`` tonal bands (darkest to lightest)
           using evenly-spaced luminance thresholds.

        2. **Flat stroke patches** — For each band, sample random pixels
           inside that band and paint broad, nearly-flat strokes using the
           reference colour at that pixel.  Very low wet_blend keeps each
           patch from bleeding into adjacent bands (the 'mosaic' quality).

        3. **Plane-boundary dark strokes** — Detect the luminance gradient
           (edges between planes) and lay short, bold dark strokes along
           those edges.  Manet's characteristic border mark: a loaded flat
           brush pulled swiftly along the shadow side of a form.  Black is
           used as a pure chromatic colour here, not a neutral shadow mixer.

        Parameters
        ----------
        reference        : PIL Image or ndarray
        n_planes         : Number of tonal value bands (4–6 gives best results).
                           Too many → approaches normal painting; too few →
                           posterised / woodblock feel.
        strokes_per_plane: Broad flat strokes per tonal band.
        stroke_size      : Width of the flat plane strokes in pixels.
        plane_opacity    : Opacity of each flat stroke (high = decisive, loaded).
        border_strokes   : Short dark strokes placed at plane boundaries.
        border_size      : Width of the dark border strokes.
        border_opacity   : Opacity of the border strokes (deliberately high —
                           Manet's borders are confident, not timid).
        black_color      : The rich black used for border and shadow strokes.
                           Manet used black as a chromatic value, not merely
                           shadow — so this is a warm-neutral near-black, not
                           (0, 0, 0).
        wet_blend        : Within-plane wet blending.  Keep very low (0.10–0.20)
                           so patches stay flat.  Manet's whole point is the
                           absence of smooth gradients between planes.
        """
        print(f"Flat plane pass  ({n_planes} planes  {strokes_per_plane} strokes/plane)…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        tip_flat  = BrushTip(BrushTip.FLAT)
        tip_round = BrushTip(BrushTip.ROUND)

        # ── 1. Luminance map and plane thresholds ─────────────────────────────
        # Manet's cool-biased palette: weight luminance toward the green channel
        # (standard photometric) but suppress the red channel slightly so warm
        # tones read a touch darker — matching his silvery cool half-tones.
        lum = (0.28 * rarr[:, :, 0] +
               0.60 * rarr[:, :, 1] +
               0.12 * rarr[:, :, 2]).astype(np.float32)

        thresholds = [i / n_planes for i in range(1, n_planes)]

        # ── 2. Flat stroke patches per tonal band ─────────────────────────────
        for plane_idx in range(n_planes):
            lo = 0.0          if plane_idx == 0            else thresholds[plane_idx - 1]
            hi = 1.001        if plane_idx == n_planes - 1 else thresholds[plane_idx]

            plane_mask_bool = (lum >= lo) & (lum < hi)
            candidate_ys, candidate_xs = np.where(plane_mask_bool)
            if len(candidate_ys) == 0:
                continue

            # Apply figure mask if available — prefer painting the figure first,
            # then background (matches Manet's process: figure block-in, then bg).
            if self._figure_mask is not None:
                fig_vals = self._figure_mask[candidate_ys, candidate_xs]
                # Prefer figure pixels (high mask weight) — sample with weighting
                probs = 0.3 + 0.7 * fig_vals
                probs = probs / probs.sum()
            else:
                probs = None

            # Per plane, lay strokes sampling broadly across that tonal band.
            n_here = min(strokes_per_plane, len(candidate_ys))
            chosen = self.rng.choice(len(candidate_ys), size=n_here,
                                         replace=len(candidate_ys) < n_here,
                                         p=probs)

            for idx in chosen:
                py, px = int(candidate_ys[idx]), int(candidate_xs[idx])
                col = tuple(float(rarr[py, px, c]) for c in range(3))

                # Manet's key: cool silver in mid-tones, not warm brown.
                # Slightly desaturate mid-tones and nudge them cool.
                t_plane = plane_idx / max(n_planes - 1, 1)   # 0=dark, 1=light
                is_midtone = 0.25 < t_plane < 0.75
                if is_midtone:
                    col = temp_shift(col, warmth=-0.4)

                col = jitter(col, 0.028, self._rng_py)

                # Stroke direction: roughly horizontal for the torso/background
                # (Manet's confident loaded flat-brush sweep), with slight
                # individual variation.  This produces the visible planar
                # quality — strokes have direction, not random noise.
                base_angle = 0.0   # horizontal (flat drag)
                if plane_idx < n_planes // 2:
                    # Darker planes: slightly diagonal toward lower-left —
                    # Manet's shadow-side strokes have a deliberate lean.
                    base_angle = math.radians(20.0)
                a = base_angle + self._rng_py.uniform(-0.35, 0.35)

                # Broad strokes: length 2.5–5× width for a 'loaded sweep' look
                length = stroke_size * self._rng_py.uniform(2.5, 5.0)
                start  = (px - math.cos(a) * length * 0.5,
                          py - math.sin(a) * length * 0.5)
                pts    = stroke_path(start, a, length,
                                     curve=self._rng_py.uniform(-0.04, 0.04),
                                     n=max(3, int(length / 6)))
                ws     = [stroke_size * self._rng_py.uniform(0.85, 1.15)] * len(pts)

                self.canvas.apply_stroke(
                    pts, ws, col, tip_flat,
                    opacity=plane_opacity * self._rng_py.uniform(0.85, 1.0),
                    wet_blend=wet_blend,
                    jitter_amt=0.018,
                    rng=self._rng_py,
                    region_mask=self._figure_mask,
                )

        # ── 3. Plane-boundary dark strokes ────────────────────────────────────
        # Detect luminance gradients — high gradient = boundary between planes.
        # Manet placed short, bold, dark strokes (often black) right at these
        # boundaries — the most distinctive mark of his style.
        grad_y = ndimage.sobel(lum, axis=0)
        grad_x = ndimage.sobel(lum, axis=1)
        grad_mag = np.hypot(grad_x, grad_y).astype(np.float32)
        grad_mag /= (grad_mag.max() + 1e-9)

        # Threshold: only paint at genuine plane boundaries
        boundary_mask = grad_mag > 0.18
        bys, bxs = np.where(boundary_mask)
        if len(bys) > 0:
            n_border = min(border_strokes, len(bys))
            b_chosen = self.rng.choice(len(bys), size=n_border, replace=False)

            for idx in b_chosen:
                py, px = int(bys[idx]), int(bxs[idx])

                # Dark colour: Manet's black — warm-neutral, not absolute.
                # In the lightest areas add a hint of the local colour so the
                # shadow stroke is 'coloured dark' rather than dead grey.
                if lum[py, px] > 0.65:
                    local = tuple(float(rarr[py, px, c]) for c in range(3))
                    # Darken local by blending with black 70:30
                    col = mix_paint(local, black_color, 0.70)
                else:
                    col = jitter(black_color, 0.015, self._rng_py)

                # Stroke direction: follow the gradient direction (perpendicular
                # to the edge, into the darker side) — matching how Manet's
                # loaded brush draws across the shadow side of a form boundary.
                gx = float(grad_x[py, px])
                gy = float(grad_y[py, px])
                mag = math.sqrt(gx * gx + gy * gy) or 1.0
                # Perpendicular to gradient = along the edge
                a = math.atan2(gx / mag, -(gy / mag))
                a += self._rng_py.uniform(-0.30, 0.30)

                length = border_size * self._rng_py.uniform(3.0, 7.0)
                start  = (px - math.cos(a) * length * 0.5,
                          py - math.sin(a) * length * 0.5)
                pts    = stroke_path(start, a, length, curve=0.0,
                                     n=max(2, int(length / 5)))
                ws     = [border_size * self._rng_py.uniform(0.8, 1.2)] * len(pts)

                self.canvas.apply_stroke(
                    pts, ws, col, tip_flat,
                    opacity=border_opacity * self._rng_py.uniform(0.75, 1.0),
                    wet_blend=0.04,     # very dry — Manet's dark accents don't bleed
                    jitter_amt=0.012,
                    rng=self._rng_py,
                    region_mask=None,   # border strokes cross figure/background boundary
                )

    def focused_pass(self,
                     reference:   Union[np.ndarray, Image.Image],
                     region_mask: np.ndarray,
                     stroke_size: float = 8,
                     n_strokes:   int   = 600,
                     opacity:     float = 0.82,
                     wet_blend:   float = 0.12,
                     jitter_amt:  float = 0.025,
                     curvature:   float = 0.06,
                     form_angles: Optional[np.ndarray] = None):
        """
        High-density detail pass concentrated in a masked region.

        region_mask — (H, W) float32 array in [0, 1].
                      1.0 = stroke here, 0.0 = never stroke here.
        form_angles — optional pre-computed flow field (H, W) float32
                      in radians.  If None, derived from reference gradient.
                      Pass a spherical/radial field for faces so strokes
                      follow the curved surface rather than the flat image.

        This is how a portrait painter works: after the broad block-in,
        they move close to the canvas and place many small strokes on the
        face alone, with the brush following cheekbone curves and orbital
        contours rather than just colour edges.
        """
        label = f"Focused pass   ({n_strokes} strokes  size={stroke_size:.0f}px)"
        print(f"{label}…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        # Error map
        cbuf = np.frombuffer(self.canvas.surface.get_data(),
                             dtype=np.uint8).reshape(h, w, 4).copy()
        carr = cbuf[:, :, [2, 1, 0]].astype(np.float32) / 255.0
        err  = np.mean(np.abs(carr - rarr), axis=2).astype(np.float32)
        err  = ndimage.gaussian_filter(err, sigma=stroke_size * 0.3)

        # Reference luminance gradient — captures facial feature edges (nose
        # shadow, orbital rim, lip line) that error alone misses once the
        # block-in pass has covered the face in roughly-correct skin tone.
        lum_ref = (0.299 * rarr[:,:,0] + 0.587 * rarr[:,:,1]
                   + 0.114 * rarr[:,:,2]).astype(np.float32)
        gx = ndimage.sobel(lum_ref, axis=1).astype(np.float32)
        gy = ndimage.sobel(lum_ref, axis=0).astype(np.float32)
        grad_mag = np.sqrt(gx**2 + gy**2)
        if grad_mag.max() > 1e-9:
            grad_mag /= grad_mag.max()

        mask = np.clip(region_mask, 0, 1).astype(np.float32)

        # Intersect face/feature ellipse with the figure mask so focused_pass
        # strokes never land in the background.  Without this the ellipse extends
        # past the figure silhouette and strokes painted there (with pale skin
        # colours) appear as bright smears above/beside the head.
        if self._figure_mask is not None:
            mask = mask * self._figure_mask

        # Tripartite weight: raw error + gradient edges within mask + base mask coverage.
        # The gradient term pulls strokes toward nose/eye/lip feature boundaries.
        weight = err * 0.25 + (grad_mag * mask) * 0.45 + mask * 0.30
        weight = weight.flatten()
        weight /= weight.sum() + 1e-9

        angles = form_angles if form_angles is not None else flow_field(rarr)
        tip    = BrushTip(BrushTip.ROUND)

        # Local contrast lookup window (half-width in pixels)
        _contrast_hw = max(8, int(stroke_size * 1.5))
        _contrast_amp = 1.7   # push colours away from local mean

        self.canvas.dry(0.7)
        positions = self.rng.choice(h * w, size=n_strokes,
                                    p=weight, replace=True)
        lengths = stroke_size * self.rng.uniform(1.4, 2.8, n_strokes)

        for i, pos in enumerate(positions):
            py, px = int(pos // w), int(pos % w)
            margin = max(3, int(stroke_size * 1.5))
            px = int(np.clip(px, margin, w - margin))
            py = int(np.clip(py, margin, h - margin))

            col = tuple(float(rarr[py, px, c]) for c in range(3))

            # Local contrast enhancement within the masked region: shadows are
            # pushed darker, highlights brighter relative to the local mean.
            # Without this the face reads as a uniform pale blob because coarse
            # passes have already averaged out the subtle light/shadow gradient.
            if mask[py, px] > 0.4:
                hw = _contrast_hw
                patch = rarr[max(0, py-hw):py+hw+1,
                             max(0, px-hw):px+hw+1, :]
                pm = tuple(float(np.mean(patch[:, :, c])) for c in range(3))
                col = tuple(
                    max(0.0, min(1.0, pm[c] + (col[c] - pm[c]) * _contrast_amp))
                    for c in range(3)
                )

            col = jitter(col, jitter_amt, self._rng_py)

            a = float(angles[py, px]) + self._rng_py.uniform(-0.22, 0.22)
            L = lengths[i]
            start = (px - math.cos(a)*L*0.5, py - math.sin(a)*L*0.5)
            n_pts = max(4, int(L / 4))
            pts = stroke_path(start, a, L,
                              curve=self._rng_py.uniform(-curvature, curvature),
                              n=n_pts)
            ww = stroke_size * self._rng_py.uniform(0.55, 1.05)
            ws = [ww] * len(pts)

            # region_mask contains strokes within the face/feature ellipse
            self.canvas.apply_stroke(pts, ws, col, tip,
                                     opacity=opacity, wet_blend=wet_blend,
                                     jitter_amt=jitter_amt, rng=self._rng_py,
                                     region_mask=mask if mask is not None else None)

    def dark_void_pass(self,
                       reference:       Union[np.ndarray, Image.Image],
                       void_darkness:   float = 0.96,
                       n_strokes:       int   = 600,
                       stroke_size:     float = 16,
                       flesh_color:     Color = (0.68, 0.55, 0.35),
                       accent_color:    Color = (0.72, 0.18, 0.08),
                       accent_prob:     float = 0.08,
                       void_depth:      float = 0.80):
        """
        Pinturas Negras (Black Paintings) technique — inspired by Francisco Goya.

        Goya painted his Black Paintings directly onto the plaster walls of his
        Quinta del Sordo between 1819–1823, aged 73–75, deaf, and living in
        voluntary isolation.  *Saturn Devouring His Son*, *The Dog*, *Witches'
        Sabbath* — these works share a single visual strategy: near-black void
        surrounding barely-resolved figures.

        The technique:
          1. **Void ground** — the background is deepened to near-black by
             compositing a dark screen over background pixels. The figure is
             the only light source in a universe of darkness.
          2. **Crude figure strokes** — applied with a spatula and stiff brush;
             no wet blending, no refinement. Forms emerge from the dark only
             enough to be horrifying.  Ashen ochre and charred umber predominate.
          3. **Blood accent** — a single small intense stroke of blood-red or
             bone-white carries extraordinary weight against the surrounding void.
             Goya used this with surgical restraint.
          4. **Void encroachment** — dark strokes are placed even in figure areas
             near the edges, letting the void bleed into and consume the figure.
             This creates the sensation of figures dissolving rather than standing.

        Parameters
        ----------
        reference    : PIL Image or ndarray reference.
        void_darkness: Opacity of the black void overlay on background (0–1).
                       0.90–0.96 gives the characteristic impenetrable black.
        n_strokes    : Number of figure strokes.  Goya used fewer, larger marks
                       than conventional painters — 400–700 is appropriate.
        stroke_size  : Base width of strokes in pixels.  Keep large (12–20px) —
                       these are spatula marks, not fine brushwork.
        flesh_color  : Ashen ochre-grey used for figure flesh and mid-tones.
        accent_color : Blood red (or pale ash) used for the single hot accent.
        accent_prob  : Probability (0–1) that a stroke is placed in the accent
                       color rather than the flesh/umber range. Keep very low
                       (0.05–0.12) — Goya's restraint is part of the effect.
        void_depth   : Fraction of background pixels that receive additional
                       dark strokes (encroachment into the figure's territory).
        """
        print(f"Dark void pass  ({n_strokes} strokes  size={stroke_size:.0f}px"
              f"  void={void_darkness:.2f})…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        # ── Stage 1: Void the background ─────────────────────────────────────
        # Overlay pure near-black on all non-figure pixels.
        # This replicates Goya's black ground — the wall plaster was dark before
        # he began, and background areas received no light-valued paint at all.
        print("  Voiding background…")
        void_color = (0.02, 0.015, 0.008)   # near-black with a faint warm cast

        ctx = self.canvas.ctx
        if self._figure_mask is not None:
            # Background mask as a soft numpy field
            bg = np.clip(1.0 - self._figure_mask, 0.0, 1.0)
            # Read current canvas buffer
            buf = np.frombuffer(self.canvas.surface.get_data(),
                                dtype=np.uint8).reshape(h, w, 4).copy()
            carr = buf[:, :, [2, 1, 0]].astype(np.float32) / 255.0  # RGB

            # Blend toward void using the mask
            for c_idx, v in enumerate(void_color):
                src_ch = carr[:, :, c_idx]
                carr[:, :, c_idx] = src_ch * (1.0 - bg * void_darkness) + v * (bg * void_darkness)

            # Write back — Cairo BGRA
            buf[:, :, 2] = np.clip(carr[:, :, 0] * 255, 0, 255).astype(np.uint8)
            buf[:, :, 1] = np.clip(carr[:, :, 1] * 255, 0, 255).astype(np.uint8)
            buf[:, :, 0] = np.clip(carr[:, :, 2] * 255, 0, 255).astype(np.uint8)
            buf[:, :, 3] = 255
            tmp = cairo.ImageSurface.create_for_data(
                bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
            ctx.set_source_surface(tmp, 0, 0)
            ctx.paint()
        else:
            # No mask: darken the whole canvas (full-void approach)
            ctx.set_source_rgba(*void_color, void_darkness * 0.5)
            ctx.rectangle(0, 0, w, h)
            ctx.fill()

        # ── Stage 2: Crude figure strokes ────────────────────────────────────
        # Ashen, umber, and occasional blood-red strokes on the figure.
        # Error-driven sampling ensures strokes go where the reference differs
        # most from the dark canvas — i.e., where the figure should be.
        print(f"  Figure strokes ({n_strokes})…")

        cbuf = np.frombuffer(self.canvas.surface.get_data(),
                             dtype=np.uint8).reshape(h, w, 4).copy()
        carr = cbuf[:, :, [2, 1, 0]].astype(np.float32) / 255.0
        err  = np.mean(np.abs(carr - rarr), axis=2).astype(np.float32)
        err  = ndimage.gaussian_filter(err, sigma=stroke_size * 0.5)

        region = self._figure_mask
        if region is not None:
            err = err * region

        err_flat = err.flatten()
        total    = err_flat.sum()
        if total < 1e-9:
            prob = np.ones(h * w, dtype=np.float32) / (h * w)
        else:
            prob = err_flat / total

        positions = self.rng.choice(h * w, size=n_strokes, p=prob, replace=True)
        tip_flat  = BrushTip(BrushTip.FLAT, bristle_noise=0.25)  # crude, bristled
        self.canvas.dry(1.0)

        angles = flow_field(rarr)   # gradient-based angles

        for pos in positions:
            py, px = int(pos // w), int(pos % w)
            margin = max(int(stroke_size) + 2, 4)
            px = int(np.clip(px, margin, w - margin))
            py = int(np.clip(py, margin, h - margin))

            # Goya's colour choice: almost always ashen ochre/umber unless the
            # accent_prob dice roll fires.
            if self._rng_py.random() < accent_prob:
                col = accent_color
            else:
                # Reference-sampled colour crushed toward ashen flesh palette
                ref_col = tuple(float(rarr[py, px, c]) for c in range(3))
                # Lerp toward flesh_color (50/50): makes everything read more ashen
                col = mix_paint(ref_col, flesh_color, 0.55)

            col = jitter(col, 0.06, self._rng_py)

            a = float(angles[py, px]) + self._rng_py.uniform(-0.4, 0.4)  # crude angle jitter
            length = stroke_size * self._rng_py.uniform(1.5, 3.5)
            start  = (px - math.cos(a) * length * 0.5,
                      py - math.sin(a) * length * 0.5)
            pts = stroke_path(start, a, length,
                              curve=self._rng_py.uniform(-0.12, 0.12),
                              n=max(3, int(length / 4)))
            ws  = [stroke_size * self._rng_py.uniform(0.6, 1.3)] * len(pts)

            self.canvas.apply_stroke(pts, ws, col, tip_flat,
                                     opacity=self._rng_py.uniform(0.65, 0.92),
                                     wet_blend=0.08,   # near-zero blending — crude
                                     jitter_amt=0.05, rng=self._rng_py,
                                     region_mask=region)

        # ── Stage 3: Void encroachment ────────────────────────────────────────
        # Dark strokes placed near the figure's silhouette edge consume parts
        # of the figure, replicating how Goya's figures dissolve into blackness.
        if self._figure_mask is not None and void_depth > 0.0:
            print("  Void encroachment…")
            # Edge zone: where figure mask transitions from 1→0
            edge_zone = ndimage.gaussian_filter(self._figure_mask, sigma=stroke_size * 0.8)
            edge_zone = np.clip(self._figure_mask - edge_zone * 0.55, 0.0, 1.0)
            edge_zone *= void_depth

            edge_flat = edge_zone.flatten()
            total_e   = edge_flat.sum()
            if total_e > 1e-9:
                n_edge    = max(50, n_strokes // 5)
                prob_e    = edge_flat / total_e
                edge_pos  = self.rng.choice(h * w, size=n_edge, p=prob_e, replace=True)

                for pos in edge_pos:
                    py, px = int(pos // w), int(pos % w)
                    margin = max(int(stroke_size) + 2, 4)
                    px = int(np.clip(px, margin, w - margin))
                    py = int(np.clip(py, margin, h - margin))

                    # Very dark — almost void colour, with a faint umber warmth
                    col = jitter(void_color, 0.04, self._rng_py)
                    a   = self._rng_py.uniform(0, math.pi * 2)
                    length = stroke_size * self._rng_py.uniform(1.0, 2.0)
                    start  = (px - math.cos(a) * length * 0.5,
                              py - math.sin(a) * length * 0.5)
                    pts = stroke_path(start, a, length, curve=0.0,
                                      n=max(2, int(length / 6)))
                    ws  = [stroke_size * 0.7] * len(pts)

                    self.canvas.apply_stroke(pts, ws, col, tip_flat,
                                             opacity=self._rng_py.uniform(0.55, 0.85),
                                             wet_blend=0.05,
                                             jitter_amt=0.03, rng=self._rng_py,
                                             region_mask=None)  # allow crossing boundary

    def sfumato_veil_pass(self,
                          reference:             Union[np.ndarray, Image.Image],
                          n_veils:               int   = 7,
                          blur_radius:           float = 12.0,
                          warmth:                float = 0.35,
                          veil_opacity:          float = 0.08,
                          edge_only:             bool  = True,
                          chroma_dampen:         float = 0.18,
                          depth_gradient:        float = 0.0,
                          shadow_warm_recovery:  float = 0.0,
                          chroma_gate:           float = 0.0,
                          highlight_ivory_lift:  float = 0.0,
                          highlight_ivory_thresh: float = 0.82,
                          atmospheric_blue_shift: float = 0.0,
                          penumbra_bloom:         float = 0.0,
                          penumbra_bloom_lo:      float = 0.30,
                          penumbra_bloom_hi:      float = 0.60,
                          highlight_sharpness_recovery: float = 0.0,
                          highlight_sharpness_thresh:   float = 0.75,
                          highlight_sharpness_sigma:    float = 1.2,
                          penumbra_chroma_bloom:        float = 0.0,
                          penumbra_chroma_lo:           float = 0.28,
                          penumbra_chroma_hi:           float = 0.52):
        """
        Sfumato veil — improved Renaissance edge-softening technique.

        Named after Leonardo da Vinci's term 'sfumato' (from *sfumare*,
        'to evaporate like smoke'), this pass simulates the imperceptible
        transitions between light and shadow that are the hallmark of
        Leonardo's portrait technique.

        **Improvement over naive edge-softness:**
        Previous sessions approximated sfumato by reducing edge_softness in
        stroke_params.  This pass provides a physically motivated simulation:
        multiple thin, warm, blurred semi-transparent glazes are composited
        over the edge zone only, replicating how Leonardo built up sfumato
        through 30–40 imperceptible layers of oil glaze with fingertip
        blending.

        Technique:
          1. Detect the edge zone — where luminance gradient is above a
             threshold (form boundaries, transitions between light and shadow).
          2. Generate a blurred, warm-tinted version of the reference at
             each edge pixel.
          3. Composite n_veils thin copies at progressively larger blur
             radii, so the final result has a gentle gradient of haziness
             that increases away from the lit surface.

        The result: edges do not simply become soft (a smear) — they become
        *atmospheric*, as if seen through a thin curtain of warm smoke.
        Form is still readable; the boundary simply ceases to be findable.

        Parameters
        ----------
        reference    : PIL Image or ndarray — the reference to draw from.
        n_veils      : Number of glaze layers.  7–12 gives best results;
                       fewer looks too abrupt, more reads as out-of-focus.
        blur_radius  : Gaussian sigma for the initial blur, in pixels.
                       Final veil uses blur_radius * 2.0 (grows outward).
        warmth       : Warm tint strength (0 = neutral, 1 = full amber glaze).
                       Leonardo used a warm amber sfumato that shifts flesh
                       tones toward golden ochre at the edges.
        veil_opacity  : Alpha per veil layer.  Keep very low (0.04–0.12) —
                        the veils accumulate across n_veils layers.
        edge_only     : If True (default), veils are masked to the gradient
                        edge zone only — form interiors are not hazed, matching
                        Leonardo's selective sfumato. If False, applies globally.
        chroma_dampen : Chromatic desaturation at the edge zone (0 = no dampening,
                        1 = full greyscale).  Leonardo's sfumato zones are not
                        merely blurred — they are also slightly desaturated, as if
                        seen through thin warm smoke.  A value of 0.15–0.25 gives
                        the subtle grey-amber edge quality visible under X-ray at
                        the mouth corners of the Mona Lisa.  Applied per-veil so
                        outer veils are more desaturated than inner ones.
        depth_gradient : When > 0, intensifies the sfumato effect toward the
                         upper portion of the canvas (the distant background), and
                         reduces it toward the lower foreground.  This matches
                         Leonardo's actual technique: the landscape behind the Mona
                         Lisa — the rocky terrain and winding road that recede into
                         the far distance — is significantly more hazed than the
                         figure in the foreground.  The sfumato effect exists along
                         a vertical gradient of atmospheric depth, not uniformly.
                         At ``depth_gradient=1.0`` the top of the canvas receives
                         full veil_opacity while the bottom receives ~20% — a strong
                         but naturalistic atmospheric recession.  At 0.0 (default)
                         the behaviour is unchanged from prior sessions.

        Notes
        -----
        *Mona Lisa* (Louvre) shows sfumato most clearly at the corners of
        the mouth and eyes — precisely where expression is ambiguous.
        Leonardo never resolved these areas; the ambiguity is the technique.

        X-ray and infrared reflectography reveal up to 30 distinct glaze
        layers in the sfumato zones, each individually invisible.  The zones
        are also slightly desaturated relative to adjacent flesh areas — a
        quality missed by blur-only approximations.  chroma_dampen replicates
        this.

        The ``depth_gradient`` improvement (session 54): prior sessions applied
        sfumato uniformly across the canvas, which missed Leonardo's spatial
        logic — near-foreground forms are less hazed than distant ones.  The
        gradient weight corrects this by modulating veil opacity per-row.

        chroma_gate  : When > 0, reduces veil opacity in high-chroma (saturated)
                       zones of the reference — Leonardo applied sfumato most
                       heavily to near-neutral transitions (the shadow/light
                       boundary at the mouth corners, the temple region) rather
                       than to the chromatic accents (the warm sienna dress
                       fabric, the muted rose of the lips).  A ``chroma_gate``
                       of 0.4–0.6 gates the sfumato away from saturated pixels
                       proportionally, preserving their chromatic identity while
                       still dissolving the grey-amber transitions.  At 0.0
                       (default) the behaviour is unchanged from prior sessions.
                       This is the session-89 improvement.

        shadow_warm_recovery : When > 0, warms the current canvas in deep shadow
                               zones (luminance < ~0.35) before applying the sfumato
                               veils.  This corrects a subtle residual coolness in
                               the darkest passages that accumulates from the
                               blue-push operations in earlier passes (Lotto
                               chromatic anxiety, cool atmospheric recession, aerial
                               perspective).  Leonardo's deepest shadows — verified
                               by multispectral analysis of the Mona Lisa (Louvre
                               2020) — are never cool grey; they are warm dark umber,
                               reading almost as red-brown at extreme density.  At
                               shadow_warm_recovery=0.12, the correction is
                               perceptible but not intrusive; at 0.25 it produces
                               the characteristically warm dark void of the original.
                               Recovery is applied directly to the canvas before the
                               veil loop; the veils then inherit the corrected warmth.
                               (Session 82 improvement.)
        highlight_ivory_lift  : When > 0, adds a warm-ivory lift to the brightest
                               highlight zones (luminance > highlight_ivory_thresh,
                               default 0.82) BEFORE the sfumato veils are applied.
                               This simulates the Milanese Renaissance technique —
                               documented in technical studies of both Leonardo and
                               Bernardino Luini — of placing a lead-white chalk
                               preparation in the highest flesh highlights.  When the
                               warm amber sfumato veils are composited over this
                               ivory ground, the result is a luminous warm-ivory
                               glow rather than flat white: the highest lights feel
                               softly radiant, not bleached.  The lift is a gentle
                               warm neutral: R+0.06, G+0.04, B+0.02 at full
                               highlight_ivory_lift=1.0.  Recommended range: 0.04–0.10
                               for Milanese / Florentine High Renaissance; leave 0.0
                               for Baroque and Dutch Golden Age work where highlights
                               are typically warmer or sharper.  (Session 97 improvement,
                               inspired by Bernardino Luini's Madonna-type portraits.)
        highlight_ivory_thresh : Luminance threshold above which the ivory lift applies.
                               Default 0.82 targets only the very brightest flesh zones
                               (forehead peak, nose bridge, chin highlight) without
                               affecting the mid-tone flesh range.
        atmospheric_blue_shift : When > 0, applies a cool blue-grey colour temperature
                               shift to the upper portion of the canvas (distant
                               background) AFTER all sfumato veils have been composited.
                               This complements ``depth_gradient`` (which controls veil
                               *opacity* as a function of depth) with a matching colour
                               *temperature* recession: the very distant landscape shifts
                               toward the cool blue-grey that Leonardo's aerial
                               perspective imposes on forms seen through miles of
                               atmosphere.  The shift is a linear gradient from full
                               strength at the top canvas edge to zero at the midpoint
                               — below the midpoint (the figure zone) there is no
                               blue-grey push.  Practical values: 0.30–0.60 for a
                               clearly legible atmospheric recession; 0.15–0.25 for a
                               subtle improvement to background colour temperature.
                               Inspired by James Tissot's precise atmospheric colour
                               recession in his outdoor Thames scenes, where distant
                               backgrounds shift consistently toward cooler blue-grey
                               even when the foreground is painted in warm amber light.
                               (Session 102 improvement.)
        penumbra_bloom        : When > 0, adds a warm amber bloom in the penumbra zone
                               (the transition band between lit flesh and deep shadow)
                               BEFORE the sfumato veils are composited.  The veils
                               then naturally feather the edges of the bloom, integrating
                               it into the sfumato haze.  This enriches the penumbra
                               with Guercino's characteristic amber-ochre warmth —
                               the transitional zone where golden light makes its last
                               stand before surrendering to shadow.  A Gaussian bell
                               mask centred at the midpoint of [penumbra_bloom_lo,
                               penumbra_bloom_hi] applies the warm lift selectively
                               to the penumbra without affecting the full highlights
                               or deep shadows.  Practical values: 0.04–0.10 for
                               a subtle enrichment; 0.12–0.18 for a more pronounced
                               Guercinesque amber glow.
                               (Session 105 improvement, inspired by il Guercino.)
        penumbra_bloom_lo / _hi : luminance range for the penumbra bloom bell mask.
                               Default [0.30, 0.60] targets the mid-tone transition
                               zone typical of flesh passages.
        highlight_sharpness_recovery : When > 0, applies a targeted unsharp mask to
                               the brightest highlight zones (luminance above
                               highlight_sharpness_thresh) AFTER all sfumato veils
                               have been composited.  This corrects a systematic
                               flattening of peak highlights that accumulates when
                               multiple veils are layered: the nose-bridge catchlight,
                               forehead apex, and chin highlight lose subtle crispness
                               and begin to read as merely light zones rather than
                               gleaming surfaces.  In Leonardo's actual paintings (the
                               Mona Lisa, Lady with an Ermine), sfumato transitions are
                               soft, but peak highlights retain a subtle presence —
                               bright point against soft surroundings — that gives flesh
                               its quality of living surface rather than painted mist.
                               The unsharp mask uses fine sigma (default 1.2px) so
                               recovery targets only the sharpest transitions within
                               the highlight zone, not the gentle sfumato gradients.
                               Practical range: 0.04–0.12 for subtle recovery; 0.15–0.25
                               for more pronounced effect after heavy veil accumulation.
                               (Session 177 improvement.)
        highlight_sharpness_thresh : Luminance threshold above which sharpness recovery
                               applies.  Default 0.75 targets only the brightest flesh
                               highlights without affecting mid-tone or shadow regions.
        highlight_sharpness_sigma  : Gaussian sigma for the unsharp mask kernel.  Default
                               1.2px gives fine-detail recovery; increase to 2.5–4.0
                               for broader clarity enhancement.
        penumbra_chroma_bloom : When > 0, selectively boosts colour saturation in the
                               penumbra transition zone (luma penumbra_chroma_lo to
                               penumbra_chroma_hi) AFTER all other sfumato passes.
                               This encodes the art-historical observation that
                               Leonardo's flesh in the penumbra zone — the transition
                               from lit to shadow — carries the MAXIMUM chromatic
                               warmth of any zone: the highlights are pulled toward
                               ivory (desaturated), the deep shadows toward warm umber
                               (also muted), but the mid-shadow transition glows with
                               full carnation warmth.  Multispectral analysis of the
                               Mona Lisa (Louvre 2020) confirms that the penumbra at the
                               mouth corners and cheek shadow edge shows peak saturation
                               relative to adjacent zones.  Implemented as neutral-mean
                               chromatic expansion gated to the penumbra luma zone via
                               a Gaussian bell mask: delta = channel - neutral;
                               boosted = neutral + delta × (1 + strength × gate).
                               Practical range: 0.10–0.20 for subtle penumbra richness;
                               0.25–0.40 for a more pronounced chromatic glow.
                               (Session 178 improvement, inspired by Leonardo's
                               Mona Lisa multispectral data.)
        penumbra_chroma_lo / _hi : Luminance bounds for the penumbra saturation gate.
                               Default [0.28, 0.52] targets the mid-shadow transition
                               zone where carnation warmth peaks.
        """
        print(f"Sfumato veil pass  ({n_veils} veils  blur={blur_radius:.1f}px"
              f"  warmth={warmth:.2f}  chroma_dampen={chroma_dampen:.2f}"
              f"  depth_gradient={depth_gradient:.2f}"
              f"  shadow_warm_recovery={shadow_warm_recovery:.2f}"
              f"  chroma_gate={chroma_gate:.2f}"
              f"  highlight_ivory_lift={highlight_ivory_lift:.2f}"
              f"  atmospheric_blue_shift={atmospheric_blue_shift:.2f})…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        # ── Session 89: Chroma gate — pre-compute reference chroma map ────────
        # In high-chroma (saturated) zones, sfumato is gated back proportionally.
        # Leonardo applied sfumato most heavily to near-neutral transitions, not
        # to the chromatic accents (warm dress fabric, rose lips, etc.).
        if chroma_gate > 0.0:
            ref_max = np.maximum(np.maximum(rarr[:, :, 0], rarr[:, :, 1]), rarr[:, :, 2])
            ref_min = np.minimum(np.minimum(rarr[:, :, 0], rarr[:, :, 1]), rarr[:, :, 2])
            _ref_chroma = np.clip(ref_max - ref_min, 0.0, 1.0)  # per-pixel chroma [0, 1]
        else:
            _ref_chroma = None

        # ── Warm the reference toward amber (Leonardo's characteristic tone) ──
        # The sfumato is not a neutral grey haze but a warm golden one —
        # Leonardo used lead white + raw umber + a touch of red ochre in his glaze.
        amber = (0.80, 0.62, 0.35)
        warmed = np.zeros_like(rarr)
        for c in range(3):
            warmed[:, :, c] = rarr[:, :, c] * (1.0 - warmth) + amber[c] * warmth

        # ── Edge zone mask ────────────────────────────────────────────────────
        lum = (0.299 * rarr[:, :, 0] + 0.587 * rarr[:, :, 1] + 0.114 * rarr[:, :, 2])
        gx  = ndimage.sobel(lum, axis=1).astype(np.float32)
        gy  = ndimage.sobel(lum, axis=0).astype(np.float32)
        grad_mag = np.sqrt(gx ** 2 + gy ** 2)
        if grad_mag.max() > 1e-9:
            grad_mag /= grad_mag.max()

        if edge_only:
            # Expand the gradient edge zone with a Gaussian so the sfumato
            # covers a band around form boundaries, not just the 1-pixel edge.
            edge_mask = ndimage.gaussian_filter(
                grad_mag.astype(np.float32), sigma=blur_radius * 0.7)
            edge_mask = np.clip(edge_mask * 3.5, 0.0, 1.0)
            # Also apply figure mask if available
            if self._figure_mask is not None:
                edge_mask = edge_mask * self._figure_mask
        else:
            if self._figure_mask is not None:
                edge_mask = self._figure_mask.copy()
            else:
                edge_mask = np.ones((h, w), dtype=np.float32)

        # ── Depth gradient weight (session 54 improvement) ───────────────────────
        # Build a (H, 1) vertical weight map: rows near the top (background /
        # distant landscape) receive more sfumato; rows near the bottom
        # (foreground) receive less.  This matches Leonardo's spatial logic:
        # the far landscape behind the Mona Lisa is far more hazed than the
        # figure in the foreground.  depth_gradient=0 disables this (uniform).
        if depth_gradient > 0.0:
            # ys: 1.0 at the top row (row 0), fading toward a minimum of
            # (1 - depth_gradient) at the bottom row.
            ys = np.linspace(1.0, 1.0 - depth_gradient, h, dtype=np.float32)
            depth_w = np.clip(ys, 0.01, 1.0)[:, np.newaxis]  # (H, 1)
        else:
            depth_w = 1.0   # scalar broadcast — no per-row adjustment

        # ── Session 82: Shadow warm recovery ─────────────────────────────────
        # Before applying sfumato veils, warm the current canvas in the deep
        # shadow zones.  Pixels below a luminance threshold receive a gentle
        # R↑ G↑ B↓ push toward warm umber, correcting the cool-grey residual
        # that accumulates from blue-push passes (Lotto, aerial perspective, etc.).
        # The recovery is applied in-place to the live canvas surface, so the
        # sfumato veils that follow will inherit the corrected warm darkness.
        if shadow_warm_recovery > 0.0:
            canvas_raw = np.frombuffer(
                self.canvas.surface.get_data(), dtype=np.uint8
            ).reshape(h, w, 4).copy()
            # Cairo BGRA
            cb = canvas_raw[:, :, 0].astype(np.float32) / 255.0
            cg = canvas_raw[:, :, 1].astype(np.float32) / 255.0
            cr = canvas_raw[:, :, 2].astype(np.float32) / 255.0
            c_lum = 0.299 * cr + 0.587 * cg + 0.114 * cb
            # Shadow mask: full effect below 0.28 lum, fading out by 0.40
            shad_mask = np.clip((0.40 - c_lum) / (0.40 - 0.10), 0.0, 1.0)
            shad_str  = shad_mask * shadow_warm_recovery
            # Warm push: R↑ (umber red), G tiny ↑, B↓ (remove cool cast)
            cr_out = np.clip(cr + shad_str * 0.12, 0.0, 1.0)
            cg_out = np.clip(cg + shad_str * 0.04, 0.0, 1.0)
            cb_out = np.clip(cb - shad_str * 0.10, 0.0, 1.0)
            out_raw = canvas_raw.copy()
            out_raw[:, :, 0] = np.clip(cb_out * 255, 0, 255).astype(np.uint8)
            out_raw[:, :, 1] = np.clip(cg_out * 255, 0, 255).astype(np.uint8)
            out_raw[:, :, 2] = np.clip(cr_out * 255, 0, 255).astype(np.uint8)
            dst_surf = cairo.ImageSurface.create_for_data(
                bytearray(out_raw.tobytes()), cairo.FORMAT_ARGB32, w, h)
            self.canvas.ctx.set_source_surface(dst_surf, 0, 0)
            self.canvas.ctx.paint()
            print(f"    Shadow warm recovery applied (strength={shadow_warm_recovery:.2f}).")

        # ── Session 97: Highlight ivory lift ─────────────────────────────────
        # Before the sfumato veils composite, add a warm-ivory lift to the
        # brightest canvas highlights (lum > highlight_ivory_thresh).  This
        # simulates the Milanese Renaissance lead-white chalk ground in the
        # upper flesh highlights — a preparation documented in technical
        # analyses of Luini and Leonardo.  The ivory base then reads through
        # the amber sfumato veils as a soft luminous glow rather than flat white.
        if highlight_ivory_lift > 0.0:
            hi_raw = np.frombuffer(
                self.canvas.surface.get_data(), dtype=np.uint8
            ).reshape(h, w, 4).copy()
            hb = hi_raw[:, :, 0].astype(np.float32) / 255.0
            hg = hi_raw[:, :, 1].astype(np.float32) / 255.0
            hr = hi_raw[:, :, 2].astype(np.float32) / 255.0
            h_lum = 0.299 * hr + 0.587 * hg + 0.114 * hb
            # Linear ramp above the threshold, Gaussian feathered for smooth transition
            hi_mask = np.clip(
                (h_lum - highlight_ivory_thresh) / (1.0 - highlight_ivory_thresh + 1e-6),
                0.0, 1.0
            )
            hi_mask = ndimage.gaussian_filter(hi_mask.astype(np.float32), sigma=2.5)
            hi_mask = np.clip(hi_mask * highlight_ivory_lift, 0.0, 1.0)
            # Warm-ivory shift: R↑ most, G↑ moderately, B↑ least (ivory not pure white)
            hr_out = np.clip(hr + hi_mask * 0.06, 0.0, 1.0)
            hg_out = np.clip(hg + hi_mask * 0.04, 0.0, 1.0)
            hb_out = np.clip(hb + hi_mask * 0.02, 0.0, 1.0)
            hi_buf = hi_raw.copy()
            hi_buf[:, :, 2] = np.clip(hr_out * 255.0, 0, 255).astype(np.uint8)
            hi_buf[:, :, 1] = np.clip(hg_out * 255.0, 0, 255).astype(np.uint8)
            hi_buf[:, :, 0] = np.clip(hb_out * 255.0, 0, 255).astype(np.uint8)
            hi_surf = cairo.ImageSurface.create_for_data(
                bytearray(hi_buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
            self.canvas.ctx.set_source_surface(hi_surf, 0, 0)
            self.canvas.ctx.paint()
            print(f"    Highlight ivory lift applied (lift={highlight_ivory_lift:.2f}"
                  f"  thresh={highlight_ivory_thresh:.2f}).")

        # ── Session 105: Penumbra bloom (Guercino-inspired) ──────────────────
        # Before the sfumato veils, add a warm amber bloom in the penumbra zone —
        # the transition band from lit flesh to deep shadow.  Inspired by
        # Guercino's observation that the penumbra carries the greatest emotional
        # warmth: where golden candlelight breathes before surrendering to umber.
        # The sfumato veils that follow naturally feather the edges of the bloom,
        # integrating it into the smoky haze without hard boundaries.
        if penumbra_bloom > 0.0:
            pb_raw = np.frombuffer(
                self.canvas.surface.get_data(), dtype=np.uint8
            ).reshape(h, w, 4).copy()
            pb_b = pb_raw[:, :, 0].astype(np.float32) / 255.0
            pb_g = pb_raw[:, :, 1].astype(np.float32) / 255.0
            pb_r = pb_raw[:, :, 2].astype(np.float32) / 255.0
            pb_lum = 0.299 * pb_r + 0.587 * pb_g + 0.114 * pb_b
            # Gaussian bell centred at midpoint of [penumbra_bloom_lo, penumbra_bloom_hi]
            pb_mid   = (penumbra_bloom_lo + penumbra_bloom_hi) * 0.5
            pb_width = (penumbra_bloom_hi - penumbra_bloom_lo) * 0.5 + 1e-6
            pb_mask  = np.exp(
                -0.5 * ((pb_lum - pb_mid) / pb_width) ** 2
            ).astype(np.float32)
            pb_mask  = ndimage.gaussian_filter(pb_mask, sigma=4.0)
            pb_mask  = np.clip(pb_mask * penumbra_bloom, 0.0, 1.0)
            # Warm amber bloom: R↑ (amber), G↑ slight, B↓ (cool dampen for warmth)
            pb_r_out = np.clip(pb_r + pb_mask * 0.042, 0.0, 1.0)
            pb_g_out = np.clip(pb_g + pb_mask * 0.018, 0.0, 1.0)
            pb_b_out = np.clip(pb_b - pb_mask * 0.008, 0.0, 1.0)
            pb_buf = pb_raw.copy()
            pb_buf[:, :, 2] = np.clip(pb_r_out * 255.0, 0, 255).astype(np.uint8)
            pb_buf[:, :, 1] = np.clip(pb_g_out * 255.0, 0, 255).astype(np.uint8)
            pb_buf[:, :, 0] = np.clip(pb_b_out * 255.0, 0, 255).astype(np.uint8)
            pb_surf = cairo.ImageSurface.create_for_data(
                bytearray(pb_buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
            self.canvas.ctx.set_source_surface(pb_surf, 0, 0)
            self.canvas.ctx.paint()
            print(f"    Penumbra bloom applied (bloom={penumbra_bloom:.2f}"
                  f"  lo={penumbra_bloom_lo:.2f}  hi={penumbra_bloom_hi:.2f}).")

        # ── Multi-veil accumulation ───────────────────────────────────────────
        # Each veil: blur the warmed reference at a slightly larger radius,
        # weight by the edge mask, and composite at veil_opacity.
        ctx = self.canvas.ctx

        for i in range(n_veils):
            t = (i + 1) / n_veils                      # 0→1 across veil sequence
            sigma = blur_radius * (0.5 + t * 1.5)      # grows from small to large
            veil_warmth = warmth * (0.6 + 0.4 * t)     # warmer in outer veils

            # Re-warm each veil individually (outer veils are warmer / more golden)
            veil_ref = np.zeros_like(rarr)
            for c in range(3):
                veil_ref[:, :, c] = (rarr[:, :, c] * (1.0 - veil_warmth)
                                     + amber[c] * veil_warmth)

            # Chromatic dampening — outer veils are progressively desaturated so
            # the edge zone acquires a warm grey-amber quality (Leonardo's edges
            # under X-ray).  Desaturate by blending toward luminance-grey before
            # blurring so the effect is spatially coherent, not just an HSV shift.
            if chroma_dampen > 0.0:
                dampen_t = chroma_dampen * t   # ramps from 0 at first veil to full
                lum_veil = (0.299 * veil_ref[:, :, 0]
                            + 0.587 * veil_ref[:, :, 1]
                            + 0.114 * veil_ref[:, :, 2])
                for c in range(3):
                    veil_ref[:, :, c] = (veil_ref[:, :, c] * (1.0 - dampen_t)
                                         + lum_veil * dampen_t)

            # Gaussian blur to create the smoke effect
            blurred = np.stack([
                ndimage.gaussian_filter(veil_ref[:, :, c].astype(np.float32), sigma=sigma)
                for c in range(3)
            ], axis=2)

            # Composite: only where edge_mask is active; modulate by depth gradient
            # so distant (upper) regions receive stronger sfumato.
            alpha = edge_mask * veil_opacity * depth_w  # (H, W) float

            # Session 89: Chroma gate — reduce sfumato in saturated areas.
            # High-chroma pixels (vivid dress, warm skin accents) retain more of
            # their colour identity; desaturated transitions receive full sfumato.
            if _ref_chroma is not None:
                alpha = alpha * (1.0 - _ref_chroma * chroma_gate)

            # Build an ARGB32 Cairo surface for this veil.
            # IMPORTANT: Cairo's FORMAT_ARGB32 uses PREMULTIPLIED alpha.
            # Each channel must be multiplied by alpha before storing, or Cairo
            # will composite the raw (full-brightness) RGB values as if they were
            # already premultiplied, producing severe over-brightening at edges.
            alpha_3ch = alpha[:, :, np.newaxis]          # (H, W, 1) for broadcast
            premul_rgb = blurred * alpha_3ch              # (H, W, 3) premultiplied

            veil_rgba = np.zeros((h, w, 4), dtype=np.uint8)
            veil_rgba[:, :, 0] = np.clip(premul_rgb[:, :, 2] * 255, 0, 255).astype(np.uint8)  # B premul
            veil_rgba[:, :, 1] = np.clip(premul_rgb[:, :, 1] * 255, 0, 255).astype(np.uint8)  # G premul
            veil_rgba[:, :, 2] = np.clip(premul_rgb[:, :, 0] * 255, 0, 255).astype(np.uint8)  # R premul
            veil_rgba[:, :, 3] = np.clip(alpha * 255, 0, 255).astype(np.uint8)                 # A

            veil_surf = cairo.ImageSurface.create_for_data(
                bytearray(veil_rgba.tobytes()), cairo.FORMAT_ARGB32, w, h)
            ctx.set_source_surface(veil_surf, 0, 0)
            ctx.paint()   # alpha is premultiplied into R/G/B

        # ── Session 102: Atmospheric blue shift ──────────────────────────────────
        # After all sfumato veils are composited, apply a cool blue-grey colour
        # temperature shift to the upper canvas (distant background landscape).
        # This complements depth_gradient (which modulates opacity) with a physical
        # colour temperature change: atmosphere seen through depth is not merely
        # hazier, it is cooler and bluer — a well-documented phenomenon in colour
        # science (Rayleigh scattering) and in Leonardo's own aerial perspective.
        # Inspired by Tissot's precise cool recession in outdoor Thames scenes.
        if atmospheric_blue_shift > 0.0:
            atm_raw = np.frombuffer(
                self.canvas.surface.get_data(), dtype=np.uint8
            ).reshape(h, w, 4).copy()
            # Cairo BGRA channel layout
            ab = atm_raw[:, :, 0].astype(np.float32) / 255.0
            ag = atm_raw[:, :, 1].astype(np.float32) / 255.0
            ar = atm_raw[:, :, 2].astype(np.float32) / 255.0
            # Vertical weight: 1.0 at row 0 (top / distant sky), fading to 0.0
            # at the midpoint (row h//2), zero below — upper half only.
            atm_ys = np.linspace(1.0, 0.0, h // 2, dtype=np.float32)
            atm_full = np.concatenate([atm_ys, np.zeros(h - h // 2, dtype=np.float32)])
            atm_w = (atm_full * atmospheric_blue_shift)[:, np.newaxis]  # (H, 1)
            # Shift: R↓ G↓ B↑ — pull toward cool atmospheric blue-grey
            ar_out = np.clip(ar - atm_w * 0.09, 0.0, 1.0)
            ag_out = np.clip(ag - atm_w * 0.05, 0.0, 1.0)
            ab_out = np.clip(ab + atm_w * 0.07, 0.0, 1.0)
            atm_buf = atm_raw.copy()
            atm_buf[:, :, 2] = np.clip(ar_out * 255.0, 0, 255).astype(np.uint8)
            atm_buf[:, :, 1] = np.clip(ag_out * 255.0, 0, 255).astype(np.uint8)
            atm_buf[:, :, 0] = np.clip(ab_out * 255.0, 0, 255).astype(np.uint8)
            atm_surf = cairo.ImageSurface.create_for_data(
                bytearray(atm_buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
            self.canvas.ctx.set_source_surface(atm_surf, 0, 0)
            self.canvas.ctx.paint()
            print(f"    Atmospheric blue shift applied (strength={atmospheric_blue_shift:.2f}).")

        # ── Session 177: Highlight sharpness recovery ─────────────────────────
        # After all sfumato veils, recover subtle crispness in peak highlights.
        # Veils accumulate mild softening; brightest highlights (nose bridge,
        # forehead apex, chin) lose the tonal presence that distinguishes a
        # living painted surface from painted haze.  An unsharp mask gated to
        # high-luminance zones restores this quality.
        if highlight_sharpness_recovery > 0.0:
            hs_raw = np.frombuffer(
                self.canvas.surface.get_data(), dtype=np.uint8
            ).reshape(h, w, 4).copy()
            hs_b = hs_raw[:, :, 0].astype(np.float32) / 255.0
            hs_g = hs_raw[:, :, 1].astype(np.float32) / 255.0
            hs_r = hs_raw[:, :, 2].astype(np.float32) / 255.0
            hs_lum = 0.299 * hs_r + 0.587 * hs_g + 0.114 * hs_b
            hs_gate = np.clip(
                (hs_lum - highlight_sharpness_thresh)
                / (1.0 - float(highlight_sharpness_thresh) + 1e-6),
                0.0, 1.0
            ).astype(np.float32)
            hs_gate_smooth = ndimage.gaussian_filter(hs_gate, sigma=3.0)

            def _usm(ch):
                blurred = ndimage.gaussian_filter(
                    ch.astype(np.float32), sigma=float(highlight_sharpness_sigma))
                detail = ch.astype(np.float32) - blurred
                return np.clip(
                    ch.astype(np.float32)
                    + detail * hs_gate_smooth * float(highlight_sharpness_recovery),
                    0.0, 1.0)

            hs_r_out = _usm(hs_r)
            hs_g_out = _usm(hs_g)
            hs_b_out = _usm(hs_b)
            hs_buf = hs_raw.copy()
            hs_buf[:, :, 2] = np.clip(hs_r_out * 255.0, 0, 255).astype(np.uint8)
            hs_buf[:, :, 1] = np.clip(hs_g_out * 255.0, 0, 255).astype(np.uint8)
            hs_buf[:, :, 0] = np.clip(hs_b_out * 255.0, 0, 255).astype(np.uint8)
            hs_buf[:, :, 3] = hs_raw[:, :, 3]
            hs_surf = cairo.ImageSurface.create_for_data(
                bytearray(hs_buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
            self.canvas.ctx.set_source_surface(hs_surf, 0, 0)
            self.canvas.ctx.paint()
            print(f"    Highlight sharpness recovery applied"
                  f" (strength={highlight_sharpness_recovery:.2f}"
                  f"  thresh={highlight_sharpness_thresh:.2f}"
                  f"  sigma={highlight_sharpness_sigma:.1f}).")

        # ── Session 178: Penumbra chroma bloom ───────────────────────────────
        # After all sfumato passes, boost colour saturation in the penumbra
        # transition zone (luma 0.28–0.52 by default).  Art-historical basis:
        # multispectral analysis of the Mona Lisa (Louvre 2020) shows maximum
        # chromatic warmth in the mid-shadow transition, not the highlights.
        # Leonardo's highlights are ivory (desaturated); his deep shadows are
        # warm umber (muted); his penumbra glows with full carnation saturation.
        if penumbra_chroma_bloom > 0.0:
            pc_raw = np.frombuffer(
                self.canvas.surface.get_data(), dtype=np.uint8
            ).reshape(h, w, 4).copy()
            pc_b = pc_raw[:, :, 0].astype(np.float32) / 255.0
            pc_g = pc_raw[:, :, 1].astype(np.float32) / 255.0
            pc_r = pc_raw[:, :, 2].astype(np.float32) / 255.0
            pc_lum = 0.299 * pc_r + 0.587 * pc_g + 0.114 * pc_b
            pc_mid   = (float(penumbra_chroma_lo) + float(penumbra_chroma_hi)) * 0.5
            pc_width = (float(penumbra_chroma_hi) - float(penumbra_chroma_lo)) * 0.5 + 1e-6
            pc_gate  = np.exp(
                -0.5 * ((pc_lum - pc_mid) / pc_width) ** 2
            ).astype(np.float32)
            pc_gate  = ndimage.gaussian_filter(pc_gate, sigma=3.0)
            pc_boost = float(penumbra_chroma_bloom) * pc_gate
            pc_neutral = (pc_r + pc_g + pc_b) / 3.0
            pc_r_out = np.clip(pc_neutral + (pc_r - pc_neutral) * (1.0 + pc_boost), 0.0, 1.0)
            pc_g_out = np.clip(pc_neutral + (pc_g - pc_neutral) * (1.0 + pc_boost), 0.0, 1.0)
            pc_b_out = np.clip(pc_neutral + (pc_b - pc_neutral) * (1.0 + pc_boost), 0.0, 1.0)
            pc_buf = pc_raw.copy()
            pc_buf[:, :, 2] = np.clip(pc_r_out * 255.0, 0, 255).astype(np.uint8)
            pc_buf[:, :, 1] = np.clip(pc_g_out * 255.0, 0, 255).astype(np.uint8)
            pc_buf[:, :, 0] = np.clip(pc_b_out * 255.0, 0, 255).astype(np.uint8)
            pc_buf[:, :, 3] = pc_raw[:, :, 3]
            pc_surf = cairo.ImageSurface.create_for_data(
                bytearray(pc_buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
            self.canvas.ctx.set_source_surface(pc_surf, 0, 0)
            self.canvas.ctx.paint()
            print(f"    Penumbra chroma bloom applied"
                  f" (bloom={penumbra_chroma_bloom:.2f}"
                  f"  lo={penumbra_chroma_lo:.2f}  hi={penumbra_chroma_hi:.2f}).")

        print(f"  Sfumato complete ({n_veils} veils accumulated).")

    def angular_contour_pass(self,
                             reference:           Union[np.ndarray, Image.Image],
                             n_flat_strokes:      int   = 800,
                             flat_stroke_size:    float = 10.0,
                             n_contour_strokes:   int   = 1600,
                             contour_thickness:   float = 2.8,
                             contour_color:       Color = (0.12, 0.07, 0.04),
                             flesh_desaturation:  float = 0.40,
                             flesh_green_shift:   float = 0.12,
                             accent_color:        Color = (0.70, 0.12, 0.04),
                             accent_prob:         float = 0.06):
        """
        Viennese Expressionist contour pass — inspired by Egon Schiele.

        Schiele's drawings and gouaches are immediately recognisable by their
        violent, fractured contour line.  He drew with a reed pen or fine brush
        and pressed hard at joints, knuckles, and collar-bones where the anatomy
        is most exposed — the line swells, then almost vanishes between significant
        points.  The interior of the figure is filled with flat, barely-modelled
        patches of pale, slightly sickly flesh (often pulled toward yellow-green
        rather than warm pink), against a near-bare paper void.

        This pass has three sub-stages:

          Stage 1 — Flat interior fill:
            The figure interior is painted with short, flat, low-wet-blend strokes
            in slightly desaturated, greenish-shifted flesh tones.  Two brightness
            zones: lighter (lit surfaces) and darker (shadowed planes).  Very little
            wet blending — patches stay distinct, like gouache on dry paper.

          Stage 2 — Angular contour lines:
            Sobel edge detection locates all structural boundaries (silhouette,
            limb separations, form edges).  Short (10–30px) line segments are
            placed along these edges, each deliberately offset in angle from its
            neighbour by a small random amount.  This creates the fractured,
            re-starting quality of Schiele's mark — the line breaks, skips, then
            re-attacks.  At points of high edge magnitude (strong boundaries, joints)
            strokes are wider and more opaque.  At low-magnitude edges the line
            thins and fades.

          Stage 3 — Sparse blood-red accent:
            A small number of strokes in a warm blood-red or deep sienna accent are
            placed at the highest-gradient edge points — replicating Schiele's
            precise use of a single vivid accent to intensify the most psychologically
            loaded part of the composition (usually a hand, face, or collar).

        Parameters
        ----------
        reference           : PIL Image or ndarray.
        n_flat_strokes      : Number of interior flat-fill strokes.
        flat_stroke_size    : Width of the flat interior fill strokes in pixels.
        n_contour_strokes   : Number of angular contour line segments.
        contour_thickness   : Base width of contour lines in pixels.
                              Actual width varies ±50% per stroke to simulate
                              pressure variation on the reed pen.
        contour_color       : Near-black warm ink colour used for contour lines.
                              Schiele's lines were warm dark sienna-black, not a
                              neutral grey or cold blue-black.
        flesh_desaturation  : Fraction [0–1] by which the reference colour is
                              pulled toward grey before placing interior strokes.
                              0.30–0.50 gives the characteristically pallid look.
        flesh_green_shift   : Amount by which the flesh mid-tones are shifted
                              toward green (Schiele's jaundiced shadow planes).
                              Applied only to mid-luminance pixels (0.35–0.65 lum).
        accent_color        : Blood-red or hot sienna used for accent strokes.
        accent_prob         : Probability that a high-edge-strength contour stroke
                              is placed in the accent colour rather than near-black.
                              Keep very low (0.04–0.08) — Schiele's restraint is key.

        Notes
        -----
        Schiele died of Spanish flu in 1918, aged 28.  His entire known output
        spans only eleven years (1907–1918), yet he produced around 3,000 works
        on paper and 330 oil paintings.  The contour line was his primary instrument
        — even his oils read as drawings with colour added.

        Famous works to study:
          *Self-Portrait with Physalis* (1912) — pure angular contour + pale fill.
          *Death and the Maiden* (1915) — two figures dissolving into each other;
            the contour line becomes an embrace and a fracture simultaneously.
          *Seated Couple* (1915) — two figures locked together; limb boundaries
            drawn with multiple overlapping angular short strokes.
        """
        print(f"Angular contour pass  ({n_flat_strokes} fill  {n_contour_strokes} contour"
              f"  thick={contour_thickness:.1f}px)…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        # ── Luminance map (used throughout) ───────────────────────────────────
        lum = (0.299 * rarr[:, :, 0] +
               0.587 * rarr[:, :, 1] +
               0.114 * rarr[:, :, 2]).astype(np.float32)

        # ── Stage 1: Flat interior fill ───────────────────────────────────────
        # Schiele's interiors are flat, dry, barely blended.  Split into two
        # tonal zones: lit (lum ≥ 0.45) and shadowed (lum < 0.45).  Each zone
        # gets flat strokes with desaturated, slightly green-shifted colour.
        print("  Stage 1: flat interior fill…")

        # Desaturation helper: pull colour toward grey, then optionally green-shift
        def _schiele_flesh(col: tuple, pix_lum: float) -> tuple:
            """Apply Schiele's characteristic flesh treatment to a sampled colour."""
            r, g, b = col
            # Desaturate: lerp toward luminance grey
            grey = pix_lum
            r = r * (1.0 - flesh_desaturation) + grey * flesh_desaturation
            g = g * (1.0 - flesh_desaturation) + grey * flesh_desaturation
            b = b * (1.0 - flesh_desaturation) + grey * flesh_desaturation
            # Green shift in mid-tones (the sickly shadow planes)
            if 0.30 < pix_lum < 0.65:
                g = min(1.0, g + flesh_green_shift * (1.0 - abs(pix_lum - 0.475) / 0.175))
                r = max(0.0, r - flesh_green_shift * 0.35)
            return (r, g, b)

        tip_flat = BrushTip(BrushTip.FLAT, bristle_noise=0.03)
        region = self._figure_mask

        # Build sampling distribution: error-weighted within figure mask
        cbuf = np.frombuffer(self.canvas.surface.get_data(),
                             dtype=np.uint8).reshape(h, w, 4).copy()
        carr = cbuf[:, :, [2, 1, 0]].astype(np.float32) / 255.0
        err  = np.mean(np.abs(carr - rarr), axis=2).astype(np.float32)
        err  = ndimage.gaussian_filter(err, sigma=flat_stroke_size * 0.4)
        if region is not None:
            err = err * region
        err_total = err.flatten().sum()
        if err_total < 1e-9:
            prob_flat = (region.flatten() if region is not None
                         else np.ones(h * w, dtype=np.float32) / (h * w))
        else:
            prob_flat = err.flatten() / err_total

        positions = self.rng.choice(h * w, size=n_flat_strokes, p=prob_flat, replace=True)
        angles_bg = flow_field(rarr)   # follow colour contours for flat patches

        for pos in positions:
            py, px = int(pos // w), int(pos % w)
            margin = max(5, int(flat_stroke_size * 1.5))
            px = int(np.clip(px, margin, w - margin))
            py = int(np.clip(py, margin, h - margin))

            col = tuple(float(rarr[py, px, c]) for c in range(3))
            col = _schiele_flesh(col, float(lum[py, px]))
            col = jitter(col, 0.022, self._rng_py)

            # Flat strokes follow the image gradient (contours), with wide
            # confident sweeps rather than following form curvature.
            a = float(angles_bg[py, px]) + self._rng_py.uniform(-0.35, 0.35)
            L = flat_stroke_size * self._rng_py.uniform(2.0, 4.5)
            start = (px - math.cos(a) * L * 0.5,
                     py - math.sin(a) * L * 0.5)
            pts = stroke_path(start, a, L, curve=0.0,
                               n=max(3, int(L / 6)))
            ws = [flat_stroke_size * self._rng_py.uniform(0.7, 1.3)] * len(pts)

            self.canvas.apply_stroke(
                pts, ws, col, tip_flat,
                opacity=0.76,
                wet_blend=0.04,       # near-dry — no blending between patches
                jitter_amt=0.018,
                rng=self._rng_py,
                region_mask=region,
            )

        # ── Stage 2: Angular contour lines ────────────────────────────────────
        # Detect edges in the reference to locate figure silhouettes, limb
        # separations, and major form boundaries.  Place short, angular line
        # segments along these boundaries.
        print("  Stage 2: angular contour lines…")

        gx = ndimage.sobel(lum, axis=1).astype(np.float32)
        gy = ndimage.sobel(lum, axis=0).astype(np.float32)
        edge_mag = np.sqrt(gx ** 2 + gy ** 2).astype(np.float32)
        if edge_mag.max() > 1e-9:
            edge_mag /= edge_mag.max()

        # Lightly smooth so contour strokes cluster around edges without
        # pixel-level jitter
        edge_mag_smooth = ndimage.gaussian_filter(edge_mag, sigma=contour_thickness * 0.5)

        # Sample heavily from strong edges + a small uniform base so even
        # soft inner-form edges receive some line work
        if region is not None:
            edge_weight = edge_mag_smooth * region + region * 0.08
        else:
            edge_weight = edge_mag_smooth + 0.04
        edge_total = edge_weight.flatten().sum()
        if edge_total < 1e-9:
            return
        edge_prob = edge_weight.flatten() / edge_total

        # Contour direction: tangent to the edge gradient (along the edge)
        contour_angles_map = np.arctan2(gx, -gy).astype(np.float32)
        contour_angles_map = ndimage.gaussian_filter(contour_angles_map, sigma=1.5)

        positions_c = self.rng.choice(h * w, size=n_contour_strokes,
                                       p=edge_prob, replace=True)

        tip_round = BrushTip(BrushTip.ROUND, bristle_noise=0.01)
        margin_c = max(3, int(contour_thickness * 2))

        for pos in positions_c:
            py, px = int(pos // w), int(pos % w)
            px = int(np.clip(px, margin_c, w - margin_c))
            py = int(np.clip(py, margin_c, h - margin_c))

            local_edge = float(edge_mag[py, px])

            # Schiele accent: rare blood-red at very strong boundary points
            if (local_edge > 0.55 and
                    self._rng_py.random() < accent_prob * local_edge * 2.0):
                stroke_col = jitter(accent_color, 0.015, self._rng_py)
            else:
                stroke_col = jitter(contour_color, 0.02, self._rng_py)

            # Angular break: the contour direction is the gradient tangent, but
            # Schiele's line re-starts at a slightly different angle rather than
            # flowing smoothly.  Add a per-stroke angular deviation sampled from
            # a bimodal distribution: usually small (±0.15 rad), occasionally
            # larger (±0.55 rad) to simulate a genuine break and re-attack.
            if self._rng_py.random() < 0.18:
                angle_jitter = self._rng_py.choice([-1, 1]) * self._rng_py.uniform(0.35, 0.65)
            else:
                angle_jitter = self._rng_py.uniform(-0.14, 0.14)
            a = float(contour_angles_map[py, px]) + angle_jitter

            # Line length scales with local edge strength: strong edges → longer
            # strokes (Schiele pressed hardest at joints and silhouette).
            L_min = contour_thickness * 3.5
            L_max = contour_thickness * 9.0
            L = L_min + (L_max - L_min) * min(1.0, local_edge * 1.4)
            L *= self._rng_py.uniform(0.7, 1.3)

            start = (px - math.cos(a) * L * 0.5,
                     py - math.sin(a) * L * 0.5)
            pts = stroke_path(start, a, L, curve=0.0,
                               n=max(2, int(L / 5)))

            # Pressure variation: strong at joints (high edge mag), faint between.
            thickness_here = (contour_thickness
                              * self._rng_py.uniform(0.55, 1.50)
                              * (0.6 + 0.8 * local_edge))
            ws = [thickness_here] * len(pts)

            # Opacity also scales with edge strength — Schiele's line disappears
            # on soft form transitions, punches through on silhouette/joint edges.
            opacity_here = 0.55 + 0.40 * min(1.0, local_edge * 1.5)

            self.canvas.apply_stroke(
                pts, ws, stroke_col, tip_round,
                opacity=opacity_here,
                wet_blend=0.0,   # dry — ink on paper does not blend
                jitter_amt=0.008,
                rng=self._rng_py,
                region_mask=None,  # contour lines cross the figure/bg boundary
            )

        print(f"  Angular contour complete ({n_flat_strokes} fill  "
              f"{n_contour_strokes} contour lines).")

    def cloisonne_pass(self,
                       reference:          Union[np.ndarray, Image.Image],
                       n_colors:           int   = 8,
                       contour_thickness:  float = 4.5,
                       contour_color:      Color = (0.06, 0.04, 0.10),
                       saturation_boost:   float = 1.40,
                       hue_exotic_shift:   float = 0.03,
                       zone_opacity:       float = 0.92,
                       contour_opacity:    float = 0.94,
                       n_zone_strokes:     int   = 1400):
        """
        Cloisonnism / Synthetism pass — inspired by Paul Gauguin.

        Gauguin's Cloisonnism (named for cloisonné enamel jewellery where
        metallic 'cloisons' separate vivid glass fields) renders the world as
        flat zones of saturated, anti-naturalistic colour enclosed in dark
        thick organic contour lines — like stained-glass leading.  Chiaroscuro
        modelling is abandoned in favour of colour-as-emotion.  In Tahiti
        (1891–1903) his palette became the most exotic in Western painting:
        hot cadmium orange, deep cerulean, rose-magenta, viridian, golden ochre.

        Algorithm
        ---------
        1. Quantize the reference to ``n_colors`` flat zones using PIL palette
           quantization.  Each zone is assigned its mean colour from the
           reference, then saturation-boosted and hue-drifted toward Gauguin's
           tropical register.
        2. Fill each colour zone with flat loaded-brush strokes — opaque,
           low-wet-blend, broad.  Strokes are sampled from within each zone's
           pixel mask so colour never crosses a zone boundary.
        3. Detect inter-zone boundaries with Sobel on the zone index map.
        4. Draw thick dark organic contour lines along all zone boundaries —
           the 'cloisonné leading' that gives the technique its graphic power.
           Gauguin used near-black Prussian blue-black, not pure black.

        Parameters
        ----------
        reference         : PIL Image or ndarray reference.
        n_colors          : Number of colour zones (6–10 is Gauguin's range).
        contour_thickness : Width of the dark boundary lines in pixels.
        contour_color     : Cloisonné line colour — near-black with blue-purple
                            warmth (Gauguin used Prussian blue-black, not raw black).
        saturation_boost  : HSV saturation multiplier applied to each zone's
                            mean colour.  > 1 pushes toward exotic intensity.
        hue_exotic_shift  : Fraction of the hue wheel to drift each zone colour.
                            Small positive values push toward warm-tropical.
        zone_opacity      : Opacity of flat zone fill strokes.
        contour_opacity   : Opacity of contour line strokes.
        n_zone_strokes    : Total flat-fill strokes across all colour zones.
        """
        print(f"Cloisonné pass  (n_colors={n_colors}  "
              f"contour={contour_thickness:.1f}px  boost={saturation_boost:.2f})…")

        ref  = self._prep(reference)
        h, w = ref.shape[:2]

        # ── Step 1: Palette quantization ─────────────────────────────────────
        # PIL quantize gives us an index image and a compact palette.
        ref_pil = Image.fromarray(ref[:, :, :3])
        quantized = ref_pil.quantize(colors=n_colors, method=0, dither=0)
        index_arr = np.array(quantized, dtype=np.int32)   # (H, W), values 0..n_colors-1

        # Extract the palette as (n_colors, 3) float array in [0, 1].
        raw_palette = quantized.getpalette()               # flat list R,G,B × 256
        zone_colors_rgb: List[Color] = []
        for zi in range(n_colors):
            r = raw_palette[zi * 3]     / 255.0
            g = raw_palette[zi * 3 + 1] / 255.0
            b = raw_palette[zi * 3 + 2] / 255.0
            zone_colors_rgb.append((r, g, b))

        # ── Step 2: Boost saturation and drift hue toward tropical palette ───
        def _gauguin_shift(c: Color) -> Color:
            """Boost saturation and apply exotic hue drift in HSV space."""
            h_hsv, s, v = colorsys.rgb_to_hsv(*c)
            # Drift hue toward warm-tropical (orange-red register)
            h_hsv = (h_hsv + hue_exotic_shift) % 1.0
            # Boost saturation — Gauguin's colours are never muddy
            s = min(1.0, s * saturation_boost)
            # Slight value push: very dark zones stay dark, but mid-tones
            # are pushed slightly lighter (paper under thin paint glows through)
            if 0.15 < v < 0.65:
                v = v * 0.85 + 0.15
            return colorsys.hsv_to_rgb(h_hsv, s, v)

        zone_colors_shifted = [_gauguin_shift(c) for c in zone_colors_rgb]

        # ── Step 3: Flat zone fill ────────────────────────────────────────────
        print("  Stage 1: flat colour zone fill…")
        rarr = ref[:, :, :3].astype(np.float32) / 255.0

        tip_flat = BrushTip(BrushTip.FLAT, bristle_noise=0.04)

        # Distribute strokes across zones proportional to zone area.
        zone_areas = np.array([float((index_arr == zi).sum())
                                for zi in range(n_colors)], dtype=np.float32)
        total_area = zone_areas.sum() + 1e-9
        zone_strokes_alloc = [
            max(20, int(n_zone_strokes * (zone_areas[zi] / total_area)))
            for zi in range(n_colors)
        ]

        for zi in range(n_colors):
            zone_mask = (index_arr == zi).astype(np.float32)  # (H, W)
            if zone_mask.sum() < 4:
                continue

            # Apply figure mask if set — prefer not to flood background with
            # garish tropical colour unless the reference has a figure there.
            effective_zone = zone_mask
            if self._figure_mask is not None:
                # Blend: full weight in figure zone, 0.6 weight in background zone
                bg_weight = 0.60 * (1.0 - self._figure_mask)
                effective_zone = zone_mask * (self._figure_mask + bg_weight)
                effective_zone = np.clip(effective_zone, 0.0, 1.0)

            zone_flat = effective_zone.flatten()
            zone_total = zone_flat.sum()
            if zone_total < 1e-9:
                continue
            zone_prob = zone_flat / zone_total

            col_base = zone_colors_shifted[zi]
            n_here   = zone_strokes_alloc[zi]

            positions = self.rng.choice(h * w, size=n_here, p=zone_prob, replace=True)

            stroke_size = max(6.0, min(w, h) * 0.018)   # ~1.8% canvas short side

            for pos in positions:
                py, px = int(pos // w), int(pos % w)
                margin = max(3, int(stroke_size))
                px = int(np.clip(px, margin, w - margin))
                py = int(np.clip(py, margin, h - margin))

                # Slight per-stroke jitter in hue/value to avoid perfectly flat blocks
                col = jitter(col_base, 0.022, self._rng_py)

                # Broadly horizontal strokes — Gauguin's zone fills are confident
                # lateral sweeps, not random marks
                a      = self._rng_py.uniform(-0.20, 0.20)   # near-horizontal
                length = stroke_size * self._rng_py.uniform(2.0, 4.5)
                start  = (px - math.cos(a) * length * 0.5,
                          py - math.sin(a) * length * 0.5)
                n_pts  = max(3, int(length / 7))
                pts    = stroke_path(start, a, length, curve=0.0, n=n_pts)
                ws     = [stroke_size * self._rng_py.uniform(0.85, 1.15)] * len(pts)

                self.canvas.apply_stroke(
                    pts, ws, col, tip_flat,
                    opacity=zone_opacity * self._rng_py.uniform(0.88, 1.0),
                    wet_blend=0.05,      # Synthetism: flat, not blended
                    jitter_amt=0.015,
                    rng=self._rng_py,
                    region_mask=zone_mask,   # hard zone boundary — no colour bleed
                )

        # ── Step 4: Cloisonné contour lines (zone boundaries) ────────────────
        # Sobel on the index map locates every transition between colour zones.
        # This is the 'cloisonné leading' — the dark line that gives the
        # technique its graphic, stained-glass quality.
        print("  Stage 2: cloisonné boundary lines…")

        idx_float = index_arr.astype(np.float32) / max(n_colors - 1, 1)
        gx = ndimage.sobel(idx_float, axis=1).astype(np.float32)
        gy = ndimage.sobel(idx_float, axis=0).astype(np.float32)
        edge_mag = np.sqrt(gx ** 2 + gy ** 2).astype(np.float32)
        if edge_mag.max() > 1e-9:
            edge_mag /= edge_mag.max()

        # Smooth slightly so contour strokes cluster neatly, not pixel-by-pixel
        edge_smooth = ndimage.gaussian_filter(edge_mag, sigma=contour_thickness * 0.45)

        # Sample contour positions heavily from boundary pixels
        boundary_weight = edge_smooth.flatten()
        boundary_total  = boundary_weight.sum()
        if boundary_total < 1e-9:
            print("  No zone boundaries detected — skipping contour stage.")
        else:
            boundary_weight /= boundary_total

            # Contour stroke count scales with canvas area
            n_contour = max(600, int(w * h / 500))
            positions_c = self.rng.choice(h * w, size=n_contour,
                                           p=boundary_weight, replace=True)

            # Contour direction: tangent to the zone edge (perpendicular to Sobel gradient)
            contour_angles = np.arctan2(gx, -gy).astype(np.float32)
            contour_angles = ndimage.gaussian_filter(contour_angles, sigma=1.8)

            tip_round = BrushTip(BrushTip.ROUND, bristle_noise=0.02)
            margin_c  = max(3, int(contour_thickness * 2))

            for pos in positions_c:
                py, px = int(pos // w), int(pos % w)
                px = int(np.clip(px, margin_c, w - margin_c))
                py = int(np.clip(py, margin_c, h - margin_c))

                local_edge = float(edge_mag[py, px])
                if local_edge < 0.05:
                    continue   # skip weak-boundary noise

                # Gauguin's cloisonné line: thick where the zone contrast is
                # highest, thinner across gentler transitions — the 'lead'
                # varies in weight like hand-drawn metalwork.
                thick = (contour_thickness
                         * self._rng_py.uniform(0.70, 1.35)
                         * (0.55 + 0.75 * min(1.0, local_edge * 1.5)))

                a = float(contour_angles[py, px])
                a += self._rng_py.uniform(-0.10, 0.10)   # organic wobble

                # Short strokes — the leading is a series of overlapping segments,
                # not a single continuous ruled line.
                L = thick * self._rng_py.uniform(4.0, 9.0)
                start = (px - math.cos(a) * L * 0.5,
                         py - math.sin(a) * L * 0.5)
                pts = stroke_path(start, a, L, curve=0.0,
                                   n=max(2, int(L / 5)))
                ws  = [thick] * len(pts)

                col = jitter(contour_color, 0.018, self._rng_py)

                self.canvas.apply_stroke(
                    pts, ws, col, tip_round,
                    opacity=contour_opacity * (0.72 + 0.28 * min(1.0, local_edge * 2)),
                    wet_blend=0.0,   # ink contour — never wet-blends
                    jitter_amt=0.010,
                    rng=self._rng_py,
                    region_mask=None,   # contour lines cross all boundaries
                )

        print(f"  Cloisonné complete ({n_colors} zones  contour={contour_thickness:.1f}px).")

    def pigment_granulation_pass(self,
                                 strength:   float = 0.42,
                                 lum_lo:     float = 0.08,
                                 lum_hi:     float = 0.82,
                                 tex_mean:   float = 0.84):
        """
        Watercolour pigment granulation — physical paper-tooth pigment settling.

        Certain watercolour pigments (ultramarine blue PB29, burnt sienna PR101,
        cobalt PB28, raw umber PBr7) have unusually large or heavy particles.
        As a freshly-applied wash dries, these particles settle by gravity and
        surface tension into the depressions ('hollows') of the paper tooth, while
        the water-soluble binder lifts them off the peaks.  The result is a
        speckled, tactile texture where:
          - **Paper hollows** (low texture value) = concentrated dark pigment
          - **Paper peaks** (high texture value) = diluted or absent pigment

        This is impossible to replicate by varying stroke size or opacity alone —
        it requires a direct pixel-level modulation of the painted surface using
        the same paper texture that drives the substrate rendering.

        The pass reads the current canvas buffer, computes per-pixel luminance,
        then applies the paper-texture map (self.canvas.texture) as a physical
        offset: hollows are darkened, peaks are lightened, by up to ``strength``.
        Only mid-luminance pixels (lum_lo … lum_hi) receive the effect — bare
        paper (very light) and deep darks are left untouched, matching how real
        granulating pigments are transparent in high-dilution zones.

        This improvement is applied *after* the wet-into-wet wash passes so that
        the granulation reads as a property of the dried pigment deposit, not an
        additional paint layer.

        Parameters
        ----------
        strength : Maximum luminance shift at full texture contrast (0–1).
                   0.35–0.50 gives a naturalistic granulation; above 0.60
                   looks like deliberate texture.
        lum_lo   : Lower luminance gate (shadows below this are untouched).
        lum_hi   : Upper luminance gate (lights above this are untouched — bare paper).
        tex_mean : Neutral texture value around which hollows and peaks are measured.
                   Should match the midpoint of the texture range (linen ~0.86,
                   cold-press paper ~0.84).
        """
        print(f"Pigment granulation pass  (strength={strength:.2f}  "
              f"lum=[{lum_lo:.2f}, {lum_hi:.2f}])…")

        h, w = self.h, self.w

        # ── Read current canvas ───────────────────────────────────────────────
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(h, w, 4).copy()
        # Cairo BGRA → RGB float [0, 1]
        carr = buf[:, :, [2, 1, 0]].astype(np.float32) / 255.0

        # ── Paper texture (already generated for the substrate) ───────────────
        tex = self.canvas.texture   # (H, W) float32 in [0.68, 1.0]

        # ── Luminance map ─────────────────────────────────────────────────────
        lum = (0.299 * carr[:, :, 0] +
               0.587 * carr[:, :, 1] +
               0.114 * carr[:, :, 2]).astype(np.float32)

        # ── Granulation mask: only mid-luminance painted areas ────────────────
        gran_mask = ((lum > lum_lo) & (lum < lum_hi)).astype(np.float32)

        # Smooth the mask so the effect fades in at both luminance extremes
        gran_mask = ndimage.gaussian_filter(gran_mask, sigma=1.5)
        gran_mask = np.clip(gran_mask, 0.0, 1.0)

        # Apply figure mask if present: granulation is strongest on figure
        # surfaces (where pigment was actually applied) and weaker in the
        # bare-paper background.
        if self._figure_mask is not None:
            fig_weight = 0.40 + 0.60 * self._figure_mask   # bg gets 40% strength
            gran_mask  = gran_mask * fig_weight

        # ── Texture offset ────────────────────────────────────────────────────
        # tex values below tex_mean = hollow = more pigment → darker
        # tex values above tex_mean = peak   = less pigment → lighter
        # offset is negative in hollows (darken), positive on peaks (lighten)
        tex_offset = (tex - tex_mean) * strength   # (H, W) in [-strength*0.16, +strength*0.16]
        # Scale by mask so effect only appears in the painted mid-tone zone
        tex_offset = tex_offset * gran_mask         # (H, W)

        # ── Apply modulation to RGB channels ──────────────────────────────────
        # All three channels shift equally to preserve hue; only luminance changes.
        modified = np.zeros_like(carr)
        for c in range(3):
            modified[:, :, c] = np.clip(carr[:, :, c] + tex_offset, 0.0, 1.0)

        # ── Write back to Cairo surface (RGB → BGR for BGRA layout) ──────────
        buf[:, :, 2] = np.clip(modified[:, :, 0] * 255, 0, 255).astype(np.uint8)  # R
        buf[:, :, 1] = np.clip(modified[:, :, 1] * 255, 0, 255).astype(np.uint8)  # G
        buf[:, :, 0] = np.clip(modified[:, :, 2] * 255, 0, 255).astype(np.uint8)  # B
        buf[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print("  Granulation complete.")

    def dappled_light_pass(
            self,
            reference:          "Union[np.ndarray, Image.Image]",
            n_pools:            int   = 38,
            pool_radius:        float = 0.065,
            light_color:        Color = (1.00, 0.97, 0.82),
            shadow_color:       Color = (0.62, 0.58, 0.80),
            light_intensity:    float = 0.28,
            shadow_intensity:   float = 0.14,
            scatter_jitter:     float = 0.18,
            lum_gate:           float = 0.30,
            blur_sigma:         float = 3.5,
    ):
        """
        Dappled light pass — inspired by Joaquín Sorolla's luminismo.

        Sorolla's outdoor paintings are defined by broken pools of Mediterranean
        sunlight scattered across figures, fabric, and water.  Direct sunlight
        filters through leaves (or reflects off water) to create irregular,
        overlapping patches of warm brilliance surrounded by cool violet shadow.

        This pass simulates that effect entirely in the painted pixel buffer:

        1. **Pool placement** — ``n_pools`` elliptical masks are placed pseudo-
           randomly across the canvas, biased toward mid-luminance areas (the
           brightly-lit regions where the effect is most readable).

        2. **Warm light dabs** — inside each pool the canvas is nudged toward
           ``light_color`` (warm golden-white) proportional to ``light_intensity``.
           The shift is strongest at the pool centre and falls off with a Gaussian
           envelope, so each patch is softer at its perimeter — imitating the
           penumbral edge of filtered sunlight.

        3. **Cool violet shadow fringe** — immediately outside each pool the
           complement effect kicks in: the shadow side is shifted toward
           ``shadow_color`` (cool violet / blue) at ``shadow_intensity``.
           This simultaneous contrast is the defining Sorolla move: warm light
           makes the adjacent shadow *cooler and more violet* by comparison.

        4. **Specular impasto dot** — at each pool's brightest point a single
           very bright near-white dab (radius ≈ pool_radius × 0.12) marks the
           direct specular highlight.  In Sorolla's technique these dots are
           painted last with a heavily loaded brush.

        The pass works in float32 pixel space for accuracy, then writes back to
        the Cairo ARGB32 surface — exactly like ``pigment_granulation_pass``.

        Parameters
        ----------
        reference        : Reference image for luminance-biased placement.
        n_pools          : Number of light pools to scatter.
        pool_radius      : Pool radius as a fraction of canvas width (0.03–0.12).
        light_color      : Warm sunlight colour to push into pool centres.
        shadow_color     : Cool shadow/violet colour for pool fringes.
        light_intensity  : Maximum lightening strength inside each pool (0–1).
        shadow_intensity : Maximum shadow fringe shift (0–1).
        scatter_jitter   : Fraction of canvas added as uniform random noise to
                           pool positions beyond the luminance-biased grid.
        lum_gate         : Only place pools over pixels above this luminance —
                           avoids scattering light into already-dark shadow areas.
        blur_sigma       : Gaussian sigma (px) for pool envelope softening.
        """
        print(f"Dappled light pass  (n_pools={n_pools}  "
              f"radius={pool_radius:.3f}  intensity={light_intensity:.2f})…")

        ref = self._prep(reference)
        h, w = self.h, self.w
        rng  = random.Random(42)           # deterministic within a painting session

        # ── Read current canvas ───────────────────────────────────────────────
        buf  = np.frombuffer(self.canvas.surface.get_data(),
                             dtype=np.uint8).reshape(h, w, 4).copy()
        carr = buf[:, :, [2, 1, 0]].astype(np.float32) / 255.0   # BGR→RGB

        # ── Reference luminance for placement bias ────────────────────────────
        ref_lum = (0.299 * ref[:, :, 0] +
                   0.587 * ref[:, :, 1] +
                   0.114 * ref[:, :, 2])

        # Build a candidate set: pixels above lum_gate
        bright_ys, bright_xs = np.where(ref_lum > lum_gate)
        if bright_ys.size == 0:
            bright_ys, bright_xs = np.where(ref_lum >= 0)   # fallback: anywhere

        # Pixel radius
        radius_px = max(6, int(pool_radius * w))

        # Accumulator for light and shadow shifts — summed, then applied once
        light_acc  = np.zeros((h, w), dtype=np.float32)   # +lightening
        shadow_acc = np.zeros((h, w), dtype=np.float32)   # +shadow fringe

        ys_f = np.arange(h, dtype=np.float32)
        xs_f = np.arange(w, dtype=np.float32)

        for _ in range(n_pools):
            # Sample a candidate pixel, biased toward bright areas
            idx = rng.randrange(len(bright_ys))
            cy  = int(bright_ys[idx] + rng.uniform(-scatter_jitter * h,
                                                     scatter_jitter * h))
            cx  = int(bright_xs[idx] + rng.uniform(-scatter_jitter * w,
                                                     scatter_jitter * w))
            cy  = max(0, min(h - 1, cy))
            cx  = max(0, min(w - 1, cx))

            # Elliptical Gaussian pool envelope (slight aspect-ratio variation)
            rx  = radius_px * rng.uniform(0.75, 1.25)
            ry  = radius_px * rng.uniform(0.75, 1.25)

            # Distance grid — vectorised
            dy  = (ys_f[:, np.newaxis] - cy) / max(ry, 1)
            dx  = (xs_f[np.newaxis, :] - cx) / max(rx, 1)
            d2  = dx * dx + dy * dy

            # Gaussian core: peaks at the pool centre (d2=0)
            gauss  = np.exp(-d2 * 1.8).astype(np.float32)

            # Shadow fringe: annular region just outside the core
            fringe = np.exp(-((d2 - 1.0) ** 2) * 2.5).astype(np.float32)
            fringe = np.where(d2 > 0.6, fringe, 0.0).astype(np.float32)

            light_acc  += gauss  * rng.uniform(0.65, 1.0)
            shadow_acc += fringe * rng.uniform(0.50, 1.0)

        # Normalise accumulators so overlapping pools don't over-saturate
        max_l = light_acc.max()
        max_s = shadow_acc.max()
        if max_l > 0:
            light_acc  /= max_l
        if max_s > 0:
            shadow_acc /= max_s

        # Optional Gaussian blur to soften pool boundaries
        if blur_sigma > 0:
            light_acc  = ndimage.gaussian_filter(light_acc,  sigma=blur_sigma)
            shadow_acc = ndimage.gaussian_filter(shadow_acc, sigma=blur_sigma)

        light_acc  = light_acc.clip(0, 1)
        shadow_acc = shadow_acc.clip(0, 1)

        # ── Warm light shift ──────────────────────────────────────────────────
        lc = np.array(light_color,  dtype=np.float32)
        sc = np.array(shadow_color, dtype=np.float32)

        out = carr.copy()
        for c in range(3):
            # Blend each pixel toward light_color proportional to pool presence
            out[:, :, c] = (carr[:, :, c]
                            + (lc[c] - carr[:, :, c]) * light_acc  * light_intensity
                            + (sc[c] - carr[:, :, c]) * shadow_acc * shadow_intensity)
        out = out.clip(0.0, 1.0)

        # ── Specular impasto dot at each pool centre ──────────────────────────
        # A single very bright near-white dab at the pool core — the small
        # loaded-brush impasto mark that catches the eye in Sorolla's work.
        # Only placed when light is actually being applied (intensity > 0).
        if light_intensity > 0:
            spec_r = max(2, int(radius_px * 0.12))
            spec_c = np.array([1.00, 0.98, 0.90], dtype=np.float32)
            ys_g, xs_g = np.ogrid[:h, :w]
            for _ in range(min(n_pools, 12)):   # only the first 12 pools get specular dots
                idx = rng.randrange(len(bright_ys))
                cy  = int(bright_ys[idx])
                cx  = int(bright_xs[idx])
                dg  = (ys_g - cy) ** 2 + (xs_g - cx) ** 2
                within = dg <= spec_r ** 2
                for c in range(3):
                    out[:, :, c] = np.where(within,
                                            out[:, :, c] * 0.25 + spec_c[c] * 0.75,
                                            out[:, :, c])

        out = out.clip(0.0, 1.0)

        # ── Write back to Cairo surface ───────────────────────────────────────
        buf[:, :, 2] = np.clip(out[:, :, 0] * 255, 0, 255).astype(np.uint8)  # R→G2
        buf[:, :, 1] = np.clip(out[:, :, 1] * 255, 0, 255).astype(np.uint8)  # G→G1
        buf[:, :, 0] = np.clip(out[:, :, 2] * 255, 0, 255).astype(np.uint8)  # B→G0
        buf[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print("  Dappled light complete.")

    def glaze(self, color: Color, opacity: float = 0.10):
        """
        Step 6 — Final glaze.
        Thin transparent wash over the whole painting.
        Warms or cools the overall tone; unifies the palette.
        """
        print(f"Glazing  colour={color}  opacity={opacity:.0%}…")
        self.canvas.dry(1.0)
        self.canvas.glaze(color, opacity)

    def finish(self, vignette: float = 0.50, crackle: bool = True):
        """
        Final post-processing: vignette + aged-varnish crackle.
        """
        print("Finishing…")
        self.canvas.vignette(vignette)
        if crackle:
            print("  Adding crackle…")
            self.canvas.crackle()

    def save(self, path: str):
        self.canvas.save(path)

    def show(self, viewer: str = "inkscape"):
        import tempfile, subprocess
        tmp = tempfile.mktemp(suffix=".png", prefix="painting_")
        self.canvas.save(tmp)
        inkscape = r"C:\Program Files\Inkscape\bin\inkscape.exe"
        subprocess.Popen([inkscape, tmp])
        return tmp

    # ── Internal helpers ──────────────────────────────────────────────────────

    @staticmethod
    def _prep(img: Union[np.ndarray, Image.Image]) -> np.ndarray:
        """Ensure reference is a (H, W, 4) uint8 numpy array."""
        if isinstance(img, Image.Image):
            img = img.convert("RGBA")
            return np.array(img)
        if img.ndim == 3 and img.shape[2] == 3:
            return np.dstack([img,
                              np.full(img.shape[:2], 255, dtype=np.uint8)])
        return img.astype(np.uint8)

    @staticmethod
    def _to_value(ref: np.ndarray,
                  warm_tint: Color = (0.4, 0.32, 0.20)) -> np.ndarray:
        """
        Desaturate to luminosity and tint toward warm_tint.
        Used for the underpainting (dead-colour) layer.
        """
        f  = ref[:, :, :3].astype(np.float32) / 255.0
        lm = (0.299*f[:,:,0] + 0.587*f[:,:,1] + 0.114*f[:,:,2])
        wt = np.array(warm_tint, dtype=np.float32)
        out = np.zeros_like(f)
        for c in range(3):
            out[:, :, c] = np.clip(lm * 0.55 + wt[c] * 0.45, 0, 1)
        rgb  = (out * 255).astype(np.uint8)
        alph = ref[:, :, 3:4]
        return np.concatenate([rgb, alph], axis=2)

    # ── Improvement #10: non-linear drying curve ─────────────────────────────

    @staticmethod
    def _drying_curve(pass_index: int, total_passes: int,
                      early_dry: float = 0.88,
                      late_dry:  float = 0.42) -> float:
        """
        Return a canvas drying amount for the current pass in a sequence.

        Early passes (underpainting, block-in) dry quickly — bold marks need
        a firm foundation.  Later passes (glazing, sfumato) stay wetter longer
        so colour blends smoothly.  The transition follows a smooth cosine
        curve rather than a linear ramp so the change is barely perceptible
        in the mid-sequence passes.

        Parameters
        ----------
        pass_index   : 0-based index of the current pass.
        total_passes : Total number of passes in the session.
        early_dry    : canvas.dry() amount at pass 0 (fastest drying).
        late_dry     : canvas.dry() amount at the final pass (slowest drying).

        Returns a float suitable for canvas.dry(amount).
        """
        if total_passes <= 1:
            return early_dry
        t = pass_index / (total_passes - 1)            # 0.0 → 1.0
        # Cosine ease-in-out: slow at both ends, fastest change in the middle
        ease = 0.5 * (1.0 - math.cos(math.pi * t))
        return early_dry + (late_dry - early_dry) * ease

    # ── Composition helpers ───────────────────────────────────────────────────

    def _build_composition_map(self,
                               focal_xy:   tuple = None,
                               strength:   float = 0.6,
                               focal_pull: float = 0.0,
                               ) -> np.ndarray:
        """
        Build a composition weight map with soft peaks at rule-of-thirds and
        golden-ratio intersections, plus a focal point boost.

        Returns a (H, W) float32 array where values > 1.0 attract strokes and
        values < 1.0 repel them.  Mean is normalised to 1.0 so the map is a
        relative bias, not an absolute scale.

        Parameters
        ----------
        focal_xy   : (x, y) normalised focal point.  Extra tighter Gaussian
                     added at that position when provided.
        strength   : 0 = no compositional bias (returns uniform 1.0); 1 = full.
        focal_pull : Improvement #9.  Additional multiplier [0, 1] that blends
                     the error-driven component toward the composition map at
                     the _place_strokes call site.  This method only constructs
                     the map; the caller uses focal_pull to scale how much the
                     map overrides the error distribution.  Setting it here on
                     the stored self._comp_map amplifies its effect: values > 1
                     attract more, < 1 repel more, proportional to focal_pull.
                     0 = no amplification beyond `strength`.
        """
        w, h = self.w, self.h
        cmap = np.ones((h, w), dtype=np.float32)

        if strength < 1e-6:
            return cmap

        comp   = Composition(w, h)
        thirds = comp.thirds()
        golden = comp.golden()
        sigma  = min(w, h) * 0.12

        # Rule-of-thirds intersections: (x1,y1), (x1,y2), (x2,y1), (x2,y2)
        thirds_pts = [
            (thirds['x1'], thirds['y1']),
            (thirds['x1'], thirds['y2']),
            (thirds['x2'], thirds['y1']),
            (thirds['x2'], thirds['y2']),
        ]
        # Golden-ratio intersection: single point
        golden_pts = [(golden['x'], golden['y'])]

        ys, xs = np.ogrid[:h, :w]

        for gx, gy in thirds_pts + golden_pts:
            bump = np.exp(-((xs - gx) ** 2 + (ys - gy) ** 2) / (2.0 * sigma ** 2))
            cmap += bump.astype(np.float32)

        # Optional focal-point boost — stronger, tighter Gaussian
        if focal_xy is not None:
            fx = focal_xy[0] * w
            fy = focal_xy[1] * h
            sigma_f    = min(w, h) * 0.08
            focal_bump = 1.5 * np.exp(
                -((xs - fx) ** 2 + (ys - fy) ** 2) / (2.0 * sigma_f ** 2)
            )
            cmap += focal_bump.astype(np.float32)

        # Lerp between uniform 1.0 and the biased map according to strength
        cmap = 1.0 + (cmap - 1.0) * strength

        # Improvement #9: focal_pull amplifies the map's peaks and valleys so
        # _place_strokes' error * cmap product steers placement more strongly
        # toward compositionally significant zones.
        if focal_pull > 0.0:
            # Exponentiate: pull > 0 sharpens the Gaussian peaks vs flat areas.
            cmap = np.power(np.clip(cmap, 1e-6, None), 1.0 + focal_pull)

        # Normalise so the mean is 1.0 — preserves overall stroke density
        mean = cmap.mean()
        if mean > 1e-9:
            cmap /= mean

        # Clip: never suppress strokes entirely; never over-concentrate
        cmap = np.clip(cmap, 0.5, 3.5)
        return cmap.astype(np.float32)

    def _derive_focal_xy(self) -> tuple:
        """
        Derive the focal point as normalised (x, y) from the figure mask.

        Uses the centroid of the top 40% of the figure mask, which typically
        captures the head and upper-chest region.  Falls back to (0.50, 0.35)
        when no figure mask is loaded.
        """
        if self._figure_mask is None:
            return (0.50, 0.35)

        h, w = self._figure_mask.shape[:2]

        # Resize mask to canvas dimensions if needed
        if h != self.h or w != self.w:
            from PIL import Image as _PILImg
            m_img = _PILImg.fromarray((self._figure_mask * 255).astype(np.uint8))
            m_img = m_img.resize((self.w, self.h), _PILImg.NEAREST)
            mask = np.array(m_img, dtype=np.float32) / 255.0
            h, w = self.h, self.w
        else:
            mask = self._figure_mask

        # Crop to the top 40% of the canvas — head / upper-chest zone
        crop_h = int(h * 0.40)
        top_mask = mask[:crop_h, :]

        ys_nz, xs_nz = np.nonzero(top_mask > 0.5)
        if ys_nz.size == 0:
            # No figure pixels in the top region — fall back to default
            return (0.50, 0.35)

        cx = float(xs_nz.mean()) / w
        cy = float(ys_nz.mean()) / h
        return (cx, cy)

    # ── Atmospheric passes ────────────────────────────────────────────────────

    def _atmosphere_fog_pass(self,
                             atmosphere: float,
                             fog_color:  tuple = (0.85, 0.88, 0.92)):
        """
        Apply atmospheric haze to background pixels only.

        atmosphere : 0.0 = clear, 1.0 = heavy fog.
        fog_color  : RGB (float) of the haze colour.  Default is a cool
                     atmospheric blue-grey reminiscent of aerial perspective.

        Only modifies pixels outside the figure mask.  If no mask is set,
        the haze is applied uniformly (background-only behaviour is preserved
        wherever a mask exists).
        """
        if atmosphere < 0.01:
            return

        print(f"  Atmosphere fog pass  (atmosphere={atmosphere:.2f}  "
              f"fog={fog_color})")

        h, w = self.h, self.w
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(h, w, 4).copy()
        # Cairo ARGB32 stores pixels as BGRA in memory
        R = buf[:, :, 2].astype(np.float32) / 255.0
        G = buf[:, :, 1].astype(np.float32) / 255.0
        B = buf[:, :, 0].astype(np.float32) / 255.0

        # Background mask: 1.0 where no figure, 0.0 over figure
        if self._figure_mask is not None:
            fig = self._figure_mask
            if fig.shape != (h, w):
                from PIL import Image as _PILImg
                m_img = _PILImg.fromarray((fig * 255).astype(np.uint8))
                fig = np.array(m_img.resize((w, h), _PILImg.NEAREST),
                               dtype=np.float32) / 255.0
            bg_mask = 1.0 - fig
        else:
            bg_mask = np.ones((h, w), dtype=np.float32)

        # Blend coefficient: atmosphere * bg_mask, scaled to 0.7 max
        t = np.clip(atmosphere * bg_mask * 0.7, 0.0, 1.0)

        fr, fg, fb = fog_color

        # Slight Gaussian blur in background only — depth-of-field haze
        if atmosphere > 0.05:
            sigma = atmosphere * 2.5
            R_blurred = ndimage.gaussian_filter(R, sigma=sigma)
            G_blurred = ndimage.gaussian_filter(G, sigma=sigma)
            B_blurred = ndimage.gaussian_filter(B, sigma=sigma)
            # Only use blurred values in background region
            R = R + bg_mask * (R_blurred - R)
            G = G + bg_mask * (G_blurred - G)
            B = B + bg_mask * (B_blurred - B)

        # Blend toward fog colour in background
        R_out = R * (1.0 - t) + fr * t
        G_out = G * (1.0 - t) + fg * t
        B_out = B * (1.0 - t) + fb * t

        # Write back (BGRA layout)
        buf[:, :, 2] = np.clip(R_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(G_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 0] = np.clip(B_out * 255, 0, 255).astype(np.uint8)

        surface_data = self.canvas.surface.get_data()
        surface_buf  = np.frombuffer(surface_data, dtype=np.uint8).reshape(h, w, 4)
        surface_buf[:] = buf

    def background_environment_pass(self,
                                     ref:         np.ndarray,
                                     env_type:    str,
                                     description: str   = "",
                                     atmosphere:  float = 0.0):
        """
        Paint an environment-specific background behind the figure.

        Strokes are placed only in the background region (outside the figure
        mask).  If no figure mask is loaded the pass has no effect.

        Parameters
        ----------
        ref         : Reference image array (H, W, 3/4 uint8).
        env_type    : One of 'INTERIOR', 'EXTERIOR', 'LANDSCAPE', 'ABSTRACT'.
        description : Optional scene description (not used by current branches
                      but available for future narrative-driven colour sampling).
        atmosphere  : 0.0 = clear, 1.0 = heavy fog.  Passed to
                      _atmosphere_fog_pass() after painting.
        """
        if self._figure_mask is None:
            return

        print(f"  Background environment pass  (env_type={env_type}  "
              f"atmosphere={atmosphere:.2f})")

        ref_arr = self._prep(ref)
        h, w    = self.h, self.w
        bg_mask = 1.0 - self._figure_mask

        rarr = ref_arr[:, :, :3].astype(np.float32) / 255.0

        if env_type == "INTERIOR":
            # Warm, enclosed space: architectural recession lines + floor gradient
            # + ambient warm light on one side.

            # Large atmospheric strokes in warm shadow tones
            self._place_strokes(
                ref_arr,
                stroke_size  = 75,
                n_strokes    = 40,
                opacity      = 0.30,
                wet_blend    = 0.10,
                jitter_amt   = 0.025,
                curvature    = 0.02,
                tip          = BrushTip(BrushTip.FLAT),
                stroke_mask  = bg_mask,
            )

            # Floor plane suggestion — horizontal gradient darkening at bottom third.
            # We paint opaque dark strokes across the lower background region.
            floor_mask = bg_mask.copy()
            floor_y0 = int(h * 0.65)
            floor_mask[:floor_y0, :] = 0.0   # only active below 65% height

            buf = np.frombuffer(self.canvas.surface.get_data(),
                                dtype=np.uint8).reshape(h, w, 4).copy()
            for row in range(floor_y0, h):
                # Darkening ramp: 0 at floor_y0, max at bottom
                t_floor = (row - floor_y0) / max(1, h - floor_y0)
                darken  = t_floor * 0.18
                for ch, bgra_idx in ((0, 2), (1, 1), (2, 0)):
                    col_arr = buf[row, :, bgra_idx].astype(np.float32) / 255.0
                    col_arr = np.clip(col_arr * (1.0 - darken * bg_mask[row, :]),
                                      0.0, 1.0)
                    buf[row, :, bgra_idx] = (col_arr * 255).astype(np.uint8)
            surface_data = self.canvas.surface.get_data()
            surface_buf  = np.frombuffer(surface_data,
                                         dtype=np.uint8).reshape(h, w, 4)
            surface_buf[:] = buf

            # Warm ambient light on left side — lighter strokes on the left
            left_mask = bg_mask.copy()
            left_mask[:, w//2:] = 0.0    # left half only
            self._place_strokes(
                ref_arr,
                stroke_size  = 85,
                n_strokes    = 20,
                opacity      = 0.25,
                wet_blend    = 0.12,
                jitter_amt   = 0.020,
                curvature    = 0.03,
                tip          = BrushTip(BrushTip.FLAT),
                stroke_mask  = left_mask,
                override_color = (0.78, 0.64, 0.45),   # warm amber ambient
            )

        elif env_type in ("EXTERIOR", "LANDSCAPE"):
            # Sky / horizon / ground three-zone treatment.

            sky_mask    = bg_mask.copy()
            horizon_mask = bg_mask.copy()
            ground_mask  = bg_mask.copy()

            sky_y1     = int(h * 0.45)
            horizon_y0 = int(h * 0.40)
            horizon_y1 = int(h * 0.55)
            ground_y0  = int(h * 0.55)

            sky_mask[sky_y1:, :]     = 0.0
            horizon_mask[:horizon_y0, :] = 0.0
            horizon_mask[horizon_y1:, :] = 0.0
            ground_mask[:ground_y0, :]   = 0.0

            # Sky: broad horizontal strokes, light airy tones
            sky_color = (0.62, 0.76, 0.88)   # pale blue sky
            self._place_strokes(
                ref_arr,
                stroke_size   = 90,
                n_strokes     = 10,
                opacity       = 0.35,
                wet_blend     = 0.14,
                jitter_amt    = 0.018,
                curvature     = 0.01,
                tip           = BrushTip(BrushTip.FLAT),
                stroke_mask   = sky_mask,
                override_color = sky_color,
            )

            # Horizon: atmospheric haze blending sky into ground
            horizon_color = (0.72, 0.74, 0.70)   # neutral mid-tone haze
            self._place_strokes(
                ref_arr,
                stroke_size   = 80,
                n_strokes     = 6,
                opacity       = 0.30,
                wet_blend     = 0.16,
                jitter_amt    = 0.020,
                curvature     = 0.01,
                tip           = BrushTip(BrushTip.FLAT),
                stroke_mask   = horizon_mask,
                override_color = horizon_color,
            )

            # Ground: darker, warmer strokes
            ground_color = (0.42, 0.38, 0.28)   # earth tone
            self._place_strokes(
                ref_arr,
                stroke_size   = 80,
                n_strokes     = 8,
                opacity       = 0.38,
                wet_blend     = 0.12,
                jitter_amt    = 0.022,
                curvature     = 0.02,
                tip           = BrushTip(BrushTip.FLAT),
                stroke_mask   = ground_mask,
                override_color = ground_color,
            )

            # LANDSCAPE only: atmospheric mid-tone suggesting distant hills
            if env_type == "LANDSCAPE":
                hill_mask = bg_mask.copy()
                hill_y0 = int(h * 0.40)
                hill_y1 = int(h * 0.50)
                hill_mask[:hill_y0, :] = 0.0
                hill_mask[hill_y1:, :] = 0.0
                hill_color = (0.48, 0.56, 0.50)   # cool atmospheric hill green
                self._place_strokes(
                    ref_arr,
                    stroke_size   = 70,
                    n_strokes     = 5,
                    opacity       = 0.40,
                    wet_blend     = 0.14,
                    jitter_amt    = 0.025,
                    curvature     = 0.04,
                    tip           = BrushTip(BrushTip.FLAT),
                    stroke_mask   = hill_mask,
                    override_color = hill_color,
                )

        else:
            # ABSTRACT / fallback: large atmospheric strokes, no theme.
            self._place_strokes(
                ref_arr,
                stroke_size = 60,
                n_strokes   = 60,
                opacity     = 0.40,
                wet_blend   = 0.10,
                jitter_amt  = 0.020,
                curvature   = 0.04,
                tip         = BrushTip(BrushTip.FLAT),
                stroke_mask = bg_mask,
            )

        # Apply atmospheric fog on top of the painted background
        if atmosphere > 0.01:
            self._atmosphere_fog_pass(atmosphere)

    def _place_strokes(self,
                       ref:                 np.ndarray,
                       stroke_size:         float,
                       n_strokes:           int,
                       opacity:             float,
                       wet_blend:           float,
                       jitter_amt:          float,
                       curvature:           float,
                       tip:                 Union[BrushTip, BrushProfile],
                       stroke_mask:         Optional[np.ndarray] = None,
                       override_color:      Optional[Color]      = None,
                       composition_map:     Optional[np.ndarray] = None,
                       # ── Improvement #2 — lognormal size distribution ──────
                       size_sigma:          float = 0.40,
                       # ── Improvement #3 — depth / atmospheric perspective ──
                       depth_field:         Optional[np.ndarray] = None,
                       depth_size_scale:    float = 0.55,   # min size at max depth
                       depth_opacity_scale: float = 0.65,   # min opacity at max depth
                       depth_cool_amount:   float = 0.14,   # max cool shift at horizon
                       # ── Improvement #4 — light-coherent color ────────────
                       light_pos:           Optional[Tuple[float, float]] = None,
                       light_warmth:        float = 0.15,   # max warm shift at source
                       # ── Improvement #6 — anti-clustering ─────────────────
                       min_spacing:         float = 0.0,    # px; 0 = disabled
                       # ── Improvement #7 — imprimatura reveal ──────────────
                       imprimatura_reveal:  float = 0.0,    # [0, 0.25] fraction skip
                       # ── Improvement #8 — complexity-scaled n_strokes ─────
                       complexity_scale:    bool  = False,
                       # ── Improvement #11 — palette harmony snapping ────────
                       palette_colors:      Optional[List[Color]] = None,
                       harmony_snap:        float = 0.0,   # [0, 1]; 0 = off
                       # ── Brush system v2 ───────────────────────────────────
                       pressure_profile:    Optional[PressureProfile] = None,
                       paint_load:          Optional[PaintLoad]       = None,
                       brush_profile:       Optional[BrushProfile]    = None,
                       ):
        """
        Core stroke placement loop.

        Positions are sampled from the guided-filtered error map (canvas vs
        reference) so strokes concentrate where most improvement is needed,
        while respecting object edges in the reference image.

        Parameters
        ----------
        stroke_mask    : (H, W) float32 in [0,1].  Stroke centres sampled only
                         inside the mask; eroded by stroke half-reach to prevent
                         boundary crossing.  Each segment is clipped at the mask.
        override_color : Fixed RGB for cel-shading passes (toon_paint).
        composition_map: (H, W) float32 bias field.  >1 attracts, <1 repels.
                         Falls back to self._comp_map when None.
        size_sigma     : Lognormal σ for per-stroke size variation.  0 = old
                         uniform belt (±55%).  0.40 gives a natural power-law
                         spread so a few large marks coexist with many small ones.
        depth_field    : (H, W) float32 in [0,1]; 0=near, 1=far.  When set,
                         far strokes are smaller, cooler, and more transparent
                         (atmospheric perspective).
        light_pos      : (x, y) normalised light source position.  Strokes near
                         the source receive a warm temperature shift; far strokes
                         are cool.  Physically consistent with place_lights().
        min_spacing    : Minimum pixel distance between stroke centres in this
                         pass.  Reduces accidental clumping in uniform regions.
        imprimatura_reveal : Probability [0, 0.25] that a stroke is skipped so
                             the toned ground shows through — Titian's technique.
        complexity_scale   : If True, adjust n_strokes by the spatial-frequency
                             complexity of the active region so busy areas get
                             more coverage than flat zones.
        """
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        # Canvas current state
        cbuf = np.frombuffer(self.canvas.surface.get_data(),
                             dtype=np.uint8).reshape(h, w, 4).copy()
        carr = cbuf[:, :, [2, 1, 0]].astype(np.float32) / 255.0

        # ── Error map ────────────────────────────────────────────────────────
        err = np.mean(np.abs(carr - rarr), axis=2).astype(np.float32)
        # Improvement #1: guided filter preserves object edges in placement.
        guide_lum = (0.299 * rarr[:, :, 0] +
                     0.587 * rarr[:, :, 1] +
                     0.114 * rarr[:, :, 2]).astype(np.float32)
        gf_radius = max(1, int(stroke_size * 0.45))
        err = guided_filter(err, guide_lum, radius=gf_radius, eps=0.005)

        # ── Region masking ───────────────────────────────────────────────────
        region_mask_for_draw = None
        if stroke_mask is not None:
            binary    = (stroke_mask > 0.5)
            erosion_r = max(1, int(stroke_size * 1.4))
            struct    = np.ones((erosion_r * 2 + 1, erosion_r * 2 + 1), dtype=bool)
            eroded    = ndimage.binary_erosion(binary, structure=struct)
            err       = err * eroded.astype(np.float32)
            region_mask_for_draw = stroke_mask.astype(np.float32)

        # ── Composition map ──────────────────────────────────────────────────
        _cmap = composition_map if composition_map is not None else self._comp_map
        if _cmap is not None:
            err = err * _cmap

        err_flat = err.flatten()
        total    = err_flat.sum()
        if total < 1e-9:
            return   # mask too small / nothing to paint
        prob = err_flat / total

        # ── Improvement #8: complexity-based stroke count ────────────────────
        # Busier regions (high spatial frequency) warrant more coverage.
        if complexity_scale:
            gy, gx    = np.gradient(guide_lum)
            grad_mag  = np.sqrt(gx ** 2 + gy ** 2)
            if stroke_mask is not None:
                active_grad = grad_mag[stroke_mask > 0.5]
            else:
                active_grad = grad_mag.ravel()
            complexity = float(np.mean(active_grad)) if active_grad.size else 0.0
            max_comp   = float(np.percentile(grad_mag, 95)) + 1e-8
            comp_ratio = float(np.clip(complexity / max_comp, 0.3, 1.0))
            n_strokes  = max(1, int(n_strokes * (0.45 + 0.55 * comp_ratio)))

        # ── Stroke direction field ───────────────────────────────────────────
        angles = flow_field(rarr)

        # ── Sample positions ─────────────────────────────────────────────────
        positions = self.rng.choice(h * w, size=n_strokes,
                                    p=prob, replace=True)

        # ── Improvement #2: lognormal length distribution ────────────────────
        if size_sigma > 0.0:
            log_mean = math.log(stroke_size * 2.2)   # median length
            lengths  = np.exp(self.rng.normal(log_mean, size_sigma, n_strokes))
            lengths  = np.clip(lengths, stroke_size * 0.8, stroke_size * 5.0)
        else:
            lengths  = stroke_size * self.rng.uniform(1.6, 3.2, n_strokes)

        # ── Light source vector (normalised canvas coords) ───────────────────
        light_cx = float(light_pos[0]) * w if light_pos is not None else None
        light_cy = float(light_pos[1]) * h if light_pos is not None else None
        max_dist  = math.sqrt(w * w + h * h) + 1e-8  # for normalisation

        # ── Anti-clustering state ─────────────────────────────────────────────
        placed_centres: List[Tuple[int, int]] = []
        min_spacing_sq = min_spacing * min_spacing

        for i, pos in enumerate(positions):
            py, px = int(pos // w), int(pos % w)
            margin = max(4, int(stroke_size * 1.8))
            px = int(np.clip(px, margin, w - margin))
            py = int(np.clip(py, margin, h - margin))

            # ── Improvement #7: imprimatura reveal ───────────────────────────
            # Skip a fraction of strokes so the toned ground shows through.
            if imprimatura_reveal > 0.0 and \
                    self._rng_py.random() < imprimatura_reveal:
                continue

            # ── Improvement #6: anti-clustering ─────────────────────────────
            if min_spacing > 0.0 and placed_centres:
                too_close = any(
                    (px - cx) ** 2 + (py - cy) ** 2 < min_spacing_sq
                    for cx, cy in placed_centres
                )
                if too_close:
                    continue
            placed_centres.append((px, py))

            # ── Per-stroke size (lognormal for width too) ────────────────────
            if size_sigma > 0.0:
                log_w_mean = math.log(max(0.5, stroke_size))
                w_val = float(np.clip(
                    math.exp(self._rng_py.gauss(log_w_mean, size_sigma * 0.6)),
                    stroke_size * 0.35, stroke_size * 2.2,
                ))
            else:
                w_val = stroke_size * self._rng_py.uniform(0.55, 1.15)

            # ── Improvement #3: depth-field modulation ───────────────────────
            stroke_opacity = opacity
            eff_w_val      = w_val
            depth_val      = 0.0
            if depth_field is not None:
                depth_val     = float(depth_field[py, px])
                # Far objects: smaller, less opaque
                size_t        = 1.0 - depth_val * (1.0 - depth_size_scale)
                eff_w_val     = w_val * size_t
                stroke_opacity = opacity * (1.0 - depth_val * (1.0 - depth_opacity_scale))

            # ── Color sampling ───────────────────────────────────────────────
            if override_color is not None:
                col = jitter(override_color, jitter_amt, self._rng_py)
            else:
                col = tuple(float(rarr[py, px, c]) for c in range(3))
                col = jitter(col, jitter_amt, self._rng_py)

            # ── Improvement #11: palette harmony snapping ────────────────────
            # Gently nudge sampled color toward nearest harmony palette entry
            # so adjacent strokes share hue family without losing local detail.
            if palette_colors and harmony_snap > 0.0:
                col = snap_to_harmony(col, palette_colors, harmony_snap)

            # ── Improvement #3 cont.: atmospheric cool shift for far objects ─
            if depth_field is not None and depth_val > 0.05:
                col = temp_shift(col, -depth_val * depth_cool_amount)

            # ── Improvement #4: light-coherent warm/cool shift ───────────────
            if light_cx is not None:
                dist_to_light = math.sqrt(
                    (px - light_cx) ** 2 + (py - light_cy) ** 2
                )
                # Proximity [0,1]: 1 = at light source, 0 = far away
                proximity   = 1.0 - min(1.0, dist_to_light / (max_dist * 0.55))
                warmth_amt  = proximity * light_warmth
                # Attenuate warm boost in far/atmospheric zones
                if depth_field is not None:
                    warmth_amt *= (1.0 - depth_val * 0.5)
                col = temp_shift(col, warmth_amt)

            # ── Stroke geometry ──────────────────────────────────────────────
            # Direction field angle + small jitter (tighter than before so
            # strokes follow form more faithfully — improvement #6).
            a     = float(angles[py, px]) + self._rng_py.uniform(-0.18, 0.18)
            L     = lengths[i]
            # Scale length proportionally when depth shrinks the stroke
            if depth_field is not None:
                L *= (1.0 - depth_val * (1.0 - depth_size_scale))
            start = (px - math.cos(a) * L * 0.5, py - math.sin(a) * L * 0.5)

            n_pts = max(4, int(L / 5))
            pts   = stroke_path(start, a, L,
                                curve=self._rng_py.uniform(-curvature, curvature),
                                n=n_pts)
            ws    = [eff_w_val] * len(pts)

            effective_tip = brush_profile if brush_profile is not None else tip
            self.canvas.apply_stroke(pts, ws, col, effective_tip,
                                     opacity=stroke_opacity,
                                     wet_blend=wet_blend,
                                     jitter_amt=jitter_amt,
                                     rng=self._rng_py,
                                     region_mask=region_mask_for_draw,
                                     pressure_profile=pressure_profile,
                                     paint_load=paint_load)

        # ── Edge treatment ─────────────────────────────────────────────────────────
        # full_coverage: paint the border strip that the erosion + margin clamp leaves
        # empty.  overpainting uses a wider strip.  natural_border (default) skips.
        if getattr(self, 'edge_treatment', 'natural_border') != 'natural_border':
            bw = max(4, int(stroke_size * 2.0))
            if self.edge_treatment == 'overpainting':
                bw = int(bw * 2)

            edge_wt = np.zeros((h, w), dtype=np.float32)
            edge_wt[:bw, :]  = 1.0
            edge_wt[-bw:, :] = 1.0
            edge_wt[:, :bw]  = 1.0
            edge_wt[:, -bw:] = 1.0

            if stroke_mask is not None:
                edge_wt *= stroke_mask
            edge_err   = err * edge_wt
            edge_total = float(edge_err.sum())
            if edge_total > 1e-9:
                edge_prob = (edge_err / edge_total).flatten()
                n_edge    = max(1, n_strokes // 4)
                edge_pos  = self.rng.choice(h * w, size=n_edge,
                                             p=edge_prob, replace=True)
                for pos in edge_pos:
                    ey, ex = int(pos // w), int(pos % w)
                    ex = int(np.clip(ex, 1, w - 2))
                    ey = int(np.clip(ey, 1, h - 2))

                    if override_color is not None:
                        ecol = jitter(override_color, jitter_amt, self._rng_py)
                    else:
                        ecol = tuple(float(rarr[ey, ex, c]) for c in range(3))
                        ecol = jitter(ecol, jitter_amt, self._rng_py)

                    ea    = float(angles[ey, ex]) + self._rng_py.uniform(-0.25, 0.25)
                    eL    = stroke_size * self._rng_py.uniform(0.9, 2.2)
                    estart = (ex - math.cos(ea) * eL * 0.5,
                              ey - math.sin(ea) * eL * 0.5)
                    epts  = stroke_path(estart, ea, eL,
                                        curve=self._rng_py.uniform(
                                            -curvature * 0.5, curvature * 0.5),
                                        n=max(3, int(eL / 5)))
                    ews   = [stroke_size * self._rng_py.uniform(0.55, 1.10)] * len(epts)

                    eff_t = brush_profile if brush_profile is not None else tip
                    self.canvas.apply_stroke(
                        epts, ews, ecol, eff_t,
                        opacity=opacity,
                        wet_blend=wet_blend * 0.8,
                        jitter_amt=jitter_amt,
                        rng=self._rng_py,
                        region_mask=(stroke_mask.astype(np.float32)
                                     if stroke_mask is not None else None),
                        pressure_profile=pressure_profile,
                        paint_load=paint_load)

    def color_field_pass(self,
                         reference:              Union[np.ndarray, Image.Image],
                         n_bands:                int   = 3,
                         n_washes:               int   = 14,
                         wash_opacity:           float = 0.16,
                         edge_blur_sigma:        float = 0.0,
                         figure_preserve:        float = 0.60,
                         chromatic_vibration:    float = 0.035,
                         band_hue_drift:         float = 0.018):
        """
        Color Field pass — inspired by Mark Rothko.

        Rothko's mature paintings from the 1950s–60s consist of two or three
        large horizontal rectangles of colour that appear to float against a
        dark absorbing ground.  The rectangles have no hard edge — their
        boundaries are built up over many (often 15–20) thin transparent washes
        applied wet-into-wet, so the colour seems to emerge from within the
        canvas rather than sitting on top of it.  The result is a luminous,
        breathing quality that no single opaque stroke can achieve.

        Key perceptual mechanisms Rothko exploited:

          1. **Simultaneous contrast** — adjacent bands are chosen from opposite
             ends of the warm/cool spectrum so each makes the other appear more
             intense than it actually is.

          2. **Dark absorbing void** — the ground and lower band are very dark,
             making upper lighter bands appear self-luminous by comparison.

          3. **Optical layering** — each wash is semi-transparent; the light
             shifts wavelength as it passes through each layer, bounces off the
             canvas, and passes back out through all the layers.  This creates
             a depth and warmth that cannot be replicated by flat opaque paint.

          4. **Chromatic vibration at the edge** — the boundary zone between two
             bands contains both colours at once, creating a narrow fringe that
             visually vibrates.  Rothko described this as "the breath of the
             painting."

        This pass:
          Stage 1 — Analyse the reference image.  Divide it into `n_bands`
                    horizontal strips and compute the mean colour of each strip,
                    biased toward the dominant hue of that zone.

          Stage 2 — Apply `n_washes` thin Cairo rectangle washes per band,
                    each wash slightly shifting hue/value so the accumulated
                    colour has depth and variation.  The band boundaries are
                    feathered using a per-row opacity falloff (Gaussian profile).

          Stage 3 — Chromatic vibration pass.  At each band boundary, composite
                    an additional thin wash of the complementary colour mixed
                    from both adjacent bands.  This brightens the boundary
                    perceptually while remaining physically thin.

          Stage 4 — If `figure_preserve` > 0, blend the painted color field with
                    the underlying canvas (which holds the standard oil underpainting
                    that blender_bridge runs before this pass), so the figure remains
                    recognisable as a warmth or luminosity within the field rather
                    than being completely erased.

        Parameters
        ----------
        reference           : PIL Image or ndarray.
        n_bands             : Number of horizontal color bands (Rothko typically
                              used 2–4; 3 is canonical).
        n_washes            : Washes applied per band.  More = more optical depth.
                              12–18 is the practical sweet spot.
        wash_opacity        : Opacity of each individual wash.  Cumulative effect
                              of `n_washes` washes is approximately
                              1 - (1 - wash_opacity)^n_washes.
        edge_blur_sigma     : Additional Gaussian blur applied to each band mask
                              beyond the intrinsic Gaussian falloff (pixels).
                              0 = rely only on the Gaussian profile; values of
                              20–60 create very soft dissolution.
        figure_preserve     : How much of the pre-existing canvas (typically the
                              oil underpainting) to blend back in [0–1].  0 = pure
                              color field erases the figure; 1 = color field has no
                              effect.  0.55–0.70 gives Rothko-like results where
                              you sense a form within the field without defining it.
        chromatic_vibration : Opacity of the boundary vibration wash.
                              0.03–0.06 gives a subtle shimmer; 0 disables it.
        band_hue_drift      : Per-wash hue rotation (HSV) applied cumulatively so
                              successive washes shift the band's colour slightly.
                              Models Rothko's deliberate hue shifts between layers.

        Notes
        -----
        Mark Rothko (1903–1970) was born Marcus Rothkowitz in Dvinsk, Latvia.
        He emigrated to the United States at age 10.  After years of surrealist
        influence he arrived at his signature "Multiform" and then pure Color
        Field style around 1950.  He rejected interpretation and said his
        paintings were about "basic human emotions — tragedy, ecstasy, doom."
        He insisted his works be hung close to the floor and experienced at
        close range so the viewer is enveloped rather than distanced.

        The Rothko Chapel in Houston (1971) contains 14 large paintings he
        made for the space.  He died by suicide on 25 February 1970, at 66,
        before the chapel opened.

        Famous works:
          *No. 61 (Rust and Blue)* (1953) — rust band over deep blue void.
          *Orange, Red, Yellow* (1961) — sold for $86.9M in 2012; warm chromatic field.
          *Black on Maroon* (1958) — Seagram mural; near-black dissolving geometry.
        """
        print(f"Color field pass  (n_bands={n_bands}  n_washes={n_washes}"
              f"  opacity/wash={wash_opacity:.2f})…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        # ── Stage 1: Sample dominant colour per horizontal strip ──────────────
        # Each band covers an equal fraction of image height.  Mean colour is
        # computed over all pixels in the strip (in float [0, 1] space).
        band_colors: List[Color] = []
        band_y_centers: List[float] = []
        for b in range(n_bands):
            y0 = int(b * h / n_bands)
            y1 = int((b + 1) * h / n_bands)
            strip = rarr[y0:y1, :, :]          # (strip_h, W, 3)
            mean_col = strip.reshape(-1, 3).mean(axis=0)
            band_colors.append((float(mean_col[0]),
                                 float(mean_col[1]),
                                 float(mean_col[2])))
            band_y_centers.append((y0 + y1) * 0.5)

        # ── Save pre-pass canvas snapshot for figure_preserve blending ────────
        # Read the current canvas into a float array so we can blend it back in
        # during Stage 4.  This captures whatever underpainting was run first.
        if figure_preserve > 0.0:
            pre_buf = np.frombuffer(self.canvas.surface.get_data(),
                                    dtype=np.uint8).reshape(h, w, 4).copy()
            # BGRA → RGB float
            pre_rgb = pre_buf[:, :, [2, 1, 0]].astype(np.float32) / 255.0
        else:
            pre_rgb = None

        # ── Stage 2: Band washes ──────────────────────────────────────────────
        # For each band, apply n_washes thin Cairo rectangle composites.
        # Opacity is modulated by a Gaussian weight that peaks at the band
        # centre and falls to ~5% at the adjacent band centres — creating the
        # feathered dissolution that defines Rothko's edge language.
        #
        # band_sigma: standard deviation of the Gaussian in image pixels.
        # For 3 bands across height H, each band is H/3 tall, so sigma ≈ H/6.
        band_sigma = h / (n_bands * 2.2)   # Gaussian half-width ≈ one half-band

        ys_all = np.arange(h, dtype=np.float32)

        for b, (base_col, cy_b) in enumerate(zip(band_colors, band_y_centers)):
            print(f"  Band {b+1}/{n_bands}: ({base_col[0]:.2f}, {base_col[1]:.2f},"
                  f" {base_col[2]:.2f})  cy={cy_b:.0f}px…")

            # Per-row Gaussian weight for this band
            gauss_weights = np.exp(-0.5 * ((ys_all - cy_b) / band_sigma) ** 2)

            if edge_blur_sigma > 0.0:
                gauss_weights = ndimage.gaussian_filter1d(
                    gauss_weights, sigma=edge_blur_sigma)
            gauss_weights = np.clip(gauss_weights, 0.0, 1.0)

            # Iterative hue-drift wash loop
            h_hsv, s_hsv, v_hsv = colorsys.rgb_to_hsv(*base_col)
            for wash_i in range(n_washes):
                # Cumulative hue drift — each wash shifted slightly
                h_drift = (h_hsv + wash_i * band_hue_drift) % 1.0
                # Value alternates slightly: even washes slightly lighter,
                # odd washes slightly darker — mimics the oscillation of a
                # loaded brush vs. a drawing-back stroke.
                v_drift = max(0.02, min(1.0,
                    v_hsv + 0.015 * math.sin(wash_i * 1.47)))
                wash_r, wash_g, wash_b = colorsys.hsv_to_rgb(h_drift, s_hsv, v_drift)
                wash_r = float(np.clip(wash_r + self._rng_py.uniform(-0.005, 0.005), 0, 1))
                wash_g = float(np.clip(wash_g + self._rng_py.uniform(-0.005, 0.005), 0, 1))
                wash_b = float(np.clip(wash_b + self._rng_py.uniform(-0.005, 0.005), 0, 1))

                # Draw a full-width rectangle at each row, with per-row alpha
                # = wash_opacity * gauss_weight[y].  Cairo's set_source_rgba
                # applies a single alpha; we vary by row by iterating over rows
                # in chunks or per-pixel.  For efficiency we batch by rounding
                # gauss_weights to 4-decimal precision and group consecutive rows.
                ctx = self.canvas.ctx
                for row_y in range(h):
                    row_alpha = wash_opacity * float(gauss_weights[row_y])
                    if row_alpha < 0.002:
                        continue
                    ctx.set_source_rgba(wash_r, wash_g, wash_b, row_alpha)
                    ctx.rectangle(0.0, float(row_y), float(w), 1.0)
                    ctx.fill()

        # ── Stage 3: Chromatic vibration at band boundaries ───────────────────
        # Between each pair of adjacent bands, compute a boundary colour as the
        # mean of the two bands, then shift it toward the complement of whichever
        # band dominates at the boundary.  Apply a narrow Gaussian wash.
        if chromatic_vibration > 0.0:
            print("  Chromatic vibration pass…")
            boundary_sigma = band_sigma * 0.22   # very narrow fringe

            for b in range(n_bands - 1):
                by = (band_y_centers[b] + band_y_centers[b + 1]) * 0.5
                col_a = band_colors[b]
                col_b = band_colors[b + 1]
                # Mean colour at the boundary
                mid_col = ((col_a[0] + col_b[0]) * 0.5,
                           (col_a[1] + col_b[1]) * 0.5,
                           (col_a[2] + col_b[2]) * 0.5)
                # Shift toward complement to create perceptual shimmer
                comp_col = complement(mid_col)
                vib_col  = mix_paint(mid_col, comp_col, 0.25)

                vib_gauss = np.exp(-0.5 * ((ys_all - by) / boundary_sigma) ** 2)
                vib_gauss = np.clip(vib_gauss, 0.0, 1.0)

                ctx = self.canvas.ctx
                for row_y in range(h):
                    row_alpha = chromatic_vibration * float(vib_gauss[row_y])
                    if row_alpha < 0.002:
                        continue
                    ctx.set_source_rgba(vib_col[0], vib_col[1], vib_col[2], row_alpha)
                    ctx.rectangle(0.0, float(row_y), float(w), 1.0)
                    ctx.fill()

        # ── Stage 4: Figure preserve — blend pre-pass canvas back in ─────────
        # Composite pre_rgb (the underpainting/reference pass canvas) at
        # `figure_preserve` opacity over the color field.  This lets the figure
        # remain recognisable as a luminous warmth within the field.
        if pre_rgb is not None and figure_preserve > 0.0:
            print(f"  Figure preserve blend  ({figure_preserve:.0%})…")
            ctx = self.canvas.ctx

            # Re-bake pre_rgb into a cairo surface and composite at figure_preserve
            pre_arr = np.zeros((h, w, 4), dtype=np.uint8)
            pre_arr[:, :, 2] = np.clip(pre_rgb[:, :, 0] * 255, 0, 255).astype(np.uint8)  # R→BGRA
            pre_arr[:, :, 1] = np.clip(pre_rgb[:, :, 1] * 255, 0, 255).astype(np.uint8)
            pre_arr[:, :, 0] = np.clip(pre_rgb[:, :, 2] * 255, 0, 255).astype(np.uint8)
            pre_arr[:, :, 3] = 255

            pre_surf = cairo.ImageSurface.create_for_data(
                bytearray(pre_arr.tobytes()), cairo.FORMAT_ARGB32, w, h)

            ctx.set_source_surface(pre_surf, 0, 0)
            ctx.paint_with_alpha(figure_preserve)

        # Dampen wetness after color field — the vast washes add significant wet
        # surface; let them dry partially before any subsequent stroke passes.
        self.canvas.wetness *= 0.30

    # ── El Greco Mannerist technique ──────────────────────────────────────────

    def elongation_distortion_pass(
            self,
            reference:          Union[np.ndarray, Image.Image],
            elongation_factor:  float = 0.15,
            figure_mask:        Optional[np.ndarray] = None,
            jewel_boost:        float = 1.30,
            inner_glow_radius:  float = 14.0,
            inner_glow_opacity: float = 0.22,
            glow_color:         Color = (0.88, 0.86, 0.80),
    ) -> None:
        """
        El Greco Mannerist elongation pass.

        Three-stage technique inspired by Domenikos Theotokopoulos (El Greco):

        Stage 1 — Figure elongation
            Reads the current canvas buffer.  In the figure region (defined by
            figure_mask or the whole canvas if None), compresses source rows
            over a larger destination range to vertically stretch forms.  The
            elongation is soft-weighted at top and bottom so faces and feet
            don't warp — only the torso and limbs receive maximum stretch.
            This mimics El Greco's characteristic spiritual lengthening where
            figures seem to aspire upward beyond anatomical possibility.

        Stage 2 — Jewel-tone saturation boost
            Converts the canvas buffer to HSV, multiplies saturation by
            `jewel_boost`, and writes back.  El Greco's palette is famous for
            its jewel-like intensity: vermilion, cerulean, lemon, viridian —
            colours that vibrate rather than harmonise.

        Stage 3 — Inner-glow on pale flesh
            Identifies canvas pixels whose luminance exceeds 0.72 (the pale
            silver-grey flesh zones that El Greco made self-luminous).  Applies
            a Gaussian soft bright halo radiating outward from those pixels,
            composited at `inner_glow_opacity`.  This creates the uncanny
            inner-lit quality unique to his flesh rendering.

        Parameters
        ----------
        reference       : reference image (PIL or ndarray) — used for luminance
                          masking of the inner-glow stage.
        elongation_factor : fractional vertical stretch to apply to the figure
                            region (0.15 = 15% taller, El Greco's typical range).
        figure_mask     : (H, W) float32 mask — 1.0 inside figure, 0.0 outside.
                          If None the whole canvas is treated as figure.
        jewel_boost     : HSV saturation multiplier (> 1 = more saturated).
        inner_glow_radius  : Gaussian blur sigma in pixels for glow spread.
        inner_glow_opacity : opacity at which the glow layer is composited.
        glow_color      : warm silver-grey colour of the inner glow.
        """
        from PIL import ImageFilter as _IF

        w, h = self.canvas.w, self.canvas.h

        # ── Stage 1: Figure elongation ────────────────────────────────────────
        # Read current canvas as BGRA uint8 array
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(h, w, 4).copy()

        if figure_mask is not None:
            # Determine the vertical extent of the figure region
            mask_rows = figure_mask.max(axis=1)   # (H,) — row is in figure if > 0.5
            fig_rows  = np.where(mask_rows > 0.5)[0]
            if len(fig_rows) >= 4:
                y_top    = int(fig_rows[0])
                y_bottom = int(fig_rows[-1])
                fig_height = y_bottom - y_top

                # Source height we will compress into [y_top, y_bottom]:
                # We read from the figure region at a contracted sample spacing
                # so that the same content covers more pixels = elongation.
                src_height = max(1, round(fig_height / (1.0 + elongation_factor)))
                src_y_top  = y_top + (fig_height - src_height) // 2

                stretched = buf.copy()
                # Soft weight for elongation: zero at very top/bottom 15% of
                # figure, rising to 1.0 in the middle 70%.
                for dst_y in range(y_top, y_bottom + 1):
                    t = (dst_y - y_top) / max(fig_height, 1)
                    # Linear ramp in / ramp out at 15% top and bottom
                    blend = min(t / 0.15, 1.0, (1.0 - t) / 0.15)

                    # Source row: lerp between original row and the stretched row
                    src_t   = (dst_y - y_top) / max(fig_height, 1)
                    src_row = src_y_top + int(src_t * src_height)
                    src_row = max(0, min(h - 1, src_row))

                    # Blend the stretched row in according to mask weight and
                    # distance from figure centre.
                    row_mask = (figure_mask[dst_y, :] * blend)[:, np.newaxis]  # (W, 1)
                    stretched[dst_y] = (
                        buf[src_row] * row_mask + buf[dst_y] * (1.0 - row_mask)
                    ).astype(np.uint8)

                buf = stretched
        # else: no mask — elongation is subtle across the whole image by
        # slightly stretching the vertical centre portion.  Apply at half weight.
        else:
            centre_start = h // 5
            centre_end   = h - h // 5
            region_h     = centre_end - centre_start
            src_h        = max(1, round(region_h / (1.0 + elongation_factor * 0.5)))
            src_start    = centre_start + (region_h - src_h) // 2
            stretched    = buf.copy()
            for dst_y in range(centre_start, centre_end):
                t       = (dst_y - centre_start) / max(region_h, 1)
                blend   = min(t / 0.20, 1.0, (1.0 - t) / 0.20) * 0.55
                src_t   = t
                src_row = src_start + int(src_t * src_h)
                src_row = max(0, min(h - 1, src_row))
                stretched[dst_y] = (
                    buf[src_row] * blend + buf[dst_y] * (1.0 - blend)
                ).astype(np.uint8)
            buf = stretched

        # Write stretched buffer back to canvas
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"  Elongation applied  (factor={elongation_factor:.0%})")

        # ── Stage 2: Jewel-tone saturation boost ──────────────────────────────
        # Read canvas back (may have been modified by stage 1 write)
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(h, w, 4).copy()
        rgb = buf[:, :, [2, 1, 0]].astype(np.float32) / 255.0  # BGRA→RGB

        # Vectorised HSV saturation boost
        # Reshape to (H*W, 3) for colorsys-style computation
        flat = rgb.reshape(-1, 3)
        maxc = flat.max(axis=1)
        minc = flat.min(axis=1)
        span = maxc - minc  # saturation numerator

        # Boost saturation while keeping hue and value identical
        # For pixels already nearly grey (span < 0.02) — skip; no hue to boost.
        boosted = flat.copy()
        mask_sat = span > 0.02
        if mask_sat.any():
            # Compute scale factor: new_sat = min(1, old_sat * jewel_boost)
            # old_sat = span / maxc  (HSV definition)
            # new_span = old_sat * jewel_boost * maxc = span * jewel_boost
            # Clamp so no channel exceeds maxc.
            scale = np.where(mask_sat, np.minimum(jewel_boost, maxc / (span + 1e-8)), 1.0)
            # Grey point of the pixel: midpoint between min and max
            grey = ((flat - minc[:, None]) * scale[:, None] + minc[:, None])
            boosted[mask_sat] = np.clip(grey[mask_sat], 0, 1)

        rgb_boosted = boosted.reshape(h, w, 3)

        # Write back to canvas buffer
        buf[:, :, 2] = np.clip(rgb_boosted[:, :, 0] * 255, 0, 255).astype(np.uint8)  # R
        buf[:, :, 1] = np.clip(rgb_boosted[:, :, 1] * 255, 0, 255).astype(np.uint8)  # G
        buf[:, :, 0] = np.clip(rgb_boosted[:, :, 2] * 255, 0, 255).astype(np.uint8)  # B

        tmp2 = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        self.canvas.ctx.set_source_surface(tmp2, 0, 0)
        self.canvas.ctx.paint()

        print(f"  Jewel saturation boost applied  (×{jewel_boost:.2f})")

        # ── Stage 3: Inner glow on pale flesh zones ───────────────────────────
        # El Greco's flesh is silver-grey and appears self-luminous — not lit from
        # outside but radiating from within.  We simulate this by:
        #   1. Find canvas pixels where luminance > 0.72 (the pale silver zones)
        #   2. Build a grey-scale "seed" map from those pixels
        #   3. Gaussian-blur it to spread the glow outward
        #   4. Composite the glow at inner_glow_opacity using glow_color
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(h, w, 4).copy()
        rgb_f = buf[:, :, [2, 1, 0]].astype(np.float32) / 255.0

        lum = 0.2126 * rgb_f[:, :, 0] + 0.7152 * rgb_f[:, :, 1] + 0.0722 * rgb_f[:, :, 2]
        pale_seed = np.clip((lum - 0.72) / 0.28, 0.0, 1.0).astype(np.float32)

        if pale_seed.max() > 0.01 and inner_glow_radius > 0.5 and inner_glow_opacity > 0.0:
            # Blur the seed to spread glow
            glow_map = ndimage.gaussian_filter(pale_seed, sigma=inner_glow_radius)
            glow_map = np.clip(glow_map / (glow_map.max() + 1e-8), 0.0, 1.0)

            gr, gg, gb = glow_color
            ctx = self.canvas.ctx
            for row_y in range(h):
                row_max = float(glow_map[row_y].max())
                if row_max < 0.005:
                    continue
                # Per-pixel would be too slow; use a per-row composite with the
                # row's average glow value as alpha — adequate for a soft glow.
                row_alpha = inner_glow_opacity * row_max
                ctx.set_source_rgba(gr, gg, gb, row_alpha)
                ctx.rectangle(0.0, float(row_y), float(w), 1.0)
                ctx.fill()

        print(f"  Inner glow applied  (radius={inner_glow_radius:.1f}px, "
              f"opacity={inner_glow_opacity:.0%})")

    # ── Impasto texture pass — physical thick-paint ridge simulation ──────────

    def impasto_texture_pass(
            self,
            light_angle:   float = 315.0,
            ridge_height:  float = 0.55,
            blur_sigma:    float = 1.4,
            highlight_opacity: float = 0.28,
            shadow_opacity:    float = 0.22,
            ridge_warmth:      float = 0.0,
    ) -> None:
        """
        Simulate the physical texture of thick impasto oil paint.

        Rembrandt, Van Gogh, and Velázquez all applied paint so thickly in
        their lit areas that the dried ridges of paint cast real shadows and
        catch directional light — giving the surface a three-dimensional,
        sculptural quality that photographs cannot fully capture.

        This pass approximates that texture by:

        Stage 1 — Local gradient detection
            Computes the Sobel gradient of the canvas luminance to identify
            stroke ridges.  Strong gradient = paint ridge boundary.

        Stage 2 — Directional ridge highlight
            Along the upwind side of each ridge (relative to `light_angle`),
            adds a thin bright white-cream highlight strip.  Real impasto ridges
            catch the light on their upper face.

        Stage 3 — Directional ridge shadow
            Along the downwind side of each ridge, adds a thin dark shadow
            strip.  Real ridges cast a micro-shadow on the canvas below.

        The combination of adjacent highlight + shadow creates the visual
        illusion of a three-dimensional paint surface without requiring a
        full normal map or 3D geometry.

        Parameters
        ----------
        light_angle     : direction light arrives from, in degrees clockwise
                          from north (0° = from top, 315° = upper-left,
                          the traditional studio north-light convention).
        ridge_height    : controls how pronounced the ridge effect is.
                          0 = off; 1 = very strong raised impasto.
        blur_sigma      : Gaussian blur applied to the gradient before
                          thresholding — wider sigma = softer, broader ridges.
        highlight_opacity : opacity of the bright ridge highlight.
        shadow_opacity    : opacity of the dark ridge shadow.
        ridge_warmth    : SESSION-93 ARTISTIC IMPROVEMENT.  Shifts the ridge
                          highlight colour from cool creamy-white toward warm
                          amber, simulating the way thick oil-paint ridges catch
                          warm directional light rather than cool diffuse light.

                          At 0.0 (default): the existing cool-cream white
                          (R=0.98, G=0.96, B=0.90) is used, as in all prior
                          sessions.  At 1.0: the ridge highlight becomes a
                          warm amber (R=0.98, G=0.84, B=0.62), like candlelight
                          glancing across thick impasto.  Values between 0 and 1
                          linearly interpolate between the two colours.

                          Inspired by Hugo van der Goes, whose thick oil-glaze
                          layers on warm amber imprimatura produce ridges that
                          glow amber when raked light catches them — very
                          different from the cool white micro-highlights on
                          Rembrandt's lighter passages.  At the default value
                          of 0.0, behaviour is identical to all prior sessions;
                          set to 0.28 for a subtle warm-light impasto quality.
        """
        if ridge_height < 0.01:
            return

        w, h = self.canvas.w, self.canvas.h

        # ── Stage 1: Compute luminance gradient ───────────────────────────────
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(h, w, 4).copy()
        rgb = buf[:, :, [2, 1, 0]].astype(np.float32) / 255.0
        lum = (0.2126 * rgb[:, :, 0] +
               0.7152 * rgb[:, :, 1] +
               0.0722 * rgb[:, :, 2])

        # Sobel x and y gradients
        gx = ndimage.sobel(lum, axis=1)
        gy = ndimage.sobel(lum, axis=0)

        if blur_sigma > 0.1:
            gx = ndimage.gaussian_filter(gx, sigma=blur_sigma)
            gy = ndimage.gaussian_filter(gy, sigma=blur_sigma)

        # Gradient magnitude — proxy for ridge height
        gmag = np.sqrt(gx ** 2 + gy ** 2)
        if gmag.max() < 1e-6:
            return   # uniform canvas — no ridges to enhance

        gmag = (gmag / gmag.max()).astype(np.float32)

        # ── Stage 2–3: Directional highlight and shadow ───────────────────────
        # Convert light_angle to a unit direction vector (light_dx, light_dy)
        # 0° = from top = (0, -1), 90° = from right = (1, 0), etc.
        angle_rad = math.radians(light_angle)
        # Light arrives FROM this direction; the highlight is on the surface
        # perpendicular facing INTO the light.
        # gy: gradient in Y (positive = brighter below), gx: gradient in X
        # Ridge faces light if dot(gradient_dir, light_dir) > 0
        light_dx = math.sin(angle_rad)    # component pointing right
        light_dy = -math.cos(angle_rad)   # component pointing down (image coords)

        # Normalise gradient direction map
        gnorm = gmag + 1e-8
        gdx = gx / gnorm
        gdy = gy / gnorm

        # Directional component: positive = facing light, negative = shadow
        directional = gdx * light_dx + gdy * light_dy  # in [-1, 1]

        highlight_map = np.clip( directional, 0.0, 1.0) * gmag * ridge_height
        shadow_map    = np.clip(-directional, 0.0, 1.0) * gmag * ridge_height

        ctx = self.canvas.ctx

        # Ridge highlight colour — linearly interpolated by ridge_warmth.
        # Cool-cream base (R=0.98, G=0.96, B=0.90) at warmth=0.
        # Warm amber target (R=0.98, G=0.84, B=0.62) at warmth=1.
        t = float(np.clip(ridge_warmth, 0.0, 1.0))
        hl_r = 0.98
        hl_g = 0.96 * (1.0 - t) + 0.84 * t
        hl_b = 0.90 * (1.0 - t) + 0.62 * t

        # Highlight: cool creamy white shifting toward warm amber via ridge_warmth
        for row_y in range(h):
            row_max = float(highlight_map[row_y].max())
            if row_max < 0.005:
                continue
            row_alpha = highlight_opacity * row_max
            ctx.set_source_rgba(hl_r, hl_g, hl_b, row_alpha)
            ctx.rectangle(0.0, float(row_y), float(w), 1.0)
            ctx.fill()

        # Shadow: cool dark (slightly blue-black to suggest indirect skylight)
        for row_y in range(h):
            row_max = float(shadow_map[row_y].max())
            if row_max < 0.005:
                continue
            row_alpha = shadow_opacity * row_max
            ctx.set_source_rgba(0.05, 0.06, 0.10, row_alpha)
            ctx.rectangle(0.0, float(row_y), float(w), 1.0)
            ctx.fill()

        print(f"  Impasto texture pass complete  "
              f"(angle={light_angle:.0f}°, ridge_height={ridge_height:.2f}  "
              f"ridge_warmth={ridge_warmth:.2f})")

    # ── Atmospheric depth pass — aerial perspective (Leonardo / Friedrich) ─────

    def atmospheric_depth_pass(
            self,
            haze_color:          Color = (0.72, 0.78, 0.88),  # cool blue-grey haze
            desaturation:        float = 0.65,                  # saturation loss at max depth
            lightening:          float = 0.50,                  # blend toward haze at max depth
            depth_gamma:         float = 1.6,                   # depth curve shape (>1 = effect
                                                                # concentrates near horizon)
            background_only:     bool  = True,                  # apply only outside figure mask
            horizon_glow_band:   float = 0.0,                   # strength of luminous horizon band
            horizon_y_frac:      float = 0.55,                  # vertical position (0=top, 1=bottom)
            horizon_band_sigma:  float = 0.06,                  # falloff width as fraction of height
            zenith_luminance_boost: float = 0.0,                # strength of zenith sky luminance lift
            zenith_band_sigma:   float = 0.10,                  # falloff width as fraction of height
            foreground_warmth:   float = 0.0,                   # warm ochre lift at canvas bottom
            foreground_band_sigma: float = 0.18,                # falloff width for foreground warmth
    ) -> None:
        """
        Atmospheric depth (aerial perspective) pass.

        Leonardo da Vinci described this phenomenon in *Trattato della Pittura*
        (c. 1490–1510) as *prospettiva aerea* (aerial perspective): the
        atmosphere between the viewer and a distant object scatters and absorbs
        light so that distant surfaces appear progressively —

          1. **Lighter in value** — atmosphere adds a veil of bright sky to
             every distant surface.
          2. **Cooler / bluer** — Rayleigh scattering shifts the apparent colour
             of distant elements toward the blue of the sky.
          3. **Less saturated** — the atmosphere desaturates and blends all
             colours toward the ambient sky tone.
          4. **Lower contrast** — dark darks become less dark; lights become
             less light, as everything resolves toward the same atmospheric grey.

        This pass simulates the effect by reading the current canvas state and
        applying a depth-weighted blend: pixels near the top of the canvas
        (the far sky / distant landscape) receive the strongest atmospheric
        treatment; pixels at the bottom (foreground) are untouched.

        The depth gradient is purely positional (y-axis), which is physically
        correct for landscape paintings where the horizon is always above the
        foreground ground plane.

        Caspar David Friedrich applied aerial perspective with extraordinary
        systematic rigour: each of the three major zones (foreground, middle
        distance, far horizon / sky) is painted in its own atmospheric register,
        each noticeably cooler, lighter, and less saturated than the one below.
        The technique pre-dates photographic depth-of-field but achieves a
        similar sense of spatial recession through colour temperature alone.

        Parameters
        ----------
        haze_color      : The colour toward which distant pixels are blended.
                          Should match the ambient sky / horizon tone.
                          Default: pale blue-grey (0.72, 0.78, 0.88).
        desaturation    : How much to desaturate at maximum depth (0–1).
                          0 = no desaturation; 1 = full greyscale at the horizon.
                          Typical range 0.50–0.75.
        lightening      : How much to blend toward haze_color at maximum depth
                          (0–1).  0 = no atmospheric tinting; 1 = full haze.
                          Typical range 0.35–0.60.
        depth_gamma     : Shape of the depth falloff curve.  Values > 1.0
                          concentrate the atmospheric effect near the horizon;
                          values < 1.0 spread it further into the mid-ground.
                          1.6 (default) gives a convincing natural falloff.
        background_only : If True (default), apply only to the background zone
                          (pixels outside the figure mask).  The figure is left
                          untouched so portrait subjects retain their local colour.
                          Pass False to apply to the whole canvas (landscape-only
                          scenes with no figure mask).
        horizon_glow_band : When > 0, adds a subtle luminous warm-cool glow band
                            centred at ``horizon_y_frac`` from the top of the canvas.
                            The band brightens and slightly warms pixels at that
                            vertical position, creating the characteristic atmospheric
                            horizon light seen in Leonardo's Mona Lisa background —
                            a diffuse bright zone where the distant sky and rocky
                            terrain meet, causing the distinctive pale shimmer that
                            sits behind the figure's shoulders.  The effect uses a
                            Gaussian falloff (sigma ≈ horizon_band_sigma × canvas
                            height) so the transition is soft and imperceptible at its
                            edges.  Values 0.08–0.20 produce a subtle, naturalistic
                            result; above 0.30 the band becomes visually explicit.
                            At 0.0 (default) the behaviour is unchanged.
                            (Session 90 improvement.)
        horizon_y_frac    : Vertical position of the glow band as a fraction from
                            the top of the canvas (0 = top, 1 = bottom).  The
                            default of 0.55 places the band slightly below canvas
                            centre, matching the typical landscape horizon position
                            in three-quarter portrait compositions.
        horizon_band_sigma : Gaussian falloff width as a fraction of canvas height.
                             Larger values create a wider, more diffuse glow;
                             smaller values produce a tighter, more defined band.
        zenith_luminance_boost : When > 0, adds a luminance lift concentrated at the
                                 very top of the canvas (y=0), simulating the brilliant
                                 zenith luminosity of Luca Giordano's ceiling fresco
                                 tradition.  In Giordano's large ceiling compositions
                                 (Palazzo Medici-Riccardi, the Escorial) the uppermost
                                 zone reads as an open, brilliantly lit sky — the
                                 atmospheric zenith is the brightest zone rather than
                                 merely the most hazed.  Unlike horizon_glow_band (which
                                 brightens a mid-canvas horizontal zone), this parameter
                                 lifts luminance at the canvas ceiling and falls off
                                 downward with a Gaussian envelope.  Values 0.05–0.12
                                 produce a subtle, naturalistic zenith sky brightening;
                                 above 0.20 the effect becomes explicitly theatrical.
                                 Applied to background only, consistent with the rest of
                                 the pass.  (Session 104 improvement.)
        zenith_band_sigma  : Gaussian falloff width for the zenith lift, as a fraction
                             of canvas height.  Larger values spread the brightening
                             further down the canvas; default 0.10 confines it to the
                             uppermost 20–25% of the image.
        foreground_warmth  : When > 0, adds a warm ochre-amber temperature lift
                             concentrated at the very bottom of the canvas (y=H),
                             simulating the warm earth tones in the near foreground
                             of landscape backgrounds.  Leonardo's Mona Lisa
                             background and Corot's landscapes both exhibit this
                             warm-foreground / cool-distance temperature gradient:
                             the earth at the viewer's feet is warm sienna-ochre,
                             while the distant sky is cool blue-grey.  This parameter
                             creates that complementary warm base to the cool haze at
                             the top of the canvas, reinforcing spatial depth through
                             colour temperature contrast rather than value alone.
                             A Gaussian centred at y=H falls off upward; default
                             ``foreground_band_sigma`` of 0.18 applies warmth to
                             roughly the lowest 35% of the canvas.  Values 0.04–0.10
                             produce a subtle naturalistic ground warmth; above 0.15
                             the effect becomes an explicit warm zone.  Applied to
                             background only, consistent with the rest of the pass.
                             (Session 106 improvement.)
        foreground_band_sigma : Gaussian falloff width for the foreground warmth, as
                             a fraction of canvas height.  Larger values spread the
                             warmth further up the canvas; default 0.18 confines it
                             to the lower third.

        Notes
        -----
        Friedrich's *Wanderer above the Sea of Fog* (1818) demonstrates the
        three atmospheric zones almost diagrammatically: jet-black pine
        silhouettes at the very bottom; grey-green fog-draped ridges in the
        middle; a pale cerulean-white sky at the top.  Each zone is internally
        consistent and makes the next zone read correctly by contrast.

        Leonardo's own instructions in Trattato della Pittura:
          "Objects at a distance should be less dark and their outlines lost;
           the further you place them the lighter, bluer and more blurred."

        Applies to all landscape-heavy paintings:
        ROMANTIC (Turner, Friedrich), RENAISSANCE landscape bg (Leonardo),
        IMPRESSIONIST exterior (Monet, Pissarro), Ukiyo-e background sky.
        """
        print(f"Atmospheric depth pass  "
              f"(haze={haze_color}  desat={desaturation:.2f}"
              f"  lighten={lightening:.2f}  gamma={depth_gamma:.1f}"
              f"  horizon_glow={horizon_glow_band:.2f}"
              f"  zenith_boost={zenith_luminance_boost:.2f}"
              f"  fg_warmth={foreground_warmth:.2f})…")

        w, h = self.canvas.w, self.canvas.h

        # ── Read current canvas buffer ──────────────────────────────────────────
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(h, w, 4).copy()
        # Cairo stores BGRA; convert to float RGB [0, 1]
        rgb = buf[:, :, [2, 1, 0]].astype(np.float32) / 255.0  # (H, W, 3)

        hr, hg, hb = haze_color

        # ── Build spatial depth map ─────────────────────────────────────────────
        # y=0 is the TOP of the image (most distant / sky);
        # y=H-1 is the BOTTOM (foreground).
        # depth = 1 at the very top, 0 at the very bottom.
        ys = np.arange(h, dtype=np.float32)
        depth_linear = 1.0 - ys / max(h - 1, 1)              # (H,)
        depth        = depth_linear ** depth_gamma             # apply curve
        depth        = depth[:, np.newaxis]                    # (H, 1)  — broadcast over W

        # ── Background mask ─────────────────────────────────────────────────────
        if background_only and self._figure_mask is not None:
            # bg_weight[y, x] = 0 where figure is present, 1 in background.
            bg_weight = np.clip(1.0 - self._figure_mask, 0.0, 1.0)
        else:
            bg_weight = np.ones((h, w), dtype=np.float32)

        # Combined per-pixel effect weight: depth × background_weight
        # Both broadcast over the 3 colour channels.
        effect = (depth * bg_weight)[:, :, np.newaxis]       # (H, W, 1)

        # ── Stage 1: Desaturate toward luminance ─────────────────────────────────
        # Convert to per-pixel luminance (BT.601 weights) and lerp toward it.
        lum = (0.299 * rgb[:, :, 0] +
               0.587 * rgb[:, :, 1] +
               0.114 * rgb[:, :, 2])[:, :, np.newaxis]       # (H, W, 1)

        desaturation_weight = effect * desaturation
        rgb_desat = rgb * (1.0 - desaturation_weight) + lum * desaturation_weight

        # ── Stage 2: Haze blend toward haze_color ────────────────────────────────
        haze_vec = np.array([hr, hg, hb], dtype=np.float32)   # (3,)
        lightening_weight = effect * lightening
        rgb_final = rgb_desat * (1.0 - lightening_weight) + haze_vec * lightening_weight

        # ── Stage 3: Horizon glow band (session 90 improvement) ───────────────
        # Adds a subtle luminous warm-cool band at the atmospheric horizon,
        # simulating the bright glowing zone where distant sky meets terrain in
        # Leonardo's Mona Lisa background.  A Gaussian falloff centred at
        # horizon_y_frac × H brightens and slightly warms pixels in that zone.
        if horizon_glow_band > 0.0:
            sigma_px = max(horizon_band_sigma * h, 1.0)
            # Gaussian weight centred on horizon row.
            horizon_row = horizon_y_frac * (h - 1)
            row_dist = (np.arange(h, dtype=np.float32) - horizon_row) / sigma_px
            glow_profile = np.exp(-0.5 * row_dist ** 2)        # (H,) Gaussian
            glow_profile = glow_profile[:, np.newaxis, np.newaxis]  # (H, 1, 1) broadcast

            # Apply only to background region (same mask as rest of pass).
            glow_weight = glow_profile * bg_weight[:, :, np.newaxis] * horizon_glow_band  # (H, W, 1)

            # Warm ivory-amber glow colour — the pale diffuse sky at the Mona
            # Lisa horizon reads as warm ivory cooling into pale blue-grey.
            glow_color = np.array([0.92, 0.90, 0.84], dtype=np.float32)
            rgb_final = rgb_final * (1.0 - glow_weight * 0.55) + glow_color * (glow_weight * 0.55)
            # Additional slight luminance lift (brighten toward white).
            rgb_final = rgb_final + glow_weight * 0.08

        # ── Stage 4: Zenith luminance boost (session 104 improvement) ─────────
        # Luca Giordano's ceiling fresco tradition: the very top of the canvas
        # (the zenith sky) reads as brilliantly lit and luminous, not merely
        # hazed.  A Gaussian centred at y=0 lifts luminance and slightly cools
        # the uppermost zone, simulating the open celestial sky of his vast
        # ceiling compositions.  Applied only to background pixels.
        if zenith_luminance_boost > 0.0:
            zenith_sigma_px = max(zenith_band_sigma * h, 1.0)
            # Gaussian centred at row 0 (top of canvas)
            row_dist_z = np.arange(h, dtype=np.float32) / zenith_sigma_px
            zenith_profile = np.exp(-0.5 * row_dist_z ** 2)          # (H,)
            zenith_profile = zenith_profile[:, np.newaxis, np.newaxis]  # (H, 1, 1)
            zenith_weight  = zenith_profile * bg_weight[:, :, np.newaxis] * zenith_luminance_boost

            # Cool-blue zenith: lift luminance uniformly with a slight blue bias
            # (Giordano's open cerulean sky colour above the dramatic compositions).
            zenith_color = np.array([0.88, 0.92, 0.98], dtype=np.float32)
            rgb_final = rgb_final * (1.0 - zenith_weight * 0.45) + zenith_color * (zenith_weight * 0.45)
            rgb_final = rgb_final + zenith_weight * 0.06

        # ── Stage 5: Foreground warmth (session 106 improvement) ──────────────
        # Warm ochre-amber temperature lift at the canvas bottom simulates the
        # near-foreground earth tones in landscape backgrounds.  Leonardo's
        # Mona Lisa background, Corot's Barbizon landscapes, and Poussin's
        # classical scenes all exhibit this warm-ground / cool-sky temperature
        # gradient.  A Gaussian centred at y=H (bottom) falls off upward,
        # complementing the cool haze at the top and reinforcing depth through
        # colour temperature contrast.  Applied to background only.
        if foreground_warmth > 0.0:
            fg_sigma_px = max(foreground_band_sigma * h, 1.0)
            # Gaussian centred at row H-1 (bottom of canvas)
            row_dist_fg = (h - 1 - np.arange(h, dtype=np.float32)) / fg_sigma_px
            fg_profile = np.exp(-0.5 * row_dist_fg ** 2)           # (H,)
            fg_profile = fg_profile[:, np.newaxis, np.newaxis]     # (H, 1, 1)
            fg_weight  = fg_profile * bg_weight[:, :, np.newaxis] * foreground_warmth

            # Warm ochre-sienna foreground: the warm earth tones of near-ground
            # that appear at the viewer's feet in Renaissance landscape backgrounds.
            fg_color = np.array([0.78, 0.62, 0.38], dtype=np.float32)
            rgb_final = rgb_final * (1.0 - fg_weight * 0.50) + fg_color * (fg_weight * 0.50)
            # Slight additional warm luminance lift at ground level
            rgb_final = rgb_final + fg_weight * np.array([0.04, 0.02, 0.0], dtype=np.float32)

        rgb_final = np.clip(rgb_final, 0.0, 1.0)

        # ── Write modified pixels back to Cairo surface ──────────────────────────
        # Build BGRA uint8 array: Cairo needs B, G, R, A channel order.
        # Alpha channel is preserved from the original buffer.
        out = np.zeros((h, w, 4), dtype=np.uint8)
        out[:, :, 0] = (rgb_final[:, :, 2] * 255).astype(np.uint8)   # B
        out[:, :, 1] = (rgb_final[:, :, 1] * 255).astype(np.uint8)   # G
        out[:, :, 2] = (rgb_final[:, :, 0] * 255).astype(np.uint8)   # R
        out[:, :, 3] = buf[:, :, 3]                                    # A (preserve)

        out_bytes = bytearray(out.tobytes())
        haze_surf = cairo.ImageSurface.create_for_data(
            out_bytes, cairo.FORMAT_ARGB32, w, h)
        self.canvas.ctx.set_source_surface(haze_surf, 0, 0)
        self.canvas.ctx.paint()

        print(f"  Atmospheric depth complete  "
              f"({h}×{w} canvas, gamma={depth_gamma:.1f})")

    def folk_retablo_pass(
            self,
            ref,
            n_levels:             int   = 4,
            saturation_boost:     float = 1.55,
            outline_thickness:    float = 2.5,
            outline_color:        Color = (0.05, 0.03, 0.02),
            outline_opacity:      float = 0.88,
            boundary_vibration:   bool  = True,
            vibration_width:      float = 1.8,
            vibration_opacity:    float = 0.28,
    ) -> None:
        """
        Folk retablo / ex-voto painting pass.

        Inspired by Frida Kahlo's technique — itself rooted in the Mexican
        retablo tradition of small devotional paintings on metal or masonite —
        this pass transforms the current canvas into a flat, zone-based,
        high-saturation rendering with heavy dark contour outlines at every
        colour boundary.

        Three-stage process
        -------------------
        **Stage 1 — Posterization and saturation boost.**
        Converts the canvas to HSV colour space and quantizes the Value channel
        into ``n_levels`` discrete levels.  The Saturation channel is multiplied
        by ``saturation_boost`` so every colour moves toward its maximum
        intensity.  This models Kahlo's preference for volcanic earth reds,
        deep jungle greens, and Aztec turquoise — none of which are naturalistic;
        all are emotionally driven.

        **Stage 2 — Boundary vibration (simultaneous contrast).**
        This is the key artistic improvement in this session: at every detected
        zone boundary the pass applies a thin warm/cool opposing accent stripe.
        On the side of the boundary closer to a warm tone (R > B), a cool blue-
        grey veil is applied; on the cool side, a warm amber veil is applied.
        This replicates the perceptual "hum" of Kahlo's figure-ground
        relationships — her jungle-green backgrounds read as more vivid because
        the warm figure edge pushes them cooler, and the skin reads as warmer
        because the cool foliage edge pushes it warmer.  Simultaneous contrast
        was first theorised by Chevreul (1839) and used systematically by Seurat,
        but Kahlo applied it intuitively in every work regardless of period.

        **Stage 3 — Contour outlines.**
        Sobel edge detection on the posterized result identifies all zone
        boundaries.  A thick dark (near-black umber) line is composited over
        every strong boundary at ``outline_opacity``.  This directly models the
        retablo craftsman's final step of reinforcing every object boundary with
        a loaded dark-paint contour.

        Parameters
        ----------
        ref               : PIL Image reference for local colour sampling.
        n_levels          : Posterization levels (3 = flat folk, 5 = more tonal).
        saturation_boost  : HSV saturation multiplier (> 1.0 intensifies colour).
                            Kahlo's palette is typically 1.4–1.7× natural saturation.
        outline_thickness : Pixel width of the dark contour strokes.
        outline_color     : RGB colour of the contour lines (near-black umber).
        outline_opacity   : Compositing opacity for the contour overlay (0–1).
        boundary_vibration: Enable simultaneous-contrast warm/cool accent stripes.
        vibration_width   : Width of the accent stripe on each side of a boundary.
        vibration_opacity : Opacity of the vibration stripe (subtle — 0.20–0.35).

        Notes
        -----
        This pass should run AFTER the standard form-building passes
        (underpainting, block_in, build_form) so it has fully rendered subject
        matter to posterize, and BEFORE place_lights() or any final glaze so the
        impasto highlights land on top of the flat zones.

        The ``boundary_vibration`` parameter implements the "random aspect
        improvement" for this session: simultaneous colour contrast at zone
        edges is a general technique that applies to any period with hard colour
        boundaries, including SYNTHETIST, REALIST, and UKIYO_E, but is most
        critical for SURREALIST / folk-art rendering.
        """
        print(f"Folk retablo pass  (levels={n_levels}  sat_boost={saturation_boost:.2f}"
              f"  outline_t={outline_thickness:.1f}  vibration={boundary_vibration})…")

        from PIL import Image as _PILImage
        import colorsys as _cs

        w, h = self.canvas.w, self.canvas.h

        # ── Read current canvas buffer ──────────────────────────────────────────
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(h, w, 4).copy()
        # Cairo BGRA → float RGB (H, W, 3)
        rgb = buf[:, :, [2, 1, 0]].astype(np.float32) / 255.0

        # ── Stage 1: Posterize + saturation boost ──────────────────────────────
        # Vectorised HSV conversion via scipy/colorsys is slow for large arrays;
        # use a direct numpy approximation instead.

        # RGB → HSV (all in [0, 1])
        r, g, b = rgb[:, :, 0], rgb[:, :, 1], rgb[:, :, 2]
        v = np.maximum(np.maximum(r, g), b)                      # Value
        s_denom = np.where(v > 1e-6, v, 1e-6)
        s = (v - np.minimum(np.minimum(r, g), b)) / s_denom      # Saturation

        # Hue (0–6 scale; undefined for achromatic pixels)
        delta = v - np.minimum(np.minimum(r, g), b)
        safe_delta = np.where(delta > 1e-6, delta, 1e-6)
        hue = np.where(
            v == r, (g - b) / safe_delta % 6.0,
            np.where(v == g, (b - r) / safe_delta + 2.0,
                     (r - g) / safe_delta + 4.0)
        )
        hue = hue / 6.0   # normalise to [0, 1]

        # Posterize Value to n_levels discrete steps
        v_steps  = np.round(v * (n_levels - 1)) / (n_levels - 1)

        # Boost saturation; clip to [0, 1]
        s_boosted = np.clip(s * saturation_boost, 0.0, 1.0)

        # HSV → RGB reconstruction
        h6  = hue * 6.0
        hi  = np.floor(h6).astype(np.int32) % 6
        f   = h6 - np.floor(h6)
        p   = v_steps * (1.0 - s_boosted)
        q   = v_steps * (1.0 - s_boosted * f)
        t   = v_steps * (1.0 - s_boosted * (1.0 - f))

        r2 = np.select([hi == 0, hi == 1, hi == 2, hi == 3, hi == 4, hi == 5],
                       [v_steps, q,       p,       p,       t,       v_steps])
        g2 = np.select([hi == 0, hi == 1, hi == 2, hi == 3, hi == 4, hi == 5],
                       [t,       v_steps, v_steps, q,       p,       p])
        b2 = np.select([hi == 0, hi == 1, hi == 2, hi == 3, hi == 4, hi == 5],
                       [p,       p,       t,       v_steps, v_steps, q])

        rgb_post = np.stack([r2, g2, b2], axis=-1).astype(np.float32)
        rgb_post = np.clip(rgb_post, 0.0, 1.0)

        # ── Stage 2: Boundary vibration (simultaneous contrast) ────────────────
        # Detect zone boundaries on the posterized Value image.  Sobel gives a
        # gradient magnitude at every pixel; high magnitude = zone boundary.
        from scipy.ndimage import sobel as _sobel, uniform_filter as _uf
        v_map = v_steps.astype(np.float32)
        gx = _sobel(v_map, axis=1)
        gy = _sobel(v_map, axis=0)
        grad_mag = np.hypot(gx, gy)

        # Normalise gradient magnitude to [0, 1]
        g_max = grad_mag.max()
        if g_max > 1e-6:
            grad_norm = grad_mag / g_max
        else:
            grad_norm = grad_mag

        if boundary_vibration:
            # Determine warmth of each pixel: R-dominance means warm, B-dominance cool.
            warmth = rgb_post[:, :, 0] - rgb_post[:, :, 2]   # (H, W): + = warm, - = cool

            # Boundary zone: use a dilated version of the gradient so the accent
            # stripe has the specified pixel width.
            vib_w = max(1, int(round(vibration_width)))
            boundary_zone = _uf(grad_norm, size=vib_w * 2 + 1)
            boundary_zone = np.clip(boundary_zone / (boundary_zone.max() + 1e-6),
                                    0.0, 1.0)

            # Warm-side accent: cool blue-grey tint
            warm_accent  = np.array([0.60, 0.68, 0.85], dtype=np.float32)
            # Cool-side accent: warm amber tint
            cool_accent  = np.array([0.90, 0.68, 0.38], dtype=np.float32)

            # Select which accent applies at each pixel
            is_warm = (warmth > 0.0)[:, :, np.newaxis]
            accent  = np.where(is_warm, warm_accent, cool_accent)

            vib_weight = (boundary_zone * vibration_opacity)[:, :, np.newaxis]
            rgb_post   = rgb_post * (1.0 - vib_weight) + accent * vib_weight
            rgb_post   = np.clip(rgb_post, 0.0, 1.0)

        # ── Stage 3: Dark contour outlines ─────────────────────────────────────
        # Threshold the gradient at a moderate level to find only the strongest
        # zone boundaries.  Dilate to outline_thickness pixels, then composite
        # the dark outline_color at outline_opacity.
        outline_threshold = 0.30
        outline_mask = (grad_norm > outline_threshold).astype(np.float32)

        # Grow the outline to the requested thickness via uniform filter
        ot = max(1, int(round(outline_thickness)))
        outline_grown = _uf(outline_mask, size=ot * 2 + 1)
        outline_grown = np.clip(outline_grown / (outline_grown.max() + 1e-6),
                                0.0, 1.0)

        or_, og_, ob_ = outline_color
        outline_rgb = np.array([or_, og_, ob_], dtype=np.float32)
        ol_weight   = (outline_grown * outline_opacity)[:, :, np.newaxis]
        rgb_final   = rgb_post * (1.0 - ol_weight) + outline_rgb * ol_weight
        rgb_final   = np.clip(rgb_final, 0.0, 1.0)

        # ── Write back to Cairo surface ─────────────────────────────────────────
        out = np.zeros((h, w, 4), dtype=np.uint8)
        out[:, :, 0] = (rgb_final[:, :, 2] * 255).astype(np.uint8)   # B
        out[:, :, 1] = (rgb_final[:, :, 1] * 255).astype(np.uint8)   # G
        out[:, :, 2] = (rgb_final[:, :, 0] * 255).astype(np.uint8)   # R
        out[:, :, 3] = buf[:, :, 3]                                    # A preserve

        out_bytes = bytearray(out.tobytes())
        retablo_surf = cairo.ImageSurface.create_for_data(
            out_bytes, cairo.FORMAT_ARGB32, w, h)
        self.canvas.ctx.set_source_surface(retablo_surf, 0, 0)
        self.canvas.ctx.paint()

        # Final pass: place a handful of loaded thick strokes along the main
        # figure contours in the outline colour to reinforce the retablo outline.
        rng = random.Random(77)
        n_contour = int(outline_thickness * 200)
        for _ in range(n_contour):
            yw = rng.randint(0, h - 1)
            xw = rng.randint(0, w - 1)
            # Sample gradient at this point — only draw where there is a strong edge
            if rng.random() > float(grad_norm[yw, xw]):
                continue
            length = outline_thickness * 3.0
            angle  = math.atan2(float(gy[yw, xw] + 1e-9),
                                 float(gx[yw, xw] + 1e-9)) + math.pi / 2.0
            x2 = xw + length * math.cos(angle)
            y2 = yw + length * math.sin(angle)
            self.canvas.ctx.set_source_rgba(or_, og_, ob_, outline_opacity * 0.60)
            self.canvas.ctx.set_line_width(outline_thickness * 0.7)
            self.canvas.ctx.move_to(float(xw), float(yw))
            self.canvas.ctx.line_to(float(x2), float(y2))
            self.canvas.ctx.stroke()

        print(f"  Folk retablo pass complete  "
              f"({h}×{w}, {n_levels} levels, vib={'on' if boundary_vibration else 'off'})")

    def geometric_resonance_pass(self,
                                 reference:      Union[np.ndarray, Image.Image],
                                 n_circles:      int   = 12,
                                 n_triangles:    int   = 8,
                                 n_lines:        int   = 18,
                                 shape_opacity:  float = 0.18,
                                 min_radius:     float = 0.04,
                                 max_radius:     float = 0.18,
                                 line_thickness: float = 2.0,
                                 seed:           int   = 42):
        """
        Geometric Resonance Pass — inspired by Wassily Kandinsky.

        Kandinsky believed each geometric form carried an intrinsic emotional
        and acoustic resonance that could be used to compose a painting the way
        a musician composes a symphony.  In "Concerning the Spiritual in Art"
        (1911) and in his Bauhaus colour theory course he mapped:

          • Yellow / triangle  — sharp, advancing, trumpet-like energy
          • Blue   / circle    — receding, heavenly, cello-deep resonance
          • Red    / square    — earthbound, stable, drumbeat warmth
          • Black  / line      — tension, boundary, the silence after sound

        This pass scatters floating geometric primitives across the canvas:

          1. Circles in cool-blue resonance zones  (Kandinsky's "cosmic" form)
          2. Triangles in warm-yellow/orange zones  (his "active" pointing form)
          3. Radiating tension lines from focal points  (his "musical notations")

        Each primitive samples a harmonically-related colour from the region
        beneath it, then applies it at low opacity — the underlying painting
        remains legible.  The effect gives any composition an internally
        vibrating, musical quality as if solid form is dissolving into sensation.

        Parameters
        ----------
        reference     : PIL Image or ndarray used for colour sampling.
        n_circles     : Number of floating circles to overlay.
        n_triangles   : Number of floating triangles to overlay.
        n_lines       : Number of radiating tension lines to overlay.
        shape_opacity : Base alpha for each geometric primitive (0.05–0.35).
                        Keep low so underlying painting reads through.
        min_radius    : Smallest circle/triangle radius as fraction of canvas W.
        max_radius    : Largest circle/triangle radius as fraction of canvas W.
        line_thickness: Stroke width for tension lines, in pixels.
        seed          : Random seed for reproducible placement.
        """
        print(f"Geometric resonance pass  (circles={n_circles}, tri={n_triangles}, "
              f"lines={n_lines}, opacity={shape_opacity:.2f})…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = rarr.shape[:2]
        ctx  = self.canvas.ctx
        rng  = random.Random(seed)

        def _sample_region_color(cx: float, cy: float, radius: float) -> Color:
            """Sample the mean RGB of a disc region in the reference."""
            x0 = max(0, int(cx - radius))
            x1 = min(w, int(cx + radius) + 1)
            y0 = max(0, int(cy - radius))
            y1 = min(h, int(cy + radius) + 1)
            patch = rarr[y0:y1, x0:x1]
            if patch.size == 0:
                return (0.5, 0.5, 0.5)
            return (float(patch[:, :, 0].mean()),
                    float(patch[:, :, 1].mean()),
                    float(patch[:, :, 2].mean()))

        def _resonance_color(base: Color) -> Color:
            """
            Map a sampled base colour to its Kandinsky resonance complement.

            Cool blue zones → circle drawn in luminous warm yellow (advancing)
            Warm yellow zones → triangle drawn in deep ultramarine (contrasting)
            Neutral/grey zones → drawn in pure saturated version of dominant hue
            All colours are slightly over-saturated to read through the painting.
            """
            import colorsys as _cs
            h_hsv, s_hsv, v_hsv = _cs.rgb_to_hsv(*base)
            # Boost saturation so the resonance colour sings above the ground
            s_boosted = min(1.0, s_hsv * 1.6 + 0.2)
            # Rotate hue toward warm complement: cool hues → warm, warm → cool
            # (hue rotation is 0.5 = 180° = complementary)
            hue_complement = (h_hsv + 0.5) % 1.0
            r, g, b = _cs.hsv_to_rgb(hue_complement, s_boosted, min(1.0, v_hsv + 0.1))
            return (r, g, b)

        def _set_resonance_source(base: Color):
            r, g, b = _resonance_color(base)
            ctx.set_source_rgba(r, g, b, shape_opacity)

        # ── 1. Floating circles  (Kandinsky: cosmic / blue / receding) ─────────
        for _ in range(n_circles):
            cx = rng.uniform(0.0, float(w))
            cy = rng.uniform(0.0, float(h))
            r  = rng.uniform(min_radius * w, max_radius * w)
            base = _sample_region_color(cx, cy, r * 0.5)

            # Unfilled circle ring — resonance at the boundary only
            _set_resonance_source(base)
            ctx.set_line_width(max(1.0, r * 0.06))
            ctx.arc(cx, cy, r, 0, 2 * math.pi)
            ctx.stroke()

            # Optionally add a very faint interior fill for larger circles
            if r > min_radius * w * 2.5:
                r2, g2, b2 = _resonance_color(base)
                ctx.set_source_rgba(r2, g2, b2, shape_opacity * 0.25)
                ctx.arc(cx, cy, r, 0, 2 * math.pi)
                ctx.fill()

        # ── 2. Floating triangles  (Kandinsky: active / yellow / advancing) ───
        for _ in range(n_triangles):
            cx  = rng.uniform(0.05 * w, 0.95 * w)
            cy  = rng.uniform(0.05 * h, 0.95 * h)
            r   = rng.uniform(min_radius * w, max_radius * w * 0.80)
            # Random rotation so triangles point in varied directions
            angle_offset = rng.uniform(0, 2 * math.pi)
            base = _sample_region_color(cx, cy, r * 0.5)

            # Compute equilateral triangle vertices
            verts = []
            for k in range(3):
                a = angle_offset + k * (2 * math.pi / 3)
                verts.append((cx + r * math.cos(a), cy + r * math.sin(a)))

            _set_resonance_source(base)
            ctx.set_line_width(max(1.0, r * 0.05))
            ctx.move_to(*verts[0])
            ctx.line_to(*verts[1])
            ctx.line_to(*verts[2])
            ctx.close_path()
            ctx.stroke()

        # ── 3. Radiating tension lines  (Kandinsky: the musical notation) ─────
        # Lines radiate outward from N focal points distributed across the canvas.
        # Each line samples the colour of the region it crosses and draws its
        # resonance complement, creating chromatic tension along its length.
        n_foci = max(2, n_lines // 5)
        foci   = [(rng.uniform(0.2 * w, 0.8 * w),
                   rng.uniform(0.2 * h, 0.8 * h))
                  for _ in range(n_foci)]

        lines_per_focus = max(1, n_lines // n_foci)
        for fx, fy in foci:
            for _ in range(lines_per_focus):
                angle    = rng.uniform(0, 2 * math.pi)
                length   = rng.uniform(0.06 * w, 0.35 * w)
                x2       = fx + length * math.cos(angle)
                y2       = fy + length * math.sin(angle)
                mid_x    = (fx + x2) / 2.0
                mid_y    = (fy + y2) / 2.0
                base     = _sample_region_color(mid_x, mid_y, line_thickness * 3)

                r_c, g_c, b_c = _resonance_color(base)
                ctx.set_source_rgba(r_c, g_c, b_c, shape_opacity * 0.75)
                ctx.set_line_width(line_thickness)
                ctx.move_to(fx, fy)
                ctx.line_to(x2, y2)
                ctx.stroke()

        print(f"  Geometric resonance complete  "
              f"({n_circles} circles, {n_triangles} triangles, {n_lines} lines)")

    def venetian_glaze_pass(self,
                            reference:       Union[np.ndarray, Image.Image],
                            n_glaze_layers:  int   = 6,
                            glaze_warmth:    float = 0.55,
                            shadow_depth:    float = 0.72,
                            impasto_strokes: int   = 400,
                            impasto_size:    float = 7.0,
                            impasto_opacity: float = 0.85):
        """
        Venetian glaze pass — inspired by Titian's colorist technique.

        Titian built his paintings through accumulating transparent warm glazes
        over a white underpaint.  The layered structure produces flesh tones of
        extraordinary luminosity: light penetrates the transparent colour layers,
        reflects off the white ground beneath, and returns through the glazes —
        a visual analog of subsurface light scattering in real skin.

        The pass has three stages:

          1. Transparent shadow glazes: warm red-umber glaze layers are applied
             to all areas darker than a luminance threshold.  Shadow areas deepen
             with warm umber rather than cool grey — the Venetian principle that
             shadows are warm, not cold.  Multiple thin layers accumulate to
             produce depth without opacity.

          2. Mid-tone colour enrichment: short gestural strokes are applied with
             the Venetian vermilion-gold palette, with moderate wet_blend.  These
             represent Titian's active wet-into-wet working method where colours
             are pushed and pulled across the wet surface before each layer dries.

          3. Impasto highlights: thick, directional highlight strokes in near-
             white to warm ivory are placed only at the highest luminance peaks
             (lum > 0.70).  These represent the loaded-brush impasto that gives
             Titian's surfaces their three-dimensional, relief-like quality.
             Titian's impasto reads as physically built-up paint even in
             reproduction — light catches the edges of thick strokes.

        Parameters
        ----------
        reference       : PIL Image or ndarray — painted base to glaze over.
        n_glaze_layers  : Number of transparent shadow glaze passes.
                          6–9 gives the characteristic Venetian depth; fewer
                          looks too thin, more can muddy the shadows.
        glaze_warmth    : Warmth of the shadow glaze (0 = neutral umber,
                          1 = full warm vermilion).  Titian's glazes are
                          distinctly warm — a value of 0.5–0.65 is authentic.
        shadow_depth    : Luminance threshold below which shadow glazing
                          is applied (0 = only deepest shadows, 1 = everywhere).
                          0.65–0.80 is appropriate; too high flattens lit areas.
        impasto_strokes : Number of loaded highlight strokes for the impasto
                          stage.  300–600 for a half-length portrait.
        impasto_size    : Mean brush radius for impasto strokes (pixels).
                          Titian's impasto is bold — 6–12px is appropriate.
        impasto_opacity : Opacity of impasto strokes.  High (0.80–0.95) so the
                          highlights are physically opaque, as in real impasto.
        """
        print(f"Venetian glaze pass  ({n_glaze_layers} glaze layers  "
              f"warmth={glaze_warmth:.2f}  impasto={impasto_strokes} strokes)…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        lum = (0.299 * rarr[:, :, 0] + 0.587 * rarr[:, :, 1] + 0.114 * rarr[:, :, 2])

        # ── Stage 1: Transparent warm shadow glazes ───────────────────────────
        # Titian's signature move: warm umber deepens shadows while preserving
        # their transparency.  Each glaze is a thin wash of warm-red tone,
        # masked to shadow regions.  The accumulated effect produces the
        # characteristic "glowing dark" of Venetian painting.
        warm_shadow_a = (0.55, 0.28, 0.12)   # warm red-umber base
        warm_shadow_b = (0.72, 0.40, 0.18)   # vermilion-shifted warm glaze
        ctx = self.canvas.ctx

        shadow_mask = np.clip((shadow_depth - lum) / max(shadow_depth, 0.01), 0.0, 1.0)
        if self._figure_mask is not None:
            shadow_mask = shadow_mask * self._figure_mask

        for i in range(n_glaze_layers):
            t = (i + 1) / n_glaze_layers
            # Alternate between warm umber and vermilion across layers —
            # Titian interleaved pigment types for chromatic complexity
            glaze_col = tuple(
                warm_shadow_a[c] * (1 - glaze_warmth) + warm_shadow_b[c] * glaze_warmth
                for c in range(3)
            )

            # Build glaze layer: current canvas colour shifted toward glaze_col
            # in shadow regions, at very low per-layer opacity (accumulates)
            per_layer_opacity = 0.055 * (0.7 + 0.3 * t)   # slightly heavier in later layers

            # ARGB32 premultiplied — shadow mask controls where glaze lands
            glaze_arr = np.zeros((h, w, 4), dtype=np.uint8)
            alpha_map = shadow_mask * per_layer_opacity
            premul = np.stack([
                alpha_map * glaze_col[2],  # B premul
                alpha_map * glaze_col[1],  # G premul
                alpha_map * glaze_col[0],  # R premul
            ], axis=2)
            glaze_arr[:, :, :3] = np.clip(premul * 255, 0, 255).astype(np.uint8)
            glaze_arr[:, :, 3]  = np.clip(alpha_map * 255, 0, 255).astype(np.uint8)

            glaze_surf = cairo.ImageSurface.create_for_data(
                bytearray(glaze_arr.tobytes()), cairo.FORMAT_ARGB32, w, h)
            ctx.set_source_surface(glaze_surf, 0, 0)
            ctx.paint()

        # ── Stage 2: Gestural mid-tone enrichment strokes ─────────────────────
        # Short, directional strokes in the Venetian vermilion-gold register are
        # pushed across mid-tone areas.  This represents Titian's wet-into-wet
        # working where colours are physically merged on the surface.
        venetian_palette = [
            (0.84, 0.28, 0.18),   # vermilion
            (0.76, 0.52, 0.18),   # Naples yellow-gold
            (0.90, 0.80, 0.60),   # warm ivory
            (0.60, 0.18, 0.14),   # deep red lake
        ]
        n_midtone_strokes = 300
        rng = self._rng_py

        for _ in range(n_midtone_strokes):
            # Sample position from mid-tone region (lum 0.30–0.65)
            attempts = 0
            cx_s = rng.randint(0, w - 1)
            cy_s = rng.randint(0, h - 1)
            while attempts < 8:
                tx = rng.randint(0, w - 1)
                ty = rng.randint(0, h - 1)
                if 0.28 < lum[ty, tx] < 0.68:
                    cx_s, cy_s = tx, ty
                    break
                attempts += 1

            col = venetian_palette[rng.randint(0, len(venetian_palette) - 1)]
            # Sample underlying colour for wet_blend mix
            ref_col = tuple(float(rarr[cy_s, cx_s, c]) for c in range(3))
            blended = tuple(
                math.sqrt(0.35 * col[c] ** 2 + 0.65 * ref_col[c] ** 2)
                for c in range(3)
            )
            sz = max(3.0, impasto_size * rng.uniform(0.6, 1.1))
            angle = rng.uniform(0, math.pi)
            length = sz * rng.uniform(2.0, 4.5)
            pts = stroke_path((cx_s, cy_s), angle, length, 0.06, 8)
            widths = [sz * w_v for w_v in width_profile(len(pts), tip_frac=0.28)]

            self.canvas.apply_stroke(
                pts, widths, blended,
                tip=BRUSH_PRESETS['hog_filbert'],
                opacity=0.28,
                wet_blend=0.72,
                jitter_amt=0.022,
                rng=rng,
                region_mask=self._figure_mask,
                pressure_profile=PressureProfile('feather', 0.55),
            )

        # ── Stage 3: Loaded impasto highlights ────────────────────────────────
        # Titian's impasto is a physical presence — thick ridges of lead white
        # and pale yellow that catch directional light.  Applied only at
        # luminance peaks so they read as genuine specular highlights.
        highlight_lum_thresh = 0.68
        highlight_palette = [
            (0.96, 0.92, 0.78),   # near-white ivory — lead white
            (0.94, 0.87, 0.62),   # warm Naples yellow-white
            (0.98, 0.95, 0.84),   # cool pale highlight
        ]

        highlight_mask = np.clip((lum - highlight_lum_thresh) / (1.0 - highlight_lum_thresh),
                                 0.0, 1.0)
        if self._figure_mask is not None:
            highlight_mask = highlight_mask * self._figure_mask

        placed = 0
        attempts_total = 0
        while placed < impasto_strokes and attempts_total < impasto_strokes * 8:
            attempts_total += 1
            tx = rng.randint(0, w - 1)
            ty = rng.randint(0, h - 1)
            if highlight_mask[ty, tx] < rng.uniform(0.1, 0.9):
                continue

            col = highlight_palette[rng.randint(0, len(highlight_palette) - 1)]
            # Mix with reference colour — impasto sits on top but is not fully opaque
            ref_col = tuple(float(rarr[ty, tx, c]) for c in range(3))
            mixed = tuple(
                math.sqrt(impasto_opacity * col[c] ** 2 + (1 - impasto_opacity) * ref_col[c] ** 2)
                for c in range(3)
            )
            sz = max(2.5, impasto_size * rng.uniform(0.5, 1.4))
            # Impasto strokes are short and fat — directional brush loads
            angle = rng.uniform(0, math.pi)
            length = sz * rng.uniform(1.5, 3.0)
            pts = stroke_path((tx, ty), angle, length, 0.04, 6)
            widths = [sz * w_v for w_v in width_profile(len(pts), tip_frac=0.22)]

            self.canvas.apply_stroke(
                pts, widths, mixed,
                tip=BRUSH_PRESETS['hog_flat'],
                opacity=impasto_opacity * 0.95,
                wet_blend=0.10,    # impasto: minimal blending, crisp mark
                jitter_amt=0.028,
                rng=rng,
                region_mask=self._figure_mask,
                pressure_profile=PressureProfile('stab', 1.0),
                paint_load=PaintLoad('every_stroke'),
            )
            placed += 1

        print(f"  Venetian glaze complete  ({n_glaze_layers} glazes, "
              f"{n_midtone_strokes} mid-tone strokes, {placed} impasto highlights)")

    def subsurface_glow_pass(self,
                             reference:     Union[np.ndarray, Image.Image],
                             glow_color:    Color = (0.90, 0.42, 0.24),
                             glow_strength: float = 0.18,
                             blur_sigma:    float = 10.0,
                             edge_falloff:  float = 0.55):
        """
        Subsurface scattering glow — simulates light transmission through thin skin.

        In real human skin, light does not simply bounce off the surface —
        it penetrates a millimetre or two, scatters through the translucent
        dermis, and exits at a slightly different point, tinted by the
        haemoglobin and melanin in the tissue.  The result is a warm reddish
        glow at the edges of the figure silhouette (where the skin is thin and
        the light path through tissue is short) and at anatomical thin-skin
        areas (ear lobes, nose tip, inner corners of the eye).

        Titian achieved this effect through red-lake glazes over white underpaint.
        The transparent red-lake layer selectively absorbs blue and green,
        transmitting warm red-orange light from the ground beneath.  The
        visual result is flesh that glows warm from within rather than reflecting
        cold light from the surface.

        Implementation
        --------------
        1. Detect edge/silhouette zone from the figure mask (or luminance
           gradient if no mask is available).  The glow is strongest where
           the figure boundary is thin and light can penetrate.
        2. Blur this zone outward (Gaussian) so the glow halos around the edge
           rather than sitting exactly on it.
        3. Tint the glow with a warm red-orange (haemoglobin scattering colour)
           and composite at low opacity over the existing painting.

        The pass should always be applied before final glazing so the glow
        is unified under the ambient glaze.

        Parameters
        ----------
        reference     : PIL Image or ndarray — used to detect edge zones.
        glow_color    : RGB tint of the scattered light.  (0.90, 0.42, 0.24)
                        is warm vermilion-orange — correct for pale skin.
                        Darker or more melanated skin should use a deeper,
                        more umber-red: e.g. (0.70, 0.28, 0.14).
        glow_strength : Maximum opacity of the glow composite.  0.10–0.25
                        is subtle and naturalistic; >0.35 looks artificial.
        blur_sigma    : Gaussian spread of the glow in pixels.  Larger values
                        create a broader, softer halo.  8–14px for a portrait
                        at 780×1080.
        edge_falloff  : How strongly to weight the glow toward true silhouette
                        edges vs. internal form-transition edges.  1.0 = figure
                        silhouette only; 0.0 = all luminance gradient edges.
                        0.5 gives a natural blend.
        """
        print(f"Subsurface glow pass  (glow={glow_color}  "
              f"strength={glow_strength:.2f}  sigma={blur_sigma:.1f})…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        lum = (0.299 * rarr[:, :, 0] + 0.587 * rarr[:, :, 1] + 0.114 * rarr[:, :, 2])

        # ── Build glow zone mask ──────────────────────────────────────────────
        # Primary source: figure silhouette edge (where mask transitions 0→1)
        if self._figure_mask is not None:
            # Detect silhouette edge via Sobel on the binary figure mask
            sil_gx = ndimage.sobel(self._figure_mask, axis=1).astype(np.float32)
            sil_gy = ndimage.sobel(self._figure_mask, axis=0).astype(np.float32)
            silhouette_edge = np.sqrt(sil_gx ** 2 + sil_gy ** 2)
            if silhouette_edge.max() > 1e-9:
                silhouette_edge /= silhouette_edge.max()
        else:
            silhouette_edge = np.zeros((h, w), dtype=np.float32)

        # Secondary source: luminance gradient (internal form transitions)
        lum_gx = ndimage.sobel(lum, axis=1).astype(np.float32)
        lum_gy = ndimage.sobel(lum, axis=0).astype(np.float32)
        lum_edge = np.sqrt(lum_gx ** 2 + lum_gy ** 2)
        if lum_edge.max() > 1e-9:
            lum_edge /= lum_edge.max()

        # Blend silhouette and luminance edges according to edge_falloff
        glow_zone = silhouette_edge * edge_falloff + lum_edge * (1.0 - edge_falloff)
        if glow_zone.max() > 1e-9:
            glow_zone /= glow_zone.max()

        # Blur outward so the glow halos around the edge
        glow_zone = ndimage.gaussian_filter(glow_zone.astype(np.float32), sigma=blur_sigma)
        glow_zone = np.clip(glow_zone * 3.5, 0.0, 1.0)

        # Restrict glow to figure interior and immediate edge only
        if self._figure_mask is not None:
            # Allow glow to extend slightly beyond figure boundary (halo effect)
            dilated_mask = ndimage.gaussian_filter(
                self._figure_mask.astype(np.float32), sigma=blur_sigma * 0.4)
            dilated_mask = np.clip(dilated_mask * 2.5, 0.0, 1.0)
            glow_zone = glow_zone * dilated_mask

        # ── Composite warm glow over current painting ─────────────────────────
        # ARGB32 premultiplied — Cairo compositing handles the alpha correctly
        ctx = self.canvas.ctx

        alpha_map = glow_zone * glow_strength
        alpha_3ch = alpha_map[:, :, np.newaxis]
        premul_rgb = np.array(glow_color)[np.newaxis, np.newaxis, :] * alpha_3ch

        glow_rgba = np.zeros((h, w, 4), dtype=np.uint8)
        glow_rgba[:, :, 0] = np.clip(premul_rgb[:, :, 2] * 255, 0, 255).astype(np.uint8)  # B premul
        glow_rgba[:, :, 1] = np.clip(premul_rgb[:, :, 1] * 255, 0, 255).astype(np.uint8)  # G premul
        glow_rgba[:, :, 2] = np.clip(premul_rgb[:, :, 0] * 255, 0, 255).astype(np.uint8)  # R premul
        glow_rgba[:, :, 3] = np.clip(alpha_map * 255, 0, 255).astype(np.uint8)             # A

        glow_surf = cairo.ImageSurface.create_for_data(
            bytearray(glow_rgba.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(glow_surf, 0, 0)
        ctx.paint()

        print(f"  Subsurface glow complete  "
              f"(peak alpha={glow_strength:.2f}  blur={blur_sigma:.1f}px)")

    # ─────────────────────────────────────────────────────────────────────────
    # Fauvist mosaic pass — Henri Matisse / Les Fauves (session 16)
    # ─────────────────────────────────────────────────────────────────────────

    def fauvist_mosaic_pass(self,
                            reference:         Union[np.ndarray, Image.Image],
                            n_zones:           int   = 8,
                            saturation_boost:  float = 1.70,
                            lum_flatten:       float = 0.55,
                            contour_thickness: float = 2.5,
                            contour_opacity:   float = 0.92,
                            n_zone_strokes:    int   = 0,
                            complement_shadow: bool  = True,
                            shadow_threshold:  float = 0.38):
        """
        Fauvist mosaic technique — inspired by Henri Matisse and Les Fauves.

        Fauvism (1905–1908) was the first European movement to declare that
        colour need not represent reality.  Matisse placed pure cadmium red
        where there was a green shadow, pure cerulean blue where there was a
        brown wall — not because he mis-observed, but because the emotional
        truth of the colour chord mattered more than accurate hue transcription.
        The result is a flat, tile-like mosaic of saturated zones, separated
        by coloured (not black) contour lines.

        This pass implements the three stages of Matisse's Fauvist technique:

          Stage 1 — Hue liberation:
            Quantize the reference image to N colour zones using PIL palette
            reduction.  For each zone, extract the dominant hue, then REPLACE
            it with the nearest hue from the Fauvist palette (pure primaries and
            secondaries at maximum saturation).  The palette is not neutral —
            every zone is forced toward full chromatic intensity.

          Stage 2 — Luminance suppression:
            Matisse flattened chiaroscuro: forms are indicated by hue contrast,
            not by light/shadow gradients.  The luminance channel is compressed
            toward mid-value by `lum_flatten` (0 = no suppression, 1 = all
            zones at uniform mid-grey value).  Shadow areas are particularly
            affected: instead of darkening toward brown/black, they receive
            the COMPLEMENTARY colour (orange for blue zones, green for red
            zones), making the shadow zone as vivid as the lit zone.

          Stage 3 — Coloured contour lines:
            Sobel-detect zone boundaries, then draw contour strokes in a
            saturated colour (not black) — Matisse used vermilion, deep green,
            and ultramarine as his contour colours.  The coloured outline is
            what gives Fauvist works their stained-glass quality.

        Parameters
        ----------
        reference         : PIL Image or ndarray reference for colour sampling.
        n_zones           : Number of flat colour zones (6–12 typical).
        saturation_boost  : HSV saturation multiplier applied to every zone
                           colour before painting.  1.60–1.90 gives vivid Fauvist
                           saturation; values above 2.0 clip excessively.
        lum_flatten       : Fraction by which luminance variation is suppressed
                           toward mid-value (0.50).  0 = no flattening (natural
                           contrast retained); 0.55 = moderate Fauvist flatness;
                           1.0 = all zones at exactly v=0.50.
        contour_thickness : Width of coloured contour strokes in pixels.
        contour_opacity   : Opacity of contour strokes (0–1).
        n_zone_strokes    : Loaded-brush strokes to apply per zone for texture.
                           0 = auto-compute from canvas area.
        complement_shadow : If True, shadow zones receive their complementary
                           hue rather than a darkened version of the local hue.
                           This is the defining Fauvist technique.
        shadow_threshold  : Reference luminance below which a pixel is
                           classified as a shadow zone (0–1).
        """
        print(f"Fauvist mosaic pass  (zones={n_zones}  sat_boost={saturation_boost:.2f}"
              f"  lum_flatten={lum_flatten:.2f})…")

        ref  = self._prep(reference)
        rarr = ref[:, :, :3].astype(np.float32) / 255.0
        h, w = ref.shape[:2]

        # ── Stage 1: Hue quantization and liberation ──────────────────────────
        # Convert reference to PIL and quantize to N zones using median-cut.
        ref_pil   = Image.fromarray(ref[:, :, :3])
        quantized = ref_pil.quantize(colors=n_zones, method=Image.Quantize.MEDIANCUT)
        zone_idx  = np.array(quantized, dtype=np.int32)   # (H, W) zone indices

        # Matisse Fauvist palette — pure, maximum-saturation hues.
        # These are the raw pigments he squeezed directly from tube onto canvas.
        fauvist_hues = [
            0.00,   # cadmium red
            0.08,   # cadmium orange
            0.15,   # cadmium yellow
            0.38,   # viridian green
            0.57,   # cerulean / cobalt blue
            0.75,   # ultramarine blue-violet
            0.85,   # violet-rose / magenta
            0.92,   # rose madder
        ]

        # For each zone, determine representative hue from reference,
        # then assign the nearest Fauvist hue at maximum saturation.
        n_z = n_zones
        zone_colors = {}
        for z in range(n_z):
            mask = zone_idx == z
            if mask.sum() < 1:
                zone_colors[z] = (0.60, 0.20, 0.15)  # fallback red
                continue
            # Mean reference colour for this zone
            mean_rgb = rarr[mask].mean(axis=0)
            mean_h, mean_s, mean_v = colorsys.rgb_to_hsv(*mean_rgb)

            # Apply luminance suppression toward 0.50
            suppressed_v = mean_v + (0.50 - mean_v) * lum_flatten

            # Complement shadow: if this zone is in shadow, rotate hue by 180°
            is_shadow_zone = mean_v < shadow_threshold
            if complement_shadow and is_shadow_zone:
                target_hue = (mean_h + 0.5) % 1.0
            else:
                # Snap to nearest Fauvist hue
                dists = [min(abs(mean_h - fh), 1.0 - abs(mean_h - fh))
                         for fh in fauvist_hues]
                target_hue = fauvist_hues[int(np.argmin(dists))]

            # Apply saturation boost (cap at 1.0)
            target_sat = min(1.0, max(0.35, mean_s) * saturation_boost)
            zone_colors[z] = colorsys.hsv_to_rgb(target_hue, target_sat,
                                                  suppressed_v)

        # ── Stage 2: Flat zone fill via loaded-brush strokes ──────────────────
        # Matisse covered each zone in confident flat loaded-brush patches.
        # Stroke count auto-scales with canvas size if n_zone_strokes == 0.
        total_strokes = n_zone_strokes if n_zone_strokes > 0 else max(
            1200, int(w * h / 480))
        strokes_per_zone = max(80, total_strokes // max(1, n_z))

        print(f"  Zone fill  ({n_z} zones  ~{strokes_per_zone} strokes each)…")

        tip_flat  = BrushTip(BrushTip.FLAT, bristle_noise=0.05)
        base_size = max(6, int(min(w, h) / 65))   # ~1.5% of smaller dimension

        for z in range(n_z):
            mask = (zone_idx == z).astype(np.float32)
            if mask.sum() < 4:
                continue

            # Combine zone mask with figure mask for figure zones
            region = mask
            if self._figure_mask is not None:
                region = region  # allow both figure and background zones

            # Error map: paint where reference zone colour differs most from canvas
            cbuf = np.frombuffer(self.canvas.surface.get_data(),
                                 dtype=np.uint8).reshape(h, w, 4).copy()
            carr = cbuf[:, :, [2, 1, 0]].astype(np.float32) / 255.0
            zt   = np.array(zone_colors[z], dtype=np.float32)
            err  = np.mean(np.abs(carr - zt[np.newaxis, np.newaxis, :]), axis=2)
            prob = (err * mask)
            total_p = prob.sum()
            if total_p < 1e-9:
                continue
            prob = prob / total_p

            positions = self.rng.choice(
                h * w, size=strokes_per_zone, p=prob.flatten(), replace=True)

            zc = zone_colors[z]
            for pos in positions:
                py, px = int(pos // w), int(pos % w)
                margin = max(base_size + 2, 4)
                px = int(np.clip(px, margin, w - margin))
                py = int(np.clip(py, margin, h - margin))

                # Short confident flat strokes — Matisse's direct loaded-brush mark
                stroke_size = float(base_size) * self._rng_py.uniform(0.7, 1.8)
                angle = self._rng_py.uniform(0, math.pi)
                L     = stroke_size * self._rng_py.uniform(1.2, 3.0)
                pts   = stroke_path((float(px), float(py)), angle, L,
                                    curve=0.0, n=max(2, int(L / 4)))
                ws    = [stroke_size] * len(pts)
                self.canvas.apply_stroke(
                    pts, ws, zc, tip_flat,
                    opacity=0.88, wet_blend=0.04,
                    jitter_amt=0.018, rng=self._rng_py,
                    region_mask=region,
                )

        # ── Stage 3: Coloured contour lines ───────────────────────────────────
        # Detect zone boundaries via Sobel on the quantized zone index map.
        # Draw coloured (not black) contour strokes — the stained-glass signature.
        print(f"  Coloured contour lines  (thickness={contour_thickness:.1f}px)…")

        # Boundary map from zone index discontinuities
        zf   = zone_idx.astype(np.float32)
        bx   = ndimage.sobel(zf, axis=1).astype(np.float32)
        by   = ndimage.sobel(zf, axis=0).astype(np.float32)
        bmag = np.sqrt(bx ** 2 + by ** 2)
        if bmag.max() > 1e-9:
            bmag /= bmag.max()

        # Contour angle map (perpendicular to gradient = along the boundary)
        bangles = np.arctan2(by, bx) + math.pi / 2.0

        # Contour colour: rich ultramarine blue-green — Matisse's preferred outline
        contour_color = (0.06, 0.28, 0.55)   # deep ultramarine

        # Place contour strokes along high-magnitude boundary pixels
        boundary_prob = (bmag ** 1.5).flatten()
        bp_total = boundary_prob.sum()
        if bp_total > 1e-9:
            boundary_prob /= bp_total
            n_contour = max(500, int(w * h / 700))
            positions = self.rng.choice(h * w, size=n_contour,
                                        p=boundary_prob, replace=True)
            tip_c = BrushTip(BrushTip.FLAT, bristle_noise=0.0)
            margin = max(3, int(contour_thickness * 2))

            for pos in positions:
                py, px = int(pos // w), int(pos % w)
                px = max(margin, min(w - margin, px))
                py = max(margin, min(h - margin, py))
                a  = float(bangles[py, px])
                L  = self._rng_py.uniform(6.0, 18.0)
                start = (px - math.cos(a) * L * 0.5,
                         py - math.sin(a) * L * 0.5)
                n_pts = max(3, int(L / 4))
                pts   = stroke_path(start, a, L, curve=0.0, n=n_pts)
                ws    = [contour_thickness] * len(pts)
                self.canvas.apply_stroke(
                    pts, ws, contour_color, tip_c,
                    opacity=contour_opacity, wet_blend=0.0,
                    jitter_amt=0.006, rng=self._rng_py,
                )

        print(f"  Fauvist mosaic complete")

    # ─────────────────────────────────────────────────────────────────────────
    # Chroma zone pass — tonal chroma management (session 16 random improvement)
    # ─────────────────────────────────────────────────────────────────────────

    def chroma_zone_pass(self,
                         light_suppress:  float = 0.55,
                         shadow_suppress: float = 0.40,
                         midtone_boost:   float = 1.20,
                         light_thresh:    float = 0.72,
                         shadow_thresh:   float = 0.30):
        """
        Tonal chroma management — inspired by Vermeer's luminance-saturation control.

        The Old Masters — Vermeer especially — understood that chromatic intensity
        (saturation) should vary across the luminance range in a specific, non-obvious
        way:

          • Highest lights → warm white, nearly neutral (low saturation).  Pure
            white light bleaches colour; the highest highlight on a red dress is
            almost white, not red.

          • Deep shadows → cool neutral (low saturation).  Pigment in the deepest
            shadows is absorbed by darkness; a saturated blue-black is less
            convincing than a near-neutral dark grey with a faint cool cast.

          • Mid-tones → maximum saturation.  This is where colour lives.  The
            'local colour' of a surface — its true red, blue, or green — is most
            legible in the mid-tone zone, where it is neither bleached by light
            nor absorbed by shadow.

        This pass reads the current canvas buffer, performs per-pixel HSV analysis,
        and applies three targeted adjustments:

          1. **Light zone suppression**: pixels above `light_thresh` luminance have
             their saturation multiplied by `light_suppress` (< 1.0), driving
             highlights toward warm white.

          2. **Shadow zone suppression**: pixels below `shadow_thresh` luminance have
             their saturation multiplied by `shadow_suppress` (< 1.0), driving
             deep shadows toward cool neutral.

          3. **Mid-tone boost**: pixels between the two thresholds have their
             saturation multiplied by `midtone_boost` (> 1.0), enriching the
             zone where colour is most expressive.

        All changes are vectorised via numpy and written back in a single Cairo
        surface operation — no stroke-by-stroke overhead.

        This pass should be called AFTER the main painting passes and BEFORE the
        final glaze and finish(), so that colour temperature of the glaze is applied
        on top of correctly managed saturation zones.

        Parameters
        ----------
        light_suppress  : Saturation multiplier for highlight pixels (< 1.0).
                         0.40–0.65 gives the warm-neutral highlight typical of
                         Vermeer and Dutch masters.
        shadow_suppress : Saturation multiplier for shadow pixels (< 1.0).
                         0.30–0.55 gives cool near-neutral darks.
        midtone_boost   : Saturation multiplier for mid-tone pixels (> 1.0).
                         1.15–1.35 enriches the local-colour zone without clipping.
        light_thresh    : Luminance threshold above which pixels are 'highlight'
                         zone (0–1).  0.68–0.75 is appropriate for oil painting.
        shadow_thresh   : Luminance threshold below which pixels are 'shadow'
                         zone (0–1).  0.25–0.35 is appropriate for oil painting.
        """
        print(f"Chroma zone pass  (light_suppress={light_suppress:.2f}"
              f"  shadow_suppress={shadow_suppress:.2f}"
              f"  midtone_boost={midtone_boost:.2f})…")

        h, w = self.h, self.w
        ctx  = self.canvas.ctx

        # Read current canvas (Cairo BGRA layout)
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(h, w, 4).copy()
        # Extract RGB float in [0, 1]
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0

        # Vectorised RGB → HSV
        # Luminance (value in HSV = max of RGB channels)
        v_ch = np.maximum(np.maximum(r_ch, g_ch), b_ch)
        mn   = np.minimum(np.minimum(r_ch, g_ch), b_ch)
        span = v_ch - mn

        # Saturation = span / v  (0 where v is 0)
        with np.errstate(divide='ignore', invalid='ignore'):
            s_ch = np.where(v_ch > 1e-9, span / v_ch, 0.0)

        # Hue (0–1 range)
        with np.errstate(divide='ignore', invalid='ignore'):
            h_ch = np.zeros_like(v_ch)
            # Red is max
            m = (v_ch == r_ch) & (span > 1e-9)
            h_ch[m] = ((g_ch[m] - b_ch[m]) / span[m]) % 6.0
            # Green is max
            m = (v_ch == g_ch) & (span > 1e-9)
            h_ch[m] = (b_ch[m] - r_ch[m]) / span[m] + 2.0
            # Blue is max
            m = (v_ch == b_ch) & (span > 1e-9)
            h_ch[m] = (r_ch[m] - g_ch[m]) / span[m] + 4.0
        h_ch = (h_ch / 6.0) % 1.0   # normalise to [0, 1]

        # ── Apply tonal chroma adjustments ───────────────────────────────────
        lum = v_ch  # use V channel as luminance proxy

        # Light zone: bleach toward neutral warm white
        light_mask   = lum >= light_thresh
        s_ch[light_mask] = np.clip(s_ch[light_mask] * light_suppress, 0.0, 1.0)

        # Shadow zone: cool near-neutral darks
        shadow_mask  = lum <= shadow_thresh
        s_ch[shadow_mask] = np.clip(s_ch[shadow_mask] * shadow_suppress, 0.0, 1.0)

        # Mid-tone zone: enrich local colour
        mid_mask = (~light_mask) & (~shadow_mask)
        s_ch[mid_mask] = np.clip(s_ch[mid_mask] * midtone_boost, 0.0, 1.0)

        # ── Vectorised HSV → RGB ─────────────────────────────────────────────
        # Uses the standard HSV→RGB sector formula, fully vectorised.
        h6   = h_ch * 6.0
        i    = np.floor(h6).astype(np.int32) % 6
        f    = h6 - np.floor(h6)
        p    = v_ch * (1.0 - s_ch)
        q    = v_ch * (1.0 - f * s_ch)
        t    = v_ch * (1.0 - (1.0 - f) * s_ch)

        r_out = np.select(
            [i == 0, i == 1, i == 2, i == 3, i == 4, i == 5],
            [v_ch,   q,      p,      p,      t,      v_ch],  0.0)
        g_out = np.select(
            [i == 0, i == 1, i == 2, i == 3, i == 4, i == 5],
            [t,      v_ch,   v_ch,   q,      p,      p],     0.0)
        b_out = np.select(
            [i == 0, i == 1, i == 2, i == 3, i == 4, i == 5],
            [p,      p,      t,      v_ch,   v_ch,   q],     0.0)

        # Clamp and write back to Cairo BGRA buffer
        buf[:, :, 2] = np.clip(r_out * 255, 0, 255).astype(np.uint8)  # R → BGRA[2]
        buf[:, :, 1] = np.clip(g_out * 255, 0, 255).astype(np.uint8)  # G → BGRA[1]
        buf[:, :, 0] = np.clip(b_out * 255, 0, 255).astype(np.uint8)  # B → BGRA[0]
        buf[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp, 0, 0)
        ctx.paint()

        print(f"  Chroma zone pass complete  "
              f"(light zone: {light_mask.sum()} px  "
              f"shadow zone: {shadow_mask.sum()} px  "
              f"mid-tone: {mid_mask.sum()} px)")

    # ─────────────────────────────────────────────────────────────────────────
    # Oval mask pass — Amedeo Modigliani / Primitivist portrait (session 17)
    # ─────────────────────────────────────────────────────────────────────────

    def oval_mask_pass(self,
                       reference:        Union[np.ndarray, Image.Image],
                       flesh_color:      Color = (0.84, 0.62, 0.38),
                       shadow_color:     Color = (0.68, 0.44, 0.24),
                       outline_color:    Color = (0.10, 0.07, 0.06),
                       outline_thickness: float = 2.5,
                       outline_opacity:  float = 0.88,
                       neck_elongation:  float = 0.18,
                       flesh_flatten:    float = 0.55,
                       flesh_tint:       float = 0.30):
        """
        Primitivist mask pass — inspired by Amedeo Modigliani.

        Modigliani's faces are derived from two primary sources: African ritual
        masks (long oval form, almond eye cavities) and Cycladic marble idols
        (featureless, archaic simplification).  His portrait technique reduces
        the human face to its essential geometry:

          1. An oval — smooth, unbroken, elongated about 30% beyond anatomical
             proportion.  One continuous contour line defines the whole face.

          2. Flat warm-ochre flesh fill — minimal modelling.  The only shadow
             colour is raw sienna or blue-grey, placed only beneath the chin
             and at the eye sockets.  No chiaroscuro: form is stated by the
             contour alone.

          3. Almond eyes — solid ellipses of cobalt blue or grey-mauve.  No
             pupils in the early work; tiny iris slits in the later portraits.
             The eye is a shape, not a window.

          4. Elongated neck — longer than the face itself, a single unbroken
             column.  This is the most visually distinctive Modigliani marker.

        Implementation
        --------------
        1. Detect face region from figure mask (upper figure region) or
           luminance analysis if no mask is available.

        2. Within the face ellipse: compress luminance variation toward a
           neutral mid-value (``flesh_flatten`` controls strength).  This
           simulates the near-total suppression of chiaroscuro Modigliani used.

        3. Tint the flattened face zone toward warm ochre (``flesh_tint``
           controls strength — 0 = unchanged, 1 = fully ochre).

        4. Draw a smooth oval contour around the detected face region using
           Cairo arc operations.  The oval is slightly taller than the detected
           face (elongation factor), giving the mask-like silhouette.

        5. Elongate the neck: extend the face contour downward by
           ``neck_elongation`` as a fraction of the face height.

        Parameters
        ----------
        reference         : PIL Image or ndarray — used for luminance analysis.
        flesh_color       : RGB of the warm ochre flesh fill target.
        shadow_color      : RGB of the raw sienna shadow placed at chin/eyes.
        outline_color     : RGB of the near-black oval contour line.
        outline_thickness : Width of the contour line in pixels.
        outline_opacity   : Alpha of the contour composite.
        neck_elongation   : Neck extension as fraction of face height (0.18 =
                            18%).  Modigliani's necks are about 0.3–0.45 of the
                            face height but 0.18–0.25 is enough in the pipeline.
        flesh_flatten     : Strength of luminance compression in the face zone
                            (0 = no change, 1 = fully flat mid-value).
        flesh_tint        : Strength of ochre tint overlay (0 = no tint,
                            1 = full replacement with flesh_color).

        Notes
        -----
        Famous works to study:
          *Jeanne Hébuterne with a Hat* (1918) — definitive oval, tilted neck.
          *Nu couché* (1917) — the mask face on a reclining nude.
          *Portrait of Lunia Czechowska* (1918) — severe elongation, cobalt eyes.
        """
        print(f"Oval mask pass  (flatten={flesh_flatten:.2f}  tint={flesh_tint:.2f}  "
              f"neck={neck_elongation:.2f})…")

        ref  = self._prep(reference)
        h, w = ref.shape[:2]

        # ── Locate face ellipse centre from figure mask ───────────────────────
        # If a figure mask is available, the face is in the upper ~40% of the
        # figure bounding box.  Without a mask, fall back to the upper-centre
        # of the canvas where a portrait subject would typically sit.
        if self._figure_mask is not None:
            rows   = np.any(self._figure_mask > 0.5, axis=1)
            cols   = np.any(self._figure_mask > 0.5, axis=0)
            if rows.any() and cols.any():
                r0, r1 = int(np.argmax(rows)), int(h - 1 - np.argmax(rows[::-1]))
                c0, c1 = int(np.argmax(cols)), int(w - 1 - np.argmax(cols[::-1]))
                # Face is upper 40% of figure height
                face_top    = r0
                face_bottom = r0 + int((r1 - r0) * 0.42)
                face_cx     = (c0 + c1) // 2
                face_cy     = (face_top + face_bottom) // 2
                face_ry     = max(20, (face_bottom - face_top) // 2)
                face_rx     = max(14, int(face_ry * 0.62))   # oval is taller than wide
            else:
                face_cx, face_cy = w // 2, h // 3
                face_ry = h // 6
                face_rx = int(face_ry * 0.62)
        else:
            face_cx, face_cy = w // 2, h // 3
            face_ry = h // 6
            face_rx = int(face_ry * 0.62)

        # ── Stage 1: Flatten and tint face zone ──────────────────────────────
        # Read current canvas pixel values
        ctx  = self.canvas.ctx
        surf = self.canvas.surface
        buf  = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()

        # Build face ellipse mask (soft-edged)
        yy, xx = np.ogrid[:h, :w]
        dist_sq = ((xx - face_cx) / max(face_rx, 1)) ** 2 + \
                  ((yy - face_cy) / max(face_ry, 1)) ** 2
        # Feather: 1.0 at centre, 0.0 outside the ellipse, smooth transition
        face_zone = np.clip(1.5 - dist_sq, 0.0, 1.0).astype(np.float32)

        # Current canvas RGB (Cairo BGRA: [B, G, R, A])
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        lum = 0.299 * r_ch + 0.587 * g_ch + 0.114 * b_ch
        mid_lum = float(np.median(lum[face_zone > 0.5])) if (face_zone > 0.5).any() else 0.55

        # Compress luminance variation toward mid-value within face zone
        # New lum = lerp(lum, mid_lum, flesh_flatten * face_zone)
        blend_w = flesh_flatten * face_zone
        flat_r  = r_ch * (1.0 - blend_w) + mid_lum * blend_w
        flat_g  = g_ch * (1.0 - blend_w) + mid_lum * blend_w
        flat_b  = b_ch * (1.0 - blend_w) + mid_lum * blend_w

        # Tint face zone toward warm ochre flesh colour
        fr, fg, fb = flesh_color
        tint_w = flesh_tint * face_zone
        final_r = flat_r * (1.0 - tint_w) + fr * tint_w
        final_g = flat_g * (1.0 - tint_w) + fg * tint_w
        final_b = flat_b * (1.0 - tint_w) + fb * tint_w

        # Write back into buffer (BGRA order)
        buf[:, :, 2] = np.clip(final_r * 255, 0, 255).astype(np.uint8)  # R
        buf[:, :, 1] = np.clip(final_g * 255, 0, 255).astype(np.uint8)  # G
        buf[:, :, 0] = np.clip(final_b * 255, 0, 255).astype(np.uint8)  # B
        buf[:, :, 3] = 255

        tmp_surf = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp_surf, 0, 0)
        ctx.paint()

        # ── Stage 2: Draw oval contour and neck line ──────────────────────────
        # Modigliani's contour is a single continuous near-black line around the
        # face oval.  The neck is two near-parallel lines extending downward from
        # the chin point, separated by roughly the chin width.
        neck_length = int(face_ry * neck_elongation * 2.0)
        or_, og, ob = outline_color

        ctx.save()
        ctx.set_source_rgba(or_, og, ob, outline_opacity)
        ctx.set_line_width(outline_thickness)

        # Face oval (slightly taller than detected: *1.05 elongation factor)
        oval_ry = face_ry * 1.05
        oval_rx = face_rx
        ctx.arc(face_cx, face_cy, 1.0, 0, 2 * math.pi)  # unit circle → scaled
        ctx.new_path()
        ctx.save()
        ctx.translate(face_cx, face_cy)
        ctx.scale(oval_rx, oval_ry)
        ctx.arc(0, 0, 1.0, 0, 2 * math.pi)
        ctx.restore()
        ctx.stroke()

        # Neck column: two vertical lines from chin down by neck_length
        chin_y   = face_cy + int(oval_ry)
        neck_w   = max(4, int(face_rx * 0.38))   # neck width fraction of face

        ctx.move_to(face_cx - neck_w, chin_y)
        ctx.line_to(face_cx - neck_w, chin_y + neck_length)
        ctx.stroke()

        ctx.move_to(face_cx + neck_w, chin_y)
        ctx.line_to(face_cx + neck_w, chin_y + neck_length)
        ctx.stroke()

        ctx.restore()

        print(f"  Oval mask pass complete  "
              f"(face_cx={face_cx}, face_cy={face_cy}  "
              f"rx={face_rx}, ry={face_ry}  neck={neck_length}px)")

    # ─────────────────────────────────────────────────────────────────────────
    # Warm-cool boundary pass — session 17 random artistic improvement
    # ─────────────────────────────────────────────────────────────────────────

    def warm_cool_boundary_pass(self,
                                strength:    float = 0.14,
                                edge_thresh: float = 0.08,
                                blur_sigma:  float = 1.8,
                                warm_push:   Color = (0.12, 0.02, -0.06),
                                cool_push:   Color = (-0.06, 0.01, 0.10)):
        """
        Warm-cool boundary vibration — universally applicable tonal refinement.

        Painters from Delacroix through Cézanne, the Impressionists, and
        Modigliani discovered that boundaries between colour areas appear more
        perceptually vivid when warm and cool tones are juxtaposed across the
        edge.  This is simultaneous contrast (Chevreul, 1839): each colour
        intensifies the apparent contrast of its neighbour across an edge by
        shifting the viewer's perception slightly toward the complementary.

        In practice this means:
          - The warm side of a boundary (more red/yellow) gets a micro-push
            toward warm (boost R slightly, damp B).
          - The cool side (more blue/green) gets a micro-push toward cool
            (boost B slightly, damp R).

        The visual result is that boundaries feel "inhabited" — alive and
        subtly vibrating — rather than static.  This is particularly important
        in portrait painting where the face-to-background edge is the central
        perceptual event.

        Unlike folk_retablo_pass() boundary_vibration (which uses explicit
        warm/cool strokes at zone edges), this pass operates directly on the
        canvas pixel buffer using vectorised numpy operations — fast, globally
        applied, and style-agnostic.  It is useful after any style pass that
        tends to produce flat or dead-looking boundaries.

        Implementation
        --------------
        1. Read the current canvas buffer as float32 RGB.
        2. Compute a Sobel edge-magnitude map.
        3. Threshold: pixels above ``edge_thresh`` are boundary pixels.
        4. For each boundary pixel, classify as "warm side" or "cool side"
           by comparing local R+G (warm channels) vs B+G (cool channels).
           A simple warm/cool score = (R - B) in the blurred reference.
        5. Apply ``warm_push`` delta to warm-side boundary pixels and
           ``cool_push`` delta to cool-side boundary pixels, weighted by
           edge magnitude and ``strength``.
        6. Composite back to the Cairo surface.

        Parameters
        ----------
        strength    : Overall intensity of the temperature push.  0.10–0.18
                      is subtle and naturalistic; >0.25 reads as artificial.
        edge_thresh : Minimum normalised edge magnitude to receive the push.
                      0.06–0.12 is a good range.
        blur_sigma  : Gaussian blur applied to the edge map before thresholding,
                      so isolated noise pixels don't fire.  1.5–2.5 is good.
        warm_push   : RGB delta applied to the warm side of each boundary.
                      Positive R, small positive G, negative B = red-orange push.
        cool_push   : RGB delta applied to the cool side.
                      Negative R, small positive G, positive B = blue-violet push.

        Notes
        -----
        This pass should be called AFTER the main style passes and BEFORE the
        final glaze/vignette.  It is particularly effective after:
          - oval_mask_pass() — to make the face-background boundary vibrate
          - fauvist_mosaic_pass() — to micro-push zone boundaries even further
          - flat_plane_pass() — to animate Manet's flat value-plane edges
        """
        print(f"Warm-cool boundary pass  (strength={strength:.2f}  "
              f"thresh={edge_thresh:.2f}  sigma={blur_sigma:.1f})…")

        surf = self.canvas.surface
        h, w = surf.get_height(), surf.get_width()

        buf = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()

        # Current canvas RGB (Cairo BGRA: [B, G, R, A])
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        # ── Edge detection ───────────────────────────────────────────────────
        lum = 0.299 * r_ch + 0.587 * g_ch + 0.114 * b_ch
        gx  = ndimage.sobel(lum, axis=1).astype(np.float32)
        gy  = ndimage.sobel(lum, axis=0).astype(np.float32)
        edge_mag = np.sqrt(gx ** 2 + gy ** 2)
        if edge_mag.max() > 1e-9:
            edge_mag /= edge_mag.max()

        # Smooth to reduce noise
        edge_mag = ndimage.gaussian_filter(edge_mag, sigma=blur_sigma)
        if edge_mag.max() > 1e-9:
            edge_mag /= edge_mag.max()

        # ── Warm / cool classification ───────────────────────────────────────
        # warm_score > 0 → warm side (reddish), < 0 → cool side (bluish)
        warm_score = r_ch - b_ch

        # Apply a slight blur so that classification reflects local neighbourhood,
        # not just the single edge pixel (which may be a neutral transition colour).
        warm_score = ndimage.gaussian_filter(warm_score, sigma=blur_sigma * 1.5)

        warm_side = warm_score > 0.0
        cool_side = ~warm_side

        # ── Build delta maps ─────────────────────────────────────────────────
        # Weight by edge magnitude * strength so only true boundaries are affected.
        edge_weight = np.clip(edge_mag, 0.0, 1.0) * strength

        # Only apply where edge is above threshold
        active = edge_mag > edge_thresh

        dr = np.zeros((h, w), dtype=np.float32)
        dg = np.zeros((h, w), dtype=np.float32)
        db = np.zeros((h, w), dtype=np.float32)

        # Warm-side pixels get the warm push
        wp = active & warm_side
        dr[wp] += warm_push[0] * edge_weight[wp]
        dg[wp] += warm_push[1] * edge_weight[wp]
        db[wp] += warm_push[2] * edge_weight[wp]

        # Cool-side pixels get the cool push
        cp = active & cool_side
        dr[cp] += cool_push[0] * edge_weight[cp]
        dg[cp] += cool_push[1] * edge_weight[cp]
        db[cp] += cool_push[2] * edge_weight[cp]

        # ── Apply deltas to canvas buffer ────────────────────────────────────
        buf[:, :, 2] = np.clip((r_ch + dr) * 255, 0, 255).astype(np.uint8)  # R
        buf[:, :, 1] = np.clip((g_ch + dg) * 255, 0, 255).astype(np.uint8)  # G
        buf[:, :, 0] = np.clip((b_ch + db) * 255, 0, 255).astype(np.uint8)  # B
        buf[:, :, 3] = 255

        ctx = self.canvas.ctx
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp, 0, 0)
        ctx.paint()

        n_active = int(active.sum())
        n_warm   = int((active & warm_side).sum())
        n_cool   = int((active & cool_side).sum())
        print(f"  Warm-cool boundary pass complete  "
              f"(active={n_active}px  warm={n_warm}  cool={n_cool})")

    def glazed_panel_pass(self,
                          reference:       Union[np.ndarray, Image.Image],
                          n_glaze_layers:  int   = 8,
                          glaze_opacity:   float = 0.07,
                          shadow_warmth:   float = 0.28,
                          highlight_cool:  float = 0.12,
                          shadow_thresh:   float = 0.38,
                          highlight_thresh: float = 0.72,
                          panel_bloom:     float = 0.08):
        """
        Flemish panel painting glaze technique — inspired by Jan van Eyck.

        Van Eyck's revolutionary contribution was the systematic use of
        transparent oil glazes stacked over a chalk-white gesso panel ground.
        Unlike tempera (which is opaque and cannot be glazed), oil paint can be
        diluted to near-transparency.  Each glaze layer adds colour depth while
        allowing light to penetrate to the brilliant white ground below and
        reflect back upward through all layers — creating a luminosity that no
        opaque paint technique can replicate.

        The key physics: light entering a glazed oil painting travels through
        N transparent films of varying colour, strikes the white ground, and
        returns through the same films.  Shadow areas accumulate more amber-
        umber glaze (warm deep shadows); highlights retain the cool brilliance
        of the nearly-bare white ground.  This warm-shadow / cool-highlight
        reversal is the defining quality of Flemish panel luminosity and the
        opposite of the warm-light / cool-shadow convention used in outdoor
        Impressionism.

        Implementation
        --------------
        1. Read current canvas buffer as float32 RGB.
        2. Build a per-pixel luminance map from the reference.
        3. Shadow zones (lum < shadow_thresh): accumulate thin warm amber-umber
           glaze layers — each layer is composited at very low opacity so the
           effect builds gradually without over-darkening.
        4. Highlight zones (lum > highlight_thresh): apply a faint cool-neutral
           tint toward the chalk-white panel ground — the highlights are not
           pushed warm; they stay cool and bright.
        5. Mid-tone zones receive balanced warm/cool glazes for tonal unity.
        6. Panel bloom: a very slight radial luminance boost centred on the
           brightest highlight zone, simulating how light diffuses slightly in
           the topmost oil glaze film.

        Parameters
        ----------
        reference        : PIL Image or numpy array — original scene reference
                           used to compute the luminance guidance map.
        n_glaze_layers   : Number of simulated transparent glaze layers to
                           accumulate.  8–12 is realistic for a Flemish portrait.
        glaze_opacity    : Per-layer opacity.  0.05–0.10 keeps each layer
                           physically thin.  n_layers × opacity = total shadow depth.
        shadow_warmth    : Warmth of the shadow glaze (R-channel boost, B-damp).
                           0.20–0.35 gives the characteristic warm Flemish shadow.
        highlight_cool   : Cool pull applied to highlights.  0.08–0.15 gives
                           the chalk-grey Flemish highlight quality.
        shadow_thresh    : Luminance below which shadow glaze is applied (0–1).
        highlight_thresh : Luminance above which highlight cool is applied (0–1).
        panel_bloom      : Opacity of the panel bloom diffusion (0.05–0.12).

        Notes
        -----
        This pass must be called AFTER the main form-building passes and BEFORE
        the final glaze / vignette calls.  It is designed for EARLY_NETHERLANDISH
        period but the luminosity effect is beneficial for any period using a
        light ground (BAROQUE, RENAISSANCE).
        """
        print(f"Glazed panel pass  (n_layers={n_glaze_layers}  "
              f"opacity={glaze_opacity:.3f}  shadow_warmth={shadow_warmth:.2f})…")

        surf = self.canvas.surface
        h, w = surf.get_height(), surf.get_width()

        # ── Build luminance guidance map from reference ───────────────────────
        ref_arr = self._prep(reference)   # (H, W, 3) uint8
        ref_f   = ref_arr.astype(np.float32) / 255.0
        lum_ref = (0.299 * ref_f[:, :, 0]
                   + 0.587 * ref_f[:, :, 1]
                   + 0.114 * ref_f[:, :, 2])   # (H, W) in [0, 1]

        # Resize lum_ref to canvas size if needed
        if lum_ref.shape != (h, w):
            from PIL import Image as _PILImg
            lum_pil = _PILImg.fromarray((lum_ref * 255).astype(np.uint8), "L")
            lum_pil = lum_pil.resize((w, h), _PILImg.BILINEAR)
            lum_ref = np.array(lum_pil).astype(np.float32) / 255.0

        # ── Read canvas buffer ────────────────────────────────────────────────
        buf = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        # ── Shadow zone glaze accumulation ────────────────────────────────────
        # Warm amber-umber glaze: boost R slightly, slightly reduce B.
        # Multiple thin layers simulate the stacked transparent film effect.
        shadow_mask = np.clip((shadow_thresh - lum_ref) / shadow_thresh, 0.0, 1.0)
        # Slightly blur the mask for smooth zone transitions
        shadow_mask = ndimage.gaussian_filter(shadow_mask.astype(np.float32), sigma=2.0)

        glaze_r_boost =  shadow_warmth * 0.55
        glaze_b_damp  = -shadow_warmth * 0.35
        glaze_g_boost =  shadow_warmth * 0.08

        for _ in range(n_glaze_layers):
            alpha = glaze_opacity * shadow_mask
            r_ch = np.clip(r_ch + alpha * glaze_r_boost, 0.0, 1.0)
            g_ch = np.clip(g_ch + alpha * glaze_g_boost, 0.0, 1.0)
            b_ch = np.clip(b_ch + alpha * glaze_b_damp,  0.0, 1.0)

        # ── Highlight zone cool pull ──────────────────────────────────────────
        # Chalk-white gesso reflects slightly cool — the highest lights retain
        # a slight blue-grey neutral quality (not the warm highlights of Italian oil).
        highlight_mask = np.clip((lum_ref - highlight_thresh) / (1.0 - highlight_thresh),
                                 0.0, 1.0)
        highlight_mask = ndimage.gaussian_filter(highlight_mask.astype(np.float32), sigma=1.5)

        cool_r_damp  = -highlight_cool * 0.30
        cool_b_boost =  highlight_cool * 0.25
        cool_g_boost =  highlight_cool * 0.05

        r_ch = np.clip(r_ch + highlight_mask * cool_r_damp,  0.0, 1.0)
        g_ch = np.clip(g_ch + highlight_mask * cool_g_boost, 0.0, 1.0)
        b_ch = np.clip(b_ch + highlight_mask * cool_b_boost, 0.0, 1.0)

        # ── Panel bloom — diffuse luminance spread at brightest highlight ─────
        # The outermost oil glaze film creates a slight scattering halo around
        # specular highlights, visible in close inspection of van Eyck's panels
        # (e.g. the pearls in the Arnolfini Portrait).
        if panel_bloom > 0.001:
            bright_zone = np.clip((lum_ref - 0.85) / 0.15, 0.0, 1.0).astype(np.float32)
            bloom = ndimage.gaussian_filter(bright_zone, sigma=4.0)
            if bloom.max() > 1e-9:
                bloom = bloom / bloom.max() * panel_bloom
            r_ch = np.clip(r_ch + bloom, 0.0, 1.0)
            g_ch = np.clip(g_ch + bloom * 0.92, 0.0, 1.0)
            b_ch = np.clip(b_ch + bloom * 0.82, 0.0, 1.0)

        # ── Write back to canvas ──────────────────────────────────────────────
        buf[:, :, 2] = np.clip(r_ch * 255, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(g_ch * 255, 0, 255).astype(np.uint8)
        buf[:, :, 0] = np.clip(b_ch * 255, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255

        ctx = self.canvas.ctx
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp, 0, 0)
        ctx.paint()

        shadow_px    = int((shadow_mask > 0.1).sum())
        highlight_px = int((highlight_mask > 0.1).sum())
        print(f"  Glazed panel pass complete  "
              f"(shadow_px={shadow_px}  highlight_px={highlight_px}  "
              f"layers={n_glaze_layers})")

    def micro_detail_pass(self,
                          strength:       float = 0.22,
                          fine_sigma:     float = 0.8,
                          coarse_sigma:   float = 3.5,
                          edge_thresh:    float = 0.06,
                          light_boost:    float = 0.18,
                          shadow_deepen:  float = 0.14,
                          figure_only:    bool  = True):
        """
        Flemish micro-detail enhancement — inspired by Jan van Eyck's
        hyper-precise rendering of individual hairs, fabric threads, and
        gemstone reflections.

        Van Eyck painted at a level of detail that remained unmatched until
        photography: individual hairs are painted one by one, fabric weave
        threads are rendered at near-microscopic scale, reflections in pearls
        and polished metal show tiny accurate mirror images of the room.
        This was possible partly because of the slow-drying oil medium
        (allowing fine rework) and partly because of his extraordinary
        patience and technique.

        The micro-detail pass enhances fine-scale edge contrast across the
        entire canvas — brightening the light side of every fine edge and
        deepening the shadow side.  This is equivalent to an unsharp-mask
        but physically motivated: it simulates the way a thin specular
        oil film produces micro-highlights along texture ridges.

        Implementation
        --------------
        1. Read the current canvas RGB buffer.
        2. Compute a fine-scale luminance gradient (tight Sobel with small sigma).
        3. Subtract a coarse-scale gradient to isolate only the finest edges
           (high-pass filtering in the spatial frequency domain).
        4. For each fine edge pixel:
             - The light side (gradient pointing toward bright area) receives
               a small brightness boost (``light_boost``).
             - The shadow side receives a small darkening (``shadow_deepen``).
        5. Apply ``strength`` weighting and ``edge_thresh`` threshold so that
           only genuine fine edges are processed, not noise or flat areas.
        6. If ``figure_only`` and a figure mask exists, restrict the pass to
           the figure region (fabric, skin, hair).

        Parameters
        ----------
        strength      : Overall intensity multiplier.  0.15–0.25 is subtle
                        and naturalistic; >0.35 looks sharpened.
        fine_sigma    : Gaussian blur sigma for the fine edge detection.
                        0.5–1.0 captures hair-scale detail.
        coarse_sigma  : Gaussian blur sigma for the coarse subtracted layer.
                        3.0–5.0 removes broad gradients, isolating micro-detail.
        edge_thresh   : Minimum edge magnitude (fine-scale, normalised) to
                        receive the micro-detail enhancement.  0.04–0.08 is good.
        light_boost   : Brightness boost applied to the light side of fine edges.
                        Simulates specular oil film micro-highlights.
        shadow_deepen : Darkening applied to the shadow side of fine edges.
                        Simulates the tiny shadow grooves of fabric weave.
        figure_only   : If True and a figure mask is loaded, restrict the pass
                        to the figure region only.  This prevents excessive
                        sharpening of background elements.

        Notes
        -----
        This pass should be called AFTER glazed_panel_pass() and BEFORE the
        final vignette.  It is designed for EARLY_NETHERLANDISH period but
        benefits any period with visible micro-texture (BAROQUE, VENETIAN_RENAISSANCE,
        MANNERIST).  Keep strength below 0.30 to avoid an over-sharpened look.
        """
        print(f"Micro-detail pass  (strength={strength:.2f}  "
              f"fine_sigma={fine_sigma:.1f}  coarse_sigma={coarse_sigma:.1f})...")

        surf = self.canvas.surface
        h, w = surf.get_height(), surf.get_width()

        buf = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        lum = 0.299 * r_ch + 0.587 * g_ch + 0.114 * b_ch

        # ── Fine-scale edge detection ─────────────────────────────────────────
        # Blur at fine scale, then compute Sobel gradient.
        lum_fine   = ndimage.gaussian_filter(lum, sigma=fine_sigma)
        gx_fine    = ndimage.sobel(lum_fine, axis=1).astype(np.float32)
        gy_fine    = ndimage.sobel(lum_fine, axis=0).astype(np.float32)
        mag_fine   = np.sqrt(gx_fine ** 2 + gy_fine ** 2)

        # ── Coarse-scale edge detection to subtract ───────────────────────────
        # Removing the coarse gradient isolates only micro-scale edges.
        lum_coarse = ndimage.gaussian_filter(lum, sigma=coarse_sigma)
        gx_coarse  = ndimage.sobel(lum_coarse, axis=1).astype(np.float32)
        gy_coarse  = ndimage.sobel(lum_coarse, axis=0).astype(np.float32)
        mag_coarse = np.sqrt(gx_coarse ** 2 + gy_coarse ** 2)

        # High-pass: fine edges minus coarse edges
        mag_micro = np.clip(mag_fine - mag_coarse * 0.5, 0.0, None)
        if mag_micro.max() > 1e-9:
            mag_micro = mag_micro / mag_micro.max()

        # ── Build enhancement weight map ──────────────────────────────────────
        active     = mag_micro > edge_thresh
        edge_wt    = np.clip(mag_micro, 0.0, 1.0) * strength

        # Apply figure mask if requested
        if figure_only and self._figure_mask is not None:
            active  = active & (self._figure_mask > 0.1)
            edge_wt = edge_wt * self._figure_mask

        # ── Gradient direction for light/shadow side classification ───────────
        # The gradient vector points from dark → bright.
        # Light side: move in gradient direction → more luminance nearby → boost.
        # Shadow side: move against gradient direction → less luminance → deepen.
        # Approximate: use local luminance relative to neighbourhood mean.
        lum_mean = ndimage.uniform_filter(lum, size=5)
        light_side = (lum > lum_mean) & active
        shadow_side = (lum <= lum_mean) & active

        # ── Apply enhancement ─────────────────────────────────────────────────
        boost_map  = light_boost  * edge_wt
        deepen_map = shadow_deepen * edge_wt

        r_ch = np.clip(r_ch + light_side * boost_map  - shadow_side * deepen_map, 0.0, 1.0)
        g_ch = np.clip(g_ch + light_side * boost_map * 0.95 - shadow_side * deepen_map * 0.95, 0.0, 1.0)
        b_ch = np.clip(b_ch + light_side * boost_map * 0.88 - shadow_side * deepen_map * 0.90, 0.0, 1.0)

        # ── Write back to canvas ──────────────────────────────────────────────
        buf[:, :, 2] = np.clip(r_ch * 255, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(g_ch * 255, 0, 255).astype(np.uint8)
        buf[:, :, 0] = np.clip(b_ch * 255, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255

        ctx = self.canvas.ctx
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp, 0, 0)
        ctx.paint()

        n_boosted  = int(light_side.sum())
        n_deepened = int(shadow_side.sum())
        print(f"  Micro-detail pass complete  "
              f"(light_side={n_boosted}px  shadow_side={n_deepened}px)")

    # ──────────────────────────────────────────────────────────────────────────
    # chiaroscuro_focus_pass — Artemisia Gentileschi / Caravaggesque spotlight
    # ──────────────────────────────────────────────────────────────────────────

    def chiaroscuro_focus_pass(self,
                               light_center:      Tuple[float, float] = (0.35, 0.30),
                               light_radius:      float = 0.38,
                               falloff_sharpness: float = 2.5,
                               shadow_strength:   float = 0.72,
                               shadow_color:      Color = (0.28, 0.18, 0.08),
                               light_warmth:      float = 0.12,
                               light_boost:       float = 0.06,
                               figure_only:       bool  = False):
        """
        Caravaggesque spotlight effect inspired by Artemisia Gentileschi.

        Gentileschi used a tightly focused single light source to pool warm
        ivory light in one zone while the rest of the composition fell into
        deep, velvety warm shadow.  Unlike Rembrandt's rough impasto highlights,
        her lit surfaces are smooth and seamless — built from careful blending
        rather than thick paint application.

        This pass simulates the directional falloff of her characteristic
        single-candle or directed-window lighting:

        1. Each pixel receives a light weight = exp(-d^p / r^p) where d is the
           distance from light_center (in normalised canvas coords), p =
           falloff_sharpness, and r = light_radius.  This creates a Gaussian-
           like pool for p≈2 or a harder-edged lantern at p>3.
        2. Shadow zone (weight < 0.5): progressively blend toward shadow_color.
           The blend amount is proportional to (1 - weight)^1.5, keeping the
           mid-tone transition smooth.
        3. Light zone (weight > 0.5): apply a subtle warm shift (light_warmth)
           and a small luminance boost (light_boost) to emphasise the pool.

        Parameters
        ----------
        light_center      : (cx, cy) in normalised [0,1] canvas coordinates.
                            (0,0) = top-left; (1,1) = bottom-right.
                            Default (0.35, 0.30) — upper-left source, Gentileschi
                            convention matching Caravaggio's typical arrangement.
        light_radius      : Radius of the light pool in normalised coords.
                            0.25 = very tight spot; 0.50 = broad soft fill.
        falloff_sharpness : Exponent p of the falloff curve.  2.0 = Gaussian
                            (soft); 3.5+ = lantern-like (hard edge).
        shadow_strength   : Maximum darkening factor in the shadow zone.
                            0.60 = moderate shadow; 0.85 = near-black void.
        shadow_color      : Target colour in the deepest shadow zone.
                            Warm umber default matches Gentileschi's dark grounds.
        light_warmth      : Red-channel boost in the light zone.  Simulates the
                            warm amber tint of candlelight / northern window.
        light_boost       : Overall luminance boost in the lit zone.
        figure_only       : If True and a figure mask is loaded, restrict shadow
                            darkening to the figure; leave the background as-is.
                            Default False — Gentileschi darkens backgrounds too.

        Notes
        -----
        Call AFTER block_in() / build_form() and BEFORE the final glaze.
        Combine with impasto_texture_pass() on the lit highlights for a more
        Caravaggesque texture in the specular peaks, or omit for Gentileschi's
        characteristic smooth luminosity.
        """
        print(f"Chiaroscuro focus pass  (center={light_center}  "
              f"radius={light_radius:.2f}  strength={shadow_strength:.2f})…")

        surf = self.canvas.surface
        h, w = surf.get_height(), surf.get_width()

        buf = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        # ── Build distance field from light_center ─────────────────────────────
        cx_px = light_center[0] * w
        cy_px = light_center[1] * h
        # Normalised distance — use canvas diagonal as reference so radius is scale-invariant
        diag = math.sqrt(w * w + h * h)

        ys = np.arange(h, dtype=np.float32)
        xs = np.arange(w, dtype=np.float32)
        xx, yy = np.meshgrid(xs, ys)
        dist_px = np.sqrt((xx - cx_px) ** 2 + (yy - cy_px) ** 2)
        dist_n  = dist_px / diag   # normalised distance

        # ── Light weight map ───────────────────────────────────────────────────
        # Soft exponential falloff: weight = exp(-(d/r)^p)
        p       = max(1.0, falloff_sharpness)
        r_n     = max(1e-6, light_radius)
        wt      = np.exp(- (dist_n / r_n) ** p)   # shape (h, w), range [0, 1]

        # ── Shadow zone blend ─────────────────────────────────────────────────
        # blend_amount: how much to push toward shadow_color (stronger away from light)
        blend_amount = np.clip((1.0 - wt) ** 1.5 * shadow_strength, 0.0, 1.0)

        sc_r, sc_g, sc_b = shadow_color
        r_new = r_ch * (1.0 - blend_amount) + sc_r * blend_amount
        g_new = g_ch * (1.0 - blend_amount) + sc_g * blend_amount
        b_new = b_ch * (1.0 - blend_amount) + sc_b * blend_amount

        # ── Light zone warm boost ──────────────────────────────────────────────
        # Only applied where wt > 0.5 — the illuminated pool
        lit_mask = wt > 0.5
        lit_wt   = np.clip((wt - 0.5) * 2.0, 0.0, 1.0)   # 0→1 in the lit zone

        r_new = np.clip(r_new + lit_mask * lit_wt * (light_warmth + light_boost), 0.0, 1.0)
        g_new = np.clip(g_new + lit_mask * lit_wt * light_boost * 0.85,           0.0, 1.0)
        b_new = np.clip(b_new + lit_mask * lit_wt * light_boost * 0.65,           0.0, 1.0)

        # ── Apply figure mask restriction ──────────────────────────────────────
        if figure_only and self._figure_mask is not None:
            fm = self._figure_mask
            r_new = r_ch * (1.0 - fm) + r_new * fm
            g_new = g_ch * (1.0 - fm) + g_new * fm
            b_new = b_ch * (1.0 - fm) + b_new * fm

        # ── Write back ─────────────────────────────────────────────────────────
        buf[:, :, 2] = np.clip(r_new * 255, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(g_new * 255, 0, 255).astype(np.uint8)
        buf[:, :, 0] = np.clip(b_new * 255, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255

        ctx = self.canvas.ctx
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp, 0, 0)
        ctx.paint()

        n_lit    = int(lit_mask.sum())
        n_shadow = int((~lit_mask).sum())
        print(f"  Chiaroscuro focus pass complete  "
              f"(lit_zone={n_lit}px  shadow_zone={n_shadow}px)")

    # ──────────────────────────────────────────────────────────────────────────
    # highlight_bloom_pass — luminous glow around specular highlights
    # ──────────────────────────────────────────────────────────────────────────

    def highlight_bloom_pass(self,
                             threshold:     float = 0.78,
                             bloom_sigma:   float = 8.0,
                             bloom_opacity: float = 0.22,
                             bloom_color:   Optional[Color] = None,
                             multi_scale:   bool  = True,
                             figure_only:   bool  = False):
        """
        Subtle photographic bloom around the brightest specular highlights.

        In real optical systems — the human eye, early photographic lenses,
        and oil-painted varnish surfaces — very bright highlights scatter light
        into the surrounding area.  This creates a soft luminous halo, sometimes
        called 'halation', where the specular peak bleeds into the adjacent mid-tone.

        Classical portrait painters were aware of this effect: Leonardo described
        how the eye cannot focus on extreme brightness without perceiving a soft
        surrounding glow.  Gentileschi's smooth highlights on forehead and
        cheekbones appear to radiate light rather than simply reflect it — partly
        a painting convention and partly a faithful rendering of what the eye sees.

        Implementation
        --------------
        1. Read the current canvas buffer and compute luminance.
        2. Extract a highlight mask: pixels where luminance >= threshold.
        3. Multiply the RGB of masked pixels by the mask weight to get the
           'raw bloom source'.
        4. Apply Gaussian blur at bloom_sigma (and optionally at 2× and 4× for a
           multi-scale glow that has a tight inner core and a soft outer halo).
        5. Blend the blurred bloom glow back onto the canvas using a soft-light
           compositing formula: result = canvas + glow × bloom_opacity.
        6. Apply optional bloom_color tint (default: slightly warmer than the
           original highlight, simulating the warm chromatic aberration of light
           scattering through oil or glass).

        Parameters
        ----------
        threshold    : Luminance threshold above which a pixel contributes to the
                       bloom source.  0.75–0.85 isolates only the specular peaks.
        bloom_sigma  : Gaussian blur sigma for the bloom halo.  5–10 = tight,
                       elegant; 15–25 = broader, more romantic glow.
        bloom_opacity: Blend weight of the glow layer.  0.10–0.20 = subtle and
                       photographic; 0.30+ = impressionistic light flare.
        bloom_color  : Optional (R,G,B) tint applied to the glow layer.  None =
                       use the native highlight colour (no tint).  A very slight
                       warm tint (0.02, 0.0, -0.01) simulates candlelight.
        multi_scale  : If True, add a tighter inner glow (sigma/2) at half opacity
                       and a broader outer halo (sigma*2) at quarter opacity, giving
                       the characteristic three-layer bloom of optical systems.
        figure_only  : If True and a figure mask is loaded, restrict the bloom to
                       the figure region only.

        Notes
        -----
        Call AFTER all painting passes and BEFORE the final vignette / crackle.
        This is the last image-enhancement step before finishing, so it should
        see the near-final colour values.  Keep bloom_opacity low (0.12–0.22) for
        realism; higher values become painterly or impressionistic.
        """
        print(f"Highlight bloom pass  (threshold={threshold:.2f}  "
              f"sigma={bloom_sigma:.1f}  opacity={bloom_opacity:.2f})…")

        surf = self.canvas.surface
        h, w = surf.get_height(), surf.get_width()

        buf = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        lum = 0.299 * r_ch + 0.587 * g_ch + 0.114 * b_ch

        # ── Build highlight source mask ────────────────────────────────────────
        # Weight ramps smoothly from 0 at threshold to 1 at pure white.
        hi_wt = np.clip((lum - threshold) / max(1.0 - threshold, 1e-6), 0.0, 1.0)

        if figure_only and self._figure_mask is not None:
            hi_wt = hi_wt * self._figure_mask

        # ── Bloom source: highlight-coloured, weighted ─────────────────────────
        bloom_r = r_ch * hi_wt
        bloom_g = g_ch * hi_wt
        bloom_b = b_ch * hi_wt

        # ── Blur the bloom source — optionally at multiple scales ──────────────
        sigma = max(0.5, bloom_sigma)

        def _blur_channel(ch: np.ndarray, s: float) -> np.ndarray:
            return ndimage.gaussian_filter(ch, sigma=s)

        glow_r = _blur_channel(bloom_r, sigma)
        glow_g = _blur_channel(bloom_g, sigma)
        glow_b = _blur_channel(bloom_b, sigma)

        if multi_scale:
            # Inner tight glow (sigma/2) at 50% weight
            ir = _blur_channel(bloom_r, sigma * 0.5)
            ig = _blur_channel(bloom_g, sigma * 0.5)
            ib = _blur_channel(bloom_b, sigma * 0.5)
            glow_r = glow_r + ir * 0.50
            glow_g = glow_g + ig * 0.50
            glow_b = glow_b + ib * 0.50
            # Outer broad halo (sigma*2) at 25% weight
            or_ = _blur_channel(bloom_r, sigma * 2.0)
            og  = _blur_channel(bloom_g, sigma * 2.0)
            ob  = _blur_channel(bloom_b, sigma * 2.0)
            glow_r = glow_r + or_ * 0.25
            glow_g = glow_g + og  * 0.25
            glow_b = glow_b + ob  * 0.25

        # ── Apply optional colour tint ─────────────────────────────────────────
        if bloom_color is not None:
            bc_r, bc_g, bc_b = bloom_color
            # Tint the glow layer: blend toward tint color weighted by glow intensity
            glow_lum = (glow_r + glow_g + glow_b) / 3.0
            glow_r = glow_r * (1.0 - 0.35) + bc_r * glow_lum * 0.35
            glow_g = glow_g * (1.0 - 0.35) + bc_g * glow_lum * 0.35
            glow_b = glow_b * (1.0 - 0.35) + bc_b * glow_lum * 0.35

        # ── Composite: additive blend clamped ─────────────────────────────────
        r_out = np.clip(r_ch + glow_r * bloom_opacity, 0.0, 1.0)
        g_out = np.clip(g_ch + glow_g * bloom_opacity, 0.0, 1.0)
        b_out = np.clip(b_ch + glow_b * bloom_opacity, 0.0, 1.0)

        # ── Write back ─────────────────────────────────────────────────────────
        buf[:, :, 2] = np.clip(r_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(g_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 0] = np.clip(b_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255

        ctx = self.canvas.ctx
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp, 0, 0)
        ctx.paint()

        n_bloomed = int((hi_wt > 0.01).sum())
        print(f"  Highlight bloom pass complete  (bloom_source={n_bloomed}px)")

    def art_deco_facet_pass(self,
                            reference,
                            n_zones:           int   = 5,
                            smooth_sigma:      float = 3.5,
                            boundary_contrast: float = 0.28,
                            metallic_sheen:    float = 0.22,
                            saturation_boost:  float = 1.18,
                            sheen_color:       Optional[Color] = None,
                            figure_only:       bool  = False):
        """
        Art Deco faceted surface technique inspired by Tamara de Lempicka.

        De Lempicka painted flesh and drapery as a series of smooth, clearly
        bounded tonal facets — influenced equally by Ingres' polished surfaces
        and Léger's Cubist geometry.  Each facet is a discrete, nearly flat
        plane of colour.  The boundary between adjacent facets is sharpened
        to a crisp, slightly darker edge.  The overall surface reads as
        lacquered or enamelled — metal, not skin.

        The technique differs from Manet's flat_plane_pass in that:
        (a) de Lempicka's zones are smoothed *within* but contrasted *between* —
            a distinct polished-metal quality rather than Manet's chalky flatness;
        (b) a metallic sheen highlight (cool silver-cream) is placed at the top
            of each bright zone boundary, simulating the specular ridge of a
            curved reflective surface;
        (c) shadow zones receive a saturation boost toward the dominant hue —
            de Lempicka's shadows are rich and chromatic, never muddy grey.

        Implementation
        --------------
        1. Read canvas buffer; compute luminance map.
        2. Quantize luminance into n_zones tonal bands.
        3. Within each zone, apply Gaussian smoothing (sigma=smooth_sigma) to
           suppress micro-variation (the intra-zone polish).
        4. Detect zone boundaries with Sobel; build a boundary weight map.
        5. At boundaries: push toward darker tone on shadow side, lighter cool
           sheen (sheen_color) on highlight side — boundary_contrast controls
           the strength of this edge sharpening.
        6. Boost saturation in mid-tone and shadow zones (metallic surfaces
           desaturate in direct light, saturate in shadow).
        7. Composite back onto canvas; optionally figure-only.

        Parameters
        ----------
        n_zones           : Number of tonal quantization bands.  3 = very broad
                            cubist planes; 6 = finely faceted, almost smooth.
        smooth_sigma      : Gaussian sigma for intra-zone smoothing.  Higher =
                            more polished, less textured surfaces.
        boundary_contrast : Strength of boundary sharpening.  0.0 = no effect;
                            0.4 = very dramatic edge sharpening.
        metallic_sheen    : Opacity of the cool silver highlight placed at the
                            top (light side) of each boundary.
        saturation_boost  : HSV saturation multiplier applied to shadow and
                            mid-tone zones.  > 1.0 = richer shadow colour.
        sheen_color       : RGB of the metallic sheen highlight.  Default is
                            a cool silver-cream (0.90, 0.88, 0.86).
        figure_only       : If True and a figure mask is loaded, restrict the
                            pass to the figure region only.
        """
        print(f"Art Deco facet pass  (zones={n_zones}  sigma={smooth_sigma:.1f}  "
              f"contrast={boundary_contrast:.2f}  sheen={metallic_sheen:.2f})…")

        if sheen_color is None:
            sheen_color = (0.90, 0.88, 0.86)   # cool silver-cream

        surf = self.canvas.surface
        h, w = surf.get_height(), surf.get_width()

        buf = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        lum = 0.299 * r_ch + 0.587 * g_ch + 0.114 * b_ch

        # ── Figure mask ────────────────────────────────────────────────────────
        fig_mask = self._figure_mask if (figure_only and self._figure_mask is not None) \
                   else np.ones((h, w), dtype=np.float32)

        # ── Stage 1: Tonal zone quantization ──────────────────────────────────
        zone_idx = np.floor(np.clip(lum, 0.0, 1.0 - 1e-6) * n_zones).astype(np.int32)

        # ── Stage 2: Per-zone Gaussian smoothing (intra-zone polish) ──────────
        r_smooth = ndimage.gaussian_filter(r_ch, sigma=smooth_sigma)
        g_smooth = ndimage.gaussian_filter(g_ch, sigma=smooth_sigma)
        b_smooth = ndimage.gaussian_filter(b_ch, sigma=smooth_sigma)

        # Blend toward smoothed version within each zone (intra-zone polish)
        # The zone index keeps boundary transitions from bleeding across zones.
        smooth_weight = 0.65   # 65% toward smoothed — keeps paint-feel from disappearing
        r_out = r_ch * (1.0 - smooth_weight) + r_smooth * smooth_weight
        g_out = g_ch * (1.0 - smooth_weight) + g_smooth * smooth_weight
        b_out = b_ch * (1.0 - smooth_weight) + b_smooth * smooth_weight

        # ── Stage 3: Zone boundary detection ──────────────────────────────────
        # Sobel on the quantized zone index map — picks up tonal boundaries.
        zone_float = zone_idx.astype(np.float32)
        sobel_x = ndimage.sobel(zone_float, axis=1)
        sobel_y = ndimage.sobel(zone_float, axis=0)
        boundary = np.sqrt(sobel_x**2 + sobel_y**2)
        # Normalise boundary to [0, 1]
        b_max = boundary.max()
        if b_max > 1e-6:
            boundary = boundary / b_max

        # ── Stage 4: Boundary sharpening ──────────────────────────────────────
        # Shadow side of each boundary: push slightly darker (warm umber)
        # Light side: add cool silver sheen
        # The Sobel gradient direction distinguishes warm from cool side:
        # positive gradient = transitioning to lighter zone (light side here)
        grad_dir = np.sign(sobel_y + sobel_x)   # rough light/shadow discriminator

        # Boundary weight: how strongly to apply sharpening at each pixel
        bwt = np.clip(boundary * boundary_contrast, 0.0, 1.0) * fig_mask

        # Shadow-side darkening (where gradient direction indicates shadow approach)
        shadow_side = np.clip(grad_dir * -1.0, 0.0, 1.0)   # pixels on shadow side
        r_out = r_out - bwt * shadow_side * 0.18
        g_out = g_out - bwt * shadow_side * 0.14
        b_out = b_out - bwt * shadow_side * 0.10

        # Light-side metallic sheen (cool silver-cream highlight at boundary ridge)
        light_side = np.clip(grad_dir, 0.0, 1.0)   # pixels on light side
        sheen_wt = bwt * light_side * metallic_sheen
        r_out = r_out + (sheen_color[0] - r_out) * sheen_wt
        g_out = g_out + (sheen_color[1] - g_out) * sheen_wt
        b_out = b_out + (sheen_color[2] - b_out) * sheen_wt

        # ── Stage 5: Shadow/midtone saturation boost ──────────────────────────
        # De Lempicka's shadows are richly coloured, never grey.
        # Convert to HSV, boost S in dark and mid-tone zones.
        r_vec = r_out.ravel()
        g_vec = g_out.ravel()
        b_vec = b_out.ravel()

        import colorsys as _cs
        r_new = r_vec.copy()
        g_new = g_vec.copy()
        b_new = b_vec.copy()

        lum_out = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
        # Apply saturation boost only to mid-tone and shadow pixels
        boost_mask = (lum_out < 0.72).ravel()
        for i in np.where(boost_mask)[0]:
            rv, gv, bv = float(r_vec[i]), float(g_vec[i]), float(b_vec[i])
            hh, ss, vv = _cs.rgb_to_hsv(rv, gv, bv)
            ss = min(1.0, ss * saturation_boost)
            rr, gg, bb = _cs.hsv_to_rgb(hh, ss, vv)
            r_new[i], g_new[i], b_new[i] = rr, gg, bb

        r_out = r_new.reshape(h, w)
        g_out = g_new.reshape(h, w)
        b_out = b_new.reshape(h, w)

        # ── Clamp and write back ───────────────────────────────────────────────
        buf[:, :, 2] = np.clip(r_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(g_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 0] = np.clip(b_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255

        ctx = self.canvas.ctx
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp, 0, 0)
        ctx.paint()

        n_boundary_px = int((boundary > 0.1).sum())
        print(f"  Art Deco facet pass complete  "
              f"(boundary={n_boundary_px}px  zones={n_zones})")

    def velatura_pass(self,
                      midtone_tint:       Color = (0.62, 0.52, 0.32),
                      shadow_tint:        Optional[Color] = None,
                      midtone_opacity:    float = 0.10,
                      shadow_opacity:     float = 0.06,
                      midtone_lo:         float = 0.28,
                      midtone_hi:         float = 0.72,
                      lum_preserve:       bool  = True,
                      figure_only:        bool  = False):
        """
        Italian Old Master velatura (glazed midtone enrichment) technique.

        Velatura — from the Italian for 'veil' — is a technique in which a thin,
        semi-transparent coloured glaze is applied selectively over the midtone
        zones of a painting.  Unlike an overall unifying glaze (which shifts the
        entire surface), velatura is zone-selective: it enriches the mid-value
        range where local colour is most expressive while leaving highlights
        (which should stay cool-neutral) and deep shadows (which should stay
        warm-dark) relatively undisturbed.

        The technique was described by Cennini and practiced by Leonardo, Titian,
        and the Flemish masters.  In portraits it creates the sensation that flesh
        has an inner warmth — as if blood moves beneath the surface.  In landscape
        it deepens the colour complexity of middle-distance zones.

        This pass differs from the Painter.glaze() method in three ways:
        (a) It is zone-selective (midtone only), not uniform;
        (b) An optional complementary shadow tint can be applied to shadow zones
            simultaneously, creating optical depth from the warm/cool pairing;
        (c) Luminance preservation: the tint shifts hue and saturation but does
            not change the value, keeping the tonal structure intact.

        Implementation
        --------------
        1. Read canvas buffer; compute luminance.
        2. Build a soft midtone mask: 1.0 at the midtone centre, falling off to
           0.0 at shadow_lo and highlight_hi boundaries (triangle falloff).
        3. Blend each midtone pixel toward midtone_tint weighted by mask ×
           midtone_opacity.  If lum_preserve=True, adjust the tinted result to
           match the original luminance (hue/chroma shift only).
        4. If shadow_tint is given, build a complementary shadow mask and apply
           the same blend logic to shadow-zone pixels.
        5. Composite result back onto canvas; optionally figure-only.

        Parameters
        ----------
        midtone_tint    : Warm or cool tint colour for the midtone zone.  Default
                          (0.62, 0.52, 0.32) = warm amber — typical Leonardo/Titian.
                          A cool blue-grey (0.42, 0.50, 0.58) works for austere
                          Northern European portraits.
        shadow_tint     : Optional tint for shadow zone.  None = no shadow tint.
                          A warm umber (0.35, 0.24, 0.10) deepens shadows richly.
        midtone_opacity : Blend strength toward midtone_tint.  0.05–0.15 = subtle
                          and authentic; > 0.25 = strongly coloured, painterly.
        shadow_opacity  : Blend strength toward shadow_tint (if given).
        midtone_lo      : Lower luminance boundary of the midtone zone.
        midtone_hi      : Upper luminance boundary of the midtone zone.
        lum_preserve    : If True, adjust tinted result to maintain original
                          luminance so the pass is purely a hue/chroma enrichment.
        figure_only     : If True and a figure mask is loaded, restrict the pass
                          to the figure region only.

        Notes
        -----
        Call AFTER main painting passes (underpainting, block_in, build_form,
        place_lights) and BEFORE the final glaze and finish.  Velatura is an
        intermediate enrichment step, not a finishing varnish.
        """
        print(f"Velatura pass  (midtone_tint={midtone_tint}  "
              f"opacity={midtone_opacity:.2f}  lum_preserve={lum_preserve})…")

        surf = self.canvas.surface
        h, w = surf.get_height(), surf.get_width()

        buf = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        lum = 0.299 * r_ch + 0.587 * g_ch + 0.114 * b_ch

        # ── Figure mask ────────────────────────────────────────────────────────
        fig_mask = self._figure_mask if (figure_only and self._figure_mask is not None) \
                   else np.ones((h, w), dtype=np.float32)

        # ── Build midtone mask (triangle falloff) ─────────────────────────────
        mid_center = (midtone_lo + midtone_hi) * 0.5
        mid_half   = (midtone_hi - midtone_lo) * 0.5
        # Linear ramp from 0 at edges to 1 at center of midtone zone
        mid_mask = np.clip(1.0 - np.abs(lum - mid_center) / max(mid_half, 1e-6),
                           0.0, 1.0) * fig_mask

        # ── Apply midtone tint ─────────────────────────────────────────────────
        mt_r, mt_g, mt_b = midtone_tint
        blend_wt = mid_mask * midtone_opacity

        r_out = r_ch + (mt_r - r_ch) * blend_wt
        g_out = g_ch + (mt_g - g_ch) * blend_wt
        b_out = b_ch + (mt_b - b_ch) * blend_wt

        # ── Luminance preservation ─────────────────────────────────────────────
        if lum_preserve:
            lum_out = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
            # Scale RGB uniformly so lum_out matches original lum
            # Avoid divide-by-zero in near-black areas
            scale = np.where(lum_out > 1e-4, lum / (lum_out + 1e-6), 1.0)
            scale = np.clip(scale, 0.0, 3.0)   # guard against runaway in pure black
            r_out = np.clip(r_out * scale, 0.0, 1.0)
            g_out = np.clip(g_out * scale, 0.0, 1.0)
            b_out = np.clip(b_out * scale, 0.0, 1.0)

        # ── Optional shadow tint ───────────────────────────────────────────────
        if shadow_tint is not None:
            st_r, st_g, st_b = shadow_tint
            # Shadow mask: pixels below midtone_lo, falling off to 0 at midtone_lo
            shad_mask = np.clip(1.0 - lum / max(midtone_lo, 1e-6),
                                0.0, 1.0) * fig_mask
            s_wt = shad_mask * shadow_opacity

            r_out = r_out + (st_r - r_out) * s_wt
            g_out = g_out + (st_g - g_out) * s_wt
            b_out = b_out + (st_b - b_out) * s_wt

            if lum_preserve:
                lum_out2 = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
                scale2 = np.where(lum_out2 > 1e-4, lum / (lum_out2 + 1e-6), 1.0)
                scale2 = np.clip(scale2, 0.0, 3.0)
                r_out = np.clip(r_out * scale2, 0.0, 1.0)
                g_out = np.clip(g_out * scale2, 0.0, 1.0)
                b_out = np.clip(b_out * scale2, 0.0, 1.0)

        # ── Write back ─────────────────────────────────────────────────────────
        buf[:, :, 2] = np.clip(r_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(g_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 0] = np.clip(b_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255

        ctx = self.canvas.ctx
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp, 0, 0)
        ctx.paint()

        n_midtone_px = int((mid_mask > 0.05).sum())
        print(f"  Velatura pass complete  (midtone_zone={n_midtone_px}px  "
              f"lo={midtone_lo:.2f}  hi={midtone_hi:.2f})")

    def chromatic_shadow_pass(self,
                              shadow_threshold: float = 0.42,
                              strength:         float = 0.22,
                              shadow_tint:      Optional[Color] = None,
                              lum_preserve:     bool  = True,
                              figure_only:      bool  = False):
        """
        Chromatic shadow pass — inspired by Eugène Delacroix's key colour discovery.

        Delacroix's journal records his pivotal observation: shadows are not simply
        dark versions of the lit colour — they contain the chromatic COMPLEMENT of
        the dominant light.  Under warm (yellowish) light, shadows trend toward
        violet-blue; under cool (bluish) studio light, shadows trend toward warm
        amber-orange.  This is the foundational insight that separates Delacroix
        from the academic tradition and anticipates Impressionism by 30 years.

        This pass identifies shadow zones (luminance < shadow_threshold) and adds a
        subtle complementary tint to each pixel in proportion to its darkness.  The
        luminance is optionally preserved (hue/chroma shift only, not brightness) so
        the pass cannot lighten or darken the painting — only enrich the colour depth
        of shadow passages.

        Implementation
        --------------
        1. Read the current canvas buffer as float32 RGB.
        2. Compute per-pixel luminance.
        3. Build a shadow weight: shadow_wt = max(0, (threshold − lum) / threshold)^1.5
           — ramps from 0 at the threshold boundary to maximum at luminance = 0.
        4. Compute the per-pixel complement colour:
               complement = (1 − r, 1 − g, 1 − b)   [spectral complement]
           If shadow_tint is provided, use that as the fixed tint colour instead.
        5. Blend toward the complement by shadow_wt × strength × 0.5:
               r_out = r + blend × (tint_r − r)
        6. If lum_preserve: rescale each output pixel to match the original luminance,
           keeping all brightness intact — only hue and saturation shift.
        7. Apply optional figure_only masking.

        Parameters
        ----------
        shadow_threshold : Luminance below which a pixel is 'in shadow'.
                          0.42 captures the lower half of the tonal range.
                          Lower (0.30) → stronger effect; higher (0.55) → includes
                          mid-tones.
        strength         : Maximum blend fraction toward the complement colour.
                          0.15–0.25 = subtle, photographic (Impressionist level).
                          0.30–0.45 = strong, expressive (late Delacroix).
        shadow_tint      : Optional fixed (R,G,B) shadow tint.  Use when the dominant
                          light colour is known, e.g. (0.30, 0.25, 0.70) for violet
                          shadows under warm candlelight.  None = per-pixel complement.
        lum_preserve     : If True (default), rescale each shadow pixel to its
                          original luminance after blending (chrominance-only shift).
                          If False, the complement blend may lighten dark pixels.
        figure_only      : If True and a figure mask is loaded, restrict the chromatic
                          shift to the figure region only.

        Notes
        -----
        Call AFTER block_in() and build_form() but BEFORE the final glaze, so the
        chromatic shift is gently softened by the glaze layer on top.

        Delacroix used this empirically; Chevreul formulated it as the law of
        simultaneous contrast (1839); Seurat operationalised it as Divisionism;
        Monet made it the entire subject of his serial paintings (Haystacks,
        Rouen Cathedral series).
        """
        print(f"Chromatic shadow pass  (threshold={shadow_threshold:.2f}  "
              f"strength={strength:.2f}  lum_preserve={lum_preserve})…")

        surf = self.canvas.surface
        h, w = surf.get_height(), surf.get_width()

        buf = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()
        # Cairo FORMAT_ARGB32 byte order: index 0=B, 1=G, 2=R, 3=A
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        lum = 0.299 * r_ch + 0.587 * g_ch + 0.114 * b_ch

        # ── Shadow weight: strongest in deepest darks, fades to 0 at threshold ──
        # Power 1.5 concentrates the effect in the true shadow zones and avoids
        # contaminating the mid-tone range where the effect would look muddy.
        shadow_wt = np.clip(
            (shadow_threshold - lum) / max(shadow_threshold, 1e-6), 0.0, 1.0
        ) ** 1.5

        # ── Optional figure mask ──────────────────────────────────────────────
        if figure_only and self._figure_mask is not None:
            shadow_wt = shadow_wt * self._figure_mask

        # ── Target tint per pixel ─────────────────────────────────────────────
        if shadow_tint is not None:
            # Fixed shadow tint: the painter knows the dominant light colour
            tint_r = np.full_like(r_ch, float(shadow_tint[0]))
            tint_g = np.full_like(g_ch, float(shadow_tint[1]))
            tint_b = np.full_like(b_ch, float(shadow_tint[2]))
        else:
            # Per-pixel spectral complement: each shadow pixel drifts toward
            # its chromatic opposite.  Warm shadow pixels → cooler tint;
            # cool shadow pixels → warmer tint.  Exactly Delacroix's observation.
            tint_r = 1.0 - r_ch
            tint_g = 1.0 - g_ch
            tint_b = 1.0 - b_ch

        # ── Blend toward tint in proportion to shadow weight ──────────────────
        # Factor of 0.5 dampens the blend to a gentle chromatic enrichment rather
        # than a jarring hue inversion.  Delacroix's effect is felt, not seen.
        blend = shadow_wt * strength * 0.5
        r_out = r_ch + blend * (tint_r - r_ch)
        g_out = g_ch + blend * (tint_g - g_ch)
        b_out = b_ch + blend * (tint_b - b_ch)

        # ── Luminance preservation ────────────────────────────────────────────
        # Rescale each pixel so the output luminance matches the input.
        # This ensures chromatic_shadow_pass is a pure hue/saturation adjustment —
        # it cannot brighten or darken the painting, only enrich shadow colour.
        if lum_preserve:
            out_lum = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
            # Where the shadow_wt is near-zero, scale ≈ 1.0 (no change).
            # Clamp scale to [0.5, 2.0] to prevent numerical explosion near black.
            scale = np.where(
                out_lum > 1e-6,
                np.clip(lum / (out_lum + 1e-8), 0.5, 2.0),
                1.0
            )
            r_out = np.clip(r_out * scale, 0.0, 1.0)
            g_out = np.clip(g_out * scale, 0.0, 1.0)
            b_out = np.clip(b_out * scale, 0.0, 1.0)
        else:
            r_out = np.clip(r_out, 0.0, 1.0)
            g_out = np.clip(g_out, 0.0, 1.0)
            b_out = np.clip(b_out, 0.0, 1.0)

        # ── Write back to canvas surface ──────────────────────────────────────
        buf[:, :, 0] = np.clip(b_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(g_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 2] = np.clip(r_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255

        ctx = self.canvas.ctx
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp, 0, 0)
        ctx.paint()

        n_shadow = int((shadow_wt > 0.01).sum())
        print(f"  Chromatic shadow pass complete  (shadow_pixels={n_shadow})")

    def scumble_pass(self,
                     opacity:        float = 0.18,
                     drag_distance:  int   = 14,
                     n_drags:        int   = 420,
                     dry_factor:     float = 0.72,
                     angle_jitter:   float = 0.45,
                     figure_only:    bool  = False):
        """
        Dry-brush scumbling: semi-opaque paint dragged sideways over a dry surface.

        Scumbling is the counterpart of glazing.  Where glazing applies a
        transparent dark layer to deepen shadows (working from dark to light),
        scumbling drags a lighter, semi-opaque colour across a darker dry surface
        (working from dark toward light).  It is the technique that gives the
        chalky, slightly broken surface quality distinctive of:

          - Rembrandt's face passages: warm ivory dragged over darker flesh
          - Vuillard's Intimiste canvases: matte distemper dragged over board
          - Hals and Sargent's spontaneous dry-brush drapery marks
          - The granular mid-tones of Baroque costume painting

        Physics model
        -------------
        A loaded but dry brush touches the raised texture peaks of the canvas
        and skips the valleys.  The result is a broken field: the drag direction
        is visible, and the underlying colour shows through in gaps.  Because the
        paint is thick and dry (not wet-on-wet), the drag does not blend -- it
        deposits as a hatched, semi-transparent mark.

        Implementation
        --------------
        1. Read the current canvas into a float32 RGB buffer.
        2. For each of n_drags scumble strokes:
           a. Choose a random origin and direction (with angle_jitter variation
              around a dominant near-horizontal direction -- scumbling is usually
              a sideways arm movement).
           b. Sample the canvas colour along the drag path; compute a lightened
              version (mix toward white/cream to simulate the dry lighter pigment).
           c. Weight the deposit by the linen-texture elevation at each pixel:
              deposit only where the texture is above its median (peaks only).
              This creates the characteristic broken, granular quality.
           d. Apply at reduced opacity (dry_factor x opacity) so the underlying
              paint shows through the gaps.
        3. Write the modified buffer back to the Cairo surface.

        Parameters
        ----------
        opacity       : Global blend weight of the scumble layer.  0.10-0.20 =
                        subtle chalky patina; 0.25-0.35 = pronounced dry-brush.
        drag_distance : Length of each scumble drag stroke in pixels.  Short
                        (8-12px) = fine chalk-dust texture; longer (20-30px) =
                        visible directional marks.
        n_drags       : Number of individual drag strokes.  400-600 gives even
                        coverage; 800+ creates a strong directional texture.
        dry_factor    : How dry the paint is -- controls how strongly the texture
                        elevation gates the deposit.  1.0 = deposits only on peaks
                        (most broken / granular); 0.5 = deposits more evenly.
        angle_jitter  : Variation in drag angle (radians).  0.3 = mostly horizontal
                        with slight variation; 1.2 = multi-directional hatching.
        figure_only   : If True and a figure mask is loaded, restrict scumbling
                        to the figure region only.

        Usage examples
        --------------
        Vuillard matte chalky surface::
            scumble_pass(opacity=0.14, n_drags=600, dry_factor=0.85, drag_distance=10)
        Baroque portrait flesh::
            scumble_pass(opacity=0.10, n_drags=300, dry_factor=0.65, drag_distance=18,
                         figure_only=True)
        Sargent spontaneous drapery::
            scumble_pass(opacity=0.22, n_drags=480, drag_distance=22, dry_factor=0.55,
                         angle_jitter=0.80)
        """
        print(f"Scumble pass  (opacity={opacity:.2f}  drags={n_drags}"
              f"  drag_dist={drag_distance}px  dry={dry_factor:.2f})...")

        surf = self.canvas.surface
        h, w = surf.get_height(), surf.get_width()

        # Read current canvas
        buf = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        # Linen texture as deposit gate
        if hasattr(self.canvas, 'texture') and self.canvas.texture is not None:
            tex = self.canvas.texture
        else:
            tex = make_linen_texture(w, h)

        tex_median = float(np.median(tex))
        tex_norm = np.clip((tex - tex_median) / max(tex.max() - tex_median, 1e-6),
                           0.0, 1.0)

        # Figure mask gating
        if figure_only and self._figure_mask is not None:
            region = self._figure_mask
        else:
            region = np.ones((h, w), dtype=np.float32)

        # Scumble accumulation buffers
        acc_r = np.zeros((h, w), dtype=np.float32)
        acc_g = np.zeros((h, w), dtype=np.float32)
        acc_b = np.zeros((h, w), dtype=np.float32)
        acc_w = np.zeros((h, w), dtype=np.float32)

        rng = self.rng

        for _ in range(n_drags):
            ox = int(rng.uniform(0, w))
            oy = int(rng.uniform(0, h))

            # Near-horizontal drag with angle_jitter spread
            angle = float(rng.uniform(-angle_jitter, angle_jitter))

            cos_a, sin_a = math.cos(angle), math.sin(angle)

            # Sample canvas colour at origin; scumble lightens toward warm cream
            cr = float(np.clip(r_ch[oy, ox], 0.0, 1.0))
            cg = float(np.clip(g_ch[oy, ox], 0.0, 1.0))
            cb = float(np.clip(b_ch[oy, ox], 0.0, 1.0))

            cream_r, cream_g, cream_b = 0.94, 0.89, 0.78
            scumble_r = cr * 0.62 + cream_r * 0.38
            scumble_g = cg * 0.62 + cream_g * 0.38
            scumble_b = cb * 0.62 + cream_b * 0.38

            for s in range(drag_distance):
                px = int(ox + s * cos_a)
                py = int(oy + s * sin_a)

                if px < 0 or px >= w or py < 0 or py >= h:
                    break

                # Bell taper: full weight in middle, fades at both ends
                t = s / max(drag_distance - 1, 1)
                taper = math.sin(t * math.pi)

                # Texture gate: deposit strength rises with texture elevation
                tex_gate = tex_norm[py, px] ** dry_factor

                reg = float(region[py, px])
                if reg < 0.01:
                    continue

                wt = taper * tex_gate * reg * opacity
                if wt < 1e-6:
                    continue

                acc_r[py, px] += scumble_r * wt
                acc_g[py, px] += scumble_g * wt
                acc_b[py, px] += scumble_b * wt
                acc_w[py, px] += wt

        # Composite scumble over current canvas
        wt_clamp = np.clip(acc_w, 0.0, 1.0)
        safe_w = np.where(acc_w > 1e-6, acc_w, 1.0)

        mean_r = acc_r / safe_w
        mean_g = acc_g / safe_w
        mean_b = acc_b / safe_w

        r_out = np.clip(r_ch * (1.0 - wt_clamp) + mean_r * wt_clamp, 0.0, 1.0)
        g_out = np.clip(g_ch * (1.0 - wt_clamp) + mean_g * wt_clamp, 0.0, 1.0)
        b_out = np.clip(b_ch * (1.0 - wt_clamp) + mean_b * wt_clamp, 0.0, 1.0)

        # Write back to Cairo surface
        buf[:, :, 2] = np.clip(r_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(g_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 0] = np.clip(b_out * 255, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255

        ctx = self.canvas.ctx
        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        ctx.set_source_surface(tmp, 0, 0)
        ctx.paint()

        n_active = int((acc_w > 0.01).sum())
        print(f"  Scumble pass complete  (active_pixels={n_active})")

    def intimiste_pattern_pass(
        self,
        palette:         List[Color],
        tile_size:       int   = 28,
        n_motif_strokes: int   = 600,
        opacity:         float = 0.32,
        pattern_type:    str   = "diamond",
        figure_only:     bool  = False,
        rng_seed:        Optional[int] = None,
    ):
        """
        Vuillard-inspired Intimiste pattern pass — seeds background regions
        with a soft repeating textile motif so figure and environment share
        the same pictorial plane.

        Édouard Vuillard's hallmark is the dissolution of boundary between
        person and setting: a woman's blouse echoes the wallpaper behind
        her; a tablecloth merges with the floor.  This creates the sensation
        that figure and ground are woven from the same fabric — literally,
        since he often painted on cardboard laid on a patterned surface and
        let the support colour read through.

        This pass replicates that effect by stamping small repeating
        textile-motif strokes (diamond lattice, floral rosette, or fine
        cross-hatch) across the background, using colours drawn from the
        same palette as the figure.  The strokes are rendered at low opacity
        so the underlying paint is visible through them, creating the warm,
        layered richness of aged fabric rather than wallpaper paste.

        Implementation
        --------------
        1. Read the current canvas buffer and compute luminance.
        2. Build a background mask: use figure_mask if available, otherwise
           threshold low-chroma pixels as background.
        3. Generate tile anchor positions across the canvas in a regular grid
           offset slightly by Perlin noise (the irregularity of handmade
           textiles vs mechanical printing).
        4. For each anchor in the background mask, stamp a small motif stroke
           in a randomly selected palette colour at the given opacity.
        5. Composite using alpha blending so the underlying paint shows through.

        Pattern types
        -------------
        'diamond'  : Diagonal lattice — repeating ◆ grid, warm and domestic.
                     Most characteristic of late-19th-century French wallpaper.
        'rosette'  : Small floral blossoms — circle with radial petals.
                     Evokes the dense floral fabrics in Vuillard's interiors.
        'crosshatch': Fine parallel cross-hatching — fabric weave texture.
                     Subtler; reads as cloth rather than wallpaper.

        Parameters
        ----------
        palette          : List of (R,G,B) colours to draw from.  Pass the
                           artist's ArtStyle.palette for authentic palette harmony.
        tile_size        : Spacing in pixels between motif anchors.  Smaller =
                           denser, more wallpaper-like.  Larger = looser textile.
        n_motif_strokes  : Total number of individual motif marks to stamp.
                           600–1200 for a full 800×1000 canvas.
        opacity          : Blend weight of each motif stroke.  0.20–0.35 = warm
                           textile shimmer; 0.50+ = dominant pattern.
        pattern_type     : One of 'diamond', 'rosette', 'crosshatch'.
        figure_only      : If True, apply pattern to figure region instead of
                           background (unusual but useful for costume detailing).
        rng_seed         : Optional seed for reproducibility.

        Notes
        -----
        Call AFTER block_in() / build_form() but BEFORE glaze() and vignette().
        The pass adds warmth and pictorial flatness — calling it after glazing
        risks competing with the unifying glaze tone.
        """
        print(f"Intimiste pattern pass  (type={pattern_type!r}  "
              f"tile_size={tile_size}  opacity={opacity:.2f}  "
              f"strokes={n_motif_strokes})…")

        rng = random.Random(rng_seed)
        np_rng = np.random.default_rng(rng_seed)

        surf = self.canvas.surface
        h, w = surf.get_height(), surf.get_width()

        buf = np.frombuffer(surf.get_data(), dtype=np.uint8).reshape((h, w, 4)).copy()
        b_ch = buf[:, :, 0].astype(np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(np.float32) / 255.0
        r_ch = buf[:, :, 2].astype(np.float32) / 255.0

        # ── Build background mask ─────────────────────────────────────────────
        if self._figure_mask is not None and not figure_only:
            # Background is where figure mask is near zero
            bg_mask = (1.0 - self._figure_mask).astype(np.float32)
            # Feather the transition zone slightly
            bg_mask = ndimage.gaussian_filter(bg_mask, sigma=6.0)
            bg_mask = np.clip(bg_mask, 0.0, 1.0)
        elif self._figure_mask is not None and figure_only:
            bg_mask = self._figure_mask.astype(np.float32)
        else:
            # No figure mask — use chroma saturation as a proxy:
            # Low-saturation areas are likely background
            lum = 0.299 * r_ch + 0.587 * g_ch + 0.114 * b_ch
            # Treat pixels within 15% of mean luminance as background
            mean_lum = float(lum.mean())
            bg_mask = np.where(np.abs(lum - mean_lum) < 0.15, 1.0, 0.4).astype(np.float32)

        # ── Build candidate anchor grid with Perlin jitter ────────────────────
        anchors = []
        inv_w, inv_h = 1.0 / max(w, 1), 1.0 / max(h, 1)
        for gy in range(tile_size // 2, h, tile_size):
            for gx in range(tile_size // 2, w, tile_size):
                # Perlin noise jitter so the grid reads as hand-woven, not printed
                jit_x = pnoise2(gx * inv_w * 8.0, gy * inv_h * 8.0, octaves=2) * tile_size * 0.4
                jit_y = pnoise2(gx * inv_w * 8.0 + 100, gy * inv_h * 8.0 + 100, octaves=2) * tile_size * 0.4
                ax = int(gx + jit_x)
                ay = int(gy + jit_y)
                if 0 <= ax < w and 0 <= ay < h:
                    weight = float(bg_mask[ay, ax])
                    if weight > 0.1:
                        anchors.append((ax, ay, weight))

        if not anchors:
            print("  Intimiste pattern pass: no background anchors found — skipping.")
            return

        # Normalise weights to a probability distribution
        weights = np.array([a[2] for a in anchors], dtype=np.float64)
        weights /= weights.sum()

        chosen_idx = np_rng.choice(len(anchors), size=min(n_motif_strokes, len(anchors)),
                                   replace=True, p=weights)

        # ── Stamp motifs via cairo ────────────────────────────────────────────
        ctx = self.canvas.ctx
        ctx.save()

        for idx in chosen_idx:
            ax, ay, wt = anchors[idx]
            col = rng.choice(palette)
            cr, cg, cb = jitter(col, amount=0.04, rng=rng)
            alpha_base = opacity * (0.7 + 0.3 * wt)     # weaker near figure edges
            # Add a tiny per-mark size variation for the handmade textile feel
            s_factor = 0.7 + rng.uniform(0, 0.6)
            s = max(2, int(tile_size * 0.28 * s_factor))

            ctx.set_source_rgba(cr, cg, cb, alpha_base)

            if pattern_type == "diamond":
                # Rotated square (◆) — classic 19th-century French wallpaper motif
                ctx.move_to(ax,     ay - s)   # top
                ctx.line_to(ax + s, ay)       # right
                ctx.line_to(ax,     ay + s)   # bottom
                ctx.line_to(ax - s, ay)       # left
                ctx.close_path()
                ctx.set_line_width(max(1.0, s * 0.18))
                ctx.stroke()

            elif pattern_type == "rosette":
                # Small floral blossoms — circle with 6 tiny petal dabs
                petal_r = max(1.0, s * 0.30)
                for petal in range(6):
                    angle = math.pi / 3 * petal
                    px = ax + math.cos(angle) * s * 0.55
                    py = ay + math.sin(angle) * s * 0.55
                    ctx.arc(px, py, petal_r, 0, 2 * math.pi)
                    ctx.fill()
                # Centre dot
                ctx.arc(ax, ay, max(1.0, s * 0.18), 0, 2 * math.pi)
                ctx.fill()

            else:  # crosshatch
                # Fine crossed lines — fabric weave texture
                lw = max(0.8, s * 0.12)
                ctx.set_line_width(lw)
                half = s * 0.6
                ctx.move_to(ax - half, ay)
                ctx.line_to(ax + half, ay)
                ctx.stroke()
                ctx.move_to(ax, ay - half)
                ctx.line_to(ax, ay + half)
                ctx.stroke()

        ctx.restore()

        n_painted = len(chosen_idx)
        print(f"  Intimiste pattern pass complete  ({n_painted} motif marks, "
              f"type={pattern_type!r})")

    # ─────────────────────────────────────────────────────────────────────────
    # radiance_bloom_pass — Raphael High Renaissance inner luminosity
    # ─────────────────────────────────────────────────────────────────────────

    def radiance_bloom_pass(self,
                            reference,
                            glow_radius:   float = 14.0,
                            glow_opacity:  float = 0.18,
                            glow_tint:     Color = (0.78, 0.62, 0.36),
                            lum_lo:        float = 0.42,
                            lum_hi:        float = 0.74,
                            sharpness:     float = 2.0,
                            figure_only:   bool  = False):
        """
        Raphael-inspired warm radiance bloom in the lit midtone zone.

        Raphael's figures appear to *emit* warm light rather than merely reflect
        it.  Unlike specular highlight bloom (which targets the very brightest
        pixels), this pass targets the warm midtone-to-highlight transition zone
        (lum in [lum_lo, lum_hi]) — the "radiant amber band" that is the
        defining quality of Raphael's flesh rendering.

        The effect is achieved by:
          1. Building a triangle-falloff midtone mask: pixels exactly at the
             midpoint of [lum_lo, lum_hi] have weight 1.0; values at the edges
             of the range have weight 0.0. This isolates the glowing penumbra
             zone without touching deep shadows or pure highlights.
          2. Applying a wide Gaussian blur (glow_radius) to this mask so the
             warm tint blooms softly outward into adjacent tones.
          3. Blending the glow_tint colour into canvas pixels proportional to
             the blurred mask weight × glow_opacity, preserving luminance so
             the pass warms the hue/chroma without lightening or darkening
             the tonal structure.

        Unlike highlight_bloom_pass (which adds luminance), radiance_bloom_pass
        is a *chromatic* operation — it shifts warmth within the midtone range
        rather than brightening it.  This matches Raphael's technique: his
        midtones are not brighter than they should be, but they are distinctly
        *warmer* (amber-gold) compared to the cooler highlights above and the
        transparent umber shadows below.

        Parameters
        ----------
        reference   : PIL Image — used only to extract the luminance map; the
                      bloom is computed from the *current canvas*, not reference.
        glow_radius : Gaussian blur sigma for the radiance spread (pixels).
                      10–16 = realistic penumbra; 20+ = glowing halo effect.
        glow_opacity: Blend weight of the warm glow layer.  0.12–0.20 = subtle
                      Raphael-like radiance; 0.25+ = stronger warm glow.
        glow_tint   : (R,G,B) target colour for the warm glow zone.  Default is
                      warm amber-gold — Raphael's characteristic midtone colour.
        lum_lo      : Lower luminance boundary of the midtone radiance zone.
        lum_hi      : Upper luminance boundary of the midtone radiance zone.
        sharpness   : Triangle falloff exponent.  1.0 = linear; 2.0 = quadratic
                      (peakier, concentrates glow closer to the midpoint).
        figure_only : If True and a figure mask is loaded, restrict glow to the
                      figure region only (avoids warming background/landscape).

        Notes
        -----
        Call AFTER build_form() / place_lights() and BEFORE the final glaze and
        finish().  Effective on HIGH_RENAISSANCE, VENETIAN_RENAISSANCE, and any
        portrait where warm inner luminosity is desired.
        """
        import numpy as np
        from scipy.ndimage import gaussian_filter

        print(f"  Radiance bloom pass  (radius={glow_radius:.1f}  "
              f"opacity={glow_opacity:.2f}  lum=[{lum_lo:.2f},{lum_hi:.2f}])")

        # ── Read current canvas ARGB32 (premultiplied) ────────────────────────
        buf  = np.frombuffer(self.canvas.surface.get_data(),
                             dtype=np.uint8).reshape(self.h, self.w, 4).copy()
        # ARGB32: channels = B, G, R, A (little-endian BGRA on most platforms)
        B = buf[:, :, 0].astype(np.float32) / 255.0
        G = buf[:, :, 1].astype(np.float32) / 255.0
        R = buf[:, :, 2].astype(np.float32) / 255.0

        # ── Luminance map ────────────────────────────────────────────────────
        lum = 0.299 * R + 0.587 * G + 0.114 * B   # (h, w)

        # ── Triangle-falloff midtone mask ────────────────────────────────────
        mid   = (lum_lo + lum_hi) * 0.5
        span  = (lum_hi - lum_lo) * 0.5 + 1e-9
        dist  = np.abs(lum - mid) / span            # 0 at midpoint, 1 at edges
        mask  = np.clip(1.0 - dist, 0.0, 1.0) ** sharpness   # (h, w)
        mask  = np.where((lum >= lum_lo) & (lum <= lum_hi), mask, 0.0)

        # ── Apply figure mask if requested ───────────────────────────────────
        if figure_only and self._figure_mask is not None:
            fm   = self._figure_mask
            if fm.shape != (self.h, self.w):
                from PIL import Image as _PILImg
                fm = np.array(
                    _PILImg.fromarray((fm * 255).astype(np.uint8)).resize(
                        (self.w, self.h), _PILImg.BILINEAR)) / 255.0
            mask = mask * fm

        # ── Blur mask to create soft radiant spread ──────────────────────────
        blurred = gaussian_filter(mask, sigma=glow_radius)
        blurred = np.clip(blurred / (blurred.max() + 1e-9), 0.0, 1.0) * mask.max()

        # ── Blend warm tint toward canvas pixels (lum-preserve) ──────────────
        tr, tg, tb = glow_tint
        weight = blurred * glow_opacity   # (H, W) per-pixel blend weight

        # Shift toward glow_tint while preserving luminance
        new_R = R + (tr - R) * weight
        new_G = G + (tg - G) * weight
        new_B = B + (tb - B) * weight

        # Luminance preservation: rescale so lum is unchanged
        new_lum = 0.299 * new_R + 0.587 * new_G + 0.114 * new_B
        safe    = np.where(new_lum > 1e-6, lum / new_lum, 1.0)
        new_R   = np.clip(new_R * safe, 0.0, 1.0)
        new_G   = np.clip(new_G * safe, 0.0, 1.0)
        new_B   = np.clip(new_B * safe, 0.0, 1.0)

        # ── Write back to ARGB32 (BGRA layout) ────────────────────────────────
        buf[:, :, 0] = np.clip(new_B * 255.0, 0, 255).astype(np.uint8)  # B
        buf[:, :, 1] = np.clip(new_G * 255.0, 0, 255).astype(np.uint8)  # G
        buf[:, :, 2] = np.clip(new_R * 255.0, 0, 255).astype(np.uint8)  # R
        buf[:, :, 3] = 255                                                 # A

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

    # ─────────────────────────────────────────────────────────────────────────
    # reflected_light_pass — classical shadow bounce illumination
    # ─────────────────────────────────────────────────────────────────────────

    def reflected_light_pass(self,
                             warm_bounce_color: Color = (0.72, 0.52, 0.28),
                             cool_bounce_color: Color = (0.45, 0.55, 0.72),
                             warm_strength:     float = 0.14,
                             cool_strength:     float = 0.08,
                             shadow_threshold:  float = 0.40,
                             warm_y_split:      float = 0.50,
                             figure_only:       bool  = False):
        """
        Classical reflected-light shadow enrichment.

        The fundamental principle of classical painting — codified by Leonardo,
        practised by Raphael, Rubens, Vermeer, and every Academy-trained painter
        thereafter — is that *shadows contain reflected light*.  A shadow area
        is never purely dark: it receives indirect light bounced from surrounding
        surfaces.  In a standard portrait setup:

          - The lower shadow zones (facing the warm ground plane, ochre-red
            imprimatura, warm fabrics) receive a *warm* bounce:
            deep amber-sienna reflected up from below.
          - The upper shadow zones (facing the cool open sky) receive a *cool*
            bounce: blue-violet sky light filtering down from above.

        Without reflected light, shadows read as flat, dead, and painterly-wrong.
        With reflected light, even the darkest shadow passage has chromatic life
        and the painting appears to breathe.

        Implementation
        --------------
        1. Read the canvas buffer and compute luminance.
        2. Build a shadow mask: pixels where luminance < shadow_threshold.
        3. Compute a vertical gradient weight: pixels in the lower half of the
           canvas (y > warm_y_split × H) receive warm_bounce_color; pixels in
           the upper half receive cool_bounce_color.
        4. Blend the bounce color into shadow pixels at the corresponding
           strength, with luminance preservation so the tonal structure is
           unchanged — only the chromatic quality of the shadow shifts.

        This is a style-agnostic improvement: it benefits RENAISSANCE,
        HIGH_RENAISSANCE, BAROQUE, VENETIAN_RENAISSANCE, and any period where
        traditional oil-painting technique is appropriate.  It was validated as
        the session-23 random artistic improvement.

        Parameters
        ----------
        warm_bounce_color : (R,G,B) warm reflected light colour — the bounce
                            from warm ground / imprimatura / fabric below.
                            Default: warm amber-sienna.
        cool_bounce_color : (R,G,B) cool reflected light colour — sky bounce
                            from above.  Default: cool blue-violet.
        warm_strength     : Blend weight for warm bounce (lower shadows).
                            0.08–0.15 = classical subtlety; 0.20+ = vivid.
        cool_strength     : Blend weight for cool bounce (upper shadows).
                            Typically slightly weaker than warm (sky is less
                            intense than ground-plane bounce indoors).
        shadow_threshold  : Luminance below which a pixel is treated as
                            shadow and receives bounce light.  0.35–0.45.
        warm_y_split      : Normalised Y coordinate (0=top, 1=bottom) dividing
                            warm-bounce zone (below) from cool-bounce (above).
                            Default 0.50 = canvas midpoint.
        figure_only       : If True and a figure mask is loaded, restrict bounce
                            to the figure region (avoids warming background).

        Notes
        -----
        Call AFTER build_form() and before place_lights() or the final glaze,
        so the warm/cool shadow enrichment is visible but can be slightly
        modulated by subsequent highlights and glazes.
        """
        import numpy as np

        print(f"  Reflected light pass  (warm={warm_strength:.2f}  "
              f"cool={cool_strength:.2f}  shadow_thresh={shadow_threshold:.2f})")

        # ── Read current canvas ARGB32 ─────────────────────────────────────
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(np.float32) / 255.0
        G = buf[:, :, 1].astype(np.float32) / 255.0
        R = buf[:, :, 2].astype(np.float32) / 255.0

        # ── Luminance and shadow mask ──────────────────────────────────────
        lum  = 0.299 * R + 0.587 * G + 0.114 * B
        # Shadow weight: 1.0 deep in shadow, 0.0 at threshold edge
        shad = np.clip((shadow_threshold - lum) / (shadow_threshold + 1e-9),
                       0.0, 1.0)   # (h, w)

        # ── Figure mask ────────────────────────────────────────────────────
        if figure_only and self._figure_mask is not None:
            fm = self._figure_mask
            if fm.shape != (self.h, self.w):
                from PIL import Image as _PILImg
                fm = np.array(
                    _PILImg.fromarray((fm * 255).astype(np.uint8)).resize(
                        (self.w, self.h), _PILImg.BILINEAR)) / 255.0
            shad = shad * fm

        # ── Vertical bounce gradient ───────────────────────────────────────
        ys   = np.arange(self.h, dtype=np.float32).reshape(-1, 1) / self.h  # (h,1)
        # warm_weight: 0 at top, 1 at bottom (below warm_y_split → warm)
        warm_w = np.clip((ys - warm_y_split) / (1.0 - warm_y_split + 1e-9),
                         0.0, 1.0)   # (H, 1) broadcast to (H, W)
        cool_w = np.clip((warm_y_split - ys) / (warm_y_split + 1e-9),
                         0.0, 1.0)   # (H, 1)

        # ── Apply warm bounce to lower shadows ─────────────────────────────
        wr, wg, wb = warm_bounce_color
        w_alpha    = shad * warm_w * warm_strength

        new_R = R + (wr - R) * w_alpha
        new_G = G + (wg - G) * w_alpha
        new_B = B + (wb - B) * w_alpha

        # ── Apply cool bounce to upper shadows ─────────────────────────────
        cr, cg, cb = cool_bounce_color
        c_alpha    = shad * cool_w * cool_strength

        new_R = new_R + (cr - new_R) * c_alpha
        new_G = new_G + (cg - new_G) * c_alpha
        new_B = new_B + (cb - new_B) * c_alpha

        # ── Luminance preservation ─────────────────────────────────────────
        new_lum = 0.299 * new_R + 0.587 * new_G + 0.114 * new_B
        safe    = np.where(new_lum > 1e-6, lum / new_lum, 1.0)
        new_R   = np.clip(new_R * safe, 0.0, 1.0)
        new_G   = np.clip(new_G * safe, 0.0, 1.0)
        new_B   = np.clip(new_B * safe, 0.0, 1.0)

        # ── Write back to ARGB32 (BGRA layout) ────────────────────────────────
        buf[:, :, 0] = np.clip(new_B * 255.0, 0, 255).astype(np.uint8)  # B
        buf[:, :, 1] = np.clip(new_G * 255.0, 0, 255).astype(np.uint8)  # G
        buf[:, :, 2] = np.clip(new_R * 255.0, 0, 255).astype(np.uint8)  # R
        buf[:, :, 3] = 255                                                 # A

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

    # ─────────────────────────────────────────────────────────────────────────
    # luminous_fabric_pass — Zurbarán hyper-real white cloth technique
    # ─────────────────────────────────────────────────────────────────────────

    def luminous_fabric_pass(self,
                             reference,
                             white_lum_threshold: float = 0.62,
                             white_sat_threshold:  float = 0.22,
                             fold_contrast:        float = 0.55,
                             void_darken:          float = 0.72,
                             found_edge_strength:  float = 0.60,
                             figure_only:          bool  = False):
        """
        Zurbarán hyper-real white fabric technique.

        Zurbarán's defining achievement was the sculptural rendering of white
        cloth — monk habits, linen tunics, altar cloths — emerging from near-
        absolute darkness with almost photographic precision.  Every fold of
        white fabric is a self-contained study in value: brilliant lit peak,
        warm ochre mid-shadow, deep umber at the fold recess.  The edge between
        white cloth and void background is the sharpest, most *found* edge in
        17th-century painting.

        Three operations:
        1. **Fabric fold micro-contrast** — Fine Sobel within white/ivory zones
           brightens lit fold sides and darkens shadow sides.
        2. **Void deepening** — Background zones are darkened toward absolute black.
        3. **Found-edge sharpening** — Contrast at the fabric-void boundary is
           steepened to produce Zurbarán's razor-sharp silhouettes.

        Parameters
        ----------
        reference          : PIL Image — scene reference for fabric detection.
        white_lum_threshold: Luminance above which a pixel is potentially fabric.
        white_sat_threshold: HSV saturation below which a bright pixel is cloth.
        fold_contrast      : Strength of fold micro-contrast enhancement (0–1).
        void_darken        : Blend weight toward pure black for background zones.
        found_edge_strength: Strength of fabric-void boundary contrast boost.
        figure_only        : Restrict fabric detection to figure region if True.
        """
        import numpy as np
        from PIL import Image as _PILImg
        from scipy.ndimage import gaussian_filter, sobel as _sobel

        print(f"  Luminous fabric pass  "
              f"(fold_contrast={fold_contrast:.2f}  "
              f"void_darken={void_darken:.2f}  "
              f"found_edge={found_edge_strength:.2f})")

        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(self.h, self.w, 4).copy()
        B_c = buf[:, :, 0].astype(np.float32) / 255.0
        G_c = buf[:, :, 1].astype(np.float32) / 255.0
        R_c = buf[:, :, 2].astype(np.float32) / 255.0
        lum_c = 0.299 * R_c + 0.587 * G_c + 0.114 * B_c

        # Build fabric and void masks from reference
        ref_np = np.array(reference.convert("RGB"), dtype=np.float32) / 255.0
        ref_r, ref_g, ref_b = ref_np[:, :, 0], ref_np[:, :, 1], ref_np[:, :, 2]
        ref_lum = 0.299 * ref_r + 0.587 * ref_g + 0.114 * ref_b
        cmax = np.maximum(np.maximum(ref_r, ref_g), ref_b)
        cmin = np.minimum(np.minimum(ref_r, ref_g), ref_b)
        ref_sat = np.where(cmax > 1e-6, (cmax - cmin) / (cmax + 1e-9), 0.0)
        fabric_mask = (
            (ref_lum >= white_lum_threshold) & (ref_sat <= white_sat_threshold)
        ).astype(np.float32)
        if figure_only and self._figure_mask is not None:
            fm = self._figure_mask
            if fm.shape != (self.h, self.w):
                fm = np.array(
                    _PILImg.fromarray((fm * 255).astype(np.uint8)).resize(
                        (self.w, self.h), _PILImg.BILINEAR)) / 255.0
            fabric_mask = fabric_mask * fm
        void_mask = (ref_lum < 0.30).astype(np.float32)

        # Fold micro-contrast: Sobel on canvas luminance, apply within fabric zone
        smooth_lum = gaussian_filter(lum_c, sigma=0.8)
        gx = _sobel(smooth_lum, axis=1)
        gy = _sobel(smooth_lum, axis=0)
        edge_mag   = np.sqrt(gx ** 2 + gy ** 2)
        edge_norm  = np.clip(edge_mag / (edge_mag.max() + 1e-8), 0.0, 1.0)
        grad_sign  = np.sign(gx + gy)
        fold_delta = grad_sign * edge_norm * fold_contrast * 0.18 * fabric_mask
        new_R = np.clip(R_c + fold_delta,        0.0, 1.0)
        new_G = np.clip(G_c + fold_delta * 0.88, 0.0, 1.0)
        new_B = np.clip(B_c + fold_delta * 0.62, 0.0, 1.0)

        # Void deepening
        vd_alpha = void_mask * void_darken
        new_R = new_R * (1.0 - vd_alpha)
        new_G = new_G * (1.0 - vd_alpha)
        new_B = new_B * (1.0 - vd_alpha)

        # Found-edge sharpening at fabric-void boundary
        boundary_fabric = gaussian_filter(fabric_mask, sigma=1.5)
        boundary_void   = gaussian_filter(void_mask,   sigma=1.5)
        boundary_zone   = np.minimum(boundary_fabric, boundary_void)
        fabric_side = boundary_zone * (fabric_mask > 0.5).astype(float)
        void_side   = boundary_zone * (void_mask   > 0.5).astype(float)
        boost = found_edge_strength * 0.12
        new_R = np.clip(new_R + fabric_side * boost - void_side * boost * 1.5, 0.0, 1.0)
        new_G = np.clip(new_G + fabric_side * boost - void_side * boost * 1.5, 0.0, 1.0)
        new_B = np.clip(new_B + fabric_side * boost - void_side * boost * 1.5, 0.0, 1.0)

        buf[:, :, 0] = np.clip(new_B * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(new_G * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 2] = np.clip(new_R * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255
        _tmp_fab = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(_tmp_fab, 0, 0)
        self.canvas.ctx.paint()

    # ─────────────────────────────────────────────────────────────────────────
    # edge_lost_and_found_pass — classical edge quality control (session-24 random)
    # ─────────────────────────────────────────────────────────────────────────

    def edge_lost_and_found_pass(self,
                                  focal_xy:            tuple = (0.50, 0.30),
                                  found_radius:        float = 0.28,
                                  found_sharpness:     float = 0.50,
                                  lost_blur:           float = 1.8,
                                  strength:            float = 0.35,
                                  figure_only:         bool  = False,
                                  gradient_selectivity: float = 0.0,
                                  soft_halo_strength:  float = 0.0):
        """
        Classical edge quality control — "lost and found" edges.

        Every skilled portrait painter distinguishes two edge types:

        - **Found edges** — sharp, crisp, advance visually.  At the focal point:
          the lit side of the face, the highest-contrast detail the eye goes to
          first.
        - **Lost edges** — soft, dissolved, recede.  At the turning of a form
          into shadow, in peripheral areas, in atmospheric distance.

        Without this distinction all edges appear equally important and the
        painting reads as flat and mechanical.  This pass:

        1. Computes a cosine-falloff "found weight" from the focal point.
        2. Applies unsharp masking to the found zone.
        3. Applies Gaussian softening to the lost zone.
        4. Blends the result into the canvas at ``strength``.

        Useful for any portrait period.  Validated as the session-24 random
        artistic improvement.

        Session-81 improvement — ``gradient_selectivity``:
        The original pass applied found-zone sharpening uniformly to all pixels
        near the focal point, including smooth interior tones with no actual edge
        information.  This caused slight noise amplification in well-blended flesh
        areas: the unsharp mask finds and enhances micro-variation (brush texture,
        earlier pass seams) that the painter would have left smooth.

        ``gradient_selectivity > 0`` multiplies the found_wt by the normalised
        local luminance gradient magnitude, so that only pixels that lie on actual
        form boundaries (where gradient is high) receive the full sharpening.
        Smooth interior passages (gradient ≈ 0) are left undisturbed.  This
        matches how Old Masters used the technique: a found edge is an edge that
        actually exists in the form; it is not applied to smooth skin.

        At ``gradient_selectivity=1.0`` the sharpening is fully gradient-gated —
        only the clearest form transitions are found; at 0.0 (default) behaviour
        is identical to the pre-session-81 version for backward compatibility.
        Values around 0.5–0.7 give the best results for portrait work.

        Parameters
        ----------
        focal_xy             : (x, y) normalised focal point (0,0=top-left).
                               Default (0.50, 0.30) = upper-centre portrait face.
        found_radius         : Normalised radius within which edges are sharpened.
        found_sharpness      : Unsharp mask strength in found zone (0–1).
        lost_blur            : Gaussian sigma (pixels) for lost zone softening.
        strength             : Overall blend weight (0 = no effect, 1 = full).
        figure_only          : Restrict found-zone sharpening to figure if True.
        gradient_selectivity : When > 0, gates found-zone sharpening by local
                               luminance gradient magnitude.  Prevents noise
                               amplification in smooth skin passages; preserves
                               strong sharpening on actual form boundaries only.
                               Range [0, 1]; 0 = original behaviour.
        soft_halo_strength   : Session-91 improvement.  When > 0, adds a faint
                               Gaussian luminous bloom around edges in the lost
                               zone (outside the focal ring), simulating the
                               way Leonardo's sfumato glazing builds a gentle
                               aureole around dissolving boundary zones.  This
                               produces the 'present-but-dissolving' edge
                               perceptually associated with the Mona Lisa smile
                               area: the edge is not erased but surrounded by
                               a soft light envelope, as if viewed through
                               multiple transparent glaze layers.  Range [0, 1];
                               0 = no halo (original behaviour); ~0.10–0.18
                               gives a subtle sfumato aureole effect.
        """
        import numpy as np
        from PIL import Image as _PILImg
        from scipy.ndimage import gaussian_filter

        print(f"  Edge lost-and-found pass  "
              f"(focal={focal_xy}  found_r={found_radius:.2f}  "
              f"sharpness={found_sharpness:.2f}  lost_blur={lost_blur:.1f}  "
              f"strength={strength:.2f})")

        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(self.h, self.w, 4).copy()
        B_lf = buf[:, :, 0].astype(np.float32) / 255.0
        G_lf = buf[:, :, 1].astype(np.float32) / 255.0
        R_lf = buf[:, :, 2].astype(np.float32) / 255.0

        # Radial found-weight: cosine falloff from focal point
        fx, fy = focal_xy
        ys, xs = np.ogrid[:self.h, :self.w]
        dist_norm = np.sqrt(
            ((xs / self.w) - fx) ** 2 + ((ys / self.h) - fy) ** 2
        ) / (found_radius + 1e-9)
        found_wt = np.clip(
            0.5 * (1.0 + np.cos(np.pi * np.minimum(dist_norm, 1.0))),
            0.0, 1.0).astype(np.float32)
        lost_wt = 1.0 - found_wt

        if figure_only and self._figure_mask is not None:
            fm = self._figure_mask
            if fm.shape != (self.h, self.w):
                fm = np.array(
                    _PILImg.fromarray((fm * 255).astype(np.uint8)).resize(
                        (self.w, self.h), _PILImg.BILINEAR)) / 255.0
            found_wt = found_wt * fm

        # Session-81: gradient-selective sharpening gate.
        # Multiplies found_wt by the normalised luminance gradient so that only
        # actual form boundaries receive sharpening — smooth interior flesh is
        # left undisturbed, preventing noise amplification in well-blended areas.
        if gradient_selectivity > 0.0:
            lum_lf = 0.2126 * R_lf + 0.7152 * G_lf + 0.0722 * B_lf
            lum_smooth = gaussian_filter(lum_lf, sigma=1.0)
            gx = np.gradient(lum_smooth, axis=1).astype(np.float32)
            gy = np.gradient(lum_smooth, axis=0).astype(np.float32)
            grad_mag = np.sqrt(gx ** 2 + gy ** 2).astype(np.float32)
            # Normalise gradient to [0, 1] using the 98th percentile to avoid
            # outlier edges dominating the scale
            grad_p98 = float(np.percentile(grad_mag, 98)) or 1e-8
            grad_norm = np.clip(grad_mag / grad_p98, 0.0, 1.0).astype(np.float32)
            # Blend between full weight (selectivity=0) and gradient-gated weight
            found_wt = found_wt * (
                (1.0 - gradient_selectivity) + gradient_selectivity * grad_norm
            )

        # Unsharp mask for found zone
        um_sigma = max(0.8, lost_blur * 0.45)
        R_blur = gaussian_filter(R_lf, sigma=um_sigma)
        G_blur = gaussian_filter(G_lf, sigma=um_sigma)
        B_blur = gaussian_filter(B_lf, sigma=um_sigma)
        sharp_R = np.clip(R_lf + found_sharpness * found_wt * (R_lf - R_blur), 0.0, 1.0)
        sharp_G = np.clip(G_lf + found_sharpness * found_wt * (G_lf - G_blur), 0.0, 1.0)
        sharp_B = np.clip(B_lf + found_sharpness * found_wt * (B_lf - B_blur), 0.0, 1.0)

        # Gaussian softening for lost zone
        R_soft = gaussian_filter(sharp_R, sigma=lost_blur)
        G_soft = gaussian_filter(sharp_G, sigma=lost_blur)
        B_soft = gaussian_filter(sharp_B, sigma=lost_blur)
        result_R = sharp_R * (1.0 - lost_wt) + R_soft * lost_wt
        result_G = sharp_G * (1.0 - lost_wt) + G_soft * lost_wt
        result_B = sharp_B * (1.0 - lost_wt) + B_soft * lost_wt

        # Session-91: Soft halo / perioral sfumato aureole.
        # In the lost zone (low found_wt), detect luminance edges and surround
        # them with a gentle Gaussian luminance bloom.  This mimics the way
        # Leonardo's multiple thin glaze layers build up a faint light aureole
        # around dissolving boundary zones -- particularly the lip corners,
        # the boundary of nose shadow into cheek, and the jaw line into neck.
        if soft_halo_strength > 0.0:
            lum_res = 0.2126 * result_R + 0.7152 * result_G + 0.0722 * result_B
            lum_smooth_h = gaussian_filter(lum_res, sigma=1.2)
            gx_h = np.gradient(lum_smooth_h, axis=1).astype(np.float32)
            gy_h = np.gradient(lum_smooth_h, axis=0).astype(np.float32)
            edge_h = np.sqrt(gx_h ** 2 + gy_h ** 2).astype(np.float32)
            if edge_h.max() > 1e-9:
                edge_h = edge_h / edge_h.max()
            # Gate: only edges in the lost zone get the halo
            edge_lost = edge_h * lost_wt
            halo_sigma = max(1.5, lost_blur * 1.8)
            halo = gaussian_filter(edge_lost, sigma=halo_sigma)
            halo = np.clip(halo * soft_halo_strength * 3.0, 0.0, soft_halo_strength)
            result_R = np.clip(result_R + halo, 0.0, 1.0)
            result_G = np.clip(result_G + halo, 0.0, 1.0)
            result_B = np.clip(result_B + halo, 0.0, 1.0)

        # Blend result into canvas
        final_R = np.clip(R_lf * (1.0 - strength) + result_R * strength, 0.0, 1.0)
        final_G = np.clip(G_lf * (1.0 - strength) + result_G * strength, 0.0, 1.0)
        final_B = np.clip(B_lf * (1.0 - strength) + result_B * strength, 0.0, 1.0)

        buf[:, :, 0] = np.clip(final_B * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(final_G * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 2] = np.clip(final_R * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255
        _tmp_lf = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(_tmp_lf, 0, 0)
        self.canvas.ctx.paint()

    # ─────────────────────────────────────────────────────────────────────────
    # porcelain_skin_pass — Ingres / Neoclassical smooth flesh technique
    # ─────────────────────────────────────────────────────────────────────────

    def porcelain_skin_pass(self,
                             smooth_strength:  float = 0.65,
                             highlight_cool:   float = 0.08,
                             blush_opacity:    float = 0.10,
                             highlight_thresh: float = 0.75,
                             blush_lo:         float = 0.42,
                             blush_hi:         float = 0.68,
                             smooth_sigma:     float = 2.5,
                             figure_only:      bool  = True):
        """
        Ingres / Neoclassical porcelain skin technique.

        Ingres was obsessed with an impossibly smooth, seamless skin surface —
        often described as "ivory" or "porcelain" by contemporary critics.  He
        achieved it through meticulous wet-into-wet blending of closely-valued
        flesh tones until all trace of brushwork vanished.  Two chromatic
        qualities define his flesh:

        1. **Cool pearl highlight** — the highest-lum flesh zone receives a
           barely perceptible shift toward silver-white (cool blue-white tint).
           This creates the illusion of a smooth, translucent surface catching
           diffuse light, unlike the warm-tinted highlights of most oil painters.

        2. **Warm rose blush** — flesh midtones (moderate luminance) carry a
           gentle rose warmth: a slight boost to the red channel that gives the
           face life without making it look sun-burnt.

        The pass also performs weighted Gaussian smoothing of the flesh zone to
        suppress any residual brushstroke micro-texture, then restores shadow
        edges at full contrast so the smooth flesh reads against a defined form.

        Style-agnostic: benefits NEOCLASSICAL, ACADEMIC, and any portrait period
        where the artist sought an idealised, polished skin surface.

        Parameters
        ----------
        smooth_strength  : Blend weight for Gaussian smoothing in flesh zones
                           (0 = no smoothing, 1 = full replacement with smooth).
        highlight_cool   : Strength of the cool-pearl tint applied at bright
                           flesh highlights (lum > highlight_thresh).
        blush_opacity    : Intensity of the warm rose blush in flesh midtones.
        highlight_thresh : Luminance threshold above which the cool tint is applied.
        blush_lo / hi    : Luminance range for the rose blush zone.
        smooth_sigma     : Gaussian blur sigma (pixels) for flesh smoothing.
        figure_only      : Restrict all effects to the figure mask region.
        """
        import numpy as np
        from scipy.ndimage import gaussian_filter
        from PIL import Image as _PILImg

        print(f"  Porcelain skin pass  "
              f"(smooth={smooth_strength:.2f}  cool={highlight_cool:.2f}  "
              f"blush={blush_opacity:.2f}  sigma={smooth_sigma:.1f})")

        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(self.h, self.w, 4).copy()
        # Cairo ARGB32 is stored BGRA
        B_ps = buf[:, :, 0].astype(np.float32) / 255.0
        G_ps = buf[:, :, 1].astype(np.float32) / 255.0
        R_ps = buf[:, :, 2].astype(np.float32) / 255.0

        # ── Luminance ────────────────────────────────────────────────────────
        lum_ps = 0.299 * R_ps + 0.587 * G_ps + 0.114 * B_ps

        # ── Flesh zone detection ──────────────────────────────────────────────
        # Warm pixels (R noticeably exceeds B), mid-to-high luminance.
        # The warmth criterion avoids smoothing blue/green drapery or dark hair.
        flesh_mask = (
            (R_ps > B_ps + 0.06) &
            (lum_ps > 0.28) &
            (lum_ps < 0.92)
        ).astype(np.float32)

        # Optionally restrict to figure region
        if figure_only and self._figure_mask is not None:
            fm = self._figure_mask
            if fm.shape != (self.h, self.w):
                fm = np.array(
                    _PILImg.fromarray((fm * 255).astype(np.uint8)).resize(
                        (self.w, self.h), _PILImg.BILINEAR)) / 255.0
            flesh_mask = flesh_mask * fm

        # ── Stage 1: Weighted Gaussian smoothing of flesh zones ───────────────
        # Smooth the full canvas, then composite the smoothed version back onto
        # the original canvas only in the flesh zone.  This removes brushstroke
        # micro-texture from skin without touching drapery or background.
        R_smooth = gaussian_filter(R_ps, sigma=smooth_sigma)
        G_smooth = gaussian_filter(G_ps, sigma=smooth_sigma)
        B_smooth = gaussian_filter(B_ps, sigma=smooth_sigma)

        blend = flesh_mask * smooth_strength
        R_out = R_ps * (1.0 - blend) + R_smooth * blend
        G_out = G_ps * (1.0 - blend) + G_smooth * blend
        B_out = B_ps * (1.0 - blend) + B_smooth * blend

        # ── Stage 2: Cool pearl highlight tint ───────────────────────────────
        # In the brightest flesh zone, shift toward silver-white (0.96, 0.96, 1.0).
        # This is the defining Ingres quality: porcelain-cool on the highest light.
        highlight_zone = flesh_mask * np.clip(
            (lum_ps - highlight_thresh) / (1.0 - highlight_thresh + 1e-8),
            0.0, 1.0
        ) * highlight_cool
        # Pearl tint is slightly cool: R and G stay, B lifts a little
        R_out = np.clip(R_out - highlight_zone * 0.02, 0.0, 1.0)
        G_out = np.clip(G_out - highlight_zone * 0.01, 0.0, 1.0)
        B_out = np.clip(B_out + highlight_zone * 0.06, 0.0, 1.0)

        # ── Stage 3: Rose blush in midtone flesh ─────────────────────────────
        # A gentle warm-rose boost in the flesh midtone range gives the face
        # the flushed, living warmth that separates an Ingres portrait from a
        # cold academic study.  Blush_opacity ≤ 0.12 keeps it subtle.
        blush_zone_wt = np.clip(
            1.0 - 2.0 * np.abs(lum_ps - 0.5 * (blush_lo + blush_hi))
            / (blush_hi - blush_lo + 1e-8),
            0.0, 1.0
        )
        blush_zone = flesh_mask * blush_zone_wt * blush_opacity
        R_out = np.clip(R_out + blush_zone * 0.045, 0.0, 1.0)
        G_out = np.clip(G_out + blush_zone * 0.012, 0.0, 1.0)

        # ── Write back ───────────────────────────────────────────────────────
        buf[:, :, 0] = np.clip(B_out * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(G_out * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 2] = np.clip(R_out * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255
        _tmp_ps = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(_tmp_ps, 0, 0)
        self.canvas.ctx.paint()

    # ─────────────────────────────────────────────────────────────────────────
    # tonal_compression_pass — academic value range management
    # Session-25 random artistic improvement
    # ─────────────────────────────────────────────────────────────────────────

    def tonal_compression_pass(self,
                                shadow_lift:        float = 0.04,
                                highlight_compress: float = 0.96,
                                midtone_contrast:   float = 0.06,
                                midtone_lo:         float = 0.30,
                                midtone_hi:         float = 0.70,
                                figure_only:        bool  = False):
        """
        Academic tonal range management — compression toward a refined value structure.

        Academic salon painters from David and Ingres through Bouguereau and
        Gérôme carefully managed their tonal range to create what critics called
        a "velvety" or "enamel-like" surface quality.  The key technique:

        - **No crushed blacks** — the deepest darks are lifted very slightly off
          pure black (a value of about 0.03–0.06 rather than 0.0).  This ensures
          that form structure survives in shadow passages: you can read the contour
          of a hand even in its darkest shadow.  Pure black loses information.

        - **No blown highlights** — the brightest lights are held just below pure
          white (about 0.94–0.97 rather than 1.0).  This avoids the "poster" look
          of completely lost highlights and preserves delicate surface modelling on
          forehead, collar, and satin drapery.

        - **S-curve midtone contrast** — a subtle lift of contrast in the midtone
          region (roughly 0.30–0.70 lum) creates a slight S-curve response that
          makes the tonal transitions feel richer and more intentional.  The effect
          is the same as dodging the light midtones and burning the dark midtones —
          standard darkroom practice in the 20th-century analogue of academic
          technique.

        The result is the characteristic academic tonal quality: luminous but never
        glaring, deep but never empty, with a feeling of controlled, considered
        illumination across the entire canvas.

        Parameters
        ----------
        shadow_lift        : Amount to lift the deepest shadows (0 = no change,
                             0.06 = lift 0→0.06; typical: 0.03–0.06).
        highlight_compress : Ceiling for highlights (1.0 = no compress,
                             0.95 = compress down; typical: 0.93–0.97).
        midtone_contrast   : Strength of the midtone S-curve lift (0 = none,
                             0.08 = moderate; typical: 0.03–0.10).
        midtone_lo / hi    : Luminance bounds of the midtone region for S-curve.
        figure_only        : Restrict to figure mask region if True.
        """
        import numpy as np
        from PIL import Image as _PILImg

        print(f"  Tonal compression pass  "
              f"(shadow_lift={shadow_lift:.3f}  "
              f"hi_compress={highlight_compress:.3f}  "
              f"midtone_contrast={midtone_contrast:.3f})")

        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(self.h, self.w, 4).copy()
        B_tc = buf[:, :, 0].astype(np.float32) / 255.0
        G_tc = buf[:, :, 1].astype(np.float32) / 255.0
        R_tc = buf[:, :, 2].astype(np.float32) / 255.0

        # ── Compute per-channel luminance-like scaling ────────────────────────
        # We apply the tonal mapping to each channel proportionally, preserving
        # chroma (hue and saturation) while shifting the lightness curve.
        lum_tc = 0.299 * R_tc + 0.587 * G_tc + 0.114 * B_tc
        lum_safe = np.maximum(lum_tc, 1e-8)

        # ── Stage 1: Shadow lift ──────────────────────────────────────────────
        # Remap: lum_new = lum * (1 - shadow_lift) + shadow_lift
        # Applied as a luminance scale so all channels shift equally.
        lum_lifted = lum_tc * (1.0 - shadow_lift) + shadow_lift
        scale_lift = lum_lifted / lum_safe
        R_out = np.clip(R_tc * scale_lift, 0.0, 1.0)
        G_out = np.clip(G_tc * scale_lift, 0.0, 1.0)
        B_out = np.clip(B_tc * scale_lift, 0.0, 1.0)

        # ── Stage 2: Highlight compression ───────────────────────────────────
        # Remap: lum_new = min(lum, highlight_compress)
        # Pixels brighter than the ceiling are proportionally scaled down.
        lum_after_lift = 0.299 * R_out + 0.587 * G_out + 0.114 * B_out
        lum_safe2 = np.maximum(lum_after_lift, 1e-8)
        lum_compressed = np.minimum(lum_after_lift, highlight_compress)
        scale_compress = lum_compressed / lum_safe2
        R_out = np.clip(R_out * scale_compress, 0.0, 1.0)
        G_out = np.clip(G_out * scale_compress, 0.0, 1.0)
        B_out = np.clip(B_out * scale_compress, 0.0, 1.0)

        # ── Stage 3: Midtone S-curve contrast ────────────────────────────────
        # Build a smooth triangle-peak contrast boost: peaked at the midpoint
        # of [midtone_lo, midtone_hi], falling to zero at the boundaries.
        # Pixels in the lower half of the midtone range are darkened slightly;
        # pixels in the upper half are brightened — the classic S-curve shape.
        if midtone_contrast > 0.0:
            lum_mid = 0.299 * R_out + 0.587 * G_out + 0.114 * B_out
            mid_center = 0.5 * (midtone_lo + midtone_hi)
            # Smooth triangle weight inside [midtone_lo, midtone_hi]
            mid_wt = np.clip(
                1.0 - np.abs(lum_mid - mid_center) / (0.5 * (midtone_hi - midtone_lo) + 1e-8),
                0.0, 1.0
            )
            # S-curve direction: above center → lift, below center → deepen
            s_direction = np.sign(lum_mid - mid_center)
            # Magnitude: proportional to distance from center × window weight
            s_boost = s_direction * np.abs(lum_mid - mid_center) / (mid_center + 1e-8) \
                      * mid_wt * midtone_contrast

            lum_safe3 = np.maximum(lum_mid, 1e-8)
            lum_scurve = np.clip(lum_mid + s_boost, 0.0, 1.0)
            scale_scurve = lum_scurve / lum_safe3
            R_out = np.clip(R_out * scale_scurve, 0.0, 1.0)
            G_out = np.clip(G_out * scale_scurve, 0.0, 1.0)
            B_out = np.clip(B_out * scale_scurve, 0.0, 1.0)

        # ── Apply figure_only masking if requested ────────────────────────────
        if figure_only and self._figure_mask is not None:
            fm = self._figure_mask
            from PIL import Image as _PILImg2
            if fm.shape != (self.h, self.w):
                fm = np.array(
                    _PILImg2.fromarray((fm * 255).astype(np.uint8)).resize(
                        (self.w, self.h), _PILImg2.BILINEAR)) / 255.0
            R_out = R_tc * (1.0 - fm) + R_out * fm
            G_out = G_tc * (1.0 - fm) + G_out * fm
            B_out = B_tc * (1.0 - fm) + B_out * fm

        # ── Write back ───────────────────────────────────────────────────────
        buf[:, :, 0] = np.clip(B_out * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(G_out * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 2] = np.clip(R_out * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255
        _tmp_tc = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(_tmp_tc, 0, 0)
        self.canvas.ctx.paint()

    def candlelight_pass(
            self,
            candle_x:       float = 0.50,
            candle_y:       float = 0.55,
            radius:         float = 0.55,
            candle_color:   Color = (0.92, 0.62, 0.18),
            dark_color:     Color = (0.04, 0.02, 0.01),
            warmth_peak:    float = 0.55,
            void_crush:     float = 0.88,
            falloff_power:  float = 2.2,
            figure_only:    bool  = False,
    ):
        """
        Candlelight pass — inspired by Georges de La Tour's nocturnal paintings.

        La Tour's defining achievement is the single concealed candle as sole light
        source.  His nocturnes are built on three interlocking principles:

        1. **Warm radial gradient** — a concentrated amber-orange glow emanates from
           the candle position, falling off gradually across the picture plane.  Unlike
           Caravaggio's sudden chiaroscuro cut, La Tour's light transition is long and
           tender — warmth persists into the mid-shadow before the void takes over.

        2. **Absolute void** — beyond the light's reach the canvas approaches
           near-black.  There is no reflected ambient light, no secondary source,
           no horizon.  The darkness is total and meditative.

        3. **Warm colour push** — all lit surfaces are shifted toward the candle
           color (amber-orange).  La Tour's flesh in candlelight is not ivory-white
           but a deep warm amber-rust, and his drapery loses its local colour in
           favour of the universal amber tint.

        This pass simulates all three effects in pixel space:

        * **Radial distance mask** — for each pixel, normalised distance from
          (candle_x, candle_y) is computed in canvas-diagonal units and raised to
          ``falloff_power`` to create the characteristic La Tour gradient shape
          (power > 2 keeps the bright core tight; power < 2 spreads light wider).

        * **Warmth blend** — in the bright zone (distance < radius × 0.6) the
          canvas RGB is nudged toward ``candle_color`` by ``warmth_peak × (1-t)``
          where ``t`` is the normalised distance.  This warms lit flesh and cloth.

        * **Void crush** — in the shadow zone (distance > radius × 0.5) the canvas
          is blended toward ``dark_color`` (near-black) by ``void_crush × t``.
          The transition is smooth: both effects overlap in the mid-shadow band,
          creating La Tour's characteristic amber-to-black gradient.

        The pass respects the figure mask if ``figure_only=True``, restricting the
        effect to the painted figure — useful if the background has already been
        taken to near-black by a preceding dark_void_pass or vignette.

        Parameters
        ----------
        candle_x, candle_y : Normalised canvas position (0-1) of the candle.
                             (0.5, 0.5) is dead centre.  La Tour often places the
                             candle slightly below centre (0.5, 0.55–0.65).
        radius             : Light falloff radius as a fraction of the canvas
                             diagonal.  0.45–0.65 gives a realistic candlelit pool.
        candle_color       : RGB colour of the warm candlelight (amber-orange).
        dark_color         : RGB colour of the absolute void darkness (near-black).
        warmth_peak        : Maximum warm colour push in the bright zone (0–1).
                             0.40–0.65 is typical; lower = cooler candle.
        void_crush         : Maximum darkness push in the shadow zone (0–1).
                             0.75–0.95 produces La Tour's near-black void.
        falloff_power      : Exponent controlling the shape of the radial falloff.
                             2.0 = quadratic (wide, soft); 3.0 = cubic (tighter core).
        figure_only        : Restrict effect to the figure mask if True.
        """
        print(f"  Candlelight pass  "
              f"(candle=({candle_x:.2f},{candle_y:.2f})  "
              f"radius={radius:.2f}  "
              f"warmth={warmth_peak:.2f}  void_crush={void_crush:.2f})")

        import numpy as np

        h, w = self.h, self.w

        # ── Build normalised distance map from candle position ────────────────
        # Distance is measured in canvas-diagonal units so the radius parameter
        # is resolution-independent.
        diag = math.sqrt(w * w + h * h)
        ys = np.arange(h, dtype=np.float32) / h          # 0 … 1 top→bottom
        xs = np.arange(w, dtype=np.float32) / w          # 0 … 1 left→right
        xg, yg = np.meshgrid(xs, ys)                     # (h, w)
        dx = (xg - candle_x) * w / diag
        dy = (yg - candle_y) * h / diag
        dist_raw = np.sqrt(dx * dx + dy * dy)            # 0 … ~1, candle=0

        # Normalise so radius maps to 1.0
        dist_norm = np.clip(dist_raw / max(radius, 1e-6), 0.0, 1.0)

        # Apply falloff power — tighter bright core, longer shadow tail
        t = dist_norm ** falloff_power                   # 0=candle, 1=void

        # ── Read current canvas into float32 RGB ─────────────────────────────
        buf = np.frombuffer(self.canvas.surface.get_data(),
                            dtype=np.uint8).reshape(h, w, 4).copy()
        # Cairo ARGB32: channel order in memory is B G R A
        R = buf[:, :, 2].astype(np.float32) / 255.0
        G = buf[:, :, 1].astype(np.float32) / 255.0
        B = buf[:, :, 0].astype(np.float32) / 255.0

        # ── Stage 1: Warm colour push toward candle_color ────────────────────
        # The warmth blend is strongest at t=0 (candle) and zero at t=1 (void).
        # We use a smooth curve: warmth_weight = warmth_peak * (1 - t)^2
        # so the warm push falls off quadratically — a slow, tender gradient.
        warmth_weight = warmth_peak * np.clip((1.0 - t) ** 2, 0.0, 1.0)
        cr, cg, cb = candle_color
        R_out = R + (cr - R) * warmth_weight
        G_out = G + (cg - G) * warmth_weight
        B_out = B + (cb - B) * warmth_weight

        # ── Stage 2: Void crush toward dark_color ────────────────────────────
        # The darkness blend is zero at t=0 and void_crush at t=1.
        # We use a smooth curve: crush_weight = void_crush * t^2
        # so the void creeps in gradually — the mid-shadow band stays warm.
        crush_weight = void_crush * np.clip(t ** 2, 0.0, 1.0)
        dr, dg, db = dark_color
        R_out = R_out + (dr - R_out) * crush_weight
        G_out = G_out + (dg - G_out) * crush_weight
        B_out = B_out + (db - B_out) * crush_weight

        R_out = np.clip(R_out, 0.0, 1.0)
        G_out = np.clip(G_out, 0.0, 1.0)
        B_out = np.clip(B_out, 0.0, 1.0)

        # ── Apply figure_only masking if requested ────────────────────────────
        if figure_only and self._figure_mask is not None:
            from PIL import Image as _PILImg
            fm = self._figure_mask
            if fm.shape != (h, w):
                fm = np.array(
                    _PILImg.fromarray((fm * 255).astype(np.uint8)).resize(
                        (w, h), _PILImg.BILINEAR)) / 255.0
            R_out = R * (1.0 - fm) + R_out * fm
            G_out = G * (1.0 - fm) + G_out * fm
            B_out = B * (1.0 - fm) + B_out * fm

        # ── Write back to Cairo surface ───────────────────────────────────────
        buf[:, :, 2] = np.clip(R_out * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 1] = np.clip(G_out * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 0] = np.clip(B_out * 255.0, 0, 255).astype(np.uint8)
        buf[:, :, 3] = 255
        _tmp_cl = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        self.canvas.ctx.set_source_surface(_tmp_cl, 0, 0)
        self.canvas.ctx.paint()

    def verdaccio_pass(
            self,
            strength:        float = 0.18,
            shadow_thresh:   float = 0.42,
            shadow_width:    float = 0.28,
            green_shift:     float = 0.55,
            figure_only:     bool  = True,
    ):
        """
        Verdaccio underpainting pass — Renaissance shadow-cooling technique.

        Verdaccio (Italian: *greenish-grey*) is the cool grey-green underpaint
        used by Leonardo, Raphael, and the Flemish masters beneath flesh tones.
        It is a mixture of terre verte (green earth), ivory black, and white,
        applied as the value-construction layer over which warm flesh glazes are
        later laid.  Where the flesh glazes are thinner — in the shadows — the
        cool grey-green shows through, creating the characteristic luminous cool
        cast of Renaissance shadow flesh.  This is why Mona Lisa's shadow side
        reads as cool blue-green rather than the warm ochre of the lit side.

        This pass simulates the optical result of a verdaccio ground that was
        never fully covered by subsequent flesh:

        * **Shadow identification** — a luminance map of the current canvas
          identifies pixels below ``shadow_thresh``.  A smooth ramp of width
          ``shadow_width`` transitions from full effect (deep shadow) to zero
          effect (highlight).

        * **Hue rotation toward verdaccio** — in-shadow pixels have their hue
          gently rotated toward the cool grey-green of terre verte (HSV hue
          ≈ 0.30–0.38).  The ``green_shift`` parameter controls the fraction of
          hue rotation applied (0 = no shift; 1 = full verdaccio tint).
          Saturation is mildly boosted in mid-shadow to match the slight
          colouration of actual terre verte (which is more green than grey).

        * **Chroma desaturation in deep shadow** — where luminance drops below
          ``shadow_thresh × 0.55``, saturation is gently reduced.  This prevents
          the verdaccio from looking artificially green in the deepest shadows
          where the underpaint would actually be near-black.

        * **Figure-only masking** — when ``figure_only=True`` (default), the
          effect is restricted to the figure mask so the background landscape
          is not affected.

        Placement in the pipeline
        -------------------------
        Call AFTER ``build_form()`` and ``atmospheric_depth_pass()`` but BEFORE
        the first ``sfumato_veil_pass()`` and any glazing.  The verdaccio sits
        below the glaze layers; the subsequent warm amber glaze re-warms the
        highlights while the cool verdaccio persists in the shadow half.

        Parameters
        ----------
        strength       : Overall blend weight toward the verdaccio tint (0–1).
                         0.12–0.22 is the typical visible range — beyond 0.30
                         the green becomes too obvious against warm flesh glazes.
        shadow_thresh  : Luminance (0–1) below which the verdaccio is applied.
                         0.38–0.46 targets shadow flesh without touching mid-tones.
        shadow_width   : Width of the smooth transition ramp from shadow to light.
                         Wider ramp = gentler transition; narrower = hard edge.
        green_shift    : Fraction of hue rotated toward terre-verte green (0–1).
                         0.40–0.65 is historically accurate; above 0.75 reads
                         as obvious green paint rather than subtle cool shadow.
        figure_only    : Apply only to the figure region if True (recommended).
        """
        print(f"  Verdaccio pass  "
              f"(strength={strength:.2f}  shadow_thresh={shadow_thresh:.2f}  "
              f"green_shift={green_shift:.2f}  figure_only={figure_only})")

        import colorsys as _cs
        import numpy as _np

        h, w = self.h, self.w

        # ── Read current canvas into float32 RGB ──────────────────────────────
        buf = _np.frombuffer(self.canvas.surface.get_data(), dtype=_np.uint8)
        buf = buf.reshape((h, w, 4)).copy()

        R = buf[:, :, 2].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        B = buf[:, :, 0].astype(_np.float32) / 255.0

        # ── Luminance map (perceptual weights) ────────────────────────────────
        lum = 0.2126 * R + 0.7152 * G + 0.0722 * B

        # Shadow mask: smooth ramp from 1.0 (deep shadow) to 0.0 (highlight)
        # Ramp: 1.0 for lum ≤ (shadow_thresh - shadow_width/2)
        #        linear fall-off to 0.0 at lum = shadow_thresh + shadow_width/2
        lo = shadow_thresh - shadow_width * 0.5
        hi = shadow_thresh + shadow_width * 0.5
        shadow_mask = _np.clip((hi - lum) / (hi - lo + 1e-8), 0.0, 1.0)

        # ── Apply figure-only masking ─────────────────────────────────────────
        if figure_only and self._figure_mask is not None:
            from PIL import Image as _PILImg
            fm = self._figure_mask
            if fm.shape != (h, w):
                fm = _np.array(
                    _PILImg.fromarray((fm * 255).astype(_np.uint8)).resize(
                        (w, h), _PILImg.BILINEAR)) / 255.0
            shadow_mask = shadow_mask * fm

        # ── Per-pixel hue rotation toward terre verte ─────────────────────────
        # Terre verte HSV hue ≈ 0.33 (greenish-grey).
        # We vectorise by processing unique quantised hue buckets for speed.
        TARGET_HUE = 0.33
        TARGET_SAT_BOOST = 0.08   # slight saturation increase in mid-shadow

        R_out = R.copy()
        G_out = G.copy()
        B_out = B.copy()

        # Flatten for vectorised HSV conversion
        r_flat = R.ravel()
        g_flat = G.ravel()
        b_flat = B.ravel()
        mask_flat = shadow_mask.ravel()
        lum_flat  = lum.ravel()

        r_new = r_flat.copy()
        g_new = g_flat.copy()
        b_new = b_flat.copy()

        # Only process pixels where shadow_mask > 0.005 (skip highlights)
        active = mask_flat > 0.005
        if active.any():
            ra = r_flat[active]
            ga = g_flat[active]
            ba = b_flat[active]
            ma = mask_flat[active]
            la = lum_flat[active]

            # Convert to HSV in vectorised fashion via a small loop over blocks
            block_size = 4096
            n = ra.shape[0]
            h_arr = _np.zeros(n, dtype=_np.float32)
            s_arr = _np.zeros(n, dtype=_np.float32)
            v_arr = _np.zeros(n, dtype=_np.float32)

            for start in range(0, n, block_size):
                end = min(start + block_size, n)
                for i in range(start, end):
                    hh, ss, vv = _cs.rgb_to_hsv(float(ra[i]), float(ga[i]), float(ba[i]))
                    h_arr[i] = hh
                    s_arr[i] = ss
                    v_arr[i] = vv

            # Hue rotation toward TARGET_HUE
            # The rotation is weighted by green_shift * shadow_mask
            hue_blend = green_shift * ma
            # Shortest-path hue interpolation
            dh = TARGET_HUE - h_arr
            # Wrap to [-0.5, 0.5]
            dh = (dh + 0.5) % 1.0 - 0.5
            h_new = h_arr + dh * hue_blend

            # Saturation: slight boost in mid-shadow, slight cut in deep shadow
            deep_shadow = _np.clip((shadow_thresh * 0.55 - la) /
                                   (shadow_thresh * 0.55 + 1e-8), 0.0, 1.0)
            mid_shadow  = ma * (1.0 - deep_shadow)
            s_new = _np.clip(s_arr + TARGET_SAT_BOOST * mid_shadow * green_shift
                             - 0.10 * deep_shadow * ma, 0.0, 1.0)

            # Convert back to RGB
            r_a_new = _np.zeros(n, dtype=_np.float32)
            g_a_new = _np.zeros(n, dtype=_np.float32)
            b_a_new = _np.zeros(n, dtype=_np.float32)

            for start in range(0, n, block_size):
                end = min(start + block_size, n)
                for i in range(start, end):
                    rr, gg, bb = _cs.hsv_to_rgb(float(h_new[i] % 1.0),
                                                 float(s_new[i]), float(v_arr[i]))
                    r_a_new[i] = rr
                    g_a_new[i] = gg
                    b_a_new[i] = bb

            # Blend: verdaccio weighted by strength × shadow_mask
            blend_w = strength * ma
            r_new[active] = ra * (1.0 - blend_w) + r_a_new * blend_w
            g_new[active] = ga * (1.0 - blend_w) + g_a_new * blend_w
            b_new[active] = ba * (1.0 - blend_w) + b_a_new * blend_w

        R_out = r_new.reshape(h, w)
        G_out = g_new.reshape(h, w)
        B_out = b_new.reshape(h, w)

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(R_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(G_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(B_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255
        _tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, w, h)
        self.canvas.ctx.set_source_surface(_tmp, 0, 0)
        self.canvas.ctx.paint()
        n_active = int(active.sum()) if active.any() else 0
        print(f"    Verdaccio complete  (shadow_pixels={n_active})")

    def dry_granulation_pass(
            self,
            palette:      List[Color],
            n_marks:      int   = 1800,
            mark_size:    float = 4.5,
            opacity:      float = 0.18,
            hue_spread:   float = 0.04,
            value_spread: float = 0.06,
            figure_only:  bool  = False,
            rng_seed:     Optional[int] = None,
    ):
        """
        Dry granulation pass — inspired by Jean-Baptiste-Siméon Chardin's
        powdery, granular surface technique.

        Chardin built his surfaces through tiny overlapping dry-brush marks of
        subtly varied related colours — what Diderot described as 'pastel without
        a stylus'.  Rather than wet-blending pigments into a smooth gradient, he
        juxtaposed closely related hues (ochre-grey, blue-grey, rose-grey) in the
        same shadow passage, relying on optical mixing at viewing distance to
        resolve them into a unified, luminous tone.

        This pass simulates that granular optical surface by stamping small
        directional marks sampled from a provided palette — each mark varied
        slightly in hue and value from its neighbours.  The effect is additive
        optical mixing: no single mark dominates, but their aggregate creates
        the characteristic Chardin texture — simultaneously powdery and rich.

        Implementation
        --------------
        1. Build a luminance map of the current canvas.
        2. For each of ``n_marks`` sampled positions (uniform random over the
           canvas or figure region):
           a. Sample a base colour from ``palette``.
           b. Apply small random hue perturbation (±``hue_spread``) and value
              perturbation (±``value_spread``) in HSV space.
           c. Stamp a small rectangular mark (``mark_size`` × ``mark_size`` px)
              rotated by a random angle drawn from a Gaussian (mean=0, σ=35°)
              to simulate the natural directional variation of dry-brush marks.
           d. Composite the mark at ``opacity`` using standard alpha blending.
        3. The mark density is uniform across the canvas — Chardin's hallmark
           is that every passage (shadows, highlights, background) receives the
           same intimate attention.

        Parameters
        ----------
        palette       : List of (R,G,B) base colours to sample from.  Use
                        the artist's ``ArtStyle.palette`` for authentic harmony.
                        Chardin's palette should include warm greys, ochres, and
                        soft whites — avoid saturated colours.
        n_marks       : Number of individual dry-brush marks to stamp.
                        1500–2500 for a full 780×1080 canvas; fewer = coarser grain.
        mark_size     : Width of each stamp mark in pixels (height = 1.8 × width
                        to simulate the elongated brush mark).  3–6px is typical.
        opacity       : Composite weight of each mark.  0.12–0.22 preserves the
                        underlying paint; 0.30+ begins to overpower it.
        hue_spread    : Maximum ±hue variation from the base colour (HSV units).
                        0.03–0.06 creates varied-but-related marks; above 0.10
                        reads as random colour noise rather than optical mixing.
        value_spread  : Maximum ±value variation.  0.04–0.08 gives the powdery
                        light–dark variation within a single tone zone.
        figure_only   : If True, restrict marks to the figure mask.
        rng_seed      : Optional seed for reproducibility.
        """
        print(f"  Dry granulation pass  "
              f"(marks={n_marks}  mark_size={mark_size:.1f}  "
              f"opacity={opacity:.2f}  figure_only={figure_only})")

        import colorsys as _cs
        import numpy as _np

        rng = random.Random(rng_seed)
        h, w = self.h, self.w

        # ── Build candidate pixel pool ────────────────────────────────────────
        if figure_only and self._figure_mask is not None:
            from PIL import Image as _PILImg
            fm = self._figure_mask
            if fm.shape != (h, w):
                fm = _np.array(
                    _PILImg.fromarray((fm * 255).astype(_np.uint8)).resize(
                        (w, h), _PILImg.BILINEAR)) / 255.0
            ys, xs = _np.where(fm > 0.15)
        else:
            ys, xs = _np.mgrid[0:h:1, 0:w:1]
            ys = ys.ravel()
            xs = xs.ravel()

        n_candidates = len(ys)
        if n_candidates == 0:
            print("    No active pixels — skipping dry granulation")
            return

        mh = int(mark_size * 1.8)
        mw = int(mark_size)

        n_placed = 0
        for _ in range(n_marks):
            # Random position from candidate pool
            idx = rng.randint(0, n_candidates - 1)
            cy = int(ys[idx])
            cx = int(xs[idx])

            # Sample and perturb colour
            base = rng.choice(palette)
            bh, bs, bv = _cs.rgb_to_hsv(*base)
            bh = (bh + rng.uniform(-hue_spread, hue_spread)) % 1.0
            bv = max(0.0, min(1.0, bv + rng.uniform(-value_spread, value_spread)))
            cr, cg, cb = _cs.hsv_to_rgb(bh, bs, bv)

            # Random rotation angle (Gaussian, σ=35°)
            # Use rng.gauss; clamp to ±80°
            angle = max(-80.0, min(80.0, rng.gauss(0, 35.0)))
            angle_r = math.radians(angle)
            cos_a = math.cos(angle_r)
            sin_a = math.sin(angle_r)

            # Rasterise rotated rectangle mark
            half_h = mh / 2.0
            half_w = mw / 2.0
            for ry in range(-int(half_h) - 1, int(half_h) + 2):
                for rx in range(-int(half_w) - 1, int(half_w) + 2):
                    # Inverse rotate to check if inside unrotated rectangle
                    local_x =  rx * cos_a + ry * sin_a
                    local_y = -rx * sin_a + ry * cos_a
                    if abs(local_x) <= half_w and abs(local_y) <= half_h:
                        px = cx + rx
                        py = cy + ry
                        if 0 <= px < w and 0 <= py < h:
                            self.canvas.ctx.set_source_rgba(cr, cg, cb, opacity)
                            self.canvas.ctx.rectangle(px, py, 1, 1)
                            self.canvas.ctx.fill()
            n_placed += 1

        print(f"    Dry granulation complete  (marks_placed={n_placed})")

    def palette_knife_pass(
            self,
            palette:        List[Color],
            n_strokes:      int   = 600,
            min_length:     float = 18.0,
            max_length:     float = 60.0,
            thickness:      float = 8.0,
            opacity:        float = 0.72,
            edge_ridge:     float = 0.18,
            angle_spread:   float = 45.0,
            value_contrast: float = 0.18,
            figure_only:    bool  = False,
            rng_seed:       Optional[int] = None,
    ):
        """
        Palette knife pass — inspired by Gustave Courbet's thick impasto technique.

        Courbet frequently applied paint with flexible steel palette knives rather
        than brushes, producing a distinctive surface character:

        1. **Flat colour planes** — the knife deposits a uniform layer of paint
           in a single directional stroke.  Within each stroke the colour is nearly
           constant (unlike a brush stroke whose opacity tapers at both ends).

        2. **Clean hard edges** — the knife's straight steel edge leaves a crisp
           boundary along the sides of each stroke, unlike the feathered edge of a
           bristle brush.  Tonal transitions between planes are abrupt.

        3. **Edge ridges** — paint accumulates in a thin ridge at the terminus and
           sides of each knife stroke, creating a subtle 3D relief.  This is
           simulated here by painting a narrow darker-value border around each stroke.

        4. **Directional drag texture** — the knife moves in a single direction,
           leaving a faint linear grain along the stroke axis.

        This pass operates over the existing canvas state, building the mid-tone and
        shadow passages characteristic of Courbet's dark-ground realism.  Call it
        after ``tone_ground()`` and ``underpainting()`` but before ``place_lights()``.

        Implementation
        --------------
        For each stroke:
        1. Choose a random position (within the figure mask if ``figure_only``).
        2. Sample a colour from ``palette`` and shift its value by ±``value_contrast``
           (simulating the tonal variation between adjacent knife planes).
        3. Draw a filled rectangle of size ``length × thickness`` at a random angle
           drawn uniformly from ±``angle_spread`` degrees.
        4. Optionally draw a thin darker border (``edge_ridge`` opacity) around the
           rectangle to simulate the paint ridge.

        Parameters
        ----------
        palette        : List of (R,G,B) base colours to sample from.  Use the
                         artist's ``ArtStyle.palette`` for authentic harmony.
                         Courbet's palette should be dark earth tones.
        n_strokes      : Number of knife strokes.  400–800 for a full 780×1080
                         canvas gives the characteristic Courbet plane density.
        min_length     : Minimum stroke length in pixels.
        max_length     : Maximum stroke length in pixels.
        thickness      : Knife width in pixels (height of the stroke rectangle).
        opacity        : Fill opacity of each stroke.  0.65–0.80 keeps underlying
                         ground visible in the gaps between strokes.
        edge_ridge     : Opacity of the edge-ridge border.  0.10–0.25 gives a
                         subtle physical relief suggestion without overdoing it.
        angle_spread   : ±degrees from horizontal for stroke direction.  45° gives
                         the varied-but-mostly-horizontal feel of Courbet's large
                         outdoor compositions.
        value_contrast : ±value shift applied to each stroke's base colour in HSV.
                         0.12–0.22 creates the tonal plane separation that defines
                         Courbet's form-building without palette-knife flatness.
        figure_only    : If True, restrict strokes to the figure mask region.
        rng_seed       : Optional seed for reproducibility.
        """
        print(f"  Palette knife pass  "
              f"(strokes={n_strokes}  thickness={thickness:.1f}  "
              f"opacity={opacity:.2f}  figure_only={figure_only})")

        import colorsys as _cs
        import numpy as _np

        rng = random.Random(rng_seed)
        h, w = self.h, self.w

        # ── Build candidate pixel pool ────────────────────────────────────────
        if figure_only and self._figure_mask is not None:
            from PIL import Image as _PILImg
            fm = self._figure_mask
            if fm.shape != (h, w):
                fm = _np.array(
                    _PILImg.fromarray((fm * 255).astype(_np.uint8)).resize(
                        (w, h), _PILImg.BILINEAR)) / 255.0
            ys, xs = _np.where(fm > 0.15)
        else:
            ys, xs = _np.mgrid[0:h:1, 0:w:1]
            ys = ys.ravel()
            xs = xs.ravel()

        n_candidates = len(ys)
        if n_candidates == 0:
            print("    No active pixels — skipping palette knife pass")
            return

        half_t = thickness / 2.0
        n_placed = 0

        for _ in range(n_strokes):
            # Random anchor position
            idx = rng.randint(0, n_candidates - 1)
            cy = int(ys[idx])
            cx = int(xs[idx])

            # Stroke geometry: length and angle
            length    = rng.uniform(min_length, max_length)
            angle_deg = rng.uniform(-angle_spread, angle_spread)
            angle_r   = math.radians(angle_deg)
            half_l    = length / 2.0

            # Sample and value-shift colour (tonal plane separation)
            base = rng.choice(palette)
            bh, bs, bv = _cs.rgb_to_hsv(*base)
            bv = max(0.0, min(1.0, bv + rng.uniform(-value_contrast, value_contrast)))
            cr, cg, cb = _cs.hsv_to_rgb(bh, bs, bv)

            # Path: two endpoints along stroke direction
            dx = math.cos(angle_r) * half_l
            dy = math.sin(angle_r) * half_l
            pts_k  = [(cx - dx, cy - dy), (cx + dx, cy + dy)]
            wids_k = [thickness, thickness]

            region = (self._figure_mask.astype(np.float32)
                      if figure_only and self._figure_mask is not None else None)

            self.canvas.apply_knife_stroke(
                pts_k, wids_k, (cr, cg, cb),
                profile=BRUSH_PRESETS['knife_trowel'],
                opacity=opacity,
                scrape=False,
                wet_blend=0.06,
                jitter_amt=0.02,
                rng=rng,
                region_mask=region,
            )
            n_placed += 1

        print(f"    Palette knife complete  (strokes_placed={n_placed})")

    # academic_skin_pass — Bouguereau porcelain-smooth flesh technique
    # ─────────────────────────────────────────────────────────────────────────
    def academic_skin_pass(
            self,
            reference:      Union[np.ndarray, Image.Image],
            n_passes:       int   = 4,
            strokes_per_pass: int = 600,
            stroke_size:    float = 3.5,
            wet_blend:      float = 0.88,
            opacity:        float = 0.38,
            skin_thresh_low: float = 0.38,
            skin_thresh_high: float = 0.88,
            jitter_amt:     float = 0.008,
            rng_seed:       Optional[int] = None,
    ):
        """
        Academic skin pass — inspired by William-Adolphe Bouguereau's porcelain-smooth
        flesh technique.

        Bouguereau built his characteristically seamless flesh through many sessions of
        imperceptibly fine brushwork.  Each session laid down tiny, carefully graduated
        strokes that were immediately blended with a dry soft brush before the paint set.
        After multiple sessions — each at a slightly different stroke angle — all trace of
        individual marks was erased, leaving a surface of extraordinary smoothness that
        critics described as "wax" or "porcelain."

        This pass simulates that quality:

        1. **Skin detection**: only skin-toned pixels in the reference are targeted —
           regions where luminance is in the mid-to-high range and the hue is in the
           warm flesh band (red-orange-yellow).  This keeps the pass from touching
           hair, clothing, or the background.

        2. **Multi-pass micro-blending**: ``n_passes`` passes of tiny strokes are applied.
           Each pass uses a slightly different angle offset so the directionality of no
           single pass dominates.  Within each pass, strokes are placed with very high
           ``wet_blend`` (default 0.88) so each mark is nearly fully blended with the
           paint already on the canvas beneath it — the stroke deposits colour without
           leaving a discrete edge.

        3. **Graduated colour sampling**: the colour for each stroke is sampled from the
           reference at the stroke's anchor point, then perturbed by a tiny jitter
           (default ±0.008).  At this jitter level the perceptual variation is below the
           threshold of the human eye but above zero, preventing the mechanical
           uniformity of a flat digital fill.

        4. **Angle variation per pass**: each of the ``n_passes`` passes rotates the
           stroke angle distribution by ``180° / n_passes``.  The cumulative effect is
           that strokes cross each other at many angles, producing the isotropic surface
           quality of true Academic blending — no single brush direction can be seen.

        Call this pass AFTER ``build_form()`` and BEFORE ``place_lights()``.
        The pass concentrates on the figure area (if a figure mask is set) and within
        that area on skin-toned regions detected from the reference.  Follow with
        ``glazed_panel_pass()`` at low opacity to add Bouguereau's characteristic warm
        golden depth without disturbing the smooth surface.

        Parameters
        ----------
        reference        : The colour reference image — used both to detect skin regions
                           and to sample stroke colours.
        n_passes         : Number of blending passes.  Each adds a further layer of
                           imperceptible smoothing.  4–6 passes approximate a single
                           Bouguereau glazing session; 8–12 approach his full multi-day
                           technique.
        strokes_per_pass : Number of strokes per pass.  600–1000 covers a 780×1080 face
                           region with dense micro-marks.
        stroke_size      : Stroke radius in pixels.  2–4px gives Bouguereau's finest
                           filbert-tip quality.  Values above 6 produce a visible, more
                           Sargent-like mark.
        wet_blend        : Blending strength.  0.85–0.92 for true porcelain smoothness.
                           Values below 0.70 leave a visible brushstroke texture.
        opacity          : Per-stroke opacity.  0.30–0.45 allows many passes to build up
                           without any single pass dominating the surface.
        skin_thresh_low  : Minimum luminance for a pixel to be considered skin.  Default
                           0.38 excludes deep shadow regions (which do not benefit from
                           the smooth blending pass).
        skin_thresh_high : Maximum luminance for a pixel to be considered skin.  Default
                           0.88 excludes specular highlights (which should remain crisp
                           after ``place_lights()``).
        jitter_amt       : Per-stroke colour jitter.  0.005–0.012 is the sweet spot for
                           organic variation below the threshold of perception.
        rng_seed         : Optional seed for reproducibility.
        """
        print(f"  Academic skin pass  "
              f"(n_passes={n_passes}  strokes/pass={strokes_per_pass}  "
              f"size={stroke_size:.1f}  wet_blend={wet_blend:.2f})")

        import colorsys as _cs
        import numpy as _np

        rng   = random.Random(rng_seed)
        ref   = self._prep(reference)           # → uint8 (H, W, 4)
        h, w  = self.h, self.w

        # ── Normalize to float32 [0, 1] and resize if necessary ──────────────
        # _prep() returns uint8 (H, W, 4); we always need float32 (H, W, 3)
        # in [0, 1] for luminance computation and skin detection thresholds.
        if ref.shape[:2] != (h, w):
            from PIL import Image as _PILImg
            ref_img = _PILImg.fromarray(ref[:, :, :3].astype(_np.uint8), "RGB")
            ref = _np.array(ref_img.resize((w, h), _PILImg.BILINEAR)).astype(_np.float32) / 255.0
        else:
            ref = ref[:, :, :3].astype(_np.float32) / 255.0

        # ── Build skin mask: warm-hue + mid-luminance pixels ─────────────────
        # Luminance (perceptual): 0.299 R + 0.587 G + 0.114 B
        lum = (0.299 * ref[:, :, 0] +
               0.587 * ref[:, :, 1] +
               0.114 * ref[:, :, 2])

        # Warm skin hue: red channel dominant, green secondary, blue minimal.
        # This detects orange-yellow-red flesh without picking up foliage or sky.
        warm_hue = (ref[:, :, 0] > ref[:, :, 2] + 0.06) & \
                   (ref[:, :, 0] > ref[:, :, 1] - 0.10)

        skin_mask = (
            warm_hue &
            (lum >= skin_thresh_low) &
            (lum <= skin_thresh_high)
        )

        # Intersect with figure mask if available
        if self._figure_mask is not None:
            fm = self._figure_mask
            if fm.shape != (h, w):
                from PIL import Image as _PILImg
                fm = _np.array(
                    _PILImg.fromarray((fm * 255).astype(_np.uint8)).resize(
                        (w, h), _PILImg.BILINEAR)) / 255.0
            skin_mask = skin_mask & (fm > 0.15)

        ys, xs = _np.where(skin_mask)
        n_candidates = len(ys)
        if n_candidates == 0:
            print("    No skin pixels detected — skipping academic_skin_pass")
            return

        print(f"    Skin region: {n_candidates} pixels  "
              f"({100.0 * n_candidates / (h * w):.1f}% of canvas)")

        total_placed = 0

        for pass_idx in range(n_passes):
            # Each pass rotates the angle distribution to erase directionality
            angle_offset = pass_idx * (180.0 / n_passes)
            pass_placed  = 0

            for _ in range(strokes_per_pass):
                idx = rng.randint(0, n_candidates - 1)
                cy  = int(ys[idx])
                cx  = int(xs[idx])

                # Sample colour from reference at this location
                r_s = float(ref[cy, cx, 0])
                g_s = float(ref[cy, cx, 1])
                b_s = float(ref[cy, cx, 2])
                # Tiny perceptual jitter — organic but sub-threshold
                r_s = max(0.0, min(1.0, r_s + rng.uniform(-jitter_amt, jitter_amt)))
                g_s = max(0.0, min(1.0, g_s + rng.uniform(-jitter_amt, jitter_amt)))
                b_s = max(0.0, min(1.0, b_s + rng.uniform(-jitter_amt, jitter_amt)))

                # Stroke angle: small spread around the per-pass base angle
                angle_deg = angle_offset + rng.uniform(-22.0, 22.0)
                angle_r   = math.radians(angle_deg)

                # Stroke length: short — these are micro-blending marks, not form strokes
                length = rng.uniform(stroke_size * 1.8, stroke_size * 4.5)

                # Place the stroke using the canvas's apply_stroke infrastructure
                # Build a two-point path along the stroke direction
                dx = math.cos(angle_r) * length * 0.5
                dy = math.sin(angle_r) * length * 0.5
                pts = [(cx - dx, cy - dy), (cx + dx, cy + dy)]

                n_pts = len(pts)
                widths = [stroke_size * 0.9, stroke_size * 0.9]  # uniform width — filbert flat

                self.canvas.apply_stroke(
                    pts     = pts,
                    widths  = widths,
                    color   = (r_s, g_s, b_s),
                    tip     = BRUSH_PRESETS['round_sable'],
                    opacity = opacity,
                    wet_blend = wet_blend,
                    rng     = rng,
                )
                pass_placed += 1

            total_placed += pass_placed
            # Partial dry between passes: settles slightly but stays workable.
            # This prevents consecutive passes from becoming a single merged wash.
            self.canvas.dry(amount=0.18)

        # Bouguereau's finishing step: a dry fan brush swept across the surface
        # to merge micro-marks into seamless flesh.  Only if skin region detected.
        if n_candidates > 0:
            y0 = int(ys.min())
            y1 = int(ys.max())
            x0 = int(xs.min())
            x1 = int(xs.max())
            mid_y = float((y0 + y1) * 0.5)
            sweep_pts = [(float(x0), mid_y), (float(x1), mid_y)]
            fan_w = max(20.0, float(y1 - y0) * 0.4)
            self.canvas.fan_blend(
                sweep_pts,
                width=fan_w,
                strength=0.30,
                n_passes=2,
                region_mask=(self._figure_mask
                             if self._figure_mask is not None else None),
            )

        print(f"    Academic skin complete  "
              f"(total_strokes={total_placed}  passes={n_passes})")

    # ─────────────────────────────────────────────────────────────────────────
    # north_light_diffusion_pass — Mary Cassatt's north-window indoor daylight
    # ─────────────────────────────────────────────────────────────────────────

    def north_light_diffusion_pass(
            self,
            light_side:            str   = "left",
            cool_highlight_color:  Color = (0.72, 0.80, 0.92),
            warm_shadow_color:     Color = (0.88, 0.70, 0.42),
            cool_strength:         float = 0.10,
            warm_strength:         float = 0.08,
            gradient_sharpness:    float = 2.0,
            blend_opacity:         float = 0.30,
    ):
        """
        Simulates Mary Cassatt's characteristic north-window indoor daylight.

        Unlike the dramatic single-source chiaroscuro of Baroque painting or the
        outdoor broken-colour sunlight of Impressionism, Cassatt's indoor north-
        window light has three qualities that distinguish it:

        1. **Diffused and even**: the sky is the light source, not the sun.
           There is no hard terminator between light and shadow — the transition
           is gradual and soft across the whole form.

        2. **Cool on the lit side**: indirect sky light is perceptually cooler
           (blue-grey) than daylight.  The lit side of flesh and fabric carries
           a cool, silvery quality rather than the warm golden tone of sunlight.

        3. **Warm in the shadow**: interior shadows receive reflected warm light
           bouncing from walls, floors, and warm-coloured furniture.  Cassatt's
           shadow areas are never cold or dead — they glow with amber warmth.

        Implementation
        --------------
        A smooth horizontal (or vertical) gradient divides the canvas into a
        lit half and a shadow half.  The gradient uses a raised-cosine profile
        so the transition is natural rather than mechanical:

          - Lit pixels receive a cool blue-grey tint (``cool_highlight_color``)
            blended at ``cool_strength``.
          - Shadow pixels receive a warm amber tint (``warm_shadow_color``)
            blended at ``warm_strength``.
          - In the transition zone both influences are present, weighted by the
            gradient: no hard edge anywhere on the canvas.

        Luminance is preserved throughout: only the chromatic quality of the
        surface changes, not its tonal structure.

        Call AFTER ``build_form()`` and BEFORE ``place_lights()`` or the final
        glaze.  The pass complements ``reflected_light_pass()`` — they can be
        used together, with this pass setting the broad cool/warm temperature
        split and ``reflected_light_pass()`` adding fine shadow chromatics.

        Parameters
        ----------
        light_side            : Which side the north window is on.
                                "left", "right", "top", or "bottom".
        cool_highlight_color  : (R,G,B) for the lit-side cool tint.
                                Default: pale blue-grey (north sky quality).
        warm_shadow_color     : (R,G,B) for the shadow-side warm tint.
                                Default: warm amber (wall/floor bounce).
        cool_strength         : Blend weight for the cool highlight tint.
                                0.06–0.12 = subtle Cassatt quality; 0.20+ = very blue.
        warm_strength         : Blend weight for the warm shadow tint.
                                Slightly weaker than cool by default — the warm
                                bounce is gentler than the sky's influence on the lit.
        gradient_sharpness    : Controls how quickly the gradient transitions.
                                1.0 = linear; 2.0 = S-curve; 3.0+ = more abrupt.
                                Cassatt's diffused north light suits 1.8–2.5.
        blend_opacity         : Global opacity of the entire pass.  Allows the
                                pass to be stacked multiple times at low opacity
                                for a more gradual build (Cassatt's pastel technique).

        Notes
        -----
        Inspired by: "In the Loge" (1878), "The Child's Bath" (1893),
        "Little Girl in a Blue Armchair" (1878).
        Validated as this session's random artistic improvement pass.
        """
        import numpy as _np

        print(f"  North-light diffusion pass  "
              f"(side={light_side}  cool={cool_strength:.2f}  "
              f"warm={warm_strength:.2f}  opacity={blend_opacity:.2f})")

        # ── Read current canvas ARGB32 (BGRA byte order in pycairo) ──────────
        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * R + 0.587 * G + 0.114 * B

        # ── Build the light-to-shadow gradient (0 = full shadow, 1 = full lit) ─
        # Raised cosine profile: smooth S-curve between 0 and 1.
        h, w = self.h, self.w
        if light_side == "left":
            axis = _np.linspace(0.0, 1.0, w, dtype=_np.float32)[_np.newaxis, :]
        elif light_side == "right":
            axis = _np.linspace(1.0, 0.0, w, dtype=_np.float32)[_np.newaxis, :]
        elif light_side == "top":
            axis = _np.linspace(0.0, 1.0, h, dtype=_np.float32)[:, _np.newaxis]
        else:   # "bottom"
            axis = _np.linspace(1.0, 0.0, h, dtype=_np.float32)[:, _np.newaxis]

        # Smooth S-curve via raised cosine raised to gradient_sharpness power
        # Value = 1.0 at the lit side; 0.0 at the shadow side.
        lit_weight  = (0.5 - 0.5 * _np.cos(_np.pi * axis)) ** gradient_sharpness
        shad_weight = 1.0 - lit_weight   # complement

        # Broadcast to (H, W) — both arrays are already (1, W) or (H, 1)
        # _np broadcasting handles the expansion automatically.
        lit_weight  = lit_weight  * _np.ones((h, w), dtype=_np.float32)
        shad_weight = shad_weight * _np.ones((h, w), dtype=_np.float32)

        # ── Apply cool tint on the lit side ───────────────────────────────────
        cr, cg, cb = cool_highlight_color
        cool_alpha  = lit_weight * cool_strength * blend_opacity
        new_R = R + (cr - R) * cool_alpha
        new_G = G + (cg - G) * cool_alpha
        new_B = B + (cb - B) * cool_alpha

        # ── Apply warm tint on the shadow side ────────────────────────────────
        wr, wg, wb = warm_shadow_color
        warm_alpha  = shad_weight * warm_strength * blend_opacity
        new_R = new_R + (wr - new_R) * warm_alpha
        new_G = new_G + (wg - new_G) * warm_alpha
        new_B = new_B + (wb - new_B) * warm_alpha

        # ── Luminance preservation — chromatic shift only, tonal structure kept ─
        new_lum = 0.299 * new_R + 0.587 * new_G + 0.114 * new_B
        safe    = _np.where(new_lum > 1e-6, lum / new_lum, 1.0)
        new_R   = _np.clip(new_R * safe, 0.0, 1.0)
        new_G   = _np.clip(new_G * safe, 0.0, 1.0)
        new_B   = _np.clip(new_B * safe, 0.0, 1.0)

        # ── Write back to ARGB32 surface (BGRA layout) ───────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    North-light diffusion complete")

    # ─────────────────────────────────────────────────────────────────────────
    # bruegel_panorama_pass — Flemish aerial perspective
    # ─────────────────────────────────────────────────────────────────────────

    def bruegel_panorama_pass(
        self,
        *,
        haze_color:        Tuple[float, float, float] = (0.72, 0.78, 0.88),
        horizon_fraction:  float = 0.65,
        near_fraction:     float = 0.25,
        haze_opacity:      float = 0.55,
        desaturation:      float = 0.70,
        lightening:        float = 0.30,
        blend_mode:        str   = "normal",
    ) -> None:
        """
        Systematic aerial-perspective haze inspired by Pieter Bruegel the Elder.

        Bruegel was the first Northern European painter to apply Leonardo's
        atmospheric recession theory consistently across a whole canvas.  The
        result is a three-zone depth system that gives his panoramic landscapes
        their sensation of vast inhabited space:

          Foreground  (bottom near_fraction of the canvas)
              Warm, fully saturated earth tones — no haze applied.

          Middle-ground  (between near_fraction and horizon_fraction)
              Gradual cool temperature shift; moderate desaturation; faint
              blue-grey overlay blended in at rising opacity.

          Far-ground  (top, above horizon_fraction from bottom)
              Full desaturation toward near-monochrome; maximum blue-grey
              haze overlay at haze_opacity; atmospheric lightening lifts darks.

        Parameters
        ----------
        haze_color       : (R, G, B) in [0, 1] — atmospheric haze colour.
                           Bruegel's distance is cool blue-grey; winter scenes
                           use a paler, greyer variant.
        horizon_fraction : fraction of canvas height (from bottom) where the far
                           haze reaches full strength.  Default 0.65 places the
                           horizon in the upper third — Bruegel's high vantage.
        near_fraction    : fraction of canvas height (from bottom) that is
                           pure foreground — no haze applied here.  Default 0.25.
        haze_opacity     : maximum opacity of the haze overlay at full distance.
        desaturation     : fraction by which to desaturate at full depth (0 = none,
                           1 = full greyscale).
        lightening       : fraction by which to lighten dark pixels at full depth,
                           simulating the luminous pale horizon sky bleeding into
                           far-distance land masses.
        blend_mode       : 'normal' (alpha composite) or 'screen' (lighter effect).

        Notes
        -----
        The pass reads the current canvas pixel buffer, computes per-pixel
        depth weight from vertical position, then writes the modified buffer
        back to the cairo surface.  It is composable: apply after tone_ground()
        and build_form() passes but before final glaze.
        """
        import numpy as _np

        buf = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((self.h, self.w, 4)).copy()

        # BGRA → float RGB
        R = buf[:, :, 2].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        B = buf[:, :, 0].astype(_np.float32) / 255.0

        # ── Depth weight: 0.0 at foreground base, 1.0 at far horizon ──────────
        # y=0 is the top of the canvas (far distance in a high-horizon scene).
        # Bruegel's foreground is at the bottom (y_norm = 1); far at top (0).
        y_norm = _np.arange(self.h, dtype=_np.float32)[:, _np.newaxis] / self.h
        # y_norm: 0 = top (far), 1 = bottom (near)
        near_start  = 1.0 - near_fraction        # depth starts above this y_norm
        horiz_start = 1.0 - horizon_fraction      # full haze at and above this y_norm

        # depth_w = 0 in foreground, ramps linearly to 1 at horizon and beyond
        depth_w = _np.clip(
            (near_start - y_norm) / (near_start - horiz_start + 1e-9), 0.0, 1.0
        )
        depth_w = depth_w * _np.ones((self.h, self.w), dtype=_np.float32)

        # ── Desaturation toward grey ───────────────────────────────────────────
        lum = 0.299 * R + 0.587 * G + 0.114 * B
        desat_amount = depth_w * desaturation
        R = R + (lum - R) * desat_amount
        G = G + (lum - G) * desat_amount
        B = B + (lum - B) * desat_amount

        # ── Atmospheric lightening — lifts dark values at distance ────────────
        lighten_amount = depth_w * lightening
        R = R + (1.0 - R) * lighten_amount * (1.0 - R)
        G = G + (1.0 - G) * lighten_amount * (1.0 - G)
        B = B + (1.0 - B) * lighten_amount * (1.0 - B)

        # ── Haze colour overlay ───────────────────────────────────────────────
        hr, hg, hb = haze_color
        alpha = depth_w * haze_opacity
        if blend_mode == "screen":
            R = 1.0 - (1.0 - R) * (1.0 - hr * alpha)
            G = 1.0 - (1.0 - G) * (1.0 - hg * alpha)
            B = 1.0 - (1.0 - B) * (1.0 - hb * alpha)
        else:
            R = R + (hr - R) * alpha
            G = G + (hg - G) * alpha
            B = B + (hb - B) * alpha

        # ── Write back to ARGB32 surface (BGRA layout) ───────────────────────
        buf[:, :, 2] = _np.clip(R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    Bruegel panorama pass complete (haze={haze_color})")

    # ─────────────────────────────────────────────────────────────────────────
    # zorn_tricolor_pass — Anders Zorn's warm limited-palette skin technique
    # ─────────────────────────────────────────────────────────────────────────

    def zorn_tricolor_pass(
            self,
            ochre_warmth:       float = 0.08,
            vermillion_accent:  float = 0.12,
            shadow_warmth:      float = 0.06,
            midtone_low:        float = 0.28,
            midtone_high:       float = 0.75,
            blend_opacity:      float = 0.40,
    ):
        """
        Simulates Anders Zorn's characteristic warm limited-palette skin technique.

        Zorn famously restricted himself to four pigments: yellow ochre, ivory black,
        vermillion, and lead white.  Because there is no blue, green, or purple in this
        set, all flesh rendering must be achieved through warm mixtures — the entire tonal
        range of skin is negotiated between ochre-light, ochre-dark, and vermillion accent.
        The result is a distinctive warmth that permeates every value: highlights are
        cream-ochre rather than cool silver; midtones are pure warm yellow-brown; shadows
        glow with warm ivory-black rather than receding into cool grey.

        This pass imposes that quality on the current canvas by shifting three tonal zones:

        1. **Shadow zone** (luminance < ``midtone_low``): a gentle warm brown cast is
           applied — replicating the warmth of ivory black as opposed to the cool blue-grey
           of lamp black or carbon black.  Dark areas gain a subtle amber-brown undertone
           without lightening.

        2. **Midtone zone** (``midtone_low`` ≤ lum ≤ ``midtone_high``): the largest tonal
           zone is shifted toward Zorn's yellow ochre (0.82, 0.62, 0.18).  The strength is
           proportional to how close each pixel is to the mid-point of the range, so the
           effect peaks at the exact midtone and fades smoothly toward both the light and
           shadow boundaries.  This gives skin its characteristic warm amber quality at
           the form-turning transitions.

        3. **Warm-accent zone** (pixels where red channel dominates and saturation is
           high): the vermillion accent boost increases the saturation of already-warm
           reddish pixels — targeting the lips, cheekbone flush, ear helices, and nostril
           wings where Zorn typically placed his brightest red.  This is achieved by a
           small positive red-channel bias that does NOT lighten the pixel overall.

        All three effects are modulated by ``blend_opacity`` so the pass can be called
        multiple times at low opacity to build the effect gradually, mirroring Zorn's
        actual layering practice.

        The pass is tonal-structure-neutral: luminance is preserved throughout, so
        the tonal hierarchy established by ``build_form()`` is not disrupted — only the
        chromatic quality of each tonal zone is shifted.

        Call AFTER ``build_form()`` and BEFORE ``place_lights()``.  Follow with the
        warm amber ``glaze()`` at opacity 0.05–0.08 to unify the palette.

        Parameters
        ----------
        ochre_warmth       : Blend weight for the midtone ochre shift.
                             0.06–0.10 gives a subtle Zorn quality; 0.15+ is more pronounced.
        vermillion_accent  : Saturation boost for warm-red skin accents.
                             0.08–0.14 targets lips and cheeks without bleeding into neutrals.
        shadow_warmth      : Warm brown cast applied to dark areas.
                             0.04–0.08 replicates ivory black's warmth without lightening.
        midtone_low        : Lower luminance boundary of the midtone zone.
                             0.25–0.35 typical for flesh midtones.
        midtone_high       : Upper luminance boundary of the midtone zone.
                             0.70–0.80 typical (excludes near-white specular highlights).
        blend_opacity      : Global opacity of the pass.  0.35–0.50 for a single confident
                             pass; 0.20–0.30 when stacking multiple calls.

        Notes
        -----
        Inspired by: "Omnibus" (1895), "Hugo Lindqvist" (1895), "Dagmar" (1911).
        This session's random artistic improvement — the Zorn palette limitation as a
        computational painting pass.
        """
        import numpy as _np

        print(f"  Zorn tricolor pass  "
              f"(ochre={ochre_warmth:.2f}  vermillion={vermillion_accent:.2f}  "
              f"shadow={shadow_warmth:.2f}  opacity={blend_opacity:.2f})")

        # ── Read current canvas ARGB32 (BGRA byte order in pycairo) ──────────
        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Perceptual luminance ──────────────────────────────────────────────
        lum = 0.299 * R + 0.587 * G + 0.114 * B

        # ── Zone 1: Shadow warm cast — ivory-black warmth ────────────────────
        # Pixels below midtone_low receive a warm brown cast toward
        # (0.38, 0.28, 0.14) — the colour of ochre+ivory-black shadow.
        # The effect is strongest at lum=0 and fades linearly to zero at midtone_low.
        ivory_warm_r, ivory_warm_g, ivory_warm_b = 0.38, 0.28, 0.14
        shadow_t = _np.clip(1.0 - lum / (midtone_low + 1e-6), 0.0, 1.0)
        shadow_alpha = shadow_t * shadow_warmth * blend_opacity

        new_R = R + (ivory_warm_r - R) * shadow_alpha
        new_G = G + (ivory_warm_g - G) * shadow_alpha
        new_B = B + (ivory_warm_b - B) * shadow_alpha

        # ── Zone 2: Midtone ochre shift ───────────────────────────────────────
        # Pixels in [midtone_low, midtone_high] shift toward Zorn's yellow ochre
        # (0.82, 0.62, 0.18).  The effect is bell-shaped: maximum at the midpoint,
        # zero at both boundaries.
        ochre_r, ochre_g, ochre_b = 0.82, 0.62, 0.18
        mid_center = (midtone_low + midtone_high) * 0.5
        mid_half   = (midtone_high - midtone_low) * 0.5 + 1e-6
        # Raised cosine bell: 1 at the midpoint, 0 at the boundaries
        in_range   = ((lum >= midtone_low) & (lum <= midtone_high)).astype(_np.float32)
        bell       = (1.0 - _np.cos(_np.pi * (lum - midtone_low) / (midtone_high - midtone_low + 1e-6))) * 0.5
        mid_alpha  = bell * in_range * ochre_warmth * blend_opacity

        new_R = new_R + (ochre_r - new_R) * mid_alpha
        new_G = new_G + (ochre_g - new_G) * mid_alpha
        new_B = new_B + (ochre_b - new_B) * mid_alpha

        # ── Zone 3: Vermillion accent — warm-red saturation boost ────────────
        # Pixels where red dominates significantly over blue AND green
        # (i.e. already reddish skin accents) receive a small red channel boost.
        # This does not lighten the pixel — only the hue shifts warmer.
        warm_red_mask = (
            (R > G + 0.08) &
            (R > B + 0.14) &
            (lum >= midtone_low * 0.8) &
            (lum <= midtone_high)
        ).astype(_np.float32)
        # Boost red, desaturate blue slightly to keep luminance stable
        red_boost   = warm_red_mask * vermillion_accent * blend_opacity
        new_R = _np.clip(new_R + red_boost * 0.5, 0.0, 1.0)
        new_B = _np.clip(new_B - red_boost * 0.2, 0.0, 1.0)

        # ── Luminance preservation: tonal structure must not be altered ───────
        new_lum = 0.299 * new_R + 0.587 * new_G + 0.114 * new_B
        safe    = _np.where(new_lum > 1e-6, lum / new_lum, 1.0)
        new_R   = _np.clip(new_R * safe, 0.0, 1.0)
        new_G   = _np.clip(new_G * safe, 0.0, 1.0)
        new_B   = _np.clip(new_B * safe, 0.0, 1.0)

        # ── Write back to ARGB32 surface (BGRA layout) ───────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    Zorn tricolor pass complete")

    # ─────────────────────────────────────────────────────────────────────────
    # piero_crystalline_pass — Piero della Francesca's cool mineral light
    # ─────────────────────────────────────────────────────────────────────────

    def piero_crystalline_pass(
            self,
            shadow_stone:        Color = (0.44, 0.46, 0.50),  # cool stone-grey shadow target
            highlight_silver:    Color = (0.93, 0.94, 0.96),  # cool silver-white highlight target
            shadow_threshold:    float = 0.42,                 # lum below = shadow zone
            highlight_threshold: float = 0.70,                 # lum above = highlight zone
            shadow_strength:     float = 0.22,                 # shadow shift blend weight
            highlight_strength:  float = 0.16,                 # highlight shift blend weight
            chroma_dampen:       float = 0.08,                 # midtone desaturation strength
            blend_opacity:       float = 0.45,
    ):
        """
        Simulates Piero della Francesca's characteristic cool, crystalline light.

        Piero's surfaces have a quality unlike any other painter of his era: the light
        that falls on his figures is diffuse, sourceless, and mineral — as if his
        subjects were carved from pale stone and placed under an even, cloudless sky.
        Where Leonardo dissolved edges in amber sfumato and Titian warmed flesh with
        golden glazes, Piero's illumination is cool and resolved.  Shadows drift toward
        pale stone-grey rather than warm umber; highlights are silver-white rather than
        cream; and the midtones carry a gentle desaturation that gives every surface a
        geometric, fresco-like austerity.

        This pass imposes that quality through three simultaneous corrections:

        1. **Shadow cooldown** (luminance < ``shadow_threshold``):
           Dark areas are shifted toward ``shadow_stone`` — a cool stone-grey that
           replicates the pale, unsentimental shadow quality visible in the Flagellation
           and the Resurrection.  Unlike Rembrandt or Caravaggio, Piero never lets a
           shadow become warm umber or dramatic near-black; his shadows are resolutely
           cool and contained.  The blend weight is highest at the darkest pixels and
           fades smoothly to zero at the threshold boundary.

        2. **Highlight silver tint** (luminance > ``highlight_threshold``):
           Bright areas receive a cool silver-white bias.  This is the opposite of
           Leonardo's amber highlight tint and Zorn's ivory-warm brightest mark: Piero's
           highest lights read as luminous pale stone — cool, not golden.

        3. **Midtone chroma dampen** (``shadow_threshold`` < lum < ``highlight_threshold``):
           Midtone pixels are gently blended toward their own luminance grey, reducing
           saturation in the mid-range.  This replicates the restrained, mineral palette
           of Piero's fresco work — colours in the midtone zone are present but muted,
           never the full saturation of a Venetian master.  The effect is proportional
           to distance from the shadow and highlight zones: pixels squarely in the
           midrange receive the strongest desaturation; pixels near the zone boundaries
           receive progressively less.

        Together these three corrections shift any base painting toward Piero's cool,
        geometric, crystalline aesthetic without altering the fundamental tonal structure
        established by ``build_form()``.

        Call AFTER ``build_form()`` and BEFORE ``place_lights()``.  Do NOT follow
        with ``sfumato_veil_pass()`` — Piero's edges are clear and resolved, not
        dissolved into atmospheric smoke.

        Parameters
        ----------
        shadow_stone        : RGB target for the shadow zone.
                              Default (0.44, 0.46, 0.50) is a cool neutral stone-grey.
                              Shift toward (0.38, 0.40, 0.46) for deeper, cooler shadows.
        highlight_silver    : RGB target for the highlight zone.
                              Default (0.93, 0.94, 0.96) is a pale cool silver-white.
                              Shift toward (0.88, 0.90, 0.94) for a slightly warmer silver.
        shadow_threshold    : Luminance boundary below which shadow cooldown engages.
                              0.38–0.45 covers deep shadows without touching midtones.
        highlight_threshold : Luminance boundary above which silver tint engages.
                              0.66–0.74 covers highlights without touching midtones.
        shadow_strength     : Blend weight for the shadow-to-stone-grey shift.
                              0.18–0.28 gives visible cool shadow without deadening form.
        highlight_strength  : Blend weight for the highlight-to-silver shift.
                              0.12–0.22 gives cool highlights without washing the form.
        chroma_dampen       : Strength of midtone desaturation.
                              0.06–0.12 gives Piero's characteristic muted midtone palette.
                              0.0 disables midtone desaturation entirely.
        blend_opacity       : Global opacity of the entire pass.  0.40–0.55 for a single
                              confident pass; 0.25–0.35 when stacking multiple calls.

        Notes
        -----
        Inspired by: "The Flagellation of Christ" (c. 1455),
        "The Resurrection" (c. 1463), "The Baptism of Christ" (c. 1448),
        "Portrait of Federico da Montefeltro" (c. 1472).
        This session's new artist addition — Piero della Francesca's cool mineral
        quality as a computational painting pass.
        """
        import numpy as _np

        print(f"  Piero crystalline pass  "
              f"(shadow={shadow_strength:.2f}  highlight={highlight_strength:.2f}  "
              f"chroma_dampen={chroma_dampen:.3f}  opacity={blend_opacity:.2f})")

        # ── Read current canvas ARGB32 (BGRA byte order in pycairo) ──────────
        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Perceptual luminance ──────────────────────────────────────────────
        lum = 0.299 * R + 0.587 * G + 0.114 * B

        # ── Zone 1: Shadow cooldown toward stone-grey ─────────────────────────
        # Dark pixels (lum < shadow_threshold) blend toward shadow_stone.
        # Smoothstep weighting: highest blend at lum=0, fades to zero at threshold.
        ss_r, ss_g, ss_b = shadow_stone
        shadow_t = _np.clip(1.0 - lum / (shadow_threshold + 1e-6), 0.0, 1.0)
        shadow_t = shadow_t * shadow_t * (3.0 - 2.0 * shadow_t)  # smoothstep
        shadow_alpha = shadow_t * shadow_strength * blend_opacity

        new_R = R + (ss_r - R) * shadow_alpha
        new_G = G + (ss_g - G) * shadow_alpha
        new_B = B + (ss_b - B) * shadow_alpha

        # ── Zone 2: Highlight silver tint ─────────────────────────────────────
        # Bright pixels (lum > highlight_threshold) blend toward highlight_silver.
        # Quadratic ease: effect strongest at peak luminance, fades toward threshold.
        hs_r, hs_g, hs_b = highlight_silver
        hi_t = _np.clip(
            (lum - highlight_threshold) / (1.0 - highlight_threshold + 1e-6),
            0.0, 1.0,
        )
        hi_t = hi_t * hi_t  # quadratic: strongest at peak brightness
        hi_alpha = hi_t * highlight_strength * blend_opacity

        new_R = _np.clip(new_R + (hs_r - new_R) * hi_alpha, 0.0, 1.0)
        new_G = _np.clip(new_G + (hs_g - new_G) * hi_alpha, 0.0, 1.0)
        new_B = _np.clip(new_B + (hs_b - new_B) * hi_alpha, 0.0, 1.0)

        # ── Zone 3: Midtone chroma dampen ─────────────────────────────────────
        # Pixels in the midtone range (shadow_threshold < lum < highlight_threshold)
        # are gently blended toward their own luminance grey.  This replicates
        # Piero's restrained midtone palette — colours are present but never saturated.
        if chroma_dampen > 0.0:
            # Midtone weight: highest at centre of midrange, zero at both zone edges.
            mid_low    = shadow_threshold
            mid_high   = highlight_threshold
            mid_centre = 0.5 * (mid_low + mid_high)
            mid_half   = 0.5 * (mid_high - mid_low) + 1e-6
            mid_t = _np.clip(1.0 - _np.abs(lum - mid_centre) / mid_half, 0.0, 1.0)
            mid_t = mid_t * mid_t  # quadratic — softer ramp into the midzone

            chroma_alpha = mid_t * chroma_dampen * blend_opacity
            new_lum = 0.299 * new_R + 0.587 * new_G + 0.114 * new_B
            new_R = _np.clip(new_R + (new_lum - new_R) * chroma_alpha, 0.0, 1.0)
            new_G = _np.clip(new_G + (new_lum - new_G) * chroma_alpha, 0.0, 1.0)
            new_B = _np.clip(new_B + (new_lum - new_B) * chroma_alpha, 0.0, 1.0)

        # ── Write back to ARGB32 surface (BGRA layout) ───────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    Piero crystalline pass complete")

    # ─────────────────────────────────────────────────────────────────────────
    # morisot_plein_air_pass — Berthe Morisot's high-key impressionist light
    # ─────────────────────────────────────────────────────────────────────────

    def morisot_plein_air_pass(
            self,
            shadow_violet:      Color = (0.72, 0.68, 0.90),  # blue-violet shadow target
            luminosity_lift:    float = 0.10,                 # shadow brightness boost
            shadow_threshold:   float = 0.42,                 # lum below = shadow zone
            highlight_cream:    Color = (0.96, 0.93, 0.86),  # warm cream for highlights
            highlight_threshold: float = 0.76,                # lum above = highlight zone
            chroma_strength:    float = 0.18,                 # shadow hue-shift strength
            blend_opacity:      float = 0.45,
    ):
        """
        Simulates Berthe Morisot's characteristic high-key impressionist technique.

        Morisot's paintings share two defining qualities that distinguish her from her
        contemporaries: **colored shadows** and **elevated luminosity range**.  Where
        Rembrandt's shadows are warm umber, Zorn's are warm ivory-black, and Caravaggio's
        are pure void, Morisot's shadows are blue-violet or lavender — chromatic passages
        that contain as much color as the lights, only cooler.  This keeps her tonal range
        compressed into the upper half of the luminance scale, giving every canvas an
        airy, light-filled quality regardless of subject matter.

        This pass imposes that quality through two simultaneous corrections:

        1. **Shadow chroma correction** (luminance < ``shadow_threshold``):
           Dark areas are shifted toward ``shadow_violet`` — a blue-violet color
           that replicates the cool reflected sky light Morisot perceived in outdoor
           and north-lit interior settings.  The shift is proportional to how dark the
           pixel is, so the deepest shadows receive the strongest hue rotation while
           midtones blend smoothly out.  Luminance is also gently lifted by
           ``luminosity_lift`` to keep her characteristic high-key quality.

        2. **Highlight cream tint** (luminance > ``highlight_threshold``):
           The brightest areas receive a subtle warm cream bias — Morisot's highlights
           are never a brilliant blue-white but rather a luminous warm ivory, consistent
           with diffuse northern daylight reflecting off pale skin and white fabric.

        Both corrections are gated by ``blend_opacity`` so the pass can be called
        at lower strength multiple times, mirroring her layered wet-into-wet method.

        The pass is luminance-structure-neutral: unlike a simple colorize operation,
        the shadow shift targets only the chromatic component — the tonal hierarchy
        established by ``build_form()`` is preserved; only the color of each tonal
        zone is moved toward Morisot's characteristic palette.

        Call AFTER ``build_form()`` and BEFORE ``place_lights()``.  No final glaze
        is needed — Morisot's surface should remain fresh, not unified by a warm film.

        Parameters
        ----------
        shadow_violet      : RGB target color for the shadow zone.
                             Default (0.72, 0.68, 0.90) is a muted blue-violet.
                             Shift toward (0.60, 0.60, 0.92) for cooler, bluer shadows.
        luminosity_lift    : How much to lift shadow luminance toward the midtones.
                             0.06–0.12 gives Morisot's characteristic high-key quality.
                             0.0 shifts hue only without brightening.
        shadow_threshold   : Luminance boundary separating shadow from midtone zones.
                             0.38–0.45 typical for impressionist shadow treatment.
        highlight_cream    : RGB target color for the highlight zone.
                             Default (0.96, 0.93, 0.86) is warm ivory — not blue-white.
        highlight_threshold: Luminance above which the cream tint is applied.
                             0.72–0.80 avoids touching midtones.
        chroma_strength    : Blend weight for the shadow-to-violet hue shift.
                             0.12–0.22 gives visible but tasteful color in shadows.
        blend_opacity      : Global opacity of the entire pass.  0.40–0.55 for a single
                             confident pass; 0.20–0.30 when stacking multiple calls.

        Notes
        -----
        Inspired by: "The Cradle" (1872), "Summer's Day" (1879),
        "Woman at Her Toilette" (1879), "The Harbor at Lorient" (1869).
        This session's random artistic improvement — Morisot's colorful-shadow
        approach as a computational painting pass.
        """
        import numpy as _np

        print(f"  Morisot plein-air pass  "
              f"(chroma={chroma_strength:.2f}  lift={luminosity_lift:.2f}  "
              f"opacity={blend_opacity:.2f})")

        # ── Read current canvas ARGB32 (BGRA byte order in pycairo) ──────────
        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Perceptual luminance ──────────────────────────────────────────────
        lum = 0.299 * R + 0.587 * G + 0.114 * B

        # ── Zone 1: Shadow chroma shift toward blue-violet ───────────────────
        # Dark pixels (lum < shadow_threshold) are blended toward shadow_violet.
        # The blend weight is highest at lum=0 and fades to 0 at shadow_threshold.
        sv_r, sv_g, sv_b = shadow_violet
        shadow_t = _np.clip(1.0 - lum / (shadow_threshold + 1e-6), 0.0, 1.0)
        # Smoothstep: slow start, fast middle, slow end — avoids hard boundary
        shadow_t = shadow_t * shadow_t * (3.0 - 2.0 * shadow_t)
        shadow_alpha = shadow_t * chroma_strength * blend_opacity

        new_R = R + (sv_r - R) * shadow_alpha
        new_G = G + (sv_g - G) * shadow_alpha
        new_B = B + (sv_b - B) * shadow_alpha

        # ── Luminosity lift in shadow zone ────────────────────────────────────
        # Gently raise shadow luminance toward midtone — Morisot's shadows are
        # never the near-black void of Caravaggio or Rembrandt.
        if luminosity_lift > 0.0:
            lift_alpha = shadow_t * luminosity_lift * blend_opacity
            new_R = _np.clip(new_R + lift_alpha, 0.0, 1.0)
            new_G = _np.clip(new_G + lift_alpha, 0.0, 1.0)
            new_B = _np.clip(new_B + lift_alpha, 0.0, 1.0)

        # ── Zone 2: Highlight cream tint ──────────────────────────────────────
        # Bright areas (lum > highlight_threshold) receive a subtle warm cream bias.
        # Morisot's highlights read as warm ivory, not brilliant cool white.
        hc_r, hc_g, hc_b = highlight_cream
        hi_t = _np.clip(
            (lum - highlight_threshold) / (1.0 - highlight_threshold + 1e-6),
            0.0, 1.0,
        )
        hi_t = hi_t * hi_t  # quadratic ease — effect strongest at peak luminance
        hi_alpha = hi_t * 0.30 * blend_opacity  # cream tint is subtle; never overwhelm

        new_R = _np.clip(new_R + (hc_r - new_R) * hi_alpha, 0.0, 1.0)
        new_G = _np.clip(new_G + (hc_g - new_G) * hi_alpha, 0.0, 1.0)
        new_B = _np.clip(new_B + (hc_b - new_B) * hi_alpha, 0.0, 1.0)

        # ── Write back to ARGB32 surface (BGRA layout) ───────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    Morisot plein-air pass complete")

    # ──────────────────────────────────────────────────────────────────────────
    # Degas pastel pass
    # ──────────────────────────────────────────────────────────────────────────

    def degas_pastel_pass(
            self,
            shadow_grey:        Color = (0.30, 0.30, 0.42),  # deep blue-grey shadow target
            light_amber:        Color = (0.88, 0.72, 0.54),  # warm amber-orange highlight target
            shadow_threshold:   float = 0.40,                 # lum below = shadow zone
            light_threshold:    float = 0.68,                 # lum above = light zone
            shadow_strength:    float = 0.22,                 # shadow cooldown blend weight
            light_strength:     float = 0.18,                 # highlight warmup blend weight
            pastel_grain:       float = 0.04,                 # fine-grain pastel surface noise
            blend_opacity:      float = 0.50,
    ):
        """
        Simulates Edgar Degas' characteristic pastel-over-monotype technique.

        Degas built his pastels on a dark monotype ground — an oil-ink print pulled from
        a plate, leaving a tonal image with strong dark passages.  Onto that base he
        applied successive layers of pastel in directional hatching, each layer at a
        different angle, creating a surface where colours optically mix rather than
        physically blend.  The result is simultaneously structural (the monotype
        drawing holds the form) and colouristic (the pastel strokes create vibrating
        simultaneous contrast).

        This pass models that duality through three simultaneous operations:

        1. **Shadow cooldown** (luminance < ``shadow_threshold``):
           Dark areas are shifted toward ``shadow_grey`` — a deep blue-grey that
           replicates the cooled, inky darkness of the monotype ground showing through
           sparse pastel coverage.  The blend is luminance-weighted: the darkest pixels
           receive the strongest shift; the transition out of shadow is smooth.

        2. **Highlight warmup** (luminance > ``light_threshold``):
           Bright areas receive a warm amber-orange bias.  Degas' lit flesh in his ballet
           pictures is never a clean white but a warm, slightly dusty amber — the warmth
           of stage gaslight filtered through pale skin and gauze.

        3. **Pastel grain** (applied globally at low weight):
           A fine per-pixel luminance noise is added to simulate the physical texture of
           pastel pigment sitting in the tooth of the paper without fully filling it.
           Unlike photographic film grain (which is additive), pastel grain is
           bidirectional — some pixels lighten slightly, others darken — giving the
           surface a characteristic soft granularity rather than a smooth photographic
           finish.

        Together these three corrections shift any base painting toward Degas' cool-dark,
        warm-light, grain-surfaced aesthetic without altering the fundamental tonal
        structure established by ``build_form()``.

        Call AFTER ``build_form()`` and BEFORE ``place_lights()``.  The pass pairs well
        with ``dry_granulation_pass()`` for additional surface texture depth.

        Parameters
        ----------
        shadow_grey       : RGB target for the shadow zone.
                            Default (0.30, 0.30, 0.42) is a deep indigo-blue-grey.
                            Shift toward (0.22, 0.22, 0.30) for deeper, denser shadows.
        light_amber       : RGB target for the highlight zone.
                            Default (0.88, 0.72, 0.54) is a warm amber-orange.
                            Shift toward (0.96, 0.80, 0.60) for warmer stage-light effect.
        shadow_threshold  : Luminance boundary below which shadow cooldown engages.
                            0.36–0.44 covers deep shadow without touching midtones.
        light_threshold   : Luminance boundary above which highlight warmup engages.
                            0.64–0.72 covers highlights without touching midtones.
        shadow_strength   : Blend weight for the shadow-to-grey shift.
                            0.18–0.28 gives visible cool shadow without deadening the form.
        light_strength    : Blend weight for the highlight-to-amber shift.
                            0.14–0.24 gives warm highlights without over-saturating.
        pastel_grain      : Amplitude of the bidirectional per-pixel luminance noise.
                            0.03–0.06 gives Degas' characteristic soft-tooth surface.
                            0.0 disables grain entirely.
        blend_opacity     : Global opacity of the entire pass.  0.45–0.60 for a single
                            confident pass; 0.25–0.35 when stacking multiple calls.

        Notes
        -----
        Inspired by: "The Dance Class" (1874), "L'Absinthe" (1876),
        "Woman Bathing in a Shallow Tub" (1886), "Dancers in Blue" (1890).
        This session's new artist addition — Degas' pastel-over-monotype approach
        as a computational painting pass.
        """
        import numpy as _np

        print(f"  Degas pastel pass  "
              f"(shadow={shadow_strength:.2f}  light={light_strength:.2f}  "
              f"grain={pastel_grain:.3f}  opacity={blend_opacity:.2f})")

        # ── Read current canvas ARGB32 (BGRA byte order in pycairo) ──────────
        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Perceptual luminance ──────────────────────────────────────────────
        lum = 0.299 * R + 0.587 * G + 0.114 * B

        # ── Zone 1: Shadow cooldown toward blue-grey ─────────────────────────
        # Pixels darker than shadow_threshold shift toward shadow_grey.
        # Blend weight is highest at the darkest pixels and fades smoothly to zero
        # at the threshold boundary — no hard seam between shadow and midtone.
        sg_r, sg_g, sg_b = shadow_grey
        shadow_t = _np.clip(1.0 - lum / (shadow_threshold + 1e-6), 0.0, 1.0)
        # Smoothstep: prevents hard tonal boundary at the shadow/midtone transition
        shadow_t = shadow_t * shadow_t * (3.0 - 2.0 * shadow_t)
        shadow_alpha = shadow_t * shadow_strength * blend_opacity

        new_R = R + (sg_r - R) * shadow_alpha
        new_G = G + (sg_g - G) * shadow_alpha
        new_B = B + (sg_b - B) * shadow_alpha

        # ── Zone 2: Highlight warmup toward amber-orange ─────────────────────
        # Bright pixels (lum > light_threshold) blend toward light_amber.
        # Quadratic ease — strongest effect at peak luminance, fades toward threshold.
        la_r, la_g, la_b = light_amber
        light_t = _np.clip(
            (lum - light_threshold) / (1.0 - light_threshold + 1e-6),
            0.0, 1.0,
        )
        light_t = light_t * light_t  # quadratic: effect strongest at peak brightness
        light_alpha = light_t * light_strength * blend_opacity

        new_R = _np.clip(new_R + (la_r - new_R) * light_alpha, 0.0, 1.0)
        new_G = _np.clip(new_G + (la_g - new_G) * light_alpha, 0.0, 1.0)
        new_B = _np.clip(new_B + (la_b - new_B) * light_alpha, 0.0, 1.0)

        # ── Zone 3: Pastel grain — bidirectional luminance noise ──────────────
        # Simulates the physical texture of dry pastel pigment resting in the paper
        # tooth.  Unlike additive film grain, pastel grain is bidirectional: some
        # micro-areas receive more pigment (darker), some less (lighter).  The result
        # is a soft granularity rather than a smooth photographic surface.
        if pastel_grain > 0.0:
            rng = _np.random.default_rng(seed=42)  # deterministic for reproducibility
            grain = rng.uniform(-pastel_grain, pastel_grain,
                                size=(self.h, self.w)).astype(_np.float32)
            grain_alpha = blend_opacity * 0.60  # grain is applied at reduced opacity
            new_R = _np.clip(new_R + grain * grain_alpha, 0.0, 1.0)
            new_G = _np.clip(new_G + grain * grain_alpha, 0.0, 1.0)
            new_B = _np.clip(new_B + grain * grain_alpha, 0.0, 1.0)

        # ── Write back to ARGB32 surface (BGRA layout) ───────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    Degas pastel pass complete")

    # ─────────────────────────────────────────────────────────────────────────
    # waterhouse_jewel_pass — Pre-Raphaelite wet-white-ground jewel saturation
    #
    # This is this session's random artistic improvement: simulating the unique
    # luminosity that results from the Pre-Raphaelite wet white ground method.
    # Unlike any prior pass, it operates by lifting midtone SATURATION selectively
    # (not luminance, not hue) in the zone where jewel colours live.  The white
    # ground reflects back through the paint, making colours appear more saturated
    # than they would on a dark or mid-tone priming.
    # ─────────────────────────────────────────────────────────────────────────

    def waterhouse_jewel_pass(
            self,
            jewel_boost:        float = 0.14,
            jewel_low:          float = 0.20,
            jewel_high:         float = 0.62,
            shadow_cool:        float = 0.10,
            shadow_threshold:   float = 0.32,
            shadow_width:       float = 0.12,
            highlight_warmth:   float = 0.06,
            highlight_threshold: float = 0.78,
            blend_opacity:      float = 0.45,
    ):
        """
        Simulates John William Waterhouse's Pre-Raphaelite wet white ground technique.

        The Pre-Raphaelite Brotherhood (and Waterhouse as their foremost late
        successor) applied paint onto a STILL-WET white lead priming.  This "wet
        white ground" method has a profound effect on colour:

        1. **Midtone jewel saturation** — Paint applied thinly or transparently over
           a wet white ground reads at higher saturation than the same paint on a
           toned or dark ground, because the white substrate reflects light back
           through the paint film rather than absorbing it.  This is the source of
           the characteristic jewel quality of Pre-Raphaelite colours — the sapphire
           blues, deep crimsons, and rich viridians of Waterhouse, Millais, and
           Holman Hunt glow from within.  The effect is strongest in the midtone
           range (lum 0.20–0.62) where pigments are applied in one or two thin layers
           rather than the thick impasto of the highlights.

        2. **Cool shadow passages** — Where the paint is thinnest (deep shadows, the
           penumbra between lit and unlit), the cool white ground shows through as a
           pale lavender-grey tint.  Waterhouse's shadow flesh has this quality:
           the halftone cools toward blue-grey before darkening, rather than shifting
           toward warm umber as it would on a mid-tone ground.

        3. **Warm ivory highlights** — The lit passages receive confident loaded-brush
           strokes that fully cover the ground; these are warm ivory (the natural
           mixing of white and ochre flesh pigment) rather than cool.  A gentle
           warmth pass in the highlight zone reinforces this.

        The pass imposes all three effects on the current canvas without disrupting
        the tonal structure established by ``build_form()``.

        This method is this session's **random artistic improvement**: no prior pass
        in the pipeline targeted midtone saturation independently of luminance or hue.
        All earlier chromatic adjustments (``zorn_tricolor_pass``, ``morisot_plein_air_pass``,
        ``degas_pastel_pass``) shifted *hue* or *luminance*; this is the first to lift
        *chroma* directly in HSV space within a luminance window — a technique applicable
        to any artist pipeline that benefits from increased colour richness.

        Parameters
        ----------
        jewel_boost        : Saturation increase in the jewel zone (0–0.30).
                             0.10–0.18 replicates Pre-Raphaelite richness without
                             artificiality; above 0.25 reads as oversaturated.
        jewel_low          : Lower luminance boundary of the jewel (midtone) zone.
                             0.18–0.25 is appropriate — below this, paint is too thick
                             to show white ground influence.
        jewel_high         : Upper luminance boundary of the jewel zone.
                             0.58–0.68 — above this, the highlight strokes are opaque
                             loaded paint (full cover) and the ground plays no role.
        shadow_cool        : Strength of the blue-grey cool shift in deep shadows.
                             0.08–0.14 recreates the lavender quality of Waterhouse's
                             shadow flesh without making the darks look cold.
        shadow_threshold   : Luminance below which shadow cooling is applied.
                             0.28–0.36 targets deep shadow without touching midtones.
        shadow_width       : Width of the smooth ramp from shadow to neutral.
                             0.10–0.16 creates a gentle transition without a hard seam.
        highlight_warmth   : Warm ivory tint applied to high-luminance pixels.
                             0.04–0.08 — the white-ground loaded strokes are warm,
                             not neutral; this reinforces that quality.
        highlight_threshold: Luminance above which warmth is applied (0.75–0.82).
        blend_opacity      : Global blend weight for all three effects.
                             0.40–0.55 for a full confident pass; 0.25–0.35 when
                             used on top of a non-white ground for a gentler effect.

        Notes
        -----
        Inspired by: "The Lady of Shalott" (1888, Tate), "Hylas and the Nymphs"
        (1896, Manchester), "Ophelia" (1894).
        Primary reference: Joyce Townsend, Tate Conservation, on Pre-Raphaelite
        wet white ground priming technique (Tate Papers, 2004).
        This session's random artistic improvement — midtone chroma lifting as an
        independent pipeline pass applicable across all white-ground painting styles.
        """
        import numpy as _np
        import colorsys as _cs

        print(f"  Waterhouse jewel pass  "
              f"(jewel_boost={jewel_boost:.2f}  shadow_cool={shadow_cool:.2f}  "
              f"highlight_warmth={highlight_warmth:.2f}  opacity={blend_opacity:.2f})")

        # ── Read current canvas ARGB32 (BGRA byte order in pycairo) ──────────
        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Perceptual luminance ──────────────────────────────────────────────
        lum = 0.299 * R + 0.587 * G + 0.114 * B

        # Pre-allocate output arrays (modified in-place per zone)
        new_R = R.copy()
        new_G = G.copy()
        new_B = B.copy()

        # ── Zone 1: Jewel saturation boost in the midtone range ──────────────
        # The white ground reflects through thin-to-moderate paint application
        # (midtone luminance), boosting apparent saturation.  We operate in HSV:
        # convert each pixel, increase S by jewel_boost, clamp, convert back.
        #
        # The boost is weighted by how deep the pixel sits inside the jewel window:
        # 0 at the window edges, peak at the midpoint.  This gives a smooth
        # saturation gradient rather than a hard-edged mask.
        jewel_mid   = (jewel_low + jewel_high) * 0.5
        jewel_range = (jewel_high - jewel_low) * 0.5 + 1e-6
        jewel_t     = _np.clip(1.0 - _np.abs(lum - jewel_mid) / jewel_range, 0.0, 1.0)
        # Smoothstep for softer transitions
        jewel_t     = jewel_t * jewel_t * (3.0 - 2.0 * jewel_t)

        # For each pixel in the jewel zone, boost saturation in HSV space.
        # Vectorised HSV conversion: max/min per pixel.
        Cmax  = _np.maximum(_np.maximum(R, G), B)
        Cmin  = _np.minimum(_np.minimum(R, G), B)
        delta = Cmax - Cmin + 1e-9

        # HSV S (saturation) = delta / Cmax  (0 when Cmax=0)
        S = _np.where(Cmax > 1e-6, delta / Cmax, 0.0)

        # Boost S proportional to jewel_t and jewel_boost, clamped to [0, 1]
        S_new = _np.clip(S + jewel_t * jewel_boost * blend_opacity, 0.0, 1.0)
        S_boost_ratio = _np.where(S > 1e-6, S_new / S, 1.0)

        # Apply saturation boost: distance from grey (Cmax) is scaled.
        # grey_R = R where saturation = 0, i.e., R == G == B == Cmax (the grey axis).
        grey_R = Cmax
        grey_G = Cmax
        grey_B = Cmax
        new_R = _np.clip(grey_R + (R - grey_R) * S_boost_ratio, 0.0, 1.0)
        new_G = _np.clip(grey_G + (G - grey_G) * S_boost_ratio, 0.0, 1.0)
        new_B = _np.clip(grey_B + (B - grey_B) * S_boost_ratio, 0.0, 1.0)

        # ── Zone 2: Shadow cooling toward lavender-blue ───────────────────────
        # In the shadow zone the white ground shows through as a pale cool tint
        # (the lead white of the priming, visible through very thin paint).
        # Target: (0.72, 0.72, 0.86) — pale blue-grey lavender.
        sc_r, sc_g, sc_b = 0.72, 0.72, 0.86
        lo = shadow_threshold - shadow_width * 0.5
        hi = shadow_threshold + shadow_width * 0.5
        # Smooth ramp: 1.0 in deep shadow, 0.0 above the ramp
        shadow_t = _np.clip((hi - lum) / (hi - lo + 1e-6), 0.0, 1.0)
        shadow_t = shadow_t * shadow_t * (3.0 - 2.0 * shadow_t)  # smoothstep
        shadow_alpha = shadow_t * shadow_cool * blend_opacity

        new_R = _np.clip(new_R + (sc_r - new_R) * shadow_alpha, 0.0, 1.0)
        new_G = _np.clip(new_G + (sc_g - new_G) * shadow_alpha, 0.0, 1.0)
        new_B = _np.clip(new_B + (sc_b - new_B) * shadow_alpha, 0.0, 1.0)

        # ── Zone 3: Highlight warm ivory tint ────────────────────────────────
        # Loaded opaque highlight strokes are warm ivory on a white ground —
        # not cool (the white ground is not showing through thick paint here).
        # Target: (0.94, 0.88, 0.72) — warm ivory.
        hi_r, hi_g, hi_b = 0.94, 0.88, 0.72
        light_t = _np.clip(
            (lum - highlight_threshold) / (1.0 - highlight_threshold + 1e-6),
            0.0, 1.0,
        )
        light_t = light_t * light_t  # quadratic ease — strongest at peak brightness
        light_alpha = light_t * highlight_warmth * blend_opacity

        new_R = _np.clip(new_R + (hi_r - new_R) * light_alpha, 0.0, 1.0)
        new_G = _np.clip(new_G + (hi_g - new_G) * light_alpha, 0.0, 1.0)
        new_B = _np.clip(new_B + (hi_b - new_B) * light_alpha, 0.0, 1.0)

        # ── Write back to ARGB32 surface (BGRA layout) ───────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    Waterhouse jewel pass complete")

    # moreau_gilded_pass — Symbolist encrusted gold-point surface technique
    #
    # This is this session's random artistic improvement: stochastic gold-point
    # scattering to simulate Gustave Moreau's distinctive "encrusted" surface
    # quality.  Unlike every prior pass, which modifies pixel values globally
    # or within luminance bands, this pass uses a STOCHASTIC POINT-SCATTER
    # strategy: a population of small, bright gold fragments is placed at
    # randomly sampled positions within the target luminance range, blending
    # into the underlying colour.  This creates a mosaic-like, irregular texture
    # that reads as "encrusted" — paint laid on as jewel fragments rather than
    # brushed as continuous tone.
    # ─────────────────────────────────────────────────────────────────────────

    def moreau_gilded_pass(
            self,
            gold_density:       float = 0.018,
            gold_low:           float = 0.42,
            gold_high:          float = 0.88,
            crimson_shadow:     float = 0.12,
            shadow_threshold:   float = 0.28,
            gold_tint:          tuple = (0.92, 0.76, 0.22),
            blend_opacity:      float = 0.52,
    ):
        """
        Simulates Gustave Moreau's Symbolist encrusted-gold surface technique.

        Moreau's mythological canvases are unlike any other 19th-century oil
        paintings in their surface quality: they accumulate thousands of tiny
        touches of gold and jewel-coloured paint until the canvas surface reads
        as a Byzantine reliquary rather than a stretched linen support.  His
        method draws on medieval manuscript illumination and Byzantine mosaic
        as much as on the Western oil painting tradition.

        This pass replicates three distinct aspects of that technique:

        1. **Stochastic gold-point scattering** — The defining Moreau effect.
           A proportion (``gold_density``) of pixels within the midtone-to-
           highlight luminance window (``gold_low``–``gold_high``) are randomly
           selected and tinted toward the gold colour (``gold_tint``).  The
           random selection creates an irregular, fragmented appearance: each
           "gold fragment" is a single pixel or small cluster, simulating a
           tiny brushstroke of gold paint laid individually on the surface.
           This stochastic approach is the core innovation of this pass and
           distinguishes it from all prior passes in the pipeline, which modify
           pixels deterministically (globally, by luminance band, or via
           convolution).  Stochastic pixel sampling produces the irregular,
           hand-placed quality of Moreau's encrusted technique; it cannot be
           replicated by a smooth per-pixel function.

        2. **Crimson shadow enrichment** — Moreau's darks are never dead black.
           The dark warm umber-crimson ground glows through thin shadow passages,
           giving his interiors a ruby warmth.  Pixels below ``shadow_threshold``
           are shifted toward a deep warm crimson, preventing the void
           backgrounds from reading as neutral or cool.

        3. **Warm gold atmospheric tint** — A gentle overall warm gold tint
           is blended across the full image at low opacity, simulating the
           characteristic amber-gold tonality of his varnished surfaces.  This
           is the atmospheric unifier of his palette and gives his paintings
           the feeling of being viewed through warm amber glass.

        Parameters
        ----------
        gold_density   : Fraction of eligible pixels receiving a gold touch.
                         0.010–0.025 replicates Moreau's density — enough to
                         read as "scattered" not "uniform"; above 0.035 the
                         effect starts to look like a solid gold overlay.
        gold_low       : Lower luminance boundary for gold scattering.
                         0.38–0.46 — gold fragments live in the upper-midtone
                         range where thin glaze over dark ground would catch
                         light without being the full highlight.
        gold_high      : Upper luminance boundary (0.82–0.92) — gold fragments
                         extend into the highlights but not the absolute peak
                         brightness, which Moreau reserved for near-white ivory.
        crimson_shadow : Strength of the warm crimson push in deep shadows.
                         0.08–0.16 — enough to warm the darks without making
                         them look like red paint (the ground glows through, it
                         does not dominate).
        shadow_threshold: Luminance below which shadow enrichment is applied.
                         0.22–0.32 — deep shadows only; midtones unaffected.
        gold_tint      : RGB tuple for the gold scatter colour (values 0–1).
                         (0.92, 0.76, 0.22) is burnished gold; (0.90, 0.82, 0.38)
                         is pale gold leaf; (0.88, 0.62, 0.12) is deep amber.
        blend_opacity  : Global blend weight for all three effects combined.
                         0.45–0.60 for a full-strength Moreau surface;
                         0.25–0.35 as a supplementary pass over another style.

        Notes
        -----
        Inspired by: "Salome Dancing Before Herod" (1876, Musée Gustave Moreau),
        "Jupiter and Semele" (1895, Musée Gustave Moreau), "The Apparition"
        (1876, Musée d'Orsay).
        Primary reference: Julius Kaplan, "The Art of Gustave Moreau: Theory,
        Style, and Content" (1982); Geneviève Lacambre, Musée Moreau catalogue.
        This session's random artistic improvement — stochastic pixel-scatter
        as a new pipeline primitive, enabling encrusted and mosaic surface
        effects not achievable by deterministic per-pixel transforms.
        """
        import numpy as _np

        print(f"  Moreau gilded pass  "
              f"(gold_density={gold_density:.3f}  crimson_shadow={crimson_shadow:.2f}  "
              f"blend_opacity={blend_opacity:.2f})")

        # ── Read current canvas ARGB32 (BGRA byte order in pycairo) ──────────
        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Perceptual luminance ──────────────────────────────────────────────
        lum = 0.299 * R + 0.587 * G + 0.114 * B

        new_R = R.copy()
        new_G = G.copy()
        new_B = B.copy()

        # ── Zone 1: Stochastic gold-point scattering ─────────────────────────
        # Identify pixels in the eligible luminance window.
        eligible = (lum >= gold_low) & (lum <= gold_high)
        eligible_indices = _np.argwhere(eligible)

        if eligible_indices.shape[0] > 0:
            # Sample a random subset of eligible pixels.
            rng = _np.random.default_rng(seed=42)   # deterministic seed for reproducibility
            n_total   = eligible_indices.shape[0]
            n_scatter = max(1, int(n_total * gold_density))
            chosen = rng.choice(n_total, size=n_scatter, replace=False)
            ys = eligible_indices[chosen, 0]
            xs = eligible_indices[chosen, 1]

            # Gold tint RGB components
            gt_r, gt_g, gt_b = float(gold_tint[0]), float(gold_tint[1]), float(gold_tint[2])

            # Blend each chosen pixel toward the gold tint at full blend_opacity.
            # (Each fragment is an individual "touch" — full-strength application
            # at that point, not a smooth global transition.)
            new_R[ys, xs] = _np.clip(
                new_R[ys, xs] * (1.0 - blend_opacity) + gt_r * blend_opacity, 0.0, 1.0)
            new_G[ys, xs] = _np.clip(
                new_G[ys, xs] * (1.0 - blend_opacity) + gt_g * blend_opacity, 0.0, 1.0)
            new_B[ys, xs] = _np.clip(
                new_B[ys, xs] * (1.0 - blend_opacity) + gt_b * blend_opacity, 0.0, 1.0)

        # ── Zone 2: Crimson shadow enrichment ────────────────────────────────
        # Warm the darkest pixels toward deep crimson — the ground glows through.
        # Target: (0.48, 0.10, 0.06) — deep warm crimson-ruby.
        cr_r, cr_g, cr_b = 0.48, 0.10, 0.06
        shadow_t = _np.clip(
            1.0 - (lum / (shadow_threshold + 1e-6)),
            0.0, 1.0,
        )
        shadow_t = shadow_t * shadow_t   # quadratic: strongest at absolute zero
        shadow_alpha = shadow_t * crimson_shadow * blend_opacity

        new_R = _np.clip(new_R + (cr_r - new_R) * shadow_alpha, 0.0, 1.0)
        new_G = _np.clip(new_G + (cr_g - new_G) * shadow_alpha, 0.0, 1.0)
        new_B = _np.clip(new_B + (cr_b - new_B) * shadow_alpha, 0.0, 1.0)

        # ── Zone 3: Warm gold atmospheric overall tint ───────────────────────
        # A gentle warm-gold atmospheric veil at very low opacity — simulates
        # the amber-varnish quality of Moreau's finished surfaces.
        # Applied as a global blend toward the gold tint at reduced strength.
        atm_strength = blend_opacity * 0.12   # 12 % of blend_opacity → subtle
        new_R = _np.clip(new_R + (float(gold_tint[0]) - new_R) * atm_strength, 0.0, 1.0)
        new_G = _np.clip(new_G + (float(gold_tint[1]) - new_G) * atm_strength, 0.0, 1.0)
        new_B = _np.clip(new_B + (float(gold_tint[2]) - new_B) * atm_strength, 0.0, 1.0)

        # ── Write back to ARGB32 surface (BGRA layout) ───────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        import cairo as _cairo
        tmp = _cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), _cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    Moreau gilded pass complete  "
              f"(gold fragments placed: {n_scatter if eligible_indices.shape[0] > 0 else 0})")

    # ─────────────────────────────────────────────────────────────────────────
    # botticelli_linear_grace_pass — Florentine Renaissance tempera technique
    # ─────────────────────────────────────────────────────────────────────────

    def botticelli_linear_grace_pass(
            self,
            reference,
            hatch_density:   float = 0.022,
            hatch_length:    float = 12.0,
            hatch_opacity:   float = 0.55,
            gold_density:    float = 0.012,
            gold_tint:       tuple = (0.88, 0.72, 0.24),
            gold_opacity:    float = 0.70,
            luminosity_lift: float = 0.06,
    ):
        """
        Simulates Sandro Botticelli's Florentine tempera hatching technique.

        Botticelli's tempera-on-gesso method is the structural opposite of
        Leonardo's sfumato: form is built entirely through fine *parallel
        hatching* strokes laid from the contour inward, and through
        *chrysographic gold filaments* (fine shell-gold marks) scattered
        through hair, drapery highlights, and botanical detail.  No wet
        blending occurs — egg tempera dries in seconds.

        This pass replicates three distinct aspects of his technique:

        1. **Directional contour hatching** — Edge-gradient detection (Sobel)
           identifies the contour zones where Botticelli drew his defining
           lines.  Short parallel hatch-marks are drawn *along* the gradient
           direction at detected edges, simulating the fine parallel strokes
           he used to build tonal transitions in the absence of blending.
           Hatch marks are slightly darker than the local pixel, replicating
           the characteristic shadow-building of his tempera hatching.

        2. **Chrysographic gold filaments** — A stochastic scatter of bright
           gold-tinted marks in the upper-midtone to highlight luminance
           band replicates the shell-gold filaments he applied to hair, fabric
           folds, and botanical elements.  These are drawn as tiny horizontal
           dashes rather than single points, distinguishing them from the
           Moreau-style gold fragments (which are points).

        3. **Luminosity lift** — A global brightness boost simulates the pale
           white gesso ground showing through thin tempera washes.  Botticelli's
           panels glow with an internal light absent from dark-ground oil painting.
           The lift is applied as an additive blend toward white, strongest in the
           midtone and highlight zones where paint is thinnest.

        Parameters
        ----------
        reference      : PIL Image or ndarray — the reference to draw from.
        hatch_density  : Fraction of edge-zone pixels receiving hatch marks.
                         0.015–0.030: enough to read as fine hatching without
                         covering the underlying paint.
        hatch_length   : Length of each hatch mark in pixels (8–18).
                         Botticelli's marks were short, precise, and directional.
        hatch_opacity  : Opacity of hatch marks (0.35–0.70).
                         High enough to read as deliberate marks; low enough to
                         layer transparently like real tempera.
        gold_density   : Fraction of eligible midtone/highlight pixels receiving
                         a gold filament.  0.008–0.018 replicates the delicate
                         chrysographic density of his hair and drapery treatment.
        gold_tint      : RGB tuple for the chrysographic gold colour.
                         (0.88, 0.72, 0.24) is warm shell gold — slightly darker
                         and warmer than Moreau's burnished gold.
        gold_opacity   : Opacity of gold filaments (0.55–0.80).
        luminosity_lift: Global brightness additive for gesso-ground simulation.
                         0.04–0.08 is sufficient — the lift is subtle, not bleaching.

        Notes
        -----
        Inspired by: "Primavera" (c. 1477–82, Uffizi), "The Birth of Venus"
        (c. 1485, Uffizi), "Portrait of a Young Man" (c. 1480, National Gallery).
        Technical reference: Dunkerton, Foister, Gordon, Penny, "Giotto to
        Dürer: Early Renaissance Painting in the National Gallery" (1991);
        Skaug, "Punch Marks from Giotto to Fra Angelico" (1994).
        This session's randomly selected artistic improvement — sinuous contour
        hatching as a new pipeline primitive, enabling tempera and panel-painting
        surface effects not achievable by wet-blend or glaze-based passes.
        """
        import numpy as _np
        import cairo as _cairo
        from PIL import Image as _Img
        from scipy.ndimage import sobel as _sobel

        print(f"  Botticelli linear grace pass  "
              f"(hatch_density={hatch_density:.3f}  gold_density={gold_density:.3f}  "
              f"lift={luminosity_lift:.2f})")

        # ── Read reference and current canvas (BGRA) ─────────────────────────
        ref = self._prep(reference)
        rarr = ref[:, :, :3].astype(_np.float32) / 255.0   # (H, W, 3) RGB float

        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        # Perceptual luminance
        lum = 0.299 * R + 0.587 * G + 0.114 * B

        new_R = R.copy()
        new_G = G.copy()
        new_B = B.copy()

        # ── Zone 1: Directional contour hatching ─────────────────────────────
        # Compute gradient magnitude and direction via Sobel on reference lum.
        ref_lum = (0.299 * rarr[:, :, 0]
                   + 0.587 * rarr[:, :, 1]
                   + 0.114 * rarr[:, :, 2])
        gx = _sobel(ref_lum, axis=1)
        gy = _sobel(ref_lum, axis=0)
        grad_mag = _np.sqrt(gx**2 + gy**2)
        grad_mag /= (grad_mag.max() + 1e-8)

        # Edge zone: pixels above a gradient threshold
        edge_zone = grad_mag > 0.12
        edge_pixels = _np.argwhere(edge_zone)

        rng = _np.random.default_rng(seed=77)

        if edge_pixels.shape[0] > 0:
            n_hatch = max(1, int(edge_pixels.shape[0] * hatch_density))
            chosen_idx = rng.choice(edge_pixels.shape[0], size=n_hatch, replace=False)
            chosen = edge_pixels[chosen_idx]

            # Half-hatch-length for centering each mark
            hl = max(1, int(hatch_length / 2))

            for ys, xs in chosen:
                # Gradient direction at this point (tangent = perpendicular to gradient)
                gx_v = float(gx[ys, xs])
                gy_v = float(gy[ys, xs])
                norm = (gx_v**2 + gy_v**2) ** 0.5 + 1e-8
                # Tangent direction (parallel to contour edge)
                tx = -gy_v / norm
                ty =  gx_v / norm

                # Local darker tint — slightly below canvas colour
                local_r = float(new_R[ys, xs]) * 0.72
                local_g = float(new_G[ys, xs]) * 0.72
                local_b = float(new_B[ys, xs]) * 0.72

                # Draw hatch segment centered on pixel
                for step in range(-hl, hl + 1):
                    px = int(round(xs + tx * step))
                    py = int(round(ys + ty * step))
                    if 0 <= px < self.w and 0 <= py < self.h:
                        a = hatch_opacity
                        new_R[py, px] = new_R[py, px] * (1 - a) + local_r * a
                        new_G[py, px] = new_G[py, px] * (1 - a) + local_g * a
                        new_B[py, px] = new_B[py, px] * (1 - a) + local_b * a

        n_hatches = n_hatch if edge_pixels.shape[0] > 0 else 0

        # ── Zone 2: Chrysographic gold filaments ─────────────────────────────
        # Eligible: upper-midtone to highlight (0.45–0.88 luminance)
        gold_eligible = (lum >= 0.45) & (lum <= 0.88)
        gold_pixels = _np.argwhere(gold_eligible)

        n_gold = 0
        if gold_pixels.shape[0] > 0:
            n_gold = max(1, int(gold_pixels.shape[0] * gold_density))
            gold_chosen = rng.choice(gold_pixels.shape[0], size=n_gold, replace=False)
            chosen_gold = gold_pixels[gold_chosen]

            gr, gg, gb = float(gold_tint[0]), float(gold_tint[1]), float(gold_tint[2])
            filament_len = 5   # short horizontal dash simulating a pen filament

            for ys, xs in chosen_gold:
                for dx in range(-filament_len // 2, filament_len // 2 + 1):
                    px = xs + dx
                    if 0 <= px < self.w:
                        a = gold_opacity
                        new_R[ys, px] = _np.clip(new_R[ys, px] * (1 - a) + gr * a, 0, 1)
                        new_G[ys, px] = _np.clip(new_G[ys, px] * (1 - a) + gg * a, 0, 1)
                        new_B[ys, px] = _np.clip(new_B[ys, px] * (1 - a) + gb * a, 0, 1)

        # ── Zone 3: Luminosity lift (gesso-ground simulation) ─────────────────
        # Additive brightness boost — strongest in midtone/highlight areas where
        # the white gesso ground would show through thin tempera paint films.
        lift_weight = _np.clip(lum, 0.0, 1.0)   # scale lift by existing luminance
        new_R = _np.clip(new_R + luminosity_lift * lift_weight, 0.0, 1.0)
        new_G = _np.clip(new_G + luminosity_lift * lift_weight, 0.0, 1.0)
        new_B = _np.clip(new_B + luminosity_lift * lift_weight, 0.0, 1.0)

        # ── Write back to ARGB32 surface (BGRA) ──────────────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = _cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), _cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    Botticelli pass complete  "
              f"(hatch marks: {n_hatches}  gold filaments: {n_gold})")

    # ─────────────────────────────────────────────────────────────────────────
    # tonal_envelope_pass — Portrait luminosity gradient improvement
    # ─────────────────────────────────────────────────────────────────────────

    def tonal_envelope_pass(
            self,
            center_x:     Optional[float] = None,
            center_y:     Optional[float] = None,
            radius:       Optional[float] = None,
            lift_strength: float = 0.10,
            lift_warmth:   float = 0.28,
            edge_darken:   float = 0.08,
            gamma:         float = 1.8,
    ):
        """
        Tonal envelope — radial portrait luminosity gradient.

        In traditional portraiture, master painters consciously managed the
        *tonal envelope* of the composition: the overall luminance distribution
        that guides the viewer's eye from the peripheral darkening at the
        canvas edges inward to the brightest zone around the sitter's face.
        This is distinct from the finish-pass vignette (which darkens edges
        mechanically) in that it *brightens the portrait center with warmth*
        rather than only darkening the corners, creating a three-dimensional
        sense of light gathering at the face.

        Leonardo, Raphael, and Botticelli all used this compositional
        luminosity management, though it operates at the level of the full
        composition rather than individual stroke placement.  The effect is
        most visible in Leonardo's "Lady with an Ermine" and Raphael's
        "Baldassare Castiglione" — both have a subtle inner glow around the
        face that cannot be explained by the depicted light source alone; it
        is a painterly fiction that makes the face appear self-luminous.

        This pass is the session's random artistic improvement: a new
        pipeline primitive for compositional luminosity management that
        operates globally on the canvas after all stroke passes are complete,
        simulating the final tonal adjustments that Renaissance masters made
        to unify the composition before varnishing.

        Implementation
        --------------
        1. Compute a radial weight map centered on (center_x, center_y)
           with sigmoid falloff at `radius` pixels.
        2. In the central zone: additive warm lift toward ivory (simulating
           the face-glow effect of reflected candlelight or window light
           gathering at the portrait center).
        3. At the periphery: slight cool darkening (enhancing depth and
           framing the figure without the mechanical look of a flat vignette).

        Parameters
        ----------
        center_x    : Horizontal centre of the luminosity envelope, as a
                      fraction of canvas width [0, 1].  Defaults to 0.50.
        center_y    : Vertical centre, as a fraction of canvas height [0, 1].
                      Defaults to 0.35 (typical portrait face position).
        radius      : Radius of the bright zone as a fraction of the shorter
                      canvas dimension.  Defaults to 0.42 — roughly the
                      inscribed circle within which a half-length portrait's
                      face and hands are contained.
        lift_strength: Maximum additive luminance in the centre zone.
                       0.06–0.14 gives a subtle perceptible glow without
                       bleaching the face.
        lift_warmth  : Fraction of the lift applied as a warm amber tint
                       (boosting R > G > B) rather than neutral white.
                       0.20–0.40: enough warmth to simulate the characteristic
                       amber of Renaissance candle/window light.
        edge_darken  : Maximum luminance subtraction at the canvas corners.
                       0.04–0.12: subtle framing, not a heavy vignette.
        gamma        : Exponent on the radial weight — higher values create a
                       sharper boundary between the bright centre and dark
                       periphery.  1.5–2.5 gives a natural-looking gradient.
        """
        import numpy as _np
        import cairo as _cairo

        cx = center_x if center_x is not None else 0.50
        cy = center_y if center_y is not None else 0.35
        r  = radius   if radius   is not None else 0.42

        print(f"  Tonal envelope pass  "
              f"(centre=({cx:.2f},{cy:.2f})  r={r:.2f}  "
              f"lift={lift_strength:.2f}  edge_darken={edge_darken:.2f})")

        # ── Read canvas BGRA ──────────────────────────────────────────────────
        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Build radial weight map ───────────────────────────────────────────
        # w=1.0 at center, 0.0 at radius, negative (edge darkening) beyond.
        y_idx = _np.arange(self.h, dtype=_np.float32)[:, None] / self.h
        x_idx = _np.arange(self.w, dtype=_np.float32)[None, :] / self.w

        short_side = min(self.w, self.h)
        # Elliptical distance (portrait-aware: slightly wider than tall)
        dx = (x_idx - cx) / (r * 1.15)
        dy = (y_idx - cy) / r
        dist = _np.sqrt(dx**2 + dy**2)

        # Central bright zone: dist < 1 → positive weight toward lift_strength
        bright_weight = _np.clip(1.0 - dist, 0.0, 1.0) ** gamma

        # Edge dark zone: dist > 1 → negative weight toward edge_darken
        dark_weight = _np.clip(dist - 1.0, 0.0, 1.0) ** (gamma * 0.7)

        # ── Apply central luminosity lift ─────────────────────────────────────
        # Warm ivory target: more red boost than green/blue.
        warm_r = lift_strength * (1.0 + lift_warmth * 0.40)
        warm_g = lift_strength * (1.0 - lift_warmth * 0.08)
        warm_b = lift_strength * (1.0 - lift_warmth * 0.35)

        new_R = _np.clip(R + bright_weight * warm_r, 0.0, 1.0)
        new_G = _np.clip(G + bright_weight * warm_g, 0.0, 1.0)
        new_B = _np.clip(B + bright_weight * warm_b, 0.0, 1.0)

        # ── Apply peripheral darkening ────────────────────────────────────────
        # Slight cool shift (blue channel preserved more than red) to give
        # the corners an atmospheric depth rather than flat grey.
        new_R = _np.clip(new_R - dark_weight * edge_darken * 1.10, 0.0, 1.0)
        new_G = _np.clip(new_G - dark_weight * edge_darken * 0.95, 0.0, 1.0)
        new_B = _np.clip(new_B - dark_weight * edge_darken * 0.70, 0.0, 1.0)

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = _cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), _cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print("    Tonal envelope pass complete")

    # ─────────────────────────────────────────────────────────────────────────
    # durer_engraving_pass — Albrecht Dürer Northern Renaissance graphic precision
    # ─────────────────────────────────────────────────────────────────────────

    def durer_engraving_pass(
            self,
            reference,
            hatch_density:    float = 0.030,
            hatch_length:     float = 10.0,
            hatch_opacity:    float = 0.45,
            cross_hatch:      bool  = True,
            shadow_threshold: float = 0.45,
            cool_shift:       float = 0.06,
    ):
        """
        Simulates Albrecht Dürer's engraving-influenced oil shadow technique.

        Dürer's oil paintings carry the unmistakable imprint of his years as
        a master engraver.  In engraving, tonal gradations are achieved through
        the *density* and *crossing angle* of fine parallel lines, not through
        smooth blending.  Dürer applied this graphic principle to oil painting:
        in his shadow zones, forms are built through thin, directional strokes
        that run parallel and cross-parallel (at ±45°), creating a systematic
        hatching that reads as both painted and drawn simultaneously.

        This pass replicates three aspects of his technique:

        1. **Cross-hatching in shadow zones** — In areas darker than
           ``shadow_threshold``, fine diagonal strokes are drawn at +45°
           (primary hatching) and, if ``cross_hatch=True``, a second pass at
           −45° (cross-hatching).  Line density and opacity scale with local
           darkness: the deepest shadows receive the most marks at the highest
           opacity; the upper shadow zone receives sparse, lighter marks.
           This graduated density replicates the engraving convention of
           building tonal depth through accumulating hatch lines.

        2. **Directional shadow parallel lines** — Unlike Botticelli's
           contour-following tangent marks, Dürer's hatching is consistently
           directional (±45° to the picture plane), independent of local
           surface curvature.  This is the signature quality that separates
           engraving-influenced oil from purely painterly oil technique.

        3. **Cool shadow shift** — Dürer's shadows have a cool blue-grey
           quality absent from Italian chiaroscuro.  A subtle cool tint
           (reducing R, preserving B) is applied in the shadow zone,
           simulating the cool transparent grey washes he laid into shadows
           before the hatching strokes.

        Parameters
        ----------
        reference       : PIL Image or ndarray — the reference image.
        hatch_density   : Fraction of shadow-zone pixels receiving a hatch
                          mark.  0.020–0.040 replicates Dürer's shadow density.
        hatch_length    : Length of each hatch stroke in pixels (6–14).
                          Dürer's marks in oil were slightly longer than
                          Botticelli's tempera hatching.
        hatch_opacity   : Base opacity of hatch marks (0.30–0.55).
                          Scales with local darkness — deepest shadows use
                          full hatch_opacity; lighter shadow zones use 0.5×.
        cross_hatch     : Whether to apply a second pass of −45° hatching
                          over the primary +45° layer.  True = full
                          cross-hatching (Dürer's standard shadow convention).
                          False = single-direction hatching (his lighter
                          shadow passages use single-direction only).
        shadow_threshold: Luminance below which hatching is applied (0–1).
                          0.45 captures shadow and dark-midtone zones without
                          intruding into the lit flesh areas.
        cool_shift      : Magnitude of the cool (blue-grey) shift applied in
                          shadow zones.  0.04–0.08 is perceptible but subtle —
                          the cool is an undertone, not a dominant hue.

        Notes
        -----
        Inspired by: "Self-Portrait at 28" (1500, Alte Pinakothek),
        "Portrait of Hieronymus Holzschuher" (1526, Gemäldegalerie Berlin),
        "Self-Portrait at 26" (1498, Prado).
        Technical reference: Panofsky, "The Life and Art of Albrecht Dürer"
        (1943); Koerner, "The Moment of Self-Portraiture in German Renaissance
        Art" (1993); NGA technical study of Dürer panel paintings.
        Randomly selected artistic discovery for session 34 — the Northern
        Renaissance's graphic precision as a distinct oil-painting paradigm,
        extending the hatching vocabulary beyond Botticelli's tempera-specific
        contour marks to a systematic cross-directional engraving logic.
        """
        import numpy as _np
        import cairo as _cairo
        from PIL import Image as _Img

        print(f"  Dürer engraving pass  "
              f"(hatch_density={hatch_density:.3f}  cross_hatch={cross_hatch}  "
              f"cool_shift={cool_shift:.2f})")

        # ── Read reference and current canvas (BGRA) ─────────────────────────
        ref = self._prep(reference)
        rarr = ref[:, :, :3].astype(_np.float32) / 255.0   # (H, W, 3) RGB float

        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * R + 0.587 * G + 0.114 * B

        new_R = R.copy()
        new_G = G.copy()
        new_B = B.copy()

        # ── Zone 1: Cool shadow shift ─────────────────────────────────────────
        # Pixels below shadow_threshold get a cool (blue-grey) tint: reduce R
        # slightly, leave G neutral, preserve B.  The shift is proportional to
        # how far the pixel falls into the shadow zone.
        shadow_weight = _np.clip((shadow_threshold - lum) / shadow_threshold, 0.0, 1.0)
        new_R = _np.clip(new_R - shadow_weight * cool_shift * 1.20, 0.0, 1.0)
        new_G = _np.clip(new_G - shadow_weight * cool_shift * 0.60, 0.0, 1.0)
        new_B = _np.clip(new_B + shadow_weight * cool_shift * 0.35, 0.0, 1.0)

        # ── Zone 2: Directional cross-hatching in shadow zones ────────────────
        # Shadow pixels receive fine parallel lines at +45° and (if cross_hatch)
        # a second pass at −45°.  Opacity and density scale with local darkness.
        shadow_mask = lum < shadow_threshold
        shadow_pixels = _np.argwhere(shadow_mask)

        rng = _np.random.default_rng(seed=42)

        def _draw_hatch_pass(angle_deg: float, density: float, opacity_scale: float):
            """Draw a single directional hatch pass at angle_deg."""
            if shadow_pixels.shape[0] == 0:
                return 0
            n_marks = max(1, int(shadow_pixels.shape[0] * density))
            chosen_idx = rng.choice(shadow_pixels.shape[0], size=n_marks, replace=False)
            chosen = shadow_pixels[chosen_idx]

            import math as _math
            rad = _math.radians(angle_deg)
            dx = _math.cos(rad)
            dy = _math.sin(rad)
            hl = max(1, int(hatch_length / 2))

            for ys, xs in chosen:
                # Local darkness weight: deeper shadow → more opacity
                local_lum = float(lum[ys, xs])
                depth_weight = _np.clip(1.0 - local_lum / shadow_threshold, 0.0, 1.0)
                mark_opacity = hatch_opacity * opacity_scale * (0.50 + 0.50 * depth_weight)

                # Hatch colour: slightly darker and cooler than canvas pixel
                local_r = float(new_R[ys, xs]) * 0.68
                local_g = float(new_G[ys, xs]) * 0.72
                local_b = float(new_B[ys, xs]) * 0.78   # blue channel preserved more

                for step in range(-hl, hl + 1):
                    px = int(round(xs + dx * step))
                    py = int(round(ys + dy * step))
                    if 0 <= px < self.w and 0 <= py < self.h:
                        a = mark_opacity
                        new_R[py, px] = new_R[py, px] * (1 - a) + local_r * a
                        new_G[py, px] = new_G[py, px] * (1 - a) + local_g * a
                        new_B[py, px] = new_B[py, px] * (1 - a) + local_b * a

            return n_marks

        # Primary hatch at +45°
        n_primary = _draw_hatch_pass(45.0, hatch_density, 1.0)
        # Cross-hatch at −45° with slightly lower density and opacity
        n_cross = 0
        if cross_hatch:
            n_cross = _draw_hatch_pass(-45.0, hatch_density * 0.65, 0.75)

        # ── Write back to ARGB32 surface (BGRA) ──────────────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = _cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), _cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    Dürer engraving pass complete  "
              f"(primary marks: {n_primary}  cross marks: {n_cross})")

    # ─────────────────────────────────────────────────────────────────────────
    # selective_focus_pass — Portrait depth-of-field softening (random improvement)
    # ─────────────────────────────────────────────────────────────────────────

    def selective_focus_pass(
            self,
            center_x:        float = 0.50,
            center_y:        float = 0.30,
            focus_radius:    float = 0.32,
            max_blur_radius: float = 4.0,
            desaturation:    float = 0.12,
            gamma:           float = 2.0,
    ):
        """
        Applies a radial selective-focus softening to peripheral areas.

        Portrait painters throughout history — from Leonardo to Vermeer to
        Sargent — kept the focal area (typically the sitter's face) rendered
        with maximum sharpness and clarity while allowing the peripheral zones
        (clothing, background, hands) to soften gradually.  This was partly
        intentional (directing the viewer's eye) and partly a natural consequence
        of working at close range: the artist's own eye focused on the face and
        rendered it with proportionally more attention and refinement.

        This pass replicates that quality computationally: pixels beyond the
        ``focus_radius`` ellipse are progressively blurred and desaturated,
        with both effects scaling quadratically with distance from the focal
        centre.  The blur is applied as a Gaussian convolution with a radius
        that grows from zero at the focus boundary to ``max_blur_radius`` at
        the canvas corners.  Desaturation reduces the chromatic intensity of
        peripheral areas, simulating the slightly less saturated peripheral
        vision of the painting eye and the tonal wash quality of loosely-
        rendered background passages.

        The pass is designed to be subtle: the default parameters produce a
        barely-perceptible improvement in visual hierarchy that does not read
        as an obvious photographic blur effect, but as the natural quality
        difference between a carefully wrought face and a broadly indicated
        background — the quality that separates a portrait by Dürer or Holbein
        from a merely competent likeness.

        Parameters
        ----------
        center_x       : Horizontal focus centre as fraction of canvas width.
        center_y       : Vertical focus centre as fraction of canvas height.
                         0.30 places the focus at typical portrait face height.
        focus_radius   : Radius of the sharp zone as a fraction of the shorter
                         canvas dimension.  0.28–0.36 covers the face and the
                         immediate surrounding area.
        max_blur_radius: Maximum Gaussian blur sigma at the canvas corners, in
                         pixels.  2.0–5.0: subtle without reading as digital
                         post-processing.
        desaturation   : Maximum chroma reduction in the peripheral zone (0–1).
                         0.08–0.18: enough to read as a looser passage without
                         draining the peripheral colour to grey.
        gamma          : Exponent on the radial transition — higher values
                         create a sharper focus boundary.  1.5–2.5.

        Notes
        -----
        Randomly selected artistic improvement for session 34 — a composable
        selective-focus primitive that benefits any portrait pipeline by
        replicating the natural attention-gradient of the human eye as it
        studies a sitter across a working distance.  Distinct from
        ``sfumato_veil_pass`` (which targets painted edges specifically) and
        ``atmospheric_depth_pass`` (which models distance-based aerial haze):
        this pass is compositionally focused, not optically motivated.
        """
        import numpy as _np
        import cairo as _cairo
        from scipy.ndimage import gaussian_filter as _gauss

        print(f"  Selective focus pass  "
              f"(centre=({center_x:.2f},{center_y:.2f})  r={focus_radius:.2f}  "
              f"max_blur={max_blur_radius:.1f}  desat={desaturation:.2f})")

        # ── Early exit: nothing to do when both effects are zero ──────────────
        if max_blur_radius <= 0.0 and desaturation <= 0.0:
            print(f"    Selective focus pass complete  (no-op — zero blur and desat)")
            return

        # ── Read canvas BGRA ──────────────────────────────────────────────────
        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(self.h, self.w, 4).copy()
        B = buf[:, :, 0].astype(_np.float32) / 255.0
        G = buf[:, :, 1].astype(_np.float32) / 255.0
        R = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Build radial distance map ─────────────────────────────────────────
        # 0 at focus centre, 1 at focus boundary, > 1 outside
        y_idx = _np.arange(self.h, dtype=_np.float32)[:, None] / self.h
        x_idx = _np.arange(self.w, dtype=_np.float32)[None, :] / self.w

        short = min(self.w, self.h)
        # Elliptical — slightly wider than tall for portrait proportions
        edx = (x_idx - center_x) / (focus_radius * 1.15)
        edy = (y_idx - center_y) / focus_radius
        dist = _np.sqrt(edx**2 + edy**2)

        # Peripheral weight: 0 inside focus, scales to 1 at corners
        outer = _np.clip(dist - 1.0, 0.0, None)
        # Normalise: maximum possible outer distance from focus boundary
        max_dist = _np.max(outer) + 1e-8
        w_periph = _np.clip(outer / max_dist, 0.0, 1.0) ** gamma   # (H, W)

        # ── Blur channel: progressive Gaussian on the full image, blend ───────
        # Rather than per-pixel blur (expensive), blur the full canvas at the
        # maximum radius and composite using the radial weight mask.
        # This is an efficient approximation of radially-varying blur.
        if max_blur_radius > 0.5:
            R_blurred = _gauss(R, sigma=max_blur_radius)
            G_blurred = _gauss(G, sigma=max_blur_radius)
            B_blurred = _gauss(B, sigma=max_blur_radius)
        else:
            R_blurred, G_blurred, B_blurred = R, G, B

        # Composite: sharp in focus zone, blurred in periphery
        new_R = R * (1.0 - w_periph) + R_blurred * w_periph
        new_G = G * (1.0 - w_periph) + G_blurred * w_periph
        new_B = B * (1.0 - w_periph) + B_blurred * w_periph

        # ── Desaturation: reduce chroma in periphery ──────────────────────────
        # Perceptual grey conversion, then lerp toward grey by desaturation × weight
        grey = 0.299 * new_R + 0.587 * new_G + 0.114 * new_B
        desat_w = w_periph * desaturation
        new_R = new_R * (1.0 - desat_w) + grey * desat_w
        new_G = new_G * (1.0 - desat_w) + grey * desat_w
        new_B = new_B * (1.0 - desat_w) + grey * desat_w

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 0] = _np.clip(new_B * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_G * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 2] = _np.clip(new_R * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = 255

        tmp = _cairo.ImageSurface.create_for_data(
            bytearray(buf.tobytes()), _cairo.FORMAT_ARGB32, self.w, self.h)
        self.canvas.ctx.set_source_surface(tmp, 0, 0)
        self.canvas.ctx.paint()

        print(f"    Selective focus pass complete  "
              f"(blur sigma={max_blur_radius:.1f}  desat={desaturation:.2f})")

    def hatching_pass(
            self,
            reference:       "Union[np.ndarray, Image.Image]",
            n_strokes:       int   = 2400,
            stroke_size:     int   = 3,
            angle_primary:   float = 45.0,
            angle_cross:     float = -45.0,
            cross_hatch:     bool  = True,
            shadow_thresh:   float = 0.45,
            dark_color:      Color = (0.28, 0.20, 0.12),
            light_color:     Color = (0.92, 0.88, 0.75),
            opacity_shadow:  float = 0.52,
            opacity_light:   float = 0.18,
            hatch_length:    float = 12.0,
            spacing_jitter:  float = 0.35,
    ):
        """
        Tempera hatching pass — inspired by Fra Angelico's Quattrocento technique.

        Egg-tempera dries almost instantly on the chalk-white gesso panel, which
        means the wet-into-wet blending exploited by oil painters is unavailable.
        Instead, Renaissance tempera painters built tonal form through *hatching*:
        extremely fine parallel strokes laid over a dry previous layer at a
        consistent angle.  Shadow regions received dense overlapping hatch layers;
        lit areas were left relatively sparse so the brilliant gesso ground
        could shine through between the strokes.

        This pass simulates that technique by scattering short, thin, directional
        line strokes across the canvas in two ways:

        1. **Shadow hatching** — In pixels darker than ``shadow_thresh`` the pass
           lays down strokes of ``dark_color`` at ``angle_primary`` (default 45°).
           Stroke density is proportional to darkness: fully shadowed regions
           receive the most strokes; mid-tones receive fewer; fully lit areas
           receive none.  This builds tonal depth through *accumulation*, not
           blending.

        2. **Cross-hatching** — When ``cross_hatch=True`` a second pass of strokes
           at ``angle_cross`` (default −45°, perpendicular to the first) is applied
           in the deepest shadow regions (lum < shadow_thresh × 0.55).  The
           diagonal cross-pattern replicates the "piani di colore" layering that
           Fra Angelico, Botticelli, and Perugino used to model the deepest shadow
           passages in flesh and drapery.

        3. **Light accent strokes** — In bright highlight pixels (lum > 0.82) a
           sparse scatter of slightly lighter strokes in ``light_color`` at the
           primary angle indicates the gesso ground asserting itself between hatch
           layers — the distinctive luminous quality of tempera that oil painting
           cannot replicate.

        The technique is relevant to any early tempera pipeline (Fra Angelico,
        Botticelli, Piero della Francesca, Ghirlandaio) and also to the chalk /
        silverpoint underdrawing stage used before oil painting in Dürer's and
        Holbein's Northern Renaissance technique.

        Parameters
        ----------
        reference       : Tonal reference — used to read pixel luminance for
                          stroke placement and density decisions.
        n_strokes       : Total number of hatch strokes to scatter.  2000–4000
                          is typical for a portrait; increase for denser shadow.
        stroke_size     : Stroke width in pixels.  2–4px for tempera fidelity;
                          broader strokes shift toward chalk or silverpoint feel.
        angle_primary   : Angle of primary hatch strokes in degrees.  45° is the
                          canonical Fra Angelico angle derived from his San Marco
                          frescoes; 30° or 60° are period-appropriate alternatives.
        angle_cross     : Angle of the cross-hatch layer (only used when
                          cross_hatch=True).  −45° is perpendicular to 45°.
        cross_hatch     : Whether to add the second diagonal layer in deep shadows.
        shadow_thresh   : Luminance threshold below which hatch strokes are placed.
                          0.45 puts the hatching in the shadow half of the tonal
                          range; increase toward 0.65 for softer, broader coverage.
        dark_color      : Hatch stroke colour for shadow region strokes.
                          Fra Angelico used raw sienna (0.28, 0.20, 0.12) for flesh
                          shadows and a cool grey-brown for drapery.
        light_color     : Hatch stroke colour for highlight accent strokes.
                          Pure lead-white (0.92, 0.88, 0.75) for gesso showing through.
        opacity_shadow  : Base opacity of shadow hatch strokes (0–1).
        opacity_light   : Opacity of light accent strokes (0–1).
        hatch_length    : Length of each hatch stroke in pixels.  8–16px for
                          tempera; longer strokes (~20px) read more like chalk.
        spacing_jitter  : Fraction of hatch_length added as random positional noise.
                          0.30–0.45: slight irregularity avoids mechanical regularity.

        Notes
        -----
        Randomly selected artistic improvement for this session — a composable
        tempera-hatching primitive that benefits any pre-oil pipeline (Quattrocento
        tempera, silverpoint underdrawing, chalk cartoon).  Distinct from
        ``build_form()`` (which uses free-flowing paint strokes following the image
        gradient) and ``angular_contour_pass()`` (which draws expressive contour
        outlines at figure boundaries): hatching_pass builds *interior tonal form*
        through systematic parallel marks, as Renaissance masters did on gesso.
        """
        import math as _math
        import random as _random
        import numpy as _np
        import cairo as _cairo

        print(f"  Hatching pass  (n={n_strokes}  angle={angle_primary:.0f}°  "
              f"cross={cross_hatch}  shadow_thresh={shadow_thresh:.2f})…")

        ref = self._prep(reference)
        h, w = self.h, self.w
        rng = _random.Random(7)   # deterministic seed

        # Pre-compute luminance map from reference for placement decisions.
        # _prep() returns a uint8 array (0–255); normalise to [0, 1] so that
        # shadow_thresh and light thresholds compare in the same scale.
        ref_f = ref[:, :, :3].astype(_np.float32) / 255.0
        lum = (0.299 * ref_f[:, :, 0]
             + 0.587 * ref_f[:, :, 1]
             + 0.114 * ref_f[:, :, 2])   # (H, W) float32 in [0, 1]

        def _draw_hatch(angle_deg: float, color: Color, opacity: float,
                        lum_min: float, lum_max: float, count: int):
            """
            Scatter ``count`` hatch strokes in pixels with luminance in
            [lum_min, lum_max].  Each stroke is a short, thin line at
            ``angle_deg`` degrees, placed randomly within qualifying pixels.
            """
            rad = _math.radians(angle_deg)
            cos_a = _math.cos(rad)
            sin_a = _math.sin(rad)

            # Build a list of candidate pixel indices in the lum band
            mask = (lum >= lum_min) & (lum <= lum_max)
            ys, xs = _np.where(mask)
            if len(ys) == 0:
                return

            ctx = self.canvas.ctx
            ctx.save()

            r_c, g_c, b_c = color

            for _ in range(count):
                # Sample a candidate pixel biased to the lum band
                idx = rng.randrange(len(ys))
                cy  = float(ys[idx]) + rng.uniform(-spacing_jitter * hatch_length,
                                                    spacing_jitter * hatch_length)
                cx  = float(xs[idx]) + rng.uniform(-spacing_jitter * hatch_length,
                                                    spacing_jitter * hatch_length)

                half = hatch_length * 0.5
                x0 = cx - cos_a * half
                y0 = cy - sin_a * half
                x1 = cx + cos_a * half
                y1 = cy + sin_a * half

                # Stroke-density scaling: darker → more opaque hatch strokes
                if lum_min < shadow_thresh:
                    # Map pixel luminance to opacity boost: darker = higher density
                    pix_lum = float(lum[
                        max(0, min(h - 1, int(cy))),
                        max(0, min(w - 1, int(cx)))
                    ])
                    density = _np.clip(1.0 - pix_lum / (shadow_thresh + 1e-6),
                                       0.0, 1.0)
                    eff_opacity = opacity * (0.35 + 0.65 * float(density))
                else:
                    eff_opacity = opacity

                ctx.set_source_rgba(r_c, g_c, b_c, eff_opacity)
                ctx.set_line_width(stroke_size)
                ctx.set_line_cap(_cairo.LINE_CAP_ROUND)
                ctx.move_to(x0, y0)
                ctx.line_to(x1, y1)
                ctx.stroke()

            ctx.restore()

        # ── Primary shadow hatching ───────────────────────────────────────────
        # Hatch density scales inversely with luminance within the shadow zone.
        # Darkest pixels get ~70% of total strokes; lighter shadow pixels get less.
        shadow_count = n_strokes
        _draw_hatch(angle_primary, dark_color, opacity_shadow,
                    0.0, shadow_thresh, shadow_count)

        # ── Cross-hatching in deepest shadows ────────────────────────────────
        if cross_hatch:
            deep_thresh = shadow_thresh * 0.55
            cross_count = n_strokes // 3
            _draw_hatch(angle_cross, dark_color, opacity_shadow * 0.75,
                        0.0, deep_thresh, cross_count)

        # ── Light accent strokes — gesso ground showing through ──────────────
        light_count = max(1, n_strokes // 8)
        _draw_hatch(angle_primary, light_color, opacity_light,
                    0.82, 1.0, light_count)

        print(f"    Hatching pass complete  "
              f"(shadow={shadow_count}  cross={n_strokes // 3 if cross_hatch else 0}  "
              f"light={light_count})")

    def holbein_jewel_glaze_pass(
            self,
            chroma_boost:      float = 0.30,
            jewel_lo:          float = 0.22,
            jewel_hi:          float = 0.72,
            shadow_cool_shift: float = 0.08,
            highlight_pale:    float = 0.14,
            shadow_desat:      float = 0.18,
            opacity:           float = 0.82,
    ):
        """
        Holbein jewel-glaze pass — inspired by Hans Holbein the Younger's technique.

        Holbein built his surfaces through thin, resin-rich oil glazes applied to a
        near-white ground, each glaze drying completely before the next was applied.
        Because he never used a warm amber varnish to unify the surface — as Leonardo,
        Raphael, and the Venetians did — each colour zone in a Holbein portrait retains
        its full chromatic identity: the crimson sleeve stays crimson, the smalt-blue
        doublet stays cold cobalt, the malachite green remains clear and mineral.  The
        result has a jewel-like, enamel quality: every colour appears to glow from
        within, as if lit by its own internal light rather than by a shared external
        source.

        This pass simulates that effect through three targeted per-pixel adjustments:

        1. **Jewel-zone chroma boost** — In the mid-luminance band (``jewel_lo`` to
           ``jewel_hi``, default 0.22–0.72) the pass boosts HSV saturation by
           ``chroma_boost`` (default 0.30).  This is the zone where local colour is
           most legible; boosting it replicates the jewel depth that Holbein achieved
           through repeated transparent glazes.  A smooth cosine ramp at both edges of
           the zone prevents hard saturation cliffs.

        2. **Shadow cooling and desaturation** — Pixels below ``jewel_lo`` have their
           saturation reduced by ``shadow_desat`` and their hue gently shifted toward
           the blue-grey end of the spectrum by ``shadow_cool_shift``.  Holbein's
           shadows are cool and restrained — never the warm chiaroscuro of Caravaggio —
           because his thin glazes lack the optical body to absorb light into drama.
           Desaturating the darks also ensures that the boosted mid-tones read as
           jewel-bright against a neutral shadow field.

        3. **Highlight paling** — Pixels above ``jewel_hi`` have their saturation
           reduced by ``highlight_pale`` and their value (lightness) pushed slightly
           toward an ivory-white, simulating the lead-white highlights Holbein applied
           last to seal the surface.  These near-white touches make the jewel mid-tones
           read as even richer by contrast.

        All operations are fully vectorised (NumPy) and applied to the raw Cairo surface
        buffer.  The result is blended back at ``opacity`` so the caller can control the
        overall strength of the effect.  The pass is safe to call multiple times —
        successive applications compound the jewel depth without clipping.

        Parameters
        ----------
        chroma_boost      : Saturation increase in the jewel zone (0–1 delta added to
                            HSV saturation, clamped to 1.0).  0.20–0.35 gives a
                            rich but believable jewel quality; higher values read as
                            illustration.
        jewel_lo          : Lower luminance boundary of the jewel zone (default 0.22).
                            Pixels below this are treated as deep shadow.
        jewel_hi          : Upper luminance boundary of the jewel zone (default 0.72).
                            Pixels above this are treated as highlight.
        shadow_cool_shift : Amount by which the hue of shadow pixels is shifted toward
                            the blue-grey cool direction (0–1, applied as a small
                            additive hue offset toward ~0.60 in HSV).
        highlight_pale    : Saturation reduction in the highlight zone (0–1 delta).
                            0.10–0.20 drives highlights toward ivory without fully
                            neutralising any remaining warm tint.
        shadow_desat      : Saturation reduction in the shadow zone (0–1 delta).
        opacity           : Blend weight of the adjusted layer over the original
                            canvas pixels (0 = no effect, 1 = full replacement).

        Notes
        -----
        Randomly selected artistic improvement for this session — a composable
        jewel-glaze primitive inspired by Holbein's unique palette strategy.  Distinct
        from ``chroma_zone_pass()`` (which only adjusts saturation globally), this pass
        also introduces directed warm/cool temperature shifts in the luminance extremes,
        replicating the specific chromatic personality of Northern Renaissance panel
        painting: brilliant mid-tone hues, cool restrained shadows, pale ivory lights.
        """
        import numpy as _np
        import colorsys as _colorsys

        print(f"  Holbein jewel-glaze pass  "
              f"(chroma_boost={chroma_boost:.2f}  "
              f"jewel=[{jewel_lo:.2f}–{jewel_hi:.2f}]  "
              f"opacity={opacity:.2f})…")

        h, w = self.h, self.w

        # ── Read current canvas (Cairo BGRA layout) ───────────────────────────
        buf = _np.frombuffer(self.canvas.surface.get_data(),
                             dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()   # keep original for the final opacity blend

        # Extract RGB float in [0, 1] — Cairo stores BGRA
        r_ch = buf[:, :, 2].astype(_np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(_np.float32) / 255.0
        b_ch = buf[:, :, 0].astype(_np.float32) / 255.0

        # ── Vectorised RGB → HSV ──────────────────────────────────────────────
        v_ch  = _np.maximum(_np.maximum(r_ch, g_ch), b_ch)   # value
        c_min = _np.minimum(_np.minimum(r_ch, g_ch), b_ch)   # chrominance range
        delta = v_ch - c_min

        # Saturation: s = delta / v (undefined when v=0 — keep s=0)
        s_ch = _np.where(v_ch > 1e-6, delta / (v_ch + 1e-6), 0.0)

        # Hue (in [0, 1] = [0°, 360°] / 360):
        #   When delta=0 the colour is achromatic — hue is undefined; set to 0.
        eps = 1e-6
        h_ch = _np.zeros_like(r_ch)

        r_max = (v_ch == r_ch) & (delta > eps)
        g_max = (v_ch == g_ch) & (delta > eps) & ~r_max
        b_max = ~r_max & ~g_max & (delta > eps)

        h_ch[r_max] = ((g_ch[r_max] - b_ch[r_max]) / delta[r_max]) % 6.0
        h_ch[g_max] = ((b_ch[g_max] - r_ch[g_max]) / delta[g_max]) + 2.0
        h_ch[b_max] = ((r_ch[b_max] - g_ch[b_max]) / delta[b_max]) + 4.0
        h_ch = h_ch / 6.0   # normalise to [0, 1]

        # ── Luminance (perceived brightness) for zone decisions ───────────────
        lum = 0.299 * r_ch + 0.587 * g_ch + 0.114 * b_ch   # (H, W) float32

        # ── Zone masks ────────────────────────────────────────────────────────
        in_shadow   = lum < jewel_lo
        in_highlight = lum > jewel_hi
        in_jewel    = ~in_shadow & ~in_highlight

        # Smooth cosine ramp at zone boundaries to avoid saturation cliffs.
        # Within the jewel zone, ramp from 0→1 over the lower 10% and 1→0 over
        # the upper 10% of the zone width.
        zone_width = jewel_hi - jewel_lo + eps
        ramp_w     = zone_width * 0.10   # transition width at each edge

        ramp_lo = _np.clip((lum - jewel_lo) / ramp_w, 0.0, 1.0)
        ramp_hi = _np.clip((jewel_hi - lum) / ramp_w, 0.0, 1.0)
        jewel_ramp = _np.where(in_jewel,
                               0.5 * (1.0 - _np.cos(_np.pi * _np.minimum(ramp_lo, ramp_hi))),
                               0.0)

        # ── Apply jewel-zone chroma boost ─────────────────────────────────────
        s_out = s_ch.copy()
        s_out = _np.where(in_jewel,
                          _np.clip(s_ch + chroma_boost * jewel_ramp, 0.0, 1.0),
                          s_out)

        # ── Shadow cooling + desaturation ─────────────────────────────────────
        # Shift hue toward blue (0.58 in [0,1] ≈ 210° — blue-grey / slate)
        hue_blue  = 0.58
        shadow_ramp = _np.clip((jewel_lo - lum) / (jewel_lo + eps), 0.0, 1.0)
        h_out = h_ch.copy()
        h_out = _np.where(
            in_shadow,
            h_ch + shadow_cool_shift * shadow_ramp * (hue_blue - h_ch),
            h_out,
        )
        s_out = _np.where(in_shadow,
                          _np.clip(s_ch - shadow_desat * shadow_ramp, 0.0, 1.0),
                          s_out)

        # ── Highlight paling ──────────────────────────────────────────────────
        # Drive highlights toward pale ivory by reducing saturation.
        # Also push value very slightly toward 1.0 (white-lead highlights).
        hi_ramp = _np.clip((lum - jewel_hi) / (1.0 - jewel_hi + eps), 0.0, 1.0)
        s_out = _np.where(in_highlight,
                          _np.clip(s_ch - highlight_pale * hi_ramp, 0.0, 1.0),
                          s_out)
        v_out = _np.where(in_highlight,
                          _np.clip(v_ch + 0.04 * hi_ramp, 0.0, 1.0),
                          v_ch)
        v_out = _np.where(in_jewel | in_shadow, v_ch, v_out)   # only highlights

        # ── Reconstruct RGB from adjusted HSV ─────────────────────────────────
        # HSV → RGB via sector-based formula (vectorised, no per-pixel loop)
        h6  = (h_out % 1.0) * 6.0           # [0, 6)
        hi_ = h6.astype(_np.int32) % 6      # sector index 0–5
        f   = h6 - hi_.astype(_np.float32)  # fractional part

        p   = v_out * (1.0 - s_out)
        q   = v_out * (1.0 - s_out * f)
        t_  = v_out * (1.0 - s_out * (1.0 - f))

        r_out = _np.zeros_like(r_ch)
        g_out = _np.zeros_like(g_ch)
        b_out = _np.zeros_like(b_ch)

        for sec, (rv, gv, bv) in enumerate(
            [(v_out, t_, p), (q, v_out, p), (p, v_out, t_),
             (p, q, v_out), (t_, p, v_out), (v_out, p, q)]
        ):
            mask = hi_ == sec
            r_out[mask] = rv[mask]
            g_out[mask] = gv[mask]
            b_out[mask] = bv[mask]

        # Achromatic pixels: copy value to all channels
        achromatic = delta < eps
        r_out[achromatic] = v_out[achromatic]
        g_out[achromatic] = v_out[achromatic]
        b_out[achromatic] = v_out[achromatic]

        # ── Blend adjusted layer back at `opacity` ───────────────────────────
        # Cairo BGRA: blue in [0], green in [1], red in [2], alpha in [3]
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        print(f"    Holbein jewel-glaze pass complete")

    def van_dyck_silver_drapery_pass(
            self,
            fabric_angle:     float = 30.0,
            shimmer_period:   float = 18.0,
            shimmer_strength: float = 0.08,
            silver_cool:      float = 0.12,
            ivory_boost:      float = 0.06,
            neutral_thresh:   float = 0.40,
            lum_lo:           float = 0.32,
            opacity:          float = 0.75,
    ):
        """
        Van Dyck silver-drapery pass — inspired by Anthony van Dyck's technique.

        Van Dyck's greatest technical achievement is his rendering of silk —
        particularly the shimmering, pearl-grey English court silks that appear
        in virtually every portrait from his London period (1632–1641).  He
        painted these with loaded, rapid strokes that follow the fall of the
        fabric, leaving thick bright ridges of pearl-grey alternating with cool
        shadow valleys.  The result has an almost liquid quality: the silk appears
        to shift and reflect as the viewer moves.

        Technically, this effect arises from two sources:
        1. **Woven-silk anisotropy** — warp and weft threads reflect light at
           slightly different angles, producing a subtle directional shimmer
           perpendicular to the fabric's main fold direction.
        2. **Temperature contrast** — van Dyck's highlights read warm ivory
           (lead-white tinted with naples yellow) while the shadow valleys cool
           toward a blue-grey (from the reddish-brown ground showing through thin
           grey paint).

        This pass simulates both effects through three per-pixel adjustments:

        1. **Directional shimmer** — A sinusoidal brightness modulation with
           period ``shimmer_period`` pixels is applied along the direction
           *perpendicular* to ``fabric_angle``.  Pixels in the candidate silk
           zone (luminance ≥ ``lum_lo`` and saturation ≤ ``neutral_thresh``) are
           brightened at shimmer peaks and slightly darkened at troughs,
           reproducing the alternating highlight-shadow structure of woven silk.

        2. **Silver cooling** — The silk zone is shifted toward cool blue-grey by
           reducing the red channel and boosting the blue channel proportionally
           to local luminance.  This replicates the way van Dyck's thin silver-grey
           paint allows the warm reddish-brown imprimatura to warm the shadow
           passages while highlights stay cool and metallic.

        3. **Ivory specular push** — In the brightest pixels of the silk zone
           (lum > 0.78) a gentle ivory-white boost is applied via a linear ramp,
           simulating the thick lead-white impasto van Dyck pressed onto the
           highest highlight ridges as a final loaded-brush stroke.

        All operations are fully vectorised (NumPy) and applied to the raw Cairo
        surface buffer.  The result is blended back at ``opacity`` so the caller
        can control overall effect strength.  The pass is composable — call it
        after ``block_in()`` to establish the silk structure, then after
        ``place_lights()`` to sharpen the final specular ridge.

        Parameters
        ----------
        fabric_angle     : Direction of the fabric's main fold flow, in degrees.
                           0° = horizontal folds, 90° = vertical, 30–45° typical
                           for draped court costume.  The shimmer is applied
                           *perpendicular* to this angle.
        shimmer_period   : Pixel period of the woven-silk shimmer (default 18px).
                           12–22px is perceptually realistic at portrait scale;
                           larger values produce smoother, more satin-like sheen.
        shimmer_strength : Amplitude of the brightness oscillation (0–1 delta,
                           default 0.08).  0.05–0.10 gives a subtle realistic
                           shimmer; higher values read as illustration.
        silver_cool      : Strength of the cool blue-grey shift in the silk zone
                           (0–1, default 0.12).  Applied as a luminance-scaled
                           reduction of R and boost of B.
        ivory_boost      : Strength of the ivory-white specular push in the
                           brightest highlights (lum > 0.78, default 0.06).
        neutral_thresh   : HSV saturation ceiling for silk-candidate pixels
                           (default 0.40).  Near-neutral grey-white pixels qualify;
                           strongly chromatic pixels (flesh, crimson, ultramarine)
                           are excluded from the silk zone.
        lum_lo           : Minimum luminance for silk-candidate pixels (default
                           0.32).  Deep shadows are excluded — only mid-to-bright
                           areas qualify as visible silk surface.
        opacity          : Blend weight of the adjusted layer over the original
                           canvas pixels (0 = no effect, 1 = full replacement).

        Notes
        -----
        Randomly selected artistic improvement for this session — a composable
        silk-shimmer primitive inspired by van Dyck's directional drapery
        technique.  Distinct from ``luminous_fabric_pass()`` (Zurbarán's hyper-
        real razor-sharp white cloth) and ``scumble_pass()`` (undirected dry-
        brush texture): this pass introduces *directional* periodicity that
        simulates the warp/weft anisotropy of woven silk, combined with the
        warm/cool temperature contrast specific to van Dyck's pearl-grey palette.
        """
        import numpy as _np

        print(f"  Van Dyck silver-drapery pass  "
              f"(fabric_angle={fabric_angle:.0f}°  "
              f"shimmer_period={shimmer_period:.0f}px  "
              f"opacity={opacity:.2f})…")

        h, w = self.h, self.w

        # ── Read current canvas (Cairo BGRA layout) ───────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Extract RGB float in [0, 1] — Cairo stores BGRA
        r_ch = buf[:, :, 2].astype(_np.float32) / 255.0
        g_ch = buf[:, :, 1].astype(_np.float32) / 255.0
        b_ch = buf[:, :, 0].astype(_np.float32) / 255.0

        # ── Luminance and saturation for zone decisions ───────────────────────
        lum = 0.299 * r_ch + 0.587 * g_ch + 0.114 * b_ch   # (H, W)

        v_ch  = _np.maximum(_np.maximum(r_ch, g_ch), b_ch)
        c_min = _np.minimum(_np.minimum(r_ch, g_ch), b_ch)
        delta = v_ch - c_min
        s_ch  = _np.where(v_ch > 1e-6, delta / (v_ch + 1e-6), 0.0)

        # Silk candidate mask: moderate-to-high luminance AND near-neutral colour.
        # Near-neutral = low saturation: grey, white, and pale silks qualify;
        # strongly chromatic areas (flesh, crimson, blue) are excluded.
        silk_mask = (lum >= lum_lo) & (s_ch <= neutral_thresh)

        # ── Coordinate grids for directional shimmer ──────────────────────────
        # Build per-pixel (y, x) arrays and project onto the direction
        # *perpendicular* to fabric_angle.  This gives each pixel a "fiber
        # position" value; the sinusoid along this axis creates the warp/weft
        # alternation that makes woven silk shimmer.
        ys_grid = _np.arange(h, dtype=_np.float32)[:, None] * _np.ones((1, w), dtype=_np.float32)
        xs_grid = _np.ones((h, 1), dtype=_np.float32) * _np.arange(w, dtype=_np.float32)[None, :]

        rad_perp   = _np.radians(fabric_angle + 90.0)   # perpendicular to fabric flow
        fiber_proj = xs_grid * _np.cos(rad_perp) + ys_grid * _np.sin(rad_perp)

        # Sinusoidal shimmer: peaks at +shimmer_strength, troughs at −shimmer_strength
        shimmer = shimmer_strength * _np.sin(
            2.0 * _np.pi * fiber_proj / (shimmer_period + 1e-6)
        )   # (H, W)  values in [−shimmer_strength, +shimmer_strength]

        # ── Apply shimmer to silk zone ────────────────────────────────────────
        # Brighten ridges (positive shimmer), slightly darken valleys (negative).
        # Apply equally to R, G; apply at ×0.50 to B so shimmer ridges warm
        # slightly (ivory ridge) and troughs cool slightly (no additional boost).
        r_out = _np.where(silk_mask, _np.clip(r_ch + shimmer,        0.0, 1.0), r_ch)
        g_out = _np.where(silk_mask, _np.clip(g_ch + shimmer,        0.0, 1.0), g_ch)
        b_out = _np.where(silk_mask, _np.clip(b_ch + shimmer * 0.50, 0.0, 1.0), b_ch)

        # ── Silver cooling — shift silk zone toward blue-grey ─────────────────
        # Reduce R, boost B, proportionally to how bright the pixel is within
        # the silk zone.  Brighter = more silver coolness (the paint is thinner
        # at highlights, so the imprimatura shows through less, making the
        # highlight cooler and more metallic).
        cool_scale = _np.clip((lum - lum_lo) / (1.0 - lum_lo + 1e-6), 0.0, 1.0)
        r_out = _np.where(silk_mask,
                          _np.clip(r_out - silver_cool * cool_scale, 0.0, 1.0),
                          r_out)
        b_out = _np.where(silk_mask,
                          _np.clip(b_out + silver_cool * cool_scale * 0.80, 0.0, 1.0),
                          b_out)

        # ── Ivory specular push in the brightest highlights ───────────────────
        # Van Dyck pressed thick lead-white (warm ivory) onto the highest
        # highlight ridges as a final loaded-brush stroke.  Simulate this by
        # boosting R and G (toward warm ivory) in pixels above lum=0.78.
        hi_thresh = 0.78
        hi_mask   = silk_mask & (lum > hi_thresh)
        hi_ramp   = _np.where(hi_mask,
                               _np.clip((lum - hi_thresh) / (1.0 - hi_thresh + 1e-6),
                                        0.0, 1.0),
                               0.0)
        r_out = _np.where(hi_mask,
                          _np.clip(r_out + ivory_boost * hi_ramp, 0.0, 1.0),
                          r_out)
        g_out = _np.where(hi_mask,
                          _np.clip(g_out + ivory_boost * hi_ramp * 0.85, 0.0, 1.0),
                          g_out)

        # ── Blend adjusted layer back at `opacity` ───────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        print(f"    Van Dyck silver-drapery pass complete")

    # ──────────────────────────────────────────────────────────────────────────
    # Rubens flesh-vitality pass
    # ──────────────────────────────────────────────────────────────────────────

    def rubens_flesh_vitality_pass(
            self,
            blush_strength:   float = 0.14,
            cream_strength:   float = 0.10,
            warm_shadow:      float = 0.06,
            blush_lo:         float = 0.28,
            blush_hi:         float = 0.68,
            highlight_thresh: float = 0.72,
            shadow_thresh:    float = 0.22,
            opacity:          float = 0.80,
    ):
        """
        Rubens flesh-vitality pass — inspired by Peter Paul Rubens' technique.

        Rubens' most celebrated achievement is his rendering of living flesh:
        warm, rosy, translucent, and unmistakably breathing.  He achieved this
        through three distinct chromatic strategies applied simultaneously:

        1. **Rosy blush in thin-skin zones** (mid-luminance band):
           Ears, nose tip, cheeks, lips, and knuckles — places where the skin is
           thin enough for blood vessels to show — received an extra glaze of
           vermilion or rose madder.  This is the flushed, vascular warmth that
           no cool-flesh palette can replicate.  Here we apply it as a
           luminance-gated R-channel boost that peaks in the mid-tone band
           (blush_lo..blush_hi) and falls to zero at the extremes.

        2. **Cream-ivory impasto at highlight peaks** (high-luminance band):
           Rubens pressed final highlights on with a palette knife — thick
           lead-white tinted with naples yellow, warm ivory rather than pure
           white.  This cream push (R + slight G) warms the brightest peaks
           away from dead-white, giving them the luminous quality of sunlit
           porcelain.

        3. **Warm brownish-red in deep shadows** (low-luminance band):
           Unlike Northern painters who let shadows go cool and grey, Rubens'
           shadows glow with brownish-red transmitted light, as though the
           figure were lit from within.  A subtle R boost and B reduction in
           the darkest zones reproduces this quality without lifting the overall
           shadow depth.

        All three adjustments are blended back at `opacity` so the original
        canvas reading is preserved beneath the tonal shift.

        Parameters
        ----------
        blush_strength   : peak strength of the rosy blush tint in mid-tones
        cream_strength   : ivory warmth pushed into highlight peaks
        warm_shadow      : brownish-red glow added to deep shadow pixels
        blush_lo         : lower luminance bound for the blush zone
        blush_hi         : upper luminance bound for the blush zone
        highlight_thresh : luminance above which cream push begins
        shadow_thresh    : luminance below which warm shadow begins
        opacity          : global blend weight of the entire adjustment layer
        """
        import numpy as _np

        print(f"  Rubens flesh-vitality pass  "
              f"(blush={blush_strength:.2f}  cream={cream_strength:.2f}  "
              f"warm_shadow={warm_shadow:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Rubens flesh-vitality pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA channel order: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Luminance ────────────────────────────────────────────────────────
        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── 1. Rosy blush — mid-luminance thin-skin zones ────────────────────
        # A sine ramp peaks at the centre of the blush band and fades to zero
        # at both boundaries, giving a smooth, anatomically convincing taper.
        blush_range = max(blush_hi - blush_lo, 1e-6)
        blush_t     = _np.clip((lum - blush_lo) / blush_range, 0.0, 1.0)
        blush_scale = _np.sin(_np.pi * blush_t)   # 0 at edges, 1 at centre
        blush_mask  = (lum >= blush_lo) & (lum <= blush_hi)

        r_out = _np.where(blush_mask,
                          _np.clip(r_f + blush_strength * blush_scale, 0.0, 1.0),
                          r_f)
        g_out = _np.where(blush_mask,
                          _np.clip(g_f - blush_strength * 0.30 * blush_scale, 0.0, 1.0),
                          g_f)
        b_out = _np.where(blush_mask,
                          _np.clip(b_f - blush_strength * 0.50 * blush_scale, 0.0, 1.0),
                          b_f)

        # ── 2. Cream-ivory push at highlight peaks ───────────────────────────
        # Ramp from zero at highlight_thresh to full at lum=1.0.
        hi_mask = lum > highlight_thresh
        hi_ramp = _np.where(hi_mask,
                            _np.clip((lum - highlight_thresh)
                                     / (1.0 - highlight_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(hi_mask,
                          _np.clip(r_out + cream_strength * hi_ramp, 0.0, 1.0),
                          r_out)
        g_out = _np.where(hi_mask,
                          _np.clip(g_out + cream_strength * 0.85 * hi_ramp, 0.0, 1.0),
                          g_out)
        # Blue is left unchanged at highlights — warm ivory keeps its warmth.

        # ── 3. Warm brownish-red undertone in deep shadows ───────────────────
        # Ramp from zero at shadow_thresh down to full at lum=0.
        sh_mask = lum < shadow_thresh
        sh_ramp = _np.where(sh_mask,
                            _np.clip((shadow_thresh - lum)
                                     / (shadow_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(sh_mask,
                          _np.clip(r_out + warm_shadow * sh_ramp, 0.0, 1.0),
                          r_out)
        b_out = _np.where(sh_mask,
                          _np.clip(b_out - warm_shadow * 0.70 * sh_ramp, 0.0, 1.0),
                          b_out)

        # ── Blend adjusted layer back at `opacity` ───────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        print(f"    Rubens flesh-vitality pass complete")

    # ─────────────────────────────────────────────────────────────────────────
    # Poussin classical-clarity pass — Nicolas Poussin / French Classicism
    # ─────────────────────────────────────────────────────────────────────────

    def poussin_classical_clarity_pass(
            self,
            shadow_cool:      float = 0.12,
            midtone_lift:     float = 0.06,
            saturation_cap:   float = 0.72,
            highlight_ivory:  float = 0.05,
            shadow_thresh:    float = 0.32,
            highlight_thresh: float = 0.72,
            midtone_lo:       float = 0.32,
            midtone_hi:       float = 0.68,
            opacity:          float = 0.80,
    ):
        """
        Poussin classical-clarity pass — inspired by Nicolas Poussin (1594–1665).

        Nicolas Poussin built his paintings on deliberate chromatic principles
        that distinguished his work from the warm Baroque tradition around him.
        While Rubens, Rembrandt, and Caravaggio all used warm, earthy shadows,
        Poussin's shadow areas carry a silvery blue-grey quality derived from
        his close study of classical marble sculpture in Rome.  This pass
        approximates three of his defining technical signatures:

        1. **Cool, silver-grey shadows** — Poussin's shadows read as though cast
           from marble rather than lit by warm transmitted firelight.  Here we
           apply a cool blue-grey push to the darkest luminance zone (boost B,
           damp R), whose strength ramps from maximum at lum=0 down to zero at
           ``shadow_thresh``.  The result is the characteristic silvery depth
           that separates Poussin from every warm-Baroque painter of his era.

        2. **Mid-tone clarification — opening the tonal structure** — Poussin
           organised his compositions into clear, readable tonal triads (lights,
           mid-tones, darks) with crisp transitions between them.  His mid-tones
           are deliberately lifted away from the shadow zone, giving the painting
           an architectural clarity — every zone is legible from across a room.
           A sine ramp peaks at the centre of the mid-tone band
           (``midtone_lo``..``midtone_hi``) and proportionally lifts all three
           channels (preserving hue while opening value).

        3. **Cool ivory highlights** — His highest lights have a subtle blue-ivory
           quality, influenced by the cool reflected light of marble and plaster
           casts, rather than the warm lead-white cream of Rubens or the pure
           cadmium white of Academic painting.  A linear ramp applies a slight
           B boost and mild R damp above ``highlight_thresh``.

        4. **Saturation discipline** — Poussin's palette is radiant but never
           garish.  No single colour dominates; every hue is placed in a tonal
           context that gives it value without allowing it to overwhelm the whole.
           This step caps HSV saturation at ``saturation_cap`` for any pixel
           whose saturation exceeds that value, reducing chroma toward achromatic
           while preserving hue and value.

        All four adjustments are blended back at ``opacity`` so the original
        canvas reading is preserved beneath the chromatic correction.

        Parameters
        ----------
        shadow_cool      : strength of the blue-grey cool push in deep shadows
        midtone_lift     : fractional luminance lift at the centre of the
                          mid-tone band (0 = no lift, 0.10 = 10% value gain)
        saturation_cap   : maximum HSV saturation allowed after the pass
                          (1.0 = no capping; 0.70 = cap vivid pixels to 70%)
        highlight_ivory  : strength of the cool ivory push at highlight peaks
        shadow_thresh    : luminance below which the shadow-cool push is applied
        highlight_thresh : luminance above which the highlight-ivory push begins
        midtone_lo       : lower luminance bound of the mid-tone clarification
        midtone_hi       : upper luminance bound of the mid-tone clarification
        opacity          : global blend weight of the entire adjustment layer
                          (0 = noop, 1 = full replacement)

        Notes
        -----
        Call this AFTER the main style passes and BEFORE the final glaze/finish.
        Particularly effective after block_in() and build_form() on a painting
        that reads as too warm or too Baroque — it corrects the tonal register
        toward Poussin's architectural classical clarity without removing the
        underlying paint structure.

        Famous works to study:
          *Et in Arcadia Ego* (c. 1637–1638, Louvre) — definitive azure/vermilion
          triad, cool marble-grey shadows, crystalline Arcadian light.
          *The Holy Family on the Steps* (1648, Cleveland) — exemplary mid-tone
          clarification: light, mid-tone, and shadow read as three distinct zones.
          *A Dance to the Music of Time* (c. 1634–36, Wallace Collection) — the
          cool silver-blue of the sky flows into the shadow sides of the figures.
        """
        import numpy as _np

        print(f"  Poussin classical-clarity pass  "
              f"(shadow_cool={shadow_cool:.2f}  midtone_lift={midtone_lift:.2f}  "
              f"sat_cap={saturation_cap:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Poussin classical-clarity pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA channel order: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Luminance ────────────────────────────────────────────────────────
        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Cool silver-grey push in deep shadows ─────────────────────────
        # Ramp from full at lum=0 down to zero at shadow_thresh.
        # Cool push: boost B, damp R — marble-shadow quality.
        sh_mask = lum < shadow_thresh
        sh_ramp = _np.where(sh_mask,
                            _np.clip((shadow_thresh - lum)
                                     / (shadow_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(sh_mask,
                          _np.clip(r_out - shadow_cool * 0.50 * sh_ramp, 0.0, 1.0),
                          r_out)
        b_out = _np.where(sh_mask,
                          _np.clip(b_out + shadow_cool * 0.60 * sh_ramp, 0.0, 1.0),
                          b_out)

        # ── 2. Mid-tone clarification — open the tonal structure ─────────────
        # A sine ramp peaks at the centre of the mid-tone band.
        # Lift all channels proportionally (preserves hue; opens value).
        mt_range = max(midtone_hi - midtone_lo, 1e-6)
        mt_t     = _np.clip((lum - midtone_lo) / mt_range, 0.0, 1.0)
        mt_scale = _np.sin(_np.pi * mt_t)   # 0 at band edges, 1 at centre
        mt_mask  = (lum >= midtone_lo) & (lum <= midtone_hi)

        lift = 1.0 + midtone_lift * mt_scale
        r_out = _np.where(mt_mask, _np.clip(r_out * lift, 0.0, 1.0), r_out)
        g_out = _np.where(mt_mask, _np.clip(g_out * lift, 0.0, 1.0), g_out)
        b_out = _np.where(mt_mask, _np.clip(b_out * lift, 0.0, 1.0), b_out)

        # ── 3. Cool ivory push at highlight peaks ────────────────────────────
        # Linear ramp from zero at highlight_thresh to full at lum=1.0.
        # Cool ivory: slight B boost, minor R damp (marble-reflected-light quality).
        hi_mask = lum > highlight_thresh
        hi_ramp = _np.where(hi_mask,
                            _np.clip((lum - highlight_thresh)
                                     / (1.0 - highlight_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(hi_mask,
                          _np.clip(r_out - highlight_ivory * 0.40 * hi_ramp, 0.0, 1.0),
                          r_out)
        b_out = _np.where(hi_mask,
                          _np.clip(b_out + highlight_ivory * 0.35 * hi_ramp, 0.0, 1.0),
                          b_out)

        # ── 4. Saturation discipline — cap over-vivid pixels ─────────────────
        # Vectorised HSV saturation capping.
        # For each pixel: sat = (max_c - min_c) / max_c.
        # If sat > saturation_cap, scale the non-max channels toward max_c
        # (reduce chroma without changing value or hue).
        max_c  = _np.maximum(_np.maximum(r_out, g_out), b_out)   # value
        min_c  = _np.minimum(_np.minimum(r_out, g_out), b_out)
        chroma = max_c - min_c

        sat  = _np.where(max_c > 1e-6, chroma / max_c, 0.0)
        over = sat > saturation_cap

        # Scale factor: new_chroma = max_c * saturation_cap → scale = new/old
        # Use safe_chroma to avoid a div-by-zero runtime warning from numpy's
        # vectorised evaluation (np.where evaluates both branches before selecting).
        new_chroma  = max_c * saturation_cap
        safe_chroma = _np.where(chroma > 1e-6, chroma, 1.0)
        scale = _np.where(over & (chroma > 1e-6), new_chroma / safe_chroma, 1.0)

        # Each channel: new_ch = max_c - (max_c - old_ch) * scale
        r_out = _np.where(over, _np.clip(max_c - (max_c - r_out) * scale, 0.0, 1.0), r_out)
        g_out = _np.where(over, _np.clip(max_c - (max_c - g_out) * scale, 0.0, 1.0), g_out)
        b_out = _np.where(over, _np.clip(max_c - (max_c - b_out) * scale, 0.0, 1.0), b_out)

        # ── Blend adjusted layer back at `opacity` ───────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        n_shadow    = int(sh_mask.sum())
        n_midtone   = int(mt_mask.sum())
        n_highlight = int(hi_mask.sum())
        n_over_sat  = int(over.sum())
        print(f"    Poussin classical-clarity pass complete  "
              f"(shadow={n_shadow}px  midtone={n_midtone}px  "
              f"highlight={n_highlight}px  sat-capped={n_over_sat}px)")

    # ─────────────────────────────────────────────────────────────────────────
    # Gainsborough feathery pass — Thomas Gainsborough / British Rococo Portrait
    # ─────────────────────────────────────────────────────────────────────────

    def gainsborough_feathery_pass(
            self,
            silver_strength:  float = 0.10,
            feather_spread:   float = 2.5,
            shimmer_strength: float = 0.04,
            shadow_haze:      float = 0.06,
            highlight_thresh: float = 0.68,
            midtone_lo:       float = 0.30,
            midtone_hi:       float = 0.72,
            shadow_thresh:    float = 0.35,
            opacity:          float = 0.78,
    ):
        """
        Gainsborough feathery pass — inspired by Thomas Gainsborough (1727–1788).

        Thomas Gainsborough was the supreme British portrait and landscape painter
        of the 18th century.  He worked in direct competition with Sir Joshua
        Reynolds — while Reynolds favoured warm academic flesh tones and grand
        classical gravity, Gainsborough's answer was silvery lightness: cool,
        feathery, alive with atmospheric breath.

        This pass approximates three of his defining technical signatures:

        1. **Cool silver-blue highlights** — Gainsborough's brightest lights lean
           toward a cool blue-white silver rather than warm ivory or cream.  He
           admired Van Dyck's pearl-grey silk passages and carried that quality
           into his flesh, drapery, and sky.  Here we apply a gentle B-channel
           boost and slight R damp above ``highlight_thresh``, ramping linearly
           to full strength at lum=1.0.

        2. **Feathery edge dissolution** — His most iconic quality.  Using
           long flexible brushes held at arm's length, each mark ended in a
           broken, tapered "feather" that dissolved into the surrounding paint
           before it dried.  We approximate this by detecting edge zones with a
           Sobel magnitude map, then applying a directional Gaussian blur along
           the edge gradient perpendicular (across the edge, not along it).
           The result is the characteristic soft dissolution of a figure's
           silhouette into its background — without losing the interior
           structure of the form.

        3. **Fluid midtone shimmer** — He applied paint in very thin, liquid
           layers that would almost run on the canvas.  In mid-tone areas this
           produces a subtle horizontal streaming quality — as if the paint
           is still in motion.  We simulate this with a stochastic horizontal
           scatter: for each mid-luminance pixel, a small random R/B offset is
           sampled from its neighbourhood along the horizontal axis, adding the
           optical sense of a fresh, fluid brushstroke that has not yet set.

        4. **Cool atmospheric background haze** — Gainsborough always united
           his sitter and landscape into one atmospheric world.  Shadow areas
           receive a subtle B boost and slight R damp, pushing them toward the
           cool blue-grey of an English cloudy sky.  This is most effective in
           the periphery of the composition where the background sits.

        All four adjustments are composited back at ``opacity`` so the original
        canvas reading is preserved beneath the tonal shifts.

        Parameters
        ----------
        silver_strength  : strength of the cool silver push in highlights
        feather_spread   : Gaussian sigma (pixels) for the edge feathering blur
        shimmer_strength : amplitude of the horizontal fluid shimmer in midtones
        shadow_haze      : strength of the cool atmospheric push in shadows
        highlight_thresh : luminance above which the silver push begins
        midtone_lo       : lower luminance bound of the shimmer zone
        midtone_hi       : upper luminance bound of the shimmer zone
        shadow_thresh    : luminance below which the atmospheric haze begins
        opacity          : global blend weight of the entire adjustment layer
                          (0 = noop, 1 = full replacement)

        Notes
        -----
        Call this AFTER the main style passes and BEFORE the final glaze/finish.
        Particularly effective on warm-fleshed portraits that need the cool
        British atmosphere added without removing the underlying painterly warmth.

        Famous works to study:
          *The Blue Boy* (c. 1770, Huntington Library) — his most celebrated
          portrait; the cool silver-blue of the suit reads against a warm
          autumnal landscape background, demonstrating his mastery of warm-cool
          simultaneous contrast.
          *Mrs. Richard Brinsley Sheridan* (1785–87, National Gallery of Art,
          Washington) — the feathery dissolution of her hair and dress into the
          landscape background is the quintessential Gainsborough edge quality.
          *The Morning Walk* (1785, National Gallery) — the cool silver of her
          dress and his coat unified with the sky through atmospheric feathering.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss

        print(f"  Gainsborough feathery pass  "
              f"(silver={silver_strength:.2f}  feather_spread={feather_spread:.1f}  "
              f"shimmer={shimmer_strength:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Gainsborough feathery pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA channel order: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Luminance ────────────────────────────────────────────────────────
        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── 1. Cool silver-blue push in highlights ───────────────────────────
        # Linear ramp from zero at highlight_thresh to full at lum=1.0.
        # Silver push: boost B, damp R — pearl-grey quality Gainsborough
        # learned from studying Van Dyck's silk passages.
        hi_mask = lum > highlight_thresh
        hi_ramp = _np.where(hi_mask,
                            _np.clip((lum - highlight_thresh)
                                     / (1.0 - highlight_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(hi_mask,
                          _np.clip(r_out - silver_strength * 0.45 * hi_ramp, 0.0, 1.0),
                          r_out)
        b_out = _np.where(hi_mask,
                          _np.clip(b_out + silver_strength * 0.55 * hi_ramp, 0.0, 1.0),
                          b_out)

        # ── 2. Feathery edge dissolution ──────────────────────────────────────
        # Detect edges via Sobel gradient magnitude, then apply a
        # cross-edge Gaussian blur proportional to edge strength.
        # The blur is applied independently per channel so colour at
        # the edge bleeds laterally — simulating the tapered "feather"
        # where the final stroke tip breaks and dissolves.
        if feather_spread > 0.1:
            # Luminance Sobel for edge detection
            sobel_x = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]],
                                 dtype=_np.float32)
            sobel_y = _np.array([[-1, -2, -1], [0, 0, 0], [1, 2, 1]],
                                 dtype=_np.float32)
            from scipy.ndimage import convolve as _conv
            gx = _conv(lum, sobel_x, mode='reflect')
            gy = _conv(lum, sobel_y, mode='reflect')
            edge_mag = _np.sqrt(gx * gx + gy * gy)
            edge_mag = _np.clip(edge_mag / (edge_mag.max() + 1e-6), 0.0, 1.0)

            # Blurred versions of each channel
            r_blurred = _gauss(r_out, sigma=feather_spread, mode='reflect')
            g_blurred = _gauss(g_out, sigma=feather_spread, mode='reflect')
            b_blurred = _gauss(b_out, sigma=feather_spread, mode='reflect')

            # Blend sharpened vs. blurred based on edge strength —
            # strong edges dissolve most; interior stays crisp.
            feather_w = _np.clip(edge_mag * 0.80, 0.0, 1.0)
            r_out = r_out * (1.0 - feather_w) + r_blurred * feather_w
            g_out = g_out * (1.0 - feather_w) + g_blurred * feather_w
            b_out = b_out * (1.0 - feather_w) + b_blurred * feather_w

        # ── 3. Fluid midtone shimmer ─────────────────────────────────────────
        # For each mid-luminance pixel, replace its R and B with a value
        # sampled from a small horizontal neighbourhood (±4px), weighted by
        # a random shift.  This mimics the optical streaming quality of very
        # thin, liquid oil paint that has not fully set — a horizontal
        # "aliveness" in the mid-tones.
        if shimmer_strength > 0.0:
            # Build shifted versions ±3px horizontally
            shift_l = _np.roll(r_f, -3, axis=1)   # left shift
            shift_r = _np.roll(r_f,  3, axis=1)   # right shift
            shift_bl = _np.roll(b_f, -3, axis=1)
            shift_br = _np.roll(b_f,  3, axis=1)

            # Random per-pixel blend weights in midtone zone
            rng_arr = _np.random.RandomState(42).uniform(
                0.0, shimmer_strength, size=(h, w)).astype(_np.float32)

            mt_mask = (lum >= midtone_lo) & (lum <= midtone_hi)
            mt_ramp = _np.zeros((h, w), dtype=_np.float32)
            mt_range = max(midtone_hi - midtone_lo, 1e-6)
            mt_t = _np.clip((lum - midtone_lo) / mt_range, 0.0, 1.0)
            mt_ramp = _np.where(mt_mask, _np.sin(_np.pi * mt_t), 0.0)

            # Blend the shifted samples in at shimmer weight
            shimmer_r = (shift_l + shift_r) * 0.5
            shimmer_b = (shift_bl + shift_br) * 0.5
            w_mt = rng_arr * mt_ramp
            r_out = _np.clip(r_out * (1.0 - w_mt) + shimmer_r * w_mt, 0.0, 1.0)
            b_out = _np.clip(b_out * (1.0 - w_mt) + shimmer_b * w_mt, 0.0, 1.0)

        # ── 4. Cool atmospheric haze in shadows ──────────────────────────────
        # Ramp from full at lum=0 down to zero at shadow_thresh.
        # Cool haze: boost B, damp R — English cloudy-sky quality in shadows.
        sh_mask = lum < shadow_thresh
        sh_ramp = _np.where(sh_mask,
                            _np.clip((shadow_thresh - lum)
                                     / (shadow_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(sh_mask,
                          _np.clip(r_out - shadow_haze * 0.50 * sh_ramp, 0.0, 1.0),
                          r_out)
        b_out = _np.where(sh_mask,
                          _np.clip(b_out + shadow_haze * 0.60 * sh_ramp, 0.0, 1.0),
                          b_out)

        # ── Blend adjusted layer back at `opacity` ───────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        n_highlight = int(hi_mask.sum())
        n_shadow    = int(sh_mask.sum())
        n_midtone   = int(mt_mask.sum()) if shimmer_strength > 0.0 else 0
        print(f"    Gainsborough feathery pass complete  "
              f"(highlight={n_highlight}px  midtone={n_midtone}px  "
              f"shadow={n_shadow}px)")

    # ─────────────────────────────────────────────────────────────────────────
    # homer_marine_clarity_pass — Winslow Homer American Realism / Marine
    # ─────────────────────────────────────────────────────────────────────────

    def homer_marine_clarity_pass(
        self,
        *,
        highlight_lift: float = 0.12,
        shadow_cool: float = 0.10,
        contrast_strength: float = 0.08,
        wash_luminosity: float = 0.06,
        highlight_thresh: float = 0.72,
        shadow_thresh: float = 0.35,
        opacity: float = 0.72,
    ) -> None:
        """
        Winslow Homer marine clarity pass (session 41 artist pass).

        Homer's Atlantic seascapes and genre paintings are defined by four
        qualities that this pass approximates:

        1. **Brilliant maritime highlight lift** — Near-white light striking
           wave crests, sails, and lit figure tops is pushed higher and
           slightly warmer (warm ivory, not the cool silver of Gainsborough).
           R and G channels lift proportionally in the brightest zone, giving
           the sensation of glittering Atlantic noon-sun.

        2. **Cool Prussian shadow** — Shadow zones receive a strong B boost
           and R damp, pushing them toward the deep slate-blue of the North
           Atlantic in overcast weather.  Homer's shadows are cold and deep —
           the opposite of Rembrandt's warm amber shadow glow.

        3. **Tonal contrast push** — Homer separated light from dark decisively
           (inspired by Japanese woodblock prints).  A gentle S-curve is applied
           to the luminance channel: values above the midpoint are lifted, values
           below are pushed down, increasing the tonal spread without clipping.

        4. **Transparent wash luminosity** — In the light and midtone zones,
           the paint is treated as though it were thin watercolour over a white
           ground: saturation is very slightly reduced (transparent pigment reads
           less saturated than opaque body colour) and luminance is lifted subtly
           to simulate the ground glowing through the pigment film.

        All four adjustments composite back at ``opacity`` over the original
        canvas, preserving the underlying painterly layer beneath.

        Parameters
        ----------
        highlight_lift     : strength of the warm ivory push in highlights
        shadow_cool        : strength of the cool Prussian push in shadows
        contrast_strength  : amplitude of the tonal S-curve contrast boost
        wash_luminosity    : luminance lift in the midtone / light zones
        highlight_thresh   : luminance above which the highlight lift begins
        shadow_thresh      : luminance below which the cool shadow push begins
        opacity            : global blend weight of the entire adjustment
                             (0 = noop, 1 = full replacement)

        Notes
        -----
        Call this AFTER the main style passes and BEFORE the final glaze/finish.
        Most effective on paintings with a near-white ground where the white
        support is already contributing luminosity through thin paint layers.

        Famous works to study:
          *Breezing Up (A Fair Wind)* (1876, National Gallery of Art) — his
          most beloved oil; the warm ivory of the sails against the cool
          blue-green sea is the definitive Homer warm-cool contrast.
          *The Life Line* (1884, Philadelphia Museum of Art) — the orange
          rescue line against stormy blue-grey sea; tonal clarity at its peak.
          *Fog Warning* (1885, MFA Boston) — a lone fisherman in a dory,
          fog-grey distance, the sea almost black in the near-field troughs.
        """
        import numpy as _np

        print(f"  Homer marine clarity pass  "
              f"(highlight_lift={highlight_lift:.2f}  shadow_cool={shadow_cool:.2f}  "
              f"contrast={contrast_strength:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Homer marine clarity pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA channel order: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Luminance ─────────────────────────────────────────────────────────
        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── 1. Brilliant maritime highlight lift ──────────────────────────────
        # Linear ramp from zero at highlight_thresh to full at lum=1.0.
        # Warm ivory push: lift R and G (warm white), slightly boost B less —
        # maritime noon light is warm, not the cool silver of northern European sky.
        hi_mask = lum > highlight_thresh
        hi_ramp = _np.where(hi_mask,
                            _np.clip((lum - highlight_thresh)
                                     / (1.0 - highlight_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(hi_mask,
                          _np.clip(r_out + highlight_lift * 0.55 * hi_ramp, 0.0, 1.0),
                          r_out)
        g_out = _np.where(hi_mask,
                          _np.clip(g_out + highlight_lift * 0.40 * hi_ramp, 0.0, 1.0),
                          g_out)
        b_out = _np.where(hi_mask,
                          _np.clip(b_out + highlight_lift * 0.15 * hi_ramp, 0.0, 1.0),
                          b_out)

        # ── 2. Cool Prussian shadow push ──────────────────────────────────────
        # Ramp from full at lum=0 down to zero at shadow_thresh.
        # Atlantic cold: strong B boost, damp R — the opposite of warm Baroque shadow.
        sh_mask = lum < shadow_thresh
        sh_ramp = _np.where(sh_mask,
                            _np.clip((shadow_thresh - lum)
                                     / (shadow_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(sh_mask,
                          _np.clip(r_out - shadow_cool * 0.55 * sh_ramp, 0.0, 1.0),
                          r_out)
        b_out = _np.where(sh_mask,
                          _np.clip(b_out + shadow_cool * 0.65 * sh_ramp, 0.0, 1.0),
                          b_out)

        # ── 3. Tonal contrast S-curve ─────────────────────────────────────────
        # Simple cubic S-curve centred at 0.5:
        #   lum_new = lum + contrast_strength * sin(pi * lum) * (lum - 0.5)
        # Pixels above 0.5 lift; pixels below 0.5 drop.
        # Applied to all channels proportionally (preserves hue).
        s_curve = contrast_strength * _np.sin(_np.pi * lum) * (lum - 0.5)
        r_out = _np.clip(r_out + s_curve, 0.0, 1.0)
        g_out = _np.clip(g_out + s_curve, 0.0, 1.0)
        b_out = _np.clip(b_out + s_curve, 0.0, 1.0)

        # ── 4. Transparent wash luminosity in midtones / lights ───────────────
        # For pixels above shadow_thresh (mid-to-bright zone), apply a small
        # luminance lift simulating thin transparent pigment over a white ground.
        # The lift is proportional to distance from shadow_thresh — darkest
        # midtones get the least lift; highlights already lifted in step 1.
        wash_zone = lum >= shadow_thresh
        wash_ramp = _np.where(wash_zone,
                              _np.clip((lum - shadow_thresh)
                                       / (1.0 - shadow_thresh + 1e-6) * 0.60,
                                       0.0, 1.0),
                              0.0)
        lift = wash_luminosity * wash_ramp
        r_out = _np.clip(r_out + lift, 0.0, 1.0)
        g_out = _np.clip(g_out + lift, 0.0, 1.0)
        b_out = _np.clip(b_out + lift, 0.0, 1.0)

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        n_highlight = int(hi_mask.sum())
        n_shadow    = int(sh_mask.sum())
        print(f"    Homer marine clarity pass complete  "
              f"(highlight={n_highlight}px  shadow={n_shadow}px)")

    # ─────────────────────────────────────────────────────────────────────────
    # fragonard_bravura_pass — session 42 artist pass
    # ─────────────────────────────────────────────────────────────────────────

    def fragonard_bravura_pass(
        self,
        *,
        warmth_strength: float = 0.08,
        highlight_bloom: float = 0.06,
        shadow_warm: float = 0.05,
        highlight_thresh: float = 0.65,
        shadow_thresh: float = 0.30,
        opacity: float = 0.70,
    ) -> None:
        """
        Jean-Honoré Fragonard bravura pass (session 42 artist pass).

        Fragonard's French Rococo canvases are defined by three tonal qualities
        that this pass approximates:

        1. **Warm highlight bloom** — In bright zones (lum > highlight_thresh),
           highlights are pushed toward a creamy warm tone rather than the cool
           silver of northern European painting.  R and G channels lift; B is
           gently boosted only slightly (warm cream, not cold white).  This
           gives the sensation of afternoon garden light striking silk and flesh
           rather than cold studio daylight.

        2. **Rosy peach midtone warmth** — In the middle zone
           (shadow_thresh ≤ lum ≤ highlight_thresh), a gentle warmth push
           toward peach-rose is applied: R lifts slightly, B is subtly damped.
           Fragonard's flesh tones are warm and rosy — not the cool ivory of
           Academic painting, not the amber of Rembrandt, but a light garden-
           afternoon peach.

        3. **Warm shadow damping** — In shadow zones (lum < shadow_thresh),
           any cool blue is gently damped and R is slightly boosted, keeping
           shadows in warm umber-brown territory.  Fragonard's shadows are warm
           throughout — the contrast in his work is light warm versus dark warm,
           never the warm-light/cool-shadow convention of Academic Realism.

        All three adjustments composite back at ``opacity`` over the original
        canvas, preserving the underlying painterly layer.

        Parameters
        ----------
        warmth_strength   : strength of the rose-peach push in midtones
        highlight_bloom   : extra warm-cream boost in highlight zones
        shadow_warm       : strength of the warm shadow damping (reduces B in darks)
        highlight_thresh  : luminance above which highlight bloom begins
        shadow_thresh     : luminance below which shadow warmth applies
        opacity           : global blend weight of the entire adjustment
                            (0 = noop, 1 = full replacement)

        Notes
        -----
        Call this AFTER the main style passes and BEFORE the final glaze/finish.
        Pairs well with a warm honey-amber glaze (0.88, 0.78, 0.62) applied after.

        Famous works to study:
          *The Swing* (1767, Wallace Collection, London) — the definitive
          Fragonard; the pink-silk dress and foliage are lit with warm cream-
          gold afternoon sun; shadows are warm leafy green-umber, never cool.
          *Young Girl Reading* (c. 1776, National Gallery of Art, Washington) —
          the yellow dress in warm afternoon light; a masterclass in warm
          highlight and warm shadow coexisting without any cool tone.
          *The Bathers* (c. 1765, Louvre) — luminous rose-cream flesh bathed in
          dappled warm light; the water shadows are warm olive, not cool blue.
        """
        import numpy as _np

        print(f"  Fragonard bravura pass  "
              f"(warmth={warmth_strength:.2f}  hi_bloom={highlight_bloom:.2f}  "
              f"shadow_warm={shadow_warm:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Fragonard bravura pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA channel order: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Luminance ─────────────────────────────────────────────────────────
        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── 1. Warm highlight bloom ───────────────────────────────────────────
        # Linear ramp from zero at highlight_thresh to full at lum=1.0.
        # Push toward warm cream: R lifts most, G lifts moderately, B lifts
        # just slightly — creamy warm, not silvery cool.
        hi_mask = lum > highlight_thresh
        hi_ramp = _np.where(hi_mask,
                            _np.clip((lum - highlight_thresh)
                                     / (1.0 - highlight_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(hi_mask,
                          _np.clip(r_out + highlight_bloom * 0.70 * hi_ramp, 0.0, 1.0),
                          r_out)
        g_out = _np.where(hi_mask,
                          _np.clip(g_out + highlight_bloom * 0.50 * hi_ramp, 0.0, 1.0),
                          g_out)
        b_out = _np.where(hi_mask,
                          _np.clip(b_out + highlight_bloom * 0.20 * hi_ramp, 0.0, 1.0),
                          b_out)

        # ── 2. Rosy peach midtone warmth ─────────────────────────────────────
        # The midtone band: shadow_thresh ≤ lum ≤ highlight_thresh.
        # Gently warm toward peach-rose: lift R, damp B slightly.
        mid_mask = (lum >= shadow_thresh) & (lum <= highlight_thresh)
        # Weight peaks at the centre of the midtone band, tapering to zero at edges.
        mid_centre = (shadow_thresh + highlight_thresh) * 0.5
        mid_half   = (highlight_thresh - shadow_thresh) * 0.5 + 1e-6
        mid_weight = _np.where(mid_mask,
                               1.0 - _np.abs(lum - mid_centre) / mid_half,
                               0.0)
        r_out = _np.where(mid_mask,
                          _np.clip(r_out + warmth_strength * 0.55 * mid_weight, 0.0, 1.0),
                          r_out)
        b_out = _np.where(mid_mask,
                          _np.clip(b_out - warmth_strength * 0.30 * mid_weight, 0.0, 1.0),
                          b_out)

        # ── 3. Warm shadow damping ────────────────────────────────────────────
        # In shadows (lum < shadow_thresh): slightly boost R, damp B.
        # This keeps Fragonard's shadows warm umber-brown rather than cool Prussian.
        sh_mask = lum < shadow_thresh
        sh_ramp = _np.where(sh_mask,
                            _np.clip((shadow_thresh - lum)
                                     / (shadow_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(sh_mask,
                          _np.clip(r_out + shadow_warm * 0.40 * sh_ramp, 0.0, 1.0),
                          r_out)
        b_out = _np.where(sh_mask,
                          _np.clip(b_out - shadow_warm * 0.45 * sh_ramp, 0.0, 1.0),
                          b_out)

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        n_highlight = int(hi_mask.sum())
        n_midtone   = int(mid_mask.sum())
        n_shadow    = int(sh_mask.sum())
        print(f"    Fragonard bravura pass complete  "
              f"(highlight={n_highlight}px  midtone={n_midtone}px  shadow={n_shadow}px)")

    # ─────────────────────────────────────────────────────────────────────────
    # renoir_luminous_warmth_pass — Pierre-Auguste Renoir artist pass
    # ─────────────────────────────────────────────────────────────────────────

    def renoir_luminous_warmth_pass(
        self,
        *,
        saturation_boost: float = 0.18,
        rose_warmth: float = 0.07,
        highlight_glow: float = 0.06,
        highlight_thresh: float = 0.62,
        shadow_thresh: float = 0.28,
        opacity: float = 0.72,
    ) -> None:
        """
        Pierre-Auguste Renoir luminous warmth pass (artist pass).

        Renoir's French Impressionist canvases are defined by three tonal qualities
        that this pass approximates:

        1. **Chromatic saturation boost** — Renoir's palette runs at maximum
           luminous intensity across all hue zones.  The saturation of every
           non-shadow pixel is lifted toward full chroma, giving the canvas its
           characteristic vivid, jewel-like quality.  The boost is strongest in
           the midtone band (shadows and near-white highlights are less affected
           to avoid cartoon-like oversaturation).

        2. **Rose-peach midtone warmth** — In the midtone band
           (shadow_thresh ≤ lum ≤ highlight_thresh), R is lifted and B is
           gently damped, pushing toward Renoir's signature warm rose-peach.
           He explicitly rejected the Impressionist convention of cool violet
           shadows; his darks remain warm throughout.

        3. **Luminous warm highlight glow** — In bright zones
           (lum > highlight_thresh), highlights are pushed toward a warm
           cream-gold tone: R and G lift, B lifts only slightly.  This replicates
           the characteristic Renoir bloom — warm afternoon sunlight striking
           white lace, pale skin, or gleaming hair — as opposed to the cool
           silver of Northern European painting.

        All three adjustments composite back at ``opacity`` over the original
        canvas, preserving the underlying painterly layer structure.

        Parameters
        ----------
        saturation_boost : how much saturation is lifted in mid-lum zones
                           (0 = no change, 1 = full saturation clamp at 1.0)
        rose_warmth      : strength of the rose-peach push in midtones
        highlight_glow   : warm-cream boost amplitude in highlight zones
        highlight_thresh : luminance above which highlight glow begins
        shadow_thresh    : luminance below which warm push tapers off
        opacity          : global blend weight of the entire adjustment
                           (0 = noop, 1 = full replacement)

        Notes
        -----
        Call this AFTER the main style passes (block_in, build_form) and
        BEFORE the final glaze/finish.  Pairs well with a warm peach-rose
        glaze (0.90, 0.72, 0.62) applied afterward.

        Famous works to study:
          *Dance at Le Moulin de la Galette* (1876, Musée d'Orsay) — dappled
          afternoon garden light; warm rose-cream skin dabs interleaved with
          cool blue-grey shadow strokes; saturation maximised throughout.
          *Luncheon of the Boating Party* (1880–1881, Phillips Collection) —
          the pink-cheeked faces and richly coloured drapery; warm golden light
          on every highlight; not a cool tone in the entire canvas.
          *Two Sisters (On the Terrace)* (1881, Art Institute of Chicago) —
          the warm spring green foliage and rose-peach flesh; highlights are
          cream-warm, shadows are warm ochre-umber; vivid chromatic punch.
        """
        import colorsys as _cs
        import numpy as _np

        print(f"  Renoir luminous warmth pass  "
              f"(sat_boost={saturation_boost:.2f}  warmth={rose_warmth:.2f}  "
              f"hi_glow={highlight_glow:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Renoir luminous warmth pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA channel order: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Luminance ─────────────────────────────────────────────────────────
        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── 1. Chromatic saturation boost ─────────────────────────────────────
        # Convert each pixel to HSV, lift S by saturation_boost, convert back.
        # The boost is weighted by a bell curve centred in the midtone band so
        # very dark shadows and near-white highlights are less affected.
        # We implement this with a fast vectorised HSV round-trip via colorsys
        # logic expressed as array operations (avoids slow per-pixel loops).

        # HSV conversion (vectorised):
        cmax = _np.maximum(_np.maximum(r_out, g_out), b_out)
        cmin = _np.minimum(_np.minimum(r_out, g_out), b_out)
        delta = cmax - cmin

        # Value (V) = cmax
        v_ch = cmax

        # Saturation (S) = delta / cmax  (0 when cmax == 0)
        s_ch = _np.where(cmax > 1e-6, delta / (cmax + 1e-6), 0.0)

        # Hue computation (6 segments)
        with _np.errstate(invalid='ignore', divide='ignore'):
            h_seg = _np.zeros_like(r_out)
            mask_r = (cmax == r_out) & (delta > 1e-6)
            mask_g = (cmax == g_out) & (delta > 1e-6)
            mask_b = (cmax == b_out) & (delta > 1e-6)
            h_seg = _np.where(
                mask_r,
                ((g_out - b_out) / (delta + 1e-6)) % 6.0,
                _np.where(
                    mask_g,
                    (b_out - r_out) / (delta + 1e-6) + 2.0,
                    _np.where(
                        mask_b,
                        (r_out - g_out) / (delta + 1e-6) + 4.0,
                        0.0)))
        h_ch = h_seg / 6.0  # normalise to [0, 1]

        # Saturation boost weight — peaks at the midtone centre, zero at extremes
        mid_centre = (shadow_thresh + highlight_thresh) * 0.5
        mid_half   = (highlight_thresh - shadow_thresh) * 0.5 + 1e-6
        sat_weight = _np.clip(1.0 - _np.abs(lum - mid_centre) / (mid_half * 1.4), 0.0, 1.0)
        s_new = _np.clip(s_ch + saturation_boost * sat_weight, 0.0, 1.0)

        # HSV → RGB back-conversion (vectorised)
        h6   = h_ch * 6.0
        i    = _np.floor(h6).astype(_np.int32) % 6
        f    = h6 - _np.floor(h6)
        p_v  = v_ch * (1.0 - s_new)
        q_v  = v_ch * (1.0 - s_new * f)
        t_v  = v_ch * (1.0 - s_new * (1.0 - f))

        r_sat = _np.select(
            [i == 0, i == 1, i == 2, i == 3, i == 4, i == 5],
            [v_ch,   q_v,    p_v,    p_v,    t_v,    v_ch],
            default=r_out)
        g_sat = _np.select(
            [i == 0, i == 1, i == 2, i == 3, i == 4, i == 5],
            [t_v,    v_ch,   v_ch,   q_v,    p_v,    p_v],
            default=g_out)
        b_sat = _np.select(
            [i == 0, i == 1, i == 2, i == 3, i == 4, i == 5],
            [p_v,    p_v,    t_v,    v_ch,   v_ch,   q_v],
            default=b_out)

        # Where delta==0 (grey pixels), saturation boost has no effect — keep original
        grey_mask = delta < 1e-6
        r_out = _np.where(grey_mask, r_out, _np.clip(r_sat, 0.0, 1.0))
        g_out = _np.where(grey_mask, g_out, _np.clip(g_sat, 0.0, 1.0))
        b_out = _np.where(grey_mask, b_out, _np.clip(b_sat, 0.0, 1.0))

        # ── 2. Rose-peach midtone warmth ──────────────────────────────────────
        # In the midtone band: lift R toward rose-peach, damp B slightly.
        # Weight peaks at the midtone centre.
        mid_mask = (lum >= shadow_thresh) & (lum <= highlight_thresh)
        mid_w    = _np.where(mid_mask,
                             1.0 - _np.abs(lum - mid_centre) / (mid_half + 1e-6),
                             0.0)
        r_out = _np.where(mid_mask,
                          _np.clip(r_out + rose_warmth * 0.60 * mid_w, 0.0, 1.0),
                          r_out)
        b_out = _np.where(mid_mask,
                          _np.clip(b_out - rose_warmth * 0.28 * mid_w, 0.0, 1.0),
                          b_out)

        # Shadow zone: keep warm — gentle R lift, B damp to prevent cool invasion
        sh_mask = lum < shadow_thresh
        sh_ramp = _np.where(sh_mask,
                            _np.clip((shadow_thresh - lum) / (shadow_thresh + 1e-6),
                                     0.0, 1.0),
                            0.0)
        r_out = _np.where(sh_mask,
                          _np.clip(r_out + rose_warmth * 0.25 * sh_ramp, 0.0, 1.0),
                          r_out)
        b_out = _np.where(sh_mask,
                          _np.clip(b_out - rose_warmth * 0.35 * sh_ramp, 0.0, 1.0),
                          b_out)

        # ── 3. Luminous warm highlight glow ──────────────────────────────────
        # In bright zones: push toward warm cream-gold.
        # R lifts most, G moderately, B just slightly — warm cream, not cold silver.
        hi_mask = lum > highlight_thresh
        hi_ramp = _np.where(hi_mask,
                            _np.clip((lum - highlight_thresh)
                                     / (1.0 - highlight_thresh + 1e-6), 0.0, 1.0),
                            0.0)
        r_out = _np.where(hi_mask,
                          _np.clip(r_out + highlight_glow * 0.72 * hi_ramp, 0.0, 1.0),
                          r_out)
        g_out = _np.where(hi_mask,
                          _np.clip(g_out + highlight_glow * 0.48 * hi_ramp, 0.0, 1.0),
                          g_out)
        b_out = _np.where(hi_mask,
                          _np.clip(b_out + highlight_glow * 0.18 * hi_ramp, 0.0, 1.0),
                          b_out)

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        n_highlight = int(hi_mask.sum())
        n_midtone   = int(mid_mask.sum())
        n_shadow    = int(sh_mask.sum())
        print(f"    Renoir luminous warmth pass complete  "
              f"(highlight={n_highlight}px  midtone={n_midtone}px  shadow={n_shadow}px)")

    # ─────────────────────────────────────────────────────────────────────────
    # wet_on_wet_bleeding_pass — session 41 random improvement
    # ─────────────────────────────────────────────────────────────────────────

    def wet_on_wet_bleeding_pass(
        self,
        *,
        bleed_radius: float = 2.5,
        bleed_strength: float = 0.18,
        edge_sensitivity: float = 0.55,
        opacity: float = 0.65,
    ) -> None:
        """
        Wet-on-wet paint bleeding pass (session 41 random improvement).

        When oil paint is applied to a still-wet canvas, pigment migrates
        across colour boundaries — colours from adjacent zones partially
        invade each other, softening the boundary into a transitional blended
        strip while leaving the interior of each colour zone intact.  This is
        fundamentally different from the global blur of sfumato_veil_pass:
        bleeding is *localised to detected colour boundaries* and only mixes
        the colours that are physically adjacent.

        Algorithm
        ---------
        1. **Edge detection** — Sobel gradient magnitude on the luminance
           channel identifies zones of high colour change (boundary pixels).
        2. **Neighbourhood blend** — At each boundary pixel, the colour is
           replaced with a Gaussian-blurred version (radius = bleed_radius),
           simulating pigment spreading outward from the loaded brush.
        3. **Selective composition** — The blended result is composited back
           only in proportion to the local edge strength × bleed_strength,
           so the interior of each colour zone is untouched — only the
           boundary zone softens.
        4. **Final opacity** — The entire layer is blended at ``opacity``
           over the original so the effect is subtle and controllable.

        The result gives the canvas a "freshly painted, still-wet" quality:
        edges that were previously hard become softly transitional, as though
        a master's palette-knife has just laid adjacent colours wet-to-wet
        and the pigments are beginning to move into each other.

        Parameters
        ----------
        bleed_radius      : Gaussian sigma (pixels) for the cross-boundary spread
        bleed_strength    : how strongly the blurred colour replaces the
                            sharp edge colour (0 = no bleed, 1 = full replace)
        edge_sensitivity  : normalised threshold controlling which gradient
                            magnitudes register as boundaries (0.0 = very
                            sensitive / all edges bleed; 1.0 = only strongest
                            edges bleed)
        opacity           : global blend weight of the entire pass
                            (0 = noop, 1 = full replacement of original)

        Notes
        -----
        Best applied AFTER the main form-building passes (block_in, build_form)
        and BEFORE the final highlights (place_lights) — it softens the mid-
        range boundary edges without removing the fine highlight details added
        later.  Use low opacity (0.4–0.7) for a subtle living-paint quality;
        high opacity (0.9+) produces an overly blended academic-school effect.

        References
        ----------
        Observable in: Rubens alla-prima passages, Sargent's wet-paper
        watercolours, Zorn's fluid oil portraits — all artists who prized the
        chromatic liveliness of paint that had not yet dried.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss, convolve as _conv

        print(f"  Wet-on-wet bleeding pass  "
              f"(bleed_radius={bleed_radius:.1f}  strength={bleed_strength:.2f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Wet-on-wet bleeding pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Luminance for edge detection ──────────────────────────────────────
        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── Sobel edge magnitude ──────────────────────────────────────────────
        sobel_x = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]],
                             dtype=_np.float32)
        sobel_y = _np.array([[-1, -2, -1], [0, 0, 0], [1, 2, 1]],
                             dtype=_np.float32)
        gx = _conv(lum, sobel_x, mode='reflect')
        gy = _conv(lum, sobel_y, mode='reflect')
        edge_mag = _np.sqrt(gx * gx + gy * gy)

        # Normalise to [0, 1]
        edge_max = edge_mag.max()
        if edge_max > 1e-6:
            edge_mag = edge_mag / edge_max
        else:
            # Flat canvas — nothing to bleed
            print(f"    Wet-on-wet bleeding pass complete (flat canvas — no edges detected)")
            return

        # Apply edge sensitivity threshold: only edges above the threshold
        # contribute; ramp from threshold to 1.0 for smooth roll-off.
        edge_weight = _np.clip(
            (edge_mag - (1.0 - edge_sensitivity)) / (edge_sensitivity + 1e-6),
            0.0, 1.0)

        # ── Gaussian-blurred versions of each channel ─────────────────────────
        # This is the "bled" colour — what adjacent pigments look like after
        # migrating across the boundary into the current pixel's zone.
        r_bleed = _gauss(r_f, sigma=bleed_radius, mode='reflect')
        g_bleed = _gauss(g_f, sigma=bleed_radius, mode='reflect')
        b_bleed = _gauss(b_f, sigma=bleed_radius, mode='reflect')

        # ── Selective blending at boundary zones ──────────────────────────────
        # w_bleed: how much of the blurred colour replaces the original,
        #          scaled by edge_weight and bleed_strength.
        w_bleed = _np.clip(edge_weight * bleed_strength, 0.0, 1.0)

        r_out = r_f * (1.0 - w_bleed) + r_bleed * w_bleed
        g_out = g_f * (1.0 - w_bleed) + g_bleed * w_bleed
        b_out = b_f * (1.0 - w_bleed) + b_bleed * w_bleed

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        n_edge = int((edge_weight > 0.01).sum())
        print(f"    Wet-on-wet bleeding pass complete  "
              f"(boundary pixels={n_edge}  bleed_radius={bleed_radius:.1f}px)")

    # ─────────────────────────────────────────────────────────────────────────
    # gentileschi_dramatic_flesh_pass — inspired by Artemisia Gentileschi
    # ─────────────────────────────────────────────────────────────────────────

    def gentileschi_dramatic_flesh_pass(
        self,
        *,
        shadow_deepen:    float = 0.20,
        shadow_warmth:    float = 0.12,
        penumbra_warmth:  float = 0.09,
        highlight_gold:   float = 0.10,
        shadow_thresh:    float = 0.30,
        highlight_thresh: float = 0.68,
        opacity:          float = 0.75,
    ) -> None:
        """
        Artemisia Gentileschi dramatic flesh pass (artist pass).

        Gentileschi inherited Caravaggio's tenebrism but departed from it in one
        defining way: her shadows are *warm*.  Where Caravaggio's void is cold —
        a near-black that has no temperature — Gentileschi's darks carry a deep
        umber-brown warmth absorbed from her dark ground and amber glazes.  This
        pass replicates that quality by operating separately on three tonal zones:

        1. **Shadow deepening** — In the darkest zone (lum < shadow_thresh), value
           is pulled further down toward deep shadow, but simultaneously warmed:
           R is lifted relative to G and B.  The result is warm umber-brown dark
           rather than cold near-black — the defining difference between Gentileschi's
           emotional tenebrism and Caravaggio's nihilistic void.

        2. **Penumbra warmth** — In the lower half of the midtone zone (shadow_thresh
           ≤ lum ≤ midtone centre), the colour is pushed toward a warm olive-amber.
           This is the *penumbra* — the zone of partial shadow — which Gentileschi
           glazed with warm amber to create an intermediate transition that reads as
           firelight absorbed into flesh.  It is distinct from both the warm golden
           highlight above it and the warm umber shadow below.

        3. **Candlelit highlight gold** — In the brightest zone (lum > highlight_thresh),
           highlights are warmed toward amber-gold: R lifts most, G moderately, B
           barely.  Gentileschi's highlights are not the cool silver of northern
           painting or the ivory of Academic painters — they carry the warm golden
           quality of single-source candlelight or torch illumination.

        All three adjustments are composited back at ``opacity`` over the original
        canvas, preserving the underlying layer structure.

        Parameters
        ----------
        shadow_deepen    : how strongly the dark zone is deepened (value pulled down)
        shadow_warmth    : warm umber push in the shadow zone (lifts R relative to G/B)
        penumbra_warmth  : olive-amber push in the lower midtone / penumbra zone
        highlight_gold   : warm amber-gold lift in the bright highlight zone
        shadow_thresh    : luminance boundary below which shadow adjustments apply
        highlight_thresh : luminance boundary above which highlight adjustments apply
        opacity          : global blend weight (0 = noop, 1 = full replacement)

        Notes
        -----
        Call this AFTER the main form-building passes (block_in, build_form) and
        BEFORE the final highlights (place_lights).  Pairs well with a warm
        amber-umber glaze (0.58, 0.38, 0.16) applied afterward.

        The penumbra zone (shadow_thresh to midtone centre) is where this pass
        does its most distinctive work — the olive-warm half-shadow is the
        quality most absent from generic tenebrism implementations and most
        characteristic of Gentileschi's specific style.

        Famous works to study:
          *Judith Slaying Holofernes* (c. 1614–1620, Uffizi) — the lit side of
          Judith's arm and chest gleam with warm golden impasto; her shadow side
          falls into deep warm umber, not cold black; the penumbra zone between
          them carries a warm olive-amber transition.
          *Self-Portrait as the Allegory of Painting* (c. 1638–1639, Royal
          Collection) — the lit face and arm show warm candlelit gold; the
          shadow half is warm umber-brown with visible amber glaze in the
          half-shadow.
        """
        import numpy as _np

        print(f"  Gentileschi dramatic flesh pass  "
              f"(shadow_deepen={shadow_deepen:.2f}  shadow_warmth={shadow_warmth:.2f}  "
              f"penumbra_warmth={penumbra_warmth:.2f}  highlight_gold={highlight_gold:.2f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Gentileschi dramatic flesh pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA channel order: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Luminance ─────────────────────────────────────────────────────────
        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── Thresholds and zone midpoint ──────────────────────────────────────
        mid_centre = (shadow_thresh + highlight_thresh) * 0.5
        penumbra_top = mid_centre  # penumbra warmth applies from shadow_thresh to mid_centre

        # ── 1. Shadow zone: deepen and warm toward umber ──────────────────────
        # Pixels darker than shadow_thresh are pulled deeper (shadow_deepen) and
        # simultaneously warmed (shadow_warmth): R lifted, G/B damped.
        # The warm push is proportional to how deep into the shadow the pixel is,
        # so the darkest pixels get the most warmth (they need it most to escape
        # cold-black appearance).
        sh_mask = lum < shadow_thresh
        sh_ramp = _np.where(
            sh_mask,
            _np.clip((shadow_thresh - lum) / (shadow_thresh + 1e-6), 0.0, 1.0),
            0.0)  # peaks at lum=0, zero at lum=shadow_thresh

        # Deepen: pull all channels down proportionally
        deepen_factor = 1.0 - shadow_deepen * sh_ramp
        r_out = _np.where(sh_mask, r_out * deepen_factor, r_out)
        g_out = _np.where(sh_mask, g_out * deepen_factor, g_out)
        b_out = _np.where(sh_mask, b_out * deepen_factor, b_out)

        # Warm umber push: after deepening, lift R, damp B relative to mid
        # — turns the deepened tone from cold grey-black to warm umber-brown
        r_out = _np.where(sh_mask,
                          _np.clip(r_out + shadow_warmth * 0.70 * sh_ramp, 0.0, 1.0),
                          r_out)
        g_out = _np.where(sh_mask,
                          _np.clip(g_out + shadow_warmth * 0.20 * sh_ramp, 0.0, 1.0),
                          g_out)
        b_out = _np.where(sh_mask,
                          _np.clip(b_out - shadow_warmth * 0.30 * sh_ramp, 0.0, 1.0),
                          b_out)

        # ── 2. Penumbra zone: olive-amber warmth ──────────────────────────────
        # The lower midtone band (shadow_thresh to mid_centre) — where Gentileschi
        # applied warm amber glazes to create the characteristic olive-warm half-shadow.
        # This is the most distinctive quality of her flesh rendering.
        pen_mask = (lum >= shadow_thresh) & (lum < penumbra_top)
        pen_ramp = _np.where(
            pen_mask,
            # peaks midway between shadow_thresh and penumbra_top; zero at both ends
            1.0 - _np.abs(lum - (shadow_thresh + penumbra_top) * 0.5)
                  / ((penumbra_top - shadow_thresh) * 0.5 + 1e-6),
            0.0)
        pen_ramp = _np.clip(pen_ramp, 0.0, 1.0)

        # Olive-amber: R up (warm), G up slightly (olive), B down (remove cool)
        r_out = _np.where(pen_mask,
                          _np.clip(r_out + penumbra_warmth * 0.65 * pen_ramp, 0.0, 1.0),
                          r_out)
        g_out = _np.where(pen_mask,
                          _np.clip(g_out + penumbra_warmth * 0.30 * pen_ramp, 0.0, 1.0),
                          g_out)
        b_out = _np.where(pen_mask,
                          _np.clip(b_out - penumbra_warmth * 0.40 * pen_ramp, 0.0, 1.0),
                          b_out)

        # ── 3. Highlight zone: warm amber-gold lift ───────────────────────────
        # In bright zones above highlight_thresh, warm the highlights toward
        # amber-gold: R lifts most, G moderately, B barely.  Gentileschi's
        # highlights carry the colour of a single warm candle or torch — not
        # the cool silver of northern painting.
        hi_mask = lum > highlight_thresh
        hi_ramp = _np.where(
            hi_mask,
            _np.clip((lum - highlight_thresh) / (1.0 - highlight_thresh + 1e-6),
                     0.0, 1.0),
            0.0)  # zero at lum=highlight_thresh, peaks at lum=1.0

        r_out = _np.where(hi_mask,
                          _np.clip(r_out + highlight_gold * 0.80 * hi_ramp, 0.0, 1.0),
                          r_out)
        g_out = _np.where(hi_mask,
                          _np.clip(g_out + highlight_gold * 0.45 * hi_ramp, 0.0, 1.0),
                          g_out)
        b_out = _np.where(hi_mask,
                          _np.clip(b_out + highlight_gold * 0.08 * hi_ramp, 0.0, 1.0),
                          b_out)

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        n_shadow    = int(sh_mask.sum())
        n_penumbra  = int(pen_mask.sum())
        n_highlight = int(hi_mask.sum())
        print(f"    Gentileschi dramatic flesh pass complete  "
              f"(shadow={n_shadow}px  penumbra={n_penumbra}px  highlight={n_highlight}px)")

    # ─────────────────────────────────────────────────────────────────────────
    # munch_anxiety_swirl_pass — inspired by Edvard Munch
    # ─────────────────────────────────────────────────────────────────────────

    def munch_anxiety_swirl_pass(
        self,
        *,
        n_swirl_strokes:  int   = 320,
        swirl_amplitude:  float = 0.22,
        swirl_frequency:  float = 3.8,
        color_intensity:  float = 0.55,
        bg_only:          bool  = True,
        stroke_opacity:   float = 0.28,
        stroke_size:      float = 9.0,
    ) -> None:
        """
        Munch Anxiety Swirl Pass — Edvard Munch's sinuous background turbulence.

        Munch's defining compositional gesture is the undulating, serpentine
        brushstroke that spirals across the canvas in long curving arcs —
        most famously in "The Scream" (1893), where the entire sky and
        landscape becomes a single churning vortex of anxious energy.  This
        technique dissolves the distinction between figure and environment,
        making the external world an expression of an internal psychological
        state.

        Implementation strategy
        -----------------------
        The pass places a series of long sinusoidal stroke paths across the
        canvas.  Each path is a sine-wave trajectory with randomised phase,
        frequency, and amplitude, oriented at a shallow diagonal to suggest
        the rolling, fjord-scape undulations in Munch's oils.  The colour
        of each stroke is drawn from the Munch palette — blood reds, saffron
        yellows, prussian blues, sickly greens — with per-stroke jitter to
        introduce the characteristic raw, trembling quality of his surface.

        When bg_only=True (the default), strokes are suppressed wherever the
        figure mask is solid, confining the turbulence to the background and
        leaving the portrait subject as a calmer, mask-like presence within
        the swirling landscape.  This matches Munch's portrait practice:
        the sitter is simplified and steady while the world behind them writhes.

        Parameters
        ----------
        n_swirl_strokes : int
            Number of sinusoidal swirl paths to place.  320 produces dense
            coverage; reduce to 180–220 for a looser, more gestural reading.
        swirl_amplitude : float
            Amplitude of the sinusoidal wave as a fraction of canvas height.
            0.22 produces medium-depth undulation; raise to 0.35+ for extreme
            churning, lower to 0.10 for shallow ripples.
        swirl_frequency : float
            Number of complete wave cycles across the canvas width.  3.8
            gives roughly four undulations per stroke — the Munch characteristic
            rhythm.  Higher values produce tighter, more frantic coils.
        color_intensity : float
            Blend weight of the Munch palette colours into the existing canvas.
            0.55 is psychologically vivid without obliterating the underpainting.
            Raise toward 1.0 for maximum expressionist intensity.
        bg_only : bool
            If True, strokes are masked to the background only (suppressed
            where figure mask alpha > 0.5).  Recommended True for portraiture.
        stroke_opacity : float
            Per-stroke opacity in [0, 1].  Lower values (0.20–0.28) build up
            colour gradually as strokes cross; higher values (0.40+) create
            bold individual marks visible from across the room.
        stroke_size : float
            Base brush radius in pixels.  Munch's loaded-brush swirl marks
            are wider than most portrait passes — 9px is appropriate for a
            512×512 canvas; scale proportionally for larger outputs.

        Notes
        -----
        Call AFTER block_in() / build_form() and BEFORE glaze() and finish().
        Pair with a warm crimson-amber glaze (0.65, 0.30, 0.10) at opacity
        0.07–0.10 after this pass to unify the turbulent surface in fever warmth.
        """
        import math as _math
        import numpy as _np
        import cairo as _cairo

        print(f"  Munch anxiety swirl pass  "
              f"(n={n_swirl_strokes}  amp={swirl_amplitude:.2f}  "
              f"freq={swirl_frequency:.1f}  intensity={color_intensity:.2f})…")

        surf = self.canvas.surface
        W    = surf.get_width()
        H    = surf.get_height()

        # ── Munch characteristic palette ──────────────────────────────────────
        munch_colors = [
            (0.82, 0.28, 0.14),   # cadmium-red anxiety
            (0.88, 0.62, 0.18),   # saffron-amber atmospheric warmth
            (0.18, 0.32, 0.52),   # prussian-cobalt cold depth
            (0.42, 0.58, 0.38),   # sickly verdigris
            (0.62, 0.22, 0.35),   # crimson-violet psychic wound
        ]
        n_colors = len(munch_colors)

        # ── Figure mask for bg_only suppression ───────────────────────────────
        fig_mask = self._figure_mask   # (H, W) float32 in [0, 1] or None

        rng = _np.random.default_rng(seed=42)   # deterministic for reproducibility

        strokes_placed = 0
        for _ in range(n_swirl_strokes):
            # Starting y position distributed across full canvas height
            y0_frac = rng.uniform(0.0, 1.0)
            phase   = rng.uniform(0.0, 2.0 * _math.pi)
            # Diagonal angle — Munch's lines rarely run purely horizontal
            angle_deg = rng.uniform(-18.0, 18.0)
            cos_a = _math.cos(_math.radians(angle_deg))
            sin_a = _math.sin(_math.radians(angle_deg))

            # Choose colour with slight jitter
            base_col = munch_colors[rng.integers(0, n_colors)]
            jitter   = rng.uniform(-0.06, 0.06, size=3)
            col = tuple(float(_np.clip(c + j, 0.0, 1.0))
                        for c, j in zip(base_col, jitter))

            # Build sinusoidal path across the canvas
            n_pts   = 32
            pts     = []
            amp_px  = swirl_amplitude * H
            for i in range(n_pts):
                t  = i / (n_pts - 1)          # 0 → 1 across the stroke length
                # Base x progresses across canvas; y follows sine wave
                bx = t * W
                by = y0_frac * H + amp_px * _math.sin(
                    2.0 * _math.pi * swirl_frequency * t + phase
                )
                # Apply rotational tilt
                cx = bx * cos_a - (by - y0_frac * H) * sin_a
                cy = by * cos_a + (bx - 0) * sin_a * 0.08   # subtle rotation
                pts.append((cx, cy))

            # Check whether the stroke midpoint falls in background
            mid_x = int(_np.clip(pts[n_pts // 2][0], 0, W - 1))
            mid_y = int(_np.clip(pts[n_pts // 2][1], 0, H - 1))
            if bg_only and fig_mask is not None:
                if fig_mask[mid_y, mid_x] > 0.50:
                    continue   # Skip — this stroke would cover the figure

            # Draw the swirl path as a series of connected segments
            ctx = self.canvas.ctx
            ctx.save()

            # Scale opacity by color_intensity
            effective_opacity = stroke_opacity * color_intensity

            r_col, g_col, b_col = col
            ctx.set_source_rgba(r_col, g_col, b_col, effective_opacity)
            ctx.set_line_width(stroke_size)
            ctx.set_line_cap(_cairo.LINE_CAP_ROUND)
            ctx.set_line_join(_cairo.LINE_JOIN_ROUND)

            ctx.move_to(pts[0][0], pts[0][1])
            for px, py in pts[1:]:
                ctx.line_to(px, py)
            ctx.stroke()
            ctx.restore()

            strokes_placed += 1

        print(f"    Munch anxiety swirl pass complete  ({strokes_placed} swirl strokes placed)")

    # ─────────────────────────────────────────────────────────────────────────
    # hals_bravura_stroke_pass — inspired by Frans Hals
    # ─────────────────────────────────────────────────────────────────────────

    def hals_bravura_stroke_pass(
        self,
        reference:        Union[np.ndarray, Image.Image, None] = None,
        *,
        n_strokes:        int   = 480,
        stroke_size:      float = 8.0,
        opacity:          float = 0.62,
        angle_jitter_deg: float = 42.0,
        color_jitter:     float = 0.05,
        broken_tone:      bool  = True,
        figure_mask:      Optional[np.ndarray] = None,
    ) -> None:
        """
        Hals Bravura Stroke Pass — Frans Hals's alla prima broken-tone technique.

        Frans Hals (c. 1582–1666) was the first great master of the 'broken
        tone': adjacent strokes of slightly different value and colour
        temperature are set down directly on the canvas without blending, so
        the eye synthesises the tonal mixture from a normal reading distance.
        This anticipates Impressionist divided colour by two centuries and
        gives Hals's portraits their startling sense of psychological
        immediacy — as if the sitter were caught mid-thought.

        The improvement this pass introduces
        -------------------------------------
        No previous pass in this pipeline simulates 'broken tone' as a
        deliberate compositional strategy.  Existing passes blend colours
        through wet_blend or glaze layers.  This pass withholds blending
        entirely and instead places two value-contrasting strokes side-by-side,
        trusting the viewer's eye to resolve the optical mixture.  This is a
        distinct artistic capability not previously available in the pipeline.

        Implementation strategy
        -----------------------
        The pass samples n_strokes positions across the canvas, each time
        reading the reference colour at that location and applying a bold
        angular jitter (±angle_jitter_deg degrees) to the local flow-field
        direction.  Each stroke is short — approximately 2–3× its width — to
        match the compact, decisive mark Hals preferred.  Per-stroke colour
        jitter (color_jitter) ensures no two adjacent strokes are identical;
        the variation is the technique, not a flaw.

        When broken_tone=True (default), each primary stroke is accompanied
        by a slightly lighter or darker companion stroke offset roughly one
        brush-width perpendicular to the stroke direction.  The companion uses
        an inverted value delta (lighter companion for a shadow stroke, darker
        companion for a highlight stroke), creating the shimmering half-tone
        quality that distinguishes Hals from any smooth-blended technique.

        Parameters
        ----------
        reference : PIL Image, numpy array, or None
            Reference to sample colours from.  When None the current canvas
            buffer is used as reference — useful for a post-processing pass.
        n_strokes : int
            Number of bravura strokes.  480 gives good coverage on 512×512.
        stroke_size : float
            Base brush radius in pixels.  8.0 is the primary Hals mark.
        opacity : float
            Per-stroke opacity in [0, 1].  0.62 places marks confidently
            without fully obliterating the warm straw ground.
        angle_jitter_deg : float
            Maximum angular deviation from local flow direction in degrees.
            42.0 produces the spontaneous multi-directional quality of Hals.
            Do not reduce below 35 or the surface becomes too regular.
        color_jitter : float
            Per-stroke colour variation amplitude.  0.05 is faithful to
            Hals's subtle broken tone; raise toward 0.10 for more vibration.
        broken_tone : bool
            When True, each primary stroke is accompanied by a value-shifted
            companion stroke to simulate Hals's broken-tone technique.
        figure_mask : numpy array, optional
            Overrides self._figure_mask for stroke placement bias.

        Notes
        -----
        Call AFTER block_in() / build_form() and BEFORE any final glaze().
        No glazing pass is needed or recommended afterward — Hals finished
        directly, without a unifying glaze layer.
        Pair with tone_ground((0.78, 0.70, 0.52)) beforehand so the warm
        straw buff shows through in the half-tone areas.
        """
        print(f"  Hals bravura stroke pass  "
              f"(n={n_strokes}  size={stroke_size:.1f}  "
              f"opacity={opacity:.2f}  broken_tone={broken_tone})…")

        h, w = self.h, self.w

        # ── Reference: sample canvas buffer when none provided ────────────────
        if reference is not None:
            ref  = self._prep(reference)
            rarr = ref[:, :, :3].astype(np.float32) / 255.0
        else:
            # Use current canvas state as colour reference
            buf  = np.frombuffer(self.canvas.surface.get_data(),
                                 dtype=np.uint8).reshape(h, w, 4).copy()
            # Cairo stores BGRA; convert to RGB for consistency
            rarr = buf[:, :, [2, 1, 0]].astype(np.float32) / 255.0

        # ── Flow field: stroke angle follows colour contours ──────────────────
        angles = flow_field(rarr)

        # ── Effective region mask ──────────────────────────────────────────────
        effective_mask = figure_mask if figure_mask is not None else self._figure_mask

        # ── Sampling weight: uniform with modest figure bias ──────────────────
        # Hals painted background and figure with the same bravura approach,
        # so we do not mask to figure only — we merely weight figure pixels
        # slightly higher to concentrate detail where it matters.
        weight = np.ones((h, w), dtype=np.float32)
        if effective_mask is not None:
            weight = np.where(effective_mask > 0.5, 2.0, 1.0).astype(np.float32)
        weight_flat = weight.flatten()
        weight_flat /= weight_flat.sum() + 1e-9

        if n_strokes <= 0:
            print("    Hals bravura stroke pass skipped (n_strokes=0)")
            return

        positions = self.rng.choice(h * w, size=n_strokes,
                                    p=weight_flat, replace=True)

        tip              = BrushTip(BrushTip.FILBERT)
        angle_jitter_rad = math.radians(angle_jitter_deg)
        strokes_placed   = 0

        for pos in positions:
            py, px = int(pos // w), int(pos % w)
            margin = max(4, int(stroke_size * 2))
            px = int(np.clip(px, margin, w - margin))
            py = int(np.clip(py, margin, h - margin))

            # ── Colour from reference + per-stroke jitter ─────────────────────
            col = tuple(float(rarr[py, px, c]) for c in range(3))
            col = jitter(col, color_jitter, self._rng_py)

            # ── Stroke direction: flow field + bold angular jitter ────────────
            # Hals's bravura mark does not consistently follow the form contour;
            # it departs at a bold angle, creating the restless spontaneous energy
            # of his technique.  angle_jitter_rad applies a uniform random offset
            # of up to ±42° from the locally dominant colour-contour direction.
            a = (float(angles[py, px])
                 + self._rng_py.uniform(-angle_jitter_rad, angle_jitter_rad))

            # ── Short, decisive stroke: ~2–3× width in length ─────────────────
            length = stroke_size * self._rng_py.uniform(2.0, 3.2)
            start  = (px - math.cos(a) * length * 0.5,
                      py - math.sin(a) * length * 0.5)
            # Slight S-curve (curve parameter) for organic cursive quality
            curve = self._rng_py.uniform(-0.18, 0.18)
            pts   = stroke_path(start, a, length,
                                curve=curve,
                                n=max(3, int(length / 4)))
            ws    = [stroke_size * self._rng_py.uniform(0.75, 1.15)] * len(pts)

            self.canvas.apply_stroke(
                pts, ws, col, tip,
                opacity=opacity,
                wet_blend=0.10,        # alla prima: minimal wet blending
                jitter_amt=color_jitter * 0.5,
                rng=self._rng_py,
                region_mask=effective_mask,
            )
            strokes_placed += 1

            # ── Broken-tone companion stroke ───────────────────────────────────
            # Hals's defining innovation: a value-shifted companion stroke placed
            # perpendicular to the primary, one brush-width offset.  The companion
            # is lighter adjacent to a shadow stroke and darker adjacent to a
            # highlight stroke — the eye resolves the optical mixture into a
            # vibrant, living half-tone that no blended technique can replicate.
            if broken_tone:
                lum = 0.299 * col[0] + 0.587 * col[1] + 0.114 * col[2]
                # Positive delta (lighter) for dark strokes; negative (darker) for lights
                value_delta = 0.12 if lum < 0.45 else -0.09
                comp_col = (
                    max(0.0, min(1.0, col[0] + value_delta)),
                    max(0.0, min(1.0, col[1] + value_delta * 0.88)),
                    max(0.0, min(1.0, col[2] + value_delta * 0.72)),
                )
                # Perpendicular offset — one brush-radius away from primary stroke
                perp_offset = stroke_size * 0.85
                perp_cos    = -math.sin(a)
                perp_sin    =  math.cos(a)
                comp_pts    = [
                    (px_ + perp_cos * perp_offset,
                     py_ + perp_sin * perp_offset)
                    for (px_, py_) in pts
                ]
                comp_ws = [wi * 0.75 for wi in ws]

                self.canvas.apply_stroke(
                    comp_pts, comp_ws, comp_col, tip,
                    opacity=opacity * 0.55,
                    wet_blend=0.06,
                    jitter_amt=color_jitter * 0.35,
                    rng=self._rng_py,
                    region_mask=effective_mask,
                )

        print(f"    Hals bravura stroke pass complete  "
              f"({strokes_placed} bravura strokes placed)")

    # ─────────────────────────────────────────────────────────────────────────
    # dali_paranoiac_critical_pass — inspired by Salvador Dali
    # ─────────────────────────────────────────────────────────────────────────

    def dali_paranoiac_critical_pass(
        self,
        *,
        chroma_shift:        int   = 3,
        shadow_ultramarine:  float = 0.18,
        highlight_warmth:    float = 0.06,
        shadow_thresh:       float = 0.28,
        highlight_thresh:    float = 0.78,
        figure_sharpen:      float = 0.38,
        bg_only_aberration:  bool  = True,
        opacity:             float = 0.82,
    ) -> None:
        """
        Dali Paranoiac-Critical Pass — Salvador Dali's hyper-realist surrealist technique.

        Salvador Dali (1904–1989) called his method the 'Paranoiac-Critical Method':
        by deliberately inducing a paranoid hallucinatory state, he trained himself
        to discover hidden double images within compositions — two or more distinct
        subjects occupying the same visual space, readable depending on the viewer's
        mental frame.  The painterly technique he applied to these visions was the
        precise opposite of psychological instability: obsessively photographic,
        with near-invisible brushwork and seamless enamel-like surfaces he called
        'hand-painted dream photographs.'

        This pass replicates four defining qualities of Dali's technique:

        1. **Ultramarine shadow deepening** — In the darkest tonal zone (lum <
           shadow_thresh), shadows are pushed toward deep ultramarine-violet rather
           than neutral black.  This is the Catalonian light signature: sunlit
           Mediterranean surfaces against cool ultramarine void — the same quality
           that appears in Velázquez's Catalan-influenced shadows, intensified by
           the brilliant overhead sun of the Empordà plain near Dali's home in
           Cadaqués.  The push is graduated: the deepest shadows get the most
           ultramarine, while the penumbra edge preserves a warm transition.

        2. **Catalan sunlight warmth** — In the brightest tonal zone (lum >
           highlight_thresh), lit surfaces are pushed toward warm amber-gold — the
           colour of Catalan sunlight on ochre stone.  This contrasts with the cool
           ultramarine shadows to produce the extreme tonal polarity that gives
           Dali's canvases their almost hallucinogenic vibrancy.

        3. **Chromatic prismatic aberration** — A subtle lateral offset of the R
           and B channels in background regions simulates the dreamlike out-of-phase
           quality of Dali's hyper-realist surfaces.  Real optics introduce small
           chromatic aberrations from lens dispersion; Dali's hyper-realist technique
           seems to replicate this on canvas, suggesting the image is a photograph
           of a dream rather than a painting from life.  When bg_only_aberration=True
           (default), this effect is restricted to regions outside the figure mask,
           preserving crisp foreground precision while the background shimmers.

        4. **Hyper-realist figure sharpening** — An unsharp-mask pass applied to
           figure regions reinforces the 'hand-painted photograph' quality.  Dali
           rendered his subjects with impossible photographic crispness — every pore,
           every hair, every reflected catch-light resolved with precision.  The
           figure_sharpen parameter controls the strength of this unsharp mask.

        Parameters
        ----------
        chroma_shift : int
            Lateral pixel offset for chromatic aberration.  3 gives a subtle
            prismatic fringe at edges; 0 disables aberration entirely.
        shadow_ultramarine : float
            Strength of the ultramarine push in the dark zone.  0.18 is faithful
            to Dali's deep shadow colour; raise toward 0.30 for stronger effect.
        highlight_warmth : float
            Strength of the amber-gold warmth in the bright zone.  0.06 is subtle.
        shadow_thresh : float
            Luminance below which shadow adjustments apply.
        highlight_thresh : float
            Luminance above which highlight adjustments apply.
        figure_sharpen : float
            Unsharp-mask strength applied to figure regions.  0.38 gives
            photographic crispness without artefacts.  0 disables sharpening.
        bg_only_aberration : bool
            When True, chromatic aberration is applied only to background
            regions (figure_mask < 0.5).  When False, applied everywhere.
        opacity : float
            Global blend weight for all adjustments.  0 = noop, 1 = full.

        Notes
        -----
        Call AFTER block_in() and build_form().  Pairs with a warm amber
        glaze (0.88, 0.78, 0.42) applied afterward for the final unifying
        Catalan sunlight quality.

        Famous works to study:
          *The Persistence of Memory* (1931, MoMA) — the melting watches sit
          on a table in a hyper-precisely rendered Catalonian cove; every
          sand grain, every reflective surface is resolved with photographic
          fidelity; the impossible (melting metal) gains its power from
          the photographic reality of everything around it.

          *Dream Caused by the Flight of a Bee* (1944, Thyssen-Bornemisza) —
          Gala floats in mid-air above a sunlit ledge; the tiger emerging
          from a pomegranate is rendered with the same obsessive precision
          as Gala's skin; deep ultramarine shadows define the spatial
          recession behind the brilliant warm-lit foreground.
        """
        import numpy as _np
        from scipy import ndimage as _ndimage

        print(f"  Dali paranoiac-critical pass  "
              f"(chroma_shift={chroma_shift}  "
              f"shadow_ultramarine={shadow_ultramarine:.2f}  "
              f"figure_sharpen={figure_sharpen:.2f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Dali paranoiac-critical pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA channel order: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Luminance ─────────────────────────────────────────────────────────
        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── 1. Ultramarine shadow deepening ───────────────────────────────────
        # In the darkest tonal zone, push colour toward deep ultramarine-violet.
        # The ramp peaks at lum=0 (maximum adjustment on pure black) and falls
        # to zero at lum=shadow_thresh (no adjustment at the shadow boundary).
        sh_mask = lum < shadow_thresh
        sh_ramp = _np.where(
            sh_mask,
            _np.clip((shadow_thresh - lum) / (shadow_thresh + 1e-6), 0.0, 1.0),
            0.0)

        # Cool R and G down; lift B toward deep ultramarine
        r_out = _np.where(sh_mask,
                          _np.clip(r_out - shadow_ultramarine * 0.55 * sh_ramp,
                                   0.0, 1.0),
                          r_out)
        g_out = _np.where(sh_mask,
                          _np.clip(g_out - shadow_ultramarine * 0.42 * sh_ramp,
                                   0.0, 1.0),
                          g_out)
        b_out = _np.where(sh_mask,
                          _np.clip(b_out + shadow_ultramarine * 0.70 * sh_ramp,
                                   0.0, 1.0),
                          b_out)

        # ── 2. Catalan sunlight warmth in highlights ──────────────────────────
        # Push bright zones toward warm amber-gold — the colour of Catalan
        # sunlight on ochre stone and warm ivory flesh.  The ramp peaks at
        # lum=1.0 and falls to zero at lum=highlight_thresh.
        hi_mask = lum > highlight_thresh
        hi_ramp = _np.where(
            hi_mask,
            _np.clip((lum - highlight_thresh) / (1.0 - highlight_thresh + 1e-6),
                     0.0, 1.0),
            0.0)

        r_out = _np.where(hi_mask,
                          _np.clip(r_out + highlight_warmth * 0.80 * hi_ramp,
                                   0.0, 1.0),
                          r_out)
        g_out = _np.where(hi_mask,
                          _np.clip(g_out + highlight_warmth * 0.50 * hi_ramp,
                                   0.0, 1.0),
                          g_out)
        b_out = _np.where(hi_mask,
                          _np.clip(b_out - highlight_warmth * 0.25 * hi_ramp,
                                   0.0, 1.0),
                          b_out)

        # ── 3. Chromatic prismatic aberration ─────────────────────────────────
        # Shift R right and B left by chroma_shift pixels to simulate the
        # dreamlike out-of-phase quality of Dali's hyper-realist surfaces.
        # When bg_only_aberration=True, apply only to background regions so
        # the crisp foreground precision of his figure rendering is preserved.
        if chroma_shift > 0:
            if bg_only_aberration and self._figure_mask is not None:
                # Background: where figure_mask < 0.5; smooth the edge transition
                bg_mask_2d = (self._figure_mask < 0.5).astype(_np.float32)
                bg_mask_2d = _ndimage.gaussian_filter(
                    bg_mask_2d, sigma=float(chroma_shift))
            else:
                bg_mask_2d = _np.ones((h, w), dtype=_np.float32)

            # Lateral shift: R right (+col), B left (-col)
            r_aberrated = _np.roll(r_out, chroma_shift, axis=1)
            b_aberrated = _np.roll(b_out, -chroma_shift, axis=1)

            # Remove wrap-around artefacts at canvas edges
            r_aberrated[:, :chroma_shift] = r_out[:, :chroma_shift]
            b_aberrated[:, w - chroma_shift:] = b_out[:, w - chroma_shift:]

            # Blend aberrated channels into background area (60% blend weight)
            blend = bg_mask_2d * 0.60
            r_out = _np.clip(r_out * (1.0 - blend) + r_aberrated * blend, 0.0, 1.0)
            b_out = _np.clip(b_out * (1.0 - blend) + b_aberrated * blend, 0.0, 1.0)

        # ── 4. Hyper-realist figure sharpening ────────────────────────────────
        # Apply an unsharp mask to figure regions to achieve the 'hand-painted
        # photograph' precision of Dali's subject rendering.  The sigma is
        # adaptive (0.8% of the shorter canvas dimension) so it scales cleanly
        # across canvas sizes without requiring manual tuning.
        if figure_sharpen > 0.0 and self._figure_mask is not None:
            fig_mask = (self._figure_mask > 0.5).astype(_np.float32)
            sigma    = max(1.0, float(min(h, w)) * 0.008)

            for ch_arr in (r_out, g_out, b_out):
                blurred = _ndimage.gaussian_filter(ch_arr, sigma=sigma)
                unsharp = _np.clip(ch_arr + figure_sharpen * (ch_arr - blurred),
                                   0.0, 1.0)
                # In-place update restricted to figure pixels
                ch_arr[:, :] = ch_arr * (1.0 - fig_mask) + unsharp * fig_mask

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        n_shadow    = int(sh_mask.sum())
        n_highlight = int(hi_mask.sum())
        print(f"    Dali paranoiac-critical pass complete  "
              f"(shadow={n_shadow}px  highlight={n_highlight}px  "
              f"aberration={'on' if chroma_shift > 0 else 'off'})")

    # ─────────────────────────────────────────────────────────────────────────
    # hammershoi_grey_silence_pass — Vilhelm Hammershøi near-monochrome silence
    # ─────────────────────────────────────────────────────────────────────────

    def hammershoi_grey_silence_pass(
        self,
        desaturation:   float = 0.82,
        window_thresh:  float = 0.68,
        window_cool:    float = 0.08,
        shadow_thresh:  float = 0.35,
        shadow_cool:    float = 0.04,
        opacity:        float = 0.88,
    ) -> None:
        """
        Vilhelm Hammershøi's near-monochrome interior silence pass.

        Hammershøi's Copenhagen interiors are built from a single grey chord
        modulated across the canvas — almost all colour saturation stripped away,
        leaving only a ghost of hue.  What little colour survives is the
        differential between warm ivory (north window light) and cool blue-grey
        (shadowed wall and floor).  The net effect is a profound, held-breath
        silence — the room exists outside of ordinary time.

        Three-strategy pass:

        1. **Desaturation toward grey** — Each RGB channel is blended toward
           its perceptual luminance value at ``desaturation`` rate.  At 0.82,
           each channel retains only 18 % of its original colour deviation from
           grey.  The result reads as near-monochrome but is not a mechanical
           greyscale conversion — a ghost of the original hue survives.

        2. **Window-light cooling** — Bright pixels (``lum > window_thresh``)
           receive a cool blue-grey shift (B lift, R+G damp) simulating the
           diffuse north window daylight that illuminates all of Hammershøi's
           interiors.  The ramp peaks at the brightest pixels and fades to zero
           at the window threshold boundary.

        3. **Shadow cooling** — Dark pixels (``lum < shadow_thresh``) receive a
           further subtle blue-grey cool shift (B lift, R damp) simulating the
           cool reflected sky quality in shadowed room recesses.  Hammershøi
           never introduces warm bounce light in his shadows — they are simply
           cooler and darker versions of the wall tone.

        Parameters
        ----------
        desaturation : float
            Fraction of colour deviation from grey to remove (0 = no change,
            1 = full greyscale).  0.82 retains 18 % of original hue.
        window_thresh : float
            Luminance above which the window-light cooling applies.
        window_cool : float
            Strength of the cool blue-grey shift in lit zones.
        shadow_thresh : float
            Luminance below which the shadow cooling applies.
        shadow_cool : float
            Strength of the cool blue-grey shift in shadow zones.
        opacity : float
            Global blend weight for all adjustments.  0 = noop, 1 = full.

        Notes
        -----
        Call AFTER ``build_form()`` and BEFORE the final ``glaze()``.  Pairs
        with the cool grey unifying glaze ``(0.78, 0.77, 0.74)`` applied
        afterward.

        Famous works to study:
          *Dust Motes Dancing in Sunrays* (1900, Ordrupgaard) — shafts of
          north-window light fall across an otherwise silent grey interior;
          the drama is entirely tonal, not chromatic.

          *Interior, Strandgade 30* (1901, Statens Museum for Kunst) — a door
          stands open into a further room; the recession of grey-on-grey planes
          into depth is the complete subject; no narrative, no figure.
        """
        import numpy as _np

        print(f"  Hammershøi grey silence pass  "
              f"(desaturation={desaturation:.2f}  "
              f"window_cool={window_cool:.2f}  "
              f"shadow_cool={shadow_cool:.2f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Hammershøi grey silence pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA channel order: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Luminance ─────────────────────────────────────────────────────────
        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── 1. Desaturation toward grey ────────────────────────────────────────
        # Blend each channel toward the luminance value.
        # At desaturation=0.82: output = 0.18 * channel + 0.82 * luminance.
        # The ghost of colour (18 %) prevents mechanical greyscale while
        # achieving the near-monochrome appearance of Hammershøi's palette.
        r_out = (1.0 - desaturation) * r_f + desaturation * lum
        g_out = (1.0 - desaturation) * g_f + desaturation * lum
        b_out = (1.0 - desaturation) * b_f + desaturation * lum

        # ── 2. Window-light cooling (bright zone) ─────────────────────────────
        # In the lightest tonal zone, push colour toward cool blue-grey to
        # simulate diffuse north window daylight.  The ramp peaks at lum=1.0
        # and falls to zero at lum=window_thresh.
        win_mask = lum > window_thresh
        win_ramp = _np.where(
            win_mask,
            _np.clip((lum - window_thresh) / (1.0 - window_thresh + 1e-6),
                     0.0, 1.0),
            0.0)

        # Cool R and G slightly; lift B toward blue-grey
        r_out = _np.clip(r_out - window_cool * 0.60 * win_ramp, 0.0, 1.0)
        g_out = _np.clip(g_out - window_cool * 0.30 * win_ramp, 0.0, 1.0)
        b_out = _np.clip(b_out + window_cool * 0.55 * win_ramp, 0.0, 1.0)

        # ── 3. Shadow cooling (dark zone) ─────────────────────────────────────
        # In the darkest tonal zone, add a further subtle cool blue-grey push
        # simulating the cool reflected sky quality in shadowed room recesses.
        # The ramp peaks at lum=0 and falls to zero at lum=shadow_thresh.
        sh_mask = lum < shadow_thresh
        sh_ramp = _np.where(
            sh_mask,
            _np.clip((shadow_thresh - lum) / (shadow_thresh + 1e-6), 0.0, 1.0),
            0.0)

        r_out = _np.clip(r_out - shadow_cool * 0.50 * sh_ramp, 0.0, 1.0)
        b_out = _np.clip(b_out + shadow_cool * 0.40 * sh_ramp, 0.0, 1.0)

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        n_win = int(win_mask.sum())
        n_sh  = int(sh_mask.sum())
        print(f"    Hammershøi grey silence pass complete  "
              f"(desaturated={h * w}px  window={n_win}px  shadow={n_sh}px)")

    # ─────────────────────────────────────────────────────────────────────────
    # horizon_mist_pass — graduated mid-ground atmospheric haze
    # ─────────────────────────────────────────────────────────────────────────

    def horizon_mist_pass(
        self,
        horizon_y:      float = 0.48,
        band_height:    float = 0.18,
        mist_color:     "Color" = (0.78, 0.80, 0.86),
        mist_strength:  float = 0.28,
        blur_sigma:     float = 2.5,
        opacity:        float = 0.72,
    ) -> None:
        """
        Graduated mid-ground atmospheric haze for landscape backgrounds.

        Renaissance portrait masters — Leonardo most famously in the Mona Lisa —
        placed their figures before imaginary geological landscapes that dissolve
        into cool atmospheric haze as they recede.  The transition from the
        warmly lit foreground to the pale blue-grey distant horizon is not
        linear: the most pronounced haze collects in the *mid-ground transition
        zone* — roughly at the horizon line — where near and far space meet.
        This band reads as a silvery veil of distance, thicker than the clear
        foreground but lighter than the distant sky.

        This pass targets that mid-ground zone.  It identifies a horizontal band
        centred on ``horizon_y`` (as a fraction of canvas height, measured from
        the top), applies a Gaussian-blurred cool mist overlay whose strength
        peaks at the band centre and fades to zero at its edges, then blends
        that mist over the canvas at ``opacity``.

        Unlike ``atmospheric_depth_pass`` (which applies globally across the
        full vertical range based on luminance thresholds) this pass acts only
        on the specified horizontal band.  It is therefore well-suited to
        portrait backgrounds where the foreground figure must remain unaffected
        but the mid-ground landscape recedes into haze.

        Strategies
        ----------
        1. **Band weighting** — A 1-D Gaussian weight function peaks at
           ``horizon_y`` and has half-power width ``band_height``.  The weight
           is broadcast across the full width of the canvas so the mist thins
           gradually above and below the horizon band.

        2. **Mist overlay** — ``mist_color`` (default cool silver-blue
           ``(0.78, 0.80, 0.86)``) is blended over the canvas at each pixel
           with a weight equal to ``band_weight × mist_strength``.  The colour
           choice models the characteristic pale blue-grey of atmosphere seen
           against a distant sky — slightly blue (cool scattered light), lighter
           than mid-tone (atmospheric translucency), with low saturation.

        3. **Edge softening** — The band boundary is Gaussian-smoothed
           (sigma = ``blur_sigma`` percent of canvas height) so the haze
           dissolves seamlessly into the clear foreground and clear sky above,
           avoiding any visible hard boundary at the band edges.

        Parameters
        ----------
        horizon_y : float
            Vertical centre of the haze band, as a fraction of canvas height
            (0 = top, 1 = bottom).  Default 0.48 places the band just below
            the canvas mid-line, typical for a half-length portrait.
        band_height : float
            Half-width of the haze band as a fraction of canvas height.  0.18
            gives a band spanning roughly the middle third of the canvas.
        mist_color : Color
            RGB colour of the atmospheric mist overlay.  Default (0.78, 0.80,
            0.86) is a cool silver-blue — characteristic of aerial perspective.
        mist_strength : float
            Peak opacity of the mist overlay at the band centre.  0.28 gives
            a visible but non-dominating haze; raise toward 0.50 for a strongly
            misty effect.
        blur_sigma : float
            Gaussian sigma for edge smoothing of the band weight, expressed as
            a fraction of canvas height (percent).  2.5 % gives smooth dissolve.
        opacity : float
            Global blend weight applied on top of the per-pixel mist weight.

        Notes
        -----
        Apply AFTER ``build_form()`` and atmospheric passes, BEFORE the final
        glaze.  Pairs naturally with ``atmospheric_depth_pass()`` for full
        landscape recession: ``atmospheric_depth_pass`` handles the overall
        value/saturation falloff with distance; ``horizon_mist_pass`` adds the
        specific mid-ground haze band that makes the transition read as deep
        natural space.
        """
        from scipy import ndimage as _ndimage
        import numpy as _np

        print(f"  Horizon mist pass  "
              f"(horizon_y={horizon_y:.2f}  band_height={band_height:.2f}  "
              f"mist_strength={mist_strength:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Horizon mist pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA channel order: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── 1. Build 1-D band weight (Gaussian along Y) ────────────────────────
        # Peak at horizon_y, half-power radius = band_height.
        # sigma_px derived from band_height so the 1-sigma point is at the
        # band edge: sigma = band_height * h / 2 (converts fraction to pixels).
        sigma_band_px = max(1.0, band_height * h / 2.0)
        ys        = _np.arange(h, dtype=_np.float32)
        cy        = horizon_y * h
        band_1d   = _np.exp(-0.5 * ((ys - cy) / sigma_band_px) ** 2)

        # Apply additional Gaussian blur to soften band edges
        sigma_blur_px = max(1.0, blur_sigma / 100.0 * h)
        band_1d = _ndimage.gaussian_filter1d(band_1d, sigma=sigma_blur_px)

        # Clamp to [0, 1] after blur; broadcast to (H, W)
        band_1d  = _np.clip(band_1d, 0.0, 1.0)
        band_2d  = band_1d[:, _np.newaxis]   # shape (H, 1) → broadcast to (H, W)

        # Per-pixel blend weight: peak mist_strength at band centre
        weight = band_2d * mist_strength      # shape (H, W)

        # ── 2. Mist overlay blend ──────────────────────────────────────────────
        # Blend mist_color over the current pixel at the computed weight.
        # This is a standard screen-space opacity blend:
        #   out = (1 - weight) * src + weight * mist
        mr, mg, mb = mist_color

        r_out = _np.clip((1.0 - weight) * r_f + weight * mr, 0.0, 1.0)
        g_out = _np.clip((1.0 - weight) * g_f + weight * mg, 0.0, 1.0)
        b_out = _np.clip((1.0 - weight) * b_f + weight * mb, 0.0, 1.0)

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        peak_weight = float(weight.max())
        print(f"    Horizon mist pass complete  "
              f"(band_center_px={int(horizon_y * h)}  "
              f"peak_weight={peak_weight:.3f})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 50 — John Constable artist pass
    # ──────────────────────────────────────────────────────────────────────────

    def constable_cloud_sky_pass(
        self,
        sky_threshold:    float = 0.40,
        warm_top:         float = 0.16,
        cool_base:        float = 0.10,
        silver_strength:  float = 0.30,
        silver_density:   float = 0.04,
        opacity:          float = 0.72,
    ) -> None:
        """
        Build luminous English skies in the manner of John Constable.

        Constable's skies are the most technically studied element of his
        paintings.  He conducted hundreds of dedicated cloud studies from life,
        noting meteorological conditions on the verso.  His sky technique has
        three distinct registers:

        1. **Warm cream tops / cool grey undersides** — Cloud formations read
           as three-dimensional forms lit from above: the top surfaces catch
           warm direct light (cream-ivory); the undersides carry cool grey-blue
           shadow.  The overall sky tone is not a flat blue wash but a complex
           field of warm and cool passages in dialogue.

        2. **Luminous horizon** — The sky near the horizon is always lighter
           and cooler than the sky at the zenith, modelling the way atmospheric
           perspective reduces colour and value contrast near the far ground.
           This lift also provides luminosity beneath the clouds, pushing the
           sky reading as a genuine *light source* rather than a backdrop.

        3. **'Constable's snow'** — His signature impasto device: tiny dagger-
           touches of thick, undiluted white (sometimes pure lead white or
           flake white) scattered across lit cloud edges, water glints, and
           wet leaf surfaces.  These touches are not blended; they sit proud of
           the picture surface and catch raking light in a way that illusory
           white paint alone cannot.  In this pass they are simulated as sparse
           scattered bright-white pixels, slightly above the existing local tone.

        The pass operates only on the sky zone (``y < sky_threshold * h``),
        leaving the landscape below unmodified.  A soft cosine gradient feathers
        the sky-to-landscape transition so no hard band appears at the boundary.

        Strategies
        ----------
        1. **Sky gradient** — A 1-D cosine weight along Y (1.0 at top → 0.0 at
           ``sky_threshold``) modulates two simultaneous colour pushes: a warm
           cream push toward the zenith (``warm_top``) and a cool pale-blue push
           toward the horizon base of the sky zone (``cool_base``).

        2. **Silver sparkle** — A sparse binary mask (Bernoulli with probability
           ``silver_density``) restricted to the sky zone selects candidate
           pixels.  Only pixels already brighter than the local mean in their
           3×3 neighbourhood are promoted further toward (1.0, 1.0, 0.95) —
           Constable's impasto white — at strength ``silver_strength``.

        Parameters
        ----------
        sky_threshold : float
            Fraction of canvas height (from top) defining the sky zone.
            0.40 means the upper 40 % is treated as sky.
        warm_top : float
            Strength of the warm cream push (R lift, G lift, B damp) at the
            sky zenith.  0.16 gives a subtle creamy warmth without browning.
        cool_base : float
            Strength of the cool pale-blue push (B lift, R+G slight damp) at
            the base of the sky zone.  0.10 gives a gentle horizon luminosity.
        silver_strength : float
            How strongly selected pixels are pushed toward pure silver-white.
            0.30 gives convincing sparkle without over-brightening.
        silver_density : float
            Probability that any given sky pixel becomes a sparkle candidate
            before brightness-gating.  0.04 (4 %) gives a lively but not
            over-crowded scatter.
        opacity : float
            Global blend weight for the pass result over the original canvas.

        Notes
        -----
        Apply AFTER ``build_form()`` and before the final glaze.  Pairs well
        with ``atmospheric_depth_pass()`` for full landscape recession and
        ``horizon_mist_pass()`` for mid-ground haze.
        """
        import numpy as _np

        print(f"  Constable cloud sky pass  "
              f"(sky_threshold={sky_threshold:.2f}  warm_top={warm_top:.2f}  "
              f"cool_base={cool_base:.2f}  silver_strength={silver_strength:.2f}  "
              f"silver_density={silver_density:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Constable cloud sky pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # Sky zone: rows 0 … sky_px-1 inclusive
        sky_px = max(1, int(sky_threshold * h))

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:sky_px, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:sky_px, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:sky_px, :, 2].astype(_np.float32) / 255.0

        # ── 1. Sky gradient — warm top → cool horizon base ───────────────────
        # cosine weight: 1.0 at row 0 (zenith), 0.0 at row sky_px-1 (horizon)
        ys         = _np.linspace(0.0, 1.0, sky_px, dtype=_np.float32)
        warm_w     = ((_np.cos(_np.pi * ys) + 1.0) * 0.5)[:, _np.newaxis]   # (sky_px, 1)
        cool_w     = (1.0 - warm_w)                                           # (sky_px, 1)

        # Warm top push: cream-ivory — lift R and G, slight B damp
        r_f = _np.clip(r_f + warm_w * warm_top * 0.90, 0.0, 1.0)
        g_f = _np.clip(g_f + warm_w * warm_top * 0.80, 0.0, 1.0)
        b_f = _np.clip(b_f - warm_w * warm_top * 0.15, 0.0, 1.0)

        # Cool base push: pale cerulean — lift B, slight R+G damp
        b_f = _np.clip(b_f + cool_w * cool_base * 1.10, 0.0, 1.0)
        r_f = _np.clip(r_f - cool_w * cool_base * 0.20, 0.0, 1.0)
        g_f = _np.clip(g_f - cool_w * cool_base * 0.10, 0.0, 1.0)

        # ── 2. Constable's silver sparkle ─────────────────────────────────────
        # Sparse bright-white impasto touches on already-lit sky pixels
        rng       = _np.random.default_rng(seed=42)
        candidate = rng.random(size=(sky_px, w), dtype=_np.float32) < silver_density

        # Brightness-gate: only promote pixels already locally bright
        lum       = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f
        bright    = lum > 0.55   # keep only pixels that are already in the light
        mask      = candidate & bright

        # Push selected pixels toward silver-white (1.0, 1.0, 0.95)
        r_f = _np.where(mask, _np.clip(r_f + silver_strength, 0.0, 1.0), r_f)
        g_f = _np.where(mask, _np.clip(g_f + silver_strength, 0.0, 1.0), g_f)
        b_f = _np.where(mask, _np.clip(b_f + silver_strength * 0.92, 0.0, 1.0), b_f)

        # ── Blend sky zone back at `opacity` ──────────────────────────────────
        buf[:sky_px, :, 2] = _np.clip(
            orig[:sky_px, :, 2] * (1.0 - opacity) + r_f * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:sky_px, :, 1] = _np.clip(
            orig[:sky_px, :, 1] * (1.0 - opacity) + g_f * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:sky_px, :, 0] = _np.clip(
            orig[:sky_px, :, 0] * (1.0 - opacity) + b_f * opacity * 255.0,
            0, 255).astype(_np.uint8)
        # Alpha and landscape zone unchanged
        buf[:sky_px, :, 3] = orig[:sky_px, :, 3]

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        sparkle_count = int(mask.sum())
        print(f"    Constable cloud sky pass complete  "
              f"(sky_px={sky_px}  sparkle_pixels={sparkle_count})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 50 — random improvement: chiaroscuro_modelling_pass
    # ──────────────────────────────────────────────────────────────────────────

    def chiaroscuro_modelling_pass(
        self,
        figure_mask:    "Optional[_np.ndarray]" = None,
        light_thresh:   float = 0.65,
        shadow_thresh:  float = 0.38,
        light_warmth:   float = 0.10,
        shadow_cool:    float = 0.08,
        shadow_deepen:  float = 0.07,
        opacity:        float = 0.68,
    ) -> None:
        """
        Enhance three-dimensional figure modelling via chiaroscuro warm/cool split.

        Chiaroscuro — Italian for 'light-dark' — is the classical technique of
        modelling solid form through a deliberate warm-to-cool tonal shift from
        the lit side to the shadow side of a figure.  It was perfected in the
        Italian Renaissance and then extended into its most extreme expression
        by Caravaggio (tenebrism) and Rembrandt (luminous impasto against deep
        shadow).  The physical basis is real: direct sunlight (or lamplight)
        is warm (high colour temperature ~3000–5500 K) while open-sky fill
        light and shadow is cool (high colour temperature ~7000–12000 K from
        scattered blue skylight).

        This pass implements the two-zone correction:

        **Light zone** (``luminance > light_thresh``) — Push toward warm ivory.
        Lift R and G slightly (toward cream), damp B slightly.  This enriches
        the sense that lit flesh is warm with blood and direct light.

        **Shadow zone** (``luminance < shadow_thresh``) — Deepen and cool
        shadows simultaneously.  Lower R+G (darker), lift B slightly (cooler).
        This prevents shadows from looking like mere grey mud and gives them
        the quality of atmospheric open-sky fill: cold, airy, and receding.

        The pass is most effective on portrait figures with a clear three-
        quarter lighting setup.  When ``figure_mask`` is provided the effect
        is spatially limited to the figure, preserving the background tone.

        Strategies
        ----------
        1. **Luminance gating** — Per-pixel luminance (BT.709 coefficients) is
           computed from the current canvas state.  Pixels are sorted into three
           zones: light, midtone (unchanged), and shadow.  A soft falloff is
           applied: the correction strength ramps from zero at the threshold to
           full at the zone extreme, avoiding a hard step.

        2. **Warm light push** — Light-zone R + G lift, B slight damp.  The
           asymmetric weighting (R > G > B) targets the ivory-amber of lit skin
           rather than a generic white push.

        3. **Cool shadow deepen** — Shadow-zone R + G damp (darkening), B lift
           (cooling).  The B lift is smaller than the R+G damp so the net effect
           is a *darker* cool, not a bright blue.

        4. **Mask compositing** — When ``figure_mask`` (float32 H×W in [0,1])
           is provided, adjustments are weighted by the mask: corrections are
           full-strength at mask=1 and zero at mask=0.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 array of shape ``(H, W)`` with values in [0, 1].  1 = fully
            inside figure, 0 = background.  If None, the pass operates on the
            full canvas.
        light_thresh : float
            Luminance threshold above which a pixel is considered 'in the
            light'.  0.65 catches highlights and upper mid-tones.
        shadow_thresh : float
            Luminance threshold below which a pixel is considered 'in shadow'.
            0.38 catches deep shadows and lower mid-tones.
        light_warmth : float
            Magnitude of the warm push on the lit side.  0.10 is noticeable
            but restrained — suitable for a Renaissance portrait.
        shadow_cool : float
            Magnitude of the B channel lift in shadow zones.  0.08 gives a
            cold-air quality without turning shadows blue.
        shadow_deepen : float
            Magnitude of the R+G channel damp in shadow zones.  0.07 darkens
            the shadows while the B lift adds coolness.
        opacity : float
            Global blend weight applied to the full adjusted layer.

        Notes
        -----
        Apply AFTER ``build_form()`` and ``sfumato_veil_pass()`` (if used),
        BEFORE the final glaze.  Pairs naturally with ``subsurface_glow_pass()``
        (warm sub-surface scatter in the lit zone amplifies the warm reading)
        and ``reflected_light_pass()`` (bounce light in shadow zones).
        """
        import numpy as _np

        print(f"  Chiaroscuro modelling pass  "
              f"(light_thresh={light_thresh:.2f}  shadow_thresh={shadow_thresh:.2f}  "
              f"light_warmth={light_warmth:.2f}  shadow_cool={shadow_cool:.2f}  "
              f"shadow_deepen={shadow_deepen:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Chiaroscuro modelling pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Luminance (BT.709) ───────────────────────────────────────────────
        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f  # (H, W)

        # ── Soft zone weights ────────────────────────────────────────────────
        # light_w ramps 0→1 as lum rises from light_thresh to 1.0
        light_range = max(1e-6, 1.0 - light_thresh)
        light_w     = _np.clip((lum - light_thresh) / light_range, 0.0, 1.0)

        # shadow_w ramps 0→1 as lum falls from shadow_thresh to 0.0
        shadow_range = max(1e-6, shadow_thresh)
        shadow_w     = _np.clip(1.0 - lum / shadow_range, 0.0, 1.0)

        # ── Apply figure mask if provided ────────────────────────────────────
        if figure_mask is not None:
            fm   = _np.asarray(figure_mask, dtype=_np.float32)
            if fm.shape != (h, w):
                # resize mask to canvas dimensions if needed
                from scipy.ndimage import zoom as _zoom
                fm = _zoom(fm, (h / fm.shape[0], w / fm.shape[1]), order=1)
                fm = _np.clip(fm, 0.0, 1.0)
            light_w  = light_w  * fm
            shadow_w = shadow_w * fm

        # ── 1. Warm light push ───────────────────────────────────────────────
        r_out = _np.clip(r_f + light_w * light_warmth * 0.90, 0.0, 1.0)
        g_out = _np.clip(g_f + light_w * light_warmth * 0.70, 0.0, 1.0)
        b_out = _np.clip(b_f - light_w * light_warmth * 0.25, 0.0, 1.0)

        # ── 2. Cool shadow deepen ────────────────────────────────────────────
        r_out = _np.clip(r_out - shadow_w * shadow_deepen, 0.0, 1.0)
        g_out = _np.clip(g_out - shadow_w * shadow_deepen * 0.90, 0.0, 1.0)
        b_out = _np.clip(b_out + shadow_w * shadow_cool,   0.0, 1.0)

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]   # alpha unchanged

        # Write back to Cairo surface
        self.canvas.surface.get_data()[:] = buf.tobytes()

        light_count  = int((light_w  > 0.05).sum())
        shadow_count = int((shadow_w > 0.05).sum())
        print(f"    Chiaroscuro modelling pass complete  "
              f"(light_pixels={light_count}  shadow_pixels={shadow_count})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 51 — artist pass: bellini_sacred_light_pass
    # ──────────────────────────────────────────────────────────────────────────

    def bellini_sacred_light_pass(
        self,
        figure_mask:      "Optional[_np.ndarray]" = None,
        light_thresh:     float = 0.62,
        shadow_thresh:    float = 0.32,
        honey_warmth:     float = 0.12,
        lapis_cool:       float = 0.10,
        halo_thresh:      float = 0.82,
        halo_gold:        float = 0.06,
        opacity:          float = 0.70,
    ) -> None:
        """
        Apply the crystalline sacred luminosity of Giovanni Bellini's glazing technique.

        Bellini was the first Venetian master to fully exploit the transparency of
        oil paint as a glazing medium.  He adopted the Flemish technique (brought
        to Venice by Antonello da Messina c. 1475) and transformed it with an
        unmistakably Italian warm, golden quality.

        His sacred figures — Madonnas, saints, the enthroned Christ — glow with
        an interior warmth that is both technically and spiritually distinctive.
        The effect comes from three layered interactions:

        1. **Honey-amber glaze in the light zone** — Bellini applied a warm amber
           glaze (raw sienna diluted in oil) over the lit passages of flesh and drapery.
           This warm glaze over the cool white gesso reflector creates the characteristic
           ivory-gold quality of his lit flesh, distinct from both the cooler Flemish
           tradition and the more sfumatoed Florentine approach.

        2. **Lapis lazuli depth in shadows** — Deep shadow passages received thin
           transparent glazes of lapis lazuli or indigo, giving the shadows a cool
           blue-violet depth that recedes optically.  This warm light / cool shadow
           contrast generates the three-dimensional solidity that distinguishes his
           mature altarpieces from his earlier tempera work.

        3. **Golden halo zone in the brightest highlights** — The very brightest
           pixels — the lit crown of the head, the shoulder peak, the white of the
           eye, the knuckle highlight — receive a faint golden push toward warm
           ivory.  This simulates the slight warm lead-white highlight that Bellini
           applied as final impasto touches over the dried glaze layers, giving the
           highlights a warm, solid, material quality rather than cold specular glare.

        Strategies
        ----------
        1. **Luminance gating** — BT.709 luminance partitions pixels into three
           zones: light (``lum > light_thresh``), shadow (``lum < shadow_thresh``),
           and midtone (unchanged).  Soft ramps from the thresholds prevent banding.

        2. **Honey light push** — In the light zone: lift R and G toward warm amber,
           slight B damp.  Asymmetric weights (R 0.85, G 0.65, B −0.20) reproduce
           the warm-ivory quality of Bellini's flesh glazes — neither white nor gold,
           but the precise ivory-honey of his Madonnas.

        3. **Lapis shadow push** — In the shadow zone: lift B (lapis coolness),
           slight R damp.  The B lift is stronger than the R damp so the net result
           is a cool but not dark shadow — receding blue depth rather than black mud.

        4. **Golden halo zone** — Pixels with luminance above ``halo_thresh`` receive
           a further warm push: a gentle R + G lift (``halo_gold``) that turns the
           brightest white into warm ivory.  Keeps highlights from appearing cold.

        5. **Mask compositing** — When ``figure_mask`` is provided, all three
           corrections are weighted by the mask so the background is unaffected.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 array ``(H, W)`` in [0, 1].  1 = figure, 0 = background.
        light_thresh : float
            Luminance threshold for the light zone.  0.62 covers highlights and
            upper mid-tones without reaching into the deep midtone.
        shadow_thresh : float
            Luminance threshold below which a pixel is considered shadow.
            0.32 catches deep shadows and lower mid-tones.
        honey_warmth : float
            Magnitude of the warm honey push in the light zone.  0.12 gives a
            visible but restrained warm glow without yellowing.
        lapis_cool : float
            Magnitude of the blue (lapis) lift in shadow zones.  0.10 gives the
            cool receding quality of lapis shadow glazes.
        halo_thresh : float
            Luminance threshold above which the golden halo push applies.
            0.82 captures only the brightest highlights.
        halo_gold : float
            Strength of the warm ivory push on halo-zone pixels.  0.06 is subtle
            — a faint gold cast, not a yellow highlight.
        opacity : float
            Global blend weight for the pass result over the original canvas.

        Notes
        -----
        Apply AFTER ``build_form()`` and before the final glaze.  Pairs naturally
        with ``venetian_glaze_pass()`` (adds further warm oil depth), ``subsurface_
        glow_pass()`` (warm SSS reinforces the honey light zone), and
        ``sfumato_veil_pass()`` (if used — apply sfumato before this pass so the
        warm glow overlays the softened edges).
        """
        import numpy as _np

        print(f"  Bellini sacred light pass  "
              f"(light_thresh={light_thresh:.2f}  shadow_thresh={shadow_thresh:.2f}  "
              f"honey_warmth={honey_warmth:.2f}  lapis_cool={lapis_cool:.2f}  "
              f"halo_thresh={halo_thresh:.2f}  halo_gold={halo_gold:.2f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Bellini sacred light pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Luminance (BT.709) ───────────────────────────────────────────────
        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        # ── Soft zone weights ────────────────────────────────────────────────
        light_range = max(1e-6, 1.0 - light_thresh)
        light_w     = _np.clip((lum - light_thresh) / light_range, 0.0, 1.0)

        shadow_range = max(1e-6, shadow_thresh)
        shadow_w     = _np.clip(1.0 - lum / shadow_range, 0.0, 1.0)

        halo_range   = max(1e-6, 1.0 - halo_thresh)
        halo_w       = _np.clip((lum - halo_thresh) / halo_range, 0.0, 1.0)

        # ── Apply figure mask if provided ────────────────────────────────────
        if figure_mask is not None:
            fm = _np.asarray(figure_mask, dtype=_np.float32)
            if fm.shape != (h, w):
                from scipy.ndimage import zoom as _zoom
                fm = _zoom(fm, (h / fm.shape[0], w / fm.shape[1]), order=1)
                fm = _np.clip(fm, 0.0, 1.0)
            light_w  = light_w  * fm
            shadow_w = shadow_w * fm
            halo_w   = halo_w   * fm

        # ── 1. Honey-amber light push ─────────────────────────────────────────
        r_out = _np.clip(r_f + light_w * honey_warmth * 0.85, 0.0, 1.0)
        g_out = _np.clip(g_f + light_w * honey_warmth * 0.65, 0.0, 1.0)
        b_out = _np.clip(b_f - light_w * honey_warmth * 0.20, 0.0, 1.0)

        # ── 2. Lapis lazuli shadow push ───────────────────────────────────────
        r_out = _np.clip(r_out - shadow_w * lapis_cool * 0.35, 0.0, 1.0)
        g_out = _np.clip(g_out - shadow_w * lapis_cool * 0.10, 0.0, 1.0)
        b_out = _np.clip(b_out + shadow_w * lapis_cool * 1.00, 0.0, 1.0)

        # ── 3. Golden halo zone ───────────────────────────────────────────────
        r_out = _np.clip(r_out + halo_w * halo_gold * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + halo_w * halo_gold * 0.80, 0.0, 1.0)
        # B unchanged in halo zone — keep highlights warm ivory, not white

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        light_count  = int((light_w  > 0.05).sum())
        shadow_count = int((shadow_w > 0.05).sum())
        halo_count   = int((halo_w   > 0.05).sum())
        print(f"    Bellini sacred light pass complete  "
              f"(light_px={light_count}  shadow_px={shadow_count}  halo_px={halo_count})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 51 — random improvement: penumbra_zone_pass
    # ──────────────────────────────────────────────────────────────────────────

    def penumbra_zone_pass(
        self,
        figure_mask:      "Optional[_np.ndarray]" = None,
        light_thresh:     float = 0.62,
        shadow_thresh:    float = 0.35,
        penumbra_warmth:  float = 0.08,
        penumbra_chroma:  float = 0.06,
        opacity:          float = 0.65,
    ) -> None:
        """
        Enrich the penumbra zone — the transition between lit and shadow flesh.

        The penumbra is the soft band of transitional tone between the directly lit
        surface of a face and the shadowed side.  In life this zone has a subtle
        but important warm-rosy quality: the blood vessels beneath the skin are
        most visible in this transitional zone where the surface curves away from
        the light, and where subsurface scattering is strongest.

        Classical painters understood this empirically.  Rubens called it the
        *"demitint"* (half-tone); his flesh glazes were warmest not in the full
        light but in this transitional zone.  Rembrandt's penumbra passages carry
        a warm amber-brown glow.  Titian's demi-tints are the most celebrated in
        Western painting: a warm peach-sienna passage that makes his flesh appear
        genuinely alive rather than painted.

        This pass targets exactly this zone — the luminance band between
        ``shadow_thresh`` and ``light_thresh`` — and applies a gentle warm blush
        (slight R and G lift) plus a modest chroma boost (saturation increase in
        the midtone) to make the transitional flesh more vivid and alive.

        Strategies
        ----------
        1. **Penumbra weight** — The weight function is a tent shape: 0 at both
           the light threshold and the shadow threshold, reaching maximum 1.0 at
           the midpoint of the two.  This ensures the correction is strongest in
           the true penumbra centre and fades smoothly to zero at both edges,
           avoiding any hard step at either boundary.

        2. **Warm blush** — A gentle R lift (``penumbra_warmth × 0.80``) and
           G lift (``× 0.45``) with no B change pushes toward warm peach-rose
           in the penumbra.  This reproduces the warm blood-flush visible in life
           at the light-to-shadow transition of the cheeks and temples.

        3. **Chroma boost** — The penumbra zone also receives a modest saturation
           increase: the RGB values are pushed away from their luminance (toward
           their chroma direction) by ``penumbra_chroma``.  This prevents the warm
           blush from looking washed-out and gives the transitional zone the
           vibrant living quality of Titian's demi-tints.

        4. **Mask compositing** — When ``figure_mask`` is provided, corrections are
           weighted by the mask, confining the blush to the figure and leaving the
           background neutral.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 array ``(H, W)`` in [0, 1].  1 = figure, 0 = background.
        light_thresh : float
            Upper luminance boundary of the penumbra zone.  Pixels above this
            are in the full light and receive no blush.  0.62 matches the default
            light zone threshold of chiaroscuro_modelling_pass().
        shadow_thresh : float
            Lower luminance boundary of the penumbra zone.  Pixels below this
            are in deep shadow and receive no blush.  0.35 catches the upper
            shadow fringe rather than the deep void.
        penumbra_warmth : float
            Magnitude of the warm blush R+G push in the penumbra zone.  0.08
            is subtly visible — a warm flush, not a paint-bucket fill.
        penumbra_chroma : float
            Magnitude of the chroma (saturation) boost in the penumbra.  0.06
            enriches the blush without over-saturating.
        opacity : float
            Global blend weight for the pass result over the original canvas.

        Notes
        -----
        Apply AFTER ``build_form()`` and ``chiaroscuro_modelling_pass()`` (if
        used) so the warm/cool split is already established before the penumbra
        enrichment is applied.  Pairs naturally with ``subsurface_glow_pass()``
        (warm SSS in the light zone extends into the penumbra) and
        ``reflected_light_pass()`` (the cool shadow bounce sets the dark boundary
        of the zone this pass enriches).
        """
        import numpy as _np

        print(f"  Penumbra zone pass  "
              f"(light_thresh={light_thresh:.2f}  shadow_thresh={shadow_thresh:.2f}  "
              f"penumbra_warmth={penumbra_warmth:.2f}  penumbra_chroma={penumbra_chroma:.2f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Penumbra zone pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Luminance (BT.709) ───────────────────────────────────────────────
        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        # ── Penumbra tent weight ──────────────────────────────────────────────
        # Tent: peaks at the midpoint of [shadow_thresh, light_thresh], 0 outside.
        mid = (light_thresh + shadow_thresh) * 0.5
        half_width = max(1e-6, (light_thresh - shadow_thresh) * 0.5)
        pen_w = _np.clip(1.0 - _np.abs(lum - mid) / half_width, 0.0, 1.0)

        # ── Apply figure mask if provided ────────────────────────────────────
        if figure_mask is not None:
            fm = _np.asarray(figure_mask, dtype=_np.float32)
            if fm.shape != (h, w):
                from scipy.ndimage import zoom as _zoom
                fm = _zoom(fm, (h / fm.shape[0], w / fm.shape[1]), order=1)
                fm = _np.clip(fm, 0.0, 1.0)
            pen_w = pen_w * fm

        # ── 1. Warm blush push ────────────────────────────────────────────────
        r_out = _np.clip(r_f + pen_w * penumbra_warmth * 0.80, 0.0, 1.0)
        g_out = _np.clip(g_f + pen_w * penumbra_warmth * 0.45, 0.0, 1.0)
        b_out = b_f.copy()   # B unchanged — a red-gold blush, not orange

        # ── 2. Chroma boost in penumbra zone ──────────────────────────────────
        # Push RGB away from their luminance toward their chroma direction.
        # delta = (r, g, b) − lum → normalize, then push outward
        lum3 = lum[:, :, _np.newaxis] if lum.ndim == 2 else lum
        rgb  = _np.stack([r_out, g_out, b_out], axis=-1)   # (H, W, 3)
        lum_s = lum[:, :, None]
        delta = rgb - lum_s   # colour deviation from grey (H, W, 3)
        chroma_push = pen_w[:, :, None] * penumbra_chroma
        rgb_boosted = _np.clip(rgb + delta * chroma_push, 0.0, 1.0)
        r_out, g_out, b_out = rgb_boosted[..., 0], rgb_boosted[..., 1], rgb_boosted[..., 2]

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        pen_count = int((pen_w > 0.05).sum())
        print(f"    Penumbra zone pass complete  (penumbra_pixels={pen_count})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 52 — new artist: Pontormo / FLORENTINE_MANNERIST
    # ──────────────────────────────────────────────────────────────────────────

    def pontormo_dissonance_pass(
        self,
        figure_mask:      "Optional[_np.ndarray]" = None,
        light_thresh:     float = 0.60,
        shadow_thresh:    float = 0.32,
        acid_lift:        float = 0.14,
        violet_push:      float = 0.12,
        midtone_chroma:   float = 0.10,
        opacity:          float = 0.68,
    ) -> None:
        """
        Apply Pontormo's signature chromatic dissonance to the canvas.

        Jacopo Pontormo (1494–1557) abandoned the warm harmonic colour systems
        of the High Renaissance in favour of a deliberately unsettling palette:
        acid chartreuse in the lights, cold violet-black in the shadows, and a
        competing tension of rose and chartreuse in the midtones that denies the
        viewer a comfortable resting point.  The effect is one of sustained
        chromatic anxiety — a visual correlate of the psychological intensity
        that characterises his greatest work, the Deposition from the Cross
        (Capponi Chapel, Florence, c.1525–28).

        This pass applies three distinct zone corrections:

        1. **Highlight zone** (``lum > light_thresh``): Pushes the lit passages
           toward acid lemon-yellow by lifting R strongly and G moderately while
           reducing B.  This produces the characteristic cold-warm paradox of
           Pontormo's lights — they are bright but not warm in the conventional
           ivory-to-gold sense; instead they carry the acid quality of a lemon
           or chartreuse that sits at the hot-cool boundary.

        2. **Shadow zone** (``lum < shadow_thresh``): Pushes the shadow
           passages toward cool violet-black by reducing R and boosting B
           significantly.  Pontormo's shadows are not warm Rembrandt umbers;
           they are cold, slightly purple-tinged near-blacks that make the
           surrounding acid colours appear even more dissonant by contrast.

        3. **Midtone zone**: Applies a spatially modulated chroma push: pixels
           in the left half of the canvas receive a rose-carmine pull (R boost,
           slight B push) while pixels in the right half receive a chartreuse
           pull (G boost, R moderate).  This creates the competing colour
           tension across the midtone band that reads as Pontormo's instinctive
           refusal to let any colour zone fully resolve into harmonic agreement
           with its neighbours.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 array ``(H, W)`` in [0, 1].  When provided, the correction
            is weighted by the mask so the dissonance is strongest on the figure
            and fades toward the neutral background.
        light_thresh : float
            Luminance boundary above which the acid-yellow highlight push is
            applied.  0.60 catches the upper midtone zone as well as the
            direct lights, giving a broad, assertive acid highlight zone.
        shadow_thresh : float
            Luminance boundary below which the violet-black shadow push is
            applied.  0.32 targets the core shadow without eating into the
            penumbra zone, which is left for the midtone correction.
        acid_lift : float
            Strength of the acid lemon-yellow highlight push.  0.14 is a
            visible, assertive lift — Pontormo's highlights are unmistakably
            acid, not subtle.
        violet_push : float
            Strength of the violet-black shadow push.  0.12 gives a clearly
            cooler, more purple shadow without becoming a digital chroma-key.
        midtone_chroma : float
            Strength of the spatial rose/chartreuse chroma pull in the midtone
            zone.  0.10 is a moderate pull — visible in the midtones without
            dominating the composition.
        opacity : float
            Global blend weight for the entire pass over the original canvas.

        Notes
        -----
        Apply AFTER ``build_form()`` and before final glaze.  Pairs with a cool
        grey ``glaze()`` (not warm amber) to reinforce the Mannerist palette.
        Do NOT combine with ``sfumato_veil_pass()`` — sfumato warms and softens;
        Pontormo's dissonance requires crisp, unsmoked colour zones.
        """
        import numpy as _np

        print(f"  Pontormo dissonance pass  "
              f"(light_thresh={light_thresh:.2f}  shadow_thresh={shadow_thresh:.2f}  "
              f"acid_lift={acid_lift:.2f}  violet_push={violet_push:.2f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Pontormo dissonance pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Luminance (BT.709) ───────────────────────────────────────────────
        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        # ── Zone weights ─────────────────────────────────────────────────────
        light_w  = _np.clip((lum - light_thresh) / (1.0 - light_thresh + 1e-6), 0.0, 1.0)
        shadow_w = _np.clip((shadow_thresh - lum) / (shadow_thresh + 1e-6), 0.0, 1.0)
        mid_w    = _np.clip(1.0 - light_w - shadow_w, 0.0, 1.0)

        # ── Spatial left/right split for midtone dissonance ──────────────────
        # xs: 0.0 at left edge, 1.0 at right edge — (H, W) broadcast
        xs = _np.linspace(0.0, 1.0, w, dtype=_np.float32)[_np.newaxis, :]  # (1, W)
        rose_w  = mid_w * _np.clip(0.55 - xs, 0.0, 1.0) * 2.0   # left → rose
        chart_w = mid_w * _np.clip(xs - 0.45, 0.0, 1.0) * 2.0   # right → chartreuse

        # ── Apply figure mask ────────────────────────────────────────────────
        if figure_mask is not None:
            fm = _np.asarray(figure_mask, dtype=_np.float32)
            if fm.shape != (h, w):
                from scipy.ndimage import zoom as _zoom
                fm = _zoom(fm, (h / fm.shape[0], w / fm.shape[1]), order=1)
                fm = _np.clip(fm, 0.0, 1.0)
            light_w  = light_w  * fm
            shadow_w = shadow_w * fm
            rose_w   = rose_w   * fm
            chart_w  = chart_w  * fm

        # ── 1. Acid lemon-yellow highlight push ───────────────────────────────
        # R up strong, G up moderate, B down — acid chartreuse-yellow
        r_out = _np.clip(r_f + light_w * acid_lift * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_f + light_w * acid_lift * 0.75, 0.0, 1.0)
        b_out = _np.clip(b_f - light_w * acid_lift * 0.55, 0.0, 1.0)

        # ── 2. Violet-black shadow push ───────────────────────────────────────
        # R down, G slightly down, B up — cool violet-black
        r_out = _np.clip(r_out - shadow_w * violet_push * 0.90, 0.0, 1.0)
        g_out = _np.clip(g_out - shadow_w * violet_push * 0.30, 0.0, 1.0)
        b_out = _np.clip(b_out + shadow_w * violet_push * 0.60, 0.0, 1.0)

        # ── 3. Midtone spatial dissonance ─────────────────────────────────────
        # Left: rose-carmine pull (R up, slight B up)
        r_out = _np.clip(r_out + rose_w  * midtone_chroma * 0.80, 0.0, 1.0)
        b_out = _np.clip(b_out + rose_w  * midtone_chroma * 0.20, 0.0, 1.0)
        # Right: chartreuse pull (G up, R moderate up, B down)
        r_out = _np.clip(r_out + chart_w * midtone_chroma * 0.45, 0.0, 1.0)
        g_out = _np.clip(g_out + chart_w * midtone_chroma * 0.85, 0.0, 1.0)
        b_out = _np.clip(b_out - chart_w * midtone_chroma * 0.40, 0.0, 1.0)

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        light_count  = int((light_w  > 0.05).sum())
        shadow_count = int((shadow_w > 0.05).sum())
        mid_count    = int((mid_w    > 0.05).sum())
        print(f"    Pontormo dissonance pass complete  "
              f"(light_px={light_count}  shadow_px={shadow_count}  mid_px={mid_count})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 52 — random improvement: aerial_perspective_pass
    # ──────────────────────────────────────────────────────────────────────────

    def aerial_perspective_pass(
        self,
        sky_band:             float = 0.45,
        fade_power:           float = 2.2,
        desaturation:         float = 0.55,
        cool_push:            float = 0.10,
        haze_lift:            float = 0.06,
        opacity:              float = 0.72,
        warm_foreground_push: float = 0.0,
        fg_band:              float = 0.35,
    ) -> None:
        """
        Apply systematic aerial (atmospheric) perspective to the upper canvas zone.

        Aerial perspective — the optical phenomenon by which distant objects
        appear lighter, bluer, and less saturated than near objects — was first
        codified by Leonardo da Vinci in his notebooks and is visible in the
        Mona Lisa's famous hazy background landscape.  The principle derives from
        the physical reality that atmospheric particles (water vapour, dust,
        aerosols) scatter shorter wavelengths (blue) preferentially and absorb
        longer wavelengths (red, green), causing the following perceptual shifts
        with increasing distance:

        - **Desaturation**: colours lose their purity, converging toward neutral grey
        - **Cool push**: the residual hue drifts toward blue-grey (atmospheric blue)
        - **Value lift**: shadows lighten toward the atmospheric tone (near-white haze)
        - **Edge softening**: distant contours dissolve into the ambient atmosphere

        This pass applies a vertical weight gradient — maximum at the top of the
        canvas (sky and far horizon), fading to zero at ``sky_band * H`` — and
        applies three corrections weighted by that gradient:

        1. **Desaturation**: pixels are blended toward their BT.709 luminance
           (grey) by ``desaturation × weight``.  This models the loss of chroma
           that accumulates over distance as atmospheric particles scatter colour
           out of the light path.

        2. **Cool push**: the desaturated result is pushed further toward cool
           blue-grey by boosting B and reducing R in proportion to ``cool_push``
           and the atmospheric weight.  This models the preferential scattering
           of short-wavelength (blue) light, which tints the atmosphere itself
           blue and simultaneously removes the warm wavelengths from distant objects.

        3. **Haze lift**: the overall luminance in the atmospheric zone is raised
           by ``haze_lift × weight``.  In nature, the atmospheric column between
           the observer and a distant surface adds a veil of semi-luminous haze;
           even a dark distant mountain reads lighter than a nearby shadow of
           the same tonal value.

        Parameters
        ----------
        sky_band : float
            Fractional height from the top of the canvas over which the
            atmospheric effect is applied.  0.45 = upper 45% of the image.
            Below this line the weight fades to zero and the pass has no effect.
        fade_power : float
            Power exponent of the vertical weight gradient.  Higher values make
            the effect more concentrated at the very top (faster fade from the
            top edge).  2.2 gives a natural-looking quadratic falloff that
            matches the perceptual experience of aerial perspective.
        desaturation : float
            Maximum desaturation applied at the top of the canvas.  0.55 gives
            a clearly atmospheric haze in the far sky zone; 0.0 disables
            desaturation while allowing the cool push and haze lift alone.
        cool_push : float
            Maximum blue-grey push applied at the top.  0.10 is a gentle but
            clearly visible cool shift in the sky zone.
        haze_lift : float
            Maximum luminance lift applied at the top.  0.06 is a subtle veil
            of atmospheric light — visible in the distant sky but not washing
            out foreground tones (which receive near-zero weight).
        opacity : float
            Global blend weight for the pass result over the original canvas.
        warm_foreground_push : float
            **Improvement (session 59+):** When > 0, applies a complementary
            warm push to the lower foreground zone — the inverse of the cool
            atmospheric push applied to the sky.  This implements the complete
            atmospheric perspective principle: not only does distance make
            objects cooler and more desaturated, but proximity makes them
            comparatively warmer and more saturated.  Venetian painters —
            Titian, Tiepolo, Veronese — consistently exploited this contrast:
            foreground figures glow with warm ochre and vermilion while the
            background recedes into cool grey-blue haze.

            The warm push boosts R slightly and suppresses B slightly in the
            lower ``fg_band`` fraction of the canvas, weighted by a gradient
            that peaks at the bottom edge and fades to zero at ``fg_band * H``.
            At ``warm_foreground_push=0.08`` the foreground receives a subtle
            but perceptible warmth relative to the sky zone; at 0.15 the
            contrast is more theatrical (appropriate for Tiepolo or Rubens).
            Default 0.0 preserves the existing behaviour exactly.
        fg_band : float
            Fractional height from the bottom of the canvas over which the
            warm foreground push is applied.  0.35 = lower 35% of the image.
            Has no effect if ``warm_foreground_push`` is 0.

        Notes
        -----
        Apply AFTER ``build_form()`` and before ``place_lights()`` so the
        atmospheric haze is established before the final light accents are
        placed.  Pairs especially well with ``sfumato_veil_pass()`` (which
        softens edges) and ``tonal_envelope_pass()`` (which enriches the
        foreground figure separately from the receding background).  Do NOT
        apply to images with no landscape or sky zone — the effect has no
        meaning on flat-background portrait compositions.
        """
        import numpy as _np

        print(f"  Aerial perspective pass  "
              f"(sky_band={sky_band:.2f}  fade_power={fade_power:.2f}  "
              f"desaturation={desaturation:.2f}  cool_push={cool_push:.2f}  "
              f"haze_lift={haze_lift:.2f}  opacity={opacity:.2f}  "
              f"warm_fg={warm_foreground_push:.3f}) ...")

        if opacity <= 0.0:
            print("    Aerial perspective pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Vertical weight: 1.0 at top row, fading to 0 at sky_band * H ─────
        # ys: normalised position within the sky band [0 = top, 1 = bottom of band]
        sky_px = max(1, int(h * sky_band))
        ys = _np.linspace(0.0, 1.0, sky_px, dtype=_np.float32)   # (sky_px,)
        atm_weight_1d = _np.clip(1.0 - ys, 0.0, 1.0) ** fade_power  # (sky_px,)

        # Expand to full canvas height: zeros for rows below sky_band
        atm_w = _np.zeros((h,), dtype=_np.float32)
        atm_w[:sky_px] = atm_weight_1d
        atm_w = atm_w[:, _np.newaxis]   # (H, 1) — broadcast over W

        # ── 1. Desaturate toward luminance ────────────────────────────────────
        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f   # (H, W)
        desat = atm_w * desaturation   # (H, W)
        r_out = r_f * (1.0 - desat) + lum * desat
        g_out = g_f * (1.0 - desat) + lum * desat
        b_out = b_f * (1.0 - desat) + lum * desat

        # ── 2. Cool push: boost B, reduce R, toward atmospheric blue-grey ─────
        cool = atm_w * cool_push
        r_out = _np.clip(r_out - cool * 0.80, 0.0, 1.0)
        g_out = _np.clip(g_out - cool * 0.15, 0.0, 1.0)
        b_out = _np.clip(b_out + cool * 0.60, 0.0, 1.0)

        # ── 3. Haze lift: raise overall luminance in atmospheric zone ─────────
        haze = atm_w * haze_lift
        r_out = _np.clip(r_out + haze, 0.0, 1.0)
        g_out = _np.clip(g_out + haze, 0.0, 1.0)
        b_out = _np.clip(b_out + haze, 0.0, 1.0)

        # ── 4. Warm foreground push (session 59 improvement) ─────────────────
        # Applies the complementary half of atmospheric perspective: not only
        # does distance cool and desaturate, but proximity comparatively warms
        # and saturates.  Venetian masters (Titian, Tiepolo, Veronese) relied
        # on this contrast.  The gradient mirrors the sky band — maximum weight
        # at the bottom row, fading to zero at fg_band * H from the bottom.
        if warm_foreground_push > 0.0:
            fg_px = max(1, int(h * fg_band))
            # ys_fg: 0 at the bottom row, 1 at the top of the fg_band
            ys_fg = _np.linspace(0.0, 1.0, fg_px, dtype=_np.float32)
            fg_weight_1d = _np.clip(1.0 - ys_fg, 0.0, 1.0) ** fade_power
            fg_w = _np.zeros((h,), dtype=_np.float32)
            # fg_weight_1d[0] = bottom-most row of the fg_band → maps to h-1
            fg_w[h - fg_px:] = fg_weight_1d[::-1]
            fg_w = fg_w[:, _np.newaxis]   # (H, 1) — broadcast over W
            warm = fg_w * warm_foreground_push
            # Warm push: boost R, modest G, suppress B — Naples yellow / ochre push
            r_out = _np.clip(r_out + warm * 0.85, 0.0, 1.0)
            g_out = _np.clip(g_out + warm * 0.30, 0.0, 1.0)
            b_out = _np.clip(b_out - warm * 0.45, 0.0, 1.0)

        # ── Blend adjusted layer back at `opacity` ────────────────────────────
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - opacity) + r_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - opacity) + g_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - opacity) + b_out * opacity * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        atm_count = int((atm_w.squeeze() > 0.05).sum() * w)
        print(f"    Aerial perspective pass complete  (affected_px~{atm_count})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 53 — new artist: Rogier van der Weyden / weyden_angular_shadow_pass
    # ──────────────────────────────────────────────────────────────────────────

    def weyden_angular_shadow_pass(
        self,
        figure_mask:      "Optional[_np.ndarray]" = None,
        shadow_thresh:    float = 0.38,
        light_thresh:     float = 0.60,
        edge_sharpen:     float = 0.55,
        shadow_cool:      float = 0.08,
        highlight_cool:   float = 0.04,
        opacity:          float = 0.70,
    ) -> None:
        """
        Apply Rogier van der Weyden's angular, geometric shadow modelling.

        Rogier van der Weyden (c. 1399/1400–1464) achieved emotional intensity
        through the precise geometry of light and shadow.  Unlike Leonardo's
        sfumato — which dissolves tonal transitions into imperceptible atmospheric
        haze — Weyden's shadows have clean, angular found edges that describe the
        geometry of folded drapery with almost architectural clarity.  A cloth fold
        passes from brilliantly lit surface to near-black shadow in a single,
        sharp step.  This gives his robes, mantles, and shrouds the quality of
        carved stone: every plane fully resolved, every edge intentional.

        His flesh is correspondingly pale — almost waxen — with cool blue-tinged
        shadows rather than the warm ambers of Rembrandt or the glowing umbers of
        Titian.  The coolness in the shadows reads as a kind of spiritual rigour:
        where Rubens's flesh glows with vitality, Weyden's flesh endures with
        austere, grief-stricken dignity.

        This pass applies three distinct operations:

        1. **Shadow zone cooling** (``lum < shadow_thresh``): Shadow pixels
           receive a slight cool-violet push — R is reduced and B is lifted
           by ``shadow_cool``.  This gives the characteristic Flemish cool-
           shadow quality that distinguishes Weyden from the warm Venetians.

        2. **Edge sharpening at the penumbra boundary**: The pixels in the
           narrow band around the shadow threshold are pushed toward their
           extreme (toward full shadow or full light, depending on which side
           of the boundary they fall).  This is a local contrast stretch at
           the transition zone only — replicating the effect of a found edge.
           The strength is controlled by ``edge_sharpen``.

        3. **Highlight cooling** (``lum > light_thresh``): The lit passages
           receive a subtle cool-ivory push — a slight B lift by
           ``highlight_cool``.  Weyden's lit flesh is not warm ivory (as in
           Titian or Rembrandt) but pale, slightly cool — almost the tonality
           of white linen rather than warm skin.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 array ``(H, W)`` in [0, 1].  1 = figure, 0 = background.
            When provided, all corrections are composited only within the figure.
        shadow_thresh : float
            Luminance boundary below which pixels are treated as shadow.
            Default 0.38 matches a slightly deeper shadow zone than the
            penumbra_zone_pass boundary, capturing the full Flemish shadow void.
        light_thresh : float
            Luminance boundary above which pixels are treated as lit.
            Default 0.60 — a broad, bright-lit zone for pale Flemish flesh.
        edge_sharpen : float
            Strength of the found-edge contrast push at the light-shadow boundary.
            0.0 = no sharpening (smooth transition preserved); 1.0 = maximum
            push (extreme jump from lit to shadow at each boundary pixel).
            Default 0.55 — strong but not posterised.
        shadow_cool : float
            Magnitude of the cool-violet push in shadow zones.  Reduces R,
            lifts B.  0.08 produces a subtle but clearly visible cool shift.
        highlight_cool : float
            Magnitude of the pale-ivory cool lift in fully lit zones.  Lifts
            B gently.  0.04 is a light correction — barely perceptible alone
            but collectively shifts the flesh tonality from warm to pale.
        opacity : float
            Global blend factor: 0 = no effect, 1 = full correction applied.

        Notes
        -----
        Apply AFTER ``build_form()`` and before ``glaze()`` so the geometric
        shadow structure is established before any warm unifying layer is applied
        (a warm glaze applied afterward will slightly mellow the coolness —
        exactly as Weyden's oak panel ground does in his originals).
        Pairs well with ``holbein_jewel_glaze_pass()`` for panel-painting finish
        and ``edge_lost_and_found_pass()`` for final edge refinement.
        """
        import numpy as _np

        print(f"  Weyden angular shadow pass  "
              f"(shadow_thresh={shadow_thresh:.2f}  light_thresh={light_thresh:.2f}  "
              f"edge_sharpen={edge_sharpen:.2f}  shadow_cool={shadow_cool:.2f}  "
              f"highlight_cool={highlight_cool:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Weyden angular shadow pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f   # (H, W)

        # ── Figure mask weight ────────────────────────────────────────────────
        if figure_mask is not None:
            mask_w = _np.clip(
                _np.array(figure_mask, dtype=_np.float32), 0.0, 1.0
            )
            if mask_w.shape != (h, w):
                from PIL import Image as _Img
                mask_w = _np.array(
                    _Img.fromarray((mask_w * 255).astype(_np.uint8)).resize(
                        (w, h), _Img.BILINEAR
                    ), dtype=_np.float32
                ) / 255.0
        else:
            mask_w = _np.ones((h, w), dtype=_np.float32)

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Shadow zone cooling (lum < shadow_thresh) ─────────────────────
        # Push deep shadows toward cool violet: reduce R, lift B.
        shadow_zone = (lum < shadow_thresh).astype(_np.float32)
        r_out = _np.clip(r_out - shadow_zone * shadow_cool * 0.85, 0.0, 1.0)
        b_out = _np.clip(b_out + shadow_zone * shadow_cool * 0.70, 0.0, 1.0)

        # ── 2. Edge sharpening at the penumbra boundary ───────────────────────
        # The penumbra band is the zone between shadow_thresh and light_thresh.
        # Within this band, push each pixel toward whichever extreme (lit or
        # shadow) it is closest to — creating a sharper step at the boundary.
        penumbra_band = ((lum >= shadow_thresh) & (lum < light_thresh)).astype(
            _np.float32
        )
        # Normalised position within the band: 0 = deep shadow edge, 1 = light edge
        band_width = max(light_thresh - shadow_thresh, 1e-6)
        pos_in_band = _np.clip(
            (lum - shadow_thresh) / band_width, 0.0, 1.0
        )   # 0 near shadow, 1 near light

        # Pixels in the lower half of the band → push toward shadow (darken)
        # Pixels in the upper half of the band → push toward light (brighten)
        push_direction = (pos_in_band - 0.5) * 2.0   # [-1, +1]
        edge_correction = penumbra_band * edge_sharpen * push_direction * 0.15

        r_out = _np.clip(r_out + edge_correction, 0.0, 1.0)
        g_out = _np.clip(g_out + edge_correction * 0.85, 0.0, 1.0)
        b_out = _np.clip(b_out + edge_correction * 0.70, 0.0, 1.0)

        # ── 3. Highlight cooling (lum > light_thresh) ─────────────────────────
        # Weyden's lit flesh is cool pale ivory, not warm gold.  Lift B gently.
        light_zone = (lum >= light_thresh).astype(_np.float32)
        b_out = _np.clip(b_out + light_zone * highlight_cool, 0.0, 1.0)

        # ── Blend corrected layer back at `opacity`, weighted by mask ─────────
        blend = opacity * mask_w

        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - blend) + r_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - blend) + g_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - blend) + b_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        shadow_count    = int((shadow_zone > 0.5).sum())
        highlight_count = int((light_zone  > 0.5).sum())
        print(f"    Weyden angular shadow pass complete  "
              f"(shadow_px={shadow_count}  highlight_px={highlight_count})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 54 — new artist: Hans Memling / memling_jewel_light_pass
    # ──────────────────────────────────────────────────────────────────────────

    def memling_jewel_light_pass(
        self,
        figure_mask:         "Optional[_np.ndarray]" = None,
        highlight_thresh:    float = 0.72,
        midtone_low:         float = 0.32,
        midtone_high:        float = 0.58,
        jewel_strength:      float = 0.07,
        subsurface_strength: float = 0.055,
        opacity:             float = 0.72,
    ) -> None:
        """
        Apply Hans Memling's crystalline jewel-light luminosity to the canvas.

        Hans Memling (c. 1430/1440–1494) — trained in Rogier van der Weyden's
        Brussels workshop — transformed Early Netherlandish technique into a
        world of serene, jewel-like luminosity.  Where Weyden's shadows are
        tense and architectural, Memling's lights are warm and crystalline:
        the brightest highlight passages read as polished enamel — brilliant,
        cold, and luminous rather than simply pale.

        He achieved this through stacked transparent oil glazes on a chalk-
        white gesso ground.  Each glaze layer (lead white + pale ochre) was
        dried separately, so light could pass through the paint film, reflect
        from the white ground, and exit cooled and brightened.  The result:
        highlights that have interior depth rather than surface opaqueness.

        The other defining quality is the blue-green coolness in the shadow
        transitions of his flesh.  Unlike Rembrandt's warm amber shadows or
        Titian's glowing umbers, Memling's mid-tones carry a subtle blue-green
        undertone — the Flemish subsurface quality — that reads as translucent
        skin with light scattering through it before exiting.

        This pass applies two operations:

        1. **Jewel-highlight push** (``lum > highlight_thresh``): The brightest
           pixels are pushed toward cool pale ivory — R is gently reduced and
           B is lifted, making the highlights read as slightly cooler and more
           luminous than the warm mid-tones.  Unlike Rembrandt's warm golden
           highlights, Memling's lights are almost white with a faint blue
           quality, like the reflection from polished silver.  Controlled by
           ``jewel_strength``.

        2. **Subsurface mid-tone tint** (``midtone_low ≤ lum < midtone_high``):
           The shadow-transition zone receives a gentle blue-green push — G
           and B lifted slightly, R reduced fractionally.  This mimics the
           effect of light scattering through translucent skin and exiting
           slightly cooled and greenish.  Controlled by ``subsurface_strength``.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 array ``(H, W)`` in [0, 1].  1 = figure, 0 = background.
            When provided, corrections are applied only within the figure.
        highlight_thresh : float
            Luminance threshold above which pixels are treated as bright
            highlights.  Default 0.72 — a high value to target only the
            genuine enamel-bright specular zones, not the mid-tones.
        midtone_low : float
            Lower luminance bound for the subsurface mid-tone band.
            Default 0.32 — below this the shadows are too deep for the
            translucent effect.
        midtone_high : float
            Upper luminance bound for the subsurface mid-tone band.
            Default 0.58 — above this the flesh begins to be clearly lit.
        jewel_strength : float
            Magnitude of the cool ivory push in the highlight zone.  Lifts B,
            reduces R fractionally.  Default 0.07 — visible but not stark.
        subsurface_strength : float
            Magnitude of the blue-green push in the mid-tone shadow zone.
            Lifts G and B, reduces R slightly.  Default 0.055 — a subtle
            glowing coolness rather than an obvious colour shift.
        opacity : float
            Global blend factor: 0 = no effect, 1 = full correction.

        Notes
        -----
        Apply AFTER ``build_form()`` — the subsurface quality is a refinement
        of the modelled form, not a substitute for it.  Works well before a
        warm ``glaze()`` call: the warm glaze will slightly mellow the cool
        quality, exactly as Memling's final amber varnish does on his panels.
        Pairs naturally with ``weyden_angular_shadow_pass()`` (which cools the
        deepest shadows); Memling handled the highlights and mid-shadows,
        while the Weyden pass handles the dark shadow geometry.
        """
        import numpy as _np

        print(f"  Memling jewel-light pass  "
              f"(highlight_thresh={highlight_thresh:.2f}  "
              f"midtone_low={midtone_low:.2f}  midtone_high={midtone_high:.2f}  "
              f"jewel_strength={jewel_strength:.3f}  "
              f"subsurface_strength={subsurface_strength:.3f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Memling jewel-light pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f   # (H, W)

        # ── Figure mask weight ────────────────────────────────────────────────
        if figure_mask is not None:
            mask_w = _np.clip(
                _np.array(figure_mask, dtype=_np.float32), 0.0, 1.0
            )
            if mask_w.shape != (h, w):
                from PIL import Image as _Img
                mask_w = _np.array(
                    _Img.fromarray((mask_w * 255).astype(_np.uint8)).resize(
                        (w, h), _Img.BILINEAR
                    ), dtype=_np.float32
                ) / 255.0
        else:
            mask_w = _np.ones((h, w), dtype=_np.float32)

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Jewel highlight push (lum > highlight_thresh) ──────────────────
        # Lift the brightest zones toward cool ivory: B up, R slightly down.
        # Memling's highlights are not warm gold (Rembrandt) but cool enamel-
        # white — as if the light has been filtered through a thin silver mirror.
        highlight_zone = (lum > highlight_thresh).astype(_np.float32)
        # Scale the push by how far above the threshold the pixel is — the
        # very brightest pixels get the full push; pixels just above threshold
        # receive only a fractional correction.
        highlight_excess = _np.clip(
            (lum - highlight_thresh) / max(1.0 - highlight_thresh, 1e-6),
            0.0, 1.0
        )
        highlight_w = highlight_zone * highlight_excess
        b_out = _np.clip(b_out + highlight_w * jewel_strength,           0.0, 1.0)
        r_out = _np.clip(r_out - highlight_w * jewel_strength * 0.40,    0.0, 1.0)

        # ── 2. Subsurface mid-tone tint (midtone_low ≤ lum < midtone_high) ───
        # Lift G and B in the shadow-transition band, reduce R fractionally.
        # This mimics light scattering through translucent skin: wavelengths
        # in the blue-green range penetrate more shallowly and exit from the
        # surface adjacent to the entry point, giving the transition zones a
        # slightly cooler, glowing quality.
        midtone_zone = (
            (lum >= midtone_low) & (lum < midtone_high)
        ).astype(_np.float32)

        # Weight peaks in the middle of the mid-tone band — subtlest at edges,
        # strongest at the centre of the transition zone (most translucent area).
        band_width = max(midtone_high - midtone_low, 1e-6)
        band_pos   = _np.clip((lum - midtone_low) / band_width, 0.0, 1.0)
        # Triangular weighting: 0 at band edges, 1 at centre
        sub_weight = midtone_zone * (1.0 - _np.abs(band_pos * 2.0 - 1.0))

        g_out = _np.clip(g_out + sub_weight * subsurface_strength * 0.70, 0.0, 1.0)
        b_out = _np.clip(b_out + sub_weight * subsurface_strength,         0.0, 1.0)
        r_out = _np.clip(r_out - sub_weight * subsurface_strength * 0.30,  0.0, 1.0)

        # ── Blend corrected layer back at `opacity`, weighted by mask ─────────
        blend = opacity * mask_w

        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - blend) + r_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - blend) + g_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - blend) + b_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        highlight_count  = int((highlight_zone  > 0.5).sum())
        midtone_count    = int((midtone_zone    > 0.5).sum())
        print(f"    Memling jewel-light pass complete  "
              f"(highlight_px={highlight_count}  midtone_px={midtone_count})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 56 — new artist: Agnolo Bronzino / bronzino_enamel_skin_pass
    # ──────────────────────────────────────────────────────────────────────────

    def bronzino_enamel_skin_pass(
        self,
        figure_mask:          "Optional[_np.ndarray]" = None,
        midtone_low:          float = 0.35,
        midtone_high:         float = 0.72,
        compression_strength: float = 0.18,
        highlight_thresh:     float = 0.72,
        cool_strength:        float = 0.05,
        shadow_thresh:        float = 0.35,
        desaturate_strength:  float = 0.22,
        opacity:              float = 0.70,
    ) -> None:
        """
        Apply Agnolo Bronzino's enamel-smooth flesh quality to the canvas.

        Agnolo Bronzino (1503–1572) — court painter to Cosimo I de' Medici and
        the supreme Florentine Mannerist portraitist — achieved a surface quality
        unlike any other painter of his era.  Where Leonardo dissolved edges in
        sfumato smoke and Rembrandt built impasto mountains of light, Bronzino
        refined and refined until the flesh read as polished ivory: seamless,
        cool, and utterly opaque to the emotions beneath.

        The technical basis was patient oil layering on a prepared panel, with
        each layer dried and sanded before the next was applied.  The result:
        a surface without visible brushwork, without texture, without incident.
        Tonal transitions in the midtones are minimal — barely perceptible —
        and this near-flat quality in the flesh is paradoxically more unsettling
        than bold modelling: the face becomes a mask.

        His highlights are not warm gold (as in Rembrandt or Titian) but cool
        pale ivory — as if the brightest zones have been lightly touched with
        white lead mixed with a trace of cool grey rather than Naples yellow.
        His deepest shadows carry no warm amber undertone; they desaturate toward
        cool grey, draining vitality from the flesh and replacing it with a
        controlled, aristocratic neutrality.

        This pass applies three distinct operations:

        1. **Midtone compression** (``midtone_low ≤ lum ≤ midtone_high``):
           Each pixel in the midtone band is blended toward a locally smoothed
           (gaussian-filtered) version of itself.  This compresses the tonal
           micro-texture of the painted surface — the fine variation that reads
           as brushwork — toward a smooth, seamless average.  The blend strength
           is highest at the band centre and tapers to zero at the edges
           (triangular weighting).  Controlled by ``compression_strength``.

        2. **Cool highlight push** (``lum > highlight_thresh``): The brightest
           pixels are pushed toward cool pale ivory: B is lifted and R is
           reduced.  Unlike Memling's jewel-light (which targets a specific
           enamel brilliance) this is a subtler, more uniform cooling — the
           entire lit zone is shifted very slightly toward silver-white rather
           than warm gold.  Controlled by ``cool_strength``.

        3. **Shadow desaturation** (``lum < shadow_thresh``): Deep shadow
           pixels are mixed toward their luminance value (neutral grey).  This
           drains warm undertones from the dark zones — removing the amber and
           sienna that warm oil grounds tend to impart — and leaves the shadows
           cool, chromatic-neutral, and slightly lifeless.  The strength scales
           with shadow depth: deepest shadows receive the full desaturation;
           pixels at the shadow boundary receive a fractional push.  Controlled
           by ``desaturate_strength``.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 array ``(H, W)`` in [0, 1].  1 = figure, 0 = background.
            When provided, all corrections are applied only within the figure.
        midtone_low : float
            Lower luminance boundary of the midtone compression band.
            Default 0.35 — below this the pixel is in shadow territory.
        midtone_high : float
            Upper luminance boundary of the midtone compression band.
            Default 0.72 — above this the pixel transitions to highlight.
        compression_strength : float
            Maximum blend fraction toward the gaussian-smoothed neighbourhood.
            0.0 = no smoothing; 1.0 = fully replaces local texture with the
            neighbourhood average.  Default 0.18 — perceptible but not extreme.
        highlight_thresh : float
            Luminance threshold above which pixels receive the cool push.
            Default 0.72 — only genuinely bright highlight zones are affected.
        cool_strength : float
            Magnitude of the cool ivory push in highlight zones.  Lifts B,
            reduces R.  Default 0.05 — subtle; stacks well with other passes.
        shadow_thresh : float
            Luminance boundary below which pixels are desaturated.
            Default 0.35 — captures the lower-mid and deep shadow zones.
        desaturate_strength : float
            Maximum desaturation strength at the deepest shadows.  0.0 = no
            change; 1.0 = full grayscale in the darkest pixels.  Default 0.22.
        opacity : float
            Global blend factor: 0 = no effect applied, 1 = full correction.

        Notes
        -----
        Apply AFTER ``build_form()`` — the compression suppresses brushwork
        texture, not the modelled tonal structure.  Works well before the final
        ``glaze()`` call: a cool pale ivory glaze (as in Bronzino's catalog
        entry) will complement and extend the enamel quality introduced here.
        Pairs well with ``weyden_angular_shadow_pass()`` (for precise shadow
        geometry) and ``holbein_jewel_glaze_pass()`` (for panel-painting
        finish).  Does NOT pair well with ``sfumato_veil_pass()`` at high
        settings — sfumato and enamel are aesthetically opposed techniques.
        """
        import numpy as _np

        print(f"  Bronzino enamel-skin pass  "
              f"(midtone_low={midtone_low:.2f}  midtone_high={midtone_high:.2f}  "
              f"compression={compression_strength:.3f}  cool={cool_strength:.3f}  "
              f"desaturate={desaturate_strength:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Bronzino enamel-skin pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f   # (H, W)

        # ── Figure mask weight ────────────────────────────────────────────────
        if figure_mask is not None:
            mask_w = _np.clip(
                _np.array(figure_mask, dtype=_np.float32), 0.0, 1.0
            )
            if mask_w.shape != (h, w):
                from PIL import Image as _Img
                mask_w = _np.array(
                    _Img.fromarray((mask_w * 255).astype(_np.uint8)).resize(
                        (w, h), _Img.BILINEAR
                    ), dtype=_np.float32
                ) / 255.0
        else:
            mask_w = _np.ones((h, w), dtype=_np.float32)

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Midtone compression (midtone_low ≤ lum ≤ midtone_high) ─────────
        # Blend each pixel in the midtone band toward a locally smoothed version.
        # The gaussian kernel produces a neighbourhood average that reflects the
        # broad colour mass rather than individual brushstroke variation — mixing
        # toward it compresses local tonal texture without affecting the overall
        # tonal structure of the painting.
        sigma = max(2.0, min(w, h) * 0.012)
        r_smooth = ndimage.gaussian_filter(r_f, sigma=sigma).astype(_np.float32)
        g_smooth = ndimage.gaussian_filter(g_f, sigma=sigma).astype(_np.float32)
        b_smooth = ndimage.gaussian_filter(b_f, sigma=sigma).astype(_np.float32)

        midtone_zone = (
            (lum >= midtone_low) & (lum <= midtone_high)
        ).astype(_np.float32)
        # Triangular weighting: 0 at band edges, 1 at centre
        band_width = max(midtone_high - midtone_low, 1e-6)
        band_pos   = _np.clip((lum - midtone_low) / band_width, 0.0, 1.0)
        mid_weight = midtone_zone * (1.0 - _np.abs(band_pos * 2.0 - 1.0))
        blend_w    = mid_weight * compression_strength

        r_out = r_out * (1.0 - blend_w) + r_smooth * blend_w
        g_out = g_out * (1.0 - blend_w) + g_smooth * blend_w
        b_out = b_out * (1.0 - blend_w) + b_smooth * blend_w

        # ── 2. Cool highlight push (lum > highlight_thresh) ───────────────────
        # Lift B, reduce R in the brightest zones — Bronzino's highlights read
        # as cool pale ivory, not the warm Naples yellow of Italian Renaissance
        # painting.  Scale by how far above the threshold the pixel sits.
        highlight_zone   = (lum > highlight_thresh).astype(_np.float32)
        highlight_excess = _np.clip(
            (lum - highlight_thresh) / max(1.0 - highlight_thresh, 1e-6),
            0.0, 1.0
        )
        hi_w = highlight_zone * highlight_excess * cool_strength
        b_out = _np.clip(b_out + hi_w,            0.0, 1.0)
        r_out = _np.clip(r_out - hi_w * 0.50,     0.0, 1.0)

        # ── 3. Shadow desaturation (lum < shadow_thresh) ─────────────────────
        # Mix deep shadow pixels toward their luminance value (grayscale).
        # This removes the warm amber undertone that oil grounds introduce,
        # leaving Bronzino's characteristic cool, chromatic-neutral shadows.
        # Strength scales with depth — deepest shadows receive full push.
        shadow_depth = _np.clip(
            (shadow_thresh - lum) / max(shadow_thresh, 1e-6), 0.0, 1.0
        )
        desat_w = shadow_depth * desaturate_strength
        r_out = _np.clip(r_out * (1.0 - desat_w) + lum * desat_w, 0.0, 1.0)
        g_out = _np.clip(g_out * (1.0 - desat_w) + lum * desat_w, 0.0, 1.0)
        b_out = _np.clip(b_out * (1.0 - desat_w) + lum * desat_w, 0.0, 1.0)

        # ── Blend corrected layer back at `opacity`, weighted by mask ─────────
        blend = opacity * mask_w

        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - blend) + r_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - blend) + g_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - blend) + b_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        midtone_count   = int((midtone_zone   > 0.5).sum())
        highlight_count = int((highlight_zone  > 0.5).sum())
        shadow_count    = int((shadow_depth    > 0.05).sum())
        print(f"    Bronzino enamel-skin pass complete  "
              f"(midtone_px={midtone_count}  highlight_px={highlight_count}  "
              f"shadow_px={shadow_count})")

    def tintoretto_dynamic_light_pass(
        self,
        figure_mask:         "Optional[_np.ndarray]" = None,
        contrast_strength:   float = 0.22,
        highlight_thresh:    float = 0.68,
        silver_strength:     float = 0.08,
        shadow_thresh:       float = 0.30,
        shadow_depth_push:   float = 0.18,
        opacity:             float = 0.75,
    ) -> None:
        """
        Apply Jacopo Tintoretto's silver lightning-highlight and dramatic void quality.

        Tintoretto (Jacopo Robusti, 1518–1594) — Il Furioso — transformed Venetian
        painting by combining the Venetian tradition of rich colourism with a
        Michelangelesque command of dramatic light.  Where his teacher Titian built
        luminosity through patient transparent glazing on warm ochre grounds,
        Tintoretto slashed silver-white impasto directly onto near-black grounds,
        creating a quality of light that reads less like warm sunlight and more like
        a sudden bolt of lightning cutting across absolute darkness.

        His technique in the Scuola Grande di San Rocco — the largest body of
        paintings by a single artist in any single building — represents the extreme
        development of this approach: figures emerge from near-absolute void, lit by
        cool, directional, electric-silver highlights rather than warm diffuse glow.
        The tonal range from darkest shadow to brightest highlight is among the widest
        in Italian Renaissance painting; the drama lives in that gap.

        This pass applies three layered operations:

        1. **Contrast amplification** (global): Expands the tonal range by darkening
           shadows and brightening highlights simultaneously.  Applies a mild S-curve
           to luminance — the midpoint is held, but both ends are pushed outward.
           This models the quality of Tintoretto's extreme ground-to-highlight range.
           Controlled by ``contrast_strength``.

        2. **Silver highlight push** (``lum > highlight_thresh``): The brightest
           pixels are cooled toward silver-white — B is lifted, R is slightly reduced.
           This is the inverse of Rembrandt or Titian warm gold highlights: Tintoretto's
           impasto peaks read as cool, metallic, almost electrically bright.  The effect
           scales with distance above the threshold (brightest pixels receive full push).
           Controlled by ``silver_strength``.

        3. **Shadow void deepening** (``lum < shadow_thresh``): Dark pixels are pulled
           further toward the near-black Venetian ground.  This widens the luminance gap
           between lit and unlit areas, reinforcing the drama of sudden emergence from
           darkness.  Strength scales with depth: deepest shadows receive the full push.
           Controlled by ``shadow_depth_push``.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 array ``(H, W)`` in [0, 1].  1 = figure, 0 = background.
            When provided, all corrections are confined to the figure region.
        contrast_strength : float
            Amplitude of the S-curve contrast expansion.  0 = no change; 0.22 = visible
            dramatic extension of tonal range.  Values > 0.40 will crush shadows and
            blow highlights; use with care.
        highlight_thresh : float
            Luminance above which the silver cool-push is applied.  Default 0.68.
            Only genuine impasto highlights should receive the silver treatment.
        silver_strength : float
            Magnitude of the silver push: B lifted, R reduced.  Default 0.08 — subtle
            but perceptible; stacks with contrast amplification to produce the
            characteristic electric-silver impasto quality.
        shadow_thresh : float
            Luminance below which shadow void deepening is applied.  Default 0.30.
        shadow_depth_push : float
            How strongly shadows are pushed toward absolute black.  0 = no change;
            1 = full push to zero.  Default 0.18.  Preserves the slight warm-brown
            undertone of Tintoretto's ground rather than crushing to pure black.
        opacity : float
            Global blend factor: 0 = no effect, 1 = full correction applied.

        Notes
        -----
        Apply AFTER ``build_form()`` — contrast amplification acts on the modelled
        tonal structure, not the unformed underpainting.  Works well before ``glaze()``
        with a deep amber Venetian glaze: the silver highlights read through the amber
        as a warm-then-cool flicker, reproducing the Tintoretto luminosity exactly.
        Pairs well with ``chiaroscuro_modelling_pass()`` (to establish the initial
        tonal drama) and ``reflected_light_pass()`` (the secondary silver reflection
        in shadow areas that Tintoretto used to animate his void backgrounds).
        Does NOT pair well with ``bronzino_enamel_skin_pass()`` — they are
        aesthetically opposite techniques (seamless surface vs. slashed impasto).
        """
        import numpy as _np

        print(f"  Tintoretto dynamic-light pass  "
              f"(contrast={contrast_strength:.3f}  silver={silver_strength:.3f}  "
              f"shadow_push={shadow_depth_push:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Tintoretto dynamic-light pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Acquire raw BGRA buffer ───────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape(h, w, 4).copy()
        orig = buf.copy()

        # Cairo BGRA: index 0=B, 1=G, 2=R, 3=A
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f   # (H, W)

        # ── Figure mask weight ────────────────────────────────────────────────
        if figure_mask is not None:
            mask_w = _np.clip(
                _np.array(figure_mask, dtype=_np.float32), 0.0, 1.0
            )
            if mask_w.shape != (h, w):
                from PIL import Image as _Img
                mask_w = _np.array(
                    _Img.fromarray((mask_w * 255).astype(_np.uint8)).resize(
                        (w, h), _Img.BILINEAR
                    ), dtype=_np.float32
                ) / 255.0
        else:
            mask_w = _np.ones((h, w), dtype=_np.float32)

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Contrast amplification (S-curve centred at 0.5) ───────────────
        # A mild S-curve pushes darks darker and brights brighter simultaneously.
        # Implementation: lum_new = 0.5 + (lum - 0.5) * (1 + contrast_strength)
        # We compute a luminance delta and apply it proportionally to each channel
        # so that hue is preserved while the tonal range is expanded.
        if contrast_strength > 0.0:
            scale = 1.0 + contrast_strength
            lum_new = _np.clip(0.5 + (lum - 0.5) * scale, 0.0, 1.0)
            lum_safe = _np.where(lum > 1e-6, lum, 1e-6)
            ratio = lum_new / lum_safe
            # Clamp ratio so no channel exceeds [0, 1]
            ratio = _np.clip(ratio, 0.0, 1.0 / _np.maximum(
                _np.stack([r_out, g_out, b_out], axis=-1).max(axis=-1), 1e-6
            ))
            r_out = _np.clip(r_out * ratio, 0.0, 1.0)
            g_out = _np.clip(g_out * ratio, 0.0, 1.0)
            b_out = _np.clip(b_out * ratio, 0.0, 1.0)
            # Recompute luminance after contrast step for subsequent operations
            lum = 0.2126 * r_out + 0.7152 * g_out + 0.0722 * b_out

        # ── 2. Silver highlight push (lum > highlight_thresh) ────────────────
        # The brightest impasto ridges are cooled toward silver-white:
        # B is lifted, R is slightly reduced.  This is Tintoretto's cool electric
        # highlight — neither Rembrandt's warm amber glow nor Leonardo's sfumato.
        # Strength scales with excess luminance above the threshold.
        highlight_excess = _np.clip(
            (lum - highlight_thresh) / max(1.0 - highlight_thresh, 1e-6),
            0.0, 1.0
        )
        hi_w = highlight_excess * silver_strength
        b_out = _np.clip(b_out + hi_w,         0.0, 1.0)
        r_out = _np.clip(r_out - hi_w * 0.55,  0.0, 1.0)

        # ── 3. Shadow void deepening (lum < shadow_thresh) ───────────────────
        # Dark pixels are pulled further toward black — widening the tonal gap
        # between Tintoretto's lit impasto peaks and his near-black Venetian void.
        # Strength scales with how deep the shadow is (deepest = full push).
        shadow_depth = _np.clip(
            (shadow_thresh - lum) / max(shadow_thresh, 1e-6), 0.0, 1.0
        )
        push_w = shadow_depth * shadow_depth_push
        r_out  = _np.clip(r_out * (1.0 - push_w), 0.0, 1.0)
        g_out  = _np.clip(g_out * (1.0 - push_w), 0.0, 1.0)
        b_out  = _np.clip(b_out * (1.0 - push_w), 0.0, 1.0)

        # ── Blend corrected layer back at `opacity`, weighted by mask ─────────
        blend = opacity * mask_w

        buf[:, :, 2] = _np.clip(
            orig[:, :, 2] * (1.0 - blend) + r_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1] * (1.0 - blend) + g_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0] * (1.0 - blend) + b_out * blend * 255.0,
            0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        highlight_count = int((highlight_excess > 0.05).sum())
        shadow_count    = int((shadow_depth     > 0.05).sum())
        print(f"    Tintoretto dynamic-light pass complete  "
              f"(highlight_px={highlight_count}  shadow_px={shadow_count})")

    # ─────────────────────────────────────────────────────────────────────────
    # Giorgione — tonal poetry pass
    # ─────────────────────────────────────────────────────────────────────────

    def giorgione_tonal_poetry_pass(
        self,
        figure_mask:         "Optional[_np.ndarray]" = None,
        midtone_low:         float = 0.30,
        midtone_high:        float = 0.70,
        luminous_lift:       float = 0.12,
        warm_shadow_strength: float = 0.06,
        cool_edge_strength:  float = 0.05,
        opacity:             float = 0.70,
    ) -> None:
        """
        Apply Giorgione's tonal-poetry quality to the canvas.

        Giorgione (Giorgio Barbarelli da Castelfranco, c.1477–1510) — Venetian High
        Renaissance — invented 'tonalismo': building form entirely through pooled
        tone and colour rather than linear underdrawing.  His flesh appears to breathe
        from within because his midtones carry a mysterious inner luminosity — forms
        are neither crisp (Flemish) nor dissolved (sfumato) but softly, warmly
        present.  Landscape and atmosphere seep into the figure's peripheral silhouette,
        creating the warm-cool oscillation that binds figure to environment.

        This pass applies three distinct operations:

        1. **Luminous midtone lift** (midtone_low ≤ lum ≤ midtone_high): Brightens
           midtone pixels by a soft, lum-weighted amount, creating the characteristic
           inner glow.  Controlled by luminous_lift.

        2. **Warm amber shadow-transition push** (lum < midtone_high): At the
           shadow-to-midtone boundary, warms the tone toward Giorgione's raw-sienna
           earth palette by slightly elevating the red-channel relative to blue.
           Controlled by warm_shadow_strength.

        3. **Cool blue-green peripheral bleed** (figure_mask provided, mask < 0.4):
           At the figure's peripheral silhouette, bleeds a subtle cool blue-green
           tint inward — the landscape atmosphere seeping into the figure edge.
           Controlled by cool_edge_strength.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 array (H, W) in [0, 1]. 1 = figure interior, 0 = background.
            When provided, operation 3 is applied at the figure's soft edge zone
            (mask values 0.05–0.40).  If None, operation 3 is skipped.
        midtone_low : float
            Lower luminance boundary of the midtone zone in [0, 1].  Pixels with
            luminance below this are treated as shadows; only operation 2 applies
            at the shadow-midtone transition.  Default 0.30.
        midtone_high : float
            Upper luminance boundary of the midtone zone in [0, 1].  Pixels above
            this are highlights; operation 1 tapers off toward this threshold.
            Default 0.70.
        luminous_lift : float
            Magnitude of the midtone luminance lift in [0, 1].  0 = no inner glow;
            0.20+ produces a noticeably bright, almost Bellini-esque glow.
            Default 0.12 — subtle inner light.
        warm_shadow_strength : float
            Red-channel boost applied in the shadow-to-midtone transition zone.
            Warms the deep half-tones toward Giorgione's raw-sienna earth palette.
            Default 0.06.
        cool_edge_strength : float
            Blue-green tint added at the figure's peripheral mask edge (mask 0.05–0.40).
            Simulates the landscape atmosphere seeping into the silhouette.
            Default 0.05.
        opacity : float
            Global blend factor: 0 = no effect, 1 = full correction applied.
            The three operations are each independently blended at this opacity.

        Notes
        -----
        Apply AFTER build_form().  Works best before glaze(), which will warm and
        deepen the final surface over the tonal work this pass establishes.
        Pairs well with sfumato_veil_pass() (softens remaining hard edges further)
        and atmospheric_depth_pass() (extends the cool recessive logic into the
        background).
        Does NOT pair well with tintoretto_dynamic_light_pass() (which dramatically
        re-contrasts what this pass intentionally softens).
        """
        import numpy as _np

        print(f"  Giorgione tonal-poetry pass  "
              f"(luminous_lift={luminous_lift:.3f}  "
              f"warm_shadow={warm_shadow_strength:.3f}  "
              f"cool_edge={cool_edge_strength:.3f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Giorgione tonal-poetry pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas buffer ────────────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Normalise to float [0, 1] — cairo surface is BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # Perceived luminance
        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        # When a figure_mask is provided, operations 1 and 2 are gated to figure
        # pixels — pixels where mask=0 (pure background) are not altered.
        # This matches the convention of every other artist-specific pass in this engine.
        if figure_mask is not None:
            mask_f  = figure_mask.astype(_np.float32)
            fig_w   = _np.clip(mask_f, 0.0, 1.0)   # [0, 1] spatial weight for ops 1 & 2
        else:
            mask_f  = None
            fig_w   = _np.ones((h, w), dtype=_np.float32)   # apply everywhere

        # ── Operation 1: luminous midtone lift ────────────────────────────────
        # Bell-shaped weight: peaks at midpoint of midtone_low..midtone_high,
        # falls to zero at either boundary.
        mid_centre = (midtone_low + midtone_high) * 0.5
        mid_half   = (midtone_high - midtone_low) * 0.5 + 1e-8
        in_mid     = (lum >= midtone_low) & (lum <= midtone_high)
        # Cosine bell: weight 1 at centre, 0 at edges of midtone zone
        bell       = _np.where(in_mid,
                               0.5 * (1.0 + _np.cos(
                                   _np.pi * (lum - mid_centre) / mid_half)),
                               0.0).astype(_np.float32)
        lift       = bell * luminous_lift * opacity * fig_w

        r_out = _np.clip(r_f + lift, 0.0, 1.0)
        g_out = _np.clip(g_f + lift * 0.92, 0.0, 1.0)   # slightly less green lift
        b_out = _np.clip(b_f + lift * 0.80, 0.0, 1.0)   # least blue lift — keeps warm

        # ── Operation 2: warm amber shadow-transition push ────────────────────
        # Target zone: shadow-to-midtone boundary (midtone_low ± half its span)
        shadow_zone_top = midtone_low + (midtone_high - midtone_low) * 0.25
        in_shadow_trans = (lum >= (midtone_low * 0.5)) & (lum <= shadow_zone_top)
        # Weight strongest at midtone_low, fading at either side
        shadow_bell     = _np.where(
            in_shadow_trans,
            _np.clip(1.0 - _np.abs(lum - midtone_low) / (shadow_zone_top - midtone_low * 0.5 + 1e-8), 0.0, 1.0),
            0.0).astype(_np.float32)
        warm_push       = shadow_bell * warm_shadow_strength * opacity * fig_w

        # Raise R slightly, pull B slightly — raw-sienna warmth in the half-tones
        r_out = _np.clip(r_out + warm_push,        0.0, 1.0)
        b_out = _np.clip(b_out - warm_push * 0.50, 0.0, 1.0)

        # ── Operation 3: cool blue-green peripheral bleed ─────────────────────
        if mask_f is not None:
            # Edge zone: mask values between 0.05 and 0.40 — soft peripheral silhouette
            in_edge = (mask_f >= 0.05) & (mask_f <= 0.40)
            # Weight inversely proportional to mask density — strongest at outer edge
            edge_w  = _np.where(in_edge,
                                (0.40 - mask_f) / 0.35,
                                0.0).astype(_np.float32)
            cool_push = edge_w * cool_edge_strength * opacity

            # Add blue-green at the peripheral edge — Giorgione's landscape seeping in
            b_out = _np.clip(b_out + cool_push * 1.20, 0.0, 1.0)
            g_out = _np.clip(g_out + cool_push * 0.80, 0.0, 1.0)
            r_out = _np.clip(r_out - cool_push * 0.40, 0.0, 1.0)

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        midtone_px = int(in_mid.sum())
        print(f"    Giorgione tonal-poetry pass complete  "
              f"(midtone_px={midtone_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Veronese — luminous feast pass
    # ─────────────────────────────────────────────────────────────────────────

    def veronese_luminous_feast_pass(
        self,
        figure_mask:            "Optional[_np.ndarray]" = None,
        midtone_low:            float = 0.35,
        midtone_high:           float = 0.65,
        saturation_boost:       float = 0.14,
        cool_highlight_strength: float = 0.06,
        shadow_chroma_preserve: float = 0.08,
        opacity:                float = 0.72,
    ) -> None:
        """
        Apply Paolo Veronese's luminous colour quality to the canvas.

        Paolo Veronese (Paolo Caliari, 1528–1588) — Venetian Colorism — bathed his
        enormous feast-scene canvases in a clear, silvery, almost outdoor light that
        sets him apart from both Titian's warm-amber depth and Tintoretto's near-black
        void drama.  His palette is the most brilliantly saturated of the three great
        Venetians: rose-crimson draperies, clear warm-yellow fabric, and cool grey-green
        shadow tones read with festive, architectural clarity.  Unlike the tonal
        dissolvers (Leonardo, Giorgione), Veronese's forms stand confidently in light;
        his shadows remain colour-filled and relatively luminous, not collapsing toward
        black.

        This pass applies three distinct operations:

        1. **Mid-tone saturation boost** (midtone_low ≤ lum ≤ midtone_high): Increases
           colour saturation in the mid-luminance band using a bell-shaped weight.
           In HSV space: S is lifted toward 1.0.  This intensifies Veronese's brilliant
           fabric colours — rose, yellow-gold, grey-green — without blowing out
           highlights or muddying deep shadows.  Controlled by saturation_boost.

        2. **Cool silver-ivory highlight push** (lum > highlight_thresh=0.70): Adds a
           subtle B-channel and slight G-channel lift in the brightest lit pixels —
           pushing them toward Veronese's characteristic cool north-light ivory
           (not Titian's warm gold).  Controlled by cool_highlight_strength.

        3. **Shadow chroma preservation** (lum < shadow_thresh=0.30): In deep shadow
           zones, slightly boosts saturation (the same HSV logic as op 1 but applied
           to dark pixels).  Prevents shadows from collapsing toward grey, maintaining
           the colour-filled quality of Veronese's lit, airy shadow zones.
           Controlled by shadow_chroma_preserve.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 array (H, W) in [0, 1].  1 = figure interior, 0 = background.
            When provided, all three operations are gated to figure pixels — pure
            background pixels (mask=0) are not altered.  If None, the pass applies
            globally across the canvas.
        midtone_low : float
            Lower luminance boundary of the mid-tone saturation zone.  Pixels darker
            than this are treated as shadows (operation 3 applies instead).
            Default 0.35.
        midtone_high : float
            Upper luminance boundary of the mid-tone saturation zone.  Pixels brighter
            than this receive the cool highlight push (operation 2) instead.
            Default 0.65.
        saturation_boost : float
            Magnitude of the HSV saturation lift in the mid-tone band.  0 = no change;
            0.25+ produces visibly intense Fauvist-approaching colour.  Default 0.14 —
            noticeable vibrancy without cartoonish saturation.
        cool_highlight_strength : float
            Blue-green channel lift applied in the brightest pixels (lum > 0.70).
            Pushes highlights toward cool silver-ivory rather than warm gold.
            Default 0.06 — subtle but distinguishable from Titian's warm glaze.
        shadow_chroma_preserve : float
            HSV saturation lift applied in the deepest shadow zone (lum < 0.30).
            Prevents colour from draining completely in dark areas; keeps shadows
            luminous.  Default 0.08.
        opacity : float
            Global blend factor: 0 = no effect, 1 = full correction applied.
            All three operations are composited at this opacity.  Default 0.72.

        Notes
        -----
        Apply AFTER build_form() and BEFORE glaze().  The mid-tone saturation boost
        enhances the colours that the subsequent warm glaze will deepen — together they
        produce Veronese's characteristic rich-yet-luminous surface.
        Pairs well with penumbra_zone_pass() (warms the light-to-shadow transition)
        and sfumato_veil_pass() (if a softer sfumato variant of the portrait is desired,
        though Veronese himself used clear edges).
        Does NOT pair well with tintoretto_dynamic_light_pass() (which darkens shadows
        and contracts colour into near-black, opposite to Veronese's luminous intent).
        """
        import numpy as _np
        import colorsys as _colorsys

        print(f"  Veronese luminous-feast pass  "
              f"(sat_boost={saturation_boost:.3f}  "
              f"cool_hi={cool_highlight_strength:.3f}  "
              f"shadow_chroma={shadow_chroma_preserve:.3f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Veronese luminous-feast pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas buffer ────────────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Normalise to float [0, 1] — cairo surface is BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # Perceived luminance
        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        # Spatial weight: figure_mask gating (same convention as all artist passes)
        if figure_mask is not None:
            fig_w = _np.clip(figure_mask.astype(_np.float32), 0.0, 1.0)
        else:
            fig_w = _np.ones((h, w), dtype=_np.float32)

        # ── Operation 1 & 3: saturation boost via HSV ────────────────────────
        # Bell weight for mid-tone zone (op 1)
        mid_centre = (midtone_low + midtone_high) * 0.5
        mid_half   = (midtone_high - midtone_low) * 0.5 + 1e-8
        in_mid     = (lum >= midtone_low) & (lum <= midtone_high)
        mid_bell   = _np.where(in_mid,
                               0.5 * (1.0 + _np.cos(
                                   _np.pi * (lum - mid_centre) / mid_half)),
                               0.0).astype(_np.float32)

        # Linear weight for shadow zone (op 3): strongest at lum=0, fades at shadow_thresh
        shadow_thresh = midtone_low
        in_shadow     = lum < shadow_thresh
        shadow_w      = _np.where(in_shadow,
                                  1.0 - lum / (shadow_thresh + 1e-8),
                                  0.0).astype(_np.float32)

        # Apply saturation boost pixel-by-pixel using vectorised HSV conversion.
        # For efficiency: compute max/min across RGB channels to get S and V in HSV.
        cmax   = _np.maximum(_np.maximum(r_f, g_f), b_f)
        cmin   = _np.minimum(_np.minimum(r_f, g_f), b_f)
        delta  = cmax - cmin + 1e-8   # avoid division by zero

        # HSV saturation = delta / cmax  (when cmax > 0)
        sat_orig = _np.where(cmax > 1e-6, delta / cmax, 0.0).astype(_np.float32)

        # Combined boost weight: mid-tone bell + shadow preservation
        mid_boost_w    = mid_bell   * saturation_boost       * fig_w
        shadow_boost_w = shadow_w   * shadow_chroma_preserve * fig_w

        sat_new = _np.clip(sat_orig
                           + mid_boost_w * opacity
                           + shadow_boost_w * opacity,
                           0.0, 1.0)

        # Scale RGB channels: to increase saturation in HSV, scale each channel
        # away from its grey (cmax) by the ratio of new S to old S.
        # If old S = 0 (grey pixel), no change can be made.
        nonzero_sat = sat_orig > 1e-4
        scale = _np.where(nonzero_sat, sat_new / sat_orig, 1.0).astype(_np.float32)
        # Clamp scale to avoid oversaturation artefacts
        scale = _np.clip(scale, 0.0, 2.5)

        # The neutral grey reference per-pixel is cmax (max channel = V in HSV).
        # Saturation boost shifts each channel: c_new = cmax + (c_old - cmax) * scale
        r_out = _np.clip(cmax + (r_f - cmax) * scale, 0.0, 1.0)
        g_out = _np.clip(cmax + (g_f - cmax) * scale, 0.0, 1.0)
        b_out = _np.clip(cmax + (b_f - cmax) * scale, 0.0, 1.0)

        # ── Operation 2: cool silver-ivory highlight push ─────────────────────
        highlight_thresh = midtone_high
        in_hi  = lum > highlight_thresh
        # Weight: linear ramp, strongest at lum=1, zero at highlight_thresh
        hi_w   = _np.where(in_hi,
                           (lum - highlight_thresh) / (1.0 - highlight_thresh + 1e-8),
                           0.0).astype(_np.float32)
        cool_push = hi_w * cool_highlight_strength * opacity * fig_w

        # Cool silver-ivory: slight B lift and G lift, slight R reduction
        b_out = _np.clip(b_out + cool_push * 1.10, 0.0, 1.0)
        g_out = _np.clip(g_out + cool_push * 0.55, 0.0, 1.0)
        r_out = _np.clip(r_out - cool_push * 0.20, 0.0, 1.0)

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        midtone_px   = int(in_mid.sum())
        highlight_px = int(in_hi.sum())
        shadow_px    = int(in_shadow.sum())
        print(f"    Veronese luminous-feast pass complete  "
              f"(midtone_px={midtone_px}  highlight_px={highlight_px}  "
              f"shadow_px={shadow_px})")

    def murillo_vapor_pass(
        self,
        figure_mask:       "Optional[_np.ndarray]" = None,
        warmth_strength:   float = 0.18,
        bloom_radius:      int   = 12,
        shadow_warmth:     float = 0.10,
        highlight_glow:    float = 0.08,
        opacity:           float = 0.68,
    ) -> None:
        """
        Apply Bartolomé Esteban Murillo's 'estilo vaporoso' (vaporous style) to the canvas.

        Murillo (1617–1682) — Spanish Baroque — is distinguished from all other Spanish
        Baroque painters by his warm, diffused luminosity: the 'estilo vaporoso' that
        18th-century collectors named to describe the soft, glowing quality of his mature
        work.  Where Caravaggio and Zurbarán used cold, dramatic chiaroscuro and near-black
        voids, Murillo bathed every surface in warm amber-rose light that reads not as
        theatrical drama but as spiritual tenderness.  His Immaculate Conception (c.1678,
        Prado) seems literally to glow; his beggar boys are not grim but radiant.

        This pass applies three distinct operations that together produce the 'vaporous'
        quality:

        1. **Warm luminous bloom** (all luminance zones, strongest in midtones):
           A warm amber-rose bloom is diffused outward from highlighted areas using a
           Gaussian-blurred luminance kernel.  The bloom radiates warmth into the
           surrounding midtone zones — simulating how Murillo's light sources appear to
           warm the air around them, not merely illuminate surfaces.  Controlled by
           warmth_strength and bloom_radius.

        2. **Shadow warmth injection** (lum < 0.32):
           Deep shadow zones receive a warm amber-rose lift, preventing the cold collapse
           toward near-black that defines Caravaggio and Zurbarán.  Murillo's shadows
           retain colour — they read as warm dark amber, not cold black void.
           Controlled by shadow_warmth.

        3. **Pearl highlight push** (lum > 0.68):
           The very brightest pixels receive a slight warm ivory push — adding a tiny
           red-channel lift and modest green lift while leaving blue unchanged.  This
           produces the characteristic Murillo 'pearl' quality in lit skin: highlights
           that feel warm, creamy, and almost edible, contrasting with the cool silver
           of Veronese and the golden warmth of Titian.  Controlled by highlight_glow.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 (H, W) array in [0, 1].  1 = figure interior, 0 = background.
            When provided, all operations are gated to figure pixels — background
            pixels (mask=0) are left unchanged.  If None, applies globally.
        warmth_strength : float
            Magnitude of the warm bloom halo.  0 = no bloom; 0.30+ produces a
            visibly strong warm aureole around lit areas.  Default 0.18 — noticeable
            warmth without aureole artefacts.
        bloom_radius : int
            Gaussian blur radius (in pixels) for the warm bloom diffusion kernel.
            Larger values spread warmth over a wider halo; smaller values keep it close
            to the highlight zone.  Default 12 — appropriate for a 780×1080 canvas.
        shadow_warmth : float
            Warm amber-rose lift in the darkest shadow pixels (lum < 0.32).  Prevents
            dark zones from collapsing to near-black.  Default 0.10 — a perceptible
            warm amber quality in shadows without washing out the dark value.
        highlight_glow : float
            Warm ivory push applied to the brightest highlights (lum > 0.68).
            Lifts the red and green channels fractionally, producing the 'pearl' quality
            of Murillo's lit skin.  Default 0.08.
        opacity : float
            Global blend factor.  0 = no effect applied; 1 = full operations.
            Default 0.68 — strong but not overwhelming.

        Notes
        -----
        Apply AFTER build_form() and BEFORE the final glaze().  The warm bloom and
        shadow warmth operations work best when form is already fully established;
        applying them earlier can wash out the structural underpainting.

        Pairs naturally with:
        - sfumato_veil_pass(warmth=0.30) for a further warm-edge softening.
        - glaze(color=(0.68, 0.50, 0.34), opacity=0.06) — Murillo's characteristic
          amber-rose final glaze that deepens the warm harmony.

        Does NOT pair with:
        - tintoretto_dynamic_light_pass() — Tintoretto's cold near-black shadows
          directly oppose Murillo's warm shadow warmth.
        - veronese_luminous_feast_pass() with high saturation_boost — Veronese's
          cool-highlight push (B-channel) conflicts with Murillo's warm red-channel glow.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Murillo vapor pass  "
              f"(warmth={warmth_strength:.3f}  bloom_r={bloom_radius}  "
              f"shadow_warmth={shadow_warmth:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Murillo vapor pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas buffer ────────────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Normalise to float [0, 1] — cairo surface is BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # Perceived luminance
        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        # Spatial gating weight from figure_mask
        if figure_mask is not None:
            fig_w = _np.clip(figure_mask.astype(_np.float32), 0.0, 1.0)
        else:
            fig_w = _np.ones((h, w), dtype=_np.float32)

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Operation 1: Warm luminous bloom ─────────────────────────────────
        # Build the bloom kernel: Gaussian-blurred luminance map.
        # We convert lum to PIL Image, apply GaussianBlur, convert back.
        lum_img = _Image.fromarray(
            _np.clip(lum * 255.0, 0, 255).astype(_np.uint8), mode="L"
        )
        bloom_img = lum_img.filter(
            _ImageFilter.GaussianBlur(radius=float(bloom_radius))
        )
        bloom_arr = _np.asarray(bloom_img, dtype=_np.float32) / 255.0

        # The bloom contribution: warm amber-rose — R:1.0, G:0.62, B:0.28
        bloom_weight = bloom_arr * warmth_strength * opacity * fig_w
        r_out = _np.clip(r_out + bloom_weight * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + bloom_weight * 0.62, 0.0, 1.0)
        b_out = _np.clip(b_out + bloom_weight * 0.28, 0.0, 1.0)

        # ── Operation 2: Shadow warmth injection ─────────────────────────────
        shadow_thresh = 0.32
        in_shadow = lum < shadow_thresh
        shadow_w  = _np.where(in_shadow,
                              (1.0 - lum / (shadow_thresh + 1e-8)) * fig_w,
                              0.0).astype(_np.float32)
        warm_lift = shadow_w * shadow_warmth * opacity
        # Warm amber-rose shadow: +R, +slight G, minimal B
        r_out = _np.clip(r_out + warm_lift * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + warm_lift * 0.55, 0.0, 1.0)
        b_out = _np.clip(b_out + warm_lift * 0.15, 0.0, 1.0)

        # ── Operation 3: Pearl highlight push ────────────────────────────────
        highlight_thresh = 0.68
        in_hi = lum > highlight_thresh
        hi_w  = _np.where(in_hi,
                          (lum - highlight_thresh) / (1.0 - highlight_thresh + 1e-8) * fig_w,
                          0.0).astype(_np.float32)
        pearl_push = hi_w * highlight_glow * opacity
        # Warm ivory pearl: strong R lift, moderate G lift, minimal B
        r_out = _np.clip(r_out + pearl_push * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + pearl_push * 0.78, 0.0, 1.0)
        b_out = _np.clip(b_out + pearl_push * 0.38, 0.0, 1.0)

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        bloom_px   = int((bloom_arr > 0.05).sum())
        shadow_px  = int(in_shadow.sum())
        hi_px      = int(in_hi.sum())
        print(f"    Murillo vapor pass complete  "
              f"(bloom_px={bloom_px}  shadow_px={shadow_px}  hi_px={hi_px})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 59 — new artist: Giovanni Battista Tiepolo / tiepolo_celestial_light_pass
    # ──────────────────────────────────────────────────────────────────────────

    def tiepolo_celestial_light_pass(
        self,
        figure_mask:       "Optional[_np.ndarray]" = None,
        azure_push:        float = 0.12,
        naples_glow:       float = 0.10,
        pearl_bloom:       float = 0.08,
        azure_band:        float = 0.50,
        bloom_radius:      int   = 18,
        opacity:           float = 0.70,
    ) -> None:
        """
        Apply Giovanni Battista Tiepolo's defining celestial light effect.

        Tiepolo (1696–1770) was the supreme master of the Venetian Rococo and
        the last great fresco painter of the Western tradition.  His signature
        visual quality — a vast luminous sky from which overhead celestial
        light descends onto figures below — depends on three simultaneous
        colour operations that this pass implements:

        1. **Azure sky push** (upper canvas zone): The upper ``azure_band``
           fraction of the canvas is pushed toward Tiepolo's characteristic
           brilliant azure-cerulean sky.  Unlike the muted grey-blue of
           ordinary atmospheric perspective, Tiepolo's skies are saturated
           and vibrant — a positive chromatic assertion, not merely a
           desaturated haze.  The push boosts B, reduces R, and very slightly
           lifts G in the sky zone, weighted by a gradient that is maximum at
           the top of the canvas and fades to zero at ``azure_band * H``.

        2. **Naples yellow warm glow** (figure zone): Within the figure_mask —
           or globally if none is provided — the lit tops of forms (pixels
           above the luminance midpoint) receive a warm Naples-yellow bloom.
           Tiepolo's flesh is modelled from a warm Naples yellow base:
           highlights lean warm-gold rather than the cool pearl of Ingres or
           the ivory of Leonardo.  The glow adds R and G in proportion to
           luminance, creating the self-luminous quality of his figures
           standing in direct overhead light.

        3. **Pearl-white zenith bloom**: The highest-luminance pixels (above
           0.75 lum) receive a brilliant near-white bloom — boosting all
           channels toward equal, pure white — simulating the dazzling zenith
           highlights on drapery, metallic armour, and upturned faces.
           Tiepolo's whites are not warm ivory (Rembrandt) nor cool silver
           (Velázquez) but a neutral brilliant pearl that reads as direct
           exposure to celestial light.

        Together these three operations recreate the distinctive quality of a
        Tiepolo fresco seen from below: figures in brilliant natural overhead
        light against a vivid azure sky, with both the sky and the figures
        appearing to radiate rather than merely reflect the light.

        Parameters
        ----------
        figure_mask : ndarray or None
            Float mask [0, 1] restricting the Naples-yellow glow to the
            figure zone.  If None, the glow applies globally.
        azure_push : float
            Strength of the azure-cerulean push in the sky zone.  0.12
            produces the clear, saturated Tiepolo sky; 0.0 disables it.
        naples_glow : float
            Strength of the Naples-yellow warm glow on lit figure surfaces.
        pearl_bloom : float
            Strength of the brilliant pearl-white bloom on the highest
            highlights.  Keep low (0.06–0.10) to avoid washing out.
        azure_band : float
            Fractional height from the top of the canvas over which the
            azure sky push is applied.  0.50 = upper half.
        bloom_radius : int
            Gaussian blur radius for the pearl bloom kernel, in pixels.
        opacity : float
            Global blend weight for the combined result over the original.

        Pairs with
        ----------
        - ``aerial_perspective_pass()`` — set ``warm_foreground_push > 0``
          to complement the azure sky with a warm foreground (the complete
          Tiepolo atmospheric contrast).
        - ``sfumato_veil_pass()`` — NOT recommended at high warmth values;
          sfumato's warm amber haze conflicts with the cool azure sky.
        - ``veronese_luminous_feast_pass()`` — Veronese's cool silver
          highlights share the same Venetian chromatic family as Tiepolo;
          the two passes may be sequenced for a combined Venetian luminosity.

        Does NOT pair with
        ------------------
        - ``murillo_vapor_pass()`` — Murillo's warm amber-rose glow
          opposes Tiepolo's brilliant azure-pearl light system.
        - ``tintoretto_dynamic_light_pass()`` — Tintoretto's near-black
          void ground conflicts with Tiepolo's pale, luminous imprimatura.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Tiepolo celestial light pass  "
              f"(azure={azure_push:.3f}  naples={naples_glow:.3f}  "
              f"pearl={pearl_bloom:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Tiepolo celestial light pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas buffer ────────────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Normalise to float [0, 1] — cairo surface is BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # Perceived luminance (BT.709)
        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Operation 1: Azure sky push ───────────────────────────────────────
        # Vertical weight gradient — max at top row, fades to 0 at azure_band * H
        sky_px = max(1, int(h * azure_band))
        ys = _np.linspace(0.0, 1.0, sky_px, dtype=_np.float32)
        sky_w_1d = _np.clip(1.0 - ys, 0.0, 1.0) ** 2.0
        sky_w = _np.zeros((h,), dtype=_np.float32)
        sky_w[:sky_px] = sky_w_1d
        sky_w = sky_w[:, _np.newaxis]   # (H, 1) broadcast over W

        az = sky_w * azure_push * opacity
        # Azure-cerulean: boost B strongly, slight G lift, reduce R
        r_out = _np.clip(r_out - az * 0.60, 0.0, 1.0)
        g_out = _np.clip(g_out + az * 0.10, 0.0, 1.0)
        b_out = _np.clip(b_out + az * 0.85, 0.0, 1.0)

        # ── Operation 2: Naples yellow warm glow on figure highlights ─────────
        if figure_mask is not None:
            fig_w = _np.clip(figure_mask.astype(_np.float32), 0.0, 1.0)
        else:
            fig_w = _np.ones((h, w), dtype=_np.float32)

        # Target: mid-to-high luminance pixels in the figure zone
        midlit = _np.clip((lum - 0.35) / (0.65 + 1e-8), 0.0, 1.0) * fig_w
        naples = midlit * naples_glow * opacity
        # Naples yellow: R strong, G moderate, minimal B
        r_out = _np.clip(r_out + naples * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + naples * 0.72, 0.0, 1.0)
        b_out = _np.clip(b_out + naples * 0.08, 0.0, 1.0)

        # ── Operation 3: Pearl-white bloom on highest highlights ──────────────
        # Build bloom from the brightest pixels via Gaussian blur
        lum_img = _Image.fromarray(
            _np.clip(lum * 255.0, 0, 255).astype(_np.uint8), mode="L"
        )
        bloom_img = lum_img.filter(
            _ImageFilter.GaussianBlur(radius=float(bloom_radius))
        )
        bloom_arr = _np.asarray(bloom_img, dtype=_np.float32) / 255.0

        # Gate bloom to the very bright highlights only
        highlight_gate = _np.clip((lum - 0.72) / (0.28 + 1e-8), 0.0, 1.0) * fig_w
        pearl = highlight_gate * bloom_arr * pearl_bloom * opacity
        # Pearl white: equal R, G, B push toward neutral brilliant white
        r_out = _np.clip(r_out + pearl * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + pearl * 0.95, 0.0, 1.0)
        b_out = _np.clip(b_out + pearl * 0.88, 0.0, 1.0)

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        sky_px_count   = int((sky_w.squeeze() > 0.05).sum() * w)
        naples_px      = int((midlit * fig_w > 0.05).sum())
        pearl_px       = int((highlight_gate > 0.05).sum())
        print(f"    Tiepolo celestial light pass complete  "
              f"(sky_px={sky_px_count}  naples_px={naples_px}  pearl_px={pearl_px})")

    def zurbaran_stark_devotion_pass(
        self,
        figure_mask:          "Optional[_np.ndarray]" = None,
        void_depth:           float = 0.22,
        crystalline_strength: float = 0.16,
        midtone_compression:  float = 0.12,
        opacity:              float = 0.72,
    ) -> None:
        """
        Apply Francisco de Zurbarán's 'stark devotion' tonal polarity to the canvas.

        Zurbarán (1598–1664) — Spanish Golden Age — is the supreme painter of austere
        monasticism.  Known as 'the painter of monks', he polarises his tonal range into
        cold, near-black voids and crystalline cold-white highlights with minimal midtone
        transition.  Where Murillo suffuses every shadow with warm amber-rose tenderness,
        Zurbarán's darkness is cold, silent, absent — a void from which forms emerge with
        sculptural clarity.  His white habits are rendered in pure cold-white light
        modelled by cool blue-grey shadows, reading as marble rather than fabric.

        This pass applies three distinct operations that together produce Zurbarán's
        devotional austerity:

        1. **Cold void deepening** (lum < 0.28):
           The darkest shadow zones are cooled and slightly desaturated, pushing them
           toward the near-black cold void that defines Zurbarán's backgrounds.  Unlike
           Murillo's warm shadow warmth (+R, +G), this operation withdraws warmth from
           dark regions: a small red-channel reduction and slight blue-channel lift
           creates cold darkness rather than warm amber shadow.  Controlled by void_depth.

        2. **Crystalline white drapery push** (lum > 0.70):
           The brightest highlight zones receive a cool-white crystalline push: a subtle
           blue-channel lift and slight green-channel lift with no red addition, producing
           the cold, almost alabaster quality of Zurbarán's white habits.  This is the
           polar opposite of Murillo's warm pearl highlight push.  Controlled by
           crystalline_strength.

        3. **Midtone compression** (0.28 < lum < 0.70):
           The midtone register is gently darkened — a slight overall luminance reduction
           that compresses the middle tones toward the dark end, accentuating the stark
           polarity between void-black and crystalline-white.  The near-zero midtone
           transition is what gives Zurbarán's work its devotional sharpness: forms do
           not graduate through grey; they are present or absent.  Controlled by
           midtone_compression.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 (H, W) array in [0, 1].  1 = figure interior, 0 = background.
            When provided, all operations are gated to figure pixels — background
            pixels (mask=0) are left unchanged.  If None, applies globally.
        void_depth : float
            Magnitude of the cold void deepening in shadows (lum < 0.28).  0 = no
            darkening; 0.30+ produces very deep cold near-black voids.  Default 0.22 —
            perceptible cold absence without losing all shadow detail.
        crystalline_strength : float
            Magnitude of the cool-white push in brightest highlights (lum > 0.70).
            0 = no change; 0.25+ produces visible blue-white alabaster quality.
            Default 0.16 — clear crystalline quality without colour cast.
        midtone_compression : float
            Darkening applied to the midtone register (0.28–0.70 lum).  Compresses
            mid-grey toward the dark end, accentuating tonal polarity.  Default 0.12 —
            perceptible compression without washing out midtone detail entirely.
        opacity : float
            Global blend factor.  0 = no effect; 1 = full operations.  Default 0.72.

        Notes
        -----
        Apply AFTER build_form() and BEFORE the final glaze().  The void deepening and
        crystalline push work best once form is fully established; applying earlier can
        collapse the structural underpainting.

        Pairs naturally with:
        - chiaroscuro_modelling_pass() for further tonal range extension
        - scumble_pass() over the white drapery zones for subtle fabric texture

        Does NOT pair with:
        - murillo_vapor_pass() — Murillo's warm shadow warmth directly opposes
          Zurbarán's cold void deepening; the two cancel each other out.
        - sfumato_veil_pass() — Zurbarán's crisp edges are incompatible with
          sfumato's deliberate edge dissolution.
        """
        import numpy as _np

        print(f"  Zurbarán stark devotion pass  "
              f"(void={void_depth:.3f}  crystal={crystalline_strength:.3f}  "
              f"compress={midtone_compression:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Zurbarán stark devotion pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas buffer ────────────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Normalise to float [0, 1] — cairo surface is BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # Perceived luminance
        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        # Spatial gating weight from figure_mask
        if figure_mask is not None:
            fig_w = _np.clip(figure_mask.astype(_np.float32), 0.0, 1.0)
        else:
            fig_w = _np.ones((h, w), dtype=_np.float32)

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Operation 1: Cold void deepening ─────────────────────────────────
        # In the darkest zones, withdraw warmth and add a fractional cool-blue lift.
        # This produces cold darkness — the silent void of a monastery interior.
        shadow_thresh = 0.28
        in_shadow = lum < shadow_thresh
        shadow_w  = _np.where(in_shadow,
                              (1.0 - lum / (shadow_thresh + 1e-8)) * fig_w,
                              0.0).astype(_np.float32)
        cold_pull = shadow_w * void_depth * opacity
        # Withdraw warmth (reduce R), add cold blue-black quality (slight +B)
        r_out = _np.clip(r_out - cold_pull * 0.80, 0.0, 1.0)
        g_out = _np.clip(g_out - cold_pull * 0.55, 0.0, 1.0)
        b_out = _np.clip(b_out - cold_pull * 0.20, 0.0, 1.0)

        # ── Operation 2: Crystalline white drapery push ───────────────────────
        # In the brightest zones, add a cool blue-white lift — marble/alabaster quality.
        # No red channel addition: keeps the whites cold, not warm like Murillo or Titian.
        hi_thresh = 0.70
        in_hi  = lum > hi_thresh
        hi_w   = _np.where(in_hi,
                           (lum - hi_thresh) / (1.0 - hi_thresh + 1e-8) * fig_w,
                           0.0).astype(_np.float32)
        crystal_push = hi_w * crystalline_strength * opacity
        # Cool alabaster: slight G lift, stronger B lift, no R addition
        r_out = _np.clip(r_out + crystal_push * 0.10, 0.0, 1.0)
        g_out = _np.clip(g_out + crystal_push * 0.55, 0.0, 1.0)
        b_out = _np.clip(b_out + crystal_push * 1.00, 0.0, 1.0)

        # ── Operation 3: Midtone compression ─────────────────────────────────
        # The midtone register (28–70% lum) is slightly darkened, compressing it
        # toward the dark end.  This accentuates the stark polarity between void and
        # crystalline highlight — the characteristic Zurbarán tonal binary.
        lo, hi = 0.28, 0.70
        in_mid = (lum >= lo) & (lum <= hi)
        # Weight peaks at 0.50 luminance, falls off toward both thresholds
        mid_w  = _np.where(in_mid,
                           (1.0 - _np.abs(lum - 0.49) / (0.21 + 1e-8)) * fig_w,
                           0.0).astype(_np.float32)
        mid_w  = _np.clip(mid_w, 0.0, 1.0)
        compress_pull = mid_w * midtone_compression * opacity
        # Uniform darkening across all channels — pure tonal compression, not a hue shift
        r_out = _np.clip(r_out - compress_pull * 0.90, 0.0, 1.0)
        g_out = _np.clip(g_out - compress_pull * 0.90, 0.0, 1.0)
        b_out = _np.clip(b_out - compress_pull * 0.90, 0.0, 1.0)

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        void_px    = int(in_shadow.sum())
        crystal_px = int(in_hi.sum())
        mid_px     = int(in_mid.sum())
        print(f"    Zurbarán stark devotion pass complete  "
              f"(void_px={void_px}  crystal_px={crystal_px}  mid_px={mid_px})")

    def sfumato_thermal_gradient_pass(
        self,
        figure_mask:        "Optional[_np.ndarray]" = None,
        warm_strength:      float = 0.06,
        cool_strength:      float = 0.08,
        horizon_y:          float = 0.55,
        gradient_width:     float = 0.30,
        edge_soften_radius: int   = 8,
        opacity:            float = 0.55,
    ) -> None:
        """
        Apply Leonardo da Vinci's sfumato atmospheric thermal gradient to the canvas.

        This pass models the warm-to-cool color temperature depth gradient that Leonardo
        perfected in his landscape backgrounds — most visibly in the Mona Lisa and
        Virgin of the Rocks.  The technique is distinct from simple aerial perspective
        (which only adds blue atmospheric haze) in that it simultaneously:

        (a) Warms the lower-foreground zone with subtle ochre-earth tones, simulating
            the warm reflected light of the earth plane and near-ground atmosphere.
        (b) Cools the upper-distance zone with cool blue-grey, simulating atmospheric
            scattering of short-wavelength light at depth.
        (c) Softens edges in the transitional atmospheric zone (around the horizon
            line) using Gaussian blurring — the sfumato dissolution where forms lose
            their boundaries as they recede.

        This combination produces the dreamlike atmospheric depth of Leonardo's
        backgrounds: foreground earth feels grounded and warm; middle-distance forms
        begin to lose definition; the horizon and distance dissolve into a cool,
        luminous blue-grey haze that is neither sky nor land but a nameless atmospheric
        zone.  The effect is deliberately subtle — power lives in the accumulation of
        thin, nearly imperceptible layers.

        Three operations are applied:

        1. **Foreground warm zone** (canvas rows below horizon_y):
           A radial-weighted warm earth lift (soft ochre: +R, +G-dim, slight -B) is
           applied strongest at the very bottom of the canvas, fading to zero at the
           horizon line.  This warms the earth plane and the base of the figure as if
           light bounced upward from warm ground.

        2. **Distance cool zone** (canvas rows above horizon_y):
           A linear cool lift (atmospheric blue-grey: -R-dim, -G-dim, +B) is applied
           strongest at the top of the canvas, fading to zero at the horizon line.
           This simulates Rayleigh scattering — distant forms shift toward cool blue-grey.

        3. **Atmospheric edge dissolution** (transition zone around horizon_y):
           A Gaussian-blurred version of the original canvas is blended into the
           transition zone weighted by the horizon proximity.  This produces sfumato's
           characteristic edge dissolution where forms lose sharp boundaries as they
           recede into the atmospheric middle distance.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 (H, W) array in [0, 1].  1 = figure interior, 0 = background.
            When provided, the warm/cool gradient operations are gated to background
            pixels only — the figure is protected from the atmospheric gradient (the
            figure sits in front of the landscape, not within it).
            Edge dissolution applies to background only when mask is provided.
            If None, applies globally (useful for full-canvas landscape passes).
        warm_strength : float
            Magnitude of the warm earth lift in the foreground zone.  0 = no warming;
            0.12+ produces a visible warm ochre bloom at the canvas base.  Default 0.06
            — subtly warm without visibly tinting the lower figure region.
        cool_strength : float
            Magnitude of the cool blue-grey lift in the distance zone.  0 = no cooling;
            0.15+ produces a visible atmospheric haze at the canvas top.  Default 0.08
            — light atmospheric blue without an artificial sky colour cast.
        horizon_y : float
            Vertical position of the horizon line as a fraction of canvas height.
            0.0 = top of canvas; 1.0 = bottom.  Default 0.55 — slightly below centre,
            as in many three-quarter portrait compositions where the figure's shoulders
            align with the mid-canvas and the landscape extends above.
        gradient_width : float
            Width of the transition zone as a fraction of canvas height.  Larger values
            produce a wider, smoother gradient; smaller values sharpen the warm/cool
            boundary.  Default 0.30 — a broad, smooth atmospheric transition.
        edge_soften_radius : int
            Gaussian blur radius (pixels) for the atmospheric edge dissolution in the
            transition zone.  Larger values produce a wider sfumato dissolution.
            Default 8 — appropriate for a 780×1080 canvas.
        opacity : float
            Global blend factor.  0 = no effect; 1 = full operations.  Default 0.55.

        Notes
        -----
        Apply AFTER build_form() and artist-specific passes, BEFORE the final glaze().
        This pass is most effective on images that already have an established background
        landscape — applying it to a blank canvas produces the gradient with no structural
        content to dissolve.

        Pairs naturally with:
        - aerial_perspective_pass() for combined haze + thermal gradient
        - sfumato_veil_pass() for further figure-edge dissolution
        - glaze(color=(0.72, 0.78, 0.88), opacity=0.04) — cool blue glaze that
          unifies the distant zone with the figure's atmospheric context.

        Does NOT pair with:
        - pontormo_dissonance_pass() — the dissonant acid palette is incompatible
          with atmospheric naturalness.
        - fauvist_mosaic_pass() — fauvism rejects atmospheric depth entirely.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Sfumato thermal gradient pass  "
              f"(warm={warm_strength:.3f}  cool={cool_strength:.3f}  "
              f"horizon_y={horizon_y:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Sfumato thermal gradient pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas buffer ────────────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Normalise to float [0, 1] — cairo surface is BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Build vertical gradient maps ──────────────────────────────────────
        # Row index as fraction of canvas height, 0 = top, 1 = bottom
        row_frac = _np.linspace(0.0, 1.0, h, dtype=_np.float32)[:, None]  # (H, 1)

        horizon_px    = horizon_y
        half_grad     = gradient_width / 2.0

        # Foreground warm weight: 1 at bottom, 0 at horizon, 0 above horizon
        warm_raw = (row_frac - horizon_px) / (1.0 - horizon_px + 1e-8)
        warm_raw = _np.clip(warm_raw, 0.0, 1.0)                           # (H, 1)
        warm_map = _np.broadcast_to(warm_raw, (h, w)).copy()              # (H, W)

        # Distance cool weight: 1 at top, 0 at horizon, 0 below horizon
        cool_raw = (horizon_px - row_frac) / (horizon_px + 1e-8)
        cool_raw = _np.clip(cool_raw, 0.0, 1.0)                           # (H, 1)
        cool_map = _np.broadcast_to(cool_raw, (h, w)).copy()              # (H, W)

        # Transition zone weight: peaks at horizon, falls off with gradient_width
        dist_to_horiz = _np.abs(row_frac - horizon_px)                    # (H, 1)
        trans_raw     = 1.0 - _np.clip(dist_to_horiz / (half_grad + 1e-8), 0.0, 1.0)
        trans_map     = _np.broadcast_to(trans_raw, (h, w)).copy()        # (H, W)

        # Spatial gating: if figure_mask provided, apply gradient to background only
        if figure_mask is not None:
            fig_w  = _np.clip(figure_mask.astype(_np.float32), 0.0, 1.0)
            bg_w   = 1.0 - fig_w
        else:
            bg_w   = _np.ones((h, w), dtype=_np.float32)

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Operation 1: Foreground warm earth lift ───────────────────────────
        # Soft warm ochre: strong R, moderate G, slight negative B
        # Weighted by luminance complement — darker areas receive proportionally less
        # (avoids tinting near-black shadow zones which should remain colour-neutral)
        lum   = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f
        lum_w = _np.clip(lum + 0.30, 0.0, 1.0)   # allow even mid-darks some warmth

        warm_contrib = warm_map * bg_w * lum_w * warm_strength * opacity
        r_out = _np.clip(r_out + warm_contrib * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + warm_contrib * 0.62, 0.0, 1.0)
        b_out = _np.clip(b_out - warm_contrib * 0.18, 0.0, 1.0)

        # ── Operation 2: Distance cool atmospheric lift ───────────────────────
        # Cool blue-grey: slight R reduction, slight G reduction, stronger B addition
        cool_contrib = cool_map * bg_w * cool_strength * opacity
        r_out = _np.clip(r_out - cool_contrib * 0.30, 0.0, 1.0)
        g_out = _np.clip(g_out - cool_contrib * 0.10, 0.0, 1.0)
        b_out = _np.clip(b_out + cool_contrib * 1.00, 0.0, 1.0)

        # ── Operation 3: Atmospheric edge dissolution in transition zone ──────
        # Gaussian blur of the current (post-gradient) working buffer in transition zone
        # Blend blurred version into the output weighted by trans_map * bg_w
        r_work = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        g_work = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        b_work = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)

        # Build blurred versions of each channel
        def _blur_channel(arr_u8: "_np.ndarray") -> "_np.ndarray":
            img    = _Image.fromarray(arr_u8, mode="L")
            blurred = img.filter(_ImageFilter.GaussianBlur(radius=float(edge_soften_radius)))
            return _np.asarray(blurred, dtype=_np.float32) / 255.0

        r_blur = _blur_channel(r_work)
        g_blur = _blur_channel(g_work)
        b_blur = _blur_channel(b_work)

        # Blend factor: transition zone weight × background mask × opacity × 0.45
        # (0.45 keeps dissolution subtle — sfumato is never a hard blur)
        blend_w = trans_map * bg_w * opacity * 0.45

        r_out = r_out * (1.0 - blend_w) + r_blur * blend_w
        g_out = g_out * (1.0 - blend_w) + g_blur * blend_w
        b_out = b_out * (1.0 - blend_w) + b_blur * blend_w

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        warm_px  = int((warm_map * bg_w > 0.05).sum())
        cool_px  = int((cool_map * bg_w > 0.05).sum())
        trans_px = int((trans_map * bg_w > 0.05).sum())
        print(f"    Sfumato thermal gradient pass complete  "
              f"(warm_px={warm_px}  cool_px={cool_px}  trans_px={trans_px})")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 62 — new artist: Parmigianino / parmigianino_serpentine_elegance_pass
    # Session 62 — artistic improvement: translucent_gauze_pass
    # ──────────────────────────────────────────────────────────────────────────

    def parmigianino_serpentine_elegance_pass(
        self,
        figure_mask:        "Optional[_np.ndarray]" = None,
        porcelain_strength: float = 0.14,
        lavender_shadow:    float = 0.12,
        silver_highlight:   float = 0.10,
        opacity:            float = 0.72,
    ) -> None:
        """
        Apply Parmigianino's cool porcelain refinement to the canvas.

        Parmigianino (1503–1540) — Parma / Florentine Mannerism — achieved a
        distinctive aesthetic of cool, translucent elegance that stands apart from
        every other Italian tradition.  Where the Venetians built warm amber
        subsurface luminosity (Titian's 'colorito'), and Leonardo built warm
        atmospheric sfumato, Parmigianino built COOL REFINEMENT: flesh tones that
        read as translucent porcelain or alabaster, shadows that shift toward
        silver-lavender rather than warm umber, and highlights polished to cool
        silver-white rather than warm gold.

        This pass applies three operations that together produce the porcelain
        elegance of his mature portrait style:

        1. **Porcelain midlight push** (lum 0.52–0.82, 'the face zone'):
           Midlight zones are shifted toward cool ivory — raising R and G slightly
           while adding a disproportionately larger B raise.  This cools the flesh
           tones away from warm amber and toward translucent cool porcelain.
           The effect is strongest in the upper midlight range (lum ~0.70) and
           fades toward both the highlights (too bright for colour shift) and the
           shadow zone (handled separately).

        2. **Shadow lavender-silver cool** (lum < 0.42):
           Deep and mid-shadow zones receive a cool lavender-silver push: B raised,
           G raised slightly, R reduced slightly.  This converts the expected warm
           umber/brown of oil shadows into the silvery grey-lavender characteristic
           of Parmigianino's drapery and face shadows — as seen in 'Schiava Turca'
           (c.1530–32) where face shadows read as cool lavender-grey, not warm brown.

        3. **Highlight silver polish** (lum > 0.82):
           The brightest pixels receive a cool silver-white push — B raised modestly,
           R and G raised less — producing a cool polished highlight quality.  This
           is the opposite of the warm ivory pearl used in Murillo and Rubens: no red
           warmth is added.  The result is the almost metallic highlight quality
           visible in 'Self-Portrait in a Convex Mirror' where the back of the hand
           catches the light as if glazed ceramic.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 (H, W) in [0, 1].  When provided, all operations are gated to
            the figure zone.  Background is left unchanged.
        porcelain_strength : float
            Magnitude of the cool ivory midlight push.  0.10–0.18 gives a perceptible
            but refined porcelain quality; above 0.22 the effect becomes clinical.
        lavender_shadow : float
            Strength of the cool lavender push into shadow zones.  0.08–0.15 produces
            the characteristic Parma shadow coolness; above 0.20 reads as unnatural.
        silver_highlight : float
            Strength of the cool silver polish on the highest lights.  0.06–0.14 adds
            metallic sheen without over-brightening.
        opacity : float
            Global blend factor.  Default 0.72.

        Notes
        -----
        Apply AFTER build_form() and BEFORE glaze().

        Pairs naturally with:
        - sfumato_veil_pass(warmth=0.10, chroma_dampen=0.20) — the cool sfumato
          reinforces the porcelain quality without introducing warm amber haze.
        - glaze(color=(0.92, 0.88, 0.84), opacity=0.05) — the pale cool ivory
          final glaze ties the tones into the characteristic 'enamel' surface.

        Does NOT pair well with:
        - murillo_vapor_pass() — Murillo's warm amber bloom directly opposes
          the cool ivory characteristic of Parmigianino's flesh rendering.
        - tiepolo_celestial_light_pass() — Tiepolo's warm Naples-yellow sky push
          would overwhelm the cool silvery refinement.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Parmigianino serpentine elegance pass  "
              f"(porcelain={porcelain_strength:.3f}  lavender={lavender_shadow:.3f}  "
              f"silver={silver_highlight:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Parmigianino serpentine elegance pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas buffer ────────────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo surface: BGRA channel order
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        # Spatial gating
        if figure_mask is not None:
            fig_w = _np.clip(figure_mask.astype(_np.float32), 0.0, 1.0)
        else:
            fig_w = _np.ones((h, w), dtype=_np.float32)

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Operation 1: Porcelain midlight push ─────────────────────────────
        # Target zone: lum 0.52–0.82  (the midlight to upper-midlight face zone)
        # Bell-shaped weight: peaks at lum ~0.67, falls to 0 at each boundary.
        mid_lo, mid_hi = 0.52, 0.82
        in_mid = _np.clip((lum - mid_lo) / (mid_hi - mid_lo + 1e-8), 0.0, 1.0)
        # Symmetrical bell: multiply by its mirror to create a peak at centre
        in_mid_bell = in_mid * (1.0 - in_mid) * 4.0  # peaks at 1.0 at midpoint
        porcelain_w = in_mid_bell * fig_w * porcelain_strength * opacity
        # Cool ivory: R+moderate, G+moderate, B+strong  (net: shift toward cool white)
        r_out = _np.clip(r_out + porcelain_w * 0.60, 0.0, 1.0)
        g_out = _np.clip(g_out + porcelain_w * 0.70, 0.0, 1.0)
        b_out = _np.clip(b_out + porcelain_w * 1.00, 0.0, 1.0)

        # ── Operation 2: Shadow lavender-silver cool ─────────────────────────
        # Target zone: lum < 0.42  (mid-shadow to deep shadow)
        shadow_thresh = 0.42
        shadow_w = _np.clip(1.0 - lum / (shadow_thresh + 1e-8), 0.0, 1.0)
        shadow_w = shadow_w * fig_w * lavender_shadow * opacity
        # Lavender-silver: B raised most, G slight raise, R slight reduction
        r_out = _np.clip(r_out - shadow_w * 0.30, 0.0, 1.0)
        g_out = _np.clip(g_out + shadow_w * 0.20, 0.0, 1.0)
        b_out = _np.clip(b_out + shadow_w * 1.00, 0.0, 1.0)

        # ── Operation 3: Highlight silver polish ─────────────────────────────
        # Target zone: lum > 0.82
        hi_thresh = 0.82
        hi_w = _np.clip((lum - hi_thresh) / (1.0 - hi_thresh + 1e-8), 0.0, 1.0)
        hi_w = hi_w * fig_w * silver_highlight * opacity
        # Cool silver: B raised, G raised moderately, R raised least
        r_out = _np.clip(r_out + hi_w * 0.50, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_w * 0.75, 0.0, 1.0)
        b_out = _np.clip(b_out + hi_w * 1.00, 0.0, 1.0)

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        mid_px    = int((in_mid_bell * fig_w > 0.05).sum())
        shadow_px = int((shadow_w > 0.005).sum())
        hi_px     = int((hi_w > 0.005).sum())
        print(f"    Parmigianino serpentine elegance pass complete  "
              f"(midlight_px={mid_px}  shadow_px={shadow_px}  highlight_px={hi_px})")

    def translucent_gauze_pass(
        self,
        figure_mask:    "Optional[_np.ndarray]" = None,
        zone_top:       float = 0.42,
        zone_bottom:    float = 0.72,
        opacity:        float = 0.35,
        cool_shift:     float = 0.06,
        weave_strength: float = 0.018,
        blur_radius:    float = 4.0,
    ) -> None:
        """
        Simulate semi-transparent gauze or velo fabric over a defined canvas zone.

        The *velo* — a thin, semi-transparent gauze wrap — appears in Renaissance
        and Mannerist portraiture as a device to add a soft, airy layer between the
        viewer and the sitter's bodice or shoulders.  Notable examples include:

        - **Mona Lisa** (Leonardo, c.1503–19) — the fine gauze at the décolletage
          creates a soft edge between the dark dress and the bare neck, adding a
          layer of translucent material that softens the neckline.
        - **Parmigianino's 'Antea'** (c.1531–35) — a translucent shoulder wrap
          that drifts across the figure, simultaneously revealing and concealing
          the dark dress beneath.
        - **Raphael's 'La Velata'** (c.1515, Pitti Palace) — a tour de force of
          painted textile: a translucent veil that covers the sitter's torso,
          showing the fabric layers beneath through a thin shimmer of gauze.

        Technically, gauze transmits light with a slight scattering — the colours
        beneath become visible but are slightly washed-out and cooled by the thin
        white fibres.  This pass simulates that optical effect using three operations:

        1. **Translucent blend**: Within the gauze zone (zone_top → zone_bottom,
           expressed as fractions of canvas height), the canvas values are blended
           toward a near-white, slightly cool scattering tone — simulating the white
           woven fibres of the gauze absorbing and scattering the underlying colours.
           The blend weight is soft (Gaussian-weighted within the zone) so the gauze
           has natural vignette edges rather than a sharp mask boundary.

        2. **Cool temperature shift**: The scattering fibres of white gauze introduce
           a very slight cooling of the transmitted light (cool_shift).  This is the
           optical equivalent of seeing warm flesh through a white diffusing layer —
           the result is slightly cooler, as if a thin cool mist has been interposed.

        3. **Woven texture** (optional, weave_strength > 0): A very subtle horizontal
           sinusoidal pattern at pixel frequency is added at the gauze zone to suggest
           the warp/weft weave of fine cloth without reading as visible lines at normal
           viewing distance.  The frequency is set to approximate the weave of a fine
           linen gauze at approximately 1:10 canvas scale.

        Parameters
        ----------
        figure_mask : np.ndarray or None
            Float32 (H, W) in [0, 1].  When provided, the gauze effect is confined
            to the figure zone.  Background is unaffected.
        zone_top : float
            Top edge of the gauze zone as fraction of canvas height (0 = top, 1 = bottom).
            Default 0.42 — approximates the neckline of a half-length portrait.
        zone_bottom : float
            Bottom edge of the gauze zone.  Default 0.72 — covers the upper torso.
        opacity : float
            Strength of the translucent blend toward the gauze scattering tone.
            0.20 = barely perceptible veil; 0.50 = clearly visible gauze.
            Default 0.35 — a visible but delicate translucency.
        cool_shift : float
            Magnitude of the cool temperature shift in the gauze zone.
            Reduces R slightly, raises B slightly.  Default 0.06.
        weave_strength : float
            Amplitude of the woven texture pattern.  0 = no texture.  Default 0.018
            — a barely-perceptible structural hint at the weave.
        blur_radius : float
            Gaussian radius (pixels) for softening the zone mask edges, ensuring
            natural vignette transitions rather than hard-cut boundaries.
            Default 4.0.

        Notes
        -----
        Apply AFTER build_form() and sfumato passes, and BEFORE final glaze().
        The gauze effect should be one of the last surface treatments.

        Pairs naturally with:
        - sfumato_veil_pass() — adds atmospheric sfumato at the edges of the
          gauze zone, further dissolving the boundary between gauze and skin.
        - parmigianino_serpentine_elegance_pass() — Parmigianino painted the most
          famous gauze wraps in Italian Mannerism; this pass directly supports his
          aesthetic.
        - bronzino_enamel_skin_pass() — Bronzino's cool enamel skin pairs naturally
          with gauze, which similarly suppresses warm tones.

        Does NOT pair with:
        - impasto_texture_pass() on the gauze zone — impasto implies thick pigment,
          which is physically incompatible with transparent fabric.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Translucent gauze pass  "
              f"(zone={zone_top:.2f}->{zone_bottom:.2f}  opacity={opacity:.2f}  "
              f"cool={cool_shift:.3f}  weave={weave_strength:.3f}) ...")

        if opacity <= 0.0:
            print(f"    Translucent gauze pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas buffer ────────────────────────────────────────────────
        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Build soft zone mask ──────────────────────────────────────────────
        # Row fractions 0 (top) → 1 (bottom)
        row_frac = _np.linspace(0.0, 1.0, h, dtype=_np.float32)[:, _np.newaxis]  # (H, 1)

        # Tent function: ramps up from zone_top, ramps down at zone_bottom
        rise = _np.clip((row_frac - zone_top)   / (max(zone_bottom - zone_top, 1e-8) * 0.25), 0.0, 1.0)
        fall = _np.clip((zone_bottom - row_frac) / (max(zone_bottom - zone_top, 1e-8) * 0.25), 0.0, 1.0)
        zone_raw = _np.minimum(rise, fall)                      # (H, 1) tent peak = 1.0 at centre

        # Broadcast to (H, W) and apply Gaussian softening at zone edges
        zone_2d = _np.broadcast_to(zone_raw, (h, w)).copy().astype(_np.float32)  # (H, W)
        zone_img   = _Image.fromarray(_np.clip(zone_2d * 255, 0, 255).astype(_np.uint8), mode="L")
        zone_blurred = _Image.fromarray(
            _np.asarray(zone_img.filter(_ImageFilter.GaussianBlur(radius=float(blur_radius))),
                        dtype=_np.uint8), mode="L")
        zone_mask = _np.asarray(zone_blurred, dtype=_np.float32) / 255.0  # (H, W)

        # Apply figure mask gating
        if figure_mask is not None:
            zone_mask = zone_mask * _np.clip(figure_mask.astype(_np.float32), 0.0, 1.0)

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Operation 1: Translucent scatter blend ────────────────────────────
        # Gauze scattering tone: near-white with very slight warm off-white cast
        # (white linen woven threads reflecting diffused interior light)
        scatter_r, scatter_g, scatter_b = 0.96, 0.94, 0.92
        blend_w = zone_mask * opacity
        r_out = r_out * (1.0 - blend_w) + scatter_r * blend_w
        g_out = g_out * (1.0 - blend_w) + scatter_g * blend_w
        b_out = b_out * (1.0 - blend_w) + scatter_b * blend_w

        # ── Operation 2: Cool temperature shift ──────────────────────────────
        # White gauze scatters more at shorter wavelengths — introduces a very
        # slight blue-shift (cool) relative to the warm skin underneath.
        cool_w = zone_mask * cool_shift
        r_out = _np.clip(r_out - cool_w * 0.60, 0.0, 1.0)
        g_out = _np.clip(g_out - cool_w * 0.10, 0.0, 1.0)
        b_out = _np.clip(b_out + cool_w * 0.80, 0.0, 1.0)

        # ── Operation 3: Woven texture ────────────────────────────────────────
        # Very fine sinusoidal modulation at warp/weft frequency — simulates
        # the rhythmic weave of fine linen.  Amplitude is tiny (weave_strength).
        if weave_strength > 0.0:
            # Horizontal warp threads: modulate along Y axis
            y_idx = _np.arange(h, dtype=_np.float32)[:, _np.newaxis]  # (H, 1)
            warp_freq = 8.0   # ~8px period for a fine weave at portrait scale
            warp = _np.sin(y_idx * 2.0 * _np.pi / warp_freq) * weave_strength
            warp_2d = _np.broadcast_to(warp, (h, w)).copy()  # (H, W)

            # Weave only appears in the gauze zone
            weave_contrib = warp_2d * zone_mask
            # Modulate value slightly (darken at warp threads, lighten at gaps)
            r_out = _np.clip(r_out + weave_contrib, 0.0, 1.0)
            g_out = _np.clip(g_out + weave_contrib, 0.0, 1.0)
            b_out = _np.clip(b_out + weave_contrib, 0.0, 1.0)

        # ── Write back ────────────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        gauze_px = int((zone_mask > 0.05).sum())
        print(f"    Translucent gauze pass complete  (gauze_px={gauze_px})")



    def corot_silver_veil_pass(
        self,
        figure_mask:       "Optional[_np.ndarray]" = None,
        desaturation:      float = 0.38,
        cool_shift:        float = 0.04,
        green_silver:      float = 0.22,
        edge_blur_radius:  int   = 5,
        opacity:           float = 0.60,
    ) -> None:
        """
        Apply Jean-Baptiste-Camille Corot's silver veil atmospheric effect.

        Corot (1796-1875), Barbizon School / Proto-Impressionism, developed a
        systematic atmospheric technique: an all-pervading tonal unity achieved by
        desaturating all colours toward a cool silver-grey register.  His greens are
        never richly saturated - they are muted, silvery, as if seen through morning
        mist.  Skies and foliage occupy the same tonal register; this tonal
        compression is the essence of his lyrical landscape vision.

        Four operations:
        1. Chromatic desaturation toward silver-grey (global)
        2. Cool temperature shift (subtle blue lift, red reduction)
        3. Green-to-silver conversion (foliage zones)
        4. Atmospheric edge dissolution (soft blur blend)
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Corot silver veil pass  "
              f"(desat={desaturation:.3f}  cool={cool_shift:.3f}  "
              f"green_silver={green_silver:.3f}  blur_r={edge_blur_radius}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Corot silver veil pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        if figure_mask is not None:
            bg_w = 1.0 - _np.clip(figure_mask.astype(_np.float32), 0.0, 1.0)
        else:
            bg_w = _np.ones((h, w), dtype=_np.float32)

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        desat_w = bg_w * desaturation * opacity
        r_out = r_out * (1.0 - desat_w) + lum * desat_w
        g_out = g_out * (1.0 - desat_w) + lum * desat_w
        b_out = b_out * (1.0 - desat_w) + lum * desat_w

        cool_w = bg_w * cool_shift * opacity
        r_out = _np.clip(r_out - cool_w * 0.60, 0.0, 1.0)
        g_out = _np.clip(g_out - cool_w * 0.15, 0.0, 1.0)
        b_out = _np.clip(b_out + cool_w * 1.00, 0.0, 1.0)

        green_dom  = (g_out > r_out) & (g_out > b_out)
        mid_lum    = (lum > 0.25) & (lum < 0.75)
        foliage_px = green_dom & mid_lum
        gs_w       = _np.where(foliage_px, bg_w * green_silver * opacity, 0.0).astype(_np.float32)
        r_out = r_out * (1.0 - gs_w) + lum * gs_w
        g_out = g_out * (1.0 - gs_w * 0.90) + lum * gs_w * 0.90
        b_out = b_out * (1.0 - gs_w) + (lum + 0.04) * gs_w

        r_out = _np.clip(r_out, 0.0, 1.0)
        g_out = _np.clip(g_out, 0.0, 1.0)
        b_out = _np.clip(b_out, 0.0, 1.0)

        r_u8 = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        g_u8 = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        b_u8 = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)

        def _blur_ch(arr):
            img = _Image.fromarray(arr, mode="L")
            return _np.asarray(
                img.filter(_ImageFilter.GaussianBlur(radius=float(edge_blur_radius))),
                dtype=_np.float32
            ) / 255.0

        r_blur = _blur_ch(r_u8)
        g_blur = _blur_ch(g_u8)
        b_blur = _blur_ch(b_u8)

        blur_w = bg_w * opacity * 0.22
        r_out = r_out * (1.0 - blur_w) + r_blur * blur_w
        g_out = g_out * (1.0 - blur_w) + g_blur * blur_w
        b_out = b_out * (1.0 - blur_w) + b_blur * blur_w

        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        foliage_px_count = int(foliage_px.sum())
        print(f"    Corot silver veil pass complete  "
              f"(foliage_px={foliage_px_count})")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 63 — Canaletto luminous veduta pass
    # ─────────────────────────────────────────────────────────────────────────

    def canaletto_luminous_veduta_pass(
        self,
        sky_lift: float = 0.18,
        stone_warm: float = 0.14,
        water_cool: float = 0.12,
        sky_band: float = 0.38,
        opacity: float = 0.65,
    ) -> None:
        """
        Apply Canaletto's defining chromatic clarity: the three-register
        Venetian veduta palette.

        Three operations applied to distinct luminance/hue zones:

        1. **Sky cerulean lift** — the upper canvas (above sky_band) receives a
           blue-channel boost and slight desaturation toward cerulean.  Canaletto's
           skies are the clearest in the whole Western landscape tradition: no
           warm haze at the horizon, just saturated, direct Venetian blue.

        2. **Warm honey-stone push** — sunlit mid-tones (moderate luminance with
           warm R>G>B dominance) are pushed further toward warm ochre-honey.
           This is the warm masonry that fills the centre of every veduta —
           the Doge's Palace, the Procuratie, the Rialto stone.

        3. **Canal silver-blue pull** — cool mid-tones (B ≥ R, moderate luminance)
           are pulled further toward cool silver-blue.  This distinguishes the
           canal-water reflections from the stone architecture in every painting
           Canaletto made of the Grand Canal.

        Parameters
        ----------
        sky_lift      : strength of the cerulean blue push in the sky zone
        stone_warm    : strength of the warm ochre push in sunlit stone zones
        water_cool    : strength of the cool silver-blue pull in water/shadow zones
        sky_band      : canvas fraction (from top) treated as sky zone (0 = top)
        opacity       : overall pass blend weight
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Canaletto luminous veduta pass "
              f"(sky_lift={sky_lift:.3f} stone_warm={stone_warm:.3f} "
              f"water_cool={water_cool:.3f} opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Canaletto luminous veduta pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Sky cerulean lift ──────────────────────────────────────────────
        sky_y = int(h * sky_band)
        sky_mask = _np.zeros((h, w), dtype=_np.float32)
        if sky_y > 0:
            # linear falloff: full at top row, zero at sky_y
            for yi in range(sky_y):
                sky_mask[yi, :] = 1.0 - yi / float(sky_y)

        sky_w = sky_mask * sky_lift * opacity
        # cerulean = boost B, slight boost G, restrain R
        r_out = _np.clip(r_out - sky_w * 0.30, 0.0, 1.0)
        g_out = _np.clip(g_out + sky_w * 0.12, 0.0, 1.0)
        b_out = _np.clip(b_out + sky_w * 0.85, 0.0, 1.0)

        # ── 2. Warm stone push (sunlit masonry) ───────────────────────────────
        # Pixels where R > G > B (warm hue) and mid-high luminance (sunlit)
        warm_dom  = (r_out > g_out) & (g_out > b_out * 1.08)
        sunlit    = (lum > 0.38) & (lum < 0.88)
        stone_px  = warm_dom & sunlit & (sky_mask < 0.25)   # below sky zone
        stone_w   = _np.where(stone_px, stone_warm * opacity, 0.0).astype(_np.float32)
        # warm ochre push: lift R, gentle G, suppress B
        r_out = _np.clip(r_out + stone_w * 0.70, 0.0, 1.0)
        g_out = _np.clip(g_out + stone_w * 0.30, 0.0, 1.0)
        b_out = _np.clip(b_out - stone_w * 0.40, 0.0, 1.0)

        # ── 3. Canal silver-blue pull (water and cool shadow) ─────────────────
        # Pixels where B ≥ R (cool hue) and moderate luminance (not deepest shadow)
        cool_dom  = b_out >= r_out
        water_lum = (lum > 0.20) & (lum < 0.72)
        water_px  = cool_dom & water_lum & (sky_mask < 0.25)
        water_w   = _np.where(water_px, water_cool * opacity, 0.0).astype(_np.float32)
        # silver-blue: slight desaturation + blue tint
        r_out = _np.clip(r_out * (1.0 - water_w * 0.35) + lum * water_w * 0.35
                         - water_w * 0.06, 0.0, 1.0)
        g_out = _np.clip(g_out * (1.0 - water_w * 0.20) + lum * water_w * 0.20, 0.0, 1.0)
        b_out = _np.clip(b_out + water_w * 0.18, 0.0, 1.0)

        # Write back (BGRA)
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        stone_count = int(stone_px.sum())
        water_count = int(water_px.sum())
        print(f"    Canaletto luminous veduta pass complete  "
              f"(stone_px={stone_count}  water_px={water_count})")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 63 — Artistic improvement: old-master varnish patina pass
    # ─────────────────────────────────────────────────────────────────────────

    def old_master_varnish_pass(
        self,
        amber_strength: float = 0.18,
        edge_darken: float = 0.12,
        highlight_desat: float = 0.08,
        opacity: float = 0.55,
    ) -> None:
        """
        Simulate three centuries of aged amber varnish on an old master painting.

        Museum-quality old master paintings (Rembrandt, Vermeer, Titian, Leonardo)
        have accumulated multiple layers of natural resin varnish that has yellowed
        and darkened over centuries.  The visible effect is:

        1. **Amber tint** — a warm yellow-brown cast over the entire surface.
           The blue channel is most suppressed; red and green are gently boosted.
           This is the most immediately recognisable quality of a varnished old
           master: colours that were once cooler now read as warmer, and the
           overall key is slightly lower.

        2. **Edge oxidation darkening** — varnish on the edges and corners of a
           panel or canvas oxidizes faster than the centre (less UV exposure at
           margins, but more moisture ingress).  A radial darkening mask is applied
           with a cos² falloff that is strongest at the canvas border and zero
           toward the centre.  This subtly reinforces a vignette effect.

        3. **Highlight desaturation** — the brightest specular highlights on skin,
           drapery, and metalwork are slightly desaturated by the amber overlay.
           Where a freshly-painted Titian might have pure white highlights, a
           varnished Titian has warm ivory highlights.

        This pass is intentionally subtle at default opacity (0.55) — it should
        add the sense of age and museum authenticity without noticeably distorting
        colour relationships.  Use opacity=0.20–0.35 for a barely-perceptible
        museum patina; 0.55–0.75 for a heavily varnished look.

        Parameters
        ----------
        amber_strength   : strength of the warm amber tint (R+G↑, B↓)
        edge_darken      : strength of the edge/corner darkening vignette
        highlight_desat  : desaturation of the brightest highlights
        opacity          : overall pass blend weight
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Old-master varnish pass "
              f"(amber={amber_strength:.3f} edge_darken={edge_darken:.3f} "
              f"highlight_desat={highlight_desat:.3f} opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Old-master varnish pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Amber tint (yellowed varnish) ──────────────────────────────────
        # Natural resin varnish yellows: suppresses B channel most, boosts R+G
        amb = amber_strength * opacity
        r_out = _np.clip(r_out + amb * 0.22, 0.0, 1.0)
        g_out = _np.clip(g_out + amb * 0.12, 0.0, 1.0)
        b_out = _np.clip(b_out - amb * 0.38, 0.0, 1.0)

        # ── 2. Edge oxidation darkening ───────────────────────────────────────
        # cos² radial falloff: 1.0 at border, 0.0 at centre
        ys = _np.linspace(-1.0, 1.0, h)[:, _np.newaxis]
        xs = _np.linspace(-1.0, 1.0, w)[_np.newaxis, :]
        r2 = _np.clip(ys ** 2 + xs ** 2, 0.0, None)
        edge_mask = _np.clip((r2 - 0.55) / 0.45, 0.0, 1.0).astype(_np.float32)
        edge_w = edge_mask * edge_darken * opacity
        r_out = _np.clip(r_out * (1.0 - edge_w), 0.0, 1.0)
        g_out = _np.clip(g_out * (1.0 - edge_w), 0.0, 1.0)
        b_out = _np.clip(b_out * (1.0 - edge_w), 0.0, 1.0)

        # ── 3. Highlight desaturation (amber wash dulls pure whites) ─────────
        bright_px = lum > 0.78
        desat_w   = _np.where(bright_px, highlight_desat * opacity, 0.0).astype(_np.float32)
        r_out = r_out * (1.0 - desat_w) + lum * desat_w
        g_out = g_out * (1.0 - desat_w) + lum * desat_w
        b_out = b_out * (1.0 - desat_w) + lum * desat_w
        # Re-apply a gentle amber tint to desaturated highlights
        r_out = _np.clip(r_out + desat_w * 0.04, 0.0, 1.0)
        b_out = _np.clip(b_out - desat_w * 0.06, 0.0, 1.0)

        # Write back (BGRA)
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        bright_count = int(bright_px.sum())
        print(f"    Old-master varnish pass complete  "
              f"(bright_px={bright_count})")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 64 — New artist: Vigée Le Brun pearlescent grace pass
    # ─────────────────────────────────────────────────────────────────────────

    def vigee_le_brun_pearlescent_grace_pass(
        self,
        rose_bloom_strength: float = 0.10,
        pearl_highlight:     float = 0.06,
        shadow_warmth:       float = 0.04,
        midtone_low:         float = 0.48,
        midtone_high:        float = 0.82,
        opacity:             float = 0.65,
    ) -> None:
        """
        Apply Élisabeth Louise Vigée Le Brun's defining skin quality.

        Vigée Le Brun (1755–1842), court portraitist to Marie Antoinette and
        the European aristocracy, developed a skin-rendering technique unique
        among her contemporaries: a warm pearlescent iridescence that makes her
        sitters appear lit from within rather than merely lit from without.

        She worked from the midtone outward — establishing a warm rose-ivory
        foundation across the whole face, then modulating toward shadow and
        highlight from that pink centre.  The result is that even her deepest
        shadows retain rose-warm quality; and her highlights, rather than
        reaching warm ivory, attain a cool pearl iridescence — the slight
        blue-cool shimmer of nacre.

        Three operations:

        1. **Rose bloom in warm midtones** — pixels with luminance in
           [midtone_low, midtone_high] receive a warm rose-ivory push
           (R+ strongly, G+ modestly, B+ very slightly).  This is the primary
           characteristic: not the red-orange of SSS but the pink-ivory of
           18th-century French aristocratic skin.

        2. **Pearl highlight** — very bright pixels (lum > midtone_high)
           receive a slight cool pearl shift (B+ slight, R- slight), converting
           pure white specular highlights to the characteristic nacre quality.
           Pearl reflects slightly cool-blue — not the warm ivory of Raphael.

        3. **Shadow warmth injection** — deepest shadow pixels (lum < 0.30)
           receive a subtle warm rose-violet push.  Vigée Le Brun's shadows are
           never cold grey — they are warm, inhabited, alive.

        Parameters
        ----------
        rose_bloom_strength : warm rose push in the lit midtone zone
        pearl_highlight     : cool pearl shift in the brightest highlights
        shadow_warmth       : warm rose-violet push in the deepest shadows
        midtone_low         : lower luminance boundary of the midtone bloom zone
        midtone_high        : upper luminance boundary of the midtone bloom zone
        opacity             : overall blend weight
        """
        import numpy as _np

        print(f"  Vigée Le Brun pearlescent grace pass "
              f"(rose={rose_bloom_strength:.3f}  pearl={pearl_highlight:.3f}  "
              f"shadow_warm={shadow_warmth:.3f}  "
              f"lum=[{midtone_low:.2f},{midtone_high:.2f}]  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Vigée Le Brun pearlescent grace pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Rose bloom in warm midtones ────────────────────────────────────
        # Tent mask peaking at the centre of [midtone_low, midtone_high]
        mid_c = (midtone_low + midtone_high) * 0.5
        mid_h = (midtone_high - midtone_low) * 0.5
        midtone_mask = _np.clip(1.0 - _np.abs(lum - mid_c) / max(mid_h, 1e-8),
                                0.0, 1.0)

        rose_w = midtone_mask * rose_bloom_strength * opacity
        r_out = _np.clip(r_out + rose_w * 0.85, 0.0, 1.0)   # strong pink-rose
        g_out = _np.clip(g_out + rose_w * 0.32, 0.0, 1.0)   # modest — keeps it rose not orange
        b_out = _np.clip(b_out + rose_w * 0.10, 0.0, 1.0)   # tiny — prevents pure red cast

        # ── 2. Pearl highlight ────────────────────────────────────────────────
        # Pixels above midtone_high receive the cool nacre shimmer
        pearl_mask = _np.clip(
            (lum - midtone_high) / max(1.0 - midtone_high, 1e-8), 0.0, 1.0)
        pearl_w = pearl_mask * pearl_highlight * opacity
        r_out = _np.clip(r_out - pearl_w * 0.30, 0.0, 1.0)   # slight R pull → cooler
        b_out = _np.clip(b_out + pearl_w * 0.40, 0.0, 1.0)   # slight B lift → pearl shimmer

        # ── 3. Shadow warmth injection ────────────────────────────────────────
        # Pixels below lum=0.30 — Vigée Le Brun shadows are rose-warm, not cold
        shadow_mask = _np.clip(1.0 - lum / 0.30, 0.0, 1.0)
        shadow_w = shadow_mask * shadow_warmth * opacity
        r_out = _np.clip(r_out + shadow_w * 0.55, 0.0, 1.0)   # warm rose
        g_out = _np.clip(g_out + shadow_w * 0.15, 0.0, 1.0)
        b_out = _np.clip(b_out + shadow_w * 0.25, 0.0, 1.0)   # slight violet cast

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        midtone_px = int((midtone_mask > 0.05).sum())
        print(f"    Vigée Le Brun pearlescent grace pass complete  "
              f"(midtone_px={midtone_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 64 — Artistic improvement: subsurface scatter pass
    # ─────────────────────────────────────────────────────────────────────────

    def subsurface_scatter_pass(
        self,
        scatter_strength:    float = 0.14,
        scatter_radius:      float = 8.0,
        scatter_low:         float = 0.42,
        scatter_high:        float = 0.82,
        penumbra_warm:       float = 0.06,
        shadow_cool:         float = 0.04,
        shadow_pellucidity:  float = 0.0,
        penumbra_warmth_depth: float = 0.0,
        opacity:             float = 0.65,
    ) -> None:
        """
        Simulate subsurface light scattering through human skin.

        When light strikes skin, a significant fraction penetrates the epidermis
        and scatters through the layers beneath — dermis, subcutaneous fat,
        capillary beds — before re-emerging at the surface displaced a few
        millimetres from the entry point.  This scattering is strongly
        wavelength-dependent: long wavelengths (red, orange) penetrate deepest
        and scatter furthest; short wavelengths (blue, violet) are absorbed near
        the surface.

        The result is the warm red-orange inner glow that distinguishes real
        skin from any painted imitation — most visible in three zones:

        1. **Lit midtones** (luminance scatter_low–scatter_high): the lit-but-
           not-specular zone where scatter path length is greatest.  These pixels
           receive a diffuse warm red-orange bloom — R+ most, G+ modest, B-.
           The bloom is softened with a Gaussian (radius ~8px) because the
           scatter path is non-directional and covers a finite skin area.

        2. **Penumbra / shadow edge** (luminance 0.28–scatter_low): the zone
           where light entering from the adjacent lit surface has scattered
           sideways into the shadow edge — the warm "inner light" that curves
           around the terminator.  A subtler deep-red warmth without bloom.

        3. **Deep shadow cool recovery** (luminance < 0.28): subsurface scatter
           fails in the deepest shadows — no light penetrates here.  A slight
           cool push (R-, B+) reinforces shadow colour separation from the warm
           lit zones, increasing perceived luminosity by contrast.

        4. **Shadow pellucidity** (session 92 artistic improvement — inspired by
           Antonello da Messina): when shadow_pellucidity > 0, a very faint
           cool-blue lift is applied to the absolute darkest pixels (lum < 0.18),
           simulating the way multiple thin transparent oil-glaze layers allow a
           trace of light to seep through even the deepest shadows.  Unlike
           shadow_cool (which cools *all* dark areas below 0.28), this parameter
           targets only the innermost shadows and lifts them with a faint warm-
           neutral transparency rather than a cold push — replicating the quality
           Antonello da Messina achieved through his Flemish glazing method: the
           paint film is never completely opaque, so the white gesso ground
           exerts a faint luminous presence even behind the darkest darks.
           Apply at 0.02–0.08 for Flemish/Sicilian Renaissance portraits; leave
           at 0.0 (default) for Caravaggio-style or Rembrandt tenebrist shadows
           where absolute blackness is intentional.

        This pass should be applied *before* final glazing and artist-specific
        passes.  At default opacity (0.65) it is visibly present but natural.
        Use opacity=0.35–0.50 for a barely-perceptible glow; 0.80–1.0 for the
        jewel-like Bouguereau/Vigée Le Brun hyper-real effect.

        Parameters
        ----------
        scatter_strength    : peak red-orange scatter boost in lit midtones
        scatter_radius      : Gaussian blur radius of scatter bloom (pixels)
        scatter_low         : lower luminance boundary of the lit-midtone zone
        scatter_high        : upper luminance boundary (above = specular, not scatter)
        penumbra_warm       : warm push in the penumbra zone (0.28–scatter_low)
        shadow_cool         : cool push in deepest shadows (lum < 0.28)
        shadow_pellucidity  : Antonello/Flemish faint lift in absolute darks (lum < 0.18)
        penumbra_warmth_depth : Carlo Dolci — concentrated amber resonance at the very
                              centre of the penumbra zone, simulating the warm interior
                              depth built from layered amber-brown glazes on copper
                              panels.  Unlike penumbra_warm (which is broadly applied
                              across the whole 0.28–scatter_low band), this parameter
                              concentrates a narrow, intense amber glow at the exact
                              mid-point of the penumbra, where light and shadow meet
                              most evenly — the zone where Dolci's glazed warmth is
                              most visible.  Use 0.04–0.10 for his devotional panels;
                              leave at 0.0 (default) for all other artists.
        opacity             : overall blend weight
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Subsurface scatter pass "
              f"(scatter={scatter_strength:.3f}  radius={scatter_radius:.1f}  "
              f"lum=[{scatter_low:.2f},{scatter_high:.2f}]  "
              f"penumbra={penumbra_warm:.3f}  shadow_cool={shadow_cool:.3f}  "
              f"shadow_pellucidity={shadow_pellucidity:.3f}  "
              f"penumbra_warmth_depth={penumbra_warmth_depth:.3f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Subsurface scatter pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Lit-midtone scatter bloom ──────────────────────────────────────
        # Build a ramp mask over the lit-midtone range
        scatter_range = max(scatter_high - scatter_low, 1e-8)
        scatter_raw = _np.clip((lum - scatter_low) / scatter_range, 0.0, 1.0)
        scatter_raw = _np.where(lum > scatter_high, 0.0, scatter_raw)  # clamp above specular

        # Soften with Gaussian to simulate the non-local scatter path length
        scatter_img = _Image.fromarray(
            _np.clip(scatter_raw * 255, 0, 255).astype(_np.uint8), mode="L")
        scatter_blurred = _np.asarray(
            scatter_img.filter(_ImageFilter.GaussianBlur(radius=float(scatter_radius))),
            dtype=_np.float32) / 255.0

        # Apply warm red-orange bloom (R >> G > 0 > B)
        s_w = scatter_blurred * scatter_strength * opacity
        r_out = _np.clip(r_out + s_w * 0.90, 0.0, 1.0)   # strong red
        g_out = _np.clip(g_out + s_w * 0.28, 0.0, 1.0)   # modest green (orange component)
        b_out = _np.clip(b_out - s_w * 0.45, 0.0, 1.0)   # damp blue

        # ── 2. Penumbra warmth ────────────────────────────────────────────────
        # Tent mask centred on the midpoint of [0.28, scatter_low]
        pen_lo  = 0.28
        pen_mid = (pen_lo + scatter_low) * 0.5
        pen_h   = max((scatter_low - pen_lo) * 0.5, 1e-8)
        penumbra_mask = _np.clip(
            1.0 - _np.abs(lum - pen_mid) / pen_h, 0.0, 1.0)

        p_w = penumbra_mask * penumbra_warm * opacity
        r_out = _np.clip(r_out + p_w * 0.70, 0.0, 1.0)   # deep red
        g_out = _np.clip(g_out + p_w * 0.15, 0.0, 1.0)
        b_out = _np.clip(b_out - p_w * 0.20, 0.0, 1.0)

        # ── 3. Deep shadow cool recovery ─────────────────────────────────────
        # Subsurface scatter fails in the deepest shadows
        shadow_mask = _np.clip(1.0 - lum / 0.28, 0.0, 1.0)
        sc_w = shadow_mask * shadow_cool * opacity
        r_out = _np.clip(r_out - sc_w * 0.50, 0.0, 1.0)
        b_out = _np.clip(b_out + sc_w * 0.60, 0.0, 1.0)

        # ── 4½. Penumbra warmth depth (session 103 — Carlo Dolci) ────────────
        # Concentrated amber resonance at the exact penumbra midpoint — the
        # zone where Dolci's layered copper-panel glazes create maximum amber
        # depth.  A narrow Gaussian spike centred on pen_mid, applied as a
        # warm-amber push (R+, G+ slight, B-) that is more concentrated than
        # the broad penumbra_warm spread.  Only active when > 0.0.
        if penumbra_warmth_depth > 0.0:
            pen_depth_mask = _np.clip(
                1.0 - _np.abs(lum - pen_mid) / max(pen_h * 0.45, 1e-8), 0.0, 1.0)
            pd_w = pen_depth_mask * penumbra_warmth_depth * opacity
            r_out = _np.clip(r_out + pd_w * 0.80, 0.0, 1.0)   # warm amber R
            g_out = _np.clip(g_out + pd_w * 0.20, 0.0, 1.0)   # slight amber G
            b_out = _np.clip(b_out - pd_w * 0.25, 0.0, 1.0)   # damp blue

        # ── 4. Shadow pellucidity (session 92 — Antonello da Messina) ─────────
        # Flemish oil-glaze quality: white gesso ground glows faintly through
        # even the darkest paint layers.  Apply a very faint warm-neutral lift
        # to absolute darks (lum < 0.18) when shadow_pellucidity > 0.
        if shadow_pellucidity > 0.0:
            from scipy.ndimage import gaussian_filter as _gf_sp
            pellucid_raw = _np.clip(1.0 - lum / 0.18, 0.0, 1.0)
            pellucid_mask = _gf_sp(pellucid_raw, sigma=3.0)  # soften spatially
            p_lift = pellucid_mask * shadow_pellucidity * opacity
            # Warm-neutral lift: R+modest, G+modest, B+slight — not cold, but translucent
            r_out = _np.clip(r_out + p_lift * 0.55, 0.0, 1.0)
            g_out = _np.clip(g_out + p_lift * 0.42, 0.0, 1.0)
            b_out = _np.clip(b_out + p_lift * 0.30, 0.0, 1.0)

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        scatter_px = int((scatter_blurred > 0.05).sum())
        print(f"    Subsurface scatter pass complete  "
              f"(scatter_px={scatter_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 65 — Alma-Tadema marble luminance pass
    # ─────────────────────────────────────────────────────────────────────────

    def alma_tadema_marble_luminance_pass(
        self,
        marble_warm_strength: float = 0.08,
        specular_cool_shift:  float = 0.06,
        specular_thresh:      float = 0.86,
        translucent_low:      float = 0.52,
        translucent_high:     float = 0.86,
        opacity:              float = 0.60,
    ) -> None:
        """
        Apply Lawrence Alma-Tadema's characteristic marble luminance quality.

        Alma-Tadema (1836–1912), Dutch-British painter of ancient Greco-Roman
        scenes, became the foremost renderer of marble in the history of Western
        painting.  His marble is not a grey-white inert solid: it is a translucent
        material that absorbs light at the surface and radiates it from within,
        simultaneously warm in the body and cool at the sharpest specular peaks.

        Three mechanisms drive his marble luminosity:

        1. **Warm translucent body** — marble in the mid-luminance range
           (translucent_low–translucent_high) receives a warm cream-gold push
           (R+ strong, G+ moderate, B-).  Pentelic and Giallo Antico marble
           contain iron impurities that give the stone a warm cast when
           backlit or side-lit.  This is the "glow from within" quality — the
           opposite of the cold grey of plaster.

        2. **Cool crystalline specular** — very bright pixels above
           specular_thresh receive a slight cool shift (B+, R-).  This is
           the direct specular reflection off the polished marble surface.
           Polished marble acts as a near-perfect mirror for the coolest
           component of daylight (skylight, not sunlight), so the very
           brightest highlights are distinctly cooler than the warm marble body.
           The contrast between warm body and cool peak creates the crystalline
           quality that sets his marble apart from Bouguereau's ivory skin.

        3. **Shadow depth** — deep shadows (lum < translucent_low * 0.5)
           receive a slight warm ochre push.  Marble shadow is not neutral grey —
           the warm stone body colours the shadow from within.

        Parameters
        ----------
        marble_warm_strength : warm cream-gold push in the marble body zone
        specular_cool_shift  : cool (B+/R-) shift in the sharpest specular peaks
        specular_thresh      : luminance threshold above which specular cooling applies
        translucent_low      : lower luminance of the warm-body translucency zone
        translucent_high     : upper luminance of the warm-body zone (below specular peak)
        opacity              : overall blend weight
        """
        import numpy as _np

        print(f"  Alma-Tadema marble luminance pass "
              f"(marble_warm={marble_warm_strength:.3f}  "
              f"specular_cool={specular_cool_shift:.3f}  "
              f"specular_thresh={specular_thresh:.2f}  "
              f"lum=[{translucent_low:.2f},{translucent_high:.2f}]  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Alma-Tadema marble luminance pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Warm translucent marble body ───────────────────────────────────
        # Tent mask peaking at centre of [translucent_low, translucent_high]
        mid_c = (translucent_low + translucent_high) * 0.5
        mid_h = (translucent_high - translucent_low) * 0.5
        body_mask = _np.clip(
            1.0 - _np.abs(lum - mid_c) / max(mid_h, 1e-8), 0.0, 1.0)

        warm_w = body_mask * marble_warm_strength * opacity
        r_out = _np.clip(r_out + warm_w * 0.80, 0.0, 1.0)   # cream-gold: strong R
        g_out = _np.clip(g_out + warm_w * 0.50, 0.0, 1.0)   # moderate G
        b_out = _np.clip(b_out - warm_w * 0.10, 0.0, 1.0)   # slight B suppression

        # ── 2. Cool crystalline specular ──────────────────────────────────────
        # Pixels above specular_thresh: direct specular from skylight — cool
        specular_mask = _np.clip(
            (lum - specular_thresh) / max(1.0 - specular_thresh, 1e-8), 0.0, 1.0)
        specular_w = specular_mask * specular_cool_shift * opacity
        r_out = _np.clip(r_out - specular_w * 0.40, 0.0, 1.0)  # R- → cooler
        b_out = _np.clip(b_out + specular_w * 0.50, 0.0, 1.0)  # B+ → pearl-crystal

        # ── 3. Shadow warm ochre depth ────────────────────────────────────────
        shadow_thresh = translucent_low * 0.5
        shadow_mask = _np.clip(1.0 - lum / max(shadow_thresh, 1e-8), 0.0, 1.0)
        shadow_w = shadow_mask * (marble_warm_strength * 0.4) * opacity
        r_out = _np.clip(r_out + shadow_w * 0.60, 0.0, 1.0)   # warm ochre
        g_out = _np.clip(g_out + shadow_w * 0.38, 0.0, 1.0)
        b_out = _np.clip(b_out - shadow_w * 0.08, 0.0, 1.0)

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        specular_px = int((specular_mask > 0.05).sum())
        body_px     = int((body_mask > 0.05).sum())
        print(f"    Alma-Tadema marble luminance pass complete  "
              f"(body_px={body_px}  specular_px={specular_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 65 — Artistic improvement: crystalline surface pass
    # ─────────────────────────────────────────────────────────────────────────

    def crystalline_surface_pass(
        self,
        specular_radius:    float = 2.5,
        specular_strength:  float = 0.12,
        specular_thresh:    float = 0.80,
        micro_cool_shift:   float = 0.04,
        halo_radius:        float = 6.0,
        halo_warmth:        float = 0.05,
        halo_thresh:        float = 0.70,
        opacity:            float = 0.55,
    ) -> None:
        """
        Simulate specular coherence on smooth, polished surfaces.

        Inspired by Lawrence Alma-Tadema's glass-like mastery of polished marble,
        this pass applies a universal surface-quality improvement to any painted
        image: it sharpens and concentrates the specular peaks while introducing
        the warm halo that real materials produce around a sharp specular — the
        zone where the surface is not quite bright enough for direct specular
        but is close enough to receive diffuse reflected light from the bright
        zone.

        Two complementary operations:

        1. **Specular peak concentration** — the very brightest pixels
           (above specular_thresh) are enhanced with a Gaussian-sharpened
           version of themselves.  The sharpened version is computed by
           subtracting a blurred version from the original (unsharp mask
           principle) and compositing the result.  A slight cool shift
           (micro_cool_shift) is applied to the peak: polished surfaces
           reflect the coolest component of the ambient light at their
           sharpest specular angle — the same principle as Alma-Tadema's
           marble peaks.

        2. **Specular halo warmth** — pixels in a surrounding zone
           (halo_thresh–specular_thresh) receive a slight warm push.  This
           is the diffuse component of the specular lobe — the zone adjacent
           to the mirror-like peak where light is scattered in a narrow cone.
           On warm materials (marble, ivory, skin), this halo has a warm
           cream-gold cast.  Adding this halo increases the perceptual "depth"
           of the specular peak by providing a warm-to-cool gradient: warm
           halo → neutral midtone → cool peak.

        This pass is universally applicable and should be placed near the end
        of the pipeline, after artist-specific skin and material passes and
        before the final varnish.

        Parameters
        ----------
        specular_radius   : Gaussian radius for the unsharp mask (pixels)
        specular_strength : peak enhancement strength
        specular_thresh   : luminance threshold for the specular zone
        micro_cool_shift  : cool (B+/R-) shift applied to the specular peak
        halo_radius       : Gaussian radius for the halo zone blending
        halo_warmth       : warm push in the halo zone (halo_thresh–specular_thresh)
        halo_thresh       : lower luminance boundary of the halo zone
        opacity           : overall blend weight
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Crystalline surface pass "
              f"(spec_r={specular_radius:.1f}  strength={specular_strength:.3f}  "
              f"thresh={specular_thresh:.2f}  cool={micro_cool_shift:.3f}  "
              f"halo_r={halo_radius:.1f}  halo_warm={halo_warmth:.3f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print(f"    Crystalline surface pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Specular peak concentration (unsharp mask on bright zone) ──────
        # Build a blurred luminance map to identify the broad bright region
        lum_img = _Image.fromarray(
            _np.clip(lum * 255.0, 0, 255).astype(_np.uint8), "L")
        lum_blur = _np.array(
            lum_img.filter(_ImageFilter.GaussianBlur(radius=specular_radius)),
            dtype=_np.float32) / 255.0

        # Unsharp mask: detail = original - blurred
        lum_detail = lum - lum_blur

        # Specular zone mask — only pixels above threshold
        specular_mask = _np.clip(
            (lum - specular_thresh) / max(1.0 - specular_thresh, 1e-8), 0.0, 1.0)

        # Apply concentrated detail push to all channels
        spec_w = specular_mask * specular_strength * opacity
        detail_lift = lum_detail * spec_w
        r_out = _np.clip(r_out + detail_lift, 0.0, 1.0)
        g_out = _np.clip(g_out + detail_lift, 0.0, 1.0)
        b_out = _np.clip(b_out + detail_lift, 0.0, 1.0)

        # Cool shift on the sharpened peaks
        cool_w = specular_mask * micro_cool_shift * opacity
        r_out = _np.clip(r_out - cool_w * 0.35, 0.0, 1.0)
        b_out = _np.clip(b_out + cool_w * 0.45, 0.0, 1.0)

        # ── 2. Specular halo warmth ────────────────────────────────────────────
        # Halo zone: halo_thresh ≤ lum < specular_thresh
        halo_mask = _np.clip(
            (lum - halo_thresh) / max(specular_thresh - halo_thresh, 1e-8),
            0.0, 1.0) * (1.0 - specular_mask)

        # Blur the halo mask slightly for a smooth transition
        halo_img  = _Image.fromarray(
            _np.clip(halo_mask * 255.0, 0, 255).astype(_np.uint8), "L")
        halo_soft = _np.array(
            halo_img.filter(_ImageFilter.GaussianBlur(radius=halo_radius)),
            dtype=_np.float32) / 255.0

        halo_w = halo_soft * halo_warmth * opacity
        r_out = _np.clip(r_out + halo_w * 0.75, 0.0, 1.0)   # warm cream-gold
        g_out = _np.clip(g_out + halo_w * 0.48, 0.0, 1.0)
        b_out = _np.clip(b_out - halo_w * 0.06, 0.0, 1.0)

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        specular_px = int((specular_mask > 0.05).sum())
        halo_px     = int((halo_soft > 0.05).sum())
        print(f"    Crystalline surface pass complete  "
              f"(specular_px={specular_px}  halo_px={halo_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Patinir world-landscape atmospheric recession pass (session 66)
    # ─────────────────────────────────────────────────────────────────────────

    def patinir_weltlandschaft_pass(self,
                                    warm_foreground:  float = 0.10,
                                    green_midground:  float = 0.08,
                                    cool_distance:    float = 0.12,
                                    horizon_near:     float = 0.55,
                                    horizon_far:      float = 0.72,
                                    transition_blur:  float = 18.0,
                                    opacity:          float = 0.55) -> None:
        """
        Patinir Weltlandschaft three-zone atmospheric recession pass.

        Joachim Patinir (c. 1480–1524) established the 'world landscape'
        (Weltlandschaft) as an independent genre: vast panoramic terrain viewed
        from a high vantage point, with systematic colour recession across three
        distinct atmospheric zones.

        Zone 1 — Foreground (below horizon_near):
            Push toward warm sandy ochre.  Rocks and earth read as warm brown,
            sunlit and textured.  Geological crispness: no aerial softening.

        Zone 2 — Middle distance (horizon_near → horizon_far):
            Push toward muted olive-green.  Foliage, water, and terrain shift to
            the characteristic Patinir sage-green hue that separates foreground
            brown from distant blue.

        Zone 3 — Far distance (above horizon_far):
            Push toward pale cool blue-grey.  The far distance dissolves into
            sky-like aerial haze — Patinir's skies and distant mountains share
            the same pale cerulean tint.

        Transition between zones is Gaussian-blurred so the colour bands
        dissolve into one another rather than producing hard horizontal seams.

        Parameters
        ----------
        warm_foreground  : strength of warm ochre push in foreground zone
        green_midground  : strength of olive-green push in middle zone
        cool_distance    : strength of cool blue-grey push in far zone
        horizon_near     : canvas Y fraction where foreground ends (0=top, 1=bottom)
        horizon_far      : canvas Y fraction where middle zone ends
        transition_blur  : Gaussian radius (px) to soften zone boundaries
        opacity          : overall blend weight
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter
        from scipy import ndimage as _ndimage

        print(f"  Patinir Weltlandschaft pass "
              f"(warm={warm_foreground:.3f}  green={green_midground:.3f}  "
              f"cool={cool_distance:.3f}  hn={horizon_near:.2f}  "
              f"hf={horizon_far:.2f}  blur={transition_blur:.1f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Patinir Weltlandschaft pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # Build per-pixel Y-fraction array (0=top, 1=bottom)
        y_frac = (_np.arange(h, dtype=_np.float32) / max(h - 1, 1))[:, _np.newaxis]
        y_frac = _np.broadcast_to(y_frac, (h, w)).copy()

        # ── Zone masks (soft-edged via Gaussian blur) ─────────────────────────
        # Foreground mask: peaks at bottom, falls off above horizon_near
        fg_raw = _np.clip((y_frac - horizon_near) / max(1.0 - horizon_near, 1e-8),
                          0.0, 1.0)
        fg_img  = _Image.fromarray(
            _np.clip(fg_raw * 255, 0, 255).astype(_np.uint8), "L")
        fg_mask = _np.array(
            fg_img.filter(_ImageFilter.GaussianBlur(radius=transition_blur)),
            dtype=_np.float32) / 255.0

        # Far-distance mask: peaks at top, falls off below horizon_far
        far_raw = _np.clip((horizon_far - y_frac) / max(horizon_far, 1e-8),
                           0.0, 1.0)
        far_img  = _Image.fromarray(
            _np.clip(far_raw * 255, 0, 255).astype(_np.uint8), "L")
        far_mask = _np.array(
            far_img.filter(_ImageFilter.GaussianBlur(radius=transition_blur)),
            dtype=_np.float32) / 255.0

        # Middle-ground mask: complement of the other two
        mid_mask = _np.clip(1.0 - fg_mask - far_mask, 0.0, 1.0)

        # ── Zone 1: Foreground warm ochre push ────────────────────────────────
        # Warm sandy ochre: R↑ G slight↑ B↓
        w1 = fg_mask * warm_foreground * opacity
        r_out = _np.clip(r_out + w1 * 0.72, 0.0, 1.0)
        g_out = _np.clip(g_out + w1 * 0.32, 0.0, 1.0)
        b_out = _np.clip(b_out - w1 * 0.28, 0.0, 1.0)

        # ── Zone 2: Middle-distance olive-green push ──────────────────────────
        # Muted olive green: G↑ R slight↑ B slight↓
        w2 = mid_mask * green_midground * opacity
        r_out = _np.clip(r_out + w2 * 0.12, 0.0, 1.0)
        g_out = _np.clip(g_out + w2 * 0.65, 0.0, 1.0)
        b_out = _np.clip(b_out - w2 * 0.10, 0.0, 1.0)

        # ── Zone 3: Far-distance cool blue-grey push ──────────────────────────
        # Pale cool blue-grey: B↑ R↓ G slight↑
        w3 = far_mask * cool_distance * opacity
        r_out = _np.clip(r_out - w3 * 0.30, 0.0, 1.0)
        g_out = _np.clip(g_out + w3 * 0.15, 0.0, 1.0)
        b_out = _np.clip(b_out + w3 * 0.55, 0.0, 1.0)

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        fg_px  = int((fg_mask  > 0.05).sum())
        mid_px = int((mid_mask > 0.05).sum())
        far_px = int((far_mask > 0.05).sum())
        print(f"    Patinir Weltlandschaft pass complete  "
              f"(fg_px={fg_px}  mid_px={mid_px}  far_px={far_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Warm/cool form duality pass — session 66 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────

    def warm_cool_form_duality_pass(self,
                                    warm_strength:      float = 0.08,
                                    cool_strength:      float = 0.07,
                                    midtone:            float = 0.50,
                                    transition_width:   float = 0.18,
                                    blur_radius:        float = 6.0,
                                    opacity:            float = 0.55) -> None:
        """
        Warm-light / cool-shadow form duality pass.

        The single most universal principle of traditional oil painting technique:
        lit surfaces are warmer than shadow surfaces.  This emerges from the
        physical reality of outdoor light — the warm yellow sun heats the lit side
        while the cool blue sky fills the shadow — but virtually all portrait and
        figure painters apply it indoors too as a formal device for creating the
        sensation of rounded, three-dimensional form.

        Zorn, Sargent, Velázquez, and Rembrandt all employed this principle.
        Leonardo's warm amber glaze over the lit flesh and cooler deep-shadow
        umbers is essentially the same idea at a larger tonal scale.

        Algorithm
        ---------
        1. Compute per-pixel luminance.
        2. Lit zone (lum > midtone + transition_width/2):
             push toward warm — R↑, slight G↑, B↓.
        3. Shadow zone (lum < midtone - transition_width/2):
             push toward cool — R↓, B↑.
        4. Transition zone: blend linearly between warm and cool pushes.
        5. Apply Gaussian softening to the zone mask to avoid banding.

        This pass is placed after artist-specific colour passes but before the
        final varnish.  It acts as a tonal unifier that reinforces three-
        dimensionality without overriding any artist-specific colour decisions.

        Parameters
        ----------
        warm_strength    : warm push magnitude in lit zone (R+/B- scale)
        cool_strength    : cool push magnitude in shadow zone (B+/R- scale)
        midtone          : luminance pivot point (default 0.50)
        transition_width : width of the cross-fade zone around midtone
        blur_radius      : Gaussian radius (px) for mask softening
        opacity          : overall blend weight
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Warm/cool form duality pass "
              f"(warm={warm_strength:.3f}  cool={cool_strength:.3f}  "
              f"mid={midtone:.2f}  tw={transition_width:.2f}  "
              f"blur={blur_radius:.1f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Warm/cool form duality pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Lit-zone mask: ramps from 0 at midtone to 1 in bright highlights ─
        half_tw = transition_width / 2.0
        lit_raw = _np.clip((lum - (midtone + half_tw)) / max(half_tw, 1e-8),
                           0.0, 1.0)
        lit_img  = _Image.fromarray(
            _np.clip(lit_raw * 255, 0, 255).astype(_np.uint8), "L")
        lit_mask = _np.array(
            lit_img.filter(_ImageFilter.GaussianBlur(radius=blur_radius)),
            dtype=_np.float32) / 255.0

        # ── Shadow-zone mask: ramps from 0 at midtone to 1 in deepest shadows ─
        shd_raw = _np.clip(((midtone - half_tw) - lum) / max(half_tw, 1e-8),
                           0.0, 1.0)
        shd_img  = _Image.fromarray(
            _np.clip(shd_raw * 255, 0, 255).astype(_np.uint8), "L")
        shd_mask = _np.array(
            shd_img.filter(_ImageFilter.GaussianBlur(radius=blur_radius)),
            dtype=_np.float32) / 255.0

        # ── Apply warm push in lit zone (R↑ G slight↑ B↓) ────────────────────
        lw = lit_mask * warm_strength * opacity
        r_out = _np.clip(r_out + lw * 0.80, 0.0, 1.0)
        g_out = _np.clip(g_out + lw * 0.25, 0.0, 1.0)
        b_out = _np.clip(b_out - lw * 0.35, 0.0, 1.0)

        # ── Apply cool push in shadow zone (R↓ B↑) ───────────────────────────
        sw = shd_mask * cool_strength * opacity
        r_out = _np.clip(r_out - sw * 0.40, 0.0, 1.0)
        b_out = _np.clip(b_out + sw * 0.55, 0.0, 1.0)

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        lit_px = int((lit_mask > 0.05).sum())
        shd_px = int((shd_mask > 0.05).sum())
        print(f"    Warm/cool form duality pass complete  "
              f"(lit_px={lit_px}  shadow_px={shd_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Mantegna sculptural form pass — session 67 artist pass
    # ─────────────────────────────────────────────────────────────────────────

    # ─────────────────────────────────────────────────────────────────────────
    # Claude Lorrain golden light pass — session 68 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────

    def claude_lorrain_golden_light_pass(self,
                                         horizon_y:      float = 0.60,
                                         glow_spread:    float = 0.45,
                                         warmth:         float = 0.18,
                                         sky_cool:       float = 0.10,
                                         water_shimmer:  float = 0.08,
                                         opacity:        float = 0.55) -> None:
        """
        Claude Lorrain golden light pass.

        Claude Lorrain (1600–1682) was the supreme master of contre-jour landscape
        light: a low sun on the horizon floods the sky with warm amber-gold while
        the upper sky remains cool cerulean blue.  The same golden glow is mirrored
        in water below the horizon.  Distant forms dissolve in the atmospheric haze.

        This pass applies a vertical luminance gradient that:

        1.  Warms the lower sky and horizon band with amber-gold (R↑ G↑ B↓).
            The maximum warm shift is at horizon_y; it falls off with a Gaussian
            envelope of width glow_spread * image_height above and below.

        2.  Cools the upper sky region (above the horizon) with a gentle blue shift
            (R↓ B↑), reinforcing the temperature contrast that defines Lorrain's
            palette: warm horizon against cool zenith.

        3.  Adds a subtle shimmer on the lower portion of the image (water / earth
            below the horizon): a faint warm-gold lift that suggests reflected light.

        Parameters
        ----------
        horizon_y      : normalised Y position of the horizon (0=top, 1=bottom).
                         0.60 places the horizon in the lower third — typical Lorrain.
        glow_spread    : standard-deviation of the horizon glow in normalised Y units.
                         Larger values spread the warm glow further up the sky.
        warmth         : maximum warm shift magnitude at the horizon centre.
        sky_cool       : cool blue shift applied to upper sky above the glow.
        water_shimmer  : additional warm lift on water/earth below the horizon.
        opacity        : overall blend weight (0=no effect, 1=full replacement).
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Claude Lorrain golden light pass "
              f"(horizon_y={horizon_y:.2f}  spread={glow_spread:.2f}  "
              f"warmth={warmth:.3f}  sky_cool={sky_cool:.3f}  "
              f"shimmer={water_shimmer:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Claude Lorrain golden light pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Vertical coordinate (0=top, 1=bottom) ────────────────────────────
        ys = _np.linspace(0.0, 1.0, h, dtype=_np.float32)  # (H,)
        # Broadcast to (H, W)
        yy = _np.tile(ys[:, _np.newaxis], (1, w))           # (H, W)

        # ── 1. Horizon warm glow — Gaussian centred on horizon_y ─────────────
        # The glow is strongest at horizon_y and falls off symmetrically above/below.
        sigma = max(glow_spread, 0.05)
        horizon_glow = _np.exp(-0.5 * ((yy - horizon_y) / sigma) ** 2)  # (H, W)

        # Warm amber-gold: R↑ strongly, G↑ moderately, B↓ slightly
        w_factor = horizon_glow * warmth * opacity
        r_out = _np.clip(r_out + w_factor * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + w_factor * 0.62, 0.0, 1.0)
        b_out = _np.clip(b_out - w_factor * 0.30, 0.0, 1.0)

        # ── 2. Upper sky cooling (above horizon) ─────────────────────────────
        # Linear ramp: maximum cool shift at the very top, zero at horizon_y
        sky_ramp = _np.clip((horizon_y - yy) / max(horizon_y, 0.01), 0.0, 1.0)
        c_factor = sky_ramp * sky_cool * opacity
        r_out = _np.clip(r_out - c_factor * 0.45, 0.0, 1.0)
        g_out = _np.clip(g_out - c_factor * 0.10, 0.0, 1.0)
        b_out = _np.clip(b_out + c_factor * 0.60, 0.0, 1.0)

        # ── 3. Water / earth shimmer below the horizon ───────────────────────
        # Gentle warm-gold lift on everything below horizon_y, attenuating with depth.
        water_ramp = _np.clip((yy - horizon_y) / max(1.0 - horizon_y, 0.01),
                              0.0, 1.0)
        # Soft sinusoidal: maximum shimmer just below horizon, fading to near-zero at bottom
        shimmer_mask = _np.sin(water_ramp * _np.pi * 0.5)
        s_factor = shimmer_mask * water_shimmer * opacity
        r_out = _np.clip(r_out + s_factor * 0.90, 0.0, 1.0)
        g_out = _np.clip(g_out + s_factor * 0.55, 0.0, 1.0)
        b_out = _np.clip(b_out - s_factor * 0.15, 0.0, 1.0)

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        # Alpha channel untouched
        buf[:, :, 3] = _np.frombuffer(self.canvas.surface.get_data(),
                                      dtype=_np.uint8).reshape((h, w, 4))[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        warm_px = int((horizon_glow > 0.10).sum())
        print(f"    Claude Lorrain golden light pass complete  "
              f"(warm_px={warm_px})")

    # ─────────────────────────────────────────────────────────────────────────

    def mantegna_sculptural_form_pass(self,
                                      highlight_lift:   float = 0.10,
                                      shadow_deepen:    float = 0.08,
                                      edge_crisp:       float = 0.06,
                                      blur_radius:      float = 4.0,
                                      opacity:          float = 0.50) -> None:
        """
        Mantegna sculptural form pass.

        Andrea Mantegna (1431–1506) rendered the human figure as if it were
        carved from cold stone or cast in bronze.  Where Leonardo dissolved
        forms into sfumato smoke, Mantegna engraved them into mineral clarity.

        This pass detects ridge-form geometry by computing a local luminance
        gradient magnitude map.  Pixels that sit at the peak of a bright ridge
        (high luminance, surrounded by falling-away shadow) receive a pale
        chalk-cool highlight lift — the characteristic Mantegna highlight on
        the brow bone, cheekbone arc, nose bridge, and chin.  Pixels that sit
        in shadow troughs flanking these ridges receive a mild further deepening.

        Additionally, a very light sharpening kernel is applied to high-contrast
        edges in the mid-luminance range, reinforcing the engraved, graphic
        quality of Mantegna's form language.

        Parameters
        ----------
        highlight_lift  : pale chalk highlight intensity on ridge peaks
        shadow_deepen   : additional depth in shadow troughs adjacent to ridges
        edge_crisp      : unsharp-mask strength for edge reinforcement
        blur_radius     : Gaussian radius (px) for ridge peak detection
        opacity         : overall blend weight
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Mantegna sculptural form pass "
              f"(hl={highlight_lift:.3f}  sd={shadow_deepen:.3f}  "
              f"ec={edge_crisp:.3f}  blur={blur_radius:.1f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Mantegna sculptural form pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Ridge peak detection ──────────────────────────────────────────────
        # Blur luminance to find local average; pixels brighter than blur-average
        # by a margin are ridge peaks.
        lum_uint8 = _np.clip(lum * 255, 0, 255).astype(_np.uint8)
        lum_img   = _Image.fromarray(lum_uint8, "L")
        lum_blur  = _np.array(
            lum_img.filter(_ImageFilter.GaussianBlur(radius=blur_radius)),
            dtype=_np.float32) / 255.0

        # Ridge peak: local brightness above blurred neighbour average
        ridge_raw = _np.clip((lum - lum_blur) / max(0.10, 1e-8), 0.0, 1.0)
        ridge_raw = ridge_raw * (lum > 0.40).astype(_np.float32)  # only lit areas

        # Shadow trough: local darkness below blurred neighbour average
        trough_raw = _np.clip((lum_blur - lum) / max(0.10, 1e-8), 0.0, 1.0)
        trough_raw = trough_raw * (lum < 0.60).astype(_np.float32)  # only shadow areas

        # ── Pale chalk-cool highlight on ridge peaks (R↑ G↑ B↑↑) ────────────
        # Mantegna's highlights are slightly cool — whiter-grey rather than warm ivory
        hl = ridge_raw * highlight_lift * opacity
        r_out = _np.clip(r_out + hl * 0.82, 0.0, 1.0)
        g_out = _np.clip(g_out + hl * 0.86, 0.0, 1.0)
        b_out = _np.clip(b_out + hl * 0.95, 0.0, 1.0)   # slightly bluer → cool chalk

        # ── Shadow trough deepening ───────────────────────────────────────────
        # Deepen shadows at the flanks of ridge-forms (warm umber deepening)
        sd = trough_raw * shadow_deepen * opacity
        r_out = _np.clip(r_out - sd * 0.40, 0.0, 1.0)
        g_out = _np.clip(g_out - sd * 0.50, 0.0, 1.0)
        b_out = _np.clip(b_out - sd * 0.60, 0.0, 1.0)

        # ── Edge crispening (unsharp-mask on mid-luminance) ───────────────────
        # Reinforces the engraved graphic quality of Mantegna's contour lines.
        # Applied only in the mid-luminance band (0.25–0.75) to avoid blowing
        # out highlights or crushing shadows.
        if edge_crisp > 0.0:
            for ch_out, ch_f in [(r_out, r_f), (g_out, g_f), (b_out, b_f)]:
                # Per-channel unsharp mask
                ch_uint8 = _np.clip(ch_f * 255, 0, 255).astype(_np.uint8)
                ch_img   = _Image.fromarray(ch_uint8, "L")
                ch_blur  = _np.array(
                    ch_img.filter(_ImageFilter.GaussianBlur(radius=2.0)),
                    dtype=_np.float32) / 255.0
                detail = ch_f - ch_blur
                mid_mask = 1.0 - _np.abs(lum - 0.50) / 0.25   # peaks at lum=0.50
                mid_mask = _np.clip(mid_mask, 0.0, 1.0)
                # write sharpened result back into ch_out in-place via +=
                ch_out += detail * edge_crisp * opacity * mid_mask
                _np.clip(ch_out, 0.0, 1.0, out=ch_out)

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        ridge_px  = int((ridge_raw  > 0.05).sum())
        trough_px = int((trough_raw > 0.05).sum())
        print(f"    Mantegna sculptural form pass complete  "
              f"(ridge_px={ridge_px}  trough_px={trough_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Skin zone temperature pass — session 67 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────

    def skin_zone_temperature_pass(self,
                                   face_cx:         float = 0.50,
                                   face_cy:         float = 0.20,
                                   face_rx:         float = 0.13,
                                   face_ry:         float = 0.18,
                                   forehead_warm:   float = 0.04,
                                   temple_cool:     float = 0.03,
                                   nose_pink:       float = 0.04,
                                   lip_rose:        float = 0.03,
                                   jaw_cool:        float = 0.03,
                                   blur_radius:     float = 8.0,
                                   opacity:         float = 0.55) -> None:
        """
        Skin zone temperature pass — session 67 artistic improvement.

        Every human face is not a uniform colour field.  Traditional painters
        from Rubens to Sargent exploited the anatomical fact that different
        facial zones have different colour temperatures:

          Forehead / brow bone:
              Slightly warmer (golden-amber).  The skin is thickest here;
              the underlying blood vessels are closer to the surface across a
              wide area.  Great portrait painters subtly warm the forehead
              relative to the cheek plane.

          Temples / eye sockets:
              Slightly cooler (blue-grey).  The skin is thinner, the bone is
              close, and small surface veins show through.  Velázquez and
              Rembrandt both added a faint cool-blue-grey tone to the temple
              zone of their portrait sitters.

          Nose tip and alar wings:
              Slightly warmer-pink (rosacea zone).  Capillaries are dense
              here; the nose picks up warmth and pink even in pale skin.

          Lips and surrounding zone (oral zone):
              Rose-pink.  Lip mucosa is supplied by dense capillary networks.
              The skin around the mouth has a slight greenish-neutral undertone
              (the orbicularis oris muscle close to surface), but the lips
              themselves are distinctly rose.

          Chin and jaw plane:
              Slightly cooler (violet-grey).  The jaw plane faces away from
              the dominant overhead light source; it receives more cool skylight
              and the bone mass cools the overlying skin.

        Algorithm
        ---------
        1. Build normalised (x, y) coordinate maps relative to the face centre.
        2. Create five Gaussian-shaped region masks — one per zone above.
        3. Apply a targeted RGB colour push to each mask, with Gaussian blur
           to soften zone boundaries so the transition is imperceptible.
        4. Blend at the specified opacity so the effect reinforces rather
           than overrides the existing painting.

        Parameters
        ----------
        face_cx        : face centre X as fraction of canvas width
        face_cy        : face centre Y as fraction of canvas height
        face_rx        : face half-width as fraction of canvas width
        face_ry        : face half-height as fraction of canvas height
        forehead_warm  : golden-warm push strength on forehead / brow
        temple_cool    : cool blue-grey push strength on temples / eye sockets
        nose_pink      : warm-pink push strength on nose tip
        lip_rose       : rose push strength on the oral zone / lips
        jaw_cool       : cool violet-grey push strength on chin / jaw plane
        blur_radius    : Gaussian radius (px) for zone mask softening
        opacity        : overall blend weight
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  Skin zone temperature pass "
              f"(face_cx={face_cx:.2f}  face_cy={face_cy:.2f}  "
              f"rx={face_rx:.2f}  ry={face_ry:.2f}  "
              f"fwarm={forehead_warm:.3f}  tcool={temple_cool:.3f}  "
              f"npink={nose_pink:.3f}  lrose={lip_rose:.3f}  "
              f"jcool={jaw_cool:.3f}  blur={blur_radius:.1f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Skin zone temperature pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Coordinate grids ──────────────────────────────────────────────────
        cx_px = int(face_cx * w)
        cy_px = int(face_cy * h)
        rx_px = max(1, int(face_rx * w))
        ry_px = max(1, int(face_ry * h))

        ys = (_np.arange(h, dtype=_np.float32) - cy_px) / ry_px
        xs = (_np.arange(w, dtype=_np.float32) - cx_px) / rx_px
        yy, xx = _np.meshgrid(ys, xs, indexing="ij")  # (H, W)

        # Elliptical face mask — only pixels inside the face ellipse get treated.
        face_dist = xx ** 2 + yy ** 2
        face_mask = _np.clip(1.0 - (face_dist - 0.70) / 0.30, 0.0, 1.0)

        def _zone_mask(x0: float, y0: float, sigma: float) -> _np.ndarray:
            """Gaussian blob centred at (x0, y0) in normalised face coords."""
            raw = _np.exp(-((xx - x0) ** 2 + (yy - y0) ** 2) / (2 * sigma ** 2))
            raw = raw * face_mask
            img = _Image.fromarray(
                _np.clip(raw * 255, 0, 255).astype(_np.uint8), "L")
            blurred = _np.array(
                img.filter(_ImageFilter.GaussianBlur(radius=blur_radius)),
                dtype=_np.float32) / 255.0
            return blurred

        # ── Zone 1: Forehead — warm golden-amber (R↑ G↑ B- slight) ─────────
        # Centred at top of face ellipse (y ≈ -0.55 normalised)
        fh_mask = _zone_mask(0.0, -0.55, sigma=0.38)
        fw = fh_mask * forehead_warm * opacity
        r_out = _np.clip(r_out + fw * 0.85, 0.0, 1.0)
        g_out = _np.clip(g_out + fw * 0.48, 0.0, 1.0)
        b_out = _np.clip(b_out - fw * 0.18, 0.0, 1.0)

        # ── Zone 2: Temples / eye sockets — cool blue-grey (R↓ B↑) ─────────
        # Two lobes, left and right temple
        for temple_x in (-0.72, 0.72):
            t_mask = _zone_mask(temple_x, -0.10, sigma=0.28)
            tw = t_mask * temple_cool * opacity
            r_out = _np.clip(r_out - tw * 0.35, 0.0, 1.0)
            g_out = _np.clip(g_out - tw * 0.10, 0.0, 1.0)
            b_out = _np.clip(b_out + tw * 0.42, 0.0, 1.0)

        # ── Zone 3: Nose tip — warm pink (R↑ G slight↑ B slight↑) ──────────
        # Centred slightly below face centre (y ≈ +0.28 normalised)
        n_mask = _zone_mask(0.05, 0.28, sigma=0.14)
        nw = n_mask * nose_pink * opacity
        r_out = _np.clip(r_out + nw * 0.90, 0.0, 1.0)
        g_out = _np.clip(g_out + nw * 0.30, 0.0, 1.0)
        b_out = _np.clip(b_out + nw * 0.15, 0.0, 1.0)

        # ── Zone 4: Lips / oral zone — rose (R↑ G↓ slight B slight) ────────
        # Centred at y ≈ +0.50 normalised
        l_mask = _zone_mask(0.04, 0.50, sigma=0.18)
        lw = l_mask * lip_rose * opacity
        r_out = _np.clip(r_out + lw * 0.80, 0.0, 1.0)
        g_out = _np.clip(g_out - lw * 0.12, 0.0, 1.0)
        b_out = _np.clip(b_out + lw * 0.22, 0.0, 1.0)

        # ── Zone 5: Chin / jaw plane — cool violet-grey (R↓ slight B↑) ─────
        # Centred at y ≈ +0.82 normalised
        j_mask = _zone_mask(0.0, 0.82, sigma=0.30)
        jw = j_mask * jaw_cool * opacity
        r_out = _np.clip(r_out - jw * 0.30, 0.0, 1.0)
        g_out = _np.clip(g_out - jw * 0.12, 0.0, 1.0)
        b_out = _np.clip(b_out + jw * 0.38, 0.0, 1.0)

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        active_px = int((face_mask > 0.05).sum())
        print(f"    Skin zone temperature pass complete  "
              f"(face_px={active_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # David neoclassical clarity pass — session 69 (Jacques-Louis David)
    # ─────────────────────────────────────────────────────────────────────────

    def david_neoclassical_clarity_pass(self,
                                        figure_cx:       float = 0.50,
                                        figure_top:      float = 0.02,
                                        figure_bottom:   float = 0.85,
                                        figure_rx:       float = 0.28,
                                        bg_cool_shift:   float = 0.06,
                                        contour_crisp:   float = 0.05,
                                        amber_glaze:     float = 0.04,
                                        blur_radius:     float = 6.0,
                                        opacity:         float = 0.50) -> None:
        """
        David neoclassical clarity pass — session 69.

        Jacques-Louis David (1748–1825) is the supreme master of the French
        Neoclassical school.  Where Ingres pursued sensuous surface perfection,
        David sought civic heroism — the painting as a rational argument.  His
        visual language has three defining characteristics that this pass
        reinforces:

          1.  Cool, receding stone-grey backgrounds.
              David systematically pushed his backgrounds toward neutral grey
              and near-black to maximise the contrast between the lit heroic
              figure and the architectural void behind it.  The background is
              not a landscape or atmosphere — it is a political stage flat.

          2.  Crisp classical figure contours.
              David trained as a draughtsman before he painted.  His figures
              have a precise, sculptor's edge — clear and decisive but not
              hard like an engraving.  This pass detects high-contrast edges
              in the mid-luminance region and applies a mild sharpening to
              reinforce that decisive contour.

          3.  Warm amber glaze over the flesh zone.
              Despite his cool backgrounds, David's flesh is warm and luminous.
              He applied a thin unifying amber glaze over portraits, warming
              the midtones without tinting the pale highlights.  This pass
              applies a mild warm glaze restricted to the estimated figure
              zone, reproducing that characteristic warmth.

        Algorithm
        ---------
        1. Build a figure ellipse mask (the warm foreground zone) and its
           inverse (the cool background zone) using the supplied parameters.
        2. Apply a cool grey desaturation shift to the background zone,
           pushing it toward the neutral stone-grey of David's architectural
           settings.
        3. Apply a mild unsharp-mask edge enhancement across the boundary
           between figure and background, reinforcing David's crisp contour.
        4. Apply a warm amber tint restricted to the figure zone, reproducing
           the final unifying glaze of his portrait technique.

        Parameters
        ----------
        figure_cx      : figure centre X as fraction of canvas width
        figure_top     : figure top edge as fraction of canvas height
        figure_bottom  : figure bottom edge as fraction of canvas height
        figure_rx      : figure half-width as fraction of canvas width
        bg_cool_shift  : strength of cool-grey desaturation on background
        contour_crisp  : unsharp-mask strength at figure/background boundary
        amber_glaze    : warm amber glaze strength on flesh/figure zone
        blur_radius    : Gaussian radius (px) for mask softening
        opacity        : overall blend weight
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _ImageFilter

        print(f"  David neoclassical clarity pass "
              f"(fx={figure_cx:.2f}  ft={figure_top:.2f}  fb={figure_bottom:.2f}  "
              f"frx={figure_rx:.2f}  bg_cool={bg_cool_shift:.3f}  "
              f"crisp={contour_crisp:.3f}  amber={amber_glaze:.3f}  "
              f"blur={blur_radius:.1f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    David neoclassical clarity pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r_f + 0.7152 * g_f + 0.0722 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Figure ellipse mask ───────────────────────────────────────────────
        cy_px  = int(((figure_top + figure_bottom) / 2.0) * h)
        ry_px  = max(1, int(((figure_bottom - figure_top) / 2.0) * h))
        cx_px  = int(figure_cx * w)
        rx_px  = max(1, int(figure_rx * w))

        ys = (_np.arange(h, dtype=_np.float32) - cy_px) / ry_px
        xs = (_np.arange(w, dtype=_np.float32) - cx_px) / rx_px
        yy, xx = _np.meshgrid(ys, xs, indexing="ij")

        fig_dist   = xx ** 2 + yy ** 2
        fig_mask_hard = _np.clip(1.5 - fig_dist, 0.0, 1.0)

        fig_uint8 = _np.clip(fig_mask_hard * 255, 0, 255).astype(_np.uint8)
        fig_img   = _Image.fromarray(fig_uint8, "L")
        fig_mask  = _np.array(
            fig_img.filter(_ImageFilter.GaussianBlur(radius=blur_radius)),
            dtype=_np.float32) / 255.0

        bg_mask = 1.0 - fig_mask

        # ── 1. Cool grey shift on background (R↓ G slight↓ B slight↑) ────────
        bg_w = bg_mask * bg_cool_shift * opacity
        r_out = _np.clip(r_out - bg_w * 0.60, 0.0, 1.0)
        g_out = _np.clip(g_out - bg_w * 0.30, 0.0, 1.0)
        b_out = _np.clip(b_out + bg_w * 0.10, 0.0, 1.0)

        # ── 2. Edge crispening at figure/background boundary ──────────────────
        if contour_crisp > 0.0:
            boundary_mask = 1.0 - _np.abs(fig_mask - 0.50) / 0.30
            boundary_mask = _np.clip(boundary_mask, 0.0, 1.0)
            mid_lum_mask  = 1.0 - _np.abs(lum - 0.45) / 0.30
            mid_lum_mask  = _np.clip(mid_lum_mask, 0.0, 1.0)
            combined_edge = boundary_mask * mid_lum_mask

            for ch_out, ch_f in [(r_out, r_f), (g_out, g_f), (b_out, b_f)]:
                ch_uint8 = _np.clip(ch_f * 255, 0, 255).astype(_np.uint8)
                ch_img   = _Image.fromarray(ch_uint8, "L")
                ch_blur  = _np.array(
                    ch_img.filter(_ImageFilter.GaussianBlur(radius=2.0)),
                    dtype=_np.float32) / 255.0
                detail = ch_f - ch_blur
                ch_out += detail * contour_crisp * opacity * combined_edge
                _np.clip(ch_out, 0.0, 1.0, out=ch_out)

        # ── 3. Warm amber glaze on figure zone (R↑↑ G↑ slight B-) ───────────
        mid_lum = 1.0 - _np.abs(lum - 0.50) / 0.35
        mid_lum = _np.clip(mid_lum, 0.0, 1.0)
        glaze_w  = fig_mask * mid_lum * amber_glaze * opacity
        r_out = _np.clip(r_out + glaze_w * 0.90, 0.0, 1.0)
        g_out = _np.clip(g_out + glaze_w * 0.52, 0.0, 1.0)
        b_out = _np.clip(b_out - glaze_w * 0.12, 0.0, 1.0)

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        fig_px = int((fig_mask > 0.05).sum())
        bg_px  = int((bg_mask  > 0.05).sum())
        print(f"    David neoclassical clarity pass complete  "
              f"(fig_px={fig_px}  bg_px={bg_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Ground tone recession pass — session 69 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────

    def ground_tone_recession_pass(self,
                                   horizon_y:       float = 0.55,
                                   fg_warm_lift:    float = 0.03,
                                   bg_cool_lift:    float = 0.04,
                                   transition_band: float = 0.25,
                                   opacity:         float = 0.45) -> None:
        """
        Ground tone recession pass — session 69 artistic improvement.

        Old Master painters prepared their canvases with a coloured imprimatura
        (ground tone) that was not uniform but varied in colour temperature from
        foreground to background.  This subtle pre-existing warmth gradient
        does two things simultaneously:

          Foreground warms:
              The warm ochre or raw umber of the imprimatura shows through
              thin glazes in the foreground, tying the near ground to the
              flesh tones of the figure and giving the whole composition a
              unified warmth in the immediate space around the subject.

          Background cools:
              As depth increases, painters applied progressively cooler tones
              — grey, blue-grey, neutral — over the warm ground, suppressing
              its warmth and creating a natural atmospheric recession without
              requiring explicit aerial-perspective blue hazing.  Rembrandt,
              Velázquez, and Vermeer all used this principle: the background is
              not painted over a warm ground but over a cool mid-tone.

        This pass implements that principle post-hoc by applying a smooth
        vertical gradient of colour temperature.  The foreground (below the
        horizon) receives a mild warm push; the background (above the horizon)
        receives a mild cool push.  The transition is Gaussian-blended so the
        effect is imperceptible at first glance but measurably improves the
        depth reading of the composition.

        Parameters
        ----------
        horizon_y        : Y position of the horizon as fraction of canvas height
        fg_warm_lift     : strength of the warm (amber) push in the foreground
        bg_cool_lift     : strength of the cool (blue-grey) push in the background
        transition_band  : half-width of the transition zone in Y (fraction of h)
        opacity          : overall blend weight
        """
        import numpy as _np

        print(f"  Ground tone recession pass "
              f"(horizon_y={horizon_y:.2f}  fg_warm={fg_warm_lift:.3f}  "
              f"bg_cool={bg_cool_lift:.3f}  band={transition_band:.2f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Ground tone recession pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── Vertical gradient masks ───────────────────────────────────────────
        hz_px    = int(horizon_y * h)
        sigma_px = max(1.0, transition_band * h)

        ys = _np.arange(h, dtype=_np.float32)

        fg_mask = 1.0 / (1.0 + _np.exp(-(ys - hz_px) / (sigma_px * 0.5)))
        fg_mask = fg_mask[:, _np.newaxis]  # broadcast across width

        bg_mask = 1.0 - fg_mask

        # ── Foreground: warm amber lift (R↑ G slight↑ B slight↓) ─────────────
        fw = fg_mask * fg_warm_lift * opacity
        r_out = _np.clip(r_out + fw * 0.80, 0.0, 1.0)
        g_out = _np.clip(g_out + fw * 0.42, 0.0, 1.0)
        b_out = _np.clip(b_out - fw * 0.15, 0.0, 1.0)

        # ── Background: cool grey-blue lift (R slight↓ G slight↓ B↑) ─────────
        bw = bg_mask * bg_cool_lift * opacity
        r_out = _np.clip(r_out - bw * 0.35, 0.0, 1.0)
        g_out = _np.clip(g_out - bw * 0.18, 0.0, 1.0)
        b_out = _np.clip(b_out + bw * 0.30, 0.0, 1.0)

        # ── Write back (BGRA) ─────────────────────────────────────────────────
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        fg_px = int((fg_mask > 0.10).sum())
        bg_px = int((bg_mask > 0.10).sum())
        print(f"    Ground tone recession pass complete  "
              f"(fg_px={fg_px}  bg_px={bg_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Guido Reni angelic grace pass — session 70 artist pass
    # ─────────────────────────────────────────────────────────────────────────

    def guido_reni_angelic_grace_pass(self,
                                      face_cx:         float = 0.50,
                                      face_cy:         float = 0.35,
                                      face_rx:         float = 0.20,
                                      face_ry:         float = 0.25,
                                      pearl_lift:      float = 0.08,
                                      pearl_cool:      float = 0.04,
                                      cheek_rose:      float = 0.05,
                                      lip_rose:        float = 0.06,
                                      shadow_violet:   float = 0.05,
                                      blur_radius:     float = 8.0,
                                      opacity:         float = 0.50) -> None:
        """
        Guido Reni angelic grace pass — session 70 artist inspiration.

        Reni's hallmark is an otherworldly skin luminosity built from three
        simultaneous operations:

          1. Alabaster pearl lift on highlights
             Reni's lit skin is not simply warm ivory — it has a faint cool
             luminosity at the specular peak, as if the skin itself were
             translucent alabaster lit from within.  This operation lifts pixels
             above the highlight threshold toward a cool pearl-white
             (R↑ slight, G↑ slight, B↑ more) creating that characteristic
             pale iridescence.

          2. Rose injection into cheek and lip zones
             Where Leonardo's midtones are neutral warm ochre, Reni's are
             distinctly rose — warm pink that reads as both lifelike warmth and
             ideal beauty simultaneously.  This operation adds a localised rose
             push (R↑ slight B↑ very slight) in the anatomical cheek and lip
             zones of the face ellipse.

          3. Violet-grey shadow cooling
             Reni's shadows are not umber-black but a distinctive cool
             violet-grey that gives even the darkest passages a spiritual
             weightlessness.  This operation cools the shadow region
             (lum < shadow_thresh) by pushing B↑ and R↓ slightly toward
             the lavender-grey of his deepest passages.

        Parameters
        ----------
        face_cx/cy    : face ellipse centre as fraction of canvas width/height
        face_rx/ry    : face ellipse radii as fraction of canvas width/height
        pearl_lift    : strength of the highlight pearl-white lift
        pearl_cool    : blue component of the pearl cooling
        cheek_rose    : rose injection strength in the cheek zone
        lip_rose      : rose injection strength in the lip zone
        shadow_violet : violet-grey cooling strength in the shadow zone
        blur_radius   : Gaussian softening radius for all zone masks
        opacity       : overall blend weight for the pass
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Guido Reni angelic grace pass "
              f"(pearl_lift={pearl_lift:.3f}  cheek_rose={cheek_rose:.3f}  "
              f"shadow_violet={shadow_violet:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Guido Reni angelic grace pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── Build face ellipse mask ───────────────────────────────────────────
        cx_px = int(face_cx * w)
        cy_px = int(face_cy * h)
        rx_px = max(1, int(face_rx * w))
        ry_px = max(1, int(face_ry * h))

        ys, xs = _np.mgrid[0:h, 0:w]
        face_d = ((xs - cx_px) / rx_px) ** 2 + ((ys - cy_px) / ry_px) ** 2
        face_mask = _np.clip(1.0 - face_d, 0.0, 1.0)
        face_mask = _gf(face_mask.astype(_np.float32), sigma=blur_radius)
        face_mask = _np.clip(face_mask, 0.0, 1.0)

        # ── 1. Alabaster pearl lift on highlights ────────────────────────────
        hl_thresh = 0.70
        hl_mask   = _np.clip((lum - hl_thresh) / (1.0 - hl_thresh), 0.0, 1.0)
        hl_mask   = _gf(hl_mask.astype(_np.float32), sigma=max(1.0, blur_radius * 0.5))
        hl_zone   = face_mask * hl_mask

        r_out = _np.clip(r_out + hl_zone * pearl_lift * 0.55, 0.0, 1.0)
        g_out = _np.clip(g_out + hl_zone * pearl_lift * 0.65, 0.0, 1.0)
        b_out = _np.clip(b_out + hl_zone * (pearl_lift * 0.55 + pearl_cool), 0.0, 1.0)

        # ── 2. Rose injection — cheek zone (upper lateral face) ───────────────
        # Cheek centre: lateral from face centre, upper-mid height
        cheek_offset_x = rx_px * 0.42
        cheek_offset_y = ry_px * 0.12

        for side in (-1.0, 1.0):
            cck_x = cx_px + side * cheek_offset_x
            cck_y = cy_px + cheek_offset_y
            cck_d = ((xs - cck_x) / (rx_px * 0.55)) ** 2 + \
                    ((ys - cck_y) / (ry_px * 0.38)) ** 2
            cck_mask = _np.clip(1.0 - cck_d, 0.0, 1.0)
            cck_mask = _gf(cck_mask.astype(_np.float32), sigma=blur_radius * 1.2)
            cck_zone = face_mask * _np.clip(cck_mask, 0.0, 1.0)

            r_out = _np.clip(r_out + cck_zone * cheek_rose * 0.80, 0.0, 1.0)
            b_out = _np.clip(b_out + cck_zone * cheek_rose * 0.12, 0.0, 1.0)

        # ── 3. Rose injection — lip zone (lower face) ─────────────────────────
        lip_y = cy_px + ry_px * 0.48
        lip_d = ((xs - cx_px) / (rx_px * 0.38)) ** 2 + \
                ((ys - lip_y) / (ry_px * 0.15)) ** 2
        lip_mask = _np.clip(1.0 - lip_d, 0.0, 1.0)
        lip_mask = _gf(lip_mask.astype(_np.float32), sigma=max(1.0, blur_radius * 0.8))
        lip_zone = face_mask * _np.clip(lip_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + lip_zone * lip_rose * 0.85, 0.0, 1.0)
        b_out = _np.clip(b_out + lip_zone * lip_rose * 0.18, 0.0, 1.0)

        # ── 4. Violet-grey shadow cooling ────────────────────────────────────
        sh_thresh = 0.38
        sh_mask   = _np.clip((sh_thresh - lum) / sh_thresh, 0.0, 1.0)
        sh_mask   = _gf(sh_mask.astype(_np.float32), sigma=max(1.0, blur_radius * 0.6))

        r_out = _np.clip(r_out - sh_mask * shadow_violet * 0.40, 0.0, 1.0)
        b_out = _np.clip(b_out + sh_mask * shadow_violet * 0.65, 0.0, 1.0)

        # ── Blend with original ───────────────────────────────────────────────
        r_out = r_f * (1.0 - opacity) + r_out * opacity
        g_out = g_f * (1.0 - opacity) + g_out * opacity
        b_out = b_f * (1.0 - opacity) + b_out * opacity

        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        hl_px = int((hl_zone > 0.05).sum())
        sh_px = int((sh_mask > 0.05).sum())
        print(f"    Guido Reni angelic grace pass complete  "
              f"(hl_px={hl_px}  sh_px={sh_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Highlight bloom pass — session 70 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────

    def highlight_bloom_pass(self,
                             threshold:      float = 0.75,
                             bloom_sigma:    float = 12.0,
                             bloom_opacity:  float = 0.30,
                             bloom_color:    "Optional[tuple]" = None,
                             multi_scale:    bool  = True,
                             figure_only:    bool  = False,
                             chromatic_bloom: bool = False) -> None:
        """
        Highlight bloom pass — session 70 artistic improvement.
        Session 83 improvement: chromatic_bloom parameter.

        Inspired by Guido Reni's radiant, light-emitting skin quality.  In
        Reni's paintings the brightest passages — the alabaster brow, the
        cheekbone specular, the pearl highlight on the nose — appear to glow
        softly outward, as if light is scattering at the surface of translucent
        skin.  This is a physically real phenomenon (subsurface scattering
        causes bright highlights to have a soft luminous halo) that Reni
        enhanced through thin, repeated glazes.

        This pass simulates that quality in two or three Gaussian operations:

          1. Inner bloom  (always active)
             Extract pixels above threshold.  Apply a Gaussian at bloom_sigma
             to create a soft, concentrated glow around the brightest areas.

          2. Outer halo  (when multi_scale=True, the default)
             Apply a second, wider Gaussian (bloom_sigma * 2.5) to the same
             highlight mask to create a broader, more diffuse luminous envelope.
             This captures the wider scattering envelope that gives Reni's skin
             its lit-from-within quality.

          3. Colour tint  (when bloom_color is provided)
             Blend the bloom region toward the specified RGB tint rather than
             toward neutral white — useful for warm candlelight bloom or cool
             moonlit glow.

          4. Chromatic bloom  (when chromatic_bloom=True — session 83 improvement)
             Applies spectrally split bloom based on how light physically scatters
             through oil paint binders and old varnish layers.  In aged oil
             paintings, highlights do not bloom as neutral white: the warm inner
             core of a highlight reflects the paint layer's warm pigment base,
             while the broader outer halo takes on a slightly cooler, bluer cast
             from light scattering through the transparent oil/varnish medium.
             This creates the subtle spectral fringe visible in old master
             paintings — warm centre, slightly cool edge — that reads as depth
             and age rather than flatness.

             Implementation: the inner bloom is tinted warm (R+0.04, G+0.01,
             B-0.02 relative to the base bloom_color) while the outer halo
             (multi_scale) is tinted slightly cool (R-0.01, B+0.03).  The net
             effect at typical bloom_opacity values is a barely perceptible
             spectral spread that adds the quality of old varnished oil painting
             without being identifiable as a specific colour effect.

        Parameters
        ----------
        threshold      : luminance cutoff above which bloom is applied (0–1)
        bloom_sigma    : Gaussian sigma for the inner bloom (pixels)
        bloom_opacity  : opacity of the bloom composite (0 = no change)
        bloom_color    : optional (R, G, B) tint for the bloom; None = neutral
        multi_scale    : if True, add a second wider Gaussian halo envelope
        figure_only    : if True, restrict bloom to the figure mask region
                         (uses self._figure_mask if set, otherwise skips silently)
        chromatic_bloom: if True (session 83), apply spectrally split bloom —
                         warm inner core, slightly cool outer halo — simulating
                         the spectral scattering of light through aged oil binders.
                         Historically grounded in the optical behaviour of old
                         master varnish layers under raking and diffuse light.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Highlight bloom pass "
              f"(thresh={threshold:.2f}  sigma={bloom_sigma:.1f}  "
              f"opacity={bloom_opacity:.2f}  multi_scale={multi_scale}  "
              f"figure_only={figure_only}  chromatic_bloom={chromatic_bloom}) ...")

        if bloom_opacity <= 0.0:
            print("    Highlight bloom pass skipped (bloom_opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── Build figure mask (if figure_only) ────────────────────────────────
        fig_mask = _np.ones((h, w), dtype=_np.float32)
        if figure_only:
            fm = getattr(self, "_figure_mask", None)
            if fm is not None:
                fig_mask = _np.clip(fm.astype(_np.float32), 0.0, 1.0)
                if fig_mask.shape != (h, w):
                    fig_mask = _np.ones((h, w), dtype=_np.float32)

        # ── Extract highlight mask ────────────────────────────────────────────
        hl_range = max(0.01, 1.0 - threshold)
        hl_mask  = _np.clip((lum - threshold) / hl_range, 0.0, 1.0) * fig_mask

        # ── Determine bloom colour target ──────────────────────────────────────
        if bloom_color is not None:
            bc_r, bc_g, bc_b = float(bloom_color[0]), float(bloom_color[1]), float(bloom_color[2])
        else:
            bc_r = bc_g = bc_b = 1.0   # neutral white bloom

        # Session 83: chromatic bloom — spectrally split inner/outer targets
        # Inner core: warm (paint layer reflection); outer halo: slightly cool
        # (oil/varnish medium scattering).  Offsets are small by design.
        if chromatic_bloom:
            inner_r = _np.clip(bc_r + 0.04, 0.0, 1.0)
            inner_g = _np.clip(bc_g + 0.010, 0.0, 1.0)
            inner_b = _np.clip(bc_b - 0.020, 0.0, 1.0)
            outer_r = _np.clip(bc_r - 0.010, 0.0, 1.0)
            outer_g = bc_g
            outer_b = _np.clip(bc_b + 0.030, 0.0, 1.0)
        else:
            inner_r, inner_g, inner_b = bc_r, bc_g, bc_b
            outer_r, outer_g, outer_b = bc_r, bc_g, bc_b

        # ── Inner bloom — primary Gaussian ────────────────────────────────────
        inner_bloom = _gf(hl_mask.astype(_np.float32), sigma=bloom_sigma)
        inner_bloom = _np.clip(inner_bloom, 0.0, 1.0)

        alpha = inner_bloom * bloom_opacity
        r_out = r_out + alpha * (inner_r - r_out)
        g_out = g_out + alpha * (inner_g - g_out)
        b_out = b_out + alpha * (inner_b - b_out)

        # ── Outer halo — wider Gaussian (multi_scale only) ────────────────────
        if multi_scale:
            outer_halo = _gf(hl_mask.astype(_np.float32),
                             sigma=bloom_sigma * 2.5)
            outer_halo = _np.clip(outer_halo, 0.0, 1.0)
            alpha2 = outer_halo * bloom_opacity * 0.35
            r_out = r_out + alpha2 * (outer_r - r_out)
            g_out = g_out + alpha2 * (outer_g - g_out)
            b_out = b_out + alpha2 * (outer_b - b_out)

        r_out = _np.clip(r_out, 0.0, 1.0)
        g_out = _np.clip(g_out, 0.0, 1.0)
        b_out = _np.clip(b_out, 0.0, 1.0)

        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()

        bloom_px = int((inner_bloom > 0.05).sum())
        print(f"    Highlight bloom pass complete  (bloom_px={bloom_px})")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 71 — Correggio golden tenderness pass
    # ─────────────────────────────────────────────────────────────────────────

    def correggio_golden_tenderness_pass(self,
                                         midtone_low:     float = 0.30,
                                         midtone_high:    float = 0.78,
                                         gold_lift:       float = 0.06,
                                         amber_shadow:    float = 0.05,
                                         face_cx:         float = 0.515,
                                         face_cy:         float = 0.210,
                                         face_rx:         float = 0.140,
                                         face_ry:         float = 0.190,
                                         glow_strength:   float = 0.05,
                                         blur_radius:     float = 10.0,
                                         opacity:         float = 0.46) -> None:
        """
        Correggio golden tenderness pass — session 71 artist inspiration.

        Antonio Allegri da Correggio (1489–1534) developed the warmest, most
        honeyed rendering of human flesh in the entire Italian Renaissance.
        Unlike Leonardo's cool sfumato or Raphael's clear idealisation, Correggio
        suffuses every passage — highlights, midtones, and shadows alike — with
        a warm amber-gold luminosity that makes his figures appear to glow from
        within.  His shadows are amber-brown, never grey-violet; his highlights
        are warm ivory rather than cool pearl.  This creates the 'Correggesque'
        quality: a tenderness of light that anticipates the entire Flemish
        Baroque tradition.

        This pass applies three operations:

          1. Golden midtone lift — nudges the midtone band (midtone_low to
             midtone_high) toward a warm amber-gold by boosting red, slightly
             boosting green, and gently damping blue.  This warms the skin
             without making it look sunburned.

          2. Warm shadow resistance — in the shadow zones (below midtone_low),
             adds a subtle amber warmth that prevents shadows from reading as
             cool or grey.  Correggio's shadows are always warm — this is the
             most distinctive Correggesque signature.

          3. Face glow — applies a radial warm glow centred on the face ellipse,
             simulating the concentration of warm light on the primary subject
             that appears in Jupiter and Io and The Holy Night.

        Parameters
        ----------
        midtone_low    : luminance threshold below which shadow warm-resistance applies
        midtone_high   : luminance threshold above which highlights are excluded
        gold_lift      : strength of the amber-gold midtone boost (0–0.15)
        amber_shadow   : warmth added to shadow zones (0–0.10)
        face_cx        : face centre X as fraction of canvas width
        face_cy        : face centre Y as fraction of canvas height
        face_rx        : face ellipse half-width X as fraction of canvas width
        face_ry        : face ellipse half-height Y as fraction of canvas height
        glow_strength  : opacity of the radial warm face glow (0–0.15)
        blur_radius    : Gaussian blur radius for the glow mask
        opacity        : overall pass opacity blended against the input (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Correggio golden tenderness pass "
              f"(gold_lift={gold_lift:.3f}  amber_shadow={amber_shadow:.3f}  "
              f"glow={glow_strength:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Correggio pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 1. Golden midtone lift ─────────────────────────────────────────────
        # Weight is 1.0 in the midtone band, fading to 0 at boundaries.
        mt_range = max(0.01, midtone_high - midtone_low)
        mt_weight = _np.clip((lum - midtone_low) / (mt_range * 0.4), 0.0, 1.0)
        mt_weight *= _np.clip((midtone_high - lum) / (mt_range * 0.4), 0.0, 1.0)

        # Gold = boost R, slight G, damp B
        r_out = _np.clip(r_out + mt_weight * gold_lift * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + mt_weight * gold_lift * 0.35, 0.0, 1.0)
        b_out = _np.clip(b_out - mt_weight * gold_lift * 0.40, 0.0, 1.0)

        # ── 2. Warm shadow resistance ──────────────────────────────────────────
        # Shadow zones (lum < midtone_low): add amber warmth, resist cool lean.
        sh_weight = _np.clip((midtone_low - lum) / max(0.01, midtone_low), 0.0, 1.0)
        r_out = _np.clip(r_out + sh_weight * amber_shadow * 0.80, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_weight * amber_shadow * 0.30, 0.0, 1.0)
        b_out = _np.clip(b_out - sh_weight * amber_shadow * 0.20, 0.0, 1.0)

        # ── 3. Radial warm face glow ───────────────────────────────────────────
        # Build a soft Gaussian-blurred elliptical mask centred on the face.
        ys = _np.arange(h, dtype=_np.float32) / h
        xs = _np.arange(w, dtype=_np.float32) / w
        xx, yy = _np.meshgrid(xs, ys)
        dx_face = (xx - face_cx) / max(0.001, face_rx * 1.5)
        dy_face = (yy - face_cy) / max(0.001, face_ry * 1.5)
        face_dist = dx_face * dx_face + dy_face * dy_face
        face_mask = _np.clip(1.0 - face_dist, 0.0, 1.0).astype(_np.float32)
        face_mask = _gf(face_mask, sigma=blur_radius)
        face_mask = _np.clip(face_mask / max(1e-6, face_mask.max()), 0.0, 1.0)

        gw = face_mask * glow_strength
        r_out = _np.clip(r_out + gw * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + gw * 0.60, 0.0, 1.0)
        b_out = _np.clip(b_out + gw * 0.10, 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        r_final = r_f * (1.0 - opacity) + r_out * opacity
        g_final = g_f * (1.0 - opacity) + g_out * opacity
        b_final = b_f * (1.0 - opacity) + b_out * opacity

        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Correggio golden tenderness pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 71 — Luminous haze pass (artistic improvement)
    # ─────────────────────────────────────────────────────────────────────────

    def luminous_haze_pass(self,
                           haze_warmth:         float = 0.04,
                           haze_opacity:        float = 0.12,
                           haze_color:          "Optional[tuple]" = None,
                           soften_radius:       float = 3.0,
                           contrast_damp:       float = 0.06,
                           shadow_lift:         float = 0.018,
                           spectral_dispersion: float = 0.0,
                           opacity:             float = 0.48) -> None:
        """
        Luminous haze pass — session 71 artistic improvement.
        Session 88 improvement: spectral_dispersion parameter.

        Inspired by Correggio's extraordinary ability to suffuse an entire
        composition with a warm, unifying atmospheric light — a quality that
        distinguishes his work from every other Renaissance painter.  In physical
        terms this arises from two sources:

          1. Aged golden varnish: old master oil paintings are coated with natural
             resin varnishes (mastic, damar) that yellow and warm over centuries.
             This gives the entire painting a subtle amber-honey tone that unifies
             disparate passages into a single coherent palette.

          2. Atmospheric diffusion: interior scenes lit by candle or diffused
             window light have a soft, low-contrast quality — the darkest shadows
             are lifted by ambient scatter, and the highlights are softened by the
             same diffusion.  The overall effect is a gentle compression of the
             tonal scale toward the midtone.

        This pass simulates both effects:

          1. Warm haze overlay — blends a soft, warm haze color (default: amber-
             honey) over the image at low opacity.  This is the varnish effect:
             everything shifted fractionally toward amber without losing colour.

          2. Shadow lift — gently raises the luminance floor of the darkest areas
             by a fixed amount, simulating ambient scatter that prevents deep
             blacks from appearing truly dead.

          3. Contrast damping — reduces the overall luminance range by pulling
             values fractionally toward the midpoint, creating the softer, more
             unified tonal scale of an interior lit by diffused warm light.

          4. Softening — applies a very gentle Gaussian blur before compositing
             to simulate the slight optical softening that occurs when light
             scatters through old varnish and aged glazes.

          5. Spectral dispersion (session 88 improvement) — when
             spectral_dispersion > 0, the three colour channels are blurred with
             different Gaussian sigmas before compositing, modelling Rayleigh
             scattering in the atmospheric haze layer.  Blue light scatters more
             strongly than red light in the real atmosphere (λ⁻⁴ dependence), so
             the blue channel receives a larger softening blur than the green or
             red channels.  The relative sigmas scale as:

               sigma_r = soften_radius × 1.00  (red — least scatter)
               sigma_g = soften_radius × (1.00 + spectral_dispersion × 0.30)
               sigma_b = soften_radius × (1.00 + spectral_dispersion × 0.65)

             This creates a subtle cool-blue halo at the horizon of the
             atmospheric haze while warm reds remain more sharply concentrated
             in the figure zone — the same warm-foreground / cool-distance
             temperature split that Leonardo exploited in his sfumato landscapes
             and that atmospheric science confirms is physically real.  At
             spectral_dispersion=0 the behaviour is identical to the pre-s88
             single-sigma formulation.

        Parameters
        ----------
        haze_warmth          : amber-shift added uniformly across all tones (0–0.10)
        haze_opacity         : opacity of the warm haze color overlay (0–0.25)
        haze_color           : (R, G, B) of the haze; None defaults to warm honey amber
        soften_radius        : Gaussian sigma for the pre-composite softening blur
        contrast_damp        : amount to compress tonal range toward midpoint (0–0.15)
        shadow_lift          : luminance floor lift for the darkest areas (0–0.05)
        spectral_dispersion  : Rayleigh channel-split strength; 0 = no split (0–1)
        opacity              : overall pass opacity blended against the input (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Luminous haze pass "
              f"(haze_warmth={haze_warmth:.3f}  haze_opacity={haze_opacity:.2f}  "
              f"contrast_damp={contrast_damp:.3f}  shadow_lift={shadow_lift:.3f}  "
              f"spectral_dispersion={spectral_dispersion:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Luminous haze pass skipped (opacity=0)")
            return

        # Default haze colour: warm honey amber — aged varnish tone
        if haze_color is None:
            haze_color = (0.86, 0.74, 0.48)

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Optional softening blur (with spectral dispersion) ────────────────
        # Session 88: when spectral_dispersion > 0 each channel is blurred with
        # a different sigma (Rayleigh: blue scatters more than red).
        if soften_radius > 0.5:
            sigma_r = soften_radius * 1.00
            sigma_g = soften_radius * (1.00 + spectral_dispersion * 0.30)
            sigma_b = soften_radius * (1.00 + spectral_dispersion * 0.65)
            r_soft = _gf(r_f, sigma=sigma_r)
            g_soft = _gf(g_f, sigma=sigma_g)
            b_soft = _gf(b_f, sigma=sigma_b)
        else:
            r_soft, g_soft, b_soft = r_f.copy(), g_f.copy(), b_f.copy()

        # ── Contrast damp — pull all values fractionally toward 0.5 ───────────
        r_out = r_soft + (0.5 - r_soft) * contrast_damp
        g_out = g_soft + (0.5 - g_soft) * contrast_damp
        b_out = b_soft + (0.5 - b_soft) * contrast_damp

        # ── Shadow lift — raise luminance floor of darkest areas ──────────────
        lum = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
        dark_weight = _np.clip(1.0 - lum / max(0.01, shadow_lift * 8.0), 0.0, 1.0)
        r_out = _np.clip(r_out + dark_weight * shadow_lift, 0.0, 1.0)
        g_out = _np.clip(g_out + dark_weight * shadow_lift * 0.75, 0.0, 1.0)
        b_out = _np.clip(b_out + dark_weight * shadow_lift * 0.50, 0.0, 1.0)

        # ── Uniform amber-warmth shift ─────────────────────────────────────────
        r_out = _np.clip(r_out + haze_warmth * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + haze_warmth * 0.50, 0.0, 1.0)
        b_out = _np.clip(b_out - haze_warmth * 0.30, 0.0, 1.0)

        # ── Warm haze color overlay ────────────────────────────────────────────
        hc_r, hc_g, hc_b = float(haze_color[0]), float(haze_color[1]), float(haze_color[2])
        r_out = _np.clip(r_out + haze_opacity * (hc_r - r_out), 0.0, 1.0)
        g_out = _np.clip(g_out + haze_opacity * (hc_g - g_out), 0.0, 1.0)
        b_out = _np.clip(b_out + haze_opacity * (hc_b - b_out), 0.0, 1.0)

        # ── Composite at opacity against original ─────────────────────────────
        r_final = r_f * (1.0 - opacity) + r_out * opacity
        g_final = g_f * (1.0 - opacity) + g_out * opacity
        b_final = b_f * (1.0 - opacity) + b_out * opacity

        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Luminous haze pass complete.")

    def watteau_crepuscular_reverie_pass(self,
                                         amber_shift:       float = 0.04,
                                         shadow_lift:       float = 0.022,
                                         edge_soften:       float = 4.0,
                                         crepuscular_low:   float = 0.30,
                                         crepuscular_high:  float = 0.70,
                                         periphery_darken:  float = 0.06,
                                         opacity:           float = 0.46) -> None:
        """
        Watteau crepuscular reverie pass — session 72 artistic improvement.

        Inspired by Jean-Antoine Watteau (1684–1721), the founder of the fête
        galante and one of the most poetic painters in Western art.  Watteau's
        defining atmospheric quality is crepuscular: every scene exists in a
        warm, golden twilight — beautiful, fleeting, already fading.  His warm
        golden-sienna imprimatura glows through thin paint films; shadows never
        cool toward blue because the warm ground always shows through; even his
        most festive outdoor scenes carry an autumnal amber melancholy.

        This pass encodes three elements of his atmospheric character:

          1. Amber-shift: a warm amber-gold bias applied across all tones,
             stronger in the midtones than in the deep shadows (which the warm
             ground already warms) and lighter than in the highlights (which
             remain ivory rather than golden).  This simulates the effect of
             Watteau's warm imprimatura glowing uniformly through the paint film.

          2. Shadow lift with warm bias: gently lifts the darkest shadows with
             a warm amber-brown tone (R > G >> B).  This encodes the optical
             fact that Watteau's shadows are always warmed by the ground showing
             through — they never become cold or neutral, but retain a golden
             residual warmth even at their deepest.

          3. Edge dissolution in the midtone band: the midtone range (luminance
             between crepuscular_low and crepuscular_high) is gently blurred,
             simulating Watteau's characteristic melting of edges in the ambient
             zones of his compositions — particularly the foliage and background
             drapery, which dissolve into the overall golden haze.  The near-
             shadow and highlight extremes are preserved more sharply.

          4. Peripheral amber vignette: a very gentle darkening toward the
             canvas edges that concentrates warmth in the central figure zone —
             the compositional equivalent of Watteau's practice of placing his
             figures in an oval of warm light surrounded by deeper, more golden
             shadow at the margins.

        The result is a surface with the characteristic Watteau twilight quality:
        warm, autumnal, gently melancholic — as if the scene is observed at the
        precise moment when afternoon begins to surrender to evening.

        Parameters
        ----------
        amber_shift      : warm amber-gold bias added uniformly to all tones (0–0.08)
        shadow_lift      : warm lift applied to the darkest shadow zones (0–0.05)
        edge_soften      : Gaussian sigma for the midtone edge dissolution blur (1–8)
        crepuscular_low  : lower luminance boundary of the midtone softening band (0.2–0.5)
        crepuscular_high : upper luminance boundary of the midtone softening band (0.5–0.85)
        periphery_darken : strength of the gentle amber peripheral vignette (0–0.12)
        opacity          : overall pass opacity blended against the input (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Watteau crepuscular reverie pass "
              f"(amber_shift={amber_shift:.3f}  shadow_lift={shadow_lift:.3f}  "
              f"edge_soften={edge_soften:.1f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Watteau crepuscular reverie pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f

        # ── 1. Amber-shift — warm the whole image toward golden-amber ─────────
        r_out = _np.clip(r_f + amber_shift * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_f + amber_shift * 0.55, 0.0, 1.0)
        b_out = _np.clip(b_f - amber_shift * 0.35, 0.0, 1.0)

        # ── 2. Shadow lift — warm amber lift in the darkest zones ─────────────
        dark_w = _np.clip(1.0 - lum / max(0.001, shadow_lift * 7.0), 0.0, 1.0)
        r_out = _np.clip(r_out + dark_w * shadow_lift * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + dark_w * shadow_lift * 0.60, 0.0, 1.0)
        b_out = _np.clip(b_out + dark_w * shadow_lift * 0.10, 0.0, 1.0)

        # ── 3. Midtone edge dissolution — the Watteau crepuscular softening ───
        if edge_soften > 0.5:
            # Build midtone weight mask
            mid_lo = _np.clip((lum - crepuscular_low) /
                              max(0.001, crepuscular_high - crepuscular_low), 0.0, 1.0)
            mid_hi = _np.clip((crepuscular_high - lum) /
                              max(0.001, crepuscular_high - crepuscular_low), 0.0, 1.0)
            mid_mask = (mid_lo * mid_hi) ** 0.5   # peaks at centre of band

            r_blur = _gf(r_out, sigma=edge_soften)
            g_blur = _gf(g_out, sigma=edge_soften)
            b_blur = _gf(b_out, sigma=edge_soften)

            r_out = r_out + mid_mask * (r_blur - r_out) * 0.60
            g_out = g_out + mid_mask * (g_blur - g_out) * 0.60
            b_out = b_out + mid_mask * (b_blur - b_out) * 0.60

        # ── 4. Peripheral amber vignette ──────────────────────────────────────
        if periphery_darken > 0.0:
            ys = (_np.arange(h, dtype=_np.float32) / (h - 1) - 0.5) * 2.0
            xs = (_np.arange(w, dtype=_np.float32) / (w - 1) - 0.5) * 2.0
            xx, yy = _np.meshgrid(xs, ys)
            dist = _np.sqrt(xx ** 2 + yy ** 2)
            # Smooth radial falloff — dark at corners, clear at centre
            vignette = _np.clip(dist / 1.414, 0.0, 1.0) ** 1.5 * periphery_darken
            # Apply as warm darkening (reduce green and blue slightly more than red
            # — matches Watteau's warm peripheral shadow)
            r_out = _np.clip(r_out - vignette * 0.70, 0.0, 1.0)
            g_out = _np.clip(g_out - vignette * 0.90, 0.0, 1.0)
            b_out = _np.clip(b_out - vignette * 1.10, 0.0, 1.0)

        # ── Composite at opacity against original ─────────────────────────────
        r_final = r_f * (1.0 - opacity) + r_out * opacity
        g_final = g_f * (1.0 - opacity) + g_out * opacity
        b_final = b_f * (1.0 - opacity) + b_out * opacity

        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Watteau crepuscular reverie pass complete.")

    def anguissola_intimacy_pass(self,
                                  focus_cx:       float = 0.50,
                                  focus_cy:       float = 0.30,
                                  focus_radius:   float = 0.14,
                                  sharpen_strength: float = 0.55,
                                  eye_cx_offset:  float = 0.06,
                                  eye_cy_offset:  float = 0.00,
                                  eye_radius:     float = 0.07,
                                  lip_cy_offset:  float = 0.09,
                                  lip_rx:         float = 0.06,
                                  lip_ry:         float = 0.032,
                                  periphery_soften: float = 1.8,
                                  warm_ambient:   float = 0.025,
                                  opacity:        float = 0.70) -> None:
        """
        Anguissola intimacy pass — session 73 artistic improvement.

        Inspired by Sofonisba Anguissola (c. 1535–1625), the first woman to
        achieve international recognition as a major portrait painter.  Her
        defining technical achievement — identified by Anthony van Dyck, who
        visited her in Palermo in 1624 when she was nearly ninety — was the
        'breathing' quality of her portraits: a specific psychological presence
        that makes sitters appear individually alive rather than generically
        idealised.

        The source of this quality is a deliberate focus hierarchy: the eyes
        and lips — the emotional centres of any portrait — are rendered with
        maximum sharpness and specificity, while the surrounding flesh, hair,
        and drapery soften into the warm Lombard ambient light.  This creates
        the visual equivalent of what the eyes do naturally when they focus on
        a face: the gaze locks on the eyes, and peripheral form dissolves.

        This pass encodes three elements of Anguissola's intimacy technique:

          1. Psychological focus sharpening: the eye zones (two small ellipses
             flanking the face centre) and lip zone (a small horizontal ellipse
             below the face centre) are sharpened via unsharp mask.  The
             sharpening is moderate — enough to give specificity without the
             mechanical hardness of Flemish enamel technique.  This encodes
             the Lombard observation that the face is seen in detail at its
             emotional centres and softer everywhere else.

          2. Peripheral flesh softening: the zones outside the focal circle
             are gently blurred, simulating the warm Lombard ambient light
             that wraps around the figure and softens all boundaries except
             those the eye concentrates on.  Unlike Leonardo's uniform sfumato,
             Anguissola's softening is selective — it does not dissolve the
             eyes and mouth, which remain present and direct.

          3. Warm Lombard ambient drift: a subtle global warm bias is applied
             — less than Watteau's amber shift, more golden than Leonardo's
             cool sfumato — that represents the warm afternoon Lombard light
             that characterises her studio conditions.  This drift lifts the
             overall tonality toward the golden warmth that makes her flesh
             tones appear to glow from within.

        The result is a surface with the characteristic Anguissola portrait
        quality: psychologically present eyes and lips embedded in warm,
        softly luminous flesh — as if the sitter has just turned to meet
        the viewer's gaze.

        Parameters
        ----------
        focus_cx        : normalised x-centre of the face ellipse [0, 1]
        focus_cy        : normalised y-centre of the face ellipse [0, 1]
        focus_radius    : radius of the sharpening focus zone (normalised)
        sharpen_strength: unsharp mask strength for eye/lip sharpening (0–1)
        eye_cx_offset   : horizontal offset from face centre to each eye (normalised)
        eye_cy_offset   : vertical offset from face centre to each eye (normalised)
        eye_radius      : radius of each eye sharpening zone (normalised)
        lip_cy_offset   : vertical offset downward from face centre to lip zone (normalised)
        lip_rx          : horizontal radius of lip sharpening zone (normalised)
        lip_ry          : vertical radius of lip sharpening zone (normalised)
        periphery_soften: Gaussian sigma for peripheral softening outside focus zone (pixels)
        warm_ambient    : warm Lombard ambient drift — R/G/B channel bias (0–0.05)
        opacity         : overall pass opacity blended against input (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Anguissola intimacy pass "
              f"(focus=({focus_cx:.2f},{focus_cy:.2f})  r={focus_radius:.2f}  "
              f"sharpen={sharpen_strength:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Anguissola intimacy pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Build coordinate grids ────────────────────────────────────────────
        xs = _np.linspace(0.0, 1.0, w, dtype=_np.float32)[None, :]   # (1, W)
        ys = _np.linspace(0.0, 1.0, h, dtype=_np.float32)[:, None]   # (H, 1)

        # ── 1. Eye zone masks (two ellipses flanking face centre) ─────────────
        def _ellipse_weight(cx, cy, rx, ry, power=2.5):
            """Soft elliptical mask, peak=1 at centre, 0 at boundary."""
            dx = (xs - cx) / max(rx, 1e-6)
            dy = (ys - cy) / max(ry, 1e-6)
            d2 = dx ** 2 + dy ** 2
            return _np.clip(1.0 - d2 ** (power / 2.0), 0.0, 1.0)

        # Left eye
        left_eye  = _ellipse_weight(focus_cx - eye_cx_offset,
                                    focus_cy + eye_cy_offset,
                                    eye_radius, eye_radius * 0.70)
        # Right eye
        right_eye = _ellipse_weight(focus_cx + eye_cx_offset,
                                    focus_cy + eye_cy_offset,
                                    eye_radius, eye_radius * 0.70)
        # Lips
        lip_zone  = _ellipse_weight(focus_cx,
                                    focus_cy + lip_cy_offset,
                                    lip_rx, lip_ry)

        # Combined psychological focus mask
        focus_mask = _np.clip(left_eye + right_eye + lip_zone, 0.0, 1.0)

        # ── 2. Peripheral soft mask (outside focus_radius) ───────────────────
        dx_p = (xs - focus_cx) / max(focus_radius, 1e-6)
        dy_p = (ys - focus_cy) / max(focus_radius, 1e-6)
        face_d2 = dx_p ** 2 + dy_p ** 2
        # periphery_weight: 0 at face centre, 1 at edges
        periphery_weight = _np.clip((face_d2 - 1.0) / 3.0, 0.0, 1.0)

        # ── 3. Sharpen eye/lip zones via unsharp mask ─────────────────────────
        blur_sig = max(1.2, focus_radius * min(w, h) * 0.20)
        r_blur = _gf(r_f, sigma=blur_sig)
        g_blur = _gf(g_f, sigma=blur_sig)
        b_blur = _gf(b_f, sigma=blur_sig)

        r_sharp = _np.clip(r_f + sharpen_strength * focus_mask * (r_f - r_blur), 0.0, 1.0)
        g_sharp = _np.clip(g_f + sharpen_strength * focus_mask * (g_f - g_blur), 0.0, 1.0)
        b_sharp = _np.clip(b_f + sharpen_strength * focus_mask * (b_f - b_blur), 0.0, 1.0)

        # ── 4. Peripheral softening ───────────────────────────────────────────
        soft_sig = max(0.5, periphery_soften)
        r_soft = _gf(r_sharp, sigma=soft_sig)
        g_soft = _gf(g_sharp, sigma=soft_sig)
        b_soft = _gf(b_sharp, sigma=soft_sig)

        # Blend: periphery gets softened, focus zone preserves sharpened version
        focus_preserve = _np.clip(1.0 - periphery_weight * 0.85, 0.0, 1.0)
        r_out = r_sharp * focus_preserve + r_soft * (1.0 - focus_preserve)
        g_out = g_sharp * focus_preserve + g_soft * (1.0 - focus_preserve)
        b_out = b_sharp * focus_preserve + b_soft * (1.0 - focus_preserve)

        # ── 5. Warm Lombard ambient drift ─────────────────────────────────────
        # Warm R and G slightly, damp B — Lombard afternoon golden light
        r_out = _np.clip(r_out + warm_ambient * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + warm_ambient * 0.65, 0.0, 1.0)
        b_out = _np.clip(b_out - warm_ambient * 0.20, 0.0, 1.0)

        # ── Composite at opacity against original ─────────────────────────────
        r_final = r_f * (1.0 - opacity) + r_out * opacity
        g_final = g_f * (1.0 - opacity) + g_out * opacity
        b_final = b_f * (1.0 - opacity) + b_out * opacity

        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Anguissola intimacy pass complete.")

    def bosch_phantasmagoria_pass(self,
                                   palette:          Optional[List[Color]] = None,
                                   n_detail_marks:   int   = 900,
                                   n_jewel_accents:  int   = 80,
                                   mark_size:        float = 2.5,
                                   mark_opacity:     float = 0.28,
                                   jewel_opacity:    float = 0.55,
                                   void_darken:      float = 0.06,
                                   background_only:  bool  = True,
                                   rng_seed:         int   = 74) -> None:
        """
        Bosch phantasmagoria pass — session 74 artist discovery.

        Inspired by Hieronymus Bosch (c. 1450–1516), the Brabantine master whose
        paintings teem with symbolic incident in every square centimetre.  Where
        other painters allow background areas to breathe as simple dark voids or
        calm atmospheric fields, Bosch populated every corner with micro-detail:
        distant burning cities, fantastical hybrid creatures, symbolic objects, and
        hellish architecture.  The result is a painting surface that rewards
        prolonged looking — each zone of background conceals new symbolic content.

        This pass encodes Bosch's defining aesthetic:

          1. **Micro-detail marks**: Small, dark, irregular marks scattered across
             background regions, creating the sense that symbolic incident lurks
             everywhere.  Marks vary in shape (short strokes, dots, curved slivers)
             mimicking the variety of small creatures and distant figures in Bosch's
             backgrounds.  Applied at low opacity so they accumulate as a textural
             density rather than solid forms — the viewer senses the presence of
             detail without deciphering individual shapes.

          2. **Jewel-tone accents**: Occasional small, intensely coloured marks in
             Bosch's characteristic accent colours — crimson blood-red, lapis blue,
             golden amber — that suggest the presence of symbolic objects (gems,
             fire, celestial light) caught in the dark void.  Applied at higher
             opacity so they read as distinct points of colour against the ground.

          3. **Void deepening**: A subtle darkening of the background mid-tones to
             reinforce the warm Brabantine void quality — Bosch's backgrounds are
             never neutral grey but warm olive-brown, suggesting candlelit interiors
             or the glow of hell's fires.

        The pass respects the figure mask: detail marks are constrained to background
        regions so focal figures are not obscured.  The effect reads as atmospheric
        when viewed at a distance and reveals symbolic texture under close inspection.

        Parameters
        ----------
        palette          : List of (R,G,B) colours to draw accent marks from.
                           If None, uses Bosch's characteristic accent colours
                           (crimson, lapis blue, amber, olive-green).
        n_detail_marks   : Number of small dark background detail marks to scatter.
                           600–1200 for a full canvas; scale by (W*H)/(800*1000).
        n_jewel_accents  : Number of intense jewel-tone accent marks.
                           50–120 is typical; too many removes the focal contrast.
        mark_size        : Base radius in pixels of each detail mark.
                           2–4px gives micro-detail density; larger reads as loose.
        mark_opacity     : Blend weight for detail marks (0.15–0.35 for subtlety).
        jewel_opacity    : Blend weight for jewel accent marks (0.45–0.70 for punch).
        void_darken      : How much to deepen the dark mid-tones toward warm void
                           (0.0 = no darkening; 0.05–0.10 = typical Bosch void depth).
        background_only  : If True (default), constrain marks to the background
                           (inverted figure mask).  If False, apply everywhere.
        rng_seed         : Seed for reproducibility.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        # Default Bosch accent palette: crimson, lapis, amber, olive-green, charcoal
        if palette is None:
            palette = [
                (0.75, 0.15, 0.10),   # crimson — hell fire / blood
                (0.15, 0.28, 0.62),   # lapis blue — celestial accent
                (0.72, 0.58, 0.15),   # warm amber — symbolic gold
                (0.62, 0.72, 0.32),   # bilious olive-green — creatures
                (0.18, 0.14, 0.10),   # deep charcoal — darkest marks
            ]

        print(f"  Bosch phantasmagoria pass "
              f"(detail={n_detail_marks}  jewels={n_jewel_accents}  "
              f"mark_size={mark_size:.1f}  void_darken={void_darken:.2f}) ...")

        rng = random.Random(rng_seed)
        np_rng = _np.random.default_rng(rng_seed)

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()

        # Cairo stores BGRA
        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Build background mask ─────────────────────────────────────────────
        if background_only and self._figure_mask is not None:
            # Background is where figure mask is near zero; feather slightly
            bg = (1.0 - self._figure_mask).astype(_np.float32)
            bg = _np.clip(_gf(bg, sigma=4.0), 0.0, 1.0)
        else:
            bg = _np.ones((h, w), dtype=_np.float32)

        # ── 1. Void deepening — warm the dark mid-tones toward olive-brown ───
        if void_darken > 0.0:
            lum = 0.299 * r_f + 0.587 * g_f + 0.114 * b_f
            # Darken mid-tone and shadow areas (lum < 0.5)
            dark_mask = _np.clip((0.5 - lum) * 2.0, 0.0, 1.0) * bg
            void_r, void_g, void_b = 0.24, 0.18, 0.10  # warm olive-brown
            r_f = _np.clip(r_f - void_darken * dark_mask * (r_f - void_r), 0.0, 1.0)
            g_f = _np.clip(g_f - void_darken * dark_mask * (g_f - void_g), 0.0, 1.0)
            b_f = _np.clip(b_f - void_darken * dark_mask * (b_f - void_b), 0.0, 1.0)

        # Write void-deepened values back for compositing
        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()

        # ── 2. Micro-detail marks ─────────────────────────────────────────────
        # Scatter small dark marks in background areas: short line segments,
        # dots, and curved slivers — a mix of shapes to mimic creature variety.
        ctx = self.canvas.ctx
        ctx.save()

        # Build weighted candidate positions from background mask
        ys_idx, xs_idx = _np.where(bg > 0.15)
        if len(ys_idx) > 0:
            bg_weights = bg[ys_idx, xs_idx].astype(_np.float64)
            bg_weights /= bg_weights.sum()

            chosen = np_rng.choice(len(ys_idx),
                                   size=min(n_detail_marks, len(ys_idx)),
                                   replace=True, p=bg_weights)

            for idx in chosen:
                py, px = int(ys_idx[idx]), int(xs_idx[idx])
                # Vary mark shape: 0=dot, 1=short stroke, 2=sliver arc
                shape = rng.randint(0, 2)
                # Dark warm colours — the micro-detail reads as shadow not colour
                tone = rng.uniform(0.06, 0.22)
                warmth = rng.uniform(0.85, 1.0)  # slightly warmer than neutral
                cr = tone * warmth
                cg = tone * 0.82
                cb = tone * 0.65

                alpha = mark_opacity * rng.uniform(0.55, 1.0)
                ctx.set_source_rgba(cr, cg, cb, alpha)

                s = mark_size * rng.uniform(0.6, 1.6)

                if shape == 0:
                    # Small dot
                    ctx.arc(px, py, max(0.5, s * 0.45), 0, math.pi * 2)
                    ctx.fill()
                elif shape == 1:
                    # Short directional stroke
                    angle = rng.uniform(0, math.pi * 2)
                    length = s * rng.uniform(1.2, 3.0)
                    ex = px + math.cos(angle) * length
                    ey = py + math.sin(angle) * length
                    ctx.set_line_width(max(0.5, s * 0.35))
                    ctx.move_to(px, py)
                    ctx.line_to(ex, ey)
                    ctx.stroke()
                else:
                    # Curved sliver — partial arc suggesting a creature limb
                    angle_start = rng.uniform(0, math.pi * 2)
                    angle_end   = angle_start + rng.uniform(0.4, 1.2)
                    radius = s * rng.uniform(0.8, 1.8)
                    ctx.set_line_width(max(0.4, s * 0.25))
                    ctx.arc(px, py, radius, angle_start, angle_end)
                    ctx.stroke()

        # ── 3. Jewel-tone accent marks ────────────────────────────────────────
        if len(ys_idx) > 0 and n_jewel_accents > 0:
            chosen_j = np_rng.choice(len(ys_idx),
                                     size=min(n_jewel_accents, len(ys_idx)),
                                     replace=True, p=bg_weights)

            for idx in chosen_j:
                py, px = int(ys_idx[idx]), int(xs_idx[idx])
                col = rng.choice(palette[:4])  # first 4: crimson, lapis, amber, green
                cr, cg, cb = jitter(col, amount=0.06, rng=rng)
                alpha = jewel_opacity * rng.uniform(0.65, 1.0)
                ctx.set_source_rgba(cr, cg, cb, alpha)

                # Jewel marks are tiny, precise dots or very short strokes
                s = mark_size * rng.uniform(0.5, 1.2)
                ctx.arc(px, py, max(0.6, s * 0.50), 0, math.pi * 2)
                ctx.fill()

        ctx.restore()

        # ── Composite void-deepened base back into canvas ─────────────────────
        # The cairo context already wrote the marks directly to the surface.
        # Now composite the void-darken result over the current canvas.
        if void_darken > 0.0:
            buf2 = _np.frombuffer(self.canvas.surface.get_data(),
                                  dtype=_np.uint8).reshape((h, w, 4)).copy()
            r2 = buf2[:, :, 2].astype(_np.float32) / 255.0
            g2 = buf2[:, :, 1].astype(_np.float32) / 255.0
            b2 = buf2[:, :, 0].astype(_np.float32) / 255.0

            # Blend void-deepened base with current (mark-painted) surface
            blend = void_darken * 3.0  # how strongly to push toward void tone
            blend = _np.clip(blend, 0.0, 0.6)
            r_merged = r2 * (1.0 - blend * dark_mask) + r_out * blend * dark_mask
            g_merged = g2 * (1.0 - blend * dark_mask) + g_out * blend * dark_mask
            b_merged = b2 * (1.0 - blend * dark_mask) + b_out * blend * dark_mask

            buf2[:, :, 2] = _np.clip(r_merged * 255.0, 0, 255).astype(_np.uint8)
            buf2[:, :, 1] = _np.clip(g_merged * 255.0, 0, 255).astype(_np.uint8)
            buf2[:, :, 0] = _np.clip(b_merged * 255.0, 0, 255).astype(_np.uint8)
            self.canvas.surface.get_data()[:] = buf2.tobytes()

        print("    Bosch phantasmagoria pass complete.")

    def cool_atmospheric_recession_pass(self,
                                         horizon_y:                  float = 0.35,
                                         cool_strength:              float = 0.22,
                                         bright_lift:                float = 0.10,
                                         desaturate:                 float = 0.30,
                                         blur_background:            float = 0.8,
                                         feather:                    float = 0.15,
                                         opacity:                    float = 0.75,
                                         lateral_horizon_asymmetry:  float = 0.0,
                                         warm_ground_glow:           float = 0.0) -> None:
        """
        Cool atmospheric recession pass — session 74 artistic improvement.

        Improves the rendering of aerial perspective in background landscapes,
        inspired directly by Leonardo da Vinci's treatment of the vast atmospheric
        wilderness behind the Mona Lisa (and more broadly by his Treatise on
        Painting, where he describes the progressive cooling and brightening of
        colours as they recede toward the horizon).

        **Why this improves the pipeline:**
        Prior sessions handled sfumato (edge-softening) very well via
        sfumato_veil_pass() and depth_gradient, but the specific physics of
        atmospheric colour shift — the cool blue-grey transformation of distant
        forms — was not isolated as a standalone, tuneable effect.  This pass
        extracts that quality as a composable operation:

          1. **Progressive colour cooling**: Rows above the horizon line receive
             an increasing shift toward cool grey-blue, mimicking how the
             atmosphere scatters short wavelengths (blue/violet) and absorbs
             warm long wavelengths (red/orange) over distance.  The shift is
             zero at the horizon_y row and increases toward the top of canvas.

          2. **Atmospheric brightness lift**: Distant areas receive a gentle
             luminosity increase, simulating the bright haze that accumulates
             in layers of atmosphere.  The horizon zone is the brightest point;
             the top of the distant sky lightens toward white haze.

          3. **Progressive desaturation**: Colours lose saturation with distance
             — distant mountains become the characteristic pale grey-blue rather
             than retaining their local colours.  This is visible in the Mona Lisa
             background: the near landscape retains warm green-brown tones; the
             far distance is pure silver-blue haze.

          4. **Soft background blur**: A gentle, distance-weighted Gaussian blur
             dissolves fine detail in distant areas, reinforcing the depth cue.
             Near areas (foreground) remain sharp; far areas dissolve into haze.

        All four effects are composited at ``opacity`` against the original
        surface, allowing the pass to be applied at different weights depending
        on the desired depth effect.

        This pass is designed to work with the figure mask: if a figure mask is
        set, the effect is suppressed in the figure region so the sitter's skin
        tones are not cooled or desaturated.

        Parameters
        ----------
        horizon_y        : Normalised vertical position of the horizon [0, 1].
                           0 = top of canvas; 1 = bottom.  Rows above this line
                           receive progressive recession; rows at/below are unchanged.
                           Default 0.35 matches a typical portrait with figure in
                           the lower two-thirds and landscape above.
        cool_strength    : Maximum blue-grey colour shift at the top of the canvas.
                           0.0 = no colour shift; 0.20–0.30 = strong Leonardo-style
                           atmospheric recession.  Intermediate values give Turner
                           (0.15), Corot (0.18), or Claude Lorrain (0.25) effects.
        bright_lift      : Maximum luminosity increase at the top of canvas (horizon haze).
                           0.05–0.15 = gentle; 0.20+ = thick foggy haze.
        desaturate       : Maximum chromatic desaturation at the top of canvas.
                           0.0 = no desaturation; 0.3–0.5 = Leonardo-style grey-blue
                           distant peaks.
        blur_background  : Gaussian sigma for the distance-weighted background blur.
                           0 = no blur; 0.5–1.5 = subtle; 2+ = heavy dissolve.
        feather          : Width of the feathering zone around the horizon line
                           (normalised). Prevents a hard line at the horizon.
                           0.10–0.20 is typical.
        opacity          : Overall pass opacity blended against original (0–1).
        lateral_horizon_asymmetry : Fractional canvas-height shift between the left and
                           right horizon positions.  Positive values raise the left
                           horizon (left side of background is higher, right side is
                           lower); negative values raise the right.  Default 0.0 gives a
                           perfectly level horizon.  This replicates the famous left/right
                           horizon height mismatch in the Mona Lisa — where the landscape
                           on the left sits visibly higher than the landscape on the right,
                           creating a subtle, disorienting perspective discontinuity.
                           Implemented by computing a per-column effective horizon position
                           that varies linearly across the canvas width; when zero the
                           behaviour is identical to the prior single-horizon formulation.
                           Typical range: −0.10 to +0.10 (up to 10 % of canvas height).
        warm_ground_glow   : Strength of warm amber glow near the base of the recession
                           zone — session 91 artistic improvement.  In Renaissance and
                           Venetian landscape painting, the terrain just above the
                           figure's horizon is not simply the coolest point; it retains
                           a warm, golden character where sunlit earth and reflected
                           ground-light heat the lower atmosphere.  The cool aerial
                           blue-grey only dominates higher up, where the line of sight
                           passes through more atmosphere.  When > 0, pixels in the
                           lower portion of the recession zone (within ~20 % above the
                           per-column horizon) receive a warm amber push (R↑, G↑ slightly,
                           B↓) that softly fades as the recession weight increases toward
                           the top of canvas, where the cool atmospheric haze takes over.
                           The warm zone is bell-curve profiled so there is no hard edge:
                           deepest warmth at ≈ 8 % above the horizon, tapering to zero
                           both at the horizon itself and at the cool zone above.  When
                           warm_ground_glow = 0 the behaviour is identical to the
                           prior formulation.  Typical range: 0.05–0.20.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Cool atmospheric recession pass "
              f"(horizon_y={horizon_y:.2f}  cool={cool_strength:.2f}  "
              f"lift={bright_lift:.2f}  desat={desaturate:.2f}  "
              f"opacity={opacity:.2f}  lateral_asym={lateral_horizon_asymmetry:+.3f}  "
              f"warm_ground_glow={warm_ground_glow:.2f}) ...")

        if opacity <= 0.0:
            print("    Cool atmospheric recession pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        b_f = buf[:, :, 0].astype(_np.float32) / 255.0
        g_f = buf[:, :, 1].astype(_np.float32) / 255.0
        r_f = buf[:, :, 2].astype(_np.float32) / 255.0

        # ── Build vertical depth weight ───────────────────────────────────────
        # depth_w[y, x]: 0 at the effective horizon for each column, increases
        # toward the top of the canvas (row 0).  Rows at or below the per-column
        # horizon are unaffected.
        #
        # When lateral_horizon_asymmetry == 0, horizon_y_cols is constant and the
        # result is identical to the former single-horizon 1D broadcast.  When
        # non-zero, the effective horizon varies linearly from column 0 to column W-1:
        #   left edge  (x=0):   horizon_y − lateral_horizon_asymmetry × 0.5
        #   right edge (x=W-1): horizon_y + lateral_horizon_asymmetry × 0.5
        # A positive asymmetry therefore raises the left horizon and lowers the right,
        # matching the Mona Lisa background geometry.
        xs = _np.arange(w, dtype=_np.float32)
        horizon_y_cols = (horizon_y
                          - lateral_horizon_asymmetry * (0.5 - xs / max(w - 1, 1)))
        horizon_px_cols = _np.clip(
            (horizon_y_cols * h).astype(_np.float32), 0.0, float(h - 1)
        )  # shape (W,)

        ys = _np.arange(h, dtype=_np.float32)[:, _np.newaxis]  # shape (H, 1)
        # Normalised distance above the per-column horizon: 1 at top, 0 at horizon
        t_raw = (horizon_px_cols[_np.newaxis, :] - ys) / _np.maximum(
            horizon_px_cols[_np.newaxis, :], 1.0
        )
        t_raw = _np.clip(t_raw, 0.0, 1.0)

        # Feather: smoothstep-style ramp over the feather zone so there is no
        # hard transition at the horizon row
        t_feathered = _np.clip(
            (t_raw - feather) / max(1.0 - feather, 1e-6), 0.0, 1.0
        )
        depth_w = t_feathered ** 1.5   # nonlinear: effect accelerates with distance
        # depth_w shape: (H, W)

        # ── Figure mask suppression ───────────────────────────────────────────
        # Do not apply recession to the figure (sitter's skin must stay warm)
        if self._figure_mask is not None:
            # figure_mask: 1=figure, 0=background
            # suppress_mask: 0 where figure, 1 where background
            suppress = (1.0 - _np.clip(self._figure_mask, 0.0, 1.0)).astype(_np.float32)
            # Feather the suppression boundary
            suppress = _np.clip(_gf(suppress, sigma=8.0), 0.0, 1.0)
        else:
            suppress = _np.ones((h, w), dtype=_np.float32)

        # Combined recession weight: depth × background mask
        recession_w = depth_w * suppress   # (H, W)

        # ── 0. Warm ground glow (session 91 improvement) ──────────────────────
        # In Renaissance landscape painting the terrain just above the horizon
        # glows with warm amber — reflected ground light and low-angle sun warm
        # the lower atmosphere before the cool aerial haze dominates higher up.
        # A bell-curve weight centred at ~8 % above the horizon drives a warm
        # push (R↑, G↑, B↓) that peaks just above the horizon and tapers to
        # zero both at the horizon itself and well into the cool zone above.
        # Initialise working buffers (may be modified by warm glow below).
        r_out = r_f.copy()
        g_out = g_f.copy()
        b_out = b_f.copy()
        if warm_ground_glow > 0.0:
            # glow_t: normalised distance above horizon in [0, 1], but only within
            # the lower 30 % of the recession zone where the warm glow lives.
            glow_t_raw = _np.clip(t_raw * (1.0 / 0.30), 0.0, 1.0)   # 0 at horizon, 1 at 30 % up
            # Bell curve peaking at glow_t ≈ 0.27 (≈ 8 % above horizon in depth_w terms)
            glow_bell = _np.exp(-((glow_t_raw - 0.27) ** 2) / (2.0 * 0.12 ** 2))
            # Suppress glow at the horizon itself and taper it out above 30 %
            glow_mask = glow_bell * _np.clip(t_raw / 0.05, 0.0, 1.0) * suppress
            glow_mask = _np.clip(_gf(glow_mask, sigma=4.0) * warm_ground_glow, 0.0, 1.0)
            # Warm amber push: R↑, G↑ slightly, B↓
            r_out = _np.clip(r_out + glow_mask * 0.14, 0.0, 1.0)
            g_out = _np.clip(g_out + glow_mask * 0.07, 0.0, 1.0)
            b_out = _np.clip(b_out - glow_mask * 0.06, 0.0, 1.0)

        # ── 1. Progressive colour cooling ─────────────────────────────────────
        # Target: cool grey-blue horizon haze — pale blue-grey
        haze_r, haze_g, haze_b = 0.72, 0.76, 0.82   # cool pale blue-grey
        r_out = r_out * (1.0 - recession_w * cool_strength) + haze_r * recession_w * cool_strength
        g_out = g_out * (1.0 - recession_w * cool_strength * 0.85) + haze_g * recession_w * cool_strength * 0.85
        b_out = b_out * (1.0 - recession_w * cool_strength * 0.65) + haze_b * recession_w * cool_strength * 0.65

        # ── 2. Atmospheric brightness lift ────────────────────────────────────
        # Distant zones brighten toward the pale horizon haze
        r_out = _np.clip(r_out + recession_w * bright_lift, 0.0, 1.0)
        g_out = _np.clip(g_out + recession_w * bright_lift * 0.92, 0.0, 1.0)
        b_out = _np.clip(b_out + recession_w * bright_lift * 0.80, 0.0, 1.0)

        # ── 3. Progressive desaturation ───────────────────────────────────────
        lum = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
        desat_w = recession_w * desaturate
        r_out = r_out * (1.0 - desat_w) + lum * desat_w
        g_out = g_out * (1.0 - desat_w) + lum * desat_w
        b_out = b_out * (1.0 - desat_w) + lum * desat_w

        # ── 4. Distance-weighted background blur ──────────────────────────────
        if blur_background > 0.0:
            r_blurred = _gf(r_out, sigma=blur_background)
            g_blurred = _gf(g_out, sigma=blur_background)
            b_blurred = _gf(b_out, sigma=blur_background)
            # Blend: distant areas get more blur; near areas stay sharp
            blur_w = _np.clip(recession_w * 1.5, 0.0, 1.0)
            r_out = r_out * (1.0 - blur_w) + r_blurred * blur_w
            g_out = g_out * (1.0 - blur_w) + g_blurred * blur_w
            b_out = b_out * (1.0 - blur_w) + b_blurred * blur_w

        r_out = _np.clip(r_out, 0.0, 1.0)
        g_out = _np.clip(g_out, 0.0, 1.0)
        b_out = _np.clip(b_out, 0.0, 1.0)

        # ── Composite at opacity against original ─────────────────────────────
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Cool atmospheric recession pass complete.")

    def de_hooch_threshold_light_pass(self,
                                      light_x:         float = 0.15,
                                      light_width:     float = 0.50,
                                      light_falloff:   float = 0.55,
                                      warm_color:      tuple = (0.78, 0.58, 0.28),
                                      cool_color:      tuple = (0.36, 0.46, 0.58),
                                      warm_strength:   float = 0.28,
                                      cool_strength:   float = 0.18,
                                      doorway_y:       float = 0.30,
                                      doorway_h:       float = 0.55,
                                      doorway_w:       float = 0.18,
                                      doorway_x:       float = 0.82,
                                      opacity:         float = 0.72) -> None:
        """
        De Hooch threshold light pass — session 75 artistic improvement.

        Models Pieter de Hooch's signature warm/cool threshold light contrast:
        warm amber interior light flooding from the left creating oblique diagonal
        illumination across the figure and floor, set against the cooler exterior
        daylight entering from an open doorway or window in the background.

        **Why this improves the pipeline:**
        De Hooch's domestic interiors achieve their luminous, inhabitable quality
        through a precise warm/cool light architecture that was not previously
        represented as a standalone composable pass.  Prior sessions had:
          - sfumato_veil_pass() for Leonardo-style edge dissolution
          - cool_atmospheric_recession_pass() for background aerial perspective
          - luminous_glow_pass() for Turner-style atmospheric radiance

        But de Hooch's threshold light is fundamentally different: it is an
        *interior warm/cool contrast* — the warmth comes from a lateral window
        illuminating the floor and figures obliquely, while the cool light enters
        through a receding doorway creating a characteristic colour-temperature
        threshold.  This pass models both components:

          1. **Warm lateral light shaft**: An oblique warm amber gradient enters
             from the left edge, falling across the lower register of the canvas
             (floor, figures, wall) with a diagonal falloff that replicates the
             characteristic de Hooch illumination angle.  The warm tint lifts
             the red and green channels differentially, replicating the amber-ochre
             quality of interior daylight filtered through period-correct windows.

          2. **Cool threshold window**: A precisely located cool exterior light
             rectangle (the doorway/window in the background) introduces a foil
             of cool grey-blue.  This is the compositional device that made
             de Hooch's interiors famous — without the cool counterpoint the warm
             foreground reads as merely yellow; with it the interior achieves
             luminous contrast and spatial depth.

          3. **Diagonal light attenuation**: The warm light fades with distance
             from the left edge using a smooth sigmoid attenuation, so the right
             side and far background remain relatively cool — replicating the
             physical behaviour of oblique interior window light.

        The pass is composited at `opacity` against the existing canvas surface,
        allowing it to be applied at different strengths depending on the degree
        of interior warmth desired.

        :param light_x:       Normalised x position of the warm light source edge
                              (0.0 = left canvas edge; typically 0.05–0.25).
        :param light_width:   Normalised width of the warm light gradient spread
                              across the canvas (0.3–0.7 typical).
        :param light_falloff: Sigmoid steepness of the warm light attenuation.
                              Higher values create a sharper warm/cool boundary.
        :param warm_color:    RGB tuple [0,1] of the warm interior light tint.
        :param cool_color:    RGB tuple [0,1] of the cool exterior threshold tint.
        :param warm_strength: Additive strength of the warm light overlay (0–1).
        :param cool_strength: Additive strength of the cool exterior overlay (0–1).
        :param doorway_y:     Top edge of the cool doorway rectangle (normalised).
        :param doorway_h:     Height of the cool doorway rectangle (normalised).
        :param doorway_w:     Width of the cool doorway rectangle (normalised).
        :param doorway_x:     Left edge x of the cool doorway rectangle (normalised).
        :param opacity:       Final composite opacity of the entire pass (0–1).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        w_px = surface.get_width()
        h_px = surface.get_height()

        # Extract canvas BGRA buffer
        orig = _np.frombuffer(surface.get_data(),
                              dtype=_np.uint8).reshape((h_px, w_px, 4)).copy()

        # ── Coordinate grids [0, 1] ───────────────────────────────────────────
        yy = _np.linspace(0.0, 1.0, h_px, dtype=_np.float32)[:, None] * _np.ones((1, w_px), dtype=_np.float32)
        xx = _np.ones((h_px, 1), dtype=_np.float32) * _np.linspace(0.0, 1.0, w_px, dtype=_np.float32)[None, :]

        # ── Decompose to float RGB ────────────────────────────────────────────
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── 1. Warm lateral light shaft ────────────────────────────────────────
        # Oblique warm amber gradient from the left edge.
        # sigmoid(light_falloff, xx - light_x - light_width) creates a smooth
        # gradient that is near-1.0 at the left, falling to near-0.0 at the right.
        warm_dist = (xx - light_x) / max(light_width, 0.01)
        warm_weight = _np.clip(1.0 - warm_dist, 0.0, 1.0)
        # Mild diagonal: light slightly stronger in the upper-lower register
        # (simulates light entering from slightly above-left)
        diagonal_bias = 1.0 + 0.25 * (0.65 - yy)
        warm_weight = _np.clip(warm_weight * diagonal_bias, 0.0, 1.0)
        warm_weight = (warm_weight ** light_falloff).astype(_np.float32)

        wr, wg, wb = warm_color
        r_out = _np.clip(r_out + warm_weight * warm_strength * wr, 0.0, 1.0)
        g_out = _np.clip(g_out + warm_weight * warm_strength * wg * 0.85, 0.0, 1.0)
        b_out = _np.clip(b_out + warm_weight * warm_strength * wb * 0.50, 0.0, 1.0)

        # ── 2. Cool exterior threshold (doorway/window rectangle) ─────────────
        # A cool blue-grey rectangle in the background represents exterior light
        # entering through a doorway — de Hooch's defining compositional device.
        door_mask = (
            (xx >= doorway_x) & (xx <= doorway_x + doorway_w) &
            (yy >= doorway_y) & (yy <= doorway_y + doorway_h)
        ).astype(_np.float32)
        # Soft feathered edges for the doorway (5 px sigma proportional to size)
        feather_px = max(4, int(min(h_px, w_px) * 0.022))
        door_mask = _gf(door_mask, sigma=feather_px).astype(_np.float32)
        door_mask = _np.clip(door_mask, 0.0, 1.0)

        cr, cg, cb = cool_color
        r_out = _np.clip(r_out * (1.0 - door_mask * cool_strength * 0.40)
                         + door_mask * cool_strength * cr, 0.0, 1.0)
        g_out = _np.clip(g_out * (1.0 - door_mask * cool_strength * 0.25)
                         + door_mask * cool_strength * cg, 0.0, 1.0)
        b_out = _np.clip(b_out * (1.0 - door_mask * cool_strength * 0.15)
                         + door_mask * cool_strength * cb, 0.0, 1.0)

        # ── 3. Composite at opacity ────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    De Hooch threshold light pass complete.")

    def steen_warm_vitality_pass(self,
                                  face_cx:          float = 0.515,
                                  face_cy:          float = 0.210,
                                  face_rx:          float = 0.140,
                                  face_ry:          float = 0.190,
                                  amber_lift:       float = 0.055,
                                  rose_flush:       float = 0.040,
                                  shadow_warmth:    float = 0.038,
                                  shadow_thresh:    float = 0.35,
                                  highlight_thresh: float = 0.70,
                                  blur_radius:      float = 8.0,
                                  opacity:          float = 0.54) -> None:
        """
        Jan Steen warm vitality pass — session 76 artistic improvement.

        Inspired by Jan Steen (1626–1679), master of Dutch Golden Age genre comedy.
        Steen's distinctive quality among his Dutch contemporaries is the extraordinary
        *warmth and vitality of his flesh painting*: his figures appear flushed, alive,
        and luminous in a way that is immediately recognisable against the cooler,
        more silvery flesh of Vermeer or the solemn amber of de Hooch.

        This arises from three interlocking technical choices:

          1. **Warm amber highlight lift** — Steen's warm ochre-amber imprimatura glows
             visibly through thin paint in the lightest passages.  Where Vermeer's
             highlights have a pearl-cool quality, Steen's are distinctly golden-amber.
             This pass boosts the R and G channels in pixels above `highlight_thresh`
             luminance, simulating the imprimatura asserting itself through highlight
             glazing.  B is suppressed slightly so the warmth reads as ochre, not ivory.

          2. **Rose flush in face/figure zone** — Steen's genre figures always have
             warm, slightly flushed complexions — the result of his confident alla prima
             working into wet paint and his preference for vermilion-tinged flesh priming.
             This pass applies a rose-amber drift (R+rose, G+rose×0.4, B suppressed) to
             an elliptical face/skin zone, restoring the warm blush quality that pure
             rendering pipelines tend to cool down.

          3. **Warm amber shadow depth** — Unlike Caravaggio (cold tenebrist void) or
             Vermeer (cool diffuse shadow), Steen's shadows are consistently warm amber-
             brown, created by the dark Vandyke-brown ground showing through thin shadow
             glazing.  This pass lifts the red channel and slightly the green in pixels
             below `shadow_thresh` luminance, ensuring no cold neutral blacks remain.

        Together these three operations produce the 'warm vitality' that characterises
        Steen's flesh: luminous in the lights, rosy in the midtones, amber-brown in the
        darks — a complete warm tonal envelope that reads as vivid life.

        **Why this improves the Mona Lisa pipeline:**
        The accumulated passes from sessions 53–75 have, cumulatively, pushed the portrait
        toward increasing refinement and softness (sfumato, pearl grace, angelic lift).
        Steen's vitality pass reintroduces tonal warmth and flesh energy that prevents the
        figure from reading as remote or glassy.  The warm amber highlight lift in
        particular reinforces the impression of an ochre imprimatura beneath translucent
        paint layers — historically accurate to a Florentine poplar panel preparation.

        :param face_cx:          Normalised x-centre of the face/skin ellipse.
        :param face_cy:          Normalised y-centre of the face/skin ellipse.
        :param face_rx:          Normalised x-radius of the face/skin ellipse.
        :param face_ry:          Normalised y-radius of the face/skin ellipse.
        :param amber_lift:       Additive strength of the warm amber highlight boost.
        :param rose_flush:       Additive strength of the rose flush in the face zone.
        :param shadow_warmth:    Additive strength of the warm shadow lift.
        :param shadow_thresh:    Luminance threshold below which shadow warmth applies.
        :param highlight_thresh: Luminance threshold above which amber lift applies.
        :param blur_radius:      Gaussian blur radius for mask feathering.
        :param opacity:          Final composite opacity of the entire pass.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        w_px = surface.get_width()
        h_px = surface.get_height()

        orig = _np.frombuffer(surface.get_data(),
                              dtype=_np.uint8).reshape((h_px, w_px, 4)).copy()

        # ── Decompose to float RGB ────────────────────────────────────────────
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── 1. Warm amber highlight lift ──────────────────────────────────────
        # Pixels above highlight_thresh: lift R and G to simulate imprimatura
        # glowing through thin paint; suppress B so colour reads as warm ochre.
        hi_mask = _np.clip((lum - highlight_thresh) / max(1.0 - highlight_thresh, 0.01),
                           0.0, 1.0).astype(_np.float32)
        hi_mask = _gf(hi_mask, sigma=blur_radius).astype(_np.float32)
        r_out = _np.clip(r_out + hi_mask * amber_lift * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * amber_lift * 0.72, 0.0, 1.0)
        b_out = _np.clip(b_out - hi_mask * amber_lift * 0.28, 0.0, 1.0)

        # ── 2. Rose flush in face / figure zone ───────────────────────────────
        # An elliptical face mask receives a warm rose-amber drift in midtone pixels.
        yy = _np.linspace(0.0, 1.0, h_px, dtype=_np.float32)[:, None]
        xx = _np.linspace(0.0, 1.0, w_px, dtype=_np.float32)[None, :]
        dx = (xx - face_cx) / max(face_rx, 0.01)
        dy = (yy - face_cy) / max(face_ry, 0.01)
        face_d = (dx * dx + dy * dy).astype(_np.float32)
        # Soft elliptical weight: 1.0 at centre, 0.0 at 1.4× the axis
        face_mask = _np.clip(1.0 - (face_d - 0.70) / 0.70, 0.0, 1.0).astype(_np.float32)
        face_mask = _gf(face_mask, sigma=blur_radius * 1.5).astype(_np.float32)
        # Apply only in midtone zone: avoid over-flushing highlights or deeps
        mid_weight = _np.clip(1.0 - _np.abs(lum - 0.62) / 0.35, 0.0, 1.0)
        flush_mask = (face_mask * mid_weight).astype(_np.float32)
        r_out = _np.clip(r_out + flush_mask * rose_flush * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + flush_mask * rose_flush * 0.38, 0.0, 1.0)
        b_out = _np.clip(b_out - flush_mask * rose_flush * 0.22, 0.0, 1.0)

        # ── 3. Warm amber shadow depth ────────────────────────────────────────
        # Pixels below shadow_thresh: warm the R and G channels so all darks
        # carry Steen's amber-brown shadow quality rather than cold neutral black.
        sh_mask = _np.clip(1.0 - lum / max(shadow_thresh, 0.01), 0.0, 1.0)
        sh_mask = _gf(sh_mask.astype(_np.float32), sigma=blur_radius).astype(_np.float32)
        r_out = _np.clip(r_out + sh_mask * shadow_warmth * 0.90, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * shadow_warmth * 0.48, 0.0, 1.0)
        b_out = _np.clip(b_out - sh_mask * shadow_warmth * 0.18, 0.0, 1.0)

        # ── 4. Composite at opacity ────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Jan Steen warm vitality pass complete.")

    def poussin_classical_clarity_pass(self,
                                       shadow_cool:      float = 0.10,
                                       midtone_lift:     float = 0.06,
                                       saturation_cap:   float = 0.82,
                                       highlight_ivory:  float = 0.04,
                                       shadow_thresh:    float = 0.32,
                                       highlight_thresh: float = 0.75,
                                       midtone_lo:       float = 0.32,
                                       midtone_hi:       float = 0.68,
                                       blur_radius:      float = 6.0,
                                       opacity:          float = 0.50) -> None:
        """
        Nicolas Poussin classical clarity pass — session 77 artistic improvement.

        Inspired by Nicolas Poussin (1594–1665), the supreme master of French Classical
        painting.  Poussin worked in Rome and forged a chromatic philosophy that became
        the foundation of French Academic doctrine: colour must serve reason, not sensation.

        His paintings are defined by four interlocking chromatic qualities that this pass
        encodes:

          1. **Cool silver-grey shadows** — Unlike the warm amber shadows of the Flemish
             Baroque (Rubens, Van Dyck) or the near-black voids of Caravaggio/Rembrandt,
             Poussin's shadows are consistently cool grey-silver — the colour of Roman
             stone in diffuse overcast light.  This signals Classical Stoic restraint.
             This pass boosts the B channel in pixels below `shadow_thresh` luminance,
             converting any residual warm-amber shadow bias into cool grey-blue.

          2. **Midtone clarification lift** — Poussin's colour zones read with architectural
             clarity: each narrative element occupies a distinct, legible tonal band.
             There is no Rembrandtesque tenebrism collapsing the mid-values into void.
             This pass lifts the luminance of pixels in the midtone band (between
             `midtone_lo` and `midtone_hi`) so the compositional architecture of light
             and shadow remains rationally readable at a distance.

          3. **Saturation discipline** — Poussin famously subordinated chromatic intensity
             to narrative weight: only the most important figure wore pure ultramarine or
             vermilion; background figures were always desaturated in deference.  This pass
             caps HSV saturation at `saturation_cap`, ensuring that no colour zone shouts
             louder than the picture's moral hierarchy demands.  Pure decorative saturation
             is the enemy of his system.

          4. **Highlight ivory warmth** — Poussin's stone-lit highlights carry a faint
             warm ivory quality — the colour of Roman travertine in raking afternoon sun.
             This is far from the golden amber of Rembrandt or the pearl-cool of Ingres;
             it is a stone-warm neutral that anchors his flesh highlights in the physical
             world of Roman sculpture.  This pass adds a soft, gentle ivory shift to the
             brightest pixels (above `highlight_thresh`).

        Together these operations produce the characteristic French Classical chromatic
        reading: cool in the darks, clear in the midtones, disciplined in colour intensity,
        stone-warm in the lights — a complete tonality of rational, architectural dignity.

        **Why this improves the Mona Lisa pipeline:**
        The Mona Lisa's palette is warm-amber throughout (Leonardo's sfumato glaze pushes
        the shadows toward brown-gold).  Poussin's pass provides a counterpoint: it cools
        the shadow tone (pulling it toward the blue-grey of the mountain atmosphere behind
        the figure), lifts the midtone clarity (making the sfumato veil read more legibly),
        and disciplines over-saturated passages that can creep in from successive warm
        passes.  This creates a more nuanced tonal architecture — warm lights, cool darks,
        clear midtones — that is historically consistent with High Renaissance panel technique
        even if Poussin himself came a century later.

        :param shadow_cool:       Additive strength of the blue-grey shadow push.
        :param midtone_lift:      Additive luminance boost in the mid-tone band.
        :param saturation_cap:    Maximum allowed HSV saturation (1.0 = no cap).
        :param highlight_ivory:   Additive ivory warmth in pixels above highlight_thresh.
        :param shadow_thresh:     Luminance threshold below which shadow cooling applies.
        :param highlight_thresh:  Luminance threshold above which ivory highlight applies.
        :param midtone_lo:        Lower bound of the midtone band.
        :param midtone_hi:        Upper bound of the midtone band.
        :param blur_radius:       Gaussian sigma for feathering all tonal masks.
        :param opacity:           Final composite opacity of the entire pass.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        w_px = surface.get_width()
        h_px = surface.get_height()

        orig = _np.frombuffer(surface.get_data(),
                              dtype=_np.uint8).reshape((h_px, w_px, 4)).copy()

        # ── Decompose to float RGB (cairo BGRA → R/G/B float arrays) ─────────
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── 1. Cool silver-grey shadow push ───────────────────────────────────
        # Pixels below shadow_thresh receive a blue-grey push: B↑, R slightly↓,
        # converting warm-amber shadow residue into cool French Classical grey.
        sh_mask = _np.clip(1.0 - lum / max(shadow_thresh, 0.01), 0.0, 1.0)
        sh_mask = _gf(sh_mask.astype(_np.float32), sigma=blur_radius).astype(_np.float32)
        r_out = _np.clip(r_out - sh_mask * shadow_cool * 0.30, 0.0, 1.0)
        g_out = _np.clip(g_out - sh_mask * shadow_cool * 0.10, 0.0, 1.0)
        b_out = _np.clip(b_out + sh_mask * shadow_cool * 1.00, 0.0, 1.0)

        # ── 2. Midtone clarification lift ─────────────────────────────────────
        # Pixels inside [midtone_lo, midtone_hi] receive a uniform luminance
        # boost — raising the architectural mid-ground so the composition reads
        # with Poussin's characteristic clarity at a distance.
        mid_band = _np.clip(
            _np.minimum(
                (lum - midtone_lo) / max(midtone_hi - midtone_lo, 0.01),
                (midtone_hi - lum) / max(midtone_hi - midtone_lo, 0.01),
            ) * 2.0,
            0.0, 1.0
        ).astype(_np.float32)
        mid_mask = _gf(mid_band, sigma=blur_radius).astype(_np.float32)
        r_out = _np.clip(r_out + mid_mask * midtone_lift, 0.0, 1.0)
        g_out = _np.clip(g_out + mid_mask * midtone_lift, 0.0, 1.0)
        b_out = _np.clip(b_out + mid_mask * midtone_lift, 0.0, 1.0)

        # ── 3. Saturation cap (HSV model) ─────────────────────────────────────
        # For pixels where HSV saturation S > saturation_cap, reduce S to the cap
        # by interpolating each channel toward the V (max-channel) value:
        #   new_c = V - (V - c) * (saturation_cap / S)
        # This preserves hue and value while disciplining chromatic intensity.
        max_c  = _np.maximum(_np.maximum(r_out, g_out), b_out)
        delta  = max_c - _np.minimum(_np.minimum(r_out, g_out), b_out)
        sat    = _np.where(max_c > 1e-6, delta / max_c, 0.0).astype(_np.float32)
        excess = (sat > saturation_cap) & (delta > 1e-6)
        safe_sat = _np.where(sat > 1e-6, sat, 1.0).astype(_np.float32)
        factor = _np.where(excess, saturation_cap / safe_sat, 1.0).astype(_np.float32)
        r_out  = _np.where(excess, max_c - (max_c - r_out) * factor, r_out)
        g_out  = _np.where(excess, max_c - (max_c - g_out) * factor, g_out)
        b_out  = _np.where(excess, max_c - (max_c - b_out) * factor, b_out)
        r_out  = _np.clip(r_out, 0.0, 1.0).astype(_np.float32)
        g_out  = _np.clip(g_out, 0.0, 1.0).astype(_np.float32)
        b_out  = _np.clip(b_out, 0.0, 1.0).astype(_np.float32)

        # ── 4. Highlight ivory warmth ─────────────────────────────────────────
        # Bright pixels (lum > highlight_thresh) receive a soft ivory push:
        # R↑ (most), G slightly↑, B↓ — Roman travertine in afternoon light.
        hi_mask = _np.clip(
            (lum - highlight_thresh) / max(1.0 - highlight_thresh, 0.01),
            0.0, 1.0
        ).astype(_np.float32)
        hi_mask = _gf(hi_mask, sigma=blur_radius).astype(_np.float32)
        r_out = _np.clip(r_out + hi_mask * highlight_ivory * 1.00, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * highlight_ivory * 0.58, 0.0, 1.0)
        b_out = _np.clip(b_out - hi_mask * highlight_ivory * 0.30, 0.0, 1.0)

        # ── 5. Composite at opacity ────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Poussin classical clarity pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    def rigaud_velvet_drapery_pass(
        self,
        *,
        velvet_thresh: float    = 0.30,
        velvet_dark:   float    = 0.12,
        velvet_warm_r: float    = 0.08,
        velvet_warm_g: float    = 0.04,
        silk_thresh:   float    = 0.65,
        silk_cool_b:   float    = 0.10,
        silk_cool_r:   float    = 0.04,
        skin_r_lo:     float    = 0.45,
        skin_r_hi:     float    = 0.85,
        skin_g_lo:     float    = 0.32,
        skin_g_hi:     float    = 0.75,
        skin_b_hi:     float    = 0.65,
        blur_radius:   float    = 5.0,
        opacity:       float    = 0.55,
    ) -> None:
        """
        Hyacinthe Rigaud's defining material quality: deep velvet darkness
        with warm chestnut mid-tones and cool silk specular highlights.

        Rigaud was the master of court portraiture at Versailles (1690–1740)
        and his technical signature is the convincing illusion of sumptuous
        fabrics — particularly deep velvet and shimmering silk.  These two
        materials are chromatic opposites: velvet absorbs light into near-black
        warmth, while silk reflects it as cool, silvery brightness.  The tension
        between them creates the opulent material presence of his portraits.

        This pass models that duality in three operations:

        1. **Velvet void deepening** — dark, non-skin pixels (lum < velvet_thresh)
           are pushed toward near-black while preserving warm chestnut undertone:
           luminance is reduced, R channel stays relatively elevated (warm), B is
           suppressed.  This makes velvet shadows recede into a rich, warm darkness
           rather than a cold dead black.  Feathered with Gaussian so the transition
           from lit to shadowed velvet fold is not abrupt.

        2. **Silk specular sheen** — bright, non-skin pixels (lum > silk_thresh)
           receive a cool silvery push: B↑, R slightly↓.  This is the cool shimmer
           of light striking silk at an angle — the chromatic opposite of warm flesh
           and warm velvet.  The cool highlight makes silk appear to float above the
           surrounding velvet darkness.  Feathered so the highlight transitions
           smoothly into the mid-tone fabric.

        3. **Composite at opacity** — both effects are blended at the specified
           opacity, allowing the underlying painted surface to remain dominant.

        Parameters:
            velvet_thresh   Luminance ceiling for velvet shadow pixels [0–1].
            velvet_dark     Strength of the velvet shadow deepening push.
            velvet_warm_r   R-channel warm undertone boost in velvet voids.
            velvet_warm_g   G-channel slight warmth boost in velvet voids.
            silk_thresh     Luminance floor for silk highlight pixels [0–1].
            silk_cool_b     B-channel cool boost on silk highlights.
            silk_cool_r     R-channel reduction on silk highlights (coolness).
            skin_r_lo/hi    R-channel range that characterises skin pixels (excluded).
            skin_g_lo/hi    G-channel range that characterises skin pixels (excluded).
            skin_b_hi       B-channel ceiling that characterises skin pixels (excluded).
            blur_radius     Gaussian feathering radius for mask transitions.
            opacity         Final blend opacity of the combined pass [0–1].
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        w_px    = surface.get_width()
        h_px    = surface.get_height()

        orig = _np.frombuffer(
            surface.get_data(), dtype=_np.uint8
        ).reshape((h_px, w_px, 4)).copy()

        # Read channels as float32 in [0, 1] (cairo: BGRA byte order)
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Skin mask (exclude skin pixels from fabric operations) ────────────
        # Skin has warm R, moderate G, lower B — we protect these from the
        # velvet deepening and silk cooling operations.
        skin_mask = (
            (r0 >= skin_r_lo) & (r0 <= skin_r_hi) &
            (g0 >= skin_g_lo) & (g0 <= skin_g_hi) &
            (b0 <= skin_b_hi)
        ).astype(_np.float32)
        # Feather the skin mask so the boundary is not harsh
        skin_mask = _gf(skin_mask, sigma=blur_radius * 1.5).astype(_np.float32)
        non_skin = (1.0 - skin_mask).astype(_np.float32)

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── 1. Velvet void deepening ──────────────────────────────────────────
        # Dark pixels in non-skin areas are pushed toward warm near-black.
        # The warmth (R > B in the void) distinguishes Rigaud velvet from cold
        # modern fabric rendering — there is always a chestnut undertone.
        v_raw = _np.clip(
            (velvet_thresh - lum) / max(velvet_thresh, 0.01),
            0.0, 1.0
        ).astype(_np.float32)
        v_mask = _gf(v_raw, sigma=blur_radius).astype(_np.float32) * non_skin

        # Darken all channels, but preserve/add warm chestnut R undertone
        r_out = _np.clip(r_out - v_mask * (velvet_dark - velvet_warm_r), 0.0, 1.0)
        g_out = _np.clip(g_out - v_mask * (velvet_dark - velvet_warm_g), 0.0, 1.0)
        b_out = _np.clip(b_out - v_mask * velvet_dark, 0.0, 1.0)

        # ── 2. Silk specular sheen ────────────────────────────────────────────
        # Bright pixels in non-skin areas receive a cool silvery push.
        # B↑ (most), R↓ — silk highlights are cooler than the warm flesh
        # around them, creating the characteristic visual contrast of
        # Rigaud's portraits between warm sitter and cool drapery highlights.
        s_raw = _np.clip(
            (lum - silk_thresh) / max(1.0 - silk_thresh, 0.01),
            0.0, 1.0
        ).astype(_np.float32)
        s_mask = _gf(s_raw, sigma=blur_radius).astype(_np.float32) * non_skin

        r_out = _np.clip(r_out - s_mask * silk_cool_r, 0.0, 1.0)
        b_out = _np.clip(b_out + s_mask * silk_cool_b, 0.0, 1.0)

        # ── 3. Composite at opacity ───────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Rigaud velvet drapery pass complete.")

    def lotto_chromatic_anxiety_pass(
        self,
        *,
        flesh_mid_lo:      float = 0.42,
        flesh_mid_hi:      float = 0.72,
        cool_b_boost:      float = 0.06,
        cool_r_reduce:     float = 0.04,
        eye_left_cx:       float = 0.38,
        eye_left_cy:       float = 0.38,
        eye_right_cx:      float = 0.62,
        eye_right_cy:      float = 0.38,
        eye_rx:            float = 0.07,
        eye_ry:            float = 0.04,
        eye_contrast:      float = 0.12,
        eye_cool_b:        float = 0.05,
        eye_cool_r:        float = 0.03,
        bg_mid_lo:         float = 0.28,
        bg_mid_hi:         float = 0.68,
        bg_green_lift:     float = 0.05,
        bg_blue_lift:      float = 0.03,
        skin_r_lo:         float = 0.45,
        skin_r_hi:         float = 0.88,
        skin_g_lo:         float = 0.30,
        skin_g_hi:         float = 0.78,
        skin_b_hi:         float = 0.68,
        blur_radius:       float = 4.0,
        opacity:           float = 0.48,
    ) -> None:
        """
        Lorenzo Lotto chromatic anxiety pass (session 79).

        Models Lotto chief psychological quality: cool undertone injection
        beneath Venetian warmth. Three operations:
        1. Cool flesh midtone injection -- skin midtone pixels: B up, R down.
        2. Eye-region chromatic intensification -- contrast boost + cool shadow
           shift in two eye ellipses.
        3. Background color dissonance -- non-skin midtone bg: G up, B up
           (cool muted green + grey-blue background discord).

        Parameters:
            flesh_mid_lo/hi    Luminance band for flesh midtone injection.
            cool_b_boost       B-channel boost in flesh midtones.
            cool_r_reduce      R-channel reduction in flesh midtones.
            eye_left/right_cx  Eye centre x as fraction of canvas width.
            eye_left/right_cy  Eye centre y as fraction of canvas height.
            eye_rx / eye_ry    Eye ellipse radii as fractions of width/height.
            eye_contrast       Local contrast stretch in eye zones.
            eye_cool_b/r       Cool shadow push within eye ellipses.
            bg_mid_lo/hi       Luminance band for background dissonance.
            bg_green_lift      G-channel lift in background midtones.
            bg_blue_lift       B-channel lift in background midtones.
            skin_r/g/b_*       Skin detection channel ranges.
            blur_radius        Gaussian feathering radius.
            opacity            Final blend opacity [0-1].
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        w_px    = surface.get_width()
        h_px    = surface.get_height()

        orig = _np.frombuffer(
            surface.get_data(), dtype=_np.uint8
        ).reshape((h_px, w_px, 4)).copy()

        # cairo BGRA byte order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        lum = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # Skin mask
        skin_raw = (
            (r0 >= skin_r_lo) & (r0 <= skin_r_hi) &
            (g0 >= skin_g_lo) & (g0 <= skin_g_hi) &
            (b0 <= skin_b_hi)
        ).astype(_np.float32)
        skin_mask = _gf(skin_raw, sigma=blur_radius * 1.5).astype(_np.float32)
        non_skin  = _np.clip(1.0 - skin_mask, 0.0, 1.0)

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # 1. Cool flesh midtone injection
        band_span = max(flesh_mid_hi - flesh_mid_lo, 0.01)
        flesh_band = _np.clip(
            _np.minimum(
                (lum - flesh_mid_lo) / band_span,
                (flesh_mid_hi - lum) / band_span,
            ) * 2.0,
            0.0, 1.0
        ).astype(_np.float32)
        flesh_mask = _gf(flesh_band * skin_mask, sigma=blur_radius).astype(_np.float32)
        r_out = _np.clip(r_out - flesh_mask * cool_r_reduce, 0.0, 1.0)
        b_out = _np.clip(b_out + flesh_mask * cool_b_boost,  0.0, 1.0)

        # 2. Eye-region chromatic intensification
        ys = _np.linspace(0.0, 1.0, h_px, dtype=_np.float32)[:, _np.newaxis]
        xs = _np.linspace(0.0, 1.0, w_px, dtype=_np.float32)[_np.newaxis, :]
        for (ecx, ecy) in [(eye_left_cx, eye_left_cy), (eye_right_cx, eye_right_cy)]:
            dist_sq = ((xs - ecx) / max(eye_rx, 0.001)) ** 2 +                       ((ys - ecy) / max(eye_ry, 0.001)) ** 2
            eye_raw  = _np.clip(1.0 - dist_sq, 0.0, 1.0).astype(_np.float32)
            eye_zone = _gf(eye_raw, sigma=blur_radius * 0.8).astype(_np.float32)
            delta = lum - 0.5
            r_out = _np.clip(r_out + eye_zone * delta * eye_contrast, 0.0, 1.0)
            g_out = _np.clip(g_out + eye_zone * delta * eye_contrast, 0.0, 1.0)
            b_out = _np.clip(b_out + eye_zone * delta * eye_contrast, 0.0, 1.0)
            shadow_half = _np.clip(0.5 - lum, 0.0, 0.5) * 2.0
            r_out = _np.clip(r_out - eye_zone * shadow_half * eye_cool_r, 0.0, 1.0)
            b_out = _np.clip(b_out + eye_zone * shadow_half * eye_cool_b, 0.0, 1.0)

        # 3. Background color dissonance
        bg_span = max(bg_mid_hi - bg_mid_lo, 0.01)
        bg_band = _np.clip(
            _np.minimum(
                (lum - bg_mid_lo) / bg_span,
                (bg_mid_hi - lum) / bg_span,
            ) * 2.0,
            0.0, 1.0
        ).astype(_np.float32)
        bg_mask = _gf(bg_band * non_skin, sigma=blur_radius).astype(_np.float32)
        g_out = _np.clip(g_out + bg_mask * bg_green_lift, 0.0, 1.0)
        b_out = _np.clip(b_out + bg_mask * bg_blue_lift,  0.0, 1.0)

        # 4. Composite at opacity
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Lotto chromatic anxiety pass complete.")

    # Session 80 — New artist: Andrea del Sarto golden sfumato pass
    # ─────────────────────────────────────────────────────────────────────────

    def andrea_del_sarto_golden_sfumato_pass(
        self,
        flesh_mid_lo:     float = 0.45,   # lower luminance bound of the midtone bloom zone
        flesh_mid_hi:     float = 0.80,   # upper luminance bound of the midtone bloom zone
        gold_r_boost:     float = 0.05,   # R-channel boost for amber warmth in midtones
        gold_g_boost:     float = 0.028,  # G-channel boost — keeps it ivory-gold, not orange
        sfumato_blur:     float = 5.5,    # Gaussian radius for edge-transition zone softening
        edge_grad_lo:     float = 0.06,   # gradient magnitude floor (no softening below)
        edge_grad_hi:     float = 0.22,   # gradient magnitude ceiling (full softening above)
        harmony_sat_cap:  float = 0.85,   # saturation cap above which harmony pull activates
        harmony_pull:     float = 0.055,  # desaturation strength toward warm palette centre
        skin_r_lo:        float = 0.44,
        skin_r_hi:        float = 0.92,
        skin_g_lo:        float = 0.28,
        skin_g_hi:        float = 0.84,
        skin_b_hi:        float = 0.74,
        blur_radius:      float = 5.0,
        opacity:          float = 0.46,
    ) -> None:
        """
        Apply Andrea del Sarto's defining painterly quality: warm golden sfumato.

        Del Sarto (1486–1530) was called 'il pittore sanza errori' — the faultless
        painter — by Vasari for the seamless, inevitable quality of his tonal
        transitions.  His skin tones move from warm ivory highlight through golden
        midtone to warm umber shadow without any visible seam or temperature break,
        a quality quite distinct from the cool dissolution of Leonardo's sfumato or
        the warm-orange vitality of Rubens.

        Three operations:

        1. **Golden midtone warmth** — pixels with luminance in [flesh_mid_lo,
           flesh_mid_hi] receive a warm amber push (R+ strongly, G+ modestly, B
           unchanged).  The ratio R:G ≈ 1.8:1 produces the ivory-gold characteristic
           of his flesh — warm but never orange.  A tent mask peaking at the midpoint
           of the band concentrates the push at the true midtone rather than at
           highlights or shadows.

        2. **Sfumato edge feathering** — form boundaries (detected via luminance
           gradient magnitude) receive an additional Gaussian blur pass weighted by
           the gradient.  This dissolves the hard edges that accumulate across
           successive painting passes into del Sarto's atmospheric transitions.
           The gradient-weighted approach ensures only actual edges are softened;
           the smooth interior of well-blended zones is left undisturbed.

        3. **Colour harmony pull** — pixels whose per-channel saturation exceeds
           harmony_sat_cap are mildly desaturated toward the warm centre of the del
           Sarto palette.  This prevents chromatic outliers left by preceding passes
           (e.g. vivid cool accents from Lotto or Poussin passes) from fighting the
           warm Florentine register.  The pull is gentle (harmony_pull ≈ 0.055) and
           operates only above the saturation cap to preserve normal variation.

        Parameters
        ----------
        flesh_mid_lo     : lower luminance boundary of the midtone bloom zone
        flesh_mid_hi     : upper luminance boundary of the midtone bloom zone
        gold_r_boost     : R-channel boost for the amber warmth component
        gold_g_boost     : G-channel boost for the yellow-gold component
        sfumato_blur     : Gaussian sigma for edge-zone softening
        edge_grad_lo     : gradient magnitude below which no softening applies
        edge_grad_hi     : gradient magnitude above which maximum softening applies
        harmony_sat_cap  : saturation cap above which harmony pull engages
        harmony_pull     : desaturation strength toward warm palette centre
        skin_r_lo/hi     : skin detection R-channel range
        skin_g_lo/hi     : skin detection G-channel range
        skin_b_hi        : skin detection B-channel ceiling
        blur_radius      : Gaussian sigma for skin mask feathering
        opacity          : overall blend weight
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Andrea del Sarto golden sfumato pass "
              f"(gold_r={gold_r_boost:.3f}  gold_g={gold_g_boost:.3f}  "
              f"sfumato_blur={sfumato_blur:.1f}  harmony={harmony_pull:.3f}  "
              f"lum=[{flesh_mid_lo:.2f},{flesh_mid_hi:.2f}]  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Andrea del Sarto golden sfumato pass skipped (opacity=0)")
            return

        h_px, w_px = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h_px, w_px, 4)).copy()
        orig = buf.copy()

        # cairo BGRA → float RGB
        b0 = buf[:, :, 0].astype(_np.float32) / 255.0
        g0 = buf[:, :, 1].astype(_np.float32) / 255.0
        r0 = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── 1. Golden midtone warmth ──────────────────────────────────────────
        # Tent mask peaking at the midpoint of [flesh_mid_lo, flesh_mid_hi]
        mid_c = (flesh_mid_lo + flesh_mid_hi) * 0.5
        mid_h = max((flesh_mid_hi - flesh_mid_lo) * 0.5, 1e-8)
        midtone_mask = _np.clip(1.0 - _np.abs(lum - mid_c) / mid_h, 0.0, 1.0)

        # Skin mask — limit warmth injection to flesh areas
        skin_raw = (
            (r0 >= skin_r_lo) & (r0 <= skin_r_hi) &
            (g0 >= skin_g_lo) & (g0 <= skin_g_hi) &
            (b0 <= skin_b_hi)
        ).astype(_np.float32)
        skin_mask = _gf(skin_raw, sigma=blur_radius * 1.2).astype(_np.float32)

        gold_mask = (midtone_mask * skin_mask).astype(_np.float32)
        gold_w = gold_mask * opacity
        r_out = _np.clip(r_out + gold_w * gold_r_boost, 0.0, 1.0)
        g_out = _np.clip(g_out + gold_w * gold_g_boost, 0.0, 1.0)

        # ── 2. Sfumato edge feathering ────────────────────────────────────────
        # Detect edge zones via luminance gradient magnitude
        lum_smooth = _gf(lum, sigma=1.2)
        grad_x = _np.gradient(lum_smooth, axis=1).astype(_np.float32)
        grad_y = _np.gradient(lum_smooth, axis=0).astype(_np.float32)
        grad_mag = _np.sqrt(grad_x ** 2 + grad_y ** 2).astype(_np.float32)

        # Map gradient magnitude to [0,1] softening weight
        edge_span = max(edge_grad_hi - edge_grad_lo, 1e-8)
        edge_weight = _np.clip(
            (grad_mag - edge_grad_lo) / edge_span, 0.0, 1.0
        ).astype(_np.float32)

        # Blur each channel and blend into edge zones
        r_blurred = _gf(r_out, sigma=sfumato_blur).astype(_np.float32)
        g_blurred = _gf(g_out, sigma=sfumato_blur).astype(_np.float32)
        b_blurred = _gf(b_out, sigma=sfumato_blur).astype(_np.float32)

        blend_w = edge_weight * opacity * 0.55   # partial blend — del Sarto keeps form clarity
        r_out = r_out * (1.0 - blend_w) + r_blurred * blend_w
        g_out = g_out * (1.0 - blend_w) + g_blurred * blend_w
        b_out = b_out * (1.0 - blend_w) + b_blurred * blend_w

        # ── 3. Colour harmony pull ────────────────────────────────────────────
        # Compute per-pixel saturation (max - min of RGB)
        ch_max = _np.maximum(_np.maximum(r_out, g_out), b_out)
        ch_min = _np.minimum(_np.minimum(r_out, g_out), b_out)
        sat = (ch_max - ch_min).astype(_np.float32)

        # Warm palette centre (del Sarto's characteristic amber-ivory midtone)
        warm_r, warm_g, warm_b = 0.82, 0.72, 0.55

        # Pull saturated pixels toward the warm centre
        over_cap = _np.clip((sat - harmony_sat_cap) / max(1.0 - harmony_sat_cap, 1e-8),
                            0.0, 1.0).astype(_np.float32)
        pull_w = over_cap * harmony_pull * opacity
        r_out = _np.clip(r_out + pull_w * (warm_r - r_out), 0.0, 1.0)
        g_out = _np.clip(g_out + pull_w * (warm_g - g_out), 0.0, 1.0)
        b_out = _np.clip(b_out + pull_w * (warm_b - b_out), 0.0, 1.0)

        # ── 4. Composite at opacity ───────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Andrea del Sarto golden sfumato pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # chardin_granular_intimacy_pass — Chardin's quiet optical texture
    # ─────────────────────────────────────────────────────────────────────────

    def chardin_granular_intimacy_pass(
        self,
        dab_radius:      float = 3.5,    # neighbourhood radius for color sampling (pixels)
        dab_density:     float = 0.55,   # fraction of pixels receiving a dab (0–1)
        mute_strength:   float = 0.20,   # pull strength toward warm-gray center (0–1)
        lum_cap:         float = 0.86,   # luminance ceiling — suppress harsh specular peaks
        lum_cap_str:     float = 0.30,   # strength of luminance cap compression
        warm_gray_r:     float = 0.68,   # warm-gray palette center R
        warm_gray_g:     float = 0.64,   # warm-gray palette center G
        warm_gray_b:     float = 0.54,   # warm-gray palette center B
        opacity:         float = 0.38,   # overall blend weight (keep low; effect accumulates)
        rng_seed:        int   = 42,
    ) -> None:
        """
        Jean-Baptiste-Siméon Chardin's defining optical intimacy: granular atmospheric texture.

        Chardin (1699–1779) was the supreme master of the quiet domestic painting — still
        lifes, kitchen scenes, gentle genre interiors — and his technique is as distinctive
        as Leonardo's sfumato: he built up surfaces from small individual dabs of slightly
        varied colour placed side by side, allowing the optical mixing to happen on the
        retina rather than on the palette.  Diderot, the great Enlightenment critic, described
        the effect as a 'magic' he could not explain — 'approach the picture and everything
        blurs and flattens out; step back and everything reconstitutes and comes back to
        life.'  This is the principle of optical granulation as opposed to blended sfumato.

        Three operations:

        1. **Granular dab layer** — for ``dab_density`` fraction of pixels, the colour is
           resampled from a small neighbourhood (radius ``dab_radius``) with slight random
           offset.  This scatters the paint surface into slightly varied micro-touches without
           importing new colour from outside the painting — the variation comes from the
           existing surface texture being redistributed.  The result is a warm, dusty optical
           grain.  Unlike Seurat's systematic divisionism, Chardin's granulation is random and
           asymmetric, resembling aged canvas texture more than a colour theory exercise.

        2. **Atmospheric muting** — pixels whose per-channel saturation exceeds a low threshold
           are gently pulled toward the warm-gray center of Chardin's palette
           (R=``warm_gray_r``, G=``warm_gray_g``, B=``warm_gray_b``).  Chardin's palette is
           muted not because his subjects are dull but because he understood that the eye
           naturally desaturates texture-rich surfaces — the granulation itself reads as
           'colour' without requiring high chroma.  The muting pull is soft (``mute_strength``
           ≈ 0.20) so it adjusts rather than flattens.

        3. **Luminance cap** — pixels above ``lum_cap`` luminance receive a gentle brightness
           compression toward the cap value.  Chardin's paintings have no blazing highlights —
           the most-lit surfaces read as warm ivory, never brilliant white.  This intimate
           restraint is essential: it is what makes his candlelit kitchen interiors feel warm
           and inhabited rather than theatrical.  The cap is soft (``lum_cap_str`` ≈ 0.30)
           so true highlights are reduced but not eliminated.

        Parameters
        ----------
        dab_radius    : Pixel radius of the neighborhood sampled for each granular dab.
                        Smaller values → finer grain; larger values → coarser atmospheric
                        texture.  3.5 px corresponds roughly to one bristle-width at
                        typical portrait scale.
        dab_density   : Fraction of canvas pixels that receive a granular dab.  0.55 means
                        roughly every other pixel is touched.  Avoid values > 0.80 as the
                        result becomes uniformly blurred.
        mute_strength : How strongly oversaturated pixels are pulled toward the warm-gray
                        center.  0.20 is barely perceptible per pass but accumulates across
                        repeated applications.
        lum_cap       : Luminance ceiling above which highlights are compressed.  0.86
                        retains warm ivory highlights while suppressing specular blazing.
        lum_cap_str   : Softness of the luminance compression.  0 = no compression;
                        1 = hard clip to lum_cap.  Keep at 0.25–0.35 for Chardin's quiet
                        restraint.
        warm_gray_r/g/b : RGB values of the warm-gray palette center.  The default
                        (0.68, 0.64, 0.54) matches Chardin's characteristic warm ochre-gray
                        midtone as observed across his mature still-life work.
        opacity       : Global blend weight.  Keep in [0.25, 0.50] — the granular effect is
                        meant to be subtle.  Multiple passes accumulate convincingly.
        rng_seed      : Random seed for reproducible granulation pattern.

        Notes
        -----
        Chardin's technique was so subtle that contemporaries believed he used a secret medium.
        Analysis of his paint layers (Louvre, 2000) revealed no unusual medium — the effect
        comes entirely from how and where small dabs of standard oil paint are placed.

        The pass can be applied multiple times at low opacity to build up the granular
        atmosphere incrementally, as Chardin himself applied his paint in patient sessions.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Chardin granular intimacy pass  "
              f"(dab_r={dab_radius:.1f}  density={dab_density:.2f}  "
              f"mute={mute_strength:.2f}  lum_cap={lum_cap:.2f}  "
              f"opacity={opacity:.2f})…")

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo stores BGRA — extract float channels
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        b_out = b0.copy()
        g_out = g0.copy()
        r_out = r0.copy()

        # ── 1. Granular dab layer ─────────────────────────────────────────────
        # For a random subset of pixels, resample colour from a small neighbourhood.
        # This redistributes existing paint texture into Chardin's optical grain.
        rng = _np.random.default_rng(rng_seed)
        h, w = self.h, self.w

        # Build padded reference arrays for safe neighbourhood access
        pad = max(1, int(_np.ceil(dab_radius)))
        r_pad = _np.pad(r0, pad, mode='reflect')
        g_pad = _np.pad(g0, pad, mode='reflect')
        b_pad = _np.pad(b0, pad, mode='reflect')

        # Pixel indices that receive a dab
        n_dabs = int(h * w * dab_density)
        ys = rng.integers(0, h, size=n_dabs)
        xs = rng.integers(0, w, size=n_dabs)

        # Random offsets within dab_radius (disk sampling)
        angles = rng.uniform(0, 2 * _np.pi, size=n_dabs)
        radii  = rng.uniform(0, dab_radius, size=n_dabs)
        dy = (_np.round(radii * _np.sin(angles))).astype(int)
        dx = (_np.round(radii * _np.cos(angles))).astype(int)

        # Sample from padded arrays (pad shifts coords by `pad`)
        sy = _np.clip(ys + dy + pad, 0, h + 2 * pad - 1)
        sx = _np.clip(xs + dx + pad, 0, w + 2 * pad - 1)

        r_out[ys, xs] = r_pad[sy, sx]
        g_out[ys, xs] = g_pad[sy, sx]
        b_out[ys, xs] = b_pad[sy, sx]

        # Light Gaussian smooth to prevent pure noise from the scatter
        # (Chardin's dabs merge at their edges — they are not isolated dots)
        r_out = _gf(r_out, sigma=0.7).astype(_np.float32)
        g_out = _gf(g_out, sigma=0.7).astype(_np.float32)
        b_out = _gf(b_out, sigma=0.7).astype(_np.float32)

        # ── 2. Atmospheric muting pull toward warm-gray center ────────────────
        # Per-channel saturation (max-min of RGB)
        ch_max = _np.maximum(_np.maximum(r_out, g_out), b_out)
        ch_min = _np.minimum(_np.minimum(r_out, g_out), b_out)
        sat = (ch_max - ch_min).astype(_np.float32)

        # Pull oversaturated pixels toward warm gray (Chardin's muted register)
        # Use a gentle linear weight so even moderately saturated pixels get a nudge
        pull_w = _np.clip(sat * mute_strength, 0.0, mute_strength).astype(_np.float32)
        r_out = r_out * (1.0 - pull_w) + warm_gray_r * pull_w
        g_out = g_out * (1.0 - pull_w) + warm_gray_g * pull_w
        b_out = b_out * (1.0 - pull_w) + warm_gray_b * pull_w

        # ── 3. Luminance cap — quiet the specular peaks ───────────────────────
        # Chardin's highlights are restrained warm ivory, never blazing white.
        lum = 0.2126 * r_out + 0.7152 * g_out + 0.0722 * b_out
        over_cap = _np.clip((lum - lum_cap) / max(1.0 - lum_cap, 1e-8),
                            0.0, 1.0).astype(_np.float32)
        cap_w = over_cap * lum_cap_str
        # Compress toward lum_cap by desaturating and darkening slightly
        r_out = _np.clip(r_out - cap_w * (r_out - warm_gray_r * lum_cap), 0.0, 1.0)
        g_out = _np.clip(g_out - cap_w * (g_out - warm_gray_g * lum_cap), 0.0, 1.0)
        b_out = _np.clip(b_out - cap_w * (b_out - warm_gray_b * lum_cap), 0.0, 1.0)

        # ── 4. Composite at opacity ───────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Chardin granular intimacy pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # gericault_romantic_turbulence_pass — Géricault's Romantic chiaroscuro
    # ─────────────────────────────────────────────────────────────────────────

    def gericault_romantic_turbulence_pass(
        self,
        shadow_thresh:     float = 0.32,   # luminance below which shadow warmth is applied
        shadow_warm_r:     float = 0.14,   # R boost in deep shadows (toward warm umber)
        shadow_warm_g:     float = 0.05,   # G tiny boost in deep shadows
        shadow_cool_b:     float = 0.12,   # B reduction in deep shadows (remove cool cast)
        turb_low:          float = 0.30,   # luminance range low for turbulent highlight zone
        turb_high:         float = 0.68,   # luminance range high for turbulent highlight zone
        turb_strength:     float = 0.055,  # magnitude of directional luminance variance
        turb_frequency:    float = 8.0,    # spatial frequency of turbulent pattern (cycles)
        contrast_midpoint: float = 0.48,   # sigmoid midpoint for dramatic contrast curve
        contrast_gain:     float = 3.5,    # sigmoid steepness — higher = more dramatic
        contrast_strength: float = 0.14,   # blend weight of contrast tone curve
        opacity:           float = 0.44,   # global blend weight
        rng_seed:          int   = 82,
    ) -> None:
        """
        Théodore Géricault's defining chromatic and tonal signature: Romantic turbulence.

        Géricault (1791–1824) was the founding voice of French Romanticism, and his
        paintings are immediately recognisable by their concentrated dramatic power.  Where
        Neoclassicism sought cool rational clarity and polished academic surfaces, Géricault
        pursued raw emotional force: the unbridled energy of horses, the horror of the Raft
        of the Medusa, the interior life of the insane.  His technical signature has three
        interlocking components that this pass replicates:

        1. **Warm shadow depth enrichment** — Géricault began on a dark warm ground
           (burnt umber + ivory black) and never allowed his deep shadows to cool.
           Multispectral analysis of *The Raft of the Medusa* (Louvre) confirms that
           the near-black passages retain a warm red-umber cast throughout — a sharp
           contrast with the cool-grey darks of Ingres or Poussin.  This pass pushes
           all pixels below ``shadow_thresh`` luminance toward warm near-black by
           boosting R slightly, boosting G very slightly (for umber warmth), and
           reducing B (to remove any cool residual from prior blue-push passes).

        2. **Turbulent highlight striations** — Géricault applied thick impasto with
           vigorous directional marks; the ridges of paint catch storm light and create
           a turbulent luminance variance across the mid-tone zone.  This pass
           introduces a sinusoidal directional modulation in the luminance of pixels
           within the mid-tone range (``turb_low``–``turb_high``), simulating the
           light-catching quality of impasto ridges without modifying the colour
           direction.  The pattern is rotated at ~35° to simulate the characteristic
           Géricault diagonal mark direction.

        3. **Dramatic sigmoid contrast intensification** — A soft sigmoid tone curve
           is applied globally to compress the near-white highlights and deepen the
           near-black shadows, sharpening the zone of maximum drama (the transition
           between light and dark).  This is the tonal key of Géricault's paintings:
           the near-black void against the sudden warm eruption of light.  The curve
           is blended at ``contrast_strength`` to preserve the existing tonal range
           while shifting it toward higher drama.

        Parameters
        ----------
        shadow_thresh    : Luminance below which shadow warm recovery is applied.
                           0.32 covers the full dark zone; lower values target only
                           the deepest passages.
        shadow_warm_r    : R channel boost in shadow zone.  Keep below 0.18 —
                           Géricault's shadows are warm but not orange.
        shadow_warm_g    : G channel tiny boost (contributes umber warmth).
        shadow_cool_b    : B channel reduction.  0.12 removes a full cool-grey cast
                           without introducing warmth artifact.
        turb_low/high    : Luminance range of the turbulent impasto zone.
                           [0.30, 0.68] covers the dramatic mid-tone transition band.
        turb_strength    : Magnitude of the sinusoidal luminance modulation.
                           0.055 is barely perceptible per pixel but reads as
                           surface texture across the mid-tone zone.
        turb_frequency   : Spatial cycles of the turbulent pattern.  8 cycles
                           at portrait scale produces ~10px wavelength — matching
                           a thick impasto ridge width.
        contrast_midpoint: Sigmoid inflection point.  0.48 places the maximum
                           contrast gain in the dark-to-mid transition — where
                           Géricault's drama lives.
        contrast_gain    : Sigmoid steepness.  3.5 produces a moderately dramatic
                           S-curve; values above 6 produce hard tonal compression.
        contrast_strength: Blend weight of the contrast tone curve.  0.14 is
                           a strong but not overwhelming contribution.
        opacity          : Global blend weight for the entire pass.  0.44 is the
                           recommended value for portrait use — the dramatic
                           pressure is present but does not override the figure's
                           existing character.
        rng_seed         : RNG seed (unused in this pass; reserved for future use).

        Notes
        -----
        Géricault died at 32, leaving fewer than 200 paintings.  His influence on
        Delacroix, Courbet, and through them the entire tradition of Realism and
        Impressionism is immeasurable.  His Portraits of the Insane (c. 1819–22)
        — painted as psychological studies for Dr. Georget at the Salpêtrière —
        are considered the first portraits to treat the mentally ill as fully
        human subjects, not objects of curiosity.  Each of the ten known portraits
        shows the same technical signature: warm near-black void, sudden warm
        highlight, thick directional impasto.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Géricault romantic turbulence pass  "
              f"(shadow_thresh={shadow_thresh:.2f}  turb_str={turb_strength:.3f}  "
              f"contrast_gain={contrast_gain:.1f}  opacity={opacity:.2f})…")

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        b_out = b0.copy()
        g_out = g0.copy()
        r_out = r0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Warm shadow depth enrichment ──────────────────────────────────
        # Push deep shadow pixels toward warm near-black (umber, not cool grey).
        # Shadow mask fades from full at lum=0.0 to zero at shadow_thresh.
        shad_mask = _np.clip(1.0 - lum / max(shadow_thresh, 1e-6), 0.0, 1.0)
        r_out = _np.clip(r_out + shad_mask * shadow_warm_r,  0.0, 1.0)
        g_out = _np.clip(g_out + shad_mask * shadow_warm_g,  0.0, 1.0)
        b_out = _np.clip(b_out - shad_mask * shadow_cool_b,  0.0, 1.0)

        # ── 2. Turbulent highlight striations ────────────────────────────────
        # Build a sinusoidal directional pattern at ~35° to simulate impasto
        # ridges catching storm light.  The modulation is applied only in the
        # mid-tone zone (turb_low–turb_high) and affects luminance uniformly
        # across all channels (pure tonal modulation, no colour shift).
        h, w = self.h, self.w
        ys, xs = _np.mgrid[0:h, 0:w].astype(_np.float32)
        # Rotate coordinate for directional brushstroke pattern (~35°)
        angle   = _np.deg2rad(35.0)
        cos_a, sin_a = _np.cos(angle), _np.sin(angle)
        rot_x   = xs * cos_a - ys * sin_a
        # Normalise to [0, 2π] over turb_frequency cycles
        phase   = (rot_x / w) * turb_frequency * 2.0 * _np.pi
        turb    = _np.sin(phase).astype(_np.float32) * turb_strength

        # Gate turbulence to mid-tone zone only
        turb_mask = _np.clip(
            _np.minimum(
                (lum - turb_low)  / max(turb_high - turb_low, 1e-6),
                (turb_high - lum) / max(turb_high - turb_low, 1e-6),
            ) * 2.0, 0.0, 1.0
        )
        turb_weighted = turb * turb_mask
        r_out = _np.clip(r_out + turb_weighted, 0.0, 1.0)
        g_out = _np.clip(g_out + turb_weighted, 0.0, 1.0)
        b_out = _np.clip(b_out + turb_weighted, 0.0, 1.0)

        # ── 3. Dramatic sigmoid contrast intensification ──────────────────────
        # Apply a soft S-curve: compresses near-whites and deepens near-blacks,
        # concentrating drama at the light-dark transition zone.
        # Sigmoid: s(x) = 1 / (1 + exp(-gain * (x - midpoint)))
        # Normalised so midpoint maps to midpoint (no DC shift).
        def _sigmoid_curve(x: _np.ndarray) -> _np.ndarray:
            """Normalised sigmoid that maps midpoint→midpoint."""
            raw = 1.0 / (1.0 + _np.exp(-contrast_gain * (x - contrast_midpoint)))
            # Normalise so x=0→0 and x=1→1 approximately (subtract offset, rescale)
            raw_at_0 = 1.0 / (1.0 + _np.exp(-contrast_gain * (0.0 - contrast_midpoint)))
            raw_at_1 = 1.0 / (1.0 + _np.exp(-contrast_gain * (1.0 - contrast_midpoint)))
            return (raw - raw_at_0) / max(raw_at_1 - raw_at_0, 1e-9)

        r_curved = _sigmoid_curve(r_out)
        g_curved = _sigmoid_curve(g_out)
        b_curved = _sigmoid_curve(b_out)

        r_out = _np.clip(r_out * (1.0 - contrast_strength) + r_curved * contrast_strength,
                         0.0, 1.0)
        g_out = _np.clip(g_out * (1.0 - contrast_strength) + g_curved * contrast_strength,
                         0.0, 1.0)
        b_out = _np.clip(b_out * (1.0 - contrast_strength) + b_curved * contrast_strength,
                         0.0, 1.0)

        # ── 4. Composite at opacity ───────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Géricault romantic turbulence pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 83 — Fra Filippo Lippi tenerezza pass
    # ─────────────────────────────────────────────────────────────────────────

    def fra_filippo_lippi_tenerezza_pass(
        self,
        flesh_mid_lo:       float = 0.42,   # luminance low bound of flesh midtone zone
        flesh_mid_hi:       float = 0.80,   # luminance high bound of flesh midtone zone
        rose_r_boost:       float = 0.048,  # R boost in flesh midtones (toward rose-ivory)
        rose_g_boost:       float = 0.018,  # G tiny boost (keeps the warm pink, not orange)
        rose_b_dampen:      float = 0.028,  # B slight reduction in flesh midtones
        glow_thresh:        float = 0.72,   # luminance above which interior glow is applied
        glow_lift:          float = 0.040,  # warm ivory lift in the highest flesh passages
        glow_blur:          float = 8.0,    # blur radius for the interior glow softening
        bg_cool_shift:      float = 0.022,  # B push in background (luminance < 0.48) to
        #                                    separate figure from ground
        bg_desaturate:      float = 0.12,   # desaturation amount in background passages
        bg_thresh:          float = 0.44,   # luminance below which background adjustment applies
        blur_radius:        float = 6.0,    # main smoothing blur for all adjustments
        opacity:            float = 0.42,   # global blend weight
    ) -> None:
        """
        Fra Filippo Lippi's defining quality: 'tenerezza' — tenderness of light.

        Fra Filippo Lippi (c. 1406–1469) is the bridge figure between Masaccio's
        austere sculptural realism and Leonardo's sfumato lyricism.  His paintings
        are recognised immediately by a quality of warmth and intimacy in the
        rendering of flesh that contemporaries called 'tenerezza' — tenderness.

        Where Masaccio's figures carry the gravity of ancient sculpture and the
        cool, certain light of early Florentine rationalism, Lippi's Madonnas and
        angels glow with a warm rose-ivory luminosity that makes them feel like
        living presences in warm afternoon light.  His shadows are always warm
        (ochre, amber, burnt sienna) and his highlights are a warm ivory that
        passes through a distinctive pinkish-rose midtone before brightening to
        near-white.  This warm rose-pink intermediate zone — visible especially
        on the cheeks, the inner corners of the eyes, and across the brow — is
        the tonal fingerprint of Lippi.

        This pass replicates that quality in three operations:

        1. **Rose-ivory flesh midtone warm lift** — In the flesh midtone luminance
           band (flesh_mid_lo to flesh_mid_hi), nudges the colour toward the
           characteristic Lippi rose-ivory by boosting red, very slightly boosting
           green (for ivory warmth rather than orange), and gently damping blue.
           The effect is modulated by the existing saturation so that already-
           desaturated passages (background, drapery) are not affected.

        2. **Interior luminous glow** — In the brightest flesh passages
           (luminance > glow_thresh), applies a very gentle warm ivory lift that
           simulates Lippi's characteristic interior radiance.  The lift is
           softened by a Gaussian blur before compositing so it reads as a
           diffuse glow rather than a hard brightening.  This is not Correggio's
           golden luminosity or Vigée Le Brun's pearl iridescence — it is quieter,
           a very subtle brightening that makes the highest lights feel lit from
           within rather than lit from without.

        3. **Background quieting** — In dark-to-midtone background passages
           (luminance < bg_thresh), applies a gentle blue push and slight
           desaturation.  This reinforces the Quattrocento convention of pushing
           the background back so the figure occupies a clear luminous space.
           Lippi always maintained clear figure-ground separation even as he
           softened the figure's own internal boundaries.

        Parameters
        ----------
        flesh_mid_lo / hi  : Luminance range for the flesh midtone warm lift.
                             [0.42, 0.80] covers the full flesh register from
                             shadow-side skin to near-highlight.
        rose_r_boost       : R boost magnitude.  0.048 gives a perceptible
                             pinkish warmth without making flesh look flushed.
        rose_g_boost       : G tiny boost.  Keeps warmth ivory-rose rather than
                             pure orange.
        rose_b_dampen      : B reduction.  Removes cool cast from flesh midtones.
        glow_thresh        : Luminance threshold for interior glow.  0.72 targets
                             the top quarter of the tonal range.
        glow_lift          : Warm ivory brightness lift in glow zone.  0.040 is
                             subtle — one of the lightest effects in the pipeline.
        glow_blur          : Gaussian sigma for glow softening (pixels).  8px
                             gives diffuse halo quality without hard edges.
        bg_cool_shift      : B channel push in background darks.  0.022 is
                             imperceptible in isolation but creates a slight
                             atmospheric recession.
        bg_desaturate      : Desaturation in background.  0.12 quietly removes
                             competing chromatic interest from the background.
        bg_thresh          : Background luminance ceiling.  0.44 targets the
                             dark-to-midtone passages where Lippi's backgrounds
                             lived.
        blur_radius        : Gaussian for all adjustment maps.  6px prevents
                             any adjustment from having pixel-sharp edges.
        opacity            : Global blend weight.  0.42 recommended for portrait
                             work — tenerezza accumulates quietly.

        Notes
        -----
        Lippi's influence ran directly to Botticelli (his pupil), to Filippino
        Lippi (his son), and through both to Leonardo.  The warm pinkish flesh
        of Leonardo's Benois Madonna and the early portraits owes a direct debt
        to Lippi's rose-ivory rendering that is rarely acknowledged in art-
        historical literature, which tends to credit Verrocchio's workshop as
        Leonardo's primary technical inheritance.  But Verrocchio himself learned
        from the Florentine tradition that Lippi helped define.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Fra Filippo Lippi tenerezza pass  "
              f"(rose_r={rose_r_boost:.3f}  glow_lift={glow_lift:.3f}  "
              f"opacity={opacity:.2f})…")

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        b_out = b0.copy()
        g_out = g0.copy()
        r_out = r0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # Compute approximate saturation to restrict flesh lift to chromatic zones
        c_max = _np.maximum(r0, _np.maximum(g0, b0))
        c_min = _np.minimum(r0, _np.minimum(g0, b0))
        sat = _np.where(c_max > 0.01, (c_max - c_min) / c_max, 0.0)

        # ── 1. Rose-ivory flesh midtone warm lift ─────────────────────────────
        # Only in flesh midtone luminance band and where saturation is present
        flesh_t = _np.clip(
            (lum - flesh_mid_lo) / max(0.01, flesh_mid_hi - flesh_mid_lo),
            0.0, 1.0
        ) * _np.clip(1.0 - (lum - flesh_mid_hi) / max(0.01, 1.0 - flesh_mid_hi), 0.0, 1.0)
        # Bell-curve shape: peaks at midpoint of the range, fades at both ends
        flesh_t = flesh_t * _np.clip(sat * 4.0, 0.0, 1.0)  # restrict to chromatic areas
        flesh_t = _gf(flesh_t.astype(_np.float32), sigma=blur_radius)
        flesh_t = _np.clip(flesh_t, 0.0, 1.0)

        r_out = _np.clip(r_out + flesh_t * rose_r_boost, 0.0, 1.0)
        g_out = _np.clip(g_out + flesh_t * rose_g_boost, 0.0, 1.0)
        b_out = _np.clip(b_out - flesh_t * rose_b_dampen, 0.0, 1.0)

        # ── 2. Interior luminous glow ─────────────────────────────────────────
        # Very gentle warm ivory lift in brightest passages, softened before apply
        glow_mask = _np.clip((lum - glow_thresh) / max(0.01, 1.0 - glow_thresh), 0.0, 1.0)
        glow_mask = _gf(glow_mask.astype(_np.float32), sigma=glow_blur)
        glow_mask = _np.clip(glow_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + glow_mask * glow_lift * 1.0, 0.0, 1.0)
        g_out = _np.clip(g_out + glow_mask * glow_lift * 0.90, 0.0, 1.0)
        b_out = _np.clip(b_out + glow_mask * glow_lift * 0.70, 0.0, 1.0)

        # ── 3. Background quieting ────────────────────────────────────────────
        # Gently push dark background areas cooler and slightly desaturate them,
        # reinforcing figure-ground separation in the Quattrocento tradition.
        bg_mask = _np.clip(1.0 - lum / max(0.01, bg_thresh), 0.0, 1.0)
        # Exclude figure (bright pixels are usually figure)
        bg_mask = bg_mask * _np.clip(1.0 - (lum - bg_thresh * 0.5) / max(0.01, bg_thresh * 0.5), 0.0, 1.0)
        bg_mask = _gf(bg_mask.astype(_np.float32), sigma=blur_radius)
        bg_mask = _np.clip(bg_mask, 0.0, 1.0)

        # Desaturate toward luminance
        r_grey = lum; g_grey = lum; b_grey = lum
        r_desat = r_out * (1.0 - bg_desaturate * bg_mask) + r_grey * (bg_desaturate * bg_mask)
        g_desat = g_out * (1.0 - bg_desaturate * bg_mask) + g_grey * (bg_desaturate * bg_mask)
        b_desat = b_out * (1.0 - bg_desaturate * bg_mask) + b_grey * (bg_desaturate * bg_mask)
        r_out = _np.clip(r_desat, 0.0, 1.0)
        g_out = _np.clip(g_desat, 0.0, 1.0)
        b_out = _np.clip(_np.clip(b_desat, 0.0, 1.0) + bg_mask * bg_cool_shift, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Fra Filippo Lippi tenerezza pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 84 — Pietro Perugino serene grace pass
    # ─────────────────────────────────────────────────────────────────────────

    def perugino_serene_grace_pass(
        self,
        sky_band:           float = 0.52,   # fraction of image height that is "sky zone"
        sky_cool_b:         float = 0.055,  # B push in sky zone (toward Umbrian cerulean)
        sky_desaturate:     float = 0.30,   # desaturation in sky zone (Perugino's pale skies)
        sky_lift:           float = 0.040,  # luminance lift in sky zone (bleached luminosity)
        shadow_thresh_lo:   float = 0.18,   # shadow zone luminance floor
        shadow_thresh_hi:   float = 0.44,   # shadow zone luminance ceiling
        shadow_cool_b:      float = 0.028,  # B push in figure shadow zone (silvery-cool)
        shadow_cool_r:      float = 0.012,  # R slight reduction in shadow zone
        shadow_violet_g:    float = 0.006,  # G subtle reduction (toward grey-violet shadow)
        midtone_lo:         float = 0.40,   # midtone smoothing luminance floor
        midtone_hi:         float = 0.76,   # midtone smoothing luminance ceiling
        smooth_sigma:       float = 3.5,    # Gaussian sigma for midtone harmonization
        smooth_strength:    float = 0.18,   # blend weight of smoothed midtone image
        blur_radius:        float = 7.0,    # Gaussian sigma for all adjustment maps
        opacity:            float = 0.38,   # global blend weight
    ) -> None:
        """
        Pietro Perugino's defining tonal and atmospheric qualities: serene grace.

        Pietro Perugino (Pietro di Cristoforo Vannucci, c. 1446–1523) was Raphael's
        master and, for a decade and a half, the most admired painter in Italy.  He
        trained in Florence alongside Leonardo (both were in the orbit of Verrocchio's
        workshop in the 1470s) and developed a style so distinctive that it became a
        cultural type: the 'Perugino face' — serene, idealised, with a faint upward
        curve of the lips that reads as spiritual composure rather than earthly emotion.

        This pass replicates three interlocking characteristics of Perugino's visual
        world:

        1. **Sky luminosity bleaching** — Perugino's backgrounds always feature an
           exceptionally luminous, pale sky.  Unlike the cool grey-blue of Flemish
           atmospheric recession or the deep cerulean of Venetian skies, Perugino's
           Umbrian sky is almost bleached: very pale, slightly warm at the very top,
           cooling and clearing toward the horizon.  This pass lifts and cools the
           upper background zone (above sky_band), desaturating toward a luminous
           blue-white and gently brightening the whole sky zone.

        2. **Cool silvery shadow harmonization** — Perugino's shadows are cooler and
           more silvery than Leonardo's warm umber darks.  Where Leonardo's sfumato
           deepens shadows toward warm amber-umber, Perugino's shadow side carries a
           gentle grey-violet cast — the colour of cool ambient light bouncing from
           a pale stone wall, not the directed drama of a single warm source.  In the
           figure's shadow zone (shadow_thresh_lo to shadow_thresh_hi luminance), this
           pass pushes slightly toward blue-grey: reducing red minimally, reducing
           green very slightly, and lifting blue fractionally.  The result is the
           Perugino shadow register: cool, silvery, and serene.

        3. **Midtone serene smoothing** — Perugino's flesh surfaces are extraordinarily
           smooth — not through sfumato (the wet merging of edges) but through careful
           layering that evens out local luminance variation in the midtone range.
           In the flesh midtone band (midtone_lo to midtone_hi), this pass blends a
           Gaussian-smoothed version of the image with the current surface at
           smooth_strength weight.  The result suppresses rough local variation in the
           mid-luminance flesh passage, giving skin the composed, almost porcelain
           quality that is Perugino's tonal fingerprint.

        Parameters
        ----------
        sky_band          : Fraction of image height below which sky zone ends.
                            0.52 = upper 52% of the canvas is treated as sky zone.
        sky_cool_b        : Blue channel lift in sky zone.  0.055 nudges the upper
                            background toward pale Umbrian cerulean without making it
                            aggressively blue.
        sky_desaturate    : Desaturation in sky zone.  0.30 produces Perugino's
                            characteristic bleached, near-white sky quality.
        sky_lift          : Brightness lift in sky zone.  0.040 lightens the whole
                            upper background toward luminous openness.
        shadow_thresh_lo/hi: Luminance range for figure shadow harmonization.
                            [0.18, 0.44] covers the dark-to-midtone shadow range.
        shadow_cool_b     : B lift in shadow zone.  0.028 is subtle — Perugino's
                            shadows are only gently cooler, not dramatically cold.
        shadow_cool_r     : R reduction in shadow zone.  0.012 barely perceptible
                            in isolation; contributes to the grey-violet register.
        shadow_violet_g   : G reduction in shadow zone.  0.006 is very slight —
                            pushes toward grey-violet without turning purple.
        midtone_lo/hi     : Luminance range for midtone smoothing.  [0.40, 0.76]
                            targets the full flesh midtone band.
        smooth_sigma      : Gaussian sigma for midtone smoothing.  3.5px gives
                            local smoothing without destroying overall form.
        smooth_strength   : Blend weight of the smoothed layer.  0.18 produces
                            a subtle evening of local contrast — Perugino's
                            surfaces still have form; they are merely quieter.
        blur_radius       : Gaussian sigma for all adjustment masks.  7px prevents
                            any adjustment from having pixel-sharp boundaries.
        opacity           : Global blend weight.  0.38 is recommended — Perugino's
                            serenity is accumulated quietly over the existing layers.

        Notes
        -----
        Perugino's influence on the Mona Lisa context is often underestimated.
        The landscape behind Lisa Gherardini — its pale, receding aerial distance,
        the mismatched horizon heights, the geological dreamscape quality — owes
        something to the Umbrian convention of the luminous, spacious background
        that Perugino helped define.  Leonardo transformed this convention by
        introducing sfumato (which Perugino never fully adopted), but the basic
        impulse — to place the human figure within an ordered, luminous, idealized
        natural world — is shared.  Both men came out of the same Florentine
        formation; the Mona Lisa and the Sposalizio are cousins.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Perugino serene grace pass  "
              f"(sky_band={sky_band:.2f}  shadow_cool_b={shadow_cool_b:.3f}  "
              f"smooth_strength={smooth_strength:.2f}  opacity={opacity:.2f})…")

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        b_out = b0.copy()
        g_out = g0.copy()
        r_out = r0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Sky luminosity bleaching ───────────────────────────────────────
        # Build a vertical gradient mask: full strength at the very top, fading
        # to zero at sky_band.  This targets the upper background sky zone.
        sky_band_px = int(self.h * sky_band)
        ys = _np.arange(self.h, dtype=_np.float32)
        sky_mask_1d = _np.clip(1.0 - ys / max(1, sky_band_px), 0.0, 1.0)
        sky_mask = sky_mask_1d[:, _np.newaxis] * _np.ones((1, self.w), dtype=_np.float32)
        sky_mask = _gf(sky_mask, sigma=blur_radius)
        sky_mask = _np.clip(sky_mask, 0.0, 1.0)

        # Desaturate sky zone toward luminance
        r_sky_desat = r_out * (1.0 - sky_desaturate * sky_mask) + lum * (sky_desaturate * sky_mask)
        g_sky_desat = g_out * (1.0 - sky_desaturate * sky_mask) + lum * (sky_desaturate * sky_mask)
        b_sky_desat = b_out * (1.0 - sky_desaturate * sky_mask) + lum * (sky_desaturate * sky_mask)

        # Lift brightness and cool (B push) in sky zone
        r_out = _np.clip(r_sky_desat + sky_mask * sky_lift * 0.85, 0.0, 1.0)
        g_out = _np.clip(g_sky_desat + sky_mask * sky_lift * 0.92, 0.0, 1.0)
        b_out = _np.clip(b_sky_desat + sky_mask * (sky_lift + sky_cool_b), 0.0, 1.0)

        # ── 2. Cool silvery shadow harmonization ──────────────────────────────
        # In shadow-to-midtone zone of the figure, push toward grey-violet.
        shadow_t = _np.clip(
            (lum - shadow_thresh_lo) / max(0.01, shadow_thresh_hi - shadow_thresh_lo),
            0.0, 1.0
        ) * _np.clip(
            1.0 - (lum - shadow_thresh_hi) / max(0.01, 1.0 - shadow_thresh_hi),
            0.0, 1.0
        )
        shadow_t = shadow_t * _np.clip(1.0 - sky_mask * 2.0, 0.0, 1.0)  # avoid sky zone
        shadow_t = _gf(shadow_t.astype(_np.float32), sigma=blur_radius)
        shadow_t = _np.clip(shadow_t, 0.0, 1.0)

        r_out = _np.clip(r_out - shadow_t * shadow_cool_r, 0.0, 1.0)
        g_out = _np.clip(g_out - shadow_t * shadow_violet_g, 0.0, 1.0)
        b_out = _np.clip(b_out + shadow_t * shadow_cool_b, 0.0, 1.0)

        # ── 3. Midtone serene smoothing ───────────────────────────────────────
        # Blend a Gaussian-smoothed version of the image into the midtone band,
        # suppressing local luminance variation to produce Perugino's smooth surfaces.
        r_smooth = _gf(r_out, sigma=smooth_sigma)
        g_smooth = _gf(g_out, sigma=smooth_sigma)
        b_smooth = _gf(b_out, sigma=smooth_sigma)

        midtone_t = _np.clip(
            (lum - midtone_lo) / max(0.01, midtone_hi - midtone_lo),
            0.0, 1.0
        ) * _np.clip(
            1.0 - (lum - midtone_hi) / max(0.01, 1.0 - midtone_hi),
            0.0, 1.0
        )
        midtone_t = midtone_t * _np.clip(1.0 - sky_mask * 2.0, 0.0, 1.0)  # figure only
        midtone_t = _gf(midtone_t.astype(_np.float32), sigma=blur_radius * 0.5)
        midtone_t = _np.clip(midtone_t, 0.0, 1.0)

        blend_w = midtone_t * smooth_strength
        r_out = _np.clip(r_out * (1.0 - blend_w) + r_smooth * blend_w, 0.0, 1.0)
        g_out = _np.clip(g_out * (1.0 - blend_w) + g_smooth * blend_w, 0.0, 1.0)
        b_out = _np.clip(b_out * (1.0 - blend_w) + b_smooth * blend_w, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Perugino serene grace pass complete.")

    def signorelli_sculptural_vigour_pass(
        self,
        contour_sigma:      float = 1.2,    # Gaussian sigma for USM edge sharpening
        contour_amount:     float = 0.55,   # unsharp-mask sharpening weight
        contour_thresh:     float = 0.04,   # minimum edge magnitude to sharpen
        shadow_lo:          float = 0.10,   # shadow zone luminance floor
        shadow_hi:          float = 0.42,   # shadow zone luminance ceiling
        shadow_warm_r:      float = 0.030,  # R lift in shadow zone (warm umber push)
        shadow_deep_b:      float = 0.018,  # B reduction in shadow zone (de-cool)
        shadow_deep_g:      float = 0.008,  # G slight reduction (toward rich brown)
        sat_boost_amount:   float = 0.22,   # saturation boost in chromatic accents
        sat_boost_thresh:   float = 0.22,   # saturation threshold to qualify for boost
        sat_boost_lo:       float = 0.30,   # luminance floor for saturation boost zone
        sat_boost_hi:       float = 0.78,   # luminance ceiling for saturation boost zone
        blur_radius:        float = 6.0,    # Gaussian sigma for all adjustment masks
        opacity:            float = 0.42,   # global blend weight
    ) -> None:
        """
        Luca Signorelli's defining sculptural and chromatic qualities: vigour.

        Luca Signorelli (c. 1445/50–1523) was among the most influential Italian
        painters of the fifteenth century, whose commitment to anatomical clarity
        and muscular three-dimensionality anticipates Michelangelo's Sistine Chapel
        ceiling and sets him apart from the sfumato tradition of Leonardo and the
        serene diffusion of Perugino.

        This pass replicates three interlocking characteristics of Signorelli's
        visual world:

        1. **Contour clarification** — Signorelli's most distinctive quality is
           the clarity of his painted edges.  Where Leonardo dissolved contours
           into atmospheric sfumato and Perugino softened them into serene
           ambient light, Signorelli drew them firmly in paint, giving each limb,
           muscle, and drapery fold a sharp structural boundary that reads as
           bas-relief carving.  This pass applies a luminance-space unsharp mask
           at a fine scale (sigma ~1.2px), targeting mid-luminance boundary zones
           where the edge signal is real and not just noise.  The effect is subtle
           — a clarification of existing edges rather than a hard outline — that
           gives the figure a more sculptural, three-dimensional presence.

        2. **Shadow depth modelling** — Signorelli's shadows are deep and warm:
           umber, sienna, and near-black, not the cool grey of the Flemish or the
           silvery violet of Perugino.  In the shadow-to-mid-tone band (luminance
           0.10–0.42), this pass warms the shadow register by lifting red slightly,
           reducing blue, and fractionally reducing green — pushing toward the rich
           warm umber that gives Signorelli's modelling its sculptural relief.  The
           result is a more dramatic separation between shadow and light than
           Perugino's ambient-light system, closer to the directed single-source
           chiaroscuro of the Baroque.

        3. **Chromatic accent lift** — Despite his earth-tone palette foundation,
           Signorelli's work is characterised by unusually vivid chromatic accents:
           intense blues, saturated reds, bright greens appear as jewel-like
           punctuations against the warm ground.  In mid-luminance pixels with
           already-appreciable saturation (sat > sat_boost_thresh), this pass
           applies a gentle sigmoid-curve saturation boost that enhances the
           vividness of these accent zones without affecting the neutral tones.
           The result is the characteristic Signorelli colour energy: warm-earth
           dominated with bright chromatic punctuation.

        Parameters
        ----------
        contour_sigma    : Gaussian sigma for USM sharpening.  1.2px operates at
                           the scale of fine edge detail — muscle boundaries and
                           drapery folds — without amplifying larger tonal transitions.
        contour_amount   : Sharpening weight.  0.55 clarifies edges perceptibly
                           without making them feel digitally sharpened; the goal
                           is to read as a firmly-drawn painted edge.
        contour_thresh   : Minimum edge magnitude to apply sharpening.  0.04 avoids
                           amplifying noise in flat colour regions.
        shadow_lo/hi     : Luminance range for shadow warming.  [0.10, 0.42] covers
                           the dark-to-mid-shadow range without affecting highlights.
        shadow_warm_r    : R lift in shadow zone.  0.030 warms the shadow register
                           toward umber-sienna without making shadows orange.
        shadow_deep_b    : B reduction in shadow zone.  0.018 removes the slight
                           coolness that neutral shadows can carry; Signorelli's
                           darks are always warm.
        shadow_deep_g    : G slight reduction in shadow zone.  0.008 contributes to
                           the rich brown register without a visible green shift.
        sat_boost_amount : Saturation boost in chromatic accent zones.  0.22 is a
                           moderate enrichment — vivid but not garish.
        sat_boost_thresh : Saturation threshold.  0.22 qualifies only pixels that
                           already carry meaningful chroma — avoids boosting neutral
                           skin tones into an unnatural cast.
        sat_boost_lo/hi  : Luminance range for saturation boost.  [0.30, 0.78]
                           targets mid-tone chromatic regions — drapery, foliage —
                           and avoids the deepest shadows and brightest highlights.
        blur_radius      : Gaussian sigma for adjustment masks.  6px prevents
                           hard-edged transitions at zone boundaries.
        opacity          : Global blend weight.  0.42 applies the pass at moderate
                           strength — Signorelli's vigour is direct, but portrait
                           context requires restraint.

        Notes
        -----
        Signorelli stands in productive counterpoint to both Leonardo and Perugino
        in the Mona Lisa context.  Where Leonardo's sfumato dissolved the world
        into atmospheric unity and Perugino's serenity diffused it into pale
        luminous openness, Signorelli's approach insisted on the structural clarity
        of individual forms.  He represents the road not taken by the High
        Renaissance — the alternative in which anatomy, not atmosphere, became the
        primary vehicle of pictorial meaning.  His influence ran forward through
        Michelangelo into the Mannerists and beyond.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Signorelli sculptural vigour pass  "
              f"(contour_amount={contour_amount:.2f}  shadow_warm_r={shadow_warm_r:.3f}  "
              f"sat_boost_amount={sat_boost_amount:.2f}  opacity={opacity:.2f})…")

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        b_out = b0.copy()
        g_out = g0.copy()
        r_out = r0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Contour clarification (unsharp mask) ───────────────────────────
        # Apply USM to luminance channel, then composite back into RGB.
        # Targets mid-luminance boundary zones where Signorelli's firm contours live.
        lum_blur = _gf(lum, sigma=contour_sigma)
        edge_map = lum - lum_blur                               # high-frequency edge signal
        edge_abs = _np.abs(edge_map)

        # Threshold mask: only sharpen where the edge is above noise floor
        edge_mask = _np.clip(
            (edge_abs - contour_thresh) / max(0.01, 1.0 - contour_thresh),
            0.0, 1.0
        )
        edge_mask = _gf(edge_mask, sigma=blur_radius * 0.4)    # slight spatial softening

        # Apply sharpening proportionally to RGB (luminance-space USM)
        sharpen_delta = edge_map * contour_amount * edge_mask
        r_out = _np.clip(r_out + sharpen_delta, 0.0, 1.0)
        g_out = _np.clip(g_out + sharpen_delta, 0.0, 1.0)
        b_out = _np.clip(b_out + sharpen_delta, 0.0, 1.0)

        # ── 2. Shadow depth modelling (warm umber push) ───────────────────────
        # In the shadow-to-mid-tone band, push toward warm umber: lift R, reduce B and G.
        shadow_t = _np.clip(
            (lum - shadow_lo) / max(0.01, shadow_hi - shadow_lo),
            0.0, 1.0
        ) * _np.clip(
            1.0 - (lum - shadow_hi) / max(0.01, 1.0 - shadow_hi),
            0.0, 1.0
        )
        shadow_t = _gf(shadow_t.astype(_np.float32), sigma=blur_radius)
        shadow_t = _np.clip(shadow_t, 0.0, 1.0)

        r_out = _np.clip(r_out + shadow_t * shadow_warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out - shadow_t * shadow_deep_g,  0.0, 1.0)
        b_out = _np.clip(b_out - shadow_t * shadow_deep_b,  0.0, 1.0)

        # ── 3. Chromatic accent lift (saturation boost) ───────────────────────
        # In mid-luminance zones with meaningful saturation, apply sigmoid saturation boost.
        # Convert RGB to HSV-like saturation estimate (max-min / max).
        rgb_max = _np.maximum(_np.maximum(r_out, g_out), b_out)
        rgb_min = _np.minimum(_np.minimum(r_out, g_out), b_out)
        chroma  = _np.where(rgb_max > 1e-5, (rgb_max - rgb_min) / rgb_max, 0.0)

        # Mask: mid-luminance, saturated-enough pixels
        lum_mid_mask = _np.clip(
            (lum - sat_boost_lo) / max(0.01, sat_boost_hi - sat_boost_lo),
            0.0, 1.0
        ) * _np.clip(
            1.0 - (lum - sat_boost_hi) / max(0.01, 1.0 - sat_boost_hi),
            0.0, 1.0
        )
        sat_qual_mask = _np.clip(
            (chroma - sat_boost_thresh) / max(0.01, 1.0 - sat_boost_thresh),
            0.0, 1.0
        )
        boost_mask = lum_mid_mask * sat_qual_mask
        boost_mask = _gf(boost_mask.astype(_np.float32), sigma=blur_radius)
        boost_mask = _np.clip(boost_mask, 0.0, 1.0)

        # Saturation boost: move each channel away from luminance by boost_amount.
        boost = boost_mask * sat_boost_amount
        r_out = _np.clip(r_out + (r_out - lum) * boost, 0.0, 1.0)
        g_out = _np.clip(g_out + (g_out - lum) * boost, 0.0, 1.0)
        b_out = _np.clip(b_out + (b_out - lum) * boost, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Signorelli sculptural vigour pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Carriera pastel glow pass — Rosalba Carriera / Venetian Rococo (session 86)
    # ─────────────────────────────────────────────────────────────────────────

    def carriera_pastel_glow_pass(
        self,
        skin_brighten_lo:   float = 0.55,   # luminance floor for skin brightening zone
        skin_brighten_hi:   float = 0.85,   # luminance ceiling for skin brightening zone
        warm_pink_r:        float = 0.028,  # R lift in skin zone (ivory-pink warmth)
        warm_pink_b:        float = 0.010,  # B lift in skin zone (soft lavender undertone)
        highlight_sigma:    float = 3.2,    # Gaussian sigma for highlight bloom diffusion
        highlight_thresh:   float = 0.88,   # luminance threshold above which to bloom
        highlight_bloom:    float = 0.18,   # bloom spread strength (0–1)
        bg_cool_b:          float = 0.025,  # B lift in background (cool lavender shift)
        bg_cool_r:          float = 0.012,  # R reduction in background (de-warm)
        blur_radius:        float = 5.0,    # Gaussian sigma for all adjustment masks
        opacity:            float = 0.35,   # global blend weight
    ) -> None:
        """
        Rosalba Carriera's pearlescent pastel glow.

        Rosalba Carriera (1673–1757) was the pre-eminent pastellist of the early
        eighteenth century.  Her portraits achieve a luminous, powdery skin
        quality unlike any oil-painting technique — the pastel pigment sits on a
        warm vellum or ivory ground, scattering light so that the face appears
        softly self-luminous rather than lit from without.

        This pass introduces three interlocking qualities of Carriera's optical
        world:

        1. **Pearlescent skin brightening** — Carriera's flesh tones have a
           distinctive warm ivory-pink quality in the mid-bright zone: warm enough
           to read as human skin, cool enough at the edges to suggest the lavender-
           grey of pastel shadow.  In the upper mid-tone range (luminance 0.55–0.85),
           this pass lifts the red channel slightly (warm pink) and applies a very
           gentle blue lift (soft lavender), approximating the warm-pink overstrokes
           on cool-lavender underlayers that define real pastel flesh.  The green
           channel is left unchanged to preserve the neutral ivory balance rather
           than pushing toward a yellow-ochre (oil-painting) register.

        2. **Highlight bloom diffusion** — Carriera's highlights are feathered and
           powdery, not the crisp impasto pearls of Vermeer or the sharp specular
           gleam of Sargent.  For pixels above the highlight threshold (> 0.88
           luminance), this pass applies a Gaussian blur to the brightest values
           and blends the result back into the canvas.  The effect widens each
           specular peak into a soft, diffused halo — the visual signature of pastel
           pigment where the light-scattering dust softens every hard edge of
           reflected light.

        3. **Background vignette cooling** — Carriera's backgrounds are invariably
           cool and neutral: a pale blue-grey or warm-beige tone that recedes and
           makes the warm, luminous face advance.  In the background zone (pixels
           outside the figure mask), this pass lifts the blue channel and reduces
           red slightly, pushing toward the cool lavender-grey of Carriera's
           characteristic background tone.  The effect is most visible at moderate
           opacity: a gentle atmospheric push that makes the figure glow.

        Parameters
        ----------
        skin_brighten_lo  : luminance floor of the skin brightening zone (0–1).
        skin_brighten_hi  : luminance ceiling of the skin brightening zone (0–1).
        warm_pink_r       : R channel lift for warm ivory-pink skin brightening.
        warm_pink_b       : B channel lift for cool lavender undertone in skin.
        highlight_sigma   : Gaussian sigma for the highlight bloom Gaussian blur.
        highlight_thresh  : luminance threshold above which to apply highlight bloom.
        highlight_bloom   : blend weight of the bloomed highlight (0 = none, 1 = full).
        bg_cool_b         : B channel lift in the background zone (cool shift).
        bg_cool_r         : R channel reduction in the background zone (de-warm).
        blur_radius       : Gaussian sigma for all zone-detection masks.
        opacity           : global compositing weight (0 = no effect, 1 = full).

        Notes
        -----
        Characteristic works:
          *Self-Portrait as Winter* (c. 1731, Gemäldegalerie Dresden) —
              the most complete example of her powdery luminous skin technique.
          *Portrait of a Young Lady* (c. 1720–1730) — feathered lavender shadows,
              warm pink highlight bloom, cool neutral background.
        """
        print(f"Carriera pastel glow pass  "
              f"(opacity={opacity:.2f}  bloom_sigma={highlight_sigma:.1f}  "
              f"highlight_thresh={highlight_thresh:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        w, h = self.canvas.w, self.canvas.h

        # ── Read current canvas buffer (BGRA, uint8) ────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(h, w, 4).copy()

        # Float RGB [0, 1] — Cairo BGRA: index 2=R, 1=G, 0=B
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0  # BT.601 luminance (H, W)

        # ── Figure / background masks ────────────────────────────────────────
        if self._figure_mask is not None:
            fig_mask = _np.clip(self._figure_mask, 0.0, 1.0)
        else:
            fig_mask = _np.ones((h, w), dtype=_np.float32)
        bg_mask = _np.clip(1.0 - fig_mask, 0.0, 1.0)

        # ── Stage 1: Pearlescent skin brightening ────────────────────────────
        # Target: upper mid-tone luminance range in the figure zone.
        skin_mask = _np.clip(
            (lum - skin_brighten_lo) / max(0.01, skin_brighten_hi - skin_brighten_lo),
            0.0, 1.0
        ) * _np.clip(
            1.0 - (lum - skin_brighten_hi) / max(0.01, 1.0 - skin_brighten_hi),
            0.0, 1.0
        ) * fig_mask
        skin_mask = _gf(skin_mask.astype(_np.float32), sigma=blur_radius)
        skin_mask = _np.clip(skin_mask, 0.0, 1.0)

        # Warm ivory-pink lift in R; soft lavender lift in B; G unchanged.
        r_out = _np.clip(r_out + skin_mask * warm_pink_r, 0.0, 1.0)
        b_out = _np.clip(b_out + skin_mask * warm_pink_b, 0.0, 1.0)

        # ── Stage 2: Highlight bloom diffusion ──────────────────────────────
        # Isolate bright pixels, Gaussian-blur them, blend back as a soft halo.
        hi_mask = _np.clip(
            (lum - highlight_thresh) / max(0.01, 1.0 - highlight_thresh),
            0.0, 1.0
        )
        # Blur each channel independently to produce a colour-accurate bloom.
        r_bloom = _gf((r_out * hi_mask).astype(_np.float32), sigma=highlight_sigma)
        g_bloom = _gf((g_out * hi_mask).astype(_np.float32), sigma=highlight_sigma)
        b_bloom = _gf((b_out * hi_mask).astype(_np.float32), sigma=highlight_sigma)

        r_out = _np.clip(r_out + r_bloom * highlight_bloom, 0.0, 1.0)
        g_out = _np.clip(g_out + g_bloom * highlight_bloom, 0.0, 1.0)
        b_out = _np.clip(b_out + b_bloom * highlight_bloom, 0.0, 1.0)

        # ── Stage 3: Background vignette cooling ─────────────────────────────
        # Shift background zone toward cool lavender-grey.
        bg_blur = _gf(bg_mask.astype(_np.float32), sigma=blur_radius)
        bg_blur = _np.clip(bg_blur, 0.0, 1.0)

        b_out = _np.clip(b_out + bg_blur * bg_cool_b, 0.0, 1.0)
        r_out = _np.clip(r_out - bg_blur * bg_cool_r, 0.0, 1.0)

        # ── Composite at opacity ─────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Carriera pastel glow pass complete.")

    def whistler_tonal_harmony_pass(
        self,
        key_center:         float = 0.48,   # target tonal key (0=black, 1=white; 0.48=mid-key)
        key_strength:       float = 0.18,   # compression strength toward key center (0–1)
        dominant_hue_r:     float = 0.56,   # R component of dominant tonal hue (cool silver-grey)
        dominant_hue_g:     float = 0.57,   # G component of dominant tonal hue
        dominant_hue_b:     float = 0.62,   # B component of dominant tonal hue
        hue_drift:          float = 0.10,   # strength of drift toward dominant hue (0–1)
        dissolution_radius: float = 0.65,   # normalised radius beyond which dissolution begins
        dissolution_sigma:  float = 2.0,    # Gaussian sigma for peripheral edge dissolution
        blur_radius:        float = 5.0,    # Gaussian sigma for mask feathering
        opacity:            float = 0.42,   # global blend weight (0–1)
    ) -> None:
        """
        James McNeill Whistler's tonal harmony — session 87 artistic improvement.

        Whistler's paintings are defined by a single overriding formal principle:
        tonal harmony.  Every value in a painting must inhabit a coherent tonal
        register — a 'key' — so that accents of dark or light read as deliberate
        placements rather than uncontrolled contrasts.  He achieved this by working
        on a pre-keyed cool grey ground with heavily diluted 'sauce' paint, wiping
        and restating the image many times to ensure the tonal ensemble remained
        coherent throughout the painting process.

        This pass introduces three interlocking qualities of Whistler's optical world:

        1. **Tonal key lock** — All luminance values are compressed toward a target
           key center (default 0.48, mid-key).  Pixels above the key center are
           pulled toward it; pixels below are lifted toward it.  The compression
           strength controls how aggressively the tonal range is narrowed.  The
           effect is not flat desaturation but a controlled compression that
           preserves relative tonal relationships while preventing extreme contrasts
           from dominating.  Low-key mode (key_center=0.35) produces Nocturne
           darkness; mid-key (0.48) gives the silver Arrangement register; high-key
           (0.65) gives the White Symphony register.

        2. **Cool silver monochromatic drift** — The palette is gently pulled toward
           Whistler's dominant cool silver-grey hue (default R=0.56, G=0.57, B=0.62),
           reducing chromatic variety without eliminating hue character.  Each pixel
           is blended toward the dominant hue proportional to its saturation — highly
           saturated colours are pulled more strongly than neutral tones — creating
           the characteristic 'harmony' where every colour feels related to a shared
           tonal key rather than existing independently.  This is different from
           simple desaturation: the hue is pulled toward a specific cool-grey rather
           than toward neutral achromatic grey.

        3. **Peripheral edge dissolution** — Progressive Gaussian softening is applied
           from the compositional periphery inward, dissolving edge detail into
           atmospheric suggestion at the picture's boundaries.  Inside the focal
           circle (dissolution_radius), the image retains full edge sharpness.
           Outside it, edges progressively dissolve into the atmospheric ground.
           Inspired by Whistler's intentionally 'lost' picture edges — visible in
           every Nocturne, where figures and architecture dissolve into the night
           sky rather than being cut against it — and by the Japanese woodblock
           treatment of empty space as an active compositional element.

        Parameters
        ----------
        key_center          : Target tonal key (0=black, 1=white; default 0.48 = mid-key).
                              0.35 = low-key Nocturne darkness; 0.65 = high-key White
                              Symphony mode.
        key_strength        : Compression strength toward key center (0 = no compression,
                              1 = full collapse to key_center).  0.15–0.22 is typical.
        dominant_hue_r/g/b  : RGB of the dominant tonal hue to drift toward.  Default is
                              Whistler's characteristic cool silver-grey (0.56, 0.57, 0.62).
                              For nocturne mode use (0.28, 0.32, 0.42) deep blue.
        hue_drift           : Strength of drift toward dominant hue (0 = none, 1 = full).
                              0.08–0.14 is typical; above 0.20 feels monochromatic.
        dissolution_radius  : Normalised radius of the focal circle (0–1 of canvas diagonal).
                              Inside: full sharpness.  Outside: progressive dissolution.
        dissolution_sigma   : Gaussian sigma for the peripheral blur (px).
        blur_radius         : Gaussian sigma for all mask feathering.
        opacity             : Global compositing weight (0 = no effect, 1 = full).
        """
        print(f"Whistler tonal harmony pass  "
              f"(key={key_center:.2f}  strength={key_strength:.2f}  "
              f"hue_drift={hue_drift:.2f}  opacity={opacity:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        w, h = self.canvas.w, self.canvas.h

        # ── Read current canvas buffer (BGRA, uint8) ────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(h, w, 4).copy()

        # Float RGB [0, 1] — Cairo BGRA: index 2=R, 1=G, 0=B
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0  # BT.601 luminance

        # ── Stage 1: Tonal key lock ──────────────────────────────────────────
        # Compress luminance toward key_center: pixels above are pulled down,
        # pixels below are lifted up.  Apply as a luminance-preserving scale so
        # chroma (relative hue) is maintained during compression.
        lum_safe = _np.maximum(lum, 1e-8)
        lum_new = lum + (key_center - lum) * key_strength   # pull toward key_center
        scale_key = lum_new / lum_safe
        r_out = _np.clip(r_out * scale_key, 0.0, 1.0)
        g_out = _np.clip(g_out * scale_key, 0.0, 1.0)
        b_out = _np.clip(b_out * scale_key, 0.0, 1.0)

        # ── Stage 2: Cool silver monochromatic drift ─────────────────────────
        # Estimate saturation (chroma) and use it to weight the drift toward the
        # dominant hue.  Highly saturated pixels are pulled more strongly.
        max_c = _np.maximum(_np.maximum(r_out, g_out), b_out)
        min_c = _np.minimum(_np.minimum(r_out, g_out), b_out)
        chroma = _np.clip(max_c - min_c, 0.0, 1.0)   # relative saturation proxy

        # Drift weight: proportional to chroma and global hue_drift
        drift_w = chroma * hue_drift
        drift_w = _np.clip(drift_w, 0.0, 1.0)

        r_out = _np.clip(r_out * (1.0 - drift_w) + dominant_hue_r * drift_w, 0.0, 1.0)
        g_out = _np.clip(g_out * (1.0 - drift_w) + dominant_hue_g * drift_w, 0.0, 1.0)
        b_out = _np.clip(b_out * (1.0 - drift_w) + dominant_hue_b * drift_w, 0.0, 1.0)

        # ── Stage 3: Peripheral edge dissolution ─────────────────────────────
        # Build a radial weight that is 0 inside dissolution_radius and ramps
        # to 1 at the canvas corners.
        ys = _np.linspace(0.0, 1.0, h, dtype=_np.float32)[:, _np.newaxis]
        xs = _np.linspace(0.0, 1.0, w, dtype=_np.float32)[_np.newaxis, :]
        # Distance from canvas center, normalised to [0, 1] at corners
        dist = _np.sqrt((xs - 0.5) ** 2 + (ys - 0.5) ** 2) / (0.5 * _np.sqrt(2.0))
        # Ramp: 0 inside radius, 1 at edge
        dissolve_mask = _np.clip(
            (dist - dissolution_radius) / max(1.0 - dissolution_radius, 1e-6),
            0.0, 1.0
        )
        dissolve_mask = _gf(dissolve_mask.astype(_np.float32), sigma=blur_radius)
        dissolve_mask = _np.clip(dissolve_mask, 0.0, 1.0)

        if dissolution_sigma > 0.0:
            r_blurred = _gf(r_out.astype(_np.float32), sigma=dissolution_sigma)
            g_blurred = _gf(g_out.astype(_np.float32), sigma=dissolution_sigma)
            b_blurred = _gf(b_out.astype(_np.float32), sigma=dissolution_sigma)
            r_out = _np.clip(r_out * (1.0 - dissolve_mask) + r_blurred * dissolve_mask, 0.0, 1.0)
            g_out = _np.clip(g_out * (1.0 - dissolve_mask) + g_blurred * dissolve_mask, 0.0, 1.0)
            b_out = _np.clip(b_out * (1.0 - dissolve_mask) + b_blurred * dissolve_mask, 0.0, 1.0)

        # ── Composite at opacity ─────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Whistler tonal harmony pass complete.")

    # Session 89 — Léon Spilliaert — Vertiginous void pass
    # ─────────────────────────────────────────────────────────────────────────

    def spilliaert_vertiginous_void_pass(
        self,
        void_thresh:      float = 0.30,   # luminance ceiling for shadow compression
        void_cool_b:      float = 0.030,  # cold blue-grey lift in deep shadows
        void_damp_r:      float = 0.015,  # red dampen — removes warm oil cast from darks
        void_damp_g:      float = 0.010,  # green dampen — Spilliaert's ink black is blue-grey
        pale_thresh:      float = 0.72,   # luminance floor for pale-isolation zone
        pale_grey_lift:   float = 0.018,  # cool-grey lift in the pale zone
        pale_cool_b:      float = 0.012,  # slight blue-cool shift in pale highlights
        vignette_strength: float = 0.18,  # peripheral near-black deepening
        vignette_radius:  float = 0.60,   # normalised radius where vignette begins
        blur_radius:      float = 8.0,    # Gaussian sigma for soft mask transitions
        opacity:          float = 0.35,   # final composite opacity
    ):
        """
        Spilliaert vertiginous void pass — inspired by Léon Spilliaert.

        Léon Spilliaert (1881–1946) worked almost exclusively in Indian ink,
        watercolour, and pastel on paper.  His palette is near-monochromatic:
        deep near-black ink voids, cold grey washes, and occasional pale ivory
        highlights, with sparse acid-yellow or electric-blue accents.  His
        defining compositional device is vertiginous geometric depth — corridors,
        staircases, and seafronts recede into absolute darkness, creating a
        sense of existential dissolution.

        Three operations encode this visual world:

        1. **Shadow compression**: Dark pixels (lum < void_thresh) are pushed
           further toward near-black with a cold blue-grey undertone.  Unlike
           the warm oil-paint darks of the Old Masters, Spilliaert's ink blacks
           are cool — they carry a faint blue-grey cast derived from his Indian
           ink medium.  Red and green channels are slightly damped; blue is
           lifted.  This creates the characteristic cold austerity that
           distinguishes his work from anything painted in oil.

        2. **Pale isolation**: Bright areas (lum > pale_thresh) receive a slight
           cool-grey lift, isolating pale forms as luminous islands against the
           dark void.  This is the 'figure emerging from darkness' quality —
           Spilliaert's self-portraits appear as pale smudges of face and collar
           against engulfing black, barely differentiated from the paper they
           are on.

        3. **Peripheral vignette**: The canvas perimeter is darkened toward
           near-absolute black, reinforcing the geometric vertiginous depth and
           pulling the eye toward the composition centre.  Spilliaert's drawings
           almost always have this quality — the corners are dead black, the
           receding geometry creates depth, and only the focal zone retains
           significant luminance.

        Parameters
        ----------
        void_thresh      : Luminance ceiling for shadow compression (pixels below
                           this receive the cold blue-grey push).  Default 0.30.
        void_cool_b      : Blue channel lift in void zone — the cold ink cast.
        void_damp_r      : Red dampen in void — removes residual warm cast.
        void_damp_g      : Green dampen in void — Spilliaert's black is blue, not olive.
        pale_thresh      : Luminance floor for pale isolation (pixels above this
                           receive the cool-grey lift).  Default 0.72.
        pale_grey_lift   : Luminance boost in the pale zone — isolates light forms.
        pale_cool_b      : Slight blue-cool shift in pale highlights — ink-on-paper
                           whites are cooler than oil-on-canvas lights.
        vignette_strength: How much the periphery darkens toward near-black.
        vignette_radius  : Normalised radius (0–1) inside which vignette is zero.
        blur_radius      : Gaussian sigma for mask transitions.
        opacity          : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Spilliaert vertiginous void pass "
              f"(void_thresh={void_thresh:.2f}  pale_thresh={pale_thresh:.2f}  "
              f"vignette={vignette_strength:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Spilliaert vertiginous void pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b0 = buf[:, :, 0].astype(_np.float32) / 255.0
        g0 = buf[:, :, 1].astype(_np.float32) / 255.0
        r0 = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Stage 1: Shadow compression (cold ink void) ───────────────────────
        # Dark pixels pushed toward near-black with cold blue-grey undertone.
        void_raw  = _np.clip(1.0 - lum / max(void_thresh, 0.01), 0.0, 1.0)
        void_mask = _gf(void_raw.astype(_np.float32), sigma=blur_radius)
        void_mask = _np.clip(void_mask, 0.0, 1.0)

        r_out = _np.clip(r_out - void_mask * void_damp_r, 0.0, 1.0)
        g_out = _np.clip(g_out - void_mask * void_damp_g, 0.0, 1.0)
        b_out = _np.clip(b_out + void_mask * void_cool_b, 0.0, 1.0)

        # ── Stage 2: Pale isolation (figure as luminous island) ───────────────
        # Bright areas lifted toward cool ivory-grey — isolated pale forms
        # against the engulfing dark field.
        pale_raw  = _np.clip((lum - pale_thresh) / max(1.0 - pale_thresh, 0.01),
                             0.0, 1.0)
        pale_mask = _gf(pale_raw.astype(_np.float32), sigma=blur_radius)
        pale_mask = _np.clip(pale_mask, 0.0, 1.0)

        # Lift all channels equally (grey) then add a slight blue-cool shift
        r_out = _np.clip(r_out + pale_mask * pale_grey_lift, 0.0, 1.0)
        g_out = _np.clip(g_out + pale_mask * pale_grey_lift, 0.0, 1.0)
        b_out = _np.clip(b_out + pale_mask * (pale_grey_lift + pale_cool_b), 0.0, 1.0)

        # ── Stage 3: Peripheral vignette (geometric vertiginous depth) ────────
        # Canvas perimeter darkened toward near-absolute black.  The vignette
        # reinforces the sense of a corridor or staircase receding into darkness.
        ys = _np.linspace(0.0, 1.0, h, dtype=_np.float32)[:, _np.newaxis]
        xs = _np.linspace(0.0, 1.0, w, dtype=_np.float32)[_np.newaxis, :]
        dist = _np.sqrt((xs - 0.5) ** 2 + (ys - 0.5) ** 2) / (0.5 * _np.sqrt(2.0))
        vig_raw = _np.clip(
            (dist - vignette_radius) / max(1.0 - vignette_radius, 0.01),
            0.0, 1.0,
        ).astype(_np.float32)
        vig_mask = _gf(vig_raw, sigma=blur_radius * 1.5)
        vig_mask = _np.clip(vig_mask * vignette_strength, 0.0, 1.0)

        r_out = _np.clip(r_out * (1.0 - vig_mask), 0.0, 1.0)
        g_out = _np.clip(g_out * (1.0 - vig_mask), 0.0, 1.0)
        b_out = _np.clip(b_out * (1.0 - vig_mask), 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Spilliaert vertiginous void pass complete.")

    # Session 88 — Odilon Redon — Luminous reverie pass
    # ─────────────────────────────────────────────────────────────────────────

    def redon_luminous_reverie_pass(
        self,
        void_thresh:        float = 0.28,   # luminance ceiling for the void zone
        void_warm_r:        float = 0.018,  # warm red lift in void shadows
        void_cool_b:        float = 0.024,  # violet-blue lift in void shadows
        void_damp_g:        float = 0.010,  # green damping in void (away from olive)
        bloom_thresh:       float = 0.32,   # chroma floor to qualify for bloom halo
        bloom_sigma:        float = 4.5,    # Gaussian sigma for aureole spread
        bloom_strength:     float = 0.20,   # bloom halo blend weight at peak chroma
        sat_boost_lo:       float = 0.36,   # jewel lift low luminance bound
        sat_boost_hi:       float = 0.74,   # jewel lift high luminance bound
        sat_boost_thresh:   float = 0.18,   # minimum chroma to qualify for lift
        sat_boost_amount:   float = 0.20,   # saturation push amount
        blur_radius:        float = 6.0,    # feathering sigma for mask edges
        opacity:            float = 0.42,   # final composite opacity
    ) -> None:
        """
        Redon luminous reverie pass — session 88 new artist pass.

        Odilon Redon (1840–1916) inhabited two visual registers simultaneously:
        the velvety near-black of his charcoal Noirs, and the jewel-bright
        spectral intensity of his mature pastel and oil work.  This pass
        encodes both.

        Three operations:

          1. Velvet void enrichment — dark pixels (luminance < void_thresh) are
             pushed toward a rich warm-violet near-black by lifting the red and
             blue channels while slightly damping green.  The result is a void
             that reads as warm and deep rather than cold and flat — the same
             quality that makes Redon's charcoal grounds feel inhabited.

          2. Spectral bloom aureole — the highest-chroma pixels are detected
             (chroma > bloom_thresh) and each channel is Gaussian-blurred
             independently at sigma=bloom_sigma.  The blurred result is blended
             back at a weight proportional to local chroma × bloom_strength,
             creating a soft halo of scattered light around saturated colour
             masses.  This simulates the optical aureole that surrounds Redon's
             floating orbs, cyclops eye, and flower-burst pastels — dry pigment
             particles sitting on the surface and catching light from multiple
             angles simultaneously.

          3. Jewel saturation lift — mid-luminance (sat_boost_lo, sat_boost_hi),
             high-chroma (chroma > sat_boost_thresh) pixels receive a saturation
             push by moving each channel further from the local luminance
             centroid by sat_boost_amount.  This produces the jewel-like
             chromatic intensity of Redon's mature work where saturation is
             pushed to the maximum the medium allows while retaining harmony.

        Parameters
        ----------
        void_thresh      : luminance ceiling for velvet void zone (0–0.40)
        void_warm_r      : red-channel lift in void zone (warm violet push)
        void_cool_b      : blue-channel lift in void zone (violet push)
        void_damp_g      : green-channel reduction in void zone (removes olive)
        bloom_thresh     : minimum chroma for bloom halo qualification
        bloom_sigma      : Gaussian sigma for aureole spread (pixels)
        bloom_strength   : peak halo blend weight at chroma=1.0
        sat_boost_lo     : lower luminance bound for jewel saturation zone
        sat_boost_hi     : upper luminance bound for jewel saturation zone
        sat_boost_thresh : minimum chroma for jewel saturation lift
        sat_boost_amount : per-channel saturation push distance
        blur_radius      : Gaussian sigma for mask edge feathering
        opacity          : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Redon luminous reverie pass "
              f"(void_thresh={void_thresh:.2f}  bloom_sigma={bloom_sigma:.1f}  "
              f"sat_boost_amount={sat_boost_amount:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Redon luminous reverie pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b0 = buf[:, :, 0].astype(_np.float32) / 255.0
        g0 = buf[:, :, 1].astype(_np.float32) / 255.0
        r0 = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── Stage 1: Velvet void enrichment ───────────────────────────────────
        # Dark pixels pushed toward warm violet-near-black.
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        void_raw = _np.clip(1.0 - lum / max(void_thresh, 0.01), 0.0, 1.0)
        void_mask = _gf(void_raw, sigma=blur_radius)

        r_out = _np.clip(r_out + void_mask * void_warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out - void_mask * void_damp_g, 0.0, 1.0)
        b_out = _np.clip(b_out + void_mask * void_cool_b, 0.0, 1.0)

        # ── Stage 2: Spectral bloom aureole ───────────────────────────────────
        # Chroma = max(R,G,B) - min(R,G,B) — perceptual saturation proxy.
        max_rgb = _np.maximum(_np.maximum(r_out, g_out), b_out)
        min_rgb = _np.minimum(_np.minimum(r_out, g_out), b_out)
        chroma  = max_rgb - min_rgb

        # Gaussian blur each channel independently for the aureole.
        r_bloom = _gf(r_out, sigma=bloom_sigma)
        g_bloom = _gf(g_out, sigma=bloom_sigma)
        b_bloom = _gf(b_out, sigma=bloom_sigma)

        # Blend weight: proportional to how far chroma exceeds bloom_thresh.
        bloom_w = _np.clip((chroma - bloom_thresh) / max(1.0 - bloom_thresh, 0.01),
                           0.0, 1.0) * bloom_strength
        bloom_w = _gf(bloom_w, sigma=blur_radius)

        r_out = _np.clip(r_out + bloom_w * (r_bloom - r_out), 0.0, 1.0)
        g_out = _np.clip(g_out + bloom_w * (g_bloom - g_out), 0.0, 1.0)
        b_out = _np.clip(b_out + bloom_w * (b_bloom - b_out), 0.0, 1.0)

        # ── Stage 3: Jewel saturation lift ────────────────────────────────────
        # Recalculate chroma after bloom adjustment.
        lum2    = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
        max2    = _np.maximum(_np.maximum(r_out, g_out), b_out)
        min2    = _np.minimum(_np.minimum(r_out, g_out), b_out)
        chroma2 = max2 - min2

        # Bell-curve luminance mask.
        lum_lo, lum_hi = sat_boost_lo, sat_boost_hi
        bell = _np.minimum(
            _np.clip((lum2 - lum_lo) / max(lum_hi - lum_lo, 0.01), 0.0, 1.0),
            _np.clip((lum_hi - lum2) / max(lum_hi - lum_lo, 0.01), 0.0, 1.0),
        ) * 2.0
        chroma_gate = _np.clip((chroma2 - sat_boost_thresh) /
                               max(1.0 - sat_boost_thresh, 0.01), 0.0, 1.0)
        boost_mask = _gf(bell * chroma_gate, sigma=blur_radius)

        # Move each channel away from luminance by boost_amount × mask.
        r_out = _np.clip(r_out + boost_mask * sat_boost_amount * (r_out - lum2),
                         0.0, 1.0)
        g_out = _np.clip(g_out + boost_mask * sat_boost_amount * (g_out - lum2),
                         0.0, 1.0)
        b_out = _np.clip(b_out + boost_mask * sat_boost_amount * (b_out - lum2),
                         0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Redon luminous reverie pass complete.")

    def hodler_parallelism_pass(
        self,
        n_bands:             int   = 6,      # number of discrete tonal bands
        band_hardness:       float = 0.60,   # sharpness of band transitions (0=soft, 1=hard)
        contour_strength:    float = 0.35,   # darkening amount at detected edge zones
        contour_sigma:       float = 1.8,    # Gaussian sigma for edge zone expansion
        contour_thresh:      float = 0.06,   # gradient magnitude threshold for edge detection
        chroma_clarity_lo:   float = 0.35,   # luminance floor of chroma clarity zone
        chroma_clarity_hi:   float = 0.75,   # luminance ceiling of chroma clarity zone
        chroma_clarity_boost: float = 0.18,  # saturation push in mid-tone clarity zone
        chroma_min:          float = 0.12,   # minimum chroma required for clarity boost
        blur_radius:         float = 2.5,    # Gaussian sigma for mask edge feathering
        opacity:             float = 0.38,   # final composite opacity
    ) -> None:
        """
        Hodler parallelism pass — session 90 new artist pass.

        Ferdinand Hodler (1853–1918) governed his mature work by a principle
        he called Parallelism: the belief that nature organises itself into
        rhythmic, symmetrical, repeated structures — parallel mountain ridges,
        parallel rows of trees, parallel extension of figures.  On canvas,
        this principle produced a characteristic visual language of bold flat
        tonal zones, strong dark contour lines between planes, and chromatic
        clarity where each colour area reads as its essential identity.  This
        pass encodes the three hallmarks of that language.

        Three operations:

          1. Tonal band simplification — the canvas luminance is mapped to a
             small number of discrete tonal bands (n_bands) using a smooth
             staircase function.  Mid-tones collapse toward a dominant plane
             value rather than blending continuously; highlights and shadows
             are preserved.  The band_hardness parameter controls whether the
             transition is smooth (0.0, still continuous) or near-discrete
             (1.0, hard posterization).  Produces the flat, zone-based tonal
             quality of Hodler's simplified figure and mountain landscape planes.

          2. Contour darkening — the luminance gradient (Sobel operator) is
             computed; pixels in the edge zone (gradient > contour_thresh,
             expanded by contour_sigma Gaussian) are darkened by contour_strength.
             This strengthens the dark outline separating Hodler's tonal planes
             and gives his compositions their characteristic bold, poster-like
             legibility at full viewing distance.

          3. Chromatic clarity — in the mid-luminance, moderate-chroma zone
             (luminance in [chroma_clarity_lo, chroma_clarity_hi] and chroma >
             chroma_min), each channel is pushed further from the luminance
             centroid by chroma_clarity_boost.  Near-neutral areas are untouched.
             Produces Hodler's effect of largely unmixed pigments, where each
             colour zone reads as its essential hue identity rather than a
             visually complex mixture.

        Parameters
        ----------
        n_bands             : number of discrete tonal bands for luminance quantisation
        band_hardness       : sharpness of band edge (0=smooth staircase, 1=hard steps)
        contour_strength    : darkening at detected contour edges (0–1)
        contour_sigma       : Gaussian sigma for expanding detected edge zone (pixels)
        contour_thresh      : minimum normalised gradient magnitude for edge detection
        chroma_clarity_lo   : lower luminance bound for chroma clarity zone
        chroma_clarity_hi   : upper luminance bound for chroma clarity zone
        chroma_clarity_boost: per-channel saturation push in mid-tone clarity zone
        chroma_min          : minimum chroma required for clarity boost qualification
        blur_radius         : Gaussian sigma for mask edge feathering
        opacity             : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        print(f"  Hodler parallelism pass "
              f"(n_bands={n_bands}  band_hardness={band_hardness:.2f}  "
              f"contour_strength={contour_strength:.2f}  "
              f"chroma_clarity_boost={chroma_clarity_boost:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Hodler parallelism pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b0 = buf[:, :, 0].astype(_np.float32) / 255.0
        g0 = buf[:, :, 1].astype(_np.float32) / 255.0
        r0 = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Stage 1: Tonal band simplification ───────────────────────────────
        # Map luminance to a smooth staircase with n_bands steps.
        # At band_hardness=0: smooth (sawtooth interpolation, minimal effect).
        # At band_hardness=1: hard posterization.
        nb = max(n_bands, 2)
        lum_q = lum * nb                         # scale to [0, nb]
        lum_floor = _np.floor(lum_q)             # integer band index
        lum_frac  = lum_q - lum_floor            # fractional position within band
        # Smooth step within each band: frac -> smoothstep(frac)
        smooth = lum_frac * lum_frac * (3.0 - 2.0 * lum_frac)  # smoothstep [0,1]
        # Blend between smooth and quantised based on band_hardness.
        mixed_frac = smooth * (1.0 - band_hardness) + _np.round(lum_frac) * band_hardness
        lum_new = (lum_floor + mixed_frac) / nb  # back to [0, 1]
        lum_new = _np.clip(lum_new, 0.0, 1.0)

        # Shift each channel by the luminance delta.
        lum_delta = lum_new - lum
        r_out = _np.clip(r_out + lum_delta, 0.0, 1.0)
        g_out = _np.clip(g_out + lum_delta, 0.0, 1.0)
        b_out = _np.clip(b_out + lum_delta, 0.0, 1.0)

        # ── Stage 2: Contour darkening ────────────────────────────────────────
        # Detect luminance edges; darken them to create Hodler's bold outlines.
        lum_f = lum.astype(_np.float32)
        gx = _sobel(lum_f, axis=1).astype(_np.float32)
        gy = _sobel(lum_f, axis=0).astype(_np.float32)
        grad_mag = _np.sqrt(gx ** 2 + gy ** 2)
        if grad_mag.max() > 1e-9:
            grad_mag = grad_mag / grad_mag.max()

        contour_raw  = _np.clip((grad_mag - contour_thresh) /
                                max(1.0 - contour_thresh, 0.01), 0.0, 1.0)
        contour_mask = _gf(contour_raw, sigma=contour_sigma)
        contour_mask = _np.clip(contour_mask * contour_strength, 0.0, contour_strength)

        r_out = _np.clip(r_out - contour_mask, 0.0, 1.0)
        g_out = _np.clip(g_out - contour_mask, 0.0, 1.0)
        b_out = _np.clip(b_out - contour_mask, 0.0, 1.0)

        # ── Stage 3: Chromatic clarity ────────────────────────────────────────
        # Push mid-tone, moderate-chroma pixels toward their dominant hue.
        lum2    = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
        max_rgb = _np.maximum(_np.maximum(r_out, g_out), b_out)
        min_rgb = _np.minimum(_np.minimum(r_out, g_out), b_out)
        chroma  = max_rgb - min_rgb

        lum_range = max(chroma_clarity_hi - chroma_clarity_lo, 0.01)
        bell = _np.minimum(
            _np.clip((lum2 - chroma_clarity_lo) / lum_range, 0.0, 1.0),
            _np.clip((chroma_clarity_hi - lum2) / lum_range, 0.0, 1.0),
        ) * 2.0
        chroma_gate = _np.clip((chroma - chroma_min) / max(1.0 - chroma_min, 0.01),
                               0.0, 1.0)
        clarity_mask = _gf(bell * chroma_gate, sigma=blur_radius)

        r_out = _np.clip(r_out + clarity_mask * chroma_clarity_boost * (r_out - lum2),
                         0.0, 1.0)
        g_out = _np.clip(g_out + clarity_mask * chroma_clarity_boost * (g_out - lum2),
                         0.0, 1.0)
        b_out = _np.clip(b_out + clarity_mask * chroma_clarity_boost * (b_out - lum2),
                         0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Hodler parallelism pass complete.")

    def caillebotte_perspective_pass(
        self,
        perspective_strength:  float = 0.30,   # edge sharpening along H/V axes
        cobblestone_boost:     float = 0.08,   # cool reflection lift in dark zones
        cool_shift:            float = 0.05,   # blue-channel lift in warm mid-tones
        axis_sigma_h:          float = 1.2,    # Gaussian sigma for H-axis sharpening
        axis_sigma_v:          float = 1.2,    # Gaussian sigma for V-axis sharpening
        dark_lum_thresh:       float = 0.45,   # max luminance for cobblestone zone
        dark_chroma_thresh:    float = 0.10,   # max chroma for cobblestone zone
        warm_lum_lo:           float = 0.30,   # lower luminance bound for cool shift
        warm_lum_hi:           float = 0.70,   # upper luminance bound for cool shift
        blur_radius:           float = 2.0,    # Gaussian sigma for mask feathering
        opacity:               float = 0.35,   # final composite opacity
    ) -> None:
        """
        Caillebotte perspective pass — session 91 new artist pass.

        Gustave Caillebotte (1848–1894) brought a photographer's eye and an
        architect's drafting precision to Impressionism.  His hallmarks are
        radical perspective foreshortening, photographic cropping of figures at
        the canvas edge, and a cool grey Parisian palette governed by overcast
        sky light diffusing evenly across wet cobblestones and limestone façades.
        This pass encodes three aspects of that visual language.

        Three operations:

          1. Axis-aligned edge sharpening — separate horizontal and vertical Sobel
             edge maps are computed and used to apply unsharp masking independently
             along each axis.  Horizontal sharpening reinforces receding cornices,
             iron bridge grids, and cobblestone joint lines.  Vertical sharpening
             reinforces lamppost silhouettes, doorframe edges, and figure outlines
             against building walls.  Because the sharpening is axis-aligned, it
             strengthens geometric perspective edges while leaving diagonal organic
             edges (hair, umbrella curves) relatively untouched.

          2. Cobblestone reflection lift — in dark, desaturated zones (luminance <
             dark_lum_thresh and chroma < dark_chroma_thresh), the blue channel is
             brightened by cobblestone_boost.  This simulates the dull reflection
             of an overcast Parisian sky in wet cobblestones: the dark pavement
             picks up just a trace of cool sky blue, the characteristic grey-blue
             sheen of rain-wet stone in 'Paris Street; Rainy Day'.

          3. Cool ambient shift — in warm mid-tones (R > B, luminance in
             [warm_lum_lo, warm_lum_hi]), the blue channel is nudged up by
             cool_shift.  This pulls the overall temperature of flesh, ochre
             overcoats, and building facades toward the diffuse cool grey of the
             Parisian overcast sky ambient, counteracting the warm tendency of
             oil paint and producing Caillebotte's characteristic neutralised
             mid-tone palette.

        Parameters
        ----------
        perspective_strength  : unsharp mask strength along H and V axes (0–1)
        cobblestone_boost     : blue-channel brightening in dark desaturated zones
        cool_shift            : blue-channel lift in warm mid-tone zones
        axis_sigma_h          : Gaussian sigma for horizontal blur in H-axis sharpening
        axis_sigma_v          : Gaussian sigma for vertical blur in V-axis sharpening
        dark_lum_thresh       : luminance ceiling defining the cobblestone zone
        dark_chroma_thresh    : chroma ceiling defining the cobblestone zone
        warm_lum_lo           : lower luminance bound for the cool ambient shift zone
        warm_lum_hi           : upper luminance bound for the cool ambient shift zone
        blur_radius           : Gaussian sigma for mask edge feathering
        opacity               : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        print(f"  Caillebotte perspective pass "
              f"(perspective_strength={perspective_strength:.2f}  "
              f"cobblestone_boost={cobblestone_boost:.2f}  "
              f"cool_shift={cool_shift:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Caillebotte perspective pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b0 = buf[:, :, 0].astype(_np.float32) / 255.0
        g0 = buf[:, :, 1].astype(_np.float32) / 255.0
        r0 = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Stage 1: Axis-aligned edge sharpening ─────────────────────────────
        # Apply unsharp masking separately along horizontal and vertical axes.
        # This preferentially sharpens H/V architectural lines (perspective grids,
        # cornices, doorframes) while leaving diagonal organic edges softer.
        for ch_in, ch_ref in zip([r_out, g_out, b_out], [r0, g0, b0]):
            # Horizontal: blur along X only (sigma=(0, axis_sigma_h))
            blurred_h = _gf(ch_in, sigma=(0.0, axis_sigma_h))
            # Vertical: blur along Y only (sigma=(axis_sigma_v, 0))
            blurred_v = _gf(ch_in, sigma=(axis_sigma_v, 0.0))
            # Unsharp mask = original + strength * (original - blurred)
            sharpened_h = _np.clip(ch_in + perspective_strength * (ch_in - blurred_h),
                                   0.0, 1.0)
            sharpened_v = _np.clip(ch_in + perspective_strength * (ch_in - blurred_v),
                                   0.0, 1.0)
            # Average the two axis sharpenings
            sharpened = (sharpened_h + sharpened_v) * 0.5
            ch_in[:] = sharpened

        # ── Stage 2: Cobblestone reflection lift ──────────────────────────────
        # In dark, desaturated zones, brighten the blue channel slightly.
        max_rgb = _np.maximum(_np.maximum(r_out, g_out), b_out)
        min_rgb = _np.minimum(_np.minimum(r_out, g_out), b_out)
        chroma  = max_rgb - min_rgb

        lum_dark_gate  = _np.clip(1.0 - lum / max(dark_lum_thresh, 0.01), 0.0, 1.0)
        chroma_low_gate = _np.clip(1.0 - chroma / max(dark_chroma_thresh, 0.01), 0.0, 1.0)
        cobble_mask = _gf(lum_dark_gate * chroma_low_gate, sigma=blur_radius)
        cobble_mask = _np.clip(cobble_mask, 0.0, 1.0)

        b_out = _np.clip(b_out + cobble_mask * cobblestone_boost, 0.0, 1.0)

        # ── Stage 3: Cool ambient shift ───────────────────────────────────────
        # In warm mid-tones (R > B, luminance in [warm_lum_lo, warm_lum_hi]),
        # nudge the blue channel upward to neutralise warmth toward cool grey.
        warm_gate   = _np.clip((r_out - b_out) / 0.3, 0.0, 1.0)   # R > B by margin
        lum_range   = max(warm_lum_hi - warm_lum_lo, 0.01)
        lum_bell    = _np.minimum(
            _np.clip((lum - warm_lum_lo) / lum_range, 0.0, 1.0),
            _np.clip((warm_lum_hi - lum) / lum_range, 0.0, 1.0),
        ) * 2.0
        cool_mask   = _gf(warm_gate * lum_bell, sigma=blur_radius)
        cool_mask   = _np.clip(cool_mask, 0.0, 1.0)

        b_out = _np.clip(b_out + cool_mask * cool_shift, 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Caillebotte perspective pass complete.")

    def antonello_pellucid_flesh_pass(
        self,
        shadow_cool_lo:      float = 0.18,   # lower luminance bound of shadow cooling zone
        shadow_cool_hi:      float = 0.46,   # upper luminance bound of shadow cooling zone
        shadow_green_lift:   float = 0.018,  # green channel lift in shadow transitions
        shadow_blue_lift:    float = 0.028,  # blue channel lift in shadow transitions (Flemish cool)
        shadow_red_damp:     float = 0.010,  # red channel damping in shadow transitions
        highlight_lo:        float = 0.74,   # luminance threshold for warm highlight zone
        highlight_warm_r:    float = 0.022,  # Naples yellow-ivory R boost in highlights
        highlight_warm_g:    float = 0.012,  # Naples yellow-ivory G boost in highlights
        highlight_cool_b:    float = 0.008,  # slight blue damping in highlights (warm ivory, not cold)
        penumbra_lo:         float = 0.44,   # lower lum bound of pellucid edge-band sharpening
        penumbra_hi:         float = 0.58,   # upper lum bound of pellucid edge-band sharpening
        penumbra_contrast:   float = 0.06,   # contrast boost in the light-shadow transition band
        blur_radius:         float = 5.0,    # Gaussian feathering radius for smooth zone masks
        opacity:             float = 0.42,   # overall pass composite opacity
    ) -> None:
        """
        Antonello da Messina pellucid flesh pass — session 92 new artist pass.

        Antonello da Messina (c. 1430–1479) fused the Flemish oil-glazing
        tradition of Jan van Eyck with the warm Italian flesh palette.  The
        result is a 'pellucid' quality — the painted skin appears crystalline
        and internally lit, with warm lit zones, a distinctive blue-green tint
        in the mid-shadow transitions (Flemish subsurface quality), and a
        crisp, precisely resolved light-shadow boundary (the Flemish 'found
        edge') that sets him apart from both Leonardo's sfumato and Raphael's
        seamless idealism.

        Three operations:

          1. Flemish shadow cooling — In mid-shadow transitions (lum in
             [shadow_cool_lo, shadow_cool_hi]), apply a slight blue-green
             subsurface tint: G + shadow_green_lift, B + shadow_blue_lift,
             R − shadow_red_damp.  This mimics the way Flemish oil glazes
             in the shadow zone allow the cool gesso ground to influence
             the final colour, creating the 'translucent skin' quality that
             distinguishes Antonello from opaque-shadow Italian painters.
             The mask is Gaussian-feathered so the transition is seamless.

          2. Warm highlight clarification — In the lit zones (lum >
             highlight_lo), push toward Naples yellow-ivory: R + highlight_warm_r,
             G + highlight_warm_g, B − highlight_cool_b.  Antonello's highlights
             are warm and small — the specular quality of polished enamel rather
             than the broad, cool highlights of Baroque painting.  This stage
             reinforces that warm-ivory quality in the lightest flesh areas.

          3. Pellucid edge band — In the light-shadow transition zone (lum
             in [penumbra_lo, penumbra_hi]), apply a subtle local contrast
             push (penumbra_contrast) that sharpens the tonal gradient without
             hardening edges: pixels above the zone midpoint are lightened
             slightly, pixels below are darkened slightly, creating the
             'found-edge' transition that Flemish painters mastered — the
             boundary reads as resolved and precise but not mechanical.

        Parameters
        ----------
        shadow_cool_lo      : lower lum boundary of Flemish shadow cooling zone
        shadow_cool_hi      : upper lum boundary of shadow cooling zone
        shadow_green_lift   : G channel boost in shadow transitions (subsurface)
        shadow_blue_lift    : B channel boost in shadow transitions (Flemish cool)
        shadow_red_damp     : R channel damping in shadow transitions
        highlight_lo        : lum threshold for warm highlight zone
        highlight_warm_r    : R boost in highlighted flesh (Naples yellow-ivory)
        highlight_warm_g    : G boost in highlighted flesh
        highlight_cool_b    : B reduction in highlighted flesh (warm, not cold)
        penumbra_lo         : lower lum bound of pellucid edge-band sharpening
        penumbra_hi         : upper lum bound of pellucid edge-band sharpening
        penumbra_contrast   : contrast push in the light-shadow transition band
        blur_radius         : Gaussian sigma for mask feathering
        opacity             : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Antonello da Messina pellucid flesh pass "
              f"(shadow_cool=[{shadow_cool_lo:.2f},{shadow_cool_hi:.2f}]  "
              f"blue_lift={shadow_blue_lift:.3f}  "
              f"highlight_lo={highlight_lo:.2f}  warm_r={highlight_warm_r:.3f}  "
              f"penumbra=[{penumbra_lo:.2f},{penumbra_hi:.2f}]  "
              f"contrast={penumbra_contrast:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Antonello pellucid flesh pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b0 = buf[:, :, 0].astype(_np.float32) / 255.0
        g0 = buf[:, :, 1].astype(_np.float32) / 255.0
        r0 = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── Stage 1: Flemish shadow cooling ───────────────────────────────────
        # Bell-shaped mask over [shadow_cool_lo, shadow_cool_hi]
        shadow_range = max(shadow_cool_hi - shadow_cool_lo, 1e-6)
        shadow_mid   = (shadow_cool_lo + shadow_cool_hi) * 0.5
        shadow_half  = shadow_range * 0.5
        shadow_bell  = _np.clip(
            1.0 - _np.abs(lum - shadow_mid) / shadow_half, 0.0, 1.0)
        shadow_mask  = _gf(shadow_bell, sigma=blur_radius)
        sc_w         = shadow_mask * opacity

        r_out = _np.clip(r_out - sc_w * shadow_red_damp,   0.0, 1.0)
        g_out = _np.clip(g_out + sc_w * shadow_green_lift, 0.0, 1.0)
        b_out = _np.clip(b_out + sc_w * shadow_blue_lift,  0.0, 1.0)

        # ── Stage 2: Warm highlight clarification ─────────────────────────────
        # Ramp mask: linearly increases from highlight_lo to 1.0 as lum → 1.0
        highlight_range = max(1.0 - highlight_lo, 1e-6)
        highlight_raw   = _np.clip((lum - highlight_lo) / highlight_range, 0.0, 1.0)
        highlight_mask  = _gf(highlight_raw, sigma=blur_radius)
        hl_w            = highlight_mask * opacity

        r_out = _np.clip(r_out + hl_w * highlight_warm_r,   0.0, 1.0)
        g_out = _np.clip(g_out + hl_w * highlight_warm_g,   0.0, 1.0)
        b_out = _np.clip(b_out - hl_w * highlight_cool_b,   0.0, 1.0)

        # ── Stage 3: Pellucid edge-band contrast ──────────────────────────────
        # Bell-shaped mask over the penumbra [penumbra_lo, penumbra_hi]
        pen_range = max(penumbra_hi - penumbra_lo, 1e-6)
        pen_mid   = (penumbra_lo + penumbra_hi) * 0.5
        pen_half  = pen_range * 0.5
        pen_bell  = _np.clip(
            1.0 - _np.abs(lum - pen_mid) / pen_half, 0.0, 1.0)
        pen_mask  = _gf(pen_bell, sigma=blur_radius * 0.6)  # tighter feather

        # Pixels above penumbra midpoint → lifted; below → deepened
        # This adds contrast in the transition zone without hardening the actual edge
        above_mid = (lum > pen_mid).astype(_np.float32)
        below_mid = 1.0 - above_mid
        pen_w     = pen_mask * penumbra_contrast * opacity

        r_out = _np.clip(r_out + pen_w * (above_mid * 0.55 - below_mid * 0.45), 0.0, 1.0)
        g_out = _np.clip(g_out + pen_w * (above_mid * 0.55 - below_mid * 0.45), 0.0, 1.0)
        b_out = _np.clip(b_out + pen_w * (above_mid * 0.55 - below_mid * 0.45), 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Antonello da Messina pellucid flesh pass complete.")

    def franz_marc_prismatic_vitality_pass(
        self,
        blue_push:           float = 0.18,   # spiritual blue intensification strength
        yellow_push:         float = 0.12,   # cadmium yellow warmth push strength
        red_deepen:          float = 0.10,   # crimson deepening in warm mid-darks
        bloom_thresh:        float = 0.40,   # chroma threshold for prismatic bloom
        bloom_sigma:         float = 3.0,    # Gaussian sigma for bloom aureole
        bloom_strength:      float = 0.15,   # bloom blend weight
        sat_boost_lo:        float = 0.30,   # lower luminance bound for clarity lift
        sat_boost_hi:        float = 0.75,   # upper luminance bound for clarity lift
        sat_boost_amount:    float = 0.22,   # saturation lift in mid-tone clarity zone
        sat_boost_thresh:    float = 0.16,   # minimum chroma for clarity boost
        blur_radius:         float = 3.0,    # Gaussian sigma for mask feathering
        opacity:             float = 0.38,   # final composite opacity
    ) -> None:
        """
        Franz Marc prismatic vitality pass — session 91 new artist pass.

        Franz Marc (1880–1916), co-founder of Der Blaue Reiter, built his art
        on a symbolic colour theory in which specific primaries carry inherent
        spiritual meaning: blue (ultramarine) = spirituality and the masculine;
        yellow = gentleness, femininity, warmth; red = violence, matter, the
        earthly.  His canvases have an almost stained-glass luminosity — each
        colour plane glows independently, unmixed primaries vibrate against one
        another, and a deep blue-violet undertone permeates the whole.  This
        pass encodes the three hallmarks of that language.

        Three operations:

          1. Symbolic colour intensification — each pixel's dominant hue is
             detected and that hue is further amplified in Marc's symbolic
             direction.  Pixels where blue dominates (B > R × 1.15 and B > G ×
             1.10) receive a push toward ultramarine (spiritual elevation: B↑,
             slight G↓, slight R↓).  Pixels where warm yellow dominates (R >
             B × 1.15 and G > B × 1.10, luminance > 0.65) receive a golden
             warmth push (R↑, G↑, B↓ slightly).  Pixels with a warm red
             dominant in mid-dark luminance (R > B × 1.20, lum in [0.25,
             0.62]) receive a deepening into warm crimson (R↑, B↓).  All
             three gates are smooth (Gaussian-feathered) and mutually
             exclusive so no pixel is doubly processed.

          2. Prismatic form bloom — per-pixel chroma (max_rgb − min_rgb) is
             computed; where chroma > bloom_thresh the excess drives a soft
             per-channel Gaussian bloom (sigma=bloom_sigma) that is added back
             at bloom_strength weight.  This produces the luminous aureole
             around Marc's pure colour planes — the characteristic glow at the
             boundary between a deep ultramarine body and the warm ground — that
             gives his work its stained-glass quality.

          3. Prismatic clarity lift — in the mid-luminance zone (lum in
             [sat_boost_lo, sat_boost_hi]) and where chroma > sat_boost_thresh,
             each channel is pushed further from the luminance mean by
             sat_boost_amount × clarity_mask.  Near-neutrals are unchanged.
             This maintains the unmixed-pigment vibrancy and prevents the
             optical muddying that would otherwise occur where Marc's pure
             colour planes touch.

        Parameters
        ----------
        blue_push         : spiritual blue intensification strength (0–0.3)
        yellow_push       : cadmium yellow warmth push strength (0–0.2)
        red_deepen        : crimson deepening in warm mid-darks (0–0.2)
        bloom_thresh      : chroma threshold for prismatic bloom activation (0–1)
        bloom_sigma       : Gaussian sigma for bloom aureole (pixels)
        bloom_strength    : bloom composite weight (0–0.3)
        sat_boost_lo      : lower luminance bound for clarity lift zone
        sat_boost_hi      : upper luminance bound for clarity lift zone
        sat_boost_amount  : saturation push per unit of clarity_mask
        sat_boost_thresh  : minimum chroma to qualify for clarity boost
        blur_radius       : Gaussian sigma for mask edge feathering
        opacity           : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Franz Marc prismatic vitality pass "
              f"(blue_push={blue_push:.2f}  yellow_push={yellow_push:.2f}  "
              f"bloom_thresh={bloom_thresh:.2f}  sat_boost={sat_boost_amount:.2f}  "
              f"opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Franz Marc prismatic vitality pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b0 = buf[:, :, 0].astype(_np.float32) / 255.0
        g0 = buf[:, :, 1].astype(_np.float32) / 255.0
        r0 = buf[:, :, 2].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Stage 1: Symbolic colour intensification ─────────────────────────
        # Gate 1a: Blue spiritual zone — B dominates R and G
        blue_gate_raw = _np.clip(
            _np.minimum(b0 - r0 * 1.15, b0 - g0 * 1.10), 0.0, 1.0
        )
        blue_gate = _gf(blue_gate_raw, sigma=blur_radius)
        blue_w = _np.clip(blue_gate * (1.0 / max(blue_gate.max(), 1e-6)) *
                          blue_push, 0.0, blue_push)
        r_out = _np.clip(r_out - blue_w * 0.6, 0.0, 1.0)
        g_out = _np.clip(g_out - blue_w * 0.3, 0.0, 1.0)
        b_out = _np.clip(b_out + blue_w, 0.0, 1.0)

        # Gate 1b: Yellow feminine zone — R > B×1.15, G > B×1.10, high luminance
        yellow_gate_raw = _np.clip(
            _np.minimum(r0 - b0 * 1.15, g0 - b0 * 1.10), 0.0, 1.0
        ) * _np.clip((lum - 0.60) / 0.25, 0.0, 1.0)   # only bright pixels
        yellow_gate = _gf(yellow_gate_raw, sigma=blur_radius)
        yellow_w = _np.clip(yellow_gate * (1.0 / max(yellow_gate.max(), 1e-6)) *
                            yellow_push, 0.0, yellow_push)
        r_out = _np.clip(r_out + yellow_w * 0.8, 0.0, 1.0)
        g_out = _np.clip(g_out + yellow_w * 0.6, 0.0, 1.0)
        b_out = _np.clip(b_out - yellow_w * 0.5, 0.0, 1.0)

        # Gate 1c: Red earthly zone — R dominates B in mid-darks
        lum_range_r = _np.clip((lum - 0.25) / 0.37, 0.0, 1.0) * \
                      _np.clip((0.62 - lum) / 0.37, 0.0, 1.0)
        red_gate_raw = _np.clip(r0 - b0 * 1.20, 0.0, 1.0) * lum_range_r
        red_gate = _gf(red_gate_raw, sigma=blur_radius)
        red_w = _np.clip(red_gate * (1.0 / max(red_gate.max(), 1e-6)) *
                         red_deepen, 0.0, red_deepen)
        r_out = _np.clip(r_out + red_w, 0.0, 1.0)
        b_out = _np.clip(b_out - red_w * 0.5, 0.0, 1.0)

        # ── Stage 2: Prismatic form bloom ─────────────────────────────────────
        # Identify high-chroma pixels; bloom their colour outward.
        max_rgb = _np.maximum(_np.maximum(r_out, g_out), b_out)
        min_rgb = _np.minimum(_np.minimum(r_out, g_out), b_out)
        chroma  = max_rgb - min_rgb

        bloom_excess = _np.clip((chroma - bloom_thresh) /
                                max(1.0 - bloom_thresh, 0.01), 0.0, 1.0)
        r_bloom = _gf(r_out * bloom_excess, sigma=bloom_sigma)
        g_bloom = _gf(g_out * bloom_excess, sigma=bloom_sigma)
        b_bloom = _gf(b_out * bloom_excess, sigma=bloom_sigma)

        bloom_w = _np.clip(bloom_excess * bloom_strength, 0.0, bloom_strength)
        r_out = _np.clip(r_out + r_bloom * bloom_w, 0.0, 1.0)
        g_out = _np.clip(g_out + g_bloom * bloom_w, 0.0, 1.0)
        b_out = _np.clip(b_out + b_bloom * bloom_w, 0.0, 1.0)

        # ── Stage 3: Prismatic clarity lift ───────────────────────────────────
        lum2    = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
        max_rgb2 = _np.maximum(_np.maximum(r_out, g_out), b_out)
        min_rgb2 = _np.minimum(_np.minimum(r_out, g_out), b_out)
        chroma2  = max_rgb2 - min_rgb2

        lum_range_s = max(sat_boost_hi - sat_boost_lo, 0.01)
        bell = _np.minimum(
            _np.clip((lum2 - sat_boost_lo) / lum_range_s, 0.0, 1.0),
            _np.clip((sat_boost_hi - lum2) / lum_range_s, 0.0, 1.0),
        ) * 2.0
        chroma_gate2 = _np.clip(
            (chroma2 - sat_boost_thresh) / max(1.0 - sat_boost_thresh, 0.01),
            0.0, 1.0
        )
        clarity_mask = _gf(bell * chroma_gate2, sigma=blur_radius)

        r_out = _np.clip(r_out + clarity_mask * sat_boost_amount * (r_out - lum2),
                         0.0, 1.0)
        g_out = _np.clip(g_out + clarity_mask * sat_boost_amount * (g_out - lum2),
                         0.0, 1.0)
        b_out = _np.clip(b_out + clarity_mask * sat_boost_amount * (b_out - lum2),
                         0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Franz Marc prismatic vitality pass complete.")

    def hugo_van_der_goes_expressive_depth_pass(
        self,
        shadow_lo:           float = 0.00,   # lower lum bound of warm shadow zone
        shadow_hi:           float = 0.35,   # upper lum bound of warm shadow zone
        shadow_amber_r:      float = 0.028,  # R boost in shadow zone (warm amber pull)
        shadow_amber_b:      float = 0.018,  # B reduction in shadow zone (damp cool)
        midtone_lo:          float = 0.45,   # lower lum bound of midtone earthing zone
        midtone_hi:          float = 0.68,   # upper lum bound of midtone earthing zone
        midtone_earth_r:     float = 0.016,  # R boost in midtones (amber-brown earthing)
        midtone_earth_g:     float = 0.008,  # G boost in midtones (slight warm-ochre push)
        midtone_earth_b:     float = 0.014,  # B reduction in midtones (pull away from cool)
        void_thresh:         float = 0.12,   # lum threshold below which void deepening acts
        void_deepen:         float = 0.015,  # RGB reduction in absolute darks (void deepening)
        blur_radius:         float = 5.0,    # Gaussian sigma for mask feathering
        opacity:             float = 0.40,   # overall pass composite opacity
    ) -> None:
        """
        Hugo van der Goes expressive depth pass — session 93 new artist pass.

        Hugo van der Goes (c. 1440–1482) is the most psychologically intense of
        the Early Netherlandish painters.  Working in Ghent alongside Memling and
        Bouts, he shared their technical precision but transformed it through an
        expressionistic weight and psychological urgency that anticipates
        Expressionism by four centuries.  His Portinari Altarpiece (c. 1475–76,
        Uffizi) is the most psychologically powerful large-scale painting of the
        15th century: its figures carry visible spiritual burden.

        Three operations encoding van der Goes' defining qualities:

          1. Warm shadow enrichment — In shadow zones (lum in [shadow_lo,
             shadow_hi]), amplify warm amber undertones: R + shadow_amber_r,
             B − shadow_amber_b.  Van der Goes' shadows are exclusively warm
             (amber-to-near-black), with no Flemish blue-green subsurface tint.
             The darks approach a velvety velour warmth — deep but not cold.
             The mask is cosine-shaped for smooth zone boundary transitions.

          2. Psychological weight through midtone earthing — In the upper-midtone
             zone (lum in [midtone_lo, midtone_hi]), apply a slight amber-brown
             pull: R + midtone_earth_r, G + midtone_earth_g, B − midtone_earth_b.
             This makes the flesh feel earthbound and weighty rather than idealized
             or radiant.  It is the quality that separates van der Goes from the
             serene, luminous Memling: his figures have gravity, presence, and
             a slightly troubled earthliness.

          3. Near-black void deepening — In the absolute darks (lum < void_thresh),
             apply a uniform RGB reduction of void_deepen.  Van der Goes placed
             his figures against near-absence — atmospheric near-black backgrounds
             that anticipate Caravaggio.  This deepens those voids without
             shifting them toward cool neutral: the darkness is warm and enveloping.

        Parameters
        ----------
        shadow_lo        : lower lum boundary of warm shadow zone
        shadow_hi        : upper lum boundary of shadow zone
        shadow_amber_r   : R boost in shadow zone (amber warmth)
        shadow_amber_b   : B reduction in shadow zone (damp cool subsurface)
        midtone_lo       : lower lum boundary of midtone earthing zone
        midtone_hi       : upper lum boundary of midtone earthing zone
        midtone_earth_r  : R boost in midtones (amber-brown earthing)
        midtone_earth_g  : G boost in midtones (warm ochre component)
        midtone_earth_b  : B reduction in midtones (pull away from cool)
        void_thresh      : lum threshold below which void deepening acts
        void_deepen      : uniform RGB reduction in near-black darks
        blur_radius      : Gaussian sigma for mask feathering
        opacity          : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Hugo van der Goes expressive depth pass "
              f"(shadow=[{shadow_lo:.2f},{shadow_hi:.2f}]  amber_r={shadow_amber_r:.3f}  "
              f"midtone=[{midtone_lo:.2f},{midtone_hi:.2f}]  earth_r={midtone_earth_r:.3f}  "
              f"void_thresh={void_thresh:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Hugo van der Goes expressive depth pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b0 = buf[:, :, 0].astype(_np.float32) / 255.0
        g0 = buf[:, :, 1].astype(_np.float32) / 255.0
        r0 = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── Stage 1: Warm shadow enrichment ───────────────────────────────────
        # Cosine-shaped mask peaking at the centre of [shadow_lo, shadow_hi].
        # Pixels in the shadow zone receive warm amber boost (R↑) and cool damp (B↓).
        shadow_mid  = (shadow_lo + shadow_hi) * 0.5
        shadow_half = max((shadow_hi - shadow_lo) * 0.5, 1e-6)
        raw_cos     = _np.cos(_np.pi * _np.clip(
            (lum - shadow_mid) / shadow_half, -1.0, 1.0))
        shadow_mask = _np.clip(raw_cos, 0.0, 1.0)
        shadow_mask = _gf(shadow_mask, sigma=blur_radius)
        sw          = shadow_mask * opacity

        r_out = _np.clip(r_out + sw * shadow_amber_r, 0.0, 1.0)
        b_out = _np.clip(b_out - sw * shadow_amber_b, 0.0, 1.0)

        # ── Stage 2: Psychological weight through midtone earthing ────────────
        # Bell-shaped mask over [midtone_lo, midtone_hi].
        # Amber-brown pull in flesh midtones → weighty, earthy presence.
        midtone_mid  = (midtone_lo + midtone_hi) * 0.5
        midtone_half = max((midtone_hi - midtone_lo) * 0.5, 1e-6)
        midtone_bell = _np.clip(
            1.0 - _np.abs(lum - midtone_mid) / midtone_half, 0.0, 1.0)
        midtone_mask = _gf(midtone_bell, sigma=blur_radius)
        mw           = midtone_mask * opacity

        r_out = _np.clip(r_out + mw * midtone_earth_r, 0.0, 1.0)
        g_out = _np.clip(g_out + mw * midtone_earth_g, 0.0, 1.0)
        b_out = _np.clip(b_out - mw * midtone_earth_b, 0.0, 1.0)

        # ── Stage 3: Near-black void deepening ───────────────────────────────
        # Hard threshold: absolute darks (lum < void_thresh) uniformly deepened.
        # Feathered near the threshold for a smooth transition.
        void_ramp = _np.clip(1.0 - lum / max(void_thresh, 1e-6), 0.0, 1.0)
        void_mask = _gf(void_ramp, sigma=blur_radius * 0.5)
        vw        = void_mask * opacity

        r_out = _np.clip(r_out - vw * void_deepen, 0.0, 1.0)
        g_out = _np.clip(g_out - vw * void_deepen, 0.0, 1.0)
        b_out = _np.clip(b_out - vw * void_deepen, 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Hugo van der Goes expressive depth pass complete.")

    def gerrit_dou_fijnschilder_pass(
        self,
        highlight_lo:        float = 0.62,   # lower lum bound of enamel micro-smoothing zone
        highlight_hi:        float = 0.95,   # upper lum bound of enamel micro-smoothing zone
        enamel_strength:     float = 0.55,   # strength of micro-smoothing: 0=none, 1=fully polished
        candle_lo:           float = 0.72,   # lower lum threshold for candle-warm gold shift
        candle_amber_r:      float = 0.022,  # R boost in candle-lit highlights (warm amber)
        candle_amber_g:      float = 0.010,  # G boost in candle-lit highlights (slight ochre)
        candle_amber_b:      float = 0.008,  # B reduction in candle-lit highlights (damp cool)
        candle_x:            float = 0.72,   # candle source X position in image-space [0,1]
        candle_y:            float = 0.12,   # candle source Y position in image-space [0,1]
        candle_radius:       float = 0.65,   # radial falloff radius of candle gradient (image-diagonal fracs)
        candle_gradient_str: float = 0.038,  # peak warm R boost at candle source centre
        blur_radius:         float = 4.0,    # Gaussian sigma for mask feathering
        opacity:             float = 0.38,   # overall pass composite opacity
    ) -> None:
        """
        Gerrit Dou fijnschilder pass — session 94 new artist pass.

        Gerrit Dou (1613–1675) was Rembrandt's first and most celebrated pupil in
        Leiden, and the founder of the fijnschilder ('fine painter') tradition.
        He represents the technical apex of Dutch Golden Age surface refinement:
        his oil paintings are composed of up to thirty or more translucent glaze
        layers, achieving a surface quality that contemporaries compared to enamel
        or polished ivory.  He reportedly used a magnifying glass while painting
        and waited for dust to settle before resuming, to preserve the perfect
        smoothness of the working surface.

        This pass encodes three defining qualities of Dou's technique:

          1. Enamel micro-smoothing (the fijnschilder quality) — In bright skin
             zones (lum in [highlight_lo, highlight_hi]), apply very gentle Gaussian
             smoothing at sigma = enamel_strength × 1.8 (range 0–1.8 pixels),
             creating the glass-like surface polish of 30+ glaze layers.  The
             smoothed layer is composited against the original at low opacity to
             retain underlying texture while adding luminous surface fineness.
             This is distinct from sfumato (which dissolves edges) — Dou's surfaces
             are polished, not misty.

          2. Candle-warm highlight gold — In the upper highlights (lum > candle_lo),
             apply a warm amber-gold shift: R + candle_amber_r, G + candle_amber_g,
             B − candle_amber_b.  Dou's later works (The Night School, Woman Reading
             by Candlelight) are defined by the warm amber quality of candlelight:
             brighter than Rembrandt's tenebrism, more intimate than La Tour's
             pure flame.  The highlight colour shift simulates the warm point-source
             illumination of a candle held just off-canvas.

          3. Point-source candle gradient (session 94 artistic improvement) — A
             radial warm gradient emanates from (candle_x, candle_y) in image-space,
             peaking at the source position and falling off with distance.  The
             warm channel (R) is lifted by candle_gradient_str at the source and
             falls smoothly to zero at candle_radius.  This creates the sense of
             a warm point source of light (a candle or lamp just outside the
             frame), warming the near side of the figure and letting the far side
             cool gently.  Unlike de_hooch_threshold_light_pass (which handles
             horizontal door-light), this gradient simulates a candle at a fixed
             3D position — it wraps around the figure's near edge, falls off over
             the body, and creates a gentle warm glow in the background near the
             source.  The effect is subtle at candle_gradient_str=0.038: barely
             perceptible as a colour shift, but meaningful as a spatial warmth
             that unifies the upper-right area of the composition.

        Parameters
        ----------
        highlight_lo         : lower lum boundary of enamel micro-smoothing zone
        highlight_hi         : upper lum boundary of enamel micro-smoothing zone
        enamel_strength      : smoothing strength 0=none, 1=full fijnschilder polish
        candle_lo            : lower lum threshold for candle-warm highlight gold shift
        candle_amber_r       : R boost in candle-lit highlights (warm amber)
        candle_amber_g       : G boost in candle-lit highlights (slight ochre)
        candle_amber_b       : B reduction in candle-lit highlights (damp cool)
        candle_x             : candle source X in image-space [0=left, 1=right]
        candle_y             : candle source Y in image-space [0=top, 1=bottom]
        candle_radius        : radial falloff radius (fraction of image diagonal)
        candle_gradient_str  : peak warm R boost at candle source (session 94 improvement)
        blur_radius          : Gaussian sigma for mask feathering
        opacity              : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Gerrit Dou fijnschilder pass "
              f"(enamel={enamel_strength:.2f}  candle_lo={candle_lo:.2f}  "
              f"candle_amber_r={candle_amber_r:.3f}  "
              f"candle_src=({candle_x:.2f},{candle_y:.2f})  "
              f"gradient_str={candle_gradient_str:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Gerrit Dou fijnschilder pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        buf  = _np.frombuffer(self.canvas.surface.get_data(),
                              dtype=_np.uint8).reshape((h, w, 4)).copy()
        orig = buf.copy()

        # Cairo stores BGRA
        b0 = buf[:, :, 0].astype(_np.float32) / 255.0
        g0 = buf[:, :, 1].astype(_np.float32) / 255.0
        r0 = buf[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── Stage 1: Enamel micro-smoothing (fijnschilder surface fineness) ───
        # Bell-shaped mask over [highlight_lo, highlight_hi]; peaks at midpoint.
        # In this zone, apply gentle Gaussian smoothing (sigma ∝ enamel_strength)
        # and composite the smoothed version against the original at the mask weight.
        # The result: highlights become glass-smooth without erasing all texture.
        if enamel_strength > 0.0:
            sigma = enamel_strength * 1.8   # max sigma ≈ 1.8 pixels at full strength
            hl_mid  = (highlight_lo + highlight_hi) * 0.5
            hl_half = max((highlight_hi - highlight_lo) * 0.5, 1e-6)
            hl_bell = _np.clip(
                1.0 - _np.abs(lum - hl_mid) / hl_half, 0.0, 1.0)
            hl_mask = _gf(hl_bell, sigma=blur_radius)

            # Smooth each channel independently
            r_smooth = _gf(r_out, sigma=sigma)
            g_smooth = _gf(g_out, sigma=sigma)
            b_smooth = _gf(b_out, sigma=sigma)

            # Composite: in the bright zone, blend toward the smoothed version
            ew = hl_mask * opacity * 0.6    # enamel weight: up to 0.6× of opacity in zone
            r_out = r_out * (1.0 - ew) + r_smooth * ew
            g_out = g_out * (1.0 - ew) + g_smooth * ew
            b_out = b_out * (1.0 - ew) + b_smooth * ew

        # ── Stage 2: Candle-warm highlight gold ───────────────────────────────
        # Linear ramp from candle_lo to 1.0; full warm-amber shift at lum=1.0.
        # Adds the characteristic warm candle illumination of Dou's later works.
        candle_ramp = _np.clip((lum - candle_lo) / max(1.0 - candle_lo, 1e-6),
                               0.0, 1.0)
        candle_mask = _gf(candle_ramp, sigma=blur_radius * 0.5)
        cw = candle_mask * opacity

        r_out = _np.clip(r_out + cw * candle_amber_r, 0.0, 1.0)
        g_out = _np.clip(g_out + cw * candle_amber_g, 0.0, 1.0)
        b_out = _np.clip(b_out - cw * candle_amber_b, 0.0, 1.0)

        # ── Stage 3: Point-source candle gradient (session 94 improvement) ───
        # Build a radial warm gradient from (candle_x, candle_y) in image-space.
        # Pixel (px, py) in normalised coords: distance d to source.
        # warm_lift = candle_gradient_str × max(0, 1 − d / candle_radius).
        # Lifts R channel (warm amber) near the candle source, fading to zero
        # at candle_radius; creates the sense of a warm point light just off-frame.
        diag     = _np.sqrt(float(h)**2 + float(w)**2)
        ys       = _np.linspace(0.0, 1.0, h, dtype=_np.float32)[:, _np.newaxis]
        xs       = _np.linspace(0.0, 1.0, w, dtype=_np.float32)[_np.newaxis, :]
        dist     = _np.sqrt((xs - candle_x)**2 + (ys - candle_y)**2)
        grad     = _np.clip(1.0 - dist / candle_radius, 0.0, 1.0)
        grad     = _gf(grad, sigma=blur_radius * 1.5)
        gw       = grad * candle_gradient_str * opacity

        r_out = _np.clip(r_out + gw, 0.0, 1.0)
        # Slight G lift at ~40% of R lift (amber rather than pure red)
        g_out = _np.clip(g_out + gw * 0.40, 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Gerrit Dou fijnschilder pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Carel Fabritius — contre-jour pass (session 95)
    # ─────────────────────────────────────────────────────────────────────────

    def fabritius_contre_jour_pass(
        self,
        shadow_threshold:   float = 0.32,   # lum below which cool ground veil is applied
        cool_veil_strength: float = 0.055,  # magnitude of cool grey lift in deep shadows
        cool_veil_b_boost:  float = 0.030,  # extra B channel lift for cool shadow tint
        edge_sigma:         float = 1.8,    # Gaussian sigma for edge detection (luminance)
        edge_threshold:     float = 0.08,   # minimum gradient magnitude to be considered an edge
        bloom_sigma:        float = 5.0,    # Gaussian sigma for the contre-jour halo bloom
        bloom_strength:     float = 0.065,  # peak luminosity lift of the contre-jour bloom
        mid_cool_lo:        float = 0.38,   # lower lum bound of atmospheric mid-tone cool tint
        mid_cool_hi:        float = 0.65,   # upper lum bound of atmospheric mid-tone cool tint
        mid_cool_strength:  float = 0.018,  # magnitude of cool grey haze in mid-tones
        blur_radius:        float = 3.0,    # Gaussian sigma for mask feathering
        opacity:            float = 0.40,   # overall pass composite opacity (0–1)
    ) -> None:
        """
        Carel Fabritius contre-jour pass — session 95 new artist pass.

        Carel Fabritius (1622–1654) was Rembrandt's most gifted pupil and the
        teacher of Johannes Vermeer.  He died at 32 in the Delft gunpowder
        explosion of 1654, taking nearly all his work with him, but the handful
        of surviving paintings — above all The Goldfinch (1654, Mauritshuis) —
        reveal a revolutionary approach to light that anticipates Vermeer and,
        in some ways, the Impressionists.

        While Rembrandt built light from dark — painting on warm brown grounds
        and coaxing luminosity upward through glaze layers — Fabritius invented
        the reverse.  He painted on pale grey-white grounds, so that the bright
        background radiates through thin glazes, and his figures read as warm
        masses against a cool, luminous field.  This contre-jour (light-against-
        light) principle transforms the spatial language of Dutch painting: forms
        are not isolated spotlit presences in a void but atmospheric shapes
        embedded in ambient, diffused daylight.

        This pass encodes three defining qualities:

          1. Cool ground veil (shadow luminosity) — In deep shadow regions
             (lum < shadow_threshold), add a gentle cool grey lift to both R, G, B,
             with a slight extra boost to B.  This simulates the pale grey ground
             showing through thin glazes in the shadow zones — Fabritius's shadows
             are cool and luminous, not warm and opaque like Rembrandt's.  The
             effect is subtle (cool_veil_strength ≈ 0.055) but structurally
             important: it prevents the shadows from becoming dead and dark,
             keeping the entire surface alive with reflected ground luminosity.

          2. Contre-jour edge bloom — Detect significant luminance gradient
             boundaries (edge_sigma Gaussian gradient ≥ edge_threshold), then
             apply a soft Gaussian bloom (bloom_sigma) to the brighter side of
             each edge.  This simulates the characteristic contre-jour glow where
             a figure silhouette reads against a bright background — the background
             light wraps around the form's edge, creating a luminous halo that
             separates the figure from the ground without any hard outline.  In
             The Goldfinch, this bloom is what makes the bird's wing-tip glow
             against the pale wall: not a highlight painted on the bird, but
             ambient light radiating around it.

          3. Atmospheric mid-tone cool haze — In the mid-luminance range
             [mid_cool_lo, mid_cool_hi], apply a very gentle cool grey tint to
             all channels, slightly emphasising R and B equally.  This unifies
             the surface with Fabritius's pale ground quality: even in the lit
             flesh zones, there is a faint cool ambient presence that prevents
             the image from reading as warm-ground Baroque.  Distinct from the
             shadow veil (which is purely in deep darks), this haze inhabits the
             transitional mid-tones and keeps them airy.

        Together these three effects encode the spatial logic of contre-jour
        painting: bright, cool-grounded backgrounds that push against warm figure
        masses, with luminous edge halos at the boundaries and an atmosphere of
        diffused grey-white ambient light throughout.

        Parameters
        ----------
        shadow_threshold   : lum below which cool ground veil is applied
        cool_veil_strength : uniform grey lift magnitude in shadow zone
        cool_veil_b_boost  : additional B channel lift for cool shadow tint
        edge_sigma         : Gaussian sigma for luminance gradient edge detection
        edge_threshold     : minimum gradient magnitude to qualify as an edge
        bloom_sigma        : Gaussian sigma for contre-jour halo bloom
        bloom_strength     : peak luminosity lift of the bloom (added to bright side)
        mid_cool_lo        : lower lum bound for atmospheric mid-tone cool tint
        mid_cool_hi        : upper lum bound for atmospheric mid-tone cool tint
        mid_cool_strength  : magnitude of cool grey haze in mid-tones
        blur_radius        : Gaussian sigma for mask feathering
        opacity            : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w
        diag  = (h * h + w * w) ** 0.5

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()

        # cairo stores BGRA; extract float channels
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── Luminance ─────────────────────────────────────────────────────────
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Cool ground veil in deep shadow zones ──────────────────────────
        # Where lum < shadow_threshold, add a gentle uniform grey lift (cool tint).
        # The lift is strongest at lum=0 and tapers off linearly to zero at
        # shadow_threshold, preserving the tonal gradient without flattening blacks.
        shadow_mask = _np.clip((shadow_threshold - lum) / (shadow_threshold + 1e-6), 0.0, 1.0)
        shadow_mask = _gf(shadow_mask.astype(_np.float32), blur_radius)
        shadow_mask = _np.clip(shadow_mask, 0.0, 1.0)

        veil = shadow_mask * cool_veil_strength
        r_out = _np.clip(r_out + veil, 0.0, 1.0)
        g_out = _np.clip(g_out + veil, 0.0, 1.0)
        b_out = _np.clip(b_out + veil + shadow_mask * cool_veil_b_boost, 0.0, 1.0)

        # ── 2. Contre-jour edge bloom ─────────────────────────────────────────
        # Detect luminance edges via gradient magnitude, then bloom the brighter
        # side to simulate contre-jour halo around figure silhouettes.
        lum_smooth = _gf(lum.astype(_np.float32), edge_sigma)

        # Compute gradient magnitude (simple forward differences)
        dy = _np.diff(lum_smooth, axis=0, append=lum_smooth[-1:, :])
        dx = _np.diff(lum_smooth, axis=1, append=lum_smooth[:, -1:])
        grad_mag = _np.sqrt(dx * dx + dy * dy)

        # Edge mask: where gradient magnitude exceeds threshold
        edge_mask = (grad_mag > edge_threshold).astype(_np.float32)
        edge_mask = _gf(edge_mask, blur_radius)
        edge_mask = _np.clip(edge_mask, 0.0, 1.0)

        # Bloom: blur the luminance around edges to simulate radiating ground light
        # The bloom is applied on the brighter side — we use the luminance itself
        # as a weight so that already-bright regions get the brightest halos.
        lum_bloom_src = _np.clip(lum * edge_mask, 0.0, 1.0)
        bloom = _gf(lum_bloom_src.astype(_np.float32), bloom_sigma)
        bloom = _np.clip(bloom * bloom_strength * 2.5, 0.0, bloom_strength)

        r_out = _np.clip(r_out + bloom, 0.0, 1.0)
        g_out = _np.clip(g_out + bloom, 0.0, 1.0)
        b_out = _np.clip(b_out + bloom * 1.08, 0.0, 1.0)  # bloom is slightly cooler

        # ── 3. Atmospheric mid-tone cool haze ─────────────────────────────────
        # In [mid_cool_lo, mid_cool_hi], add a gentle equal-channel grey lift that
        # unifies the surface with the pale ground quality — airy, not heavy.
        mid_weight = _np.clip(
            (lum - mid_cool_lo) / (mid_cool_hi - mid_cool_lo + 1e-6), 0.0, 1.0
        ) * _np.clip(
            (mid_cool_hi - lum) / (mid_cool_hi - mid_cool_lo + 1e-6), 0.0, 1.0
        )
        mid_weight = mid_weight * 4.0  # sharpen the bell-curve peak
        mid_weight = _np.clip(mid_weight, 0.0, 1.0)
        mid_weight = _gf(mid_weight.astype(_np.float32), blur_radius)
        mid_weight = _np.clip(mid_weight, 0.0, 1.0)

        haze = mid_weight * mid_cool_strength
        r_out = _np.clip(r_out + haze, 0.0, 1.0)
        g_out = _np.clip(g_out + haze, 0.0, 1.0)
        b_out = _np.clip(b_out + haze, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Carel Fabritius contre-jour pass complete.")

    def judith_leyster_joyful_light_pass(
        self,
        highlight_lo:        float = 0.65,   # lower lum bound of incandescent warm-lift zone
        highlight_amber_r:   float = 0.032,  # R boost in candlelit highlights (amber warmth)
        highlight_amber_g:   float = 0.014,  # G boost in candlelit highlights (slight ochre)
        highlight_amber_b:   float = 0.018,  # B reduction in candlelit highlights (damp blue)
        shadow_hi:           float = 0.28,   # upper lum bound of shadow-vitality zone
        shadow_warm_r:       float = 0.022,  # R lift in shadow zone (warm imprimatura show-through)
        shadow_warm_g:       float = 0.012,  # G lift in shadow zone
        shadow_warm_b:       float = 0.004,  # B lift in shadow zone (very slight, keeps warmth)
        mid_lo:              float = 0.35,   # lower lum bound of mid-tone chromatic animation zone
        mid_hi:              float = 0.60,   # upper lum bound of mid-tone chromatic animation zone
        mid_amber_r:         float = 0.018,  # R ping in mid-tones (joyful transitional warmth)
        mid_amber_g:         float = 0.008,  # G ping in mid-tones
        mid_amber_b:         float = 0.006,  # B reduction in mid-tones (keep warm)
        blur_radius:         float = 3.5,    # Gaussian sigma for mask feathering
        opacity:             float = 0.42,   # overall pass composite opacity (0–1)
    ) -> None:
        """
        Judith Leyster joyful light pass — session 96 new artist pass.

        Judith Leyster (1609–1660) was one of the most gifted painters of the Dutch
        Golden Age — a contemporary and near-neighbour of Frans Hals in Haarlem, and
        in 1633 one of the very few women admitted to the Haarlem Guild of St. Luke.
        She ran her own independent workshop with male apprentices, an extraordinary
        achievement in the seventeenth century.

        Leyster's technique synthesises the bravura directness she absorbed from Hals
        with the warm amber tonal register of the Utrecht Caravaggists (Honthorst,
        Terbrugghen).  Her defining mode is the single figure caught in a moment of
        private joy — a fiddler laughing, a child blowing a soap bubble, a seamstress
        at work by candlelight.  Unlike the cool extroversion of Hals or the pure
        tenebrism of La Tour, Leyster's scenes breathe with a warm, animated vitality
        that comes from three distinct tonal strategies:

          1. Incandescent highlight warm-lift — In upper highlight zones (lum >
             highlight_lo), add a warm amber-peach shift: R + highlight_amber_r,
             G + highlight_amber_g, B − highlight_amber_b.  Leyster's candle-source
             illumination heats the peaks of flesh to an orange-amber incandescence —
             warmer than Dou's refined highlight gold, more domestic than La Tour's
             open flame.  The effect makes lit cheeks, noses, and knuckles glow as
             though lit from within.

          2. Shadow vitality (warm imprimatura show-through) — In deep shadow zones
             (lum < shadow_hi), add a gentle warm-brown lift across all channels,
             weighted toward R.  This simulates Leyster's warm brown imprimatura
             (in the Hals/Haarlem tradition) showing through thin shadow glazes.
             Where Rembrandt's shadows read as chiaroscuro drama and Fabritius's as
             cool ground luminosity, Leyster's shadows retain a mellow amber warmth —
             they are alive and habitable, not void.  The lift is very slight
             (shadow_warm_r ≈ 0.022) but preserves the shadow zones from going neutral
             or cold, maintaining the warm imprimatura foundation throughout.

          3. Mid-tone chromatic animation (session 96 artistic improvement) — In the
             transitional lum zone [mid_lo, mid_hi], add a subtle warm amber ping:
             R + mid_amber_r, G + mid_amber_g, B − mid_amber_b.  This is the zone
             where Leyster's figures feel most alive — the half-shadow of a cheek
             turning away from the candle, the lower lip catching ambient warmth, the
             temple just below the peak highlight.  Prior sessions have accumulated
             techniques for the extremes (highlight bloom, shadow veil, sfumato) but
             the mid-tone register — the transitional flesh between full light and full
             shadow — has been cooler than Leyster's warm candlelit model demands.
             The mid-tone ping animates this zone with amber warmth, making the
             transitional passages glow with the characteristic joyful incandescence
             that defines her genre scenes.

        Together these three effects encode the spatial logic of Leyster's candlelit
        warmth: incandescent peaks, luminous warm shadows, and an animated mid-tone
        bridge between them — a tonal system unified by the amber-brown warmth of her
        imprimatura and the domestic joy of her subject matter.

        Parameters
        ----------
        highlight_lo       : lower lum threshold for incandescent warm-lift zone
        highlight_amber_r  : R boost in candlelit highlights (warm amber)
        highlight_amber_g  : G boost in candlelit highlights (slight ochre)
        highlight_amber_b  : B reduction in candlelit highlights (damp cool)
        shadow_hi          : upper lum threshold for shadow-vitality zone
        shadow_warm_r      : R lift in shadows (warm imprimatura show-through)
        shadow_warm_g      : G lift in shadows
        shadow_warm_b      : B lift in shadows (very slight)
        mid_lo             : lower lum bound of mid-tone chromatic animation zone
        mid_hi             : upper lum bound of mid-tone chromatic animation zone
        mid_amber_r        : R ping in mid-tones (joyful transitional warmth)
        mid_amber_g        : G ping in mid-tones
        mid_amber_b        : B reduction in mid-tones (maintain amber warmth)
        blur_radius        : Gaussian sigma for mask feathering
        opacity            : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy(); g_out = g0.copy(); b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # 1. Incandescent highlight warm-lift
        hi_mask = _np.clip((lum - highlight_lo) / (1.0 - highlight_lo + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_mask.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * highlight_amber_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * highlight_amber_g, 0.0, 1.0)
        b_out = _np.clip(b_out - hi_mask * highlight_amber_b, 0.0, 1.0)

        # 2. Shadow vitality — warm imprimatura show-through
        shadow_mask = _np.clip((shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0)
        shadow_mask = _gf(shadow_mask.astype(_np.float32), blur_radius)
        shadow_mask = _np.clip(shadow_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + shadow_mask * shadow_warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + shadow_mask * shadow_warm_g, 0.0, 1.0)
        b_out = _np.clip(b_out + shadow_mask * shadow_warm_b, 0.0, 1.0)

        # 3. Mid-tone chromatic animation
        mid_mask = _np.clip(
            (lum - mid_lo) / (mid_hi - mid_lo + 1e-6), 0.0, 1.0
        ) * _np.clip(
            (mid_hi - lum) / (mid_hi - mid_lo + 1e-6), 0.0, 1.0
        )
        mid_mask = mid_mask * 4.0
        mid_mask = _np.clip(mid_mask, 0.0, 1.0)
        mid_mask = _gf(mid_mask.astype(_np.float32), blur_radius)
        mid_mask = _np.clip(mid_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + mid_mask * mid_amber_r, 0.0, 1.0)
        g_out = _np.clip(g_out + mid_mask * mid_amber_g, 0.0, 1.0)
        b_out = _np.clip(b_out - mid_mask * mid_amber_b, 0.0, 1.0)

        # Composite at opacity
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Judith Leyster joyful light pass complete.")

    def hals_alla_prima_vivacity_pass(
        self,
        face_cx:          float = 0.515,  # face centre X as fraction of width
        face_cy:          float = 0.215,  # face centre Y as fraction of height
        face_rx:          float = 0.18,   # face ellipse half-width (fractions)
        face_ry:          float = 0.22,   # face ellipse half-height (fractions)
        tache_strength:   float = 0.022,  # amplitude of directional tache modulation
        tache_sigma:      float = 2.4,    # Gaussian sigma for gradient direction map smoothing
        tache_frequency:  float = 14.0,   # spatial frequency of implied brushstroke rhythm
        vivacity_lo:      float = 0.35,   # lower lum bound for alla prima warm vivacity zone
        vivacity_hi:      float = 0.78,   # upper lum bound for alla prima warm vivacity zone
        warm_r_lift:      float = 0.018,  # warm R lift in mid-tone vivacity zone
        shadow_thresh:    float = 0.30,   # lum below which shadow warm lift applies
        shadow_warm_r:    float = 0.012,  # warm R lift in shadow zone (imprimatura reading through)
        crisp_sigma:      float = 1.0,    # unsharp mask sigma for focal face sharpening
        crisp_amount:     float = 0.14,   # unsharp mask amplitude for focal face
        blur_radius:      float = 4.0,    # Gaussian sigma for mask feathering
        opacity:          float = 0.35,   # overall pass composite opacity (0–1)
    ) -> None:
        """
        Frans Hals alla prima vivacity pass — session 96 new artist pass.

        Frans Hals (1582/3–1666) was the great master of alla prima ('all at
        once') oil painting — a technique in which an entire portrait is
        completed in a single energetic session without waiting for paint to
        dry.  The result is a surface animated by visible, directional
        brushmarks called taches: confident, loaded-brush strokes that follow
        the contours of a face, placed once and never overworked.

        This pass encodes three defining qualities of Hals's technique:

          1. Directional tache energy — The pipeline's first pass to work with
             the luminance gradient direction field rather than luminance
             magnitude thresholds or spatial positions.  The gradient direction
             at each pixel indicates which way the form is 'going'; the implied
             brushstroke direction is orthogonal to this (strokes follow the
             form, not cut across it).  A sine modulation along the orthogonal
             direction adds subtle rhythmic luminance variation that reads as
             confident, contour-following mark-making — the visual signature of
             Hals's tache surface — without adding literal strokes.

          2. Warm mid-tone vivacity — In the vivacity zone [vivacity_lo,
             vivacity_hi], add a gentle R channel lift that simulates the warm
             amber-brown imprimatura showing through thin alla prima paint.
             Hals's flesh warmth comes not from glazing (he did not glaze) but
             from the ground visible through the paint in transition zones.

          3. Focal psychological crispness — Apply a subtle unsharp mask in the
             face region to heighten the sense of direct psychological presence
             and eye contact that defines Hals's portraits.

        Parameters
        ----------
        face_cx, face_cy   : face ellipse centre (fraction of width/height)
        face_rx, face_ry   : face ellipse radii (fraction of width/height)
        tache_strength     : amplitude of directional luminance modulation
        tache_sigma        : Gaussian sigma for smoothing the gradient direction map
        tache_frequency    : spatial frequency of the sine modulation (cycles per image)
        vivacity_lo/hi     : luminance range for tache and vivacity effects
        warm_r_lift        : R channel boost in vivacity zone (imprimatura warmth)
        shadow_thresh      : lum below which shadow warm lift applies
        shadow_warm_r      : R lift in shadow zone (warm ground reading through)
        crisp_sigma        : unsharp mask Gaussian sigma for face sharpening
        crisp_amount       : unsharp mask amplitude
        blur_radius        : Gaussian sigma for soft mask feathering
        opacity            : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()

        # cairo stores BGRA; extract float channels
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── Luminance ─────────────────────────────────────────────────────────
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Vivacity zone mask ────────────────────────────────────────────────
        vivacity_mask = _np.clip(
            (lum - vivacity_lo) / (vivacity_hi - vivacity_lo + 1e-6), 0.0, 1.0
        ) * _np.clip(
            (vivacity_hi - lum) / (vivacity_hi - vivacity_lo + 1e-6), 0.0, 1.0
        ) * 4.0
        vivacity_mask = _np.clip(vivacity_mask, 0.0, 1.0)
        vivacity_mask = _gf(vivacity_mask.astype(_np.float32), blur_radius)
        vivacity_mask = _np.clip(vivacity_mask, 0.0, 1.0)

        # ── 1. Directional tache energy ───────────────────────────────────────
        # Compute luminance gradient direction at each pixel.  The orthogonal
        # direction (gradient + 90°) is the implied brushstroke direction — strokes
        # follow the form contours rather than cutting across them.
        lum_smooth = _gf(lum.astype(_np.float32), tache_sigma)

        gy = _np.diff(lum_smooth, axis=0, append=lum_smooth[-1:, :])
        gx = _np.diff(lum_smooth, axis=1, append=lum_smooth[:, -1:])

        # Tache direction is perpendicular to luminance gradient
        tache_angle = _np.arctan2(gy, gx) + _np.pi / 2.0

        # Coordinate grids normalised to [0, 1]
        ys_grid = _np.linspace(0.0, 1.0, h, dtype=_np.float32)[:, _np.newaxis]
        xs_grid = _np.linspace(0.0, 1.0, w, dtype=_np.float32)[_np.newaxis, :]

        # Project pixel coordinates onto the tache direction and modulate with
        # a sine wave — creating rhythmic variation along implied stroke direction.
        tache_proj = (xs_grid * _np.cos(tache_angle)
                      + ys_grid * _np.sin(tache_angle))
        tache_mod = _np.sin(tache_proj * tache_frequency * _np.pi * 2.0)
        tache_mod = tache_mod.astype(_np.float32) * tache_strength * vivacity_mask

        r_out = _np.clip(r_out + tache_mod, 0.0, 1.0)
        g_out = _np.clip(g_out + tache_mod * 0.80, 0.0, 1.0)  # slightly less green
        b_out = _np.clip(b_out + tache_mod * 0.60, 0.0, 1.0)  # less blue: warm taches

        # ── 2. Warm mid-tone vivacity (imprimatura showing through thin paint) ─
        warm_lift = vivacity_mask * warm_r_lift
        r_out = _np.clip(r_out + warm_lift, 0.0, 1.0)

        # Shadow zone: warm ground reading through thin paint in deep shadows
        shadow_mask = _np.clip(
            (shadow_thresh - lum) / (shadow_thresh + 1e-6), 0.0, 1.0
        )
        shadow_mask = _gf(shadow_mask.astype(_np.float32), blur_radius)
        shadow_mask = _np.clip(shadow_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + shadow_mask * shadow_warm_r, 0.0, 1.0)

        # ── 3. Focal psychological crispness (face unsharp mask) ──────────────
        ys_px, xs_px = _np.ogrid[:h, :w]
        cx_px = face_cx * w
        cy_px = face_cy * h
        rx_px = face_rx * w
        ry_px = face_ry * h
        face_d2 = ((xs_px - cx_px) / (rx_px + 1e-6)) ** 2 + \
                  ((ys_px - cy_px) / (ry_px + 1e-6)) ** 2
        face_weight = _np.clip(1.0 - face_d2, 0.0, 1.0) ** 2
        face_weight = _gf(face_weight.astype(_np.float32), blur_radius)
        face_weight = _np.clip(face_weight, 0.0, 1.0)

        # Unsharp mask: sharpen = original + amount * (original − blurred)
        r_blur_usm = _gf(r_out.astype(_np.float32), crisp_sigma)
        g_blur_usm = _gf(g_out.astype(_np.float32), crisp_sigma)
        b_blur_usm = _gf(b_out.astype(_np.float32), crisp_sigma)

        r_sharp = _np.clip(r_out + crisp_amount * (r_out - r_blur_usm), 0.0, 1.0)
        g_sharp = _np.clip(g_out + crisp_amount * (g_out - g_blur_usm), 0.0, 1.0)
        b_sharp = _np.clip(b_out + crisp_amount * (b_out - b_blur_usm), 0.0, 1.0)

        r_out = r_out * (1.0 - face_weight) + r_sharp * face_weight
        g_out = g_out * (1.0 - face_weight) + g_sharp * face_weight
        b_out = b_out * (1.0 - face_weight) + b_sharp * face_weight

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]

        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Frans Hals alla prima vivacity pass complete.")

    def hals_bravura_stroke_pass(
        self,
        reference:        Optional[Union[np.ndarray, Image.Image]] = None,
        n_strokes:        int   = 200,
        stroke_size:      float = 7.0,
        opacity:          float = 0.55,
        angle_jitter_deg: float = 30.0,
        color_jitter:     float = 0.025,
        broken_tone:      bool  = True,
        figure_mask:      Optional[np.ndarray] = None,
    ) -> None:
        """
        Frans Hals bravura stroke pass — session 96 alla prima stroke layer.

        Frans Hals (1582/3–1666) completed entire portraits in a single session
        of wet-on-wet oil paint, placing each tache (confident loaded-brush
        stroke) once and never overworking it.  The strokes follow the contours
        of the face and drapery, varying in angle by ±angle_jitter_deg from
        the underlying flow field — the hallmark of bravura alla prima.

        When broken_tone=True, a slight per-stroke colour variation is applied
        before placement, simulating the 'broken tone' effect of wet-into-wet
        paint that picks up slightly different pigment mixes at each mark.

        Parameters
        ----------
        reference        : optional reference image (PIL or ndarray); if None,
                           the current canvas state is used as the source colours.
        n_strokes        : number of strokes to place (0 = no-op).
        stroke_size      : characteristic stroke length in pixels.
        opacity          : stroke opacity.
        angle_jitter_deg : ± angle variation from the flow-field direction (deg).
        color_jitter     : per-stroke colour variation amplitude.
        broken_tone      : when True, apply slight tonal variation per stroke.
        figure_mask      : optional (H, W) float32 mask biasing stroke placement.
        """
        if n_strokes == 0:
            return  # explicit noop

        h, w = self.h, self.w

        # ── Resolve reference ─────────────────────────────────────────────────
        if reference is None:
            # Use current canvas as the colour source
            cbuf = np.frombuffer(
                self.canvas.surface.get_data(), dtype=np.uint8
            ).reshape(h, w, 4).copy()
            # Convert BGRA → RGB
            ref = np.stack([cbuf[:, :, 2], cbuf[:, :, 1], cbuf[:, :, 0],
                            np.full((h, w), 255, dtype=np.uint8)], axis=2)
        else:
            ref = self._prep(reference)

        # ── Broken-tone: inject slight colour variation into reference ─────────
        if broken_tone and color_jitter > 0.0:
            noise = self.rng.uniform(-color_jitter, color_jitter,
                                     (h, w, 3)).astype(np.float32)
            ref_f = ref[:, :, :3].astype(np.float32) + noise * 255.0
            ref_f = np.clip(ref_f, 0, 255).astype(np.uint8)
            ref = np.concatenate([ref_f, ref[:, :, 3:4]], axis=2)

        # ── Place strokes ─────────────────────────────────────────────────────
        # Hals: low wet_blend (alla prima directness), high jitter, moderate
        # curvature (strokes follow form contours, not mechanical parallels).
        self._place_strokes(
            ref,
            stroke_size  = stroke_size,
            n_strokes    = n_strokes,
            opacity      = opacity,
            wet_blend    = 0.12,           # alla prima: no deep blending across strokes
            jitter_amt   = color_jitter,   # per-stroke colour variation
            curvature    = 0.12,           # form-following: strokes curve with contours
            tip          = BrushTip(BrushTip.FILBERT),
            stroke_mask  = figure_mask if figure_mask is not None else self._figure_mask,
        )
        print(f"    Frans Hals bravura stroke pass complete. ({n_strokes} strokes, "
              f"size={stroke_size:.1f}, broken_tone={broken_tone})")

    def luini_leonardesque_glow_pass(
        self,
        highlight_lo:        float = 0.70,
        ivory_r:             float = 0.028,
        ivory_g:             float = 0.016,
        ivory_b:             float = 0.006,
        shadow_hi:           float = 0.32,
        shadow_violet_b:     float = 0.018,
        shadow_violet_g:     float = 0.006,
        shadow_violet_r:     float = 0.004,
        flesh_lo:            float = 0.40,
        flesh_hi:            float = 0.74,
        smooth_sigma:        float = 1.6,
        smooth_strength:     float = 0.55,
        blur_radius:         float = 4.0,
        opacity:             float = 0.40,
    ) -> None:
        """
        Bernardino Luini leonardesque glow pass — session 97 new artist pass.

        Bernardino Luini (c. 1480/85–1532) was the most celebrated and prolific
        follower of Leonardo da Vinci in Milan.  Working in the immediate wake of
        Leonardo's Milanese period (1482–1499 and 1506–1513), Luini absorbed the
        master's sfumato technique so thoroughly that, until the nineteenth century,
        several of his works were attributed to Leonardo himself.  Giorgio Vasari
        described him as "gracious and very sweet in colouring."

        Luini distilled Leonardo's innovations into a distinctive personal idiom:
        he retained the sfumato edge dissolution and multi-glaze surface polish, but
        simplified the psychological complexity, producing Madonna-type portraits of
        extraordinary surface delicacy and warm serenity.  His flesh surfaces are
        among the smoothest in the entire Renaissance tradition — even smoother and
        more seamlessly blended than Leonardo's own — while his shadows carry a
        delicate cool-violet quality that Leonardo's Milanese works established as
        the northern Italian shadow standard.

        This pass encodes three defining qualities of Luini's Milanese technique:

          1. Warm-ivory highlight clarification — In upper highlight zones
             (lum > highlight_lo), add a gentle warm-ivory push: R + ivory_r,
             G + ivory_g, B + ivory_b.  Luini's highest flesh lights glow with
             a luminous warm-ivory quality — cream rather than silver, golden-
             ivory rather than pure ochre.  This is lead-white ground reading
             through thin warm glaze.

          2. Cool-violet shadow delicacy — In deep shadow zones (lum < shadow_hi),
             add a very faint cool-blue-violet lift: B + shadow_violet_b,
             G + shadow_violet_g, R − shadow_violet_r.  Leonardo established in
             Milan the principle that shadows should carry the colour of ambient
             sky or reflected environment.  In Luini's portraits this manifests
             as a barely perceptible violet-grey quality in the deepest shadow
             passages — atmospheric rather than visible, a quality rather than a
             colour.

          3. Sfumato flesh surface smoothing — In the transitional mid-tone zone
             [flesh_lo, flesh_hi], blend toward a gently Gaussian-smoothed version
             of the current canvas at smooth_strength.  Luini's flesh surfaces are
             even more seamlessly polished than Leonardo's own — technical analysis
             of Susanna at the Bath and the Madonna delle Rose reveals a surface so
             smooth that individual glaze layers cannot be detected by eye.

        Apply after sfumato_veil_pass() for maximum coherence; the ivory lift in
        this pass complements sfumato_veil_pass(highlight_ivory_lift=...) introduced
        in the same session.

        Parameters
        ----------
        highlight_lo       : lower lum threshold for warm-ivory highlight zone
        ivory_r            : R lift in highlights
        ivory_g            : G lift in highlights
        ivory_b            : B lift in highlights (very slight — ivory not cold white)
        shadow_hi          : upper lum threshold for cool-violet shadow zone
        shadow_violet_b    : B lift in shadows (ambient sky / cool air quality)
        shadow_violet_g    : G lift in shadows
        shadow_violet_r    : R reduction in shadows (removes warm cast)
        flesh_lo           : lower lum bound of sfumato smoothing zone
        flesh_hi           : upper lum bound of sfumato smoothing zone
        smooth_sigma       : Gaussian sigma for flesh surface smoothing
        smooth_strength    : blend fraction toward smoothed canvas in flesh zone
        blur_radius        : Gaussian sigma for mask feathering
        opacity            : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Warm-ivory highlight clarification ─────────────────────────────
        hi_mask = _np.clip(
            (lum - highlight_lo) / (1.0 - highlight_lo + 1e-6), 0.0, 1.0
        )
        hi_mask = _gf(hi_mask.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * ivory_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * ivory_g, 0.0, 1.0)
        b_out = _np.clip(b_out + hi_mask * ivory_b, 0.0, 1.0)

        # ── 2. Cool-violet shadow delicacy ────────────────────────────────────
        sh_mask = _np.clip(
            (shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0
        )
        sh_mask = _gf(sh_mask.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        r_out = _np.clip(r_out - sh_mask * shadow_violet_r, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * shadow_violet_g, 0.0, 1.0)
        b_out = _np.clip(b_out + sh_mask * shadow_violet_b, 0.0, 1.0)

        # ── 3. Sfumato flesh surface smoothing ────────────────────────────────
        flesh_mask = _np.clip(
            (lum - flesh_lo) / (flesh_hi - flesh_lo + 1e-6), 0.0, 1.0
        ) * _np.clip(
            (flesh_hi - lum) / (flesh_hi - flesh_lo + 1e-6), 0.0, 1.0
        ) * 4.0
        flesh_mask = _np.clip(flesh_mask, 0.0, 1.0)
        flesh_mask = _gf(flesh_mask.astype(_np.float32), blur_radius)
        flesh_mask = _np.clip(flesh_mask, 0.0, 1.0)

        r_smooth = _gf(r_out.astype(_np.float32), smooth_sigma)
        g_smooth = _gf(g_out.astype(_np.float32), smooth_sigma)
        b_smooth = _gf(b_out.astype(_np.float32), smooth_sigma)

        blend_w = flesh_mask * smooth_strength
        r_out = r_out * (1.0 - blend_w) + r_smooth * blend_w
        g_out = g_out * (1.0 - blend_w) + g_smooth * blend_w
        b_out = b_out * (1.0 - blend_w) + b_smooth * blend_w

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Bernardino Luini leonardesque glow pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Federico Barocci — petal flush pass (session 98)
    # ─────────────────────────────────────────────────────────────────────────

    def barocci_petal_flush_pass(
        self,
        penumbra_lo:            float = 0.42,   # lower lum bound of petal flush zone
        penumbra_hi:            float = 0.62,   # upper lum bound of petal flush zone
        rose_r:                 float = 0.022,  # R boost in penumbra (warm rose)
        rose_g:                 float = 0.008,  # G boost in penumbra (slight tint)
        rose_b:                 float = 0.010,  # B reduction in penumbra (dampen cool)
        bianca_lo:              float = 0.58,   # lower lum bound of bianca luminosity zone
        bianca_hi:              float = 0.82,   # upper lum bound of bianca luminosity zone
        bianca_r:               float = 0.018,  # R lift in bianca zone (warm ground showing)
        bianca_g:               float = 0.012,  # G lift in bianca zone
        bianca_b:               float = 0.006,  # B lift in bianca zone (warm, not cool)
        edge_dissolve_sigma:    float = 2.2,    # Gaussian sigma for warm perimeter dissolution
        edge_dissolve_radius:   float = 0.72,   # relative radius beyond which dissolution begins
        edge_dissolve_strength: float = 0.35,   # blend fraction toward dissolved in perimeter
        blur_radius:            float = 4.0,
        opacity:                float = 0.38,
    ) -> None:
        """
        Federico Barocci petal flush pass — session 98 new artist pass.

        Federico Barocci (c. 1535–1612) was the supreme colorist of Umbrian
        Mannerism and the critical bridge between late-Renaissance tradition and
        the fully realised Baroque.  Born in Urbino in the Marche, he worked
        almost exclusively for central Italy, rejecting prestigious commissions
        from Rome.  Rubens owned Barocci drawings; Annibale Carracci and Bellori
        both recognised in him the qualities that the Bolognese reform would
        systematise a generation later.

        Barocci's most distinctive technical achievement was his use of chalk
        pastel studies ('pasteletti') as full colour preparatory tools — among
        the first Italian artists to employ pastels for colour exploration rather
        than pure draughtsmanship.  This practice fed directly into his oil
        technique: each surface was built from multiple warm-cool glaze layers
        over a luminous warm ground (the 'bianca'), creating a quality that
        appears almost pastellic — soft, powdery, translucent — while retaining
        the optical depth of oil glazing.

        His defining quality is the handling of the penumbra — the transitional
        zone between direct light and shadow.  Where Leonardo dissolved this with
        grey sfumato, and Rembrandt charged it with psychological weight, Barocci
        filled it with warm rose-pink luminosity uniquely his own.  This petal
        flush — soft, warm, slightly rosy — gives his flesh a quality closer to
        living skin than paint: the cheek turned from the light carries a warm
        rose breath, as if internal warmth rises through the surface from within.

        This pass encodes three defining qualities of Barocci's technique:

          1. Petal flush — In the penumbra zone [penumbra_lo, penumbra_hi], the
             critical Barocci signature: add a warm rose-pink bloom (R + rose_r,
             G + rose_g, B - rose_b).  This is the 'pasteletti' quality translated
             into oil — the transitional zone carries living rose warmth rather
             than cool grey dissolution.  Feathered with Gaussian blur for organic
             distribution.

          2. Bianca ground luminosity — In the upper mid-tone zone
             [bianca_lo, bianca_hi], add a warm creamy lift (R + bianca_r,
             G + bianca_g, B + bianca_b) simulating the pale warm 'bianca'
             ground reading through multiple thin transparent glazes — the
             paper-white luminosity visible in the Vatican Annunciation and
             the Uffizi Madonna of the People.

          3. Warm perimeter dissolution — In the outer region of the composition
             (distance > edge_dissolve_radius from canvas centre), apply a gentle
             Gaussian softening (sigma = edge_dissolve_sigma) at
             edge_dissolve_strength.  Barocci borrowed Leonardo's sfumato edge
             loss but warmed and colourised it: figures dissolve into warm
             ambient haze rather than grey smoke.

        Session 98 artistic improvement: the penumbra as a first-class bloom
        target.  Prior sessions have treated highlights (session 83 highlight
        bloom) and shadows (multiple sessions) as zones of special attention.
        Barocci reveals that the penumbra — the half-lit transitional zone —
        is where a painting's warmth lives.  The petal flush introduces a new
        concept to the pipeline: the penumbra bloom, a targeted warm-rose
        stimulus in the light-to-shadow transition.  This zone is distinct from
        the Leyster mid-tone animation (session 96, lum 0.35–0.60, amber) in
        that it is specifically rose-pink rather than amber, and is focused on
        the upper half of the mid-tone range where light first begins to
        withdraw — the precise location of Barocci's signature warmth.

        Parameters
        ----------
        penumbra_lo       : lower lum threshold of petal flush zone
        penumbra_hi       : upper lum threshold of petal flush zone
        rose_r            : R boost in penumbra (warm rose)
        rose_g            : G boost in penumbra
        rose_b            : B reduction in penumbra (dampen cool cast)
        bianca_lo         : lower lum threshold of bianca luminosity zone
        bianca_hi         : upper lum threshold of bianca luminosity zone
        bianca_r          : R lift in bianca zone
        bianca_g          : G lift in bianca zone
        bianca_b          : B lift in bianca zone
        edge_dissolve_sigma    : Gaussian sigma for warm perimeter dissolution
        edge_dissolve_radius   : relative distance from centre beyond which dissolution applies
        edge_dissolve_strength : blend fraction toward dissolved in periphery
        blur_radius       : Gaussian sigma for mask feathering
        opacity           : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Petal flush — penumbra rose bloom ─────────────────────────────
        # Build a soft tent mask over [penumbra_lo, penumbra_hi]
        petal_mask = _np.clip(
            (lum - penumbra_lo) / (penumbra_hi - penumbra_lo + 1e-6), 0.0, 1.0
        ) * _np.clip(
            (penumbra_hi - lum) / (penumbra_hi - penumbra_lo + 1e-6), 0.0, 1.0
        ) * 4.0
        petal_mask = _np.clip(petal_mask, 0.0, 1.0)
        petal_mask = _gf(petal_mask.astype(_np.float32), blur_radius)
        petal_mask = _np.clip(petal_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + petal_mask * rose_r,  0.0, 1.0)
        g_out = _np.clip(g_out + petal_mask * rose_g,  0.0, 1.0)
        b_out = _np.clip(b_out - petal_mask * rose_b,  0.0, 1.0)

        # ── 2. Bianca ground luminosity — upper mid-tone warm lift ────────────
        bianca_mask = _np.clip(
            (lum - bianca_lo) / (bianca_hi - bianca_lo + 1e-6), 0.0, 1.0
        ) * _np.clip(
            (bianca_hi - lum) / (bianca_hi - bianca_lo + 1e-6), 0.0, 1.0
        ) * 4.0
        bianca_mask = _np.clip(bianca_mask, 0.0, 1.0)
        bianca_mask = _gf(bianca_mask.astype(_np.float32), blur_radius)
        bianca_mask = _np.clip(bianca_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + bianca_mask * bianca_r, 0.0, 1.0)
        g_out = _np.clip(g_out + bianca_mask * bianca_g, 0.0, 1.0)
        b_out = _np.clip(b_out + bianca_mask * bianca_b, 0.0, 1.0)

        # ── 3. Warm perimeter dissolution ─────────────────────────────────────
        # Build a distance-from-centre mask for the outer rim.
        ys, xs = _np.mgrid[0:h, 0:w]
        cx = w * 0.515
        cy = h * 0.50
        # Normalise distances by canvas half-diagonals so radius is consistent.
        dist = _np.sqrt(
            ((xs - cx) / (w * 0.5)) ** 2 + ((ys - cy) / (h * 0.5)) ** 2
        )
        perimeter_mask = _np.clip(
            (dist - edge_dissolve_radius) / (1.0 - edge_dissolve_radius + 1e-6),
            0.0, 1.0
        )
        perimeter_mask = _gf(perimeter_mask.astype(_np.float32), blur_radius)
        perimeter_mask = _np.clip(perimeter_mask, 0.0, 1.0)

        # Softly blur the output in the periphery zone (warm dissolution)
        r_soft = _gf(r_out.astype(_np.float32), edge_dissolve_sigma)
        g_soft = _gf(g_out.astype(_np.float32), edge_dissolve_sigma)
        b_soft = _gf(b_out.astype(_np.float32), edge_dissolve_sigma)
        w_blend = perimeter_mask * edge_dissolve_strength
        r_out = r_out * (1.0 - w_blend) + r_soft * w_blend
        g_out = g_out * (1.0 - w_blend) + g_soft * w_blend
        b_out = b_out * (1.0 - w_blend) + b_soft * w_blend

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()

    # ── Session 99 — Pierre Bonnard / Chromatic Intimisme ────────────────────

    def bonnard_chromatic_vibration_pass(
        self,
        *,
        mid_lo: float = 0.28,
        mid_hi: float = 0.76,
        warm_amp: float = 0.030,
        cool_amp: float = 0.025,
        noise_scale: float = 18.0,
        noise_octaves: int = 4,
        noise_persistence: float = 0.50,
        blur_radius: float = 3.5,
        opacity: float = 0.35,
        rng_seed: int = 99,
    ) -> None:
        """
        Bonnard chromatic vibration — Session 99 artistic improvement.

        Pierre Bonnard (1867–1947) developed his most distinctive late technique
        at Villa Le Bosquet, Le Cannet (c. 1920–1947): a pervasive warm/cool
        oscillation throughout the mid-tone zone of every surface.  Unlike
        Seurat's systematic pointillist dots or the Impressionists' atmospheric
        broken colour, Bonnard's vibration is organic and emotional — patches of
        warm cadmium-yellow push alternate with patches of cool violet-cerulean
        pull, spatially distributed by an intuitive irregular rhythm rather than
        a grid or theory.

        The result is a chromatic shimmer: the eye reads the warm/cool pairs
        simultaneously as colour and as light, making the surface appear to pulse
        and breathe.  This is the quality that distinguishes his Le Cannet
        interiors from all other Post-Impressionist work — an optical vibration
        that transcends the actual luminance range of the pigments.

        Session 99 artistic improvement: chromatic vibration as a pervasive
        surface quality.  Prior sessions have added tonal passes (Whistler,
        session 87), penumbra blooms (Barocci, session 98), and sfumato veils
        (Leonardo, session 82/89/97).  Bonnard introduces a new axis: not
        tonal unity but chromatic aliveness — the warm/cool oscillation that
        makes every mid-tone zone feel inhabited by light rather than merely
        lit by it.

        Implementation:

          1. Build a spatial oscillation field using layered Perlin noise —
             this gives an organic, irregular rhythm to the warm/cool patches
             (noise > 0 = warm phase; noise ≤ 0 = cool phase).

          2. Warm phase: in pixels where noise > 0 AND lum ∈ [mid_lo, mid_hi],
             apply +R warm_amp, -B warm_amp * 0.55 (cadmium-yellow / orange push).

          3. Cool phase: in pixels where noise ≤ 0 AND lum ∈ [mid_lo, mid_hi],
             apply +B cool_amp, -R cool_amp * 0.45 (violet / cerulean push).

          4. Apply a small Gaussian blur (sigma = blur_radius) to soften the raw
             noise boundary so the warm/cool beats blend organically rather than
             reading as hard-edged patches.

          5. Composite at opacity.

        Parameters
        ----------
        mid_lo           : lower luminance threshold for mid-tone zone
        mid_hi           : upper luminance threshold for mid-tone zone
        warm_amp         : magnitude of warm oscillation (R boost / B dampen)
        cool_amp         : magnitude of cool oscillation (B boost / R dampen)
        noise_scale      : Perlin noise frequency (higher = finer oscillation patches)
        noise_octaves    : Perlin octave count for organic detail
        noise_persistence: Perlin persistence (controls contrast of noise field)
        blur_radius      : Gaussian sigma for softening oscillation boundaries
        opacity          : overall composite opacity (0–1)
        rng_seed         : random seed for reproducibility
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from noise import pnoise2 as _pn2

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Build organic oscillation field via Perlin noise ──────────────────
        # The noise field maps each pixel to a warm/cool phase value.
        # Values > 0 → warm push; values ≤ 0 → cool push.
        # A fixed offset from rng_seed shifts the noise origin for each session.
        inv_w = 1.0 / w
        inv_h = 1.0 / h
        osc = _np.zeros((h, w), dtype=_np.float32)
        ox = (rng_seed * 37.1) % 100.0   # stable but session-unique offset
        oy = (rng_seed * 53.7) % 100.0
        for y in range(h):
            for x in range(w):
                osc[y, x] = _pn2(
                    x * inv_w * noise_scale + ox,
                    y * inv_h * noise_scale + oy,
                    octaves=noise_octaves,
                    persistence=noise_persistence,
                )

        # ── Build mid-tone mask — tent function over [mid_lo, mid_hi] ─────────
        mid_mask = _np.clip(
            (lum - mid_lo) / (mid_hi - mid_lo + 1e-6), 0.0, 1.0
        ) * _np.clip(
            (mid_hi - lum) / (mid_hi - mid_lo + 1e-6), 0.0, 1.0
        ) * 4.0
        mid_mask = _np.clip(mid_mask, 0.0, 1.0)

        # ── Warm phase — cadmium yellow / orange push ─────────────────────────
        # +R, -B in pixels where noise > 0
        warm_phase = _np.clip(osc, 0.0, None)          # positive lobe
        warm_phase = warm_phase / (warm_phase.max() + 1e-6)  # normalise to [0,1]
        warm_field = warm_phase * mid_mask
        warm_field = _gf(warm_field.astype(_np.float32), blur_radius)
        warm_field = _np.clip(warm_field, 0.0, 1.0)

        r_out = _np.clip(r0 + warm_field * warm_amp,           0.0, 1.0)
        g_out = g0.copy()
        b_out = _np.clip(b0 - warm_field * warm_amp * 0.55,    0.0, 1.0)

        # ── Cool phase — violet / cerulean push ───────────────────────────────
        # +B, -R in pixels where noise ≤ 0
        cool_phase = _np.clip(-osc, 0.0, None)          # negative lobe flipped
        cool_phase = cool_phase / (cool_phase.max() + 1e-6)
        cool_field = cool_phase * mid_mask
        cool_field = _gf(cool_field.astype(_np.float32), blur_radius)
        cool_field = _np.clip(cool_field, 0.0, 1.0)

        r_out = _np.clip(r_out - cool_field * cool_amp * 0.45, 0.0, 1.0)
        b_out = _np.clip(b_out + cool_field * cool_amp,        0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf_out = orig.copy()
        buf_out[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf_out.tobytes()

    def masaccio_architectonic_mass_pass(
        self,
        shadow_lo:         float = 0.05,
        shadow_hi:         float = 0.32,
        shadow_deepen:     float = 0.05,
        penumbra_lo:       float = 0.28,
        penumbra_hi:       float = 0.54,
        penumbra_contrast: float = 0.08,
        lit_lo:            float = 0.62,
        earth_r:           float = 0.018,
        earth_g:           float = 0.012,
        blur_radius:       float = 5.0,
        opacity:           float = 0.28,
    ) -> None:
        """
        Masaccio architectonic mass — Session 100 artistic improvement.

        Tommaso di Ser Giovanni di Simone, called Masaccio (1401–1428), achieved
        in six short years what no Italian painter had managed in over a century:
        the convincing illusion of three-dimensional mass in paint.  His Brancacci
        Chapel frescoes (c. 1424–1427) and the Trinity at Santa Maria Novella
        (c. 1427) remain the founding monuments of naturalistic Western painting.
        The revolutionary instrument was directional natural light applied with
        absolute consistency — a single source from the upper-left that catches the
        high planes of face and drapery and drops dense architectural shadows behind
        every projecting form.

        The defining quality of Masaccio's shadow modelling is what can be called
        'architectonic mass': the penumbra transition — the band of tones between
        the lit plane and the deep shadow — is narrow, decisive, and physically
        convincing.  It does not dissolve gradually (as Leonardo's sfumato would do
        three generations later) but transitions with a controlled sharpness that
        reads as the edge of a real three-dimensional surface catching or losing the
        light.  This is the quality Berenson described as 'tactile values': the
        viewer's visual cortex registers a physical object that could be touched,
        not a decorative pattern on a flat surface.

        Session 100 centennial artistic improvement: architectonic mass restoration.
        After 99 sessions of accumulated sfumato-heavy, atmosphere-dissolving passes,
        the Mona Lisa figure risks losing its sculptural foundation.  This pass
        restores Masaccio's lesson: deep shadows have genuine weight, lit planes
        have warm ochre radiance, and the penumbra between them has a physical
        decisiveness that anchors the entire form.

        The effect is deliberately subtle (opacity=0.28) so it reads as solidity
        beneath the atmospheric surface of the prior sessions rather than a visible
        stylistic intrusion.  The figure gains gravity; the sfumato gains something
        to rest on.

        Implementation:

          1. Deep shadow deepening: in pixels where lum ∈ [shadow_lo, shadow_hi],
             multiply all channels toward black by shadow_deepen, using a smooth
             ramp-in and ramp-out so the effect is zero at both boundaries.
             This prevents the sfumato-heavy deep shadows from reading as neutral
             grey mid-tones; they retain their architectural void.

          2. Penumbra contrast boost: in pixels where lum ∈ [penumbra_lo, penumbra_hi],
             apply a gentle S-curve contrast enhancement (penumbra_contrast).  The
             S-curve lifts lums above the band midpoint and depresses lums below it,
             sharpening the physical edge of the shadow/light boundary — the
             Masaccio 'found edge' of light catching a projecting plane.

          3. Lit-side ochre warm lift: in pixels where lum > lit_lo, add a warm
             ochre channel boost (earth_r, earth_g) proportional to (lum - lit_lo).
             This echoes the burnt-sienna/ochre palette of Masaccio's fresco
             technique and reinforces the directional upper-left light source.

          4. All effects are blurred with a Gaussian sigma = blur_radius before
             compositing, so transitions are smooth and don't create visible
             banding artefacts.

          5. The figure mask is respected: background and landscape zones are
             excluded so the sculptural weight applies only to the figure.

        Parameters
        ----------
        shadow_lo           : lower lum boundary of deep-shadow deepening zone
        shadow_hi           : upper lum boundary of deep-shadow deepening zone
        shadow_deepen       : multiplicative deepening magnitude in shadow zone
        penumbra_lo         : lower lum boundary of penumbra contrast zone
        penumbra_hi         : upper lum boundary of penumbra contrast zone
        penumbra_contrast   : S-curve contrast amplitude in penumbra zone
        lit_lo              : lower lum threshold for warm ochre lit-side lift
        earth_r             : R-channel ochre lift magnitude for lit side
        earth_g             : G-channel ochre lift magnitude for lit side
        blur_radius         : Gaussian sigma for transition smoothing
        opacity             : overall composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # Figure mask — restrict all effects to the figure zone
        if self._figure_mask is not None:
            fm = self._figure_mask.astype(_np.float32)
        else:
            fm = _np.ones((h, w), dtype=_np.float32)

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── 1. Deep shadow deepening ──────────────────────────────────────────
        # Smooth ramp: zero at shadow_lo and shadow_hi, peak at midpoint.
        band_w = shadow_hi - shadow_lo + 1e-6
        shadow_ramp = _np.clip(
            1.0 - _np.abs(2.0 * (lum - shadow_lo) / band_w - 1.0), 0.0, 1.0
        )
        shadow_ramp = _gf(shadow_ramp.astype(_np.float32), blur_radius)
        shadow_ramp = shadow_ramp * fm

        deepen_factor = shadow_ramp * shadow_deepen
        r_out = _np.clip(r_out - r_out * deepen_factor, 0.0, 1.0)
        g_out = _np.clip(g_out - g_out * deepen_factor, 0.0, 1.0)
        b_out = _np.clip(b_out - b_out * deepen_factor, 0.0, 1.0)

        # ── 2. Penumbra contrast boost (Masaccio found-edge sharpening) ───────
        # S-curve: above midpoint → lift; below midpoint → depress.
        p_mid = (penumbra_lo + penumbra_hi) * 0.5
        p_w   = penumbra_hi - penumbra_lo + 1e-6
        # Ramp mask — non-zero only in the penumbra band
        p_mask = _np.clip(
            1.0 - _np.abs(2.0 * (lum - penumbra_lo) / p_w - 1.0), 0.0, 1.0
        )
        p_mask = _gf(p_mask.astype(_np.float32), blur_radius)
        p_mask = p_mask * fm

        # S-curve direction: +1 above midpoint, -1 below
        s_dir = _np.where(lum >= p_mid, 1.0, -1.0).astype(_np.float32)
        s_field = p_mask * s_dir * penumbra_contrast

        r_out = _np.clip(r_out + s_field, 0.0, 1.0)
        g_out = _np.clip(g_out + s_field, 0.0, 1.0)
        b_out = _np.clip(b_out + s_field, 0.0, 1.0)

        # ── 3. Lit-side warm ochre lift ───────────────────────────────────────
        # Proportional to how far above lit_lo the pixel sits.
        lit_ramp = _np.clip((lum - lit_lo) / (1.0 - lit_lo + 1e-6), 0.0, 1.0)
        lit_ramp = _gf(lit_ramp.astype(_np.float32), blur_radius)
        lit_ramp = lit_ramp * fm

        r_out = _np.clip(r_out + lit_ramp * earth_r, 0.0, 1.0)
        g_out = _np.clip(g_out + lit_ramp * earth_g, 0.0, 1.0)
        # B is not lifted — ochre is warm, not neutral

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf_out = orig.copy()
        buf_out[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf_out.tobytes()
        print("    Federico Barocci petal flush pass complete.")

    # ──────────────────────────────────────────────────────────────────────────
    # SESSION 101 — Henri de Toulouse-Lautrec (1864–1901)
    # ──────────────────────────────────────────────────────────────────────────

    def lautrec_essence_pass(
        self,
        matte_str:      float = 0.11,
        hatch_angle:    float = 44.0,
        hatch_density:  float = 0.24,
        hatch_darkness: float = 0.08,
        mid_lo:         float = 0.22,
        mid_hi:         float = 0.62,
        warm_boost:     float = 0.06,
        cool_boost:     float = 0.045,
        blur_radius:    float = 3.5,
        opacity:        float = 0.30,
        rng_seed:       int   = 101,
    ) -> None:
        """Simulate Toulouse-Lautrec's 'peinture à l'essence' on cardboard.

        Three-stage pass:

        1. **Matte surface desaturation** — mild spatially-uniform saturation
           reduction that replaces the luminous oil-glaze surface with the dry,
           chalky quality of turpentine-diluted paint absorbed into raw cardboard.

        2. **Spidery diagonal hatching** — sparse parallel marks at ``hatch_angle``
           degrees in the mid-tone / shadow zone [``mid_lo`` – ``mid_hi``], each
           slightly darkening the pixel to simulate the cross-hatching of
           Lautrec's draughtsmanship.  Density is kept low so the texture reads
           as handmade rather than mechanical.

        3. **Warm-cool graphic separation** — pushes warm-dominant pixels toward
           mustard-amber and cool-dominant pixels toward blue-grey, echoing
           Lautrec's flat, Japonisme-influenced colour language where the warm
           cardboard ground opposes the cool shadow zones.

        Parameters
        ----------
        matte_str       : saturation reduction magnitude [0–1]; 0.10–0.14 typical
        hatch_angle     : diagonal hatch angle in degrees (42–48 ≈ 45°)
        hatch_density   : fraction of eligible pixels that receive a hatch mark
        hatch_darkness  : darkening magnitude applied to hatch pixels [0–1]
        mid_lo          : lower luminance boundary of hatch / warm-cool zone
        mid_hi          : upper luminance boundary of hatch / warm-cool zone
        warm_boost      : R-channel lift for warm-dominant pixels
        cool_boost      : B-channel lift for cool-dominant pixels
        blur_radius     : Gaussian sigma for transition smoothing
        opacity         : overall composite opacity (0–1)
        rng_seed        : RNG seed for reproducible hatching pattern
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        rng = _np.random.default_rng(rng_seed)
        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── 1. Matte surface desaturation ────────────────────────────────────
        # Pull each channel toward luminance by matte_str to kill the oil-glaze
        # sheen and leave the dry, chalky cardboard quality.
        r_out = _np.clip(r_out + (lum - r_out) * matte_str, 0.0, 1.0)
        g_out = _np.clip(g_out + (lum - g_out) * matte_str, 0.0, 1.0)
        b_out = _np.clip(b_out + (lum - b_out) * matte_str, 0.0, 1.0)

        # ── 2. Spidery diagonal hatching in mid-tone / shadow zone ───────────
        # Build a binary mask of pixels eligible for hatching: those in the
        # [mid_lo, mid_hi] luminance band.
        mid_mask = ((lum >= mid_lo) & (lum <= mid_hi)).astype(_np.float32)

        # Create a diagonal stripe field at hatch_angle degrees.  Each pixel's
        # projection onto the hatch direction gives a phase; pixels near the
        # zero-crossing of a sine wave are candidate hatch positions.
        angle_rad = _np.radians(hatch_angle)
        ys, xs = _np.mgrid[:h, :w]
        # Phase: projection of (x, y) onto the hatch-perpendicular direction,
        # then wrapped to [0, 1) with a spacing of ~6 pixels between strands.
        hatch_spacing = 6.0
        phase = (xs * _np.cos(angle_rad) + ys * _np.sin(angle_rad)) / hatch_spacing
        phase_frac = phase - _np.floor(phase)   # in [0, 1)

        # Mark pixels within the thinnest stripe zone as candidate hatch pixels.
        stripe_width = 0.18   # fraction of the spacing period that is 'on'
        stripe_mask = (phase_frac < stripe_width).astype(_np.float32)

        # Combine spatial stripe with luminance eligibility, then subsample by
        # hatch_density to keep the marks sparse and hand-drawn in character.
        combined = mid_mask * stripe_mask
        noise = rng.random((h, w)).astype(_np.float32)
        hatch_pixels = (combined > 0.5) & (noise < hatch_density)

        r_out[hatch_pixels] = _np.clip(r_out[hatch_pixels] - hatch_darkness, 0.0, 1.0)
        g_out[hatch_pixels] = _np.clip(g_out[hatch_pixels] - hatch_darkness, 0.0, 1.0)
        b_out[hatch_pixels] = _np.clip(b_out[hatch_pixels] - hatch_darkness, 0.0, 1.0)

        # Smooth the hatch layer slightly so single-pixel marks acquire a
        # hair-thin stroke quality rather than isolated pixel noise.
        r_hatch_effect = _gf((r0 - r_out).clip(0.0, 1.0), sigma=0.6)
        g_hatch_effect = _gf((g0 - g_out).clip(0.0, 1.0), sigma=0.6)
        b_hatch_effect = _gf((b0 - b_out).clip(0.0, 1.0), sigma=0.6)
        r_out = _np.clip(r0 - r_hatch_effect, 0.0, 1.0)
        g_out = _np.clip(g0 - g_hatch_effect, 0.0, 1.0)
        b_out = _np.clip(b0 - b_hatch_effect, 0.0, 1.0)

        # Re-apply the matte desaturation on top of the hatch output.
        lum2 = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
        r_out = _np.clip(r_out + (lum2 - r_out) * matte_str, 0.0, 1.0)
        g_out = _np.clip(g_out + (lum2 - g_out) * matte_str, 0.0, 1.0)
        b_out = _np.clip(b_out + (lum2 - b_out) * matte_str, 0.0, 1.0)

        # ── 3. Warm-cool graphic separation ──────────────────────────────────
        # In the mid-tone zone, identify warm-dominant pixels (R > B) and
        # push them toward mustard-amber; identify cool-dominant pixels
        # (B > R) and push them toward blue-grey.
        in_band = mid_mask  # already computed above

        warm_dominant = (r_out > b_out).astype(_np.float32) * in_band
        warm_ramp = _gf(warm_dominant, sigma=blur_radius)
        r_out = _np.clip(r_out + warm_ramp * warm_boost, 0.0, 1.0)
        g_out = _np.clip(g_out + warm_ramp * warm_boost * 0.45, 0.0, 1.0)

        cool_dominant = (b_out > r_out).astype(_np.float32) * in_band
        cool_ramp = _gf(cool_dominant, sigma=blur_radius)
        b_out = _np.clip(b_out + cool_ramp * cool_boost, 0.0, 1.0)
        r_out = _np.clip(r_out - cool_ramp * cool_boost * 0.30, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf_out = orig.copy()
        buf_out[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf_out.tobytes()
        print("    Toulouse-Lautrec essence pass complete.")

    def tissot_fashionable_gloss_pass(
        self,
        clarity_str:    float = 0.11,
        sheen_thresh:   float = 0.72,
        sheen_strength: float = 0.07,
        chroma_boost:   float = 0.06,
        mid_lo:         float = 0.28,
        mid_hi:         float = 0.72,
        highlight_cool: float = 0.04,
        blur_radius:    float = 4.0,
        opacity:        float = 0.27,
    ) -> None:
        """Simulate James Tissot's Victorian academic surface — fashionable gloss.

        Tissot's defining technical quality is what might be called 'fashionable
        gloss': the combination of an enamelled, lacquer-like surface finish with
        vivid chromatic richness in the dress fabrics and a crystalline cool-white
        quality in the finest silk highlights.  This is the surface of an academic
        painter who has studied how woven textiles reflect light at the micro-scale
        and reproduced it with systematic fidelity.

        Four-stage pass:

        1. **Enamel surface clarity** — mild unsharp-mask in the mid-tone band
           [``mid_lo`` – ``mid_hi``] (``clarity_str`` ≈ 0.10–0.14) that sharpens
           perceived surface detail without artificial HDR crunchiness.  Implemented
           as canvas - gaussian_blur(canvas, σ=``blur_radius``) * ``clarity_str``.

        2. **Specular surface sheen** — in pixels above ``sheen_thresh``, apply a
           luminance lift of ``sheen_strength`` that simulates the specular
           reflectance of fine silk and satin.  This is the micro-quality that makes
           Tissot's dress fabrics physically present rather than merely painted.

        3. **Chromatic richness** — in the warm mid-tone zone [``mid_lo`` –
           ``mid_hi``], boost saturation by ``chroma_boost`` by pulling each channel
           away from its luminance-grey equivalent in proportion to its existing
           colour deviation.  Replicates the vivid fabric quality of his fashionable
           interiors.

        4. **Cool highlight crystallization** — in the very brightest zones
           (lum > 0.85), apply a cool shift of ``highlight_cool`` (B↑, R↓) that
           turns hot-white into the crisp, crystalline whites of silk and linen under
           English afternoon light.  Distinct from the warm-ivory highlights of the
           sfumato tradition: Tissot's whites are cool and precise.

        Parameters
        ----------
        clarity_str     : unsharp-mask strength in mid-tones [0–1]; 0.09–0.13 typical
        sheen_thresh    : luminance threshold above which sheen is applied (0.70–0.76)
        sheen_strength  : luminance lift in the sheen zone [0–1]; 0.05–0.10 typical
        chroma_boost    : saturation increase in warm mid-tones [0–1]; 0.04–0.08 typical
        mid_lo          : lower luminance boundary of mid-tone zone for clarity + chroma
        mid_hi          : upper luminance boundary of mid-tone zone
        highlight_cool  : cool shift (B↑ R↓) in very bright highlight zone [0–1]
        blur_radius     : Gaussian sigma for unsharp-mask and zone transition smoothing
        opacity         : overall composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        # Cairo BGRA layout
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── 1. Enamel surface clarity (unsharp mask in mid-tone band) ─────────
        # Build mid-tone band mask, Gaussian-feathered for smooth transitions.
        mid_band = _np.clip(
            _np.minimum(lum - mid_lo, mid_hi - lum) / (0.5 * (mid_hi - mid_lo) + 1e-6),
            0.0, 1.0
        )
        mid_band = _gf(mid_band.astype(_np.float32), sigma=blur_radius)
        mid_band = _np.clip(mid_band, 0.0, 1.0)

        # Unsharp mask: sharpened = original + (original - blurred) * strength
        r_blur = _gf(r0, sigma=blur_radius)
        g_blur = _gf(g0, sigma=blur_radius)
        b_blur = _gf(b0, sigma=blur_radius)

        r_sharp = _np.clip(r0 + (r0 - r_blur) * clarity_str, 0.0, 1.0)
        g_sharp = _np.clip(g0 + (g0 - g_blur) * clarity_str, 0.0, 1.0)
        b_sharp = _np.clip(b0 + (b0 - b_blur) * clarity_str, 0.0, 1.0)

        # Apply sharpening only in mid-tone band
        r_out = r0 * (1.0 - mid_band) + r_sharp * mid_band
        g_out = g0 * (1.0 - mid_band) + g_sharp * mid_band
        b_out = b0 * (1.0 - mid_band) + b_sharp * mid_band

        # ── 2. Specular surface sheen in bright zones ─────────────────────────
        # Build a smooth sheen mask: pixels above sheen_thresh receive a
        # luminance lift proportional to how bright they already are.
        sheen_mask = _np.clip(
            (lum - sheen_thresh) / (1.0 - sheen_thresh + 1e-6), 0.0, 1.0
        )
        sheen_mask = _gf(sheen_mask.astype(_np.float32), sigma=blur_radius * 0.6)
        sheen_mask = _np.clip(sheen_mask * sheen_strength, 0.0, 1.0)

        # Apply sheen as a uniform luminance lift (preserves hue)
        r_out = _np.clip(r_out + sheen_mask, 0.0, 1.0)
        g_out = _np.clip(g_out + sheen_mask, 0.0, 1.0)
        b_out = _np.clip(b_out + sheen_mask, 0.0, 1.0)

        # ── 3. Chromatic richness in warm mid-tones ───────────────────────────
        # Pull each channel away from its luminance-grey equivalent to boost
        # saturation.  Applied only in the mid-tone band to avoid over-saturating
        # highlights or muddying the deep shadows.
        lum2 = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
        r_boost = _np.clip(r_out + (r_out - lum2) * chroma_boost * mid_band, 0.0, 1.0)
        g_boost = _np.clip(g_out + (g_out - lum2) * chroma_boost * mid_band, 0.0, 1.0)
        b_boost = _np.clip(b_out + (b_out - lum2) * chroma_boost * mid_band, 0.0, 1.0)
        r_out = r_boost
        g_out = g_boost
        b_out = b_boost

        # ── 4. Cool highlight crystallization ────────────────────────────────
        # In the very brightest zone (lum > 0.85), shift toward cool white:
        # B↑ R↓, making Tissot's silk highlights crisp and crystalline rather
        # than warm and ivory (Leonardo's approach).
        hi_mask = _np.clip((lum - 0.85) / (1.0 - 0.85 + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_mask.astype(_np.float32), sigma=blur_radius * 0.5)
        hi_mask = _np.clip(hi_mask * highlight_cool, 0.0, 1.0)

        r_out = _np.clip(r_out - hi_mask, 0.0, 1.0)
        b_out = _np.clip(b_out + hi_mask, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf_out = orig.copy()
        buf_out[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf_out.tobytes()
        print("    James Tissot fashionable gloss pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 103 — Carlo Dolci Florentine enamel pass
    # ─────────────────────────────────────────────────────────────────────────

    def dolci_florentine_enamel_pass(
        self,
        smooth_sigma:        float = 2.8,
        smooth_strength:     float = 0.55,
        flesh_lo:            float = 0.38,
        flesh_hi:            float = 0.84,
        shadow_lo:           float = 0.05,
        shadow_hi:           float = 0.32,
        shadow_depth_str:    float = 0.08,
        shadow_warm_r:       float = 0.040,
        shadow_warm_g:       float = 0.012,
        highlight_lo:        float = 0.80,
        highlight_lift:      float = 0.05,
        highlight_ivory_r:   float = 0.018,
        highlight_ivory_g:   float = 0.010,
        penumbra_lo:         float = 0.30,
        penumbra_hi:         float = 0.55,
        penumbra_amber_r:    float = 0.022,
        penumbra_amber_g:    float = 0.008,
        penumbra_amber_b:    float = 0.012,
        blur_radius:         float = 4.0,
        opacity:             float = 0.32,
    ) -> None:
        """
        Carlo Dolci (1616–1686) — Florentine devotional enamel surface pass.

        Carlo Dolci was the most technically obsessive painter of the Florentine
        Baroque, capable of spending years on a single figure in pursuit of a
        surface quality that approaches fine enamelware.  He built form through
        dozens of thin, transparent oil-glaze layers on copper panels, achieving
        a skin surface that is seamless, deep in its shadows, and crystalline in
        its highlights.

        This pass simulates four defining qualities of his devotional surface:

        1. **Enamel surface refinement** (smooth_sigma, smooth_strength, flesh_lo/hi):
           A local Gaussian smooth applied within the flesh/mid-tone luminance band,
           reducing micro-texture variation to simulate the glass-smooth quality of
           paint glazed over copper.  This is more thorough than Tissot's unsharp-mask
           clarity — it actively reduces variation rather than sharpening it.  Applied
           only in the flesh zone to preserve landscape texture.

        2. **Shadow depth enrichment** (shadow_lo/hi, shadow_depth_str, shadow_warm_*):
           In the deep shadow zone, warm walnut-brown glazes (R+ modest, G+ very slight,
           B not lifted) add interior depth without lifting the darks toward grey.
           The key Dolci quality: shadows feel warm and deep, not cool and opaque.

        3. **Crystal highlight clarification** (highlight_lo, highlight_lift,
           highlight_ivory_*): In the very brightest zones, a warm ivory lift (R+,
           G+ slight, B neutral) brings the highlight tip to near-white crystalline
           purity.  Unlike Tissot's cool crystallization (B↑ R↓), Dolci's highlights
           remain warm ivory — the goldsmith's touch on enamel.

        4. **Penumbra amber resonance** (penumbra_lo/hi, penumbra_amber_*):
           In the transition zone between light and shadow, a very faint warm-amber
           push (R+, G+ very slight, B-) simulates the amber radiance built from
           many transparent layers of warm-coloured glaze in the penumbra zone.

        Parameters
        ----------
        smooth_sigma        : Gaussian sigma for local smoothing within flesh band
        smooth_strength     : blend weight of the smoothed layer vs. original
        flesh_lo / flesh_hi : luminance range of the flesh zone to smooth
        shadow_lo / shadow_hi : luminance range of deep shadow zone
        shadow_depth_str    : strength of the shadow depth enrichment blend
        shadow_warm_r/g     : warm walnut-brown channel lifts in shadow zone
        highlight_lo        : lower luminance threshold for crystalline highlight zone
        highlight_lift      : overall luminance lift in highlight zone
        highlight_ivory_r/g : warm ivory channel lifts in highlight zone (R, G)
        penumbra_lo/hi      : luminance range of penumbra amber resonance zone
        penumbra_amber_r/g/b : amber channel shifts in penumbra zone (b is dampened)
        blur_radius         : Gaussian sigma for smooth zone-mask transitions
        opacity             : overall blend weight
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Dolci Florentine enamel pass "
              f"(smooth_sigma={smooth_sigma:.1f}  smooth_str={smooth_strength:.2f}  "
              f"shadow_depth={shadow_depth_str:.3f}  "
              f"highlight_lift={highlight_lift:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Dolci Florentine enamel pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        # Cairo BGRA layout
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── 1. Enamel surface refinement — local smoothing in flesh zone ──────
        # Build a smooth flesh-band mask and apply Gaussian smoothing within it.
        # This reduces micro-texture noise to simulate the glass-smooth quality
        # of paint built up through many glazes over copper.
        flesh_band = _np.clip(
            _np.minimum(lum - flesh_lo, flesh_hi - lum) / (0.5 * (flesh_hi - flesh_lo) + 1e-6),
            0.0, 1.0
        )
        flesh_band = _gf(flesh_band.astype(_np.float32), sigma=blur_radius)
        flesh_band = _np.clip(flesh_band, 0.0, 1.0)

        # Gaussian smooth of each channel
        r_smooth = _gf(r0, sigma=smooth_sigma)
        g_smooth = _gf(g0, sigma=smooth_sigma)
        b_smooth = _gf(b0, sigma=smooth_sigma)

        # Blend smooth into flesh zone only, weighted by smooth_strength
        blend = flesh_band * smooth_strength
        r_out = r0 * (1.0 - blend) + r_smooth * blend
        g_out = g0 * (1.0 - blend) + g_smooth * blend
        b_out = b0 * (1.0 - blend) + b_smooth * blend

        # ── 2. Shadow depth enrichment — warm walnut-brown glazes ─────────────
        # In the deep shadow zone, add a warm, concentrated amber-brown push.
        # R+ (warm walnut), G+ (very slight — earth brown), B unchanged.
        # This creates the "interior depth" quality of Dolci's glazed shadows.
        shadow_band = _np.clip(
            _np.minimum(lum - shadow_lo, shadow_hi - lum) / (0.5 * (shadow_hi - shadow_lo) + 1e-6),
            0.0, 1.0
        )
        shadow_band = _gf(shadow_band.astype(_np.float32), sigma=blur_radius)
        shadow_band = _np.clip(shadow_band, 0.0, 1.0)
        shadow_blend = shadow_band * shadow_depth_str

        r_out = _np.clip(r_out + shadow_blend * shadow_warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + shadow_blend * shadow_warm_g, 0.0, 1.0)
        # B: deliberately not lifted — keep shadows warm-brown, not neutral

        # ── 3. Crystal highlight clarification — warm ivory lift ──────────────
        # In the very brightest zones, bring the highlight tip to a pure warm
        # ivory.  Unlike Tissot's cool-crystalline (B↑ R↓), Dolci's highlights
        # remain warm — the goldsmith's touch on enamel, not English silk-white.
        hi_band = _np.clip(
            (lum - highlight_lo) / (1.0 - highlight_lo + 1e-6), 0.0, 1.0
        )
        hi_band = _gf(hi_band.astype(_np.float32), sigma=blur_radius * 0.5)
        hi_band = _np.clip(hi_band, 0.0, 1.0)

        r_out = _np.clip(r_out + hi_band * (highlight_lift + highlight_ivory_r), 0.0, 1.0)
        g_out = _np.clip(g_out + hi_band * (highlight_lift + highlight_ivory_g), 0.0, 1.0)
        b_out = _np.clip(b_out + hi_band * highlight_lift, 0.0, 1.0)

        # ── 4. Penumbra amber resonance — layered copper-panel warmth ─────────
        # In the transition zone between light and shadow, apply a concentrated
        # warm-amber push: the zone where Dolci's many transparent amber glazes
        # create maximum resonance, visually separating the warmly lit flesh from
        # the cooler deep shadow in a way that is characteristic of copper-panel
        # technique.
        pen_mid = (penumbra_lo + penumbra_hi) * 0.5
        pen_h   = max((penumbra_hi - penumbra_lo) * 0.5, 1e-8)
        pen_band = _np.clip(
            1.0 - _np.abs(lum - pen_mid) / pen_h, 0.0, 1.0
        )
        pen_band = _gf(pen_band.astype(_np.float32), sigma=blur_radius * 0.6)
        pen_band = _np.clip(pen_band, 0.0, 1.0)

        r_out = _np.clip(r_out + pen_band * penumbra_amber_r, 0.0, 1.0)
        g_out = _np.clip(g_out + pen_band * penumbra_amber_g, 0.0, 1.0)
        b_out = _np.clip(b_out - pen_band * penumbra_amber_b, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf_out = orig.copy()
        buf_out[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf_out.tobytes()
        print("    Carlo Dolci Florentine enamel pass complete.")

    def giordano_rapidita_luminosa_pass(
        self,
        aureole_cx:         float = 0.88,
        aureole_cy:         float = 0.06,
        aureole_radius:     float = 0.72,
        aureole_r:          float = 0.055,
        aureole_g:          float = 0.030,
        aureole_b:          float = 0.008,
        rim_strength:       float = 0.042,
        rim_sigma:          float = 3.0,
        shadow_hi:          float = 0.30,
        shadow_violet_b:    float = 0.014,
        shadow_violet_r:    float = 0.005,
        blur_radius:        float = 5.0,
        opacity:            float = 0.32,
    ) -> None:
        """
        Luca Giordano (1634–1705) — "Fa Presto" rapidità luminosa pass.

        Giordano was the most prodigiously fast and versatile painter of the Italian
        Baroque, capable of executing vast ceiling frescoes in weeks with sustained
        compositional energy and undiminished luminosity.  His defining illumination
        quality is a warm golden aureole sweeping from the upper-right — a theatrical
        celestial radiance characteristic of his altarpieces and ceiling compositions
        (Palazzo Medici-Riccardi, the Escorial, Certosa di San Martino).

        This pass simulates three defining qualities of his large-scale illumination:

        1. **Upper-right golden aureole** (aureole_cx/cy, aureole_radius, aureole_*):
           A warm golden radiance centred in the upper-right zone of the canvas,
           falling off gradually across the background with a large Gaussian radius.
           R+ strong, G+ moderate, B+ slight — simulating the warm golden light that
           enters from above in his theatrical ceiling compositions.  Applied with a
           distance-weighted mask so the effect is atmospheric and gradual, not a
           spotlight.

        2. **Warm rim on lit figure edges** (rim_strength, rim_sigma):
           A faint warm-gold brightening along the upper-lit edges of the figure,
           applied via a gradient of the figure mask's upper-right edge region.
           Simulates the way Giordano's figures are touched by theatrical upper
           illumination — a rim of gold separating figure from background.

        3. **Shadow violet depth** (shadow_hi, shadow_violet_*):
           In the deep shadow zone (lum < shadow_hi), a very faint cool-violet push
           (B+ slight, R+ tiny warm recovery) in the Venetian tradition absorbed from
           Titian and Ribera — the shadow colour that separates Giordano's Baroque
           warmth from the flat Caravaggio-black of pure tenebrism.

        Parameters
        ----------
        aureole_cx / aureole_cy : canvas-fraction coordinates of aureole centre (upper-right)
        aureole_radius          : Gaussian radius of the aureole falloff (as fraction of W)
        aureole_r/g/b           : warm golden channel lifts in the aureole zone
        rim_strength            : warm-gold rim brightening on lit figure edges
        rim_sigma               : Gaussian sigma for figure edge rim computation
        shadow_hi               : upper luminance threshold for the shadow violet zone
        shadow_violet_b / _r    : channel shifts in shadow zone (B up, R slight recovery)
        blur_radius             : Gaussian sigma for mask transitions
        opacity                 : overall blend weight
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Giordano rapidità luminosa pass "
              f"(aureole_r={aureole_r:.3f}  rim={rim_strength:.3f}  "
              f"shadow_violet_b={shadow_violet_b:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Giordano rapidità luminosa pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        # Cairo BGRA layout
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── Coordinate grids ──────────────────────────────────────────────────
        ys, xs = _np.mgrid[:h, :w]
        xs_f   = xs.astype(_np.float32) / w
        ys_f   = ys.astype(_np.float32) / h

        # ── 1. Upper-right golden aureole ─────────────────────────────────────
        # Distance from the upper-right aureole centre, normalised by the
        # canvas width.  Falls off with a Gaussian envelope so the effect
        # is atmospheric and gradual rather than a hard spotlight.
        dist_x     = xs_f - aureole_cx
        dist_y     = ys_f - aureole_cy
        dist       = _np.sqrt(dist_x ** 2 + dist_y ** 2).astype(_np.float32)
        # Gaussian falloff: peak at centre, decays across the canvas
        aureole_w  = max(aureole_radius, 1e-6)
        aureole_mask = _np.exp(-0.5 * (dist / aureole_w) ** 2).astype(_np.float32)
        aureole_mask = _np.clip(aureole_mask, 0.0, 1.0)

        # Apply to background zone (non-figure) and lightly to figure
        # Background pixels get the full aureole; figure pixels get 30%
        # of it to add warm rim without washing out the face.
        fig_mask = _np.zeros((h, w), dtype=_np.float32)
        if self._figure_mask is not None:
            fig_mask = _np.array(self._figure_mask, dtype=_np.float32)
            fig_mask = _np.clip(fig_mask, 0.0, 1.0)
        bg_weight  = 1.0 - fig_mask
        fig_weight = fig_mask * 0.30
        combined   = bg_weight + fig_weight  # blended influence map

        r_out = _np.clip(r_out + aureole_mask * combined * aureole_r, 0.0, 1.0)
        g_out = _np.clip(g_out + aureole_mask * combined * aureole_g, 0.0, 1.0)
        b_out = _np.clip(b_out + aureole_mask * combined * aureole_b, 0.0, 1.0)

        # ── 2. Warm golden rim on lit figure edges ────────────────────────────
        # Compute the figure mask gradient to isolate the upper-right edge region,
        # then apply a warm-gold brightening there — the theatrical rim that
        # separates Giordano's figures from the glowing background.
        if self._figure_mask is not None:
            fig_smooth = _gf(fig_mask, sigma=rim_sigma)
            # Edge = original mask minus strongly smoothed version → ring at boundary
            fig_edge   = _np.clip(fig_mask - fig_smooth, 0.0, 1.0)
            fig_edge   = _gf(fig_edge.astype(_np.float32), sigma=blur_radius * 0.4)
            # Weight toward upper-right: ys_f small (top) and xs_f large (right)
            upper_right_weight = _np.clip(
                (1.0 - ys_f) * 0.5 + xs_f * 0.5, 0.0, 1.0
            ).astype(_np.float32)
            rim_mask = fig_edge * upper_right_weight
            rim_mask = _np.clip(rim_mask, 0.0, 1.0)

            r_out = _np.clip(r_out + rim_mask * rim_strength * 1.4, 0.0, 1.0)
            g_out = _np.clip(g_out + rim_mask * rim_strength * 0.9, 0.0, 1.0)
            b_out = _np.clip(b_out + rim_mask * rim_strength * 0.3, 0.0, 1.0)

        # ── 3. Shadow violet depth — Venetian-influenced shadow colour ────────
        # In the deepest shadows, add the faint cool-violet resonance absorbed
        # from Titian and Ribera that distinguishes Giordano's Baroque warmth
        # from flat tenebrism.
        shadow_band = _np.clip(
            (shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0
        )
        shadow_band = _gf(shadow_band.astype(_np.float32), sigma=blur_radius)
        shadow_band = _np.clip(shadow_band, 0.0, 1.0)

        b_out = _np.clip(b_out + shadow_band * shadow_violet_b, 0.0, 1.0)
        r_out = _np.clip(r_out + shadow_band * shadow_violet_r, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf_out = orig.copy()
        buf_out[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf_out.tobytes()

    # ── guercino_penumbra_warmth_pass ─────────────────────────────────────────
    # Inspired by Giovanni Francesco Barbieri (il Guercino, 1591–1666),
    # Emilian Baroque master and supreme draughtsman of the Italian Baroque.
    # Session 105.

    def guercino_penumbra_warmth_pass(
        self,
        penumbra_lo:        float = 0.28,
        penumbra_hi:        float = 0.62,
        amber_r:            float = 0.038,
        amber_g:            float = 0.018,
        amber_b:            float = 0.008,
        light_cx:           float = 0.18,
        light_cy:           float = 0.08,
        light_radius:       float = 0.85,
        directional_str:    float = 0.018,
        shadow_lo:          float = 0.05,
        shadow_hi:          float = 0.28,
        shadow_warm_r:      float = 0.022,
        shadow_warm_g:      float = 0.008,
        blur_radius:        float = 4.5,
        opacity:            float = 0.28,
    ) -> None:
        """
        Giovanni Francesco Barbieri (il Guercino, 1591–1666) — penumbra warmth pass.

        Guercino was the supreme master of the Emilian Baroque school and one of
        the greatest draughtsmen in the history of Western art.  His pen-and-wash
        drawings — sweeping calligraphic marks building form with breathtaking
        economy — directly inform the intelligence of his painted surfaces.  His
        early works (c. 1617–1627) deploy a dramatic Caravaggesque chiaroscuro
        suffused with extraordinary amber warmth; his late works (after 1642,
        influenced by Guido Reni) adopt a lighter, more idealised palette but
        retain the defining quality that separates him from every other Baroque
        painter: the concentrated golden warmth of his penumbra.

        Where Caravaggio moves abruptly from the lit zone to cold shadow, and
        Leonardo dissolves everything into cool grey sfumato, Guercino's light
        makes a slow, warm journey.  The penumbra — the transition band between
        lit flesh and deep shadow — glows with concentrated amber-ochre warmth,
        as if the golden light is spending its last intensity there before
        surrendering to the dark.  This zone is not incidental; it is the
        emotional centre of Guercino's flesh passages.

        This pass simulates three defining qualities:

        1. **Penumbra amber enrichment** (penumbra_lo/hi, amber_*):
           In the luminance band [penumbra_lo, penumbra_hi], apply a warm amber-
           ochre lift via a Gaussian bell mask peaking at the midpoint of the
           range.  R+ strong (amber), G+ moderate, B- slight (cool dampen) — the
           signature golden ochre of Guercino's transitional flesh.  The bell
           shape ensures the effect peaks at the penumbra midpoint and fades
           smoothly at the lit and shadow extremes.

        2. **Upper-left directional warmth** (light_cx/cy, light_radius, directional_str):
           Apply a gentle warm gradient falling off from the upper-left corner
           with a large Gaussian radius (≈0.85 of canvas width).  Guercino's
           light was typically upper-left — intimate and domestic rather than
           Giordano's theatrical upper-right celestial drama.  The effect
           brightens the canvas in warm ochre near the light source, creating
           a directional warmth across the composition.

        3. **Deep shadow warm retention** (shadow_lo/hi, shadow_warm_*):
           In the deepest shadow zone (lum < shadow_hi), add a gentle warm-umber
           retention (R+ slight, G+ very slight) to prevent cold black voids.
           Guercino prepared on a dark warm-brown imprimatura that shows through
           the shadow zones, warming the darks with residual amber ground rather
           than the cold nihilism of pure tenebrism.

        Parameters
        ----------
        penumbra_lo / penumbra_hi : luminance range for the penumbra zone bell mask
        amber_r / amber_g / amber_b : channel shifts in the penumbra zone
                                      (amber_b is subtracted to warm by reducing blue)
        light_cx / light_cy         : canvas-fraction coordinates of the upper-left
                                      light source centre
        light_radius                : Gaussian falloff radius (as fraction of W)
        directional_str             : strength of the upper-left directional warmth
        shadow_lo / shadow_hi       : luminance range for the deep shadow zone
        shadow_warm_r / _g          : warm-umber retention channel shifts in shadows
        blur_radius                 : Gaussian sigma for mask transitions
        opacity                     : overall blend weight
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Guercino penumbra warmth pass "
              f"(amber_r={amber_r:.3f}  directional_str={directional_str:.3f}  "
              f"shadow_warm_r={shadow_warm_r:.3f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Guercino penumbra warmth pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        # Cairo BGRA layout
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── Coordinate grids ──────────────────────────────────────────────────
        ys, xs = _np.mgrid[:h, :w]
        xs_f   = xs.astype(_np.float32) / w
        ys_f   = ys.astype(_np.float32) / h

        # ── 1. Penumbra amber enrichment ─────────────────────────────────────
        # The defining quality of Guercino's flesh: the penumbra zone glows
        # with concentrated amber-ochre warmth before surrendering to shadow.
        # Gaussian bell peaking at the midpoint of [penumbra_lo, penumbra_hi].
        pb_mid   = (penumbra_lo + penumbra_hi) * 0.5
        pb_width = (penumbra_hi - penumbra_lo) * 0.5 + 1e-6
        pb_mask  = _np.exp(
            -0.5 * ((lum - pb_mid) / pb_width) ** 2
        ).astype(_np.float32)
        pb_mask  = _gf(pb_mask, sigma=blur_radius)
        pb_mask  = _np.clip(pb_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + pb_mask * amber_r, 0.0, 1.0)
        g_out = _np.clip(g_out + pb_mask * amber_g, 0.0, 1.0)
        # amber_b is subtracted (reduces blue) to increase the amber quality.
        b_out = _np.clip(b_out - pb_mask * amber_b, 0.0, 1.0)

        # ── 2. Upper-left directional warmth ─────────────────────────────────
        # Guercino's light entered from the upper left — intimate and warm
        # rather than Giordano's theatrical upper-right celestial drama.
        dist_x   = xs_f - light_cx
        dist_y   = ys_f - light_cy
        dist     = _np.sqrt(dist_x ** 2 + dist_y ** 2).astype(_np.float32)
        dir_mask = _np.exp(-0.5 * (dist / max(light_radius, 1e-6)) ** 2)
        dir_mask = _np.clip(dir_mask, 0.0, 1.0).astype(_np.float32)

        # Warm directional lift: R↑ (amber warmth), G↑ slight
        r_out = _np.clip(r_out + dir_mask * directional_str * 1.2, 0.0, 1.0)
        g_out = _np.clip(g_out + dir_mask * directional_str * 0.5, 0.0, 1.0)

        # ── 3. Deep shadow warm retention ─────────────────────────────────────
        # The dark warm-brown imprimatura shows through Guercino's shadow zones,
        # preventing cold voids.  Apply a gentle umber retention in deep shadow.
        shadow_mask = _np.clip(
            (shadow_hi - lum) / (shadow_hi - shadow_lo + 1e-6), 0.0, 1.0
        )
        shadow_mask = _gf(shadow_mask.astype(_np.float32), sigma=blur_radius * 0.8)
        shadow_mask = _np.clip(shadow_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + shadow_mask * shadow_warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + shadow_mask * shadow_warm_g, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf_out_g = orig.copy()
        buf_out_g[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out_g[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out_g[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out_g[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf_out_g.tobytes()
        print("    Luca Giordano rapidità luminosa pass complete.")

    def ribera_gritty_tenebrism_pass(
        self,
        shadow_hi:          float = 0.22,
        shadow_warm_r:      float = 0.018,
        shadow_warm_g:      float = 0.007,
        grain_strength:     float = 0.032,
        penumbra_lo:        float = 0.22,
        penumbra_hi:        float = 0.45,
        penumbra_grain:     float = 0.028,
        light_cx:           float = 0.15,
        light_cy:           float = 0.08,
        light_radius:       float = 0.70,
        amber_r:            float = 0.035,
        amber_g:            float = 0.014,
        blur_radius:        float = 3.5,
        opacity:            float = 0.40,
    ) -> None:
        """
        Jusepe de Ribera (1591–1652) — gritty tenebrism pass.

        Ribera, known as "Lo Spagnoletto" (The Little Spaniard), was born in
        Valencia but spent his entire career in Naples, fusing Spanish austere
        naturalism with the most uncompromising Italian Caravaggism.  His
        tenebrism is darker and more extreme than Caravaggio's: near-black void
        shadows that consume forms absolutely, from which lit passages emerge
        with an almost shocking physical presence.

        The quality that distinguishes Ribera from every other tenebrism painter
        is the **texture of his shadows**.  Caravaggio's darks are smooth,
        pooling, and absolute — a clean, almost geometric void.  Ribera's shadow
        areas retain visible gritty brushwork: the paint marks are present even
        in the deepest darks, giving a granular, inhabited quality to the
        darkness as if it is made of rough, living matter rather than empty
        void.  This pass simulates that quality with granular noise applied
        within the shadow and penumbra zones.

        Three-stage process
        -------------------

        **Stage 1 — Near-black void reinforcement with warm umber grain:**
        In the deepest shadow zone (luminance < ``shadow_hi``), add a tiny
        warm umber lift (R+ slight, G+ very slight) that prevents flat digital
        black by simulating the warm-brown imprimatura showing through.  A
        granular noise layer (``grain_strength``) is overlaid within this zone,
        creating Ribera's characteristic gritty shadow texture — marks visible
        even in the darkest passages.

        **Stage 2 — Upper-left directional amber spotlight:**
        Apply a Gaussian directional warmth from the upper left (``light_cx``,
        ``light_cy``) to warm and lift the illuminated zone.  Ribera's single
        light source is more dramatic and has a sharper falloff than Guercino's
        gentler penumbra enrichment — it is a focused spotlight rather than an
        ambient warmth.

        **Stage 3 — Gritty penumbra texture:**
        In the mid-dark transition zone (``penumbra_lo`` to ``penumbra_hi``),
        overlay a second granular noise layer (``penumbra_grain``) that creates
        the distinctive Ribera shadow grain in the penumbra region — the sense
        that the transition from light to dark is inhabited and textured rather
        than a smooth gradient.

        Parameters
        ----------
        shadow_hi       : upper luminance bound of the deep shadow zone
        shadow_warm_r/g : warm-umber channel lifts in the deep shadow
        grain_strength  : granular noise amplitude in deep shadow zone
        penumbra_lo/hi  : luminance range for the gritty penumbra zone
        penumbra_grain  : granular noise amplitude in penumbra zone
        light_cx/cy     : upper-left spotlight centre (canvas fractions)
        light_radius    : Gaussian falloff radius as fraction of canvas W
        amber_r/g       : warm amber spotlight channel lifts
        blur_radius     : Gaussian sigma for mask softening
        opacity         : overall blend weight
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print(f"  Ribera gritty tenebrism pass "
              f"(grain={grain_strength:.3f}  amber_r={amber_r:.3f}  "
              f"shadow_hi={shadow_hi:.2f}  opacity={opacity:.2f}) ...")

        if opacity <= 0.0:
            print("    Ribera gritty tenebrism pass skipped (opacity=0)")
            return

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        # Cairo BGRA layout
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # Seed noise from canvas dimensions for deterministic grain
        rng = _np.random.default_rng(seed=int(h * w) % (2**31))

        # ── 1. Near-black void reinforcement with warm umber grain ────────────
        # The dark imprimatura shows through Ribera's deepest shadow zones,
        # and his brushwork is visible even in the voids — gritty, inhabited.
        deep_mask = _np.clip(
            (shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0
        ).astype(_np.float32)
        deep_mask = _gf(deep_mask, sigma=blur_radius)
        deep_mask = _np.clip(deep_mask, 0.0, 1.0)

        # Warm umber ground retention
        r_out = _np.clip(r_out + deep_mask * shadow_warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + deep_mask * shadow_warm_g, 0.0, 1.0)

        # Gritty grain in shadow voids — the defining Ribera quality
        shadow_noise = (rng.random((h, w), dtype=_np.float32) - 0.5) * 2.0
        shadow_noise = _gf(shadow_noise, sigma=0.8)   # slight softening
        r_out = _np.clip(r_out + deep_mask * shadow_noise * grain_strength, 0.0, 1.0)
        g_out = _np.clip(g_out + deep_mask * shadow_noise * grain_strength * 0.7, 0.0, 1.0)
        b_out = _np.clip(b_out + deep_mask * shadow_noise * grain_strength * 0.5, 0.0, 1.0)

        # ── 2. Upper-left directional amber spotlight ─────────────────────────
        # Ribera's single upper-left light source — more dramatic and sharper
        # than Guercino's gentle penumbra enrichment.
        ys, xs = _np.mgrid[:h, :w]
        xs_f = xs.astype(_np.float32) / w
        ys_f = ys.astype(_np.float32) / h

        dist2 = ((xs_f - light_cx) ** 2 + (ys_f - light_cy) ** 2)
        dir_mask = _np.exp(-0.5 * dist2 / (light_radius ** 2)).astype(_np.float32)
        dir_mask = _gf(dir_mask, sigma=blur_radius * 2.0)
        dir_mask = _np.clip(dir_mask, 0.0, 1.0)

        # Only warm the lit zone (not deep shadow)
        lit_zone = _np.clip((lum - shadow_hi) / (0.5 + 1e-6), 0.0, 1.0)
        dir_mask = dir_mask * lit_zone

        r_out = _np.clip(r_out + dir_mask * amber_r, 0.0, 1.0)
        g_out = _np.clip(g_out + dir_mask * amber_g, 0.0, 1.0)

        # ── 3. Gritty penumbra texture ────────────────────────────────────────
        # In the transition zone, Ribera's marks are visible — darkness as
        # inhabited, textured matter, not smooth Caravaggiesque void.
        pb_mask = _np.clip(
            1.0 - _np.abs(lum - (penumbra_lo + penumbra_hi) * 0.5)
            / ((penumbra_hi - penumbra_lo) * 0.5 + 1e-6),
            0.0, 1.0,
        ).astype(_np.float32)
        pb_mask = _gf(pb_mask, sigma=blur_radius)
        pb_mask = _np.clip(pb_mask, 0.0, 1.0)

        # Penumbra grain: warm noise in the transition band
        pb_noise = (rng.random((h, w), dtype=_np.float32) - 0.5) * 2.0
        pb_noise = _gf(pb_noise, sigma=1.2)
        r_out = _np.clip(r_out + pb_mask * pb_noise * penumbra_grain, 0.0, 1.0)
        g_out = _np.clip(g_out + pb_mask * pb_noise * penumbra_grain * 0.6, 0.0, 1.0)
        b_out = _np.clip(b_out + pb_mask * pb_noise * penumbra_grain * 0.35, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf_out = orig.copy()
        buf_out[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf_out[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf_out.tobytes()
        print("    Ribera gritty tenebrism pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Giovanni Antonio Boltraffio — pearled sfumato pass (session 107)
    # ─────────────────────────────────────────────────────────────────────────

    def boltraffio_pearled_sfumato_pass(
        self,
        pearl_lo:          float = 0.72,
        pearl_r:           float = 0.012,
        pearl_g:           float = 0.018,
        pearl_b:           float = 0.025,
        shadow_hi:         float = 0.30,
        shadow_b:          float = 0.024,
        shadow_g:          float = 0.008,
        shadow_r:          float = 0.006,
        flesh_lo:          float = 0.38,
        flesh_hi:          float = 0.70,
        clarity_sigma:     float = 0.8,
        clarity_strength:  float = 0.18,
        blur_radius:       float = 4.0,
        opacity:           float = 0.38,
    ) -> None:
        """
        Giovanni Antonio Boltraffio pearled sfumato pass — session 107 new artist pass.

        Giovanni Antonio Boltraffio (1467–1516) was Leonardo da Vinci's most gifted
        and personally close Milanese pupil — the only one to sign a work jointly with
        the master (the Louvre Narcissus).  While Bernardino Luini distilled Leonardo's
        sfumato into warmth, sweetness, and seamless ivory flesh, Boltraffio refined it
        into a crystalline, psychologically penetrating idiom: cooler, more jewel-like,
        and charged with a withdrawn psychological depth that reflects the master's own
        complex spirit more faithfully than Luini's serene Madonnas.

        The defining Boltraffio quality is the **pearl highlight**: where Luini's flesh
        lights glow with warm ivory luminosity (lead-white reading through amber glaze),
        Boltraffio's peak highlights approach a cool silver-white — pearl rather than
        ivory, cool-luminous rather than warm-golden.  This is the result of a cooler
        final glaze sequence and a tendency toward neutral silver in the uppermost
        impasto layer.  Technical analysis of the Portrait of Ginevra Bentivenuti
        (Louvre) confirms this cool-silver quality at the forehead and cheekbone ridge.

        His shadow passages are equally distinctive: where Luini's shadows retain amber
        warmth even in the deepest voids, Boltraffio's deepen into a genuinely cool
        blue-grey — suggesting ambient north-light or reflected sky in the shadow, a
        Leonardo principle Boltraffio carried further than any other Milanese pupil.
        The overall tonal range is thus bracketed between a cool pearl summit and a
        cool blue-grey nadir, with warm flesh tones occupying the broad mid-register.

        The mid-flesh zone in Boltraffio exhibits a jewel-like crystalline precision:
        forms emerge from shadow with unusual tonal clarity at the moment of first
        illumination, creating what art historians describe as a "crystalline sfumato" —
        the edge is as dissolved as Leonardo's, but the tonal gradation has more
        structure and precision than Luini's seamless enamel.

        This pass encodes three defining Boltraffio qualities:

          1. Pearl highlight clarification — In upper highlight zones (lum > pearl_lo),
             apply a cool-silver push: R + pearl_r (small), G + pearl_g (moderate),
             B + pearl_b (largest).  The result is a shift from warm-ivory toward neutral-
             silver-pearl at the highlight summit — Boltraffio's cool luminous quality.

          2. Cool-blue deep shadow atmosphere — In deep shadow zones (lum < shadow_hi),
             add a distinctly cool-blue atmospheric lift: B + shadow_b, G + shadow_g,
             R - shadow_r.  This is more pronounced and more distinctly blue than Luini's
             gentle violet-grey — it reads as north light or reflected sky in the void.

          3. Mid-flesh crystalline clarity — In the mid-flesh zone [flesh_lo, flesh_hi],
             blend very mildly toward a slightly sharpened (high-pass) version of the
             canvas at clarity_strength.  This captures the jewel-like tonal precision
             that makes Boltraffio's emerging-from-shadow forms appear crystalline —
             the sfumato is complete but the tonal structure is preserved within it.
             Implemented as: canvas + (canvas - blurred_canvas) * clarity_strength,
             i.e. an unsharp-mask at low strength, blended only in the mid-flesh zone.

        Apply after sfumato_veil_pass() and luini_leonardesque_glow_pass() to add the
        Boltraffio pearl quality over the established Leonardesque sfumato foundation —
        or use alone as a cool-sfumato alternative to the warm Luini variant.

        Parameters
        ----------
        pearl_lo          : lower lum threshold for pearl highlight zone
        pearl_r           : R lift in highlights (small — pearl has little extra red)
        pearl_g           : G lift in highlights (moderate — neutral silver needs green)
        pearl_b           : B lift in highlights (largest — the cool-pearl quality)
        shadow_hi         : upper lum threshold for cool-blue shadow zone
        shadow_b          : B lift in shadows (cool north-light atmosphere)
        shadow_g          : G lift in shadows (secondary cool tint)
        shadow_r          : R reduction in shadows (removes warm cast)
        flesh_lo          : lower lum bound of crystalline clarity zone
        flesh_hi          : upper lum bound of crystalline clarity zone
        clarity_sigma     : Gaussian blur sigma for unsharp-mask base
        clarity_strength  : fraction of high-pass detail added in mid-flesh zone
        blur_radius        : Gaussian sigma for mask feathering
        opacity            : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Pearl highlight clarification ──────────────────────────────────
        # Boltraffio's highlight summit is cool-silver/pearl, not warm-ivory.
        # Apply a graduated lift that shifts the uppermost lights toward neutral silver.
        hi_mask = _np.clip(
            (lum - pearl_lo) / (1.0 - pearl_lo + 1e-6), 0.0, 1.0
        )
        hi_mask = _gf(hi_mask.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * pearl_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * pearl_g, 0.0, 1.0)
        b_out = _np.clip(b_out + hi_mask * pearl_b, 0.0, 1.0)

        # ── 2. Cool-blue deep shadow atmosphere ───────────────────────────────
        # Boltraffio's deepest shadows carry ambient north-light / reflected sky —
        # more distinctly blue than Luini's gentle violet-grey quality.
        sh_mask = _np.clip(
            (shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0
        )
        sh_mask = _gf(sh_mask.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        r_out = _np.clip(r_out - sh_mask * shadow_r, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * shadow_g, 0.0, 1.0)
        b_out = _np.clip(b_out + sh_mask * shadow_b, 0.0, 1.0)

        # ── 3. Mid-flesh crystalline clarity ──────────────────────────────────
        # Unsharp-mask at very low strength in the mid-flesh zone.
        # Canvas + (Canvas - Blurred) * clarity_strength — adds tonal precision
        # without visible sharpening artifacts.  Only applied in the mid-flesh
        # register [flesh_lo, flesh_hi] where Boltraffio's jewel quality lives.
        flesh_bell = _np.clip(
            (lum - flesh_lo) / (flesh_hi - flesh_lo + 1e-6), 0.0, 1.0
        ) * _np.clip(
            (flesh_hi - lum) / (flesh_hi - flesh_lo + 1e-6), 0.0, 1.0
        ) * 4.0
        flesh_bell = _np.clip(flesh_bell, 0.0, 1.0)
        flesh_bell = _gf(flesh_bell.astype(_np.float32), blur_radius)
        flesh_bell = _np.clip(flesh_bell, 0.0, 1.0)

        r_blur = _gf(r_out.astype(_np.float32), clarity_sigma)
        g_blur = _gf(g_out.astype(_np.float32), clarity_sigma)
        b_blur = _gf(b_out.astype(_np.float32), clarity_sigma)

        # High-pass residual: original minus blurred
        r_hp = r_out - r_blur
        g_hp = g_out - g_blur
        b_hp = b_out - b_blur

        cw = flesh_bell * clarity_strength
        r_out = _np.clip(r_out + r_hp * cw, 0.0, 1.0)
        g_out = _np.clip(g_out + g_hp * cw, 0.0, 1.0)
        b_out = _np.clip(b_out + b_hp * cw, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()

    # ─────────────────────────────────────────────────────────────────────────
    # Session 108 — Giovanni Battista Moroni · BERGAMASQUE_PORTRAIT_REALISM
    # ─────────────────────────────────────────────────────────────────────────

    def moroni_silver_presence_pass(
        self,
        hi_lo:          float = 0.68,
        silver_r:       float = 0.008,
        silver_g:       float = 0.012,
        silver_b:       float = 0.020,
        shadow_hi:      float = 0.35,
        warm_r:         float = 0.018,
        warm_g:         float = 0.010,
        warm_b:         float = 0.006,
        mid_lo:         float = 0.35,
        mid_hi:         float = 0.68,
        mid_gamma_lo:   float = 0.94,
        mid_gamma_hi:   float = 1.06,
        blur_radius:    float = 3.5,
        opacity:        float = 0.36,
    ) -> None:
        """
        Giovanni Battista Moroni silver presence pass — session 108 new artist pass.

        Giovanni Battista Moroni (c. 1520–1579) is the defining master of Bergamasque
        portrait realism — a tradition of unhurried, psychologically direct observation
        rooted in the Lombard city of Bergamo and its satellite Brescia, far from the
        idealising academies of Venice, Florence, and Rome.  He trained under Moretto da
        Brescia (who had already developed a naturalist approach to the Brescian lighting
        tradition) and spent his career serving merchants, clergy, and lawyers who wanted
        to be seen as they were: not as gods, not as symbols, but as people.

        The defining Moroni quality is **silver presence** — the uncanny sense of
        physical reality his sitters project from the canvas.  Unlike Leonardo (whose
        sfumato dematerialises form into atmospheric haze) or Bronzino (whose enamel
        freezes form into cold perfection), Moroni achieves presence through tonal
        accuracy: the correct luminance value at every point of the face, as observed
        under real north-window light.

        His highlights are the key diagnostic: where Raphael's lights glow with warm
        ivory (reading as sunlight from the south, warm and golden) and Bronzino's
        are cold blue-white (the hard light of Florentine Mannerist clarity), Moroni's
        highlights are **cool silver** — not warm, not cold, but the neutral, steady
        light of overcast northern daylight.  Technical analysis of his panels and
        canvases suggests he used lead white mixed with small quantities of smalt or
        azurite in his uppermost highlight layers, producing a distinctly cool, slightly
        bluish-silver quality in the peak lights of forehead, cheekbone, and nose bridge.

        His shadow passages are the complement: warm amber-ochre recovery that prevents
        the darks from going cold or grey.  Where Ribera lets his voids approach near-
        black umber, and where Leonardo dissolves them into cool violet haze, Moroni's
        shadows retain earthy warmth — raw sienna and ochre in the deepest tones —
        keeping the face readable in three dimensions without theatrical drama.

        The mid-tone zone — where most of his sitters' faces live — is handled with
        extraordinary tonal precision: a subtle local contrast enhancement that separates
        tonal planes without visible brushwork boundaries or sfumato dissolution.  This
        is the quality that makes his sitters seem to exist in real space rather than on
        a painted surface.

        This pass encodes three defining Moroni qualities:

          1. Cool silver highlight — In the upper highlight zone (lum > hi_lo),
             apply a graduated cool-silver shift: R - silver_r (small reduction —
             removes the warm cast), G + silver_g (moderate — silver needs green),
             B + silver_b (largest lift — the cool north-daylight quality).
             The shift is graduated by a Gaussian-smoothed luminance mask so it
             is strongest at the peak highlights and fades smoothly into the midtones.

          2. Warm shadow recovery — In the shadow zone (lum < shadow_hi),
             add earthy amber-ochre warmth: R + warm_r, G + warm_g (smaller),
             B - warm_b (tiny reduction — removes blue-grey cast).
             This prevents Moroni's shadows from going cold and gives his sitters
             their characteristic grounded warmth even in the darkest passages.

          3. Mid-tone presence enhancement — In the mid-tone zone [mid_lo, mid_hi],
             apply a mild luminance gamma separation: pixels in the lower half of the
             mid-tone range receive a subtle darkening (gamma > 1, mid_gamma_lo)
             while pixels in the upper half receive a subtle lightening (gamma < 1,
             mid_gamma_hi).  This slightly separates the tonal planes in the
             transition zone without visible sharpening artifacts, producing the
             quiet tonal precision that makes Moroni's faces seem physically present.

        Apply after sfumato_veil_pass() (if soft ground is desired) or directly on a
        clearly-modelled base.  Works well after old_master_varnish_pass() to add the
        Moroni silver quality over an established warm-toned Italian base.

        Parameters
        ----------
        hi_lo           : lower lum threshold for cool silver highlight zone
        silver_r        : R reduction in highlights (removes warm cast, small)
        silver_g        : G lift in highlights (moderate — silver needs green balance)
        silver_b        : B lift in highlights (largest — the cool north-daylight quality)
        shadow_hi       : upper lum threshold for warm shadow recovery zone
        warm_r          : R lift in shadows (amber-ochre warmth)
        warm_g          : G lift in shadows (secondary warm tint, smaller)
        warm_b          : B reduction in shadows (removes blue-grey cast)
        mid_lo          : lower lum bound of mid-tone presence zone
        mid_hi          : upper lum bound of mid-tone presence zone
        mid_gamma_lo    : gamma for lower mid-tone half (> 1 = subtle darkening)
        mid_gamma_hi    : gamma for upper mid-tone half (< 1 = subtle lightening)
        blur_radius     : Gaussian sigma for mask feathering
        opacity         : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Cool silver highlight ──────────────────────────────────────────
        # Moroni's north-daylight highlights are cool silver rather than warm ivory.
        # Graduate the shift by a smoothed mask strongest at the luminance peak.
        hi_mask = _np.clip(
            (lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0
        )
        hi_mask = _gf(hi_mask.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out - hi_mask * silver_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * silver_g, 0.0, 1.0)
        b_out = _np.clip(b_out + hi_mask * silver_b, 0.0, 1.0)

        # ── 2. Warm shadow recovery ───────────────────────────────────────────
        # Moroni's shadows retain amber-ochre warmth — earthy, not cold or grey.
        sh_mask = _np.clip(
            (shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0
        )
        sh_mask = _gf(sh_mask.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + sh_mask * warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * warm_g, 0.0, 1.0)
        b_out = _np.clip(b_out - sh_mask * warm_b, 0.0, 1.0)

        # ── 3. Mid-tone presence enhancement ──────────────────────────────────
        # Mild gamma separation within the mid-tone zone [mid_lo, mid_hi]:
        # lower mid-tones receive a subtle darkening push (gamma > 1 → values drop);
        # upper mid-tones receive a subtle lightening push (gamma < 1 → values rise).
        # This gently separates the mid-tone planes without sharpening artifacts —
        # the quiet tonal precision behind Moroni's sense of physical presence.
        mid_range = mid_hi - mid_lo + 1e-6

        # Normalised position within the mid-tone zone [0, 1]
        t = _np.clip((lum - mid_lo) / mid_range, 0.0, 1.0)
        t = _gf(t.astype(_np.float32), blur_radius)
        t = _np.clip(t, 0.0, 1.0)

        # Blend gamma: 0 → mid_gamma_lo (darkening), 1 → mid_gamma_hi (lightening)
        gamma_map = mid_gamma_lo + t * (mid_gamma_hi - mid_gamma_lo)

        # Mid-tone bell mask — zero outside [mid_lo, mid_hi], smooth inside
        mid_bell = (
            _np.clip((lum - mid_lo) / mid_range, 0.0, 1.0) *
            _np.clip((mid_hi - lum) / mid_range, 0.0, 1.0) * 4.0
        )
        mid_bell = _np.clip(mid_bell, 0.0, 1.0)
        mid_bell = _gf(mid_bell.astype(_np.float32), blur_radius)
        mid_bell = _np.clip(mid_bell, 0.0, 1.0)

        # Apply gamma within mid-zone; blend with original by mid_bell weight
        eps = 1e-6
        r_gamma = _np.clip(_np.power(_np.clip(r_out, eps, 1.0), gamma_map), 0.0, 1.0)
        g_gamma = _np.clip(_np.power(_np.clip(g_out, eps, 1.0), gamma_map), 0.0, 1.0)
        b_gamma = _np.clip(_np.power(_np.clip(b_out, eps, 1.0), gamma_map), 0.0, 1.0)

        r_out = r_out * (1.0 - mid_bell) + r_gamma * mid_bell
        g_out = g_out * (1.0 - mid_bell) + g_gamma * mid_bell
        b_out = b_out * (1.0 - mid_bell) + b_gamma * mid_bell

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Giovanni Battista Moroni silver presence pass complete.")

    def strozzi_amber_impasto_pass(
        self,
        shadow_hi:   float = 0.38,
        amber_r:     float = 0.032,
        amber_g:     float = 0.016,
        amber_b:     float = 0.024,
        hi_lo:       float = 0.72,
        cream_r:     float = 0.014,
        cream_g:     float = 0.008,
        cream_b:     float = 0.010,
        hi_boost:    float = 1.04,
        mid_lo:      float = 0.38,
        mid_hi:      float = 0.72,
        rose_r:      float = 0.016,
        rose_b:      float = 0.008,
        blur_radius: float = 4.0,
        opacity:     float = 0.42,
    ) -> None:
        """
        Bernardo Strozzi amber impasto pass — session 109 new artist pass.

        Bernardo Strozzi (1581–1644), nicknamed "Il Cappuccino" (Capuchin friar) and
        "Il Prete Genovese" (The Genoese Priest), is one of the most physically
        compelling painters of the Italian seventeenth century.  Born in Genoa, he
        absorbed the Rubensian energy that Peter Paul Rubens left in Genoa after his
        two extended visits (1600–02 and 1607–08): the loaded brush, the warm amber
        shadows, the frank vitality of flesh seen in honest northern light.  Moving to
        Venice around 1631, he merged this Genoese bravura foundation with the deep
        colour saturation and atmospheric warmth of the Venetian tradition, producing
        portraits and religious paintings of extraordinary richness.

        The defining Strozzi quality is **warm amber bravura** — a chromatic unity
        across the entire tonal range that keeps even the darkest shadows warm and
        accessible.  This is the opposite of the Caravaggist approach: where Caravaggio
        and Ribera use near-black voids to intensify the drama of light, Strozzi's
        shadows are warm chestnut-amber, as if the darkness itself were suffused with
        candlelight.  His famous "Old Woman at the Mirror" (c. 1615) is the canonical
        demonstration: even the deepest darks of her robe are warm brown, not cold
        umber-black, and the whole image glows with an amber internal coherence.

        His impasto highlights are the second diagnostic: where Rembrandt loads his
        darkest shadow passages with thick paint, Strozzi loads the lights, depositing
        cream-warm paint in single confident strokes on the highest points of forehead,
        cheekbone, and nose.  These are not cool-silver Moroni highlights or pearl-blue
        Boltraffio lights — they are warm Naples-ivory, the colour of cream in candlelight.

        His flesh mid-tones are rose-sienna — warm, saturated, alive — giving his
        sitters a physical vitality that cold-palette painters (Zurbarán, Moroni,
        Boltraffio) never attempt.  The mid-tone warmth is reinforced by a warm
        burnt-sienna imprimatura that shows through at the edges of forms and in the
        thinner paint passages, contributing an internal golden warmth.

        This pass encodes three defining Strozzi qualities:

          1. Amber shadow enrichment — In the shadow zone (lum < shadow_hi),
             shift decisively toward warm chestnut-amber: R + amber_r (strong),
             G + amber_g (moderate), B - amber_b (notable reduction — removes cold cast).
             This is Strozzi's most distinctive quality: his shadows glow with the
             same amber-chestnut warmth as a warm brown imprimatura seen through
             semi-transparent paint layers.  The mask is graduated from maximum
             strength at the deepest shadows to zero at shadow_hi, smoothed by
             a Gaussian to prevent any visible transition boundary.

          2. Impasto highlight bloom — In the upper highlight zone (lum > hi_lo),
             apply a warm creamy colour shift: R + cream_r, G + cream_g,
             B - cream_b (cream is warm — more red and green than blue).
             Additionally apply a local luminance boost (multiply by hi_boost ≈ 1.04)
             to push the peak highlights slightly brighter, simulating the physical
             relief of loaded impasto paint catching the light.  The combined effect
             is a warm, luminous bloom on the highest flesh planes, distinct from
             the cool-silver quality of Moroni or the pearl-blue of Boltraffio.

          3. Warm mid-tone vitality — In the mid-tone zone [mid_lo, mid_hi],
             apply a gentle warm-rose tint: R + rose_r (small warm push),
             B - rose_b (tiny reduction — removes the slight blue-grey cast
             that can accumulate in mid-tones from underlying cool layers).
             This adds the characteristic rose-sienna flesh warmth that makes
             Strozzi's sitters seem physically present and vitally alive —
             the quality the Venetians called "color di carne" (flesh colour).

        Apply after old_master_varnish_pass() or warm_ground_pass() to build on a
        warm tonal foundation.  Can be applied over sfumato_veil_pass() results to
        add Strozzi's amber warmth over a softened base.

        Parameters
        ----------
        shadow_hi    : upper lum threshold for amber shadow enrichment zone
        amber_r      : R lift in shadows (warm chestnut-amber — the dominant shift)
        amber_g      : G lift in shadows (secondary warm tint, smaller)
        amber_b      : B reduction in shadows (removes cold blue-grey cast)
        hi_lo        : lower lum threshold for impasto highlight bloom zone
        cream_r      : R lift in highlights (warm cream, Naples-ivory quality)
        cream_g      : G lift in highlights (cream needs green balance)
        cream_b      : B reduction in highlights (cream is warm — remove blue)
        hi_boost     : multiplicative luminance boost for peak highlights (>1 = brighter)
        mid_lo       : lower lum bound of warm mid-tone vitality zone
        mid_hi       : upper lum bound of warm mid-tone vitality zone
        rose_r       : R lift in mid-tones (rose-sienna warm flesh tint)
        rose_b       : B reduction in mid-tones (removes cool accumulation)
        blur_radius  : Gaussian sigma for mask feathering
        opacity      : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Amber shadow enrichment ────────────────────────────────────────
        # Strozzi's shadows are warm chestnut-amber — not cold grey, not near-black void.
        # Graduate from maximum strength at the deepest shadows to zero at shadow_hi.
        sh_mask = _np.clip(
            (shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0
        )
        sh_mask = _gf(sh_mask.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + sh_mask * amber_r, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * amber_g, 0.0, 1.0)
        b_out = _np.clip(b_out - sh_mask * amber_b, 0.0, 1.0)

        # ── 2. Impasto highlight bloom ────────────────────────────────────────
        # Warm creamy Naples-ivory colour shift + slight luminance boost in the
        # upper highlight zone.  Simulates Strozzi's loaded-brush impasto lights.
        hi_mask = _np.clip(
            (lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0
        )
        hi_mask = _gf(hi_mask.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        # Warm cream colour shift
        r_out = _np.clip(r_out + hi_mask * cream_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * cream_g, 0.0, 1.0)
        b_out = _np.clip(b_out - hi_mask * cream_b, 0.0, 1.0)
        # Luminance boost — simulates physical impasto relief catching light
        boost_factor = 1.0 + hi_mask * (hi_boost - 1.0)
        r_out = _np.clip(r_out * boost_factor, 0.0, 1.0)
        g_out = _np.clip(g_out * boost_factor, 0.0, 1.0)
        b_out = _np.clip(b_out * boost_factor, 0.0, 1.0)

        # ── 3. Warm mid-tone vitality ─────────────────────────────────────────
        # Rose-sienna warm tint in the mid-tone zone — Strozzi's "color di carne"
        # quality that makes his sitters seem vitally present and alive.
        mid_range = mid_hi - mid_lo + 1e-6
        mid_bell = (
            _np.clip((lum - mid_lo) / mid_range, 0.0, 1.0) *
            _np.clip((mid_hi - lum) / mid_range, 0.0, 1.0) * 4.0
        )
        mid_bell = _np.clip(mid_bell, 0.0, 1.0)
        mid_bell = _gf(mid_bell.astype(_np.float32), blur_radius)
        mid_bell = _np.clip(mid_bell, 0.0, 1.0)
        r_out = _np.clip(r_out + mid_bell * rose_r, 0.0, 1.0)
        b_out = _np.clip(b_out - mid_bell * rose_b, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Bernardo Strozzi amber impasto pass complete.")

    def sassoferrato_pure_devotion_pass(
        self,
        ultra_thresh:  float = 0.04,
        ultra_b_lift:  float = 0.025,
        ultra_r_damp:  float = 0.018,
        pearl_lo:      float = 0.76,
        pearl_b_lift:  float = 0.012,
        pearl_r_damp:  float = 0.008,
        shadow_hi:     float = 0.30,
        shadow_b_lift: float = 0.018,
        shadow_r_damp: float = 0.010,
        blur_radius:   float = 3.5,
        opacity:       float = 0.32,
    ) -> None:
        """
        Giovanni Battista Salvi da Sassoferrato pure devotion pass — session 110
        new artist pass.

        Sassoferrato (1609–1685) worked in Rome producing devotional Madonnas and
        saints whose chromatic purity and technical refinement stand apart from the
        Baroque mainstream entirely.  He was not a court painter, not a narrative
        historian, not a decorator of palace ceilings.  He was a specialist in a
        single subject — the serene, absorbed face of the Virgin — and he achieved
        within that narrow domain a level of chromatic and technical perfection that
        remains unmatched.

        Two chromatic signatures define his work absolutely:

        **Ultramarine blue** — The most saturated, internally luminous blue in
        Western painting.  Not the purplish-blue of Flemish masters (Jan van Eyck's
        azurite), not the grey-blue of aerial perspective, not the warm cobalt of
        Raphael's Madonnas: Sassoferrato's blue is pure lapislazuli, built through
        multiple transparent glaze layers over a warm ochre imprimatura so that the
        colour appears to glow from within rather than simply reflecting incident
        light.  The warm ground glows through the cool glaze, creating a depth and
        radiance that a single opaque blue layer could never achieve.  Theologically
        this colour was reserved for the Madonna — lapis lazuli was the most
        expensive pigment in the medieval and Renaissance palette, imported from
        Afghanistan, ground and purified by hand, used only for the most sacred
        subjects.  Sassoferrato understood this tradition and took it to its
        absolute technical limit.

        **Porcelain skin translucency** — His flesh tones appear lit from within
        rather than from without.  The mechanism is the same as the blue: warm
        ochre imprimatura showing through cool final glazes.  In the highlight
        zones — forehead, cheekbone, bridge of nose — the final passage is a
        cool pearl white glaze, almost no pigment, mostly medium, that creates
        the impression of light passing through translucent skin rather than
        hitting an opaque surface.  The result is the quality that separates
        Sassoferrato's skin from Dolci's (which is smooth but opaque) and from
        Leonardo's (which dissolves into atmosphere): Sassoferrato's flesh has
        a physical translucency, as if the skin itself were luminous.

        This pass encodes three defining Sassoferrato qualities:

          1. Ultramarine purity — In blue-predominant zones
             (b0 > r0 + ultra_thresh and b0 > g0 + ultra_thresh), shift toward
             pure ultramarine by lifting blue (B + ultra_b_lift) and damping
             warm red contamination (R - ultra_r_damp).  The mask graduates from
             maximum strength at the most intensely blue pixels to zero at the
             detection threshold, smoothed by a Gaussian to prevent visible seams.
             This deepens and purifies any blue zones — sky, drapery, shadow
             passages — toward Sassoferrato's characteristic lapislazuli glow.

          2. Porcelain skin glow — In the upper highlight zone (lum > pearl_lo),
             apply a cool pearl shift: slight R reduction (R - pearl_r_damp) and
             slight B lift (B + pearl_b_lift).  This cools the peak highlights
             from warm ivory toward cool translucent pearl — the quality of light
             through skin rather than reflected from skin.  Applied at low opacity
             over the accumulated warm layers (Strozzi amber, Dolci glaze), it
             adds the final translucent refinement without washing out warmth.

          3. Ultramarine shadow depth — In shadow zones (lum < shadow_hi) where
             blue is already dominant, deepen toward lapislazuli darkness with a
             controlled violet-blue enrichment: B + shadow_b_lift, R - shadow_r_damp.
             This is the characteristic Sassoferrato shadow quality in the drapery:
             not a neutral dark or a warm brown void (Caravaggio/Rembrandt), but
             a deep, saturated blue-violet darkness — lapislazuli in the shadows
             as well as the lights.

        Parameters
        ----------
        ultra_thresh  : minimum B-over-R and B-over-G gap to detect blue zones
        ultra_b_lift  : blue channel boost in ultramarine zones (lapislazuli purity)
        ultra_r_damp  : red channel damp in ultramarine zones (removes warm contamination)
        pearl_lo      : lower highlight threshold for porcelain skin glow (lum > this)
        pearl_b_lift  : subtle blue lift in highlights (cool pearl quality)
        pearl_r_damp  : slight red damp in highlights (cool ivory, not warm cream)
        shadow_hi     : upper shadow threshold for ultramarine depth enrichment
        shadow_b_lift : blue-violet enrichment in deep blue-dominant shadows
        shadow_r_damp : red damp in deep blue shadows (removes any warm contamination)
        blur_radius   : Gaussian sigma for mask feathering (prevents hard transitions)
        opacity       : overall pass composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Ultramarine purity ─────────────────────────────────────────────
        # Detect blue-dominant pixels and push toward pure lapislazuli.
        # Both conditions must be met: more blue than red AND more blue than green
        # by at least ultra_thresh.  Strength scales linearly with the blue excess.
        blue_over_r = _np.clip((b0 - r0 - ultra_thresh) / (1.0 - ultra_thresh + 1e-6),
                               0.0, 1.0)
        blue_over_g = _np.clip((b0 - g0 - ultra_thresh) / (1.0 - ultra_thresh + 1e-6),
                               0.0, 1.0)
        ultra_mask = blue_over_r * blue_over_g   # both conditions together
        ultra_mask = _gf(ultra_mask.astype(_np.float32), blur_radius)
        ultra_mask = _np.clip(ultra_mask, 0.0, 1.0)
        b_out = _np.clip(b_out + ultra_mask * ultra_b_lift, 0.0, 1.0)
        r_out = _np.clip(r_out - ultra_mask * ultra_r_damp, 0.0, 1.0)

        # ── 2. Porcelain skin glow ────────────────────────────────────────────
        # Cool pearl shift in the upper highlight zone — translucent skin quality.
        # Cools the peak highlights from warm ivory toward a luminous pearl,
        # suggesting light through translucent skin layers.
        hi_mask = _np.clip(
            (lum - pearl_lo) / (1.0 - pearl_lo + 1e-6), 0.0, 1.0
        )
        hi_mask = _gf(hi_mask.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out - hi_mask * pearl_r_damp, 0.0, 1.0)
        b_out = _np.clip(b_out + hi_mask * pearl_b_lift, 0.0, 1.0)

        # ── 3. Ultramarine shadow depth ───────────────────────────────────────
        # In shadow zones where blue is already dominant, deepen toward
        # lapislazuli darkness — Sassoferrato's drapery shadows are blue-violet,
        # never the warm brown of Italian Baroque nor the neutral grey of Northern painters.
        sh_mask = _np.clip(
            (shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0
        ) * ultra_mask   # only where blue is already dominant
        sh_mask = _gf(sh_mask.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        b_out = _np.clip(b_out + sh_mask * shadow_b_lift, 0.0, 1.0)
        r_out = _np.clip(r_out - sh_mask * shadow_r_damp, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Giovanni Battista Salvi da Sassoferrato pure devotion pass complete.")

    def orazio_silver_daylight_pass(
        self,
        hi_lo:           float = 0.68,
        silver_r_damp:   float = 0.010,
        silver_b_lift:   float = 0.018,
        mid_lo:          float = 0.32,
        mid_hi:          float = 0.68,
        chroma_lift:     float = 0.020,
        shadow_hi:       float = 0.34,
        cool_r_damp:     float = 0.008,
        cool_b_lift:     float = 0.012,
        blur_radius:     float = 3.0,
        opacity:         float = 0.32,
    ) -> None:
        """
        Orazio Gentileschi silver daylight pass — session 111 new artist pass.

        Orazio Gentileschi (1563–1639) is the great bridge figure of the Italian
        Baroque: shaped by Caravaggio's naturalist revolution in Rome around 1600,
        he absorbed the tenebrism programme but never surrendered to its extremes.
        Where Caravaggio carved figures from near-black void with a single theatrical
        spotlight, Orazio worked with something altogether more refined: cool, even,
        north-facing daylight — aristocratic, clear, and honest.

        Born in Pisa, trained in Florence, he worked in Rome (1578–1621), Genoa
        (1621–1624), Paris at the court of Marie de' Medici (1624–1626), and finally
        London as court painter to Charles I (1626–1639), where he died.  Each
        successive court required a more polished, restrained naturalism — and Orazio
        delivered.  His London works, in particular, are among the most luminously
        precise paintings of the 17th century: figures inhabiting real space under
        real light, observed without drama and without flattery.

        Three qualities define him:

        **Cool silver daylight** — His highlights are unlike any other Baroque master's.
        Caravaggio's are warm amber (candlelight quality), Rembrandt's are warm gold
        (the dark studio with a single window), Rubens' are warm ivory (Flemish sun).
        Orazio's are cool silver-grey — the quality of lead white mixed with a trace
        of smalt under overcast northern sky.  This single chromatic decision separates
        his flesh tones from every other Baroque tradition.  In the highest lights of
        forehead, cheekbone, and nose bridge, the colour shifts from the warm flesh
        mid-tone toward cool, slightly bluish silver — as if the skin at its most
        illuminated passes from opacity to translucency.

        **Chromatic fabric precision** — Where Caravaggio's draperies are generalised
        carriers of form, Orazio's are specific observed objects: a gold satin shift
        shimmering with warm highlights and cool shadows, a red damask with saturation
        maintained even in its darkest passages, a blue silk whose cool hue stays
        vivid from highlight to shadow.  He achieves this through chromatic accuracy:
        he does not mix his colours toward neutral as they darken, but maintains their
        hue identity deeper into shadow than most of his contemporaries.  The result
        is a chromatic richness that is not theatrical (it does not shout) but precise
        (each colour is itself, clearly and fully).

        **Controlled shadow coolness** — Orazio's shadows are cool and atmospheric,
        never the warm brown void of the Italian Caravaggisti (who inherited
        Caravaggio's oil-blackened dark grounds) nor the warm amber recovery of the
        Venetian tradition.  In his shadowed flesh, a slight cool-grey quality
        prevails — not cold enough to feel artificial, but cool enough to read as the
        diffuse complement to his silver highlights.  The shadow-to-light transition
        is gradual and measured: none of Ribera's brutal chiaroscuro, none of
        Leonardo's atmospheric dissolution — just careful, observed tonal progression.

        This pass encodes all three qualities through three controlled tonal operations:

          1. Silver highlight coolness — In the upper highlight zone (lum > hi_lo),
             apply a gentle cool shift: R - silver_r_damp and B + silver_b_lift.
             Graduated smoothly by a Gaussian-blurred luminance mask, this produces
             the characteristic Orazio cool-silver quality at peak highlights without
             visible seams into the warmer mid-tone below.

          2. Midtone chroma lift — In the mid-tone band [mid_lo, mid_hi], apply a
             saturation boost toward each pixel's hue direction (away from grey).
             The magnitude is chroma_lift * mid_mask, where mid_mask is a raised-
             cosine window that peaks at the mid-tone centre.  This encodes Orazio's
             chromatic fabric precision: his colours are more themselves in the
             mid-tones — not pushed to impressionistic scatter, but precisely more
             vivid than the warm-glaze accumulation of prior sessions would allow.

          3. Cool shadow control — In shadow zones (lum < shadow_hi), apply a gentle
             cool-grey correction: R - cool_r_damp and B + cool_b_lift.  This
             counteracts the accumulated warm-shadow deposits from Guercino, Ribera,
             and Strozzi passes, restoring an Orazio-appropriate atmospheric coolness
             in the darkest passages without inverting their tonal character.

        Parameters
        ----------
        hi_lo         : lower luminance threshold for highlight zone (lum > this)
        silver_r_damp : red channel reduction in highlights (cool silver, not warm ivory)
        silver_b_lift : blue channel lift in highlights (cool daylight quality)
        mid_lo        : lower bound of mid-tone chroma-lift band
        mid_hi        : upper bound of mid-tone chroma-lift band
        chroma_lift   : saturation enhancement strength in mid-tones
        shadow_hi     : upper luminance threshold for shadow cool correction (lum < this)
        cool_r_damp   : red reduction in shadows (removes accumulated warm-amber deposits)
        cool_b_lift   : blue lift in shadows (cool atmospheric shadow quality)
        blur_radius   : Gaussian sigma for mask feathering
        opacity       : overall composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Silver highlight coolness ──────────────────────────────────────
        # Cool north-window daylight quality at peak highlights.
        # Graduated by luminance above hi_lo, smoothed with Gaussian.
        hi_raw = _np.clip((lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_raw.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out - hi_mask * silver_r_damp, 0.0, 1.0)
        b_out = _np.clip(b_out + hi_mask * silver_b_lift, 0.0, 1.0)

        # ── 2. Midtone chroma lift ────────────────────────────────────────────
        # Saturation boost in mid-tones encoding Orazio's chromatic fabric precision.
        # Raised-cosine window peaks at the centre of [mid_lo, mid_hi].
        mid_centre = 0.5 * (mid_lo + mid_hi)
        mid_half   = 0.5 * (mid_hi - mid_lo) + 1e-6
        mid_cos    = _np.clip((lum - mid_lo) / (mid_hi - mid_lo + 1e-6), 0.0, 1.0)
        mid_window = 0.5 * (1.0 - _np.cos(_np.pi * mid_cos))   # 0→1→0 across band
        mid_mask   = _gf(mid_window.astype(_np.float32), blur_radius)
        mid_mask   = _np.clip(mid_mask, 0.0, 1.0)
        # Chroma lift: move pixel away from its luminance-grey toward its colour
        grey_r = lum; grey_g = lum; grey_b = lum
        dr = r_out - grey_r; dg = g_out - grey_g; db = b_out - grey_b
        lift = mid_mask * chroma_lift
        r_out = _np.clip(r_out + lift * dr, 0.0, 1.0)
        g_out = _np.clip(g_out + lift * dg, 0.0, 1.0)
        b_out = _np.clip(b_out + lift * db, 0.0, 1.0)

        # ── 3. Cool shadow control ────────────────────────────────────────────
        # Atmospheric coolness in shadow zones — Orazio's shadows are never
        # the warm amber void of the Italian Caravaggisti.
        sh_raw  = _np.clip((shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0)
        sh_mask = _gf(sh_raw.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        r_out = _np.clip(r_out - sh_mask * cool_r_damp, 0.0, 1.0)
        b_out = _np.clip(b_out + sh_mask * cool_b_lift, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()

    def cagnacci_rose_flesh_pass(
        self,
        hi_lo:        float = 0.70,
        rose_r_lift:  float = 0.014,
        rose_b_damp:  float = 0.008,
        mid_lo:       float = 0.34,
        mid_hi:       float = 0.70,
        peach_r:      float = 0.020,
        peach_g:      float = 0.008,
        peach_b:      float = 0.010,
        shadow_hi:    float = 0.34,
        warm_r:       float = 0.016,
        warm_g:       float = 0.007,
        blur_radius:  float = 3.5,
        opacity:      float = 0.32,
    ) -> None:
        """
        Guido Cagnacci rose flesh pass — session 112 new artist pass.

        Guido Cagnacci (1601–1663) is among the most ravishing and least-celebrated
        of Emilian Baroque painters.  Born in Santarcangelo di Romagna, he trained
        in Bologna in the orbit of Guido Reni — the greatest technician of seamless
        sfumato in 17th-century Italy — before moving through Rome, Venice, and finally
        to Vienna (c. 1658), where he died in 1663 as court painter to Emperor Leopold I.

        What distinguishes Cagnacci from every other Baroque master is a single,
        unmistakable quality in his treatment of female flesh: a warm, pinkish,
        dreamlike luminescence that exists nowhere else in 17th-century painting.
        Where Guido Reni's flesh is cool ivory-pearl (idealised, remote, spiritual),
        Guercino's is amber-warm (earthy, direct, Lombard-naturalist), and Orazio
        Gentileschi's is cool silver (north-window daylight, clear and honest),
        Cagnacci's is rose — a specific warm-pink quality in the mid-tone zone that
        reads like candlelight seen through thin skin, or the blush of blood under
        translucent tissue.

        The technical mechanism was almost certainly his glazing practice: warm sienna
        imprimatura → cool lead-white dead-colouring → multiple thin rose-pink glazes
        (likely vermilion + lead white in greatly diluted oil) laid over the mid-tone
        flesh zones → final cool ivory highlights.  This sequence produces the
        characteristic Cagnacci quality: flesh that seems to glow from within, warm
        and saturated in the mid-tones, cooler and paler toward the highlights,
        always retaining a distinctly rose-amber warmth even in the shadows.

        His mature works — the three known versions of The Death of Cleopatra,
        the Repentant Magdalene, Martha Rebuking Mary for Her Vanity — all share
        this quality: women in states of high emotion or private repose whose skin
        carries an almost impossible warmth, as if lit from within rather than from
        without.  The effect is not erotic exactly, nor religious exactly, but
        occupies a dreamlike space between the two that is entirely his own.

        This pass encodes his rose flesh quality through three controlled tonal operations:

          1. Rose highlight warmth — In the upper highlight zone (lum > hi_lo),
             apply a gentle pinkish-rose warmth: R + rose_r_lift and B - rose_b_damp.
             This gives Cagnacci's characteristic pinkish-ivory at peak flesh lights —
             warmer than Boltraffio's pearl, warmer than Orazio's silver, yet not the
             amber-gold of Rembrandt nor the warm ivory of Raphael: a specific rose.
             Graduated by a Gaussian-blurred luminance mask so the transition into
             the warmer mid-tone below is seamless and sfumato-smooth.

          2. Peach mid-tone glow — In the mid-tone band [mid_lo, mid_hi], apply a
             warm rose-amber shift (R + peach_r, G + peach_g, B - peach_b) via a
             raised-cosine window peaking at the band centre.  This is the primary
             Cagnacci effect: the pinkish-peach warmth in the mid-tone flesh zone
             that defines his Emilian Baroque signature.  Unlike the Guercino amber
             warmth (which is ochre-based, raw umber quality) or the Strozzi amber
             impasto (which is loaded and vigorous), Cagnacci's rose glow is smooth,
             glazed, and inward — a quality of accumulated thin layers rather than
             visible paint.

          3. Warm shadow recovery — In shadow zones (lum < shadow_hi), apply a gentle
             rose-amber recovery (R + warm_r, G + warm_g) to prevent the accumulated
             cool corrections from Orazio's silver daylight pass and Sassoferrato's
             ultramarine from rendering the darks too cold.  Cagnacci's shadows
             stay warm — rose-amber rather than grey-cool — even at their deepest.

        Parameters
        ----------
        hi_lo        : lower luminance threshold for highlight zone (lum > this)
        rose_r_lift  : red channel lift in highlights (pinkish rose warmth)
        rose_b_damp  : blue channel damp in highlights (removes cool silver toward rose)
        mid_lo       : lower bound of mid-tone peach glow band
        mid_hi       : upper bound of mid-tone peach glow band
        peach_r      : red shift in mid-tones (primary rose-peach component)
        peach_g      : green shift in mid-tones (small — warm amber quality)
        peach_b      : blue reduction in mid-tones (removes coolness, warms toward rose)
        shadow_hi    : upper luminance threshold for warm shadow recovery (lum < this)
        warm_r       : red recovery in shadows (rose-amber warmth, anti-cold)
        warm_g       : green recovery in shadows (small amber component)
        blur_radius  : Gaussian sigma for mask feathering
        opacity      : overall composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Rose highlight warmth ──────────────────────────────────────────
        # Pinkish-ivory quality at peak flesh lights — Cagnacci's rose highlight.
        # Graduated by luminance above hi_lo, smoothed with Gaussian.
        hi_raw  = _np.clip((lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_raw.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * rose_r_lift, 0.0, 1.0)
        b_out = _np.clip(b_out - hi_mask * rose_b_damp, 0.0, 1.0)

        # ── 2. Peach mid-tone glow ────────────────────────────────────────────
        # The primary Cagnacci effect: rose-peach warmth in the mid-tone flesh.
        # Raised-cosine window peaks at the centre of [mid_lo, mid_hi].
        mid_cos    = _np.clip((lum - mid_lo) / (mid_hi - mid_lo + 1e-6), 0.0, 1.0)
        mid_window = 0.5 * (1.0 - _np.cos(_np.pi * mid_cos))   # 0→1→0 across band
        mid_mask   = _gf(mid_window.astype(_np.float32), blur_radius)
        mid_mask   = _np.clip(mid_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + mid_mask * peach_r, 0.0, 1.0)
        g_out = _np.clip(g_out + mid_mask * peach_g, 0.0, 1.0)
        b_out = _np.clip(b_out - mid_mask * peach_b, 0.0, 1.0)

        # ── 3. Warm shadow recovery ───────────────────────────────────────────
        # Rose-amber warmth in shadows — Cagnacci's darks never go cool-grey.
        sh_raw  = _np.clip((shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0)
        sh_mask = _gf(sh_raw.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + sh_mask * warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * warm_g, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Orazio Gentileschi silver daylight pass complete.")

    def jordaens_earthy_vitality_pass(
        self,
        hi_lo:        float = 0.72,
        cream_r:      float = 0.014,
        cream_g:      float = 0.007,
        mid_lo:       float = 0.28,
        mid_hi:       float = 0.72,
        ruddy_r:      float = 0.024,
        ruddy_g:      float = 0.010,
        ruddy_b:      float = 0.009,
        shadow_hi:    float = 0.38,
        ochre_r:      float = 0.020,
        ochre_g:      float = 0.010,
        blur_radius:  float = 4.0,
        opacity:      float = 0.34,
    ) -> None:
        """
        Jacob Jordaens earthy vitality pass — session 112 new artist pass.

        Jacob Jordaens (1593–1678) was the leading painter of Antwerp Baroque after
        Rubens' death in 1640 — robust, earthy, and resolutely Flemish in a way that
        his more cosmopolitan contemporaries were not.  Unlike Rubens, who absorbed the
        Italian grand manner through extended time in Italy, Jordaens never left Antwerp.
        His art reflects this: warm, physically grounded, and unashamedly artisan in the
        best sense of the word.

        Trained by Adam van Noort (also Rubens' early teacher), Jordaens built on the
        Flemish workshop tradition of warm ochre-sienna imprimatura grounds and direct
        loaded-brush painting.  His technique is often described as alla prima but his
        hand is heavier and more impasto than Rubens' fluid blending — he built up his
        highlights in thick paste, leaving the brushwork visible in the lit zones while
        the shadows are leaner and more transparent.

        Three qualities define his visual signature:

        **Earthy ruddy flesh tones** — Jordaens' flesh is characteristically warm and
        sienna-based.  Not the cool silver of Moroni or Orazio, not the warm gold of
        Rembrandt, not the rosy pink of Rubens — but an honest, earthy warmth that reads
        as real Flemish skin under warm ambient indoor light.  The mid-tones in his faces
        have a ruddy, ochre-sienna quality that is entirely his own: more physical, more
        grounded, less idealised than any of the court portraitists.

        **Warm cream impasto highlights** — Where Orazio's highlights are cool silver and
        Rembrandt's are warm gold, Jordaens' are warm cream-ivory.  Built up in thick
        impasto on the lit sides of faces, shoulders, and drapery highlights, they give
        his figures a sense of physical mass: the paint itself has weight and the light
        registers as accumulated substance rather than reflected glaze.

        **Amber shadow retention** — Even in his deepest shadows, Jordaens never lets his
        tones go cold or grey.  The warm umber-chestnut quality that prevails throughout
        his shadow zones keeps figures grounded and alive — there is no void in Jordaens,
        no near-black emptiness of the sort Caravaggio or Ribera embrace.  His darkest
        passages are deep warm brown, retaining a residual amber warmth that prevents any
        figure from sinking into dissolution.

        This pass encodes all three qualities through three controlled tonal operations:

          1. Warm cream highlight lift — In the upper highlight zone (lum > hi_lo), apply
             a warm cream boost: R + cream_r, G + cream_g.  Graduated smoothly by a
             Gaussian-blurred luminance mask, this builds Jordaens' characteristic
             impasto cream quality in the brightest pixels.  No blue lift — the contrast
             with Orazio's cool silver quality is precisely the difference between warm
             Antwerp naturalism and courtly Italian silver daylight.

          2. Earthy sienna midtone warmth — In the mid-tone band [mid_lo, mid_hi], apply
             a warm earthy boost using a raised-cosine window: R + ruddy_r, G + ruddy_g
             (smaller), B - ruddy_b (gentle damp).  The cosine window peaks at the centre
             of the mid-tone range, so the effect is smoothly graduated.  This captures
             the ruddy, sienna-based flesh quality of Jordaens' mid-tones — physically
             present and warm without tipping into theatrical orange.

          3. Shadow amber retention — In shadow zones (lum < shadow_hi), apply a warm
             ochre-amber boost: R + ochre_r, G + ochre_g (half-strength).  This prevents
             the accumulated cool shifts from Orazio's pass from making the shadows read
             as Moroni-silver or Boltraffio-cool.  Jordaens' shadows are warm umber-amber
             throughout — grounded and earthbound.

        Parameters
        ----------
        hi_lo        : lower luminance threshold for highlight zone (lum > this)
        cream_r      : red channel lift in highlights (warm cream impasto quality)
        cream_g      : green channel lift in highlights (cream warmth, less than R)
        mid_lo       : lower bound of earthy mid-tone band
        mid_hi       : upper bound of earthy mid-tone band
        ruddy_r      : red boost in mid-tones (earthy Antwerp flesh warmth)
        ruddy_g      : green boost in mid-tones (sienna quality, subdued)
        ruddy_b      : blue damp in mid-tones (remove cool contamination from prior passes)
        shadow_hi    : upper luminance threshold for shadow amber zone (lum < this)
        ochre_r      : red lift in shadows (warm amber-ochre retention)
        ochre_g      : green lift in shadows (amber warmth, half-strength)
        blur_radius  : Gaussian sigma for mask feathering
        opacity      : overall composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Warm cream highlight lift ──────────────────────────────────────
        # Jordaens' impasto peak-lights: warm cream-ivory, not cool silver.
        # Graduated by luminance above hi_lo, smoothed with Gaussian.
        hi_raw  = _np.clip((lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_raw.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * cream_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * cream_g, 0.0, 1.0)
        # No blue lift — warm cream, not cool silver (contrast with Orazio pass)

        # ── 2. Earthy sienna midtone warmth ──────────────────────────────────
        # Ruddy sienna-based flesh quality in the mid-tone zone.
        # Raised-cosine window peaks at the centre of [mid_lo, mid_hi].
        mid_cos    = _np.clip((lum - mid_lo) / (mid_hi - mid_lo + 1e-6), 0.0, 1.0)
        mid_window = 0.5 * (1.0 - _np.cos(_np.pi * mid_cos))   # 0→1→0 across band
        mid_mask   = _gf(mid_window.astype(_np.float32), blur_radius)
        mid_mask   = _np.clip(mid_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + mid_mask * ruddy_r, 0.0, 1.0)
        g_out = _np.clip(g_out + mid_mask * ruddy_g, 0.0, 1.0)
        b_out = _np.clip(b_out - mid_mask * ruddy_b, 0.0, 1.0)

        # ── 3. Shadow amber retention ─────────────────────────────────────────
        # Warm umber-chestnut quality in shadow zones — Jordaens never goes cold.
        sh_raw  = _np.clip((shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0)
        sh_mask = _gf(sh_raw.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + sh_mask * ochre_r, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * ochre_g, 0.0, 1.0)
        # No blue adjustment in shadows — amber warmth only, no cool correction

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Jacob Jordaens earthy vitality pass complete.")

    def furini_melancholic_sfumato_pass(
        self,
        hi_lo:          float = 0.68,
        ivory_r:        float = 0.012,
        ivory_g:        float = 0.008,
        ivory_b:        float = 0.004,
        penumbra_lo:    float = 0.28,
        penumbra_hi:    float = 0.60,
        lavender_b:     float = 0.018,
        lavender_r:     float = 0.008,
        shadow_hi:      float = 0.26,
        shadow_b:       float = 0.010,
        shadow_r:       float = 0.012,
        smooth_sigma:   float = 2.2,
        smooth_lo:      float = 0.30,
        smooth_hi:      float = 0.78,
        smooth_str:     float = 0.45,
        blur_radius:    float = 3.5,
        opacity:        float = 0.30,
    ) -> None:
        """
        Francesco Furini melancholic sfumato pass — session 114 new artist pass.

        Francesco Furini (1603–1646) is one of the great undiscovered masters of the
        Florentine Baroque — a painter whose technique represents perhaps the most
        extreme development of sfumato in the entire seventeenth century.  Born in
        Florence, he trained first under his father Filippo Furini (a minor goldsmith-
        painter) before entering the studio of Matteo Rosselli, whose workshop produced
        several of the most significant Florentine painters of the next generation,
        including Jacopo Vignali and Lorenzo Lippi.  Furini's decisive formative
        experience, however, came during his time in Rome in the early 1620s, where he
        absorbed both the Caravaggist tradition of tenebrism and — crucially — the
        continuing influence of Correggio's Parma sfumato that had been transmitted
        through the Roman environment.

        What makes Furini unique among his Florentine contemporaries is his synthesis
        of these two seemingly opposed impulses: the deep darkness of Caravaggism and
        the soft, almost evanescent sfumato of the Correggio-Leonardo lineage.  In a
        Caravaggio, the darkness is void — a near-black that defines form through
        sudden emergence into light.  In Furini, the darkness is atmospheric and
        enveloping, more like Leonardo's aerial perspective than Caravaggio's void:
        his figures dissolve at the periphery not into emptiness but into a warm,
        tonally continuous darkness that suggests infinite recessive depth.

        Three qualities define his visual signature:

        **Evanescent ivory skin bloom** — Furini's highlight flesh is among the
        softest and most luminous in all of Baroque painting.  Where Boltraffio's
        highlights are cool pearl and Moroni's are cool silver, Furini's are warm
        ivory — a very slightly warmer, creamier quality than either.  But the
        defining characteristic is not the colour but the *continuity*: Furini's
        highlights have no edge, no boundary, no point where they begin or end.
        They bloom outward from the peak of the form as an almost imperceptible
        warmth — the skin itself appears to emit a faint ivory light.

        **Lavender-grey penumbra at shadow edges** — This is Furini's most
        distinctive and least-imitated quality.  At the transition zone between
        the illuminated flesh and the surrounding shadow, Furini introduces a
        cool lavender-grey quality — neither the warm amber-rose of Guercino nor
        the cold blue of Sassoferrato, but a specific cool grey-lavender that
        reads as Florentine ambient reflected light from a grey sky.  This
        penumbra quality is subtle — it does not announce itself — but it creates
        a characteristic coolness at the shadow edge that sharpens the contrast
        between the warm lit flesh above and the dark warm-brown below, while
        simultaneously softening the transition so that no hard edge is visible.
        The technical origin is probably a thin grey-blue underpaint or secondary
        reflected-light source in his studio setup.

        **Ultra-smooth surface continuity** — Furini's surfaces are among the
        smoothest in all of European painting.  Contemporary sources noted that
        his flesh appeared "di marmo" — like marble — yet warm and alive.  This
        was achieved through extraordinary patience in the mid-tone zone: dozens
        of thin oil glazes blended one into the next with soft badger or fan
        brushes, creating a surface so continuous that individual pigment
        particles are invisible even under close examination.  The result is a
        quality that anticipates the porcelain-smooth academic technique of the
        nineteenth century, but with a warmth and psychological depth that the
        academics rarely matched.

        This pass encodes all three qualities through four controlled operations:

          1. Ivory highlight bloom — In the upper highlight zone (lum > hi_lo),
             apply a gentle warm ivory lift: R + ivory_r, G + ivory_g (smaller),
             B + ivory_b (very small, to avoid pure yellow).  The mask is heavily
             Gaussian-blurred so that the effect has no edge — the highlight
             quality bleeds outward from the peak of each form.  This replicates
             Furini's characteristic ivory bloom quality at the most luminous
             flesh zones.

          2. Lavender penumbra at shadow edges — In the transition zone
             [penumbra_lo, penumbra_hi], apply a cool lavender shift using a
             raised-cosine window peaking at the centre of the band:
             B + lavender_b, R - lavender_r.  This introduces Furini's
             characteristic cool grey-lavender quality exactly at the light-to-
             shadow transition — the most defining feature of his technique,
             invisible to casual inspection but responsible for the characteristic
             Furini "ring of coolness" around illuminated forms.

          3. Deep shadow cool tone — In shadow zones (lum < shadow_hi), apply a
             very subtle cool correction: B + shadow_b, R - shadow_r.  Where
             Jordaens and Cagnacci keep their shadows warm, Furini's deep shadows
             carry a slightly cooler quality — influenced by his Florentine
             environment and his absorption of Leonardo's atmospheric perspective.
             The net effect after Cagnacci's warm shadow recovery is a shadows
             that are warm amber-rose in the mid-shadow but slightly cooler in
             the deepest zones.

          4. Ultra-smooth mid-tone surface — In the mid-tone zone [smooth_lo,
             smooth_hi], apply a Gaussian-blurred blend of the current canvas
             colour with itself: the blurred version is blended in at strength
             smooth_str, creating an artificial surface continuity that mimics
             Furini's extreme glazing patience.  This is the single operation most
             responsible for the "marmo" quality in the output.

        Parameters
        ----------
        hi_lo        : lower luminance threshold for ivory highlight bloom (lum > this)
        ivory_r      : red lift in highlights (warm ivory bloom quality)
        ivory_g      : green lift in highlights (ivory warmth, less than R)
        ivory_b      : blue lift in highlights (tiny — prevents pure yellow)
        penumbra_lo  : lower bound of lavender penumbra band
        penumbra_hi  : upper bound of lavender penumbra band
        lavender_b   : blue lift in penumbra (lavender cool quality)
        lavender_r   : red damp in penumbra (lavender, not warm)
        shadow_hi    : upper luminance threshold for deep shadow zone (lum < this)
        shadow_b     : blue lift in deep shadows (atmospheric Florentine cool)
        shadow_r     : red damp in deep shadows (prevent accumulated warmth)
        smooth_sigma : Gaussian sigma for mid-tone surface smoothing
        smooth_lo    : lower bound of smoothed mid-tone zone
        smooth_hi    : upper bound of smoothed mid-tone zone
        smooth_str   : blend strength for Gaussian surface smoothing (0–1)
        blur_radius  : Gaussian sigma for mask feathering
        opacity      : overall composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Ivory highlight bloom ──────────────────────────────────────────
        # Warm ivory luminosity at the peak of illuminated flesh forms.
        # Heavy blur ensures the effect has no edge — it bleeds outward as a bloom.
        hi_raw  = _np.clip((lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_raw.astype(_np.float32), blur_radius * 1.8)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * ivory_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * ivory_g, 0.0, 1.0)
        b_out = _np.clip(b_out + hi_mask * ivory_b, 0.0, 1.0)

        # ── 2. Lavender penumbra at shadow edges ──────────────────────────────
        # Cool lavender-grey at the light-to-shadow transition zone.
        # Raised-cosine window peaks at centre of [penumbra_lo, penumbra_hi].
        pen_cos    = _np.clip((lum - penumbra_lo) / (penumbra_hi - penumbra_lo + 1e-6), 0.0, 1.0)
        pen_window = 0.5 * (1.0 - _np.cos(_np.pi * pen_cos))
        pen_mask   = _gf(pen_window.astype(_np.float32), blur_radius)
        pen_mask   = _np.clip(pen_mask, 0.0, 1.0)
        r_out = _np.clip(r_out - pen_mask * lavender_r, 0.0, 1.0)
        b_out = _np.clip(b_out + pen_mask * lavender_b, 0.0, 1.0)

        # ── 3. Deep shadow cool tone ──────────────────────────────────────────
        # Subtle atmospheric cool in the deepest shadow zones.
        # Contrasts with Cagnacci's warm shadow recovery — Furini is slightly cooler.
        sh_raw  = _np.clip((shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0)
        sh_mask = _gf(sh_raw.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        b_out = _np.clip(b_out + sh_mask * shadow_b, 0.0, 1.0)
        r_out = _np.clip(r_out - sh_mask * shadow_r, 0.0, 1.0)

        # ── 4. Ultra-smooth mid-tone surface ─────────────────────────────────
        # Gaussian blur of the mid-tone zone to simulate Furini's glazing patience.
        # The blurred values are blended back in to create surface continuity.
        r_blur = _gf(r_out.astype(_np.float32), smooth_sigma)
        g_blur = _gf(g_out.astype(_np.float32), smooth_sigma)
        b_blur = _gf(b_out.astype(_np.float32), smooth_sigma)

        mid_cos    = _np.clip((lum - smooth_lo) / (smooth_hi - smooth_lo + 1e-6), 0.0, 1.0)
        mid_window = 0.5 * (1.0 - _np.cos(_np.pi * mid_cos))
        mid_mask   = _gf(mid_window.astype(_np.float32), blur_radius * 0.5)
        mid_mask   = _np.clip(mid_mask, 0.0, 1.0)

        r_out = r_out * (1.0 - mid_mask * smooth_str) + r_blur * (mid_mask * smooth_str)
        g_out = g_out * (1.0 - mid_mask * smooth_str) + g_blur * (mid_mask * smooth_str)
        b_out = b_out * (1.0 - mid_mask * smooth_str) + b_blur * (mid_mask * smooth_str)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Francesco Furini melancholic sfumato pass complete.")

    def fontana_jewel_costume_pass(
        self,
        hi_lo:          float = 0.70,
        ivory_r:        float = 0.012,
        ivory_g:        float = 0.007,
        ivory_b:        float = 0.002,
        costume_lo:     float = 0.18,
        costume_hi:     float = 0.46,
        crimson_r:      float = 0.020,
        crimson_g:      float = 0.003,
        crimson_b:      float = 0.007,
        shadow_hi:      float = 0.22,
        amber_r:        float = 0.014,
        amber_g:        float = 0.006,
        blur_radius:    float = 3.0,
        opacity:        float = 0.28,
    ) -> None:
        """
        Lavinia Fontana jewel costume pass — session 115 new artist pass.

        Lavinia Fontana (1552–1614) was the first woman in Western history to
        establish herself as a fully professional artist.  Daughter of the Bolognese
        painter Prospero Fontana, she trained in one of the most technically rigorous
        workshops in northern Italy — the same Bolognese environment that would,
        within a generation, produce the Carracci academy and its reform of European
        painting.  She eventually received a papal invitation to Rome from Clement VIII,
        and her work entered royal and papal collections across Europe.

        Her technical inheritance is unmistakably Bolognese: a warm, amber-toned
        ground, smooth flesh modelling built up through careful glazed layers, and an
        approach to luminosity that owes more to Correggio's atmospheric warmth than
        to the cool silver precision of the Lombard portrait tradition.  Where Moroni
        observes his sitters under flat north light with tonal accuracy, Fontana
        idealises slightly — lifting the flesh toward a rose-ivory warmth that flatters
        without falsifying.

        Her defining technical signature is the rendering of costume and jewellery.
        No other Italian painter of the late sixteenth century matched her command of
        deep crimson velvet — the fabric of choice for Bolognese nobility — rendered
        with such material convincingness.  The darkness of the velvet is not the
        near-black void of a Caravaggio or the flat black of a Bronzino; it is a warm,
        rich darkness with crimson depth visible in the folds and highlights, achieved
        through multiple translucent glazes of vermilion and lake over a warm umber
        underlayer.  Against this costume depth, gold jewellery — pearl necklaces,
        gold chains, gem-set brooches — reads with extraordinary vivacity because the
        warm gold simultaneously highlights against dark velvet and ties the figure's
        costume palette together.

        Bolognese painters never let their shadows go cold or grey; even in the
        near-black void of the background, there is recoverable warm amber — the
        quality that makes Bolognese portraits feel inhabited and warm rather than
        theatrically dramatic.

        This pass encodes all three qualities through three controlled operations:

          1. Highlight warm brilliance — In the upper highlight zone (lum > hi_lo),
             apply a gentle warm ivory lift: R + ivory_r, G + ivory_g, B + ivory_b.
             The Gaussian-blurred mask ensures the highlight blooms without a hard
             edge — Bolognese luminosity is warm and present, distinct from Moroni's
             cool silver or Boltraffio's pearled quality.

          2. Costume crimson depth — In the dark costume zone [costume_lo, costume_hi],
             apply a raised-cosine warm crimson enrichment: R + crimson_r,
             G + crimson_g (tiny), B - crimson_b (slight reduction to prevent purple
             drift).  This replicates Fontana's signature deep crimson velvet quality —
             the warm, saturated darkness that gives costume zones their material
             richness, contrasting with the cold dark of a Bronzino or the void dark
             of a Caravaggio.

          3. Shadow amber warmth — In the deepest shadow zone (lum < shadow_hi), add
             warm amber retention: R + amber_r, G + amber_g.  The Bolognese warmth
             in the deepest tones — never cold grey, never void black.

        Parameters
        ----------
        hi_lo       : lower luminance threshold for highlight zone (lum > this)
        ivory_r     : red lift in highlights (warm Bolognese ivory glow)
        ivory_g     : green lift in highlights (warm but not pure yellow)
        ivory_b     : blue lift in highlights (tiny — prevents coolness)
        costume_lo  : lower bound of costume crimson zone
        costume_hi  : upper bound of costume crimson zone
        crimson_r   : red lift in costume zone (warm crimson velvet depth)
        crimson_g   : green lift in costume zone (tiny — amber quality, not pure red)
        crimson_b   : blue reduction in costume zone (prevents purple shift)
        shadow_hi   : upper luminance threshold for shadow amber zone (lum < this)
        amber_r     : red lift in deep shadows (amber warmth retention)
        amber_g     : green lift in deep shadows (amber, not pure red)
        blur_radius : Gaussian sigma for mask feathering
        opacity     : overall composite opacity (0–1)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        h, w = self.h, self.w

        # ── Read canvas ───────────────────────────────────────────────────────
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((h, w, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Highlight warm brilliance ──────────────────────────────────────
        # Warm rose-ivory luminosity at peak flesh — Bolognese warmth, not cool silver.
        hi_raw  = _np.clip((lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_raw.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * ivory_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * ivory_g, 0.0, 1.0)
        b_out = _np.clip(b_out + hi_mask * ivory_b, 0.0, 1.0)

        # ── 2. Costume crimson depth ──────────────────────────────────────────
        # Raised-cosine enrichment in the dark costume zone — Fontana's velvet signature.
        # Peaks at the centre of [costume_lo, costume_hi], fading toward both extremes.
        cos_raw    = _np.clip((lum - costume_lo) / (costume_hi - costume_lo + 1e-6), 0.0, 1.0)
        cos_window = 0.5 * (1.0 - _np.cos(_np.pi * cos_raw))
        cos_mask   = _gf(cos_window.astype(_np.float32), blur_radius)
        cos_mask   = _np.clip(cos_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + cos_mask * crimson_r, 0.0, 1.0)
        g_out = _np.clip(g_out + cos_mask * crimson_g, 0.0, 1.0)
        b_out = _np.clip(b_out - cos_mask * crimson_b, 0.0, 1.0)

        # ── 3. Shadow amber warmth ────────────────────────────────────────────
        # Warm amber retention in the deepest shadow zones — Bolognese never goes cold.
        sh_raw  = _np.clip((shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0)
        sh_mask = _gf(sh_raw.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + sh_mask * amber_r, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * amber_g, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Lavinia Fontana jewel costume pass complete.")

    def solario_pellucid_amber_pass(
        self,
        hi_lo:          float = 0.62,
        amber_r:        float = 0.018,
        amber_g:        float = 0.010,
        amber_b:        float = 0.004,
        shadow_hi:      float = 0.32,
        violet_b:       float = 0.016,
        violet_g:       float = 0.004,
        violet_r:       float = 0.005,
        arc_lo:         float = 0.32,
        arc_hi:         float = 0.62,
        arc_r:          float = 0.014,
        arc_g:          float = 0.006,
        blur_radius:    float = 3.5,
        opacity:        float = 0.30,
    ) -> None:
        """
        Andrea Solario pellucid amber pass — session 116 new artist pass.

        Andrea Solario (c. 1460–1524) is one of the most refined practitioners
        of Leonardesque sfumato in the Milanese school — a painter who absorbed
        Leonardo's atmospheric technique during the master's Milanese years and
        fused it with a Venetian chromatic sensibility to produce a style of
        singular luminous pellucidity.

        Three qualities define his visual signature:

        **Pellucid amber highlight** — Solario's highlight flesh carries a warm
        amber-honey tone unlike any other Lombard painter.  Boltraffio's highlights
        are cool pearl; Furini's are warm ivory; Solario's are amber — a honey-gold
        quality in the upper highlight zone (lum > hi_lo ≈ 0.62) that suggests
        physical depth in the paint surface: layers of thin amber-tinted glaze
        built over a warm ground, each adding warmth and transparency.

        **Cool violet shadow** — Solario's Venetian training manifests in his shadow
        treatment.  The deepest shadow zones (lum < shadow_hi ≈ 0.32) carry a
        subtle blue-violet undertone — the atmospheric shadow quality of Venetian
        painting that never appears in purely Lombard or Florentine painters.  This
        prevents the shadows from going merely warm-dark and gives them an
        atmospheric, spatially recessive quality.

        **Chromatic arc mid-tone warmth** — the penumbra zone [arc_lo, arc_hi]
        receives a sin-window warmth pulse (R + arc_r * sin_window, G + arc_g).
        This encodes Solario's continuously-varying colour temperature across the
        flesh: the transition from cool shadows through warm amber mid-tones to
        amber highlights creates a chromatic arc that gives his portraits an unusual
        sense of atmospheric depth.  The sin-window peaks at the centre of the
        penumbra range and fades toward both shadow and highlight — a smooth,
        physically motivated warmth gradient inspired by the actual behaviour of
        semi-transparent amber oil glazes.

        This is the session 116 artistic improvement: a chromatic arc mid-tone
        warmth technique, mathematically smooth and physically grounded, that
        creates continuously varying colour temperature across the flesh — more
        sophisticated than previous passes that handled highlights and shadows
        independently without modelling the transition zone.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Pellucid amber highlight ───────────────────────────────────────
        # Warm amber-honey lift at peak flesh — Solario's pellucid warmth quality.
        # Warmer than Boltraffio's pearl, more amber than Furini's ivory.
        hi_raw  = _np.clip((lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_raw.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * amber_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * amber_g, 0.0, 1.0)
        b_out = _np.clip(b_out - hi_mask * amber_b, 0.0, 1.0)

        # ── 2. Cool violet shadow ─────────────────────────────────────────────
        # Raised-cosine blue-violet in the deepest shadow zone — Venetian inheritance.
        # Prevents purely warm-dark shadows; gives spatial, atmospheric recession.
        sh_raw    = _np.clip((shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0)
        cos_raw   = _np.clip(sh_raw, 0.0, 1.0)
        cos_win   = 0.5 * (1.0 - _np.cos(_np.pi * cos_raw))
        sh_mask   = _gf(cos_win.astype(_np.float32), blur_radius)
        sh_mask   = _np.clip(sh_mask, 0.0, 1.0)
        b_out = _np.clip(b_out + sh_mask * violet_b, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * violet_g, 0.0, 1.0)
        r_out = _np.clip(r_out - sh_mask * violet_r, 0.0, 1.0)

        # ── 3. Chromatic arc mid-tone warmth ──────────────────────────────────
        # Sin-window warmth pulse in the penumbra zone [arc_lo, arc_hi].
        # Models the continuously-varying colour temperature of Solario's flesh:
        # cool shadows → warm penumbra → amber highlights.  The sin-window ensures
        # the warmth peaks at the centre of the penumbra and fades toward both
        # extremes — a smooth, physically motivated amber gradient.
        arc_raw    = _np.clip((lum - arc_lo) / (arc_hi - arc_lo + 1e-6), 0.0, 1.0)
        arc_window = _np.sin(_np.pi * arc_raw)        # peaks at 0.5 of the range
        arc_mask   = _gf(arc_window.astype(_np.float32), blur_radius)
        arc_mask   = _np.clip(arc_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + arc_mask * arc_r, 0.0, 1.0)
        g_out = _np.clip(g_out + arc_mask * arc_g, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Andrea Solario pellucid amber pass complete.")

    def perugino_serene_grace_pass(
        self,
        ground_lo:   float = 0.30,
        ground_hi:   float = 0.75,
        ground_r:    float = 0.014,
        ground_g:    float = 0.007,
        hi_lo:       float = 0.70,
        ivory_r:     float = 0.010,
        ivory_g:     float = 0.006,
        ivory_b:     float = 0.003,
        shadow_hi:   float = 0.35,
        warm_r:      float = 0.014,
        warm_g:      float = 0.006,
        blur_radius: float = 4.0,
        opacity:     float = 0.30,
    ) -> None:
        """
        Pietro Perugino serene grace pass — session 117 new artist pass.

        Pietro Perugino (c. 1446–1523), teacher of Raphael, founded the Umbrian
        school — a tradition of serene, harmonious painting defined by a diffuse
        warm luminosity that seems to emanate from the ground itself.  Unlike
        Leonardo's sfumato (atmospheric edge dissolution), Rembrandt's chiaroscuro
        (dramatic lighting contrast), or the Venetian colorists (saturated chromatic
        vitality), Perugino achieves his quality through luminous ground warmth:
        the warm ochre imprimatura glowing softly through thin glazes, suffusing
        every passage with gentle inner warmth.

        Three qualities define his visual signature:

        **Luminous ground warmth** — a broad warm ambient lift applied throughout
        the mid-tone zone [ground_lo, ground_hi] via a sin²(π·t) bell-window.
        R + ground_r, G + ground_g.  The sin² window (broader and more gradual
        than a simple sine peak) encodes the diffuse, pervasive quality of
        Perugino's warmth — not a targeted penumbra effect but an ambient field
        of warmth emanating from the ground layer through thin glazes.  This is
        the session 117 artistic improvement: sin²-windowed ground warmth, a
        more spatially uniform and physically grounded warmth model than the
        sin-windowed penumbra pulse of Solario's arc (session 116) — simulating
        the optical behaviour of a warm imprimatura viewed through multiple
        semi-transparent oil layers.

        **Ivory highlight serenity** — in the upper highlight zone (lum > hi_lo),
        a warm ivory-gold lift (R + ivory_r, G + ivory_g, B - ivory_b).  Perugino's
        highlights are creamy ivory-gold rather than cool pearl (Boltraffio), silver
        (Moroni), or amber-pellucid (Solario): warm, unassuming, harmonious — the
        light of an Umbrian afternoon.

        **Warm amber shadow** — in the shadow zone (lum < shadow_hi), a gentle
        raised-cosine warm amber recovery (R + warm_r, G + warm_g).  Perugino's
        shadows never go cold; dark passages retain the warm amber-sienna quality
        of the Umbrian earth — fundamentally different from Solario's cool violet
        Venetian shadows.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Luminous ground warmth (sin² bell window) ──────────────────────
        # The defining Umbrian quality: warm imprimatura glowing through glazes.
        # sin²(π·t) is broader and more gradual than sin(π·t) — encodes the
        # diffuse ambient character of ground warmth vs. a targeted penumbra pulse.
        t_ground = _np.clip(
            (lum - ground_lo) / (ground_hi - ground_lo + 1e-6), 0.0, 1.0
        )
        sin2_win = _np.sin(_np.pi * t_ground) ** 2
        ground_mask = _gf(sin2_win.astype(_np.float32), blur_radius)
        ground_mask = _np.clip(ground_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + ground_mask * ground_r, 0.0, 1.0)
        g_out = _np.clip(g_out + ground_mask * ground_g, 0.0, 1.0)

        # ── 2. Ivory highlight serenity ───────────────────────────────────────
        # Warm ivory-gold at peak flesh — Perugino's serene Umbrian highlight.
        # Warmer than Boltraffio's pearl, not as amber as Solario, not as silvery
        # as Moroni: creamy ivory-gold, harmonious and unassuming.
        hi_raw = _np.clip((lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_raw.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * ivory_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * ivory_g, 0.0, 1.0)
        b_out = _np.clip(b_out - hi_mask * ivory_b, 0.0, 1.0)

        # ── 3. Warm amber shadow ──────────────────────────────────────────────
        # Raised-cosine amber recovery in the shadow zone — Umbrian earth warmth.
        # Unlike Solario's cool violet shadows, Perugino's darks stay warm and
        # grounded: the amber-sienna quality of the Umbrian plain even in darkness.
        sh_raw  = _np.clip((shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0)
        cos_win = 0.5 * (1.0 - _np.cos(_np.pi * sh_raw))
        sh_mask = _gf(cos_win.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + sh_mask * warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * warm_g, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Pietro Perugino serene grace pass complete.")

    def savoldo_silver_veil_pass(
        self,
        penumbra_lo:  float = 0.28,
        penumbra_hi:  float = 0.62,
        silver_r:     float = 0.010,
        silver_b:     float = 0.022,
        hi_lo:        float = 0.70,
        ivory_r:      float = 0.012,
        ivory_g:      float = 0.007,
        shadow_hi:    float = 0.32,
        warm_r:       float = 0.012,
        warm_g:       float = 0.005,
        blur_radius:  float = 4.0,
        opacity:      float = 0.28,
    ) -> None:
        """
        Giovanni Gerolamo Savoldo silver moonveil pass — session 118 new artist pass.

        Giovanni Gerolamo Savoldo (c. 1480/85–1548), Brescian painter working in
        Venice, pioneered a distinctive treatment of nocturnal and candlelit light
        that has no exact parallel in the Renaissance tradition.  His defining
        quality — visible most fully in Saint Mary Magdalen Approaching the
        Sepulchre (National Gallery, London) — is a phosphorescent silver-grey
        shimmer concentrated at the transitional boundary between light and shadow.
        In his nocturnal drapery passages, the fold crests read as luminous silver-
        grey while the shadowed valleys retain warm amber depth; the transition
        between them carries a cool silver cast that resembles scattered moonlight
        diffusing through cloth and atmosphere.

        Three qualities define his visual signature:

        **Silver moonveil at the penumbra boundary** — a Gaussian-peaked weight
        centred at the midpoint of [penumbra_lo, penumbra_hi].  The Gaussian
        concentrates the silver shimmer at the precise light-shadow transition:
        R - silver_r, B + silver_b.  This Gaussian-peaked penumbra window is the
        session 118 artistic improvement: a more physically grounded model of
        scattered moonlight than the sin window (session 116 arc) or sin²-window
        (session 117 ground warmth) — a Gaussian naturally models the bell-shaped
        distribution of scattered radiance at a surface whose normal is tangent to
        the illumination direction, exactly the condition at the penumbra boundary.

        **Warm ivory highlight** — in the bright zone (lum > hi_lo), R + ivory_r,
        G + ivory_g.  Savoldo's highlights are warm silver-ivory, not cold blue.
        The warmth comes from the Venetian-Lombard imprimatura still visible through
        thin highlights — it moderates the silver with Brescian earth warmth.

        **Warm shadow retention** — in the shadow zone (lum < shadow_hi), a gentle
        raised-cosine warm recovery (R + warm_r, G + warm_g) prevents cold black
        voids.  Savoldo's nocturnal shadows retain warmth even at their deepest —
        the Brescian ground warmth prevents the shadows from becoming the arctic
        cold black of Caravaggio's Roman tenebrism.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Silver moonveil (Gaussian-peaked penumbra window) ──────────────
        # The defining Savoldo quality: phosphorescent silver at the light-shadow
        # boundary.  A Gaussian centred at the penumbra midpoint concentrates the
        # cool-silver shimmer exactly at the transition zone.  This is the session
        # 118 improvement: a Gaussian penumbra peak is a more physically accurate
        # model of scattered moonlight at a tangent surface than the sin or sin²
        # windows of previous sessions.
        p_mid    = 0.5 * (penumbra_lo + penumbra_hi)
        p_sigma  = 0.20 * (penumbra_hi - penumbra_lo)
        gauss_win = _np.exp(-0.5 * ((lum - p_mid) / (p_sigma + 1e-6)) ** 2)
        silver_mask = _gf(gauss_win.astype(_np.float32), blur_radius)
        silver_mask = _np.clip(silver_mask, 0.0, 1.0)
        r_out = _np.clip(r_out - silver_mask * silver_r, 0.0, 1.0)
        b_out = _np.clip(b_out + silver_mask * silver_b, 0.0, 1.0)

        # ── 2. Warm ivory highlight ───────────────────────────────────────────
        # Savoldo's highlights are warm silver-ivory — the Venetian-Lombard
        # imprimatura moderates the silver with Brescian warmth.
        hi_raw  = _np.clip((lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_raw.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * ivory_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * ivory_g, 0.0, 1.0)

        # ── 3. Warm shadow retention (raised-cosine) ──────────────────────────
        # Savoldo's nocturnal darks retain Brescian warmth — never the arctic cold
        # of Caravaggio.  Raised-cosine recovery in the shadow zone.
        sh_raw  = _np.clip((shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0)
        cos_win = 0.5 * (1.0 - _np.cos(_np.pi * sh_raw))
        sh_mask = _gf(cos_win.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + sh_mask * warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + sh_mask * warm_g, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Giovanni Gerolamo Savoldo silver moonveil pass complete.")

    def batoni_silk_sheen_pass(
        self,
        streak_angle:   float = 45.0,
        streak_width:   float = 4.0,
        streak_spacing: float = 11.0,
        silk_lo:        float = 0.48,
        streak_r:       float = 0.032,
        streak_g:       float = 0.022,
        streak_b:       float = 0.008,
        blur_along:     float = 12.0,
        blur_across:    float = 1.5,
        opacity:        float = 0.26,
    ) -> None:
        """
        Pompeo Batoni anisotropic silk-sheen pass — session 119 new artist pass.

        Pompeo Batoni (1708–1787), the most celebrated portraitist in 18th-century
        Rome, was famed above all for his rendering of silk and satin drapery.  His
        technique produced a directional sheen unlike anything achieved by his
        contemporaries — a pattern of warm ivory highlight streaks running along the
        weave direction of the fabric, creating an anisotropic shimmer that reads
        immediately as woven silk.  This quality is vivid in his Grand Tour portraits
        (Thomas William Coke, Francis Basset, John Staples) where the sitters'
        red, blue, or gold coats have a liquid, fabric-specific luminosity.

        The defining optical phenomenon is *anisotropic specular reflectance*: woven
        silk reflects specular light preferentially along the warp/weft thread
        direction rather than isotropically.  Each thread acts as a cylindrical
        mirror; the highlight lobe is elongated along the thread axis and narrow
        across it.  This is distinct from the diffuse or spherical-Gaussian
        highlights of portrait masters working in oil without this speciality.

        The session 119 artistic improvement is the *anisotropic_silk_streak kernel*:
        a directional Gaussian kernel whose sigma along the streak angle (blur_along)
        is much larger than its sigma across it (blur_across).  Applied only where
        luminance exceeds silk_lo (the mid-bright zone where silk sheen is visible),
        the elongated kernel creates streaks of warm ivory at the given angle.
        Warm ivory tone: R + streak_r, G + streak_g, B + streak_b — slightly warm,
        never cold.  This models the warm daylight reflected by high-quality silk
        in a Roman interior lit by tall south-facing windows, as in Batoni's studio.

        Parameters
        ----------
        streak_angle   : angle of silk weave direction in degrees (0 = horizontal)
        streak_width   : Gaussian sigma *across* the streak (px) — narrower = finer
        streak_spacing : not used in the kernel but documents the visual periodicity
        silk_lo        : luminance threshold below which no sheen is applied
        streak_r/g/b   : warm ivory colour increment of the sheen
        blur_along     : Gaussian sigma *along* the streak — controls streak length
        blur_across    : Gaussian sigma across the streak (controls streak width)
        opacity        : blend factor against the original canvas
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Silk luminance mask — sheen only in mid-bright zone ────────────────
        silk_mask_raw = _np.clip((lum - silk_lo) / (1.0 - silk_lo + 1e-6), 0.0, 1.0)

        # ── Anisotropic directional blur — the session 119 improvement ────────
        # Build an anisotropic Gaussian kernel by filtering twice in rotated
        # coordinates.  The streak direction is streak_angle degrees; we rotate
        # the image, apply separable 1-D Gaussians (long along axis-1, short along
        # axis-0), then rotate back.  scipy.ndimage.rotate handles the geometry.
        from scipy.ndimage import rotate as _rot
        theta = streak_angle % 180.0
        silk_rot = _rot(silk_mask_raw, -theta, reshape=False, order=1, mode="nearest")
        # Along-streak (axis=1) — elongated highlight lobe
        silk_rot = _gf(silk_rot, sigma=[blur_across, blur_along])
        # Rotate back
        silk_dir = _rot(silk_rot, theta, reshape=False, order=1, mode="nearest")
        silk_dir = _np.clip(silk_dir, 0.0, 1.0)

        # ── Apply warm ivory sheen increment ──────────────────────────────────
        r_out = _np.clip(r0 + silk_dir * streak_r, 0.0, 1.0)
        g_out = _np.clip(g0 + silk_dir * streak_g, 0.0, 1.0)
        b_out = _np.clip(b0 + silk_dir * streak_b, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Pompeo Batoni anisotropic silk-sheen pass complete.")

    def lotto_restless_vivacity_pass(
        self,
        hi_lo:          float = 0.68,
        vivacity_r:     float = 0.014,
        vivacity_g:     float = 0.008,
        vivacity_b:     float = 0.004,
        shadow_hi:      float = 0.36,
        shadow_cool_b:  float = 0.012,
        shadow_warm_g:  float = 0.004,
        mid_lo:         float = 0.36,
        mid_hi:         float = 0.68,
        vibration_str:  float = 0.010,
        noise_scale:    float = 25.0,
        blur_radius:    float = 4.0,
        opacity:        float = 0.30,
    ) -> None:
        """
        Lorenzo Lotto multi-scale chromatic vibration pass — session 120 new artist pass.

        Lorenzo Lotto (c. 1480–1556/57), Venetian painter later based in Bergamo
        and the Marche, is one of the most psychologically intense and formally
        eccentric portraitists of the Italian Renaissance.  His famous sitters
        appear caught mid-thought — the Portrait of Andrea Odoni (1527, Hampton
        Court) depicts a collector surrounded by antique fragments, his gaze turned
        inward with an almost disquieting self-absorption — and his palette makes
        unexpected colour contrasts: vivid grass-green against mauve, cool grey-blue
        against warm ochre, acidic yellow-green in shadow zones.

        Three qualities define his visual signature:

        **Warm vivacity lift in highlights** — above hi_lo (≈ 0.68), a warm rose-
        ivory lift: R + vivacity_r, G + vivacity_g, B - vivacity_b.  Lotto's
        highlights are warm and slightly saturated — neither the cool pearl of
        Boltraffio nor the neutral ivory of Raphael, but a rose-warm quality
        reflecting his Venetian-ground warmth and his restless chromatic sensibility.

        **Cool eccentric shadow accent** — below shadow_hi (≈ 0.36), a slight blue-
        grey shift: B + shadow_cool_b, G - shadow_warm_g.  Lotto's darks often carry
        unexpected cool accents — a quality that distinguishes his psychological
        intensity from the warm-dark Giorgionesque tradition.  The blue-grey
        shadows give his figures a slightly chilly, searching quality.

        **Multi-scale chromatic vibration field** — the session 120 artistic
        improvement.  A noise field is built from Gaussian-smoothed random noise at
        three spatial scales:
          - Fine grain  (σ = noise_scale × 0.32) — stroke-level pigment variation
          - Medium      (σ = noise_scale × 1.00) — single glaze layer variation
          - Coarse      (σ = noise_scale × 2.40) — atmospheric imprimatura breathing
        Weighted combination: 0.50 fine + 0.35 medium + 0.15 coarse.  The result is
        a smooth, spatially non-uniform field normalised to [-1, 1], applied in the
        mid-tone zone (mid_lo–mid_hi) via a sin²-bell mask with amplitude
        vibration_str.  This adds ± vibration_str to the R channel (and ± 0.5 ×
        vibration_str to G) at each pixel — some areas slightly warmer, others
        slightly cooler — modelling the optical complexity of Venetian multi-glaze
        technique.  Unlike the uniform single-frequency effects of previous sessions
        (sin-window s116, sin²-window s117, Gaussian-peaked s118, anisotropic streak
        s119), the multi-scale field captures the full spatial frequency content of
        oil glazing over canvas texture: each scale models one part of the layering
        stack, and their combination produces the chromatic 'singing quality' that
        Lotto's flesh is known for.

        Parameters
        ----------
        hi_lo          : luminance threshold above which warm vivacity lift applies
        vivacity_r/g/b : warm rose-ivory highlight increment (b is subtracted)
        shadow_hi      : luminance threshold below which cool shadow accent applies
        shadow_cool_b  : cool blue increment in shadows
        shadow_warm_g  : green reduction in shadows (removes warm cast)
        mid_lo / mid_hi: luminance range for the vibration field bell mask
        vibration_str  : amplitude of the multi-scale chromatic vibration (± value)
        noise_scale    : primary Gaussian sigma (px) for the noise field
        blur_radius    : Gaussian blur radius for zone transition smoothing
        opacity        : blend factor against the original canvas
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── 1. Warm vivacity lift in highlights ──────────────────────────────────
        # Lotto's highlights are warm rose-ivory — the Venetian ground warmth
        # expressing itself through thin highlight glazes.
        hi_raw  = _np.clip((lum - hi_lo) / (1.0 - hi_lo + 1e-6), 0.0, 1.0)
        hi_mask = _gf(hi_raw.astype(_np.float32), blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)
        r_out = _np.clip(r_out + hi_mask * vivacity_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * vivacity_g, 0.0, 1.0)
        b_out = _np.clip(b_out - hi_mask * vivacity_b, 0.0, 1.0)

        # ── 2. Cool eccentric shadow accent ──────────────────────────────────────
        # Lotto's darks carry unexpected cool blue-grey — distinguishing his
        # psychological intensity from the warm-dark Giorgionesque tradition.
        sh_raw  = _np.clip((shadow_hi - lum) / (shadow_hi + 1e-6), 0.0, 1.0)
        cos_win = 0.5 * (1.0 - _np.cos(_np.pi * sh_raw))
        sh_mask = _gf(cos_win.astype(_np.float32), blur_radius)
        sh_mask = _np.clip(sh_mask, 0.0, 1.0)
        b_out = _np.clip(b_out + sh_mask * shadow_cool_b, 0.0, 1.0)
        g_out = _np.clip(g_out - sh_mask * shadow_warm_g, 0.0, 1.0)

        # ── 3. Multi-scale chromatic vibration field (session 120 improvement) ───
        # A weighted sum of Gaussian-smoothed noise at three spatial scales models
        # the optical complexity of Venetian multi-glaze technique — each scale
        # corresponds to one layer of the glazing stack:
        #   fine grain  (σ × 0.32) → stroke-level pigment variation
        #   medium      (σ × 1.00) → single glaze layer variation
        #   coarse      (σ × 2.40) → imprimatura breathing through
        # The combination creates chromatic 'singing quality' in the mid-tones.
        rng = _np.random.default_rng(seed=120)
        noise_raw = rng.standard_normal((H, W)).astype(_np.float32)
        fine   = _gf(noise_raw, sigma=noise_scale * 0.32)
        medium = _gf(noise_raw, sigma=noise_scale)
        coarse = _gf(noise_raw, sigma=noise_scale * 2.40)
        vibration_field = 0.50 * fine + 0.35 * medium + 0.15 * coarse
        vf_max = _np.abs(vibration_field).max() + 1e-6
        vibration_field = vibration_field / vf_max  # normalise to [-1, 1]

        # Bell mask: sin² window in the mid-tone zone
        mid_raw  = _np.clip((lum - mid_lo) / (mid_hi - mid_lo + 1e-6), 0.0, 1.0)
        mid_bell = _np.sin(_np.pi * mid_raw) ** 2
        mid_mask = _gf(mid_bell.astype(_np.float32), blur_radius)
        mid_mask = _np.clip(mid_mask, 0.0, 1.0)

        vib = vibration_field * mid_mask * vibration_str
        r_out = _np.clip(r_out + vib, 0.0, 1.0)
        g_out = _np.clip(g_out + vib * 0.50, 0.0, 1.0)  # green follows red at half amplitude

        # ── Composite at opacity ─────────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Lorenzo Lotto multi-scale chromatic vibration pass complete.")

    # ─────────────────────────────────────────────────────────────────────────

    def boldini_swirl_bravura_pass(
        self,
        primary_angle:   float = 45.0,    # primary swirl angle (degrees from horizontal)
        secondary_angle: float = -28.0,   # secondary swirl angle (degrees from horizontal)
        swirl_lo:        float = 0.42,    # luminance floor for swirl mask
        blur_along:      float = 14.0,    # aniso Gaussian sigma along streak axis (px)
        blur_across:     float = 1.5,     # aniso Gaussian sigma across streak axis (px)
        swirl_str:       float = 0.038,   # primary streak brightness increment
        flesh_lo:        float = 0.50,    # luminance floor for flesh luminosity zone
        flesh_hi:        float = 0.85,    # luminance ceiling for flesh luminosity zone
        flesh_r:         float = 0.016,   # R lift in flesh zone (warm ivory)
        flesh_g:         float = 0.009,   # G lift in flesh zone
        flesh_b:         float = 0.005,   # B reduction in flesh zone (de-cool)
        dark_factor:     float = 0.94,    # background darkening multiplier
        bg_warm_r:       float = 0.005,   # warm undertone added to background
        blur_radius:     float = 4.0,     # Gaussian sigma for mask transitions
        opacity:         float = 0.32,
    ) -> None:
        """
        Giovanni Boldini dual-angle swirl bravura pass — session 121 new artist pass.

        Giovanni Boldini (1842–1931), the Ferrarese-born 'Master of Swirl' and supreme
        virtuoso of Belle Époque portraiture in Paris, developed a technique unlike any
        of his contemporaries: the diagonal swirling brushstroke applied at two or more
        competing angles across the canvas surface.  The result is a visual vibration —
        the painted surface itself appears to be in motion.  Only the face and hands
        emerge as resolved zones of focus; drapery, hair, and background environment
        dissolve into directional gestural energy.

        This pass encodes Boldini's visual signature in three interlocking stages:

        **Stage 1 — Dual-angle diagonal swirl field** (session 121 artistic improvement)
        The defining feature of Boldini's technique is that his strokes cross at two
        competing angles rather than aligning in a single direction like Batoni's silk
        sheen (session 119).  Two anisotropic streak fields are computed:

          - Primary field at primary_angle (default 45°): the dominant swirl direction.
          - Secondary field at secondary_angle (default -28°): the crossing energy.

        Each field is built by:
          (a) Extracting the luminance swirl mask (lum > swirl_lo, cosine ramp).
          (b) Rotating the mask by -angle, applying an anisotropic Gaussian
              (σ_along >> σ_across: long along axis-1, narrow along axis-0), rotating back.
          (c) Clipping to [0, 1].

        The two fields are combined: primary at swirl_str, secondary at swirl_str × 0.50.
        Applied as a warm ivory brightness increment (R += total_swirl * swirl_str,
        G += total_swirl * swirl_str * 0.65, B += total_swirl * swirl_str * 0.20) in
        the figure zone.  The warm-ivory tint mimics the loaded-lead-white highlights
        that Boldini dragged across his canvases.

        **Stage 2 — Warm flesh luminosity lift**
        In the upper mid-tone zone of the figure (luminance 0.50–0.85), apply a
        sin²-bell-weighted lift: R + flesh_r, G + flesh_g, B - flesh_b.  Boldini's
        flesh tones are warmer than those of his Impressionist contemporaries — a warm
        ivory with a faint rose-tawny undertone that contrasts sharply with the cool
        near-black background.  This stage reinforces the luminous emergence of the
        figure from the dark ground.

        **Stage 3 — Background darkening**
        In the background zone (outside the figure mask), multiply all channels by
        dark_factor (< 1.0) and add a faint warm undertone (R += bg_warm_r).  Boldini's
        backgrounds have a deep chestnut-umber quality — not pure neutral black but a
        very dark warm ground that reinforces the warm tonal hierarchy of the composition
        and makes the luminous flesh advance powerfully.

        Parameters
        ----------
        primary_angle   : angle of the dominant swirl direction (degrees from horizontal)
        secondary_angle : angle of the crossing swirl direction (degrees from horizontal)
        swirl_lo        : luminance floor for the swirl activation mask
        blur_along      : Gaussian sigma along the streak axis (px) — controls streak length
        blur_across     : Gaussian sigma across the streak axis (px) — controls streak width
        swirl_str       : warm ivory brightness increment for the primary streak field
        flesh_lo        : luminance floor of the flesh luminosity zone (0–1)
        flesh_hi        : luminance ceiling of the flesh luminosity zone (0–1)
        flesh_r/g/b     : warm ivory flesh lift (flesh_b is subtracted to de-cool)
        dark_factor     : background darkening multiplier (< 1.0 darkens)
        bg_warm_r       : warm amber undertone added to background R channel
        blur_radius     : Gaussian sigma for zone transition masks
        opacity         : global compositing weight (0 = no effect, 1 = full)

        Notes
        -----
        Characteristic works:
          *Portrait of the Marchesa Luisa Casati* (1908, private collection) —
              the fullest expression of the dual-angle swirl technique.
          *Portrait of Madame Charles Max* (1896, Musée d'Orsay) —
              luminous warm flesh, near-black swirling background.
        """
        print(f"Boldini dual-angle swirl bravura pass  "
              f"(opacity={opacity:.2f}  primary={primary_angle:.0f}°  "
              f"secondary={secondary_angle:.0f}°  swirl_str={swirl_str:.3f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from scipy.ndimage import rotate as _rot

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Figure / background masks ────────────────────────────────────────
        if self._figure_mask is not None:
            fig_mask = _np.clip(self._figure_mask, 0.0, 1.0)
        else:
            fig_mask = _np.ones((H, W), dtype=_np.float32)
        bg_mask = _np.clip(1.0 - fig_mask, 0.0, 1.0)

        # ── Stage 1: Dual-angle diagonal swirl field ─────────────────────────
        # Boldini's signature: two competing diagonal stroke directions.
        # Base swirl mask: smooth cosine ramp above swirl_lo.
        swirl_raw = _np.clip((lum - swirl_lo) / (1.0 - swirl_lo + 1e-6), 0.0, 1.0)
        swirl_cos = 0.5 * (1.0 - _np.cos(_np.pi * swirl_raw))
        swirl_cos = _gf(swirl_cos.astype(_np.float32), sigma=blur_radius)
        swirl_cos = _np.clip(swirl_cos, 0.0, 1.0)

        def _aniso_streak(mask_2d, angle_deg):
            """Anisotropic Gaussian in direction angle_deg: long along, narrow across."""
            theta = float(angle_deg) % 180.0
            # Rotate so the desired direction becomes horizontal (axis-1)
            rotated = _rot(mask_2d, -theta, reshape=False, order=1, mode="nearest")
            # axis=0 = across (narrow), axis=1 = along (elongated)
            blurred = _gf(rotated, sigma=[blur_across, blur_along])
            # Rotate back
            result = _rot(blurred, theta, reshape=False, order=1, mode="nearest")
            return _np.clip(result, 0.0, 1.0)

        primary_streak   = _aniso_streak(swirl_cos, primary_angle)
        secondary_streak = _aniso_streak(swirl_cos, secondary_angle)

        # Combine: primary at full strength, secondary at half
        total_swirl = primary_streak + secondary_streak * 0.50
        # Clamp to avoid over-brightening
        total_swirl = _np.clip(total_swirl, 0.0, 1.0) * fig_mask

        # Apply warm ivory brightness along streak axes
        r_out = _np.clip(r_out + total_swirl * swirl_str,          0.0, 1.0)
        g_out = _np.clip(g_out + total_swirl * swirl_str * 0.65,   0.0, 1.0)
        b_out = _np.clip(b_out + total_swirl * swirl_str * 0.20,   0.0, 1.0)

        # ── Stage 2: Warm flesh luminosity lift ──────────────────────────────
        # Boldini's flesh tones are warm ivory-rose — warmer than Sargent.
        # Bell mask over the flesh luminosity zone.
        flesh_raw  = _np.clip(
            (lum - flesh_lo) / max(0.01, flesh_hi - flesh_lo), 0.0, 1.0
        ) * _np.clip(
            1.0 - (lum - flesh_hi) / max(0.01, 1.0 - flesh_hi), 0.0, 1.0
        ) * fig_mask
        flesh_mask = _gf(flesh_raw.astype(_np.float32), sigma=blur_radius)
        flesh_mask = _np.clip(flesh_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + flesh_mask * flesh_r, 0.0, 1.0)
        g_out = _np.clip(g_out + flesh_mask * flesh_g, 0.0, 1.0)
        b_out = _np.clip(b_out - flesh_mask * flesh_b, 0.0, 1.0)

        # ── Stage 3: Background darkening ────────────────────────────────────
        # Boldini's backgrounds: deep warm chestnut-umber, not pure neutral black.
        bg = _gf(bg_mask, sigma=blur_radius)
        bg = _np.clip(bg, 0.0, 1.0)

        r_out = r_out * (1.0 - bg) + (r_out * dark_factor + bg_warm_r) * bg
        g_out = g_out * (1.0 - bg) + (g_out * dark_factor) * bg
        b_out = b_out * (1.0 - bg) + (b_out * dark_factor) * bg
        r_out = _np.clip(r_out, 0.0, 1.0)
        g_out = _np.clip(g_out, 0.0, 1.0)
        b_out = _np.clip(b_out, 0.0, 1.0)

        # ── Composite at opacity ─────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Giovanni Boldini dual-angle swirl bravura pass complete.")

    # ─────────────────────────────────────────────────────────────────────────

    def annibale_carracci_tonal_reform_pass(
        self,
        light_angle_deg: float = 135.0,   # direction FROM which light comes (degrees; 0=right, 90=top, 135=upper-left)
        warm_r:          float = 0.022,   # R lift on lit face (warm amber)
        warm_g:          float = 0.010,   # G lift on lit face
        warm_b:          float = 0.014,   # B reduction on lit face (subtract — de-cool)
        cool_r:          float = 0.012,   # R reduction on shadow face (subtract — de-warm)
        cool_g:          float = 0.005,   # G lift on shadow face (very slight)
        cool_b:          float = 0.022,   # B lift on shadow face (blue-violet atmospheric shadow)
        penumbra_lo:     float = 0.22,    # luminance floor of temperature-shift zone
        penumbra_hi:     float = 0.72,    # luminance ceiling of temperature-shift zone
        shadow_hi:       float = 0.28,    # luminance ceiling of deep shadow (warm ground glow)
        shadow_warm_r:   float = 0.016,   # R lift in deep shadow (warm imprimatura glow)
        shadow_warm_g:   float = 0.007,   # G lift in deep shadow
        hi_lo:           float = 0.74,    # luminance floor of specular highlight zone
        hi_r:            float = 0.012,   # R lift in highlights (warm ivory)
        hi_g:            float = 0.006,   # G lift in highlights
        blur_radius:     float = 5.0,     # Gaussian sigma for all zone transitions
        opacity:         float = 0.32,
    ) -> None:
        """
        Annibale Carracci directional tonal temperature field — session 122 new artist pass.

        Annibale Carracci (1560–1609), co-founder of the Accademia degli Incamminati in Bologna
        with Agostino Carracci and Ludovico Carracci, led the most important reform of European
        painting since Raphael: the systematic rejection of late Mannerist artificiality in favour
        of direct observation of nature.  His paintings are warm, golden, physically grounded,
        and humanly immediate — and they trained the generation (Reni, Domenichino, Albani) that
        defined the Baroque.

        The defining technical feature of Bolognese naturalism is the *directional tonal
        temperature field*: lit surfaces facing the light source (typically upper-left) develop
        a warm amber-ochre colour temperature, while shadow faces develop a cool blue-violet tone
        from atmospheric and reflected-light influences.  This warm-light / cool-shadow contrast
        is physically motivated — it describes how a single warm point source simultaneously
        modulates luminance and colour temperature — and creates the internal luminosity that
        distinguishes Bolognese from both flat Venetian tonality and harsh Caravaggesque tenebrism.

        **Session 122 artistic improvement — Spatially-varying directional tonal temperature field**

        All previous temperature or colour-correction passes in this pipeline derive their masks
        purely from *luminance value*: if a pixel is bright, it receives one treatment; if dark,
        another.  This is a scalar approach.  The Carracci reform pass introduces a *vector*
        approach: the luminance gradient (computed via Sobel operators) provides directional
        information about which way luminance is rising or falling at each pixel.  The dot product
        between the normalised gradient direction and the light-source direction vector produces
        a signed temperature field in [-1, 1]:

          - Positive region (gradient points toward light): lit face — warm temperature shift.
          - Negative region (gradient points away from light): shadow face — cool shift.
          - Near-zero region (gradient perpendicular to light): penumbra — smooth transition.

        This directional field is restricted to the penumbra luminance zone where the temperature
        contrast is perceptually dominant (bright highlights and deep shadows are already
        colour-correct; only the mid-tone ramp benefits from the directional modulation).  The
        result is a spatially-aware, physically-motivated temperature correction that cannot be
        achieved by any luminance-only pass.

        Implementation:
        1. Compute luminance L from BGRA canvas.
        2. Sobel x-gradient (dL/dx) and y-gradient (dL/dy) → gradient vector at each pixel.
        3. Normalise gradient vector; handle zero-gradient pixels (set to 0).
        4. Compute light direction unit vector from light_angle_deg:
             lx = cos(angle_rad), ly = -sin(angle_rad)  [image y increases downward].
        5. dot = gradient_x * lx + gradient_y * ly  ∈ [-1, 1].
        6. warm_mask = clip(dot, 0, 1) * penumbra_bell_mask * figure_mask.
        7. cool_mask  = clip(-dot, 0, 1) * penumbra_bell_mask * figure_mask.
        8. Smooth both masks with Gaussian(sigma=blur_radius).
        9. Apply colour shifts:
             lit-face:    R += warm_mask * warm_r, G += warm_mask * warm_g, B -= warm_mask * warm_b
             shadow-face: R -= cool_mask * cool_r, G += cool_mask * cool_g, B += cool_mask * cool_b
        10. Warm shadow ground glow (lum < shadow_hi): R += shadow_warm_r, G += shadow_warm_g.
        11. Highlight ivory lift (lum > hi_lo): R += hi_r, G += hi_g.
        12. Composite at opacity.

        Parameters
        ----------
        light_angle_deg : direction from which light comes (degrees; 0=right, 90=top, 135=upper-left)
        warm_r/g/b      : colour temperature shifts for the lit face (b is subtracted — de-cool)
        cool_r/g/b      : colour temperature shifts for the shadow face (r is subtracted — de-warm)
        penumbra_lo     : luminance floor of the temperature-active zone
        penumbra_hi     : luminance ceiling of the temperature-active zone
        shadow_hi       : luminance ceiling of deep shadow zone (warm imprimatura glow)
        shadow_warm_r/g : warm amber lift in deep shadows (Carracci's sienna imprimatura glow)
        hi_lo           : luminance floor of specular highlight zone
        hi_r/g          : warm ivory lift in highlights (naturalistic warm peak)
        blur_radius     : Gaussian sigma for all zone and gradient transitions
        opacity         : global compositing weight (0 = no effect, 1 = full)

        Notes
        -----
        Characteristic works:
          *Farnese Gallery ceiling frescoes* (1597–1602, Palazzo Farnese, Rome) —
              the greatest decorative fresco cycle of the Baroque; warm, physically-grounded
              figures on a simulated architectural vault, every surface modelled with warm/cool
              temperature contrast.
          *Self-Portrait on an Easel in a Workshop* (c. 1604, Uffizi) —
              intimate naturalistic portrait; warm sienna imprimatura glowing through shadow glazes.
        """
        print(f"Annibale Carracci tonal reform pass  "
              f"(opacity={opacity:.2f}  light={light_angle_deg:.0f}°  "
              f"warm_r={warm_r:.3f}  cool_b={cool_b:.3f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from scipy.ndimage import sobel as _sobel

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Figure mask ───────────────────────────────────────────────────────
        if self._figure_mask is not None:
            fig_mask = _np.clip(self._figure_mask, 0.0, 1.0)
        else:
            fig_mask = _np.ones((H, W), dtype=_np.float32)

        # ── Stage 1: Directional tonal temperature field (session 122 improvement) ──
        # Sobel gradient of luminance → direction of luminance change
        lum_smooth = _gf(lum.astype(_np.float32), sigma=1.5)  # pre-smooth to reduce noise
        gx = _sobel(lum_smooth, axis=1).astype(_np.float32)   # dL/dx
        gy = _sobel(lum_smooth, axis=0).astype(_np.float32)   # dL/dy

        # Normalise gradient vector to unit length
        gnorm = _np.sqrt(gx * gx + gy * gy)
        safe  = gnorm > 1e-6
        gx_n  = _np.where(safe, gx / gnorm, 0.0)
        gy_n  = _np.where(safe, gy / gnorm, 0.0)

        # Light direction unit vector (image coords: x right, y downward)
        angle_rad = _np.deg2rad(float(light_angle_deg))
        lx = _np.cos(angle_rad)
        ly = -_np.sin(angle_rad)  # minus because image y increases downward

        # Signed dot product: +1 = gradient points toward light (lit face)
        #                      -1 = gradient points away from light (shadow face)
        dot = (gx_n * lx + gy_n * ly).astype(_np.float32)

        # Penumbra bell mask — temperature effects strongest in mid-tone zone
        t = _np.clip((lum - penumbra_lo) / max(0.01, penumbra_hi - penumbra_lo), 0.0, 1.0)
        penumbra_bell = (0.5 * (1.0 - _np.cos(_np.pi * t))).astype(_np.float32)
        # Fade out near the top of the penumbra range
        t_hi = _np.clip((lum - penumbra_hi) / max(0.01, 1.0 - penumbra_hi), 0.0, 1.0)
        penumbra_bell = penumbra_bell * (1.0 - t_hi)
        penumbra_bell = _np.clip(penumbra_bell, 0.0, 1.0)

        # Directed masks restricted to penumbra zone and figure
        warm_mask_raw = _np.clip(dot, 0.0, 1.0) * penumbra_bell * fig_mask
        cool_mask_raw = _np.clip(-dot, 0.0, 1.0) * penumbra_bell * fig_mask

        warm_mask = _gf(warm_mask_raw.astype(_np.float32), sigma=blur_radius)
        cool_mask = _gf(cool_mask_raw.astype(_np.float32), sigma=blur_radius)
        warm_mask = _np.clip(warm_mask, 0.0, 1.0)
        cool_mask = _np.clip(cool_mask, 0.0, 1.0)

        # Apply warm shift on lit face, cool shift on shadow face
        r_out = _np.clip(r_out + warm_mask * warm_r,  0.0, 1.0)
        g_out = _np.clip(g_out + warm_mask * warm_g,  0.0, 1.0)
        b_out = _np.clip(b_out - warm_mask * warm_b,  0.0, 1.0)  # subtract to de-cool

        r_out = _np.clip(r_out - cool_mask * cool_r,  0.0, 1.0)  # subtract to de-warm
        g_out = _np.clip(g_out + cool_mask * cool_g,  0.0, 1.0)
        b_out = _np.clip(b_out + cool_mask * cool_b,  0.0, 1.0)

        # ── Stage 2: Warm shadow ground glow ─────────────────────────────────
        # Carracci built on a warm sienna imprimatura that glows through shadow glazes.
        shadow_raw = _np.clip(1.0 - lum / max(0.01, shadow_hi), 0.0, 1.0) * fig_mask
        shadow_mask = _gf(shadow_raw.astype(_np.float32), sigma=blur_radius)
        shadow_mask = _np.clip(shadow_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + shadow_mask * shadow_warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + shadow_mask * shadow_warm_g, 0.0, 1.0)

        # ── Stage 3: Highlight ivory lift ────────────────────────────────────
        # Carracci's highlights are naturalistic warm ivory — not cold blue-white.
        hi_raw  = _np.clip((lum - hi_lo) / max(0.01, 1.0 - hi_lo), 0.0, 1.0) * fig_mask
        hi_mask = _gf(hi_raw.astype(_np.float32), sigma=blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + hi_mask * hi_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * hi_g, 0.0, 1.0)

        # ── Composite at opacity ─────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Annibale Carracci tonal reform pass complete.")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 123: Salvator Rosa — turbulent displacement field
    # ──────────────────────────────────────────────────────────────────────────

    def salvator_rosa_wild_bravura_pass(
        self,
        n_octaves:       int   = 4,        # number of Perlin-like noise octaves to sum
        max_disp:        float = 2.0,      # maximum pixel displacement magnitude
        shadow_hi:       float = 0.30,     # luminance ceiling of deep shadow zone
        shadow_warm_r:   float = 0.018,    # warm raw umber lift in deep shadows
        shadow_warm_g:   float = 0.008,    # warm raw umber lift in deep shadows (green)
        vignette_str:    float = 0.12,     # dark atmospheric vignette strength at border
        vignette_sigma:  float = 0.35,     # vignette radial falloff (fraction of diagonal)
        blur_radius:     float = 4.0,      # Gaussian sigma for smooth zone transitions
        opacity:         float = 0.26,
    ) -> None:
        """
        Salvator Rosa turbulent displacement field — session 123 new artist pass.

        Salvator Rosa (1615–1673), the most deliberately unconventional personality in
        17th-century European art, painted wilderness landscapes of storm-charged grandeur
        and allegories of brooding philosophical melancholy.  His technique is defined by
        *gestural turbulence*: broad, energetic, direction-less brushstrokes that leave the
        painted surface in perpetual visual motion — as if a storm were passing through the
        canvas itself.  His near-black raw umber grounds let the darkness be the canvas
        showing through thin, transparent paint, with only the focal areas of warm amber
        light receiving opaque, loaded impasto.

        **Session 123 artistic improvement — Multi-scale turbulent displacement field**

        All previous passes in this pipeline operate by modifying pixel *colour values*
        in place: additive blends, temperature shifts, luminance lifts, gradient dot products.
        This pass introduces a fundamentally different operation: spatial *image warping*
        via a stochastic multi-scale displacement field.

        A displacement field (dx, dy) is generated by summing N_OCTAVES octaves of
        Gaussian-filtered white noise, each at doubling spatial scale, following a 1/f
        pink-noise power spectrum (octave n weighted by 1/(n+1)).  The summed scalar field
        is converted into two orthogonal displacement components by treating the field value
        as a potential: dx is the horizontal gradient of the smoothed field, dy is the
        vertical gradient.  These components are scaled to max_disp pixels and used to warp
        the canvas via scipy.ndimage.map_coordinates (bicubic interpolation).

        This warp is subtle at max_disp ≈ 1.5–2.5 px — below the threshold of obvious
        distortion but above the threshold of perceptual smoothness.  The result is a
        canvas that feels energetically unstable, as if the paint were being pushed by
        invisible gestural forces.  Unlike any previous pass, it is the *spatial arrangement*
        of paint that changes, not merely its colour.

        Implementation:
        1. Generate N_OCTAVES random noise fields at base_sigma * 2^octave spatial scales.
        2. Sum with 1/(octave+1) weighting → single scalar turbulence field T.
        3. Normalise T to [-1, 1].
        4. Compute dx = horizontal gradient of T; dy = vertical gradient of T.
        5. Scale to max_disp pixels.
        6. Build sampling coordinate grids: xs = x_grid + dx, ys = y_grid + dy.
        7. Warp all three colour channels via map_coordinates (order=1, mode='reflect').
        8. Warm shadow glow: in pixels where luminance < shadow_hi, lift R and G by
           shadow_warm_r/g (raw umber warmth of the dark canvas ground showing through).
        9. Dark vignette: compute radial mask from image centre; multiply border by
           (1 - vignette_str) to press atmospheric darkness inward from all edges.
        10. Composite warped+adjusted canvas with original at opacity.

        Parameters
        ----------
        n_octaves       : number of pink-noise octaves (more = richer turbulence texture)
        max_disp        : maximum pixel displacement (keep ≤ 3.0 to avoid obvious distortion)
        shadow_hi       : luminance ceiling for the warm shadow glow zone
        shadow_warm_r/g : raw umber lift in shadow zone (warm dark canvas ground)
        vignette_str    : darkness multiplier added at border (0 = no vignette, 1 = black)
        vignette_sigma  : width of the vignette falloff as fraction of the image diagonal
        blur_radius     : Gaussian sigma for smooth zone transitions (shadow, vignette)
        opacity         : global compositing weight

        Notes
        -----
        Characteristic works:
          *L'Umana Fragilità* (c. 1656, Fitzwilliam Museum) —
              allegorical figure of Time writing on a tablet held by an infant Cupid;
              turbulent atmospheric darkness presses in from all edges.
          *Self-Portrait as Democritus* (c. 1651–1655, Statens Museum for Kunst) —
              brooding self-presentation as the laughing philosopher; stormy natural
              setting; gestural background dissolves into near-black umber void.
          *Landscape with Soldiers and Hunters* (c. 1670, Uffizi) —
              the archetype of Rosa's wild landscape: fractured rock, storm-twisted trees,
              armed figures dwarfed by the chiaroscuro wilderness.
        """
        print(f"Salvator Rosa turbulent displacement pass  "
              f"(opacity={opacity:.2f}  max_disp={max_disp:.1f}px  "
              f"n_octaves={n_octaves}  vignette={vignette_str:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from scipy.ndimage import map_coordinates as _mc

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Stage 1: Turbulent displacement field (session 123 improvement) ──
        # Sum N_OCTAVES octaves of Gaussian-filtered noise with 1/f weighting.
        rng = _np.random.default_rng(seed=123)
        turb = _np.zeros((H, W), dtype=_np.float32)
        base_sigma = 2.0
        total_weight = 0.0
        for octave in range(n_octaves):
            weight = 1.0 / (octave + 1)
            sigma  = base_sigma * (2 ** octave)
            noise  = rng.standard_normal((H, W)).astype(_np.float32)
            smooth = _gf(noise, sigma=sigma)
            turb  += smooth * weight
            total_weight += weight

        # Normalise field to [-1, 1]
        turb /= max(total_weight, 1e-6)
        t_max = _np.abs(turb).max()
        if t_max > 1e-6:
            turb /= t_max

        # Derive orthogonal displacement components from the turbulence field.
        # dx from horizontal gradient; dy from vertical gradient.
        dx = _np.gradient(turb, axis=1).astype(_np.float32)
        dy = _np.gradient(turb, axis=0).astype(_np.float32)

        # Normalise component magnitudes and scale to max_disp pixels.
        d_max = max(_np.abs(dx).max(), _np.abs(dy).max(), 1e-6)
        dx = (dx / d_max) * float(max_disp)
        dy = (dy / d_max) * float(max_disp)

        # Build warped sampling grids.
        y_grid, x_grid = _np.mgrid[0:H, 0:W].astype(_np.float32)
        xs = _np.clip(x_grid + dx, 0, W - 1)
        ys = _np.clip(y_grid + dy, 0, H - 1)
        coords = _np.array([ys.ravel(), xs.ravel()])

        # Warp each colour channel independently.
        r_out = _mc(r0, coords, order=1, mode='reflect').reshape(H, W).astype(_np.float32)
        g_out = _mc(g0, coords, order=1, mode='reflect').reshape(H, W).astype(_np.float32)
        b_out = _mc(b0, coords, order=1, mode='reflect').reshape(H, W).astype(_np.float32)
        r_out = _np.clip(r_out, 0.0, 1.0)
        g_out = _np.clip(g_out, 0.0, 1.0)
        b_out = _np.clip(b_out, 0.0, 1.0)

        # ── Stage 2: Warm shadow glow ─────────────────────────────────────────
        # The near-black umber canvas ground glows warmly through thin shadow glazes.
        shadow_raw  = _np.clip(1.0 - lum / max(0.01, shadow_hi), 0.0, 1.0)
        shadow_mask = _gf(shadow_raw.astype(_np.float32), sigma=blur_radius)
        shadow_mask = _np.clip(shadow_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + shadow_mask * shadow_warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + shadow_mask * shadow_warm_g, 0.0, 1.0)

        # ── Stage 3: Dark atmospheric vignette ───────────────────────────────
        # Rosa's characteristic storm-charged darkness pressing in from all edges.
        cy, cx = H / 2.0, W / 2.0
        diag   = _np.sqrt(float(W) ** 2 + float(H) ** 2)
        sigma_px = vignette_sigma * diag
        y_idx, x_idx = _np.ogrid[0:H, 0:W]
        dist = _np.sqrt((x_idx - cx) ** 2 + (y_idx - cy) ** 2).astype(_np.float32)
        # Radial distance normalised by half-diagonal → 0 at centre, ≥1 at corners
        dist_norm = dist / (diag / 2.0)
        # Vignette weight: 0 at centre (no effect), 1 at corners (full darkening)
        vig_weight = _np.clip(dist_norm ** 2, 0.0, 1.0)
        vig_mask   = _gf(vig_weight.astype(_np.float32), sigma=sigma_px * 0.3)
        vig_mask   = _np.clip(vig_mask, 0.0, 1.0)

        darken = 1.0 - vig_mask * vignette_str
        r_out  = _np.clip(r_out * darken, 0.0, 1.0)
        g_out  = _np.clip(g_out * darken, 0.0, 1.0)
        b_out  = _np.clip(b_out * darken, 0.0, 1.0)

        # ── Composite at opacity ─────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Salvator Rosa turbulent displacement pass complete.")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 124: Massimo Stanzione — Neapolitan Baroque Classicism
    # ──────────────────────────────────────────────────────────────────────────

    def stanzione_noble_repose_pass(
        self,
        pyramid_levels:      int   = 4,     # number of frequency bands in Laplacian pyramid
        mid_freq_boost:      float = 0.10,  # contrast boost applied to L1 (mid-frequency band)
        fine_suppress:       float = 0.08,  # contrast suppression of L0 (finest noise band)
        hi_lo:               float = 0.70,  # luminance threshold for highlight zone
        ivory_r:             float = 0.014, # warm ivory lift in highlights (R channel)
        ivory_g:             float = 0.008, # warm ivory lift in highlights (G channel)
        penumbra_lo:         float = 0.24,  # luminance floor of cool violet shadow zone
        penumbra_hi:         float = 0.56,  # luminance ceiling of cool violet shadow zone
        violet_b:            float = 0.018, # cool violet lift in shadow penumbra (B channel)
        violet_r:            float = 0.009, # cool violet damp in shadow penumbra (R channel)
        blur_radius:         float = 4.0,   # Gaussian sigma for smooth zone transitions
        opacity:             float = 0.30,
    ) -> None:
        """
        Massimo Stanzione noble repose pass — session 124 new artist pass.

        Massimo Stanzione (c. 1585–1656), "il Cavalier Calabrese," was the dominant
        master of Neapolitan Baroque painting between the raw tenebrism of Caravaggio
        and the luminous classicism of Guido Reni.  His flesh tones are the defining
        achievement of his career: warm golden-ivory in the light, cooling through a
        lavender-violet penumbra into a deep amber shadow that glows rather than darkens.
        Sometimes called "the Neapolitan Guido Reni," Stanzione grafted Bolognese
        academic smoothness onto Neapolitan warmth and shadow depth.

        **Session 124 artistic improvement — Laplacian pyramid multi-scale clarity**

        All previous passes in this pipeline operate in one of two modes:
        colour-space transforms (additive RGB blends, temperature shifts, luminance lifts)
        or spatial-domain transforms (image warping via displacement fields, session 123).
        This pass introduces a third, entirely new mode: *frequency-band decomposition*
        via a stationary Laplacian pyramid.

        The canvas is decomposed into four additive frequency bands:
          L0 = original − Gauss(σ=2)         finest detail (~2 px scale)
          L1 = Gauss(σ=2) − Gauss(σ=4)       mid-frequency structural form (~4 px)
          L2 = Gauss(σ=4) − Gauss(σ=8)       coarse tonal planes (~8 px)
          L3 = Gauss(σ=8)                     global tonal base

        The pipeline then selectively adjusts contrast within each band:
          L1 *= (1 + mid_freq_boost)   → boosts mid-frequency form clarity
          L0 *= (1 − fine_suppress)    → suppresses finest noise for surface smoothness

        Reconstruction: canvas = L0' + L1' + L2 + L3 (applied per channel).

        This replicates the perceptual effect of Bolognese academic glazing — carefully
        built-up transparent layers that enhance mid-spatial-frequency facial structure
        (forehead planes, cheekbone volumes, chin form) while smoothing out the finest
        grain artifacts that accumulate across many painting passes.  The result is
        increased apparent clarity and structural presence at the middle scale without
        sharpening noise or disturbing global tonality.

        Implementation:
        1. Read current canvas as float32 R, G, B.
        2. Per channel, compute Gaussian pyramid: G0=orig, G1=Gauss(σ=2), G2=Gauss(σ=4),
           G3=Gauss(σ=8).
        3. Derive Laplacian bands: L0=G0−G1, L1=G1−G2, L2=G2−G3, L3=G3.
        4. Apply per-band scaling: L0 *= (1 − fine_suppress); L1 *= (1 + mid_freq_boost).
        5. Reconstruct: out = L0' + L1' + L2 + L3, clipped to [0, 1].
        6. Warm ivory highlight lift: pixels where lum > hi_lo receive +ivory_r/+ivory_g.
        7. Cool violet penumbra: pixels where penumbra_lo < lum < penumbra_hi receive
           +violet_b (blue lift) and −violet_r (red damp) — Stanzione's Caravaggist shadow
           depth softened by Reni's cool classicist reflected light.
        8. Composite at opacity.

        Parameters
        ----------
        pyramid_levels   : number of pyramid levels (L0..L{N-1}, L{N} = base)
        mid_freq_boost   : contrast multiplier increase for L1 (mid-frequency structural band)
        fine_suppress    : contrast multiplier decrease for L0 (finest noise band)
        hi_lo            : luminance threshold above which warm ivory lift applies
        ivory_r/g        : warm ivory channel offsets for highlight zone
        penumbra_lo/hi   : luminance range for cool violet shadow penumbra zone
        violet_b/r       : blue lift and red damp in shadow penumbra
        blur_radius      : Gaussian sigma for smooth zone-boundary transitions
        opacity          : global compositing weight

        Notes
        -----
        Characteristic works:
          *Judith with the Head of Holofernes* (Prado, c. 1630s) —
              most psychologically composed Judith of the era; ivory flesh, composed gaze.
          *Pietà* (Prado, c. 1637) —
              Reni-derived luminous grief; warm golden flesh against cool atmospheric shadow.
          *Baptism of Christ* (S. Giovanni dei Fiorentini, Naples, c. 1635) —
              monumental devotional clarity; classicist form with Neapolitan warmth.
        """
        print(f"Massimo Stanzione noble repose pass  "
              f"(opacity={opacity:.2f}  pyramid_levels={pyramid_levels}  "
              f"mid_freq_boost={mid_freq_boost:.2f}  fine_suppress={fine_suppress:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Stage 1: Laplacian pyramid multi-scale clarity (session 124 improvement) ──
        # Stationary Laplacian pyramid — all bands at full resolution.
        # sigma values: 2.0, 4.0, 8.0 px for 4-level pyramid.
        def _pyramid_enhance(ch):
            """Apply Laplacian pyramid enhancement to a single channel (float32 2-D)."""
            sigmas = [2.0 * (2 ** k) for k in range(pyramid_levels - 1)]
            # Build Gaussian pyramid levels.
            gauss = [ch]
            for s in sigmas:
                gauss.append(_gf(ch, sigma=s))
            # Derive Laplacian bands (stationary: all at original resolution).
            bands = []
            for i in range(len(gauss) - 1):
                bands.append(gauss[i] - gauss[i + 1])
            bands.append(gauss[-1])   # coarsest band = final Gaussian level
            # Apply per-band scaling.
            bands[0] = bands[0] * (1.0 - fine_suppress)       # suppress finest noise
            if len(bands) > 1:
                bands[1] = bands[1] * (1.0 + mid_freq_boost)  # boost mid-frequency form
            # Reconstruct.
            return _np.clip(sum(bands), 0.0, 1.0)

        r_out = _pyramid_enhance(r0)
        g_out = _pyramid_enhance(g0)
        b_out = _pyramid_enhance(b0)

        # ── Stage 2: Warm ivory highlight lift ────────────────────────────────
        # Stanzione's lights are Reni-derived: warm golden-ivory, not cool pearl.
        hi_raw    = _np.clip((lum - hi_lo) / max(0.01, 1.0 - hi_lo), 0.0, 1.0)
        hi_mask   = _gf(hi_raw.astype(_np.float32), sigma=blur_radius)
        hi_mask   = _np.clip(hi_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + hi_mask * ivory_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * ivory_g, 0.0, 1.0)

        # ── Stage 3: Cool violet shadow penumbra ──────────────────────────────
        # Caravaggist shadow depth softened by Reni's cool reflected-light classicism.
        span    = max(0.01, penumbra_hi - penumbra_lo)
        pen_raw = _np.clip(1.0 - _np.abs(lum - 0.5 * (penumbra_lo + penumbra_hi))
                           / (0.5 * span), 0.0, 1.0)
        pen_mask = _gf(pen_raw.astype(_np.float32), sigma=blur_radius)
        pen_mask = _np.clip(pen_mask, 0.0, 1.0)

        b_out = _np.clip(b_out + pen_mask * violet_b, 0.0, 1.0)
        r_out = _np.clip(r_out - pen_mask * violet_r, 0.0, 1.0)

        # ── Composite at opacity ─────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Massimo Stanzione noble repose pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 125 — Francesco Albani + BOLOGNESE_ARCADIAN_CLASSICISM
    # ─────────────────────────────────────────────────────────────────────────

    def chromatic_aerial_perspective_pass(
        self,
        *,
        sky_fraction:    float = 0.55,
        cool_r:          float = 0.64,
        cool_g:          float = 0.72,
        cool_b:          float = 0.85,
        haze_strength:   float = 0.18,
        desat_strength:  float = 0.22,
        haze_lift:       float = 0.06,
        gamma:           float = 1.20,
        blur_radius:     float = 12.0,
        opacity:         float = 1.0,
    ) -> None:
        """
        Chromatic aerial perspective — session 125 artistic improvement.

        Applies a vertical gradient of progressive blue-grey cooling and saturation
        reduction from the lower foreground to the upper atmospheric distance,
        modeling the physical scattering of short-wavelength (blue) light by
        intervening atmosphere along long sight lines.

        This is the foundation of classical landscape depth: Leonardo's sfumato
        dell'aria, Albani's pastoral sky-fill, Claude Lorrain's golden-horizon
        contre-jour — all depend on this physical atmospheric reality.

        Mathematically distinct from the directional tonal temperature field (s122),
        which operates on per-pixel luminance lookup tables.  This pass operates on
        a 2D spatial gradient: the atmospheric depth weight increases from bottom
        (foreground, warm, saturated) to top (distant, cool, desaturated), creating
        the illusion of recession through chromatic attenuation rather than through
        tonal darkening alone.

        Parameters
        ----------
        sky_fraction   : fraction of image height that receives maximum aerial cooling
                         (measured from the top); defaults to upper 55%
        cool_r/g/b     : RGB components of the atmospheric haze colour
                         (default: cool blue-grey, pale sky tone)
        haze_strength  : blend weight toward atmospheric haze colour at maximum depth
        desat_strength : desaturation strength at maximum depth (0 = none, 1 = greyscale)
        haze_lift      : luminance brightening at maximum depth (atmospheric veiling)
        gamma          : gradient shaping exponent (>1 = gradual onset; <1 = abrupt)
        blur_radius    : Gaussian sigma to smooth the gradient edge transition
        opacity        : global compositing weight

        Notes
        -----
        Key applications:
          Leonardo da Vinci — Mona Lisa background mountains fade to pale blue-grey
          Francesco Albani — pastoral Arcadian skies fill shadows with cool blue air
          Claude Lorrain — golden horizons against hazy blue-grey atmospheric distance
          Caspar David Friedrich — receding mountain ridges dissolve into atmospheric blue
        """
        print(f"Chromatic aerial perspective pass  "
              f"(opacity={opacity:.2f}  sky_fraction={sky_fraction:.2f}  "
              f"haze_strength={haze_strength:.2f}  desat_strength={desat_strength:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Build vertical depth-weight map ───────────────────────────────────
        # weight = 1 at top (y=0, atmospheric distance), 0 at bottom (y=H, foreground).
        # sky_fraction controls how far down the maximum aerial effect extends.
        ys = _np.linspace(1.0, 0.0, H, dtype=_np.float32)    # top=1, bottom=0
        # Scale so that ys[y] > sky_fraction clips to ~1, below ramps to 0
        raw_weight = _np.clip(ys / max(sky_fraction, 0.01), 0.0, 1.0) ** gamma
        # Broadcast to (H, W)
        weight_2d  = _np.tile(raw_weight[:, _np.newaxis], (1, W))
        # Smooth the gradient edge softly
        weight_2d  = _gf(weight_2d.astype(_np.float32), sigma=blur_radius)
        weight_2d  = _np.clip(weight_2d, 0.0, 1.0)

        # ── Stage 1: Chromatic haze blend ─────────────────────────────────────
        # Blend canvas pixels toward the atmospheric cool colour weighted by depth.
        w_haze = weight_2d * haze_strength
        r_out = r0 * (1.0 - w_haze) + cool_r * w_haze
        g_out = g0 * (1.0 - w_haze) + cool_g * w_haze
        b_out = b0 * (1.0 - w_haze) + cool_b * w_haze

        # ── Stage 2: Desaturation with depth ─────────────────────────────────
        # Convert to greyscale luma and lerp toward it, reducing chromatic saturation.
        lum_out = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
        w_desat = weight_2d * desat_strength
        r_out = r_out * (1.0 - w_desat) + lum_out * w_desat
        g_out = g_out * (1.0 - w_desat) + lum_out * w_desat
        b_out = b_out * (1.0 - w_desat) + lum_out * w_desat

        # ── Stage 3: Atmospheric veiling lift ────────────────────────────────
        # Distant objects appear slightly lighter due to atmospheric scattering.
        w_lift = weight_2d * haze_lift
        r_out = _np.clip(r_out + w_lift, 0.0, 1.0)
        g_out = _np.clip(g_out + w_lift, 0.0, 1.0)
        b_out = _np.clip(b_out + w_lift, 0.0, 1.0)

        # ── Composite at opacity ─────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Chromatic aerial perspective pass complete.")

    def albani_arcadian_grace_pass(
        self,
        *,
        bloom_lo:        float = 0.42,
        bloom_hi:        float = 0.78,
        peach_r:         float = 0.045,
        peach_g:         float = 0.018,
        sky_lo:          float = 0.12,
        sky_hi:          float = 0.40,
        sky_b:           float = 0.048,
        sky_r:           float = 0.018,
        ambient_lift:    float = 0.012,
        blur_radius:     float = 5.0,
        opacity:         float = 1.0,
    ) -> None:
        """
        Francesco Albani arcadian grace pass — session 125.

        Encodes Albani's Bolognese Arcadian Classicism in three stages:

        (1) Rose-peach skin bloom — in mid-tone zones (bloom_lo..bloom_hi),
        add a delicate rose-peach warmth.  Albani's flesh tones are the
        sweetest in Bolognese painting: lighter and more peach than Reni's
        cool pearl, warmer and rosier than Stanzione's Mediterranean gold,
        with a pastoral innocence that reads as idealized outdoor sunlight
        on young, smooth skin.

        (2) Cool sky-reflected shadow — in the shadow zone (sky_lo..sky_hi),
        add a delicate cool blue-lavender tint.  Albani's outdoor pastoral
        figures catch ambient sky light in their shadows — the cool blue-grey
        reflected from open sky replaces the warm amber of interior candlelight
        with the airy luminosity of Arcadian outdoors.

        (3) Pearl ambient lift — a very gentle global luminance lift that
        gives Albani's pictures their characteristic pearlescent airiness:
        nothing is truly dark; even shadows have a soft glow as if the entire
        scene breathes in open sunlit air.

        Parameters
        ----------
        bloom_lo/hi    : luminance range for rose-peach skin bloom zone
        peach_r/g      : red and green channel offsets for rose-peach bloom
        sky_lo/hi      : luminance range for cool sky-reflected shadow zone
        sky_b/r        : blue lift and red damp in shadow zone
        ambient_lift   : uniform luminance lift for pearlescent airiness
        blur_radius    : Gaussian sigma to smooth zone boundary transitions
        opacity        : global compositing weight

        Notes
        -----
        Characteristic works:
          *The Four Seasons (Albani Tondi)* (Galleria Borghese, c. 1616–1617) —
              putti and goddesses in soft Arcadian light; Bolognese pearl skin.
          *Diana and Actaeon* (c. 1617) —
              cool sky-shadow on nymph figures beside a forest pool.
          *Venus with Putti* (Pinacoteca di Bologna, c. 1621) —
              sweetest rose-peach flesh quality in all Bolognese Baroque.
        """
        print(f"Francesco Albani arcadian grace pass  "
              f"(opacity={opacity:.2f}  peach_r={peach_r:.3f}  "
              f"sky_b={sky_b:.3f}  ambient_lift={ambient_lift:.3f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Stage 1: Rose-peach skin bloom ────────────────────────────────────
        # Albani's mid-tone flesh — sweet pastoral peach warmth in mid-tones.
        bloom_span  = max(0.01, bloom_hi - bloom_lo)
        bloom_raw   = _np.clip(1.0 - _np.abs(lum - 0.5 * (bloom_lo + bloom_hi))
                               / (0.5 * bloom_span), 0.0, 1.0)
        bloom_mask  = _gf(bloom_raw.astype(_np.float32), sigma=blur_radius)
        bloom_mask  = _np.clip(bloom_mask, 0.0, 1.0)

        r_out = r0 + bloom_mask * peach_r
        g_out = g0 + bloom_mask * peach_g

        # ── Stage 2: Cool sky-reflected shadow ────────────────────────────────
        # Outdoor pastoral shadows take on the cool blue-grey of open sky light.
        sky_span    = max(0.01, sky_hi - sky_lo)
        sky_raw     = _np.clip(1.0 - _np.abs(lum - 0.5 * (sky_lo + sky_hi))
                               / (0.5 * sky_span), 0.0, 1.0)
        sky_mask    = _gf(sky_raw.astype(_np.float32), sigma=blur_radius)
        sky_mask    = _np.clip(sky_mask, 0.0, 1.0)

        b_out = b0 + sky_mask * sky_b
        r_out = r_out - sky_mask * sky_r

        # ── Stage 3: Pearl ambient lift ───────────────────────────────────────
        # Albani's pictures have a pearlescent airiness — a soft global lift
        # that prevents any region from becoming truly dark or heavy.
        r_out = _np.clip(r_out + ambient_lift, 0.0, 1.0)
        g_out = _np.clip(g_out + ambient_lift, 0.0, 1.0)
        b_out = _np.clip(b_out + ambient_lift, 0.0, 1.0)

        # ── Composite at opacity ─────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Francesco Albani arcadian grace pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 126 — Fra Bartolommeo + FLORENTINE_MONUMENTAL_CLASSICISM
    # ─────────────────────────────────────────────────────────────────────────

    def fra_bartolommeo_velo_shadow_pass(
        self,
        *,
        gradient_sigma:   float = 2.0,    # Gaussian pre-blur sigma before Sobel
        edge_threshold:   float = 0.03,   # minimum Sobel magnitude to activate modulation
        lit_warmth_r:     float = 0.018,  # warm R lift on lit side of form ridges
        lit_warmth_g:     float = 0.007,  # warm G lift on lit side of form ridges
        shadow_cool_b:    float = 0.020,  # cool B deepening on shadow side of ridges
        shadow_cool_r:    float = 0.008,  # R damp on shadow side of ridges
        mid_lo:           float = 0.25,   # lower luminance bound of penumbra zone
        mid_hi:           float = 0.70,   # upper luminance bound of penumbra zone
        saturation_boost: float = 0.04,   # mild saturation boost in mid-zone (Bartolommeo's rich colour)
        blur_radius:      float = 4.0,    # Gaussian sigma for mask edge smoothing
        opacity:          float = 1.0,
    ) -> None:
        """
        Fra Bartolommeo velo shadow pass — session 126.

        Fra Bartolommeo (1472–1517) pioneered the use of a 'velo' (sheer cloth veil)
        draped over posed models to systematically study how light and shadow travel
        across three-dimensional forms.  Where the veil stretched taut over a
        protruding ridge (brow bone, cheekbone, nose bridge, shoulder), it caught
        the light at a sharply-defined boundary; where it fell into shadow in the
        concave recesses, the shadow deepened with a precise, volumetrically
        committed gradient.

        This pass encodes that velo observation in three computational stages using
        the SESSION 126 ARTISTIC IMPROVEMENT: Sobel-gradient-driven form boundary
        modulation.  This is the fourth distinct processing mode in this pipeline:

          s123 Rosa   — spatial displacement (image warping via turbulent flow)
          s124 Stanzione — frequency-band decomposition (Laplacian pyramid)
          s125 Albani — vertical spatial gradient (chromatic aerial perspective)
          s126 Bartolommeo — EDGE-MAP-DRIVEN selective modulation (Sobel gradient)

        Unlike Laplacian pyramid decomposition (s124), which separates globally by
        spatial frequency across the entire canvas, Sobel-gradient detection finds the
        precise tonal boundary LOCATIONS where light-to-shadow transitions occur.
        The resulting edge mask is then used to apply warm/cool thermal contrast
        selectively at detected form ridges — not uniformly, not frequency-banded,
        but spatially anchored to where the painting's three-dimensional forms
        actually turn away from the light.

        Three stages:
        (1) Sobel edge detection — pre-smooth luminance (gradient_sigma), compute
            Sobel magnitude sqrt(Gx²+Gy²), normalize to [0,1].  Pixels below
            edge_threshold receive near-zero edge weight.
        (2) Lit-side warm lift — where luminance > penumbra midpoint AND edge weight
            is significant: R += lit_warmth_r, G += lit_warmth_g.  Fra Bartolommeo's
            lit form-ridges read as warm amber-ivory crests against shadowed troughs.
        (3) Shadow-side cool deepening — where luminance < penumbra midpoint AND edge
            weight is significant: B += shadow_cool_b, R -= shadow_cool_r.  The velo's
            shadow troughs have a precisely-bounded cool quality, giving forms volumetric
            weight without Leonardo's smoky dissolution.
        (4) Mild saturation boost across the mid-zone (saturation_boost) — Fra
            Bartolommeo's palette is rich and warm-saturated throughout; this stage
            prevents the cumulative passes from greying out the mid-tones.

        Parameters
        ----------
        gradient_sigma   : Gaussian pre-blur sigma applied to luminance before Sobel
        edge_threshold   : minimum normalised Sobel magnitude to participate in modulation
        lit_warmth_r/g   : warm channel offsets on lit side of detected form ridges
        shadow_cool_b/r  : blue lift and red damp on shadow side of detected ridges
        mid_lo / mid_hi  : luminance range of the penumbra zone to modulate
        saturation_boost : strength of mid-tone saturation recovery
        blur_radius      : Gaussian sigma to smooth zone boundary transitions
        opacity          : global compositing weight

        Notes
        -----
        Characteristic works encoding the velo technique:
          *Mystical Marriage of St. Catherine* (Uffizi, 1511) —
              monumental architectural figures; velo-derived shadow precision on drapery.
          *God the Father with Saints* (c. 1509) —
              deep chiaroscuro with warm-lit ridges and cool shadow troughs.
          *Salvator Mundi* (c. 1516) —
              luminous warm flesh against deep devotional shadow; the velo boundary visible
              on the brow, nose, and chin forms.
        """
        print(f"Fra Bartolommeo velo shadow pass  "
              f"(opacity={opacity:.2f}  gradient_sigma={gradient_sigma:.1f}  "
              f"edge_threshold={edge_threshold:.3f}  lit_warmth_r={lit_warmth_r:.3f}  "
              f"shadow_cool_b={shadow_cool_b:.3f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from scipy.ndimage import sobel as _sobel

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Stage 1: Sobel-gradient form-ridge detection ──────────────────────
        # Pre-smooth luminance to reduce noise amplification in the gradient.
        lum_smooth = _gf(lum.astype(_np.float32), sigma=gradient_sigma)
        # Compute Sobel gradient components (axis=1 = horizontal, axis=0 = vertical).
        gx = _sobel(lum_smooth, axis=1)
        gy = _sobel(lum_smooth, axis=0)
        grad_mag = _np.sqrt(gx * gx + gy * gy)
        # Normalise gradient magnitude to [0, 1] for threshold application.
        g_max = grad_mag.max()
        if g_max > 1e-9:
            grad_norm = grad_mag / g_max
        else:
            grad_norm = grad_mag
        # Edge weight: zero below threshold, linear above.
        edge_weight = _np.clip((grad_norm - edge_threshold) / max(0.01, 1.0 - edge_threshold),
                               0.0, 1.0)
        edge_weight = _gf(edge_weight.astype(_np.float32), sigma=blur_radius)
        edge_weight = _np.clip(edge_weight, 0.0, 1.0)

        # ── Penumbra zone mask (mid_lo .. mid_hi) ─────────────────────────────
        mid_span = max(0.01, mid_hi - mid_lo)
        pen_raw  = _np.clip(1.0 - _np.abs(lum - 0.5 * (mid_lo + mid_hi))
                            / (0.5 * mid_span), 0.0, 1.0)
        pen_mask = _gf(pen_raw.astype(_np.float32), sigma=blur_radius)
        pen_mask = _np.clip(pen_mask, 0.0, 1.0)

        # Combined gate: only activate where both form ridge AND penumbra overlap.
        gate = edge_weight * pen_mask

        # ── Stage 2: Lit-side warm lift ────────────────────────────────────────
        # Pixels with lum > penumbra midpoint are on the lit side of the form ridge.
        mid_point   = 0.5 * (mid_lo + mid_hi)
        lit_frac    = _np.clip((lum - mid_point) / max(0.01, mid_hi - mid_point), 0.0, 1.0)
        lit_mask    = gate * lit_frac

        r_out = r0 + lit_mask * lit_warmth_r
        g_out = g0 + lit_mask * lit_warmth_g
        b_out = b0.copy()

        # ── Stage 3: Shadow-side cool deepening ───────────────────────────────
        # Pixels with lum < penumbra midpoint are on the shadow side of the ridge.
        shd_frac    = _np.clip((mid_point - lum) / max(0.01, mid_point - mid_lo), 0.0, 1.0)
        shd_mask    = gate * shd_frac

        b_out = _np.clip(b_out + shd_mask * shadow_cool_b, 0.0, 1.0)
        r_out = _np.clip(r_out - shd_mask * shadow_cool_r, 0.0, 1.0)

        # ── Stage 4: Mild mid-tone saturation boost ───────────────────────────
        # Fra Bartolommeo's palette is richly saturated; recover any grey-out from
        # cumulative passes by pushing mid-zone channels away from their luma value.
        if saturation_boost > 0.0:
            lum_out = 0.299 * r_out + 0.587 * g_out + 0.114 * b_out
            r_out = _np.clip(r_out + pen_mask * (r_out - lum_out) * saturation_boost, 0.0, 1.0)
            g_out = _np.clip(g_out + pen_mask * (g_out - lum_out) * saturation_boost, 0.0, 1.0)
            b_out = _np.clip(b_out + pen_mask * (b_out - lum_out) * saturation_boost, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Fra Bartolommeo velo shadow pass complete.")

    def cantarini_pearl_fog_pass(
        self,
        *,
        penumbra_lo:     float = 0.32,   # lower luminance bound of penumbra zone
        penumbra_hi:     float = 0.72,   # upper luminance bound of penumbra zone
        sigma_r:         float = 1.2,    # Gaussian blur sigma for red channel (long wavelength — least scatter)
        sigma_g:         float = 2.0,    # Gaussian blur sigma for green channel (mid wavelength)
        sigma_b:         float = 3.5,    # Gaussian blur sigma for blue channel (short wavelength — most scatter)
        scatter_strength: float = 0.55,  # how much the blurred channels replace the originals in penumbra
        rose_hi_lo:      float = 0.70,   # luminance threshold for rose highlight lift
        rose_r:          float = 0.012,  # rose-pink R lift in highlights (Cantarini's warm carnations)
        rose_b_damp:     float = 0.005,  # slight B damp to keep rose warm rather than lilac
        ivory_lo:        float = 0.80,   # luminance threshold for ivory specular lift
        ivory_r:         float = 0.010,  # ivory specular R lift
        ivory_g:         float = 0.007,  # ivory specular G lift
        blur_radius:     float = 4.0,    # Gaussian sigma to smooth zone boundary transitions
        opacity:         float = 1.0,
    ) -> None:
        """
        Simone Cantarini pearl-fog pass — session 127.

        Simone Cantarini (1612–1648), called 'il Pesarese', was Guido Reni's most
        gifted and difficult pupil.  Born in Oropezza near Pesaro, he arrived in
        Reni's Bologna workshop around 1635–37 and rapidly absorbed the master's
        silver-ivory palette while developing a distinctly personal 'pearl-fog'
        quality: a softly glowing penumbra zone in which flesh tones appear to
        emit a cool iridescent haze rather than simply recede into shadow.
        Cantarini achieved this through exceptionally thin multi-layer glazing —
        as many as eight to twelve superimposed transparent films of lead white,
        smalt (cobalt-blue glass), and lake — creating a physically layered medium
        in which different wavelengths of light scatter at different depths.

        This pass encodes Cantarini's glazing physics in the SESSION 127 ARTISTIC
        IMPROVEMENT: spectral channel-selective diffusion.  This is the fifth
        distinct processing mode introduced in this pipeline:

          s123 Rosa       — spatial displacement (image warping via turbulent flow)
          s124 Stanzione  — frequency-band decomposition (Laplacian pyramid)
          s125 Albani     — vertical spatial gradient (chromatic aerial perspective)
          s126 Bartolommeo — edge-map-driven selective modulation (Sobel gradient)
          s127 Cantarini  — SPECTRAL CHANNEL-SELECTIVE DIFFUSION (wavelength-
                            dependent per-channel Gaussian blur)

        All previous blur operations in this pipeline apply identical Gaussian
        sigma to all three RGB channels uniformly.  Cantarini's glazing physics
        demand a different approach: Rayleigh-type scattering in translucent media
        is inversely proportional to the fourth power of wavelength (λ⁻⁴).
        Blue light (λ ≈ 450 nm) scatters ~5× more than red (λ ≈ 650 nm).  When
        thin translucent glazes of smalt and lead white are layered over a warm
        ground, the short-wavelength blue component diffuses laterally across
        form boundaries while the long-wavelength red component remains relatively
        crisp.  This creates the characteristic 'pearl-fog' — the penumbra appears
        to breathe a soft blue-violet haze while the underlying warm structure
        stays legible.

        Three stages:
        (1) Spectral diffusion — extract R, G, B channels independently and apply
            Gaussian blur with channel-specific sigmas:
              σ_R = sigma_r  (smallest, red travels deepest before scattering)
              σ_G = sigma_g  (intermediate)
              σ_B = sigma_b  (largest, blue scatters most at the surface layers)
            In the penumbra zone, blend the blurred channels with the originals at
            scatter_strength.  Outside the penumbra the channels are unchanged.
        (2) Rose highlight warmth — above rose_hi_lo luminance: lift R by rose_r,
            damp B by rose_b_damp.  Cantarini's carnations have a distinctly warmer
            pink than Reni's pure silver-white — a personal inflection that marks
            his best works with a delicate sensuality.
        (3) Ivory specular lift — above ivory_lo luminance: lift R + G by ivory_r/g.
            The highest specular points receive a creamy ivory warmth, preventing
            the accumulated cool scatter from leaving the painting colourless.

        Parameters
        ----------
        penumbra_lo / penumbra_hi  : luminance bounds of the penumbra zone for scatter
        sigma_r / sigma_g / sigma_b : per-channel Gaussian blur sigmas (R < G < B)
        scatter_strength           : blend weight of blurred vs original in penumbra
        rose_hi_lo / rose_r / rose_b_damp : rose carnation warmth in highlights
        ivory_lo / ivory_r / ivory_g      : ivory specular lift above ivory threshold
        blur_radius                : sigma for smoothing zone boundary masks
        opacity                    : global compositing weight

        Notes
        -----
        Characteristic works encoding Cantarini's pearl-fog glazing:
          *Rest on the Flight into Egypt* (c. 1635–40, Pinacoteca di Brera) —
              the Virgin's face: pearl-grey penumbra with warm rose carnations; the
              quintessential Cantarini palette.
          *Madonna and Child with the Young St. John* (Uffizi) —
              ultra-smooth sfumato with that characteristic cool-haze penumbra
              and warm ivory highlights.
          *St. Joseph with the Christ Child* (Pesaro, Musei Civici) —
              compact compositional warmth; the Christ child's flesh shows the
              full pearl-fog quality — blue scatter in shadow, rose in mid-tone.
        """
        print(f"Cantarini pearl-fog pass  "
              f"(opacity={opacity:.2f}  sigma_r={sigma_r:.1f}  sigma_g={sigma_g:.1f}  "
              f"sigma_b={sigma_b:.1f}  scatter_strength={scatter_strength:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Penumbra zone mask ────────────────────────────────────────────────
        mid_c    = 0.5 * (penumbra_lo + penumbra_hi)
        mid_span = max(0.01, penumbra_hi - penumbra_lo)
        pen_raw  = _np.clip(1.0 - _np.abs(lum - mid_c) / (0.5 * mid_span), 0.0, 1.0)
        pen_mask = _gf(pen_raw.astype(_np.float32), sigma=blur_radius)
        pen_mask = _np.clip(pen_mask, 0.0, 1.0)

        # ── Stage 1: Spectral channel-selective diffusion ─────────────────────
        # Apply wavelength-dependent Gaussian blur to each channel independently.
        # The blur is applied only in the penumbra zone via a weighted blend.
        r_blurred = _gf(r0.astype(_np.float32), sigma=sigma_r)
        g_blurred = _gf(g0.astype(_np.float32), sigma=sigma_g)
        b_blurred = _gf(b0.astype(_np.float32), sigma=sigma_b)

        blend = pen_mask * scatter_strength
        r_out = r0 * (1.0 - blend) + r_blurred * blend
        g_out = g0 * (1.0 - blend) + g_blurred * blend
        b_out = b0 * (1.0 - blend) + b_blurred * blend

        # ── Stage 2: Rose carnation warmth in highlights ──────────────────────
        hi_raw   = _np.clip((lum - rose_hi_lo) / max(0.01, 1.0 - rose_hi_lo), 0.0, 1.0)
        hi_mask  = _gf(hi_raw.astype(_np.float32), sigma=blur_radius)
        hi_mask  = _np.clip(hi_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + hi_mask * rose_r,     0.0, 1.0)
        b_out = _np.clip(b_out - hi_mask * rose_b_damp, 0.0, 1.0)

        # ── Stage 3: Ivory specular lift ──────────────────────────────────────
        iv_raw  = _np.clip((lum - ivory_lo) / max(0.01, 1.0 - ivory_lo), 0.0, 1.0)
        iv_mask = _gf(iv_raw.astype(_np.float32), sigma=blur_radius)
        iv_mask = _np.clip(iv_mask, 0.0, 1.0)

        r_out = _np.clip(r_out + iv_mask * ivory_r, 0.0, 1.0)
        g_out = _np.clip(g_out + iv_mask * ivory_g, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Cantarini pearl-fog pass complete.")

    def carpaccio_venetian_clarity_pass(
        self,
        variance_sigma:       float = 5.0,
        detail_clarity_boost: float = 0.08,
        smooth_zone_sigma:    float = 1.5,
        smooth_str:           float = 0.18,
        hi_lo:                float = 0.65,
        warm_r:               float = 0.018,
        warm_g:               float = 0.008,
        shadow_hi:            float = 0.35,
        cool_b:               float = 0.016,
        cool_r:               float = 0.008,
        blur_radius:          float = 4.0,
        opacity:              float = 0.30,
    ) -> None:
        """
        Vittore Carpaccio Venetian clarity pass — session 128 new artist pass.

        Carpaccio (c. 1465–1526) was the supreme Venetian narrative painter:
        crystalline detail, warm amber highlights, and luminous cool shadows
        permeated with reflected Venetian sky-light.

        Session 128 artistic improvement: LOCAL VARIANCE MAP SPATIAL ADAPTATION.

        Previous processing modes in this pipeline:
          s122 Carracci    — direction-aware RGB temperature field
          s123 Rosa        — spatial displacement (Perlin noise warp)
          s124 Stanzione   — frequency decomposition (Laplacian pyramid)
          s125 Albani      — spatial depth gradient (aerial perspective)
          s126 Bartolommeo — Sobel edge-map driven selective modulation
          s128 Carpaccio   — local variance map spatial adaptation [NEW]

        The local luminance standard deviation is computed via the
        difference-of-blurred-squares identity:
          std = sqrt(max(GaussBlur(lum²) - GaussBlur(lum)², 0))

        This yields a per-pixel texture measure:
          std ≈ 0  → smooth zone (skin, background sky, flat fabric)
          std ≈ max → detail zone (hair, costume, architectural relief)

        Three independent stages compose Carpaccio's clarity:

        Stage 1 — Detail zone clarification.
          In high-variance regions, push each channel away from its blurred
          value (local contrast boost), scaled by std_norm.  Sharpens costume
          and architecture without over-processing smooth skin.

        Stage 2 — Smooth zone refinement.
          In low-variance regions, blend toward a spatially smoothed version
          (sigma=smooth_zone_sigma), weighted by (1 - std_norm) × smooth_str.
          Carpaccio's skin and sky passages are seamless and fresh.

        Stage 3 — Warm/cool luminous atmosphere.
          In highlight zone (lum > hi_lo): warm amber R/G lift — Carpaccio's
          golden Venetian daylight on stone and costume.
          In shadow zone (lum < shadow_hi): cool blue B lift + slight R damp
          — his shadows are permeated with reflected Venice-sky light; they
          are never muddy brown.

        Parameters
        ----------
        variance_sigma        : Gaussian sigma for local variance estimation
        detail_clarity_boost  : local contrast boost in high-variance zones
        smooth_zone_sigma     : smoothing sigma for low-variance zones
        smooth_str            : blend strength of smooth-zone smoothing
        hi_lo                 : luminance threshold above which highlights begin
        warm_r, warm_g        : warm amber channel lifts in highlight zone
        shadow_hi             : luminance threshold below which shadows begin
        cool_b                : cool blue lift in shadow zone
        cool_r                : cool red damp in shadow zone
        blur_radius           : Gaussian sigma for zone mask transitions
        opacity               : final blend weight (0 = no effect, 1 = full)
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        # ── Extract surface data ───────────────────────────────────────────────
        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Session 128 improvement: local variance map ────────────────────────
        # Var(X) = E[X²] - E[X]² via Gaussian expectation (efficient, single-pass).
        lum_sq  = (lum * lum).astype(_np.float32)
        e_sq    = _gf(lum_sq, sigma=variance_sigma)
        e_lum   = _gf(lum,    sigma=variance_sigma)
        var_map = _np.maximum(e_sq - e_lum * e_lum, 0.0)
        std_map = _np.sqrt(var_map)
        std_max = std_map.max()
        std_norm = (std_map / std_max) if std_max > 1e-9 else std_map.copy()

        # Smooth zone mask (strongest where local variance is lowest)
        detail_mask = _gf(std_norm.astype(_np.float32), sigma=blur_radius)
        detail_mask = _np.clip(detail_mask, 0.0, 1.0)
        smooth_mask = _gf((1.0 - std_norm).astype(_np.float32), sigma=blur_radius)
        smooth_mask = _np.clip(smooth_mask, 0.0, 1.0)

        # ── Stage 1: Detail zone clarification (local contrast boost) ─────────
        # In high-variance regions, push each channel away from its blurred value.
        r_blur = _gf(r0.astype(_np.float32), sigma=variance_sigma)
        g_blur = _gf(g0.astype(_np.float32), sigma=variance_sigma)
        b_blur = _gf(b0.astype(_np.float32), sigma=variance_sigma)

        r_out = r0 + detail_mask * (r0 - r_blur) * detail_clarity_boost
        g_out = g0 + detail_mask * (g0 - g_blur) * detail_clarity_boost
        b_out = b0 + detail_mask * (b0 - b_blur) * detail_clarity_boost

        # ── Stage 2: Smooth zone refinement (adaptive spatial smoothing) ───────
        r_smooth = _gf(r_out.astype(_np.float32), sigma=smooth_zone_sigma)
        g_smooth = _gf(g_out.astype(_np.float32), sigma=smooth_zone_sigma)
        b_smooth = _gf(b_out.astype(_np.float32), sigma=smooth_zone_sigma)

        r_out = r_out + smooth_mask * (r_smooth - r_out) * smooth_str
        g_out = g_out + smooth_mask * (g_smooth - g_out) * smooth_str
        b_out = b_out + smooth_mask * (b_smooth - b_out) * smooth_str

        # ── Stage 3: Warm highlights / cool luminous shadows ───────────────────
        hi_raw  = _np.clip((lum - hi_lo) / max(0.01, 1.0 - hi_lo), 0.0, 1.0)
        hi_mask = _gf(hi_raw.astype(_np.float32), sigma=blur_radius)
        hi_mask = _np.clip(hi_mask, 0.0, 1.0)

        shd_raw  = _np.clip((shadow_hi - lum) / max(0.01, shadow_hi), 0.0, 1.0)
        shd_mask = _gf(shd_raw.astype(_np.float32), sigma=blur_radius)
        shd_mask = _np.clip(shd_mask, 0.0, 1.0)

        # Warm amber lift in highlights — Carpaccio's golden Venetian daylight
        r_out = _np.clip(r_out + hi_mask * warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_mask * warm_g, 0.0, 1.0)

        # Cool blue clarity in shadows — Venice sky-reflected luminous penumbra
        b_out = _np.clip(b_out + shd_mask * cool_b, 0.0, 1.0)
        r_out = _np.clip(r_out - shd_mask * cool_r, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Carpaccio Venetian clarity pass complete.")

    def piazzetta_velvet_shadow_pass(
        self,
        shadow_percentile:  float = 0.20,
        highlight_percentile: float = 0.85,
        shadow_warm_r:      float = 0.018,
        shadow_warm_b:      float = 0.022,
        highlight_warm_r:   float = 0.032,
        highlight_warm_g:   float = 0.012,
        opacity:            float = 0.32,
    ) -> None:
        """
        Piazzetta velvet shadow pass — session 129.

        Encodes Giovanni Battista Piazzetta's Venetian Baroque Tenebrism via the
        session 129 artistic improvement: PERCENTILE-ADAPTIVE TONAL SCULPTING.

        All prior passes use LOCAL spatial analysis — sliding windows, pyramids,
        gradients, edge maps.  This pass operates on the GLOBAL LUMINANCE HISTOGRAM:
        each pixel is mapped to its rank-order PERCENTILE within the full image
        distribution.  That percentile rank drives the tonal intervention, not any
        local neighbourhood relationship.

        Algorithm:
          (1) Compute luminance for every pixel (BT.601: 0.299R + 0.587G + 0.114B).
          (2) Argsort the flat luminance array → percentile rank map in [0, 1].
          (3) Shadow zone (rank < shadow_percentile):
                R += shadow_warm_r · weight   — warm umber deepening
                B -= shadow_warm_b · weight   — B pull to warm the velvet dark
          (4) Highlight zone (rank > highlight_percentile):
                R += highlight_warm_r · weight  — amber impasto lift
                G += highlight_warm_g · weight  — golden warmth lift
          (5) Midtone zone: unchanged — the quiet bridge.
          (6) Composite result with input at `opacity`.

        Piazzetta reference works:
          *The Fortune Teller* (Accademia, Venice, c. 1740) —
            warm near-black velvet ground with glowing amber figure highlight
          *Saint James Led to Martyrdom* (San Stae, Venice, 1717) —
            dramatic tenebrism with compressed velvet dark, impasto amber light
          *Rebecca at the Well* (Pinacoteca di Brera, c. 1735) —
            characteristic warm-umber darkness and impasto warm ivory highlights
        """
        print(f"Piazzetta velvet shadow pass "
              f"(opacity={opacity:.2f} shadow_pct={shadow_percentile:.2f} "
              f"hi_pct={highlight_percentile:.2f})…")

        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Global luminance percentile map ──────────────────────────
        # Session 129 artistic improvement: rank-order percentile analysis.
        # Each pixel maps to its position in the global luminance distribution —
        # a fundamentally different approach from all prior local-spatial modes.
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).ravel()
        order   = _np.argsort(lum, kind="stable")
        rank    = _np.empty_like(order)
        rank[order] = _np.arange(len(lum))
        pct_map = (rank.astype(_np.float32) / max(len(lum) - 1, 1)).reshape(H, W)

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        # ── Stage 2: Velvet shadow zone — warm-umber compression ─────────────
        # In the darkest shadow_percentile fraction of pixels, push R slightly
        # upward and B slightly downward — warming the dark toward Piazzetta's
        # characteristic umber near-black (not cold Caravaggio void).
        shd_weight = _np.clip(
            (shadow_percentile - pct_map) / (shadow_percentile + 1e-7), 0.0, 1.0
        )
        r_out = _np.clip(r_out + shd_weight * shadow_warm_r, 0.0, 1.0)
        b_out = _np.clip(b_out - shd_weight * shadow_warm_b, 0.0, 1.0)

        # ── Stage 3: Impasto highlight zone — amber warm lift ─────────────────
        # In the brightest (1 - highlight_percentile) fraction of pixels, lift R
        # and G — simulating Piazzetta's thick, warm amber impasto highlights
        # that seem to glow against the surrounding velvet dark.
        hi_weight = _np.clip(
            (pct_map - highlight_percentile) / (1.0 - highlight_percentile + 1e-7),
            0.0, 1.0,
        )
        r_out = _np.clip(r_out + hi_weight * highlight_warm_r, 0.0, 1.0)
        g_out = _np.clip(g_out + hi_weight * highlight_warm_g, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Piazzetta velvet shadow pass complete.")

    # ──────────────────────────────────────────────────────────────────────────
    # sebastiano_sculptural_depth_pass — Session 130
    # ──────────────────────────────────────────────────────────────────────────

    def sebastiano_sculptural_depth_pass(
        self,
        integration_sigma: float = 2.5,
        smooth_sigma: float = 4.0,
        coherence_power: float = 2.0,
        warm_tint_r: float = 0.012,
        opacity: float = 0.30,
    ) -> None:
        """
        Sebastiano del Piombo sculptural depth pass.

        Session 130 artistic improvement — eighth distinct processing mode:
        IMAGE STRUCTURE TENSOR COHERENCE-DRIVEN FORM SMOOTHING.

        Sebastiano del Piombo (1485–1547) trained under Giovanni Bellini and
        Giorgione in Venice, absorbing their rich colorism and deep blended
        shadow warmth.  In 1511 he moved permanently to Rome, where he
        befriended Michelangelo — the only painter Michelangelo ever respected
        as an equal.  From Michelangelo he absorbed a sense of monumental,
        gravity-weighted sculptural form.  His mature portraits fuse these two
        traditions: the Venetian warmth and sfumato-adjacent blending of
        surface; the Roman weight and carved, three-dimensional solidity of
        form.

        This pass encodes that fusion through a fundamentally new spatial
        analysis mode.  All prior processing modes work in either the spatial
        domain (local neighbourhood statistics) or the tonal domain (global
        histogram rank):
          s123 Rosa      — spatial displacement (flow warping)
          s124 Stanzione — frequency-band decomposition (Laplacian pyramid)
          s125 Albani    — vertical spatial gradient
          s126 Bartolommeo — edge-map modulation (Sobel)
          s127 Cantarini — spectral channel-selective diffusion
          s128 Carpaccio — local variance std map spatial adaptation
          s129 Piazzetta — global histogram percentile tonal sculpting

        Session 130 introduces the eighth distinct mode:
        IMAGE STRUCTURE TENSOR ANALYSIS.

        The structure tensor J is a 2×2 symmetric positive semi-definite
        matrix field derived from the image gradient.  At each pixel, it is:
          J = Gaussian_sigma( [Gx, Gy]^T · [Gx, Gy] )
        where Gx, Gy are the spatial gradient components.

        The two eigenvalues λ1 ≥ λ2 of J describe local image anisotropy:
          - Both large:  the pixel lies at a corner / complex texture
          - λ1 large, λ2 ≈ 0: the pixel lies on a smooth, directional edge
          - Both small:  the pixel lies in a flat / uniform region

        The coherence index c = ((λ1−λ2) / (λ1+λ2+ε))^coherence_power
        maps this to [0, 1]:
          - c ≈ 1 (high coherence): strong directional edge — preserve
          - c ≈ 0 (low coherence): flat interior of a form — smooth freely

        The pass then interpolates at each pixel:
          result = original · c + Gaussian_smooth(original) · (1−c)

        In high-coherence (edge) regions the original is kept — edges and
        modelled boundaries remain crisp and present.  In low-coherence
        (interior) regions, the channel is replaced with a smooth, blended
        version — the flat planes of a cheek, the interior of a sleeve, the
        open sky — acquire a deep, rounded, sculptural quality without the
        haze of sfumato.

        A gentle warm Venetian amber tint (R channel boost, proportional to
        the smoothed fraction) encodes the warm colour richness Sebastiano
        brought from Venice.

        Parameters
        ----------
        integration_sigma   : Gaussian scale for structure tensor integration
                              (controls how large a neighbourhood contributes
                              to each tensor estimate)
        smooth_sigma        : Gaussian scale for the form-smoothing step
                              (larger → more sculptural depth roundness)
        coherence_power     : Exponent applied to the coherence index;
                              higher values → harder edge/interior separation
        warm_tint_r         : R-channel warm tint applied to the smoothed
                              (interior) fraction — Venetian amber warmth
        opacity             : Composite weight in [0, 1]
        """
        print(f"Sebastiano sculptural depth pass "
              f"(opacity={opacity:.2f} int_sigma={integration_sigma:.1f} "
              f"smooth_sigma={smooth_sigma:.1f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Build luminance for structure tensor ─────────────────────
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0)

        # ── Stage 2: Compute image gradient (Sobel) ───────────────────────────
        gx = _sobel(lum, axis=1).astype(_np.float32)
        gy = _sobel(lum, axis=0).astype(_np.float32)

        # ── Stage 3: Build structure tensor components ────────────────────────
        # J11 = smoothed(Gx²), J12 = smoothed(Gx·Gy), J22 = smoothed(Gy²)
        j11 = _gf((gx * gx).astype(_np.float32), sigma=integration_sigma)
        j12 = _gf((gx * gy).astype(_np.float32), sigma=integration_sigma)
        j22 = _gf((gy * gy).astype(_np.float32), sigma=integration_sigma)

        # ── Stage 4: Eigenvalues of structure tensor ──────────────────────────
        # For 2×2 symmetric [[a,b],[b,c]]:
        #   trace = a + c
        #   half_disc = sqrt(((a-c)/2)² + b²)
        #   λ1 = trace/2 + half_disc  (larger eigenvalue)
        #   λ2 = trace/2 - half_disc  (smaller eigenvalue)
        trace     = j11 + j22
        half_diff = (j11 - j22) * 0.5
        half_disc = _np.sqrt(half_diff * half_diff + j12 * j12 + 1e-12)

        lam1 = 0.5 * trace + half_disc   # larger eigenvalue
        lam2 = 0.5 * trace - half_disc   # smaller eigenvalue

        # ── Stage 5: Coherence index ──────────────────────────────────────────
        # c = ((λ1 - λ2) / (λ1 + λ2 + ε))^power
        # High coherence → edge (directional); low coherence → flat interior
        coherence = _np.clip(
            (lam1 - lam2) / (lam1 + lam2 + 1e-7), 0.0, 1.0
        ) ** coherence_power

        # ── Stage 6: Form-smoothing (Gaussian) of each channel ───────────────
        r_smooth = _gf(r0.astype(_np.float32), sigma=smooth_sigma)
        g_smooth = _gf(g0.astype(_np.float32), sigma=smooth_sigma)
        b_smooth = _gf(b0.astype(_np.float32), sigma=smooth_sigma)

        # ── Stage 7: Coherence-weighted interpolation ─────────────────────────
        # Edge pixels (high coherence) → keep original
        # Interior pixels (low coherence) → replace with smooth version
        smooth_fraction = 1.0 - coherence

        r_out = r0 * coherence + r_smooth * smooth_fraction
        g_out = g0 * coherence + g_smooth * smooth_fraction
        b_out = b0 * coherence + b_smooth * smooth_fraction

        # ── Stage 8: Venetian warm tint on smoothed interiors ─────────────────
        # Sebastiano brought Venetian amber-warmth to Rome.  Apply a gentle
        # R-channel lift proportional to the smooth_fraction so that the deep,
        # rounded interior planes acquire a warm Venetian glow.
        r_out = _np.clip(r_out + smooth_fraction * warm_tint_r, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Sebastiano sculptural depth pass complete.")

    def rosso_chromatic_dissonance_pass(
        self,
        hue_shift_flesh:      float = 8.0,
        flesh_desat_amount:   float = 0.08,
        hue_shift_shadow:     float = 14.0,
        shadow_v_thresh:      float = 0.46,
        hue_shift_highlight:  float = 7.0,
        highlight_v_thresh:   float = 0.72,
        opacity:              float = 0.26,
    ) -> None:
        """
        Rosso Fiorentino — Florentine Acidic Mannerism (session 131).

        Giovanni Battista di Jacopo, called Rosso Fiorentino (1494–1540), was
        the most extreme of the Florentine Mannerists.  While Pontormo withdrew
        into melancholy, Rosso attacked — his palette is aggressive, his colors
        deliberately wrong: acid lemon-yellows where warm ivory should be,
        poison green-grey where warm umber shadow should rest, vermilion accents
        placed with the shock logic of a colorist who wanted the viewer to feel
        the composition before understanding it.

        The Volterra Deposition (1521) is the defining image: bleached, angular
        figures under existential stress, a palette of jaundiced skin, cold
        blue drapery and shadow zones that read green-grey-poisonous.  No
        sfumato, no tonal comfort, no harmonic resolution.

        This pass encodes Rosso's chromatic violence as the ninth distinct
        processing mode: HUE-SELECTIVE CHROMATIC TENSION MAPPING.

        All prior pipeline processing modes operate in one of eight domains:
          s123 Rosa       — spatial displacement (turbulent flow warping)
          s124 Stanzione  — frequency-band decomposition (Laplacian pyramid)
          s125 Albani     — vertical spatial gradient
          s126 Bartolommeo — edge-map modulation (Sobel form ridges)
          s127 Cantarini  — spectral channel-selective diffusion
          s128 Carpaccio  — local variance std-map spatial adaptation
          s129 Piazzetta  — global histogram percentile tonal sculpting
          s130 Sebastiano — image structure tensor coherence analysis

        Session 131 introduces the ninth distinct mode:
        HUE-SELECTIVE CHROMATIC TENSION MAPPING.

        This pass operates exclusively in HSV hue-angle space with spatially-
        selective, luminance-conditional hue rotation.  It is the first pipeline
        mode to directly manipulate HUE ANGLE as a primary expressive lever.

        Three-zone chromatic intervention:

        (1) FLESH HUE TENSION
            Pixels where hue ∈ [10°, 38°] (warm orange flesh zone) and
            saturation > flesh_sat_min receive a hue rotation of -hue_shift_flesh
            (rotating toward cooler lemon-yellow, away from warm orange-ivory)
            plus a saturation reduction of flesh_desat_amount.
            Effect: warm, living flesh tone becomes bleached, jaundiced,
            near-cadaverous — the unmistakable Rosso skin.

        (2) SHADOW GREEN INJECTION
            Pixels with value < shadow_v_thresh (dark/shadow regions) receive
            a hue rotation of +hue_shift_shadow (toward the acidic green-grey
            zone, away from warm umber) plus a slight saturation boost.
            Effect: warm umber shadows become the characteristic poison-green
            dissonance of Rosso's shadow logic.

        (3) HIGHLIGHT ACID SHIFT
            Pixels with value > highlight_v_thresh and saturation > 0.08
            receive a hue rotation of +hue_shift_highlight (toward acid-yellow
            from whatever warm near-white they were).
            Effect: highlights read jaundiced-acid rather than warm-ivory —
            the defining quality that separates Rosso from all other Mannerists.

        Parameters
        ----------
        hue_shift_flesh      : Degrees to rotate warm flesh hues toward cool lemon
                               (subtracted from hue — moves orange toward yellow)
        flesh_desat_amount   : Saturation reduction in the flesh zone (0–1)
        hue_shift_shadow     : Degrees to rotate shadow hues toward acid green
                               (added to hue — moves umber toward yellow-green)
        shadow_v_thresh      : Value (brightness) threshold below which shadow
                               green injection applies (0–1)
        hue_shift_highlight  : Degrees to rotate bright highlights toward acid-yellow
        highlight_v_thresh   : Value threshold above which highlight acid shift applies
        opacity              : Composite weight blended back onto the original (0–1)
        """
        print(f"Rosso Fiorentino chromatic dissonance pass "
              f"(opacity={opacity:.2f} flesh_shift={hue_shift_flesh:.1f}° "
              f"shadow_shift={hue_shift_shadow:.1f}°)…")

        import numpy as _np
        import colorsys as _cs

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo ARGB32 layout: channel 0 = B, 1 = G, 2 = R, 3 = A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Convert RGB → HSV (vectorised) ───────────────────────────────────
        Cmax  = _np.maximum(_np.maximum(r0, g0), b0)
        Cmin  = _np.minimum(_np.minimum(r0, g0), b0)
        delta = Cmax - Cmin

        # Value
        V = Cmax

        # Saturation
        S = _np.where(Cmax > 1e-7, delta / (Cmax + 1e-8), 0.0).astype(_np.float32)

        # Hue (degrees, 0–360)
        eps = 1e-8
        h_r = _np.where(
            delta > eps,
            _np.where(Cmax == r0,
                      (60.0 * ((g0 - b0) / (delta + eps))) % 360.0,
                      _np.where(Cmax == g0,
                                60.0 * ((b0 - r0) / (delta + eps)) + 120.0,
                                60.0 * ((r0 - g0) / (delta + eps)) + 240.0)),
            0.0,
        ).astype(_np.float32)
        H_arr = h_r % 360.0

        # Work on mutable copies
        H_out = H_arr.copy()
        S_out = S.copy()
        V_out = V.copy()

        # ── Zone 1: FLESH HUE TENSION ─────────────────────────────────────────
        # Warm flesh hues: H ∈ [10°, 38°], S > 0.12
        flesh_mask = (H_arr >= 10.0) & (H_arr <= 38.0) & (S > 0.12)
        H_out  = _np.where(flesh_mask, (H_out - hue_shift_flesh) % 360.0, H_out)
        S_out  = _np.where(flesh_mask, _np.clip(S_out - flesh_desat_amount, 0.0, 1.0), S_out)

        # ── Zone 2: SHADOW GREEN INJECTION ───────────────────────────────────
        # Dark shadow regions: V < shadow_v_thresh
        shadow_mask = (V < shadow_v_thresh)
        H_out = _np.where(shadow_mask, (H_out + hue_shift_shadow) % 360.0, H_out)
        S_out = _np.where(shadow_mask, _np.clip(S_out + 0.05, 0.0, 1.0), S_out)

        # ── Zone 3: HIGHLIGHT ACID SHIFT ─────────────────────────────────────
        # Bright highlights: V > highlight_v_thresh, S > 0.08
        highlight_mask = (V > highlight_v_thresh) & (S > 0.08)
        H_out = _np.where(highlight_mask, (H_out + hue_shift_highlight) % 360.0, H_out)

        # ── Convert HSV → RGB (vectorised) ───────────────────────────────────
        h6    = H_out / 60.0
        i_arr = _np.floor(h6).astype(_np.int32) % 6
        f_arr = h6 - _np.floor(h6)

        p_arr = V_out * (1.0 - S_out)
        q_arr = V_out * (1.0 - f_arr * S_out)
        t_arr = V_out * (1.0 - (1.0 - f_arr) * S_out)

        r_out = _np.select(
            [i_arr == 0, i_arr == 1, i_arr == 2, i_arr == 3, i_arr == 4, i_arr == 5],
            [V_out, q_arr, p_arr, p_arr, t_arr, V_out],
        ).astype(_np.float32)
        g_out = _np.select(
            [i_arr == 0, i_arr == 1, i_arr == 2, i_arr == 3, i_arr == 4, i_arr == 5],
            [t_arr, V_out, V_out, q_arr, p_arr, p_arr],
        ).astype(_np.float32)
        b_out = _np.select(
            [i_arr == 0, i_arr == 1, i_arr == 2, i_arr == 3, i_arr == 4, i_arr == 5],
            [p_arr, p_arr, t_arr, V_out, V_out, q_arr],
        ).astype(_np.float32)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + _np.clip(r_out, 0.0, 1.0) * opacity
        g_final = g0 * (1.0 - opacity) + _np.clip(g_out, 0.0, 1.0) * opacity
        b_final = b0 * (1.0 - opacity) + _np.clip(b_out, 0.0, 1.0) * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Rosso Fiorentino chromatic dissonance pass complete.")

    # dosso_luminance_reflectance_pass — Session 132
    # ─────────────────────────────────────────────────────────────────────────
    def dosso_luminance_reflectance_pass(
        self,
        sigma_illum:    float = 60.0,
        sat_boost:      float = 0.22,
        illum_warm_r:   float = 0.06,
        illum_warm_g:   float = 0.02,
        opacity:        float = 0.34,
    ) -> None:
        """
        Dosso Dossi — Ferrarese Colorist Poesia (session 132).

        Giovanni di Niccolò de Lutteri, called Dosso Dossi (c.1490–1542), was
        the premier court painter of Ferrara under Alfonso I d'Este.  He united
        the chromatic vision of Giorgione and Titian with Ferrarese jewel-like
        color intensity and a poetic, mythological imagination.  His palette
        has an unmistakable quality of inner luminosity: warm amber-gold light
        seems to emanate from the ground of the canvas itself, saturating colors
        from below rather than illuminating them from above.  The Circe (c.1514)
        and Melissa (c.1520) are the defining images — rich, saturated jewel
        tones, dense forest shadows, and warm ochre-gold light that reads like
        a dream of Renaissance color.

        This pass encodes Dosso's inner luminosity as the tenth distinct
        processing mode: ILLUMINATION-REFLECTANCE DECOMPOSITION (Retinex).

        All prior pipeline processing modes:
          s123 Rosa        — spatial displacement (turbulent flow warping)
          s124 Stanzione   — frequency-band decomposition (Laplacian pyramid)
          s125 Albani      — vertical spatial gradient
          s126 Bartolommeo — edge-map modulation (Sobel form ridges)
          s127 Cantarini   — spectral channel-selective diffusion
          s128 Carpaccio   — local variance std-map spatial adaptation
          s129 Piazzetta   — global histogram percentile tonal sculpting
          s130 Sebastiano  — image structure tensor coherence analysis
          s131 Rosso       — hue-selective chromatic tension mapping

        Session 132 introduces the tenth distinct mode:
        ILLUMINATION-REFLECTANCE DECOMPOSITION (Retinex-inspired).

        Physical model: any image L can be approximated as the product of
        illumination I (slowly-varying, large-scale light distribution) and
        reflectance R (fine-grained, local surface color):

            L = I × R   →   log(L) = log(I) + log(R)

        The illumination I is estimated as a strong Gaussian blur of the
        log-image.  The reflectance R = L / (I + ε) captures the intrinsic
        local color, liberated from the global light envelope.

        Two artistic interventions are then applied independently:

        (1) REFLECTANCE SATURATION BOOST
            The reflectance layer R is converted to HSV, and its saturation
            channel is amplified by sat_boost.  This is Dosso's "jewel"
            quality: locally saturated colors that read as luminous from
            within, not as brightly lit from without.

        (2) ILLUMINATION WARMTH TINT
            The illumination layer I receives a warm amber tint — a slight
            positive offset on R and G channels (illum_warm_r, illum_warm_g).
            This models Dosso's warm Ferrarese ground: a pervasive golden
            warmth that unifies the canvas without flattening the local colors.

        The modified I' and R' are recombined (I' × R'), clamped to [0, 1],
        and composited at opacity over the original canvas.

        This is the first pipeline mode to operate in LOG-DOMAIN
        ILLUMINATION/REFLECTANCE SPACE — decomposing the image into its
        physical lighting component and its surface-color component, then
        modifying each independently before reconstruction.

        Parameters
        ----------
        sigma_illum   : Gaussian blur sigma for illumination estimation (pixels)
                        Larger → smoother illumination model, more of the
                        local color detail attributed to reflectance
        sat_boost     : Saturation multiplier added to reflectance HSV S channel
                        (0 = no effect; 0.22 = Dosso's jewel richness)
        illum_warm_r  : Warm amber offset added to illumination R channel (0–1)
        illum_warm_g  : Warm amber offset added to illumination G channel (0–1)
        opacity       : Composite weight blended back onto the original (0–1)
        """
        print(f"Dosso Dossi illumination-reflectance pass "
              f"(opacity={opacity:.2f} sigma_illum={sigma_illum:.0f} "
              f"sat_boost={sat_boost:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo ARGB32 layout: channel 0 = B, 1 = G, 2 = R, 3 = A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        eps = 1e-6

        # ── Log-domain illumination estimation ───────────────────────────────
        log_r = _np.log(r0 + eps)
        log_g = _np.log(g0 + eps)
        log_b = _np.log(b0 + eps)

        # Illumination = blurred log-image (large scale light distribution)
        log_I_r = _gf(log_r, sigma=sigma_illum)
        log_I_g = _gf(log_g, sigma=sigma_illum)
        log_I_b = _gf(log_b, sigma=sigma_illum)

        I_r = _np.exp(log_I_r)
        I_g = _np.exp(log_I_g)
        I_b = _np.exp(log_I_b)

        # Reflectance = image / illumination (intrinsic local color)
        R_r = _np.clip(r0 / (I_r + eps), 0.0, 4.0)
        R_g = _np.clip(g0 / (I_g + eps), 0.0, 4.0)
        R_b = _np.clip(b0 / (I_b + eps), 0.0, 4.0)

        # ── (1) Reflectance saturation boost (Dosso's jewel quality) ─────────
        # Convert reflectance RGB → HSV, boost S, convert back
        Cmax_R = _np.maximum(_np.maximum(R_r, R_g), R_b)
        Cmin_R = _np.minimum(_np.minimum(R_r, R_g), R_b)
        delta_R = Cmax_R - Cmin_R

        V_R = Cmax_R
        S_R = _np.where(Cmax_R > eps, delta_R / (Cmax_R + eps), 0.0).astype(_np.float32)
        S_R_boosted = _np.clip(S_R + sat_boost, 0.0, 1.0)

        # Scale individual channels to preserve hue while boosting saturation
        # New channel = V - S_new*(V - channel_old/V_old * (V_old - S_old*V_old))
        # Simplified: channel_out = V * (1 - S_new) + channel_in * (S_new / (S_R + eps))
        # where S_R here is the old saturation — but this is tricky vectorially.
        # Simpler approach: desaturate fully then re-saturate at new level.
        # channel_grey = V_R (pure value, S=0); channel_out = lerp(grey, channel_in, S_new/max(S_R,eps))
        S_scale = _np.where(S_R > eps, S_R_boosted / (S_R + eps), 1.0)
        grey_R = V_R  # desaturated target (S=0 means R=G=B=V)
        R_r_sat = _np.clip(grey_R + (R_r - grey_R) * S_scale, 0.0, 4.0)
        R_g_sat = _np.clip(grey_R + (R_g - grey_R) * S_scale, 0.0, 4.0)
        R_b_sat = _np.clip(grey_R + (R_b - grey_R) * S_scale, 0.0, 4.0)

        # ── (2) Illumination warmth tint (Ferrarese amber ground) ─────────────
        I_r_warm = _np.clip(I_r + illum_warm_r, 0.0, 2.0)
        I_g_warm = _np.clip(I_g + illum_warm_g, 0.0, 2.0)
        I_b_warm = I_b  # blue channel unchanged — amber tint = warm R+G shift

        # ── Reconstruct ───────────────────────────────────────────────────────
        out_r = _np.clip(I_r_warm * R_r_sat, 0.0, 1.0).astype(_np.float32)
        out_g = _np.clip(I_g_warm * R_g_sat, 0.0, 1.0).astype(_np.float32)
        out_b = _np.clip(I_b_warm * R_b_sat, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + out_r * opacity
        g_final = g0 * (1.0 - opacity) + out_g * opacity
        b_final = b0 * (1.0 - opacity) + out_b * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Dosso Dossi illumination-reflectance pass complete.")

    # bassano_pastoral_glow_pass — Session 133
    # ─────────────────────────────────────────────────────────────────────────
    def bassano_pastoral_glow_pass(
        self,
        n_iter:           int   = 14,
        K:                float = 0.07,
        gamma:            float = 0.10,
        firelight_warm:   float = 0.22,
        firelight_thresh: float = 0.45,
        opacity:          float = 0.32,
    ) -> None:
        """
        Jacopo Bassano — Venetian Pastoral Luminism (session 133).

        Jacopo da Ponte, called Jacopo Bassano (c.1510–1592), spent nearly his
        entire career in the small Venetian market town of Bassano del Grappa,
        developing a profoundly personal vision outside the pressures of
        Serenissima's official culture.  His paintings are structured from a
        deep warm umber ground: darkness is not empty but warm and inhabited,
        and light — most often the flickering warmth of torches or candles —
        erupts from it in creamy, loaded impasto passages.  His later works
        develop an extraordinary calligraphic looseness that anticipates
        Tintoretto and prefigures Impressionism.

        This pass encodes Bassano's defining quality as the eleventh distinct
        processing mode: ANISOTROPIC DIFFUSION (Perona-Malik filter).

        All prior pipeline processing modes:
          s123 Rosa        — spatial displacement (turbulent flow warping)
          s124 Stanzione   — frequency-band decomposition (Laplacian pyramid)
          s125 Albani      — vertical spatial gradient
          s126 Bartolommeo — edge-map modulation (Sobel form ridges)
          s127 Cantarini   — spectral channel-selective diffusion
          s128 Carpaccio   — local variance std-map spatial adaptation
          s129 Piazzetta   — global histogram percentile tonal sculpting
          s130 Sebastiano  — image structure tensor coherence analysis
          s131 Rosso       — hue-selective chromatic tension mapping
          s132 Dosso       — illumination-reflectance decomposition (Retinex)

        Session 133 introduces the eleventh distinct mode:
        ANISOTROPIC DIFFUSION (Perona-Malik, 1990).

        Physical model: ordinary Gaussian blur smooths everything equally,
        destroying edges.  Perona-Malik diffusion is a PDE:

            ∂I/∂t = div( c(|∇I|) · ∇I )

        where the conductance function c(s) = exp(-(s/K)²) approaches:
          - 1.0  in regions of LOW gradient (flat tonal areas) → smoothed
          - 0.0  in regions of HIGH gradient (edges) → preserved

        The result is a surface where all the flat, luminous tonal zones
        merge into smooth, gradient-free pools — while the form-defining
        edges (the line where lit cheek meets shadow neck, the rim where
        torchlight carves a shoulder from dark ground) remain exactly as
        drawn.  This is Bassano's fundamental tonal construction: smooth,
        pooled lights and shadows, separated by firm chiaroscuro edges.

        After n_iter iterations of anisotropic diffusion, a FIRELIGHT
        WARMTH BOOST is applied: pixels above firelight_thresh luminance
        receive a warm copper-amber tint proportional to their brightness.
        This encodes Bassano's candlelight and torchlight quality — the
        orange-amber warmth that saturates his highlights and gives them
        their particular glow.

        Parameters
        ----------
        n_iter           : Number of Perona-Malik diffusion iterations.
                           More iterations → smoother tonal pools, stronger
                           edge preservation. 10–18 is the useful range.
        K                : Conductance threshold (gradient magnitude scale).
                           Smaller K → preserves finer edges (more selective).
                           Larger K → smooths more aggressively across edges.
                           Typical range: 0.04–0.15.
        gamma            : Step size per iteration (stability: gamma ≤ 0.25).
                           Smaller → more controlled, more iterations needed.
        firelight_warm   : Strength of the warm amber tint added to bright
                           pixels above firelight_thresh. 0 = no firelight
                           effect; 0.22 = Bassano's characteristic warmth.
        firelight_thresh : Luminance threshold above which firelight warmth
                           is applied (0–1). Pixels below are in shadow and
                           receive no warm boost.
        opacity          : Composite weight blended back onto original (0–1).
        """
        print(f"Jacopo Bassano anisotropic diffusion pass "
              f"(opacity={opacity:.2f} n_iter={n_iter} K={K:.3f})…")

        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo ARGB32 layout: channel 0 = B, 1 = G, 2 = R, 3 = A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Stack to (H, W, 3) in RGB order for processing
        img = _np.stack([r0, g0, b0], axis=2)

        # ── Perona-Malik anisotropic diffusion ───────────────────────────────
        diffused = img.copy()
        for _ in range(n_iter):
            # Compute luminance for conductance (more stable than per-channel)
            lum = (0.299 * diffused[:, :, 0]
                   + 0.587 * diffused[:, :, 1]
                   + 0.114 * diffused[:, :, 2])

            # Neighbour differences in 4 cardinal directions
            lN = _np.roll(lum, -1, axis=0) - lum
            lS = _np.roll(lum,  1, axis=0) - lum
            lE = _np.roll(lum, -1, axis=1) - lum
            lW = _np.roll(lum,  1, axis=1) - lum

            # Zero-pad boundaries to prevent wrap-around artefacts
            lN[-1, :] = 0.0
            lS[0, :]  = 0.0
            lE[:, -1] = 0.0
            lW[:, 0]  = 0.0

            # Perona-Malik conductance: c(s) = exp(-(s/K)²)
            # Broadcast to (H, W, 1) for per-channel update
            cN = _np.exp(-(lN / K) ** 2)[:, :, _np.newaxis]
            cS = _np.exp(-(lS / K) ** 2)[:, :, _np.newaxis]
            cE = _np.exp(-(lE / K) ** 2)[:, :, _np.newaxis]
            cW = _np.exp(-(lW / K) ** 2)[:, :, _np.newaxis]

            # Per-channel neighbour differences
            dN = _np.roll(diffused, -1, axis=0) - diffused
            dS = _np.roll(diffused,  1, axis=0) - diffused
            dE = _np.roll(diffused, -1, axis=1) - diffused
            dW = _np.roll(diffused,  1, axis=1) - diffused

            # Boundary zero-pad
            dN[-1, :, :] = 0.0
            dS[0,  :, :] = 0.0
            dE[:,  -1, :] = 0.0
            dW[:,  0,  :] = 0.0

            diffused = _np.clip(
                diffused + gamma * (cN * dN + cS * dS + cE * dE + cW * dW),
                0.0, 1.0
            )

        # ── Firelight warmth boost ────────────────────────────────────────────
        # Bright pixels (above firelight_thresh) receive warm copper-amber tint
        # proportional to their luminance — simulating torchlight saturation.
        lum_d = (0.299 * diffused[:, :, 0]
                 + 0.587 * diffused[:, :, 1]
                 + 0.114 * diffused[:, :, 2])
        warm_mask = _np.clip(
            (lum_d - firelight_thresh) / (1.0 - firelight_thresh + 1e-6),
            0.0, 1.0
        )[:, :, _np.newaxis]

        # Amber tint: lift R strongly, G slightly, leave B alone
        fire_r = diffused[:, :, 0:1] + firelight_warm * warm_mask * 0.70
        fire_g = diffused[:, :, 1:2] + firelight_warm * warm_mask * 0.25
        fire_b = diffused[:, :, 2:3]  # blue unchanged — warmth = remove cool

        diffused = _np.clip(
            _np.concatenate([fire_r, fire_g, fire_b], axis=2),
            0.0, 1.0
        )

        # ── Composite at opacity ──────────────────────────────────────────────
        result = img * (1.0 - opacity) + diffused * opacity
        result = _np.clip(result, 0.0, 1.0)

        # Write back (RGB → Cairo BGRA: channel 2=R, 1=G, 0=B)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(result[:, :, 0] * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(result[:, :, 1] * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(result[:, :, 2] * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Jacopo Bassano anisotropic diffusion pass complete.")

    # shadow_temperature_relief_pass — Session 133 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────
    def shadow_temperature_relief_pass(
        self,
        shadow_thresh:   float = 0.35,
        shadow_warm_r:   float = 0.04,
        shadow_warm_g:   float = 0.01,
        light_cool_b:    float = 0.03,
        light_thresh:    float = 0.70,
        transition_zone: float = 0.20,
        opacity:         float = 0.40,
    ) -> None:
        """
        Shadow temperature relief — Session 133 artistic improvement.

        Old master painters consistently differentiated the COLOR TEMPERATURE
        of shadows from the color temperature of lights.  This is not a simple
        warm/cool rule (it reverses by artist and period), but the key insight
        is that shadows and lights inhabit DIFFERENT thermal registers:

          Warm-light / cool-shadow painters (Baroque, Caravaggio, Rembrandt):
            Warm amber in shadows (reflected warm ground) + cooler neutral lights.

          Cool-light / warm-shadow painters (Venetian, Titian, Veronese):
            Warm sienna-red in the shadow half-tones (the "shadow warm recovery"
            of Venetian colorism) + cooler ivory-white in the direct lights.

          Neutral-light / warm-shadow painters (Leonardo, Raphael):
            Warm amber-golden shadow bloom — the shadow feels inhabited by
            residual warmth from the ground, not dead.

        This pass implements SHADOW THERMAL RELIEF — independently modulating
        the color temperature of the shadow zone and the highlight zone:

        (1) SHADOW ZONE (luminance < shadow_thresh):
            Receives a warm amber tint (+R, +G slightly) — the "breathing"
            quality of warm dark interiors.  Baroque and old master shadows
            are never simply dark; they contain warm ambient glow from
            adjacent warm surfaces (ochre ground, warm walls, reflected light).

        (2) HIGHLIGHT ZONE (luminance > light_thresh):
            Receives a slight cool blue lift (+B) — the sky-reflected or
            diffused-daylight quality of Leonardo's primary lights, which
            are cool-neutral ivory rather than warm orange.

        (3) TRANSITION ZONE (shadow_thresh ± transition_zone):
            Smoothly interpolated between 0 and 1 using a sigmoid to avoid
            any visible discontinuity at the threshold boundaries.

        The result: shadows feel warm and inhabited; highlights feel cool,
        clear, and reflective of diffused light.  The split gives the
        painting the characteristic old master tonal resonance.

        Parameters
        ----------
        shadow_thresh    : Luminance value below which shadow warmth applies.
        shadow_warm_r    : R-channel offset added to shadow pixels (warmth).
        shadow_warm_g    : G-channel offset added to shadow pixels (slight warmth).
        light_cool_b     : B-channel offset added to bright pixels (cool drift).
        light_thresh     : Luminance value above which cool highlight drift applies.
        transition_zone  : Half-width of the sigmoid transition region (luminance units).
        opacity          : Composite weight blended back onto original (0–1).
        """
        print(f"Shadow temperature relief pass "
              f"(opacity={opacity:.2f} shadow_thresh={shadow_thresh:.2f} "
              f"light_thresh={light_thresh:.2f})…")

        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo ARGB32: channel 0=B, 1=G, 2=R, 3=A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Shadow warmth mask (sigmoid) ──────────────────────────────────────
        # 1.0 deep in shadows, 0.0 in lights, smooth transition at shadow_thresh
        eps = 1e-6
        shadow_mask = 1.0 / (1.0 + _np.exp(
            (lum - shadow_thresh) / (transition_zone + eps) * 4.0
        ))

        # ── Highlight cool mask (sigmoid) ─────────────────────────────────────
        # 1.0 in bright highlights, 0.0 in shadows
        light_mask = 1.0 / (1.0 + _np.exp(
            -(lum - light_thresh) / (transition_zone + eps) * 4.0
        ))

        # ── Apply temperature modulation ──────────────────────────────────────
        r_out = _np.clip(r0 + shadow_warm_r * shadow_mask,              0.0, 1.0)
        g_out = _np.clip(g0 + shadow_warm_g * shadow_mask,              0.0, 1.0)
        b_out = _np.clip(b0 + light_cool_b  * light_mask,               0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()

    # cuyp_golden_hour_pass — Session 134
    # ─────────────────────────────────────────────────────────────────────────
    def cuyp_golden_hour_pass(
        self,
        gold_warm_r:   float = 0.18,
        gold_warm_g:   float = 0.08,
        gold_cool_b:   float = 0.10,
        sigma_base:    float = 0.8,
        sigma_scale:   float = 6.0,
        n_blur_levels: int   = 4,
        opacity:       float = 0.34,
    ) -> None:
        """
        Cuyp golden-hour pass — Session 134 (Aelbert Cuyp).

        TWELFTH DISTINCT PROCESSING MODE IN THE PIPELINE:
        LUMINANCE-ADAPTIVE SPATIAL FREQUENCY ATTENUATION
        (Contrast Sensitivity Function simulation).

        Physical / perceptual model:
        ─────────────────────────────
        The human visual system's Contrast Sensitivity Function (CSF) is not
        fixed — it is modulated by background luminance.  At very high
        background luminance (as in Cuyp's blazing afternoon light), sensitivity
        to high spatial frequencies (fine texture, sharp edge detail) falls
        sharply.  This "luminance masking" or "bright-field contrast masking"
        means that in brightly lit zones, the eye genuinely cannot perceive
        fine spatial detail — it dissolves into the luminous field.

        Cuyp observed and encoded this perceptual truth two centuries before it
        was formally measured.  His brightly lit cattle, meadows, and river
        surfaces appear to merge with the golden air; shadow zones retain their
        structural definition.

        Algorithm:
        ──────────
        (1) LUMINANCE MAP:  L = 0.299R + 0.587G + 0.114B  (float32, [0, 1])

        (2) GOLDEN WARMTH SHIFT:
              R_warm = clip(R + gold_warm_r × L², 0, 1)   — amber-orange gain
              G_warm = clip(G + gold_warm_g × L², 0, 1)   — slight yellow tint
              B_warm = clip(B − gold_cool_b  × L², 0, 1)  — blue depletion

            The L² weighting means only the brightest pixels receive the full
            golden shift; shadows and mid-tones are almost unaffected.

        (3) LUMINANCE-ADAPTIVE SPATIALLY-VARYING BLUR:
            The effective Gaussian sigma at each pixel is:
              σ(x,y) = sigma_base + sigma_scale × L(x,y)²

            A spatially-varying Gaussian is expensive to compute directly.
            Approximation: pre-compute `n_blur_levels` Gaussian blurs at sigma
            values evenly distributed from sigma_base to sigma_base +
            sigma_scale; then for each pixel blend between adjacent levels
            proportionally to L² — a piecewise-linear approximation of the
            ideal spatially-variant PSF.

        (4) COMPOSITE:
            out = original × (1 − opacity) + blurred_warm × opacity

        Unlike anisotropic diffusion (s133, Bassano), which PRESERVES edges
        while smoothing flat areas, this pass DELIBERATELY DISSOLVES fine
        detail in proportion to luminance — a fundamentally different physical
        model (CSF masking vs. PDE conductance function).  This is the
        twelfth distinct processing mode in the pipeline.

        Parameters
        ──────────
        gold_warm_r    : R-channel gain for the golden warm shift (L²-weighted).
        gold_warm_g    : G-channel gain for the golden warm shift.
        gold_cool_b    : B-channel loss for the golden warm shift (blue depletion).
        sigma_base     : Baseline Gaussian sigma (pixels) — applied everywhere.
        sigma_scale    : Additional sigma at luminance = 1.0 — bright pixels get
                         this much extra blur dissolving detail into golden glow.
        n_blur_levels  : Number of pre-computed blur levels for the approximation.
        opacity        : Final composite weight (0–1).
        """
        print(f"Cuyp golden-hour pass (CSF luminance-adaptive blur, "
              f"opacity={opacity:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo ARGB32: buf[y, x, 0]=B, [1]=G, [2]=R, [3]=A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── (1) Luminance ─────────────────────────────────────────────────────
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        lum2 = lum * lum      # quadratic: only brightest pixels get full effect

        # ── (2) Golden warmth shift ───────────────────────────────────────────
        r_warm = _np.clip(r0 + gold_warm_r * lum2, 0.0, 1.0)
        g_warm = _np.clip(g0 + gold_warm_g * lum2, 0.0, 1.0)
        b_warm = _np.clip(b0 - gold_cool_b * lum2, 0.0, 1.0)

        # ── (3) Luminance-adaptive spatially-varying blur ─────────────────────
        if n_blur_levels < 2:
            n_blur_levels = 2
        sigmas = [
            sigma_base + sigma_scale * (i / (n_blur_levels - 1))
            for i in range(n_blur_levels)
        ]

        blurred_r = [_gf(r_warm, sigma=s) for s in sigmas]
        blurred_g = [_gf(g_warm, sigma=s) for s in sigmas]
        blurred_b = [_gf(b_warm, sigma=s) for s in sigmas]

        # Piecewise-linear interpolation: lum2 in [0,1] → blur level index
        t = lum2 * (n_blur_levels - 1)
        r_blurred = _np.zeros_like(r0)
        g_blurred = _np.zeros_like(g0)
        b_blurred = _np.zeros_like(b0)

        for lvl in range(n_blur_levels - 1):
            alpha = _np.clip(t - lvl, 0.0, 1.0)
            in_interval = ((t >= lvl) & (t < lvl + 1)).astype(_np.float32)
            r_blurred += in_interval * ((1.0 - alpha) * blurred_r[lvl] + alpha * blurred_r[lvl + 1])
            g_blurred += in_interval * ((1.0 - alpha) * blurred_g[lvl] + alpha * blurred_g[lvl + 1])
            b_blurred += in_interval * ((1.0 - alpha) * blurred_b[lvl] + alpha * blurred_b[lvl + 1])
        # Handle lum2 == 1.0 edge case (top level)
        top = (t >= (n_blur_levels - 1)).astype(_np.float32)
        r_blurred += top * blurred_r[-1]
        g_blurred += top * blurred_g[-1]
        b_blurred += top * blurred_b[-1]

        # ── (4) Composite at opacity ──────────────────────────────────────────
        r_cuyp = r0 * (1.0 - opacity) + r_blurred * opacity
        g_cuyp = g0 * (1.0 - opacity) + g_blurred * opacity
        b_cuyp = b0 * (1.0 - opacity) + b_blurred * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_cuyp * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_cuyp * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_cuyp * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Cuyp golden-hour CSF pass complete.")

    # cranach_enamel_clarity_pass — Session 135
    # ─────────────────────────────────────────────────────────────────────────
    def cranach_enamel_clarity_pass(
        self,
        chroma_boost: float = 0.40,
        sigma_pool:   float = 1.8,
        pool_weight:  float = 0.30,
        opacity:      float = 0.32,
    ) -> None:
        """
        Cranach enamel clarity — Session 135 (Lucas Cranach the Elder).

        THIRTEENTH DISTINCT PROCESSING MODE IN THE PIPELINE:
        CHROMATICITY/LUMINANCE DECOMPOSITION (mean-achromatic separation
        with chromatic boost and spatial colour pooling).

        Historical / physical model:
        Each chromatic area in a Cranach panel sits at maximum chromatic
        purity for its luminance level — vermilion, jet-black, pearl ivory —
        with no grey contamination from atmospheric blending.  This enamel-like
        chromatic purity is achieved by decomposing each pixel into its
        achromatic grey component and chromatic deviation, boosting the
        deviation, then optionally pooling the chroma layer spatially to
        create the flat colour zones that define Cranach's panel surfaces.

        Algorithm:
        (1) grey = (R + G + B) / 3   (achromatic; cr+cg+cb = 0 identically)
        (2) Chromatic deviation:  cr = R - grey, cg = G - grey, cb = B - grey
        (3) Boost:  cr *= (1 + chroma_boost), etc.
        (4) Spatial pooling of chroma only (Gaussian sigma_pool, blend pool_weight)
        (5) Reconstruct:  R_out = grey + cr_final  →  clamp [0, 1]
        (6) Composite at opacity.

        Distinct from Mode 9 (Rosso, HSV hue-selective): that uses max-channel
        V and selects specific hue ranges; this uses mean-channel grey and
        applies uniformly to all hues.  Distinct from Mode 10 (Dosso, Retinex):
        that decomposes illumination × reflectance in log space; this decomposes
        achromatic × chromatic in linear space.  Thirteenth distinct mode.

        Parameters
        chroma_boost : Fractional saturation boost to the chromatic deviation.
        sigma_pool   : Gaussian sigma (pixels) for chroma spatial pooling.
        pool_weight  : Blend weight toward the spatially-pooled chroma layer.
        opacity      : Final composite weight (0–1).
        """
        print(f"Cranach enamel clarity pass (chromaticity decomposition, "
              f"opacity={opacity:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo ARGB32: buf[y, x, 0]=B, [1]=G, [2]=R, [3]=A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── (1) Achromatic/chromatic decomposition ────────────────────────────
        grey = (r0 + g0 + b0) / 3.0
        cr = r0 - grey
        cg = g0 - grey
        cb = b0 - grey

        # ── (2) Chromatic saturation boost ───────────────────────────────────
        scale = 1.0 + chroma_boost
        cr_boost = cr * scale
        cg_boost = cg * scale
        cb_boost = cb * scale

        # ── (3) Chroma spatial pooling (smooths colour within flat zones) ─────
        if sigma_pool > 0.0 and pool_weight > 0.0:
            cr_pool = _gf(cr_boost, sigma=sigma_pool)
            cg_pool = _gf(cg_boost, sigma=sigma_pool)
            cb_pool = _gf(cb_boost, sigma=sigma_pool)
            cr_final = cr_boost * (1.0 - pool_weight) + cr_pool * pool_weight
            cg_final = cg_boost * (1.0 - pool_weight) + cg_pool * pool_weight
            cb_final = cb_boost * (1.0 - pool_weight) + cb_pool * pool_weight
        else:
            cr_final, cg_final, cb_final = cr_boost, cg_boost, cb_boost

        # ── (4) Reconstruct ───────────────────────────────────────────────────
        r_out = _np.clip(grey + cr_final, 0.0, 1.0)
        g_out = _np.clip(grey + cg_final, 0.0, 1.0)
        b_out = _np.clip(grey + cb_final, 0.0, 1.0)

        # ── (5) Composite at opacity ──────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Cranach enamel clarity (chromaticity decomposition) complete.")

    # highlight_crystalline_pass — Session 135 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────
    def highlight_crystalline_pass(
        self,
        lum_thresh: float = 0.72,
        usm_sigma:  float = 1.2,
        usm_amount: float = 0.55,
        transition: float = 0.14,
        opacity:    float = 0.35,
    ) -> None:
        """
        Highlight crystalline clarity — Session 135 artistic improvement.

        Van Eyck and Early Netherlandish masters applied pure lead-white
        touches to the very brightest specular highlights — tiny precise
        dabs that make surfaces read as three-dimensional and brilliantly lit.
        This pass applies LUMINANCE-GATED UNSHARP MASKING: only pixels above
        lum_thresh receive sharpening.  Below threshold, canvas is unaffected.

        This is the complementary operation to the blurring passes elsewhere
        (Cuyp CSF s134 dissolves bright detail; Bassano anisotropic diffusion
        s133 smooths within tonal pools).  Van Eyck's highlights SHARPEN.

        Algorithm:
        (1) L = 0.299R + 0.587G + 0.114B
        (2) Sigmoid highlight gate centred at lum_thresh (width transition)
        (3) USM: sharpened = clip(orig + usm_amount × (orig - gauss(orig)), 0, 1)
        (4) Gated: result = mask × sharpened + (1-mask) × original
        (5) Composite at opacity.

        Parameters
        lum_thresh : Luminance threshold above which sharpening applies.
        usm_sigma  : Gaussian sigma for the unsharp mask base blur.
        usm_amount : Unsharp mask strength.
        transition : Sigmoid transition half-width (luminance units).
        opacity    : Final composite weight (0–1).
        """
        print(f"Highlight crystalline pass (luminance-gated USM, "
              f"opacity={opacity:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Highlight gate (sigmoid) ──────────────────────────────────────────
        eps = 1e-6
        hi_mask = 1.0 / (1.0 + _np.exp(
            -(lum - lum_thresh) / (transition + eps) * 6.0
        ))

        # ── Unsharp mask ──────────────────────────────────────────────────────
        r_blur = _gf(r0, sigma=usm_sigma)
        g_blur = _gf(g0, sigma=usm_sigma)
        b_blur = _gf(b0, sigma=usm_sigma)
        r_sharp = _np.clip(r0 + usm_amount * (r0 - r_blur), 0.0, 1.0)
        g_sharp = _np.clip(g0 + usm_amount * (g0 - g_blur), 0.0, 1.0)
        b_sharp = _np.clip(b0 + usm_amount * (b0 - b_blur), 0.0, 1.0)

        # ── Apply only in highlight zone ──────────────────────────────────────
        r_gated = hi_mask * r_sharp + (1.0 - hi_mask) * r0
        g_gated = hi_mask * g_sharp + (1.0 - hi_mask) * g0
        b_gated = hi_mask * b_sharp + (1.0 - hi_mask) * b0

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_gated * opacity
        g_final = g0 * (1.0 - opacity) + g_gated * opacity
        b_final = b0 * (1.0 - opacity) + b_gated * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Highlight crystalline pass complete.")

    # moretto_silver_luminance_pass — Session 136
    # ─────────────────────────────────────────────────────────────────────────
    def moretto_silver_luminance_pass(
        self,
        l_lift:       float = 0.06,
        b_silver:     float = 0.55,
        a_cool_hi:    float = 0.08,
        opacity:      float = 0.32,
    ) -> None:
        """
        Moretto silver luminance pass — Session 136 (Moretto da Brescia).

        FOURTEENTH DISTINCT PROCESSING MODE IN THE PIPELINE:
        PERCEPTUAL COLOR SPACE SCULPTING (CIE L*a*b*).

        Encodes the Lombard silver light of Moretto da Brescia: cool, pearlescent,
        diffused tonality achieved by sculpting in CIE L*a*b* perceptual space.
        First pipeline mode to operate in perceptual Lab space.

        Algorithm:
        (1) sRGB linearisation + RGB -> XYZ (D65) -> L*a*b*
        (2) L* midtone lift: Gaussian bell centred at L*=55
        (3) b* silver neutralisation: b_new = b * (1 - b_silver * (L/100)^2)
        (4) a* cool highlight drift in brightest zones (L* > 70)
        (5) L*a*b* -> XYZ -> sRGB; composite at opacity.

        Parameters
        l_lift    : Peak midtone L* lift (fraction of L* range, 0–1).
        b_silver  : b* neutralisation strength in highlights.
        a_cool_hi : Negative a* shift in brightest highlights.
        opacity   : Final composite weight (0–1).
        """
        print(f"Moretto silver luminance pass (CIE Lab perceptual sculpting, "
              f"opacity={opacity:.2f})…")

        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo ARGB32: [y,x,0]=B, [1]=G, [2]=R, [3]=A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── (1) Linearise sRGB ────────────────────────────────────────────────
        def _lin(c):
            return _np.where(c <= 0.04045, c / 12.92,
                             ((c + 0.055) / 1.055) ** 2.4)

        rl, gl, bl = _lin(r0), _lin(g0), _lin(b0)

        # ── (2) Linear RGB → XYZ (D65) ────────────────────────────────────────
        X = 0.4124564 * rl + 0.3575761 * gl + 0.1804375 * bl
        Y = 0.2126729 * rl + 0.7151522 * gl + 0.0721750 * bl
        Z = 0.0193339 * rl + 0.1191920 * gl + 0.9503041 * bl

        # ── (3) XYZ → CIE L*a*b* ─────────────────────────────────────────────
        Xn, Yn, Zn = 0.95047, 1.00000, 1.08883
        delta = 6.0 / 29.0

        def _f(t):
            return _np.where(t > delta ** 3,
                             t ** (1.0 / 3.0),
                             t / (3.0 * delta ** 2) + 4.0 / 29.0)

        fx = _f(X / Xn)
        fy = _f(Y / Yn)
        fz = _f(Z / Zn)

        L_star = 116.0 * fy - 16.0
        a_star = 500.0 * (fx - fy)
        b_star = 200.0 * (fy - fz)

        # ── (4a) Midtone L* lift ──────────────────────────────────────────────
        bell = _np.exp(-0.5 * ((L_star - 55.0) / 28.0) ** 2)
        L_mod = L_star + l_lift * 100.0 * bell

        # ── (4b) b* silver neutralisation ────────────────────────────────────
        Ln = _np.clip(L_mod / 100.0, 0.0, 1.0)
        b_mod = b_star * (1.0 - b_silver * Ln * Ln)

        # ── (4c) a* cool highlight drift ─────────────────────────────────────
        hi_drift = _np.clip((L_mod - 70.0) / 30.0, 0.0, 1.0)
        a_mod = a_star - a_cool_hi * 10.0 * hi_drift

        # ── (5) L*a*b* → XYZ → linear sRGB → sRGB ───────────────────────────
        fy2 = (L_mod + 16.0) / 116.0
        fx2 = a_mod / 500.0 + fy2
        fz2 = fy2 - b_mod / 200.0

        def _f_inv(t):
            return _np.where(t > delta,
                             t ** 3,
                             3.0 * delta ** 2 * (t - 4.0 / 29.0))

        X2 = Xn * _f_inv(fx2)
        Y2 = Yn * _f_inv(fy2)
        Z2 = Zn * _f_inv(fz2)

        rl2 =  3.2404542 * X2 - 1.5371385 * Y2 - 0.4985314 * Z2
        gl2 = -0.9692660 * X2 + 1.8760108 * Y2 + 0.0415560 * Z2
        bl2 =  0.0556434 * X2 - 0.2040259 * Y2 + 1.0572252 * Z2

        rl2 = _np.clip(rl2, 0.0, None)
        gl2 = _np.clip(gl2, 0.0, None)
        bl2 = _np.clip(bl2, 0.0, None)

        def _gamma(c):
            return _np.where(c <= 0.0031308,
                             12.92 * c,
                             1.055 * c ** (1.0 / 2.4) - 0.055)

        r_out = _np.clip(_gamma(rl2), 0.0, 1.0)
        g_out = _np.clip(_gamma(gl2), 0.0, 1.0)
        b_out = _np.clip(_gamma(bl2), 0.0, 1.0)

        # ── (6) Composite at opacity ──────────────────────────────────────────
        r_fin = r0 * (1.0 - opacity) + r_out * opacity
        g_fin = g0 * (1.0 - opacity) + g_out * opacity
        b_fin = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_fin * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_fin * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_fin * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Moretto silver luminance (CIE Lab) pass complete.")

    # pearlescent_sfumato_pass — Session 136 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────
    def pearlescent_sfumato_pass(
        self,
        smooth_sigma: float = 2.5,
        pearl_cool:   float = 0.04,
        pearl_lift:   float = 0.03,
        grad_thresh:  float = 0.06,
        opacity:      float = 0.28,
    ) -> None:
        """
        Pearlescent sfumato pass — Session 136 artistic improvement.

        Identifies smooth tonal zones (low local gradient) and applies a gentle
        pearlescent modulation: cool-blue lift in bright smooth areas + subtle
        luminance boost in smooth midtones. Local and structure-sensitive.

        Algorithm:
        (1) Gradient magnitude on pre-smoothed luminance
        (2) Smoothness mask S = clip(1 - M/grad_thresh, 0, 1)^2
        (3) B channel boost in bright smooth areas (pearl_cool * S * L)
        (4) Luminance lift in smooth areas (pearl_lift * S * L)
        (5) Composite at opacity.
        """
        print(f"Pearlescent sfumato pass (smooth-zone opalescent shimmer, "
              f"opacity={opacity:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── (1) Gradient magnitude on pre-smoothed luminance ─────────────────
        lum_smooth = _gf(lum, sigma=smooth_sigma)
        sx = _sobel(lum_smooth, axis=1)
        sy = _sobel(lum_smooth, axis=0)
        grad_mag = _np.sqrt(sx * sx + sy * sy)

        # ── (2) Smoothness mask ───────────────────────────────────────────────
        eps = 1e-6
        raw_mask = _np.clip(1.0 - grad_mag / (grad_thresh + eps), 0.0, 1.0)
        smooth_mask = raw_mask * raw_mask

        # ── (3) Pearlescent cool lift ─────────────────────────────────────────
        b_pearl = _np.clip(b0 + pearl_cool * smooth_mask * lum, 0.0, 1.0)

        # ── (4) Smooth zone luminance lift ────────────────────────────────────
        r_lift = _np.clip(r0 + pearl_lift * smooth_mask * lum, 0.0, 1.0)
        g_lift = _np.clip(g0 + pearl_lift * smooth_mask * lum, 0.0, 1.0)
        b_lift = _np.clip(b_pearl + pearl_lift * smooth_mask * lum, 0.0, 1.0)

        # ── (5) Composite at opacity ──────────────────────────────────────────
        r_fin = r0 * (1.0 - opacity) + r_lift * opacity
        g_fin = g0 * (1.0 - opacity) + g_lift * opacity
        b_fin = b0 * (1.0 - opacity) + b_lift * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_fin * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_fin * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_fin * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Pearlescent sfumato pass complete.")

    # parmigianino_pearl_refinement_pass — Session 137 main pass (15th mode)
    # ─────────────────────────────────────────────────────────────────────────
    def parmigianino_pearl_refinement_pass(
        self,
        sigma_chroma: float = 2.5,
        sigma_luma:   float = 1.0,
        usm_amount:   float = 0.45,
        cool_tint:    float = 0.025,
        opacity:      float = 0.34,
    ) -> None:
        """
        Parmigianino pearl refinement — Session 137 main pass.

        FIFTEENTH DISTINCT PROCESSING MODE IN THE PIPELINE:
        LUMINANCE-CHROMINANCE DECOUPLED FILTERING.

        Encodes Parmigianino's defining quality: ultra-smooth pearl skin with
        crisp tonal precision. Decomposes each pixel into perceptual luma
        (0.299R+0.587G+0.114B) and chroma residuals, then applies DIFFERENT
        filters to each — Gaussian smoothing to chroma, USM to luma — plus
        optional cool-pearl tint on the blue chroma residual.

        Distinct from Mode 13 (Cranach mean-grey chromaticity decomposition):
          (a) Perceptual luminance weighting vs mean grey (R+G+B)/3
          (b) DUAL filtering: smooth chroma, sharpen luma
          (c) Optional directional cool-pearl tint

        Algorithm:
        (1) Luma L = 0.299R + 0.587G + 0.114B
        (2) Chroma residuals: Cr = R-L, Cg = G-L, Cb = B-L
        (3) Gaussian smooth each chroma channel (sigma_chroma)
        (4) USM on luma (sigma_luma, usm_amount)
        (5) Cool tint: Cb_tinted = Cb_smooth + cool_tint
        (6) Reconstruct + clip + composite at opacity.

        Parameters
        sigma_chroma : Gaussian sigma for chroma smoothing.
        sigma_luma   : Gaussian sigma for luma USM base blur.
        usm_amount   : Unsharp mask strength for luminance.
        cool_tint    : Positive offset added to Cb residual.
        opacity      : Final composite weight (0–1).
        """
        print(f"Parmigianino pearl refinement (luma-chroma decoupled, "
              f"opacity={opacity:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo BGRA: channel 0=B, 1=G, 2=R, 3=A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── (1) Perceptual luminance ───────────────────────────────────────────
        luma = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── (2) Chroma residuals ──────────────────────────────────────────────
        cr = r0 - luma
        cg = g0 - luma
        cb = b0 - luma

        # ── (3) Smooth chroma ─────────────────────────────────────────────────
        cr_smooth = _gf(cr, sigma=sigma_chroma)
        cg_smooth = _gf(cg, sigma=sigma_chroma)
        cb_smooth = _gf(cb, sigma=sigma_chroma)

        # ── (4) USM on luma ───────────────────────────────────────────────────
        luma_blur  = _gf(luma, sigma=sigma_luma)
        luma_sharp = _np.clip(luma + usm_amount * (luma - luma_blur), 0.0, 1.0)

        # ── (5) Cool-pearl tint on blue chroma ────────────────────────────────
        cb_tinted = cb_smooth + cool_tint

        # ── (6) Reconstruct ───────────────────────────────────────────────────
        r_out = _np.clip(luma_sharp + cr_smooth, 0.0, 1.0)
        g_out = _np.clip(luma_sharp + cg_smooth, 0.0, 1.0)
        b_out = _np.clip(luma_sharp + cb_tinted, 0.0, 1.0)

        # ── (7) Composite at opacity ──────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_out * opacity
        g_final = g0 * (1.0 - opacity) + g_out * opacity
        b_final = b0 * (1.0 - opacity) + b_out * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Parmigianino pearl refinement (luma-chroma decoupled) complete.")

    # penumbra_cool_tint_pass — Session 137 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────
    def penumbra_cool_tint_pass(
        self,
        shadow_lo:  float = 0.15,
        shadow_hi:  float = 0.52,
        transition: float = 0.10,
        blue_lift:  float = 0.055,
        red_drop:   float = 0.018,
        opacity:    float = 0.30,
    ) -> None:
        """
        Penumbra cool tint — Session 137 artistic improvement.

        Applies a cool blue-lavender tint specifically in the penumbra / midtone
        zone (luminance between shadow_lo and shadow_hi). Deep shadows and bright
        highlights are left unchanged; only the transitional penumbra half-tone
        zone receives a cool shift — encoding the warm/cool split exploited by
        Parmigianino and Leonardo for translucent three-dimensional skin.

        Algorithm:
        (1) L = 0.299R + 0.587G + 0.114B
        (2) Penumbra mask: product of two sigmoids bounding [shadow_lo, shadow_hi]
        (3) In penumbra zone: B += blue_lift * mask; R -= red_drop * mask
        (4) Clip to [0, 1], composite at opacity.

        Parameters
        shadow_lo  : Lower luminance boundary of the penumbra zone.
        shadow_hi  : Upper luminance boundary of the penumbra zone.
        transition : Sigmoid transition half-width (luminance units).
        blue_lift  : Amount to raise the blue channel in the penumbra.
        red_drop   : Amount to drop the red channel in the penumbra.
        opacity    : Final composite weight (0–1).
        """
        print(f"Penumbra cool tint pass (shadow_lo={shadow_lo:.2f}, "
              f"shadow_hi={shadow_hi:.2f}, opacity={opacity:.2f})…")

        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        eps = 1e-6

        # ── Penumbra band mask (soft sigmoid product) ──────────────────────────
        gate_hi = 1.0 / (1.0 + _np.exp(
            (lum - shadow_hi) / (transition + eps) * 6.0
        ))
        gate_lo = 1.0 / (1.0 + _np.exp(
            -(lum - shadow_lo) / (transition + eps) * 6.0
        ))
        penumbra_mask = gate_hi * gate_lo

        # ── Apply cool tint in penumbra zone ───────────────────────────────────
        b_tinted = _np.clip(b0 + blue_lift * penumbra_mask, 0.0, 1.0)
        r_tinted = _np.clip(r0 - red_drop  * penumbra_mask, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_tinted * opacity
        b_final = b0 * (1.0 - opacity) + b_tinted * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g0      * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Penumbra cool tint pass complete.")

    # giorgione_tonal_poetry_pass — Session 138 main pass (mode 16)
    # ─────────────────────────────────────────────────────────────────────────
    def giorgione_tonal_poetry_pass(
        self,
        midtone_low:          float = 0.28,
        midtone_high:         float = 0.68,
        luminous_lift:        float = 0.08,
        warm_shadow_strength: float = 0.04,
        cool_edge_strength:   float = 0.03,
        figure_mask:          "np.ndarray | None" = None,
        opacity:              float = 0.30,
    ) -> None:
        """
        Giorgione tonal poetry pass — Session 138 main pass.

        Sixteenth distinct processing mode: LUMINANCE-ZONED DUAL-TEMPERATURE
        SCULPTING.

        Models Giorgione's poesia through three luminance-responsive zones:
        1. MIDTONE FOCAL WARMTH LIFT (midtone_low … midtone_high): warm amber
           luminous lift with brightness increase — the glowing core tones.
        2. SHADOW WARM TRANSITION: warm amber tint in deep-to-mid shadow where
           umber ground shows through thin oil glazes.
        3. SILHOUETTE COOL EDGE ACCENT: if figure_mask provided, cool tint at
           the silhouette boundary (gradient of the mask > 0).

        Geometrically distinct from all 15 prior modes: uses THREE luminance
        zones with dual-temperature responses (warm midtone + shadow, cool
        edge), mask-gated edge detection, and a combined brightness+hue lift
        that no previous mode applies in this configuration.

        Parameters
        midtone_low          : Lower luminance boundary of midtone zone.
        midtone_high         : Upper luminance boundary of midtone zone.
        luminous_lift        : Warm-luminance lift applied in midtone zone.
        warm_shadow_strength : Warm amber tint in shadow transition zone.
        cool_edge_strength   : Cool-tint at figure silhouette edge.
        figure_mask          : Optional H×W float32 mask (1=figure, 0=bg).
        opacity              : Final composite weight (0–1).
        """
        print(f"Giorgione tonal poetry pass (luminous_lift={luminous_lift:.2f}, "
              f"opacity={opacity:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        eps = 1e-6

        # ── (1) Midtone zone mask (smooth sigmoid product) ─────────────────────
        trans = 0.06
        gate_hi = 1.0 / (1.0 + _np.exp((lum - midtone_high) / (trans + eps) * 6.0))
        gate_lo = 1.0 / (1.0 + _np.exp(-(lum - midtone_low) / (trans + eps) * 6.0))
        midtone_mask = gate_hi * gate_lo

        # ── (2) Warm midtone luminous lift ─────────────────────────────────────
        # Amber warmth lift in midtone zone (R more than G, no blue change)
        r_lift = luminous_lift * 1.00  # red primary warm lift
        g_lift = luminous_lift * 0.60  # green secondary (amber hue)
        r_mid = _np.clip(r0 + r_lift * midtone_mask, 0.0, 1.0)
        g_mid = _np.clip(g0 + g_lift * midtone_mask, 0.0, 1.0)
        b_mid = b0

        # ── (3) Shadow warm transition ─────────────────────────────────────────
        # Warm amber in deep shadows (lum < midtone_low) fading toward zero
        shadow_gate = 1.0 / (1.0 + _np.exp(
            (lum - midtone_low) / (trans + eps) * 6.0
        ))
        r_out = _np.clip(r_mid + warm_shadow_strength * 1.0 * shadow_gate, 0.0, 1.0)
        g_out = _np.clip(g_mid + warm_shadow_strength * 0.5 * shadow_gate, 0.0, 1.0)
        b_out = b_mid

        # ── (4) Silhouette cool edge accent ───────────────────────────────────
        if figure_mask is not None and cool_edge_strength > 0.0:
            mask_f = figure_mask.astype(_np.float32)
            mask_blur = _gf(mask_f, sigma=2.0)
            # Edge = difference between original and blurred mask, renormalised
            edge = _np.abs(mask_f - mask_blur)
            edge_norm = edge / (_np.max(edge) + eps)
            # Cool accent: add blue, drop red at silhouette
            r_out = _np.clip(r_out - cool_edge_strength * edge_norm, 0.0, 1.0)
            b_out = _np.clip(b_out + cool_edge_strength * edge_norm, 0.0, 1.0)

        # ── (5) Apply figure_mask: background pixels (mask=0) must be unchanged
        if figure_mask is not None:
            mask_f = figure_mask.astype(_np.float32)
            # Clamp mask to [0,1] for blending
            mask_f = _np.clip(mask_f, 0.0, 1.0)
            r_out = r0 * (1.0 - mask_f) + r_out * mask_f
            g_out = g0 * (1.0 - mask_f) + g_out * mask_f
            b_out = b0 * (1.0 - mask_f) + b_out * mask_f

        # ── (6) Composite at opacity ──────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + _np.clip(r_out, 0.0, 1.0) * opacity
        g_final = g0 * (1.0 - opacity) + _np.clip(g_out, 0.0, 1.0) * opacity
        b_final = b0 * (1.0 - opacity) + _np.clip(b_out, 0.0, 1.0) * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Giorgione tonal poetry pass (luma-zoned dual-temperature) complete.")

    # giorgione_focal_warmth_pass — Session 138 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────
    def giorgione_focal_warmth_pass(
        self,
        cx:          float = 0.50,
        cy:          float = 0.44,
        rx:          float = 0.60,
        ry:          float = 0.55,
        warm_peak:   float = 1.0,
        warm_r:      float = 0.12,
        warm_g:      float = 0.06,
        sigma:       float = 0.38,
        sat_radius:  float = 0.55,
        sat_fade:    float = 0.18,
        opacity:     float = 0.30,
    ) -> None:
        """
        Giorgione focal warmth pass — Session 138 main pass.

        Sixteenth distinct processing mode: ELLIPTICAL FOCAL WARMTH SCULPTING.

        Models Giorgione's defining optical quality: warm amber-golden light
        radiating from the compositional focal centre, cooling and desaturating
        toward the picture margins. Geometrically driven by normalised elliptical
        distance from focal point — distinct from all 15 prior modes.

        Algorithm:
        (1) Compute normalised elliptical distance d for each pixel:
            d = sqrt(((x - cx*W) / (rx*W))^2 + ((y - cy*H) / (ry*H))^2)
        (2) Gaussian warmth kernel: W = warm_peak * exp(-d^2 / (2*sigma^2))
        (3) Apply warm tint in focal zone: R += warm_r*W; G += warm_g*W
        (4) Peripheral saturation fade: for d > sat_radius, reduce saturation
            linearly proportional to (d - sat_radius) * sat_fade, capped at 1
        (5) Clip to [0, 1], composite at opacity

        Parameters
        cx, cy      : Focal centre as fraction of canvas width/height.
        rx, ry      : Ellipse semi-axes as fractions of canvas width/height.
        warm_peak   : Peak amplitude of the Gaussian warmth kernel.
        warm_r      : Red channel warm lift at peak.
        warm_g      : Green channel warm lift at peak.
        sigma       : Gaussian standard deviation in normalised elliptical units.
        sat_radius  : Normalised elliptical distance at which saturation fade begins.
        sat_fade    : Saturation reduction rate per unit distance beyond sat_radius.
        opacity     : Final composite weight (0–1).
        """
        print(f"Giorgione focal warmth pass (cx={cx:.2f}, cy={cy:.2f}, "
              f"sigma={sigma:.2f}, opacity={opacity:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── (1) Normalised elliptical distance map ─────────────────────────────
        x_idx = _np.arange(W, dtype=_np.float32)
        y_idx = _np.arange(H, dtype=_np.float32)
        xx, yy = _np.meshgrid(x_idx, y_idx)
        dx = (xx - cx * W) / (rx * W + 1e-6)
        dy = (yy - cy * H) / (ry * H + 1e-6)
        dist = _np.sqrt(dx * dx + dy * dy)

        # ── (2) Gaussian warmth kernel ─────────────────────────────────────────
        warmth = warm_peak * _np.exp(-dist * dist / (2.0 * sigma * sigma + 1e-9))

        # ── (3) Warm tint in focal zone ────────────────────────────────────────
        r_warm = _np.clip(r0 + warm_r * warmth, 0.0, 1.0)
        g_warm = _np.clip(g0 + warm_g * warmth, 0.0, 1.0)
        b_warm = b0  # blue channel unmodified by warmth

        # ── (4) Peripheral saturation fade ────────────────────────────────────
        # In regions where dist > sat_radius, reduce saturation proportionally.
        sat_excess = _np.maximum(dist - sat_radius, 0.0)
        sat_reduction = _np.minimum(sat_excess * sat_fade, 1.0)  # clamp at 1
        grey = 0.299 * r_warm + 0.587 * g_warm + 0.114 * b_warm
        # Blend toward grey by sat_reduction factor (1 = fully desaturated)
        r_out = r_warm * (1.0 - sat_reduction) + grey * sat_reduction
        g_out = g_warm * (1.0 - sat_reduction) + grey * sat_reduction
        b_out = b_warm * (1.0 - sat_reduction) + grey * sat_reduction

        # ── (5) Composite at opacity ──────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + _np.clip(r_out, 0.0, 1.0) * opacity
        g_final = g0 * (1.0 - opacity) + _np.clip(g_out, 0.0, 1.0) * opacity
        b_final = b0 * (1.0 - opacity) + _np.clip(b_out, 0.0, 1.0) * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Giorgione focal warmth pass (elliptical Gaussian radiance) complete.")

    # warm_shadow_lift_pass — Session 138 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────
    def warm_shadow_lift_pass(
        self,
        shadow_thresh: float = 0.18,
        transition:    float = 0.08,
        warm_r:        float = 0.040,
        warm_g:        float = 0.018,
        opacity:       float = 0.30,
    ) -> None:
        """
        Warm shadow lift — Session 138 artistic improvement.

        Lifts the deepest shadow zones with a subtle warm amber tint, modelling
        how Renaissance oil painters avoided pure dead black in shadows.  Even
        the deepest painted shadows contain warm reflected ambient light — a
        secondary warm glow from umber ground visible through thin shadow glazes.

        This pass targets only the deep shadow zone (luminance < shadow_thresh),
        using a smooth sigmoid gate to avoid hard transitions. Bright areas and
        midtones are completely unaffected.

        Complements penumbra_cool_tint_pass (which cools midtone penumbra) by
        warming the deepest shadows — together they create the full warm/cool
        three-zone model: warm highlights, cool penumbra, warm-amber deep shadows.

        Algorithm:
        (1) L = 0.299R + 0.587G + 0.114B
        (2) Shadow gate: sigmoid falloff above shadow_thresh (1 = deep shadow)
        (3) In shadow zone: R += warm_r * gate; G += warm_g * gate
        (4) Clip to [0, 1], composite at opacity.

        Parameters
        shadow_thresh : Upper luminance boundary of the shadow zone.
        transition    : Sigmoid half-width (luminance units) for smooth edge.
        warm_r        : Red channel warm lift at peak (deep shadow centre).
        warm_g        : Green channel warm lift (amber hue balance).
        opacity       : Final composite weight (0–1).
        """
        print(f"Warm shadow lift pass (shadow_thresh={shadow_thresh:.2f}, "
              f"opacity={opacity:.2f})…")

        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        eps = 1e-6

        # ── Shadow zone mask (sigmoid gate: 1 = deep shadow, 0 = bright) ──────
        shadow_gate = 1.0 / (1.0 + _np.exp(
            (lum - shadow_thresh) / (transition + eps) * 6.0
        ))

        # ── Warm amber lift in shadow zone ────────────────────────────────────
        r_lifted = _np.clip(r0 + warm_r * shadow_gate, 0.0, 1.0)
        g_lifted = _np.clip(g0 + warm_g * shadow_gate, 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_lifted * opacity
        g_final = g0 * (1.0 - opacity) + g_lifted * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b0      * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Warm shadow lift pass complete.")

    def palma_blonde_luminance_pass(
        self,
        luminance_centre: float = 0.60,
        luminance_sigma:  float = 0.22,
        warm_r:           float = 0.08,
        warm_g:           float = 0.04,
        opacity:          float = 0.32,
    ) -> None:
        """
        Palma Vecchio blonde luminance pass — Session 139 artistic improvement.

        Encodes Palma Vecchio's defining quality: GOLDEN BLONDE LUMINANCE — the
        warm amber glow that radiates from flesh, hair, and drapery in the
        mid-to-high luminance zone.  Where Giorgione's tonalism is cool and
        atmospheric and Titian's is richly saturated, Palma's is warmly golden
        and naturalistic — an internal amber light concentrated in the midtone zone.

        Algorithm:
        (1) L = 0.299R + 0.587G + 0.114B
        (2) Gaussian gate centred on luminance_centre with width luminance_sigma:
            gate = exp(-0.5 * ((L - centre) / sigma) ** 2)
            This peaks at the midtone zone and falls smoothly to near-zero at
            deep shadows and pure highlights — exactly where Palma's golden warmth lives.
        (3) R += warm_r * gate;  G += warm_g * gate   (warm amber tint)
        (4) Clip to [0, 1], composite at opacity.

        The Gaussian gate distinguishes this pass from warm_shadow_lift_pass
        (which targets only deep shadows) and from giorgione_focal_warmth_pass
        (which is spatially centred on the canvas focal point).  Palma's blonde
        luminance is luminance-zoned, not spatially zoned — it follows the tonal
        value of the paint regardless of position.

        Parameters
        luminance_centre : Peak luminance of the golden warmth zone (0.0–1.0).
        luminance_sigma  : Gaussian half-width controlling zone breadth.
        warm_r           : Red channel warm lift at gate peak.
        warm_g           : Green channel warm lift (amber hue balance).
        opacity          : Final composite weight (0–1).
        """
        print(f"Palma blonde luminance pass (centre={luminance_centre:.2f}, "
              f"sigma={luminance_sigma:.2f}, opacity={opacity:.2f})…")

        import numpy as _np

        if opacity <= 0.0:
            print("    Palma blonde luminance pass skipped (opacity=0).")
            return

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Gaussian luminance gate — peaks at warm midtone zone ─────────────
        eps = 1e-6
        gate = _np.exp(
            -0.5 * ((lum - luminance_centre) / (luminance_sigma + eps)) ** 2
        )

        # ── Warm amber tint in the golden luminance zone ──────────────────────
        r_lifted = _np.clip(r0 + warm_r * gate, 0.0, 1.0)
        g_lifted = _np.clip(g0 + warm_g * gate, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_final = r0 * (1.0 - opacity) + r_lifted * opacity
        g_final = g0 * (1.0 - opacity) + g_lifted * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_final * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b0      * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Palma blonde luminance pass complete.")

    def cossa_enamel_structure_pass(
        self,
        chroma_boost:       float = 0.18,
        structure_strength: float = 0.22,
        blur_sigma:         float = 1.2,
        gem_low:            float = 0.15,
        gem_high:           float = 0.88,
        opacity:            float = 0.36,
    ) -> None:
        """
        Francesco del Cossa enamel structure pass — Session 140 artistic improvement.

        Encodes the defining quality of Cossa and the Ferrarese quattrocento school:
        GEM-ENAMEL CLARITY — the crisp, jewel-like brilliance of distinctly bounded
        colour zones with a hard, semi-glazed surface quality.  Where Venetian masters
        dissolved forms in atmosphere and Florentines built form through sfumato,
        the Ferrarese school (Cossa, Tura, de'Roberti) created colour-zone paintings
        that look almost like cloisonné enamel: each hue occupies its own discrete
        territory, bounded by firm contours, and glows with crystalline purity.

        Algorithm:
        (1) Gem-zone mask: pixels where 0.15 < L < 0.88 (the painting zone —
            excludes near-black shadows and pure white highlights where the enamel
            quality does not apply).
        (2) Chroma boost in the gem zone — shift RGB away from its own luminance axis:
            new_ch = L + (ch - L) × (1 + chroma_boost × gem_mask)
            This amplifies colour zone purity without altering luminance structure,
            producing the jewel-like saturation of Ferrarese pigments.
        (3) Unsharp mask for structural clarity (enamel surface crispness):
            detail  = boosted − Gaussian(boosted, sigma)
            sharpened = boosted + structure_strength × detail × gem_mask
            Applied only in the gem zone so deep shadows are not sharpened to noise.
        (4) Composite at opacity.

        Parameters
        chroma_boost       : Saturation multiplier in the gem zone (0–0.5 typical).
        structure_strength : Unsharp mask weight for edge clarity (0–0.5 typical).
        blur_sigma         : Gaussian radius for the detail extraction.
        gem_low, gem_high  : Luminance bounds of the enamel gem zone.
        opacity            : Final composite weight (0–1).
        """
        print(f"Cossa enamel structure pass (chroma={chroma_boost:.2f}, "
              f"structure={structure_strength:.2f}, opacity={opacity:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            print("    Cossa enamel structure pass skipped (opacity=0).")
            return

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo stores BGRA — channels: 0=B, 1=G, 2=R, 3=A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Luminance and gem-zone mask ────────────────────────────────────
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        gem = _np.where((lum >= gem_low) & (lum <= gem_high),
                        1.0, 0.0).astype(_np.float32)

        # ── Step 1: Chroma boost — amplify colour zone purity ─────────────
        scale = 1.0 + chroma_boost * gem
        r_b = _np.clip(lum + (r0 - lum) * scale, 0.0, 1.0)
        g_b = _np.clip(lum + (g0 - lum) * scale, 0.0, 1.0)
        b_b = _np.clip(lum + (b0 - lum) * scale, 0.0, 1.0)

        # ── Step 2: Unsharp mask — reinforce enamel contour clarity ───────
        r_blur = _gf(r_b, sigma=blur_sigma)
        g_blur = _gf(g_b, sigma=blur_sigma)
        b_blur = _gf(b_b, sigma=blur_sigma)

        r_s = _np.clip(r_b + structure_strength * (r_b - r_blur) * gem, 0.0, 1.0)
        g_s = _np.clip(g_b + structure_strength * (g_b - g_blur) * gem, 0.0, 1.0)
        b_s = _np.clip(b_b + structure_strength * (b_b - b_blur) * gem, 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────
        r_f = r0 * (1.0 - opacity) + r_s * opacity
        g_f = g0 * (1.0 - opacity) + g_s * opacity
        b_f = b0 * (1.0 - opacity) + b_s * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        print("    Cossa enamel structure pass complete.")

    # ── Session 141 ───────────────────────────────────────────────────────────

    def crivelli_gold_leaf_pass(
        self,
        gilt_thresh:  float = 0.72,
        gilt_power:   float = 2.2,
        gold_r:       float = 0.22,
        gold_g:       float = 0.12,
        gold_b_damp:  float = 0.06,
        opacity:      float = 0.38,
    ) -> None:
        """Apply Crivelli's specular power-curve gold-leaf highlight gilding.

        Simulates the optical behaviour of burnished gold leaf: a hard specular
        spike that fires only in the top luminance percentile.  Pixels above
        gilt_thresh receive a warm gold tint scaled by
        ((L - gilt_thresh) / (1 - gilt_thresh)) ^ gilt_power, creating a sharp
        specular peak at the highest highlights — unlike the diffuse warm bloom
        of prior modes.

        Nineteenth distinct mode: luminance-threshold specular power-curve
        gilding.  Distinct from s139 (Gaussian-gated mid-luminance bloom,
        fires in 0.25–0.85 zone), s138 (sigmoid shadow/midtone dual-temperature),
        and s140 (gem-zone chroma boost + USM) by operating exclusively in the
        top luminance percentile (L > gilt_thresh) with a sharp power exponent
        that produces a hard specular peak rather than a soft tonal lift.

        Args:
            gilt_thresh : Luminance threshold; no gold added below this value.
            gilt_power  : Power exponent — higher values create a sharper gilt peak.
            gold_r      : Red channel addition at maximum specular gate.
            gold_g      : Green channel addition at maximum specular gate.
            gold_b_damp : Blue suppression at maximum specular gate (adds warmth).
            opacity     : Final composite weight (0–1).
        """
        print(f"Crivelli gold leaf pass (thresh={gilt_thresh:.2f}, "
              f"power={gilt_power:.1f}, opacity={opacity:.2f})…")

        import numpy as _np

        if opacity <= 0.0:
            print("    Crivelli gold leaf pass skipped (opacity=0).")
            return

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo stores BGRA — channels: 0=B, 1=G, 2=R, 3=A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Luminance and specular power-curve gate ────────────────────────
        lum  = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        denom = max(1.0 - gilt_thresh, 1e-6)
        gate  = _np.clip((lum - gilt_thresh) / denom, 0.0, 1.0) ** gilt_power

        # ── Gold tint: warm amber spike, slight blue suppression ───────────
        r_g = _np.clip(r0 + gold_r   * gate, 0.0, 1.0)
        g_g = _np.clip(g0 + gold_g   * gate, 0.0, 1.0)
        b_g = _np.clip(b0 - gold_b_damp * gate, 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────
        r_f = r0 * (1.0 - opacity) + r_g * opacity
        g_f = g0 * (1.0 - opacity) + g_g * opacity
        b_f = b0 * (1.0 - opacity) + b_g * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Crivelli gold leaf pass complete.")

    def glazing_depth_pass(
        self,
        glaze_sigma:  float = 3.0,
        warm_r:       float = 0.10,
        warm_g:       float = 0.04,
        depth_low:    float = 0.25,
        depth_high:   float = 0.75,
        opacity:      float = 0.22,
    ) -> None:
        """Simulate the optical depth of transparent oil glazing layers.

        Traditional oil painters built up thin transparent glaze layers over
        opaque paint.  Light penetrates each layer, reflects from the opaque
        paint beneath, and returns through the glazes — creating a warm internal
        luminosity.  This pass simulates that effect: a Gaussian-blurred warm
        echo of the mid-tone zone is composited back at low opacity, adding
        translucent depth without blurring the overall image.

        The blend is gated by a Gaussian bell centred on the mid-luminance zone
        (depth_low–depth_high), leaving deep shadows and bright highlights
        unaffected and concentrating the glaze echo in the zone where thin glazes
        would most visibly modify the perceived colour.

        Args:
            glaze_sigma         : Blur radius for the warm echo layer.
            warm_r, warm_g      : Warm amber tint added to the blurred echo.
            depth_low, depth_high: Luminance zone receiving maximum glazing effect.
            opacity             : Maximum composite weight at the bell peak (0–1).
        """
        print(f"Glazing depth pass (sigma={glaze_sigma:.1f}, opacity={opacity:.2f})…")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            print("    Glazing depth pass skipped (opacity=0).")
            return

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Gaussian bell gate centred on mid-luminance zone ──────────────
        lum       = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        mid       = 0.5 * (depth_low + depth_high)
        sigma_gate = max(0.5 * (depth_high - depth_low), 1e-6)
        gate      = _np.exp(-0.5 * ((lum - mid) / sigma_gate) ** 2).astype(_np.float32)

        # ── Blurred warm echo of the canvas ───────────────────────────────
        r_blur = _gf(r0, sigma=glaze_sigma)
        g_blur = _gf(g0, sigma=glaze_sigma)
        b_blur = _gf(b0, sigma=glaze_sigma)

        r_glaze = _np.clip(r_blur + warm_r * gate, 0.0, 1.0)
        g_glaze = _np.clip(g_blur + warm_g * gate, 0.0, 1.0)
        b_glaze = _np.clip(b_blur,                 0.0, 1.0)

        # ── Composite glazed echo at opacity scaled by gate ───────────────
        blend = (opacity * gate).astype(_np.float32)
        r_f = r0 * (1.0 - blend) + r_glaze * blend
        g_f = g0 * (1.0 - blend) + g_glaze * blend
        b_f = b0 * (1.0 - blend) + b_glaze * blend

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Glazing depth pass complete.")

    def filippino_tension_pass(
        self,
        sat_thresh:  float = 0.25,
        sat_power:   float = 1.5,
        hue_shift:   float = 0.04,
        sat_boost:   float = 0.18,
        opacity:     float = 0.30,
    ) -> None:
        """Apply Filippino Lippi's saturation-gated hue rotation for chromatic tension.

        Filippino's palette uses color as argument: adjacent chromatic zones push
        against each other rather than harmonising.  This pass encodes that quality
        as the twentieth distinct processing mode: SATURATION-GATED HUE ROTATION.

        In HSV space, pixels above sat_thresh receive a hue rotation proportional
        to their saturation excess: gate = clip((S - sat_thresh) / (1 - sat_thresh),
        0, 1) ^ sat_power.  The hue is rotated by hue_shift * gate (in [0, 1]
        normalised units, i.e. 0.04 = 14.4 degrees), and saturation is boosted by
        sat_boost * gate.  The result: highly chromatic zones are pushed further
        apart in hue space while muted zones are left untouched, creating the
        restless colour-tension characteristic of Filippino's mature work.

        Twentieth distinct mode: saturation-gated hue rotation.  Distinct from s131
        (Rosso Fiorentino hue-selective tension, which rotates only specific hue
        ANGLE ranges and targets flesh/shadow/highlight zones by luminance) because
        this mode applies a UNIVERSAL rotation scaled by saturation level -- the more
        chromatic a pixel is, the more its hue is pushed.  It does not target hue
        angle ranges or luminance zones; it targets chromatic intensity itself.

        Args:
            sat_thresh  : Saturation threshold below which no rotation is applied.
            sat_power   : Power exponent on the saturation gate.
            hue_shift   : Maximum hue rotation in [0, 1] units (0.04 ~= 14.4 deg).
            sat_boost   : Maximum saturation boost at full gate.
            opacity     : Final composite weight (0-1).
        """
        print(f"Filippino tension pass (sat_thresh={sat_thresh:.2f}, "
              f"hue_shift={hue_shift:.3f}, opacity={opacity:.2f})...")

        import numpy as _np

        if opacity <= 0.0:
            print("    Filippino tension pass skipped (opacity=0).")
            return

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # -- RGB -> HSV (vectorised) ------------------------------------------
        max_c = _np.maximum(_np.maximum(r0, g0), b0)
        min_c = _np.minimum(_np.minimum(r0, g0), b0)
        delta = max_c - min_c

        V = max_c
        S = _np.where(max_c > 1e-6, delta / (max_c + 1e-9), 0.0).astype(_np.float32)

        # Hue in [0, 1]
        H_arr = _np.zeros_like(r0)
        eps = 1e-9
        mask_r = (max_c == r0) & (delta > 1e-6)
        mask_g = (max_c == g0) & (delta > 1e-6) & ~mask_r
        mask_b = (max_c == b0) & (delta > 1e-6) & ~mask_r & ~mask_g
        H_arr = _np.where(mask_r, ((g0 - b0) / (delta + eps)) % 6.0, H_arr)
        H_arr = _np.where(mask_g, 2.0 + (b0 - r0) / (delta + eps), H_arr)
        H_arr = _np.where(mask_b, 4.0 + (r0 - g0) / (delta + eps), H_arr)
        H_arr = (H_arr / 6.0) % 1.0

        # -- Saturation gate --------------------------------------------------
        denom = max(1.0 - sat_thresh, 1e-6)
        gate  = _np.clip((S - sat_thresh) / denom, 0.0, 1.0) ** sat_power

        # -- Apply hue rotation and saturation boost --------------------------
        H_new = (H_arr + hue_shift * gate) % 1.0
        S_new = _np.clip(S * (1.0 + sat_boost * gate), 0.0, 1.0)

        # -- HSV -> RGB (vectorised) ------------------------------------------
        H6  = H_new * 6.0
        hi  = _np.floor(H6).astype(_np.int32) % 6
        f   = (H6 - _np.floor(H6)).astype(_np.float32)
        p   = (V * (1.0 - S_new)).astype(_np.float32)
        q   = (V * (1.0 - f * S_new)).astype(_np.float32)
        t   = (V * (1.0 - (1.0 - f) * S_new)).astype(_np.float32)
        V32 = V.astype(_np.float32)

        r_h = _np.select([hi==0, hi==1, hi==2, hi==3, hi==4, hi==5], [V32, q,   p,   p,   t,   V32])
        g_h = _np.select([hi==0, hi==1, hi==2, hi==3, hi==4, hi==5], [t,   V32, V32, q,   p,   p  ])
        b_h = _np.select([hi==0, hi==1, hi==2, hi==3, hi==4, hi==5], [p,   p,   t,   V32, V32, q  ])

        # -- Composite at opacity ---------------------------------------------
        r_f = r0 * (1.0 - opacity) + r_h * opacity
        g_f = g0 * (1.0 - opacity) + g_h * opacity
        b_f = b0 * (1.0 - opacity) + b_h * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Filippino tension pass complete.")

    def focal_vignette_pass(
        self,
        focal_x:           float = 0.50,
        focal_y:           float = 0.50,
        vignette_strength: float = 0.38,
        vignette_power:    float = 2.0,
        cool_shift:        float = 0.03,
        opacity:           float = 0.50,
    ) -> None:
        """Apply a radial focal vignette to darken and cool the composition edges.

        Portrait painters from the Renaissance onward used strategic tonal
        management to guide the eye toward the subject.  This pass applies a
        radial darkening and subtle cooling from the focal centre outward:
        edges receive a luminance reduction and a slight blue temperature shift,
        concentrating the viewer's attention on the central figure.

        Algorithm: compute normalised radial distance from (focal_x, focal_y);
        build vignette = 1 - (dist_norm ^ vignette_power) * vignette_strength;
        multiply each RGB channel by vignette (darkening); apply cool_shift *
        outer_weight to the blue channel for cool atmospheric recession at edges.
        Composited at opacity.

        Args:
            focal_x, focal_y   : Normalised focal centre (0-1, default centre).
            vignette_strength  : Maximum darkening at the furthest corner (0-1).
            vignette_power     : Falloff exponent; higher = sharper edge ring.
            cool_shift         : Blue channel lift at the outer edge.
            opacity            : Composite weight of the vignette effect (0-1).
        """
        print(f"Focal vignette pass (focal=({focal_x:.2f},{focal_y:.2f}), "
              f"strength={vignette_strength:.2f}, opacity={opacity:.2f})...")

        import numpy as _np

        if opacity <= 0.0:
            print("    Focal vignette pass skipped (opacity=0).")
            return

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # -- Radial distance from focal point ---------------------------------
        xs = _np.linspace(0.0, 1.0, W, dtype=_np.float32) - float(focal_x)
        ys = _np.linspace(0.0, 1.0, H, dtype=_np.float32) - float(focal_y)
        xx, yy = _np.meshgrid(xs, ys)
        dist = _np.sqrt(xx * xx + yy * yy)

        max_dist = float(_np.sqrt(
            max(focal_x, 1.0 - focal_x) ** 2 + max(focal_y, 1.0 - focal_y) ** 2
        ))
        dist_norm = _np.clip(dist / max(max_dist, 1e-6), 0.0, 1.0)

        # -- Vignette weight: 1 at centre, reduced at edges -------------------
        vignette = 1.0 - (dist_norm ** vignette_power) * vignette_strength
        vignette = _np.clip(vignette, 0.0, 1.0).astype(_np.float32)
        outer    = (1.0 - vignette).astype(_np.float32)

        # -- Apply darkening and cool shift -----------------------------------
        r_v = _np.clip(r0 * vignette,                      0.0, 1.0)
        g_v = _np.clip(g0 * vignette,                      0.0, 1.0)
        b_v = _np.clip(b0 * vignette + cool_shift * outer, 0.0, 1.0)

        # -- Composite at opacity ---------------------------------------------
        r_f = r0 * (1.0 - opacity) + r_v * opacity
        g_f = g0 * (1.0 - opacity) + g_v * opacity
        b_f = b0 * (1.0 - opacity) + b_v * opacity

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Focal vignette pass complete.")

    def magnasco_nervous_brilliance_pass(
        self,
        hf_sigma:      float = 2.5,
        scatter_px:    int   = 3,
        bright_thresh: float = 0.04,
        dark_gate_lo:  float = 0.10,
        dark_gate_hi:  float = 0.65,
        warm_tint:     float = 0.05,
        opacity:       float = 0.35,
    ) -> None:
        """Apply Magnasco's nervous scattered highlight technique.

        Alessandro Magnasco (il Lissandrino, 1667-1749) painted from near-black
        umber grounds, adding rapid impasto highlight touches with fierce nervous
        energy — figures emerge from darkness via scattered amber-gold flickers
        of paint rather than continuous tonal modelling.

        This pass encodes that quality as the twenty-first distinct processing
        mode: SPATIAL-SCATTER HIGH-FREQUENCY LUMINANCE REVIVAL.

        Algorithm:
        (1) Extract positive HF component per channel:
            HF = clip(channel - Gaussian(channel, hf_sigma) - bright_thresh, 0, inf)
        (2) Compute n_copies=4 randomly shifted versions of HF using np.roll
            at ±scatter_px pixel offsets (deterministic seed)
        (3) Average the shifted copies to form the scattered highlight layer
        (4) Compute dark-zone gate:
            gate = 1 - clip((luma - dark_gate_lo) / (dark_gate_hi - dark_gate_lo), 0, 1)
        (5) Warm-tint scattered R channel: R_scatter *= (1 + warm_tint)
        (6) Add scattered HF to original, composite at opacity * dark_gate

        Twenty-first distinct mode: spatial-scatter high-frequency luminance
        revival.  Distinct from s123 Rosa (turbulent flow warping of the ENTIRE
        image using a smooth continuous vector field) because this mode extracts
        only BRIGHT PEAKS from the high-frequency component and scatters these
        isolated highlight marks by discrete random pixel offsets — the base
        image structure is not warped, only the surface highlight flickers are
        scattered.  Distinct from s128 Carpaccio (local variance std-map
        continuous spatial adaptation of stroke behaviour) because this is a
        discrete-offset point scatter operation on thresholded luminance peaks,
        not smooth variance-driven adaptation.

        Args:
            hf_sigma      : Gaussian sigma for high-frequency extraction.
            scatter_px    : Maximum pixel offset (±) for each shifted copy.
            bright_thresh : Minimum HF amplitude to qualify as a bright peak.
            dark_gate_lo  : Luminance below which dark-zone gate is at maximum.
            dark_gate_hi  : Luminance above which dark-zone gate drops to zero.
            warm_tint     : Red-channel warm boost on scattered highlight peaks.
            opacity       : Final composite weight (0-1).
        """
        print(f"Magnasco nervous brilliance pass (hf_sigma={hf_sigma:.1f}, "
              f"scatter_px={scatter_px}, opacity={opacity:.2f})...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            print("    Magnasco nervous brilliance pass skipped (opacity=0).")
            return

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # -- Extract positive high-frequency component (bright surface peaks) --
        hf_r = _np.clip(r0 - _gf(r0, sigma=hf_sigma) - bright_thresh, 0.0, 1.0)
        hf_g = _np.clip(g0 - _gf(g0, sigma=hf_sigma) - bright_thresh, 0.0, 1.0)
        hf_b = _np.clip(b0 - _gf(b0, sigma=hf_sigma) - bright_thresh, 0.0, 1.0)

        # -- Scatter: 4 shifted copies at random ±scatter_px offsets -----------
        rng = _np.random.RandomState(143)          # deterministic per session
        n_copies = 4
        sc_r = _np.zeros_like(hf_r)
        sc_g = _np.zeros_like(hf_g)
        sc_b = _np.zeros_like(hf_b)
        for _ in range(n_copies):
            dy = int(rng.randint(-scatter_px, scatter_px + 1))
            dx = int(rng.randint(-scatter_px, scatter_px + 1))
            sc_r += _np.roll(_np.roll(hf_r, dy, axis=0), dx, axis=1)
            sc_g += _np.roll(_np.roll(hf_g, dy, axis=0), dx, axis=1)
            sc_b += _np.roll(_np.roll(hf_b, dy, axis=0), dx, axis=1)
        sc_r /= n_copies
        sc_g /= n_copies
        sc_b /= n_copies

        # -- Dark-zone gate: concentrate effect in dark and mid-dark tones -----
        luma = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        denom = max(float(dark_gate_hi - dark_gate_lo), 1e-6)
        dark_gate = (1.0 - _np.clip((luma - dark_gate_lo) / denom, 0.0, 1.0)
                     ).astype(_np.float32)

        # -- Warm-tint the scattered highlights (amber-gold candlelight) -------
        sc_r_warm = _np.clip(sc_r * (1.0 + warm_tint), 0.0, 1.0)

        # -- Composite: add scattered peaks gated by darkness and opacity ------
        blend = (opacity * dark_gate).astype(_np.float32)
        r_f = _np.clip(r0 + sc_r_warm * blend, 0.0, 1.0)
        g_f = _np.clip(g0 + sc_g    * blend, 0.0, 1.0)
        b_f = _np.clip(b0 + sc_b    * blend, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_f * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Magnasco nervous brilliance pass complete.")

    def guardi_atmospheric_shimmer_pass(
        self,
        shimmer_sigma:  float = 1.5,    # Gaussian sigma for HF/LF decomposition
        n_trembles:     int   = 6,      # number of spatially-offset HF copies to average
        tremble_px:     int   = 2,      # maximum pixel offset (±) per trembling copy
        cool_r:         float = 0.72,   # cool grey-silver R component (atmospheric target)
        cool_g:         float = 0.74,   # cool grey-silver G component
        cool_b:         float = 0.78,   # cool grey-silver B component
        cool_lo:        float = 0.30,   # luminance floor for atmospheric tint zone
        cool_hi:        float = 0.75,   # luminance ceiling for atmospheric tint zone
        cool_amount:    float = 0.06,   # tint blend strength within atmospheric zone
        sat_dampen:     float = 0.10,   # saturation reduction in atmospheric zone
        opacity:        float = 0.38,
    ) -> None:
        """Apply Francesco Guardi's trembling atmospheric veduta technique.

        Francesco Guardi (1712–1793) was the last great vedutista of Venice
        and one of the first proto-Impressionists in Western painting.  Where
        Canaletto painted Venice with crystalline architectural precision,
        Guardi painted it as a shimmer of light on water — forms perpetually
        dissolving into the cool silver-grey lagoon atmosphere.

        This pass encodes that quality as the twenty-second distinct processing
        mode: COHERENT MULTI-OFFSET HF TREMBLING with cool atmospheric tint.

        Algorithm:
        (1) Per-channel, decompose into smooth (LF) and detail (HF) components:
            LF  = Gaussian(channel, shimmer_sigma)
            HF  = channel - LF
        (2) Build the trembled HF by averaging n_trembles spatially-offset
            copies of HF, each rolled by a deterministic ±tremble_px offset:
            trembled_HF = mean over k of roll(HF, dy_k, dx_k)
            where dy_k, dx_k ∈ [−tremble_px, +tremble_px]
            (deterministic seed 144 for reproducibility)
        (3) Reconstruct the trembled image:
            trembled = clip(LF + trembled_HF, 0, 1)
            → low-frequency tonal structure is preserved exactly;
              only the fine-detail surface acquires the fractured
              Guardi trembling quality
        (4) Cool atmospheric tint in mid-luminance zone [cool_lo, cool_hi]:
            gate = clip((luma - cool_lo) / (cool_hi - cool_lo), 0, 1)
                   * clip((cool_hi - luma) / (cool_hi - cool_lo), 0, 1) * 4
            (smooth bump, peak = 1.0 at luminance midpoint)
            R_tinted = trembled_R * (1 - gate * cool_amount)
                       + cool_r   *      gate * cool_amount
            G/B similarly → replicates the pervasive cool grey-silver
            atmospheric envelope of Guardi's lagoon light
        (5) Saturation damping within the same zone:
            Y    = 0.299*R + 0.587*G + 0.114*B  (luminance grey)
            R_final = lerp(R_tinted, Y, gate * sat_dampen)
            G/B similarly → low-saturation atmospheric envelope without
            desaturating warm highlights or deep shadows
        (6) Composite at opacity:
            output = orig * (1 - opacity) + R_final * opacity

        Twenty-second distinct mode: coherent multi-offset HF trembling.
        Distinct from s143 Magnasco (spatial-scatter): Magnasco extracts
        only BRIGHT PEAKS above a threshold and scatters them at discrete
        random offsets gated by darkness.  Guardi processes the full
        bidirectional HF component (both positive and negative excursions)
        through coherent averaging of offset copies — no thresholding, no
        dark gate, no single-channel warm tint — the result is a uniform
        trembling of all surface detail.
        Distinct from s123 Rosa (turbulent flow): Rosa warps the entire
        image with a smooth continuous vector field; Guardi preserves the
        LF structure exactly and only redistributes HF detail.
        Distinct from s134 Cuyp (CSF luminance-adaptive frequency
        attenuation): Cuyp suppresses high frequencies in bright zones;
        Guardi redistributes them uniformly without suppression, then adds
        an independent cool tint layer.

        Args:
            shimmer_sigma  : Gaussian sigma for LF/HF decomposition.
            n_trembles     : Number of shifted HF copies to average.
            tremble_px     : Max pixel offset (±) for each copy.
            cool_r/g/b     : Cool grey-silver atmospheric tint target.
            cool_lo/hi     : Luminance range for atmospheric tint/sat gate.
            cool_amount    : Tint blend strength in the atmospheric zone.
            sat_dampen     : Saturation reduction in the atmospheric zone.
            opacity        : Global composite blend weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: LF/HF decomposition per channel ───────────────────────────
        lf_r = _gf(r0, sigma=shimmer_sigma)
        lf_g = _gf(g0, sigma=shimmer_sigma)
        lf_b = _gf(b0, sigma=shimmer_sigma)
        hf_r = r0 - lf_r
        hf_g = g0 - lf_g
        hf_b = b0 - lf_b

        # ── Step 2: Coherent multi-offset HF trembling ────────────────────────
        rng = _np.random.RandomState(144)
        tr_r = _np.zeros_like(hf_r)
        tr_g = _np.zeros_like(hf_g)
        tr_b = _np.zeros_like(hf_b)
        for _ in range(n_trembles):
            dy = int(rng.randint(-tremble_px, tremble_px + 1))
            dx = int(rng.randint(-tremble_px, tremble_px + 1))
            tr_r += _np.roll(_np.roll(hf_r, dy, axis=0), dx, axis=1)
            tr_g += _np.roll(_np.roll(hf_g, dy, axis=0), dx, axis=1)
            tr_b += _np.roll(_np.roll(hf_b, dy, axis=0), dx, axis=1)
        tr_r /= n_trembles
        tr_g /= n_trembles
        tr_b /= n_trembles

        # ── Step 3: Reconstruct trembled image ────────────────────────────────
        tm_r = _np.clip(lf_r + tr_r, 0.0, 1.0)
        tm_g = _np.clip(lf_g + tr_g, 0.0, 1.0)
        tm_b = _np.clip(lf_b + tr_b, 0.0, 1.0)

        # ── Step 4: Cool atmospheric tint in mid-luminance zone ───────────────
        luma = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        denom = max(float(cool_hi - cool_lo), 1e-6)
        t_lo = _np.clip((luma - cool_lo) / denom, 0.0, 1.0)
        t_hi = _np.clip((cool_hi - luma) / denom, 0.0, 1.0)
        gate = (4.0 * t_lo * t_hi).astype(_np.float32)   # smooth bump, peak=1 at midpoint

        blend_cool = (gate * cool_amount).astype(_np.float32)
        tinted_r = tm_r * (1.0 - blend_cool) + cool_r * blend_cool
        tinted_g = tm_g * (1.0 - blend_cool) + cool_g * blend_cool
        tinted_b = tm_b * (1.0 - blend_cool) + cool_b * blend_cool

        # ── Step 5: Saturation damping within atmospheric zone ────────────────
        Y = 0.299 * tinted_r + 0.587 * tinted_g + 0.114 * tinted_b
        blend_sat = (gate * sat_dampen).astype(_np.float32)
        final_r = tinted_r * (1.0 - blend_sat) + Y * blend_sat
        final_g = tinted_g * (1.0 - blend_sat) + Y * blend_sat
        final_b = tinted_b * (1.0 - blend_sat) + Y * blend_sat

        # ── Step 6: Composite at opacity ─────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + final_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + final_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + final_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Guardi atmospheric shimmer pass complete.")

    def cambiaso_geometric_planes_pass(
        self,
        sigma_coarse:   float = 20.0,   # large sigma for broad tonal-zone identification
        sigma_medium:   float = 4.0,    # medium sigma for local zone mean
        flatten_amount: float = 0.60,   # fraction of within-zone fine variation to suppress
        edge_boost:     float = 0.30,   # boundary clarification strength at zone transitions
        sigma_edge:     float = 1.5,    # tiny sigma for USM signal on coarse image
        terra_r:        float = 0.68,   # terracotta ground R (warm ochre)
        terra_g:        float = 0.45,   # terracotta ground G
        terra_b:        float = 0.18,   # terracotta ground B
        terra_lo:       float = 0.12,   # luminance floor of terracotta zone
        terra_hi:       float = 0.42,   # luminance ceiling of terracotta zone
        terra_amount:   float = 0.07,   # terracotta tint blend strength
        opacity:        float = 0.35,
    ) -> None:
        """Apply Luca Cambiaso's geometric planar schematization technique.

        Luca Cambiaso (1527–1585) was the leading Genoese Mannerist and the
        first Western artist to systematically resolve the human figure into
        simplified geometric volumes — cubes, cylinders, cones — as a method
        for understanding three-dimensional form.  His famous cubic figure
        drawings (scattered through the Uffizi, British Museum, and Louvre)
        depict apostles and saints built entirely from rectangular blocks and
        cylinders, anticipating by more than three centuries the analytical
        Cubism of Braque and Picasso.

        In Cambiaso's finished paintings, this geometric logic translates into
        broad flat tonal planes separated by relatively crisp boundaries.  The
        flesh is resolved not through continuous tonal gradation (Leonardo's
        method) but through discrete luminance planes: an illuminated top plane,
        a mid-tone tilted plane, a shadow plane.  His grounds are consistently
        warm terracotta-ochre, glowing through shadow zones with an internal
        warmth that prefigures Rembrandt's use of warm imprimatura.

        This pass encodes that quality as the twenty-third distinct processing
        mode: COARSE-ZONE TONAL FLATTENING WITH BOUNDARY CLARIFICATION.

        Algorithm:
        (1) Per-channel two-scale Gaussian decomposition:
            coarse = Gaussian(ch, sigma_coarse)  — broad tonal zone structure
            medium = Gaussian(ch, sigma_medium)  — local zone mean
        (2) Within-zone fine variation suppression:
            residual = ch - medium                (fine detail within zone)
            flattened = medium + residual * (1 - flatten_amount)
            → moving each pixel toward its local zone mean; fine texture
              within each tonal plane is suppressed so planes read as
              coherent geometric solids.
        (3) Zone boundary detection from coarse luminance:
            coarse_luma = 0.299*coarse_R + 0.587*coarse_G + 0.114*coarse_B
            boundary = normalize(|Sobel_x(coarse_luma)| + |Sobel_y(coarse_luma)|)
            → identifies transitions between broad tonal planes
        (4) Boundary clarification via USM on coarse image:
            usm = coarse_luma - Gaussian(coarse_luma, sigma_edge)
            enhanced_ch = flattened_ch + edge_boost * usm * boundary
            → sharpens the transitions between geometric planes
        (5) Warm terracotta tint in shadow zone [terra_lo, terra_hi]:
            smooth bump gate (same form as Guardi's atmospheric gate):
            gate = 4 * clip((luma-terra_lo)/denom) * clip((terra_hi-luma)/denom)
            blend channels toward (terra_r, terra_g, terra_b) at terra_amount
            → terracotta ochre imprimatura glowing through shadow transitions,
              Cambiaso's characteristic internal shadow warmth
        (6) Composite at opacity.

        Twenty-third distinct mode: coarse-zone tonal flattening.
        Distinct from Guardi (multi-offset HF trembling): Cambiaso SUPPRESSES
        fine detail (moves toward zone mean) rather than spatially redistributing it.
        Distinct from Stanzione (Laplacian pyramid): Cambiaso uses only two Gaussian
        scales, preserving medium and coarse structure; Stanzione operates across
        full multi-resolution pyramid.
        Distinct from Bartolommeo (Sobel edge modulation): Cambiaso uses edges
        only at COARSE-ZONE boundaries; Bartolommeo modulates all fine-detail edges.
        Distinct from Bassano (anisotropic diffusion): Cambiaso uses explicit
        scale-space decomposition, not PDE iterative smoothing.
        Distinct from Carpaccio (local std-map adaptation): Cambiaso's flattening
        uses deterministic zone means, not local variance statistics.

        Args:
            sigma_coarse   : Large-sigma Gaussian for coarse tonal zone identification.
            sigma_medium   : Medium-sigma Gaussian for local zone mean.
            flatten_amount : Fraction of within-zone fine variation to suppress [0, 1].
            edge_boost     : Strength of boundary clarification at zone transitions.
            sigma_edge     : Fine Gaussian sigma for USM signal on coarse image.
            terra_r/g/b    : Warm terracotta ground tint target (ochre).
            terra_lo/hi    : Luminance zone for terracotta tint application.
            terra_amount   : Tint blend strength within the terracotta zone.
            opacity        : Global composite blend weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Two-scale Gaussian decomposition ──────────────────────────
        coarse_r = _gf(r0, sigma=sigma_coarse)
        coarse_g = _gf(g0, sigma=sigma_coarse)
        coarse_b = _gf(b0, sigma=sigma_coarse)
        medium_r = _gf(r0, sigma=sigma_medium)
        medium_g = _gf(g0, sigma=sigma_medium)
        medium_b = _gf(b0, sigma=sigma_medium)

        # ── Step 2: Within-zone fine variation suppression ────────────────────
        flat_r = medium_r + (r0 - medium_r) * (1.0 - flatten_amount)
        flat_g = medium_g + (g0 - medium_g) * (1.0 - flatten_amount)
        flat_b = medium_b + (b0 - medium_b) * (1.0 - flatten_amount)

        # ── Step 3: Zone boundary detection from coarse luminance ─────────────
        coarse_luma = (0.299 * coarse_r + 0.587 * coarse_g + 0.114 * coarse_b).astype(_np.float32)
        sx = _sobel(coarse_luma, axis=1)
        sy = _sobel(coarse_luma, axis=0)
        boundary_raw = _np.abs(sx) + _np.abs(sy)
        boundary = (boundary_raw / (boundary_raw.max() + 1e-6)).astype(_np.float32)

        # ── Step 4: Boundary clarification via USM on coarse luminance ────────
        coarse_tiny = _gf(coarse_luma, sigma=sigma_edge)
        usm = (coarse_luma - coarse_tiny).astype(_np.float32)
        gate_edge = (boundary * edge_boost).astype(_np.float32)
        enh_r = _np.clip(flat_r + gate_edge * usm, 0.0, 1.0)
        enh_g = _np.clip(flat_g + gate_edge * usm, 0.0, 1.0)
        enh_b = _np.clip(flat_b + gate_edge * usm, 0.0, 1.0)

        # ── Step 5: Warm terracotta tint in shadow zone ───────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        denom = max(float(terra_hi - terra_lo), 1e-6)
        t_lo = _np.clip((luma - terra_lo) / denom, 0.0, 1.0)
        t_hi = _np.clip((terra_hi - luma) / denom, 0.0, 1.0)
        gate_terra = (4.0 * t_lo * t_hi * terra_amount).astype(_np.float32)
        tinted_r = enh_r * (1.0 - gate_terra) + terra_r * gate_terra
        tinted_g = enh_g * (1.0 - gate_terra) + terra_g * gate_terra
        tinted_b = enh_b * (1.0 - gate_terra) + terra_b * gate_terra

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + tinted_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + tinted_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + tinted_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Cambiaso geometric planes pass complete.")

    def gossaert_pearl_crystalline_pass(
        self,
        shadow_hi:       float = 0.38,   # luminance ceiling of shadow stratum
        highlight_lo:    float = 0.68,   # luminance floor of highlight stratum
        pearl_cool_b:    float = 0.06,   # blue boost in highlight zone (cool pearl)
        pearl_desat:     float = 0.18,   # desaturation in highlight zone
        shadow_warm_r:   float = 0.04,   # R boost in shadow zone (warm umber)
        shadow_warm_b:   float = 0.03,   # B reduction in shadow zone
        mid_sat_boost:   float = 0.08,   # saturation lift in midtone zone
        crystal_sigma:   float = 0.8,    # Gaussian sigma for USM at stratum boundaries
        crystal_amount:  float = 0.12,   # USM strength at crystalline boundaries
        opacity:         float = 0.38,
    ) -> None:
        """Apply Jan Gossaert's crystalline three-stratum tonal treatment.

        Jan Gossaert (c. 1478–1532), known as Mabuse, was the first Flemish
        painter to visit Rome (1508), absorbing Italian Renaissance classicism
        and fusing it with the Northern oil glazing tradition inherited from
        Jan van Eyck.  His flesh has a distinctive crystalline quality entirely
        unlike either Leonardo's sfumato warmth or Cranach's enamel flatness:

          •  Highlights are cool pearl-white — a silvery, barely-tinted luminosity
             reminiscent of polished alabaster.  Unlike the warm gold of Venetian
             painting (Titian, Palma Vecchio), Gossaert's highlights cool the flesh,
             giving a marble-like sculptural presence.

          •  Midtones carry vivid, present local colour — the rich red of the lip,
             the warm peach of the cheek — more saturated than the cool highlight
             or the deep shadow.

          •  Shadows are warm umber, glowing with the amber panel imprimatura
             visible through transparent shadow glazes.

          •  At the boundaries between strata, the transition is crisper than
             sfumato but softer than Gothic flat-colour — a crystalline precision
             that reveals the underlying drawn structure.

        This pass encodes that quality as the twenty-fourth distinct processing
        mode: MULTI-THRESHOLD LUMINANCE STRIATION WITH COOL-PEARL HIGHLIGHT
        ISOLATION.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Build three smooth stratum gates from luma:
            shadow_gate    = clip(1 − luma / shadow_hi, 0, 1)  — peaks at luma=0
            highlight_gate = clip((luma − highlight_lo) / (1 − highlight_lo), 0, 1)
            mid_gate       = clip(1 − shadow_gate − highlight_gate, 0, 1)
        (3) Apply differential colour treatment per stratum:
            Shadow zone  : warm umber tint — boost R by shadow_warm_r, reduce B by
                           shadow_warm_b (simulate warm amber ground glowing through
                           transparent shadow glazes)
            Highlight zone: cool-pearl — desaturate toward luma by pearl_desat, then
                           boost B channel by pearl_cool_b (Gossaert's marble highlight)
            Midtone zone : saturation lift — move RGB away from luma by mid_sat_boost
        (4) Build stratum-boundary mask:
            boundary_zone = shadow_gate × mid_gate + mid_gate × highlight_gate
            → peaks at 0.25 when two adjacent gates are both = 0.5; scale ×4
        (5) Compute USM signal: usm = luma − Gaussian(luma, crystal_sigma)
            enhanced = stratum_result + crystal_gate × usm  (crystalline edge sharpness)
        (6) Composite at opacity.

        Twenty-fourth distinct mode: three-stratum differential colour treatment.
        Distinct from Crivelli (gilding): Gossaert COOLS highlights; Crivelli warms them.
        Distinct from Giorgione (dual-temperature): Gossaert has THREE strata, each
          with independent chromatic treatment; Giorgione uses two smooth temperature
          gradient zones.
        Distinct from Moretto (Lab sculpting): Gossaert works in RGB channel space
          with explicit luminance gating; Moretto operates in CIE L*a*b*.
        Distinct from Piazzetta (histogram percentile sculpting): Gossaert applies
          spatially-local per-stratum treatments; Piazzetta adjusts the global histogram.
        Distinct from Cambiaso (tonal flattening): Gossaert DIFFERENTIATES between
          strata (separate chromatic treatment per zone); Cambiaso suppresses within-zone
          fine variation, moving pixels toward zone means.

        Args:
            shadow_hi      : Luminance ceiling of shadow stratum (pixels below this are 'shadow').
            highlight_lo   : Luminance floor of highlight stratum (pixels above this are 'highlight').
            pearl_cool_b   : Blue channel boost in highlight zone for pearl quality.
            pearl_desat    : Desaturation strength in highlight zone (blend toward luma).
            shadow_warm_r  : R boost in shadow zone (warm umber ground glow).
            shadow_warm_b  : B reduction in shadow zone.
            mid_sat_boost  : Saturation lift in midtone zone (vivid local colour).
            crystal_sigma  : Gaussian sigma for USM signal at stratum boundaries.
            crystal_amount : USM multiplier at stratum boundary regions.
            opacity        : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Three-stratum gates ───────────────────────────────────────
        shadow_gate    = _np.clip(1.0 - luma / max(float(shadow_hi), 1e-6),
                                  0.0, 1.0).astype(_np.float32)
        highlight_gate = _np.clip((luma - highlight_lo) / max(1.0 - float(highlight_lo), 1e-6),
                                  0.0, 1.0).astype(_np.float32)
        mid_gate       = _np.clip(1.0 - shadow_gate - highlight_gate,
                                  0.0, 1.0).astype(_np.float32)

        # ── Step 3: Differential colour treatment per stratum ─────────────────
        # Shadow zone: warm umber (R boost, B reduction)
        sh_r = _np.clip(r0 + shadow_warm_r * shadow_gate, 0.0, 1.0)
        sh_g = g0.copy()
        sh_b = _np.clip(b0 - shadow_warm_b * shadow_gate, 0.0, 1.0)

        # Highlight zone: cool pearl (desaturate + blue boost)
        desat = pearl_desat * highlight_gate
        hl_r = _np.clip(sh_r * (1.0 - desat) + luma * desat, 0.0, 1.0)
        hl_g = _np.clip(sh_g * (1.0 - desat) + luma * desat, 0.0, 1.0)
        hl_b = _np.clip(sh_b * (1.0 - desat) + luma * desat + pearl_cool_b * highlight_gate,
                        0.0, 1.0)

        # Midtone zone: saturation lift (move away from luma)
        mid_r = _np.clip(hl_r + (hl_r - luma) * mid_sat_boost * mid_gate, 0.0, 1.0)
        mid_g = _np.clip(hl_g + (hl_g - luma) * mid_sat_boost * mid_gate, 0.0, 1.0)
        mid_b = _np.clip(hl_b + (hl_b - luma) * mid_sat_boost * mid_gate, 0.0, 1.0)

        # ── Step 4: Stratum boundary USM for crystalline edge clarity ─────────
        luma_smooth = _gf(luma, sigma=crystal_sigma)
        usm = (luma - luma_smooth).astype(_np.float32)
        # Boundary zone peaks where two adjacent gates overlap (both > 0)
        boundary_zone = _np.clip(
            (shadow_gate * mid_gate + mid_gate * highlight_gate) * 4.0, 0.0, 1.0
        ).astype(_np.float32)
        crystal_gate_map = (boundary_zone * crystal_amount).astype(_np.float32)

        enh_r = _np.clip(mid_r + crystal_gate_map * usm, 0.0, 1.0)
        enh_g = _np.clip(mid_g + crystal_gate_map * usm, 0.0, 1.0)
        enh_b = _np.clip(mid_b + crystal_gate_map * usm, 0.0, 1.0)

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + enh_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + enh_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + enh_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Gossaert pearl-crystalline pass complete.")

    def shadow_transparency_pass(
        self,
        shadow_hi:       float = 0.42,   # luminance ceiling of shadow influence zone
        penumbra_lo:     float = 0.30,   # start of penumbra chroma-boost region
        penumbra_hi:     float = 0.58,   # end of penumbra chroma-boost region
        violet_r:        float = 0.38,   # cool violet tint R
        violet_g:        float = 0.32,   # cool violet tint G
        violet_b:        float = 0.72,   # cool violet tint B
        shadow_tint:     float = 0.06,   # violet blend strength in deep shadow
        penumbra_chroma: float = 0.10,   # saturation boost in penumbra zone
        opacity:         float = 0.30,
    ) -> None:
        """Enrich shadows with chromatic transparency inspired by Old Master oil glazing.

        In Old Master oil painting, deep shadows are never neutral grey or flat black.
        They are built from multiple transparent glaze layers that, by their very
        translucency, let underlying ground colours and earlier paint layers show
        through.  This creates shadows that are internally colourful — often with
        a cool blue-violet underpaint visible beneath the warm surface layers, a
        quality described by Delacroix as 'coloured shadow'.

        This pass simulates that quality by:
          1. Injecting a cool violet chromatic accent into deep shadow zones,
             as if a cool-toned underpaint were visible through the transparent glazes.
          2. Boosting saturation in the penumbra zone (the shadow-to-light transition),
             where glazed paint layers catch and refract the most chromatic light.

        This is a general-purpose artistic improvement applicable to any period.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Shadow gate: smooth ramp from 1 (at luma=0) to 0 (at luma=shadow_hi)
            shadow_gate = clip(1 − luma / shadow_hi, 0, 1)
        (3) Penumbra gate: smooth bump centred on the shadow-to-light transition
            — peaks at 1 when luma is centred between penumbra_lo and penumbra_hi,
            using a 4×t_lo×t_hi bump form (same as Guardi and Cambiaso)
        (4) Cool violet injection in shadow zone:
            blended = pixel × (1 − shadow_gate × shadow_tint) + violet × (shadow_gate × shadow_tint)
        (5) Saturation boost in penumbra zone:
            saturated = blended + (blended − luma) × penumbra_chroma × penumbra_gate
        (6) Composite at opacity.

        Distinct from gossaert_pearl_crystalline_pass:
          - Targets shadow/penumbra zones only, not all three strata
          - Injects a specific chromatic hue target (cool violet), vs. desaturating
          - General-purpose; not tied to Gossaert's crystalline three-stratum scheme
          - No USM boundary-sharpening component

        Args:
            shadow_hi       : Luminance ceiling of deep shadow zone.
            penumbra_lo     : Lower luminance bound of penumbra boost zone.
            penumbra_hi     : Upper luminance bound of penumbra boost zone.
            violet_r/g/b    : Target cool-violet accent colour for shadow injection.
            shadow_tint     : Blend strength of violet in deep shadow zone.
            penumbra_chroma : Saturation lift in penumbra zone.
            opacity         : Global composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Shadow gate ───────────────────────────────────────────────
        shadow_gate = _np.clip(1.0 - luma / max(float(shadow_hi), 1e-6),
                               0.0, 1.0).astype(_np.float32)

        # ── Step 3: Penumbra smooth-bump gate ─────────────────────────────────
        denom = max(float(penumbra_hi - penumbra_lo), 1e-6)
        t_lo = _np.clip((luma - penumbra_lo) / denom, 0.0, 1.0)
        t_hi = _np.clip((penumbra_hi - luma) / denom, 0.0, 1.0)
        penumbra_gate = (4.0 * t_lo * t_hi).astype(_np.float32)

        # ── Step 4: Cool-violet injection in shadow zone ─────────────────────
        blend = (shadow_gate * shadow_tint).astype(_np.float32)
        tinted_r = _np.clip(r0 * (1.0 - blend) + violet_r * blend, 0.0, 1.0)
        tinted_g = _np.clip(g0 * (1.0 - blend) + violet_g * blend, 0.0, 1.0)
        tinted_b = _np.clip(b0 * (1.0 - blend) + violet_b * blend, 0.0, 1.0)

        # ── Step 5: Saturation boost in penumbra zone ─────────────────────────
        chroma_lift = (penumbra_gate * penumbra_chroma).astype(_np.float32)
        sat_r = _np.clip(tinted_r + (tinted_r - luma) * chroma_lift, 0.0, 1.0)
        sat_g = _np.clip(tinted_g + (tinted_g - luma) * chroma_lift, 0.0, 1.0)
        sat_b = _np.clip(tinted_b + (tinted_b - luma) * chroma_lift, 0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + sat_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + sat_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + sat_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Shadow transparency pass complete.")

    def sodoma_sienese_dreamveil_pass(
        self,
        warm_lo:      float = 0.38,   # luminance floor of golden midtone warmth zone
        warm_hi:      float = 0.72,   # luminance ceiling of golden midtone warmth zone
        warm_r:       float = 0.030,  # R boost in warm zone (Sienese golden flesh)
        warm_g:       float = 0.016,  # G boost in warm zone (warm amber undertone)
        sat_lo:       float = 0.48,   # luminance floor of saturation lift zone
        sat_hi:       float = 0.78,   # luminance ceiling of saturation lift zone
        sat_lift:     float = 0.06,   # saturation boost strength in upper midtone zone
        veil_sigma:   float = 2.2,    # Gaussian sigma for dreamveil LF blend
        veil_amount:  float = 0.07,   # fraction of dreamveil LF blend (toward smooth version)
        sky_lo:       float = 0.80,   # luminance floor of sky-blue highlight whisper zone
        sky_b:        float = 0.020,  # B boost in brightest highlights (Sienese sky blue)
        opacity:      float = 0.32,
    ) -> None:
        """Apply Sodoma's Sienese Leonardesque warm dreamveil technique.

        Sodoma (Giovanni Antonio Bazzi, 1477–1549) occupied a unique position
        in the Italian Renaissance: trained in Lombardy under Martino Spanzotti
        (and likely exposed to Leonardo's Milanese circle — Boltraffio, de Predis,
        Marco d'Oggiono), he settled permanently in Siena by 1501, absorbing
        the city's deep tradition of warm golden grounds and luminous devotional
        tenderness.  He worked alongside Raphael at the Vatican Stanza della
        Segnatura (1508), absorbing further classical clarity, then returned to
        Siena to develop his most personal style.

        The result is a fusion unlike any other painter of the period:

          •  Warm Sienese midtone gilding: the characteristic amber-golden glow
             in the flesh midtones, inherited from Siena's tradition of warm ochre
             grounds and the Byzantine gold-ground sensibility that never entirely
             left Sienese painting.  Unlike the fully saturated golden warmth of
             Venetian painting (Titian, Palma Vecchio), Sodoma's warmth is more
             interior and delicate — the ground glowing softly through thin,
             transparent flesh paint.

          •  Leonardesque dreamveil dissolution: edges do not sharpen in the
             Gossaert or Crivelli manner, but dissolve softly — not to Leonardo's
             full sfumato extremity, but with a gentle luminous haziness that
             gives Sodoma's figures their characteristic dreamlike quality.  His
             forms are present but slightly ethereal, as if seen through warm
             amber air.

          •  Sky-blue highlight whisper: the brightest specular touches in
             Sodoma's flesh carry a barely-perceptible Sienese sky blue — a link
             between the warm figures and the cool celestial distances of his
             backgrounds, which consistently feature pale blue-grey Sienese skies.

        This pass encodes that quality as the twenty-fifth distinct processing
        mode: WARM SIENESE MIDTONE GILDING + DREAMVEIL GLOBAL LF BLEND +
        SKY-BLUE HIGHLIGHT WHISPER.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Golden midtone warmth gate (Sienese tradition):
            smooth bump in [warm_lo, warm_hi]:
            gate_warm = 4 × clip((luma−warm_lo)/denom) × clip((warm_hi−luma)/denom)
            R_warm = clip(R + gate_warm × warm_r, 0, 1)
            G_warm = clip(G + gate_warm × warm_g, 0, 1)
            (B unchanged: warm tint stays orange-amber, not yellow-green)
        (3) Saturation lift in upper midtones (Sienese chromatic richness):
            smooth bump in [sat_lo, sat_hi]: gate_sat = 4 × t_lo × t_hi
            chroma_shift = (channel − luma) × gate_sat × sat_lift
            R/G/B_sat = clip(channel + chroma_shift, 0, 1)
        (4) Dreamveil LF blend (Leonardesque soft edge dissolution):
            per channel: smooth_ch = Gaussian(ch_sat, veil_sigma)
            ch_veiled = ch_sat × (1 − veil_amount) + smooth_ch × veil_amount
            This is NOT sfumato (which operates at stroke level); it is a
            post-processing global LF bias that gently reduces the amplitude
            of all high-frequency edge transitions, giving Sodoma's characteristic
            soft dreamlike surface without full sfumato extremity.
        (5) Sky-blue highlight whisper:
            gate_sky = clip((luma − sky_lo) / (1.0 − sky_lo), 0, 1)
            B_final = clip(B_veiled + gate_sky × sky_b, 0, 1)
        (6) Composite at opacity.

        Twenty-fifth distinct mode: warm Sienese midtone gilding + dreamveil LF blend
        + sky-blue highlight whisper.
        Distinct from Gossaert (three-stratum differential): Sodoma uses smooth bump
          zones without crisp stratum transitions; adds dreamveil global LF softening
          (Gossaert has USM boundary sharpening — the opposite); Gossaert COOLS
          highlights uniformly, Sodoma adds only a whisper of blue at the absolute peak.
        Distinct from Palma Vecchio (luminance-zoned warm bloom): Palma's warmth gate
          targets higher luminance [sat_lo≈0.52, sat_hi≈0.88]; Sodoma peaks lower in
          midtones [0.38–0.72]; Palma has no dreamveil or sky-blue whisper.
        Distinct from Guardi (HF trembling): Guardi redistributes HF detail via
          coherent multi-offset rolling; Sodoma blends uniformly toward LF structure
          — no roll offsets, no spatial shift, no dark-gate.
        Distinct from Giorgione (focal radiance): Giorgione applies spatially-local
          warm radiance from the compositional centre; Sodoma applies luminance-gated
          global warming across the full canvas without spatial weighting.
        Distinct from Cambiaso (tonal flattening): Cambiaso suppresses within-zone
          variation toward coarse Gaussian means; Sodoma's dreamveil uses a small
          per-pixel sigma (2.2) creating localised soft blending, not broad zone
          flattening.
        Distinct from shadow_transparency_pass (shadow/penumbra only): that pass
          targets dark zones exclusively; Sodoma targets bright midtones and peaks.

        Args:
            warm_lo/hi    : Luminance range of the golden midtone warmth gate.
            warm_r        : R boost within the warm gate (Sienese golden flesh).
            warm_g        : G boost within the warm gate (warm amber undertone).
            sat_lo/hi     : Luminance range of the saturation lift gate.
            sat_lift      : Saturation boost strength (move away from luma).
            veil_sigma    : Gaussian sigma for dreamveil LF component.
            veil_amount   : Fraction of dreamveil blend toward smooth version.
            sky_lo        : Luminance floor of sky-blue highlight whisper zone.
            sky_b         : B channel boost within sky-blue whisper zone.
            opacity       : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Golden midtone warmth gate (Sienese tradition) ───────────
        denom_warm = max(float(warm_hi - warm_lo), 1e-6)
        t_warm_lo = _np.clip((luma - warm_lo) / denom_warm, 0.0, 1.0)
        t_warm_hi = _np.clip((warm_hi - luma) / denom_warm, 0.0, 1.0)
        gate_warm = (4.0 * t_warm_lo * t_warm_hi).astype(_np.float32)

        r_warm = _np.clip(r0 + gate_warm * warm_r, 0.0, 1.0)
        g_warm = _np.clip(g0 + gate_warm * warm_g, 0.0, 1.0)
        b_warm = b0  # blue unchanged — warmth is orange-amber, not yellow-green

        # ── Step 3: Saturation lift in upper midtones ─────────────────────────
        denom_sat = max(float(sat_hi - sat_lo), 1e-6)
        t_sat_lo = _np.clip((luma - sat_lo) / denom_sat, 0.0, 1.0)
        t_sat_hi = _np.clip((sat_hi - luma) / denom_sat, 0.0, 1.0)
        gate_sat = (4.0 * t_sat_lo * t_sat_hi * sat_lift).astype(_np.float32)

        r_sat = _np.clip(r_warm + (r_warm - luma) * gate_sat, 0.0, 1.0)
        g_sat = _np.clip(g_warm + (g_warm - luma) * gate_sat, 0.0, 1.0)
        b_sat = _np.clip(b_warm + (b_warm - luma) * gate_sat, 0.0, 1.0)

        # ── Step 4: Dreamveil LF blend (Leonardesque soft edge dissolution) ───
        # Blend uniformly toward the low-frequency (smooth) version of each
        # channel, reducing HF edge amplitude without spatial scatter or
        # zone-specific targeting — Sodoma's gentle dreamlike surface quality.
        smooth_r = _gf(r_sat, sigma=veil_sigma)
        smooth_g = _gf(g_sat, sigma=veil_sigma)
        smooth_b = _gf(b_sat, sigma=veil_sigma)

        r_veiled = r_sat * (1.0 - veil_amount) + smooth_r * veil_amount
        g_veiled = g_sat * (1.0 - veil_amount) + smooth_g * veil_amount
        b_veiled = b_sat * (1.0 - veil_amount) + smooth_b * veil_amount

        # ── Step 5: Sky-blue highlight whisper ────────────────────────────────
        gate_sky = _np.clip(
            (luma - sky_lo) / max(1.0 - sky_lo, 1e-6), 0.0, 1.0
        ).astype(_np.float32)
        b_final = _np.clip(b_veiled + gate_sky * sky_b, 0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + r_veiled * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + g_veiled * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + b_final  * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Sodoma sienese dreamveil pass complete.")

    def specular_clarity_pass(
        self,
        clarity_lo:  float = 0.72,   # luminance floor for specular highlight zone
        sigma:       float = 1.0,    # Gaussian sigma for USM high-frequency extraction
        usm_amount:  float = 0.20,   # USM sharpening strength in highlight zone
        cool_lo:     float = 0.82,   # luminance floor for very-brightest cool-pearl zone
        cool_b:      float = 0.018,  # B boost in very-brightest peak highlights
        cool_r:      float = 0.012,  # R reduction in very-brightest peak highlights
        opacity:     float = 0.28,
    ) -> None:
        """Refine specular highlights as focused point-source light (twenty-sixth mode).

        In Old Master painting, the specular highlight — the bright catch-light
        on a forehead, the gleam on a nose ridge, the reflected light on a hand
        — is not merely the brightest region of the flesh tone.  It is a qualitatively
        different phenomenon: focused specular reflection from a point light source
        (typically a single north-facing window or a carefully positioned lamp).

        This distinction is visible in Vermeer, Velázquez, and the best Flemish
        masters: their specular highlights have a precise, slightly sharper edge
        than the surrounding broad flesh illumination, and the very brightest
        peak is often marginally cooler than the warm flesh tone — as if a pure
        white light source (cooler than the warm ambient) is being reflected
        from the most convex surface point.

        This pass encodes that quality as the twenty-sixth distinct processing
        mode: BRIGHT-ZONE USM SHARPENING + VERY-BRIGHTEST COOL-PEARL PEAK.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Specular highlight gate: smooth ramp for pixels above clarity_lo
            gate_clarity = clip((luma − clarity_lo) / (1 − clarity_lo), 0, 1)
            → peaks at 1 for the brightest highlights, 0 below threshold
        (3) USM sharpening in specular zone:
            per channel: hf_ch = ch − Gaussian(ch, sigma)
            ch_sharp = clip(ch + gate_clarity × usm_amount × hf_ch, 0, 1)
            → sharpens the specular highlight edges, making them read as
              focused point-source reflections rather than broad illumination
        (4) Very-brightest cool-pearl peak (Vermeer specular quality):
            gate_cool = clip((luma − cool_lo) / (1 − cool_lo), 0, 1)
            R_final = clip(R_sharp − gate_cool × cool_r, 0, 1)
            B_final = clip(B_sharp + gate_cool × cool_b, 0, 1)
            → the absolute peak highlights receive a barely perceptible
              cool-pearl cast — the colour of pure white window light
              reflected from the most convex surface
        (5) Composite at opacity.

        Twenty-sixth distinct mode: bright-zone USM sharpening + cool-pearl peak.
        Distinct from Gossaert (three-stratum with cool-pearl): Gossaert applies
          uniform cool-pearl desaturation + blue boost to all highlights above
          highlight_lo; specular_clarity adds USM SHARPENING of point sources AND
          cools only the very brightest peak (cool_lo > highlight_lo), without
          touching mid-luminance strata.
        Distinct from Magnasco (dark-zone scattered bright peaks): Magnasco targets
          dark-zone bright HF peaks via spatial scatter; this pass targets only
          the bright zone without scatter or dark gating.
        Distinct from Crivelli (gold-leaf gilding): Crivelli WARMS highlights by
          adding specular gold; this pass slightly COOLS the very brightest peak
          and sharpens the specular focus.
        Distinct from Cambiaso (zone boundary USM): Cambiaso applies USM at coarse
          TONAL-ZONE BOUNDARIES throughout the full luminance range; this pass
          applies USM only within bright highlight pixels (above clarity_lo) to
          sharpen specular focus.
        Distinct from sodoma_sienese_dreamveil_pass (LF softening): Sodoma blends
          TOWARD smooth LF structure (softening); this pass sharpens (USM adds HF).

        Args:
            clarity_lo  : Luminance floor for specular highlight zone.
            sigma       : Gaussian sigma for USM high-frequency extraction.
            usm_amount  : USM sharpening strength in the specular highlight zone.
            cool_lo     : Luminance floor for very-brightest cool-pearl peak zone.
            cool_b      : B channel boost in very-brightest peak (cool-pearl).
            cool_r      : R channel reduction in very-brightest peak.
            opacity     : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Specular highlight gate ───────────────────────────────────
        gate_clarity = _np.clip(
            (luma - clarity_lo) / max(1.0 - clarity_lo, 1e-6), 0.0, 1.0
        ).astype(_np.float32)

        # ── Step 3: USM sharpening in specular zone ───────────────────────────
        hf_r = r0 - _gf(r0, sigma=sigma)
        hf_g = g0 - _gf(g0, sigma=sigma)
        hf_b = b0 - _gf(b0, sigma=sigma)

        r_sharp = _np.clip(r0 + gate_clarity * usm_amount * hf_r, 0.0, 1.0)
        g_sharp = _np.clip(g0 + gate_clarity * usm_amount * hf_g, 0.0, 1.0)
        b_sharp = _np.clip(b0 + gate_clarity * usm_amount * hf_b, 0.0, 1.0)

        # ── Step 4: Very-brightest cool-pearl peak ────────────────────────────
        gate_cool = _np.clip(
            (luma - cool_lo) / max(1.0 - cool_lo, 1e-6), 0.0, 1.0
        ).astype(_np.float32)
        r_final = _np.clip(r_sharp - gate_cool * cool_r, 0.0, 1.0)
        g_final = g_sharp  # green unchanged
        b_final = _np.clip(b_sharp + gate_cool * cool_b, 0.0, 1.0)

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + r_final * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + g_final * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + b_final * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Specular clarity pass complete.")

    def bordone_venetian_warmth_pass(
        self,
        deepen_amount: float = 0.12,   # chromatic deepening strength in midtone zone
        warm_r:        float = 0.025,  # R boost in midtone zone (warm amber flush)
        warm_g:        float = 0.012,  # G boost in midtone zone (warm amber flush)
        opacity:       float = 0.35,
    ) -> None:
        """Parabolic midtone chromatic deepening (twenty-seventh distinct mode).

        Paris Bordone's defining quality is an intimate chromatic richness in the
        midtone flesh zone — a warm amber-gold glow that goes beyond even Titian's
        coloring in sensuous intensity.  This arises from two phenomena working
        together in the Venetian multi-glaze tradition: (1) warm umber imprimatura
        influencing the midtone register; (2) the intrinsic Venetian practice of
        moving flesh tones away from neutral grey — making warm flesh read warmer
        and cool shadow read cooler — a chromatic deepening operation.

        This pass encodes both phenomena as the twenty-seventh distinct processing
        mode: PARABOLIC MIDTONE CHROMATIC DEEPENING.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Parabolic midtone gate:
            w = 4 × luma × (1 − luma)
            → w = 0 at luma=0 (black) and luma=1 (white)
            → w = 1 at luma=0.5 (mid-grey)
            → peaks exactly at the midtone zone; shadows and highlights unaffected
        (3) Chromatic deepening in midtone zone:
            per channel: ch_deep = clip(ch + (ch − luma) × deepen_amount × w, 0, 1)
            → moves each channel away from the per-pixel luminance mean, proportional
              to both distance from neutral and gate weight
            → increases local chroma/saturation in midtones without blowing out
              highlights or graying shadows
        (4) Warm tint in midtone zone:
            R_tinted = clip(R_deep + warm_r × w, 0, 1)
            G_tinted = clip(G_deep + warm_g × w, 0, 1)
            → adds characteristic warm amber-gold Venetian flesh flush in midtones
        (5) Composite at opacity.

        Twenty-seventh distinct mode: parabolic midtone chromatic deepening.
        Distinct from sodoma_sienese_dreamveil_pass (smooth bump gate targeting
          warm_lo–warm_hi with LF dreamveil softening): Bordone uses parabolic
          gate targeting luma=0.5 peak with no LF blur component.
        Distinct from palma_vecchio (Gaussian-gated warm bloom targeting upper
          midtones luma>bloom_lo): Bordone's parabolic gate is symmetric around
          luma=0.5 and adds chromatic deepening alongside the warm tint.
        Distinct from Giorgione (dual-temperature sculpting from Gaussian spatial
          focal warmth): Bordone operates uniformly across the image in luminance
          space, not in spatial focal zones.
        Distinct from Gossaert (three discrete strata — shadow/midtone/highlight
          with per-stratum treatment): Bordone uses a continuously varying parabolic
          weight with no stratum discontinuities.

        Args:
            deepen_amount : Chromatic deepening strength — how far each channel
                            is pushed away from luminance in the midtone zone.
            warm_r        : R channel boost in the midtone zone (amber flush).
            warm_g        : G channel boost in the midtone zone (amber flush).
            opacity       : Global composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Parabolic midtone gate ────────────────────────────────────
        # w = 4 * luma * (1 - luma): peaks at 1.0 when luma=0.5, zero at extremes
        w = (4.0 * luma * (1.0 - luma)).astype(_np.float32)

        # ── Step 3: Chromatic deepening ───────────────────────────────────────
        # Push each channel away from luma proportional to gate weight
        r_deep = _np.clip(r0 + (r0 - luma) * deepen_amount * w, 0.0, 1.0)
        g_deep = _np.clip(g0 + (g0 - luma) * deepen_amount * w, 0.0, 1.0)
        b_deep = _np.clip(b0 + (b0 - luma) * deepen_amount * w, 0.0, 1.0)

        # ── Step 4: Warm tint in midtone zone ────────────────────────────────
        r_warm = _np.clip(r_deep + warm_r * w, 0.0, 1.0)
        g_warm = _np.clip(g_deep + warm_g * w, 0.0, 1.0)
        b_warm = b_deep  # blue untouched — warm tint comes from R/G boost only

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + r_warm * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + g_warm * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + b_warm * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Bordone Venetian warmth pass complete.")

    def luminous_ground_pass(
        self,
        ground_r:      float = 0.48,   # warm ground color R (umber imprimatura)
        ground_g:      float = 0.35,   # warm ground color G
        ground_b:      float = 0.20,   # warm ground color B
        ground_hi:     float = 0.40,   # luminance ceiling — above this, no ground glow
        ground_amount: float = 0.18,   # blend strength toward ground color
        gamma_ground:  float = 2.0,    # cubic falloff power — concentrates glow in darkest zones
        opacity:       float = 0.30,
    ) -> None:
        """Simulate warm imprimatura glowing through dark paint layers (artistic improvement).

        In oil painting on a toned ground, thin dark passages never achieve true
        neutrality — the warm umber or sienna imprimatura glows through, giving
        shadows a characteristic warm amber undertone.  This is most visible in
        Venetian, Flemish, and Roman Baroque painting where the ground is a rich
        warm brown.  Vermeer, Velázquez, Rembrandt, and the Venetians all exploit
        this: their darkest passages are never dead grey or cold black, but retain
        a warm amber-brown presence from the imprimatura layer beneath.

        This pass encodes that luminous-ground phenomenon as a standalone artistic
        improvement: CUBIC-FALLOFF IMPRIMATURA WARMTH IN DARK ZONES.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Shadow gate with cubic falloff:
            normalized = clip(1 - luma / ground_hi, 0, 1)
            gate_ground = normalized ^ gamma_ground
            → 1 at luma=0 (absolute black), falls as gamma-th power toward 0 at luma=ground_hi
            → concentrates the ground warmth in the darkest zones (gamma=2 → quadratic)
        (3) Blend toward warm ground color in gated dark zone:
            R_out = R + (ground_r − R) × gate_ground × ground_amount
            G_out = G + (ground_g − G) × gate_ground × ground_amount
            B_out = B + (ground_b − B) × gate_ground × ground_amount
        (4) Composite at opacity.

        This is distinct from shadow_transparency_pass (injects cool violet into
        shadows) — luminous_ground_pass injects warm ground amber.
        Distinct from cambiaso_geometric_planes_pass (terra tint is one of five
        operations, uses smooth bump gate, very low amount=0.07) — this is a
        dedicated high-gain cubic-falloff ground-glow pass.
        Distinct from sodoma_sienese_dreamveil_pass (smooth bump gate in midtones,
        adds LF blur) — this targets the dark zone, not midtones, with no blur.
        Distinct from magnasco_nervous_brilliance_pass (HF scatter in dark zones,
        warm tint only on scattered peaks) — this blends the FULL tonal range of
        dark pixels toward the ground color, not just scattered HF peaks.

        Args:
            ground_r      : Red component of the warm ground color.
            ground_g      : Green component of the warm ground color.
            ground_b      : Blue component of the warm ground color.
            ground_hi     : Luminance ceiling — ground glow drops to zero above this.
            ground_amount : Blend fraction toward ground color at gate=1 (luma=0).
            gamma_ground  : Falloff power — higher = more concentrated in darkest pixels.
            opacity       : Global composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Cubic-falloff shadow gate ─────────────────────────────────
        normalized = _np.clip(1.0 - luma / max(ground_hi, 1e-6), 0.0, 1.0)
        gate_ground = (normalized ** gamma_ground).astype(_np.float32)

        # ── Step 3: Blend toward warm ground color ────────────────────────────
        blend = gate_ground * ground_amount
        r_out = _np.clip(r0 + (ground_r - r0) * blend, 0.0, 1.0)
        g_out = _np.clip(g0 + (ground_g - g0) * blend, 0.0, 1.0)
        b_out = _np.clip(b0 + (ground_b - b0) * blend, 0.0, 1.0)

        # ── Step 4: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + r_out * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + g_out * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + b_out * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Luminous ground pass complete.")

    def romanino_brescian_impasto_pass(
        self,
        sigma:           float = 1.0,   # Gaussian sigma for smoothed luma height field
        relief_scale:    float = 20.0,  # amplification of gradient → gate [0,1]
        impasto_warm_r:  float = 0.06,  # R boost on lit impasto ridges (warm ochre light)
        impasto_warm_g:  float = 0.030, # G boost on lit ridges (amber light)
        shadow_b:        float = 0.035, # B boost on shadowed valleys (cool recession)
        shadow_r:        float = 0.015, # R reduction on shadowed valleys
        opacity:         float = 0.35,
    ) -> None:
        """Simulate Romanino's bold Brescian impasto via oblique-light height-field (29th mode).

        Girolamo Romanino (c. 1484–1562) was the most physically expressive
        painter of the Brescian school.  Where his contemporary Moretto da
        Brescia sought silvery tonal refinement, Romanino attacked the surface
        with loaded brushes, building visible ridges of pigment that catch
        raking light as three-dimensional relief.  His impasto is structural,
        not decorative: ridges follow the form of drapery folds, the arc of
        a muscle, the weight of a falling garment.  The effect — best seen in
        the Cremona Cathedral frescoes (1519–1520) and the Palazzo della Loggia
        cycles — is a physical vitality unique in Italian Renaissance painting.

        This pass encodes that quality as the TWENTY-NINTH DISTINCT PROCESSING
        MODE: HEIGHT-FIELD OBLIQUE-LIGHT IMPASTO SIMULATION.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Height field: smooth_luma = Gaussian(luma, sigma)
            The smoothed luminance serves as a proxy for the local paint
            elevation: bright regions tend to have more raised paint
            (the dense, loaded brush deposits more pigment at peaks).
        (3) Spatial gradient of height field:
            gy, gx = np.gradient(smooth_luma)
            gx = ∂h/∂x (positive = surface rises going right)
            gy = ∂h/∂y (positive = surface rises going down)
        (4) Oblique-light illumination from upper-left:
            Surface normal N ≈ (−gx, −gy, 1) [z = out of canvas]
            Light direction L = (1, 1, 0)/√2 [from upper-left toward canvas]
            Illumination ∝ N · L = (−gx − gy) / √2
            Scale by relief_scale then clip to [−1, 1]:
            light = (−(gx + gy)) × relief_scale
            gate_high   = clip(light, 0, 1)   — lit ridges (facing upper-left)
            gate_shadow = clip(−light, 0, 1)  — shadowed valleys (facing away)
        (5) Apply directional colour tints:
            R_out = R + gate_high × impasto_warm_r − gate_shadow × shadow_r
            G_out = G + gate_high × impasto_warm_g
            B_out = B + gate_shadow × shadow_b
            All clipped to [0, 1].
        (6) Composite at opacity.

        Twenty-ninth distinct mode: height-field oblique-light impasto simulation.
        Distinct from gossaert_pearl_crystalline_pass (luminance striation; no
          spatial gradient; no directional light): Romanino uses gradient-based
          3D-relief simulation across the full spatial frequency spectrum, while
          Gossaert classifies into discrete luminance strata.
        Distinct from cossa_enamel_structure_pass (gem-zone chroma + USM
          clarity): Romanino's gradient gives asymmetric warm/cool tint based
          on local surface slope direction, not a symmetric chroma boost.
        Distinct from cambiaso_geometric_planes_pass (zone flattening + boundary
          clarification): Romanino emphasises the three-dimensional relief
          within each plane, Cambiaso suppresses it.
        Distinct from magnasco_nervous_brilliance_pass (scattered HF peaks warm-
          tinted in dark zones): Romanino uses the gradient of the full image
          as a directional height field; Magnasco rolls scattered HF copies.
        Distinct from specular_clarity_pass (USM in highlight zone only): Romanino
          operates on the gradient of smoothed luma across the full luminance
          range, giving relief to shadows as well as highlights.

        Args:
            sigma           : Gaussian sigma for smoothed height-field estimation.
            relief_scale    : Gradient amplification → controls impasto depth
                              (larger = deeper apparent relief).
            impasto_warm_r  : R boost on lit impasto ridges (warm ochre light).
            impasto_warm_g  : G boost on lit ridges (amber component).
            shadow_b        : B boost on shadowed valleys (cool atmospheric recession).
            shadow_r        : R reduction on shadowed valleys.
            opacity         : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Smoothed height field ─────────────────────────────────────
        height = _gf(luma, sigma=sigma).astype(_np.float32)

        # ── Step 3: Spatial gradient of height field ──────────────────────────
        gy, gx = _np.gradient(height)
        gx = gx.astype(_np.float32)
        gy = gy.astype(_np.float32)

        # ── Step 4: Oblique-light illumination from upper-left ────────────────
        # N · L ∝ −(gx + gy); scale and clip to [−1, 1] for gate
        light = (-(gx + gy) * relief_scale).astype(_np.float32)
        gate_high   = _np.clip(light,  0.0, 1.0)   # lit ridges
        gate_shadow = _np.clip(-light, 0.0, 1.0)   # shadowed valleys

        # ── Step 5: Directional colour tints ──────────────────────────────────
        r_out = _np.clip(r0 + gate_high * impasto_warm_r - gate_shadow * shadow_r, 0.0, 1.0)
        g_out = _np.clip(g0 + gate_high * impasto_warm_g,                          0.0, 1.0)
        b_out = _np.clip(b0 + gate_shadow * shadow_b,                              0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + r_out * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + g_out * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + b_out * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Romanino Brescian impasto pass complete.")

    def highlight_velatura_pass(
        self,
        vel_lo:           float = 0.58,  # lower luminance edge of velatura zone
        vel_hi:           float = 0.92,  # upper luminance edge of velatura zone
        glaze_r:          float = 0.88,  # warm amber glaze tint R
        glaze_g:          float = 0.68,  # warm amber glaze tint G
        glaze_b:          float = 0.28,  # warm amber glaze tint B
        vel_amount:       float = 0.12,  # fraction blended toward glaze color
        contrast_amount:  float = 0.07,  # contrast softening within velatura zone
        sigma:            float = 0.8,   # Gaussian sigma for contrast softening
        opacity:          float = 0.25,
    ) -> None:
        """Simulate the optical depth of a transparent oil-glaze veil in the highlight zone.

        In the Venetian multi-layer oil-painting tradition — and in the practice
        of the great Central Italian masters (Raphael, Perugino, Correggio) —
        "velatura" (Italian: glazing, veiling) refers to the application of a
        thin, lean, semi-transparent layer of pigment over a fully dried passage.
        Unlike imprimatura (the initial ground) or scumbling (dragging opaque
        paint), velatura is transparent: it does not cover the layer beneath but
        tints it chromatically while allowing its luminosity to show through.

        The visual effect of a warm amber velatura over a pale highlight zone is:
          •  Colour enrichment: the warm tint combines optically with the
             underlying cool or neutral highlight, shifting it toward a golden
             amber that reads as "warm light" rather than "white paint".
          •  Optical depth: the transparent glaze layer adds perceived depth —
             the highlight now appears luminous rather than flat or chalky.
          •  Slight contrast reduction: thin overlapping layers of glazing
             smooth micro-transitions in the highlight zone, giving the
             characteristic seamless continuity of velatura passages.

        This pass encodes those effects as an ARTISTIC IMPROVEMENT: TRANSPARENT
        OIL-GLAZE VEIL IN THE UPPER-MIDTONE / HIGHLIGHT ZONE.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Velatura gate — smooth bump in [vel_lo, vel_hi]:
            mid_vel = (vel_lo + vel_hi) / 2
            t_lo = clip((luma − vel_lo) / (mid_vel − vel_lo), 0, 1)
            t_hi = clip((vel_hi − luma) / (vel_hi − mid_vel), 0, 1)
            gate_vel = t_lo × t_hi          [peaks at 1 when luma = mid_vel]
        (3) Blend toward warm amber glaze color in velatura zone:
            ch_vel = ch + (glaze_ch − ch) × gate_vel × vel_amount
            → this is a partial blend toward the glaze tint, proportional
              to how deeply the pixel sits within the velatura gate zone
        (4) Contrast softening within velatura zone:
            smooth_ch = Gaussian(ch_vel, sigma)
            ch_soft = ch_vel − (ch_vel − smooth_ch) × gate_vel × contrast_amount
            → subtracts a fraction of the HF residual in the gate zone,
              reducing micro-contrast without globally blurring
        (5) Composite at opacity.

        Distinct from luminous_ground_pass (targets luma < ground_hi ≈ 0.40 dark
          zone, injects warm umber ground glow): highlight_velatura_pass targets
          luma [vel_lo=0.58, vel_hi=0.92] — the upper-midtone / highlight zone.
        Distinct from velatura_pass (classic Old Master midtone velatura in the
          [0.28, 0.72] zone with luma-preserved blending): highlight_velatura_pass
          targets only the upper-midtone / highlight zone with contrast softening.
        Distinct from bordone_venetian_warmth_pass (parabolic gate peaking at
          luma=0.5): highlight_velatura_pass's smooth-bump gate peaks at
          mid_vel ≈ 0.75, acting in the highlight zone Bordone's gate avoids.
        Distinct from sodoma_sienese_dreamveil_pass (smooth bump in [0.38,0.72] +
          global LF Gaussian): highlight_velatura_pass targets a higher luminance
          zone and uses only local per-zone contrast softening, not global LF blur.
        Distinct from palma_vecchio blonde_luminance_pass (warm Gaussian-gated bloom
          on upper midtones): palma uses a multiplicative saturation-and-warm boost
          without the glaze-blend logic or contrast softening of this pass.

        Args:
            vel_lo/hi      : Luminance range of the velatura gate zone.
            glaze_r/g/b    : Colour of the warm amber transparent glaze.
            vel_amount     : Blend fraction toward glaze color at peak gate.
            contrast_amount: Fraction of HF detail removed by velatura veil.
            sigma          : Gaussian sigma for the contrast-softening step.
            opacity        : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Velatura gate — smooth bump in [vel_lo, vel_hi] ──────────
        mid_vel = (vel_lo + vel_hi) * 0.5
        denom_lo = max(float(mid_vel - vel_lo), 1e-6)
        denom_hi = max(float(vel_hi - mid_vel), 1e-6)
        t_lo = _np.clip((luma - vel_lo) / denom_lo, 0.0, 1.0)
        t_hi = _np.clip((vel_hi - luma) / denom_hi, 0.0, 1.0)
        gate_vel = (t_lo * t_hi).astype(_np.float32)

        # ── Step 3: Blend toward warm glaze colour ────────────────────────────
        blend = gate_vel * vel_amount
        r_vel = _np.clip(r0 + (glaze_r - r0) * blend, 0.0, 1.0)
        g_vel = _np.clip(g0 + (glaze_g - g0) * blend, 0.0, 1.0)
        b_vel = _np.clip(b0 + (glaze_b - b0) * blend, 0.0, 1.0)

        # ── Step 4: Contrast softening within velatura zone ───────────────────
        # Subtract a fraction of the HF residual (ch - smooth_ch) in the gate zone
        smooth_r = _gf(r_vel, sigma=sigma)
        smooth_g = _gf(g_vel, sigma=sigma)
        smooth_b = _gf(b_vel, sigma=sigma)
        soften = gate_vel * contrast_amount
        r_soft = _np.clip(r_vel - (r_vel - smooth_r) * soften, 0.0, 1.0)
        g_soft = _np.clip(g_vel - (g_vel - smooth_g) * soften, 0.0, 1.0)
        b_soft = _np.clip(b_vel - (b_vel - smooth_b) * soften, 0.0, 1.0)

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + r_soft * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + g_soft * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + b_soft * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Highlight velatura pass complete.")

    def beccafumi_nacreous_glow_pass(
        self,
        sigma_bloom:    float = 4.0,   # Gaussian sigma for bloom blur
        glow_lo:        float = 0.28,  # lower luminance edge of mid-zone gate
        glow_hi:        float = 0.78,  # upper luminance edge of mid-zone gate
        glow_warm_r:    float = 0.055, # warm tint R added to positive bloom diff
        glow_warm_g:    float = 0.032, # warm tint G added to positive bloom diff
        glow_cool_b:    float = 0.040, # cool tint B added to negative bloom diff
        glow_cool_r:    float = 0.018, # cool tint R reduced in negative bloom diff
        glow_strength:  float = 0.60,  # blend fraction for the tinted bloom diff
        opacity:        float = 0.32,
    ) -> None:
        """Signed Gaussian bloom difference with differential warm/cool midtone iridescence.

        Domenico Beccafumi (c. 1484–1551) is the supreme master of Sienese Mannerist
        Luminism — a style defined by NACREOUS IRIDESCENCE, the mother-of-pearl quality
        where warm yellows and pinks sit beside cool acid greens and purples in a way
        that shifts chromatically like opalescent light.  His characteristic internal
        luminosity of forms arises from his unusual technique of underlaying opaque
        white or grey before glazing acid colours over it, causing light to scatter
        upward through translucent pigment layers and produce a soft, glowing bloom
        around every figure.

        This pass encodes those effects as the THIRTIETH DISTINCT MODE:
        SIGNED GAUSSIAN BLOOM DIFFERENCE WITH DIFFERENTIAL WARM/COOL TINTING.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Mid-luminance gate — smooth bump in [glow_lo, glow_hi]:
            mid_g = (glow_lo + glow_hi) / 2
            t_lo = clip((luma − glow_lo) / (mid_g − glow_lo), 0, 1)
            t_hi = clip((glow_hi − luma) / (glow_hi − mid_g), 0, 1)
            gate_glow = t_lo × t_hi     [peaks at 1 when luma = mid_g]
        (3) Compute bloom: blurred_ch = Gaussian(ch, sigma_bloom) per channel
        (4) Signed bloom difference:
            bloom_diff_ch = blurred_ch − ch
            → positive where forms overflow into surrounding lighter areas (the halo)
            → negative where dark edges resist the bloom
        (5) Differential warm/cool tinting of the signed difference:
            warm bloom (positive diff):
              r_warm = r + clip(bloom_diff_r, 0, ∞) × glow_warm_r × glow_strength × gate_glow
              g_warm = g + clip(bloom_diff_g, 0, ∞) × glow_warm_g × glow_strength × gate_glow
            cool iridescence (negative diff — shadow-edge cool push):
              b_cool = b − clip(bloom_diff_b, −∞, 0) × glow_cool_b × glow_strength × gate_glow
              r_cool = r − clip(-bloom_diff_r, 0, ∞) × glow_cool_r × glow_strength × gate_glow
        (6) Composite at opacity.

        Distinct from palma_vecchio blonde_luminance_pass (multiplicative sat+warmth
          boost via Gaussian gate, no signed difference, no cool iridescence).
        Distinct from luminous_ground_pass (targets dark zones luma < ground_hi ≈ 0.40,
          no signed difference, no warm/cool axis split).
        Distinct from specular_clarity_pass (USM sharpening — subtracts blur, opposite
          direction; only brightest zone; no warm/cool signed split).
        Distinct from sodoma_sienese_dreamveil_pass (global LF Gaussian blend toward
          smooth version, no signed difference, no differential warm/cool tinting).
        Distinct from highlight_velatura_pass (targets highlights [0.58, 0.92] only,
          blends toward glaze color, no signed Gaussian difference or cool-shadow axis).

        Args:
            sigma_bloom   : Gaussian sigma for bloom blur — controls halo radius.
            glow_lo/hi    : Luminance range of the midtone iridescence gate.
            glow_warm_r/g : Warm tint channels added proportionally to positive bloom diff.
            glow_cool_b/r : Cool tint channels added/reduced proportionally to negative diff.
            glow_strength : Overall bloom difference blend fraction at peak gate.
            opacity       : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Mid-luminance gate — smooth bump in [glow_lo, glow_hi] ───
        mid_g = (glow_lo + glow_hi) * 0.5
        denom_lo = max(float(mid_g - glow_lo), 1e-6)
        denom_hi = max(float(glow_hi - mid_g), 1e-6)
        t_lo = _np.clip((luma - glow_lo) / denom_lo, 0.0, 1.0)
        t_hi = _np.clip((glow_hi - luma) / denom_hi, 0.0, 1.0)
        gate_glow = (t_lo * t_hi).astype(_np.float32)

        # ── Step 3: Bloom — Gaussian blur per channel ─────────────────────────
        r_bloom = _gf(r0, sigma=sigma_bloom).astype(_np.float32)
        g_bloom = _gf(g0, sigma=sigma_bloom).astype(_np.float32)
        b_bloom = _gf(b0, sigma=sigma_bloom).astype(_np.float32)

        # ── Step 4: Signed bloom difference ───────────────────────────────────
        diff_r = r_bloom - r0   # positive = bright halo zone, negative = dark edge
        diff_g = g_bloom - g0
        diff_b = b_bloom - b0

        # ── Step 5: Differential warm/cool tinting ────────────────────────────
        gs = gate_glow * glow_strength

        # Warm iridescence: positive bloom diff → warm amber nacreous overflow
        warm_r = _np.clip(diff_r, 0.0, 1.0) * glow_warm_r * gs
        warm_g = _np.clip(diff_g, 0.0, 1.0) * glow_warm_g * gs

        # Cool iridescence: negative bloom diff → cool violet shadow shimmer
        neg_r = _np.clip(-diff_r, 0.0, 1.0) * glow_cool_r * gs
        neg_b = _np.clip(-diff_b, 0.0, 1.0) * glow_cool_b * gs

        out_r = _np.clip(r0 + warm_r - neg_r, 0.0, 1.0)
        out_g = _np.clip(g0 + warm_g,         0.0, 1.0)
        out_b = _np.clip(b0 + neg_b,          0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Beccafumi nacreous glow pass complete.")

    def penumbra_softening_pass(
        self,
        pen_lo:        float = 0.18,  # lower luminance edge of penumbra zone
        pen_hi:        float = 0.52,  # upper luminance edge of penumbra zone
        pen_sigma:     float = 2.0,   # Gaussian sigma for shadow-edge smoothing
        soften_amount: float = 0.45,  # blend fraction from smoothed toward original at peak gate
        opacity:       float = 0.28,
    ) -> None:
        """Gradient-magnitude-weighted shadow-edge smoothing in the penumbra zone.

        In Renaissance oil painting the PENUMBRA — the transitional zone between
        illuminated surface and shadow — is the most carefully worked passage.
        Masters achieved seamless gradations there through patient accumulation of
        thin overlapping strokes that dissolved the boundary between light and dark.
        No hard edge survives: forms round into shadow through a zone that is both
        tonally and chromatically continuous.

        This pass encodes that quality as an ARTISTIC IMPROVEMENT: GRADIENT-MAGNITUDE-
        WEIGHTED SHADOW-EDGE SMOOTHING.  Unlike a global or zone-only blur, this pass
        gates its softening by BOTH the tonal position (shadow zone) AND the local
        edge strength (luminance gradient magnitude), targeting precisely the hard
        transitions within the shadow zone while leaving clean light passages and
        deep shadow voids undisturbed.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Penumbra zone gate — smooth bump in [pen_lo, pen_hi]:
            mid_p = (pen_lo + pen_hi) / 2
            t_lo = clip((luma − pen_lo) / (mid_p − pen_lo), 0, 1)
            t_hi = clip((pen_hi − luma) / (pen_hi − mid_p), 0, 1)
            gate_pen = t_lo × t_hi
        (3) Gradient magnitude:
            gx, gy = np.gradient(luma)
            grad_mag = sqrt(gx² + gy²)
            norm_grad = clip(grad_mag / max_grad, 0, 1)  where max_grad = grad_mag.max() + ε
        (4) Shadow edge gate:
            shadow_edge = gate_pen × norm_grad
            → peaks where luma is in the penumbra zone AND the local edge is strong
        (5) Smoothed channels: smooth_ch = Gaussian(ch, sigma=pen_sigma)
        (6) Soft-blend toward smoothed in edge zone:
            ch_soft = ch × (1 − shadow_edge × soften_amount)
                    + smooth_ch × shadow_edge × soften_amount
            → hard edges in the penumbra zone are blended toward their smooth version;
              pixels not in the zone or without strong gradients are unchanged
        (7) Composite at opacity.

        Distinct from highlight_velatura_pass (targets highlights [0.58, 0.92], no
          gradient gating, purpose is glaze depth not shadow-edge smoothing).
        Distinct from romanino_brescian_impasto_pass (gradient → oblique-light relief
          simulation, adds warm/cool difference; not a softening of transitions).
        Distinct from sebastiano_del_piombo coherence_smooth_pass (structure tensor
          coherence — anisotropic diffusion along edge orientation; global application
          not gated to shadow zone × gradient strength).
        Distinct from jacopo_bassano anisotropic_diffusion_pass (Perona-Malik PDE,
          edge-preserving diffusion, global not zone-gated).

        Args:
            pen_lo/hi     : Luminance range of the penumbra zone gate.
            pen_sigma     : Gaussian sigma for the shadow-edge smoothing step.
            soften_amount : Blend fraction toward smoothed at peak shadow_edge gate.
            opacity       : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Penumbra zone gate — smooth bump in [pen_lo, pen_hi] ──────
        mid_p = (pen_lo + pen_hi) * 0.5
        denom_lo = max(float(mid_p - pen_lo), 1e-6)
        denom_hi = max(float(pen_hi - mid_p), 1e-6)
        t_lo = _np.clip((luma - pen_lo) / denom_lo, 0.0, 1.0)
        t_hi = _np.clip((pen_hi - luma) / denom_hi, 0.0, 1.0)
        gate_pen = (t_lo * t_hi).astype(_np.float32)

        # ── Step 3: Gradient magnitude ────────────────────────────────────────
        gx, gy = _np.gradient(luma)
        grad_mag = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)
        max_grad = float(grad_mag.max()) + 1e-6
        norm_grad = _np.clip(grad_mag / max_grad, 0.0, 1.0)

        # ── Step 4: Shadow edge gate ───────────────────────────────────────────
        shadow_edge = (gate_pen * norm_grad).astype(_np.float32)

        # ── Step 5: Smoothed channels ─────────────────────────────────────────
        smooth_r = _gf(r0, sigma=pen_sigma).astype(_np.float32)
        smooth_g = _gf(g0, sigma=pen_sigma).astype(_np.float32)
        smooth_b = _gf(b0, sigma=pen_sigma).astype(_np.float32)

        # ── Step 6: Blend toward smoothed in shadow edge zone ─────────────────
        blend = shadow_edge * soften_amount
        r_soft = _np.clip(r0 * (1.0 - blend) + smooth_r * blend, 0.0, 1.0)
        g_soft = _np.clip(g0 * (1.0 - blend) + smooth_g * blend, 0.0, 1.0)
        b_soft = _np.clip(b0 * (1.0 - blend) + smooth_b * blend, 0.0, 1.0)

        # ── Step 7: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + r_soft * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + g_soft * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + b_soft * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Penumbra softening pass complete.")

    def gaudenzio_warm_devotion_pass(
        self,
        shad_lo:       float = 0.05,  # lower luminance edge of shadow/penumbra gate
        shad_hi:       float = 0.42,  # upper luminance edge of shadow/penumbra gate
        warm_r:        float = 0.038, # warm amber R tint added in shadow zone
        warm_g:        float = 0.022, # warm amber G tint added in shadow zone
        warm_b:        float = 0.010, # slight blue reduction (warm shadows, not cool)
        warm_strength: float = 0.55,  # gate × this = blend amount at peak
        opacity:       float = 0.30,
    ) -> None:
        """Shadow-zone warm amber luminosity scumble — Gaudenzio Ferrari's devotional inner light.

        Gaudenzio Ferrari (c. 1477–1546), the supreme master of Piedmontese Devotional
        Luminism, is distinguished from all other Italian Renaissance painters by a
        single quality: his SHADOW ZONES ARE WARM.  Where Leonardo's sfumato leaves
        shadows cool and remote, where Raphael's clarità keeps shadows neutral and
        luminous, Ferrari floods his penumbra and shadow regions with warm amber glow —
        the inner fire of the saints he painted made physically visible in the paint.

        This effect is not a highlight bloom (which targets bright zones) and not a
        sfumato edge dissolve (which targets contours): it is a gentle AMBER SCUMBLE
        that lays warm luminosity across the shadow zone while leaving the lit surface
        and the deepest voids unchanged, simulating how Ferrari's warm amber underpaint
        bleeds upward through the glazes in dark passages.

        This pass encodes those effects as the THIRTY-FIRST DISTINCT MODE:
        SHADOW-ZONE WARM AMBER LUMINOSITY SCUMBLE.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Shadow/penumbra gate — smooth bump in [shad_lo, shad_hi]:
            mid_s = (shad_lo + shad_hi) / 2
            t_lo = clip((luma − shad_lo) / (mid_s − shad_lo), 0, 1)
            t_hi = clip((shad_hi − luma) / (shad_hi − mid_s), 0, 1)
            gate_shad = t_lo × t_hi   [peaks at 1 when luma = mid_s]
        (3) Apply warm amber tint weighted by gate × warm_strength:
            wt = gate_shad × warm_strength
            out_r = clip(r + warm_r × wt, 0, 1)
            out_g = clip(g + warm_g × wt, 0, 1)
            out_b = clip(b − warm_b × wt, 0, 1)   [slight blue reduction = warmer shadow]
        (4) Composite at opacity.

        Distinct from beccafumi_nacreous_glow_pass (targets midtones [0.28, 0.78],
          signed Gaussian bloom difference, warm AND cool split — iridescence not warmth).
        Distinct from luminous_ground_pass (targets dark zone luma < ground_hi ≈ 0.40,
          but adds warm ground glow uniformly; no smooth bump gate, no R/G/B warm tint).
        Distinct from highlight_velatura_pass (targets highlights [0.58, 0.92], blends
          toward a glaze colour — opposite tonal zone).
        Distinct from glazing_depth_pass (adds overall warm glaze to ALL tones by
          multiplicative tinting, not shadow-zone gated).

        Args:
            shad_lo/hi    : Luminance range of the shadow/penumbra gate.
            warm_r/g/b    : Warm tint channels added (R,G) or reduced (B) in shadow zone.
            warm_strength : Gate scale factor (gate × warm_strength = blend amount at peak).
            opacity       : Global composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Shadow/penumbra gate — smooth bump in [shad_lo, shad_hi] ──
        mid_s = (shad_lo + shad_hi) * 0.5
        denom_lo = max(float(mid_s - shad_lo), 1e-6)
        denom_hi = max(float(shad_hi - mid_s), 1e-6)
        t_lo = _np.clip((luma - shad_lo) / denom_lo, 0.0, 1.0)
        t_hi = _np.clip((shad_hi - luma) / denom_hi, 0.0, 1.0)
        gate_shad = (t_lo * t_hi).astype(_np.float32)

        # ── Step 3: Warm amber tint in shadow zone ────────────────────────────
        wt = gate_shad * warm_strength
        out_r = _np.clip(r0 + warm_r * wt, 0.0, 1.0)
        out_g = _np.clip(g0 + warm_g * wt, 0.0, 1.0)
        out_b = _np.clip(b0 - warm_b * wt, 0.0, 1.0)

        # ── Step 4: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Gaudenzio warm devotion pass complete.")

    def atmospheric_depth_gradient_pass(
        self,
        atm_warm_r:  float = 0.025, # warm amber R added to lower-canvas foreground
        atm_warm_g:  float = 0.014, # warm amber G added to lower-canvas foreground
        atm_cool_b:  float = 0.028, # cool blue-grey B added to upper-canvas background
        atm_cool_r:  float = 0.012, # cool R reduction in upper-canvas background
        luma_lo:     float = 0.12,  # luminance threshold: pixels darker than this are excluded
        opacity:     float = 0.28,
    ) -> None:
        """Vertical chromatic temperature gradient for atmospheric depth recession.

        Leonardo da Vinci's sfumato encompasses not only the dissolution of edges but
        also ATMOSPHERIC PERSPECTIVE: the systematic warming of foreground colours and
        cooling of background colours as aerial haze increases with depth.  In the
        Mona Lisa this is most visible in the landscape behind the figure — the warm
        ochre rocks and earth colours in the foreground give way to increasingly cool
        blue-grey atmospheric haze as the terrain recedes toward the horizon.

        This pass encodes that quality as an ARTISTIC IMPROVEMENT: LUMINANCE-WEIGHTED
        VERTICAL CHROMATIC TEMPERATURE GRADIENT.  A vertical position weight
        (v_warm = 1 − y_frac, strongest at bottom; v_cool = y_frac, strongest at top)
        drives opposing warm and cool chromatic pushes, simulating the depth gradient
        across the full canvas height while excluding pixels too dark to carry colour.

        Algorithm:
        (1) Build vertical fraction array: y_frac = row_index / (H − 1), shape (H, W)
            v_warm = y_frac       [0.0 at top row, 1.0 at bottom — canvas y=0 is top]
            v_cool = 1 − y_frac   [1.0 at top, 0.0 at bottom]
            Note: canvas row 0 = image top; bottom of canvas is foreground in portraits.
            v_warm peaks at BOTTOM (foreground / figure base) — warm ochre earth tones.
            v_cool peaks at TOP (sky / background horizon) — cool atmospheric haze.
        (2) Compute luminance gate: luma_gate = clip((luma − luma_lo) / 0.15, 0, 1)
            Excludes near-black pixels (deep shadow voids) from the colour push.
        (3) Warm foreground push (lower canvas = figure base, near earth):
            wt_warm = v_warm × luma_gate    [strongest at bottom, excluded in deep shadow]
            out_r = clip(r + atm_warm_r × wt_warm, 0, 1)
            out_g = clip(g + atm_warm_g × wt_warm, 0, 1)
        (4) Cool background push (upper canvas = sky, distant landscape):
            wt_cool = v_cool × luma_gate    [strongest at top, excluded in deep shadow]
            out_b = clip(b + atm_cool_b × wt_cool, 0, 1)
            out_r = clip(out_r − atm_cool_r × wt_cool, 0, 1)   [desaturate/cool red at top]
        (5) Composite at opacity.

        Distinct from gaudenzio_warm_devotion_pass (shadow-zone gate, no vertical
          position axis, amber scumble not atmospheric perspective).
        Distinct from luminous_ground_pass (dark-zone gate, no vertical gradient,
          warm glow only — no cool background axis).
        Distinct from beccafumi_nacreous_glow_pass (midtone gate, signed Gaussian
          bloom difference, no spatial vertical gradient).
        Distinct from sodoma_sienese_dreamveil_pass (global LF Gaussian blend, no
          vertical gradient, no warm/cool spatial axis).

        Args:
            atm_warm_r/g : Warm tint channels added to lower (foreground) canvas zone.
            atm_cool_b   : Cool blue-grey tint added to upper (background/sky) canvas zone.
            atm_cool_r   : Red reduction in upper canvas zone (desaturates toward grey-blue).
            luma_lo      : Luminance threshold below which pixels are excluded.
            opacity      : Global composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Vertical position weights ────────────────────────────────
        rows = _np.linspace(0.0, 1.0, self.h, dtype=_np.float32)   # 0=top, 1=bottom
        y_frac = rows[:, _np.newaxis] * _np.ones((1, self.w), dtype=_np.float32)
        v_warm = y_frac          # warm push peaks at BOTTOM (foreground/figure base)
        v_cool = 1.0 - y_frac   # cool push peaks at TOP (sky/background horizon)

        # ── Step 3: Luminance gate (exclude near-black pixels) ────────────────
        luma_gate = _np.clip((luma - luma_lo) / 0.15, 0.0, 1.0).astype(_np.float32)

        # ── Step 4: Warm foreground push ──────────────────────────────────────
        wt_warm = (v_warm * luma_gate).astype(_np.float32)
        out_r = _np.clip(r0 + atm_warm_r * wt_warm, 0.0, 1.0)
        out_g = _np.clip(g0 + atm_warm_g * wt_warm, 0.0, 1.0)
        out_b = b0.copy()

        # ── Step 5: Cool background push ──────────────────────────────────────
        wt_cool = (v_cool * luma_gate).astype(_np.float32)
        out_b = _np.clip(out_b + atm_cool_b * wt_cool, 0.0, 1.0)
        out_r = _np.clip(out_r - atm_cool_r * wt_cool, 0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Atmospheric depth gradient pass complete.")
    def ter_brugghen_raking_amber_pass(
        self,
        mid_lo:         float = 0.22,  # lower luminance edge of midtone gate
        mid_hi:         float = 0.76,  # upper luminance edge of midtone gate
        warm_r:         float = 0.060, # warm tint R added to lit ridges
        warm_g:         float = 0.028, # warm tint G added to lit ridges
        cool_b:         float = 0.048, # cool tint B added to shadow ridges
        cool_r:         float = 0.022, # R reduction applied to shadow ridges
        ridge_strength: float = 0.65,  # overall ridge tint blend fraction at peak gate
        opacity:        float = 0.28,
    ) -> None:
        """Directional horizontal Sobel warm-light ridge tinting with cool-shadow infill.

        Hendrick ter Brugghen (1588–1629) studied Caravaggio's tenebrism in Rome
        (1604–1614) and returned to Utrecht to create a warmer, more lyrical version.
        His defining technique is DIRECTIONAL RIDGE LIGHT: a raking amber sidelight
        that catches every elevated form surface — nose bridge, cheekbone, finger knuckle,
        collar fold — with warm ochre-amber, while the receding faces of those same forms
        drop into cool blue-grey.  This is not a global dark/light split but a LOCAL
        SURFACE-NORMAL RESPONSE: the warm/cool axis follows the direction of the light
        across every curve, making the tactile 3D structure of forms visually explicit.

        This pass encodes ter Brugghen's defining quality as the THIRTY-FIRST DISTINCT
        MODE: DIRECTIONAL HORIZONTAL SOBEL WARM-LIGHT RIDGE TINTING WITH COOL-SHADOW
        INFILL.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Horizontal Sobel (scipy.ndimage.sobel, axis=1):
            sobel_x detects the horizontal luminance gradient.
            Positive sobel_x → luma increasing left-to-right → left-lit ridge face.
            Negative sobel_x → luma decreasing left-to-right → right-facing shadow side.
            Normalise: sobel_norm = clip(sobel_x / max(|sobel_x|), −1, 1)
        (3) Midtone gate — smooth bump in [mid_lo, mid_hi]:
            mid_c = (mid_lo + mid_hi) / 2
            t_lo = clip((luma − mid_lo) / (mid_c − mid_lo), 0, 1)
            t_hi = clip((mid_hi − luma) / (mid_hi − mid_c), 0, 1)
            gate_mid = t_lo × t_hi     [peaks at 1 when luma = mid_c]
        (4) Lit ridge gate: lit_gate = clip(sobel_norm, 0, 1) × gate_mid
            Shadow ridge gate: shadow_gate = clip(−sobel_norm, 0, 1) × gate_mid
        (5) Apply warm/cool tinting:
            R_out = R + lit_gate × warm_r × rs − shadow_gate × cool_r × rs
            G_out = G + lit_gate × warm_g × rs
            B_out = B + shadow_gate × cool_b × rs
            where rs = ridge_strength
        (6) Composite at opacity.

        Distinct from romanino_brescian_impasto_pass (gradient magnitude in all
          directions, adds warm/cool simultaneously via luminance gradient — not a
          unidirectional Sobel with separate lit/shadow gates).
        Distinct from shadow_temperature_relief_pass (targets luma < shadow_hi with
          violet penumbra tint — not a Sobel-based ridge detector with warm/cool split).
        Distinct from beccafumi_nacreous_glow_pass (signed Gaussian blur difference —
          omnidirectional bloom, not directional Sobel raking).
        Distinct from penumbra_softening_pass (smooths shadow-edge transitions by
          blending — does not add warm/cool chromatic tint to ridges).
        Distinct from gossaert_pearl_crystalline_pass (luminance stratum decomposition
          into three fixed zones — not directional Sobel ridge detection).

        Args:
            mid_lo/hi     : Luminance range of the midtone gate (protects deep shadow and highlights).
            warm_r/g      : Warm tint channels added proportionally to lit ridge gate.
            cool_b/r      : Cool tint B added / R reduced proportionally to shadow ridge gate.
            ridge_strength: Overall scale factor on both warm and cool tinting at peak gate.
            opacity       : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Horizontal Sobel — detects left-to-right gradient ─────────
        sobel_x = _sobel(luma, axis=1).astype(_np.float32)
        max_abs = float(_np.abs(sobel_x).max()) + 1e-6
        sobel_norm = _np.clip(sobel_x / max_abs, -1.0, 1.0)

        # ── Step 3: Midtone gate — smooth bump in [mid_lo, mid_hi] ───────────
        mid_c = (mid_lo + mid_hi) * 0.5
        denom_lo = max(float(mid_c - mid_lo), 1e-6)
        denom_hi = max(float(mid_hi - mid_c), 1e-6)
        t_lo = _np.clip((luma - mid_lo) / denom_lo, 0.0, 1.0)
        t_hi = _np.clip((mid_hi - luma) / denom_hi, 0.0, 1.0)
        gate_mid = (t_lo * t_hi).astype(_np.float32)

        # ── Step 4: Lit and shadow ridge gates ────────────────────────────────
        lit_gate    = _np.clip( sobel_norm, 0.0, 1.0) * gate_mid
        shadow_gate = _np.clip(-sobel_norm, 0.0, 1.0) * gate_mid

        rs = ridge_strength

        # ── Step 5: Warm/cool tinting ─────────────────────────────────────────
        out_r = _np.clip(r0 + lit_gate * warm_r * rs - shadow_gate * cool_r * rs, 0.0, 1.0)
        out_g = _np.clip(g0 + lit_gate * warm_g * rs,                             0.0, 1.0)
        out_b = _np.clip(b0 + shadow_gate * cool_b * rs,                          0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Ter Brugghen raking amber pass complete.")

    def adaptive_local_contrast_pass(
        self,
        block_size:     int   = 64,   # local block dimension for percentile computation
        p_lo:           float = 0.05, # lower percentile of local channel range
        p_hi:           float = 0.95, # upper percentile of local channel range
        contrast_lo:    float = 0.20, # lower luminance zone gate (protect deep shadows)
        contrast_hi:    float = 0.80, # upper luminance zone gate (protect highlights)
        stretch_amount: float = 0.35, # blend fraction toward locally stretched at peak gate
        opacity:        float = 0.20,
    ) -> None:
        """Local-block percentile contrast stretching for enhanced form modelling.

        Renaissance painters studied forms under controlled sidelight and deliberately
        EXAGGERATED LOCAL CONTRAST within individual form regions — cheekbone, nose,
        brow ridge, hand — so that the modelling would read clearly at the distances
        at which their altarpieces and portraits were viewed.  Unlike global contrast
        adjustment (which flattens extremes uniformly) or unsharp masking (which adds
        edge halos via convolution), this pass operates on LOCAL STATISTICS: each
        region of the image is stretched independently so that its own dynamic range
        fills more of the available tonal space, making subtle form modelling visible
        without altering the global tonal design.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Midtone gate — smooth bump in [contrast_lo, contrast_hi]:
            gate = clip((luma − contrast_lo)/…, 0, 1) × clip((contrast_hi − luma)/…, 0, 1)
            → 0 in deep shadow and full highlight; 1 at midtone centre
        (3) Sample overlapping local blocks (step = block_size, centred at each grid point).
            For each block compute the p_lo and p_hi channel percentiles (per RGB channel).
        (4) Interpolate the percentile grids to full resolution via scipy.ndimage.zoom
            (bilinear, order=1) — creates smooth spatially-varying lo/hi maps.
        (5) Stretch each channel:
            ch_stretched = clip((ch − lo_map) / max(hi_map − lo_map, ε), 0, 1)
        (6) Blend toward stretched via:
            ch_blend = ch × (1 − gate × stretch_amount) + ch_stretched × gate × stretch_amount
        (7) Composite at opacity.

        Distinct from specular_clarity_pass (USM sharpening — high-frequency convolution
          boost via subtract-blur; sharpens edges, does not stretch local channel range).
        Distinct from beccafumi_nacreous_glow_pass (signed Gaussian bloom — warm/cool
          midtone iridescence; not a percentile-based histogram stretch).
        Distinct from cambiaso_geometric_planes_pass (coarse Gaussian zone flattening —
          reduces local contrast within large spatial zones; the opposite of this pass).
        Distinct from gossaert_pearl_crystalline_pass (three luminance strata — fixed
          global luminance bands, not local per-block statistics).
        Distinct from romanino_brescian_impasto_pass (gradient-height relief adding
          warm/cool tint to ridges — not a local histogram operation).

        Args:
            block_size     : Pixel dimension of each local sampling block (square).
            p_lo / p_hi    : Lower and upper percentile of local channel range to stretch to [0, 1].
            contrast_lo/hi : Luminance zone gate — restricts stretch to midtone region.
            stretch_amount : Blend fraction toward locally-stretched at peak gate.
            opacity        : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import zoom as _zoom

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1-2: Luminance + midtone gate ───────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        mid_c = (contrast_lo + contrast_hi) * 0.5
        denom_lo = max(float(mid_c - contrast_lo), 1e-6)
        denom_hi = max(float(contrast_hi - mid_c), 1e-6)
        t_lo = _np.clip((luma - contrast_lo) / denom_lo, 0.0, 1.0)
        t_hi = _np.clip((contrast_hi - luma)  / denom_hi, 0.0, 1.0)
        gate = (t_lo * t_hi).astype(_np.float32)

        # ── Step 3: Sample local block percentiles on a grid ─────────────────
        H, W = self.h, self.w
        half = block_size // 2
        ys = list(range(half, H, block_size))
        xs = list(range(half, W, block_size))
        if not ys:
            ys = [H // 2]
        if not xs:
            xs = [W // 2]
        nY, nX = len(ys), len(xs)

        plo_r = _np.zeros((nY, nX), dtype=_np.float32)
        phi_r = _np.ones( (nY, nX), dtype=_np.float32)
        plo_g = _np.zeros((nY, nX), dtype=_np.float32)
        phi_g = _np.ones( (nY, nX), dtype=_np.float32)
        plo_b = _np.zeros((nY, nX), dtype=_np.float32)
        phi_b = _np.ones( (nY, nX), dtype=_np.float32)

        pct_lo = p_lo * 100.0
        pct_hi = p_hi * 100.0

        for iy, cy in enumerate(ys):
            for ix, cx in enumerate(xs):
                y0, y1 = max(0, cy - half), min(H, cy + half)
                x0, x1 = max(0, cx - half), min(W, cx + half)
                rp = r0[y0:y1, x0:x1].ravel()
                gp = g0[y0:y1, x0:x1].ravel()
                bp = b0[y0:y1, x0:x1].ravel()
                plo_r[iy, ix] = float(_np.percentile(rp, pct_lo))
                phi_r[iy, ix] = float(_np.percentile(rp, pct_hi))
                plo_g[iy, ix] = float(_np.percentile(gp, pct_lo))
                phi_g[iy, ix] = float(_np.percentile(gp, pct_hi))
                plo_b[iy, ix] = float(_np.percentile(bp, pct_lo))
                phi_b[iy, ix] = float(_np.percentile(bp, pct_hi))

        # ── Step 4: Interpolate percentile grids to full resolution ───────────
        def _interp(grid):
            if grid.shape == (1, 1):
                return _np.full((H, W), float(grid[0, 0]), dtype=_np.float32)
            zy = H / grid.shape[0]
            zx = W / grid.shape[1]
            return _np.clip(_zoom(grid, (zy, zx), order=1).astype(_np.float32), 0.0, 1.0)

        map_lo_r = _interp(plo_r);  map_hi_r = _interp(phi_r)
        map_lo_g = _interp(plo_g);  map_hi_g = _interp(phi_g)
        map_lo_b = _interp(plo_b);  map_hi_b = _interp(phi_b)

        # ── Step 5: Stretch each channel via local range ──────────────────────
        def _stretch(ch, lo_map, hi_map):
            denom = _np.maximum(hi_map - lo_map, 1e-4)
            return _np.clip((ch - lo_map) / denom, 0.0, 1.0)

        r_s = _stretch(r0, map_lo_r, map_hi_r)
        g_s = _stretch(g0, map_lo_g, map_hi_g)
        b_s = _stretch(b0, map_lo_b, map_hi_b)

        # ── Step 6: Blend toward stretched via midtone gate ───────────────────
        blend = gate * stretch_amount
        out_r = _np.clip(r0 * (1.0 - blend) + r_s * blend, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - blend) + g_s * blend, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - blend) + b_s * blend, 0.0, 1.0)

        # ── Step 7: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Adaptive local contrast pass complete.")

    def furini_moonlit_sfumato_pass(
        self,
        hi_lo:         float = 0.55,  # lower luminance edge of highlight gate
        hi_hi:         float = 0.92,  # upper luminance edge of highlight gate
        cool_b:        float = 0.030, # cool blue-silver B channel lift in highlights
        cool_r:        float = 0.018, # R channel reduction in highlights (de-warm)
        cool_g:        float = 0.008, # small G lift for silver-grey quality
        cool_strength: float = 0.60,  # gate × this = blend amount at gate peak
        opacity:       float = 0.25,
    ) -> None:
        """Highlight-zone cool silver veil scumble — Francesco Furini's moonlit sfumato.

        Francesco Furini (c. 1603–1646) is the master of FLORENTINE BAROQUE SFUMATO —
        a refinement of Leonardo's technique that pushes edge dissolution and surface
        smoothness to their extreme, combined with a distinctive COOL SILVERY MOONLIT
        LUMINOSITY in the highlight zone.  Where Gaudenzio Ferrari floods his shadow
        zone with warm amber inner light, Furini does the opposite: his lit surfaces
        carry a cool, almost lunar quality — ivory highlights with a slight blue-silver
        cast — while his shadows retain the warmth of the umber imprimatura beneath.

        This warm-shadow / cool-highlight opposition gives his figures the appearance
        of being illuminated by moonlight rather than candlelight, and is the single
        most identifying characteristic of his style.

        The gate itself is smoothed (Gaussian sigma=1.5) to enforce Furini's
        imperceptible transitions — a painting technique so fine that contemporary
        critics speculated he used his fingers or soft leather pads to blend the glazes.

        This pass encodes those effects as the THIRTY-THIRD DISTINCT MODE:
        HIGHLIGHT-ZONE COOL SILVER VEIL SCUMBLE.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Highlight gate — smooth bump in [hi_lo, hi_hi]:
            mid_h = (hi_lo + hi_hi) / 2
            t_lo = clip((luma − hi_lo) / (mid_h − hi_lo), 0, 1)
            t_hi = clip((hi_hi − luma) / (hi_hi − mid_h), 0, 1)
            gate_hi = t_lo × t_hi   [peaks at 1 when luma = mid_h]
        (3) Smooth gate with Gaussian (sigma=1.5) — enforces sfumato transitions:
            gate_hi = gaussian_filter(gate_hi, sigma=1.5)
        (4) Apply cool silver tint weighted by gate × cool_strength:
            wt = gate_hi × cool_strength
            out_r = clip(r − cool_r × wt, 0, 1)   [de-warm: slight R reduction]
            out_g = clip(g + cool_g × wt, 0, 1)   [silver-grey G lift]
            out_b = clip(b + cool_b × wt, 0, 1)   [lunar blue-silver B lift]
        (5) Composite at opacity.

        Distinct from beccafumi_nacreous_glow_pass (midtone gate [0.28, 0.78],
          signed Gaussian bloom difference, warm AND cool split — iridescence, not
          moonlit silver; targets midtones not highlights).
        Distinct from gossaert_pearl_crystalline_pass (separate highlight/shadow zones,
          crystal USM sharpening, Flemish enamel quality — not Italian sfumato).
        Distinct from ter_brugghen_raking_amber_pass (directional horizontal Sobel,
          warm amber ridge tinting — Dutch Caravaggism, not Florentine sfumato).
        Distinct from gaudenzio_warm_devotion_pass (shadow zone gate [0.05, 0.42],
          warm amber tint — opposite tonal zone, opposite colour temperature).

        Args:
            hi_lo/hi       : Luminance range of highlight gate.
            cool_b/r/g     : Cool tint: B lifted (lunar), R reduced (de-warm), G lifted (silver).
            cool_strength  : Gate scale factor (gate × cool_strength = blend at peak).
            opacity        : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Highlight gate — smooth bump in [hi_lo, hi_hi] ────────────
        mid_h = (hi_lo + hi_hi) * 0.5
        denom_lo = max(float(mid_h - hi_lo), 1e-6)
        denom_hi = max(float(hi_hi - mid_h), 1e-6)
        t_lo = _np.clip((luma - hi_lo) / denom_lo, 0.0, 1.0)
        t_hi = _np.clip((hi_hi - luma) / denom_hi, 0.0, 1.0)
        gate_hi = (t_lo * t_hi).astype(_np.float32)

        # ── Step 3: Smooth gate with Gaussian — sfumato imperceptible transition
        gate_hi = _gf(gate_hi, sigma=1.5).astype(_np.float32)

        # ── Step 4: Cool silver tint in highlight zone ────────────────────────
        wt = gate_hi * cool_strength
        out_r = _np.clip(r0 - cool_r * wt, 0.0, 1.0)
        out_g = _np.clip(g0 + cool_g * wt, 0.0, 1.0)
        out_b = _np.clip(b0 + cool_b * wt, 0.0, 1.0)

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Furini moonlit sfumato pass complete.")

    def translucent_fabric_pass(
        self,
        fab_lo:         float = 0.30,   # lower luminance edge of mid-tone drape gate
        fab_hi:         float = 0.72,   # upper luminance edge of mid-tone drape gate
        fabric_r:       float = 0.12,   # fabric colour R (default: dark forest-green)
        fabric_g:       float = 0.18,   # fabric colour G
        fabric_b:       float = 0.14,   # fabric colour B
        fabric_opacity: float = 0.18,   # peak blend strength at gate peak
        edge_factor:    float = 0.40,   # gradient edge strength reduces drape weight
        opacity:        float = 0.22,
    ) -> None:
        """Edge-aware mid-tone fabric transparency simulation — translucent drape.

        Thin semi-transparent fabrics (veils, gauze wraps, translucent drapery) are
        a recurring element in Renaissance and Baroque portraiture.  Their optical
        quality is distinctive: the fabric adds colour to the zone beneath while
        remaining semi-transparent, allowing the underlying flesh or garment to remain
        partially visible.  The fabric distributes unequally across the surface —
        pooling over smooth, gently curved areas where the cloth lies flat, and
        stretching thin over sharp ridges, folds, and garment edges where the fabric
        tension is highest.

        This pass encodes that quality as an ARTISTIC IMPROVEMENT: EDGE-AWARE
        MID-TONE FABRIC TRANSPARENCY SIMULATION.  The fabric colour is blended into
        the mid-luminance zone (where fabric most visibly tints the surface), modulated
        by an edge-aware drape weight — fabric accumulates over smooth flat zones
        (low Sobel gradient magnitude) and thins at sharp contours (high gradient).

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Mid-tone drape gate: smooth bump in [fab_lo, fab_hi]:
            gate_mid peaks at midpoint; falls to 0 at deep shadow and bright highlight.
            [Fabric most visible in mid-tones; shadows absorb fabric colour;
             bright highlights transmit through thin fabric without tinting.]
        (3) Edge-aware modulation: compute Sobel gradient magnitude of luminance:
            gx = sobel(luma, axis=1); gy = sobel(luma, axis=0)
            grad_mag = sqrt(gx² + gy²); normalise by 99th percentile → edge_norm [0,1]
            drape_weight = gate_mid × (1 − edge_norm × edge_factor)
            [Fabric pools over flat smooth zones; thins at sharp edges/folds]
        (4) Subtractive fabric blend — linear transparency model:
            fw = drape_weight × fabric_opacity
            out_r = r × (1 − fw) + fabric_r × fw
            out_g = g × (1 − fw) + fabric_g × fw
            out_b = b × (1 − fw) + fabric_b × fw
        (5) Soften fabric transitions with Gaussian (sigma=0.8) — smooth drape edges.
        (6) Composite at opacity.

        Args:
            fab_lo/hi       : Luminance range of mid-tone drape gate.
            fabric_r/g/b    : RGB of fabric material (default dark forest-green gauze).
            fabric_opacity  : Peak blend strength at gate maximum.
            edge_factor     : How strongly Sobel edges thin the drape weight [0–1].
            opacity         : Global composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel, gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Mid-tone drape gate ───────────────────────────────────────
        mid_f = (fab_lo + fab_hi) * 0.5
        denom_lo = max(float(mid_f - fab_lo), 1e-6)
        denom_hi = max(float(fab_hi - mid_f), 1e-6)
        t_lo = _np.clip((luma - fab_lo) / denom_lo, 0.0, 1.0)
        t_hi = _np.clip((fab_hi - luma) / denom_hi, 0.0, 1.0)
        gate_mid = (t_lo * t_hi).astype(_np.float32)

        # ── Step 3: Edge-aware modulation (Sobel gradient magnitude) ─────────
        gx = _sobel(luma, axis=1)
        gy = _sobel(luma, axis=0)
        grad_mag = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)
        p99 = float(_np.percentile(grad_mag, 99))
        if p99 > 1e-6:
            edge_norm = _np.clip(grad_mag / p99, 0.0, 1.0)
        else:
            edge_norm = _np.zeros_like(grad_mag)
        drape_weight = _np.clip(gate_mid * (1.0 - edge_norm * edge_factor), 0.0, 1.0)

        # ── Step 4: Subtractive fabric blend ─────────────────────────────────
        fw = drape_weight * fabric_opacity
        out_r = r0 * (1.0 - fw) + fabric_r * fw
        out_g = g0 * (1.0 - fw) + fabric_g * fw
        out_b = b0 * (1.0 - fw) + fabric_b * fw

        # ── Step 5: Soften fabric transitions (only when fabric is present) ──
        if fabric_opacity > 1e-6:
            out_r = _np.clip(_gf(out_r.astype(_np.float32), sigma=0.8), 0.0, 1.0)
            out_g = _np.clip(_gf(out_g.astype(_np.float32), sigma=0.8), 0.0, 1.0)
            out_b = _np.clip(_gf(out_b.astype(_np.float32), sigma=0.8), 0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Translucent fabric pass complete.")

    def bartolomeo_veneto_jewel_brocade_pass(
        self,
        blue_lo:       float = 0.05,   # min luminance for blue-violet pole gate
        blue_hi:       float = 0.55,   # max luminance for blue-violet pole (shadow zone)
        gold_lo:       float = 0.42,   # min luminance for gold-amber pole gate
        gold_hi:       float = 0.88,   # max luminance for gold-amber pole
        blue_deepen:   float = 0.12,   # saturation deepening in blue-violet zone
        gold_deepen:   float = 0.14,   # saturation deepening in gold-amber zone
        pole_strength: float = 0.65,   # overall gate scale
        opacity:       float = 0.28,
    ) -> None:
        """Hue-angular dual-pole saturation deepening — Bartolomeo Veneto's jewel brocade.

        Bartolomeo Veneto (active c. 1502–c. 1546) is the LOMBARDY-VENETIAN JEWEL
        REALIST par excellence — a portraitist whose identity and origins remain almost
        entirely mysterious, yet whose technical achievement is unmistakable.  His
        works fuse two distinct chromatic systems: COOL IVORY FLESH PRECISION (Lombard,
        Leonardesque) and JEWEL-TONE BROCADE RICHNESS (Venetian, with Northern brocade
        exactitude).  The fabric in his portraits — deep ultramarine-violet brocade in
        shadow zones, warm hammered gold in highlight zones — is rendered with a precision
        that rivals the finest Flemish panel painting.

        This pass encodes those effects as the THIRTY-FOURTH DISTINCT MODE: HUE-ANGULAR
        DUAL-POLE SATURATION DEEPENING.  Two hue poles are defined via direct RGB channel
        relationships (no HSV conversion):

        BLUE-VIOLET POLE — shadow fabric saturation deepening:
            blue_proxy = clip(B − max(R, G), 0, 1)   [how much B exceeds the others]
            gated to shadow/penumbra zone via smooth bump in [blue_lo, blue_hi]
            In gate: R reduced, G lightly reduced, B boosted → deeper ultramarine depth

        GOLD-AMBER POLE — highlight fabric saturation deepening:
            gold_proxy = clip(R − B, 0, 1) × clip(G − B×0.5, 0, 1)
            [R dominant over B AND green elevated over a warm-amber hue]
            gated to mid-to-highlight zone via smooth bump in [gold_lo, gold_hi]
            In gate: R boosted, G lightly boosted, B reduced → deeper hammered gold

        These two poles are independent: blue pole acts in shadow; gold pole acts in
        highlight.  Flesh tones (low blue_proxy AND low gold_proxy) are untouched —
        the cool ivory precision remains intact.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) BLUE-VIOLET POLE:
            blue_proxy = clip(B − max(R, G), 0, 1)
            shadow_gate = smooth bump in [blue_lo, blue_hi] (peaks at midpoint)
            blue_wt = blue_proxy × shadow_gate × pole_strength
            out_r -= blue_deepen × blue_wt
            out_g -= blue_deepen × 0.40 × blue_wt
            out_b += blue_deepen × 0.60 × blue_wt
        (3) GOLD-AMBER POLE:
            gold_proxy = clip(R − B, 0, 1) × clip(G − B × 0.5, 0, 1)
            highlight_gate = smooth bump in [gold_lo, gold_hi] (peaks at midpoint)
            gold_wt = gold_proxy × highlight_gate × pole_strength
            out_r += gold_deepen × gold_wt
            out_g += gold_deepen × 0.45 × gold_wt
            out_b -= gold_deepen × 0.55 × gold_wt
        (4) Composite at opacity.

        Distinct from gossaert_pearl_crystalline_pass (three-stratum luminance zones,
          no hue-angle proximity gating, Flemish enamel crystallinity vs. brocade depth).
        Distinct from beccafumi_nacreous_glow_pass (Gaussian bloom signed diff, midtone
          iridescence, not dual-hue-pole brocade deepening).
        Distinct from cossa gem-zone pass (single gem luminance threshold, USM clarity,
          not dual-pole hue angular decomposition).

        Args:
            blue_lo/hi     : Luminance gate range for blue-violet shadow pole.
            gold_lo/hi     : Luminance gate range for gold-amber highlight pole.
            blue_deepen    : Saturation deepening strength in blue-violet zone.
            gold_deepen    : Saturation deepening strength in gold-amber zone.
            pole_strength  : Global gate scale factor.
            opacity        : Composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Blue-violet pole — shadow-zone ultramarine deepening ──────
        max_rg = _np.maximum(r0, g0)
        blue_proxy = _np.clip(b0 - max_rg, 0.0, 1.0)

        mid_blue = (blue_lo + blue_hi) * 0.5
        denom_blo = max(float(mid_blue - blue_lo), 1e-6)
        denom_bhi = max(float(blue_hi - mid_blue), 1e-6)
        t_blo = _np.clip((luma - blue_lo) / denom_blo, 0.0, 1.0)
        t_bhi = _np.clip((blue_hi - luma) / denom_bhi, 0.0, 1.0)
        shadow_gate = (t_blo * t_bhi).astype(_np.float32)

        blue_wt = (blue_proxy * shadow_gate * pole_strength).astype(_np.float32)

        out_r = _np.clip(r0 - blue_deepen * blue_wt,              0.0, 1.0)
        out_g = _np.clip(g0 - blue_deepen * 0.40 * blue_wt,       0.0, 1.0)
        out_b = _np.clip(b0 + blue_deepen * 0.60 * blue_wt,       0.0, 1.0)

        # ── Step 3: Gold-amber pole — highlight-zone hammered gold deepening ──
        gold_proxy = (
            _np.clip(out_r - out_b, 0.0, 1.0) *
            _np.clip(out_g - out_b * 0.5, 0.0, 1.0)
        ).astype(_np.float32)

        mid_gold = (gold_lo + gold_hi) * 0.5
        denom_glo = max(float(mid_gold - gold_lo), 1e-6)
        denom_ghi = max(float(gold_hi - mid_gold), 1e-6)
        t_glo = _np.clip((luma - gold_lo) / denom_glo, 0.0, 1.0)
        t_ghi = _np.clip((gold_hi - luma) / denom_ghi, 0.0, 1.0)
        highlight_gate = (t_glo * t_ghi).astype(_np.float32)

        gold_wt = (gold_proxy * highlight_gate * pole_strength).astype(_np.float32)

        out_r = _np.clip(out_r + gold_deepen * gold_wt,           0.0, 1.0)
        out_g = _np.clip(out_g + gold_deepen * 0.45 * gold_wt,    0.0, 1.0)
        out_b = _np.clip(out_b - gold_deepen * 0.55 * gold_wt,    0.0, 1.0)

        # ── Step 4: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Bartolomeo Veneto jewel brocade pass complete.")

    def iridescent_glaze_pass(
        self,
        mid_lo:           float = 0.28,   # lower luminance edge of midtone gate
        mid_hi:           float = 0.75,   # upper luminance edge of midtone gate
        warm_r:           float = 0.040,  # warm shimmer R boost in gradient warm direction
        warm_g:           float = 0.018,  # warm shimmer G boost
        cool_b:           float = 0.035,  # cool shimmer B boost in gradient cool direction
        cool_r:           float = 0.018,  # cool shimmer R reduction
        shimmer_strength: float = 0.55,   # overall gate scale
        opacity:          float = 0.18,
    ) -> None:
        """Full-gradient orientation warm/cool iridescent shimmer in paint transitions.

        Thin oil glazes on a curved painted surface exhibit a subtle IRIDESCENT
        QUALITY — as the surface curves away from the light source, the glaze
        thickness changes, and with it the visible colour of the refracted light.
        In practice, the effect is barely perceptible: at paint-layer boundaries and
        across curved forms in mid-tone zones, warm colours appear on surfaces facing
        the light source and cool colours appear on surfaces facing away.  Master
        glazers — including Flemish and Venetian oil painters — exploited this quality
        deliberately, alternating warm and cool glaze layers to give surfaces an inner
        luminosity that defies simple description.

        This pass encodes that effect as the THIRTY-FIFTH DISTINCT MODE: FULL-GRADIENT
        ORIENTATION WARM/COOL IRIDESCENT SHIMMER IN PAINT TRANSITIONS.

        The key innovation over prior directional passes is the use of the FULL 2D
        GRADIENT ORIENTATION via arctan2(gy, gx) rather than a single horizontal Sobel
        component.  This captures paint transitions in ALL directions — vertical form
        boundaries, diagonal contours, and oblique brush marks — not just left-to-right.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Compute Sobel components:
            gx = sobel(luma, axis=1)    [horizontal gradient]
            gy = sobel(luma, axis=0)    [vertical gradient]
        (3) Gradient magnitude: mag = sqrt(gx² + gy²)
            Normalise by 95th percentile → mag_norm = clip(mag / p95, 0, 1)
        (4) Gradient orientation: theta = arctan2(gy, gx) in [−π, π]
        (5) Directional gates (smooth cosine decomposition):
            warm_dir = clip(cos(theta), 0, 1)    [gradient pointing in +x direction]
            cool_dir = clip(−cos(theta), 0, 1)   [gradient pointing in −x direction]
        (6) Midtone luminance gate: smooth bump in [mid_lo, mid_hi]
        (7) Combined shimmer weights:
            warm_w = warm_dir × midgate × mag_norm × shimmer_strength
            cool_w = cool_dir × midgate × mag_norm × shimmer_strength
        (8) Apply iridescent tint:
            out_r = clip(r + warm_r × warm_w − cool_r × cool_w, 0, 1)
            out_g = clip(g + warm_g × warm_w, 0, 1)
            out_b = clip(b + cool_b × cool_w, 0, 1)
        (9) Composite at opacity.

        Distinct from ter_brugghen_raking_amber_pass (horizontal-only Sobel axis=1,
          no atan2 orientation, directional sidelight rather than iridescent glaze shimmer).
        Distinct from romanino_brescian_impasto_pass (oblique-light height-field from
          combined -(gx+gy), not full-angle orientation, warm/cool ridge vs. shimmer).
        Distinct from shadow_transparency_pass (luminance-threshold only, no gradient
          direction, violet shadow tint rather than orientation-driven shimmer).

        Args:
            mid_lo/hi         : Midtone luminance gate range (shimmer most visible here).
            warm_r/g          : Warm-direction shimmer tint (R/G boost).
            cool_b/r          : Cool-direction shimmer tint (B boost / R reduction).
            shimmer_strength  : Overall gate scale factor.
            opacity           : Composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Sobel gradient components ────────────────────────────────
        gx = _sobel(luma, axis=1).astype(_np.float32)
        gy = _sobel(luma, axis=0).astype(_np.float32)

        # ── Step 3: Gradient magnitude, normalised ────────────────────────────
        mag = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)
        p95 = float(_np.percentile(mag, 95))
        if p95 > 1e-6:
            mag_norm = _np.clip(mag / p95, 0.0, 1.0)
        else:
            mag_norm = _np.zeros_like(mag)

        # ── Step 4: Full-gradient orientation via arctan2 ─────────────────────
        theta = _np.arctan2(gy, gx).astype(_np.float32)

        # ── Step 5: Directional cosine gates ──────────────────────────────────
        warm_dir = _np.clip(_np.cos(theta), 0.0, 1.0).astype(_np.float32)
        cool_dir = _np.clip(-_np.cos(theta), 0.0, 1.0).astype(_np.float32)

        # ── Step 6: Midtone luminance gate — smooth bump in [mid_lo, mid_hi] ──
        mid_f = (mid_lo + mid_hi) * 0.5
        denom_lo = max(float(mid_f - mid_lo), 1e-6)
        denom_hi = max(float(mid_hi - mid_f), 1e-6)
        t_lo = _np.clip((luma - mid_lo) / denom_lo, 0.0, 1.0)
        t_hi = _np.clip((mid_hi - luma) / denom_hi, 0.0, 1.0)
        midgate = (t_lo * t_hi).astype(_np.float32)

        # ── Step 7: Combined shimmer weights ──────────────────────────────────
        warm_w = (warm_dir * midgate * mag_norm * shimmer_strength).astype(_np.float32)
        cool_w = (cool_dir * midgate * mag_norm * shimmer_strength).astype(_np.float32)

        # ── Step 8: Apply iridescent tint ─────────────────────────────────────
        out_r = _np.clip(r0 + warm_r * warm_w - cool_r * cool_w, 0.0, 1.0)
        out_g = _np.clip(g0 + warm_g * warm_w,                    0.0, 1.0)
        out_b = _np.clip(b0 + cool_b * cool_w,                    0.0, 1.0)

        # ── Step 9: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Iridescent glaze pass complete.")

    # Session 155 — artist pass: melozzo_zenith_radiance_pass
    # ─────────────────────────────────────────────────────────────────────────

    def melozzo_zenith_radiance_pass(
        self,
        mid_lo:          float = 0.28,  # lower luminance boundary of midtone gate
        mid_hi:          float = 0.75,  # upper luminance boundary of midtone gate
        warm_r:          float = 0.032, # R boost on zenith-lit top-of-form surfaces
        warm_g:          float = 0.016, # G boost on zenith-lit surfaces (amber warmth)
        cool_b:          float = 0.028, # B boost on under-surface shadow zones
        cool_r:          float = 0.014, # R reduction on under-surface shadow zones
        zenith_strength: float = 0.60,  # overall gate scale factor
        opacity:         float = 0.26,
    ) -> None:
        """Vertical overhead zenith light — Melozzo da Forlì's di sotto in sù radiance.

        Melozzo da Forlì (1438–1494) is the supreme master of DI SOTTO IN SÙ —
        ceiling frescoes depicting figures seen from directly below, lit by an
        overhead ZENITH LIGHT that strikes the tops of upturned faces, the backs
        of hands, and the upper surfaces of folded wings with luminous warmth,
        while under-surfaces fall into warm-umber shadow.  His fragmentary Angel
        Musicians in the Vatican Pinacoteca are the definitive example: each angel
        is modelled as if observed from below through a hole in the ceiling, with
        light descending from a sky directly overhead.

        This pass encodes those effects as the THIRTY-SIXTH DISTINCT MODE:
        VERTICAL OVERHEAD ZENITH LIGHT WITH TOP-OF-FORM WARM LIFT AND
        UNDER-SURFACE COOL SHADOW DEEPENING.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Vertical position map — canvas row 0 = image top:
            y_frac  = row_index / (H − 1)        [0.0 at top, 1.0 at bottom]
            zenith_wt = 1.0 − y_frac             [peaks at TOP = overhead zenith]
            under_wt  = y_frac                   [peaks at BOTTOM = under-surface]
        (3) Midtone luminance gate: smooth bump in [mid_lo, mid_hi]:
            mid_f = (mid_lo + mid_hi) / 2
            t_lo = clip((luma − mid_lo) / (mid_f − mid_lo), 0, 1)
            t_hi = clip((mid_hi − luma) / (mid_hi − mid_f), 0, 1)
            midgate = t_lo × t_hi
        (4) Zenith-lit surfaces (top-facing forms):
            zenith_gate = zenith_wt × midgate × zenith_strength
            out_r = clip(r + warm_r × zenith_gate, 0, 1)
            out_g = clip(g + warm_g × zenith_gate, 0, 1)
        (5) Under-surface shadow zones (bottom-facing forms):
            under_gate = under_wt × midgate × zenith_strength
            out_b = clip(b + cool_b × under_gate, 0, 1)
            out_r = clip(out_r − cool_r × under_gate, 0, 1)
        (6) Composite at opacity.

        Distinct from atmospheric_depth_gradient_pass (OPPOSITE vertical polarity:
          that pass applies WARM on BOTTOM/foreground and COOL on TOP/background,
          simulating aerial perspective in landscape recession — warm earth tones
          below, cool sky haze above.  This pass applies WARM on TOP/zenith and
          COOL on BOTTOM/under-surface, simulating overhead ambient light on
          three-dimensional figures).
        Distinct from romanino_brescian_impasto_pass (oblique upper-left light
          from gradient of smoothed luma height field: -(gx+gy)/√2; no vertical
          position axis; impasto ridge simulation not zenith sky gradient).
        Distinct from gaudenzio_warm_devotion_pass (shadow-zone luminance gate
          only, no vertical position axis, warm amber scumble not overhead light).

        Args:
            mid_lo/hi       : Luminance range of the midtone gate (zenith light most
                              visible in lit-but-not-specular midtone zone).
            warm_r/g        : Warm amber tint applied to zenith-lit top-of-form areas.
            cool_b          : Cool tint applied to under-surface shadow areas.
            cool_r          : R reduction in under-surface shadow areas.
            zenith_strength : Overall gate scale factor.
            opacity         : Composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Vertical position weights ────────────────────────────────
        rows = _np.linspace(0.0, 1.0, self.h, dtype=_np.float32)  # 0=top, 1=bottom
        y_frac = rows[:, _np.newaxis] * _np.ones((1, self.w), dtype=_np.float32)
        zenith_wt = (1.0 - y_frac).astype(_np.float32)   # strong at TOP (overhead)
        under_wt  = y_frac.astype(_np.float32)            # strong at BOTTOM (under-surface)

        # ── Step 3: Midtone luminance gate ────────────────────────────────────
        mid_f = (mid_lo + mid_hi) * 0.5
        denom_lo = max(float(mid_f - mid_lo), 1e-6)
        denom_hi = max(float(mid_hi - mid_f), 1e-6)
        t_lo = _np.clip((luma - mid_lo) / denom_lo, 0.0, 1.0)
        t_hi = _np.clip((mid_hi - luma) / denom_hi, 0.0, 1.0)
        midgate = (t_lo * t_hi).astype(_np.float32)

        # ── Step 4: Zenith-lit surfaces (warm lift at top of canvas) ──────────
        zenith_gate = (zenith_wt * midgate * zenith_strength).astype(_np.float32)
        out_r = _np.clip(r0 + warm_r * zenith_gate, 0.0, 1.0)
        out_g = _np.clip(g0 + warm_g * zenith_gate, 0.0, 1.0)
        out_b = b0.copy()

        # ── Step 5: Under-surface shadow zones (cool push at bottom of canvas) ─
        under_gate = (under_wt * midgate * zenith_strength).astype(_np.float32)
        out_b = _np.clip(out_b + cool_b * under_gate, 0.0, 1.0)
        out_r = _np.clip(out_r - cool_r * under_gate, 0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Melozzo zenith radiance pass complete.")

    # Session 155 — random improvement: warm_ambient_occlusion_pass
    # ─────────────────────────────────────────────────────────────────────────

    def warm_ambient_occlusion_pass(
        self,
        occ_radius:  float = 10.0,  # Gaussian sigma for local mean (wide neighbourhood)
        occ_max:     float = 0.25,  # maximum concavity depth clamp
        shad_lo:     float = 0.10,  # lower luminance of shadow gate
        shad_hi:     float = 0.42,  # upper luminance of shadow gate
        warm_r:      float = 0.040, # warm indirect ambient R boost in recessed zones
        warm_g:      float = 0.020, # warm indirect ambient G boost in recessed zones
        opacity:     float = 0.22,
    ) -> None:
        """Local luminance concavity warm-amber infill — ambient inter-reflection.

        In old master oil portraiture, shadowed recesses are not dead black voids
        but glow faintly with warm indirect ambient light reflected back from the
        surrounding warm surfaces — costume, architectural setting, or warm ground.
        The EYE SOCKET CORNERS, NOSTRIL WINGS, EAR CANAL, and ARMPIT FOLDS all
        receive a warm reflected light that distinguishes a living painted face from
        a flat shadow.  This quality — visible in every great old master portrait
        from Bellini to Rembrandt — arises from the physical reality of ambient
        inter-reflection: light bounces between warm surfaces before entering the
        concave recess, acquiring a warm spectral cast along the way.

        This pass encodes those effects as the THIRTY-SEVENTH DISTINCT MODE:
        LOCAL LUMINANCE CONCAVITY WARM-AMBER INFILL (AMBIENT INTER-REFLECTION).

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Wide Gaussian blur of luminance: local_mean = Gaussian(luma, sigma=occ_radius)
            The wide blur captures the average luminance of the neighbourhood.
        (3) Concavity map: occlusion = clip(local_mean − luma, 0, occ_max)
            Pixels darker than their neighbourhood are in concave recession.
        (4) Normalise: occ_norm = occlusion / occ_max → [0, 1]
        (5) Shadow luminance gate: smooth bump in [shad_lo, shad_hi]:
            shad_f = (shad_lo + shad_hi) / 2
            t_lo = clip((luma − shad_lo) / (shad_f − shad_lo), 0, 1)
            t_hi = clip((shad_hi − luma) / (shad_hi − shad_f), 0, 1)
            shad_gate = t_lo × t_hi
        (6) Combined weight: weight = occ_norm × shad_gate
        (7) Apply warm indirect ambient: R+warm_r×weight; G+warm_g×weight
        (8) Composite at opacity.

        Distinct from penumbra_zone_pass (uses global luminance tent-gate between
          shadow_thresh and light_thresh with NO spatial context — all midtone pixels
          receive the warm blush equally; this pass uses LOCAL CONCAVITY, so only
          pixels specifically darker than their spatial neighbourhood are treated).
        Distinct from subsurface_scatter_pass (targets lit-midtone zone scatter_low–
          scatter_high and applies Gaussian-blurred bloom; this targets CONCAVE SHADOW
          PIXELS darker than local average, which are precisely the opposite zone).
        Distinct from luminous_ground_pass (targets globally dark pixels below
          ground_hi; applies a fixed warm ground colour blend; no spatial concavity
          detection — globally dark pixels are treated whether or not they are
          darker than their neighbourhood).
        Distinct from gaudenzio_warm_devotion_pass (shadow-zone luminance gate only,
          warm amber scumble uniformly across all deep shadows, no spatial concavity).

        Args:
            occ_radius : Gaussian sigma for the wide neighbourhood blur (pixels).
            occ_max    : Maximum concavity depth; values larger than this are clamped.
            shad_lo/hi : Shadow luminance gate — the warm infill is active in this zone.
            warm_r/g   : Warm ambient tint applied to concave-shadow pixels.
            opacity    : Composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Wide Gaussian blur → local neighbourhood mean ─────────────
        local_mean = _gf(luma, sigma=occ_radius).astype(_np.float32)

        # ── Step 3-4: Concavity map, normalised ──────────────────────────────
        occlusion = _np.clip(local_mean - luma, 0.0, float(occ_max))
        occ_max_f = max(float(occ_max), 1e-6)
        occ_norm  = (occlusion / occ_max_f).astype(_np.float32)

        # ── Step 5: Shadow luminance gate — smooth bump in [shad_lo, shad_hi] ─
        shad_f    = (shad_lo + shad_hi) * 0.5
        denom_slo = max(float(shad_f - shad_lo), 1e-6)
        denom_shi = max(float(shad_hi - shad_f), 1e-6)
        t_slo     = _np.clip((luma - shad_lo) / denom_slo, 0.0, 1.0)
        t_shi     = _np.clip((shad_hi - luma) / denom_shi, 0.0, 1.0)
        shad_gate = (t_slo * t_shi).astype(_np.float32)

        # ── Step 6-7: Combined weight → warm indirect ambient infill ──────────
        weight = (occ_norm * shad_gate).astype(_np.float32)
        out_r  = _np.clip(r0 + warm_r * weight, 0.0, 1.0)
        out_g  = _np.clip(g0 + warm_g * weight, 0.0, 1.0)
        out_b  = b0  # blue channel unchanged

        # ── Step 8: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Warm ambient occlusion pass complete.")

    # Session 156 — artist: Gentile da Fabriano (International Gothic)
    # ─────────────────────────────────────────────────────────────────────────

    def gentile_da_fabriano_gold_tooling_pass(
        self,
        hi_lo:          float = 0.60,  # lower luminance boundary of highlight gate
        hi_hi:          float = 0.95,  # upper luminance boundary of highlight gate
        gold_r:         float = 0.070, # R boost on lit-ridge surfaces (warm gold shimmer)
        gold_g:         float = 0.045, # G boost on lit-ridge surfaces
        gold_b:         float = 0.020, # B reduction on lit-ridge surfaces (deepens gold chroma)
        ridge_strength: float = 0.70,  # overall gate scale factor
        opacity:        float = 0.28,
    ) -> None:
        """Gold-tooling shimmer — Gentile da Fabriano's punched gold-leaf radiance.

        Gentile da Fabriano (c. 1370–1427) is the supreme master of the
        INTERNATIONAL GOTHIC style.  His altarpieces — foremost the Adoration of
        the Magi (1423, Uffizi) — deploy physically punched and tooled gold-leaf
        backgrounds and halos, a technique called PASTIGLIA combined with SGRAFFITO:
        embossed decorative patterns pressed into the gold ground so that raised
        surfaces catch directional light as intense warm sparkles while recessed
        areas remain matte.  The effect is fundamentally different from painted gold:
        the surface physically modulates light by relief rather than pigment.

        This pass encodes those effects as the THIRTY-EIGHTH DISTINCT MODE:
        LUMINANCE-RIDGE WARM GOLD SHIMMER TINTING.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Isotropic Sobel gradient magnitude:
            gx = sobel(luma, axis=1); gy = sobel(luma, axis=0)
            grad_mag = sqrt(gx² + gy²)
            grad_norm = clip(grad_mag / max(grad_mag), 0, 1)
        (3) High-luminance gate — smooth bump in [hi_lo, hi_hi]:
            hi_f = (hi_lo + hi_hi) / 2
            t_lo = clip((luma − hi_lo) / (hi_f − hi_lo), 0, 1)
            t_hi = clip((hi_hi − luma) / (hi_hi − hi_f), 0, 1)
            hi_gate = t_lo × t_hi
        (4) Ridge gate = grad_norm × hi_gate × ridge_strength
        (5) Apply gold shimmer tint:
            out_r = clip(r + gold_r × ridge_gate, 0, 1)
            out_g = clip(g + gold_g × ridge_gate, 0, 1)
            out_b = clip(b − gold_b × ridge_gate, 0, 1)   ← blue reduction deepens gold chroma
        (6) Composite at opacity.

        Distinct from warm_ambient_occlusion_pass (OPPOSITE target zone: that pass
          applies warm tint to DARK concave recesses below local mean — the shadow
          infill; this pass applies warm gold tint to BRIGHT ridge highlights above
          luminance threshold — the specular lift; different spatial trigger).
        Distinct from romanino_brescian_impasto_pass (oblique-light from smoothed
          luma height field: -(gx+gy)/√2; no luminance gate; applies warm lift AND
          cool shadow; simulates impasto ridge/valley not gold sparkle).
        Distinct from melozzo_zenith_radiance_pass (vertical position axis; no Sobel
          gradient; applies to all midtone surfaces above/below, not ridge-specific).

        Args:
            hi_lo/hi        : Luminance range for highlight gate (gold shimmer visible
                              only on already-lit surfaces, not in shadow or clip).
            gold_r/g        : Warm amber-gold tint applied to lit ridge pixels.
            gold_b          : Blue reduction on lit ridges (deepens gold chroma away
                              from white-light specular into warm gold territory).
            ridge_strength  : Overall gate scale factor.
            opacity         : Composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Isotropic Sobel gradient magnitude ────────────────────────
        gx = _sobel(luma, axis=1).astype(_np.float32)
        gy = _sobel(luma, axis=0).astype(_np.float32)
        grad_mag  = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)
        max_mag   = float(grad_mag.max()) or 1e-6
        grad_norm = _np.clip(grad_mag / max_mag, 0.0, 1.0)

        # ── Step 3: High-luminance gate — smooth bump in [hi_lo, hi_hi] ──────
        hi_f     = (hi_lo + hi_hi) * 0.5
        denom_lo = max(float(hi_f - hi_lo), 1e-6)
        denom_hi = max(float(hi_hi - hi_f), 1e-6)
        t_lo     = _np.clip((luma - hi_lo) / denom_lo, 0.0, 1.0)
        t_hi     = _np.clip((hi_hi - luma) / denom_hi, 0.0, 1.0)
        hi_gate  = (t_lo * t_hi).astype(_np.float32)

        # ── Step 4: Ridge gate ────────────────────────────────────────────────
        ridge_gate = (grad_norm * hi_gate * ridge_strength).astype(_np.float32)

        # ── Step 5: Gold shimmer tint ─────────────────────────────────────────
        out_r = _np.clip(r0 + gold_r * ridge_gate, 0.0, 1.0)
        out_g = _np.clip(g0 + gold_g * ridge_gate, 0.0, 1.0)
        out_b = _np.clip(b0 - gold_b * ridge_gate, 0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Gentile da Fabriano gold tooling pass complete.")

    # Session 156 — random improvement: chromatic_fringe_pass
    # ─────────────────────────────────────────────────────────────────────────

    def chromatic_fringe_pass(
        self,
        edge_lo:          float = 0.08,  # lower norm-magnitude edge gate threshold
        edge_hi:          float = 0.80,  # upper norm-magnitude edge gate threshold
        fringe_warm_r:    float = 0.045, # R boost on bright side of edge (warm fringe)
        fringe_warm_g:    float = 0.018, # G boost on bright side of edge
        fringe_cool_b:    float = 0.040, # B boost on dark side of edge (cool fringe)
        fringe_cool_r:    float = 0.016, # R reduction on dark side of edge
        opacity:          float = 0.18,
    ) -> None:
        """Prismatic edge chromatic fringe — the THIRTY-NINTH DISTINCT MODE.

        PRISMATIC EDGE CHROMATIC FRINGE: WARM-SIDE / COOL-SIDE DISPERSION TINTING.

        Old Master oil panel paintings, when examined under raking light, display
        subtle PRISMATIC IRIDESCENCE at transitions between lit and shadowed form
        surfaces.  This effect arises from the spectral dispersion of light refracted
        through stacked oil glaze layers of differing refractive indices — each
        glazing stratum acts as a partial reflector, and at high-contrast edges the
        constructive/destructive interference pattern produces a warm fringe on the
        lit side and a cool fringe on the shadow side, visible as a thin halo of
        reddish-amber warmth against the bright form face and a blue-violet whisper
        against the shadow face.  The effect is subtle — never as obvious as a lens
        chromatic aberration — but it gives glazed Renaissance panel paintings their
        characteristic jewel-like depth and visual complexity at edge transitions.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Sobel gradients:
            gx = sobel(luma, axis=1)   [positive = bright to the RIGHT]
            gy = sobel(luma, axis=0)   [positive = bright BELOW]
        (3) Gradient magnitude: mag = sqrt(gx²+gy²)
            norm_mag = clip(mag / max(mag), 0, 1)
        (4) Edge magnitude gate — smooth bump in [edge_lo, edge_hi]:
            edge_f = (edge_lo + edge_hi) / 2
            t_lo = clip((norm_mag − edge_lo) / (edge_f − edge_lo), 0, 1)
            t_hi = clip((edge_hi − norm_mag) / (edge_hi − edge_f), 0, 1)
            edge_gate = t_lo × t_hi
        (5) Directional bright-side gate (pixels where gradient points away → bright side):
            bright_gate = clip(gx, 0, 1) × edge_gate / max(norm_mag)  — horizontal only
            [the bright side of a vertical edge is where gx > 0, i.e. the right side
            is brighter; for simplicity we use the horizontal Sobel component as a
            signed brightness indicator for the dominant edge direction]
        (6) Dark-side gate:
            dark_gate = clip(−gx, 0, 1) × edge_gate / max(norm_mag)
        (7) Warm fringe on bright side:
            out_r = clip(r + fringe_warm_r × bright_gate, 0, 1)
            out_g = clip(g + fringe_warm_g × bright_gate, 0, 1)
        (8) Cool fringe on dark side:
            out_b = clip(b + fringe_cool_b × dark_gate, 0, 1)
            out_r = clip(out_r − fringe_cool_r × dark_gate, 0, 1)
        (9) Composite at opacity.

        Distinct from ter_brugghen_raking_amber_pass (horizontal Sobel only as a
          TONAL surface-normal model for warm ridges and cool shadows across ALL
          midtone surfaces; no edge-gate; applies globally to the form surface,
          not specifically to high-contrast edge transition zones).
        Distinct from warm_cool_boundary_pass (global luma-threshold split into
          warm and cool temperature zones without Sobel edge detection or directionality;
          no gradient-magnitude gating; applies to all pixels in a luma zone regardless
          of whether they lie on a form edge).
        Distinct from gentile_da_fabriano_gold_tooling_pass (isotropic gradient
          magnitude × high-luma gate; no directional warm/cool split; applies a
          uniform warm-gold tint to lit ridges rather than a bidirectional
          warm/cool prismatic fringe on both sides of the edge simultaneously).

        Args:
            edge_lo/hi        : Normalised gradient magnitude range for edge gate.
                                Below edge_lo: noise (suppressed). Above edge_hi:
                                fully clipped specular zone (suppressed). Active on
                                real structural form edges.
            fringe_warm_r/g   : Warm amber-red tint applied to the bright side of edges.
            fringe_cool_b     : Cool blue-violet tint on the shadow side of edges.
            fringe_cool_r     : R reduction on the shadow side (pushes toward violet).
            opacity           : Composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2-3: Sobel gradients and normalised magnitude ─────────────────
        gx      = _sobel(luma, axis=1).astype(_np.float32)
        gy      = _sobel(luma, axis=0).astype(_np.float32)
        mag     = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)
        max_mag = float(mag.max()) or 1e-6
        norm_mag = _np.clip(mag / max_mag, 0.0, 1.0)

        # ── Step 4: Edge magnitude gate — active only on real structural edges ─
        edge_f    = (edge_lo + edge_hi) * 0.5
        denom_lo  = max(float(edge_f - edge_lo), 1e-6)
        denom_hi  = max(float(edge_hi - edge_f), 1e-6)
        t_lo      = _np.clip((norm_mag - edge_lo) / denom_lo, 0.0, 1.0)
        t_hi      = _np.clip((edge_hi - norm_mag) / denom_hi, 0.0, 1.0)
        edge_gate = (t_lo * t_hi).astype(_np.float32)

        # Normalised signed gradient components for directional gating
        gx_norm = (gx / max_mag).astype(_np.float32)

        # ── Step 5: Bright-side gate (gx > 0 → right side is brighter) ────────
        bright_gate = (_np.clip(gx_norm, 0.0, 1.0) * edge_gate).astype(_np.float32)

        # ── Step 6: Dark-side gate (gx < 0 → left side is brighter, right is dark) ─
        dark_gate   = (_np.clip(-gx_norm, 0.0, 1.0) * edge_gate).astype(_np.float32)

        # ── Step 7: Warm fringe on bright side ────────────────────────────────
        out_r = _np.clip(r0 + fringe_warm_r * bright_gate, 0.0, 1.0)
        out_g = _np.clip(g0 + fringe_warm_g * bright_gate, 0.0, 1.0)
        out_b = b0.copy()

        # ── Step 8: Cool fringe on dark side ──────────────────────────────────
        out_b = _np.clip(out_b + fringe_cool_b * dark_gate, 0.0, 1.0)
        out_r = _np.clip(out_r - fringe_cool_r * dark_gate, 0.0, 1.0)

        # ── Step 9: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Chromatic fringe pass complete.")

    # Session 157 — Giampietrino: dual-zone warm-highlight / cool-shadow tinting
    # ─────────────────────────────────────────────────────────────────────────

    def giampietrino_warm_devotion_pass(
        self,
        hi_lo:    float = 0.55,   # lower luminance boundary of highlight gate
        hi_hi:    float = 0.88,   # upper luminance boundary of highlight gate
        warm_r:   float = 0.055,  # R boost in highlight zone (warm amber push)
        warm_g:   float = 0.030,  # G boost in highlight zone
        shad_lo:  float = 0.05,   # lower luminance boundary of shadow gate
        shad_hi:  float = 0.42,   # upper luminance boundary of shadow gate
        cool_b:   float = 0.055,  # B boost in shadow zone (cool violet deepening)
        cool_r:   float = 0.022,  # R reduction in shadow zone (push toward violet)
        opacity:  float = 0.30,
    ) -> None:
        """Warm highlight amber + cool shadow violet — FORTIETH DISTINCT MODE.

        Giampietrino (Giovanni Pietro Rizzoli, c. 1495–1540) was Leonardo's most
        technically faithful Milanese pupil.  His devotional Madonnas and recumbent
        Magdalenes extend Leonardo's oil-glazing method with a distinctive DUAL-
        TEMPERATURE FLESH MODEL: warm honey-amber pushes the illuminated flesh crest
        while cool violet-plum deepens the recessed shadow face.  This luminance-
        gated tinting captures that chromatic two-temperature quality without
        depending on Sobel gradients or hue-proxy detection.

        This pass encodes those effects as the FORTIETH DISTINCT MODE:
        DUAL-ZONE LUMINANCE TINTING — WARM HIGHLIGHT AMBER + COOL SHADOW VIOLET.

        Algorithm:
        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Highlight gate — smooth bump in [hi_lo, hi_hi]:
            hi_f = (hi_lo + hi_hi) / 2
            t_lo = clip((luma − hi_lo) / (hi_f − hi_lo), 0, 1)
            t_hi = clip((hi_hi − luma) / (hi_hi − hi_f), 0, 1)
            hi_gate = t_lo × t_hi
        (3) Shadow gate — smooth bump in [shad_lo, shad_hi]:
            shad_f = (shad_lo + shad_hi) / 2; analogous construction
        (4) Apply warm amber to highlights:
            out_r = clip(r + warm_r × hi_gate, 0, 1)
            out_g = clip(g + warm_g × hi_gate, 0, 1)
        (5) Apply cool violet to shadows:
            out_b = clip(b + cool_b × shad_gate, 0, 1)
            out_r = clip(out_r − cool_r × shad_gate, 0, 1)
        (6) Composite at opacity.

        Distinct from beccafumi_nacreous_glow_pass (signed Gaussian BLOOM DIFFERENCE
          determines warm/cool zones — the sign of bloom-orig varies spatially based
          on convex/concave surface curvature, not fixed luminance thresholds).
        Distinct from bartolomeo_veneto_jewel_brocade_pass (HUE-PROXY detection:
          blue_proxy = clip(B−max(R,G), 0, 1); gold_proxy = clip(R−B, 0, 1)×clip(G−B×0.5,
          0, 1) — applies to hue-specific colour zones regardless of luminance level).
        Distinct from furini_moonlit_sfumato_pass (HIGHLIGHTS ONLY in [0.55, 0.92];
          applies cool silver: B+, R− in lit zones; no shadow tinting component).
        Distinct from melozzo_zenith_radiance_pass (VERTICAL POSITION axis: warm at
          top, cool at bottom — position-based not luminance-based gating).

        Args:
            hi_lo/hi_hi   : Luminance range for the highlight zone gate.
            warm_r/warm_g : Warm amber-honey tint added to highlight zone pixels.
            shad_lo/shad_hi: Luminance range for the shadow zone gate.
            cool_b        : Cool violet-blue tint added to shadow zone pixels.
            cool_r        : R reduction in shadow zone (pushes toward violet, not blue).
            opacity       : Composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Highlight gate — smooth bump in [hi_lo, hi_hi] ───────────
        hi_f    = (hi_lo + hi_hi) * 0.5
        hi_dlo  = max(float(hi_f - hi_lo), 1e-6)
        hi_dhi  = max(float(hi_hi - hi_f), 1e-6)
        hi_t_lo = _np.clip((luma - hi_lo) / hi_dlo, 0.0, 1.0)
        hi_t_hi = _np.clip((hi_hi - luma)  / hi_dhi, 0.0, 1.0)
        hi_gate = (hi_t_lo * hi_t_hi).astype(_np.float32)

        # ── Step 3: Shadow gate — smooth bump in [shad_lo, shad_hi] ──────────
        shad_f    = (shad_lo + shad_hi) * 0.5
        shad_dlo  = max(float(shad_f - shad_lo), 1e-6)
        shad_dhi  = max(float(shad_hi - shad_f), 1e-6)
        shad_t_lo = _np.clip((luma - shad_lo) / shad_dlo, 0.0, 1.0)
        shad_t_hi = _np.clip((shad_hi - luma)  / shad_dhi, 0.0, 1.0)
        shad_gate = (shad_t_lo * shad_t_hi).astype(_np.float32)

        # ── Step 4: Warm amber tint in highlights ─────────────────────────────
        out_r = _np.clip(r0 + warm_r * hi_gate, 0.0, 1.0)
        out_g = _np.clip(g0 + warm_g * hi_gate, 0.0, 1.0)
        out_b = b0.copy()

        # ── Step 5: Cool violet tint in shadows ───────────────────────────────
        out_b = _np.clip(out_b + cool_b * shad_gate, 0.0, 1.0)
        out_r = _np.clip(out_r - cool_r * shad_gate, 0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Giampietrino warm devotion pass complete.")

    # Session 157 — random improvement: peripheral_defocus_pass
    # ─────────────────────────────────────────────────────────────────────────

    def peripheral_defocus_pass(
        self,
        inner_radius:  float = 0.38,  # normalised radial fraction where blur begins (0=centre, 1=corner)
        blur_sigma:    float = 4.0,   # Gaussian blur sigma for maximum peripheral blur
        power:         float = 1.8,   # falloff exponent (higher = sharper centre-to-edge transition)
        blur_strength: float = 0.55,  # maximum blend fraction toward blurred image at far edge
        opacity:       float = 0.40,
    ) -> None:
        """Radial peripheral softening — FORTY-FIRST DISTINCT MODE.

        Old Master portrait painters deliberately softened the peripheral regions
        of their compositions to concentrate the viewer's attention on the face
        and hands.  Rembrandt, Velázquez, and the Leonardesque painters all employ
        this strategy: a central zone of relative sharpness surrounded by a zone
        of increasing tonal dissolution toward the canvas edges.  This is NOT the
        same as a vignette (which darkens edges) — peripheral softening preserves
        luminance while introducing spatial blur, simulating the natural fall-off
        of focal acuity in peripheral vision and the deliberate compositional
        softening in Old Master practice.

        This pass encodes that effect as the FORTY-FIRST DISTINCT MODE:
        RADIAL PERIPHERAL SOFTENING — SIMULATED DEPTH OF FIELD.

        Algorithm:
        (1) Compute normalised radial distance from canvas centre for each pixel:
            xs = linspace(0, 1, W) − 0.5; ys = linspace(0, 1, H) − 0.5
            dist = sqrt(xs² + ys²)  [meshgrid]
            max_dist = sqrt(0.5² + 0.5²) = 0.7071  [corner distance]
            dist_norm = clip(dist / max_dist, 0, 1)
        (2) Defocus weight map — 0 in centre, increases toward edges:
            raw_wt = clip((dist_norm − inner_radius) / (1 − inner_radius), 0, 1)
            defocus_wt = raw_wt^power × blur_strength
        (3) Full-canvas Gaussian blur per channel (sigma = blur_sigma)
        (4) Per-pixel blend: out_ch = ch × (1 − defocus_wt) + blurred_ch × defocus_wt
        (5) Composite at opacity.

        Distinct from focal_vignette_pass (DARKENS and COOLS edges by multiplying
          each channel by a vignette weight < 1 plus a cool blue shift; purely
          tonal manipulation — no spatial blurring; centre luminance is unchanged
          but edge luminance is reduced; this pass does NOT darken edges).
        Distinct from atmospheric_depth_gradient_pass (vertical linear temperature
          gradient: y_frac warms bottom pixels and cools top pixels regardless of
          horizontal position; no spatial blurring; no radial geometry).
        Distinct from penumbra_softening_pass (gradient-magnitude-weighted shadow-
          edge smoothing: applies Gaussian blur only to pixels on shadow-edge zones
          detected by combined luma gate × Sobel magnitude; not radial geometry).

        Args:
            inner_radius  : Normalised radial fraction (0–1) inside which no blur
                            is applied.  At 0.38 the sharp zone covers ~38% of the
                            corner-distance radius, keeping the figure centre sharp.
            blur_sigma    : Gaussian sigma for the peripheral blur kernel.
            power         : Exponent shaping the radial weight falloff.  1.8 gives
                            a gentle ramp; higher values sharpen the transition zone.
            blur_strength : Maximum blend fraction toward blurred image at the
                            canvas corners.  0.55 softens perimeter without fully
                            dissolving edge detail.
            opacity       : Composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gaussian_filter

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Radial distance from canvas centre ─────────────────────────
        xs       = (_np.linspace(0.0, 1.0, W, dtype=_np.float32) - 0.5)
        ys       = (_np.linspace(0.0, 1.0, H, dtype=_np.float32) - 0.5)
        xx, yy   = _np.meshgrid(xs, ys)
        dist     = _np.sqrt(xx * xx + yy * yy).astype(_np.float32)
        max_dist = float(_np.sqrt(0.5 * 0.5 + 0.5 * 0.5))   # = 0.7071 (corner)
        dist_norm = _np.clip(dist / max_dist, 0.0, 1.0)

        # ── Step 2: Defocus weight — 0 at centre, increases toward edges ──────
        denom     = max(1.0 - inner_radius, 1e-6)
        raw_wt    = _np.clip((dist_norm - inner_radius) / denom, 0.0, 1.0)
        defocus_wt = (raw_wt ** power * blur_strength).astype(_np.float32)

        # ── Step 3: Full-canvas Gaussian blur ─────────────────────────────────
        blur_r = _gaussian_filter(r0, sigma=blur_sigma).astype(_np.float32)
        blur_g = _gaussian_filter(g0, sigma=blur_sigma).astype(_np.float32)
        blur_b = _gaussian_filter(b0, sigma=blur_sigma).astype(_np.float32)

        # ── Step 4: Per-pixel blend of original and blurred ───────────────────
        out_r = r0 * (1.0 - defocus_wt) + blur_r * defocus_wt
        out_g = g0 * (1.0 - defocus_wt) + blur_g * defocus_wt
        out_b = b0 * (1.0 - defocus_wt) + blur_b * defocus_wt

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Peripheral defocus pass complete.")

    # Session 158 — Greuze (Jean-Baptiste Greuze, 1725–1805): greuze_sentimental_carnation_pass
    # ─────────────────────────────────────────────────────────────────────────

    def greuze_sentimental_carnation_pass(
        self,
        carn_lo:    float = 0.38,   # lower bound of carnation mid-flesh gate
        carn_hi:    float = 0.80,   # upper bound of carnation mid-flesh gate
        carn_r:     float = 0.048,  # warm rose-carnation R lift in flesh zone
        carn_g:     float = 0.012,  # gentle G lift (keeps flesh warm, not purely red)
        carn_b:     float = 0.022,  # B reduction in flesh zone (completes rose-carnation direction)
        dew_lo:     float = 0.82,   # lower bound of dewy peak-highlight gate
        dew_hi:     float = 1.00,   # upper bound of dewy peak-highlight gate
        dew_b:      float = 0.030,  # cool-pearl B lift at specular peaks (dewy moisture)
        dew_r:      float = 0.012,  # R reduction at specular peaks (ensures pearl not yellow)
        opacity:    float = 0.30,
    ) -> None:
        """Sentimental carnation glow — FORTY-SECOND DISTINCT MODE.

        Jean-Baptiste Greuze (1725–1805) is the supreme practitioner of the
        'tête d'expression' — the sentimental expression head, almost always of
        a young woman rendered with extraordinary emotional immediacy.  His flesh
        tones deploy a distinctive TWO-REGISTER colour system that no other painter
        in the French Academic tradition replicates exactly:

          1. WARM ROSE-CARNATION in the mid-flesh zone [0.38–0.80 luminance]:
             Not the amber-honey of Venetian painters, not the ivory-cool of the
             Northern masters, but a French rose — a warm reddish-pink flush as if
             warm blood were visible beneath translucent skin.  Greuze amplifies
             the R channel and slightly boosts G (to stay in rose rather than pure
             red) while reducing B slightly (to push toward rose rather than neutral
             warm).

          2. COOL-PEARL DEWY SHIMMER at the specular peak [0.82–1.0 luminance]:
             The characteristic 'dewy' quality of Greuze's eyes, lips, and forehead
             highlights.  At the very brightest point — where a specular highlight
             catches — he applies a cool-pearl tone (B+, R−) that makes the surface
             read as moist, luminous, and alive.  This is distinct from golden warm
             highlights (Venetian) and from silver highlights (Reni, Northern):
             Greuze's peak is cool-white with a faint pearl-blue cast, as if the
             surface is slightly wet.

        The combination is Greuze's signature: warm-rose mid-flesh rising to a
        cool-pearl specular tip — giving his subjects the impression of warm living
        flesh capped by a cool, glistening surface.  No other painter in the catalog
        applies BOTH a warm carnation lift to mid-tones AND a cool-pearl shimmer to
        the specular peak as separate gated operations.

        Algorithm — FORTY-SECOND DISTINCT MODE:
        SENTIMENTAL CARNATION GLOW — WARM ROSE-FLESH + COOL DEWY PEARL SHIMMER.

        (1) Compute luminance: luma = 0.299R + 0.587G + 0.114B
        (2) Carnation gate — smooth bump in [carn_lo, carn_hi]:
            carn_f = (carn_lo + carn_hi) / 2
            t_lo = clip((luma − carn_lo) / (carn_f − carn_lo), 0, 1)
            t_hi = clip((carn_hi − luma) / (carn_hi − carn_f), 0, 1)
            carn_gate = t_lo × t_hi
        (3) Apply warm rose-carnation to mid-flesh:
            out_r = clip(r + carn_r × carn_gate, 0, 1)
            out_g = clip(g + carn_g × carn_gate, 0, 1)
            out_b = clip(b − carn_b × carn_gate, 0, 1)
        (4) Dewy shimmer gate — smooth bump in [dew_lo, dew_hi]:
            dew_f = (dew_lo + dew_hi) / 2; analogous construction
        (5) Apply cool-pearl dewy shimmer to specular peaks:
            out_b = clip(out_b + dew_b × dew_gate, 0, 1)
            out_r = clip(out_r − dew_r × dew_gate, 0, 1)
        (6) Composite at opacity.

        Distinct from giampietrino_warm_devotion_pass (hi gate [0.55, 0.88] applies
          AMBER tint: R+G+, B untouched; shad gate [0.05, 0.42] applies VIOLET: B+R−;
          amber differs from rose-carnation: amber pushes toward yellow (R+G+B0),
          carnation pushes toward red-rose (R+G+small B−); no specular dewy zone in
          Giampietrino's pass — it stops at hi_hi=0.88, well below specular peaks).
        Distinct from furini_moonlit_sfumato_pass (HIGHLIGHTS ONLY in [0.55, 0.92];
          applies COOL SILVER: B+, R− only — purely a cool-toning pass with zero warm
          component; Greuze's pass has a WARM mid-flesh component which Furini lacks).
        Distinct from beccafumi_nacreous_glow_pass (Gaussian BLOOM DIFFERENCE determines
          warm/cool zone boundaries based on surface convexity sign; spatial rather than
          fixed luminance-threshold gating; no rose-carnation hue direction).
        Distinct from bartolomeo_veneto_jewel_brocade_pass (HUE-PROXY detection:
          blue_proxy = clip(B−max(R,G),0,1); gold_proxy = clip(R−B,0,1)×clip(G−B×0.5,0,1);
          applies to hue-specific fabric/brocade zones regardless of luminance level;
          not a flesh-toning pass and has no dewy shimmer zone).

        Args:
            carn_lo/carn_hi : Luminance range of the warm rose-carnation gate.
            carn_r          : R lift in carnation zone (the primary rose push).
            carn_g          : G lift in carnation zone (keeps rose warm, not pure red).
            carn_b          : B reduction in carnation zone (completes rose-carnation direction).
            dew_lo/dew_hi   : Luminance range of the cool-pearl dewy shimmer gate.
            dew_b           : B lift at specular peaks (the pearl-moisture effect).
            dew_r           : R reduction at specular peaks (ensures pearl not warm-white).
            opacity         : Composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Carnation gate — smooth bump in [carn_lo, carn_hi] ────────
        carn_f   = (carn_lo + carn_hi) * 0.5
        c_dlo    = max(float(carn_f - carn_lo), 1e-6)
        c_dhi    = max(float(carn_hi - carn_f),  1e-6)
        c_t_lo   = _np.clip((luma - carn_lo) / c_dlo,  0.0, 1.0)
        c_t_hi   = _np.clip((carn_hi - luma)  / c_dhi, 0.0, 1.0)
        carn_gate = (c_t_lo * c_t_hi).astype(_np.float32)

        # ── Step 3: Apply warm rose-carnation to mid-flesh ────────────────────
        out_r = _np.clip(r0 + carn_r * carn_gate, 0.0, 1.0)
        out_g = _np.clip(g0 + carn_g * carn_gate, 0.0, 1.0)
        out_b = _np.clip(b0 - carn_b * carn_gate, 0.0, 1.0)

        # ── Step 4: Dewy shimmer gate — smooth bump in [dew_lo, dew_hi] ──────
        dew_f   = (dew_lo + dew_hi) * 0.5
        d_dlo   = max(float(dew_f - dew_lo), 1e-6)
        d_dhi   = max(float(dew_hi - dew_f),  1e-6)
        d_t_lo  = _np.clip((luma - dew_lo) / d_dlo,  0.0, 1.0)
        d_t_hi  = _np.clip((dew_hi - luma)  / d_dhi, 0.0, 1.0)
        dew_gate = (d_t_lo * d_t_hi).astype(_np.float32)

        # ── Step 5: Apply cool-pearl dewy shimmer to specular peaks ───────────
        out_b = _np.clip(out_b + dew_b * dew_gate, 0.0, 1.0)
        out_r = _np.clip(out_r - dew_r * dew_gate, 0.0, 1.0)

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Greuze sentimental carnation pass complete.")

    # Session 158 — random improvement: edge_sfumato_dissolution_pass
    # ─────────────────────────────────────────────────────────────────────────

    def edge_sfumato_dissolution_pass(
        self,
        grad_threshold: float = 0.10,  # gradient magnitude above which sfumato begins
        edge_power:     float = 1.5,   # exponent shaping gradient-to-dissolution mapping
        edge_strength:  float = 0.70,  # maximum dissolution fraction at steepest edges
        blur_sigma:     float = 2.5,   # Gaussian blur sigma applied to edge zones
        opacity:        float = 0.35,
    ) -> None:
        """Gradient-selective edge dissolution — FORTY-THIRD DISTINCT MODE.

        Sfumato is not a global haze.  In Leonardo's practice — and in the work
        of his followers in the Lombard and Florentine schools — sfumato is applied
        SPECIFICALLY at the boundaries where one form meets another: the edge of
        the cheek where it meets the shadow of the neck, the lid-margin where the
        eyelid dissolves into the shadowed socket, the hairline where dark hair
        meets the pale brow.  The interior of the cheek, by contrast, is smooth
        and well-defined; the sfumato is a BOUNDARY PHENOMENON, not a surface one.

        This pass encodes that insight as the FORTY-THIRD DISTINCT MODE:
        GRADIENT-SELECTIVE EDGE DISSOLUTION — SFUMATO AT FORM BOUNDARIES.

        The algorithm uses the Sobel gradient magnitude as a proxy for 'edge strength'.
        Where the gradient is high, the image is locally sharp — a form boundary is
        present.  The pass selectively blurs those high-gradient zones, dissolving
        them into the surrounding tones exactly as Leonardo's successive glazes
        dissolved the contour of the Mona Lisa's lips into the surrounding flesh.
        Low-gradient zones (smooth interior flesh, open sky) are left unchanged.

        Algorithm:
        (1) Read canvas as float32 RGB in [0, 1].
        (2) Compute per-channel Sobel gradient:
            Gx kernel = [[-1,0,1],[-2,0,2],[-1,0,1]] (horizontal edges)
            Gy kernel = [[-1,-2,-1],[0,0,0],[1,2,1]]  (vertical edges)
            For each channel c: grad_c = sqrt(convolve(c, Gx)² + convolve(c, Gy)²)
            grad_mag = (grad_r + grad_g + grad_b) / 3.0
        (3) Normalise: grad_norm = clip(grad_mag / grad_threshold, 0, 1)
        (4) Edge dissolution weight:
            edge_wt = grad_norm^edge_power × edge_strength
        (5) Apply full-canvas Gaussian blur (sigma = blur_sigma) per channel.
        (6) Per-pixel blend at each position:
            out_ch = orig_ch × (1 − edge_wt) + blurred_ch × edge_wt
        (7) Composite at opacity.

        Distinct from penumbra_softening_pass (uses LUMA gate × Sobel magnitude:
          only dissolves edges WITHIN a specific luminance range [pen_lo, pen_hi];
          high-gradient edges in highlights or deep shadows are NOT softened; this
          pass dissolves ALL high-gradient edges regardless of luminance zone).
        Distinct from peripheral_defocus_pass (RADIAL GEOMETRY: blur weight increases
          with distance from canvas centre regardless of local gradient content;
          low-gradient peripheral pixels are blurred; high-gradient central pixels
          are not; this pass is purely gradient-driven, not position-driven).
        Distinct from atmospheric_depth_gradient_pass (vertical linear temperature
          gradient applied as a colour shift, no spatial blurring, no gradient
          detection — purely a tonal warming/cooling operation along the Y axis).

        Args:
            grad_threshold : Gradient magnitude (0–1 scale) at which dissolution
                             reaches full strength.  Smaller values dissolve even
                             subtle edges; larger values only dissolve sharp contours.
            edge_power     : Exponent applied to grad_norm before scaling by
                             edge_strength.  Higher values restrict dissolution to
                             only the sharpest edges.
            edge_strength  : Maximum blend fraction toward blurred image at the
                             steepest gradient positions.
            blur_sigma     : Gaussian sigma for the edge-dissolution kernel.  Larger
                             values produce a wider, more sfumato-like softening.
            opacity        : Composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, convolve as _convolve

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Sobel kernels ─────────────────────────────────────────────
        Kx = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        Ky = _np.array([[-1, -2, -1], [0, 0, 0], [1, 2, 1]], dtype=_np.float32)

        # ── Step 2: Per-channel gradient magnitude ────────────────────────────
        def _grad_mag(ch: "_np.ndarray") -> "_np.ndarray":
            gx = _convolve(ch, Kx, mode="reflect").astype(_np.float32)
            gy = _convolve(ch, Ky, mode="reflect").astype(_np.float32)
            return _np.sqrt(gx * gx + gy * gy)

        grad_r   = _grad_mag(r0)
        grad_g   = _grad_mag(g0)
        grad_b   = _grad_mag(b0)
        grad_mag = ((grad_r + grad_g + grad_b) / 3.0).astype(_np.float32)

        # ── Step 3: Normalise gradient ────────────────────────────────────────
        grad_norm = _np.clip(grad_mag / max(float(grad_threshold), 1e-6), 0.0, 1.0)

        # ── Step 4: Edge dissolution weight ───────────────────────────────────
        edge_wt = (grad_norm ** edge_power * edge_strength).astype(_np.float32)

        # ── Step 5: Full-canvas Gaussian blur ─────────────────────────────────
        blur_r = _gf(r0, sigma=blur_sigma).astype(_np.float32)
        blur_g = _gf(g0, sigma=blur_sigma).astype(_np.float32)
        blur_b = _gf(b0, sigma=blur_sigma).astype(_np.float32)

        # ── Step 6: Per-pixel blend — dissolve edges into surrounding tone ────
        out_r = r0 * (1.0 - edge_wt) + blur_r * edge_wt
        out_g = g0 * (1.0 - edge_wt) + blur_g * edge_wt
        out_b = b0 * (1.0 - edge_wt) + blur_b * edge_wt

        # ── Step 7: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Edge sfumato dissolution pass complete.")

    # Session 159 — Antonio Moro (c. 1519–c. 1575): moro_regal_presence_pass
    # ─────────────────────────────────────────────────────────────────────────

    def moro_regal_presence_pass(
        self,
        shadow_hi:       float = 0.38,   # luminance below which shadow deepening operates
        shadow_power:    float = 1.4,    # exponent shaping shadow-gate falloff
        shadow_deepen:   float = 0.18,   # maximum fractional darkening at luma=0
        highlight_lo:    float = 0.68,   # luminance above which highlight crystallisation begins
        highlight_power: float = 1.6,    # exponent shaping highlight-gate ramp
        silver_b:        float = 0.022,  # cool-silver B lift in the crystalline highlight zone
        silver_r:        float = 0.010,  # R reduction in highlight zone (ensures silver not warm)
        opacity:         float = 0.30,
    ) -> None:
        """High-polarity tonal amplification — FORTY-FOURTH DISTINCT MODE.

        Antonio Moro (Anthonis Mor van Dashorst, c. 1519–c. 1575) is the supreme
        Flemish-Spanish court portraitist — the painter who gave the Habsburg courts
        their definitive visual gravity.  His technical signature is a high-polarity
        tonal contrast system built from two deliberate choices:

          1. VERY DARK GROUNDS: Moro works over a near-black umber imprimatura that
             he never completely covers.  His shadows are therefore almost absolute:
             the dark ground shows through thin paint in the shadow passages, giving
             a near-total darkness that concentrates attention on the illuminated zones.

          2. PRECISELY CALIBRATED HIGHLIGHTS: Against this near-black ground, his
             highlights are precise, economical, and cool-silver.  He does not use
             the warm amber highlights of the Venetian school; his light is Northern —
             cool, exact, and controlled.  A single fleck of cool-white marks the
             specular peak of a pearl; a precise band of silver catches the pile of
             black velvet.

        The combination produces COURT PORTRAIT GRAVITY: the impression of a person
        of absolute authority emerging from near-total darkness into a controlled pool
        of Northern light.  Nothing in Moro's portraits is accidentally illuminated;
        everything has been deliberately calibrated.

        Algorithm — FORTY-FOURTH DISTINCT MODE:
        HIGH-POLARITY TONAL AMPLIFICATION — COURT PORTRAIT GRAVITY.

        (A) Shadow deepening gate [0, shadow_hi]:
            shadow_gate = clip((shadow_hi − luma) / shadow_hi, 0, 1)^shadow_power
            out_c = c × (1 − shadow_deepen × shadow_gate)   [for each channel]
            Direction: darkens pixels toward near-black as luminance approaches 0.
            The gate falls to zero at luma=shadow_hi (ensuring bright pixels
            are completely unaffected) and reaches its maximum at luma=0.

        (B) Highlight crystallisation gate [highlight_lo, 1.0]:
            hi_gate = clip((luma − highlight_lo) / (1 − highlight_lo), 0, 1)^highlight_power
            out_b = clip(b + silver_b × hi_gate, 0, 1)
            out_r = clip(r − silver_r × hi_gate, 0, 1)
            Direction: adds cool-silver (B+ R−) to the brightest pixels.
            The gate increases monotonically from highlight_lo to 1.0 — unlike
            Greuze's BUMP gate (which has an upper cutoff), this is a ONE-SIDED
            RAMP that concentrates maximum crystallisation at the very brightest pixels.

        (C) Composite at opacity.

        Distinct from focal_vignette_pass (DARKENS AND COOLS EDGES by radial
          multiplication — position-gated, not luminance-gated; the vignette darkens
          peripheral pixels regardless of their luminance; Moro's deepening is
          luminance-gated: even peripheral bright highlights are left undarkened).
        Distinct from giampietrino_warm_devotion_pass (shadow gate [0.05, 0.42] applies
          VIOLET TINT: B+, R− in shadows — color tinting, not multiplicative darkening;
          highlight gate [0.55, 0.88] applies AMBER TINT: R+, G+ — warm direction
          opposite to Moro's cool-silver; Moro does NOT add any violet to shadows,
          only darkens them multiplicatively).
        Distinct from furini_moonlit_sfumato_pass (HIGHLIGHTS ONLY in [0.55, 0.92] bump
          gate with upper cutoff; applies COOL SILVER B+ R− — same color direction as
          Moro's highlight, but FURINI'S gate is a BUMP (rises then falls) while Moro's
          is a ONE-SIDED RAMP (rises monotonically to maximum at luma=1.0); Furini also
          has no shadow deepening component — no darkening at all; Moro's pass is
          bipartite: shadow deepening + highlight crystallisation).
        Distinct from greuze_sentimental_carnation_pass (BUMP gate for both components:
          carnation [0.38, 0.80] and dewy [0.82, 1.0]; applies ROSE-CARNATION R+G+B−
          in mid-flesh, not darkening; dewy has B+ R− but in a very narrow bump at
          peak luma with upper cutoff at 1.0 and lower at 0.82 — Moro's ramp has
          highlight_lo default 0.68, lower than Greuze's dew_lo=0.82; also Moro has
          NO rose-carnation mid-flesh component whatsoever).

        Args:
            shadow_hi       : Luminance threshold below which shadow deepening is active.
            shadow_power    : Exponent shaping shadow-gate strength vs. luminance.
            shadow_deepen   : Fraction by which deep shadows are darkened (0 = no-op).
            highlight_lo    : Luminance threshold above which highlight crystallisation begins.
            highlight_power : Exponent shaping highlight-gate ramp.
            silver_b        : B lift in crystalline highlight zone (the cool-silver push).
            silver_r        : R reduction in highlight zone (prevents warm-white).
            opacity         : Composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(self.h, self.w, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Luminance ─────────────────────────────────────────────────
        luma = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Step 2: Shadow deepening gate ─────────────────────────────────────
        shadow_gate = _np.zeros_like(luma)
        if shadow_hi > 0.0:
            raw = _np.clip((shadow_hi - luma) / float(shadow_hi), 0.0, 1.0)
            shadow_gate = (raw ** shadow_power).astype(_np.float32)
        darken = (1.0 - shadow_deepen * shadow_gate).astype(_np.float32)
        out_r = _np.clip(r0 * darken, 0.0, 1.0)
        out_g = _np.clip(g0 * darken, 0.0, 1.0)
        out_b = _np.clip(b0 * darken, 0.0, 1.0)

        # ── Step 3: Highlight crystallisation gate ────────────────────────────
        hi_range = max(1.0 - float(highlight_lo), 1e-6)
        raw_hi = _np.clip((luma - highlight_lo) / hi_range, 0.0, 1.0)
        hi_gate = (raw_hi ** highlight_power).astype(_np.float32)
        out_b = _np.clip(out_b + silver_b * hi_gate, 0.0, 1.0)
        out_r = _np.clip(out_r - silver_r * hi_gate, 0.0, 1.0)

        # ── Step 4: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Moro regal presence pass complete.")

    # Session 159 — random improvement: skin_subsurface_scatter_pass
    # ─────────────────────────────────────────────────────────────────────────

    def skin_subsurface_scatter_pass(
        self,
        scatter_sigma:  float = 5.0,    # Gaussian sigma for scatter spread (simulates dermis depth)
        scatter_strength: float = 0.22, # maximum blend toward scattered image in skin zones
        warm_boost:     float = 1.04,   # multiplicative R warm lift on scattered component
        cool_damp:      float = 0.97,   # multiplicative B cool damp on scattered component
        mask_sigma:     float = 10.0,   # Gaussian sigma for skin mask softening
        opacity:        float = 0.28,
    ) -> None:
        """Skin subsurface light scattering — FORTY-FIFTH DISTINCT MODE.

        In every living human face, light does not simply bounce off the surface of
        the skin and return to the eye.  It penetrates the epidermis, scatters within
        the dermis (which contains blood vessels, collagen, and lipids), and re-emerges
        at a point several millimetres from where it entered — slightly reddened
        because the shorter wavelengths (blue, green) scatter and are partially absorbed
        by the blood in the dermis, while red wavelengths penetrate deeper and re-emerge.

        Every Renaissance master who achieved great flesh painting understood this
        intuitively, even without the vocabulary of light physics.  Leonardo's sfumato
        seeks it.  Rubens's semi-transparent flesh glazes seek it.  Titian's multi-layer
        glazing over a warm ground seeks it.  The defining quality of OLD MASTER FLESH —
        that it appears to be illuminated FROM WITHIN rather than simply reflecting
        surface light — is precisely the subsurface scatter phenomenon rendered in oil.

        This pass encodes that insight computationally as the FORTY-FIFTH DISTINCT MODE:
        SKIN SUBSURFACE LIGHT SCATTERING — WARM-RED TRANSLUCENCY GLOW.

        The algorithm:

        (1) SKIN DETECTION — identify warm flesh pixels by color range:
            skin_raw = (r > 0.40) AND (r > g) AND (g > b) AND (r − b > 0.10)
            This selects pixels that are warm-colored (reddish-to-ochre) without
            being too dark (pure brown hair/shadow) or too neutral (background).
            The binary mask is Gaussian-blurred (sigma=mask_sigma) to produce a
            smooth skin weight map skin_mask ∈ [0, 1].

        (2) SCATTER SPREAD — apply large-sigma Gaussian blur to the full image
            (sigma=scatter_sigma, default=5.0).  This blurs each color value by
            averaging it with its neighbors over a ~15–20px radius, simulating
            how light that enters a point spreads outward beneath the surface and
            re-emerges as a weighted average of the surrounding surface irradiance.

        (3) WARM-RED TINTING — the scattered component is warm-tinted:
            warm_r = clip(blur_r × warm_boost, 0, 1)   [warm_boost > 1: R lift]
            warm_b = clip(blur_b × cool_damp, 0, 1)    [cool_damp < 1: B damp]
            This mimics the spectral reddening of scattered light within the dermis.

        (4) SKIN-BLENDING — blend scattered with original proportional to skin_mask:
            blend_wt = skin_mask × scatter_strength
            scatter_c = orig_c × (1 − blend_wt) + warm_spread_c × blend_wt

        (5) Composite at opacity.

        Distinct from greuze_sentimental_carnation_pass (LUMINANCE-GATED COLOR
          TINTING: applies R+G+B− in [0.38, 0.80] mid-flesh zone regardless of
          whether the pixel is actually flesh-colored — if a blue background pixel
          has luminance in the gate range, it too is rose-tinted; subsurface scatter
          uses COLOR RANGE detection (r > g > b, r−b > 0.10) ensuring only actual
          warm flesh pixels receive the treatment; Greuze's pass does NO spatial
          spreading — it tints each pixel independently; this pass spreads the color
          information spatially over a Gaussian radius before blending back).
        Distinct from beccafumi_nacreous_glow_pass (Gaussian BLOOM DIFFERENCE
          sign determines warm/cool zones based on SURFACE CONVEXITY: the difference
          between a lightly-blurred and heavily-blurred image has positive sign on
          convex surface peaks and negative on concave shadow valleys; this is a
          SURFACE GEOMETRY detector, not a tissue-type detector; beccafumi can fire
          on convex metalwork, fabric highlights, or any bright convex surface;
          subsurface scatter fires only on warm-flesh colored pixels).
        Distinct from peripheral_defocus_pass (RADIAL GEOMETRIC softening: blur
          weight increases with distance from canvas centre, not with tissue type;
          cold background pixels at the periphery are blurred; warm flesh pixels at
          the centre are sharpened by the (1−defocus_wt) factor; no warm-red
          direction; fundamentally a DEPTH-OF-FIELD simulation, not a skin model).
        Distinct from giampietrino_warm_devotion_pass (LUMINANCE-GATED amber+violet
          tinting: hi gate applies AMBER R+G+ to all mid-bright pixels including
          background ochre tones; shad gate applies VIOLET B+R− to all shadow pixels
          regardless of color; no spatial spreading; no skin detection by color range).

        Args:
            scatter_sigma   : Gaussian blur sigma for the scatter spread. Larger values
                              simulate deeper dermis penetration (more diffuse glow).
            scatter_strength: Maximum blend fraction toward scattered image in skin zones.
            warm_boost      : Multiplicative R lift on scattered component (red tinting).
            cool_damp       : Multiplicative B reduction on scattered component (B damp).
            mask_sigma      : Gaussian sigma for softening the binary skin detection mask.
            opacity         : Composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Skin detection by color range ─────────────────────────────
        skin_raw = (
            (r0 > 0.40).astype(_np.float32) *
            (r0 > g0).astype(_np.float32) *
            (g0 > b0).astype(_np.float32) *
            ((r0 - b0) > 0.10).astype(_np.float32)
        )
        skin_mask = _np.clip(
            _gf(skin_raw, sigma=float(mask_sigma)), 0.0, 1.0
        ).astype(_np.float32)

        # ── Step 2: Scatter spread — large Gaussian over full image ───────────
        blur_r = _gf(r0, sigma=float(scatter_sigma)).astype(_np.float32)
        blur_g = _gf(g0, sigma=float(scatter_sigma)).astype(_np.float32)
        blur_b = _gf(b0, sigma=float(scatter_sigma)).astype(_np.float32)

        # ── Step 3: Warm-red tinting of scattered component ───────────────────
        warm_r = _np.clip(blur_r * float(warm_boost), 0.0, 1.0)
        warm_g = blur_g                             # green channel unchanged
        warm_b = _np.clip(blur_b * float(cool_damp), 0.0, 1.0)

        # ── Step 4: Skin-blending ─────────────────────────────────────────────
        blend_wt = (skin_mask * float(scatter_strength)).astype(_np.float32)
        out_r = r0 * (1.0 - blend_wt) + warm_r * blend_wt
        out_g = g0 * (1.0 - blend_wt) + warm_g * blend_wt
        out_b = b0 * (1.0 - blend_wt) + warm_b * blend_wt

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Skin subsurface scatter pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Baldung Grien spectral pallor — session 160 addition
    # ─────────────────────────────────────────────────────────────────────────

    def baldung_grien_spectral_pallor_pass(
        self,
        pallor_strength:  float = 0.18,   # max skin pallor blend weight
        pallor_r_reduce:  float = 0.08,   # R reduction in pallor zone (desaturate warm red)
        pallor_g_boost:   float = 0.12,   # G boost in pallor zone (acid-green direction)
        pallor_b_reduce:  float = 0.04,   # B reduction (yellow-green not blue-green)
        acid_bg_strength: float = 0.10,   # acid-green boost in non-skin mid-tone zones
        bg_green:         float = 0.10,   # G boost amount for background acid bite
        skin_sigma:       float = 8.0,    # Gaussian sigma for skin mask softening
        opacity:          float = 0.25,
    ) -> None:
        """Spectral flesh pallor — FORTY-SIXTH DISTINCT MODE.

        Hans Baldung Grien (c. 1484/85–1545) is the most psychologically
        unsettling German painter of the Renaissance.  His flesh has a
        SPECTRAL PALLOR — an acid-green, grey-cool undertone beneath the
        surface warmth, as if skin retains the memory of death.  His name
        'Grien' derives from his habitual use of acid yellow-green, a
        constant chromatic signature appearing in foliage, supernatural light,
        and the eerie pallor of flesh at the boundary of life and death.

        This pass encodes that chromatic insight as the FORTY-SIXTH DISTINCT
        MODE: SPECTRAL FLESH PALLOR — ACID-GREEN CHROMATIC TENSION.

        The algorithm:

        (1) FLESH DETECTION — identify warm flesh pixels by color range:
            skin_raw = (r > 0.38) AND (r > g * 1.05) AND (g > b * 1.02)
            Gaussian blur of the binary mask (sigma=skin_sigma) → skin_mask ∈ [0, 1].

        (2) MID-TONE GATE — pallor_gate = 4 * luma * (1 - luma)
            Quadratic gate peaking at luma=0.50, zero at luma=0 and luma=1.
            Targets mid-flesh zones; spares pure shadows and pure highlights.

        (3) PALLOR TINTING (skin zone):
            weight = skin_mask × pallor_gate × pallor_strength
            out_r = r - pallor_r_reduce × weight     [R-: reduce warm red]
            out_g = g + pallor_g_boost   × weight    [G+: acid-green pallor]
            out_b = b - pallor_b_reduce  × weight    [B-: yellow not blue-green]
            Net direction: R-G+B- = acid-yellow-green spectral pallor.

        (4) BACKGROUND ACID BITE (non-skin zone):
            bg_weight = (1 - skin_mask) × pallor_gate × acid_bg_strength
            out_g = g + bg_green × bg_weight
            Simulates Baldung's vivid acid-green landscape and supernatural greens.

        (5) Composite at opacity.

        Distinct from skin_subsurface_scatter_pass (WARM-RED R+ translucency:
          warm_boost > 1, cool_damp < 1; positive R direction; spatial Gaussian
          spreading of warm color across dermis; Baldung's pass goes R- —
          specifically reduces warmth rather than enhancing it; Baldung's G+
          is chromatic pallor tension, not thermal luminosity from below).
        Distinct from giampietrino_warm_devotion_pass (LUMINANCE-GATED amber
          hi-gate R+G+; violet shad-gate B+R-; no skin color detection by
          color range; no background acid-green treatment; applies to all
          mid-bright pixels regardless of color — background ochres receive
          the same amber tint as flesh; Baldung's pass is skin-specific and
          has a separate background treatment with opposing G+ direction).
        Distinct from morisot_plein_air_pass (violet shadow cooling B+R-; warm
          R+ in mid-bright zones; designed for Impressionist luminosity, not
          Germanic pallor; no skin mask; no acid-green background treatment;
          the B+ direction in shadows is opposite to Baldung's B- direction).
        Distinct from beccafumi_nacreous_glow_pass (surface convexity detection
          via bloom-difference sign: warm+ on convex peaks, cool- in concavities;
          fires on any bright convex surface including metalwork and fabric;
          not skin-specific by color range; no acid-green background treatment;
          the convexity detector is a GEOMETRY signal, Baldung's is a COLOR signal).

        Args:
            pallor_strength  : Maximum blend weight for the skin pallor effect.
            pallor_r_reduce  : R channel reduction in the pallor zone (desaturate red).
            pallor_g_boost   : G channel boost in the pallor zone (acid-green direction).
            pallor_b_reduce  : B channel reduction (yellow-green, not blue-green).
            acid_bg_strength : Acid-green intensity in non-skin mid-tone areas.
            bg_green         : G boost amount for background acid bite.
            skin_sigma       : Gaussian blur sigma for skin mask softening.
            opacity          : Composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        # ── Step 1: Flesh detection ───────────────────────────────────────────
        skin_raw = (
            (r0 > 0.38) &
            (r0 > g0 * 1.05) &
            (g0 > b0 * 1.02)
        ).astype(_np.float32)
        skin_mask = _np.clip(_gf(skin_raw, sigma=skin_sigma), 0.0, 1.0)

        # ── Step 2: Mid-tone gate ─────────────────────────────────────────────
        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0
        pallor_gate = 4.0 * luma * (1.0 - luma)   # quadratic peak at luma=0.5

        # ── Step 3: Pallor tinting (skin zone) ───────────────────────────────
        weight = skin_mask * pallor_gate * pallor_strength
        out_r = r0 - pallor_r_reduce * weight
        out_g = g0 + pallor_g_boost  * weight
        out_b = b0 - pallor_b_reduce * weight

        # ── Step 4: Background acid bite (non-skin zone) ──────────────────────
        bg_weight = (1.0 - skin_mask) * pallor_gate * acid_bg_strength
        out_g = out_g + bg_green * bg_weight

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Baldung Grien spectral pallor pass complete.")

    def reynolds_grand_manner_pass(
        self,
        amber_strength:   float = 0.06,   # flat amber glaze intensity (non-gated)
        amber_r:          float = 0.08,   # R lift for amber glaze
        amber_g:          float = 0.04,   # G lift for amber glaze (small)
        amber_b_reduce:   float = 0.06,   # B reduction for amber glaze
        highlight_lo:     float = 0.70,   # luma threshold for impasto highlight gate
        highlight_power:  float = 1.5,    # exponent shaping the hi gate ramp
        hi_boost:         float = 0.05,   # brightness boost at highlights
        shadow_hi:        float = 0.32,   # luma threshold for shadow deepening gate
        shadow_power:     float = 1.5,    # exponent shaping the shadow gate ramp
        shadow_deepen_r:  float = 0.14,   # R channel shadow deepen (most — warm umber direction)
        shadow_deepen_g:  float = 0.12,   # G channel shadow deepen (mid)
        shadow_deepen_b:  float = 0.10,   # B channel shadow deepen (least — preserves warmth)
        opacity:          float = 0.35,
    ) -> None:
        """Mezzotint tone — FORTY-SEVENTH DISTINCT MODE.

        Sir Joshua Reynolds (1723–1792) founded the British Royal Academy and
        invented the MEZZOTINT TONE: a unifying warm amber-brown glaze pulled
        across the entire composition to harmonise every element — flesh, drapery,
        landscape, architecture — into a single warm, velvety key.  The name
        reflects the characteristic tonality of the mezzotint engravings made
        after his work.

        This pass encodes that innovation as the FORTY-SEVENTH DISTINCT MODE:
        MEZZOTINT TONE — GRAND MANNER WARM AMBER UNIFICATION.

        Algorithm (four steps):

        (1) FLAT AMBER GLAZE (non-gated, applied uniformly at every luminance):
            out_r = r + amber_r × amber_strength    [R+]
            out_g = g + amber_g × amber_strength    [G+ small]
            out_b = b − amber_b_reduce × amber_strength    [B−]
            No luminance gate — the warm shift is applied to ALL pixels uniformly.
            This is the mezzotint tone: a flat, constant amber colour temperature
            shift that harmonises every hue in the composition.

        (2) IMPASTO HIGHLIGHT BRIGHTENING (luma-gated high):
            luma = 0.2126r + 0.7152g + 0.0722b
            hi_gate = clip((luma − highlight_lo) / (1 − highlight_lo), 0, 1)^highlight_power
            out_r += hi_boost × hi_gate
            out_g += hi_boost × 0.85 × hi_gate
            Direction: warm white R+G+ (lead-white impasto mixed with warm pigment).
            Monotonically increasing ramp from highlight_lo to 1.0, no upper cutoff.

        (3) SHADOW BITUMEN DEEPENING (luma-gated low):
            shad_gate = clip((shadow_hi − luma) / shadow_hi, 0, 1)^shadow_power
            out_r *= (1 − shadow_deepen_r × shad_gate)
            out_g *= (1 − shadow_deepen_g × shad_gate)
            out_b *= (1 − shadow_deepen_b × shad_gate)
            shadow_deepen_r > shadow_deepen_g > shadow_deepen_b — R is reduced the
            most, B the least, pushing deep shadows toward warm umber.

        (4) Composite at opacity.

        Distinct from giampietrino_warm_devotion_pass (TWO SEPARATE luminance gates:
          a hi-gate applies amber R+G+ and a SEPARATE shad-gate applies violet B+R−;
          the two gates are independently computed from different luminance thresholds
          and never merge into a flat baseline; Reynolds' step (1) applies a FLAT,
          UNGATED amber shift to ALL pixels simultaneously before any gate logic —
          this is architecturally different: giampietrino never warms the shadows
          before gating; Reynolds' amber glaze already shifts the darkest shadow warm
          before the deepening gate fires).
        Distinct from moro_regal_presence_pass (shadow deepening gate multiplies all
          channels equally with a single shadow_deepen scalar — no differential
          channel reduction; Moro's highlight gate is cool-silver B+R−; Reynolds'
          deepening has shadow_deepen_r > shadow_deepen_b for WARM UMBER direction;
          Reynolds also adds a flat amber pre-pass entirely absent from Moro).
        Distinct from furini_moonlit_sfumato_pass (cool silver B+R− at highlights in
          [0.55, 0.92] bump gate — opposite chromatic direction; Furini is COOL at
          highlights, Reynolds is WARM; Furini has an upper cutoff at 0.92; Reynolds'
          hi_gate is a monotonically increasing ramp with no upper cutoff; Furini has
          no flat amber pre-pass).
        Distinct from bordone_venetian_warmth_pass (if present: Venetian warmth is
          spatially modulated by figure geometry; Reynolds' amber is spatially uniform
          with no figure-position dependency).

        Args:
            amber_strength   : Intensity of the flat amber glaze (step 1).
            amber_r          : R channel lift per unit amber_strength.
            amber_g          : G channel lift per unit amber_strength (small).
            amber_b_reduce   : B channel reduction per unit amber_strength.
            highlight_lo     : Luma threshold for the impasto highlight gate.
            highlight_power  : Exponent shaping the hi gate ramp steepness.
            hi_boost         : Brightness boost amount at highlights.
            shadow_hi        : Luma threshold for shadow bitumen deepening gate.
            shadow_power     : Exponent shaping the shadow gate ramp steepness.
            shadow_deepen_r  : R channel deepening factor (most — warm umber).
            shadow_deepen_g  : G channel deepening factor (mid).
            shadow_deepen_b  : B channel deepening factor (least — preserves warmth).
            opacity          : Composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Flat amber glaze (non-gated, uniform mezzotint tone) ─────
        out_r = r0 + amber_r * amber_strength
        out_g = g0 + amber_g * amber_strength
        out_b = b0 - amber_b_reduce * amber_strength

        # ── Step 2: Impasto highlight brightening ─────────────────────────────
        hi_raw  = _np.clip((luma - highlight_lo) / (1.0 - highlight_lo + 1e-6), 0.0, 1.0)
        hi_gate = hi_raw ** highlight_power
        out_r = out_r + hi_boost * hi_gate
        out_g = out_g + hi_boost * 0.85 * hi_gate

        # ── Step 3: Shadow bitumen deepening (warm umber direction) ───────────
        shad_raw  = _np.clip((shadow_hi - luma) / (shadow_hi + 1e-6), 0.0, 1.0)
        shad_gate = shad_raw ** shadow_power
        out_r = out_r * (1.0 - shadow_deepen_r * shad_gate)
        out_g = out_g * (1.0 - shadow_deepen_g * shad_gate)
        out_b = out_b * (1.0 - shadow_deepen_b * shad_gate)

        # ── Step 4: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Reynolds Grand Manner mezzotint tone pass complete.")

    # ── massys_bridge_glazing_pass ─────────────────────────────────────────────
    # Quentin Massys (c. 1466–1530) — Flemish-Italian bridge.
    # Flesh-targeted warm glaze + cool Flemish shadow accent + pearl highlight
    # lift — FORTY-EIGHTH DISTINCT MODE.

    def massys_bridge_glazing_pass(
        self,
        flesh_warm_r:       float = 0.12,
        flesh_warm_g:       float = 0.04,
        flesh_warm_b_reduce: float = 0.08,
        shadow_cool_lo:     float = 0.20,
        shadow_cool_hi:     float = 0.46,
        shadow_cool_b:      float = 0.08,
        shadow_cool_r:      float = 0.05,
        pearl_lo:           float = 0.58,
        pearl_hi:           float = 0.82,
        pearl_r:            float = 0.06,
        pearl_b:            float = 0.04,
        skin_sigma:         float = 6.0,
        opacity:            float = 0.28,
    ) -> None:
        """Flemish-Italian bridge glazing — FORTY-EIGHTH DISTINCT MODE.

        Encodes Quentin Massys' unique dual technique: a warm amber-rose glaze
        applied selectively to detected warm flesh zones (the Italian influence —
        luminous, enveloping warmth), combined with a cool blue-grey accent pushed
        back into the shadow region of those same flesh zones (the Flemish
        grisaille underlayer showing through the warm oil glaze), and a pearl-like
        luminosity lift at mid-highlights within flesh.

        This is the FORTY-EIGHTH DISTINCT MODE: FLEMISH-ITALIAN BRIDGE GLAZING.

        Parameters
        ----------
        flesh_warm_r        : R lift on detected flesh (warm rose direction).
        flesh_warm_g        : G lift on detected flesh (slight warmth).
        flesh_warm_b_reduce : B reduction on detected flesh (desaturates blue).
        shadow_cool_lo      : Lower luma bound of the skin shadow zone.
        shadow_cool_hi      : Upper luma bound of the skin shadow zone.
        shadow_cool_b       : B lift in the skin shadow zone (cool grey-blue).
        shadow_cool_r       : R reduction in the skin shadow zone.
        pearl_lo            : Lower luma bound of the pearl highlight zone.
        pearl_hi            : Upper luma bound of the pearl highlight zone.
        pearl_r             : R lift in the pearl zone (warm ivory).
        pearl_b             : B lift in the pearl zone (faint pearl luminosity).
        skin_sigma          : Gaussian blur radius for skin mask softening.
        opacity             : Composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Flesh detection + soft mask ───────────────────────────────
        skin_hard = (
            (r0 > 0.36)
            & (r0 > g0 * 1.04)
            & (g0 > b0 * 1.02)
        ).astype(_np.float32)
        skin_mask = _np.clip(_gf(skin_hard, sigma=skin_sigma), 0.0, 1.0)

        out_r = r0.copy()
        out_g = g0.copy()
        out_b = b0.copy()

        # ── Step 2: Warm flesh glaze (all luma, skin zone only) ───────────────
        out_r = out_r + flesh_warm_r * skin_mask
        out_g = out_g + flesh_warm_g * skin_mask
        out_b = out_b - flesh_warm_b_reduce * skin_mask

        # ── Step 3: Cool Flemish shadow accent (skin zone, mid-shadow luma) ───
        span = max(shadow_cool_hi - shadow_cool_lo, 1e-6)
        shad_ramp_lo = _np.clip((luma - shadow_cool_lo) / span, 0.0, 1.0)
        shad_ramp_hi = _np.clip((shadow_cool_hi - luma) / span, 0.0, 1.0)
        shad_bump = shad_ramp_lo * shad_ramp_hi * 4.0   # peaks at midpoint of zone
        shad_gate = shad_bump * skin_mask
        out_r = out_r - shadow_cool_r * shad_gate
        out_b = out_b + shadow_cool_b * shad_gate

        # ── Step 4: Pearl highlight lift (skin zone, mid-highlight luma) ──────
        pspan = max(pearl_hi - pearl_lo, 1e-6)
        pearl_ramp_lo = _np.clip((luma - pearl_lo) / pspan, 0.0, 1.0)
        pearl_ramp_hi = _np.clip((pearl_hi - luma) / pspan, 0.0, 1.0)
        pearl_bump = pearl_ramp_lo * pearl_ramp_hi * 4.0  # peaks at midpoint
        pearl_gate = pearl_bump * skin_mask
        out_r = out_r + pearl_r * pearl_gate
        out_b = out_b + pearl_b * pearl_gate

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Massys Flemish-Italian bridge glazing pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Schedoni luminous emergence — session 163 addition
    # ─────────────────────────────────────────────────────────────────────────

    def schedoni_luminous_emergence_pass(
        self,
        shadow_hi:      float = 0.32,   # luma threshold for shadow compression gate
        shad_power:     float = 1.6,    # exponent shaping shadow gate ramp
        compress:       float = 0.30,   # shadow compression strength (all channels equally)
        highlight_lo:   float = 0.60,   # luma threshold for highlight chroma gate
        hi_power:       float = 1.4,    # exponent shaping highlight gate ramp
        chroma_boost:   float = 0.50,   # chroma amplification strength in lit zones
        glow_r:         float = 0.04,   # warm amber glow R channel additive lift
        glow_g:         float = 0.025,  # warm amber glow G channel additive lift
        opacity:        float = 0.35,
    ) -> None:
        """Tenebrism-brightened chroma amplification — FORTY-NINTH DISTINCT MODE.

        Bartolomeo Schedoni (1578–1615) fused Correggesque tenderness with
        Caravaggesque tenebrism.  His defining quality is LUMINOUS EMERGENCE
        FROM SHADOW: near-black void shadows combined with extraordinarily
        vivid, chromatically amplified lit zones.  Where Caravaggio's lights
        are cool and silvery, Schedoni's are warm and golden; where other
        tenebristi let lit flesh merely brighten, Schedoni's lit zones become
        MORE intensely coloured — scarlet drapery intensifies, white linen
        glows, flesh warms to amber-ivory.

        This pass encodes that innovation as the FORTY-NINTH DISTINCT MODE:
        TENEBRISM-BRIGHTENED CHROMA AMPLIFICATION.

        Algorithm (four steps):

        (1) SHADOW COMPRESSION (luma-gated deep darks):
            luma = 0.2126r + 0.7152g + 0.0722b
            shad_gate = clip((shadow_hi − luma) / shadow_hi, 0, 1)^shad_power
            out_r = r × (1 − compress × shad_gate)
            out_g = g × (1 − compress × shad_gate)
            out_b = b × (1 − compress × shad_gate)
            Equal-channel compression — Schedoni's shadows are chromatic
            near-black voids with minimal colour bias.
            Distinct from Reynolds (differential R>G>B warm-umber direction
              after a flat amber pre-pass absent here; Reynolds' shadows are
              warm umber; Schedoni's are neutral near-black).
            Distinct from Moro (also equal-channel multiplicative, but Moro
              adds a cool-silver B+R− highlight gate; Schedoni's highlight
              treatment is chroma amplification, not colour temperature shift).

        (2) HIGHLIGHT CHROMA AMPLIFICATION (luma-gated brights):
            hi_gate = clip((luma − highlight_lo) / (1 − highlight_lo), 0, 1)^hi_power
            mean_rgb = (r + g + b) / 3     [approximate achromatic centre]
            r_dev = r − mean_rgb;  g_dev = g − mean_rgb;  b_dev = b − mean_rgb
            out_r = r + r_dev × chroma_boost × hi_gate
            out_g = g + g_dev × chroma_boost × hi_gate
            out_b = b + b_dev × chroma_boost × hi_gate
            CHROMA AMPLIFICATION via per-pixel colour deviation from the
            achromatic mean — makes vivid colours MORE vivid (scarlet
            redder, white brighter, green greener) without shifting hue
            or colour temperature.  FORTY-NINTH DISTINCT MODE: no prior
            pass uses (colour − mean_rgb) as a chroma amplification signal
            in a luminance-gated highlight zone.

        (3) WARM GOLDEN GLOW (highlight zone, additive):
            out_r += glow_r × hi_gate
            out_g += glow_g × hi_gate
            Small warm amber-gold additive lift — Schedoni's warm Correggesque
            light quality above the chroma amplification layer.

        (4) Composite at opacity.

        Distinct from beccafumi_nacreous_glow_pass (convexity-signal bloom-
          difference, warm+ convex / cool- concave; fires on geometry; no
          chroma amplification; no shadow compression).
        Distinct from iridescent_glaze_pass (orientation-based warm/cool
          shimmer from gradient angle; no chroma amplification; no shadow).
        Distinct from specular_clarity_pass (USM sharpening in bright zone +
          cool-pearl peak B+; no chroma amplification using deviance-from-mean;
          opposite direction at specular peaks — cool not warm).
        Distinct from adaptive_local_contrast_pass (local block percentile
          stretching of luma independently per block; no chroma boost; no
          shadow compression pass).

        Args:
            shadow_hi    : Luma threshold for shadow compression gate.
            shad_power   : Exponent shaping shadow gate ramp steepness.
            compress     : Compression strength (equal across all channels).
            highlight_lo : Luma threshold for highlight chroma gate.
            hi_power     : Exponent shaping highlight gate ramp steepness.
            chroma_boost : Chroma amplification intensity in lit zones.
            glow_r       : Warm amber glow R additive per gate unit.
            glow_g       : Warm amber glow G additive per gate unit.
            opacity      : Composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Shadow compression (equal channels — neutral near-black) ─
        shad_raw  = _np.clip((shadow_hi - luma) / (shadow_hi + 1e-6), 0.0, 1.0)
        shad_gate = shad_raw ** float(shad_power)
        factor    = 1.0 - float(compress) * shad_gate
        out_r = r0 * factor
        out_g = g0 * factor
        out_b = b0 * factor

        # ── Step 2: Highlight chroma amplification ────────────────────────────
        hi_raw  = _np.clip((luma - highlight_lo) / (1.0 - highlight_lo + 1e-6), 0.0, 1.0)
        hi_gate = hi_raw ** float(hi_power)
        mean_rgb = (r0 + g0 + b0) / 3.0          # approximate achromatic centre
        r_dev    = r0 - mean_rgb
        g_dev    = g0 - mean_rgb
        b_dev    = b0 - mean_rgb
        boost    = float(chroma_boost) * hi_gate
        out_r = out_r + r_dev * boost
        out_g = out_g + g_dev * boost
        out_b = out_b + b_dev * boost

        # ── Step 3: Warm golden glow addition ────────────────────────────────
        out_r = out_r + float(glow_r) * hi_gate
        out_g = out_g + float(glow_g) * hi_gate

        # ── Step 4: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Schedoni luminous emergence pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Warm highlight bloom — session 163 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────

    def warm_highlight_bloom_pass(
        self,
        warm_r_thresh:  float = 0.55,   # minimum R value to qualify as warm pixel
        warm_r_ratio:   float = 1.05,   # R must exceed G by this factor (warm test)
        luma_thresh:    float = 0.55,   # minimum luma to qualify as highlight pixel
        bloom_sigma:    float = 12.0,   # Gaussian blur sigma for bloom spread
        bloom_strength: float = 0.20,   # bloom intensity (warm glow blend weight)
        bloom_r:        float = 0.80,   # R tint of the bloom glow
        bloom_g:        float = 0.60,   # G tint of the bloom glow
        bloom_b:        float = 0.30,   # B tint of the bloom glow
        opacity:        float = 0.30,
    ) -> None:
        """Warm highlight bloom — FIFTIETH DISTINCT MODE.

        In many Old Master paintings — Correggio, Schedoni, Titian — warm
        highlights have a soft aureolic quality: the warm light source appears
        to glow slightly beyond its hard edge, suffusing nearby darker areas
        with a faint warm luminosity.  This is partly an optical artefact of
        glowing candles or windows, and partly a painterly technique of
        scumbling warm pigment outward from the lit zone into the penumbra.

        This pass simulates that WARM HIGHLIGHT BLOOM by detecting warm bright
        pixels (high R, warm R/G ratio, high luma) and spreading their warmth
        spatially via Gaussian blur.  The resulting bloom mask is composited
        onto the canvas as a soft warm glow.

        Algorithm:
        (1) WARM HIGHLIGHT MASK: detect pixels where
            r > warm_r_thresh AND r > g × warm_r_ratio AND luma > luma_thresh
            Binary mask: bloom_src = r0 × mask (weighted by R channel value)
        (2) SPATIAL BLOOM SPREAD:
            bloom_spread = gaussian_blur(bloom_src, sigma=bloom_sigma)
        (3) WARM GLOW COMPOSITE:
            blend = bloom_spread × bloom_strength
            out_r = r + (bloom_r − r) × blend
            out_g = g + (bloom_g − g) × blend
            out_b = b + (bloom_b − b) × blend
        (4) Composite at opacity.

        FIFTIETH DISTINCT MODE: distinct from all prior passes because it
        combines (a) warm-tone spatial DETECTION of highlight sources and
        (b) Gaussian SPREAD of that warm glow into surrounding dark zones.
        No prior pass uses a detection mask × spatial blur to create a
        bloom glow from warm highlights.
        Distinct from peripheral_defocus_pass (blurs image peripherally
          for depth-of-field; no warm detection; no glow composite).
        Distinct from luminous_ground_pass (adds warm tint in DARK zones;
          no highlight detection; no spatial bloom spread — opposite zone).
        Distinct from skin_subsurface_scatter_pass (scatters warm tones
          within the skin region only; no bloom beyond skin boundary;
          the scatter uses the skin's own channels, not a generated glow).
        Distinct from atmospheric_depth_gradient_pass (vertical chromatic
          temperature gradient; no highlight detection; no bloom).

        Args:
            warm_r_thresh  : Minimum R value for a pixel to count as warm source.
            warm_r_ratio   : R/G ratio threshold for warmth test (R > G × ratio).
            luma_thresh    : Minimum luma for a pixel to count as highlight source.
            bloom_sigma    : Gaussian blur sigma for spatial bloom spread.
            bloom_strength : Blend weight of the bloom glow composite.
            bloom_r        : R target colour of the bloom glow.
            bloom_g        : G target colour of the bloom glow.
            bloom_b        : B target colour of the bloom glow.
            opacity        : Composite weight (0 = no-op).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Warm highlight source mask ───────────────────────────────
        warm_mask = (
            (r0 > float(warm_r_thresh)) &
            (r0 > g0 * float(warm_r_ratio)) &
            (luma > float(luma_thresh))
        ).astype(_np.float32)
        bloom_src = r0 * warm_mask      # weighted by R strength

        # ── Step 2: Spatial bloom spread ─────────────────────────────────────
        bloom_spread = _np.clip(
            _gf(bloom_src, sigma=float(bloom_sigma)), 0.0, 1.0
        )

        # ── Step 3: Warm glow composite ───────────────────────────────────────
        blend  = bloom_spread * float(bloom_strength)
        out_r  = r0 + (float(bloom_r) - r0) * blend
        out_g  = g0 + (float(bloom_g) - g0) * blend
        out_b  = b0 + (float(bloom_b) - b0) * blend

        # ── Step 4: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Warm highlight bloom pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Gentileschi dramatic flesh — session 164 artist pass
    # ─────────────────────────────────────────────────────────────────────────

    def gentileschi_dramatic_flesh_pass(
        self,
        dir_x:          float = 0.55,   # horizontal weight of spotlight gradient (left-bias)
        dir_y:          float = 0.45,   # vertical weight of spotlight gradient (top-bias)
        shadow_hi:      float = 0.38,   # luma threshold for shadow deepening gate
        shadow_deepen:  float = 0.45,   # shadow compression strength (equal channels)
        luma_lo:        float = 0.40,   # minimum luma for warm lift / chroma gate
        amber_r:        float = 0.055,  # warm amber R lift in spotlight zone
        amber_g:        float = 0.025,  # warm amber G lift in spotlight zone
        chroma_boost:   float = 0.40,   # chroma amplification in spotlight zone
        opacity:        float = 0.38,
    ) -> None:
        """Gentileschi directional tenebrism with anisotropic chroma-lift — FIFTY-FIRST DISTINCT MODE.

        Artemisia Gentileschi (1593–c.1656) painted with an intense directional
        spotlight from upper-left — inherited from Caravaggio via her father Orazio —
        but with a distinctively warm, amber-ivory quality in the illuminated flesh
        and vivid, fully saturated costume colours in the lit zone.  Her shadows
        are uncompromising Caravaggesque near-black.

        The defining innovation this pass encodes is ANISOTROPIC TREATMENT: the
        same pixel luminance value is treated differently depending on WHERE it
        sits in the canvas relative to the simulated upper-left light source.  A
        dark pixel in the upper-left (physically illuminated by the spotlight) is
        treated as a lit surface; the same dark pixel in the lower-right (the
        geometric shadow zone) is pressed toward near-black.  No prior pass uses
        a directional spatial gradient as the primary illumination model.

        Algorithm (five steps):

        (1) DIRECTIONAL SPOTLIGHT WEIGHT (spatial gradient):
            For each pixel at position (x, y) in a canvas of size (W, H):
            dx = (W − x) / W   [normalized dist from right edge; left = high]
            dy = (H − y) / H   [normalized dist from bottom; top = high]
            spot_wt = clip(dx × dir_x + dy × dir_y, 0, 1)
            Models the geometric falloff of a directional light at upper-left.
            FIFTY-FIRST DISTINCT MODE: no prior pass constructs a spatial
            directional gradient as its primary illumination model.

        (2) SHADOW DEEPENING (geometric shadow zone × dark pixels):
            shadow_gate = (1 − spot_wt) × clip((shadow_hi − luma) / shadow_hi, 0, 1)
            out_r = r × (1 − shadow_deepen × shadow_gate)
            out_g = g × (1 − shadow_deepen × shadow_gate)
            out_b = b × (1 − shadow_deepen × shadow_gate)
            Equal-channel — Caravaggesque void shadows have no warm or cool bias.
            Distinct from schedoni_luminous_emergence_pass: uses uniform luma gate
            only; Artemisia's gate combines spatial + luminance, preventing over-
            darkening of bright-valued pixels in the geometric shadow zone.

        (3) WARM AMBER ILLUMINATION LIFT (spotlight zone):
            hi_gate = spot_wt × clip((luma − luma_lo) / (1 − luma_lo), 0, 1)
            out_r += amber_r × hi_gate
            out_g += amber_g × hi_gate
            (B channel not raised — warm amber, not neutral or cool)
            Artemisia's characteristic golden-amber light quality, warmer than
            Caravaggio's silvery-cool spots, slightly cooler than Schedoni's.

        (4) DIRECTIONAL CHROMA AMPLIFICATION (spotlight zone):
            mean_rgb = (r + g + b) / 3
            out_r += (r − mean_rgb) × chroma_boost × hi_gate
            out_g += (g − mean_rgb) × chroma_boost × hi_gate
            out_b += (b − mean_rgb) × chroma_boost × hi_gate
            Makes saturated costume colours MORE vivid under the spotlight — deep
            crimson intensifies to scarlet, cobalt deepens.  The hi_gate couples
            chroma amplification to the directional spatial model: only pixels that
            are BOTH spatially in the spotlight AND above luma_lo are amplified.
            Distinct from schedoni: the gate uses spot_wt × luma, not luma alone.

        (5) Composite at opacity.

        Distinct from schedoni_luminous_emergence_pass (luma-only gate, no spatial
          directional term; shadow compression is luma-gated only; Artemisia's
          spatial × luminance factored gate is architecturally different).
        Distinct from moro_courtly_gravitas_pass (equal-channel shadow_deepen only;
          no directional spatial gradient; no warm lift; no chroma amplification).
        Distinct from reynolds_grand_manner_pass (differential warm-umber channel
          treatment R>G>B; no spatial directional gradient).
        Distinct from warm_highlight_bloom_pass (warm detection via R/G ratio +
          luma mask, then spatial Gaussian blur; no directional gradient model;
          bloom = spread of detected source, not directional geometric weight).

        Args:
            dir_x         : Horizontal component of spotlight direction (left = high).
            dir_y         : Vertical component of spotlight direction (top = high).
            shadow_hi     : Luma threshold above which shadow deepening has no effect.
            shadow_deepen : Equal-channel shadow compression strength.
            luma_lo       : Minimum luma for warm amber lift and chroma amplification.
            amber_r       : R-channel additive warm lift in spotlight zone.
            amber_g       : G-channel additive warm lift in spotlight zone.
            chroma_boost  : Chroma amplification strength in spotlight zone.
            opacity       : Composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Directional spotlight weight (spatial gradient) ───────────
        xs = _np.linspace(0.0, 1.0, W, dtype=_np.float32)  # 0=left, 1=right
        ys = _np.linspace(0.0, 1.0, H, dtype=_np.float32)  # 0=top, 1=bottom
        # dx high on left (W - x)/W  →  1 - xs
        dx = (1.0 - xs)[_np.newaxis, :]   # shape (1, W)
        dy = (1.0 - ys)[:, _np.newaxis]   # shape (H, 1)
        spot_wt = _np.clip(
            dx * float(dir_x) + dy * float(dir_y), 0.0, 1.0
        )  # shape (H, W)

        # ── Step 2: Shadow deepening (spatial shadow zone × dark pixels) ──────
        shadow_raw  = _np.clip(
            (float(shadow_hi) - luma) / (float(shadow_hi) + 1e-6), 0.0, 1.0
        )
        shadow_gate = (1.0 - spot_wt) * shadow_raw
        factor      = 1.0 - float(shadow_deepen) * shadow_gate
        out_r = r0 * factor
        out_g = g0 * factor
        out_b = b0 * factor

        # ── Step 3: Warm amber lift (spotlight zone × bright pixels) ─────────
        luma_raw = _np.clip(
            (luma - float(luma_lo)) / (1.0 - float(luma_lo) + 1e-6), 0.0, 1.0
        )
        hi_gate  = spot_wt * luma_raw
        out_r    = out_r + float(amber_r) * hi_gate
        out_g    = out_g + float(amber_g) * hi_gate

        # ── Step 4: Directional chroma amplification (spotlight zone) ─────────
        mean_rgb = (r0 + g0 + b0) / 3.0
        boost    = float(chroma_boost) * hi_gate
        out_r    = out_r + (r0 - mean_rgb) * boost
        out_g    = out_g + (g0 - mean_rgb) * boost
        out_b    = out_b + (b0 - mean_rgb) * boost

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Gentileschi dramatic flesh pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Shadow/highlight color temperature split — session 164 artistic improvement
    # ─────────────────────────────────────────────────────────────────────────

    def shadow_color_temperature_pass(
        self,
        shadow_thresh:  float = 0.42,   # luma threshold for shadow cooling gate
        shadow_power:   float = 1.4,    # exponent shaping shadow gate ramp
        cool_b:         float = 0.045,  # blue lift in shadow zone (cool shadows)
        cool_r:         float = 0.018,  # red reduction in shadow zone
        cool_g:         float = 0.008,  # green reduction in shadow zone
        highlight_thresh: float = 0.60, # luma threshold for highlight warming gate
        highlight_power: float = 1.3,   # exponent shaping highlight gate ramp
        warm_r:         float = 0.040,  # red lift in highlight zone (warm lights)
        warm_g:         float = 0.018,  # green lift in highlight zone
        opacity:        float = 0.32,
    ) -> None:
        """Warm-light / cool-shadow color temperature split — FIFTY-SECOND DISTINCT MODE.

        One of the fundamental observations of academic painting — codified by
        Rubens, refined by the French Academy, and systematized by painters from
        Boucher to Sargent — is that lit surfaces are warm and shadows are cool
        (or vice versa under a cool light source, but warm-light / cool-shadow is
        the dominant case for interior studio painting under window or candle light).
        This warm/cool chromatic temperature split gives Old Master paintings their
        characteristic sense of luminous depth: the warm highlights feel physically
        lit, the cool shadows feel physically receded, and the transition between
        them produces the characteristic Rubensian 'pearly' quality in the penumbra.

        This pass encodes that split as the FIFTY-SECOND DISTINCT MODE:
        LUMINANCE-GATED DUAL COLOR TEMPERATURE SEPARATION.

        Algorithm (three steps):

        (1) SHADOW COOLING (luma-gated dark zone):
            luma = 0.2126r + 0.7152g + 0.0722b
            shad_raw  = clip((shadow_thresh − luma) / shadow_thresh, 0, 1)
            shad_gate = shad_raw ^ shadow_power
            out_r = r − cool_r × shad_gate   [reduce red → cooler]
            out_g = g − cool_g × shad_gate   [slight green reduction]
            out_b = b + cool_b × shad_gate   [add blue → cooler, more violet]

        (2) HIGHLIGHT WARMING (luma-gated bright zone):
            hi_raw   = clip((luma − highlight_thresh) / (1 − highlight_thresh), 0, 1)
            hi_gate  = hi_raw ^ highlight_power
            out_r += warm_r × hi_gate   [add red/amber → warmer highlights]
            out_g += warm_g × hi_gate   [slight green addition]
            (B channel not raised — warm, not neutral)

        (3) Composite at opacity.

        FIFTY-SECOND DISTINCT MODE: distinct from all prior passes because it
        simultaneously applies OPPOSITE color temperature shifts to shadows and
        highlights using two independent luma gates — cooling in one zone while
        warming in another in the same pass.
        Distinct from atmospheric_depth_gradient_pass (vertical spatial gradient,
          no luminance gating; cools upper image regardless of pixel brightness).
        Distinct from chromatic_aerial_perspective_pass (top-of-canvas spatial
          gradient; no highlight warming; applied to background only).
        Distinct from schedoni_luminous_emergence_pass (shadow compression only —
          equal-channel deepening, not cool tinting; no highlight warm shift).
        Distinct from artemisia_directional_spotlight_pass (directional spatial ×
          luminance gate; warm amber additive only; no cool shadow tint shift).
        Distinct from warm_highlight_bloom_pass (detects warm sources and spreads
          them spatially via Gaussian; no shadow cooling; opposite direction).

        Args:
            shadow_thresh   : Luma threshold for shadow cooling gate.
            shadow_power    : Exponent shaping shadow gate ramp.
            cool_b          : Blue additive lift in shadow zone.
            cool_r          : Red subtractive reduction in shadow zone.
            cool_g          : Green subtractive reduction in shadow zone.
            highlight_thresh: Luma threshold for highlight warming gate.
            highlight_power : Exponent shaping highlight gate ramp.
            warm_r          : Red additive lift in highlight zone.
            warm_g          : Green additive lift in highlight zone.
            opacity         : Composite weight (0 = no-op).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Shadow cooling ────────────────────────────────────────────
        shad_raw  = _np.clip(
            (float(shadow_thresh) - luma) / (float(shadow_thresh) + 1e-6), 0.0, 1.0
        )
        shad_gate = shad_raw ** float(shadow_power)
        out_r = r0 - float(cool_r) * shad_gate
        out_g = g0 - float(cool_g) * shad_gate
        out_b = b0 + float(cool_b) * shad_gate

        # ── Step 2: Highlight warming ─────────────────────────────────────────
        hi_raw   = _np.clip(
            (luma - float(highlight_thresh)) / (1.0 - float(highlight_thresh) + 1e-6),
            0.0, 1.0,
        )
        hi_gate  = hi_raw ** float(highlight_power)
        out_r    = out_r + float(warm_r) * hi_gate
        out_g    = out_g + float(warm_g) * hi_gate

        # ── Step 3: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Shadow color temperature pass complete.")

    def schalcken_candlelight_glow_pass(
        self,
        candle_x: float = 0.50,
        candle_y: float = 0.88,
        candle_radius: float = 0.55,
        candle_falloff: float = 1.8,
        luma_lo: float = 0.12,
        amber_r: float = 0.18,
        amber_g: float = 0.08,
        void_power: float = 2.0,
        void_deepen: float = 0.55,
        opacity: float = 0.80,
    ) -> None:
        """Radial candlelight spotlight — FIFTY-THIRD DISTINCT MODE.

        Models a single isolated flame as the sole light source, encoding Godfried
        Schalcken's defining pictorial language: warm amber-saffron glow radiating
        outward from a candle position, with the unlit zone pressed toward near-absolute
        black void.

        This is the FIFTY-THIRD DISTINCT MODE: RADIAL CANDLELIGHT SPOTLIGHT WITH
        PROXIMITY FALLOFF AND VOID DEEPENING.

        Unlike all prior passes:
        - Builds a RADIAL proximity weight from a specified (x, y) flame position,
          using Euclidean distance normalised by candle_radius — not a directional
          vector (gentileschi), not a vertical spatial gradient (atmospheric passes),
          not a top-of-canvas gradient (chromatic aerial perspective).
        - SIMULTANEOUSLY adds warm amber to the lit zone AND deepens unlit pixels
          toward absolute black, encoding the extreme dual polarity of candlelight.
          No other pass applies both warmth lift and near-void deepening in the same
          operation driven by the same spatial weight field.

        Algorithm (four steps):

        (1) RADIAL PROXIMITY WEIGHT (distance from candle_x, candle_y):
            dx = (col/W − candle_x) / candle_radius
            dy = (row/H − candle_y) / candle_radius
            dist = sqrt(dx² + dy²)
            spot_wt = clip(1 − dist, 0, 1) ^ candle_falloff
            Models inverse-square-style light decay; candle_falloff > 1 sharpens
            the falloff to produce the dramatic cutoff of real candlelight.

        (2) WARM AMBER LIFT (in lit zone, luma-gated to avoid over-brightening shadows):
            luma = 0.2126r + 0.7152g + 0.0722b
            hi_gate = spot_wt × clip((luma − luma_lo) / (1 − luma_lo), 0, 1)
            out_r += amber_r × hi_gate
            out_g += amber_g × hi_gate
            (B channel not raised: the candle is warm — no blue component.)
            Adds Schalcken's characteristic saffron-amber tint to lit flesh and objects.

        (3) VOID DEEPENING (where spot_wt is low — outside the candle circle):
            void_gate = (1 − spot_wt) ^ void_power
            out_r *= (1 − void_deepen × void_gate)
            out_g *= (1 − void_deepen × void_gate)
            out_b *= (1 − void_deepen × void_gate)
            Presses unlit pixels toward absolute black, encoding the near-void darkness
            that surrounds every Schalcken composition.

        (4) Composite at opacity.

        FIFTY-THIRD DISTINCT MODE: distinct from all prior passes because it combines
        RADIAL PROXIMITY-TO-POINT weighting (distance from a candle position) with
        DUAL-ZONE TREATMENT (warm lift in lit zone + void deepening outside), all
        driven by a single Euclidean distance field. No prior pass constructs a
        radial distance field from an arbitrary canvas point and uses it to drive
        both additive warmth and multiplicative void deepening simultaneously.
        Distinct from gentileschi_directional_spotlight_pass (uses directional linear
          gradient dx×dir_x + dy×dir_y, not Euclidean distance from a point).
        Distinct from tonal_envelope_pass (brightness lift only; no shadow deepening;
          no spatial void toward black outside the radius).
        Distinct from shadow_color_temperature_pass (pure luma-gating, no spatial
          term; cools shadows rather than deepening to void; warms highlights rather
          than adding saffron from a point source).

        Args:
            candle_x      : Normalised horizontal candle position [0, 1]. Default 0.50.
            candle_y      : Normalised vertical candle position [0, 1]. Default 0.88
                            (lower-centre — typical Schalcken held-candle position).
            candle_radius : Normalised radius of the lit zone. Default 0.55.
            candle_falloff: Power-curve exponent for the spot weight falloff. Default 1.8.
            luma_lo       : Low-luma gate threshold for the warm lift. Default 0.12.
            amber_r       : Red additive in lit zone. Default 0.18.
            amber_g       : Green additive in lit zone. Default 0.08.
            void_power    : Exponent shaping the void deepening gate. Default 2.0.
            void_deepen   : Maximum multiplicative deepening in void zone. Default 0.55.
            opacity       : Composite weight (0 = no-op). Default 0.80.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Radial proximity weight from candle position ──────────────
        cols = _np.linspace(0.0, 1.0, W, dtype=_np.float32)[None, :]  # (1, W)
        rows = _np.linspace(0.0, 1.0, H, dtype=_np.float32)[:, None]  # (H, 1)
        dx = (cols - float(candle_x)) / (float(candle_radius) + 1e-6)
        dy = (rows - float(candle_y)) / (float(candle_radius) + 1e-6)
        dist = _np.sqrt(dx ** 2 + dy ** 2)   # (H, W)
        spot_wt = _np.clip(1.0 - dist, 0.0, 1.0) ** float(candle_falloff)

        # ── Step 2: Warm amber lift in lit zone (luma-gated) ──────────────────
        hi_gate = spot_wt * _np.clip(
            (luma - float(luma_lo)) / (1.0 - float(luma_lo) + 1e-6), 0.0, 1.0
        )
        out_r = r0 + float(amber_r) * hi_gate
        out_g = g0 + float(amber_g) * hi_gate
        out_b = b0  # warm candle — no blue component

        # ── Step 3: Void deepening outside the lit zone ───────────────────────
        void_gate = (1.0 - spot_wt) ** float(void_power)
        factor = 1.0 - float(void_deepen) * void_gate
        out_r = out_r * factor
        out_g = out_g * factor
        out_b = out_b * factor

        # ── Step 4: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Schalcken candlelight glow pass complete.")

    def film_grain_overlay_pass(
        self,
        grain_sigma: float = 0.030,
        grain_gamma: float = 0.70,
        grain_strength: float = 1.0,
        opacity: float = 0.65,
        seed: int = 0,
    ) -> None:
        """Luminance-gated Gaussian film grain — FIFTY-FOURTH DISTINCT MODE.

        Simulates the organic texture of linen canvas weave showing through
        thin paint layers: grain is strongest in midtones (where paint is thin
        and the canvas tooth is exposed) and invisible in near-black shadows
        (where thick paint completely covers the weave).

        This is the FIFTY-FOURTH DISTINCT MODE: LUMINANCE-GATED GAUSSIAN
        FILM GRAIN.

        Distinct from all prior passes because it is the ONLY pass that
        introduces new randomly-generated information into the image — all 53
        prior passes operate exclusively on existing pixel data (shifts,
        blurs, gates, composites).  The grain source is stochastic (Gaussian
        noise), not derived from the current canvas state.

        Algorithm (three steps):

        (1) GAUSSIAN NOISE GENERATION:
            rng = np.random.default_rng(seed)
            noise = rng.standard_normal((H, W)).astype(float32) × grain_sigma
            Generates zero-mean, sigma-scaled luminance perturbations.  The
            noise field is independent of the image content.

        (2) LUMINANCE-GATED STRENGTH:
            luma = 0.2126r + 0.7152g + 0.0722b
            grain_gate = luma ^ grain_gamma
            Scales noise amplitude by a power of the local luminance.
            grain_gamma < 1.0 (default 0.70): gate rises steeply in shadows,
            flattens in highlights — grain peaks in midtones, vanishes in
            near-black.  This matches the physical model: deep shadows = thick
            opaque paint = no canvas weave visible; midtones = thinner paint
            layers = weave texture exposed.

        (3) EQUAL CHANNEL APPLICATION (hue-preserving):
            out_r = r + noise × grain_gate × grain_strength
            out_g = g + noise × grain_gate × grain_strength
            out_b = b + noise × grain_gate × grain_strength
            The SAME noise value is added to all three channels equally,
            preserving hue: only luminance varies, not chroma.  This avoids
            the unwanted colour fringing of separate per-channel noise.

        Composite at opacity, clip to [0, 1].

        FIFTY-FOURTH DISTINCT MODE: distinct from all prior passes because:
        - Introduces STOCHASTIC information (random noise field) not present
          in the original image — no prior pass generates new random data.
        - Operates on NOISE GENERATION as its primary computational step.
        - grain_gamma gate is a direct power of luma, not a threshold gate
          (schedoni, gentileschi) or a sigmoid or linear ramp — a pure
          power-curve producing infinite smoothness at the shadow boundary.
        Distinct from peripheral_defocus_pass (blurs existing data spatially;
          no new random information; radius-based geometry).
        Distinct from chromatic_fringe_pass (creates colour-channel offset
          using existing image data; no stochastic source; edge-detection
          based).

        Args:
            grain_sigma    : Standard deviation of the Gaussian noise. Default 0.030.
            grain_gamma    : Power-curve exponent for the luma gate. Default 0.70.
            grain_strength : Overall scale multiplier on grain amplitude. Default 1.0.
            opacity        : Composite weight (0 = no-op). Default 0.65.
            seed           : RNG seed for reproducibility. Default 0.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Generate Gaussian noise ───────────────────────────────────
        rng = _np.random.default_rng(int(seed))
        noise = rng.standard_normal((H, W)).astype(_np.float32) * float(grain_sigma)

        # ── Step 2: Luminance gate (power curve) ──────────────────────────────
        grain_gate = _np.clip(luma, 0.0, 1.0) ** float(grain_gamma)

        # ── Step 3: Equal channel application (hue-preserving) ───────────────
        scaled = noise * grain_gate * float(grain_strength)
        out_r = r0 + scaled
        out_g = g0 + scaled
        out_b = b0 + scaled

        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Film grain overlay pass complete.")

    def van_der_werff_ivory_alabaster_pass(
        self,
        skin_r_lo: float = 0.42,
        skin_r_hi: float = 1.00,
        skin_g_lo: float = 0.22,
        skin_g_hi: float = 0.82,
        skin_b_lo: float = 0.10,
        skin_b_hi: float = 0.62,
        skin_rg_margin: float = 0.05,
        hi_lo: float = 0.52,
        ivory_b_lift: float = 0.10,
        ivory_r_reduce: float = 0.06,
        shadow_hi: float = 0.48,
        shadow_b_lift: float = 0.08,
        shadow_r_reduce: float = 0.07,
        opacity: float = 0.75,
    ) -> None:
        """Cool ivory alabaster skin tinting — FIFTY-FIFTH DISTINCT MODE.

        Encodes Adriaen van der Werff's defining pictorial quality: the cool,
        porcelain-like alabaster flesh that is the polar opposite of Schalcken's
        warm candlelight.  Van der Werff worked as a fijnschilder (fine-painter)
        in the tradition of Gerrit Dou and Eglon van der Neer, but pushed the
        Academic finish to an extreme: his skin has no warmth, no amber glow —
        it reads as cool ivory, pearl-blue in the highlights, cool violet-grey
        in the shadows.

        This is the FIFTY-FIFTH DISTINCT MODE: COOL IVORY ALABASTER SKIN
        TINTING WITH PEARL-BLUE HIGHLIGHT LIFT.

        Unlike ALL prior passes:
        - Every prior skin-detection pass applies WARM tints (Massys: warm flesh
          glaze; Schalcken: warm saffron via radial field; Reynolds: warm amber
          unification; Gentileschi: warm amber in lit zone).  This is the FIRST
          pass to apply a COOL tint to the detected skin zone: blue-white pearl
          lift in highlights, cool violet drain in shadows.
        - Distinct from shadow_color_temperature_pass (FIFTY-SECOND MODE), which
          applies globally to ALL pixels with no skin detection.  This pass is
          SKIN-TARGETED: only pixels matching the skin RGB range are modified.
        - Distinct from gentileschi (spatial directional gradient — no skin
          detection; warms the lit zone) and Schalcken (radial distance field —
          no skin detection; warms the proximity zone).

        Algorithm (three steps):

        (1) SKIN ZONE DETECTION:
            skin_mask = ((r ∈ [r_lo, r_hi]) &
                         (g ∈ [g_lo, g_hi]) &
                         (b ∈ [b_lo, b_hi]) &
                         (r > g + rg_margin) &
                         (g >= b))
            Detects warm-flesh pixels (r > g > b) within specified ranges.
            Identical structural form to Massys skin detection; novel in its
            subsequent application of COOL rather than WARM tint.

        (2) COOL IVORY LIFT in skin mid-highlights:
            luma = 0.2126r + 0.7152g + 0.0722b
            hi_gate = clip((luma − hi_lo) / (1 − hi_lo), 0, 1)
            ivory_gate = skin_mask × hi_gate
            out_b += ivory_b_lift × ivory_gate   (pearl-blue lift at highlight)
            out_r −= ivory_r_reduce × ivory_gate (drain red warmth from peak)
            Produces the cool alabaster/ivory quality of Van der Werff's lit skin.

        (3) COOL SHADOW DEPTH in skin shadow zone:
            shad_gate = clip((shadow_hi − luma) / shadow_hi, 0, 1)
            shadow_zone = skin_mask × shad_gate
            out_b += shadow_b_lift × shadow_zone  (blue-violet depth in shadow)
            out_r −= shadow_r_reduce × shadow_zone (drain amber from skin shadows)
            Produces Van der Werff's cool violet-grey flesh shadows — no warm
            umber, no golden shadow, only cool darkness.

        Composite at opacity.

        FIFTY-FIFTH DISTINCT MODE: novel because it is the ONLY pass that
        simultaneously (a) detects a skin zone AND (b) applies a COOL tint.
        The combination of skin_mask × hi_gate for cool highlight lift and
        skin_mask × shad_gate for cool shadow deepening encodes a complete
        cool-skin tonal model that no prior pass provides.

        Args:
            skin_r_lo      : Lower bound of skin R channel. Default 0.42.
            skin_r_hi      : Upper bound of skin R channel. Default 1.00.
            skin_g_lo      : Lower bound of skin G channel. Default 0.22.
            skin_g_hi      : Upper bound of skin G channel. Default 0.82.
            skin_b_lo      : Lower bound of skin B channel. Default 0.10.
            skin_b_hi      : Upper bound of skin B channel. Default 0.62.
            skin_rg_margin : Minimum R−G gap to confirm warm-flesh. Default 0.05.
            hi_lo          : Luma threshold above which highlight lift activates. Default 0.52.
            ivory_b_lift   : Blue additive in skin highlights (pearl coolness). Default 0.10.
            ivory_r_reduce : Red subtractive in skin highlights (warmth drain). Default 0.06.
            shadow_hi      : Luma threshold below which shadow deepening activates. Default 0.48.
            shadow_b_lift  : Blue additive in skin shadows (violet depth). Default 0.08.
            shadow_r_reduce: Red subtractive in skin shadows (amber drain). Default 0.07.
            opacity        : Composite weight (0 = no-op). Default 0.75.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Skin zone detection ───────────────────────────────────────
        skin_mask = (
            (r0 >= float(skin_r_lo)) & (r0 <= float(skin_r_hi)) &
            (g0 >= float(skin_g_lo)) & (g0 <= float(skin_g_hi)) &
            (b0 >= float(skin_b_lo)) & (b0 <= float(skin_b_hi)) &
            (r0 > g0 + float(skin_rg_margin)) &
            (g0 >= b0)
        ).astype(_np.float32)

        out_r = r0.copy()
        out_g = g0.copy()
        out_b = b0.copy()

        # ── Step 2: Cool ivory lift in skin highlights ────────────────────────
        hi_lo_f = float(hi_lo)
        hi_gate = _np.clip((luma - hi_lo_f) / (1.0 - hi_lo_f + 1e-6), 0.0, 1.0)
        ivory_gate = skin_mask * hi_gate
        out_b += float(ivory_b_lift) * ivory_gate
        out_r -= float(ivory_r_reduce) * ivory_gate

        # ── Step 3: Cool shadow depth in skin zone ────────────────────────────
        shadow_hi_f = float(shadow_hi)
        shad_gate = _np.clip((shadow_hi_f - luma) / (shadow_hi_f + 1e-6), 0.0, 1.0)
        shadow_zone = skin_mask * shad_gate
        out_b += float(shadow_b_lift) * shadow_zone
        out_r -= float(shadow_r_reduce) * shadow_zone

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Van der Werff ivory alabaster pass complete.")

    def craquelure_texture_pass(
        self,
        sigma_fine: float = 1.5,
        sigma_coarse: float = 6.0,
        crack_threshold: float = 0.55,
        crack_depth: float = 0.18,
        opacity: float = 0.60,
        seed: int = 0,
    ) -> None:
        """Synthetic craquelure crack network overlay — FIFTY-SIXTH DISTINCT MODE.

        Simulates the fine network of age cracks (craquelure) characteristic of
        old oil paintings on wood or canvas.  Over centuries, the paint film
        contracts and separates along stress lines, creating a distinctive web
        of dark hairline cracks.  This pass generates a synthetic crack network
        by applying Difference of Gaussians (DoG) to a random noise map,
        producing ridge-like structures that mimic the organic branching geometry
        of real craquelure.

        This is the FIFTY-SIXTH DISTINCT MODE: DIFFERENCE-OF-GAUSSIANS SYNTHETIC
        CRAQUELURE CRACK NETWORK.

        Unlike ALL prior passes:
        - The ONLY pass to apply Difference of Gaussians (DoG) — a standard
          edge-detection operator — to a RANDOM NOISE source rather than to the
          image itself.  Prior edge-detection passes (edge_sfumato_dissolution,
          chromatic_fringe) apply Sobel or Gaussian operators to the image canvas.
          Here the DoG is applied to an rng.random() noise field, producing
          ridge-valley crack-like structures that are entirely independent of
          image content.
        - Distinct from film_grain_overlay_pass (FIFTY-FOURTH MODE): that pass
          uses standard_normal() noise added uniformly to simulate canvas weave.
          This pass uses uniform noise → DoG → threshold to generate a SPARSE
          BINARY CRACK MASK with connected ridge-like geometry — an entirely
          different structural form.
        - Distinct from chromatic_fringe_pass (THIRTY-NINTH MODE): that pass
          detects image edges and adds colour fringing.  This pass generates
          synthetic structure from noise with no reference to image edges.

        Algorithm (four steps):

        (1) NOISE GENERATION:
            rng = np.random.default_rng(seed)
            noise = rng.random((H, W), dtype=float32)   [0, 1] uniform noise

        (2) DIFFERENCE OF GAUSSIANS (crack network synthesis):
            blur_fine   = gaussian_filter(noise, sigma=sigma_fine)
            blur_coarse = gaussian_filter(noise, sigma=sigma_coarse)
            dog = blur_fine − blur_coarse
            Normalise dog to [0, 1].
            The DoG produces a zero-crossing ridge-valley map in the noise;
            the ridges — where the fine Gaussian peaks above the coarse — form
            a connected web of elongated structures that visually resemble
            craquelure crack lines.

        (3) CRACK MASK THRESHOLDING:
            crack_mask = (dog > crack_threshold).astype(float32)
            Thresholds the normalised DoG to isolate sparse ridge lines.
            crack_threshold controls crack density: higher → fewer, finer cracks;
            lower → denser, broader crack network.

        (4) CRACK DARKENING:
            out_r = r × (1 − crack_depth × crack_mask)
            out_g = g × (1 − crack_depth × crack_mask)
            out_b = b × (1 − crack_depth × crack_mask)
            Darkens pixels along crack lines multiplicatively.  Equal-channel
            application preserves the underlying hue — cracks read as dark
            rather than coloured.  Composite at opacity.

        FIFTY-SIXTH DISTINCT MODE: novel because DoG is applied to a noise
        source (not the image), producing synthetic topographic ridge structure
        that is then thresholded into a crack mask.  No prior pass constructs
        a binary mask from a noise-derived spatial structure.

        Args:
            sigma_fine     : Gaussian sigma for the fine-scale blur in DoG. Default 1.5.
            sigma_coarse   : Gaussian sigma for the coarse-scale blur in DoG. Default 6.0.
            crack_threshold: Normalised DoG threshold for crack line extraction. Default 0.55.
            crack_depth    : Multiplicative darkening strength at crack lines. Default 0.18.
            opacity        : Composite weight (0 = no-op). Default 0.60.
            seed           : RNG seed for reproducibility. Default 0.
        """
        import numpy as _np
        from scipy import ndimage as _ndimage

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        # ── Step 1: Generate uniform noise ────────────────────────────────────
        rng = _np.random.default_rng(int(seed))
        noise = rng.random((H, W)).astype(_np.float32)

        # ── Step 2: Difference of Gaussians crack network synthesis ──────────
        blur_fine   = _ndimage.gaussian_filter(noise, sigma=float(sigma_fine))
        blur_coarse = _ndimage.gaussian_filter(noise, sigma=float(sigma_coarse))
        dog = blur_fine - blur_coarse
        dog_min, dog_max = dog.min(), dog.max()
        dog_norm = (dog - dog_min) / (dog_max - dog_min + 1e-6)

        # ── Step 3: Threshold to crack mask ───────────────────────────────────
        crack_mask = (dog_norm > float(crack_threshold)).astype(_np.float32)

        # ── Step 4: Crack darkening (multiplicative, hue-preserving) ──────────
        factor = 1.0 - float(crack_depth) * crack_mask
        out_r = r0 * factor
        out_g = g0 * factor
        out_b = b0 * factor

        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Craquelure texture pass complete.")

    def clouet_enamel_precision_pass(
        self,
        cool_r: float = 0.90,
        cool_g: float = 0.88,
        cool_b: float = 0.94,
        tint_strength: float = 0.18,
        hi_threshold: float = 0.38,
        hi_gate_power: float = 1.4,
        opacity: float = 0.50,
    ) -> None:
        """Luminance-preserving cool enamel glaze — FIFTY-SEVENTH DISTINCT MODE.

        Encodes François Clouet's defining pictorial quality: the cool, enamel-
        smooth surface of French Renaissance court portraiture, achieved through
        multiple thin, semi-transparent glazes applied with extreme precision.
        Clouet's highlights are distinctively pearl-cool — not the warm golden
        highlights of the Italian tradition, but a silvery luminosity reflecting
        the even north-window light of the French court.

        This is the FIFTY-SEVENTH DISTINCT MODE: LUMINANCE-PRESERVING COOL
        ENAMEL GLAZE.

        Unlike ALL prior passes, this is the ONLY pass to apply a
        LUMINANCE-NORMALIZING CORRECTION after the colour tint.  Every prior
        colour-tinting pass (Massys, Reynolds, van der Werff, Schalcken,
        Gentileschi, warm_highlight_bloom, shadow_color_temperature) alters both
        chroma and luminance simultaneously through additive or multiplicative
        operations.  This pass does something no prior pass does:

        (1) Apply a cool ivory chroma shift (lerp toward target colour)
        (2) Measure the resulting per-pixel luminance change
        (3) DIVIDE each pixel back to restore its exact original luminance

        The net effect: chroma changes (the image gets cooler, more pearl-ivory)
        but the tonal structure — every gradient, every shadow, every highlight —
        remains EXACTLY as painted.  This replicates the physical effect of a
        thin coloured varnish or glaze that shifts overall hue while leaving the
        underlying tonal drawing intact.  François Clouet's enamel surfaces were
        built precisely this way: cool glazes laid over a carefully constructed
        tonal underpainting without disturbing its luminance structure.

        Algorithm (four steps):

        (1) CHROMA SHIFT — LERP TOWARD COOL TARGET:
            r' = r + (cool_r − r) × tint_strength × hi_gate
            g' = g + (cool_g − g) × tint_strength × hi_gate
            b' = b + (cool_b − b) × tint_strength × hi_gate
            where hi_gate = clip((luma − hi_threshold) / (1 − hi_threshold), 0, 1)
                              raised to hi_gate_power.
            Applies the cool tint progressively in the lighter zones — the
            pearl-cool quality is most visible in Clouet's mid-highlights and
            peaks; shadows remain warmer and darker as he left them.

        (2) LUMINANCE MEASUREMENT of tinted output:
            luma_tinted = 0.2126 × r' + 0.7152 × g' + 0.0722 × b'

        (3) LUMINANCE RESTORATION — per-pixel normalisation:
            ratio = luma_orig / (luma_tinted + ε)
            r_out = r' × ratio
            g_out = g' × ratio
            b_out = b' × ratio
            Divides each pixel back to its original luma, preserving all tonal
            gradients exactly.  The colour has shifted but the 'drawing' under
            the glaze has not moved — precisely the effect of Clouet's technique.

        (4) COMPOSITE at opacity.

        FIFTY-SEVENTH DISTINCT MODE: novel because it is the ONLY pass to
        measure the luminance change introduced by a colour operation and then
        mathematically invert that change via per-pixel division.  Prior passes
        that shift colour (warm_highlight_bloom: additive bloom; van_der_werff:
        additive B-channel lift; Schalcken: additive amber in proximity zone;
        Reynolds: additive amber unification) do NOT restore original luma.
        This pass does — making the colour shift 'chrominance-only' in the
        strict colour-science sense.

        Args:
            cool_r       : Red channel of the cool target colour. Default 0.90.
            cool_g       : Green channel of the cool target colour. Default 0.88.
            cool_b       : Blue channel of the cool target colour. Default 0.94.
            tint_strength: Maximum lerp fraction toward the cool target. Default 0.18.
            hi_threshold : Luma below which the gate is zero (shadow protection). Default 0.38.
            hi_gate_power: Power applied to the luma gate (higher = more selective). Default 1.4.
            opacity      : Composite weight (0 = no-op). Default 0.50.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma_orig = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Luma gate — apply tint progressively in lighter zones ──────
        hi_thr = float(hi_threshold)
        hi_gate = _np.clip(
            (luma_orig - hi_thr) / (1.0 - hi_thr + 1e-6), 0.0, 1.0
        ) ** float(hi_gate_power)

        tint = float(tint_strength)
        cr, cg, cb = float(cool_r), float(cool_g), float(cool_b)

        # ── Step 2: Chroma shift — lerp toward cool ivory target ─────────────
        r_tinted = r0 + (cr - r0) * tint * hi_gate
        g_tinted = g0 + (cg - g0) * tint * hi_gate
        b_tinted = b0 + (cb - b0) * tint * hi_gate

        # ── Step 3: Measure tinted luma ───────────────────────────────────────
        luma_tinted = 0.2126 * r_tinted + 0.7152 * g_tinted + 0.0722 * b_tinted

        # ── Step 4: Luminance restoration — divide back to original luma ──────
        ratio = luma_orig / (luma_tinted + 1e-6)
        r_out = _np.clip(r_tinted * ratio, 0.0, 1.0)
        g_out = _np.clip(g_tinted * ratio, 0.0, 1.0)
        b_out = _np.clip(b_tinted * ratio, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        r_out = _np.clip(r0 * (1.0 - opacity) + r_out * opacity, 0.0, 1.0)
        g_out = _np.clip(g0 * (1.0 - opacity) + g_out * opacity, 0.0, 1.0)
        b_out = _np.clip(b0 * (1.0 - opacity) + b_out * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b_out * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Clouet enamel precision pass complete.")

    def wtewael_copper_jewel_pass(
        self,
        saturation_boost: float = 0.40,
        mid_lo: float = 0.25,
        mid_hi: float = 0.78,
        mid_power: float = 1.4,
        shadow_threshold: float = 0.22,
        shadow_power: float = 2.0,
        copper_r: float = 0.055,
        copper_g: float = 0.018,
        opacity: float = 0.55,
    ) -> None:
        """Copper-ground jewel saturation amplification — FIFTY-EIGHTH DISTINCT MODE.

        Encodes Joachim Wtewael's defining pictorial quality: the extraordinary,
        distance-invariant colour saturation of oil paint on a copper support.
        Wtewael (1566–1638) worked on copper panels that are non-porous and
        self-luminous, allowing paint to achieve maximum pigment concentration
        and an inner glow from the metal surface reflecting through thin layers.

        This is the FIFTY-EIGHTH DISTINCT MODE: PER-PIXEL CHROMA AMPLIFICATION
        VIA OPPONENT-SPACE DISTANCE SCALING.

        Unlike ALL prior colour-modification passes:
        - Every prior pass operates on individual channels in additive/multiplicative
          terms: warm_highlight_bloom adds a warm colour in bright zones; van_der_werff
          adds blue/subtracts red in skin zones; Schalcken adds amber via a radial
          field; shadow_color_temperature adds blue to shadows, warm to highlights;
          Clouet lerps toward a target colour.
        - This pass does something NO prior pass does: it computes the PER-PIXEL
          NEUTRAL GREY MEAN (n = (r+g+b)/3), then amplifies the CHROMA DISTANCE
          of each pixel from that neutral mean.  Every pixel's colour is treated
          as a position in opponent-colour space; the pass moves it further away
          from the neutral axis.
        - This is mathematically equivalent to increasing colour saturation in
          a perceptually consistent way — pushing reds redder, blues bluer,
          oranges more orange — without a hue shift, confined to the mid-bright
          zone where Wtewael's full-saturation technique is most visible.

        Algorithm (three steps):

        (1) PER-PIXEL NEUTRAL MEAN AND CHROMA DECOMPOSITION:
            n = (r + g + b) / 3
            delta_r = r − n
            delta_g = g − n
            delta_b = b − n
            Computes opponent-space displacement for each pixel from its own
            neutral point (not a global grey — each pixel has its own n).

        (2) MID-BRIGHT GATE (bell curve):
            luma = 0.2126r + 0.7152g + 0.0722b
            range = mid_hi − mid_lo
            gate_lo = clip((luma − mid_lo) / range, 0, 1)
            gate_hi = clip((mid_hi − luma) / range, 0, 1)
            mid_gate = (gate_lo × gate_hi) ** mid_power
            Peaks in the mid-bright zone; tapers to zero at pure black and pure
            white.  Confines amplification to the zone where Wtewael's copper
            saturation is most visible; highlights and deep shadows are protected.
            CHROMA AMPLIFICATION:
            boost = saturation_boost × mid_gate
            out_r = n + delta_r × (1 + boost)
            out_g = n + delta_g × (1 + boost)
            out_b = n + delta_b × (1 + boost)
            Pushes each pixel's colour further from its own neutral axis.

        (3) COPPER GROUND SHADOW WARMTH:
            shad_gate = clip((shadow_threshold − luma) / shadow_threshold, 0, 1)
                        ** shadow_power
            out_r += copper_r × shad_gate
            out_g += copper_g × shad_gate
            Injects warm copper-red warmth in the deepest shadows — the metal
            support showing through thin paint layers, as in Wtewael's nocturnal
            figures where impasto thins to near-transparency.

        Composite at opacity.

        FIFTY-EIGHTH DISTINCT MODE: novel because it is the ONLY pass to use
        PER-PIXEL NEUTRAL MEAN DECOMPOSITION (n = (r+g+b)/3) followed by
        CHROMA DISTANCE SCALING (amplify delta_r, delta_g, delta_b independently
        by a gate-weighted factor).  All prior colour-modification passes work on
        absolute channel values or lerp toward a fixed target colour; this pass
        works on deviation from the pixel's own neutral point — a fundamentally
        different formulation that achieves true saturation amplification in
        opponent-colour space without introducing a hue shift.

        Args:
            saturation_boost : Maximum chroma amplification factor. Default 0.40.
            mid_lo           : Lower luma bound of mid-bright gate. Default 0.25.
            mid_hi           : Upper luma bound of mid-bright gate. Default 0.78.
            mid_power        : Power applied to bell-curve gate (higher = sharper peak). Default 1.4.
            shadow_threshold : Luma below which copper warmth activates. Default 0.22.
            shadow_power     : Power applied to shadow gate (higher = more selective). Default 2.0.
            copper_r         : Red additive in copper shadow zone. Default 0.055.
            copper_g         : Green additive in copper shadow zone. Default 0.018.
            opacity          : Composite weight (0 = no-op). Default 0.55.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Per-pixel neutral mean and chroma decomposition ──────────
        n = (r0 + g0 + b0) / 3.0
        delta_r = r0 - n
        delta_g = g0 - n
        delta_b = b0 - n

        # ── Step 2: Mid-bright bell-curve gate and chroma amplification ──────
        range_f = float(mid_hi) - float(mid_lo) + 1e-6
        gate_lo = _np.clip((luma - float(mid_lo)) / range_f, 0.0, 1.0)
        gate_hi = _np.clip((float(mid_hi) - luma) / range_f, 0.0, 1.0)
        mid_gate = (gate_lo * gate_hi) ** float(mid_power)

        boost = float(saturation_boost) * mid_gate
        out_r = n + delta_r * (1.0 + boost)
        out_g = n + delta_g * (1.0 + boost)
        out_b = n + delta_b * (1.0 + boost)

        # ── Step 3: Copper ground shadow warmth ───────────────────────────────
        shad_thr = float(shadow_threshold)
        shad_gate = _np.clip(
            (shad_thr - luma) / (shad_thr + 1e-6), 0.0, 1.0
        ) ** float(shadow_power)
        out_r += float(copper_r) * shad_gate
        out_g += float(copper_g) * shad_gate

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Wtewael copper jewel pass complete.")

    def altdorfer_forest_atmosphere_pass(
        self,
        sky_band_hi: float = 0.30,
        earth_band_lo: float = 0.70,
        sky_cool_b: float = 0.055,
        sky_cool_r: float = 0.020,
        sky_cool_g: float = 0.008,
        sky_luma_lo: float = 0.35,
        forest_cool_b: float = 0.040,
        forest_warm_g: float = 0.018,
        forest_cool_r: float = 0.025,
        forest_luma_lo: float = 0.18,
        forest_luma_hi: float = 0.72,
        earth_warm_r: float = 0.045,
        earth_warm_g: float = 0.018,
        earth_luma_hi: float = 0.55,
        opacity: float = 0.50,
    ) -> None:
        """Vertical atmospheric depth layering — FIFTY-NINTH DISTINCT MODE.

        Encodes Albrecht Altdorfer's defining pictorial innovation: the
        instinctive stratification of the canvas into distinct atmospheric
        depth layers, each carrying its own chromatic identity.

        Altdorfer (c. 1480–1538), founder of the Danube School, was the
        first European painter to treat landscape as an autonomous subject.
        He consistently organised his panels into three visual layers:
          - Sky (upper): pale silver or golden atmospheric haze, dissolving
            into cool blue-grey at the zenith.
          - Mid-distance forest: the richest chromatic zone — deep blue-green
            foliage, sometimes tinged with violet, dense and atmospheric.
          - Earth / shadow (lower): warm umber and amber, the dark forest
            floor grounding the composition.

        This is the FIFTY-NINTH DISTINCT MODE: LUMINANCE-STRATIFIED
        VERTICAL ATMOSPHERIC DEPTH LAYERING.

        Unlike ALL prior spatial passes:
        - schalcken_candlelight_glow_pass uses RADIAL distance from a point.
        - gentileschi_dramatic_flesh_pass uses a DIRECTIONAL VECTOR (upper-left).
        - melozzo_da_forli_zenith_pass uses downward overhead-light gradient.
        - atmospheric_depth_gradient_pass applies a uniform vertical luma
          weight across the full canvas height (one temperature, one gradient).
        - This pass is the ONLY pass to SEGMENT the canvas into THREE
          INDEPENDENT HORIZONTAL BANDS (sky / forest / earth), each applying
          a DIFFERENT chromatic temperature shift gated by its OWN luminance
          range — three fully independent colour operations by Y position.

        Algorithm (three independent band operations):

        (1) SKY BAND (y_norm < sky_band_hi):
            band_wt = clip((sky_band_hi - y_norm) / sky_band_hi, 0, 1)^2
            luma_gate = clip((luma - sky_luma_lo) / (1.0 - sky_luma_lo), 0, 1)
            b += sky_cool_b × band_wt × luma_gate   [cool silver-blue push]
            r -= sky_cool_r × band_wt × luma_gate
            g -= sky_cool_g × band_wt × luma_gate
            Cools highlights toward pale silver-blue — Altdorfer's hazy sky.

        (2) FOREST / MID-DISTANCE BAND (sky_band_hi ≤ y_norm ≤ earth_band_lo):
            spread = earth_band_lo - sky_band_hi
            band_wt = clip(1 - |y_norm - mid| / (spread/2), 0, 1)^1.5
            luma_gate = clip((luma-forest_luma_lo)/rng, 0, 1)×clip((forest_luma_hi-luma)/rng,0,1)
            b += forest_cool_b × band_wt × luma_gate  [blue-green push]
            g += forest_warm_g × band_wt × luma_gate
            r -= forest_cool_r × band_wt × luma_gate
            Deepens mid-tones toward blue-green — Altdorfer's dense forest.

        (3) EARTH / SHADOW BAND (y_norm > earth_band_lo):
            band_wt = clip((y_norm - earth_band_lo) / (1 - earth_band_lo), 0, 1)^2
            luma_gate = clip((earth_luma_hi - luma) / earth_luma_hi, 0, 1)
            r += earth_warm_r × band_wt × luma_gate   [warm amber-umber push]
            g += earth_warm_g × band_wt × luma_gate
            Warms shadows toward amber-umber — Altdorfer's dark forest floor.

        Composite at opacity.

        FIFTY-NINTH DISTINCT MODE: novel because it is the ONLY pass to apply
        three INDEPENDENT chromatic temperature shifts to three INDEPENDENT
        horizontal Y-coordinate bands, each with its own luminance gate.
        All prior spatial passes use a single spatial field (radial, linear,
        directional); this pass uses three separate Y-segmented zones.

        Args:
            sky_band_hi     : Normalised Y threshold below which sky band activates (0 = top). Default 0.30.
            earth_band_lo   : Normalised Y threshold above which earth band activates. Default 0.70.
            sky_cool_b      : Blue channel addition in sky highlights. Default 0.055.
            sky_cool_r      : Red channel subtraction in sky highlights. Default 0.020.
            sky_cool_g      : Green channel subtraction in sky highlights. Default 0.008.
            sky_luma_lo     : Lower luma bound for sky gate (protects shadows). Default 0.35.
            forest_cool_b   : Blue channel addition in forest mid-tones. Default 0.040.
            forest_warm_g   : Green channel addition in forest mid-tones. Default 0.018.
            forest_cool_r   : Red channel subtraction in forest mid-tones. Default 0.025.
            forest_luma_lo  : Lower luma bound for forest gate. Default 0.18.
            forest_luma_hi  : Upper luma bound for forest gate. Default 0.72.
            earth_warm_r    : Red channel addition in earth shadows. Default 0.045.
            earth_warm_g    : Green channel addition in earth shadows. Default 0.018.
            earth_luma_hi   : Upper luma bound for earth gate (protects highlights). Default 0.55.
            opacity         : Composite weight (0 = no-op). Default 0.50.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # Normalised Y coordinate (0 = top, 1 = bottom)
        y_norm = _np.linspace(0.0, 1.0, H, dtype=_np.float32)[:, None] * _np.ones(
            (1, W), dtype=_np.float32
        )

        out_r = r0.copy()
        out_g = g0.copy()
        out_b = b0.copy()

        # ── Band 1: Sky (upper, y_norm < sky_band_hi) ───────────────────────
        sky_hi = float(sky_band_hi)
        sky_bwt = _np.clip((sky_hi - y_norm) / (sky_hi + 1e-6), 0.0, 1.0) ** 2
        sky_lgate = _np.clip(
            (luma - float(sky_luma_lo)) / (1.0 - float(sky_luma_lo) + 1e-6),
            0.0, 1.0,
        )
        sky_effect = sky_bwt * sky_lgate
        out_b += float(sky_cool_b) * sky_effect
        out_r -= float(sky_cool_r) * sky_effect
        out_g -= float(sky_cool_g) * sky_effect

        # ── Band 2: Forest / mid-distance ───────────────────────────────────
        mid_y = (float(sky_band_hi) + float(earth_band_lo)) / 2.0
        spread = (float(earth_band_lo) - float(sky_band_hi)) / 2.0 + 1e-6
        forest_bwt = _np.clip(1.0 - _np.abs(y_norm - mid_y) / spread, 0.0, 1.0) ** 1.5
        frng = float(forest_luma_hi) - float(forest_luma_lo) + 1e-6
        f_lo_gate = _np.clip((luma - float(forest_luma_lo)) / frng, 0.0, 1.0)
        f_hi_gate = _np.clip((float(forest_luma_hi) - luma) / frng, 0.0, 1.0)
        forest_lgate = f_lo_gate * f_hi_gate
        forest_effect = forest_bwt * forest_lgate
        out_b += float(forest_cool_b) * forest_effect
        out_g += float(forest_warm_g) * forest_effect
        out_r -= float(forest_cool_r) * forest_effect

        # ── Band 3: Earth / shadow (lower, y_norm > earth_band_lo) ─────────
        earth_lo = float(earth_band_lo)
        earth_bwt = _np.clip(
            (y_norm - earth_lo) / (1.0 - earth_lo + 1e-6), 0.0, 1.0
        ) ** 2
        earth_lgate = _np.clip(
            (float(earth_luma_hi) - luma) / (float(earth_luma_hi) + 1e-6),
            0.0, 1.0,
        )
        earth_effect = earth_bwt * earth_lgate
        out_r += float(earth_warm_r) * earth_effect
        out_g += float(earth_warm_g) * earth_effect

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Altdorfer forest atmosphere pass complete.")

    def vibrance_selective_pass(
        self,
        vibrance_strength: float = 0.45,
        vibrance_gamma: float = 1.4,
        luma_lo: float = 0.08,
        luma_hi: float = 0.90,
        opacity: float = 0.55,
    ) -> None:
        """Saturation-inverse selective chroma boost (Vibrance) — SIXTIETH DISTINCT MODE.

        Implements perceptual vibrance: a selective saturation enhancement
        that preferentially boosts less-saturated (dull, muted) pixels while
        leaving already-vivid pixels unchanged.  This matches the behaviour
        of Adobe's 'Vibrance' control and produces a more natural-looking
        saturation lift than a uniform saturation boost.

        This is the SIXTIETH DISTINCT MODE: SATURATION-INVERSE SELECTIVE
        CHROMA AMPLIFICATION.

        Unlike ALL prior chroma-boost passes:
        - wtewael_copper_jewel_pass amplifies chroma via opponent-space
          distance, gated by LUMINANCE zone (mid-bright).  All pixels in
          that zone get the same proportional boost regardless of how
          saturated they already are.
        - schedoni_luminous_emergence_pass amplifies chroma via
          (rgb - achromatic_mean) × chroma_boost × hi_gate.  Boost is
          uniform within the luminance zone.
        - bartolomeo_veneto_hue_deepening_pass gates by HUE ANGLE.  Boost
          is uniform within the selected hue ranges.
        - filippino_lippi_hue_rotation_pass scales HUE ROTATION by existing
          saturation — not chroma magnitude.
        - This pass is the ONLY pass to gate chroma amplification by the
          INVERSE of the pixel's EXISTING SATURATION LEVEL: dull pixels
          receive a large boost; already-vivid pixels receive little or none.
          This is a fundamentally different gating strategy — saturation-space
          rather than luminance-space or hue-space.

        Algorithm:

        (1) PER-PIXEL HSV SATURATION:
            vmax = max(r, g, b)
            S = (vmax - min(r, g, b)) / (vmax + ε)
            Computes the standard HSV saturation for each pixel (0 = grey,
            1 = fully saturated).

        (2) VIBRANCE GATE (saturation-inverse power curve):
            vib_gate = (1 - S) ^ vibrance_gamma
            High gate for near-grey pixels; gate → 0 for already-saturated ones.
            Power vibrance_gamma controls the roll-off (higher = sharper cutoff
            between boosted and protected zones).

        (3) LUMINANCE GATE (protects extreme shadows and specular peaks):
            luma = 0.2126r + 0.7152g + 0.0722b
            luma_gate = clip((luma - luma_lo) / rng, 0, 1)
                        × clip((luma_hi - luma) / rng, 0, 1)
            Prevents noisy saturation boosts in near-black shadows and
            prevents clipping in bright specular highlights.

        (4) CHROMA AMPLIFICATION via neutral-mean decomposition:
            n = (r + g + b) / 3
            delta = rgb − n   (opponent-colour vector)
            boost = vibrance_strength × vib_gate × luma_gate
            out = n + delta × (1 + boost)
            Pushes each pixel's colour further from its own neutral axis,
            proportional to how dull it currently is.

        Composite at opacity.

        SIXTIETH DISTINCT MODE: novel because it is the ONLY pass to gate
        chroma amplification on the INVERSE of the pixel's existing HSV
        saturation level.  All prior chroma-modification passes (wtewael,
        schedoni, etc.) apply uniform or luminance-gated boosts independent
        of the pixel's current saturation state; this pass boosts only what
        is already dull, protecting what is already vivid.

        Args:
            vibrance_strength : Maximum chroma amplification for fully-desaturated pixels. Default 0.45.
            vibrance_gamma    : Power for saturation-inverse gate (higher = sharper cutoff). Default 1.4.
            luma_lo           : Lower luma bound of luminance gate. Default 0.08.
            luma_hi           : Upper luma bound of luminance gate. Default 0.90.
            opacity           : Composite weight (0 = no-op). Default 0.55.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Per-pixel HSV saturation ─────────────────────────────────
        vmax = _np.maximum(_np.maximum(r0, g0), b0)
        vmin = _np.minimum(_np.minimum(r0, g0), b0)
        sat = (vmax - vmin) / (vmax + 1e-6)   # HSV saturation, [0, 1]

        # ── Step 2: Vibrance gate (saturation-inverse power curve) ───────────
        vib_gate = (1.0 - sat) ** float(vibrance_gamma)

        # ── Step 3: Luminance gate ────────────────────────────────────────────
        lo, hi = float(luma_lo), float(luma_hi)
        rng = hi - lo + 1e-6
        luma_gate = (
            _np.clip((luma - lo) / rng, 0.0, 1.0)
            * _np.clip((hi - luma) / rng, 0.0, 1.0)
        )

        # ── Step 4: Chroma amplification via neutral-mean decomposition ───────
        n = (r0 + g0 + b0) / 3.0
        delta_r = r0 - n
        delta_g = g0 - n
        delta_b = b0 - n

        boost = float(vibrance_strength) * vib_gate * luma_gate
        out_r = n + delta_r * (1.0 + boost)
        out_g = n + delta_g * (1.0 + boost)
        out_b = n + delta_b * (1.0 + boost)

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Vibrance selective pass complete.")

    def fabritius_pale_ground_pass(
        self,
        pale_r: float = 0.86,
        pale_g: float = 0.82,
        pale_b: float = 0.78,
        dark_hi: float = 0.45,
        dark_power: float = 1.8,
        lift_strength: float = 0.30,
        opacity: float = 0.50,
    ) -> None:
        """Inverted tenebrism background lift — SIXTY-FIRST DISTINCT MODE.

        Implements Carel Fabritius's characteristic pale-ground painting
        technique: rather than deepening shadows toward near-black void
        (as every tenebrism and candlelight pass does), this pass
        BRIGHTENS low-luminance zones by lifting them toward a pale warm-
        ivory target colour.  The result is the distinctive Delft School
        effect — figures sit dark-against-light rather than light-against-
        dark.

        This is the SIXTY-FIRST DISTINCT MODE: INVERTED TENEBRISM —
        LUMINANCE-RAISING SHADOW LIFT.

        Unlike ALL prior shadow-zone passes:
        - schedoni_luminous_emergence_pass COMPRESSES shadows toward near-
          black void.
        - schalcken_candlelight_glow_pass DEEPENS non-lit zones via
          multiplicative darkening.
        - reynolds_grand_manner_pass, shadow_color_temperature_pass,
          gentileschi_dramatic_flesh_pass — all apply colour shifts
          but further DARKEN the shadow zone in luminance terms.
        - This pass is the ONLY pass to deliberately RAISE the luminance
          of dark zones toward a lighter target, simulating pale-ground
          luminosity bleeding through thin shadow paint layers.

        Algorithm:

        (1) DARK ZONE GATE (luminance-inverse power curve):
            dark_gate = clip((dark_hi − luma) / dark_hi, 0, 1) ^ dark_power
            Peaks at luma = 0 (pure black); falls to 0 at luma = dark_hi.
            Power dark_power controls roll-off steepness.

        (2) PALE GROUND LIFT:
            out_r = r0 + (pale_r − r0) × dark_gate × lift_strength
            out_g = g0 + (pale_g − g0) × dark_gate × lift_strength
            out_b = b0 + (pale_b − b0) × dark_gate × lift_strength
            Interpolates dark pixels toward pale_ground color, simulating
            the luminous chalk-white ground showing through thin paint.

        Composite at opacity.

        SIXTY-FIRST DISTINCT MODE: novel because it is the ONLY pass to
        apply a brightening (lift) transform to dark/shadow zones.  All
        prior passes that modify the shadow zone deepen or compress it
        toward black; this pass inverts that logic entirely.

        Args:
            pale_r        : Pale ground target R channel. Default 0.86 (warm ivory).
            pale_g        : Pale ground target G channel. Default 0.82.
            pale_b        : Pale ground target B channel. Default 0.78.
            dark_hi       : Upper luminance bound of the lift zone. Default 0.45.
            dark_power    : Power-curve steepness for the dark gate. Default 1.8.
            lift_strength : Maximum lift fraction toward pale ground. Default 0.30.
            opacity       : Composite weight (0 = no-op). Default 0.50.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Dark zone gate (luminance-inverse power curve) ────────────
        dark_gate = _np.clip(
            (float(dark_hi) - luma) / (float(dark_hi) + 1e-6),
            0.0, 1.0
        ) ** float(dark_power)

        # ── Step 2: Pale ground lift ──────────────────────────────────────────
        ls = float(lift_strength)
        out_r = r0 + (float(pale_r) - r0) * dark_gate * ls
        out_g = g0 + (float(pale_g) - g0) * dark_gate * ls
        out_b = b0 + (float(pale_b) - b0) * dark_gate * ls

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Fabritius pale ground pass complete.")

    def luminance_gradient_warmth_pass(
        self,
        warm_r: float = 0.055,
        warm_g: float = 0.022,
        grad_gamma: float = 1.5,
        grad_sigma: float = 1.5,
        luma_lo: float = 0.12,
        luma_hi: float = 0.82,
        opacity: float = 0.40,
    ) -> None:
        """Penumbral zone warm tinting via luminance gradient magnitude — SIXTY-SECOND DISTINCT MODE.

        Applies a warm amber tint selectively at the transitional (penumbral)
        zones between light and shadow — the boundary zone where luminance
        changes fastest spatially.  This replicates the warm-edged penumbra
        effect seen in Dutch candlelight painting, where the transition from
        lit to unlit surface carries a brief warm amber fringe before cooling
        into shadow.

        This is the SIXTY-SECOND DISTINCT MODE: PENUMBRAL ZONE WARM TINTING
        VIA LUMINANCE GRADIENT MAGNITUDE.

        Unlike ALL prior chromatic passes:
        - shadow_color_temperature_pass, reynolds_grand_manner_pass,
          schalcken_candlelight_glow_pass — all gate their colour effects on
          LUMINANCE LEVEL (luma < threshold or luma > threshold).  A pixel
          at luma 0.30 gets the same treatment whether it is the centre of a
          broad shadow or the sharp edge of a cast shadow.
        - warm_highlight_bloom_pass gates on absolute brightness threshold.
        - This pass gates its warm-tint injection on the SPATIAL RATE OF
          CHANGE of luminance (the gradient magnitude): a pixel at luma 0.30
          at the edge of a shadow receives a large boost; the same pixel in
          the middle of a flat shadow receives almost none.  The gate is the
          Sobel gradient magnitude, not the luma level — a fundamentally
          different gating strategy.

        Algorithm:

        (1) PRE-BLUR LUMA for stable gradient estimation:
            luma_smooth = gaussian(luma, sigma=grad_sigma)

        (2) SOBEL GRADIENT MAGNITUDE:
            dx = sobel(luma_smooth, axis=1)   (horizontal gradient)
            dy = sobel(luma_smooth, axis=0)   (vertical gradient)
            grad_mag = sqrt(dx² + dy²)
            Normalise: grad_norm = grad_mag / (max(grad_mag) + ε)

        (3) PENUMBRAL GATE (power curve on normalised gradient):
            pen_gate = grad_norm ^ grad_gamma
            High gate at sharp light/shadow boundaries; near-zero in
            flat zones (uniform highlight or uniform shadow).

        (4) LUMINANCE GATE (protects near-black and specular peaks):
            luma_gate = ramp_lo × ramp_hi (bell)

        (5) WARM AMBER INJECTION:
            out_r += warm_r × pen_gate × luma_gate
            out_g += warm_g × pen_gate × luma_gate
            Adds warm amber (R+ G+) at penumbral transition zones only.

        Composite at opacity.

        SIXTY-SECOND DISTINCT MODE: novel because it is the ONLY pass to
        gate its chromatic effect on the SPATIAL GRADIENT MAGNITUDE of
        luminance (the rate of change) rather than on luminance level.
        All prior passes gate on absolute luminance value; this pass gates
        on the spatial derivative — it is blind to flat uniform zones and
        active only at tonal transitions.

        Args:
            warm_r      : Warm amber R injection strength at penumbra. Default 0.055.
            warm_g      : Warm amber G injection strength at penumbra. Default 0.022.
            grad_gamma  : Power curve on normalised gradient gate (higher = sharper). Default 1.5.
            grad_sigma  : Pre-blur sigma for smoother gradient estimate. Default 1.5.
            luma_lo     : Lower luminance bound of luma gate. Default 0.12.
            luma_hi     : Upper luminance bound of luma gate. Default 0.82.
            opacity     : Composite weight (0 = no-op). Default 0.40.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gaussian_filter, sobel as _sobel

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Pre-blur luma for stable gradient ─────────────────────────
        luma_smooth = _gaussian_filter(luma, sigma=float(grad_sigma))

        # ── Step 2: Sobel gradient magnitude ─────────────────────────────────
        dx = _sobel(luma_smooth, axis=1)
        dy = _sobel(luma_smooth, axis=0)
        grad_mag = _np.sqrt(dx * dx + dy * dy)
        gmax = float(grad_mag.max()) + 1e-6
        grad_norm = grad_mag / gmax

        # ── Step 3: Penumbral gate (power curve on gradient) ──────────────────
        pen_gate = grad_norm ** float(grad_gamma)

        # ── Step 4: Luminance gate ────────────────────────────────────────────
        lo, hi = float(luma_lo), float(luma_hi)
        rng = hi - lo + 1e-6
        luma_gate = (
            _np.clip((luma - lo) / rng, 0.0, 1.0)
            * _np.clip((hi - luma) / rng, 0.0, 1.0)
        )

        # ── Step 5: Warm amber injection in penumbral zone ────────────────────
        gate = pen_gate * luma_gate
        out_r = _np.clip(r0 + float(warm_r) * gate, 0.0, 1.0)
        out_g = _np.clip(g0 + float(warm_g) * gate, 0.0, 1.0)
        out_b = b0  # blue unchanged — warm (R+ G+ only)

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Luminance gradient warmth pass complete.")

    def bloemaert_pastoral_iridescence_pass(
        self,
        hf_sigma: float = 2.0,
        threshold: float = 0.04,
        warm_r: float = 0.05,
        warm_g: float = 0.02,
        cool_b: float = 0.06,
        cool_r_reduce: float = 0.03,
        luma_lo: float = 0.10,
        luma_hi: float = 0.90,
        opacity: float = 0.45,
    ) -> None:
        """High-frequency chromatic oscillation — SIXTY-THIRD DISTINCT MODE.

        Implements Abraham Bloemaert's characteristic fine chromatic iridescence:
        at the scale of individual brushstrokes, warm and cool tones vibrate
        against each other — warm amber in the high-frequency impasto peaks,
        cool blue-violet in the recessed inter-stroke troughs.

        This is the SIXTY-THIRD DISTINCT MODE: HIGH-FREQUENCY CHROMATIC
        OSCILLATION VIA SIGNED RESIDUAL POLARITY GATING.

        The key novelty is using the SIGN (polarity) of the high-frequency
        luminance residual as a warm/cool switch.  Unlike ALL prior passes:
        - Laplacian pyramid pass (s124 Stanzione) decomposes frequency bands
          but applies tonal sculpting, not chromatic warm/cool switching.
        - Chromatic fringe pass (s156) uses Sobel MAGNITUDE (unsigned) to
          apply prismatic warm/cool fringe symmetrically at edges.
        - Luminance gradient warmth pass (s170) uses Sobel magnitude (unsigned)
          for warm tinting only — no cool branch.
        - This pass uses the SIGNED residual: positive HF → warm; negative HF →
          cool.  The sign distinguishes impasto peaks from inter-stroke troughs,
          producing a bidirectional warm/cool oscillation that no prior pass
          achieves.

        Algorithm:

        (1) LOW-FREQUENCY BASE (Gaussian blur):
            luma_lo = gaussian(luma, sigma=hf_sigma)

        (2) HIGH-FREQUENCY RESIDUAL:
            hf_residual = luma − luma_lo
            Range is roughly [−0.5, +0.5] for a typical image.

        (3) WARM GATE (HF peaks — impasto ridges):
            warm_gate = clip((hf_residual − threshold) / threshold, 0, 1)
            Activates where HF residual exceeds +threshold.

        (4) COOL GATE (HF troughs — inter-stroke recesses):
            cool_gate = clip((−hf_residual − threshold) / threshold, 0, 1)
            Activates where HF residual falls below −threshold.

        (5) LUMINANCE BELL GATE (protects extremes):
            luma_gate = ramp_lo × ramp_hi

        (6) CHROMATIC INJECTION:
            out_r += warm_r × warm_gate × luma_gate
            out_g += warm_g × warm_gate × luma_gate
            out_b += cool_b × cool_gate × luma_gate
            out_r −= cool_r_reduce × cool_gate × luma_gate

        Composite at opacity.

        SIXTY-THIRD DISTINCT MODE: novel because it is the ONLY pass to use
        the SIGN/POLARITY of the high-frequency residual as a bidirectional
        warm/cool chromatic switch.  Prior passes using HF data (Stanzione,
        chromatic fringe, luminance gradient warmth) all work with unsigned
        magnitude only.

        Args:
            hf_sigma       : Gaussian sigma for extracting low-frequency base. Default 2.0.
            threshold      : Residual magnitude threshold to activate warm/cool gate. Default 0.04.
            warm_r         : Warm R injection at HF peaks. Default 0.05.
            warm_g         : Warm G injection at HF peaks. Default 0.02.
            cool_b         : Cool B injection at HF troughs. Default 0.06.
            cool_r_reduce  : R reduction at HF troughs. Default 0.03.
            luma_lo        : Lower luminance bound of bell gate. Default 0.10.
            luma_hi        : Upper luminance bound of bell gate. Default 0.90.
            opacity        : Composite weight (0 = no-op). Default 0.45.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gaussian_filter

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Low-frequency base via Gaussian blur ──────────────────────
        luma_base = _gaussian_filter(luma, sigma=float(hf_sigma))

        # ── Step 2: High-frequency residual ──────────────────────────────────
        hf_residual = luma - luma_base

        # ── Step 3: Warm gate (positive HF peaks) ─────────────────────────────
        thr = float(threshold) + 1e-6
        warm_gate = _np.clip((hf_residual - float(threshold)) / thr, 0.0, 1.0)

        # ── Step 4: Cool gate (negative HF troughs) ───────────────────────────
        cool_gate = _np.clip((-hf_residual - float(threshold)) / thr, 0.0, 1.0)

        # ── Step 5: Luminance bell gate ───────────────────────────────────────
        lo, hi = float(luma_lo), float(luma_hi)
        rng = hi - lo + 1e-6
        luma_gate = (
            _np.clip((luma - lo) / rng, 0.0, 1.0)
            * _np.clip((hi - luma) / rng, 0.0, 1.0)
        )

        # ── Step 6: Chromatic injection ───────────────────────────────────────
        wg = warm_gate * luma_gate
        cg = cool_gate * luma_gate
        out_r = _np.clip(r0 + float(warm_r) * wg - float(cool_r_reduce) * cg, 0.0, 1.0)
        out_g = _np.clip(g0 + float(warm_g) * wg, 0.0, 1.0)
        out_b = _np.clip(b0 + float(cool_b) * cg, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Bloemaert pastoral iridescence pass complete.")

    # Session 171 — random improvement: chromatic_vignette_pass
    # Radial chromatic vignette: darken + cool-shift periphery, simulating
    # the way Renaissance/Baroque panels often show cool ground at canvas edges.

    def chromatic_vignette_pass(
        self,
        radius: float = 0.75,
        darken_strength: float = 0.30,
        cool_b: float = 0.04,
        cool_r_reduce: float = 0.02,
        vig_gamma: float = 2.0,
        luma_lo: float = 0.08,
        opacity: float = 0.50,
    ) -> None:
        """Radial chromatic vignette darkening — SIXTY-FOURTH DISTINCT MODE.

        Applies a radial vignette that simultaneously darkens and cool-shifts
        the canvas periphery — simulating the characteristic edge behaviour of
        Renaissance and Baroque panel paintings, where thin paint layers at the
        canvas margin allow the cool ground to show through, and ambient occlusion
        naturally darkens corners.

        This is the SIXTY-FOURTH DISTINCT MODE: RADIAL CHROMATIC VIGNETTE —
        COMBINED PERIPHERAL DARKENING WITH COOL TEMPERATURE SHIFT.

        Unlike ALL prior radial/peripheral passes:
        - peripheral_defocus_pass (s157) uses radial distance to weight a
          Gaussian BLUR — it softens, it does not darken or colour-shift.
        - schalcken_candlelight_glow_pass (s165) uses radial distance from a
          specific light point for BRIGHTENING toward warm amber — inverse effect.
        - No prior pass combines radial distance-from-center with simultaneous
          luminance darkening AND chromatic temperature shift.

        Algorithm:

        (1) DISTANCE MAP (normalised to canvas half-diagonal):
            cx = W / 2, cy = H / 2
            dx = (x − cx) / (W / 2),  dy = (y − cy) / (H / 2)
            dist = sqrt(dx² + dy²) / sqrt(2)    [0 at center, 1 at corner]

        (2) VIGNETTE WEIGHT (power-curve ramp beyond radius):
            vig_raw = clip((dist − radius) / (1.0 − radius + ε), 0, 1)
            vig_weight = vig_raw ^ vig_gamma
            Zero inside radius; ramps to 1 at corners.

        (3) LUMA PROTECTION GATE (avoid crushing near-black pixels):
            luma_gate = clip((luma − luma_lo) / (1.0 − luma_lo + ε), 0, 1)

        (4) DARKENING:
            darken_factor = 1.0 − darken_strength × vig_weight × luma_gate
            out_rgb = in_rgb × darken_factor

        (5) COOL SHIFT:
            out_b += cool_b × vig_weight × luma_gate
            out_r −= cool_r_reduce × vig_weight × luma_gate

        Composite at opacity.

        SIXTY-FOURTH DISTINCT MODE: novel because it is the ONLY pass to
        combine radial distance-from-center with BOTH luminance darkening AND
        chromatic cool-temperature shift simultaneously.  Prior peripheral
        passes either blur only, or apply a warm brightening spotlight (inverse
        direction), never this combination.

        Args:
            radius          : Normalised radius (0–1) at which vignette begins. Default 0.75.
            darken_strength : Maximum darkening fraction at canvas corners. Default 0.30.
            cool_b          : Blue channel boost at periphery. Default 0.04.
            cool_r_reduce   : Red channel reduction at periphery. Default 0.02.
            vig_gamma       : Power curve on vignette weight (higher = sharper falloff). Default 2.0.
            luma_lo         : Lower luma bound — near-black pixels spared from darkening. Default 0.08.
            opacity         : Composite weight (0 = no-op). Default 0.50.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Normalised distance map from canvas centre ────────────────
        ys = _np.linspace(-1.0, 1.0, H, dtype=_np.float32)
        xs = _np.linspace(-1.0, 1.0, W, dtype=_np.float32)
        xg, yg = _np.meshgrid(xs, ys)
        dist = _np.sqrt(xg * xg + yg * yg) / (_np.sqrt(2.0) + 1e-6)
        dist = _np.clip(dist, 0.0, 1.0)

        # ── Step 2: Vignette weight ramp beyond radius ────────────────────────
        rad = float(radius)
        outer_range = max(1.0 - rad, 1e-6)
        vig_raw = _np.clip((dist - rad) / outer_range, 0.0, 1.0)
        vig_weight = vig_raw ** float(vig_gamma)

        # ── Step 3: Luma protection gate ──────────────────────────────────────
        lo = float(luma_lo)
        luma_gate = _np.clip((luma - lo) / (1.0 - lo + 1e-6), 0.0, 1.0)

        combined = vig_weight * luma_gate

        # ── Step 4: Darkening ─────────────────────────────────────────────────
        darken_factor = _np.clip(1.0 - float(darken_strength) * combined, 0.0, 1.0)
        out_r = _np.clip(r0 * darken_factor, 0.0, 1.0)
        out_g = _np.clip(g0 * darken_factor, 0.0, 1.0)
        out_b = _np.clip(b0 * darken_factor, 0.0, 1.0)

        # ── Step 5: Cool shift at periphery ───────────────────────────────────
        out_r = _np.clip(out_r - float(cool_r_reduce) * combined, 0.0, 1.0)
        out_b = _np.clip(out_b + float(cool_b) * combined, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Chromatic vignette pass complete.")

    # Session 172 — artist pass: avercamp_winter_atmosphere_pass
    # Hendrick Avercamp's overcast winter luminosity: global silver-grey target
    # blending + midtone warmth restoration — SIXTY-FIFTH DISTINCT MODE.

    def avercamp_winter_atmosphere_pass(
        self,
        silver_r: float = 0.73,
        silver_g: float = 0.76,
        silver_b: float = 0.82,
        grey_strength: float = 0.32,
        warm_r: float = 0.055,
        warm_g: float = 0.022,
        warmth_lo: float = 0.30,
        warmth_hi: float = 0.72,
        warmth_strength: float = 0.60,
        opacity: float = 0.55,
    ) -> None:
        """Silver-grey overcast desaturation + midtone warmth restoration — SIXTY-FIFTH DISTINCT MODE.

        Implements Hendrick Avercamp's characteristic flat-overcast winter
        luminosity: a global silver-grey-blue atmospheric haze from the
        Dutch winter sky, against which warm figure-costume colours (brick
        red, ochre) appear as scattered warm midtone notes.

        This is the SIXTY-FIFTH DISTINCT MODE: GLOBAL SILVER-GREY TARGET
        BLENDING WITH SELECTIVE MIDTONE WARMTH RESTORATION.

        Unlike ALL prior tinting passes:
        - Session 161 Reynolds: flat amber glaze applied unconditionally
          to every pixel (R+ G+ B-) — but does NOT blend toward a target
          grey; it shifts existing colours additively.
        - Session 145 Luca Cambiaso: tonal flattening via block-averaging —
          spatial coarsening, not chromatic target-blending.
        - Session 166 Van der Werff: skin-detection pass; cool tint applied
          to detected skin pixels only — narrow zone, not global.
        - This pass performs a GLOBAL BLEND of every pixel toward a pale
          silver-grey-blue target (simulating overcast sky diffusion across
          the entire scene), then RESTORES WARM CHROMATICITY only in the
          midtone luminance zone.  No prior pass begins from a globally
          shifted desaturated target.  Prior passes start from original
          pixel values and add or subtract effects on top; this pass first
          MOVES all pixels toward grey, then partially reverts midtone
          pixels to their warm potential.

        Algorithm:

        (1) SILVER-GREY BLEND (global overcast):
            For every channel c ∈ {R, G, B}:
            c_grey = c0 + (silver_c − c0) × grey_strength
            This pulls every pixel toward the silver target regardless
            of its original hue, simulating flat diffuse overcast illumination
            that desaturates all local colours toward atmospheric grey.

        (2) MIDTONE WARMTH GATE (figure costume zone):
            luma = 0.2126·R + 0.7152·G + 0.0722·B
            lo_ramp = clip((luma − warmth_lo) / (warmth_hi − warmth_lo), 0, 1)
            hi_ramp = clip((warmth_hi − luma) / (warmth_hi − warmth_lo), 0, 1)
            mid_gate = lo_ramp × hi_ramp   [bell peaking at midtone centre]

        (3) WARMTH RESTORATION (costume colour recovery):
            out_r = c_grey_r + warm_r × mid_gate × warmth_strength
            out_g = c_grey_g + warm_g × mid_gate × warmth_strength
            out_b = c_grey_b   (cool silver base preserved in blue channel)

        (4) COMPOSITE at opacity.

        SIXTY-FIFTH DISTINCT MODE: novel because it is the ONLY pass to
        begin by blending ALL pixels toward a grey target (global desaturation
        via target interpolation) and then selectively restore chromaticity
        in midtones.  All prior passes preserve the original colour as the
        base and apply additive/multiplicative effects.

        Args:
            silver_r       : Red component of silver-grey target. Default 0.73.
            silver_g       : Green component of silver-grey target. Default 0.76.
            silver_b       : Blue component of silver-grey target. Default 0.82.
            grey_strength  : Blend weight toward silver target (0=no-op, 1=full grey). Default 0.32.
            warm_r         : Warm R restoration in midtone zone. Default 0.055.
            warm_g         : Warm G restoration in midtone zone. Default 0.022.
            warmth_lo      : Lower luminance bound of midtone warmth gate. Default 0.30.
            warmth_hi      : Upper luminance bound of midtone warmth gate. Default 0.72.
            warmth_strength: Scale factor for warmth restoration. Default 0.60.
            opacity        : Composite weight (0 = no-op). Default 0.55.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Global silver-grey target blend (overcast desaturation) ───
        gs = float(grey_strength)
        sr, sg, sb = float(silver_r), float(silver_g), float(silver_b)
        c_grey_r = r0 + (sr - r0) * gs
        c_grey_g = g0 + (sg - g0) * gs
        c_grey_b = b0 + (sb - b0) * gs

        # ── Step 2: Midtone warmth gate (bell over [warmth_lo, warmth_hi]) ────
        lo = float(warmth_lo)
        hi = float(warmth_hi)
        rng = hi - lo + 1e-6
        lo_ramp = _np.clip((luma - lo) / rng, 0.0, 1.0)
        hi_ramp = _np.clip((hi - luma) / rng, 0.0, 1.0)
        mid_gate = lo_ramp * hi_ramp

        # ── Step 3: Warmth restoration in midtone zone ────────────────────────
        ws = float(warmth_strength)
        out_r = _np.clip(c_grey_r + float(warm_r) * mid_gate * ws, 0.0, 1.0)
        out_g = _np.clip(c_grey_g + float(warm_g) * mid_gate * ws, 0.0, 1.0)
        out_b = _np.clip(c_grey_b, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Avercamp winter atmosphere pass complete.")

    # Session 172 — random improvement: diagonal_light_gradient_pass
    # Diagonal linear coordinate warm/cool dual-ramp — SIXTY-SIXTH DISTINCT MODE.

    def diagonal_light_gradient_pass(
        self,
        angle_deg: float = 45.0,
        warm_r: float = 0.045,
        warm_g: float = 0.018,
        cool_b: float = 0.040,
        cool_r_reduce: float = 0.018,
        luma_lo: float = 0.08,
        luma_hi: float = 0.92,
        gamma: float = 1.4,
        opacity: float = 0.45,
    ) -> None:
        """Diagonal linear coordinate warm/cool dual-ramp — SIXTY-SIXTH DISTINCT MODE.

        Applies a warm-to-cool chromatic gradient along an oblique diagonal
        axis across the canvas.  Pixels at the 'low-diagonal' end (toward the
        direction pointed to by angle_deg) receive a warm tint (R+G+); pixels
        at the 'high-diagonal' end receive a cool tint (B+R-).

        This is the SIXTY-SIXTH DISTINCT MODE: DIAGONAL LINEAR COORDINATE
        GATE — OBLIQUE RAKING-LIGHT WARM/COOL DUAL-RAMP.

        Unlike ALL prior directional gradient passes:
        - atmospheric_depth_gradient_pass (s152): vertical Y-axis only.
        - altdorfer_forest_atmosphere_pass (s169): three horizontal Y-bands.
        - melozzo_zenith_light_pass (s155): vertical overhead Z direction.
        - schalcken_candlelight_glow_pass (s165): radial from a single point.
        - chromatic_vignette_pass (s171): radial from canvas centre.
        None of these uses an oblique, freely-rotatable DIAGONAL LINEAR
        coordinate.  This pass is the FIRST to project canvas coordinates
        onto an arbitrary-angle axis and use the resulting scalar as a
        warm/cool dual-ramp gate — correctly simulating oblique raking light
        or warm/cool atmospheric gradients at any angle.

        Algorithm:

        (1) DIAGONAL COORDINATE PROJECTION:
            θ = angle_deg × π / 180
            For each pixel at (x_norm, y_norm) ∈ [0,1]²:
            diag = x_norm × cos(θ) + y_norm × sin(θ)
            Normalised to [0, 1]:
            diag_norm = (diag − diag_min) / (diag_max − diag_min + ε)

        (2) WARM RAMP (toward high-diag direction):
            warm_gate = diag_norm ^ gamma

        (3) COOL RAMP (toward low-diag direction):
            cool_gate = (1 − diag_norm) ^ gamma

        (4) LUMINANCE BELL GATE (protects extremes):
            luma_gate = ramp_lo × ramp_hi

        (5) CHROMATIC INJECTION:
            out_r += warm_r × warm_gate × luma_gate
            out_g += warm_g × warm_gate × luma_gate
            out_b += cool_b × cool_gate × luma_gate
            out_r -= cool_r_reduce × cool_gate × luma_gate

        Composite at opacity.

        SIXTY-SIXTH DISTINCT MODE: novel because it is the ONLY pass to
        use an oblique, freely-rotatable linear diagonal coordinate as the
        primary spatial gate.  All prior gradient passes use vertical Y-axis,
        horizontal X-axis, or radial distance.

        Args:
            angle_deg    : Diagonal axis angle in degrees (0=horizontal, 90=vertical,
                           45=top-left→bottom-right). Default 45.0.
            warm_r       : Warm R injection at high-diagonal end. Default 0.045.
            warm_g       : Warm G injection at high-diagonal end. Default 0.018.
            cool_b       : Cool B injection at low-diagonal end. Default 0.040.
            cool_r_reduce: R reduction at low-diagonal end. Default 0.018.
            luma_lo      : Lower luminance bound of bell gate. Default 0.08.
            luma_hi      : Upper luminance bound of bell gate. Default 0.92.
            gamma        : Power curve for ramp shaping. Default 1.4.
            opacity      : Composite weight (0 = no-op). Default 0.45.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── Step 1: Diagonal coordinate projection ────────────────────────────
        theta = float(angle_deg) * _np.pi / 180.0
        cos_t = _np.cos(theta)
        sin_t = _np.sin(theta)

        xs = _np.linspace(0.0, 1.0, W, dtype=_np.float32)
        ys = _np.linspace(0.0, 1.0, H, dtype=_np.float32)
        xg, yg = _np.meshgrid(xs, ys)
        diag = xg * cos_t + yg * sin_t

        d_min = diag.min()
        d_max = diag.max()
        diag_norm = (diag - d_min) / (d_max - d_min + 1e-6)

        # ── Step 2: Warm ramp (high-diag end) ────────────────────────────────
        gam = float(gamma)
        warm_gate = diag_norm ** gam

        # ── Step 3: Cool ramp (low-diag end) ─────────────────────────────────
        cool_gate = (1.0 - diag_norm) ** gam

        # ── Step 4: Luminance bell gate ───────────────────────────────────────
        lo, hi = float(luma_lo), float(luma_hi)
        rng = hi - lo + 1e-6
        luma_gate = (
            _np.clip((luma - lo) / rng, 0.0, 1.0)
            * _np.clip((hi - luma) / rng, 0.0, 1.0)
        )

        # ── Step 5: Chromatic injection ───────────────────────────────────────
        wg = warm_gate * luma_gate
        cg = cool_gate * luma_gate
        out_r = _np.clip(r0 + float(warm_r) * wg - float(cool_r_reduce) * cg, 0.0, 1.0)
        out_g = _np.clip(g0 + float(warm_g) * wg, 0.0, 1.0)
        out_b = _np.clip(b0 + float(cool_b) * cg, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Diagonal light gradient pass complete.")

    # Session 173 — new artist: Jan van Huysum (1682–1749)
    # Dutch Golden Age floral still life — DUTCH_FLORAL_STILL_LIFE
    # huysum_crystalline_petal_pass — SIXTY-SEVENTH DISTINCT MODE.

    def huysum_crystalline_petal_pass(
        self,
        variance_sigma: float = 4.0,
        chroma_boost: float = 0.55,
        luma_lo: float = 0.12,
        luma_hi: float = 0.90,
        smooth_gamma: float = 1.8,
        opacity: float = 0.60,
    ) -> None:
        """Inverse-variance chroma crystallization — SIXTY-SEVENTH DISTINCT MODE.

        Implements Jan van Huysum's signature technique of maximum chroma purity
        in smooth, flat petal zones.  Where the Carpaccio pass (session 128)
        amplifies detail in HIGH-variance zones, this pass is the exact inverse:
        it gates chroma amplification on LOW-variance (smooth/flat) zones,
        making colour most saturated and most jewel-like precisely where the
        surface is smoothest.

        This is the SIXTY-SEVENTH DISTINCT MODE: INVERSE-VARIANCE CHROMA
        CRYSTALLIZATION.

        Unlike ALL prior variance-based passes:
        - Session 128 Carpaccio: std_norm → detail_mask = smoothed(std_norm);
          amplifies LOCAL CONTRAST in HIGH-variance zones (textured areas).
        - This pass builds smooth_gate = clip(1 − std_norm/threshold, 0, 1)^gamma
          which is MAXIMUM at ZERO local variance (perfect smooth flat zones)
          and zero wherever texture/edges/detail appear.  NOVEL: FIRST pass to
          use INVERSE of local luminance variance as chroma amplification gate.

        Algorithm:

        (1) LOCAL VARIANCE MAP:
            Compute E[luma²] and E[luma]² via Gaussian expectation at
            variance_sigma; var = max(E[luma²] − E[luma]², 0);
            std_norm = sqrt(var) / max(sqrt(var))

        (2) SMOOTH ZONE GATE:
            smooth_gate = clip(1 − std_norm, 0, 1)^smooth_gamma
            This is 1.0 at perfectly flat zones and 0.0 at high-texture zones.

        (3) LUMINANCE GATE (protect extremes):
            luma_gate = bell over [luma_lo, luma_hi]

        (4) CHROMA CRYSTALLIZATION:
            n = (R + G + B) / 3   (achromatic mean)
            delta_c = channel − n  (chromatic deviation from neutral)
            out_channel = channel + delta_c × chroma_boost × smooth_gate × luma_gate

        (5) COMPOSITE at opacity.

        SIXTY-SEVENTH DISTINCT MODE: novel because it is the ONLY pass to gate
        chroma amplification on the INVERSE of local luminance variance — all
        prior variance-using passes (Carpaccio s128) amplify effects in
        HIGH-variance / textured zones.  This pass concentrates colour richness
        where the surface is smoothest.

        Args:
            variance_sigma : Gaussian sigma for local variance estimation. Default 4.0.
            chroma_boost   : Chroma amplification multiplier in smooth zones. Default 0.55.
            luma_lo        : Lower luminance bound of protection gate. Default 0.12.
            luma_hi        : Upper luminance bound of protection gate. Default 0.90.
            smooth_gamma   : Power-curve shaping of smooth_gate. Default 1.8.
            opacity        : Composite weight (0 = no-op). Default 0.60.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        # ── Step 1: Local variance map (Gaussian expectation method) ──────────
        sigma = float(variance_sigma)
        luma_sq = luma * luma
        e_sq  = _gf(luma_sq, sigma=sigma)
        e_lum = _gf(luma,    sigma=sigma)
        var   = _np.maximum(e_sq - e_lum * e_lum, 0.0)
        std   = _np.sqrt(var)
        std_max = std.max()
        std_norm = (std / std_max) if std_max > 1e-9 else _np.zeros_like(std)

        # ── Step 2: Smooth zone gate (INVERSE of variance) ───────────────────
        smooth_gate = _np.clip(1.0 - std_norm, 0.0, 1.0) ** float(smooth_gamma)

        # ── Step 3: Luminance protection gate (bell over [luma_lo, luma_hi]) ─
        lo, hi = float(luma_lo), float(luma_hi)
        rng = hi - lo + 1e-6
        lo_ramp = _np.clip((luma - lo) / rng, 0.0, 1.0)
        hi_ramp = _np.clip((hi - luma) / rng, 0.0, 1.0)
        luma_gate = lo_ramp * hi_ramp

        gate = smooth_gate * luma_gate

        # ── Step 4: Chroma crystallization via neutral-mean decomposition ─────
        boost = float(chroma_boost)
        n = (r0 + g0 + b0) / 3.0
        out_r = _np.clip(r0 + (r0 - n) * boost * gate, 0.0, 1.0)
        out_g = _np.clip(g0 + (g0 - n) * boost * gate, 0.0, 1.0)
        out_b = _np.clip(b0 + (b0 - n) * boost * gate, 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Huysum crystalline petal pass complete.")

    # Session 173 — random improvement: frequency_domain_acuity_pass
    # FFT-domain spatial frequency band amplification — SIXTY-EIGHTH DISTINCT MODE.

    def frequency_domain_acuity_pass(
        self,
        freq_lo: float = 0.08,
        freq_hi: float = 0.35,
        boost: float = 1.40,
        luma_lo: float = 0.10,
        luma_hi: float = 0.92,
        opacity: float = 0.45,
    ) -> None:
        """FFT-domain spatial frequency band amplification — SIXTY-EIGHTH DISTINCT MODE.

        Boosts mid-spatial-frequency acuity by operating in the 2D Fourier
        frequency domain.  Applies a radial band-pass amplification ring in
        frequency space, boosting spatial frequencies in the range
        [freq_lo, freq_hi] (as fractions of the Nyquist frequency) by a
        factor of `boost`, while leaving DC and very high frequencies
        untouched.  The resulting luminance residual is added back to the
        original at a controlled opacity.

        This is the SIXTY-EIGHTH DISTINCT MODE: FFT-DOMAIN SPATIAL FREQUENCY
        BAND AMPLIFICATION.

        Unlike ALL prior detail/frequency passes:
        - Session 124 Stanzione: Laplacian pyramid (spatial domain multi-scale
          decomposition — gaussian coarse/fine) — pure spatial domain.
        - Session 128 Carpaccio: local variance std-map (spatial domain
          sliding Gaussian expectation) — pure spatial domain.
        - Session 151 ter Brugghen: horizontal Sobel (spatial domain
          first-derivative convolution) — pure spatial domain.
        - Session 163 Schedoni specular: USM (unsharp mask = original minus
          gaussian blur, re-added) — spatial domain approximation to
          frequency sharpening.
        - This pass applies DISCRETE FOURIER TRANSFORM to the luminance
          channel, selects a radial frequency band in 2D frequency space,
          amplifies those specific spatial frequency components, and applies
          INVERSE FFT.  NOVEL: FIRST pass to use the frequency domain
          (numpy FFT) for explicit spatial frequency band selection — all
          prior frequency-related passes use spatial domain convolution
          approximations.

        Algorithm:

        (1) Extract luminance channel; compute 2D FFT (numpy.fft.fft2).
        (2) Compute radial frequency map: for each frequency bin (u, v),
            freq_norm = sqrt((u/H)² + (v/W)²) / sqrt(0.5) ∈ [0, 1]
            where 1.0 = Nyquist (maximum spatial frequency).
        (3) Build band-pass gain: a smooth sigmoid ring from freq_lo to
            freq_hi with gain = `boost` inside the band, 1.0 outside.
        (4) Multiply spectrum by gain map; apply IFFT; take real part.
        (5) Compute luma residual = acuity_luma − original_luma.
        (6) Gate residual by luma_gate (bell over [luma_lo, luma_hi]) to
            protect pure highlights and deep shadows.
        (7) Apply residual to all channels uniformly; composite at opacity.

        SIXTY-EIGHTH DISTINCT MODE: novel because it is the ONLY pass to use
        the 2D Fourier transform and frequency-domain filtering.  All prior
        sharpening/detail passes (USM, Laplacian, Sobel) are equivalent to
        various spatial-domain approximations of frequency operations; this
        pass performs the exact frequency-domain computation directly.

        Args:
            freq_lo  : Lower bound of amplified frequency band (fraction of Nyquist). Default 0.08.
            freq_hi  : Upper bound of amplified frequency band (fraction of Nyquist). Default 0.35.
            boost    : Gain factor applied to frequencies within the band. Default 1.40.
            luma_lo  : Lower luminance bound for residual gate. Default 0.10.
            luma_hi  : Upper luminance bound for residual gate. Default 0.92.
            opacity  : Composite weight for the acuity residual (0 = no-op). Default 0.45.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float64)

        # ── Step 1: 2D FFT of luminance ───────────────────────────────────────
        fft_luma = _np.fft.fft2(luma)
        fft_shift = _np.fft.fftshift(fft_luma)

        # ── Step 2: Radial frequency map in [0, 1] normalised to Nyquist ──────
        cy, cx = H // 2, W // 2
        ys = (_np.arange(H) - cy) / (H / 2.0)
        xs = (_np.arange(W) - cx) / (W / 2.0)
        xx, yy = _np.meshgrid(xs, ys)
        freq_norm = _np.sqrt(xx ** 2 + yy ** 2).astype(_np.float32)
        # Clamp to [0, 1] — corners of FFT exceed Nyquist in 2D
        freq_norm = _np.clip(freq_norm, 0.0, 1.0)

        # ── Step 3: Smooth band-pass gain ────────────────────────────────────
        lo, hi = float(freq_lo), float(freq_hi)
        band_width = (hi - lo)
        transition = max(band_width * 0.25, 0.01)
        # Sigmoid ramps: smoothly enter band at freq_lo, exit at freq_hi
        ramp_in  = _np.clip((freq_norm - lo + transition) / (2.0 * transition), 0.0, 1.0)
        ramp_out = _np.clip((hi + transition - freq_norm) / (2.0 * transition), 0.0, 1.0)
        band_gate = ramp_in * ramp_out  # 1.0 inside band, 0.0 outside
        gain_map = 1.0 + (float(boost) - 1.0) * band_gate  # boost inside, 1.0 outside

        # ── Step 4: Amplify spectrum and inverse FFT ─────────────────────────
        fft_boosted = fft_shift * gain_map.astype(_np.float64)
        fft_unshift = _np.fft.ifftshift(fft_boosted)
        luma_acuity = _np.real(_np.fft.ifft2(fft_unshift)).astype(_np.float32)
        luma_acuity = _np.clip(luma_acuity, 0.0, 1.0)

        # ── Step 5 & 6: Residual + luminance gate ────────────────────────────
        luma_f32 = luma.astype(_np.float32)
        residual = luma_acuity - luma_f32

        lo_l, hi_l = float(luma_lo), float(luma_hi)
        rng_l = hi_l - lo_l + 1e-6
        lo_ramp = _np.clip((luma_f32 - lo_l) / rng_l, 0.0, 1.0)
        hi_ramp = _np.clip((hi_l - luma_f32) / rng_l, 0.0, 1.0)
        luma_gate = lo_ramp * hi_ramp

        gated_residual = residual * luma_gate

        # ── Step 7: Apply residual to all channels; composite at opacity ──────
        out_r = _np.clip(r0 + gated_residual, 0.0, 1.0)
        out_g = _np.clip(g0 + gated_residual, 0.0, 1.0)
        out_b = _np.clip(b0 + gated_residual, 0.0, 1.0)

        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Frequency domain acuity pass complete.")

    # ── Session 174 passes ────────────────────────────────────────────────────

    def claesz_tonal_monochrome_pass(
        self,
        desat: float = 0.72,
        warm_r: float = 0.018,
        warm_g: float = 0.010,
        warm_b_reduce: float = 0.014,
        luma_lo: float = 0.08,
        luma_hi: float = 0.88,
        opacity: float = 0.55,
    ) -> None:
        """Pull the entire canvas toward Pieter Claesz's warm silver-gray tonal envelope.

        Inspired by Pieter Claesz (c. 1597–1660), master of the Dutch ontbijt
        (breakfast piece) and monochrome banketje.  His radical pictorial experiment:
        suppress almost all chromatic variation in favour of a near-monochromatic
        warm silver-gray palette, distinguishing objects purely through tonal nuance
        and surface finish rather than colour difference.

        Algorithm:
        (1) Compute neutral mean: n = (R+G+B)/3 per pixel.
        (2) Compute chromatic deviation: delta_c = channel − n.
        (3) Reduce delta by desaturation factor: out_c = n + delta_c × (1 − desat).
            With desat=1.0 the image becomes fully monochrome; at desat=0.72 roughly
            72% of the chromatic deviation is removed, leaving the characteristic
            near-neutral but faintly warm tonality.
        (4) Inject warm silver bias (gated by luminance bell):
            luma_gate = smooth ramp up from luma_lo, down from luma_hi
            out_r += warm_r × luma_gate
            out_g += warm_g × luma_gate
            out_b −= warm_b_reduce × luma_gate
            This adds a very subtle warm-gray silver tone in midtones, leaving
            pure blacks and pure whites unaffected.
        (5) Composite at opacity.

        SIXTY-NINTH DISTINCT MODE: FIRST pass to combine (a) global hue desaturation
        toward neutral (regardless of hue — not targeting specific ranges) AND (b)
        a luminance-gated warm silver injection in a single unified tonal pass.
        All prior desaturation passes (avercamp_winter_atmosphere_pass, etc.) target
        specific luminance ranges or use target-blending toward a fixed colour; this
        pass desaturates globally via neutral-mean decomposition then re-injects
        a spectrally neutral warm bias.

        Args:
            desat         : Fraction of chromatic deviation to remove. 0=unchanged, 1=monochrome.
            warm_r        : Warm red injection in midtones. Default 0.018.
            warm_g        : Warm green injection in midtones. Default 0.010.
            warm_b_reduce : Blue reduction in midtones (adds warmth). Default 0.014.
            luma_lo       : Lower luminance bound for warm injection gate. Default 0.08.
            luma_hi       : Upper luminance bound for warm injection gate. Default 0.88.
            opacity       : Composite weight (0 = no-op). Default 0.55.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # Cairo BGRA: channel 0=B, 1=G, 2=R, 3=A
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1 & 2: Neutral mean and chromatic deviation ──────────────────
        neutral = (r0 + g0 + b0) / 3.0
        dr = r0 - neutral
        dg = g0 - neutral
        db = b0 - neutral

        # ── Step 3: Desaturate toward neutral ─────────────────────────────────
        factor = 1.0 - float(desat)
        out_r = neutral + dr * factor
        out_g = neutral + dg * factor
        out_b = neutral + db * factor

        # ── Step 4: Luminance-gated warm silver injection ─────────────────────
        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0
        lo_l, hi_l = float(luma_lo), float(luma_hi)
        rng_l = hi_l - lo_l + 1e-6
        lo_ramp = _np.clip((luma - lo_l) / rng_l, 0.0, 1.0)
        hi_ramp = _np.clip((hi_l - luma) / rng_l, 0.0, 1.0)
        luma_gate = lo_ramp * hi_ramp

        out_r = out_r + float(warm_r) * luma_gate
        out_g = out_g + float(warm_g) * luma_gate
        out_b = out_b - float(warm_b_reduce) * luma_gate

        # ── Step 5: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Claesz tonal monochrome pass complete.")

    def figure_contour_atmosphere_pass(
        self,
        blur_sigma: float = 4.0,
        bleed_strength: float = 0.22,
        edge_threshold: float = 0.06,
        luma_lo: float = 0.05,
        luma_hi: float = 0.95,
        opacity: float = 0.40,
    ) -> None:
        """Bidirectional sfumato dissolution at figure-background contour boundary.

        Improves the pipeline's core sfumato capability by creating a true
        bidirectional atmospheric blend at the silhouette boundary between figure
        and background.  The key insight is that Leonardo's sfumato dissolves not
        only figure edges into background but also bleeds background atmosphere
        INTO the figure edge — a two-way exchange of colour at the boundary that
        makes the figure appear to emerge from the atmosphere rather than sit in
        front of it.

        Algorithm:
        (1) Compute luminance from the current canvas.
        (2) Estimate edge map via Sobel gradient of luma; normalise to [0, 1].
        (3) Build edge gate: edge_gate = clip((grad_norm − edge_threshold) / rng, 0,1).
            Active only where the gradient exceeds the threshold — at contour
            boundaries (figure silhouette, hair edge, veil boundary, etc.).
        (4) Gaussian blur the canvas at blur_sigma to obtain a 'background atmosphere'
            estimate: the local neighbourhood colour averaged over the blur radius.
        (5) Bleed blurred colour TOWARD current colour: at each edge pixel, blend
            a fraction (bleed_strength × edge_gate) of the blurred neighbourhood
            into the current pixel — background atmosphere bleeds inward along edges.
        (6) Gate by luminance bell (luma_lo, luma_hi) to avoid contaminating pure
            whites or deep shadows.
        (7) Composite at opacity.

        SEVENTIETH DISTINCT MODE: FIRST pass to implement BIDIRECTIONAL figure-
        background sfumato dissolution by targeting the gradient-magnitude edge
        map specifically, creating a thin atmospheric aureole at every contour
        boundary.  Prior sfumato passes (sfumato_veil_pass, edge_sfumato_dissolution_pass)
        blur the entire image or apply global atmospheric veils; this pass isolates
        only pixels AT contour boundaries and creates a local two-way colour exchange
        there.  The result is that figure edges dissolve into the surrounding
        atmosphere in a precise and spatially specific way rather than globally.

        Args:
            blur_sigma      : Gaussian blur radius for neighbourhood atmosphere estimate. Default 4.0.
            bleed_strength  : Maximum fraction of blurred colour to blend at edge. Default 0.22.
            edge_threshold  : Minimum normalised gradient to qualify as a contour edge. Default 0.06.
            luma_lo         : Lower luminance gate bound. Default 0.05.
            luma_hi         : Upper luminance gate bound. Default 0.95.
            opacity         : Composite weight (0 = no-op). Default 0.40.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1 & 2: Luminance and edge map ───────────────────────────────
        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float64)
        sx = _sobel(luma, axis=1)
        sy = _sobel(luma, axis=0)
        grad_mag = _np.sqrt(sx ** 2 + sy ** 2).astype(_np.float32)
        max_grad = float(grad_mag.max())
        if max_grad < 1e-6:
            return
        grad_norm = grad_mag / max_grad

        # ── Step 3: Edge gate ─────────────────────────────────────────────────
        thresh = float(edge_threshold)
        rng_e = max(1.0 - thresh, 1e-6)
        edge_gate = _np.clip((grad_norm - thresh) / rng_e, 0.0, 1.0).astype(_np.float32)

        # ── Step 4: Gaussian blur — neighbourhood atmosphere estimate ─────────
        sigma = float(blur_sigma)
        blurred_r = _gf(r0.astype(_np.float64), sigma=sigma).astype(_np.float32)
        blurred_g = _gf(g0.astype(_np.float64), sigma=sigma).astype(_np.float32)
        blurred_b = _gf(b0.astype(_np.float64), sigma=sigma).astype(_np.float32)

        # ── Step 5 & 6: Bleed blurred atmosphere inward at edges + luma gate ──
        luma_f32 = luma.astype(_np.float32)
        lo_l, hi_l = float(luma_lo), float(luma_hi)
        rng_l = hi_l - lo_l + 1e-6
        lo_ramp = _np.clip((luma_f32 - lo_l) / rng_l, 0.0, 1.0)
        hi_ramp = _np.clip((hi_l - luma_f32) / rng_l, 0.0, 1.0)
        luma_gate = lo_ramp * hi_ramp

        blend_alpha = edge_gate * luma_gate * float(bleed_strength)
        blend_alpha = _np.clip(blend_alpha, 0.0, 1.0)

        # Bidirectional blend: current pixel toward its blurred neighbourhood
        atm_r = r0 * (1.0 - blend_alpha) + blurred_r * blend_alpha
        atm_g = g0 * (1.0 - blend_alpha) + blurred_g * blend_alpha
        atm_b = b0 * (1.0 - blend_alpha) + blurred_b * blend_alpha

        # ── Step 7: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + atm_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + atm_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + atm_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()

    # ─────────────────────────────────────────────────────────────────────────
    # Pass 84 — Benozzo Gozzoli pageant palette snap pass
    # ─────────────────────────────────────────────────────────────────────────

    def benozzo_gozzoli_pageant_pass(
            self,
            snap_strength: float = 0.12,
            luma_lo:       float = 0.18,
            luma_hi:       float = 0.88,
            opacity:       float = 0.32):
        """
        Benozzo Gozzoli pageant palette snap pass — session 182.

        FLORENTINE PAGEANT PALETTE SNAPPING:

        Benozzo Gozzoli's Magi Chapel frescoes (1459–1461) are defined by a
        zone-pure jewel palette: lapis lazuli blue, vermilion red, malachite
        green, gold ochre, warm gesso, and pure near-black outline.  Unlike
        painters who modulated freely, Benozzo maintained CHROMATIC ZONE PURITY —
        each drapery area keyed to a single vivid pigment.

        For each pixel (gated by luma range [luma_lo, luma_hi] via symmetric
        tent gate), this pass finds the nearest color in Benozzo's canonical
        jewel palette (Euclidean distance in RGB space), then softly attracts
        the pixel toward that palette color by snap_strength:

          out_rgb = rgb + (nearest_palette_color − rgb) × snap_strength × gate

        The tent gate reaches maximum weight at luma midpoint, falling to zero at
        luma_lo and luma_hi, so extreme darks and specular highlights are unaffected.

        NOVEL: EIGHTY-FOURTH DISTINCT MODE.  FIRST pass to use NEAREST-PALETTE
        SOFT-SNAP as the per-pixel correction mechanism — chromatic adjustment
        driven entirely by palette proximity rather than channel thresholds,
        gradient magnitude, frequency bands, or dominance gates.  Pixels already
        near a palette color are barely moved; off-palette pixels are gently drawn
        toward the nearest jewel color in a distance-proportional manner.  No
        prior pass uses palette distance as the driving metric for per-pixel
        chromatic correction.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        # Benozzo's canonical Magi Chapel jewel palette (R, G, B in [0, 1])
        palette = _np.array([
            [0.18, 0.28, 0.72],   # lapis lazuli blue
            [0.72, 0.14, 0.10],   # vermilion red
            [0.12, 0.48, 0.24],   # malachite green
            [0.72, 0.58, 0.18],   # gold ochre
            [0.86, 0.82, 0.72],   # gesso warm white
            [0.10, 0.08, 0.06],   # near-black outline
            [0.78, 0.52, 0.36],   # warm flesh ivory
            [0.48, 0.36, 0.60],   # purple-violet robe shadow
        ], dtype=_np.float32)

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        # Symmetric tent gate peaking at midpoint of [luma_lo, luma_hi]
        lo, hi = float(luma_lo), float(luma_hi)
        rise = _np.clip((luma - lo) / (hi - lo + 1e-6), 0.0, 1.0)
        fall = _np.clip((hi - luma) / (hi - lo + 1e-6), 0.0, 1.0)
        gate = _np.clip(rise * fall * 4.0, 0.0, 1.0)

        # Flatten pixels for vectorised nearest-palette lookup
        rgb_flat = _np.stack([r0.ravel(), g0.ravel(), b0.ravel()], axis=1)  # (H*W, 3)
        diffs    = rgb_flat[:, None, :] - palette[None, :, :]                # (H*W, N, 3)
        dists    = _np.sum(diffs * diffs, axis=2)                            # (H*W, N)
        nearest_rgb = palette[_np.argmin(dists, axis=1)]                     # (H*W, 3)

        nearest_r = nearest_rgb[:, 0].reshape(H, W)
        nearest_g = nearest_rgb[:, 1].reshape(H, W)
        nearest_b = nearest_rgb[:, 2].reshape(H, W)

        snap = float(snap_strength) * gate

        out_r = _np.clip(r0 + (nearest_r - r0) * snap, 0.0, 1.0)
        out_g = _np.clip(g0 + (nearest_g - g0) * snap, 0.0, 1.0)
        out_b = _np.clip(b0 + (nearest_b - b0) * snap, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Benozzo Gozzoli pageant palette snap pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Pass 85 — Tonal bounded warmth pass
    # ─────────────────────────────────────────────────────────────────────────

    def tonal_bounded_warmth_pass(
            self,
            mid_dark_lo:  float = 0.18,
            mid_dark_hi:  float = 0.44,
            warm_r:       float = 0.030,
            warm_g:       float = 0.012,
            warm_b:       float = -0.006,
            void_hi:      float = 0.15,
            void_cool_b:  float = 0.010,
            void_cool_r:  float = -0.008,
            opacity:      float = 0.28):
        """
        Tonal bounded warmth pass — session 182.

        IMPRIMATURA GROUND RECOVERY — TONAL-BOUNDED WARM BAND:

        Fra Bartolommeo built on a warm chestnut-amber imprimatura visible
        through thin paint layers in mid-dark transitions.  Two zones:

          MID-DARK ZONE [mid_dark_lo, mid_dark_hi]: inject warm ground recovery
          (R+warm_r, G+warm_g, B+warm_b) weighted by a symmetric tent gate that
          peaks at the zone centre (max weight 1.0, zero at boundaries).
          Replicates the warm imprimatura glow visible between the deep void and
          the opaque lit passages — the three-zone luminance signature of Fra
          Bartolommeo's toned-ground chiaroscuro.

          NEAR-VOID ZONE (luma < void_hi): slight cool push (B+void_cool_b,
          R+void_cool_r) deepens the darkest shadows toward cool umber-violet,
          increasing tonal separation from the warm mid-dark band above.

        NOVEL: EIGHTY-FIFTH DISTINCT MODE.  FIRST pass to use a TONAL BAND
        (isolated by a symmetric tent gate spanning mid_dark_lo–mid_dark_hi) for
        SELECTIVE IMPRIMATURA RECOVERY with OPPOSITE treatment at the near-void
        floor.  Unlike shadow_color_temperature_pass (which applies uniformly
        below a single threshold), this creates a warm BAND visible only in the
        mid-shadow zone, replicating the three-stratum luminance structure of
        Renaissance toned-ground panel painting: cool void → warm mid-dark →
        warm lit.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        lo = float(mid_dark_lo)
        hi = float(mid_dark_hi)

        # Symmetric tent gate: rises from 0 at lo, peaks at (lo+hi)/2, falls to 0 at hi
        rise = _np.clip((luma - lo) / (hi - lo + 1e-6), 0.0, 1.0)
        fall = _np.clip((hi - luma) / (hi - lo + 1e-6), 0.0, 1.0)
        mid_gate = _np.clip(rise * fall * 4.0, 0.0, 1.0)

        out_r = _np.clip(r0 + mid_gate * float(warm_r), 0.0, 1.0)
        out_g = _np.clip(g0 + mid_gate * float(warm_g), 0.0, 1.0)
        out_b = _np.clip(b0 + mid_gate * float(warm_b), 0.0, 1.0)

        # Near-void cool push for tonal separation
        void_gate = _np.clip((float(void_hi) - luma) / (float(void_hi) + 1e-6), 0.0, 1.0)
        out_r = _np.clip(out_r + void_gate * float(void_cool_r), 0.0, 1.0)
        out_b = _np.clip(out_b + void_gate * float(void_cool_b), 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Tonal bounded warmth pass complete.")

    def signorelli_sculptural_contour_pass(
        self,
        cool_strength: float = 0.28,
        shadow_thresh: float = 0.45,
        edge_threshold: float = 0.08,
        contour_lift: float = 0.20,
        opacity: float = 0.55,
    ) -> None:
        """Hard sculptural contour reinforcement with cool metallic shadow flesh.

        Implements the defining visual qualities of Luca Signorelli's figure painting:
        (1) cool, metallic shadow flesh — the gray-silver pewter quality of shadow zones
        that makes his figures look carved from stone; and (2) hard, crisp contour
        reinforcement — the iron-certain disegno that is the polar opposite of Leonardo's
        sfumato.  Both effects are computed simultaneously from the same gradient and
        luminance maps.

        Algorithm:
        (1) Compute luminance.
        (2) Compute Sobel gradient magnitude; normalise to [0, 1].
        (3) Build edge_gate: active at high-gradient contour boundaries.
        (4) Build shadow_gate: active in low-luminance (shadow) zones.
        (5) Cool metallic shadow shift — in shadow zones away from edges:
            For each pixel, compute neutral mean n = (R+G+B)/3.
            cool_delta = cool_strength × shadow_gate × (1 − edge_gate) × luma_bell.
            out_R = R − cool_delta × (R − n)  [pull R toward neutral = desaturate warmth]
            out_B = B + cool_delta × 0.18      [inject slight blue-silver lift]
            This creates the pewter-gray flesh shadow characteristic of Signorelli.
        (6) Contour contrast lift — at contour pixels (edge_gate high):
            Compute local_mean_luma in a 5×5 neighbourhood.
            Push luminance away from local mean: bright pixels get brighter, dark get darker.
            lift_amount = contour_lift × edge_gate × luma_bell.
            luma_push = (luma − local_mean) × lift_amount.
            Add luma_push to all three channels uniformly (preserves hue).
        (7) Composite at opacity.

        SEVENTY-FIRST DISTINCT MODE: FIRST pass to combine (a) luminance-gated cool
        metallic SHADOW shift in flesh zones AND (b) LOCAL-CONTRAST contour SHARPENING
        specifically at gradient-detected boundaries — creating the uniquely Signorellian
        sculptural quality of hard outlines combined with cool metallic shadow flesh.
        Prior cool-shift passes (DUTCH_CLASSICAL_LATE_BAROQUE's alabaster-cool in
        werff_alabaster_pearl_pass) apply globally or target highlights; prior contour
        passes (figure_contour_atmosphere_pass s174) DISSOLVE edges bidirectionally
        (sfumato).  This pass does the INVERSE: REINFORCES and SHARPENS contours while
        simultaneously cooling the shadow zones — the anti-sfumato.

        Args:
            cool_strength   : Strength of cool metallic shift in shadow flesh. Default 0.28.
            shadow_thresh   : Luminance threshold below which shadow gate is active. Default 0.45.
            edge_threshold  : Minimum normalised gradient to qualify as a contour edge. Default 0.08.
            contour_lift    : Maximum local contrast lift at contour boundaries. Default 0.20.
            opacity         : Composite weight (0 = no-op). Default 0.55.
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel, uniform_filter as _uf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1 & 2: Luminance and Sobel gradient edge map ────────────────
        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float64)
        sx = _sobel(luma, axis=1)
        sy = _sobel(luma, axis=0)
        grad_mag = _np.sqrt(sx ** 2 + sy ** 2).astype(_np.float32)
        max_grad = float(grad_mag.max())
        if max_grad < 1e-6:
            grad_norm = _np.zeros_like(grad_mag)
        else:
            grad_norm = grad_mag / max_grad

        # ── Step 3: Edge gate ─────────────────────────────────────────────────
        thresh_e = float(edge_threshold)
        rng_e = max(1.0 - thresh_e, 1e-6)
        edge_gate = _np.clip((grad_norm - thresh_e) / rng_e, 0.0, 1.0).astype(_np.float32)

        # ── Step 4: Shadow gate ───────────────────────────────────────────────
        luma_f32 = luma.astype(_np.float32)
        s_thresh = float(shadow_thresh)
        shadow_gate = _np.clip((s_thresh - luma_f32) / max(s_thresh, 1e-6), 0.0, 1.0)

        # Luminance bell: protect pure whites and near-blacks from modification
        luma_bell = _np.clip(luma_f32 / 0.06, 0.0, 1.0) * _np.clip((1.0 - luma_f32) / 0.06, 0.0, 1.0)
        luma_bell = _np.clip(luma_bell, 0.0, 1.0)

        # ── Step 5: Cool metallic shadow shift ───────────────────────────────
        # Active in shadow zones (shadow_gate high), inactive at hard edges (edge_gate low)
        cool_field = float(cool_strength) * shadow_gate * (1.0 - edge_gate) * luma_bell
        neutral = (r0 + g0 + b0) / 3.0
        out_r = r0 - cool_field * (r0 - neutral)           # pull R toward neutral
        out_g = g0.copy()                                    # G unchanged
        out_b = _np.clip(b0 + cool_field * 0.18, 0.0, 1.0) # inject slight blue-silver lift

        # ── Step 6: Contour contrast lift ────────────────────────────────────
        # At contour boundaries: amplify local contrast (hard disegno sharpening)
        local_mean = _uf(luma_f32, size=5).astype(_np.float32)
        luma_deviation = luma_f32 - local_mean          # positive = brighter than neighbourhood
        lift_amount = float(contour_lift) * edge_gate * luma_bell
        luma_push = luma_deviation * lift_amount        # push luma away from local mean
        out_r = _np.clip(out_r + luma_push, 0.0, 1.0)
        out_g = _np.clip(out_g + luma_push, 0.0, 1.0)
        out_b = _np.clip(out_b + luma_push, 0.0, 1.0)

        # ── Step 7: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Signorelli sculptural contour pass complete.")

    def skin_subsurface_scatter_pass(
        self,
        scatter_sigma: float = 6.0,
        scatter_strength: float = 0.18,
        amber_r: float = 0.06,
        amber_b: float = -0.04,
        opacity: float = 0.45,
    ) -> None:
        """Simulates physical subsurface light scattering in skin tissue.

        In oil portraits by Leonardo, Raphael, Titian, and other masters, painted skin
        has a warm luminous quality that distinguishes it from cloth, stone, or metal.
        This quality — the sense that the skin is translucent, that light penetrates the
        surface and re-emerges from within — is produced physically by subsurface
        scattering: photons enter the skin, scatter through the dermis and epidermis
        (absorbing blue-green wavelengths preferentially), and exit at a spatially offset
        position with a warm amber tint.  This pass simulates that optical process.

        Algorithm:
        (1) Build a skin detection mask in RGB space.  Skin pixels are warm (R > G > B
            approximately), mid-range in luminance, and have moderate saturation.
            skin_score = warm_score × mid_luma_gate where:
              warm_score = clip((R − G) / warm_rng, 0,1) × clip((G − B) / green_rng, 0,1)
              mid_luma_gate = bell curve centred at 0.60, active 0.25–0.90
        (2) Gaussian blur skin_score × each channel at scatter_sigma to create the
            spatially diffused 'scatter field' — how the scattered warm light spreads.
            scatter_R = gaussian(skin_score × R, σ)
            scatter_G = gaussian(skin_score × G, σ)
            scatter_B = gaussian(skin_score × B, σ)
            scatter_norm = gaussian(skin_score, σ) + ε  [normaliser]
        (3) Compute normalised scatter colour at each pixel:
            sc_R = scatter_R / scatter_norm  (local blurred skin colour)
            sc_G = scatter_G / scatter_norm
            sc_B = scatter_B / scatter_norm
        (4) Apply amber shift to scatter colour — models preferential absorption of
            blue-green in dermis:
            sc_R += amber_r × scatter_norm_normalised
            sc_B += amber_b × scatter_norm_normalised  (reduce blue)
        (5) Inject scatter glow: at skin pixels, blend scatter colour toward current:
            inject = scatter_strength × skin_score
            out_R = R × (1 − inject) + sc_R × inject
            ... same for G, B.
        (6) Composite at opacity.

        SEVENTY-SECOND DISTINCT MODE: FIRST pass to use a SPATIAL GAUSSIAN CONVOLUTION
        on hue-selected skin pixels to simulate physical subsurface photon diffusion —
        the mechanism by which light scatters through skin layers before re-emerging at a
        spatially offset position with warm amber tinting.  Prior warmth passes (Milanese
        warmth injection in giampietrino_honey_amber_highlight_pass, devotional luminism
        in ferrari_devotional_luminosity_pass, Schalcken saffron glow) apply STATIC
        colour temperature biases at individual pixels.  This pass instead SPATIALLY
        BLURS the warm skin signal and RE-INJECTS it, so the scatter glow correctly
        broadens and diffuses across the skin surface as it would in physically
        translucent tissue.  The spatial spread models the ~1–5 mm mean free path of
        photons in human skin.

        Args:
            scatter_sigma   : Gaussian blur radius for scatter field (px). Default 6.0.
            scatter_strength: Maximum injection fraction at detected skin pixels. Default 0.18.
            amber_r         : Amber warmth injection into scattered colour (R channel). Default 0.06.
            amber_b         : Blue reduction in scattered colour (B channel, negative = reduce). Default -0.04.
            opacity         : Composite weight (0 = no-op). Default 0.45.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Step 1: Skin detection mask ───────────────────────────────────────
        # Skin: warm (R > G > B), mid-tone luminance, moderate saturation
        warm_rng = 0.25
        green_rng = 0.15
        warm_score = (
            _np.clip((r0 - g0) / warm_rng, 0.0, 1.0) *
            _np.clip((g0 - b0) / green_rng, 0.0, 1.0)
        )
        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0)
        # Bell curve: peaks at luma=0.60, active from ~0.25 to ~0.90
        mid_luma_gate = (
            _np.clip((luma - 0.25) / 0.35, 0.0, 1.0) *
            _np.clip((0.90 - luma) / 0.30, 0.0, 1.0)
        ).astype(_np.float32)
        skin_score = (warm_score * mid_luma_gate).astype(_np.float32)

        # ── Step 2: Gaussian blur skin-weighted channels ──────────────────────
        sigma = float(scatter_sigma)
        scatter_r = _gf((skin_score * r0).astype(_np.float64), sigma=sigma).astype(_np.float32)
        scatter_g = _gf((skin_score * g0).astype(_np.float64), sigma=sigma).astype(_np.float32)
        scatter_b = _gf((skin_score * b0).astype(_np.float64), sigma=sigma).astype(_np.float32)
        scatter_norm = _gf(skin_score.astype(_np.float64), sigma=sigma).astype(_np.float32) + 1e-6

        # ── Step 3: Normalised scatter colour ─────────────────────────────────
        sc_r = scatter_r / scatter_norm
        sc_g = scatter_g / scatter_norm
        sc_b = scatter_b / scatter_norm

        # ── Step 4: Amber tinting of scatter colour ───────────────────────────
        # Normalise scatter_norm to [0,1] for gating the amber injection
        scatter_norm_n = _np.clip(scatter_norm / (scatter_norm.max() + 1e-6), 0.0, 1.0)
        sc_r = _np.clip(sc_r + float(amber_r) * scatter_norm_n, 0.0, 1.0)
        sc_b = _np.clip(sc_b + float(amber_b) * scatter_norm_n, 0.0, 1.0)

        # ── Step 5: Inject scatter glow at skin pixels ────────────────────────
        inject = _np.clip(float(scatter_strength) * skin_score, 0.0, 1.0)
        out_r = r0 * (1.0 - inject) + sc_r * inject
        out_g = g0 * (1.0 - inject) + sc_g * inject
        out_b = b0 * (1.0 - inject) + sc_b * inject

        # ── Step 6: Composite at opacity ──────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Skin subsurface scatter pass complete.")
        print("    Figure contour atmosphere pass complete.")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 176 — Marco d'Oggiono / Milanese Leonardesque Circle
    # ──────────────────────────────────────────────────────────────────────────

    def doggiono_leonardesque_warmth_pass(
        self,
        highlight_lo:      float = 0.60,
        ivory_r:           float = 0.022,
        ivory_g:           float = 0.014,
        ivory_b:           float = 0.003,
        shadow_hi:         float = 0.38,
        shadow_r:          float = 0.010,
        shadow_g:          float = 0.002,
        shadow_b:          float = 0.020,
        edge_thresh:       float = 0.06,
        edge_rng:          float = 0.10,
        sfumato_sigma:     float = 2.5,
        sfumato_strength:  float = 0.30,
        opacity:           float = 0.35,
    ) -> None:
        """Marco d'Oggiono's Leonardesque warmth: THREE-GATE tinting.

        SEVENTY-THIRD DISTINCT MODE.

        Gate 1 — WARM IVORY HIGHLIGHTS (luma > highlight_lo):
            Inject warm amber-ivory lift (R+ivory_r, G+ivory_g, B-ivory_b).
            Marco's peaks glow warm, not cool-pearl like Boltraffio.

        Gate 2 — COOL VIOLET SHADOW DEPTH (luma < shadow_hi):
            Inject Leonardesque cool-violet atmosphere (R-shadow_r, G-shadow_g,
            B+shadow_b).  Lighter than Boltraffio's blue-grey; Marco's shadows
            keep more amber warmth until the deep void.

        Gate 3 — SFUMATO EDGE DISSOLUTION (Sobel gradient > edge_thresh):
            Gaussian blur canvas; blend edge pixels toward blurred version by
            edge_gate × sfumato_strength; soft contour dissolution in Leonardo's
            tradition without full atmospheric depth of sfumato_veil_pass().

        NOVEL: FIRST pass to combine THREE SIMULTANEOUS ZONE GATES — highlight
        warm-tinting, shadow cool-tinting, AND gradient-detected edge sfumato —
        in a single unified Leonardesque pass.  Prior three-gate passes (Giampietrino
        s157, Greuze s158) use only luminance gates without the edge-sfumato gate.

        Args:
            highlight_lo      : Luminance threshold above which warm ivory is injected.
            ivory_r/g/b       : Warm ivory injection amounts (B is subtracted).
            shadow_hi         : Luminance threshold below which cool violet is injected.
            shadow_r/g/b      : Cool violet injection (R and G subtracted, B added).
            edge_thresh       : Sobel gradient normalised threshold for sfumato gate.
            edge_rng          : Gradient range over which sfumato gate ramps up.
            sfumato_sigma     : Gaussian blur radius (px) for edge sfumato.
            sfumato_strength  : Maximum blend fraction toward blurred at detected edges.
            opacity           : Final composite weight. Default 0.35.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0)

        # ── Gate 1: warm ivory highlight tinting ─────────────────────────────
        hi_gate = _np.clip((luma - float(highlight_lo)) / 0.15, 0.0, 1.0).astype(_np.float32)
        warm_r = r0 + float(ivory_r) * hi_gate
        warm_g = g0 + float(ivory_g) * hi_gate
        warm_b = b0 - float(ivory_b) * hi_gate

        # ── Gate 2: cool violet shadow depth ─────────────────────────────────
        sh_gate = _np.clip((float(shadow_hi) - luma) / 0.15, 0.0, 1.0).astype(_np.float32)
        out_r = warm_r - float(shadow_r) * sh_gate
        out_g = warm_g - float(shadow_g) * sh_gate
        out_b = warm_b + float(shadow_b) * sh_gate

        # ── Gate 3: sfumato edge dissolution ─────────────────────────────────
        # Compute Sobel gradient on original luminance
        luma_u8 = (luma * 255.0).astype(_np.float32)
        sx = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        sy = sx.T.copy()
        from scipy.ndimage import convolve as _conv
        gx = _conv(luma_u8, sx, mode='reflect')
        gy = _conv(luma_u8, sy, mode='reflect')
        grad_mag = _np.sqrt(gx * gx + gy * gy)
        grad_norm = grad_mag / (grad_mag.max() + 1e-6)
        edge_gate = _np.clip(
            (grad_norm - float(edge_thresh)) / float(edge_rng), 0.0, 1.0
        ).astype(_np.float32)

        sigma = float(sfumato_sigma)
        blur_r = _gf(out_r.astype(_np.float64), sigma=sigma).astype(_np.float32)
        blur_g = _gf(out_g.astype(_np.float64), sigma=sigma).astype(_np.float32)
        blur_b = _gf(out_b.astype(_np.float64), sigma=sigma).astype(_np.float32)

        blend = edge_gate * float(sfumato_strength)
        out_r = out_r * (1.0 - blend) + blur_r * blend
        out_g = out_g * (1.0 - blend) + blur_g * blend
        out_b = out_b * (1.0 - blend) + blur_b * blend

        # ── Composite at opacity ──────────────────────────────────────────────
        out_r = _np.clip(r0 * (1.0 - opacity) + out_r * opacity, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - opacity) + out_g * opacity, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - opacity) + out_b * opacity, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Marco d'Oggiono Leonardesque warmth pass complete.")

    def multilayer_atmospheric_veil_pass(
        self,
        sigma_fine:    float = 1.5,
        sigma_medium:  float = 4.5,
        sigma_coarse:  float = 12.0,
        weight_fine:   float = 0.40,
        weight_medium: float = 0.35,
        weight_coarse: float = 0.25,
        edge_thresh:   float = 0.04,
        edge_rng:      float = 0.12,
        opacity:       float = 0.45,
    ) -> None:
        """Three-scale sfumato veil: multi-frequency atmospheric dissolution.

        SEVENTY-FOURTH DISTINCT MODE.

        Applies Leonardesque sfumato simultaneously at three spatial frequencies:
        - Fine scale   (sigma_fine):   dissolves micro-detail crisp edges
        - Medium scale (sigma_medium): dissolves feature boundaries (eyelid, lip)
        - Coarse scale (sigma_coarse): creates broad atmospheric tone pooling

        All three scales are gated by Sobel gradient magnitude so that flat zones
        (smooth flesh passages, open sky) are protected and only edges experience
        dissolution.  The weighted mix of three blur depths produces a richer,
        more naturalistic atmospheric dissolution than any single-scale sfumato.

        NOVEL: FIRST pass to apply THREE SIMULTANEOUSLY WEIGHTED GAUSSIAN SCALES
        in a single sfumato operation.  All prior sfumato passes (sfumato_veil_pass,
        figure_contour_atmosphere_pass, edge_sfumato_dissolution_pass) use only
        ONE spatial scale.  The multi-scale approach mimics the physical layering of
        Leonardo's glazes: each thin transparent layer dissolved edges at a different
        depth, creating atmospheric transitions at multiple frequency bands
        simultaneously.

        Args:
            sigma_fine    : Gaussian radius for fine-scale dissolution. Default 1.5.
            sigma_medium  : Gaussian radius for medium-scale dissolution. Default 4.5.
            sigma_coarse  : Gaussian radius for coarse-scale dissolution. Default 12.0.
            weight_fine   : Contribution weight of fine scale (summed with medium+coarse).
            weight_medium : Contribution weight of medium scale.
            weight_coarse : Contribution weight of coarse scale.
            edge_thresh   : Normalised Sobel magnitude below which no dissolution occurs.
            edge_rng      : Ramp range for edge gate transition.
            opacity       : Final composite weight (0 = no-op). Default 0.45.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from scipy.ndimage import convolve as _conv

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0)

        # ── Compute Sobel edge gate ───────────────────────────────────────────
        luma_u8 = (luma * 255.0).astype(_np.float32)
        sx = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        gx = _conv(luma_u8, sx,   mode='reflect')
        gy = _conv(luma_u8, sx.T, mode='reflect')
        grad_mag = _np.sqrt(gx * gx + gy * gy)
        grad_norm = grad_mag / (grad_mag.max() + 1e-6)
        edge_gate = _np.clip(
            (grad_norm - float(edge_thresh)) / float(edge_rng), 0.0, 1.0
        ).astype(_np.float32)

        # ── Three-scale Gaussian blurs ────────────────────────────────────────
        def _blur(ch: _np.ndarray, sig: float) -> _np.ndarray:
            return _gf(ch.astype(_np.float64), sigma=sig).astype(_np.float32)

        fine_r   = _blur(r0, sigma_fine);   fine_g   = _blur(g0, sigma_fine);   fine_b   = _blur(b0, sigma_fine)
        medium_r = _blur(r0, sigma_medium); medium_g = _blur(g0, sigma_medium); medium_b = _blur(b0, sigma_medium)
        coarse_r = _blur(r0, sigma_coarse); coarse_g = _blur(g0, sigma_coarse); coarse_b = _blur(b0, sigma_coarse)

        # ── Weighted multi-scale blend ────────────────────────────────────────
        total_w = float(weight_fine) + float(weight_medium) + float(weight_coarse)
        wf = float(weight_fine)   / total_w
        wm = float(weight_medium) / total_w
        wc = float(weight_coarse) / total_w

        multi_r = wf * fine_r + wm * medium_r + wc * coarse_r
        multi_g = wf * fine_g + wm * medium_g + wc * coarse_g
        multi_b = wf * fine_b + wm * medium_b + wc * coarse_b

        # ── Apply dissolution gated on edge magnitude ─────────────────────────
        blend = edge_gate * float(opacity)
        out_r = _np.clip(r0 * (1.0 - blend) + multi_r * blend, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - blend) + multi_g * blend, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - blend) + multi_b * blend, 0.0, 1.0)

        # ── Final composite ───────────────────────────────────────────────────
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(out_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(out_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(out_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Multi-layer atmospheric veil pass complete.")

    # ── Session 177: François Boucher ─────────────────────────────────────────
    def boucher_pastel_radiance_pass(
            self,
            flesh_lo:       float = 0.42,
            flesh_hi:       float = 0.74,
            flesh_r:        float = 0.022,
            flesh_g:        float = 0.012,
            flesh_b_reduce: float = 0.018,
            sky_band:       float = 0.35,
            sky_cool_b:     float = 0.035,
            sky_cool_g:     float = 0.008,
            sky_cool_r:     float = 0.012,
            sat_boost:      float = 0.12,
            sat_gate_lo:    float = 0.30,
            sat_gate_hi:    float = 0.80,
            opacity:        float = 0.42):
        """
        Boucher pastel radiance pass — François Boucher (1703–1770).

        Encodes the two defining palette qualities of French Rococo painting at
        its Boucherian peak: the warm peach-cream flesh luminosity and the
        characteristic powder-blue sky atmosphere ('ciel Boucher').

        THREE-ZONE ENCODING:

        Zone 1 — Warm peach-cream flesh radiance:
            Gaussian bell gate centred in mid-flesh luminance zone [flesh_lo,
            flesh_hi]: R↑ (flesh_r), G↑ slight (flesh_g), B↓ (flesh_b_reduce).
            Boucher's flesh is lighter and warmer than Italian Baroque — peach-cream
            rather than amber-gold — reflecting the influence of French pastel
            portraiture on 18th-century oil technique.  The bell gate ensures
            the brightest highlights and deepest shadows are unaffected.

        Zone 2 — Cool powder-blue sky atmosphere:
            Vertical position gate fading from full effect at the top row (y=0)
            to zero at sky_band of canvas height: B↑ (sky_cool_b), G↑ slight
            (sky_cool_g), R↓ (sky_cool_r).  Reproduces 'ciel Boucher' — the
            characteristic airy, desaturated powder-blue sky that appears behind
            every Boucher mythological scene.

        Zone 3 — Mid-tone saturation lift:
            Gentle global saturation boost (sat_boost) gated to mid-luminance
            [sat_gate_lo, sat_gate_hi] via Gaussian bell mask.  Applied through
            neutral-mean chromatic expansion: delta = channel − neutral;
            boosted = neutral + delta × (1 + sat_boost × sat_gate).  Enriches
            Boucher's decorative palette without Fauvist intensity.

        NOVEL: FIRST pass combining (a) luminance-gated warm peach injection in
        flesh zones AND (b) vertical position-gated cool powder-blue sky atmosphere
        AND (c) mid-tone saturation enrichment — the three structural qualities of
        Boucher's palette working in concert: warm figure against airy background.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        out_r = r0.copy()
        out_g = g0.copy()
        out_b = b0.copy()

        # ── Zone 1: Warm peach-cream flesh radiance ───────────────────────────
        flesh_mid   = (float(flesh_lo) + float(flesh_hi)) * 0.5
        flesh_width = (float(flesh_hi) - float(flesh_lo)) * 0.5 + 1e-6
        flesh_gate  = _np.exp(
            -0.5 * ((luma - flesh_mid) / flesh_width) ** 2
        ).astype(_np.float32)

        out_r = _np.clip(out_r + flesh_gate * float(flesh_r),        0.0, 1.0)
        out_g = _np.clip(out_g + flesh_gate * float(flesh_g),        0.0, 1.0)
        out_b = _np.clip(out_b - flesh_gate * float(flesh_b_reduce), 0.0, 1.0)

        # ── Zone 2: Cool powder-blue sky atmosphere ───────────────────────────
        ys_norm  = _np.linspace(0.0, 1.0, H, dtype=_np.float32)
        sky_1d   = _np.clip(1.0 - ys_norm / (float(sky_band) + 1e-6), 0.0, 1.0)
        sky_gate = sky_1d[:, _np.newaxis]

        out_r = _np.clip(out_r - sky_gate * float(sky_cool_r), 0.0, 1.0)
        out_g = _np.clip(out_g + sky_gate * float(sky_cool_g), 0.0, 1.0)
        out_b = _np.clip(out_b + sky_gate * float(sky_cool_b), 0.0, 1.0)

        # ── Zone 3: Mid-tone saturation lift ─────────────────────────────────
        sat_mid   = (float(sat_gate_lo) + float(sat_gate_hi)) * 0.5
        sat_width = (float(sat_gate_hi) - float(sat_gate_lo)) * 0.5 + 1e-6
        sat_gate  = _np.exp(
            -0.5 * ((luma - sat_mid) / sat_width) ** 2
        ).astype(_np.float32)

        neutral = (out_r + out_g + out_b) / 3.0
        boost   = float(sat_boost) * sat_gate
        out_r   = _np.clip(neutral + (out_r - neutral) * (1.0 + boost), 0.0, 1.0)
        out_g   = _np.clip(neutral + (out_g - neutral) * (1.0 + boost), 0.0, 1.0)
        out_b   = _np.clip(neutral + (out_b - neutral) * (1.0 + boost), 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        op = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Boucher pastel radiance pass complete.")

    # Session 178 — Adriaen Brouwer: SEVENTY-FOURTH DISTINCT MODE
    def brouwer_tavern_glow_pass(
            self,
            amber_lo:       float = 0.28,
            amber_hi:       float = 0.62,
            amber_r:        float = 0.028,
            amber_g:        float = 0.010,
            amber_b_reduce: float = 0.016,
            smoke_hi:       float = 0.30,
            smoke_desat:    float = 0.08,
            accent_lo:      float = 0.55,
            accent_r:       float = 0.016,
            accent_g:       float = 0.007,
            opacity:        float = 0.42):
        """
        Brouwer tavern glow pass — Adriaen Brouwer (1605/06–1638).

        Encodes the three defining palette qualities of Brouwer's earthy genre
        realism: the warm tobacco amber that suffuses every mid-tone, the smoky
        desaturation that dims the shadow void, and the warm candlelight accent
        that glints on the highest lit surfaces.

        THREE-ZONE ENCODING:

        Zone 1 — Warm tobacco amber mid-tones:
            Gaussian bell gate centred in mid-luminance zone [amber_lo, amber_hi]:
            R↑ (amber_r), G↑ slight (amber_g), B↓ (amber_b_reduce).
            Brouwer's mid-tones are warmer than any Dutch Academic norm — tobacco,
            firelight and umber, never daylight cool.  The bell gate ensures deep
            shadows and bright highlights are not pushed further.

        Zone 2 — Smoky shadow desaturation:
            Linear gate below smoke_hi luminance: chromatic desaturation toward
            luminance mean (smoke_desat fraction).  Tavern smoke absorbs colour
            from the darkest zones, pulling them toward warm grey rather than the
            saturated deep tones of Italian Baroque.  The desaturation is chroma-
            reducing, not blue-adding — the darks remain warm, just muted.

        Zone 3 — Warm light accent (candlelight / pipe glow):
            Linear gate above accent_lo luminance: R↑ (accent_r), G↑ (accent_g).
            Where Brouwer's single warm source — candle, window, hearth — touches
            flesh or surface, it leaves a golden flicker.  No B change: the
            highlight light is warm, never neutral.

        NOVEL: FIRST pass combining (a) tobacco-amber Gaussian bell on mid-tones
        AND (b) smoky chromatic desaturation in shadow void AND (c) warm golden
        accent on highlights — the three structural qualities of Brouwer's
        enclosed tavern palette working in concert against a warm dark ground.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        out_r = r0.copy()
        out_g = g0.copy()
        out_b = b0.copy()

        # ── Zone 1: Warm tobacco amber mid-tones ─────────────────────────────
        amb_mid   = (float(amber_lo) + float(amber_hi)) * 0.5
        amb_width = (float(amber_hi) - float(amber_lo)) * 0.5 + 1e-6
        amb_gate  = _np.exp(
            -0.5 * ((luma - amb_mid) / amb_width) ** 2
        ).astype(_np.float32)

        out_r = _np.clip(out_r + amb_gate * float(amber_r),        0.0, 1.0)
        out_g = _np.clip(out_g + amb_gate * float(amber_g),        0.0, 1.0)
        out_b = _np.clip(out_b - amb_gate * float(amber_b_reduce), 0.0, 1.0)

        # ── Zone 2: Smoky shadow desaturation ────────────────────────────────
        shad_gate = _np.clip(
            (float(smoke_hi) - luma) / (float(smoke_hi) + 1e-6), 0.0, 1.0
        ).astype(_np.float32)
        smk = float(smoke_desat) * shad_gate
        neutral = (out_r + out_g + out_b) / 3.0
        out_r = _np.clip(out_r * (1.0 - smk) + neutral * smk, 0.0, 1.0)
        out_g = _np.clip(out_g * (1.0 - smk) + neutral * smk, 0.0, 1.0)
        out_b = _np.clip(out_b * (1.0 - smk) + neutral * smk, 0.0, 1.0)

        # ── Zone 3: Warm candlelight accent on highlights ────────────────────
        acc_gate = _np.clip(
            (luma - float(accent_lo)) / (1.0 - float(accent_lo) + 1e-6), 0.0, 1.0
        ).astype(_np.float32)

        out_r = _np.clip(out_r + acc_gate * float(accent_r), 0.0, 1.0)
        out_g = _np.clip(out_g + acc_gate * float(accent_g), 0.0, 1.0)

        # ── Composite at opacity ──────────────────────────────────────────────
        op = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Brouwer tavern glow pass complete.")

    # ── Session 178: Domenico Ghirlandaio ────────────────────────────────────
    def ghirlandaio_civic_clarity_pass(
            self,
            sat_hi:          float = 0.20,
            sat_lo:          float = 0.08,
            vivid_boost:     float = 0.28,
            neutral_pull:    float = 0.18,
            luma_lo:         float = 0.12,
            luma_hi:         float = 0.92,
            opacity:         float = 0.38):
        """
        Ghirlandaio civic clarity pass — Domenico Ghirlandaio (c.1448–1494).

        Encodes the defining palette quality of Ghirlandaio's Florentine civic
        painting: a clean, bimodal colour world where vivid pigments remain
        vivid and neutral passages remain cleanly neutral.

        BIMODAL SATURATION SORTING:
        HIGH-SATURATION zone (S > sat_hi): chromatic expansion (vivid_boost).
        LOW-SATURATION zone (S < sat_lo): neutral pull (neutral_pull).
        Both zones gated by Gaussian luminance bell [luma_lo, luma_hi].

        NOVEL: SEVENTY-FIFTH DISTINCT MODE.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        luma_mid   = (float(luma_lo) + float(luma_hi)) * 0.5
        luma_width = (float(luma_hi) - float(luma_lo)) * 0.5 + 1e-6
        luma_gate  = _np.exp(
            -0.5 * ((luma - luma_mid) / luma_width) ** 2
        ).astype(_np.float32)

        max_c = _np.maximum(_np.maximum(r0, g0), b0)
        min_c = _np.minimum(_np.minimum(r0, g0), b0)
        sat   = (max_c - min_c) / (max_c + 1e-6)

        neutral = (r0 + g0 + b0) / 3.0

        out_r = r0.copy()
        out_g = g0.copy()
        out_b = b0.copy()

        hi_raw  = _np.clip((sat - float(sat_hi)) / (float(sat_hi) + 1e-6), 0.0, 1.0)
        hi_gate = (hi_raw * luma_gate).astype(_np.float32)
        boost   = float(vivid_boost) * hi_gate
        out_r   = _np.clip(neutral + (out_r - neutral) * (1.0 + boost), 0.0, 1.0)
        out_g   = _np.clip(neutral + (out_g - neutral) * (1.0 + boost), 0.0, 1.0)
        out_b   = _np.clip(neutral + (out_b - neutral) * (1.0 + boost), 0.0, 1.0)

        lo_raw  = _np.clip((float(sat_lo) - sat) / (float(sat_lo) + 1e-6), 0.0, 1.0)
        lo_gate = (lo_raw * luma_gate).astype(_np.float32)
        pull    = float(neutral_pull) * lo_gate
        out_r   = _np.clip(out_r * (1.0 - pull) + neutral * pull, 0.0, 1.0)
        out_g   = _np.clip(out_g * (1.0 - pull) + neutral * pull, 0.0, 1.0)
        out_b   = _np.clip(out_b * (1.0 - pull) + neutral * pull, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Ghirlandaio civic clarity pass complete.")

    # ── Session 178: random improvement — luminance_preserving_chroma_boost_pass
    def luminance_preserving_chroma_boost_pass(
            self,
            boost:        float = 0.22,
            luma_lo:      float = 0.20,
            luma_hi:      float = 0.85,
            opacity:      float = 0.35):
        """
        Luminance-preserving chromatic boost pass — session 178 random improvement.

        Amplifies the chromatic vector while EXACTLY restoring original luminance
        via per-pixel rescaling. NOVEL: SEVENTY-SIXTH DISTINCT MODE.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma0 = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0)

        luma_mid   = (float(luma_lo) + float(luma_hi)) * 0.5
        luma_width = (float(luma_hi) - float(luma_lo)) * 0.5 + 1e-6
        gate = _np.exp(
            -0.5 * ((luma0 - luma_mid) / luma_width) ** 2
        ).astype(_np.float32)

        neutral = (r0 + g0 + b0) / 3.0
        amp     = 1.0 + float(boost) * gate

        boost_r = _np.clip(neutral + (r0 - neutral) * amp, 0.0, 1.0)
        boost_g = _np.clip(neutral + (g0 - neutral) * amp, 0.0, 1.0)
        boost_b = _np.clip(neutral + (b0 - neutral) * amp, 0.0, 1.0)

        luma1 = 0.2126 * boost_r + 0.7152 * boost_g + 0.0722 * boost_b
        scale = luma0 / (luma1 + 1e-7)
        active = (luma0 > 0.02) & (gate > 0.01)
        out_r = _np.where(active, _np.clip(boost_r * scale, 0.0, 1.0), boost_r)
        out_g = _np.where(active, _np.clip(boost_g * scale, 0.0, 1.0), boost_g)
        out_b = _np.where(active, _np.clip(boost_b * scale, 0.0, 1.0), boost_b)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Luminance-preserving chroma boost pass complete.")

    # ── Session 179: ter Borch — ter_borch_satin_sheen_pass
    def ter_borch_satin_sheen_pass(
            self,
            smooth_thresh:  float = 0.10,
            sigma_local:    float = 2.5,
            satin_lo:       float = 0.40,
            satin_hi:       float = 0.72,
            warm_r:         float = 0.028,
            warm_g:         float = 0.010,
            peak_lo:        float = 0.70,
            cool_r:         float = 0.012,
            cool_b:         float = 0.022,
            opacity:        float = 0.38):
        """
        Ter Borch satin sheen pass — Gerard ter Borch (1617–1681).

        Simulates ter Borch's signature two-zone satin fabric quality:
        a warm amber glow just below the specular peak, and a cool crystalline
        specular peak at the highest luminance — the iridescent quality that makes
        his silver satin look lit from within.

        VARIANCE-GATED DUAL-ZONE SATIN FABRIC SIMULATION:
        1. Smooth surface detection: local std via Gaussian residual on luma.
           smooth_gate = clip(1 - local_std / smooth_thresh, 0, 1) — high where
           surface is uniform (satin/skin), zero where textured (hair/background).
        2. Warm sub-peak glaze: Gaussian bell gate [satin_lo, satin_hi] ×
           smooth_gate → R+warm_r, G+warm_g (warm amber sub-highlight glow).
        3. Cool specular peak: ramp gate [peak_lo, 1.0] × smooth_gate →
           R-cool_r, B+cool_b (cool crystalline window-light reflection).

        NOVEL: SEVENTY-EIGHTH DISTINCT MODE. FIRST pass to use LOCAL VARIANCE
        as a surface smoothness mask to simultaneously gate both a WARM mid-high
        zone tint AND a COOL peak zone tint — all prior variance-based passes
        apply a single monotonic chroma change (s128 adaptation, s173 amplification);
        this applies OPPOSITE directional warm/cool treatments in two luma sub-zones,
        both masked to smooth surface regions only.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        # Local std via Gaussian blur residual — smooth_gate detects satin-like surfaces
        sig       = float(sigma_local)
        luma_blur = _gf(luma, sigma=sig)
        luma_sq   = _gf(luma * luma, sigma=sig)
        local_var = _np.clip(luma_sq - luma_blur * luma_blur, 0.0, None)
        local_std = _np.sqrt(local_var).astype(_np.float32)
        thresh    = float(smooth_thresh)
        smooth_gate = _np.clip(1.0 - local_std / (thresh + 1e-6), 0.0, 1.0)

        # Warm sub-peak: Gaussian bell gate over mid-high luma × smooth_gate
        slo = float(satin_lo)
        shi = float(satin_hi)
        mid_s = (slo + shi) * 0.5
        wid_s = (shi - slo) * 0.5 + 1e-6
        warm_bell = _np.exp(-0.5 * ((luma - mid_s) / wid_s) ** 2).astype(_np.float32)
        warm_gate = warm_bell * smooth_gate

        out_r = _np.clip(r0 + float(warm_r) * warm_gate, 0.0, 1.0)
        out_g = _np.clip(g0 + float(warm_g) * warm_gate, 0.0, 1.0)
        out_b = b0.copy()

        # Cool specular peak: one-sided ramp above peak_lo × smooth_gate
        plo       = float(peak_lo)
        peak_ramp = _np.clip((luma - plo) / (1.0 - plo + 1e-6), 0.0, 1.0)
        cool_gate = peak_ramp * smooth_gate

        out_r = _np.clip(out_r - float(cool_r) * cool_gate, 0.0, 1.0)
        out_b = _np.clip(out_b + float(cool_b) * cool_gate, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Ter Borch satin sheen pass complete.")

    # ── Session 179: random improvement — shadow_chroma_depth_pass
    def shadow_chroma_depth_pass(
            self,
            shadow_lo:      float = 0.12,
            shadow_hi:      float = 0.45,
            amplify:        float = 0.30,
            highlight_lo:   float = 0.82,
            reduce:         float = 0.18,
            opacity:        float = 0.35):
        """
        Shadow chroma depth pass — session 179 random improvement.

        Simulates the natural chromatic envelope of oil paint glazing:
        mid-shadow zones have the richest apparent saturation (transparent glazes
        pool deepest colour in the penumbra), while peak highlights have reduced
        chroma (thick lead white impasto desaturates toward neutral ivory).

        TONAL ZONE CHROMA ENVELOPE:
        MID-SHADOW zone [shadow_lo, shadow_hi]: chroma amplification via
          neutral-mean vector expansion × Gaussian bell gate.
        PEAK HIGHLIGHT zone [highlight_lo, 1.0]: chroma reduction via
          neutral pull × one-sided ramp gate.

        NOVEL: SEVENTY-NINTH DISTINCT MODE. FIRST pass to simultaneously AMPLIFY
        mid-shadow chroma AND REDUCE highlight chroma based on LUMINANCE ZONE —
        unlike ghirlandaio_civic_clarity_pass (pass 75) which sorts on HSV
        SATURATION LEVEL, this operates on LUMINANCE ZONE; unlike all prior
        chroma amplification passes which apply single monotonic boost, this
        applies OPPOSITE treatments (amplify / reduce) in distinct luma zones.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)
        neutral = (r0 + g0 + b0) / 3.0

        # Mid-shadow chroma amplification via bell gate
        slo = float(shadow_lo)
        shi = float(shadow_hi)
        mid_sh = (slo + shi) * 0.5
        wid_sh = (shi - slo) * 0.5 + 1e-6
        shadow_bell = _np.exp(-0.5 * ((luma - mid_sh) / wid_sh) ** 2).astype(_np.float32)
        amp_factor  = 1.0 + float(amplify) * shadow_bell

        out_r = _np.clip(neutral + (r0 - neutral) * amp_factor, 0.0, 1.0)
        out_g = _np.clip(neutral + (g0 - neutral) * amp_factor, 0.0, 1.0)
        out_b = _np.clip(neutral + (b0 - neutral) * amp_factor, 0.0, 1.0)

        # Peak highlight chroma reduction via one-sided ramp gate
        hlo        = float(highlight_lo)
        hi_ramp    = _np.clip((luma - hlo) / (1.0 - hlo + 1e-6), 0.0, 1.0)
        pull       = float(reduce) * hi_ramp
        out_r = _np.clip(out_r * (1.0 - pull) + neutral * pull, 0.0, 1.0)
        out_g = _np.clip(out_g * (1.0 - pull) + neutral * pull, 0.0, 1.0)
        out_b = _np.clip(out_b * (1.0 - pull) + neutral * pull, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Shadow chroma depth pass complete.")

    # ── Session 180: artist pass — cesare_da_sesto_clarity_pass
    def cesare_da_sesto_clarity_pass(
            self,
            smooth_thresh:  float = 0.08,
            grad_sigma:     float = 1.5,
            warm_r:         float = 0.025,
            warm_g:         float = 0.010,
            mid_grad_center: float = 0.50,
            mid_grad_width:  float = 0.22,
            cool_b:         float = 0.022,
            cool_r:         float = 0.010,
            opacity:        float = 0.32):
        """
        Cesare da Sesto clarity pass — session 180 artist pass.

        Simulates the defining synthesis of Cesare da Sesto (1477–1523): Leonardo's
        sfumato warmth in smooth flesh/fabric zones FUSED WITH Raphael's cool
        'air between forms' at medium-gradient form boundaries.

        MILANESE-ROMAN CLARITY BRIDGE:
        1. Sobel gradient magnitude on luma → grad_norm (normalised to [0, 1]).
        2. SMOOTH ZONE (grad_norm < smooth_thresh): warm Leonardesque injection
           R+warm_r × smooth_gate, G+warm_g × smooth_gate — sfumato warmth in
           low-gradient flesh and sky areas.
        3. MEDIUM GRADIENT ZONE: Gaussian bell gate centred on mid_grad_center
           in gradient space × cool Raphaelesque 'air' injection
           B+cool_b × mid_gate, R-cool_r × mid_gate — cool luminous separation
           at form boundaries giving classical spatial legibility.

        NOVEL: EIGHTIETH DISTINCT MODE. FIRST pass to use GRADIENT MAGNITUDE as a
        BIMODAL GATE applying OPPOSITE chromatic treatments at two gradient levels:
        WARM in low-gradient smooth zones (Leonardesque sfumato fill) AND COOL at
        medium-gradient form boundaries (Raphaelesque classical air). All prior
        gradient passes apply a single monotonic treatment — either dissolving edges
        (sfumato s158, contour blur s174) or sharpening them (anti-sfumato s175).
        This applies a WARM/COOL SPLIT keyed on gradient magnitude, not luma level.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        # Sobel gradient magnitude on blurred luma
        luma_s   = _gf(luma, sigma=float(grad_sigma))
        gx       = _sobel(luma_s, axis=1)
        gy       = _sobel(luma_s, axis=0)
        grad_mag = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)
        grad_max = grad_mag.max() + 1e-6
        grad_norm = grad_mag / grad_max

        # Smooth zone gate: low gradient → warm Leonardesque injection
        thresh      = float(smooth_thresh)
        smooth_gate = _np.clip(1.0 - grad_norm / thresh, 0.0, 1.0)

        out_r = _np.clip(r0 + float(warm_r) * smooth_gate, 0.0, 1.0)
        out_g = _np.clip(g0 + float(warm_g) * smooth_gate, 0.0, 1.0)
        out_b = b0.copy()

        # Medium gradient zone: Gaussian bell on grad_norm → cool Raphaelesque air
        mid  = float(mid_grad_center)
        wid  = float(mid_grad_width) + 1e-6
        mid_gate = _np.exp(-0.5 * ((grad_norm - mid) / wid) ** 2).astype(_np.float32)

        out_r = _np.clip(out_r - float(cool_r) * mid_gate, 0.0, 1.0)
        out_b = _np.clip(out_b + float(cool_b) * mid_gate, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Cesare da Sesto clarity pass complete.")

    # ── Session 180: random improvement — canvas_tooth_texture_pass
    def canvas_tooth_texture_pass(
            self,
            tooth_freq:  float = 48.0,
            tooth_aspect: float = 1.0,
            tooth_thresh: float = 0.25,
            tooth_lo:    float = 0.22,
            tooth_hi:    float = 0.68,
            tooth_depth: float = 0.10,
            ground_r:    float = 0.60,
            ground_g:    float = 0.52,
            ground_b:    float = 0.36,
            opacity:     float = 0.40):
        """
        Canvas tooth texture pass — session 180 random improvement.

        Simulates the physical interaction of oil paint with woven canvas tooth:
        paint fills canvas cavities (tooth troughs) differently across tonal zones.
        In highlight zones (thick paint): fills tooth completely — smooth surface.
        In midtone zones (moderate paint load): bridges across peaks — tooth visible.
        In deep shadow zones (thin scumble): paint is sparse, tooth less relevant.

        CANVAS WEAVE TOOTH SIMULATION:
        1. Crossed sine wave canvas weave: tooth = 0.5*(1+sin(x*freq_x)) *
           0.5*(1+sin(y*freq_y)) — a deterministic periodic pattern at canvas scale.
        2. Cavity mask: clip(1 - weave/tooth_thresh) → high in weave troughs.
        3. Midtone bell gate [tooth_lo, tooth_hi]: tooth most visible in midtones
           (where paint bridges but does not fill); suppressed in highlights and darks.
        4. Blend toward ground colour (warm ochre imprimatura) in cavity zones.

        NOVEL: EIGHTY-FIRST DISTINCT MODE. FIRST pass to use DETERMINISTIC PERIODIC
        STRUCTURE (crossed sine wave canvas weave) to simulate canvas tooth interaction.
        Unlike film_grain_overlay (mode 54) which uses stochastic Gaussian noise,
        this creates a canvas-scale STRUCTURED PERIODIC texture matching real woven
        canvas geometry. The midtone gating simulates how oil paint bridges canvas
        peaks fully in highlights (no tooth visible) but reveals tooth cavities in
        midtones — giving the surface the tactile woven quality visible in many
        early Renaissance oil-on-panel and oil-on-canvas works under raking light.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        # Crossed sine wave canvas weave pattern
        xs = _np.arange(W, dtype=_np.float32) / float(W)
        ys = _np.arange(H, dtype=_np.float32) / float(H)
        xm, ym = _np.meshgrid(xs, ys)
        freq   = float(tooth_freq)
        aspect = float(tooth_aspect)
        tooth_x = 0.5 * (1.0 + _np.sin(xm * 2.0 * _np.pi * freq))
        tooth_y = 0.5 * (1.0 + _np.sin(ym * 2.0 * _np.pi * freq * aspect))
        weave   = (tooth_x * tooth_y).astype(_np.float32)

        # Cavity mask: weave troughs where paint reveals canvas ground
        thresh       = float(tooth_thresh) + 1e-6
        cavity_mask  = _np.clip(1.0 - weave / thresh, 0.0, 1.0)

        # Midtone bell gate: tooth most visible in mid-luma range
        tlo     = float(tooth_lo)
        thi     = float(tooth_hi)
        mid_t   = (tlo + thi) * 0.5
        wid_t   = (thi - tlo) * 0.5 + 1e-6
        bell    = _np.exp(-0.5 * ((luma - mid_t) / wid_t) ** 2).astype(_np.float32)

        tooth_gate = cavity_mask * bell * float(tooth_depth)

        # Blend toward canvas ground color in tooth cavities
        gr = float(ground_r)
        gg = float(ground_g)
        gb = float(ground_b)
        out_r = _np.clip(r0 * (1.0 - tooth_gate) + gr * tooth_gate, 0.0, 1.0)
        out_g = _np.clip(g0 * (1.0 - tooth_gate) + gg * tooth_gate, 0.0, 1.0)
        out_b = _np.clip(b0 * (1.0 - tooth_gate) + gb * tooth_gate, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Canvas tooth texture pass complete.")

    # ── Session 181: artist pass — pinturicchio_jewel_azure_pass
    def pinturicchio_jewel_azure_pass(
            self,
            azure_delta:    float = 0.04,
            azure_boost:    float = 0.030,
            azure_r_reduce: float = 0.012,
            gold_delta_r:   float = 0.05,
            gold_delta_rg:  float = 0.04,
            gold_boost_r:   float = 0.025,
            gold_boost_g:   float = 0.010,
            gold_b_reduce:  float = 0.015,
            luma_lo:        float = 0.20,
            luma_hi:        float = 0.88,
            opacity:        float = 0.38):
        """
        Pinturicchio jewel azure pass — session 181 artist pass.

        Simulates Pinturicchio's defining chromatic achievement: the unrivalled
        LAPIS LAZULI AZURE of the Piccolomini Library frescoes, used alongside
        GOLD LEAF warmth to produce a jewel-like dual-zone chromatic intensity.

        DUAL-CHANNEL DOMINANCE JEWEL ENRICHMENT:
        1. AZURE ZONE — pixel where B > R + azure_delta AND B > G + azure_delta:
           inject B+azure_boost, R-azure_r_reduce → deepens lapis lazuli quality.
        2. GOLD ZONE — pixel where R > G + gold_delta_r AND G > B + gold_delta_rg:
           inject R+gold_boost_r, G+gold_boost_g, B-gold_b_reduce → enriches gold leaf.
        3. Both gates suppressed at extremes via luma clip [luma_lo, luma_hi] to
           preserve deep shadow void and specular white highlight.

        NOVEL: EIGHTY-SECOND DISTINCT MODE. FIRST pass to use PER-CHANNEL DOMINANCE
        DETECTION (B exceeds BOTH R and G by delta for azure; R exceeds G by delta_r
        AND G exceeds B by delta_rg for gold) as a BINARY gate for SIMULTANEOUS
        DUAL-ZONE chromatic enrichment in OPPOSITE directions (azure enrichment AND
        gold enrichment, both active simultaneously on different pixel sets).
        All prior dual-zone passes key on LUMINANCE LEVEL (Giorgione s138 mode 16,
        Giampietrino s157 mode 45, Moro s159 mode 49) or SATURATION LEVEL
        (Ghirlandaio s178 mode 78) or GRADIENT MAGNITUDE (Cesare da Sesto s180 mode 83).
        This is the first pass to key on raw RGB CHANNEL-COMPARISON DOMINANCE.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        # Luma gate: suppress in near-black and specular-white zones
        lo = float(luma_lo)
        hi = float(luma_hi)
        luma_gate = _np.clip((luma - lo) / (lo + 1e-6), 0.0, 1.0) * \
                    _np.clip((hi - luma) / (hi - lo + 1e-6), 0.0, 1.0)

        # AZURE ZONE: B dominates both R and G by azure_delta
        ad = float(azure_delta)
        azure_gate = _np.clip(
            _np.minimum(b0 - r0 - ad, b0 - g0 - ad) / (ad + 1e-6),
            0.0, 1.0
        ) * luma_gate

        # GOLD ZONE: R > G + gold_delta_r AND G > B + gold_delta_rg
        dr = float(gold_delta_r)
        drg = float(gold_delta_rg)
        gold_gate = _np.clip(
            _np.minimum((r0 - g0 - dr) / (dr + 1e-6),
                        (g0 - b0 - drg) / (drg + 1e-6)),
            0.0, 1.0
        ) * luma_gate

        # Apply azure enrichment
        out_r = _np.clip(r0 - float(azure_r_reduce) * azure_gate, 0.0, 1.0)
        out_g = g0.copy()
        out_b = _np.clip(b0 + float(azure_boost) * azure_gate, 0.0, 1.0)

        # Apply gold enrichment
        out_r = _np.clip(out_r + float(gold_boost_r) * gold_gate, 0.0, 1.0)
        out_g = _np.clip(out_g + float(gold_boost_g) * gold_gate, 0.0, 1.0)
        out_b = _np.clip(out_b - float(gold_b_reduce) * gold_gate, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Pinturicchio jewel azure pass complete.")

    # ── Session 181: random improvement — chromatic_edge_halation_pass
    def chromatic_edge_halation_pass(
            self,
            grad_threshold: float = 0.06,
            bloom_sigma:    float = 4.0,
            bleed_strength: float = 0.20,
            luma_lo:        float = 0.18,
            luma_hi:        float = 0.90,
            opacity:        float = 0.30):
        """
        Chromatic edge halation pass — session 181 random improvement.

        Simulates chromatic halation: the optical phenomenon where bright colour
        zones bleed into adjacent dark areas at form boundaries, as seen in
        Renaissance glazed oil panels where warm flesh or drapery tones subtly
        suffuse the dark background along silhouette edges.

        UNIDIRECTIONAL EDGE COLOUR BLEEDING:
        1. Compute Sobel gradient magnitude on luma → edge map.
        2. Build a BRIGHT-SIDE colour source: pixels above a luma gate carry
           their own colour, weighted by brightness; below the gate they contribute
           nothing (source mask = luma × edge_gate).
        3. Gaussian-blur the bright-side colour source at bloom_sigma — this
           spreads the colour of bright edge pixels into the surrounding dark zone.
        4. At each pixel: inject the blurred bright colour × bleed_strength
           ONLY WHERE the current pixel is DARKER than its neighbourhood colour
           (i.e. only into the dark side of each edge). Gate by luma_gate.

        NOVEL: EIGHTY-THIRD DISTINCT MODE. FIRST pass to apply UNIDIRECTIONAL
        (bright-to-dark) chromatic bleeding at detected edge boundaries: the blurred
        colour source is composed only of bright-side pixels, so the injection is
        inherently one-directional — warm bright flesh/drapery bleeds into adjacent
        dark void/shadow, never the reverse.  All prior edge passes apply either
        BIDIRECTIONAL colour exchange (figure_contour_atmosphere s174 mode 75,
        edge_sfumato_dissolution s158 mode 48) or uniform single-treatment at
        gradient pixels (many others).  This simulates the physical phenomenon of
        glazed oil layers where warm-toned transparent pigment migrates into the
        neighbouring dark imprimatura zone along form silhouettes.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        # Sobel gradient magnitude
        luma_s   = _gf(luma, sigma=1.5)
        gx       = _sobel(luma_s, axis=1)
        gy       = _sobel(luma_s, axis=0)
        grad_mag = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)
        grad_max = grad_mag.max() + 1e-6
        grad_norm = grad_mag / grad_max
        edge_gate = (grad_norm > float(grad_threshold)).astype(_np.float32)

        # Bright-side source: carry colour only for pixels above luma_lo
        lo = float(luma_lo)
        hi = float(luma_hi)
        bright_gate = _np.clip((luma - lo) / (lo + 1e-6), 0.0, 1.0)

        # Weight colour by brightness — bright pixels are the source
        src_r = r0 * bright_gate
        src_g = g0 * bright_gate
        src_b = b0 * bright_gate
        src_w = bright_gate + 1e-6   # weight map for normalisation

        # Gaussian blur the bright colour source at bloom_sigma
        sig = float(bloom_sigma)
        bloom_r = _gf(src_r, sigma=sig)
        bloom_g = _gf(src_g, sigma=sig)
        bloom_b = _gf(src_b, sigma=sig)
        bloom_wt = _gf(src_w, sigma=sig)

        # Normalised blurred colour (the neighbourhood bright colour)
        nb_r = bloom_r / bloom_wt
        nb_g = bloom_g / bloom_wt
        nb_b = bloom_b / bloom_wt

        # Dark-side gate: inject only where current pixel is darker than neighbourhood
        dark_side = _np.clip((nb_r + nb_g + nb_b) / 3.0 - luma, 0.0, 1.0)
        luma_gate = _np.clip((hi - luma) / (hi - lo + 1e-6), 0.0, 1.0)

        combined_gate = dark_side * luma_gate * float(bleed_strength)

        out_r = _np.clip(r0 + (nb_r - r0) * combined_gate, 0.0, 1.0)
        out_g = _np.clip(g0 + (nb_g - g0) * combined_gate, 0.0, 1.0)
        out_b = _np.clip(b0 + (nb_b - b0) * combined_gate, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Chromatic edge halation pass complete.")

    # ── Session 183: artist pass — sirani_contextual_warmth_pass
    def sirani_contextual_warmth_pass(
            self,
            field_sigma:         float = 28.0,
            warm_bias_threshold: float = 0.04,
            warm_r_delta:        float = 0.018,
            warm_g_delta:        float = 0.010,
            warm_b_delta:        float = 0.008,
            opacity:             float = 0.38):
        """
        Sirani contextual warmth pass — session 183 artist pass.

        Simulates the defining quality of Elisabetta Sirani's Bolognese palette:
        the WARM CHROMATIC FIELD that permeates every corner of her canvases —
        a golden Reniesque glow that warms not just the flesh but the entire
        pictorial atmosphere, arising from her warm-ground Bolognese imprimatura
        and golden glazing tradition.

        SPATIAL NEIGHBOURHOOD FIELD WARMTH AMPLIFICATION:
        1. Compute NEIGHBOURHOOD COLOUR FIELD via large-sigma Gaussian blur
           (field_sigma) — this captures the broad chromatic character of the
           surrounding area at scene scale, not local edge/texture detail.
        2. Measure NEIGHBOURHOOD WARMTH as field_r - field_b at each pixel:
           positive → warm-dominant context; negative → cool context.
        3. Build warm_field_gate = clip((field_r - field_b - bias_thresh) /
           bias_thresh, 0, 1) — nonzero only in warm-biased neighbourhoods.
        4. Inject rosy warm lift in warm-field zones:
           out_R = R + warm_r_delta × warm_field_gate
           out_G = G + warm_g_delta × warm_field_gate
           out_B = B - warm_b_delta × warm_field_gate

        NOVEL: EIGHTY-SIXTH DISTINCT MODE. FIRST pass to use SPATIAL NEIGHBOURHOOD
        FIELD WARMTH (large-sigma Gaussian blur → R-B balance of the surrounding
        colour field) as the primary gate — not the pixel's own luminance, saturation,
        hue angle, gradient magnitude, or channel dominance, but the CONTEXTUAL
        WARM-COOL BALANCE of the surrounding colour field at scene scale.
        Prior passes using local spatial aggregation: mode 6 (local std — texture
        detection), mode 63 (HF residual sign — warm/cool bidirectional), mode 72
        (inverse variance — smooth-zone gate), mode 75 (contour figure-atmosphere
        exchange). These all use LOCAL VARIANCE or RESIDUAL measures; this is
        the FIRST to use the MEAN COLOUR DIRECTION of a large neighbourhood zone
        as the gate — simulating the chromatic induction and field-warmth effect
        of painting on a warm Bolognese imprimatura ground.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Large-sigma Gaussian blur to get scene-scale neighbourhood colour field
        sig = float(field_sigma)
        field_r = _gf(r0, sigma=sig)
        field_b = _gf(b0, sigma=sig)

        # Neighbourhood warmth gate: positive in warm-dominant colour field zones
        bias = float(warm_bias_threshold)
        warm_field_gate = _np.clip(
            (field_r - field_b - bias) / (bias + 1e-6),
            0.0, 1.0
        ).astype(_np.float32)

        # Rosy warm lift in warm-field zones
        out_r = _np.clip(r0 + float(warm_r_delta) * warm_field_gate, 0.0, 1.0)
        out_g = _np.clip(g0 + float(warm_g_delta) * warm_field_gate, 0.0, 1.0)
        out_b = _np.clip(b0 - float(warm_b_delta) * warm_field_gate, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Sirani contextual warmth pass complete.")

    # ── Session 183: random improvement — adaptive_tonal_pivot_pass
    def adaptive_tonal_pivot_pass(
            self,
            contrast_strength: float = 0.22,
            sigmoid_slope:     float = 6.0,
            opacity:           float = 0.30):
        """
        Adaptive tonal pivot pass — session 183 random improvement.

        Applies a tonal contrast S-curve centred on the EMPIRICALLY COMPUTED
        MEDIAN of the current canvas luma distribution.  After many artistic
        passes, the image's tonal key may shift (getting slightly flat, or
        compressed into a narrow range).  This pass restores rich tonal contrast
        by amplifying the separation between lights and darks around the image's
        own natural midpoint — not a fixed 0.5 midpoint but the actual median
        of what has been painted so far.

        ADAPTIVE TONAL S-CURVE:
        1. Compute luma = 0.2126R + 0.7152G + 0.0722B.
        2. Compute pivot = median(luma) — the empirical midpoint.
        3. Apply sigmoid S-curve centred on pivot:
           curve = 1 / (1 + exp(-sigmoid_slope × (luma - pivot)))
           This maps [pivot → 0.5] and applies contrast amplification
           symmetrically around pivot.
        4. Compute luma_contrast = lerp(luma, curve, contrast_strength).
        5. Apply luma_contrast / (luma + ε) channel rescaling to preserve hue
           while applying the tonal adjustment equally to R, G, B.

        NOVEL: EIGHTY-SEVENTH DISTINCT MODE. FIRST pass to use ADAPTIVE S-CURVE
        centred on the EMPIRICALLY COMPUTED MEDIAN of the current canvas luma
        distribution.  The sigmoid pivot self-locates at the image's own tonal
        midpoint — adapting to whatever luminosity has been established by all
        prior passes.  Different from: histogram percentile sculpting (mode 7 —
        flattens to fixed percentile bounds, no sigmoid amplification); tonal
        flattening (mode 23 — REDUCES contrast); luminance-gated warm bloom
        (mode 17 — warm injection, not tonal contrast); local block percentile
        contrast (mode 34 — block-wise, not global S-curve); frequency domain
        acuity (mode 73 — spatial frequency domain, not tonal).  This is the
        FIRST genuinely full-canvas global SIGMOID TONE MAPPING with a
        self-locating pivot driven by the current image's empirical median.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        # Empirical pivot: median of current canvas luma
        pivot = float(_np.median(luma))

        # Sigmoid S-curve centred on empirical pivot
        slope = float(sigmoid_slope)
        curve = (1.0 / (1.0 + _np.exp(-slope * (luma - pivot)))).astype(_np.float32)

        # Blend original luma with S-curve output by contrast_strength
        cs = float(contrast_strength)
        luma_contrast = luma * (1.0 - cs) + curve * cs

        # Scale all channels by luma ratio to preserve hue
        ratio = luma_contrast / (luma + 1e-6)

        out_r = _np.clip(r0 * ratio, 0.0, 1.0)
        out_g = _np.clip(g0 * ratio, 0.0, 1.0)
        out_b = _np.clip(b0 * ratio, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Adaptive tonal pivot pass complete.")

    # ── Session 184: Giacomo Ceruti artist pass — ceruti_dignity_shadow_pass ─
    def ceruti_dignity_shadow_pass(
            self,
            shadow_lo:     float = 0.08,
            shadow_hi:     float = 0.42,
            warm_r_delta:  float = 0.018,
            warm_g_delta:  float = 0.010,
            opacity:       float = 0.32):
        """
        Ceruti dignity shadow pass — session 184 artist pass.

        Enriches the INHABITED SHADOW ZONE (luma between shadow_lo and shadow_hi)
        with a gentle warm sienna-amber infusion, replicating Giacomo Ceruti's
        characteristic treatment of darkness as warm and dignified rather than cold
        and theatrical.  In Ceruti's paintings the shadow behind a beggar's shoulder
        is the same earthy sienna as their skin — lighter by degree, not different
        in kind.  This warm shadow continuity creates the sense that figure and
        setting share the same material reality.

        Algorithm:
        1. Compute luma = 0.2126R + 0.7152G + 0.0722B.
        2. Compute zone_mid = (shadow_lo + shadow_hi) / 2.
        3. Compute half_width = (shadow_hi - shadow_lo) / 2.
        4. gate = exp(-0.5 * ((luma - zone_mid) / half_width)^2) — Gaussian bell curve
           centred on the inhabited shadow midpoint; naturally fades to ~0 at both
           zone boundaries and to 0 outside the zone.
        5. Zero the gate outside [shadow_lo, shadow_hi] for numerical clarity.
        6. In gated zone: R += warm_r_delta * gate, G += warm_g_delta * gate.
        7. Blend with original at opacity.

        NOVEL: EIGHTY-EIGHTH DISTINCT MODE. FIRST pass to target the MIDRANGE SHADOW
        ZONE (shadow_lo – shadow_hi) using a GAUSSIAN BELL-CURVE GATE centred on the
        zone midpoint.  Prior modes that gate on shadows use absolute thresholds (e.g.
        "luma < 0.35") with step or linear falloff.  This pass uses a symmetric
        Gaussian bell: maximum effect at the heart of the inhabited shadow, smoothly
        fading to zero at both the void boundary (shadow_lo) and the midtone boundary
        (shadow_hi).  Different from: tenebrism void compression (step gate, near-
        black only), Bolognese arcadian shadow (cool-sky infusion, not warm earthy),
        and all prior luma-threshold passes which gate on one side of the threshold.
        This is the FIRST genuinely DOUBLE-BOUNDARY SYMMETRIC SHADOW GATE.
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        lo    = float(shadow_lo)
        hi    = float(shadow_hi)
        mid   = (lo + hi) * 0.5
        hw    = (hi - lo) * 0.5 + 1e-6  # half-width

        # Gaussian bell-curve gate centred on zone midpoint
        gate = _np.exp(-0.5 * ((luma - mid) / hw) ** 2).astype(_np.float32)
        # Enforce strict zone boundaries
        gate = _np.where((luma >= lo) & (luma <= hi), gate, 0.0).astype(_np.float32)

        # Warm sienna-amber infusion in the inhabited shadow zone
        out_r = _np.clip(r0 + float(warm_r_delta) * gate, 0.0, 1.0)
        out_g = _np.clip(g0 + float(warm_g_delta) * gate, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Ceruti dignity shadow pass complete.")

    # ── Session 184: random improvement — hue_coherence_field_pass ───────────
    def hue_coherence_field_pass(
            self,
            field_sigma:         float = 22.0,
            coherence_boost:     float = 0.15,
            dissonance_suppress: float = 0.10,
            opacity:             float = 0.28):
        """
        Hue coherence field pass — session 184 random improvement.

        Computes the LOCAL DOMINANT HUE of the neighbourhood around each pixel
        via large-sigma Gaussian blur of the chroma unit-vector field, then
        amplifies saturation of pixels whose hue aligns with the local dominant
        hue and gently suppresses saturation of discordant hue outliers.

        This creates LOCAL HUE COHERENCE — the way Old Masters reinforced a
        dominant color in each area: warm zones become more cohesively warm,
        cool zones more cohesively cool, and chromatic outliers are subtly unified
        into the surrounding chromatic field.

        Algorithm (works entirely in RGB space without HSV conversion):
        1. Compute luma L = 0.2126R + 0.7152G + 0.0722B.
        2. Compute chroma deviation: C_r = R - L, C_g = G - L, C_b = B - L.
        3. Compute chroma magnitude C = sqrt(C_r² + C_g² + C_b²) + ε.
        4. Compute pixel hue unit vector: u_r = C_r/C, u_g = C_g/C, u_b = C_b/C.
        5. Apply large-sigma Gaussian blur to u_r, u_g, u_b → field vectors.
        6. Dot product: coherence = u · field_u (ranges ~ [-1, +1]).
           +1 = pixel hue perfectly aligned with local dominant hue.
           -1 = pixel hue perfectly opposed (complementary) to dominant hue.
        7. saturation scale:
             coherence > 0: s_scale = 1 + coherence_boost × coherence
             coherence < 0: s_scale = 1 - dissonance_suppress × (−coherence)
        8. Scale chroma deviation by s_scale, reconstruct RGB from L + scaled chroma.
        9. Blend with original at opacity.

        NOVEL: EIGHTY-NINTH DISTINCT MODE. FIRST pass to use LOCAL DOMINANT HUE
        COHERENCE via CHROMA UNIT-VECTOR GAUSSIAN FIELD as the primary mechanism.
        The hue unit vector (C_r/C, C_g/C, C_b/C) encodes direction in colour space
        without magnitude; blurring this with a large sigma yields the neighbourhood's
        dominant colour direction; the dot product of pixel and field hue vectors
        gives a coherence measure that gates saturation adjustment.  Different from:
        chromatic_split (divisionist complementary dots), chroma_zone_pass (luminance-
        gated saturation), fauvist_mosaic_pass (flat zones), Delacroix coloured
        shadows (complement injection into shadow gate), hue-rotation in Pontormo pass
        (hue shift not coherence gate).  The key novelty is using the DOT PRODUCT of
        normalised chroma vectors as a HUE ALIGNMENT GATE — alignment amplifies
        saturation, misalignment suppresses it.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Step 1: luma
        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # Step 2: chroma deviation
        cr = r0 - luma
        cg = g0 - luma
        cb = b0 - luma

        # Step 3: chroma magnitude
        c_mag = _np.sqrt(cr ** 2 + cg ** 2 + cb ** 2) + 1e-6

        # Step 4: hue unit vector
        ur = cr / c_mag
        ug = cg / c_mag
        ub = cb / c_mag

        # Step 5: Gaussian blur to get local dominant hue field
        sig  = float(field_sigma)
        f_ur = _gf(ur, sigma=sig).astype(_np.float32)
        f_ug = _gf(ug, sigma=sig).astype(_np.float32)
        f_ub = _gf(ub, sigma=sig).astype(_np.float32)

        # Normalise the field vector (blur can shrink magnitude)
        f_mag = _np.sqrt(f_ur ** 2 + f_ug ** 2 + f_ub ** 2) + 1e-6
        f_ur /= f_mag
        f_ug /= f_mag
        f_ub /= f_mag

        # Step 6: dot product (coherence measure)
        coherence = (ur * f_ur + ug * f_ug + ub * f_ub).astype(_np.float32)

        # Step 7: saturation scale factor
        cb_v  = float(coherence_boost)
        ds_v  = float(dissonance_suppress)
        s_scale = _np.where(
            coherence >= 0.0,
            1.0 + cb_v * coherence,
            1.0 - ds_v * (-coherence),
        ).astype(_np.float32)

        # Step 8: scale chroma, reconstruct RGB
        out_r = _np.clip(luma + cr * s_scale, 0.0, 1.0)
        out_g = _np.clip(luma + cg * s_scale, 0.0, 1.0)
        out_b = _np.clip(luma + cb * s_scale, 0.0, 1.0)

        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Hue coherence field pass complete.")

    # ── Pass 90: Fra Galgario — living surface inner luminescence ─────────────
    def fra_galgario_living_surface_pass(
        self,
        glow_lo:    float = 0.35,
        glow_hi:    float = 0.80,
        luma_peak:  float = 0.58,
        half_width: float = 0.20,
        glow_r_lift: float = 0.022,
        glow_g_lift: float = 0.012,
        opacity:    float = 0.30,
    ) -> None:
        """NINETIETH DISTINCT MODE — Fra Galgario living surface inner luminescence.

        Fra Galgario (1655–1743), the 'Rembrandt of Bergamo', achieved a quality
        his contemporaries called 'living surfaces': flesh that appears to glow
        from within rather than merely reflecting light from outside.  This pass
        replicates that inner luminescence effect.

        ALGORITHM:
        1. Compute per-pixel luma: L = 0.2126*R + 0.7152*G + 0.0722*B
        2. Compute Gaussian bell-curve gate centred at luma_peak with half_width:
               gate_raw = exp(-0.5 * ((L - luma_peak) / half_width)^2)
        3. Clamp gate to zero outside the living-surface zone [glow_lo, glow_hi]:
               gate = gate_raw * (L >= glow_lo) * (L <= glow_hi)
        4. Apply warm amber-gold lift in the gated zone:
               R' = R + glow_r_lift * gate
               G' = G + glow_g_lift * gate
               (B unchanged — warmth without cyan contamination)
        5. Blend with original at opacity.

        NOVELTY: First pass to target the MIDTONE-TO-HIGHLIGHT TRANSITION ZONE
        (luma 0.35–0.80) with a Gaussian bell-curve peaked at the midtone-highlight
        junction (luma 0.58) — different from ceruti_dignity_shadow_pass (shadow
        zone luma 0.08–0.42) in that it creates inner luminescence in the upper half
        of the tonal range, where living flesh actually glows.

        Args:
            glow_lo:     Lower luma boundary of the living-surface zone (default 0.35).
            glow_hi:     Upper luma boundary of the living-surface zone (default 0.80).
            luma_peak:   Luma value at which the Gaussian gate peaks (default 0.58).
            half_width:  Gaussian half-width in luma units (default 0.20).
            glow_r_lift: Red channel lift in the gated zone (default 0.022).
            glow_g_lift: Green channel lift in the gated zone (default 0.012).
            opacity:     Blend weight [0, 1] (default 0.30).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # BGRA → float32 [0, 1]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Step 1: luma
        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        # Step 2: Gaussian bell-curve gate centred at luma_peak
        hw   = float(half_width)
        peak = float(luma_peak)
        gate_raw = _np.exp(-0.5 * ((luma - peak) / hw) ** 2).astype(_np.float32)

        # Step 3: clamp gate to living-surface zone [glow_lo, glow_hi]
        lo = float(glow_lo)
        hi = float(glow_hi)
        in_zone = ((luma >= lo) & (luma <= hi)).astype(_np.float32)
        gate = gate_raw * in_zone

        # Step 4: warm amber-gold lift
        r_lift = float(glow_r_lift)
        g_lift = float(glow_g_lift)
        out_r = _np.clip(r0 + r_lift * gate, 0.0, 1.0)
        out_g = _np.clip(g0 + g_lift * gate, 0.0, 1.0)
        # Blue unchanged — warmth without cyan contamination

        # Step 5: blend with original
        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_g = _np.clip(g0 * (1.0 - op) + out_g * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fin_g * 255.0, 0, 255).astype(_np.uint8)
        # buf[:, :, 0] (B) unchanged
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Fra Galgario living surface pass complete.")

    # ── Pass 91: Chromatic temperature field — warm lights, cool shadows ───────
    def chromatic_temperature_field_pass(
        self,
        warm_strength:  float = 0.025,
        cool_strength:  float = 0.020,
        warm_luma_lo:   float = 0.62,
        cool_luma_hi:   float = 0.35,
        transition_width: float = 0.22,
        opacity:        float = 0.28,
    ) -> None:
        """NINETY-FIRST DISTINCT MODE — Warm-lights / cool-shadows colour temperature.

        A fundamental principle of Old Master portrait painting: light zones lean warm
        (towards amber-gold) and shadow zones lean cool (towards blue-grey).  This pass
        implements a smooth, luma-driven colour temperature gradient across the tonal
        range — the warm/cool opposition that gives classical portraits their spatial
        depth and atmospheric life.

        ALGORITHM:
        1. Compute per-pixel luma: L = 0.2126*R + 0.7152*G + 0.0722*B
        2. Warm gate (highlights): linear ramp from 0 at warm_luma_lo to 1 at
               warm_luma_lo + transition_width — clamped to [0, 1].
               Boost R by warm_strength * warm_gate.
        3. Cool gate (shadows): linear ramp from 0 at cool_luma_hi to 1 at
               cool_luma_hi - transition_width — clamped to [0, 1].
               Boost B by cool_strength * cool_gate.
        4. Blend with original at opacity.

        NOVELTY: First pass to implement a DUAL-DIRECTION LUMA-RAMP COLOUR TEMPERATURE
        gradient — applying simultaneous warm push in highlights and cool push in shadows
        via separate linear ramp gates, rather than a single-direction threshold or a
        constant colour overlay.  This creates the fundamental warm/cool opposition of
        classical portrait painting in a single, composable pass.

        Args:
            warm_strength:    R boost in highlight zone (default 0.025).
            cool_strength:    B boost in shadow zone (default 0.020).
            warm_luma_lo:     Luma at which warm ramp begins rising (default 0.62).
            cool_luma_hi:     Luma at which cool ramp begins rising (default 0.35).
            transition_width: Width in luma units for linear ramp (default 0.22).
            opacity:          Blend weight [0, 1] (default 0.28).
        """
        import numpy as _np

        if opacity <= 0.0:
            return

        H, W = self.h, self.w
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape(H, W, 4).copy()

        # BGRA → float32 [0, 1]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Step 1: luma
        luma = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)

        tw = float(transition_width)

        # Step 2: warm gate — linear ramp rising above warm_luma_lo
        wlo = float(warm_luma_lo)
        warm_gate = _np.clip((luma - wlo) / tw, 0.0, 1.0).astype(_np.float32)

        # Step 3: cool gate — linear ramp rising below cool_luma_hi
        chi = float(cool_luma_hi)
        cool_gate = _np.clip((chi - luma) / tw, 0.0, 1.0).astype(_np.float32)

        # Apply temperature shifts
        ws = float(warm_strength)
        cs = float(cool_strength)
        out_r = _np.clip(r0 + ws * warm_gate, 0.0, 1.0)
        out_b = _np.clip(b0 + cs * cool_gate, 0.0, 1.0)
        # Green unchanged — avoids yellow/cyan contamination

        # Step 4: blend with original
        op    = float(opacity)
        fin_r = _np.clip(r0 * (1.0 - op) + out_r * op, 0.0, 1.0)
        fin_b = _np.clip(b0 * (1.0 - op) + out_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fin_r * 255.0, 0, 255).astype(_np.uint8)
        # buf[:, :, 1] (G) unchanged
        buf[:, :, 0] = _np.clip(fin_b * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Chromatic temperature field pass complete.")

    def solario_chromatic_polar_pass(
        self,
        hue_rotate_deg: float = 8.0,
        chroma_boost:   float = 0.15,
        l_lo:           float = 20.0,
        l_hi:           float = 85.0,
        opacity:        float = 0.28,
    ) -> None:
        """
        Session 186 — 93rd mode: Solario CIELAB polar chroma rotation pass.

        Andrea Solario's colour is distinguished by a subtle chromatic warmth
        in the flesh that differs from mere tinting: the entire hue angle of the
        skin rotates toward amber-gold in a way that preserves saturation while
        shifting the chromatic balance.  This is modelled by treating the CIELAB
        (a*, b*) pair as a 2D polar vector and rotating its angle — the first pass
        in this pipeline to apply CIELAB polar hue-angle rotation of the chroma vector.

        The mid-tone L* gate [l_lo, l_hi] restricts the effect to mid-flesh,
        preserving the deep shadow cool and the specular ivory without alteration.
        After rotation, chroma magnitude is boosted by chroma_boost to intensify the
        saturated amber quality.  The modified Lab values are back-converted to sRGB
        via D65 XYZ and blended at opacity.
        """
        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # sRGB uint8 → float32 [0,1]
        b0 = orig[:, :, 0].astype(_np.float64) / 255.0
        g0 = orig[:, :, 1].astype(_np.float64) / 255.0
        r0 = orig[:, :, 2].astype(_np.float64) / 255.0

        # sRGB → linear (IEC 61966-2-1)
        def to_linear(c):
            return _np.where(c <= 0.04045, c / 12.92, ((c + 0.055) / 1.055) ** 2.4)

        rl = to_linear(r0)
        gl = to_linear(g0)
        bl = to_linear(b0)

        # linear sRGB → XYZ D65
        X = rl * 0.4124564 + gl * 0.3575761 + bl * 0.1804375
        Y = rl * 0.2126729 + gl * 0.7151522 + bl * 0.0721750
        Z = rl * 0.0193339 + gl * 0.1191920 + bl * 0.9503041

        # XYZ D65 → CIELAB
        Xn, Yn, Zn = 0.95047, 1.00000, 1.08883

        def f_lab(t):
            delta = 6.0 / 29.0
            return _np.where(t > delta ** 3,
                             t ** (1.0 / 3.0),
                             t / (3.0 * delta ** 2) + 4.0 / 29.0)

        fx = f_lab(X / Xn)
        fy = f_lab(Y / Yn)
        fz = f_lab(Z / Zn)

        L  = 116.0 * fy - 16.0
        a  = 500.0 * (fx - fy)
        b  = 200.0 * (fy - fz)

        # Mid-tone L* bell gate
        l_centre = 0.5 * (l_lo + l_hi)
        l_half   = 0.5 * (l_hi - l_lo)
        gate = _np.clip(1.0 - _np.abs(L - l_centre) / (l_half + 1e-6), 0.0, 1.0).astype(_np.float64)

        # Polar rotation of (a*, b*) chroma vector
        theta    = _np.deg2rad(hue_rotate_deg)
        cos_t, sin_t = _np.cos(theta), _np.sin(theta)
        a_rot = a * cos_t - b * sin_t
        b_rot = a * sin_t + b * cos_t

        # Chroma boost
        chroma_in  = _np.sqrt(a     ** 2 + b     ** 2)
        chroma_out = _np.sqrt(a_rot ** 2 + b_rot ** 2)
        scale = _np.where(chroma_out > 1e-6,
                          (chroma_in * (1.0 + chroma_boost)) / (chroma_out + 1e-6),
                          1.0)
        a_new = a + gate * (a_rot * scale - a)
        b_new = b + gate * (b_rot * scale - b)

        # CIELAB → XYZ D65
        fy2 = (L + 16.0) / 116.0
        fx2 = a_new / 500.0 + fy2
        fz2 = fy2 - b_new / 200.0

        def f_inv(t):
            delta = 6.0 / 29.0
            return _np.where(t > delta,
                             t ** 3,
                             3.0 * delta ** 2 * (t - 4.0 / 29.0))

        X2 = Xn * f_inv(fx2)
        Y2 = Yn * f_inv(fy2)
        Z2 = Zn * f_inv(fz2)

        # XYZ D65 → linear sRGB
        rl2 = _np.clip( 3.2404542 * X2 - 1.5371385 * Y2 - 0.4985314 * Z2, 0.0, 1.0)
        gl2 = _np.clip(-0.9692660 * X2 + 1.8760108 * Y2 + 0.0415560 * Z2, 0.0, 1.0)
        bl2 = _np.clip( 0.0556434 * X2 - 0.2040259 * Y2 + 1.0572252 * Z2, 0.0, 1.0)

        # linear → sRGB
        def to_srgb(c):
            return _np.where(c <= 0.0031308, 12.92 * c, 1.055 * c ** (1.0 / 2.4) - 0.055)

        r2 = _np.clip(to_srgb(rl2), 0.0, 1.0)
        g2 = _np.clip(to_srgb(gl2), 0.0, 1.0)
        b2 = _np.clip(to_srgb(bl2), 0.0, 1.0)

        # Blend at opacity
        op  = float(opacity)
        fr  = (r0 * (1.0 - op) + r2 * op).astype(_np.float32)
        fg  = (g0 * (1.0 - op) + g2 * op).astype(_np.float32)
        fb  = (b0 * (1.0 - op) + b2 * op).astype(_np.float32)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fr * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fg * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fb * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Solario chromatic polar pass complete.")

    def local_statistical_harmony_pass(
        self,
        sigma:            float = 12.0,
        harmony_strength: float = 0.18,
        luma_lo:          float = 0.12,
        luma_hi:          float = 0.88,
        opacity:          float = 0.26,
    ) -> None:
        """
        Session 186 random improvement — Local Gaussian mean-pull regional colour
        harmonization pass.

        Regional colour harmony is a property observed in Solario and other Lombard
        painters: large areas of the canvas exhibit a subtle tonal-chromatic unity,
        as if each region shares a common colour memory.  This is consistent with
        the 17th-century technique of mixing a unifying tint into each working area
        before adding local colour — a practice that creates inter-regional
        chromatic coherence.

        This pass models that effect via local Gaussian mean-pull: for each pixel
        and each channel, the spatial mean in a Gaussian neighbourhood (sigma px)
        is computed via scipy.ndimage.gaussian_filter.  The pixel is gently drawn
        toward its local average by harmony_strength.  A luma bell-gate [luma_lo,
        luma_hi] restricts the effect to mid-range values, preserving the deep
        shadow core and specular highlights.

        This is the first pass in this pipeline to use LOCAL GAUSSIAN MEAN-PULL
        for per-pixel adaptive regional colour harmonization.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Luma bell gate
        luma       = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0
        l_centre   = 0.5 * (luma_lo + luma_hi)
        l_half     = 0.5 * (luma_hi - luma_lo)
        gate       = _np.clip(1.0 - _np.abs(luma - l_centre) / (l_half + 1e-6),
                               0.0, 1.0).astype(_np.float32)

        sig = float(sigma)
        hs  = float(harmony_strength)

        # Per-channel local mean pull
        r_mean = _gf(r0, sig).astype(_np.float32)
        g_mean = _gf(g0, sig).astype(_np.float32)
        b_mean = _gf(b0, sig).astype(_np.float32)

        r_harm = r0 + (r_mean - r0) * hs * gate
        g_harm = g0 + (g_mean - g0) * hs * gate
        b_harm = b0 + (b_mean - b0) * hs * gate

        # Blend at opacity
        op  = float(opacity)
        fr  = _np.clip(r0 * (1.0 - op) + r_harm * op, 0.0, 1.0)
        fg  = _np.clip(g0 * (1.0 - op) + g_harm * op, 0.0, 1.0)
        fb  = _np.clip(b0 * (1.0 - op) + b_harm * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fr * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fg * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fb * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Local statistical harmony pass complete.")

    def de_predis_crystalline_clarity_pass(
        self,
        sharp_sigma:    float = 1.5,
        sharp_strength: float = 0.30,
        cool_r_shift:   float = -0.010,
        cool_b_shift:   float = 0.015,
        luma_lo:        float = 0.35,
        luma_hi:        float = 0.85,
        opacity:        float = 0.25,
    ) -> None:
        """
        Session 187 artist pass — NINETY-FOURTH DISTINCT MODE.

        De Predis Crystalline Clarity Pass: precision unsharp-mask in the
        mid-to-bright luma range with a cool-silver chromatic tint on the
        detected edge zones.

        Ambrogio de Predis (c. 1455–after 1508), Leonardo's closest Milanese
        court collaborator, achieved a crystalline metallic precision within
        sfumato: the broad passages are as smoothly blended as Leonardo's, but
        key structural transitions (chin edge, nose boundary, forehead–hairline)
        retain a faint, jewel-like sharpness.  His top highlights carry a
        cool-silver tint — a subtle blue-grey shift entirely absent from
        Leonardo's warm ivory highlights — producing an enamelled, metallic
        reading unique among the Milanese sfumato painters.

        This pass implements that effect:
          1. USM sharpening: for each pixel in the luma gate [luma_lo, luma_hi],
             compute the unsharp residual (orig – Gaussian_blur(orig, sharp_sigma))
             and add sharp_strength × residual to the pixel.
          2. Edge detection: the unsharp residual magnitude identifies
             transitional boundary pixels.
          3. Cool-silver tint: at boundary pixels (high residual magnitude),
             apply cool_r_shift to R (reduces warmth) and cool_b_shift to B
             (adds silver-cool), producing the characteristic de Predis
             metallic highlight cast.

        NOVEL: FIRST pass in this pipeline to combine UNSHARP-MASK SHARPENING
        with a COOL-SILVER CHROMATIC TINT on detected edge zones — distinct from
        all prior passes that either sharpen without chromatic shift or apply
        chromatic shifts without structural sharpening.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Luma gate — restrict to mid-to-bright zone
        luma  = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0
        l_ctr = 0.5 * (luma_lo + luma_hi)
        l_hw  = 0.5 * (luma_hi - luma_lo)
        gate  = _np.clip(1.0 - _np.abs(luma - l_ctr) / (l_hw + 1e-6),
                         0.0, 1.0).astype(_np.float32)

        sig = float(sharp_sigma)

        # Gaussian-blurred versions for USM
        r_blur = _gf(r0, sig).astype(_np.float32)
        g_blur = _gf(g0, sig).astype(_np.float32)
        b_blur = _gf(b0, sig).astype(_np.float32)

        # Unsharp residuals
        r_res = (r0 - r_blur)
        g_res = (g0 - g_blur)
        b_res = (b0 - b_blur)

        ss = float(sharp_strength)

        # Sharpened channels (USM)
        r_sharp = r0 + ss * r_res * gate
        g_sharp = g0 + ss * g_res * gate
        b_sharp = b0 + ss * b_res * gate

        # Edge magnitude from residual — normalised to [0, 1]
        edge_mag = _np.sqrt(r_res**2 + g_res**2 + b_res**2)
        edge_mag_max = edge_mag.max()
        if edge_mag_max > 1e-8:
            edge_mag = edge_mag / edge_mag_max
        edge_gate = (edge_mag * gate).astype(_np.float32)

        # Cool-silver tint: at edge zones, shift R down and B up
        r_tint = r_sharp + float(cool_r_shift) * edge_gate
        g_tint = g_sharp                                       # G unchanged
        b_tint = b_sharp + float(cool_b_shift) * edge_gate

        r_tint = _np.clip(r_tint, 0.0, 1.0)
        g_tint = _np.clip(g_tint, 0.0, 1.0)
        b_tint = _np.clip(b_tint, 0.0, 1.0)

        # Blend at opacity
        op = float(opacity)
        fr = _np.clip(r0 * (1.0 - op) + r_tint * op, 0.0, 1.0)
        fg = _np.clip(g0 * (1.0 - op) + g_tint * op, 0.0, 1.0)
        fb = _np.clip(b0 * (1.0 - op) + b_tint * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fr * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fg * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fb * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    De Predis crystalline clarity pass complete.")

    def luminous_midtone_lift_pass(
        self,
        mid_lo:  float = 0.30,
        mid_hi:  float = 0.68,
        lift_r:  float = 0.022,
        lift_g:  float = 0.012,
        lift_b:  float = 0.004,
        opacity: float = 0.24,
    ) -> None:
        """
        Session 187 random improvement — Luminous Midtone Lift Pass.

        Selectively lifts the luma of pixels in the midtone zone [mid_lo, mid_hi]
        with a warm bell-curve gate, adding lift_r to R, lift_g to G, and
        lift_b to B in the gated region.

        This models the Old Master practice of loading maximum luminosity into
        the mid-value register: when the midtone zone is the brightest region of
        the tonal scale (relative to expectation), forms appear self-illuminated
        rather than merely reflecting surface light.  The effect is a subtle
        warming and brightening of the compositional mid-register — the zone
        where flesh typically lives in a well-lit sfumato portrait.

        A Gaussian bell-curve gate centred at the midpoint of [mid_lo, mid_hi]
        ensures smooth transitions at both boundaries, preventing tonal banding
        at the gate edges.

        NOVEL: FIRST pass to use WARM BELL-CURVE LUMINANCE LIFT exclusively
        targeting the MIDTONE REGISTER — distinct from fra_galgario_living_
        surface_pass (which targets the midtone-to-highlight transition zone
        luma 0.35–0.80 with an asymmetric Gaussian peak at 0.58) in that it
        applies a symmetric lift across the full midtone band without a
        specific highlight-approach transition.
        """
        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Symmetric bell-curve gate centred at midpoint of [mid_lo, mid_hi]
        luma   = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0
        m_ctr  = 0.5 * (mid_lo + mid_hi)
        m_hw   = 0.5 * (mid_hi - mid_lo)
        gate   = _np.clip(1.0 - _np.abs(luma - m_ctr) / (m_hw + 1e-6),
                          0.0, 1.0).astype(_np.float32)

        # Warm lift in gated zone
        r_lift = _np.clip(r0 + float(lift_r) * gate, 0.0, 1.0)
        g_lift = _np.clip(g0 + float(lift_g) * gate, 0.0, 1.0)
        b_lift = _np.clip(b0 + float(lift_b) * gate, 0.0, 1.0)

        # Blend at opacity
        op = float(opacity)
        fr = _np.clip(r0 * (1.0 - op) + r_lift * op, 0.0, 1.0)
        fg = _np.clip(g0 * (1.0 - op) + g_lift * op, 0.0, 1.0)
        fb = _np.clip(b0 * (1.0 - op) + b_lift * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fr * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fg * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fb * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Luminous midtone lift pass complete.")

    def corinth_stroke_velocity_field_pass(
        self,
        detail_sigma_fine:   float = 1.2,
        detail_sigma_coarse: float = 4.0,
        sharpen_strength:    float = 0.28,
        mag_gate_thresh:     float = 0.04,
        luma_lo:             float = 0.10,
        luma_hi:             float = 0.90,
        opacity:             float = 0.28,
    ) -> None:
        """
        Session 187 parallel — 95th mode: Corinth gradient-magnitude-weighted
        band-pass detail enhancement pass.

        Lovis Corinth's impasto creates a characteristic optical effect: impasto
        ridges catch oblique light, creating intense local contrast at tonal
        transitions.  The paint surface carries kinetic energy — the stroke direction
        and loading are visible in high-frequency detail concentrated precisely where
        the light/shadow boundaries run.

        This pass models that effect by:
        1. Computing per-channel band-pass detail (fine Gaussian minus coarse Gaussian)
           which isolates the medium-frequency edge structure at the impasto-ridge scale.
        2. Weighting the detail injection by the LOCAL GRADIENT MAGNITUDE of luma —
           so sharpening is strongest exactly at tonal transitions, mimicking impasto
           ridges.  Flat areas are unaffected; edges are amplified.
        3. A luma bell-gate [luma_lo, luma_hi] preserves deep shadow voids and blown
           specular peaks without alteration.

        This is the FIRST pass in this pipeline to combine BAND-PASS DETAIL EXTRACTION
        with GRADIENT-MAGNITUDE GATING — all prior sharpening passes use isotropic
        Gaussian kernels without gradient-magnitude weighting.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Luma bell gate — preserve shadows and specular peaks
        luma       = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0
        l_centre   = 0.5 * (luma_lo + luma_hi)
        l_half     = 0.5 * (luma_hi - luma_lo)
        luma_gate  = _np.clip(1.0 - _np.abs(luma - l_centre) / (l_half + 1e-6),
                               0.0, 1.0).astype(_np.float32)

        # Gradient magnitude of luma — highest at tonal transitions (impasto ridge zones)
        luma_fine   = _gf(luma, float(detail_sigma_fine)).astype(_np.float32)
        gx          = _np.gradient(luma_fine, axis=1).astype(_np.float32)
        gy          = _np.gradient(luma_fine, axis=0).astype(_np.float32)
        grad_mag    = _np.sqrt(gx ** 2 + gy ** 2)
        # Normalize gradient weight: saturates to 1 at strong edges
        mag_weight  = grad_mag / (grad_mag + float(mag_gate_thresh) + 1e-6)
        mag_weight  = mag_weight.astype(_np.float32)

        # Band-pass detail per channel: fine scale minus coarse scale
        ss = float(sharpen_strength)

        def enhance(c):
            fine   = _gf(c, float(detail_sigma_fine)).astype(_np.float32)
            coarse = _gf(c, float(detail_sigma_coarse)).astype(_np.float32)
            detail = fine - coarse          # mid-frequency edge detail
            return c + ss * detail * mag_weight * luma_gate

        r_enh = _np.clip(enhance(r0), 0.0, 1.0)
        g_enh = _np.clip(enhance(g0), 0.0, 1.0)
        b_enh = _np.clip(enhance(b0), 0.0, 1.0)

        # Blend at opacity
        op  = float(opacity)
        fr  = r0 * (1.0 - op) + r_enh * op
        fg  = g0 * (1.0 - op) + g_enh * op
        fb  = b0 * (1.0 - op) + b_enh * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(fr * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(fg * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(fb * 255.0, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Corinth stroke velocity field pass complete.")

    def morandi_tonal_unity_pass(
        self,
        ab_sigma:             float = 14.0,
        convergence_strength: float = 0.58,
        luma_lo:              float = 0.06,
        luma_hi:              float = 0.94,
        opacity:              float = 0.55,
    ) -> None:
        """
        Session 188 — 96th distinct mode: Morandi CIELAB-space chrominance convergence.

        Giorgio Morandi's defining achievement: ALL OBJECTS IN A COMPOSITION breathe
        the same dusty, chalky atmosphere.  His bottles, jugs, and cans are painted
        not as individual chromatic identities but as members of a single tonal
        community — their hues uniformly drawn toward a shared dusty mid-grey.

        This pass achieves that quality by performing CHROMINANCE-ONLY spatial
        convergence in CIELAB colour space:
        1. Convert the canvas from BGR to linear RGB to CIELAB (L*, a*, b*).
        2. Apply a Gaussian blur to the a* and b* channels ONLY — not L*.
        3. Pull each pixel's chrominance toward its blurred neighbourhood mean at
           ``convergence_strength`` (0 = original, 1 = fully converged to mean).
        4. Leave L* mathematically unchanged — the value drawing that describes
           form is perfectly preserved.
        5. A luma gate [luma_lo, luma_hi] on the original luminance preserves
           deep-shadow blacks and specular whites unaltered.
        6. Reconstruct RGB from modified L*, a*, b* and composite at opacity.

        NOVEL: NINETY-SIXTH DISTINCT MODE.  FIRST pass in this pipeline to operate
        exclusively on CIELAB chrominance channels (a*, b*) while leaving L*
        (luminance) MATHEMATICALLY UNCHANGED.  Prior spatial convergence passes
        (including local_statistical_harmony, session 186) operate on all three
        RGB channels simultaneously, which implicitly shifts luminance.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo stores BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # sRGB → linear RGB
        def _lin(c):
            return _np.where(c <= 0.04045,
                             c / 12.92,
                             ((c + 0.055) / 1.055) ** 2.4)

        rl = _lin(r0).astype(_np.float32)
        gl = _lin(g0).astype(_np.float32)
        bl = _lin(b0).astype(_np.float32)

        # Linear RGB → XYZ (D65 illuminant)
        X = (0.4124564 * rl + 0.3575761 * gl + 0.1804375 * bl).astype(_np.float32)
        Y = (0.2126729 * rl + 0.7151522 * gl + 0.0721750 * bl).astype(_np.float32)
        Z = (0.0193339 * rl + 0.1191920 * gl + 0.9503041 * bl).astype(_np.float32)

        # XYZ → CIELAB (D65 white point: Xn=0.95047, Yn=1.00000, Zn=1.08883)
        def _f_lab(t):
            delta = 6.0 / 29.0
            return _np.where(t > delta ** 3,
                             t ** (1.0 / 3.0),
                             t / (3.0 * delta ** 2) + 4.0 / 29.0)

        fx = _f_lab(X / 0.95047).astype(_np.float32)
        fy = _f_lab(Y / 1.00000).astype(_np.float32)
        fz = _f_lab(Z / 1.08883).astype(_np.float32)

        L_star = (116.0 * fy - 16.0).astype(_np.float32)
        a_star = (500.0 * (fx - fy)).astype(_np.float32)
        b_star = (200.0 * (fy - fz)).astype(_np.float32)

        # Luma gate on original sRGB luminance
        luma_m = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)
        half_band_m = 0.5 * (float(luma_hi) - float(luma_lo))
        gate_m = _np.clip(
            _np.minimum(luma_m - float(luma_lo), float(luma_hi) - luma_m) /
            (half_band_m + 1e-6),
            0.0, 1.0
        ).astype(_np.float32)

        # Gaussian-blur only the chrominance channels (a*, b*)
        sig = float(ab_sigma)
        a_blur = _gf(a_star, sig).astype(_np.float32)
        b_blur = _gf(b_star, sig).astype(_np.float32)

        cs = float(convergence_strength)
        a_new = (a_star + cs * (a_blur - a_star) * gate_m).astype(_np.float32)
        b_new = (b_star + cs * (b_blur - b_star) * gate_m).astype(_np.float32)

        # CIELAB → XYZ (L_star is unchanged — luminance preserved exactly)
        def _f_inv_lab(t):
            delta = 6.0 / 29.0
            return _np.where(t > delta,
                             t ** 3,
                             3.0 * delta ** 2 * (t - 4.0 / 29.0))

        fy2 = ((L_star + 16.0) / 116.0).astype(_np.float32)
        fx2 = (a_new / 500.0 + fy2).astype(_np.float32)
        fz2 = (fy2 - b_new / 200.0).astype(_np.float32)

        X2 = (0.95047 * _f_inv_lab(fx2)).astype(_np.float32)
        Y2 = (1.00000 * _f_inv_lab(fy2)).astype(_np.float32)
        Z2 = (1.08883 * _f_inv_lab(fz2)).astype(_np.float32)

        # XYZ → linear RGB (D65)
        rl2 = ( 3.2404542 * X2 - 1.5371385 * Y2 - 0.4985314 * Z2).astype(_np.float32)
        gl2 = (-0.9692660 * X2 + 1.8760108 * Y2 + 0.0415560 * Z2).astype(_np.float32)
        bl2 = ( 0.0556434 * X2 - 0.2040259 * Y2 + 1.0572252 * Z2).astype(_np.float32)

        # Linear RGB → sRGB gamma
        def _gam(c):
            c = _np.clip(c, 0.0, None)
            return _np.where(c <= 0.0031308,
                             12.92 * c,
                             1.055 * c ** (1.0 / 2.4) - 0.055)

        r2 = _np.clip(_gam(rl2), 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(_gam(gl2), 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(_gam(bl2), 0.0, 1.0).astype(_np.float32)

        # Composite at opacity
        op_m = float(opacity)
        fr_m = r0 * (1.0 - op_m) + r2 * op_m
        fg_m = g0 * (1.0 - op_m) + g2 * op_m
        fb_m = b0 * (1.0 - op_m) + b2 * op_m

        buf_m = orig.copy()
        buf_m[:, :, 2] = _np.clip(fr_m * 255.0, 0, 255).astype(_np.uint8)
        buf_m[:, :, 1] = _np.clip(fg_m * 255.0, 0, 255).astype(_np.uint8)
        buf_m[:, :, 0] = _np.clip(fb_m * 255.0, 0, 255).astype(_np.uint8)
        buf_m[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf_m.tobytes()
        self.canvas.surface.mark_dirty()

    def palette_proximity_pull_pass(
        self,
        palette:       list  = None,
        pull_strength: float = 0.20,
        luma_lo:       float = 0.05,
        luma_hi:       float = 0.95,
        opacity:       float = 0.30,
    ) -> None:
        """
        Session 188 — 97th distinct mode: palette-nearest-neighbor gravity.

        The Old Masters deliberately limited their pigment selection to a pre-mixed
        set of tints, forcing every area of the canvas to be expressible as a
        combination from that restricted set.  This creates a powerful chromatic
        unity: every object, no matter how different its local hue, is pulled
        toward the same pigment family.

        This pass models that practice as SOFT PALETTE GRAVITY:
        1. For each pixel, compute the Euclidean distance (in RGB space) to every
           colour in the provided ``palette`` list.
        2. Find the nearest palette colour per pixel (vectorised, no Python loop).
        3. Pull the pixel toward that nearest colour at ``pull_strength``:
           ``new_pixel = pixel + pull_strength * (nearest_palette - pixel)``
        4. A luma gate [luma_lo, luma_hi] leaves very dark shadows and bright
           specular peaks unaffected.
        5. Composite the result at ``opacity``.

        At pull_strength=1.0 the pass hard-snaps to the palette (posterization).
        At pull_strength=0.15–0.25 it creates a subtle chromatic coherence that
        reads as intentional palette discipline.

        NOVEL: NINETY-SEVENTH DISTINCT MODE.  FIRST pass in this pipeline to
        compute NEAREST-PALETTE-NEIGHBOUR per pixel and attract toward it.  All
        prior colorisation passes use linear transforms, fixed tints, Gaussian
        spatial means, or directional chromatic shifts — none implement per-pixel
        soft quantization toward a discrete artist palette set.

        Default palette is Morandi's dust-muted still-life set.
        """
        import numpy as _np

        if palette is None:
            palette = [
                (0.90, 0.88, 0.83),   # dusty chalk-white
                (0.72, 0.70, 0.66),   # ash grey
                (0.65, 0.60, 0.50),   # warm ochre-grey
                (0.55, 0.57, 0.48),   # dusty sage
                (0.58, 0.62, 0.66),   # pale blue-grey
                (0.68, 0.52, 0.38),   # dusty sienna
                (0.42, 0.36, 0.28),   # warm earth-brown
                (0.60, 0.58, 0.56),   # neutral mid-grey
            ]

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo BGRA layout
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Luma gate
        luma_p = (0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0).astype(_np.float32)
        half_band_p = 0.5 * (float(luma_hi) - float(luma_lo))
        gate_p = _np.clip(
            _np.minimum(luma_p - float(luma_lo), float(luma_hi) - luma_p) /
            (half_band_p + 1e-6),
            0.0, 1.0
        ).astype(_np.float32)

        # Palette array (N, 3) in RGB order
        pal = _np.array(palette, dtype=_np.float32)  # (N, 3)

        # Vectorised nearest-palette-colour search: (H, W, 1, 3) vs (1, 1, N, 3)
        pixels_p = _np.stack([r0, g0, b0], axis=-1)[:, :, _np.newaxis, :]  # (H, W, 1, 3)
        pal_bc   = pal[_np.newaxis, _np.newaxis, :, :]                      # (1, 1, N, 3)
        dist2    = _np.sum((pixels_p - pal_bc) ** 2, axis=-1)               # (H, W, N)
        nearest_idx = _np.argmin(dist2, axis=-1)                            # (H, W)
        nearest = pal[nearest_idx]                                           # (H, W, 3)

        pr = nearest[:, :, 0]
        pg = nearest[:, :, 1]
        pb = nearest[:, :, 2]

        # Attract toward nearest palette colour, gated by luma
        ps = float(pull_strength)
        r2 = _np.clip(r0 + ps * (pr - r0) * gate_p, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g0 + ps * (pg - g0) * gate_p, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b0 + ps * (pb - b0) * gate_p, 0.0, 1.0).astype(_np.float32)

        # Composite at opacity
        op_p = float(opacity)
        fr_p = r0 * (1.0 - op_p) + r2 * op_p
        fg_p = g0 * (1.0 - op_p) + g2 * op_p
        fb_p = b0 * (1.0 - op_p) + b2 * op_p

        buf_p = orig.copy()
        buf_p[:, :, 2] = _np.clip(fr_p * 255.0, 0, 255).astype(_np.uint8)
        buf_p[:, :, 1] = _np.clip(fg_p * 255.0, 0, 255).astype(_np.uint8)
        buf_p[:, :, 0] = _np.clip(fb_p * 255.0, 0, 255).astype(_np.uint8)
        buf_p[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf_p.tobytes()
        self.canvas.surface.mark_dirty()

    def meso_detail_pass(
        self,
        detail_sigma_fine:   float = 0.8,
        detail_sigma_coarse: float = 3.5,
        strength:            float = 0.35,
        luma_lo:             float = 0.08,
        luma_hi:             float = 0.92,
        opacity:             float = 0.35,
    ) -> None:
        """
        Session 188 — meso-scale detail pass (96th mode).

        Targets the 0.5–3 px frequency band: larger than pores, smaller than
        form-defining strokes — the texture register that reads as 'painted
        material' at arm's length.  Meso-detail is what distinguishes a softly-lit
        oil surface from a photograph: the slight variance in paint loading at
        medium scale.

        Band-pass extraction (fine Gaussian minus coarse Gaussian) isolated in
        the mid-tone luma register via bell gate [luma_lo, luma_hi].
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma      = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0
        l_centre  = 0.5 * (luma_lo + luma_hi)
        l_half    = 0.5 * (luma_hi - luma_lo) + 1e-6
        luma_gate = _np.clip(1.0 - _np.abs(luma - l_centre) / l_half, 0.0, 1.0)

        def enhance(c):
            fine   = _gf(c, float(detail_sigma_fine)).astype(_np.float32)
            coarse = _gf(c, float(detail_sigma_coarse)).astype(_np.float32)
            return c + float(strength) * (fine - coarse) * luma_gate

        r_e = _np.clip(enhance(r0), 0.0, 1.0)
        g_e = _np.clip(enhance(g0), 0.0, 1.0)
        b_e = _np.clip(enhance(b0), 0.0, 1.0)
        op  = float(opacity)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r_e * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g_e * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b_e * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Meso-detail pass complete.")

    def canvas_grain_pass(
        self,
        noise_scale:    float = 1.2,
        noise_strength: float = 0.025,
        sharpness:      float = 0.18,
        luma_lo:        float = 0.10,
        luma_hi:        float = 0.88,
        opacity:        float = 0.28,
    ) -> None:
        """
        Session 188 — canvas grain pass (97th mode).

        Injects sub-pixel surface texture: the grain of the paint film, canvas
        tooth, and pore-scale variation that makes painted surfaces tactile.
        Targets the 0–1 px frequency band.

        Combines:
        1. Noise texture: Gaussian-filtered random field at noise_scale sigma.
        2. Micro-sharpening: unsharp mask at very fine scale (sigma=0.5).
        Both modulated by luma bell gate to preserve shadow / highlight purity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma      = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0
        l_centre  = 0.5 * (luma_lo + luma_hi)
        l_half    = 0.5 * (luma_hi - luma_lo) + 1e-6
        luma_gate = _np.clip(1.0 - _np.abs(luma - l_centre) / l_half, 0.0, 1.0)

        rng   = _np.random.default_rng(42)
        noise = rng.standard_normal((H, W)).astype(_np.float32)
        noise = _gf(noise, sigma=float(noise_scale))
        noise = noise / (noise.std() + 1e-8) * float(noise_strength) * luma_gate

        def sharpen(c):
            blurred = _gf(c, sigma=0.5).astype(_np.float32)
            return c + float(sharpness) * (c - blurred) * luma_gate

        r_e = _np.clip(sharpen(r0) + noise * 0.6, 0.0, 1.0)
        g_e = _np.clip(sharpen(g0) + noise * 0.4, 0.0, 1.0)
        b_e = _np.clip(sharpen(b0) + noise * 0.2, 0.0, 1.0)
        op  = float(opacity)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r_e * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g_e * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b_e * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Canvas grain pass complete.")

    def edge_definition_pass(
        self,
        edge_sigma:     float = 0.8,
        strength:       float = 0.40,
        soft_threshold: float = 0.05,
        luma_lo:        float = 0.05,
        luma_hi:        float = 0.95,
        opacity:        float = 0.30,
    ) -> None:
        """
        Session 188 — edge definition pass (98th mode).

        Clarifies boundaries between forms — head vs background, eye vs skin,
        feather edge vs sky — using a gradient-magnitude-gated unsharp mask.

        The soft_threshold parameter implements lost-and-found edge control:
        only fires where luma gradient magnitude exceeds soft_threshold, so
        flat regions (no gradient) are never sharpened. This prevents halos
        in smooth passages while crisping genuine contour lines.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma      = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0
        l_centre  = 0.5 * (luma_lo + luma_hi)
        l_half    = 0.5 * (luma_hi - luma_lo) + 1e-6
        luma_gate = _np.clip(1.0 - _np.abs(luma - l_centre) / l_half, 0.0, 1.0)

        gx = _np.gradient(luma, axis=1).astype(_np.float32)
        gy = _np.gradient(luma, axis=0).astype(_np.float32)
        grad_mag  = _np.sqrt(gx ** 2 + gy ** 2)
        edge_gate = _np.clip(
            (grad_mag - float(soft_threshold)) / (float(soft_threshold) + 1e-6),
            0.0, 1.0,
        )
        combined_gate = luma_gate * edge_gate

        def sharpen(c):
            blurred = _gf(c, sigma=float(edge_sigma)).astype(_np.float32)
            return c + float(strength) * (c - blurred) * combined_gate

        r_e = _np.clip(sharpen(r0), 0.0, 1.0)
        g_e = _np.clip(sharpen(g0), 0.0, 1.0)
        b_e = _np.clip(sharpen(b0), 0.0, 1.0)
        op  = float(opacity)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r_e * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g_e * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b_e * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Edge definition pass complete.")

    def beksinski_dystopian_atmosphere_pass(
        self,
        ash_pull:       float = 0.35,
        shadow_deepen:  float = 0.28,
        ember_glow:     float = 0.18,
        grain_strength: float = 0.018,
        opacity:        float = 0.40,
    ) -> None:
        """
        Session 189 — Beksiński dystopian atmosphere pass (99th distinct mode).

        Recreates the oppressive ashen void that defines Zdzisław Beksiński's
        dystopian surrealism: chrominance is desaturated toward a cold ash neutral,
        shadow zones are deepened independently, and deep-shadow regions receive a
        subtle ember-warm underpainted glow (the dark imprimatura showing through
        thin paint).  Organic grain completes the geological surface quality.

        ash_pull      : strength of per-pixel desaturation pull toward ash grey
        shadow_deepen : extra multiplicative darkening applied where luma < 0.40
        ember_glow    : warm red-orange additive bloom injected where luma < 0.20
        grain_strength: amplitude of Beksiński's obsessive micro-texture noise
        opacity       : final composite opacity

        NOVEL: NINETY-NINTH DISTINCT MODE.  FIRST pass to simultaneously apply
        CHROMINANCE DESATURATION, SHADOW-ZONE DARKENING, and EMBER GLOW in a
        single pixel operation — distinct from all prior passes which address
        these operations separately.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # 1. Desaturate toward cold ash neutral (0.50, 0.49, 0.47)
        ash_r, ash_g, ash_b = 0.50, 0.49, 0.47
        ap = float(ash_pull)
        r1 = r0 + ap * (ash_r - r0)
        g1 = g0 + ap * (ash_g - g0)
        b1 = b0 + ap * (ash_b - b0)

        # 2. Deepen shadows: multiplicative darkening where luma < 0.40
        sd = float(shadow_deepen)
        shadow_gate = _np.clip(1.0 - luma / 0.40, 0.0, 1.0)
        shadow_factor = 1.0 - sd * shadow_gate
        r1 = r1 * shadow_factor
        g1 = g1 * shadow_factor
        b1 = b1 * shadow_factor

        # 3. Ember glow in deepest shadow (luma < 0.20): warm red-orange bloom
        eg = float(ember_glow)
        ember_gate = _np.clip(1.0 - luma / 0.20, 0.0, 1.0) ** 2
        r1 = r1 + eg * ember_gate * 0.70   # warm red
        g1 = g1 + eg * ember_gate * 0.18   # faint orange component
        b1 = b1 + eg * ember_gate * 0.02   # almost no blue

        # 4. Organic grain: smoothed noise for the obsessive micro-texture
        gs = float(grain_strength)
        rng   = _np.random.default_rng(189)
        noise = rng.standard_normal((H, W)).astype(_np.float32)
        noise = _gf(noise, sigma=0.7) * gs
        r1 = r1 + noise
        g1 = g1 + noise * 0.85
        b1 = b1 + noise * 0.70

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Beksiński dystopian atmosphere pass complete.")

    def imprimatura_reveal_pass(
        self,
        ground_color:     tuple = (0.55, 0.47, 0.30),
        reveal_strength:  float = 0.30,
        thin_paint_luma:  float = 0.45,
        opacity:          float = 0.25,
    ) -> None:
        """
        Session 189 — imprimatura reveal pass (100th distinct mode).

        Simulates the old-master technique of toned-ground revelation: where paint
        is thinly applied, the warm or cool imprimatura (initial toned ground)
        shows through, creating a glowing underlayer that unifies the whole image.

        Targets the mid-dark luma register [0, thin_paint_luma] — the zones where
        a real painter would have applied the fewest opaque layers, leaving the
        ground visible.  At those pixels, the ground_color is blended in with
        strength proportional to how dark the pixel is (darker = thinner paint =
        more ground showing).

        ground_color     : RGB of the imprimatura / toned ground (0–1 floats)
        reveal_strength  : blend factor at maximum thinness
        thin_paint_luma  : luma threshold above which paint is considered opaque
        opacity          : final composite opacity

        NOVEL: ONE-HUNDREDTH DISTINCT MODE.  FIRST pass to model DIFFERENTIAL PAINT
        THICKNESS as a function of luminance, blending an explicit ground color into
        dark/mid zones — distinct from all prior passes which treat the ground color
        only as a global tint (glaze) or apply it uniformly.
        """
        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # Reveal gate: strongest at luma=0, fades to zero at thin_paint_luma
        tp = max(float(thin_paint_luma), 0.01)
        reveal_gate = _np.clip(1.0 - luma / tp, 0.0, 1.0) * float(reveal_strength)

        gr, gg, gb = float(ground_color[0]), float(ground_color[1]), float(ground_color[2])
        r1 = r0 + reveal_gate * (gr - r0)
        g1 = g0 + reveal_gate * (gg - g0)
        b1 = b0 + reveal_gate * (gb - b0)

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Imprimatura reveal pass complete.")

    def klee_magic_square_pass(
        self,
        cell_size:        int   = 18,
        harmony_strength: float = 0.06,
        freq_x:           float = 0.75,
        freq_y:           float = 0.55,
        border_opacity:   float = 0.12,
        warm_shift:       float = 0.04,
        opacity:          float = 0.40,
    ) -> None:
        """
        Session 190 — Klee magic square pass (101st distinct mode).

        Inspired by Paul Klee's polyphonic colour grid technique, as exemplified in
        'Fire in the Evening' (1929), 'Polyphony' (1932), and 'Ad Parnassum' (1932).

        Divides the canvas into a regular grid of rectangular cells and applies a
        harmonic colour variation to each cell based on its grid-position index,
        using sine/cosine waves analogous to musical counterpoint in two dimensions.
        Optionally overlays faint dark cell borders to reinforce the grid structure.
        A warm tint shift simulates burlap/muslin ground bleed-through.

        cell_size        : pixel size of each square grid cell
        harmony_strength : peak colour-shift amplitude per channel (0–1 float)
        freq_x           : horizontal spatial frequency of colour wave (radians/cell)
        freq_y           : vertical spatial frequency of colour wave (radians/cell)
        border_opacity   : opacity of thin dark cell-border lines (0 = none)
        warm_shift       : global warm tint addition (simulates warm ground bleed)
        opacity          : final composite opacity over the original image

        NOVEL: ONE HUNDRED AND FIRST DISTINCT MODE.  FIRST pass to apply
        POSITION-DEPENDENT HARMONIC COLOUR VARIATION IN A SPATIAL CELL GRID —
        distinct from all prior passes which operate per-pixel uniformly, apply
        Gaussian spatial transforms, or use luma-gated operations.  The harmonic
        structure (sine/cosine waves indexed by cell position) directly embodies
        Klee's polyphony concept: structured mathematical variation producing visual
        music — independent rhythmic voices per colour channel.
        """
        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        cs = max(1, int(cell_size))
        hs = float(harmony_strength)
        fx = float(freq_x)
        fy = float(freq_y)
        ws = float(warm_shift)

        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()

        n_cells_y = (H + cs - 1) // cs
        n_cells_x = (W + cs - 1) // cs

        # 1. Per-cell harmonic colour shift — the polyphony engine
        for cy in range(n_cells_y):
            y0c = cy * cs
            y1c = min(y0c + cs, H)
            for cx in range(n_cells_x):
                x0c = cx * cs
                x1c = min(x0c + cs, W)
                # Three independent harmonic voices — one per channel
                dr = hs * _np.sin(cx * fx)
                dg = hs * _np.cos(cy * fy + _np.pi / 4.0)
                db = hs * _np.sin((cx + cy) * fx * 0.5)
                r1[y0c:y1c, x0c:x1c] = _np.clip(r1[y0c:y1c, x0c:x1c] + dr, 0.0, 1.0)
                g1[y0c:y1c, x0c:x1c] = _np.clip(g1[y0c:y1c, x0c:x1c] + dg, 0.0, 1.0)
                b1[y0c:y1c, x0c:x1c] = _np.clip(b1[y0c:y1c, x0c:x1c] + db, 0.0, 1.0)

        # 2. Faint dark cell borders — the 'line as independent event' element
        bo = float(border_opacity)
        if bo > 0.0:
            for cy in range(n_cells_y):
                yb = cy * cs
                if yb < H:
                    r1[yb, :] = _np.clip(r1[yb, :] * (1.0 - bo), 0.0, 1.0)
                    g1[yb, :] = _np.clip(g1[yb, :] * (1.0 - bo), 0.0, 1.0)
                    b1[yb, :] = _np.clip(b1[yb, :] * (1.0 - bo), 0.0, 1.0)
            for cx in range(n_cells_x):
                xb = cx * cs
                if xb < W:
                    r1[:, xb] = _np.clip(r1[:, xb] * (1.0 - bo), 0.0, 1.0)
                    g1[:, xb] = _np.clip(g1[:, xb] * (1.0 - bo), 0.0, 1.0)
                    b1[:, xb] = _np.clip(b1[:, xb] * (1.0 - bo), 0.0, 1.0)

        # 3. Warm ground bleed — burlap/muslin amber underlayer simulation
        if ws > 0.0:
            r1 = _np.clip(r1 + ws * 0.80, 0.0, 1.0)
            g1 = _np.clip(g1 + ws * 0.50, 0.0, 1.0)
            b1 = _np.clip(b1 + ws * 0.10, 0.0, 1.0)

        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Klee magic square pass complete.")

    def twombly_calligraphic_scrawl_pass(
        self,
        n_clusters:       int   = 40,
        loops_per_cluster: int  = 5,
        loop_radius:      float = 22.0,
        chalk_color:      tuple = (0.96, 0.94, 0.88),
        accent_prob:      float = 0.08,
        smear_opacity:    float = 0.12,
        opacity:          float = 0.62,
    ) -> None:
        """
        Session 191 — Twombly calligraphic scrawl pass (102nd distinct mode).

        Inspired by Cy Twombly's signature technique of looping, spiralling, wrist-
        rotation gesture marks deposited on pale cream grounds.  Draws clusters of
        connected loop-arc Bezier marks across the canvas — legible as writing-
        motion but illegible as text — with a subtle erased-smear ghost beneath
        each cluster to simulate Twombly's characteristic underdrawing.

        n_clusters         : number of mark clusters to distribute across the canvas
        loops_per_cluster  : how many loop-arcs per cluster (Twombly 'word' mass)
        loop_radius        : base radius of each loop in pixels
        chalk_color        : dominant mark colour (cream-white chalk)
        accent_prob        : probability that a cluster is rendered in a vivid accent
                             colour (cadmium red or sienna) rather than chalk
        smear_opacity      : opacity of the gaussian-blurred dark smear ghost beneath
                             each cluster (simulates erased underdrawing)
        opacity            : final composite opacity over the original image

        NOVEL: ONE HUNDRED AND SECOND DISTINCT MODE.  FIRST pass to generate
        LOOPING WRIST-ROTATION TRAJECTORY MARKS — distinct from all prior passes
        which generate directional strokes, dabs, dots, hatching, or geometric fills.
        The loop-spiral trajectory (Bezier cubic with control points orbiting the
        anchor node at phase-offset radii) is a new mark primitive that exists nowhere
        else in the pipeline.  The combination of loop marks, smear ghost, and
        chalk-on-pale-ground compositing directly embodies Twombly's calligraphic
        accumulation method.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageDraw as _IDraw, ImageFilter as _IFilter

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        rng = _np.random.default_rng(191)

        # ── accent colour pool (cadmium red and raw sienna) ───────────────────
        accent_colors = [
            (220, 55, 40),    # cadmium red
            (194, 152, 50),   # raw sienna-yellow
        ]

        # ── mark layer (RGBA, transparent background) ─────────────────────────
        mark_layer = _Image.new("RGBA", (W, H), (0, 0, 0, 0))
        mark_draw = _IDraw.Draw(mark_layer)

        # ── smear layer (dark blurred ghost beneath marks) ────────────────────
        smear_layer = _Image.new("RGBA", (W, H), (0, 0, 0, 0))
        smear_draw = _IDraw.Draw(smear_layer)

        chalk_r8 = int(_np.clip(chalk_color[0] * 255, 0, 255))
        chalk_g8 = int(_np.clip(chalk_color[1] * 255, 0, 255))
        chalk_b8 = int(_np.clip(chalk_color[2] * 255, 0, 255))

        def _bezier_point(p0, p1, p2, p3, t):
            """Cubic Bezier point at parameter t."""
            mt = 1.0 - t
            x = (mt**3 * p0[0] + 3 * mt**2 * t * p1[0]
                 + 3 * mt * t**2 * p2[0] + t**3 * p3[0])
            y = (mt**3 * p0[1] + 3 * mt**2 * t * p1[1]
                 + 3 * mt * t**2 * p2[1] + t**3 * p3[1])
            return (x, y)

        def _draw_loop(draw, anchor, radius, phase, color, width):
            """
            Draw a single loop arc: a cubic Bezier that spirals outward from anchor,
            completing roughly one loop of radius pixels, using rotated control points.
            """
            ax, ay = anchor
            r = float(radius)
            # Control points orbit the anchor at offset phases — the wrist-rotation
            cp1 = (ax + r * _np.cos(phase),          ay + r * _np.sin(phase))
            cp2 = (ax + r * _np.cos(phase + 2.0),    ay + r * _np.sin(phase + 2.0))
            # Endpoint displaced slightly from anchor — the loop drift
            drift_angle = phase + _np.pi + rng.uniform(-0.5, 0.5)
            drift_dist  = r * rng.uniform(0.3, 0.9)
            end = (ax + drift_dist * _np.cos(drift_angle),
                   ay + drift_dist * _np.sin(drift_angle))

            pts = [_bezier_point((ax, ay), cp1, cp2, end, t / 20.0)
                   for t in range(21)]
            flat = [(int(p[0]), int(p[1])) for p in pts]
            if len(flat) >= 2:
                draw.line(flat, fill=color, width=width)
            return end   # next anchor = where this loop terminated

        for _ in range(int(n_clusters)):
            # Cluster anchor: distributed across canvas, biased away from hard edges
            cx = rng.uniform(W * 0.08, W * 0.92)
            cy = rng.uniform(H * 0.08, H * 0.92)

            # Choose mark colour
            is_accent = rng.random() < float(accent_prob)
            if is_accent:
                ac = accent_colors[int(rng.integers(len(accent_colors)))]
                mark_color = (ac[0], ac[1], ac[2], 220)
                smear_color = (30, 20, 15, int(255 * float(smear_opacity) * 2))
            else:
                mark_color = (chalk_r8, chalk_g8, chalk_b8, 210)
                smear_color = (60, 55, 45, int(255 * float(smear_opacity)))

            # Mark width: Twombly strokes are thin but not hairlines
            line_width = max(1, int(rng.uniform(1.5, 4.0)))
            radius_var = float(loop_radius) * rng.uniform(0.55, 1.45)

            # Smear ghost: blurred ellipse behind the cluster
            smear_r = int(radius_var * 2.2)
            smear_draw.ellipse(
                [cx - smear_r, cy - smear_r, cx + smear_r, cy + smear_r],
                fill=smear_color,
            )

            # Loop chain: each loop's endpoint becomes the next loop's anchor
            anchor = (cx, cy)
            phase = rng.uniform(0, 2 * _np.pi)
            for _ in range(int(loops_per_cluster)):
                phase += rng.uniform(0.8, 1.6)   # advancing phase = spiralling
                radius_step = radius_var * rng.uniform(0.6, 1.3)
                anchor = _draw_loop(mark_draw, anchor, radius_step, phase,
                                    mark_color, line_width)

        # Blur the smear layer for the erased-ghost effect
        smear_blurred = smear_layer.filter(_IFilter.GaussianBlur(radius=int(loop_radius * 0.7)))

        # ── composite smear ghost + marks over original ───────────────────────
        base = _Image.fromarray(
            _np.stack([orig[:, :, 2], orig[:, :, 1], orig[:, :, 0], orig[:, :, 3]], axis=2),
            mode="RGBA"
        )
        base.alpha_composite(smear_blurred)
        base.alpha_composite(mark_layer)
        result = _np.array(base)

        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(
            (orig[:, :, 2].astype(_np.float32) * (1 - op)
             + result[:, :, 0].astype(_np.float32) * op), 0, 255
        ).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            (orig[:, :, 1].astype(_np.float32) * (1 - op)
             + result[:, :, 1].astype(_np.float32) * op), 0, 255
        ).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            (orig[:, :, 0].astype(_np.float32) * (1 - op)
             + result[:, :, 2].astype(_np.float32) * op), 0, 255
        ).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Twombly calligraphic scrawl pass complete.")

    def kusama_infinity_dot_pass(
        self,
        n_seeds:      int   = 9,
        ring_step:    int   = 32,
        dot_radius:   int   = 14,
        dot_spacing:  int   = 36,
        jitter_frac:  float = 0.22,
        palette:      list  = None,
        opacity:      float = 0.72,
    ) -> None:
        """
        Session 193 — Kusama infinity dot pass (104th distinct mode).

        Inspired by Yayoi Kusama's signature obsessive polka-dot practice, as
        exemplified in 'Infinity Net' (1958), 'Dots Obsession' (1998), and her
        entire dot-accumulation career.

        Places N_seeds expansion centres across the canvas.  From each seed,
        concentric rings of filled circles radiate outward at ring_step intervals.
        Each ring contains dots evenly spaced circumferentially (arc distance
        ≈ dot_spacing pixels).  Ring index drives a cyclic palette rotation so
        adjacent rings alternate between complementary hues.  Dot radius carries
        a gentle per-dot noise jitter for organic life.

        n_seeds      : number of radial explosion centres
        ring_step    : pixel distance between concentric rings (controls density)
        dot_radius   : base filled-dot radius in pixels
        dot_spacing  : arc distance between dot centres within a ring
        jitter_frac  : radius noise as fraction of dot_radius (0 = perfect circles)
        palette      : list of (R, G, B) float triples; defaults to Kusama palette
        opacity      : final blend of dot layer over original canvas

        NOVEL: ONE HUNDRED AND FOURTH DISTINCT MODE.  FIRST pass to generate
        RADIALLY-EXPANDING CONCENTRIC RING DOT PLACEMENT — distinct from every
        prior pass in the pipeline:

          - pointillist_chroma_dots: randomly placed tiny dots for optical color
            mixing — no ring structure, no per-ring hue cycling
          - klee_magic_square_pass: rectangular cell grid with harmonic color shift
          - twombly_calligraphic_scrawl_pass: looping spiral cursive marks
          - agnes_martin_meditation_lines_pass: ruled horizontal lines

        The CONCENTRIC RING spatial structure — where dots are placed at even
        arc-distance along circles of increasing radius from multiple seeds, with
        PER-RING HUE CYCLING — is a new primitive that exists nowhere else in the
        pipeline.  It directly encodes Kusama's obsessive radiation logic: the eye
        follows each ring outward from the centre, then leaps to the next colour
        ring, creating the 'infinity' illusion of dots multiplying beyond the frame.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageDraw as _IDraw

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        _DEFAULT_PALETTE = [
            (0.92, 0.08, 0.08),   # vivid red
            (0.98, 0.88, 0.08),   # sunshine yellow
            (0.06, 0.12, 0.82),   # cobalt blue
            (0.10, 0.70, 0.18),   # vivid green
            (0.62, 0.06, 0.78),   # deep violet
            (0.96, 0.60, 0.06),   # cadmium orange
        ]
        pal = palette if palette is not None else _DEFAULT_PALETTE
        n_col = len(pal)
        if n_col == 0:
            return

        rng = _np.random.default_rng(193)

        # Seed positions — avoid canvas border by dot_radius + ring_step margin
        margin = int(dot_radius) + int(ring_step)
        seed_xs = rng.integers(margin, max(margin + 1, W - margin), size=n_seeds)
        seed_ys = rng.integers(margin, max(margin + 1, H - margin), size=n_seeds)

        # Determine max ring count needed to cover the canvas diagonal from any seed
        diag = _np.sqrt(W ** 2 + H ** 2)
        max_rings = int(_np.ceil(diag / max(1, ring_step))) + 1

        # Build dot layer as RGBA PIL image
        dot_layer = _Image.new("RGBA", (W, H), (0, 0, 0, 0))
        draw = _IDraw.Draw(dot_layer)

        rs = max(1, int(ring_step))
        dr = max(1, int(dot_radius))
        ds = max(1, int(dot_spacing))
        jf = float(jitter_frac)

        for si in range(n_seeds):
            sx, sy = float(seed_xs[si]), float(seed_ys[si])

            for ri in range(1, max_rings):
                radius = ri * rs
                # Number of dots in this ring — circumference / dot_spacing
                circumference = 2.0 * _np.pi * radius
                n_dots = max(1, int(circumference / ds))

                # Palette colour for this ring — cyclic rotation
                col_idx = (ri - 1) % n_col
                cr, cg, cb = pal[col_idx]
                c8r = int(_np.clip(cr * 255, 0, 255))
                c8g = int(_np.clip(cg * 255, 0, 255))
                c8b = int(_np.clip(cb * 255, 0, 255))

                # Evenly distribute dots around the ring
                angles = _np.linspace(0, 2.0 * _np.pi, n_dots, endpoint=False)
                # Per-seed angular phase offset so seeds don't align perfectly
                phase = rng.uniform(0, 2.0 * _np.pi)
                angles += phase

                for angle in angles:
                    dx = sx + radius * _np.cos(angle)
                    dy = sy + radius * _np.sin(angle)

                    # Skip dots that fall outside canvas (with margin)
                    if dx < -dr or dx >= W + dr or dy < -dr or dy >= H + dr:
                        continue

                    # Organic radius jitter
                    r_jitter = dr * (1.0 + rng.uniform(-jf, jf))
                    r_px = max(1, int(round(r_jitter)))

                    x0 = int(round(dx)) - r_px
                    y0 = int(round(dy)) - r_px
                    x1 = int(round(dx)) + r_px
                    y1 = int(round(dy)) + r_px
                    draw.ellipse((x0, y0, x1, y1), fill=(c8r, c8g, c8b, 220))

        # Composite dot layer over original canvas
        base_img = _Image.fromarray(
            _np.stack([orig[:, :, 2], orig[:, :, 1],
                       orig[:, :, 0], orig[:, :, 3]], axis=2),
            mode="RGBA"
        )
        base_img.alpha_composite(dot_layer)
        result = _np.array(base_img)

        # Blend with original at `opacity`
        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2].astype(_np.float32) * (1 - op)
            + result[:, :, 0].astype(_np.float32) * op, 0, 255
        ).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1].astype(_np.float32) * (1 - op)
            + result[:, :, 1].astype(_np.float32) * op, 0, 255
        ).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0].astype(_np.float32) * (1 - op)
            + result[:, :, 2].astype(_np.float32) * op, 0, 255
        ).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Kusama infinity dot pass complete.")

    def agnes_martin_meditation_lines_pass(
        self,
        n_lines:       int   = 320,
        tremor_sigma:  float = 1.2,
        breathe_freq:  float = 2.5,
        line_opacity:  float = 0.52,
        wash_color:    tuple = (0.84, 0.88, 0.92),
        wash_opacity:  float = 0.10,
        tone_drift:    float = 0.030,
        opacity:       float = 0.68,
    ) -> None:
        """
        Session 192 — Agnes Martin meditation lines pass (103rd distinct mode).

        Inspired by Agnes Martin's signature technique of ruling hundreds of
        nearly-horizontal pencil lines across an unprimed linen canvas, each
        carrying an almost imperceptible organic tremor and a slow breathing
        variation in tone.  The pass first lays a thin atmospheric wash over
        the canvas, then rules N fine lines from edge to edge with:

          - organic Y tremor: per-pixel offset drawn from a smoothed noise field
            so each line has the subtle waver of a human-held ruler
          - breathing opacity: a slow sine wave along X causes each line to
            fade and brighten as it crosses the canvas, simulating uneven
            pencil pressure
          - micro-tone banding: neighbouring lines drift ±tone_drift in
            luminance, creating the banded watercolour-wash effect visible in
            works like 'Friendship' (1963) and 'Loving' (1999)

        n_lines       : number of meditation lines to rule across the canvas
        tremor_sigma  : sigma of the Gaussian smoothing applied to per-pixel
                        Y noise (higher = longer-wave waver, more relaxed)
        breathe_freq  : cycles of opacity sine wave per canvas width (2–4
                        gives one slow 'breath' across the painting)
        line_opacity  : base alpha of each line (the tremor breathing modulates
                        this up and down)
        wash_color    : (R, G, B) of the pale atmosphere wash applied first
        wash_opacity  : opacity of the atmosphere wash over the base canvas
        tone_drift    : per-line luminance variation in [0, 1] — how much
                        neighbouring lines differ in brightness
        opacity       : final composite blend of the line layer over original

        NOVEL: ONE HUNDRED AND THIRD DISTINCT MODE.  FIRST pass to generate
        CONTINUOUS HORIZONTAL MEDITATION LINES with breathing opacity, organic
        pencil tremor, and micro-tone banding.  Every prior pass in the pipeline
        generates either directional strokes, dabs, dots, hatching, geometric
        cell fills, or looping spiral marks.  None create the ruled-line
        meditation structure that is Martin's unmistakable signature — a
        surface where the entire canvas is equally attended, where no focal
        point exists, and where the viewer's eye travels continuously left to
        right across hundreds of near-identical yet individually unique marks.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from PIL import Image as _Image, ImageDraw as _IDraw

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        rng = _np.random.default_rng(192)

        # ── Step 1: atmosphere wash over base canvas ──────────────────────────
        wr8 = int(_np.clip(wash_color[0] * 255, 0, 255))
        wg8 = int(_np.clip(wash_color[1] * 255, 0, 255))
        wb8 = int(_np.clip(wash_color[2] * 255, 0, 255))
        wo  = float(wash_opacity)
        washed = orig.copy()
        washed[:, :, 2] = _np.clip(
            orig[:, :, 2].astype(_np.float32) * (1 - wo) + wr8 * wo, 0, 255
        ).astype(_np.uint8)
        washed[:, :, 1] = _np.clip(
            orig[:, :, 1].astype(_np.float32) * (1 - wo) + wg8 * wo, 0, 255
        ).astype(_np.uint8)
        washed[:, :, 0] = _np.clip(
            orig[:, :, 0].astype(_np.float32) * (1 - wo) + wb8 * wo, 0, 255
        ).astype(_np.uint8)

        # ── Step 2: build line layer ──────────────────────────────────────────
        line_layer = _Image.new("RGBA", (W, H), (0, 0, 0, 0))
        draw = _IDraw.Draw(line_layer)

        n = int(n_lines)
        if n == 0:
            self.canvas.surface.get_data()[:] = washed.tobytes()
            self.canvas.surface.mark_dirty()
            print("    Agnes Martin meditation lines pass complete (0 lines).")
            return
        # Evenly spaced line Y anchors across the canvas (with small margin)
        y_anchors = _np.linspace(H * 0.02, H * 0.98, n)

        # Per-pixel Y tremor: smoothed noise field — each line gets its own row
        # of offsets so adjacent lines have correlated but not identical tremor
        raw_noise = rng.standard_normal((n, W)).astype(_np.float32)
        tremor_field = _gf(raw_noise, sigma=(float(tremor_sigma) * 4,
                                              float(tremor_sigma) * 20))
        # Scale so tremor is in ±3 px range
        t_max = _np.abs(tremor_field).max()
        if t_max > 1e-6:
            tremor_field = tremor_field / t_max * 3.0

        # Per-line micro-tone variation (luminance drift between neighbouring lines)
        tone_series = _np.cumsum(
            rng.uniform(-float(tone_drift), float(tone_drift), n)
        ).astype(_np.float32)
        # Centre the drift so it doesn't wander too far from 0
        tone_series -= tone_series.mean()
        tone_series = _np.clip(tone_series, -0.12, 0.12)

        # Breathing opacity wave — slow sine across canvas width, per-line phase
        xs_norm = _np.linspace(0, 1, W, dtype=_np.float32)
        freq = float(breathe_freq)

        base_lo = int(_np.clip(line_opacity * 0.55 * 255, 0, 255))
        base_hi = int(_np.clip(line_opacity * 1.00 * 255, 0, 255))

        # Line colour: graphite grey-pencil tone, modulated per line
        # Base graphite: (0.50, 0.50, 0.52) in RGB
        for i in range(n):
            ya = float(y_anchors[i])
            td = float(tone_series[i])   # luminance drift for this line
            # Graphite tone with drift
            lum = _np.clip(0.50 + td, 0.20, 0.75)
            lr8 = int(_np.clip((lum + 0.02) * 255, 0, 255))
            lg8 = int(_np.clip((lum + 0.02) * 255, 0, 255))
            lb8 = int(_np.clip((lum + 0.04) * 255, 0, 255))  # faint cool shift

            # Breathing alpha per pixel — sine wave with per-line phase offset
            phase_offset = rng.uniform(0, 2 * _np.pi)
            breathe = 0.5 + 0.5 * _np.sin(
                2 * _np.pi * freq * xs_norm + phase_offset
            )
            # alpha in [base_lo, base_hi]
            alphas = (base_lo + (base_hi - base_lo) * breathe).astype(_np.float32)

            # Y positions with tremor: each pixel x gets a slightly different Y
            y_positions = ya + tremor_field[i]
            y_positions = _np.clip(y_positions, 0, H - 1).astype(_np.int32)

            # Draw individual pixel segments rather than a single polyline so
            # the alpha can vary per pixel — draw short runs of pixels
            # Group consecutive pixels with the same y into horizontal runs
            for x in range(W):
                yp = int(y_positions[x])
                alpha = int(_np.clip(alphas[x], 0, 255))
                if alpha < 4:
                    continue
                line_layer.putpixel((x, yp), (lr8, lg8, lb8, alpha))

        # ── Step 3: composite line layer over washed canvas ───────────────────
        base_img = _Image.fromarray(
            _np.stack([washed[:, :, 2], washed[:, :, 1],
                       washed[:, :, 0], washed[:, :, 3]], axis=2),
            mode="RGBA"
        )
        base_img.alpha_composite(line_layer)
        result = _np.array(base_img)

        # ── Step 4: blend with original at `opacity` ──────────────────────────
        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2].astype(_np.float32) * (1 - op)
            + result[:, :, 0].astype(_np.float32) * op, 0, 255
        ).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1].astype(_np.float32) * (1 - op)
            + result[:, :, 1].astype(_np.float32) * op, 0, 255
        ).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0].astype(_np.float32) * (1 - op)
            + result[:, :, 2].astype(_np.float32) * op, 0, 255
        ).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Agnes Martin meditation lines pass complete.")

    # ── Session 194 ─────────────────────────────────────────────────────────────

    def schiele_angular_contour_pass(
        self,
        reference,
        edge_threshold=0.15,
        contour_weight=2.5,
        flesh_wash_opacity=0.18,
        hatch_opacity=0.22,
        n_hatch_lines=40,
        hatch_shadow_thresh=0.35,
        contour_color=(0.05, 0.03, 0.02),
        flesh_color=(0.86, 0.65, 0.50),
        opacity=0.80,
        seed=42,
    ):
        """
        schiele_angular_contour_pass — 105th distinct mode (Session 194).

        Inspired by Egon Schiele's Austrian Expressionist draftsmanship:
        heavy angular contour lines from edge detection, variable line weight,
        sparse directional flesh-tone washes, and diagonal shadow hatching.

        Algorithm:
          1. Compute luminance gradient magnitude (Sobel) of the reference.
          2. For each sampled edge pixel, compute the local edge direction
             (perpendicular to gradient vector), snap to the nearest of 8
             discrete angles (octagonal quantization — the source of the
             characteristic Schiele angularity), and draw a short stroke of
             width proportional to gradient magnitude.
          3. Apply a thin flesh-tone wash to midtone reference areas
             (lum in [0.35, 0.75]), leaving bright highlights and dark shadows
             as bare ground.
          4. Draw angular parallel hatch lines (20° slant) confined to
             shadow regions (lum < hatch_shadow_thresh).
          5. Composite all layers onto the canvas at `opacity`.

        Novel vs all prior passes:
          - pointillist_pass: random optical-mixing dot scatter
          - klee_magic_square_pass: rectangular harmonic cell grid
          - twombly_calligraphic_scrawl_pass: looping spiral cursive marks
          - agnes_martin_meditation_lines_pass: horizontal ruled tremor lines
          - kusama_infinity_dot_pass: concentric ring dot expansion
          This is the FIRST pass using OCTAGONAL-QUANTIZED EDGE-DETECTED
          CONTOUR STROKES with gradient-weighted line width.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageDraw as _IDraw

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        rng = _np.random.default_rng(seed)

        # ── Convert reference to float numpy array ─────────────────────────────
        if isinstance(reference, _Image.Image):
            ref_rgb = _np.array(
                reference.convert("RGB").resize((W, H), _Image.LANCZOS),
                dtype=_np.float32,
            ) / 255.0
        else:
            ref_rgb = _np.array(reference, dtype=_np.float32)
            if ref_rgb.max() > 1.5:
                ref_rgb = ref_rgb / 255.0
            if ref_rgb.shape[:2] != (H, W):
                _tmp = _Image.fromarray(
                    (ref_rgb * 255).clip(0, 255).astype(_np.uint8)
                ).resize((W, H), _Image.LANCZOS)
                ref_rgb = _np.array(_tmp, dtype=_np.float32) / 255.0

        # ── Luminance map ──────────────────────────────────────────────────────
        lum = (
            0.299 * ref_rgb[:, :, 0]
            + 0.587 * ref_rgb[:, :, 1]
            + 0.114 * ref_rgb[:, :, 2]
        )

        # ── Gradient magnitude (Sobel finite differences) ─────────────────────
        gx = _np.zeros_like(lum)
        gy = _np.zeros_like(lum)
        gx[:, 1:-1] = (lum[:, 2:] - lum[:, :-2]) * 0.5
        gy[1:-1, :] = (lum[2:, :] - lum[:-2, :]) * 0.5
        grad_mag = _np.sqrt(gx ** 2 + gy ** 2)
        if grad_mag.max() > 1e-8:
            grad_mag = grad_mag / grad_mag.max()

        # ── Create output RGBA layer ───────────────────────────────────────────
        layer = _Image.new("RGBA", (W, H), (0, 0, 0, 0))
        draw = _IDraw.Draw(layer)

        # ── Step 1: Flesh wash in midtone areas ───────────────────────────────
        flesh_mask = (lum > 0.35) & (lum < 0.75)
        if flesh_wash_opacity > 0 and flesh_mask.any():
            fr8 = int(_np.clip(flesh_color[0] * 255, 0, 255))
            fg8 = int(_np.clip(flesh_color[1] * 255, 0, 255))
            fb8 = int(_np.clip(flesh_color[2] * 255, 0, 255))
            fa8 = int(_np.clip(flesh_wash_opacity * 255, 0, 255))
            wash_arr = _np.zeros((H, W, 4), dtype=_np.uint8)
            wash_arr[flesh_mask, 0] = fr8
            wash_arr[flesh_mask, 1] = fg8
            wash_arr[flesh_mask, 2] = fb8
            wash_arr[flesh_mask, 3] = fa8
            wash_img = _Image.fromarray(wash_arr, mode="RGBA")
            layer.alpha_composite(wash_img)

        # ── Step 2: Angular shadow hatching ───────────────────────────────────
        if hatch_opacity > 0 and n_hatch_lines > 0:
            ha8 = int(_np.clip(hatch_opacity * 255, 0, 255))
            cc_r = int(_np.clip(contour_color[0] * 255, 0, 255))
            cc_g = int(_np.clip(contour_color[1] * 255, 0, 255))
            cc_b = int(_np.clip(contour_color[2] * 255, 0, 255))
            hatch_rgba = (cc_r, cc_g, cc_b, ha8)
            shadow_mask = lum < float(hatch_shadow_thresh)
            # 20° slant — Schiele's characteristic directional hatching
            hatch_angle_rad = _np.deg2rad(20.0)
            cos_a = float(_np.cos(hatch_angle_rad))
            sin_a = float(_np.sin(hatch_angle_rad))
            hatch_spacing = max(3, (H + W) // max(n_hatch_lines, 1))
            for offset in range(-H, W + H, hatch_spacing):
                # Start at (offset, 0), advance along angle
                if sin_a > 1e-8:
                    x1_f = offset + H * cos_a / sin_a
                else:
                    x1_f = float(offset + W)
                x0, y0 = int(offset), 0
                x1, y1 = int(x1_f), H
                # Sample points along segment to test shadow coverage
                n_samp = max(4, min(16, abs(x1 - x0) // 8 + abs(y1 - y0) // 8))
                sxs = _np.linspace(x0, x1, n_samp).astype(int)
                sys_ = _np.linspace(y0, y1, n_samp).astype(int)
                sxs = _np.clip(sxs, 0, W - 1)
                sys_ = _np.clip(sys_, 0, H - 1)
                if shadow_mask[sys_, sxs].any():
                    draw.line([(x0, y0), (x1, y1)], fill=hatch_rgba, width=1)

        # ── Step 3: Angular contour strokes ───────────────────────────────────
        edge_mask = grad_mag > float(edge_threshold)
        edge_ys, edge_xs = _np.where(edge_mask)

        if len(edge_xs) > 0:
            cc_r8 = int(_np.clip(contour_color[0] * 255, 0, 255))
            cc_g8 = int(_np.clip(contour_color[1] * 255, 0, 255))
            cc_b8 = int(_np.clip(contour_color[2] * 255, 0, 255))

            # Subsample: at most ~1800 strokes for performance
            n_edges = len(edge_xs)
            step = max(1, n_edges // 1800)
            sxs = edge_xs[::step]
            sys_ = edge_ys[::step]

            # Stroke length: ~1/30 of short axis
            stroke_half = max(2, min(W, H) // 30)

            # 8-direction angle table (octagonal quantization)
            n_angles = 8
            angle_step = _np.pi / n_angles

            for i in range(len(sxs)):
                ex, ey = int(sxs[i]), int(sys_[i])
                gx_v = float(gx[ey, ex])
                gy_v = float(gy[ey, ex])
                g_len = float(_np.sqrt(gx_v ** 2 + gy_v ** 2)) + 1e-8
                # Edge direction is perpendicular to gradient
                edge_dx = -gy_v / g_len
                edge_dy = gx_v / g_len
                # Snap to octagonal angle
                raw_angle = float(_np.arctan2(edge_dy, edge_dx))
                q_idx = round(raw_angle / angle_step)
                q_angle = q_idx * angle_step
                cos_q = float(_np.cos(q_angle))
                sin_q = float(_np.sin(q_angle))
                # Variable weight from gradient magnitude
                mag_here = float(grad_mag[ey, ex])
                w_px = max(1, int(contour_weight * mag_here * 3.0))
                alpha_c = int(_np.clip(mag_here * 195 + 60, 60, 245))
                c_rgba = (cc_r8, cc_g8, cc_b8, alpha_c)
                x0 = int(ex - cos_q * stroke_half)
                y0 = int(ey - sin_q * stroke_half)
                x1 = int(ex + cos_q * stroke_half)
                y1 = int(ey + sin_q * stroke_half)
                draw.line([(x0, y0), (x1, y1)], fill=c_rgba, width=w_px)

        # ── Step 4: Composite onto canvas at `opacity` ─────────────────────────
        base_img = _Image.fromarray(
            _np.stack(
                [orig[:, :, 2], orig[:, :, 1], orig[:, :, 0], orig[:, :, 3]],
                axis=2,
            ),
            mode="RGBA",
        )
        base_img.alpha_composite(layer)
        result = _np.array(base_img)

        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2].astype(_np.float32) * (1 - op)
            + result[:, :, 0].astype(_np.float32) * op,
            0, 255,
        ).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1].astype(_np.float32) * (1 - op)
            + result[:, :, 1].astype(_np.float32) * op,
            0, 255,
        ).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0].astype(_np.float32) * (1 - op)
            + result[:, :, 2].astype(_np.float32) * op,
            0, 255,
        ).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Schiele angular contour pass complete.")

    def riley_op_art_wave_pass(
        self,
        reference,
        n_waves=80,
        base_amplitude=12.0,
        freq_modulation=0.8,
        base_frequency=0.012,
        color_a=(0.05, 0.05, 0.05),
        color_b=(0.95, 0.95, 0.95),
        opacity=0.90,
        seed=42,
    ):
        """
        riley_op_art_wave_pass — 106th distinct mode (Session 195).

        Inspired by Bridget Riley's Op Art: precision sinusoidal wave bands
        whose spatial frequency is modulated by reference image luminance,
        creating optical vibration and the illusion of movement.

        Algorithm:
          1. Resample reference to canvas size; compute per-pixel luminance.
          2. Divide canvas into `n_waves` horizontal scan bands.
          3. For each band, sample a base y-position and compute a sinusoidal
             displacement curve across all x:
               y_displaced(x) = y_base
                               + amplitude * sin(2π * freq(x) * x + phase_shift)
             where freq(x) = base_frequency * (1 + freq_modulation * lum(x, y_base)).
             Bright reference pixels tighten the wave (higher frequency);
             dark pixels relax it — subject matter becomes encoded in frequency.
          4. Between consecutive displacement curves, fill a polygon with
             alternating color_a / color_b. Hard edges only (zero anti-alias).
          5. Composite the wave layer onto the canvas at `opacity`.

        Novel vs all prior passes:
          - Agnes Martin: ruled parallel horizontal tremor lines (static, uniform)
          - Schiele: octagonal edge-detected contour strokes
          - Kusama: concentric expanding dot rings
          - Klee: rectangular colour-cell harmonic grids
          - Twombly: looping calligraphic spiral beziers
          This is the FIRST pass using LUMINANCE-MODULATED SINUSOIDAL WAVE
          BANDS with two-colour alternating fill — optical interference patterns
          derived from image frequency content. The SPATIAL-FREQUENCY MODULATION
          PRIMITIVE that encodes image structure as perceptual vibration is new.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageDraw as _IDraw

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        rng = _np.random.default_rng(seed)

        # ── Convert reference to float luminance ───────────────────────────────
        if isinstance(reference, _Image.Image):
            ref_rgb = _np.array(
                reference.convert("RGB").resize((W, H), _Image.LANCZOS),
                dtype=_np.float32,
            ) / 255.0
        else:
            ref_rgb = _np.array(reference, dtype=_np.float32)
            if ref_rgb.max() > 1.5:
                ref_rgb = ref_rgb / 255.0
            if ref_rgb.shape[:2] != (H, W):
                _tmp = _Image.fromarray(
                    (ref_rgb * 255).clip(0, 255).astype(_np.uint8)
                ).resize((W, H), _Image.LANCZOS)
                ref_rgb = _np.array(_tmp, dtype=_np.float32) / 255.0

        lum = (
            0.299 * ref_rgb[:, :, 0]
            + 0.587 * ref_rgb[:, :, 1]
            + 0.114 * ref_rgb[:, :, 2]
        )

        # ── Prepare output layer ───────────────────────────────────────────────
        layer = _Image.new("RGBA", (W, H), (0, 0, 0, 0))
        draw = _IDraw.Draw(layer)

        ca_r = int(_np.clip(color_a[0] * 255, 0, 255))
        ca_g = int(_np.clip(color_a[1] * 255, 0, 255))
        ca_b = int(_np.clip(color_a[2] * 255, 0, 255))
        cb_r = int(_np.clip(color_b[0] * 255, 0, 255))
        cb_g = int(_np.clip(color_b[1] * 255, 0, 255))
        cb_b = int(_np.clip(color_b[2] * 255, 0, 255))
        fill_a = (ca_r, ca_g, ca_b, 255)
        fill_b = (cb_r, cb_g, cb_b, 255)

        # ── Build wave displacement curves ─────────────────────────────────────
        # n_waves scan positions evenly across canvas height (plus top/bottom sentinels)
        n_curves = n_waves + 1
        y_positions = _np.linspace(0.0, float(H), n_curves)

        xs = _np.arange(W, dtype=_np.float32)

        def _wave_curve(y_base: float, phase: float) -> _np.ndarray:
            """Return an array of y-values for each x along one wave curve."""
            y_row = int(_np.clip(round(y_base), 0, H - 1))
            lum_row = lum[y_row, :]   # luminance sample at this horizontal strip

            # Local frequency: brighter → tighter waves
            local_freq = base_frequency * (1.0 + float(freq_modulation) * lum_row)
            # Cumulative phase (integral of local frequency × 2π × x step)
            cum_phase = _np.cumsum(local_freq * 2.0 * _np.pi)
            # y displacement
            disp = float(base_amplitude) * _np.sin(cum_phase + phase)
            return y_base + disp

        curves = []
        for i, y_base in enumerate(y_positions):
            phase = float(rng.uniform(0.0, 2.0 * _np.pi))
            curves.append(_wave_curve(y_base, phase))

        # ── Fill polygons between consecutive wave curves ───────────────────────
        for i in range(len(curves) - 1):
            top_ys = curves[i]
            bot_ys = curves[i + 1]
            fill = fill_a if (i % 2 == 0) else fill_b

            # Build polygon: left→right along top curve, right→left along bottom
            poly = []
            step = max(1, W // 256)   # reduce vertices for performance
            for xi in range(0, W, step):
                poly.append((xi, int(round(top_ys[xi]))))
            for xi in range(W - 1, -1, -step):
                poly.append((xi, int(round(bot_ys[xi]))))

            if len(poly) >= 3:
                draw.polygon(poly, fill=fill)

        # ── Composite onto canvas at `opacity` ─────────────────────────────────
        base_img = _Image.fromarray(
            _np.stack(
                [orig[:, :, 2], orig[:, :, 1], orig[:, :, 0], orig[:, :, 3]],
                axis=2,
            ),
            mode="RGBA",
        )
        base_img.alpha_composite(layer)
        result = _np.array(base_img)

        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(
            orig[:, :, 2].astype(_np.float32) * (1 - op)
            + result[:, :, 0].astype(_np.float32) * op,
            0, 255,
        ).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            orig[:, :, 1].astype(_np.float32) * (1 - op)
            + result[:, :, 1].astype(_np.float32) * op,
            0, 255,
        ).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            orig[:, :, 0].astype(_np.float32) * (1 - op)
            + result[:, :, 2].astype(_np.float32) * op,
            0, 255,
        ).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Riley Op Art wave pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 196 — Fernand Léger — leger_tubist_contour_pass (107th mode)
    # ─────────────────────────────────────────────────────────────────────────

    def leger_tubist_contour_pass(
        self,
        reference=None,
        contour_thickness: int = 4,
        contour_threshold: float = 0.18,
        flat_fill_strength: float = 0.60,
        primary_shift: float = 0.55,
        contour_strength: float = 0.88,
        opacity: float = 0.82,
        seed: int = 196,
    ) -> None:
        """
        Léger Tubist Contour pass — Fernand Léger's mechanical poster aesthetic.

        Inspired by Léger's Tubist period (1913–1955): bold black outlines
        around every form, flat primary-colour fills, no gradients, no texture.
        Algorithm:
          1. Compute Sobel edge magnitude on canvas luminance → threshold at
             contour_threshold → binary-dilate by contour_thickness px
             → THICK BLACK CONTOUR MASK.
          2. Gaussian-blur canvas to create flat colour zones (radius ≈ 6 px).
          3. Snap each pixel toward its nearest colour in the Léger primary
             palette (cadmium red, cobalt blue, chrome yellow, forest green,
             cool grey, off-white, near-black) at primary_shift strength.
          4. Force contour-mask pixels toward near-black at contour_strength.
          5. Alpha-blend composite result onto canvas.

        NOVEL: 107TH DISTINCT MODE. FIRST pass to combine EDGE-DILATION BLACK
        CONTOUR THICKENING with per-pixel PRIMARY-PALETTE COLOUR QUANTIZATION.
        No prior pass flattens colour zones while simultaneously imposing bold
        graphic outlines. The FLAT-FILL + THICK-OUTLINE primitive is a new
        graphic-design operation — distinct from all 106 prior passes.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageFilter as _IF
        from scipy.ndimage import convolve as _conv, binary_dilation as _bd

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Extract RGB channels (canvas is BGRA: ch0=B, ch1=G, ch2=R)
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        # ── 1. Edge detection → thick black contour mask ──────────────────────
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        sobel_x = _np.array(
            [[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32
        )
        sobel_y = _np.array(
            [[-1, -2, -1], [0, 0, 0], [1, 2, 1]], dtype=_np.float32
        )
        gx = _conv(lum, sobel_x, mode="reflect")
        gy = _conv(lum, sobel_y, mode="reflect")
        grad_mag = _np.sqrt(gx ** 2 + gy ** 2)
        grad_mag = grad_mag / (_np.percentile(grad_mag, 99.0) + 1e-8)
        grad_mag = _np.clip(grad_mag, 0.0, 1.0)

        edge_mask = grad_mag > float(contour_threshold)

        k = max(1, int(contour_thickness))
        struct_el = _np.ones((k, k), dtype=bool)
        thick_edge = _bd(edge_mask, structure=struct_el).astype(_np.float32)

        # ── 2. Gaussian blur → flat colour zones ──────────────────────────────
        rgb_pil = _Image.fromarray(
            _np.stack(
                [
                    (r0 * 255).clip(0, 255).astype(_np.uint8),
                    (g0 * 255).clip(0, 255).astype(_np.uint8),
                    (b0 * 255).clip(0, 255).astype(_np.uint8),
                ],
                axis=2,
            ),
            mode="RGB",
        )
        flat_pil = rgb_pil.filter(_IF.GaussianBlur(radius=6))
        flat_arr = _np.array(flat_pil, dtype=_np.float32) / 255.0
        r_flat = flat_arr[:, :, 0]
        g_flat = flat_arr[:, :, 1]
        b_flat = flat_arr[:, :, 2]

        # ── 3. Snap toward Léger primary palette ──────────────────────────────
        #   (cadmium red, cobalt blue, chrome yellow, forest green,
        #    cool grey, off-white, near-black)
        leger_pal = _np.array(
            [
                [0.84, 0.12, 0.10],
                [0.10, 0.22, 0.70],
                [0.93, 0.80, 0.08],
                [0.15, 0.48, 0.24],
                [0.58, 0.58, 0.58],
                [0.93, 0.91, 0.88],
                [0.10, 0.10, 0.10],
            ],
            dtype=_np.float32,
        )

        flat_rgb = _np.stack([r_flat, g_flat, b_flat], axis=-1)  # (H, W, 3)
        # Vectorised nearest-palette lookup
        diffs = (
            flat_rgb[:, :, _np.newaxis, :]
            - leger_pal[_np.newaxis, _np.newaxis, :, :]
        )                                                         # (H, W, 7, 3)
        nearest_idx = (diffs ** 2).sum(axis=-1).argmin(axis=-1)  # (H, W)
        nearest_col = leger_pal[nearest_idx]                     # (H, W, 3)

        ps = float(primary_shift)
        r_snap = r_flat * (1.0 - ps) + nearest_col[:, :, 0] * ps
        g_snap = g_flat * (1.0 - ps) + nearest_col[:, :, 1] * ps
        b_snap = b_flat * (1.0 - ps) + nearest_col[:, :, 2] * ps

        # Optional flat_fill_strength blend with original
        ffs = float(flat_fill_strength)
        r_fill = r0 * (1.0 - ffs) + r_snap * ffs
        g_fill = g0 * (1.0 - ffs) + g_snap * ffs
        b_fill = b0 * (1.0 - ffs) + b_snap * ffs

        # ── 4. Force contour pixels toward near-black ──────────────────────────
        cs = float(contour_strength)
        black = 0.06
        em = thick_edge
        r1 = r_fill * (1.0 - em * cs) + black * (em * cs)
        g1 = g_fill * (1.0 - em * cs) + black * (em * cs)
        b1 = b_fill * (1.0 - em * cs) + black * (em * cs)

        # ── 5. Blend with original canvas ─────────────────────────────────────
        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(
            (r0 * (1.0 - op) + r1 * op) * 255, 0, 255
        ).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(
            (g0 * (1.0 - op) + g1 * op) * 255, 0, 255
        ).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(
            (b0 * (1.0 - op) + b1 * op) * 255, 0, 255
        ).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Léger Tubist Contour pass complete.")

    def kandinsky_geometric_resonance_pass(
        self,
        reference=None,
        n_circles: int = 18,
        n_triangles: int = 14,
        n_tension_lines: int = 22,
        n_squares: int = 10,
        n_arcs: int = 7,
        primitive_scale: float = 1.0,
        synesthetic_strength: float = 0.75,
        opacity: float = 0.65,
        seed: int = 197,
    ) -> None:
        """
        Kandinsky Geometric Resonance pass — synesthetic geometric abstraction.

        Inspired by Kandinsky's Bauhaus phase (1922–1933) and his treatise
        "Concerning the Spiritual in Art" (1911): each geometric primitive carries
        a specific acoustic-colour identity per his synesthetic theory:
          • Cadmium yellow   → triangles  (advancing, trumpet-sharp, restless)
          • Ultramarine blue → circles    (receding, cello-deep, heavenly)
          • Vermilion red    → squares    (stable, drumbeat warmth, earthbound)
          • Near-black       → tension lines (extinguished resonance, structure)
          • Violet           → open arcs  (wavering, uncertain, fading to silence)

        Algorithm:
          1. Compute canvas gradient magnitude → interest map.  If reference
             is provided, blend its gradient into the interest map (50/50).
          2. Sample n_circles positions weighted toward HIGH-gradient loci
             (blue circles float in complex spatial depths); draw 2–3 concentric
             rings per centre.
          3. Sample n_triangles positions weighted toward LOW-gradient (flat)
             zones (yellow triangles advance from calm areas); draw equilateral
             triangles at random rotation.
          4. Sample n_tension_lines positions at PEAK-gradient loci; connect
             adjacent pairs with near-black lines (structural tension).
          5. Sample n_squares positions from MID-TONE stable regions; draw
             rotated squares with vermilion fill.
          6. Sample n_arcs positions; draw open violet arcs (partial circles)
             at random sweep angles.
          7. Apply 1 px Gaussian blur to the geometric overlay for painterly
             integration, then alpha-blend onto canvas at `opacity`.

        NOVEL: 108TH DISTINCT MODE. FIRST pass to implement Kandinsky's
        SYNESTHETIC COLOUR THEORY directly as geometric form-placement rules —
        each primitive type is locked to its acoustic-colour identity and
        placed in spatially distinct zones (circles in complex areas, triangles
        in calm, lines on edges, squares in mid-tones). No prior pass uses
        interest-map-stratified multi-primitive geometric scatter with
        per-type synesthetic palette assignment. Distinct from all 107 prior
        passes.
        """
        import numpy as _np
        from PIL import Image as _Image, ImageDraw as _IDraw, ImageFilter as _IF
        from scipy.ndimage import convolve as _conv
        import math as _math

        W, H = self.canvas.w, self.canvas.h
        _rng = _np.random.default_rng(int(seed))

        # Capture canvas (BGRA: ch0=B, ch1=G, ch2=R, ch3=A)
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        # ── 1. Gradient interest map ─────────────────────────────────────────
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        sobel_x = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        sobel_y = _np.array([[-1, -2, -1], [0, 0, 0], [1, 2, 1]], dtype=_np.float32)
        gx = _conv(lum, sobel_x, mode="reflect")
        gy = _conv(lum, sobel_y, mode="reflect")
        grad_mag = _np.sqrt(gx ** 2 + gy ** 2)
        grad_norm = _np.clip(grad_mag / (_np.percentile(grad_mag, 99.0) + 1e-8), 0.0, 1.0)

        if reference is not None:
            try:
                ref_arr = _np.asarray(reference, dtype=_np.float32)
                if ref_arr.max() > 1.5:
                    ref_arr = ref_arr / 255.0
                ref_lum = (
                    0.299 * ref_arr[:, :, 0] +
                    0.587 * ref_arr[:, :, 1] +
                    0.114 * ref_arr[:, :, 2]
                ) if ref_arr.ndim == 3 else ref_arr
                if ref_lum.shape != (H, W):
                    ref_pil_g = _Image.fromarray(
                        (ref_lum * 255).clip(0, 255).astype(_np.uint8)
                    ).resize((W, H), _Image.LANCZOS)
                    ref_lum = _np.array(ref_pil_g, dtype=_np.float32) / 255.0
                rgx = _conv(ref_lum, sobel_x, mode="reflect")
                rgy = _conv(ref_lum, sobel_y, mode="reflect")
                ref_grad = _np.clip(
                    _np.sqrt(rgx ** 2 + rgy ** 2) /
                    (_np.percentile(_np.sqrt(rgx ** 2 + rgy ** 2), 99.0) + 1e-8),
                    0.0, 1.0,
                )
                grad_norm = 0.5 * grad_norm + 0.5 * ref_grad
            except Exception:
                pass

        # ── 2. Per-primitive sampling weight maps ────────────────────────────
        # Circles  → high-gradient zones (complex, receding depths)
        w_high = (grad_norm ** 1.5 + 0.04).ravel()
        w_high /= w_high.sum()
        # Triangles → flat/calm zones (advancing from stillness)
        w_calm = ((1.0 - grad_norm) ** 1.5 + 0.04).ravel()
        w_calm /= w_calm.sum()
        # Tension lines → peak-gradient loci (structural edges)
        w_edge = (grad_norm ** 3.0 + 0.01).ravel()
        w_edge /= w_edge.sum()
        # Squares → mid-tone stable zones (earthbound, steady)
        mid_dist = 1.0 - _np.abs(lum - 0.50) * 2.0
        w_mid = (_np.clip(mid_dist, 0.0, 1.0) ** 1.5 + 0.03).ravel()
        w_mid /= w_mid.sum()
        # Arcs → uniform scatter (wavering, undefined presence)
        w_uni = _np.ones(H * W, dtype=_np.float32) / (H * W)

        def _sample(n, weights):
            """Sample n unique pixel positions with given weights."""
            n = max(1, int(n))
            indices = _rng.choice(H * W, size=min(n, H * W), replace=False, p=weights)
            ys, xs = _np.unravel_index(indices, (H, W))
            return list(zip(xs.tolist(), ys.tolist()))

        # ── 3. Kandinsky synesthetic palette (RGB uint8) ─────────────────────
        KAN_YELLOW = (244, 215, 31)   # cadmium yellow — trumpet-sharp
        KAN_BLUE   = (20,  46,  173)  # ultramarine blue — cello-deep
        KAN_RED    = (209, 41,  31)   # vermilion red — drumbeat
        KAN_BLACK  = (15,  15,  15)   # near-black — extinguished resonance
        KAN_VIOLET = (140, 56,  179)  # violet — wavering, uncertain

        # ── 4. Geometric overlay (RGBA transparent canvas) ───────────────────
        overlay = _Image.new("RGBA", (W, H), (0, 0, 0, 0))
        draw = _IDraw.Draw(overlay, "RGBA")

        short = min(W, H)
        base_r = max(6, int(short * 0.050 * float(primitive_scale)))
        base_t = max(8, int(short * 0.060 * float(primitive_scale)))
        base_s = max(5, int(short * 0.040 * float(primitive_scale)))
        alpha = int(_np.clip(float(synesthetic_strength) * 220 + 20, 40, 240))

        # ── Circles (ultramarine blue) ────────────────────────────────────────
        for cx, cy in _sample(n_circles, w_high):
            r = int(base_r * (0.55 + _rng.random() * 0.90))
            for ring in range(3):
                rr = r - ring * max(2, r // 5)
                if rr <= 1:
                    break
                ring_alpha = int(alpha * (1.0 - ring * 0.28))
                ring_w = max(1, r // 7 - ring)
                draw.ellipse(
                    [cx - rr, cy - rr, cx + rr, cy + rr],
                    outline=(*KAN_BLUE, ring_alpha),
                    width=ring_w,
                )

        # ── Triangles (cadmium yellow) ────────────────────────────────────────
        for tx, ty in _sample(n_triangles, w_calm):
            size = int(base_t * (0.55 + _rng.random() * 0.90))
            angle = _rng.random() * 2.0 * _math.pi
            pts = [
                (tx + size * _math.cos(angle + k * 2.094395),
                 ty + size * _math.sin(angle + k * 2.094395))
                for k in range(3)
            ]
            draw.polygon(
                pts,
                fill=(*KAN_YELLOW, alpha),
                outline=(*KAN_BLACK, min(255, alpha + 30)),
            )

        # ── Tension lines (near-black) ────────────────────────────────────────
        line_pts = _sample(n_tension_lines, w_edge)
        lw = max(1, base_r // 6)
        for i in range(0, len(line_pts) - 1, 2):
            x1, y1 = line_pts[i]
            x2, y2 = line_pts[i + 1]
            draw.line([(x1, y1), (x2, y2)],
                      fill=(*KAN_BLACK, int(alpha * 0.88)),
                      width=lw)

        # ── Squares (vermilion red) ───────────────────────────────────────────
        for sx, sy in _sample(n_squares, w_mid):
            s = int(base_s * (0.50 + _rng.random() * 0.80))
            angle = _rng.random() * _math.pi * 0.5  # 0–90° rotation
            diag = s * _math.sqrt(2.0) * 0.5
            corners = [
                (sx + diag * _math.cos(angle + k * 1.5707963),
                 sy + diag * _math.sin(angle + k * 1.5707963))
                for k in range(4)
            ]
            draw.polygon(
                corners,
                fill=(*KAN_RED, alpha),
                outline=(*KAN_BLACK, min(255, alpha + 25)),
            )

        # ── Arcs (violet) — open partial circles, wavering ───────────────────
        for ax, ay in _sample(n_arcs, w_uni):
            ar = int(base_r * (0.70 + _rng.random() * 1.0))
            start_deg = int(_rng.random() * 360)
            sweep_deg = int(60 + _rng.random() * 200)
            aw = max(1, base_r // 5)
            draw.arc(
                [ax - ar, ay - ar, ax + ar, ay + ar],
                start=start_deg,
                end=(start_deg + sweep_deg) % 360,
                fill=(*KAN_VIOLET, int(alpha * 0.80)),
                width=aw,
            )

        # ── 5. Soft blur for painterly integration ────────────────────────────
        overlay = overlay.filter(_IF.GaussianBlur(radius=1))

        # ── 6. Alpha-blend overlay onto canvas ───────────────────────────────
        ov_arr = _np.array(overlay, dtype=_np.float32) / 255.0  # (H, W, 4) RGBA
        blend = ov_arr[:, :, 3] * float(opacity)
        r1 = r0 * (1.0 - blend) + ov_arr[:, :, 0] * blend
        g1 = g0 * (1.0 - blend) + ov_arr[:, :, 1] * blend
        b1 = b0 * (1.0 - blend) + ov_arr[:, :, 2] * blend

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Kandinsky Geometric Resonance pass complete.")

    def chirico_metaphysical_shadow_pass(
        self,
        reference=None,
        shadow_angle: float = 225.0,
        shadow_length: float = 0.35,
        shadow_opacity: float = 0.72,
        warm_strength: float = 0.45,
        warm_opacity: float = 0.38,
        edge_threshold: float = 0.18,
        seed: int = 198,
        opacity: float = 0.80,
    ) -> None:
        """
        De Chirico Metaphysical Shadow pass — directional shadow ray casting.

        Inspired by Giorgio de Chirico's Pittura Metafisica (1909–1919):
        impossibly long shadows cast at a low sun angle across empty piazzas,
        warm ochre light on architectural surfaces, cool Prussian-blue-grey
        in the shadow zones.

        Algorithm:
          1. Compute canvas luminance gradient magnitude → silhouette map.
             Threshold at `edge_threshold` fraction of the 99th percentile
             to identify strong shadow-casting edges.
          2. For each detected edge pixel, cast a SHADOW RAY of
             `shadow_length * min(W, H)` pixels along the unified
             direction vector defined by `shadow_angle` (degrees from
             positive-x, counter-clockwise). Deposit a cool Prussian-
             blue-grey tinted, darkened colour at each ray step; opacity
             falls off linearly from `shadow_opacity` at the caster to
             zero at the ray tip.
          3. Build a WARM HIGHLIGHT OVERLAY: pixels whose luminance
             exceeds 0.60 are nudged toward terracotta ochre
             (0.87, 0.72, 0.30) at strength `warm_strength`.
          4. Composite: first blend shadow overlay onto canvas at its
             per-pixel opacity, then blend warm highlight overlay at
             `warm_opacity`, finally scale the whole composite by the
             global `opacity` scalar.

        NOVEL: 109TH DISTINCT MODE. FIRST pass to use DIRECTIONAL SHADOW
        RAY CASTING — deriving silhouette edges from the canvas gradient
        and projecting long attenuated shadow rays along a unified
        directional vector with distance-falloff cool tinting. Combined
        with a WARM HIGHLIGHT OVERLAY (two-temperature split), this
        replicates de Chirico's signature metaphysical light. Distinct
        from all 108 prior passes.
        """
        import numpy as _np
        from scipy.ndimage import convolve as _conv

        W, H = self.canvas.w, self.canvas.h
        _rng = _np.random.default_rng(int(seed))

        # Capture canvas (BGRA)
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        # ── 1. Gradient-based silhouette / edge map ──────────────────────────
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        sobel_x = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        sobel_y = _np.array([[-1, -2, -1], [0, 0, 0], [1, 2, 1]], dtype=_np.float32)
        gx = _conv(lum, sobel_x, mode="reflect")
        gy = _conv(lum, sobel_y, mode="reflect")
        grad_mag = _np.sqrt(gx ** 2 + gy ** 2)
        p99 = _np.percentile(grad_mag, 99.0) + 1e-8
        edge_mask = grad_mag > (float(edge_threshold) * p99)  # (H, W) bool

        # ── 2. Shadow ray casting ────────────────────────────────────────────
        import math as _math
        ang_rad = float(shadow_angle) * _math.pi / 180.0
        dx = _math.cos(ang_rad)
        dy = -_math.sin(ang_rad)   # image y-axis is flipped

        ray_len = int(float(shadow_length) * min(W, H))
        ray_len = max(4, ray_len)

        # Prussian blue-grey shadow colour
        SHADOW_R, SHADOW_G, SHADOW_B = 0.18, 0.22, 0.38

        # Accumulate shadow contribution: (H, W) float for each channel + alpha
        shad_r = _np.zeros((H, W), dtype=_np.float32)
        shad_g = _np.zeros((H, W), dtype=_np.float32)
        shad_b = _np.zeros((H, W), dtype=_np.float32)
        shad_a = _np.zeros((H, W), dtype=_np.float32)

        ys_e, xs_e = _np.where(edge_mask)

        for step in range(1, ray_len + 1):
            attenuation = 1.0 - step / ray_len   # linear falloff
            px_offset = int(round(dx * step))
            py_offset = int(round(dy * step))

            # Vectorised: compute destination coordinates
            xs_d = xs_e + px_offset
            ys_d = ys_e + py_offset

            # Clip to canvas bounds
            valid = (xs_d >= 0) & (xs_d < W) & (ys_d >= 0) & (ys_d < H)
            xs_v = xs_d[valid]
            ys_v = ys_d[valid]

            step_alpha = float(shadow_opacity) * attenuation

            # Mix shadow colour with existing pixel via multiply-darken:
            # result = existing * (1 - step_alpha) + shadow_colour * step_alpha
            existing_r = r0[ys_v, xs_v]
            existing_g = g0[ys_v, xs_v]
            existing_b = b0[ys_v, xs_v]

            # Darken: shadow is a mix of the cool shadow hue and a darkened version
            target_r = existing_r * 0.45 + SHADOW_R * 0.55
            target_g = existing_g * 0.45 + SHADOW_G * 0.55
            target_b = existing_b * 0.45 + SHADOW_B * 0.55

            # Accumulate using max-alpha blending (shadows stack)
            shad_r[ys_v, xs_v] = _np.maximum(
                shad_r[ys_v, xs_v], target_r * step_alpha
            )
            shad_g[ys_v, xs_v] = _np.maximum(
                shad_g[ys_v, xs_v], target_g * step_alpha
            )
            shad_b[ys_v, xs_v] = _np.maximum(
                shad_b[ys_v, xs_v], target_b * step_alpha
            )
            shad_a[ys_v, xs_v] = _np.maximum(
                shad_a[ys_v, xs_v], step_alpha
            )

        # ── 3. Warm highlight overlay ────────────────────────────────────────
        WARM_R, WARM_G, WARM_B = 0.87, 0.72, 0.30
        bright_mask = (lum > 0.60).astype(_np.float32)
        ws = float(warm_strength)
        warm_r = r0 * (1.0 - ws) + WARM_R * ws
        warm_g = g0 * (1.0 - ws) + WARM_G * ws
        warm_b = b0 * (1.0 - ws) + WARM_B * ws
        warm_alpha = bright_mask * float(warm_opacity)

        # ── 4. Composite: shadow → warm → global opacity ─────────────────────
        # Apply shadow overlay
        a_s = shad_a  # (H, W) per-pixel shadow alpha
        r1 = r0 * (1.0 - a_s) + shad_r
        g1 = g0 * (1.0 - a_s) + shad_g
        b1 = b0 * (1.0 - a_s) + shad_b

        # Apply warm highlight on top
        r1 = r1 * (1.0 - warm_alpha) + warm_r * warm_alpha
        g1 = g1 * (1.0 - warm_alpha) + warm_g * warm_alpha
        b1 = b1 * (1.0 - warm_alpha) + warm_b * warm_alpha

        # Global opacity blend back to original
        op = float(opacity)
        r1 = r0 * (1.0 - op) + r1 * op
        g1 = g0 * (1.0 - op) + g1 * op
        b1 = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    De Chirico Metaphysical Shadow pass complete.")

    def aivazovsky_marine_luminance_pass(
        self,
        horizon_y: float = 0.42,
        wave_frequency: float = 8.0,
        wave_amplitude: float = 0.06,
        crest_jade: tuple = (0.18, 0.52, 0.40),
        trough_navy: tuple = (0.06, 0.14, 0.32),
        crest_strength: float = 0.68,
        trough_strength: float = 0.55,
        horizon_glow: tuple = (0.88, 0.78, 0.48),
        horizon_glow_width: float = 0.08,
        horizon_glow_strength: float = 0.60,
        foam_strength: float = 0.50,
        seed: int = 199,
        opacity: float = 0.80,
    ) -> None:
        """
        Aivazovsky Marine Luminance pass — translucent wave crest luminance.

        Inspired by Ivan Aivazovsky's Russian Romantic seascapes (1840–1900):
        the backlit jade-translucency of breaking wave crests, deep navy indigo
        in the wave troughs, and the warm amber-gold radiance at the horizon
        line where sky meets sea.

        Algorithm:
          1. Build a WAVE PHASE MAP via horizontal Perlin noise decomposition.
             A 2D noise field with high horizontal frequency identifies crest
             vs trough positions across the water area (below `horizon_y`).
             Crest zones: noise peak > threshold. Trough zones: noise < 0.
          2. CREST LUMINANCE INJECTION: at crest zones, push colour toward
             translucent jade-green `crest_jade` at `crest_strength`. This
             simulates Aivazovsky's thin-film backlit translucency — light
             penetrating the upper surface of the wave from behind.
          3. TROUGH DEEPENING: at trough zones, push colour toward deep navy
             `trough_navy` at `trough_strength`. The dark trough between
             crests creates the high-contrast energy of the sea.
          4. HORIZON RADIANCE BAND: a Gaussian-falloff band centred at
             `horizon_y` ± `horizon_glow_width` pushes colours toward warm
             amber-gold `horizon_glow` at `horizon_glow_strength`. This
             replicates Aivazovsky's glowing sea-horizon light path.
          5. FOAM SPRAY OVERLAY: at the highest crest peaks, scatter fine
             bright near-white dots (foam_strength controls density) using
             the wave phase map's extreme high values.
          6. Alpha-blend the composite onto the canvas at global `opacity`.

        NOVEL: 110TH DISTINCT MODE. FIRST pass to use TRANSLUCENT WAVE
        LUMINANCE DECOMPOSITION — a horizontal Perlin frequency analysis
        that locates crest vs trough zones and applies opposing colour
        temperatures (warm jade translucency at crests, deep navy at troughs).
        Combined with a HORIZON RADIANCE BAND (warm amber glow at the
        sea-horizon intersection), this replicates Aivazovsky's signature
        optical discovery of backlit wave-crest translucency. Distinct from
        all 109 prior passes.
        """
        import numpy as _np
        from noise import pnoise2 as _pnoise2

        W, H = self.canvas.w, self.canvas.h
        _rng = _np.random.default_rng(int(seed))

        # Capture canvas (BGRA)
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()

        ys = _np.linspace(0.0, 1.0, H)[:, _np.newaxis]   # (H,1)
        xs = _np.linspace(0.0, 1.0, W)[_np.newaxis, :]   # (1,W)

        # Water zone mask: below horizon_y
        hz = float(horizon_y)
        water_mask = _np.clip((ys - hz) / max(0.04, hz * 0.05), 0.0, 1.0).astype(_np.float32)

        # ── 1. Wave phase map via Perlin noise ────────────────────────────────
        # High horizontal frequency, low vertical frequency → horizontal wave bands
        wfreq = float(wave_frequency)
        base_x = float(_rng.integers(0, 1000))
        base_y = float(_rng.integers(0, 1000))
        wave_map = _np.zeros((H, W), dtype=_np.float32)
        inv_H, inv_W = 1.0 / H, 1.0 / W
        for y_idx in range(H):
            for x_idx in range(W):
                # High x-frequency for horizontal wave bands; lower y variation
                nx = (x_idx * inv_W) * wfreq + base_x
                ny = (y_idx * inv_H) * 2.0 + base_y
                n = _pnoise2(nx, ny, octaves=4, persistence=0.5, lacunarity=2.0)
                # Secondary fine-scale chop
                n2 = _pnoise2(nx * 2.3 + 7.1, ny * 1.8 + 3.4,
                              octaves=2, persistence=0.4, lacunarity=2.0)
                wave_map[y_idx, x_idx] = n * 0.70 + n2 * 0.30

        # Normalise to [-1, 1]
        wm_max = _np.abs(wave_map).max() + 1e-8
        wave_map /= wm_max

        # Crest mask: top 30% of wave_map values in water zone
        crest_threshold = 0.35
        trough_threshold = -0.30

        crest_map  = _np.clip((wave_map - crest_threshold) / (1.0 - crest_threshold + 1e-8), 0.0, 1.0)
        trough_map = _np.clip((trough_threshold - wave_map) / (1.0 - abs(trough_threshold) + 1e-8), 0.0, 1.0)

        # Only in water zone
        crest_map  *= water_mask
        trough_map *= water_mask

        # ── 2. Crest luminance injection — jade translucency ─────────────────
        cr, cg, cb = float(crest_jade[0]), float(crest_jade[1]), float(crest_jade[2])
        cs = float(crest_strength)
        alpha_c = crest_map * cs
        r1 = r1 * (1.0 - alpha_c) + cr * alpha_c
        g1 = g1 * (1.0 - alpha_c) + cg * alpha_c
        b1 = b1 * (1.0 - alpha_c) + cb * alpha_c

        # Brighten the crest zones (translucency = more light)
        lum_boost = crest_map * cs * 0.18
        r1 = _np.clip(r1 + lum_boost, 0.0, 1.0)
        g1 = _np.clip(g1 + lum_boost * 0.9, 0.0, 1.0)
        b1 = _np.clip(b1 + lum_boost * 0.7, 0.0, 1.0)

        # ── 3. Trough deepening — navy indigo ────────────────────────────────
        nr, ng, nb = float(trough_navy[0]), float(trough_navy[1]), float(trough_navy[2])
        ts = float(trough_strength)
        alpha_t = trough_map * ts
        r1 = r1 * (1.0 - alpha_t) + nr * alpha_t
        g1 = g1 * (1.0 - alpha_t) + ng * alpha_t
        b1 = b1 * (1.0 - alpha_t) + nb * alpha_t

        # ── 4. Horizon radiance band ─────────────────────────────────────────
        hr, hg, hb = float(horizon_glow[0]), float(horizon_glow[1]), float(horizon_glow[2])
        hgw = max(0.01, float(horizon_glow_width))
        hgs = float(horizon_glow_strength)
        # Gaussian falloff centred at horizon_y
        horizon_band = _np.exp(-0.5 * ((ys - hz) / hgw) ** 2).astype(_np.float32)
        # Stronger on lit water surface, taper off toward the sky
        horizon_band = horizon_band * _np.clip((1.0 - (ys - hz) / (hgw * 3.0)), 0.0, 1.0).astype(_np.float32)
        alpha_h = horizon_band * hgs
        alpha_h = _np.broadcast_to(alpha_h, (H, W)).astype(_np.float32)
        r1 = r1 * (1.0 - alpha_h) + hr * alpha_h
        g1 = g1 * (1.0 - alpha_h) + hg * alpha_h
        b1 = b1 * (1.0 - alpha_h) + hb * alpha_h

        # ── 5. Foam spray overlay — bright near-white at extreme crest peaks ─
        fs = float(foam_strength)
        foam_threshold = 0.65
        foam_map = _np.clip((wave_map - foam_threshold) / (1.0 - foam_threshold + 1e-8), 0.0, 1.0)
        foam_map *= water_mask
        # Add fine stochastic spray noise to the foam mask
        spray_noise = _rng.random((H, W)).astype(_np.float32)
        spray_noise = _np.where(spray_noise > 0.72, spray_noise, 0.0)
        foam_alpha = _np.clip(foam_map * spray_noise * fs, 0.0, 1.0)
        r1 = _np.clip(r1 + foam_alpha * 0.88, 0.0, 1.0)
        g1 = _np.clip(g1 + foam_alpha * 0.88, 0.0, 1.0)
        b1 = _np.clip(b1 + foam_alpha * 0.90, 0.0, 1.0)

        # ── 6. Global opacity blend ───────────────────────────────────────────
        op = float(opacity)
        r1 = r0 * (1.0 - op) + r1 * op
        g1 = g0 * (1.0 - op) + g1 * op
        b1 = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Aivazovsky Marine Luminance pass complete.")

    def bocklin_mythic_atmosphere_pass(
        self,
        shadow_cool:         float = 0.40,
        shadow_threshold:    float = 0.28,
        mist_strength:       float = 0.30,
        mist_color:          tuple = (0.38, 0.42, 0.54),
        highlight_threshold: float = 0.68,
        jewel_boost:         float = 0.32,
        vignette_strength:   float = 0.55,
        vignette_power:      float = 2.0,
        opacity:             float = 0.65,
    ) -> None:
        """
        Session 200 — Böcklin mythic atmosphere pass (111th distinct mode).

        Recreates the chromatic world of Arnold Böcklin's Symbolist paintings
        through TRIPARTITE LUMINANCE TONING: three luminance zones receive
        three distinct chromatic operations in a single composited pixel pass.

        (1) Shadow zone (luma < shadow_threshold):
            Pushed toward cool blue-violet near-black — the peripheral void
            darkness that frames every Böcklin composition like a vignette
            burned into the paint itself.

        (2) Midtone zone (shadow_threshold ≤ luma < highlight_threshold):
            Atmospheric mist injection — blended toward mist_color (cool
            blue-grey) — replicating Böcklin's successive thin glaze veils
            that push backgrounds into atmospheric recession.

        (3) Highlight zone (luma ≥ highlight_threshold):
            Per-pixel saturation boosted by jewel_boost — pulling colour
            toward maximum chrominance — replicating the jewel-bright impasto
            Böcklin used for mythological figures against dark surroundings.

        (4) Peripheral vignette: radial power-law falloff darkens canvas
            edges to near-black at vignette_strength (the compositional frame
            that concentrates all light on the central axis).

        shadow_cool        : strength of blue-violet push in shadows
        shadow_threshold   : luma boundary below which shadow toning applies
        mist_strength      : strength of cool-grey mist in midtones
        mist_color         : RGB target for atmospheric midtone mist
        highlight_threshold: luma boundary above which jewel saturation applies
        jewel_boost        : saturation amplification in highlight zone
        vignette_strength  : maximum darkness at canvas corners/edges
        vignette_power     : power-law curve of vignette falloff (higher = sharper)
        opacity            : final composite opacity

        NOVEL: ONE HUNDRED AND ELEVENTH DISTINCT MODE. FIRST pass to use
        TRIPARTITE LUMINANCE TONING — applying three distinct chromatic
        operations simultaneously to three luminance zones (shadow, midtone,
        highlight) in a single pixel pass. Prior passes address single zones
        or single operations: Beksiński (shadow zone + grain), de Chirico
        (shadow ray projection), Aivazovsky (horizontal wave-phase map).
        The TRIPARTITE approach gates per-pixel transformation through the
        luma value, achieving shadow-cooling, atmospheric-misting, and
        highlight jewel-saturation simultaneously in one composited layer.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()

        # ── Zone 1: Shadow — cool blue-violet near-black ─────────────────────
        sc = float(shadow_cool)
        st = float(shadow_threshold)
        bocklin_shadow_r, bocklin_shadow_g, bocklin_shadow_b = 0.06, 0.05, 0.12
        shadow_gate = _np.clip(1.0 - luma / (st + 1e-6), 0.0, 1.0)
        r1 = r1 + sc * shadow_gate * (bocklin_shadow_r - r1)
        g1 = g1 + sc * shadow_gate * (bocklin_shadow_g - g1)
        b1 = b1 + sc * shadow_gate * (bocklin_shadow_b - b1)

        # ── Zone 2: Midtone — atmospheric blue-grey mist injection ───────────
        ms = float(mist_strength)
        ht = float(highlight_threshold)
        mr, mg, mb = float(mist_color[0]), float(mist_color[1]), float(mist_color[2])
        # Gate is strongest at the midpoint of the midtone band; fades toward both boundaries
        midtone_raw = _np.clip((luma - st) / (ht - st + 1e-6), 0.0, 1.0)
        # Bell-shaped gate: peaks at midpoint of midtone range
        midtone_gate = 4.0 * midtone_raw * (1.0 - midtone_raw)   # parabolic bell, max = 1.0 at centre
        midtone_gate = midtone_gate * _np.clip(luma / (st + 1e-6), 0.0, 1.0)  # silence in shadow zone
        r1 = r1 + ms * midtone_gate * (mr - r1)
        g1 = g1 + ms * midtone_gate * (mg - g1)
        b1 = b1 + ms * midtone_gate * (mb - b1)

        # ── Zone 3: Highlight — jewel saturation boost ────────────────────────
        jb = float(jewel_boost)
        highlight_gate = _np.clip((luma - ht) / (1.0 - ht + 1e-6), 0.0, 1.0)
        # Per-pixel saturation boost: find the max channel and push other channels away from mean
        chan_mean = (r1 + g1 + b1) / 3.0
        r1 = r1 + jb * highlight_gate * (r1 - chan_mean)
        g1 = g1 + jb * highlight_gate * (g1 - chan_mean)
        b1 = b1 + jb * highlight_gate * (b1 - chan_mean)

        # ── Zone 4: Peripheral vignette ───────────────────────────────────────
        vs = float(vignette_strength)
        vp = float(vignette_power)
        ys_v = _np.linspace(-1.0, 1.0, H, dtype=_np.float32)[:, None]
        xs_v = _np.linspace(-1.0, 1.0, W, dtype=_np.float32)[None, :]
        radial = _np.sqrt(xs_v ** 2 + ys_v ** 2) / _np.sqrt(2.0)
        vignette_mask = _np.clip(radial ** vp, 0.0, 1.0)
        vignette_factor = 1.0 - vs * vignette_mask
        r1 = r1 * vignette_factor
        g1 = g1 * vignette_factor
        b1 = b1 * vignette_factor

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Böcklin Mythic Atmosphere pass complete.")

    def ensor_carnival_mask_pass(
        self,
        warm_boost:       float = 0.38,
        cool_boost:       float = 0.35,
        complement_ghost: float = 0.16,
        sparkle_strength: float = 0.20,
        ground_reveal:    float = 0.25,
        ground_color:     tuple = (0.72, 0.62, 0.32),
        opacity:          float = 0.65,
    ) -> None:
        """
        Session 201 — Ensor carnival mask pass (112th distinct mode).

        Recreates the chromatic world of James Ensor's Expressionist paintings
        through BIDIRECTIONAL CHROMA POLARIZATION: the dominant warm/cool hue
        direction of each pixel is amplified while simultaneously its complementary
        ghost colour is injected at reduced opacity, producing the carnival
        chromatic dissonance without a single dominant hue cast.

        Algorithm:
        (1) WARM POLARIZATION: pixels where R > B (warm-dominant) have their red
            channel boosted by warm_boost * warm_gate, where warm_gate = (R - B)
            normalised to [0, 1].  Simultaneously, a cool ghost (blue-violet
            complement) is injected at complement_ghost * warm_gate.
        (2) COOL POLARIZATION: pixels where B > R (cool-dominant) have their blue
            channel boosted by cool_boost * cool_gate, where cool_gate = (B - R)
            normalised to [0, 1].  Simultaneously, a warm ochre ghost is injected
            at complement_ghost * cool_gate.
        (3) IMPASTO SPARKLE: a high-frequency stochastic noise field is generated;
            pixels whose luma exceeds a threshold (0.55) receive a near-white
            brightness addition proportional to sparkle_strength * noise, replicating
            Ensor's loaded impasto ridges catching raking light.
        (4) OCHRE GROUND REVEAL: pixels whose luma is below a dark threshold (0.22)
            receive an injection of ground_color at ground_reveal strength, replicating
            the warm ochre ground showing through thin dark passages.

        NOVEL: ONE HUNDRED AND TWELFTH DISTINCT MODE.  FIRST pass to use
        BIDIRECTIONAL CHROMA POLARIZATION — amplifying the existing warm/cool hue
        direction of each pixel while simultaneously injecting its complement as a
        ghost colour.  Prior passes use unidirectional chroma operations:
        Böcklin (tripartite luminance toning — luminance-gated zones),
        de Chirico (shadow ray projection — directional ray casting),
        Aivazovsky (wave-phase map — horizontal frequency decomposition),
        Redon (luminous reverie bloom — dark ground retention + colour halo spread).
        The bidirectional approach is new: both the warm and cool channels are pushed
        simultaneously in opposite directions creating carnival chromatic dissonance
        without imposing a single dominant hue cast and without spatial masking.

        warm_boost        : amplification strength for warm-dominant pixels (R > B)
        cool_boost        : amplification strength for cool-dominant pixels (B > R)
        complement_ghost  : opacity of the complementary hue ghost injected into each zone
        sparkle_strength  : intensity of stochastic impasto highlight sparkle
        ground_reveal     : opacity at which ochre ground shows through dark passages
        ground_color      : warm ground colour (RGB tuple in [0, 1])
        opacity           : final composite blend opacity
        """
        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        rng = _np.random.default_rng(201)

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()

        # ── 1. Warm polarization: R > B pixels ───────────────────────────────
        wb = float(warm_boost)
        cg = float(complement_ghost)
        warm_diff = _np.clip(r0 - b0, 0.0, 1.0)          # positive where warm-dominant
        warm_gate = warm_diff / (warm_diff.max() + 1e-8)  # normalise to [0, 1]

        # Boost red channel in warm-dominant zones
        r1 = _np.clip(r1 + wb * warm_gate * (1.0 - r1), 0.0, 1.0)

        # Inject cool (blue-violet) ghost into warm zones
        cool_ghost_r, cool_ghost_g, cool_ghost_b = 0.20, 0.18, 0.72
        ghost_alpha_w = cg * warm_gate
        r1 = r1 * (1.0 - ghost_alpha_w) + cool_ghost_r * ghost_alpha_w
        g1 = g1 * (1.0 - ghost_alpha_w) + cool_ghost_g * ghost_alpha_w
        b1 = b1 * (1.0 - ghost_alpha_w) + cool_ghost_b * ghost_alpha_w

        # ── 2. Cool polarization: B > R pixels ───────────────────────────────
        cb = float(cool_boost)
        cool_diff = _np.clip(b0 - r0, 0.0, 1.0)          # positive where cool-dominant
        cool_gate = cool_diff / (cool_diff.max() + 1e-8)  # normalise to [0, 1]

        # Boost blue channel in cool-dominant zones
        b1 = _np.clip(b1 + cb * cool_gate * (1.0 - b1), 0.0, 1.0)

        # Inject warm (golden-ochre) ghost into cool zones
        warm_ghost_r, warm_ghost_g, warm_ghost_b = 0.88, 0.68, 0.12
        ghost_alpha_c = cg * cool_gate
        r1 = r1 * (1.0 - ghost_alpha_c) + warm_ghost_r * ghost_alpha_c
        g1 = g1 * (1.0 - ghost_alpha_c) + warm_ghost_g * ghost_alpha_c
        b1 = b1 * (1.0 - ghost_alpha_c) + warm_ghost_b * ghost_alpha_c

        # ── 3. Impasto sparkle: bright near-white on high-luma ridges ────────
        ss = float(sparkle_strength)
        luma = 0.2126 * r1 + 0.7152 * g1 + 0.0722 * b1
        sparkle_noise = rng.random((H, W)).astype(_np.float32)
        # Only brightest noise points contribute (top ~28% of noise values)
        sparkle_mask = _np.where(sparkle_noise > 0.72, sparkle_noise - 0.72, 0.0)
        sparkle_mask /= (sparkle_mask.max() + 1e-8)
        # Gate to high-luma zones only (impasto peaks are bright)
        luma_gate = _np.clip((luma - 0.55) / (1.0 - 0.55 + 1e-6), 0.0, 1.0)
        sparkle_alpha = sparkle_mask * luma_gate * ss
        r1 = _np.clip(r1 + sparkle_alpha * (0.96 - r1), 0.0, 1.0)
        g1 = _np.clip(g1 + sparkle_alpha * (0.94 - g1), 0.0, 1.0)
        b1 = _np.clip(b1 + sparkle_alpha * (0.88 - b1), 0.0, 1.0)

        # ── 4. Ochre ground reveal in darkest passages ───────────────────────
        gr = float(ground_reveal)
        gdr, gdg, gdb = float(ground_color[0]), float(ground_color[1]), float(ground_color[2])
        dark_gate = _np.clip(1.0 - luma / (0.22 + 1e-6), 0.0, 1.0)
        dark_gate = dark_gate ** 1.5  # sharpen the gate toward near-black only
        ground_alpha = dark_gate * gr
        r1 = r1 * (1.0 - ground_alpha) + gdr * ground_alpha
        g1 = g1 * (1.0 - ground_alpha) + gdg * ground_alpha
        b1 = b1 * (1.0 - ground_alpha) + gdb * ground_alpha

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        # ── 5. Global opacity composite ───────────────────────────────────────
        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Ensor Carnival Mask pass complete.")

    def rousseau_naive_luminance_pass(
        self,
        void_strength:      float = 0.55,
        foliage_strength:   float = 0.42,
        midlit_strength:    float = 0.48,
        highlight_strength: float = 0.40,
        sky_strength:       float = 0.35,
        void_color:         tuple = (0.06, 0.06, 0.18),
        foliage_color:      tuple = (0.08, 0.28, 0.10),
        midlit_color:       tuple = (0.75, 0.65, 0.25),
        highlight_color:    tuple = (0.90, 0.88, 0.78),
        sky_color:          tuple = (0.22, 0.28, 0.58),
        opacity:            float = 0.75,
    ) -> None:
        """
        Session 202 — Rousseau naïve luminance pass (113th distinct mode).

        Recreates the flat-zone quality of Henri Rousseau's jungle paintings
        through NAIVE LUMINANCE STRATIFICATION: each pixel is sorted into one
        of four discrete luminance bands and receives that band's target colour
        injection, suppressing continuous tonal gradation and producing
        Rousseau's characteristic cut-paper stacked-layer appearance.

        Algorithm:
        (1) VOID BAND (luma < 0.15): colours pushed toward deep indigo-black,
            replicating Rousseau's impenetrable jungle shadow deeps.
        (2) FOLIAGE BAND (0.15 <= luma < 0.40): colours receive a deep-green
            tint injection, replicating the characteristic dark jungle foliage
            layers that dominate his compositions.
        (3) MID-LIT BAND (0.40 <= luma < 0.68): colours pushed toward warm
            moonlit amber, replicating the sourceless golden illumination that
            falls on his figures, animals, and moonlit ground.
        (4) HIGHLIGHT BAND (luma >= 0.68): colours pushed toward cool ivory-
            white, replicating clean highlights on white robes and fur.
        (5) SKY VIGNETTE: a vertical gradient (top of canvas to bottom third)
            injects a cool blue-violet cast into the upper region, producing
            his flat theatrical sky without altering foreground foliage.

        NOVEL: ONE HUNDRED AND THIRTEENTH DISTINCT MODE.  FIRST pass to use
        NAIVE LUMINANCE STRATIFICATION — quantizing the continuous luminance
        field into discrete bands, each receiving a distinct target colour
        injection.  Prior passes operate on continuous fields: Bocklin
        (tripartite toning — continuous push toward targets), Ensor
        (bidirectional chroma polarization — channel balance detection),
        Aivazovsky (wave-phase map — spatially-driven frequency).  The
        stratification is new: each pixel belongs to exactly one band and
        receives that band's injection, producing the stepped flat-zone quality
        that defines naive art.

        void_strength      : blend strength toward indigo-black in darkest zone
        foliage_strength   : blend strength toward deep green in foliage zone
        midlit_strength    : blend strength toward amber in mid-lit zone
        highlight_strength : blend strength toward ivory in highlight zone
        sky_strength       : maximum blend strength for sky vignette at top
        void_color         : target RGB for void band (deep indigo-black)
        foliage_color      : target RGB for foliage band (deep jungle green)
        midlit_color       : target RGB for mid-lit band (moonlit amber)
        highlight_color    : target RGB for highlight band (cool ivory-white)
        sky_color          : target RGB for sky vignette (theatrical blue-violet)
        opacity            : final composite blend opacity
        """
        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo is BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()

        # Luminance (rec. 709 weights)
        luma = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0

        # ── 1. Void band (luma < 0.15) ────────────────────────────────────
        vs = float(void_strength)
        vr, vg, vb = float(void_color[0]), float(void_color[1]), float(void_color[2])
        # Smooth gate: ramps from 1 at luma=0 to 0 at luma=0.15
        void_gate = _np.clip(1.0 - luma / 0.15, 0.0, 1.0) ** 1.5
        void_alpha = void_gate * vs
        r1 = r1 * (1.0 - void_alpha) + vr * void_alpha
        g1 = g1 * (1.0 - void_alpha) + vg * void_alpha
        b1 = b1 * (1.0 - void_alpha) + vb * void_alpha

        # ── 2. Foliage band (0.15 <= luma < 0.40) ─────────────────────────
        fs = float(foliage_strength)
        fr, fg, fb = float(foliage_color[0]), float(foliage_color[1]), float(foliage_color[2])
        # Bell gate centred in this band: peaks at luma=0.275
        foliage_centre = 0.275
        foliage_width  = 0.125
        foliage_gate = _np.clip(
            1.0 - _np.abs(luma - foliage_centre) / foliage_width, 0.0, 1.0
        ) ** 1.2
        foliage_alpha = foliage_gate * fs
        r1 = r1 * (1.0 - foliage_alpha) + fr * foliage_alpha
        g1 = g1 * (1.0 - foliage_alpha) + fg * foliage_alpha
        b1 = b1 * (1.0 - foliage_alpha) + fb * foliage_alpha

        # ── 3. Mid-lit band (0.40 <= luma < 0.68) ─────────────────────────
        ms = float(midlit_strength)
        mr, mg, mb = float(midlit_color[0]), float(midlit_color[1]), float(midlit_color[2])
        midlit_centre = 0.54
        midlit_width  = 0.14
        midlit_gate = _np.clip(
            1.0 - _np.abs(luma - midlit_centre) / midlit_width, 0.0, 1.0
        ) ** 1.2
        midlit_alpha = midlit_gate * ms
        r1 = r1 * (1.0 - midlit_alpha) + mr * midlit_alpha
        g1 = g1 * (1.0 - midlit_alpha) + mg * midlit_alpha
        b1 = b1 * (1.0 - midlit_alpha) + mb * midlit_alpha

        # ── 4. Highlight band (luma >= 0.68) ───────────────────────────────
        hs = float(highlight_strength)
        hr, hg, hb = (
            float(highlight_color[0]), float(highlight_color[1]), float(highlight_color[2])
        )
        # Smooth gate: ramps from 0 at luma=0.68 to 1 at luma=1.0
        highlight_gate = _np.clip(
            (luma - 0.68) / (1.0 - 0.68 + 1e-6), 0.0, 1.0
        ) ** 1.5
        highlight_alpha = highlight_gate * hs
        r1 = r1 * (1.0 - highlight_alpha) + hr * highlight_alpha
        g1 = g1 * (1.0 - highlight_alpha) + hg * highlight_alpha
        b1 = b1 * (1.0 - highlight_alpha) + hb * highlight_alpha

        # ── 5. Sky vignette (vertical gradient, top to upper-40% of canvas) ─
        ss = float(sky_strength)
        sr, sg, sb = float(sky_color[0]), float(sky_color[1]), float(sky_color[2])
        # Gradient: 1.0 at y=0 (top row), 0.0 at y/H = 0.40
        y_norm = _np.arange(H, dtype=_np.float32)[:, None] / float(H)   # (H, 1) broadcast
        sky_gradient = _np.clip(1.0 - y_norm / 0.40, 0.0, 1.0) ** 1.5
        sky_alpha = sky_gradient * ss
        r1 = r1 * (1.0 - sky_alpha) + sr * sky_alpha
        g1 = g1 * (1.0 - sky_alpha) + sg * sky_alpha
        b1 = b1 * (1.0 - sky_alpha) + sb * sky_alpha

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        # ── 6. Global opacity composite ───────────────────────────────────
        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Rousseau Naive Luminance pass complete.")

    # Session 203 — Turner (J. M. W. Turner, 1775–1851): turner_vortex_luminance_pass

    def turner_vortex_luminance_pass(
        self,
        vortex_x:        float = 0.50,
        vortex_y:        float = 0.45,
        vortex_radius:   float = 0.38,
        core_strength:   float = 0.58,
        haze_strength:   float = 0.46,
        lum_lift:        float = 0.18,
        vortex_color:    tuple = (0.98, 0.92, 0.60),
        periphery_color: tuple = (0.32, 0.28, 0.48),
        opacity:         float = 0.72,
    ) -> None:
        """
        Session 203 — Turner vortex luminance pass (114th distinct mode).

        Recreates the radial atmospheric dissolve of J. M. W. Turner's late
        paintings through RADIAL TEMPERATURE VORTEX: a configurable vortex
        centre (default: upper-centre, where Turner typically placed the sun
        or light source) radiates warm yellow-gold outward, while distant
        pixels receive a progressive push toward cool blue-violet atmospheric
        haze.  A luminance lift is applied at the vortex core, brightening
        pixels toward white-gold to mimic the near-blinding solar intensity
        Turner described with "the sun is God."

        Algorithm:
        (1) DISTANCE MAP: for every pixel (px, py), compute normalised radial
            distance from vortex_center.  t = dist / (vortex_radius × min(W,H));
            clipped to [0, ∞) so pixels beyond the radius have t > 1.
        (2) CORE GATE (warm zone): gate = clip(1 − t, 0, 1)² — peaks at 1.0
            at the vortex centre, falls to 0 at t = 1.  Pixels receive a blend
            toward vortex_color at strength (gate × core_strength), plus a
            luminance lift: channels are pulled toward 1.0 by (gate × lum_lift),
            reproducing the near-overexposed brilliance of Turner's solar core.
        (3) HAZE GATE (cool periphery): gate = clip((t − 0.60) / 0.40, 0, 1)^1.2
            — ramps from 0 at t = 0.60 to 1.0 at t = 1.0.  Pixels receive a
            blend toward periphery_color at strength (gate × haze_strength),
            pushing outer areas into the cool blue-violet atmospheric haze that
            frames every Turner composition.
        (4) The two gates overlap in the transition band 0.60 < t < 1.0, where
            residual warmth and growing cool haze coexist — exactly as in
            Turner's middle-ground zones where forms "dematerialise into colour
            and light."
        (5) GLOBAL COMPOSITE at opacity blends the modified image over the
            original canvas.

        NOVEL: ONE HUNDRED AND FOURTEENTH DISTINCT MODE.  First pass to use
        RADIAL TEMPERATURE VORTEX — a simultaneous warm-core LUMINANCE LIFT
        combined with a cool-periphery HUE PUSH, both driven by the same
        radial distance field.  Prior passes operate on luminance bands
        (Rousseau: stratified bands), vertical toning (Bocklin: tripartite),
        wave frequency (Aivazovsky), or chroma polarity (Ensor).  The combined
        radial approach, with its warm-bright core and cool-dark rim, is new.

        vortex_x        : normalised X position of vortex centre (0=left, 1=right)
        vortex_y        : normalised Y position of vortex centre (0=top, 1=bottom)
        vortex_radius   : radius of the central warm zone as a fraction of min(W,H)
        core_strength   : blend strength toward vortex_color at the vortex centre
        haze_strength   : blend strength toward periphery_color at the canvas rim
        lum_lift        : luminance brightening added at vortex centre (pulls → 1.0)
        vortex_color    : target RGB for vortex core (warm yellow-gold)
        periphery_color : target RGB for outer haze (cool blue-violet)
        opacity         : final composite blend opacity
        """
        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo is BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()

        # ── Distance map ──────────────────────────────────────────────────────
        cx = float(vortex_x) * W
        cy = float(vortex_y) * H
        radius_px = float(vortex_radius) * float(min(W, H))

        ys = _np.arange(H, dtype=_np.float32)[:, None]   # (H, 1)
        xs = _np.arange(W, dtype=_np.float32)[None, :]   # (1, W)
        dist = _np.sqrt((xs - cx) ** 2 + (ys - cy) ** 2)
        t = dist / (radius_px + 1e-6)                    # (H, W), 0 at centre

        # ── 1. Core warm zone (t in [0, 1]) ───────────────────────────────────
        cs = float(core_strength)
        cr, cg, cb = float(vortex_color[0]), float(vortex_color[1]), float(vortex_color[2])
        core_gate = _np.clip(1.0 - t, 0.0, 1.0) ** 2
        core_alpha = core_gate * cs
        r1 = r1 * (1.0 - core_alpha) + cr * core_alpha
        g1 = g1 * (1.0 - core_alpha) + cg * core_alpha
        b1 = b1 * (1.0 - core_alpha) + cb * core_alpha

        # Luminance lift: pull channels toward 1.0 in proportion to core gate
        ll = float(lum_lift)
        lift_alpha = core_gate * ll
        r1 = r1 + (1.0 - r1) * lift_alpha
        g1 = g1 + (1.0 - g1) * lift_alpha
        b1 = b1 + (1.0 - b1) * lift_alpha

        # ── 2. Periphery haze zone (t > 0.60) ─────────────────────────────────
        hs = float(haze_strength)
        hr, hg, hb = (
            float(periphery_color[0]),
            float(periphery_color[1]),
            float(periphery_color[2]),
        )
        haze_raw = _np.clip((t - 0.60) / 0.40, 0.0, 1.0)
        haze_gate = haze_raw ** 1.2
        haze_alpha = haze_gate * hs
        r1 = r1 * (1.0 - haze_alpha) + hr * haze_alpha
        g1 = g1 * (1.0 - haze_alpha) + hg * haze_alpha
        b1 = b1 * (1.0 - haze_alpha) + hb * haze_alpha

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        # ── 3. Global opacity composite ───────────────────────────────────────
        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Turner Vortex Luminance pass complete.")

    # Session 204 — Hopper (Edward Hopper, 1882–1967): hopper_raking_light_pass

    def hopper_raking_light_pass(
        self,
        light_x:         float = -0.70,
        light_y:         float = -0.30,
        threshold:       float = 0.48,
        margin:          float = 0.08,
        lit_strength:    float = 0.52,
        shadow_strength: float = 0.44,
        edge_contrast:   float = 1.35,
        lit_color:       tuple = (0.97, 0.92, 0.70),
        shadow_color:    tuple = (0.48, 0.52, 0.55),
        opacity:         float = 0.68,
    ) -> None:
        """
        Session 204 — Hopper raking light pass (115th distinct mode).

        Recreates the stark directional light of Edward Hopper's paintings
        through DIRECTIONAL LIGHT BAND ISOLATION: each pixel's normalised canvas
        position is projected onto a configurable directional light vector,
        yielding a per-pixel exposure scalar.  The exposure field is normalised
        to [0, 1] and split into warm-lit and cool-shadow zones by a soft
        threshold, with edge-contrast amplification at the boundary producing
        Hopper's characteristic hard geometric 'knife-edge' light boundary.

        Algorithm:
        (1) EXPOSURE FIELD: for every pixel (px, py), normalise its canvas
            position to [-0.5, 0.5] in both axes, then project onto the
            (normalised) light direction vector: exposure = dot(pos, -light_dir).
            Normalise the resulting scalar field to [0, 1] across the canvas.
        (2) LIT ZONE (exposure > threshold + margin): apply a smooth gate that
            ramps from 0 at the threshold boundary to 1 deep in the lit zone.
            Pixels receive a blend toward lit_color at (gate × lit_strength),
            plus a luminance lift that pulls all channels toward 1.0.
        (3) SHADOW ZONE (exposure < threshold − margin): apply a symmetric
            smooth gate.  Pixels receive a blend toward shadow_color at
            (gate × shadow_strength), plus a slight luminance reduction.
        (4) TRANSITION ZONE (|exposure − threshold| < margin): luminance contrast
            is amplified by edge_contrast, pulling pixel luminance away from the
            mid-grey midpoint — values above mid-grey brighten, values below
            darken — sharpening the lit/shadow boundary to a hard architectural
            edge.
        (5) GLOBAL COMPOSITE at opacity blends the modified image over the
            original canvas.

        NOVEL: ONE HUNDRED AND FIFTEENTH DISTINCT MODE.  First pass to use
        DIRECTIONAL LIGHT BAND ISOLATION — a geometric dot-product projection of
        each pixel's canvas position onto a directional light vector, creating a
        continuous angular exposure field subsequently thresholded into warm/cool
        zones with boundary contrast amplification.  Prior passes: Rousseau
        (luminance band stratification — brightness-driven), Turner (radial
        distance from a point), Bruegel (vertical Y-axis recession), Ensor
        (chroma polarity detection).  The directional projection is new:
        exposure is a geometric scalar dot(pos, light_dir), independent of
        pixel luminance, radial distance, or any single image axis alone.

        light_x         : X component of light direction vector (negative = light from left)
        light_y         : Y component of light direction vector (negative = light from top)
        threshold       : normalised exposure value separating lit from shadow (0–1)
        margin          : half-width of the soft transition band around threshold
        lit_strength    : blend strength toward lit_color in the lit zone
        shadow_strength : blend strength toward shadow_color in the shadow zone
        edge_contrast   : luminance contrast amplification in the transition zone (1.0 = none)
        lit_color       : target RGB for the lit zone (warm yellow-white)
        shadow_color    : target RGB for the shadow zone (cool blue-grey)
        opacity         : final composite blend opacity
        """
        import numpy as _np

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo is BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()

        # ── Directional exposure field ─────────────────────────────────────────
        lx, ly = float(light_x), float(light_y)
        mag = _np.sqrt(lx ** 2 + ly ** 2) + 1e-6
        lx, ly = lx / mag, ly / mag

        # Pixel positions normalised to [-0.5, 0.5]
        xs = (_np.arange(W, dtype=_np.float32)[None, :] / float(W)) - 0.5   # (1, W)
        ys = (_np.arange(H, dtype=_np.float32)[:, None] / float(H)) - 0.5   # (H, 1)

        # Project onto reversed light direction: high value = facing the light
        exposure = -(xs * lx + ys * ly)   # (H, W)
        exp_min = exposure.min()
        exp_max = exposure.max()
        exposure = (exposure - exp_min) / (exp_max - exp_min + 1e-6)

        th = float(threshold)
        mg = float(margin)

        # ── 1. Lit zone (exposure > threshold + margin) ────────────────────────
        ls = float(lit_strength)
        lr, lg, lb = float(lit_color[0]), float(lit_color[1]), float(lit_color[2])
        lit_gate = _np.clip((exposure - (th + mg)) / (mg + 1e-6), 0.0, 1.0) ** 1.3
        lit_alpha = lit_gate * ls
        r1 = r1 * (1.0 - lit_alpha) + lr * lit_alpha
        g1 = g1 * (1.0 - lit_alpha) + lg * lit_alpha
        b1 = b1 * (1.0 - lit_alpha) + lb * lit_alpha
        # Luminance lift: pull channels toward 1.0 in lit zone; scales with lit_strength
        lift = lit_gate * ls * 0.22
        r1 = r1 + (1.0 - r1) * lift
        g1 = g1 + (1.0 - g1) * lift
        b1 = b1 + (1.0 - b1) * lift

        # ── 2. Shadow zone (exposure < threshold − margin) ─────────────────────
        ss = float(shadow_strength)
        sr, sg, sb = float(shadow_color[0]), float(shadow_color[1]), float(shadow_color[2])
        shadow_gate = _np.clip(((th - mg) - exposure) / (mg + 1e-6), 0.0, 1.0) ** 1.3
        shadow_alpha = shadow_gate * ss
        r1 = r1 * (1.0 - shadow_alpha) + sr * shadow_alpha
        g1 = g1 * (1.0 - shadow_alpha) + sg * shadow_alpha
        b1 = b1 * (1.0 - shadow_alpha) + sb * shadow_alpha
        # Slight luminance reduction in shadow zone; scales with shadow_strength
        darken = shadow_gate * ss * 0.18
        r1 = r1 * (1.0 - darken)
        g1 = g1 * (1.0 - darken)
        b1 = b1 * (1.0 - darken)

        # ── 3. Transition zone: edge contrast amplification ────────────────────
        ec = float(edge_contrast)
        if ec > 1.0:
            transition_gate = _np.clip(
                1.0 - _np.abs(exposure - th) / (mg + 1e-6), 0.0, 1.0
            )
            luma1 = 0.2126 * r1 + 0.7152 * g1 + 0.0722 * b1
            delta = (luma1 - 0.5) * (ec - 1.0) * transition_gate
            # Scale each channel by the same factor to preserve hue
            scale = _np.clip(1.0 + delta / (luma1 + 1e-6), 0.5, 2.0)
            r1 = _np.clip(r1 * scale, 0.0, 1.0)
            g1 = _np.clip(g1 * scale, 0.0, 1.0)
            b1 = _np.clip(b1 * scale, 0.0, 1.0)

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        # ── 4. Global opacity composite ───────────────────────────────────────
        op = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()

    # Session 205 — Munch (Edvard Munch, 1863–1944): munch_anxiety_swirl_pass

    def munch_anxiety_swirl_pass(
        self,
        n_swirl_strokes:  int   = 120,
        swirl_amplitude:  float = 0.25,
        swirl_frequency:  float = 6.0,
        color_intensity:  float = 0.65,
        bg_only:          bool  = False,
        stroke_opacity:   float = 0.45,
        stroke_size:      float = 9.0,
        warm_color:       tuple = (0.82, 0.28, 0.18),
        cool_color:       tuple = (0.18, 0.22, 0.52),
        focus_points:     list  = None,
        wave_frequency:   float = 9.0,
        opacity:          float = 1.0,
    ) -> None:
        """
        Session 205 — Munch anxiety swirl pass (116th distinct mode).

        Recreates the swirling, emotionally-charged chromatic distortion of
        Edvard Munch's paintings through CHROMATIC WAVE INTERFERENCE STROKES:
        N sinusoidally-undulating stroke paths are drawn across the canvas,
        each coloured by the constructive/destructive interference field of
        multiple emotional focus points.  Where the interference waves from
        different sources constructively align, strokes are tinted toward
        warm_color (fiery red-orange); where they cancel, toward cool_color
        (deep indigo).  The stroke paths themselves curl and arc in sympathy
        with Munch's characteristic swirling brushwork.

        Algorithm:
        (1) EARLY EXIT if n_swirl_strokes == 0 or effective opacity ≤ 0 → no-op.
        (2) INTERFERENCE COLOR FIELD: at any canvas position (px, py) in [0,1],
            the field value is the mean sine of Euclidean distances to all
            focus points: field = mean(sin(dist_i * wave_frequency * 2π)).
            Normalised to t ∈ [0,1]; warm blend (t > 0.5) or cool (t < 0.5),
            scaled by color_intensity.
        (3) STROKE GENERATION: for each stroke, a random origin and direction
            angle are chosen.  The stroke path follows a sinusoidal trajectory
            perpendicular to the direction: offset = swirl_amplitude * W *
            sin(swirl_frequency * π * t + random_phase), producing n_segments
            line points.
        (4) FIGURE MASK GATE (bg_only=True): the stroke midpoint is checked
            against self._figure_mask; if it falls inside the figure (mask > 0.5),
            the stroke is skipped — preserving the figure unaltered.
        (5) DRAW: each accepted stroke is drawn with self.canvas.ctx using
            LINE_CAP_ROUND at effective_opacity = stroke_opacity × opacity.

        NOVEL: ONE HUNDRED AND SIXTEENTH DISTINCT MODE. FIRST pass to use
        CHROMATIC WAVE INTERFERENCE STROKES — sinusoidally-undulating stroke
        paths whose colour is determined by a multi-source wave interference
        field (the mean sine of distances from configurable emotional focus
        points), combining stroke-based mark-making with a multi-source
        interference colour field simultaneously.  Prior passes: Hopper
        (directional pixel composite — no stroke paths), Turner (radial
        luminance field — single source, no strokes), Aivazovsky (wave-phase
        geometry for water surface — not multi-source interference coloring),
        Rousseau (luminance band stratification — pixel-only, no strokes).
        The combination of a sinusoidal stroke trajectory with multi-source
        interference coloring is new.

        n_swirl_strokes  : number of swirl strokes to draw (0 = no-op)
        swirl_amplitude  : perpendicular undulation as a fraction of canvas width
        swirl_frequency  : number of full sine cycles along each stroke
        color_intensity  : blend strength toward warm/cool color per stroke
        bg_only          : when True, skip strokes whose midpoint falls in the
                           figure mask (self._figure_mask > 0.5)
        stroke_opacity   : per-stroke alpha value (0 = transparent, 1 = opaque)
        stroke_size      : stroke line width in pixels
        warm_color       : RGB for constructive-interference (crest) zones
        cool_color       : RGB for destructive-interference (trough) zones
        focus_points     : list of (x, y) in [0,1] canvas coords; default
                           [(0.50, 0.42), (0.25, 0.25)]
        wave_frequency   : interference oscillation frequency (cycles per unit dist)
        opacity          : global multiplier on stroke_opacity
        """
        import math as _math
        import cairo as _cairo

        if n_swirl_strokes == 0:
            return

        effective_opacity = float(stroke_opacity) * float(opacity)
        if effective_opacity <= 0.0:
            return

        if focus_points is None:
            focus_points = [(0.50, 0.42), (0.25, 0.25)]

        W, H = self.canvas.w, self.canvas.h
        rng  = self._rng_py
        ctx  = self.canvas.ctx
        fig_mask = self._figure_mask   # (H, W) float32 or None

        freq = float(wave_frequency) * 2.0 * _math.pi
        ci   = float(color_intensity)
        wr, wg, wb = float(warm_color[0]), float(warm_color[1]), float(warm_color[2])
        cr_, cg_, cb_ = float(cool_color[0]), float(cool_color[1]), float(cool_color[2])

        def interference_t(px_n: float, py_n: float) -> float:
            """Return interference field t ∈ [0,1] at normalised position."""
            if not focus_points:
                return 0.5
            total = 0.0
            for fx, fy in focus_points:
                d = _math.sqrt((px_n - fx) ** 2 + (py_n - fy) ** 2)
                total += _math.sin(d * freq)
            return (total / len(focus_points) + 1.0) * 0.5

        def stroke_color(t_val: float):
            """Interpolate between neutral grey and warm/cool based on t."""
            neutral = 0.50
            if t_val >= 0.5:
                blend = (t_val - 0.5) * 2.0 * ci
                r = wr * blend + neutral * (1.0 - blend)
                g = wg * blend + neutral * (1.0 - blend)
                b = wb * blend + neutral * (1.0 - blend)
            else:
                blend = (0.5 - t_val) * 2.0 * ci
                r = cr_ * blend + neutral * (1.0 - blend)
                g = cg_ * blend + neutral * (1.0 - blend)
                b = cb_ * blend + neutral * (1.0 - blend)
            return (
                max(0.0, min(1.0, r)),
                max(0.0, min(1.0, g)),
                max(0.0, min(1.0, b)),
            )

        amp_px = float(swirl_amplitude) * float(W)
        sw_freq_pi = float(swirl_frequency) * _math.pi

        ctx.set_line_cap(_cairo.LINE_CAP_ROUND)
        ctx.set_line_join(_cairo.LINE_JOIN_ROUND)
        ctx.set_line_width(float(stroke_size))

        for _ in range(int(n_swirl_strokes)):
            # Random start position
            x0 = rng.uniform(0.0, float(W))
            y0 = rng.uniform(0.0, float(H))

            # Random direction and swirl phase
            angle = rng.uniform(0.0, 2.0 * _math.pi)
            phase = rng.uniform(0.0, 2.0 * _math.pi)
            dx = _math.cos(angle)
            dy = _math.sin(angle)
            # Perpendicular for undulation
            px_ = -dy
            py_ = dx

            # Stroke length scaled to canvas size
            length = rng.uniform(W * 0.07, W * 0.20)
            n_seg = max(8, int(length / max(1.0, float(stroke_size) * 0.8)))

            # Build stroke points
            pts = []
            for k in range(n_seg + 1):
                t_path = k / float(n_seg)
                d = t_path * length
                undulation = amp_px * _math.sin(sw_freq_pi * t_path + phase)
                sx = x0 + dx * d + px_ * undulation
                sy = y0 + dy * d + py_ * undulation
                pts.append((sx, sy))

            # Figure mask gate at midpoint
            mid_x, mid_y = pts[len(pts) // 2]
            mi = int(min(max(mid_y, 0.0), float(H - 1)))
            mj = int(min(max(mid_x, 0.0), float(W - 1)))
            if bg_only and fig_mask is not None and fig_mask[mi, mj] > 0.5:
                continue

            # Stroke color from interference field at midpoint
            t_val = interference_t(mid_x / float(W), mid_y / float(H))
            r_c, g_c, b_c = stroke_color(t_val)

            ctx.set_source_rgba(r_c, g_c, b_c, effective_opacity)
            ctx.move_to(pts[0][0], pts[0][1])
            for sx, sy in pts[1:]:
                ctx.line_to(sx, sy)
            ctx.stroke()

        self.canvas.surface.mark_dirty()
        print("    Munch Anxiety Swirl pass complete.")

    # Session 206 — Mucha (Alphonse Mucha, 1860–1939): mucha_art_nouveau_aureole_pass

    def mucha_art_nouveau_aureole_pass(
        self,
        center_x:       float = 0.50,
        center_y:       float = 0.42,
        ring_frequency: float = 8.0,
        n_spokes:       int   = 16,
        spoke_weight:   float = 0.35,
        gold_color:     tuple = (0.90, 0.78, 0.42),
        ivory_color:    tuple = (0.95, 0.90, 0.72),
        field_strength: float = 0.48,
        opacity:        float = 0.62,
    ) -> None:
        """
        Session 206 — Mucha Art Nouveau aureole pass (117th distinct mode).

        Recreates the decorative mandala-like halos and radial ornaments of
        Alphonse Mucha's Art Nouveau compositions through ANNULAR POLAR
        DIFFRACTION: for each pixel, polar coordinates (r, θ) relative to a
        configurable focal centre (typically the portrait or figure head) are
        computed and combined into a two-dimensional decorative field.

        Algorithm:
        (1) POLAR COORDINATES: for every pixel (px, py):
            r = Euclidean distance from (center_x × W, center_y × H),
                normalised to [0, 1] by dividing by min(W, H).
            θ = atan2(py − cy, px − cx), angular position in [−π, π].
        (2) CONCENTRIC RING FIELD: ring = sin(r × ring_frequency × 2π).
            Normalised to t_ring ∈ [0, 1].  Produces equidistant concentric
            rings radiating from the focal centre — Mucha's characteristic
            circular halo bands.
        (3) RADIAL SPOKE FIELD: spoke = cos(θ × n_spokes).
            Normalised to t_spoke ∈ [0, 1].  Produces n_spokes equally-spaced
            bright radial fingers — Mucha's sunburst and starburst ornaments.
        (4) COMBINED FIELD:
            field = t_ring × (1 − spoke_weight) + t_spoke × spoke_weight.
            Peaks occur where both rings and spokes coincide — at the halo
            intersections — reproducing the decorative lozenge and petal shapes
            of Art Nouveau ornamental borders.
        (5) COLOUR APPLICATION: pixels where field > 0.5 receive a blend toward
            gold_color; pixels where field < 0.5 receive a blend toward
            ivory_color.  Both blends are gated by field_strength and a
            boundary attenuation factor that ramps to zero within 15% of each
            canvas edge, preserving the unmodified subject at canvas centre.
        (6) GLOBAL COMPOSITE at opacity blends the modified image over the
            original canvas.

        NOVEL: ONE HUNDRED AND SEVENTEENTH DISTINCT MODE.  First pass to use
        ANNULAR POLAR DIFFRACTION — simultaneous modulation of colour by BOTH
        radial distance (r) AND angular position (θ) in a polar coordinate
        frame, creating a 2D decorative field whose peaks occur at specific
        ring × spoke intersections.  Prior pixel passes: Turner (r only, no θ);
        Hopper (directional dot-product scalar — no r, no θ); Munch (multi-
        source Euclidean distance sum — no θ); Rousseau (luminance band
        stratification — no spatial polar field at all).  The joint r × θ
        polar field is new: it produces the annular-and-radial mandala pattern
        that characterises Mucha's aureoles and cannot be constructed from any
        single-variable field used by prior passes.

        center_x        : normalised X of focal centre (0 = left, 1 = right)
        center_y        : normalised Y of focal centre (0 = top, 1 = bottom)
        ring_frequency  : concentric ring cycles per unit normalised distance
        n_spokes        : number of radial spokes in the angular field
        spoke_weight    : weight of spoke field in combined field (0 = rings only,
                          1 = spokes only); 0.35 gives the Art Nouveau balance
        gold_color      : RGB target for high-field decorative zones (aureole gold)
        ivory_color     : RGB target for low-field ground zones (pale parchment)
        field_strength  : maximum blend strength toward gold/ivory at field peaks
        opacity         : final composite blend opacity
        """
        import numpy as _np
        import math as _math

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo is BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()

        # ── Polar coordinate field ─────────────────────────────────────────
        cx = float(center_x) * W
        cy = float(center_y) * H

        xs = _np.arange(W, dtype=_np.float32)[None, :]   # (1, W)
        ys = _np.arange(H, dtype=_np.float32)[:, None]   # (H, 1)

        dx = xs - cx   # (1, W), broadcasts to (H, W)
        dy = ys - cy   # (H, 1), broadcasts to (H, W)

        r_raw  = _np.sqrt(dx ** 2 + dy ** 2)
        r_norm = r_raw / float(min(W, H))          # (H, W), normalised [0, ∞)
        theta  = _np.arctan2(dy, dx)               # (H, W), angular [-π, π]

        # ── Concentric ring field ──────────────────────────────────────────
        ring_raw = _np.sin(r_norm * float(ring_frequency) * 2.0 * _math.pi)
        t_ring   = (ring_raw + 1.0) * 0.5          # [0, 1]

        # ── Radial spoke field ─────────────────────────────────────────────
        spoke_raw = _np.cos(theta * float(n_spokes))
        t_spoke   = (spoke_raw + 1.0) * 0.5        # [0, 1]

        # ── Combined decorative field ──────────────────────────────────────
        sw    = float(spoke_weight)
        field = t_ring * (1.0 - sw) + t_spoke * sw  # [0, 1]

        # ── Boundary attenuation gate (preserve subject near canvas centre) ─
        edge_x = _np.minimum(xs / W, (W - xs) / W)       # (1, W)
        edge_y = _np.minimum(ys / H, (H - ys) / H)       # (H, 1)
        boundary_gate = _np.clip(
            _np.minimum(edge_x, edge_y) / 0.15, 0.0, 1.0
        )   # 0 at canvas edges, 1 beyond 15% inset

        fs = float(field_strength) * boundary_gate   # (H, W)

        # ── Colour application ─────────────────────────────────────────────
        gr, gg, gb = float(gold_color[0]),  float(gold_color[1]),  float(gold_color[2])
        ir, ig, ib = float(ivory_color[0]), float(ivory_color[1]), float(ivory_color[2])

        gold_alpha  = _np.clip((field - 0.5) * 2.0, 0.0, 1.0) * fs
        ivory_alpha = _np.clip((0.5 - field) * 2.0, 0.0, 1.0) * fs

        r1 = r1 * (1.0 - gold_alpha)  + gr * gold_alpha
        g1 = g1 * (1.0 - gold_alpha)  + gg * gold_alpha
        b1 = b1 * (1.0 - gold_alpha)  + gb * gold_alpha

        r1 = r1 * (1.0 - ivory_alpha) + ir * ivory_alpha
        g1 = g1 * (1.0 - ivory_alpha) + ig * ivory_alpha
        b1 = b1 * (1.0 - ivory_alpha) + ib * ivory_alpha

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        # ── Global opacity composite ───────────────────────────────────────
        op  = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + r1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + g1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + b1 * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Mucha Art Nouveau Aureole pass complete.")

    # Session 207 — Robert Delaunay (1885–1941): delaunay_orphist_disk_pass

    def delaunay_orphist_disk_pass(
        self,
        *,
        n_disks:        int   = 7,
        ring_frequency: float = 5.0,
        disk_sigma:     float = 0.38,
        opacity:        float = 0.65,
        disk_centers:   list  = None,
        color_pairs:    list  = None,
    ) -> None:
        """
        Session 207 — Robert Delaunay Orphist disk pass (118th distinct mode).

        Recreates the overlapping chromatic disk fields of Robert Delaunay's
        Orphism through MULTI-DISK COMPLEMENTARY RING FIELD: N independent disk
        centres, each emitting concentric ring bands coloured by its own
        complementary pair, overlaid by proximity weighting.

        Algorithm:
        (1) DISK CENTRES: n_disks centres distributed by golden-angle spiral
            unless disk_centers is specified.
        (2) COMPLEMENTARY PAIRS: each disk k is assigned a pair (color_A_k,
            color_B_k) cycling through Delaunay's primary/complementary pairs:
            cobalt-blue/vermilion-orange, cadmium-yellow/magenta-violet,
            emerald-green/orange, blue/yellow, orange/green.
        (3) RING BAND FIELD per disk: r_k = Euclidean distance from centre k,
            normalised by min(W, H); ring_k = sin(r_k × ring_frequency × 2π),
            normalised to t_ring_k ∈ [0, 1].
        (4) PROXIMITY WEIGHT per disk: w_k = exp(−r_k² / disk_sigma²),
            normalised across all disks so sum(w_k) = 1 at each pixel.
        (5) COLOUR BLEND per disk: blend_k = t_ring_k × color_A_k +
            (1 − t_ring_k) × color_B_k.
        (6) WEIGHTED SUM: pixel colour = sum_k(w_k × blend_k).
        (7) GLOBAL OPACITY COMPOSITE at opacity blends the Orphist field over the
            original canvas.

        NOVEL: ONE HUNDRED AND EIGHTEENTH DISTINCT MODE.  First pass to use
        MULTI-DISK COMPLEMENTARY RING FIELD — multiple independent chromatic disk
        centres, each carrying its own complementary colour pair, overlaid by
        proximity weighting.  Prior passes: Mucha (single centre, r × θ joint
        field — one focal point, no complementary pairing per disk); Munch
        (multi-source scalar interference — multiple centres but only scalar
        distance sum, no ring bands, no per-centre chromatic pairing); Turner
        (single centre, r gradient — no rings, no multi-centre); Hopper
        (dot-product projection — no polar field at all).  The combination of
        multi-centre layout, per-centre complementary colour pairing, and
        proximity-weighted ring-band overlay cannot be assembled from any prior
        single pass.

        n_disks         : number of overlapping chromatic disk centres
        ring_frequency  : concentric ring cycles per unit normalised distance
        disk_sigma      : proximity fall-off radius (normalised units); controls
                          how broadly each disk's colour field spreads
        opacity         : final composite blend opacity
        disk_centers    : optional list of (x_norm, y_norm) tuples overriding
                          the golden-angle spiral distribution
        color_pairs     : optional list of ((r,g,b),(r,g,b)) tuples overriding
                          the default Delaunay complementary pairs
        """
        import numpy as _np
        import math as _math

        W, H = self.canvas.w, self.canvas.h
        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo is BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Default complementary pairs (Delaunay's Orphist palette) ──────────
        _default_pairs = [
            ((0.05, 0.22, 0.78), (0.92, 0.32, 0.05)),   # cobalt-blue / vermilion-orange
            ((0.95, 0.84, 0.06), (0.78, 0.10, 0.58)),   # cadmium-yellow / magenta-violet
            ((0.08, 0.62, 0.28), (0.92, 0.32, 0.05)),   # emerald-green / orange
            ((0.05, 0.22, 0.78), (0.95, 0.84, 0.06)),   # blue / yellow
            ((0.92, 0.32, 0.05), (0.08, 0.62, 0.28)),   # orange / green
        ]
        if color_pairs is None:
            color_pairs = _default_pairs

        # ── Disk centres: golden-angle spiral ────────────────────────────────
        if disk_centers is None:
            phi = (1.0 + _math.sqrt(5.0)) / 2.0   # golden ratio
            _centers = []
            for i in range(n_disks):
                t = float(i) / max(1, n_disks - 1)
                angle = 2.0 * _math.pi * i / phi
                # Distribute within central 80% of canvas
                radius = 0.15 + 0.30 * _math.sqrt(float(i + 1) / n_disks)
                cx = 0.50 + radius * _math.cos(angle)
                cy = 0.50 + radius * _math.sin(angle) * (float(H) / W)
                cx = max(0.05, min(0.95, cx))
                cy = max(0.05, min(0.95, cy))
                _centers.append((cx, cy))
            disk_centers = _centers

        n = len(disk_centers)
        pairs = [color_pairs[i % len(color_pairs)] for i in range(n)]

        # ── Pixel coordinate grids ────────────────────────────────────────────
        xs = _np.arange(W, dtype=_np.float32)[None, :]   # (1, W)
        ys = _np.arange(H, dtype=_np.float32)[:, None]   # (H, 1)
        scale = float(min(W, H))
        sigma2 = float(disk_sigma) ** 2

        # ── Accumulate weighted colour field ──────────────────────────────────
        acc_r = _np.zeros((H, W), dtype=_np.float32)
        acc_g = _np.zeros((H, W), dtype=_np.float32)
        acc_b = _np.zeros((H, W), dtype=_np.float32)
        acc_w = _np.zeros((H, W), dtype=_np.float32)

        for k in range(n):
            cx_k = float(disk_centers[k][0]) * W
            cy_k = float(disk_centers[k][1]) * H
            col_a, col_b = pairs[k]

            dx = xs - cx_k
            dy = ys - cy_k
            r_raw  = _np.sqrt(dx ** 2 + dy ** 2)
            r_norm = r_raw / scale   # normalised distance

            # Ring band field
            ring_raw = _np.sin(r_norm * float(ring_frequency) * 2.0 * _math.pi)
            t_ring   = (ring_raw + 1.0) * 0.5   # [0, 1]

            # Proximity weight (Gaussian fall-off)
            w_k = _np.exp(-(r_norm ** 2) / sigma2)

            # Per-disk colour blend
            blend_r = t_ring * float(col_a[0]) + (1.0 - t_ring) * float(col_b[0])
            blend_g = t_ring * float(col_a[1]) + (1.0 - t_ring) * float(col_b[1])
            blend_b = t_ring * float(col_a[2]) + (1.0 - t_ring) * float(col_b[2])

            acc_r += w_k * blend_r
            acc_g += w_k * blend_g
            acc_b += w_k * blend_b
            acc_w += w_k

        # Normalise by total weight (avoid div-by-zero)
        safe_w = _np.maximum(acc_w, 1e-8)
        field_r = acc_r / safe_w
        field_g = acc_g / safe_w
        field_b = acc_b / safe_w

        field_r = _np.clip(field_r, 0.0, 1.0)
        field_g = _np.clip(field_g, 0.0, 1.0)
        field_b = _np.clip(field_b, 0.0, 1.0)

        # ── Global opacity composite ───────────────────────────────────────────
        op  = float(opacity)
        buf = orig.copy()
        buf[:, :, 2] = _np.clip((r0 * (1 - op) + field_r * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip((g0 * (1 - op) + field_g * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip((b0 * (1 - op) + field_b * op) * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Delaunay Orphist Disk pass complete.")

    # ──────────────────────────────────────────────────────────────────────────
    # Session 208 — Franz Kline: kline_gestural_slash_pass (119th distinct mode)
    # ──────────────────────────────────────────────────────────────────────────

    def kline_gestural_slash_pass(
        self,
        *,
        n_strokes:    int   = 18,
        width_scale:  float = 0.06,
        bleed_sigma:  float = 4.0,
        opacity:      float = 0.92,
        stroke_color: tuple = (0.04, 0.04, 0.05),
        angle_noise:  float = 0.18,
        seed:         int   = 0,
    ) -> None:
        """
        Session 208 — Franz Kline gestural slash pass (119th distinct mode).

        DIRECTIONAL CALLIGRAPHIC SWEEP FIELD: dominant structural axes are
        detected from the reference canvas's luminance gradient orientation
        histogram (magnitude-weighted, 36 bins over [0, π]).  N mega-strokes
        are swept along the top-3 axes with pressure-modulated width and
        Gaussian edge bleed, producing Kline's monumental black gestures on
        white ground.

        Algorithm (fully vectorised):
        (1) AXIS DETECTION: compute luminance from current canvas, take 2-D
            gradient, build orientation histogram weighted by gradient magnitude.
            Top-3 histogram bins supply the dominant angles θ₁, θ₂, θ₃.
        (2) STROKE GENERATION: for stroke i, pick angle = θ_{i mod 3} +
            uniform(−angle_noise, +angle_noise).  Random centre (cx, cy) and
            length = uniform(0.35, 0.80) × min(W, H).  Stroke width =
            width_scale × min(W, H) × uniform(0.7, 1.4).
        (3) VECTORISED RENDER per stroke: for every canvas pixel, compute
            t_proj (signed projection along stroke axis) and d_perp
            (perpendicular distance).  Within [−half_len, +half_len] along
            axis, pressure_t = sin(π × t_norm) ∈ [0, 1].  Pixels within
            d_perp < w_px × pressure_t contribute weight =
            pressure_t × (1 − d_perp / (w_at_t + ε)).
        (4) ACCUMULATION + BLEED: stroke contributions accumulate into a
            float32 mask, then Gaussian-blurred by bleed_sigma to simulate
            paint bleed at stroke edges.
        (5) COMPOSITE: near-black stroke_color composited over the canvas at
            mask × opacity.

        NOVEL: ONE HUNDRED AND NINETEENTH DISTINCT MODE.  First pass to use
        DIRECTIONAL CALLIGRAPHIC SWEEP FIELD — discrete sweeping mega-strokes
        following structural image axes derived from luminance gradient
        orientation, with variable-pressure rectangular brush footprints and
        edge bleed.  Prior passes (Delaunay, Mucha, Munch, Hopper, Riley) all
        operate as per-pixel field functions; none accumulates discrete stroke
        objects or uses axis detection + pressure modulation + bleed together.

        n_strokes    : number of calligraphic mega-strokes
        width_scale  : stroke width as fraction of min(W, H)
        bleed_sigma  : Gaussian blur radius (pixels) for edge bleed simulation
        opacity      : final composite opacity
        stroke_color : RGB of the calligraphic marks (near-black for Kline)
        angle_noise  : random angular jitter per stroke (radians)
        seed         : RNG seed for reproducibility
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        rng = _np.random.default_rng(seed)
        W, H = self.canvas.w, self.canvas.h

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── (1) Detect dominant structural axes from luminance gradient ────────
        lum = 0.2126 * r0 + 0.7152 * g0 + 0.0722 * b0
        gy, gx = _np.gradient(lum)
        gmag   = _np.sqrt(gx ** 2 + gy ** 2)
        gangle = _np.arctan2(gy, gx)
        # Undirected orientation in [0, π)
        orient = gangle % _np.pi

        n_bins = 36
        hist, bin_edges = _np.histogram(
            orient.ravel(),
            bins=n_bins,
            range=(0.0, _np.pi),
            weights=gmag.ravel(),
        )
        top_bins   = _np.argsort(hist)[::-1][:3]
        dom_angles = [
            float((bin_edges[b] + bin_edges[b + 1]) * 0.5) for b in top_bins
        ]

        # ── (2–4) Generate and render strokes ────────────────────────────────
        min_dim   = float(min(W, H))
        base_w_px = max(4.0, min_dim * float(width_scale))

        # Pixel coordinate grids (broadcast-friendly)
        xs_grid = _np.arange(W, dtype=_np.float32)[_np.newaxis, :]  # (1, W)
        ys_grid = _np.arange(H, dtype=_np.float32)[:, _np.newaxis]  # (H, 1)

        stroke_acc = _np.zeros((H, W), dtype=_np.float32)

        for i in range(n_strokes):
            angle   = dom_angles[i % len(dom_angles)] + rng.uniform(-float(angle_noise), float(angle_noise))
            cx      = rng.uniform(0.10, 0.90) * W
            cy      = rng.uniform(0.10, 0.90) * H
            length  = rng.uniform(0.35, 0.80) * min_dim
            w_px    = base_w_px * rng.uniform(0.7, 1.4)

            dx = float(_np.cos(angle))
            dy = float(_np.sin(angle))
            # Perpendicular unit vector
            px_u = -dy
            py_u =  dx

            half_len = length * 0.5

            # Per-pixel projections (vectorised)
            rel_x  = xs_grid - cx
            rel_y  = ys_grid - cy
            t_proj = rel_x * dx + rel_y * dy          # signed along-axis distance
            d_perp = _np.abs(rel_x * px_u + rel_y * py_u)  # perp distance

            in_len  = (_np.abs(t_proj) <= half_len)
            t_norm  = (t_proj + half_len) / (2.0 * half_len + 1e-8)
            pres    = _np.sin(_np.pi * _np.clip(t_norm, 0.0, 1.0))
            w_at_t  = w_px * pres

            in_wid  = (d_perp < (w_at_t + 0.5))
            contrib = pres * _np.clip(1.0 - d_perp / (w_at_t + 1e-6), 0.0, 1.0)
            stroke_acc += _np.where(in_len & in_wid, contrib * 0.55, 0.0)

        # ── (4) Edge bleed ────────────────────────────────────────────────────
        stroke_mask = _gf(_np.clip(stroke_acc, 0.0, 3.0), sigma=float(bleed_sigma))
        stroke_mask = _np.clip(stroke_mask, 0.0, 1.0)

        # ── (5) Composite ─────────────────────────────────────────────────────
        sc_r = float(stroke_color[0])
        sc_g = float(stroke_color[1])
        sc_b = float(stroke_color[2])
        op   = float(opacity)

        alpha = stroke_mask * op
        new_r = r0 * (1.0 - alpha) + sc_r * alpha
        new_g = g0 * (1.0 - alpha) + sc_g * alpha
        new_b = b0 * (1.0 - alpha) + sc_b * alpha

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Kline Gestural Slash pass complete.")

    def albers_homage_square_pass(
        self,
        *,
        n_zones:           int   = 5,
        contrast_strength: float = 0.15,
        zone_sigma:        float = 6.0,
        opacity:           float = 0.55,
    ) -> None:
        """
        Session 209 — Josef Albers Homage Square pass (120th distinct mode).

        CONCENTRIC CHEBYSHEV ZONE CHROMATIC INTERACTION FIELD: the canvas is
        divided into n_zones concentric rectangular bands by L∞ (Chebyshev)
        distance from the image centre.  For each zone z the mean RGB is
        computed.  Each zone z > 0 receives a SIMULTANEOUS CONTRAST shift:
        every pixel is pushed AWAY from the adjacent inner zone's mean by
        exaggerating their colour difference (shift = (pixel − inner_mean) ×
        contrast_strength).  The shift field is Gaussian-blurred by zone_sigma
        to produce smooth zone-boundary halation.  The adjusted image is
        composited over the original at opacity.

        Algorithm:
        (1) CHEBYSHEV DISTANCE: for pixel (y, x) normalise dy = |y − cy| / cy,
            dx = |x − cx| / cx, then cheby = max(dy, dx).  Clamp to [0, 1].
            Rectangular iso-contours match Albers' nested square geometry.
        (2) ZONE LABELS: zone_idx = floor(cheby × n_zones), clamped to
            [0, n_zones − 1].
        (3) PER-ZONE MEAN: for each zone z compute mean_r_z, mean_g_z, mean_b_z
            over all pixels assigned to that zone.
        (4) SIMULTANEOUS CONTRAST: build a zero-initialised shift field
            (delta_r, delta_g, delta_b).  For each zone z > 0:
            delta_ch[mask_z] = (ch[mask_z] − mean_ch_{z−1}) × contrast_strength.
            This EXAGGERATES each pixel's departure from the inner zone's mean.
        (5) ZONE BOUNDARY SMOOTHING: Gaussian-blur the shift field with sigma =
            zone_sigma to create soft halation at zone edges.
        (6) COMPOSITE: adjusted_ch = clip(ch + delta_ch_blurred, 0, 1).
            Final = ch × (1 − opacity) + adjusted_ch × opacity.

        NOVEL: ONE HUNDRED AND TWENTIETH DISTINCT MODE.  First pass to use
        CONCENTRIC CHEBYSHEV ZONE CHROMATIC INTERACTION FIELD: L∞ distance
        gives rectangular iso-contours (not Euclidean circles), combined with
        per-zone simultaneous contrast — exaggeration of each zone's colour
        difference from its adjacent inner zone's mean.  Prior passes:
        Delaunay (Euclidean multi-disk ring fields — circular, no zone-mean
        interaction); Kline (axis-detected sweep strokes — no zoning, no
        contrast); Riley (sinusoidal wave interference — no zone structure);
        Kusama (circular dot fields — no simultaneous contrast); Klee (tonal
        magic square cells — no zone-mean interaction, no exaggeration).
        The combination of Chebyshev rectangular zoning + per-zone mean
        colour + simultaneous contrast exaggeration + blurred shift field
        cannot be assembled from any prior single pass.

        n_zones           : number of concentric rectangular zones (default 5)
        contrast_strength : exaggeration factor per zone step (default 0.15)
        zone_sigma        : Gaussian blur sigma for zone-boundary smoothing
        opacity           : overall composite opacity over the original canvas
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        W, H = self.canvas.w, self.canvas.h

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── (1) Chebyshev distance → rectangular iso-contours ─────────────────
        cy_c = (H - 1) * 0.5
        cx_c = (W - 1) * 0.5
        ys = _np.arange(H, dtype=_np.float32).reshape(-1, 1)
        xs = _np.arange(W, dtype=_np.float32).reshape(1, -1)
        dy = _np.abs(ys - cy_c) / (cy_c + 1e-8)
        dx = _np.abs(xs - cx_c) / (cx_c + 1e-8)
        cheby = _np.minimum(_np.maximum(dy, dx), 1.0)

        # ── (2) Zone labels ───────────────────────────────────────────────────
        n = int(n_zones)
        zone_idx = _np.minimum((cheby * n).astype(_np.int32), n - 1)

        # ── (3) Per-zone mean colour ──────────────────────────────────────────
        zone_mean_r = _np.zeros(n, dtype=_np.float32)
        zone_mean_g = _np.zeros(n, dtype=_np.float32)
        zone_mean_b = _np.zeros(n, dtype=_np.float32)
        for z in range(n):
            mask_z = zone_idx == z
            n_px = int(mask_z.sum())
            if n_px > 0:
                zone_mean_r[z] = float(r0[mask_z].mean())
                zone_mean_g[z] = float(g0[mask_z].mean())
                zone_mean_b[z] = float(b0[mask_z].mean())

        # ── (4) Simultaneous contrast shift field ─────────────────────────────
        shift_r = _np.zeros((H, W), dtype=_np.float32)
        shift_g = _np.zeros((H, W), dtype=_np.float32)
        shift_b = _np.zeros((H, W), dtype=_np.float32)
        s = float(contrast_strength)
        for z in range(1, n):
            mask_z = zone_idx == z
            if not mask_z.any():
                continue
            shift_r[mask_z] = (r0[mask_z] - zone_mean_r[z - 1]) * s
            shift_g[mask_z] = (g0[mask_z] - zone_mean_g[z - 1]) * s
            shift_b[mask_z] = (b0[mask_z] - zone_mean_b[z - 1]) * s

        # ── (5) Smooth zone boundaries ────────────────────────────────────────
        sig = float(zone_sigma)
        if sig > 0.0:
            shift_r = _gf(shift_r, sigma=sig)
            shift_g = _gf(shift_g, sigma=sig)
            shift_b = _gf(shift_b, sigma=sig)

        # ── (6) Composite ─────────────────────────────────────────────────────
        adj_r = _np.clip(r0 + shift_r, 0.0, 1.0)
        adj_g = _np.clip(g0 + shift_g, 0.0, 1.0)
        adj_b = _np.clip(b0 + shift_b, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + adj_r * op
        new_g = g0 * (1.0 - op) + adj_g * op
        new_b = b0 * (1.0 - op) + adj_b * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Albers Homage Square pass complete.")

    def hofmann_push_pull_pass(
        self,
        *,
        push_sigma:     float = 18.0,
        push_strength:  float = 0.28,
        pull_strength:  float = 0.22,
        opacity:        float = 0.65,
    ) -> None:
        """
        Session 210 — Hans Hofmann Push-Pull pass (121st distinct mode).

        PUSH-PULL CHROMATIC SPATIAL TENSION FIELD: Hofmann's governing principle
        holds that warm colors ADVANCE (push toward the viewer) and cool colors
        RECEDE (pull away), creating pictorial depth through color temperature
        alone without any linear perspective.

        Algorithm:
        (1) COLOR TEMPERATURE MAP: per-pixel temperature T = (R − B), range [−1, 1].
            Positive T = warm, negative T = cool.
        (2) LOCAL REFERENCE TEMPERATURE: Gaussian-blur T with sigma = push_sigma
            to obtain T_smooth — the neighborhood mean temperature at each pixel.
        (3) DELTA TEMPERATURE: dT = T − T_smooth.  Positive dT means this pixel
            is warmer than its neighborhood (push candidate); negative dT means
            it is cooler than its neighborhood (pull candidate).
        (4) GRADIENT MAGNITUDE (boundary strength): Sobel operators on T_smooth
            give the local temperature gradient G.  Normalised to [0, 1].
            G is large at warm-cool color boundaries — Hofmann's most charged edges.
        (5) PUSH (warm advance): where dT > 0, amplify R and G toward orange-warm:
            push_amt = dT × G × push_strength
            R += push_amt,  G += push_amt × 0.35,  B −= push_amt × 0.20
            This brightens and warms pixels that are already warmer than their
            surroundings, most strongly at warm-cool boundaries.
        (6) PULL (cool recede): where dT < 0, deepen toward blue-violet:
            pull_amt = −dT × G × pull_strength
            B += pull_amt,  G += pull_amt × 0.10,  R −= pull_amt × 0.18
            This enriches and cools pixels that are cooler than their surroundings,
            most strongly at the same warm-cool boundaries.
        (7) COMPOSITE: clip to [0, 1], then blend with original at opacity.

        NOVEL: ONE HUNDRED AND TWENTY-FIRST DISTINCT MODE.  First pass to use
        LOCAL COLOR TEMPERATURE GRADIENT DIFFERENTIAL AMPLIFICATION: content-
        driven warm/cool detection via (R−B) temperature map + local neighborhood
        comparison via Gaussian smoothing + Sobel-gradient boundary finding +
        separate warm-PUSH (advance: orange-warm amplification) and cool-PULL
        (recede: blue-violet deepening) chromatic amplification weighted by
        local gradient magnitude.  Prior passes: Albers (fixed Chebyshev
        rectangular zones from centre — not content-driven); Delaunay (Euclidean
        ring geometry — fixed structure, no temperature logic); Kline (gestural
        axis sweep — no colour temperature); Munch (swirl vectors from image
        luminance mass — no warm/cool split); all 120 prior passes lack the
        combination of content-driven temperature gradient detection and
        differential directional chromatic amplification.

        push_sigma    : Gaussian sigma for local temperature reference (pixels)
        push_strength : amplitude of warm-advance amplification
        pull_strength : amplitude of cool-recession amplification
        opacity       : final composite blend over original canvas
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        W, H = self.canvas.w, self.canvas.h

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── (1) Color temperature map T = R − B ────────────────────────────────
        temp = r0 - b0   # range [-1, 1]; positive = warm, negative = cool

        # ── (2) Local reference temperature (neighborhood mean) ────────────────
        temp_smooth = _gf(temp, sigma=float(push_sigma))

        # ── (3) Delta temperature: how much warmer/cooler than local mean ──────
        dt = temp - temp_smooth   # positive = local warm, negative = local cool

        # ── (4) Gradient magnitude of smooth temperature field ─────────────────
        gx = _sobel(temp_smooth, axis=1)
        gy = _sobel(temp_smooth, axis=0)
        grad_mag = _np.sqrt(gx * gx + gy * gy)
        g_max = float(grad_mag.max())
        if g_max > 1e-8:
            grad_mag /= g_max   # normalise to [0, 1]

        # ── (5) PUSH: warm pixels advance (orange-warm amplification) ──────────
        warm_mask = (dt > 0).astype(_np.float32)
        push_amt  = dt * warm_mask * grad_mag * float(push_strength)

        r_push = push_amt
        g_push = push_amt * 0.35
        b_push = -push_amt * 0.20

        # ── (6) PULL: cool pixels recede (blue-violet deepening) ──────────────
        cool_mask = (dt < 0).astype(_np.float32)
        pull_amt  = (-dt) * cool_mask * grad_mag * float(pull_strength)

        b_pull = pull_amt
        g_pull = pull_amt * 0.10
        r_pull = -pull_amt * 0.18

        # Combine push + pull deltas
        dr = r_push + r_pull
        dg = g_push + g_pull
        db = b_push + b_pull

        # ── (7) Composite ──────────────────────────────────────────────────────
        adj_r = _np.clip(r0 + dr, 0.0, 1.0)
        adj_g = _np.clip(g0 + dg, 0.0, 1.0)
        adj_b = _np.clip(b0 + db, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + adj_r * op
        new_g = g0 * (1.0 - op) + adj_g * op
        new_b = b0 * (1.0 - op) + adj_b * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Hofmann Push-Pull pass complete.")

    def miro_surrealist_biomorph_pass(
        self,
        *,
        flat_strength:    float = 0.72,
        outline_strength: float = 0.88,
        edge_sigma:       float = 1.5,
        opacity:          float = 0.80,
    ) -> None:
        """
        Session 211 — Joan Miró Surrealist Biomorph pass (122nd distinct mode).

        BIOMORPHIC PALETTE QUANTIZATION WITH BLACK OUTLINE INJECTION: a three-stage
        content-driven style transfer that enforces Miró's flat-primary-colour
        vocabulary and bold black contour language onto an arbitrary painted surface.

        Algorithm:
        (1) NEAREST-PALETTE QUANTIZATION: for every pixel (R, G, B) compute the
            squared Euclidean distance to each of Miró's seven palette colours
            (cadmium red, cadmium yellow, ultramarine blue, pitch black, raw white,
            raw ochre, sap green).  Assign each pixel its nearest palette colour to
            build a fully quantized target array Q.
        (2) LUMINANCE GRADIENT MAGNITUDE: compute luminance L = 0.299R + 0.587G +
            0.114B.  Apply Gaussian pre-blur with sigma = edge_sigma to reduce
            noise.  Run Sobel operators on the blurred luminance to obtain gradient
            magnitude G (normalised to [0, 1]).  G is large at colour-region
            boundaries — Miró's outline positions.
        (3) FLAT ZONE BLEND: for interior pixels (low G), blend original toward
            quantized target colour:
            flat_delta_ch = flat_strength × (1 − G) × (Q_ch − original_ch)
            This flattens interior regions to pure primary colour.
        (4) BLACK OUTLINE INJECTION: for boundary pixels (high G), blend toward
            pitch black (0.04, 0.04, 0.04):
            outline_delta_ch = outline_strength × G × (black_ch − original_ch)
            This injects Miró's characteristic bold black contours precisely at
            colour-region edges driven by the image's own luminance boundaries.
        (5) COMPOSITE: adjusted_ch = clip(original_ch + flat_delta_ch +
            outline_delta_ch, 0, 1).  Final = original × (1 − opacity) +
            adjusted × opacity.

        NOVEL: ONE HUNDRED AND TWENTY-SECOND DISTINCT MODE.  First pass to combine
        CONTENT-DRIVEN PALETTE QUANTIZATION (nearest Miró palette colour per pixel)
        + GRADIENT-WEIGHTED INTERIOR FLATTENING (low-G pixels pulled toward flat
        primary colour) + EXPLICIT BLACK OUTLINE INJECTION (high-G boundary pixels
        darkened toward pitch black).  Prior passes: Hofmann (temperature
        differential amplification — no palette quantization, no outline injection);
        Albers (Chebyshev zone simultaneous contrast — no quantization, no explicit
        outline); Kline (gestural calligraphic axis sweep — black applied along
        structural image axis, NOT at colour-region edges); Kusama (circular dot
        fields — no palette quantization); all 121 prior passes lack the combination
        of palette quantization + gradient-weighted flat fill + explicit black outline
        injection at content-derived colour boundaries.

        flat_strength    : blend weight toward quantized palette in flat interiors
        outline_strength : blend weight toward pitch black at gradient boundaries
        edge_sigma       : Gaussian sigma for luminance pre-blur before Sobel
        opacity          : final composite blend over original canvas
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        W, H = self.canvas.w, self.canvas.h

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── (1) Nearest-palette quantization ──────────────────────────────────
        # Miró's seven palette colours as (R, G, B) float32
        miro_palette = _np.array([
            [0.89, 0.15, 0.07],   # cadmium red
            [0.98, 0.85, 0.04],   # cadmium yellow
            [0.06, 0.12, 0.75],   # ultramarine blue
            [0.04, 0.04, 0.04],   # pitch black
            [0.96, 0.94, 0.88],   # raw canvas white
            [0.75, 0.58, 0.20],   # raw ochre
            [0.12, 0.55, 0.25],   # sap green
        ], dtype=_np.float32)   # shape (7, 3)

        # Stack image channels → (H*W, 3) for vectorised distance computation
        pixels = _np.stack([r0, g0, b0], axis=-1).reshape(-1, 3)   # (H*W, 3)
        # Squared distances from each pixel to each palette colour: (H*W, 7)
        diff = pixels[:, _np.newaxis, :] - miro_palette[_np.newaxis, :, :]
        sq_dist = (diff * diff).sum(axis=-1)                         # (H*W, 7)
        nearest_idx = sq_dist.argmin(axis=-1)                        # (H*W,)
        q_colors = miro_palette[nearest_idx].reshape(H, W, 3)        # (H, W, 3)
        q_r = q_colors[:, :, 0]
        q_g = q_colors[:, :, 1]
        q_b = q_colors[:, :, 2]

        # ── (2) Luminance gradient magnitude ──────────────────────────────────
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        lum_blur = _gf(lum, sigma=float(edge_sigma))
        gx = _sobel(lum_blur, axis=1)
        gy = _sobel(lum_blur, axis=0)
        grad_mag = _np.sqrt(gx * gx + gy * gy)
        g_max = float(grad_mag.max())
        if g_max > 1e-8:
            grad_mag /= g_max   # normalise to [0, 1]

        # ── (3) Flat zone blend toward quantized palette ───────────────────────
        interior = (1.0 - grad_mag) * float(flat_strength)
        flat_dr = interior * (q_r - r0)
        flat_dg = interior * (q_g - g0)
        flat_db = interior * (q_b - b0)

        # ── (4) Black outline injection at boundaries ─────────────────────────
        BLACK_R, BLACK_G, BLACK_B = 0.04, 0.04, 0.04
        outline = grad_mag * float(outline_strength)
        out_dr = outline * (BLACK_R - r0)
        out_dg = outline * (BLACK_G - g0)
        out_db = outline * (BLACK_B - b0)

        # ── (5) Composite ──────────────────────────────────────────────────────
        adj_r = _np.clip(r0 + flat_dr + out_dr, 0.0, 1.0)
        adj_g = _np.clip(g0 + flat_dg + out_dg, 0.0, 1.0)
        adj_b = _np.clip(b0 + flat_db + out_db, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + adj_r * op
        new_g = g0 * (1.0 - op) + adj_g * op
        new_b = b0 * (1.0 - op) + adj_b * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Miró Surrealist Biomorph pass complete.")

    def mondrian_neoplastic_grid_pass(
        self,
        *,
        h_lines:       int   = 4,
        v_lines:       int   = 5,
        line_width:    int   = 5,
        grid_strength: float = 0.82,
        opacity:       float = 0.78,
    ) -> None:
        """
        Session 212 — Piet Mondrian Neoplastic Grid pass (123rd distinct mode).

        CONTENT-DRIVEN NEOPLASTIC GRID DECOMPOSITION: a four-stage pass that
        imposes Mondrian's orthogonal grid vocabulary onto a painted surface
        using the image's own luminance structure to determine grid line placement.

        Algorithm:
        (1) AXIS-SEPARATED GRADIENT ENERGY: compute luminance L per pixel.
            Row-wise: compute mean luminance per row → row_mean (H,); take absolute
            first-difference → row_energy (H,).  Select the h_lines rows with
            highest energy as horizontal grid line positions, suppressing candidates
            within 5% of canvas height of a stronger already-chosen line (greedy
            non-maximum suppression).  Repeat column-wise for v_lines vertical
            grid line positions.  Content-derived placement means lines fall at the
            image's own strongest tonal seams — not at arbitrary fractions.
        (2) CELL COLOR ASSIGNMENT: the (h_lines+1) × (v_lines+1) rectangular grid
            of cells is enumerated.  For each cell, compute mean (R, G, B) of
            original pixels.  Assign the nearest Mondrian color by squared Euclidean
            RGB distance from the six-color neoplastic palette:
              primary red    (0.86, 0.08, 0.06)
              primary yellow (0.97, 0.87, 0.02)
              primary blue   (0.01, 0.17, 0.54)
              white          (0.94, 0.92, 0.88)
              gray           (0.72, 0.72, 0.72)
              black          (0.06, 0.06, 0.08)
            Cells are filled with their assigned flat color weighted by grid_strength:
            cell_pixel = original × (1 − grid_strength) + assigned_color × grid_strength.
        (3) GRID LINE INJECTION: within line_width pixels of any horizontal or
            vertical grid line position, overwrite with deep black (0.06, 0.06, 0.08)
            at full weight (grid lines are always opaque black, independent of opacity).
        (4) COMPOSITE: blend reconstructed Mondrian grid image with the original
            canvas: final = original × (1 − opacity) + mondrian × opacity.

        NOVEL: ONE HUNDRED AND TWENTY-THIRD DISTINCT MODE.  First pass to perform
        CONTENT-DERIVED ORTHOGONAL GRID PLACEMENT (row/column energy peak detection,
        greedy NMS) + CELL-LEVEL NEAREST-PRIMARY-COLOR ASSIGNMENT (mean cell color
        → six-way Euclidean snap) + EXPLICIT BLACK GRIDLINE INJECTION (line_width
        pixel bands overwritten to black).
        Prior passes: Miró (pixel-level palette quantization + gradient outline —
        no grid, no cell-level assignment); Albers (concentric zones from canvas
        center — fixed geometry, not content-derived); Kline (gestural diagonal
        axis sweep — not orthogonal); Hofmann (temperature differential —
        no structural decomposition); all 122 prior passes lack the combination of
        axis-separated energy peak detection + cell-level nearest-primary fill +
        orthogonal black gridline injection.

        h_lines      : number of horizontal grid lines to detect and draw
        v_lines      : number of vertical grid lines to detect and draw
        line_width   : thickness of black grid lines in pixels (always black)
        grid_strength: blend weight of assigned Mondrian color within each cell
        opacity      : final composite blend over original canvas
        """
        import numpy as _np

        W, H = self.canvas.w, self.canvas.h

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── (1) Axis-separated gradient energy ───────────────────────────────
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0  # (H, W)

        # Horizontal grid lines: energy from row-wise mean luminance derivative
        row_mean = lum.mean(axis=1)                   # (H,)
        row_energy = _np.abs(_np.diff(row_mean, prepend=row_mean[0]))  # (H,)

        def _pick_lines(energy: _np.ndarray, n: int, excl_frac: float = 0.05) -> list:
            """Greedy NMS: pick n peak positions, suppressing within excl_frac of size."""
            size = len(energy)
            excl = max(1, int(size * excl_frac))
            e = energy.copy()
            positions = []
            for _ in range(n):
                idx = int(e.argmax())
                if e[idx] == 0.0:
                    break
                positions.append(idx)
                lo = max(0, idx - excl)
                hi = min(size, idx + excl)
                e[lo:hi] = 0.0
            return sorted(positions)

        h_pos = _pick_lines(row_energy, h_lines)      # sorted row indices
        col_mean = lum.mean(axis=0)                   # (W,)
        col_energy = _np.abs(_np.diff(col_mean, prepend=col_mean[0]))  # (W,)
        v_pos = _pick_lines(col_energy, v_lines)      # sorted column indices

        # ── (2) Cell color assignment ─────────────────────────────────────────
        # Mondrian's six-color neoplastic palette (RGB float32)
        mondrian_palette = _np.array([
            [0.86, 0.08, 0.06],   # primary red
            [0.97, 0.87, 0.02],   # primary yellow
            [0.01, 0.17, 0.54],   # primary blue
            [0.94, 0.92, 0.88],   # white
            [0.72, 0.72, 0.72],   # gray
            [0.06, 0.06, 0.08],   # black
        ], dtype=_np.float32)

        # Build row/col boundaries including 0 and H/W
        row_bounds = [0] + h_pos + [H]
        col_bounds = [0] + v_pos + [W]

        adj_r = r0.copy()
        adj_g = g0.copy()
        adj_b = b0.copy()

        gs = float(grid_strength)

        for ri in range(len(row_bounds) - 1):
            r_lo = row_bounds[ri]
            r_hi = row_bounds[ri + 1]
            for ci in range(len(col_bounds) - 1):
                c_lo = col_bounds[ci]
                c_hi = col_bounds[ci + 1]
                if r_hi <= r_lo or c_hi <= c_lo:
                    continue
                cell_r = r0[r_lo:r_hi, c_lo:c_hi].mean()
                cell_g = g0[r_lo:r_hi, c_lo:c_hi].mean()
                cell_b = b0[r_lo:r_hi, c_lo:c_hi].mean()
                mean_rgb = _np.array([cell_r, cell_g, cell_b], dtype=_np.float32)
                # Nearest Mondrian color by squared Euclidean distance
                diff = mondrian_palette - mean_rgb[_np.newaxis, :]
                sq_dist = (diff * diff).sum(axis=1)
                nearest = mondrian_palette[sq_dist.argmin()]
                # Blend cell pixels toward assigned Mondrian color
                adj_r[r_lo:r_hi, c_lo:c_hi] = (
                    r0[r_lo:r_hi, c_lo:c_hi] * (1.0 - gs) + nearest[0] * gs
                )
                adj_g[r_lo:r_hi, c_lo:c_hi] = (
                    g0[r_lo:r_hi, c_lo:c_hi] * (1.0 - gs) + nearest[1] * gs
                )
                adj_b[r_lo:r_hi, c_lo:c_hi] = (
                    b0[r_lo:r_hi, c_lo:c_hi] * (1.0 - gs) + nearest[2] * gs
                )

        # ── (3) Grid line injection ────────────────────────────────────────────
        # Black grid lines at detected positions (always full black, independent of opacity)
        black_r, black_g, black_b = 0.06, 0.06, 0.08
        lw = int(line_width)

        for hy in h_pos:
            lo = max(0, hy - lw // 2)
            hi = min(H, hy + lw // 2 + 1)
            adj_r[lo:hi, :] = black_r
            adj_g[lo:hi, :] = black_g
            adj_b[lo:hi, :] = black_b

        for vx in v_pos:
            lo = max(0, vx - lw // 2)
            hi = min(W, vx + lw // 2 + 1)
            adj_r[:, lo:hi] = black_r
            adj_g[:, lo:hi] = black_g
            adj_b[:, lo:hi] = black_b

        # ── (4) Composite ─────────────────────────────────────────────────────
        op = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + adj_r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + adj_g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + adj_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Mondrian Neoplastic Grid pass complete.")

    def rothko_color_field_pass(
        self,
        *,
        n_bands:      int   = 3,
        hue_strength: float = 0.68,
        edge_sigma:   float = 28.0,
        veil_factor:  float = 0.88,
        opacity:      float = 0.80,
    ) -> None:
        """
        Session 213 — Mark Rothko Color Field pass (124th distinct mode).

        LUMINANCE-BAND CHROMATIC FIELD AMPLIFICATION: a five-stage pass that
        imposes Rothko's horizontal colour-field vocabulary onto a painted
        surface by segmenting the canvas into horizontal luminance bands,
        amplifying each band's dominant hue, and dissolving interband
        boundaries with a sigmoid-weighted gradient.

        Algorithm:
        (1) HORIZONTAL BAND SEGMENTATION: divide the canvas into n_bands
            horizontal zones of equal pixel height.  For each band, compute
            the mean (R, G, B) of original pixels — the band's dominant colour.
        (2) BAND HUE AMPLIFICATION: for every pixel in band i, shift colour
            toward the band's dominant colour by hue_strength:
              adj = orig × (1 − hue_strength) + band_mean × hue_strength.
            Amplifies chromatic coherence within each zone.
        (3) SOFT INTERBAND BOUNDARY DISSOLVE: at each band boundary row y_b,
            compute per-row sigmoid weights:
              w_next(y) = 0.5 + 0.5 × tanh((y − y_b) / edge_sigma)
              w_prev(y) = 1 − w_next(y)
            Pixels within 3 × edge_sigma rows of a boundary receive a weighted
            blend of adjacent bands' amplified colours — the 'breathing' soft
            edge that defines Rothko's fields.
        (4) DARKENING VEIL: multiply adj channels by veil_factor to simulate
            Rothko's layered dammar-resin glazing — luminous but never bright.
        (5) COMPOSITE: blend darkened field image with the original canvas
            at opacity.

        NOVEL: ONE HUNDRED AND TWENTY-FOURTH DISTINCT MODE.  First pass to
        combine HORIZONTAL BAND HUE AMPLIFICATION (per-band mean-colour shift)
        + SOFT INTERBAND SIGMOID-WEIGHTED BOUNDARY DISSOLVE (per-row tanh
        weighting within 3×sigma of boundary) + CHROMATIC DARKENING VEIL
        (global channel multiply).  Prior passes: Mondrian (orthogonal grid +
        flat cell colour snapping — hard edges, no boundary dissolve);
        Albers (concentric rectangles from centre — fixed geometry, no
        content-derived bands); Miró (pixel-level palette quantisation +
        gradient outline — no banding); Hofmann (warm/cool temperature
        differential — whole-canvas, not band-segmented); all 123 prior
        passes lack horizontal band segmentation + per-band hue amplification
        + sigmoid interband boundary dissolve.

        n_bands      : number of horizontal colour field bands (Rothko: 2–4)
        hue_strength : blend weight toward each band's dominant colour [0, 1]
        edge_sigma   : Gaussian sigma in pixels for interband boundary dissolve
        veil_factor  : global luminance multiplier for chromatic depth [0, 1]
        opacity      : final composite blend weight over original canvas
        """
        import numpy as _np

        W, H = self.canvas.w, self.canvas.h

        orig = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()

        # Cairo BGRA channel order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        nb = max(1, int(n_bands))
        hs = float(hue_strength)
        sigma = max(1.0, float(edge_sigma))
        veil = float(veil_factor)

        # ── (1) Horizontal band segmentation ──────────────────────────────────
        band_h = H // nb
        boundaries = [i * band_h for i in range(nb)] + [H]

        band_means_r = _np.empty(nb, dtype=_np.float32)
        band_means_g = _np.empty(nb, dtype=_np.float32)
        band_means_b = _np.empty(nb, dtype=_np.float32)
        for i in range(nb):
            r_lo, r_hi = boundaries[i], boundaries[i + 1]
            band_means_r[i] = r0[r_lo:r_hi, :].mean()
            band_means_g[i] = g0[r_lo:r_hi, :].mean()
            band_means_b[i] = b0[r_lo:r_hi, :].mean()

        # ── (2) Band hue amplification ─────────────────────────────────────────
        adj_r = r0.copy()
        adj_g = g0.copy()
        adj_b = b0.copy()

        for i in range(nb):
            r_lo, r_hi = boundaries[i], boundaries[i + 1]
            adj_r[r_lo:r_hi, :] = r0[r_lo:r_hi, :] * (1.0 - hs) + band_means_r[i] * hs
            adj_g[r_lo:r_hi, :] = g0[r_lo:r_hi, :] * (1.0 - hs) + band_means_g[i] * hs
            adj_b[r_lo:r_hi, :] = b0[r_lo:r_hi, :] * (1.0 - hs) + band_means_b[i] * hs

        # ── (3) Soft interband boundary dissolve ───────────────────────────────
        for i in range(nb - 1):
            y_b = boundaries[i + 1]                       # boundary row index
            y_range = max(1, int(3.0 * sigma))
            y_lo = max(0, y_b - y_range)
            y_hi = min(H, y_b + y_range)
            if y_lo >= y_hi:
                continue

            rows_f = _np.arange(y_lo, y_hi, dtype=_np.float32) - y_b  # (n,)
            w_next = (0.5 + 0.5 * _np.tanh(rows_f / sigma))[:, _np.newaxis]  # (n, 1)
            w_prev = 1.0 - w_next

            # Amplified colours for adjacent bands
            prev_r = r0[y_lo:y_hi, :] * (1.0 - hs) + band_means_r[i]     * hs
            prev_g = g0[y_lo:y_hi, :] * (1.0 - hs) + band_means_g[i]     * hs
            prev_b = b0[y_lo:y_hi, :] * (1.0 - hs) + band_means_b[i]     * hs

            next_r = r0[y_lo:y_hi, :] * (1.0 - hs) + band_means_r[i + 1] * hs
            next_g = g0[y_lo:y_hi, :] * (1.0 - hs) + band_means_g[i + 1] * hs
            next_b = b0[y_lo:y_hi, :] * (1.0 - hs) + band_means_b[i + 1] * hs

            adj_r[y_lo:y_hi, :] = w_prev * prev_r + w_next * next_r
            adj_g[y_lo:y_hi, :] = w_prev * prev_g + w_next * next_g
            adj_b[y_lo:y_hi, :] = w_prev * prev_b + w_next * next_b

        # ── (4) Darkening veil ─────────────────────────────────────────────────
        adj_r = _np.clip(adj_r * veil, 0.0, 1.0)
        adj_g = _np.clip(adj_g * veil, 0.0, 1.0)
        adj_b = _np.clip(adj_b * veil, 0.0, 1.0)

        # ── (5) Composite ──────────────────────────────────────────────────────
        op = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + adj_r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + adj_g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + adj_b * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Rothko Color Field pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 214 — kandinsky_synesthetic_composition_pass (125th distinct mode)
    # ─────────────────────────────────────────────────────────────────────────

    def kandinsky_synesthetic_composition_pass(
        self,
        *,
        n_chords:       int   = 12,
        chord_radius:   int   = 32,
        chord_strength: float = 0.62,
        ring_alpha:     float = 0.45,
        opacity:        float = 0.76,
    ) -> None:
        """Kandinsky synesthetic composition pass — tension-field-driven chromatic chords.

        Algorithm: SYNESTHETIC CHROMATIC CHORD OVERLAY
        (1) Tension field via Sobel gradient on luminance.
        (2) Palette chord injection at n_chords tension peaks (Gaussian disc blend).
        (3) Concentric arc ring overlay at each chord centre.
        (4) Dominant-gradient directional line trace per peak.
        (5) Composite at opacity.
        """
        import numpy as _np

        W = self.canvas.w
        H = self.canvas.h

        raw  = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        orig = raw.copy()

        # BGRA channel mapping: R = ch2, G = ch1, B = ch0
        r0 = raw[:, :, 2].astype(_np.float32) / 255.0
        g0 = raw[:, :, 1].astype(_np.float32) / 255.0
        b0 = raw[:, :, 0].astype(_np.float32) / 255.0

        # ── (1) Tension field via Sobel on luminance ───────────────────────────
        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0  # (H, W)

        p = _np.pad(lum, 1, mode="edge")
        gx = (
            -1.0 * p[:-2, :-2] + 1.0 * p[:-2, 2:] +
            -2.0 * p[1:-1, :-2] + 2.0 * p[1:-1, 2:] +
            -1.0 * p[2:, :-2]  + 1.0 * p[2:, 2:]
        )
        gy = (
            -1.0 * p[:-2, :-2] - 2.0 * p[:-2, 1:-1] - 1.0 * p[:-2, 2:] +
             1.0 * p[2:, :-2]  + 2.0 * p[2:, 1:-1]  + 1.0 * p[2:, 2:]
        )
        tension = _np.hypot(gx, gy)
        t_max = tension.max()
        if t_max > 1e-9:
            tension /= t_max

        # ── (2) Greedy peak detection ──────────────────────────────────────────
        # Kandinsky palette (hardcoded to avoid circular import)
        _pal = [
            (0.95, 0.85, 0.15),  # cadmium yellow
            (0.85, 0.15, 0.12),  # vermilion red
            (0.12, 0.25, 0.72),  # cobalt blue
            (0.05, 0.05, 0.05),  # ivory black
            (0.92, 0.90, 0.85),  # titanium white
            (0.15, 0.55, 0.25),  # emerald green
            (0.75, 0.40, 0.05),  # cadmium orange
        ]

        margin      = max(2, chord_radius // 4)
        suppressed  = _np.zeros((H, W), dtype=_np.bool_)
        flat_order  = _np.argsort(tension.ravel())[::-1]
        peaks       = []

        for idx in flat_order:
            cy, cx = divmod(int(idx), W)
            if suppressed[cy, cx]:
                continue
            if cy < margin or cy > H - margin - 1 or cx < margin or cx > W - margin - 1:
                continue
            peaks.append((cy, cx))
            ys_lo = max(0, cy - chord_radius)
            ys_hi = min(H, cy + chord_radius + 1)
            xs_lo = max(0, cx - chord_radius)
            xs_hi = min(W, cx + chord_radius + 1)
            suppressed[ys_lo:ys_hi, xs_lo:xs_hi] = True
            if len(peaks) >= n_chords:
                break

        adj_r = r0.copy()
        adj_g = g0.copy()
        adj_b = b0.copy()

        sigma_disc = max(1.0, chord_radius * 0.5)
        ring_r1    = chord_radius * 0.7
        ring_r2    = chord_radius * 1.3

        ys_grid          = _np.arange(H, dtype=_np.float32)
        xs_grid          = _np.arange(W, dtype=_np.float32)
        xs_2d, ys_2d     = _np.meshgrid(xs_grid, ys_grid)  # (H, W) each

        for i, (cy, cx) in enumerate(peaks):
            cr, cg, cb = _pal[i % len(_pal)]

            dist2  = (ys_2d - cy) ** 2 + (xs_2d - cx) ** 2
            dist   = _np.sqrt(dist2)

            # Gaussian disc: blend palette colour at chord_strength
            disc_w = _np.exp(-dist2 / (2.0 * sigma_disc ** 2)) * float(chord_strength)
            adj_r  = _np.clip(adj_r * (1.0 - disc_w) + cr * disc_w, 0.0, 1.0)
            adj_g  = _np.clip(adj_g * (1.0 - disc_w) + cg * disc_w, 0.0, 1.0)
            adj_b  = _np.clip(adj_b * (1.0 - disc_w) + cb * disc_w, 0.0, 1.0)

            # Concentric ring darkening
            ra     = float(ring_alpha)
            ring   = ((dist > ring_r1 - 2.0) & (dist < ring_r1 + 2.0)) | \
                     ((dist > ring_r2 - 2.0) & (dist < ring_r2 + 2.0))
            adj_r  = _np.where(ring, adj_r * (1.0 - ra), adj_r)
            adj_g  = _np.where(ring, adj_g * (1.0 - ra), adj_g)
            adj_b  = _np.where(ring, adj_b * (1.0 - ra), adj_b)

            # Directional impulse line along dominant gradient angle
            angle  = float(_np.arctan2(float(gy[cy, cx]), float(gx[cy, cx])))
            ts     = _np.arange(-chord_radius, chord_radius, dtype=_np.float32)
            tys    = _np.clip(
                (cy + ts * _np.sin(angle)).astype(_np.int32), 0, H - 1)
            txs    = _np.clip(
                (cx + ts * _np.cos(angle)).astype(_np.int32), 0, W - 1)
            boost  = 0.30 * 0.35
            adj_r[tys, txs] = _np.clip(adj_r[tys, txs] + boost, 0.0, 1.0)
            adj_g[tys, txs] = _np.clip(adj_g[tys, txs] + boost, 0.0, 1.0)
            adj_b[tys, txs] = _np.clip(adj_b[tys, txs] + boost, 0.0, 1.0)

        # ── (5) Composite ──────────────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + adj_r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + adj_g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + adj_b * op, 0.0, 1.0)

        buf              = orig.copy()
        buf[:, :, 2]     = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1]     = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0]     = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3]     = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Kandinsky Synesthetic Composition pass complete.")

    # ─────────────────────────────────────────────────────────────────────────
    # Session 215 — freud_impasto_vulnerability_pass (126th distinct mode)
    # ─────────────────────────────────────────────────────────────────────────

    def freud_impasto_vulnerability_pass(
        self,
        *,
        ridge_radius:         int   = 4,
        ridge_threshold:      float = 0.04,
        ridge_strength:       float = 0.55,
        shadow_threshold:     float = 0.38,
        shadow_cool_strength: float = 0.40,
        raking_falloff:       float = 0.72,
        opacity:              float = 0.78,
    ) -> None:
        """Lucian Freud impasto vulnerability pass — ridge amplification + shadow cooling.

        Algorithm: FREUD IMPASTO VULNERABILITY PASS
        (1) Luminance ridge amplification via box-filter local variance.
        (2) Shadow cooling: push dark pixels toward cool green-grey (0.44, 0.49, 0.40).
        (3) Raking light gradient: cosine taper top (1.0) to bottom (raking_falloff).
        (4) Composite at opacity.
        """
        import numpy as _np
        from scipy.ndimage import uniform_filter as _uf

        W = self.canvas.w
        H = self.canvas.h

        raw  = _np.frombuffer(
            self.canvas.surface.get_data(), dtype=_np.uint8
        ).reshape((H, W, 4)).copy()
        orig = raw.copy()

        # Cairo BGRA: ch0=B, ch1=G, ch2=R, ch3=A
        b0 = raw[:, :, 0].astype(_np.float32) / 255.0
        g0 = raw[:, :, 1].astype(_np.float32) / 255.0
        r0 = raw[:, :, 2].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0  # (H, W)

        # ── (1) Luminance ridge amplification via local variance ───────────────
        k = int(ridge_radius) * 2 + 1
        lum_mean   = _uf(lum,        size=k, mode="reflect")
        lum_sq_mean = _uf(lum ** 2,  size=k, mode="reflect")
        lum_var    = _np.clip(lum_sq_mean - lum_mean ** 2, 0.0, None)
        lum_std    = _np.sqrt(lum_var)

        # Ridge mask: pixels whose local contrast exceeds threshold
        ridge_mask = (lum_std > float(ridge_threshold)).astype(_np.float32)
        rs         = float(ridge_strength)

        # Amplify luminance deviation from local mean at ridge pixels
        dev        = lum - lum_mean
        adj_lum    = _np.clip(lum_mean + dev * (1.0 + rs * ridge_mask), 0.0, 1.0)

        # Scale RGB uniformly by the luminance ratio (preserves hue)
        lum_safe   = _np.where(lum > 1e-6, lum, 1e-6)
        lum_ratio  = _np.clip(adj_lum / lum_safe, 0.0, 2.5)
        adj_r      = _np.clip(r0 * lum_ratio, 0.0, 1.0)
        adj_g      = _np.clip(g0 * lum_ratio, 0.0, 1.0)
        adj_b      = _np.clip(b0 * lum_ratio, 0.0, 1.0)

        # ── (2) Shadow cooling — shift dark pixels toward Freud's green-grey ──
        cool_r, cool_g, cool_b = 0.44, 0.49, 0.40
        sc       = float(shadow_cool_strength)
        st       = float(shadow_threshold)
        # Soft shadow weight: 0 at lum=st, sc at lum=0
        shadow_w = _np.clip((1.0 - adj_lum / max(st, 1e-6)) * sc, 0.0, sc)
        adj_r    = _np.clip(adj_r * (1.0 - shadow_w) + cool_r * shadow_w, 0.0, 1.0)
        adj_g    = _np.clip(adj_g * (1.0 - shadow_w) + cool_g * shadow_w, 0.0, 1.0)
        adj_b    = _np.clip(adj_b * (1.0 - shadow_w) + cool_b * shadow_w, 0.0, 1.0)

        # ── (3) Raking light gradient — cosine taper top→bottom ───────────────
        rf        = float(raking_falloff)
        # raking[y] = rf + (1-rf) * (1 + cos(π*y/(H-1))) / 2
        # = 1.0 at y=0, rf at y=H-1
        ys_norm   = _np.linspace(0.0, _np.pi, H, dtype=_np.float32)
        raking    = rf + (1.0 - rf) * (1.0 + _np.cos(ys_norm)) * 0.5  # (H,)
        raking    = raking[:, _np.newaxis]  # broadcast over width
        adj_r     = _np.clip(adj_r * raking, 0.0, 1.0)
        adj_g     = _np.clip(adj_g * raking, 0.0, 1.0)
        adj_b     = _np.clip(adj_b * raking, 0.0, 1.0)

        # ── (4) Composite ──────────────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + adj_r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + adj_g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + adj_b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        self.canvas.surface.get_data()[:] = buf.tobytes()
        self.canvas.surface.mark_dirty()
        print("    Lucian Freud Impasto Vulnerability pass complete.")

    def diebenkorn_ocean_park_pass(
        self,
        *,
        n_zones:           int   = 5,
        zone_smooth_sigma: float = 28.0,
        smooth_blend_frac: float = 0.55,
        line_width:        int   = 2,
        line_opacity:      float = 0.62,
        palette_shift:     float = 0.30,
        luminosity_boost:  float = 0.07,
        opacity:           float = 0.65,
    ) -> None:
        """
        Richard Diebenkorn Ocean Park pass — 127th distinct mode.

        Segments the canvas into horizontal compositional zones, smooths each
        zone into an open color field, draws thin ruled boundary lines, and
        applies Diebenkorn's luminous coastal palette shift.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        # ── (0) Read canvas ────────────────────────────────────────────────────
        surface = self.canvas.surface
        H, W    = self.canvas.h, self.canvas.w
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape((H, W, 4)).copy()
        b0      = orig[:, :, 0].astype(_np.float32) / 255.0
        g0      = orig[:, :, 1].astype(_np.float32) / 255.0
        r0      = orig[:, :, 2].astype(_np.float32) / 255.0
        adj_r   = r0.copy()
        adj_g   = g0.copy()
        adj_b   = b0.copy()

        rng = _np.random.RandomState(seed=216)

        # ── (1) Zone segmentation ──────────────────────────────────────────────
        # Place n_zones-1 sorted horizontal split points with slight diagonal tilt
        raw_splits = _np.sort(rng.uniform(0.12, 0.88, max(1, n_zones - 1))) * H
        tilt_px    = rng.uniform(-0.04, 0.04, n_zones) * W  # tilt per zone (px/full-width)

        col_idx = _np.arange(W, dtype=_np.float32)[_np.newaxis, :]  # (1, W)
        row_idx = _np.arange(H, dtype=_np.float32)[:, _np.newaxis]  # (H, 1)

        # ── (2) Zone smoothing ─────────────────────────────────────────────────
        sigma    = float(zone_smooth_sigma)
        smooth_r = _gf(adj_r, sigma=sigma, mode="reflect")
        smooth_g = _gf(adj_g, sigma=sigma, mode="reflect")
        smooth_b = _gf(adj_b, sigma=sigma, mode="reflect")

        splits_full = _np.concatenate([[0.0], raw_splits, [float(H)]])
        blend       = float(smooth_blend_frac)

        for zone_i in range(n_zones):
            y_lo  = splits_full[zone_i]
            y_hi  = splits_full[zone_i + 1]
            tilt  = tilt_px[zone_i] / W        # slope: px shift per pixel of x
            tilt_adj = col_idx * tilt           # (1, W) y-shift per column
            mask  = (row_idx >= (y_lo + tilt_adj)) & (row_idx < (y_hi + tilt_adj))
            adj_r = _np.where(mask, adj_r * (1.0 - blend) + smooth_r * blend, adj_r)
            adj_g = _np.where(mask, adj_g * (1.0 - blend) + smooth_g * blend, adj_g)
            adj_b = _np.where(mask, adj_b * (1.0 - blend) + smooth_b * blend, adj_b)

        # ── (3) Boundary lines ─────────────────────────────────────────────────
        lo      = float(line_opacity)
        half_lw = max(1, line_width // 2)

        for split_y in raw_splits:
            y_int     = int(round(float(split_y)))
            y_lo_draw = max(0, y_int - half_lw)
            y_hi_draw = min(H, y_int + half_lw + 1)
            neigh_lo  = max(0, y_int - 4)
            neigh_hi  = min(H, y_int + 5)
            # Boundary color: local neighborhood mean, darkened
            line_r    = adj_r[neigh_lo:neigh_hi, :].mean(axis=0) * 0.85
            line_g    = adj_g[neigh_lo:neigh_hi, :].mean(axis=0) * 0.85
            line_b    = adj_b[neigh_lo:neigh_hi, :].mean(axis=0) * 0.85
            adj_r[y_lo_draw:y_hi_draw, :] = (
                adj_r[y_lo_draw:y_hi_draw, :] * (1.0 - lo) + line_r * lo)
            adj_g[y_lo_draw:y_hi_draw, :] = (
                adj_g[y_lo_draw:y_hi_draw, :] * (1.0 - lo) + line_g * lo)
            adj_b[y_lo_draw:y_hi_draw, :] = (
                adj_b[y_lo_draw:y_hi_draw, :] * (1.0 - lo) + line_b * lo)

        # ── (4) Coastal palette shift ──────────────────────────────────────────
        ps  = float(palette_shift)
        lb  = float(luminosity_boost)

        # Perceptual luminance before palette shift
        lum = 0.2126 * adj_r + 0.7152 * adj_g + 0.0722 * adj_b

        # Luminosity lift: boost brightness toward white
        adj_r = _np.clip(adj_r + lb * (1.0 - adj_r), 0.0, 1.0)
        adj_g = _np.clip(adj_g + lb * (1.0 - adj_g), 0.0, 1.0)
        adj_b = _np.clip(adj_b + lb * (1.0 - adj_b), 0.0, 1.0)

        # Shadow cooling: shift dark regions toward Pacific blue-cool
        shadow_w = _np.clip((0.45 - lum) / 0.45, 0.0, 1.0) * ps
        adj_r    = _np.clip(adj_r - shadow_w * 0.08, 0.0, 1.0)
        adj_b    = _np.clip(adj_b + shadow_w * 0.06, 0.0, 1.0)

        # Mild global desaturation (sun-bleached coastal look)
        desat = 0.15 * ps
        lum2  = 0.2126 * adj_r + 0.7152 * adj_g + 0.0722 * adj_b
        adj_r = _np.clip(adj_r * (1.0 - desat) + lum2 * desat, 0.0, 1.0)
        adj_g = _np.clip(adj_g * (1.0 - desat) + lum2 * desat, 0.0, 1.0)
        adj_b = _np.clip(adj_b * (1.0 - desat) + lum2 * desat, 0.0, 1.0)

        # ── (5) Composite ──────────────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + adj_r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + adj_g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + adj_b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Richard Diebenkorn Ocean Park pass complete.")

    def soutine_visceral_distortion_pass(
        self,
        *,
        warp_strength:    float = 7.0,
        red_push:         float = 0.20,
        ochre_warm:       float = 0.28,
        impasto_radius:   int   = 6,
        impasto_strength: float = 0.50,
        opacity:          float = 0.75,
    ) -> None:
        """
        Chaïm Soutine visceral distortion pass — 128th distinct mode.

        Algorithm: SOUTINE VISCERAL DISTORTION PASS
        (1) WRITHING WARP FIELD: multi-frequency sinusoidal displacement warps
            canvas coordinates (three layers: low/mid/high spatial frequency),
            making forms appear to writhe in the Soutine manner.
            Applied via scipy.ndimage.map_coordinates bilinear remapping.
        (2) RED-OCHRE CHROMATIC PUSH: midtone reds boosted, blues suppressed;
            shadows warmed toward burnt sienna ochre (0.58, 0.38, 0.10).
        (3) IMPASTO RIDGE CARVING: local luminance variance amplified aggressively
            (no raking gradient; continuous amplification scaled by local contrast).
        (4) Composite at opacity.

        NOVEL: ONE HUNDRED AND TWENTY-EIGHTH DISTINCT MODE. First pass to combine
        multi-frequency sinusoidal coordinate warping (map_coordinates pixel
        remapping — distinct from Munch's stroke-based swirl) with warm red-ochre
        chromatic push and impasto ridge amplification without a raking gradient.
        The three-layer warp field (low/mid/high frequency sine superposition)
        produces Soutine's characteristic writhing-form distortion as a pixel-space
        coordinate transformation rather than a stroke-drawing operation.
        """
        import numpy as _np
        from scipy.ndimage import map_coordinates as _mc
        from scipy.ndimage import uniform_filter as _uf

        # ── (0) Read canvas ────────────────────────────────────────────────────
        surface = self.canvas.surface
        H, W    = self.canvas.h, self.canvas.w
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape((H, W, 4)).copy()
        b0      = orig[:, :, 0].astype(_np.float32) / 255.0
        g0      = orig[:, :, 1].astype(_np.float32) / 255.0
        r0      = orig[:, :, 2].astype(_np.float32) / 255.0

        rng    = _np.random.RandomState(seed=217)
        phases = rng.uniform(0.0, 2.0 * _np.pi, 8)
        pi2    = 2.0 * _np.pi
        ws     = float(warp_strength)

        # Normalised coordinate grids (0→1)
        yn = _np.arange(H, dtype=_np.float32)[:, _np.newaxis] / max(H - 1, 1)  # (H,1)
        xn = _np.arange(W, dtype=_np.float32)[_np.newaxis, :] / max(W - 1, 1)  # (1,W)

        # ── (1) Writhing warp field — three-frequency sine superposition ───────
        # Low frequency: broad writhing (~4 cycles across image)
        dx = (ws * 0.60) * _np.sin(pi2 * 4.0 * yn + phases[0]) * _np.cos(pi2 * 3.0 * xn + phases[1])
        dy = (ws * 0.60) * _np.cos(pi2 * 3.5 * xn + phases[2]) * _np.sin(pi2 * 4.5 * yn + phases[3])

        # Mid frequency: knotted twist (~8 cycles + cross-coupling)
        dx += (ws * 0.30) * _np.sin(pi2 * 8.0 * yn + phases[4] + pi2 * 0.7 * xn)
        dy += (ws * 0.30) * _np.cos(pi2 * 7.0 * xn + phases[5] + pi2 * 0.8 * yn)

        # High frequency: grain-level agitation (~16 cycles)
        dx += (ws * 0.10) * _np.sin(pi2 * 16.0 * yn + phases[6] * xn)
        dy += (ws * 0.10) * _np.cos(pi2 * 15.0 * xn + phases[7] * yn)

        # Build displaced pixel coordinate grids (in pixel-index space)
        row_idx = _np.arange(H, dtype=_np.float32)[:, _np.newaxis]  # (H,1)
        col_idx = _np.arange(W, dtype=_np.float32)[_np.newaxis, :]  # (1,W)
        src_row = (row_idx + dy).ravel()  # (H*W,)
        src_col = (col_idx + dx).ravel()  # (H*W,)
        coords  = [src_row, src_col]

        # Remap each channel (bilinear, reflect-pad borders)
        warped_b = _mc(b0, coords, order=1, mode="reflect").reshape((H, W))
        warped_g = _mc(g0, coords, order=1, mode="reflect").reshape((H, W))
        warped_r = _mc(r0, coords, order=1, mode="reflect").reshape((H, W))

        warped_r = _np.clip(warped_r, 0.0, 1.0)
        warped_g = _np.clip(warped_g, 0.0, 1.0)
        warped_b = _np.clip(warped_b, 0.0, 1.0)

        # ── (2) Red-ochre chromatic push ───────────────────────────────────────
        lum = 0.299 * warped_r + 0.587 * warped_g + 0.114 * warped_b

        # Midtone zone boost (lum in [0.20, 0.70])
        midtone_w = _np.clip(
            _np.minimum(lum - 0.20, 0.70 - lum) / 0.20, 0.0, 1.0
        )
        rp        = float(red_push)
        warped_r  = _np.clip(warped_r + rp * midtone_w, 0.0, 1.0)
        warped_b  = _np.clip(warped_b - rp * 0.40 * midtone_w, 0.0, 1.0)

        # Shadow ochre warming (lum < 0.40) toward burnt sienna (0.58, 0.38, 0.10)
        ochre_r, ochre_g, ochre_b = 0.58, 0.38, 0.10
        ow       = float(ochre_warm)
        shadow_w = _np.clip((0.40 - lum) / 0.40, 0.0, 1.0) * ow
        warped_r = _np.clip(warped_r * (1.0 - shadow_w) + ochre_r * shadow_w, 0.0, 1.0)
        warped_g = _np.clip(warped_g * (1.0 - shadow_w) + ochre_g * shadow_w, 0.0, 1.0)
        warped_b = _np.clip(warped_b * (1.0 - shadow_w) + ochre_b * shadow_w, 0.0, 1.0)

        # ── (3) Impasto ridge carving ──────────────────────────────────────────
        lum2        = 0.299 * warped_r + 0.587 * warped_g + 0.114 * warped_b
        k           = int(impasto_radius) * 2 + 1
        lum_mean    = _uf(lum2,        size=k, mode="reflect")
        lum_sq_mean = _uf(lum2 ** 2,   size=k, mode="reflect")
        lum_var     = _np.clip(lum_sq_mean - lum_mean ** 2, 0.0, None)
        lum_std     = _np.sqrt(lum_var)

        # Aggressive continuous amplification (no threshold; stronger cap than Freud)
        ims          = float(impasto_strength)
        ridge_amp    = 1.0 + ims * lum_std * 8.0
        dev          = lum2 - lum_mean
        adj_lum      = _np.clip(lum_mean + dev * ridge_amp, 0.0, 1.0)

        lum_safe     = _np.where(lum2 > 1e-6, lum2, 1e-6)
        lum_ratio    = _np.clip(adj_lum / lum_safe, 0.0, 2.8)
        warped_r     = _np.clip(warped_r * lum_ratio, 0.0, 1.0)
        warped_g     = _np.clip(warped_g * lum_ratio, 0.0, 1.0)
        warped_b     = _np.clip(warped_b * lum_ratio, 0.0, 1.0)

        # ── (4) Composite ──────────────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + warped_r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + warped_g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + warped_b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Chaïm Soutine Visceral Distortion pass complete.")

    def kokoschka_anxious_portrait_pass(
        self,
        *,
        edge_darkness:    float = 0.55,
        color_tension:    float = 0.30,
        scratch_strength: float = 0.40,
        shadow_gamma:     float = 1.8,
        opacity:          float = 0.80,
    ) -> None:
        """
        Oskar Kokoschka anxious portrait pass — 129th distinct mode.

        Algorithm: KOKOSCHKA ANXIOUS PORTRAIT PASS
        (1) DoG CONTOUR DARKENING: Difference-of-Gaussians edge map
            (sigma_inner=1.5, sigma_outer=5.0) on luminance identifies form
            boundaries. Modulated by RandomState(218) noise (scratch_strength)
            to produce scratchy, irregular painted contours. All channels
            darkened in proportion to edge_darkness * modulated_edge_map.
        (2) PSYCHOLOGICAL WARM/COOL ZONE SHIFT: Shadow zones (lum < 0.45)
            blended toward Kokoschka blue-green (0.20, 0.40, 0.45); warm
            midtones (lum in [0.45, 0.75]) blended toward flesh-red
            (0.65, 0.25, 0.15). Blend weight scaled by color_tension.
        (3) EXPRESSIVE SHADOW GAMMA: Power curve (shadow_gamma) applied to
            shadow zones (lum < 0.80); highlights held. RGB rescaled.
        (4) Composite at opacity.

        NOVEL: ONE HUNDRED AND TWENTY-NINTH DISTINCT MODE. Combines
        Difference-of-Gaussians contour darkening with stochastic noise
        modulation (scratchy painted outlines) and warm/cool zone-specific
        hue shifting (blue-green in shadows, warm-red in midtones) plus
        gamma-based shadow intensification. The DoG contour approach extracts
        edges from the image's own gradient structure and darkens them as
        painted marks — distinct from Schiele's geometric stroke drawing,
        Freud's raking-gradient impasto, Soutine's sinusoidal coordinate
        warping, and Munch's displacement swirl field.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        # ── (0) Read canvas ────────────────────────────────────────────────────
        surface = self.canvas.surface
        H, W    = self.canvas.h, self.canvas.w
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape((H, W, 4)).copy()
        b0      = orig[:, :, 0].astype(_np.float32) / 255.0
        g0      = orig[:, :, 1].astype(_np.float32) / 255.0
        r0      = orig[:, :, 2].astype(_np.float32) / 255.0

        r = r0.copy()
        g = g0.copy()
        b = b0.copy()

        # ── (1) DoG Contour Darkening ──────────────────────────────────────────
        lum = 0.299 * r + 0.587 * g + 0.114 * b

        # Difference-of-Gaussians edge map
        g_inner = _gf(lum, sigma=1.5)
        g_outer = _gf(lum, sigma=5.0)
        dog     = g_inner - g_outer
        dog_pos = _np.clip(dog, 0.0, None)

        # Normalize to [0, 1]
        dog_max = dog_pos.max()
        if dog_max > 1e-6:
            dog_norm = dog_pos / dog_max
        else:
            dog_norm = dog_pos

        # Stochastic modulation — makes contours scratchy and irregular
        rng       = _np.random.RandomState(seed=218)
        noise     = rng.uniform(0.0, 1.0, (H, W)).astype(_np.float32)
        noise_sm  = _gf(noise, sigma=0.8)   # slight smoothing to kill pixel-level salt noise
        modulated = dog_norm * (1.0 + float(scratch_strength) * noise_sm)
        modulated = _np.clip(modulated, 0.0, 1.0)

        # Darken channels at edge locations
        ed = float(edge_darkness)
        r  = _np.clip(r * (1.0 - ed * modulated), 0.0, 1.0)
        g  = _np.clip(g * (1.0 - ed * modulated), 0.0, 1.0)
        b  = _np.clip(b * (1.0 - ed * modulated), 0.0, 1.0)

        # ── (2) Psychological Warm/Cool Zone Shift ─────────────────────────────
        lum2 = 0.299 * r + 0.587 * g + 0.114 * b
        ct   = float(color_tension)

        # Shadow zone: blend toward Kokoschka blue-green (0.20, 0.40, 0.45)
        shadow_w = _np.clip((0.45 - lum2) / 0.40, 0.0, 1.0) * ct
        r = _np.clip(r * (1.0 - shadow_w) + 0.20 * shadow_w, 0.0, 1.0)
        g = _np.clip(g * (1.0 - shadow_w) + 0.40 * shadow_w, 0.0, 1.0)
        b = _np.clip(b * (1.0 - shadow_w) + 0.45 * shadow_w, 0.0, 1.0)

        # Warm midtone zone: blend toward warm flesh-red (0.65, 0.25, 0.15)
        mid_w = _np.clip(_np.minimum(lum2 - 0.45, 0.75 - lum2) / 0.15, 0.0, 1.0) * ct
        r = _np.clip(r * (1.0 - mid_w) + 0.65 * mid_w, 0.0, 1.0)
        g = _np.clip(g * (1.0 - mid_w) + 0.25 * mid_w, 0.0, 1.0)
        b = _np.clip(b * (1.0 - mid_w) + 0.15 * mid_w, 0.0, 1.0)

        # ── (3) Expressive Shadow Gamma ────────────────────────────────────────
        lum3    = 0.299 * r + 0.587 * g + 0.114 * b
        gamma   = float(shadow_gamma)
        # weight: 1.0 in deep shadows, 0.0 at lum >= 0.80
        dark_w  = _np.clip((0.80 - lum3) / 0.80, 0.0, 1.0)
        adj_lum = (lum3 ** gamma) * dark_w + lum3 * (1.0 - dark_w)
        adj_lum = _np.clip(adj_lum, 0.0, 1.0)

        lum_safe = _np.where(lum3 > 1e-6, lum3, 1e-6)
        lum_ratio = _np.clip(adj_lum / lum_safe, 0.0, 2.5)
        r = _np.clip(r * lum_ratio, 0.0, 1.0)
        g = _np.clip(g * lum_ratio, 0.0, 1.0)
        b = _np.clip(b * lum_ratio, 0.0, 1.0)

        # ── (4) Composite ──────────────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Oskar Kokoschka Anxious Portrait pass complete.")

    def boldini_belle_epoque_swirl_pass(
        self,
        *,
        swirl_strength: float = 8.0,
        swirl_falloff: float = 0.55,
        gold_warmth: float = 0.25,
        elongation_sigma: float = 3.5,
        opacity: float = 0.75,
    ) -> None:
        """
        Boldini Belle Époque Swirl — ONE HUNDRED AND THIRTIETH distinct mode.
        Session 219: Giovanni Boldini (1842–1931).

        Three-stage algorithm implementing Boldini's animated portrait language:
        radial spiral warp centred on the canvas, warm gold chromatic push, and
        directional edge elongation that turns form boundaries into calligraphic swirls.

        Novelty (vs. Soutine s217 warp): Soutine uses multi-frequency sinusoidal
        warp across the full canvas to convey writhing distortion.  Boldini's warp
        is radially organised — a true polar spiral — so the swirl radiates from a
        central focal point, mimicking the centrifugal energy of a turning figure.
        The additional gold-warmth pass encodes Boldini's gaslit salon atmosphere,
        and the edge-elongation blur is gated to gradient zones only, leaving the
        face and hands relatively crisp while backgrounds dissolve into spiral marks.

        swirl_strength   : Peak spiral warp displacement in pixels at the canvas
                           centre.  Controls how dramatically background elements
                           spiral around the figure.  Default 8.0 px; reduce to
                           3–4 for subtlety, raise to 12–16 for full Boldini
                           expressiveness.
        swirl_falloff    : Radial falloff power applied to warp strength.  Higher
                           values concentrate the swirl near the canvas centre
                           while preserving peripheral detail.  Default 0.55.
        gold_warmth      : Blend strength toward warm gold (0.88, 0.72, 0.30) in
                           midtone and highlight zones.  Simulates Boldini's
                           gaslit Paris salon atmosphere — warm light enriches
                           skin and dress fabrics with an amber-gold cast.
                           Default 0.25; practical range 0.15–0.40.
        elongation_sigma : Sigma of the Gaussian blur applied along gradient
                           edge zones.  Creates Boldini's characteristic brushstroke
                           elongation — form boundaries become calligraphic swirls
                           rather than crisp edges.  Default 3.5 px; range 2.0–6.0.
        opacity          : Final composite strength vs original canvas.  Default 0.75.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Boldini Belle Époque Swirl pass (130th mode)…")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        # Extract float32 BGR → RGB
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()

        # ── (1) Radial Spiral Warp ─────────────────────────────────────────────
        # Build polar coordinate map centred on the canvas.
        cy, cx  = h / 2.0, w / 2.0
        ys      = _np.arange(h, dtype=_np.float32) - cy
        xs      = _np.arange(w, dtype=_np.float32) - cx
        xx, yy  = _np.meshgrid(xs, ys)       # (H, W) coordinate grids

        r_px    = _np.sqrt(xx**2 + yy**2)    # radial distance in pixels
        theta   = _np.arctan2(yy, xx)         # polar angle

        # Warp angle offset: stronger near centre, falls off radially.
        half_diag   = _np.sqrt((h / 2)**2 + (w / 2)**2)
        norm_r      = r_px / (half_diag + 1e-6)
        falloff_map = _np.clip(1.0 - norm_r ** float(swirl_falloff), 0.0, 1.0)
        delta_theta = float(swirl_strength) / (r_px + 1.0) * falloff_map * half_diag * 0.012

        # New coordinates after spiral rotation
        theta_new = theta + delta_theta
        new_xs    = r_px * _np.cos(theta_new) + cx    # (H, W)
        new_ys    = r_px * _np.sin(theta_new) + cy    # (H, W)

        coords = [new_ys.ravel(), new_xs.ravel()]
        for arr in (r, g, b):
            warped = _ndi.map_coordinates(
                arr, coords, order=1, mode='nearest'
            ).reshape(h, w).astype(_np.float32)
            arr[:] = warped

        # ── (2) Warm Gold Enhancement ──────────────────────────────────────────
        gold  = (0.88, 0.72, 0.30)
        lum   = 0.299 * r + 0.587 * g + 0.114 * b
        # Gate to midtones and highlights: weight peaks at lum ~0.60+
        gold_w = _np.clip((lum - 0.38) / 0.35, 0.0, 1.0) * float(gold_warmth)
        r = _np.clip(r * (1.0 - gold_w) + gold[0] * gold_w, 0.0, 1.0)
        g = _np.clip(g * (1.0 - gold_w) + gold[1] * gold_w, 0.0, 1.0)
        b = _np.clip(b * (1.0 - gold_w) + gold[2] * gold_w, 0.0, 1.0)

        # ── (3) Directional Edge Elongation ───────────────────────────────────
        # Compute gradient magnitude from current luminance.
        lum2  = 0.299 * r + 0.587 * g + 0.114 * b
        gx    = _ndi.sobel(lum2, axis=1).astype(_np.float32)
        gy    = _ndi.sobel(lum2, axis=0).astype(_np.float32)
        gmag  = _np.sqrt(gx**2 + gy**2)

        # Gate blur to edge zones; suppress in flat areas.
        if gmag.max() > 1e-9:
            edge_gate = _np.clip(gmag / gmag.max() * 4.0, 0.0, 1.0)
        else:
            edge_gate = _np.zeros_like(gmag)
        edge_gate = _ndi.gaussian_filter(edge_gate.astype(_np.float32), sigma=1.0)

        # Apply Gaussian blur over edge zones only (max 55% contribution).
        sig = float(elongation_sigma)
        blurred_r = _ndi.gaussian_filter(r, sigma=sig).astype(_np.float32)
        blurred_g = _ndi.gaussian_filter(g, sigma=sig).astype(_np.float32)
        blurred_b = _ndi.gaussian_filter(b, sigma=sig).astype(_np.float32)

        elong_w = edge_gate * 0.55
        r = _np.clip(r * (1.0 - elong_w) + blurred_r * elong_w, 0.0, 1.0)
        g = _np.clip(g * (1.0 - elong_w) + blurred_g * elong_w, 0.0, 1.0)
        b = _np.clip(b * (1.0 - elong_w) + blurred_b * elong_w, 0.0, 1.0)

        # ── (4) Composite ──────────────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Giovanni Boldini Belle Époque Swirl pass complete.")

    def chromatic_zoning_pass(
        self,
        *,
        shadow_hue_shift: float = 0.12,
        highlight_ivory_lift: float = 0.08,
        midtone_saturation_boost: float = 0.18,
        opacity: float = 0.65,
    ) -> None:
        """
        Chromatic Zoning — Session 219 artistic ability improvement.

        Divides the canvas into three luminance-based zones (shadows, midtones,
        highlights) and applies targeted chromatic adjustments to each zone
        independently, improving the articulation of warm/cool temperature
        separation across the full tonal range.

        Inspired by the classical observation that in convincing figure painting,
        highlights lean toward warm ivory/gold, midtones carry the fullest
        chromatic saturation (the carnation zone), and shadows shift toward a
        cool ambient blue-grey.  This pass formalises that zoning with per-zone
        chromatic operators applied softly via bell-curve masks so zone transitions
        are imperceptible.

        Novelty (vs. existing warm_cool_form_duality_pass): that pass applies a
        global warm/cool split based on a single luminance threshold.  Chromatic
        Zoning uses THREE independently-gated zones with different operators in
        each — cool shift in shadows, saturation boost in midtones, ivory
        desaturation in highlights — producing a more nuanced tonal temperature
        articulation that mirrors classical academic painting practice.

        shadow_hue_shift        : Strength of cool blue-grey shift applied to
                                  shadow zones (luminance < 0.35).  Simulates the
                                  cool ambient sky fill that reaches shadow zones
                                  while direct warm light cannot.  Default 0.12.
        highlight_ivory_lift    : Strength of warm ivory desaturation applied
                                  to the brightest highlights (luminance > 0.78).
                                  Peak highlights lose chromatic saturation and
                                  shift toward bone-white — physically accurate
                                  for specular skin reflection.  Default 0.08.
        midtone_saturation_boost: Saturation increase in the midtone zone
                                  (0.35 < lum < 0.78).  Midtones carry the most
                                  chromatic information — carnation warmth, dress
                                  colour, environmental bounce.  A gentle boost
                                  enriches colour presence.  Default 0.18.
        opacity                 : Final composite strength.  Default 0.65.
        """
        import numpy as _np

        print("    Chromatic Zoning pass (session 219 improvement)…")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()
        lum     = 0.299 * r + 0.587 * g + 0.114 * b

        # ── Shadow zone: cool blue-grey shift ─────────────────────────────────
        # Weight peaks at lum=0, falls to zero at lum=0.35.
        shadow_w = _np.clip((0.35 - lum) / 0.35, 0.0, 1.0) ** 1.2 * float(shadow_hue_shift)
        cool     = (0.22, 0.38, 0.52)
        r = _np.clip(r * (1.0 - shadow_w) + cool[0] * shadow_w, 0.0, 1.0)
        g = _np.clip(g * (1.0 - shadow_w) + cool[1] * shadow_w, 0.0, 1.0)
        b = _np.clip(b * (1.0 - shadow_w) + cool[2] * shadow_w, 0.0, 1.0)

        # ── Highlight zone: ivory desaturation ────────────────────────────────
        # Weight peaks at lum=1, falls to zero at lum=0.78.
        hi_w  = _np.clip((lum - 0.78) / 0.22, 0.0, 1.0) * float(highlight_ivory_lift)
        ivory = (0.94, 0.92, 0.84)
        r = _np.clip(r * (1.0 - hi_w) + ivory[0] * hi_w, 0.0, 1.0)
        g = _np.clip(g * (1.0 - hi_w) + ivory[1] * hi_w, 0.0, 1.0)
        b = _np.clip(b * (1.0 - hi_w) + ivory[2] * hi_w, 0.0, 1.0)

        # ── Midtone zone: saturation boost ────────────────────────────────────
        # Triangular gate: peaks at lum≈0.55, falls to zero at lum=0.35 and 0.78.
        mid_w   = _np.clip(
            _np.minimum((lum - 0.35) / 0.20, (0.78 - lum) / 0.23), 0.0, 1.0
        ) * float(midtone_saturation_boost)
        neutral = (r + g + b) / 3.0
        r = _np.clip(neutral + (r - neutral) * (1.0 + mid_w), 0.0, 1.0)
        g = _np.clip(neutral + (g - neutral) * (1.0 + mid_w), 0.0, 1.0)
        b = _np.clip(neutral + (b - neutral) * (1.0 + mid_w), 0.0, 1.0)

        # ── Composite ─────────────────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Chromatic Zoning pass complete.")

    def tuymans_pale_wash_pass(
        self,
        *,
        desaturation_strength: float = 0.72,
        pallor_cool: float = 0.18,
        tonal_compression: float = 0.28,
        thin_paint_blur: float = 1.2,
        opacity: float = 0.80,
    ) -> None:
        """
        Tuymans Pale Wash — ONE HUNDRED AND THIRTY-FIRST distinct mode.
        Session 220: Luc Tuymans (1958–present).

        Four-stage algorithm implementing Tuymans' signature clinical desaturation:
        aggressive saturation pull toward near-achromatic, cool pallor in mid-tones
        and highlights, gamma-based tonal compression that lifts shadows and
        compresses highlights to create the washed-out quality, and a low-weight
        Gaussian blend simulating the visual effect of thinly applied oil.

        Novelty (vs. Boldini s220 swirl and existing passes): Boldini's pass
        adds warmth and movement; this pass does the opposite — it strips warmth,
        arrests movement, and compresses tonal range. The tonal compression via
        gamma lift is distinct from the existing chromatic_zoning_pass (which
        boosts midtone saturation) and from atmospheric_depth_pass (which applies
        a depth-cued gradient). This pass applies uniform tonal collapse across the
        whole canvas — the Tuymans effect is totalising, not zonal.

        desaturation_strength: Blend strength toward neutral grey per channel.
                               0 = original, 1 = fully greyscale.  Default 0.72 —
                               strong desaturation but retaining the faintest
                               hint of warmth or coolness.
        pallor_cool          : Blend strength toward cool bone-white in mid-tones
                               and highlights (lum > 0.32).  Simulates the cold
                               north-facing overcast studio light in Tuymans'
                               Antwerp and Brussels paintings.  Default 0.18.
        tonal_compression    : Gamma exponent modifier.  Applies lum^gamma where
                               gamma = 1 - tonal_compression * 0.45 < 1, which
                               lifts shadow values toward mid-grey while
                               compressing highlights toward white.  The result is
                               the characteristic Tuymans washed-out flatness —
                               no deep blacks, no pure whites, everything resolves
                               in a narrow, pale band.  Default 0.28.
        thin_paint_blur      : Sigma of the Gaussian blur mixed in at 22% weight
                               to simulate the way thinly applied oil paint
                               spreads and softens mark boundaries without fully
                               blurring the composition.  Default 1.2 px.
        opacity              : Final composite strength vs original canvas.
                               Default 0.80.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Tuymans Pale Wash pass (131st mode)…")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()

        # ── (1) Desaturation — pull toward neutral grey ────────────────────────
        neutral = (r + g + b) / 3.0
        ds      = float(desaturation_strength)
        r = r * (1.0 - ds) + neutral * ds
        g = g * (1.0 - ds) + neutral * ds
        b = b * (1.0 - ds) + neutral * ds

        # ── (2) Cool Pallor — north-light bone-white in mid+highlights ─────────
        lum     = 0.299 * r + 0.587 * g + 0.114 * b
        pallor  = (0.90, 0.91, 0.95)
        # Weight peaks at lum=1, rises from zero at lum=0.32
        pallor_w = _np.clip((lum - 0.32) / 0.42, 0.0, 1.0) * float(pallor_cool)
        r = _np.clip(r * (1.0 - pallor_w) + pallor[0] * pallor_w, 0.0, 1.0)
        g = _np.clip(g * (1.0 - pallor_w) + pallor[1] * pallor_w, 0.0, 1.0)
        b = _np.clip(b * (1.0 - pallor_w) + pallor[2] * pallor_w, 0.0, 1.0)

        # ── (3) Tonal Compression — gamma lift lifts shadows, caps highlights ──
        # gamma < 1 lifts all tones: darkest tones lifted most, highlights capped.
        gamma   = 1.0 - float(tonal_compression) * 0.45   # typical range 0.87–0.82
        gamma   = max(gamma, 0.50)                         # safety clamp

        lum2    = 0.299 * r + 0.587 * g + 0.114 * b
        safe    = _np.clip(lum2, 1e-7, 1.0)
        lum_new = _np.clip(safe ** gamma, 0.0, 1.0)
        ratio   = lum_new / safe   # per-pixel brightness adjustment factor

        r = _np.clip(r * ratio, 0.0, 1.0)
        g = _np.clip(g * ratio, 0.0, 1.0)
        b = _np.clip(b * ratio, 0.0, 1.0)

        # ── (4) Thin Paint Simulation — low-weight Gaussian spread ────────────
        sig = float(thin_paint_blur)
        if sig > 0.1:
            br = _ndi.gaussian_filter(r, sigma=sig).astype(_np.float32)
            bg = _ndi.gaussian_filter(g, sigma=sig).astype(_np.float32)
            bb = _ndi.gaussian_filter(b, sigma=sig).astype(_np.float32)
            thin_w = 0.22   # never exceed 40% to keep edges legible
            r = _np.clip(r * (1.0 - thin_w) + br * thin_w, 0.0, 1.0)
            g = _np.clip(g * (1.0 - thin_w) + bg * thin_w, 0.0, 1.0)
            b = _np.clip(b * (1.0 - thin_w) + bb * thin_w, 0.0, 1.0)

        # ── (5) Composite ──────────────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Luc Tuymans Pale Wash pass complete.")

    def bristle_separation_texture_pass(
        self,
        *,
        separation_strength: float = 0.35,
        bristle_count: int = 5,
        bristle_angle_jitter: float = 0.30,
        highlight_boost: float = 0.12,
        shadow_deepen: float = 0.08,
        opacity: float = 0.55,
    ) -> None:
        """
        Bristle Separation Texture — Session 220 artistic ability improvement.

        Simulates the distinctive optical effect of a fanned bristle brush:
        each brushstroke leaves multiple parallel sub-marks rather than a
        single continuous swath.  Between the bristle tracks the canvas
        texture breathes through, producing the characteristic broken-colour
        quality of confident, loaded-brush alla prima painting (Sargent,
        Boldini, Sorolla) and the dry-brush scumble texture of Velázquez and
        Rembrandt's late work.

        Novelty (vs. existing passes): The existing scumble_pass, canvas_grain_pass,
        and impasto_texture_pass all work with surface topology — bump maps,
        texture normals, or dry-brush deposits on a simulated canvas weave.
        This pass instead models the BRISTLE GEOMETRY: it synthesises a set of
        parallel sub-strokes per local gradient direction, producing directional
        micro-striations aligned with the inferred paint direction.  The result
        is a uniquely *painterly* surface quality — not canvas texture, not paint
        relief, but the imprint of the brush itself.

        Distinct from soutine_visceral_distortion_pass: Soutine uses sinusoidal
        warp to distort the whole image.  Bristle separation applies anisotropic
        directional micro-contrast without displacing pixel positions.

        separation_strength  : Overall strength of the bristle separation
                               effect.  Higher values make individual bristle
                               tracks more visible.  Default 0.35.
        bristle_count        : Number of parallel bristle sub-tracks per stroke
                               direction sample.  More bristles = finer texture.
                               Default 5; practical range 3–9.
        bristle_angle_jitter : Random angular spread of the bristle fan in
                               radians.  Small values (0.20–0.40) give a
                               coherent parallel-stripe feel; larger values
                               (0.80+) approach a random-bristle effect like
                               a worn brush.  Default 0.30.
        highlight_boost      : Brightness lift applied to bristle-track peaks
                               (the loaded-paint centres).  Simulates the way
                               fresh wet paint is slightly brighter than the
                               surrounding area.  Default 0.12.
        shadow_deepen        : Darkness applied in the gaps between bristle
                               tracks.  Simulates the bare canvas or dried
                               base that shows through between marks.
                               Default 0.08.
        opacity              : Final composite strength.  Default 0.55.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Bristle Separation Texture pass (session 220 improvement)…")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Infer local stroke direction from luminance gradient ───────────────
        gx = _ndi.sobel(lum, axis=1).astype(_np.float32)
        gy = _ndi.sobel(lum, axis=0).astype(_np.float32)

        # Stroke direction is perpendicular to the gradient (follow the edge).
        stroke_angle = _np.arctan2(gy, gx) + _np.pi / 2.0   # (H, W)
        gmag         = _np.sqrt(gx**2 + gy**2)
        # Smooth the direction field so bristle marks are coherent, not noisy.
        angle_x = _ndi.gaussian_filter(_np.cos(stroke_angle), sigma=4.0)
        angle_y = _ndi.gaussian_filter(_np.sin(stroke_angle), sigma=4.0)
        smooth_angle = _np.arctan2(angle_y, angle_x)

        # ── Build bristle separation mask ──────────────────────────────────────
        # For each pixel, compute a sum of cosines in the bristle-fan directions.
        # The sum oscillates between -1 and +1 across the bristle spacing, giving
        # alternating bright (loaded bristle) and dark (gap) tracks.
        ys = _np.arange(h, dtype=_np.float32)
        xs = _np.arange(w, dtype=_np.float32)
        yy, xx = _np.meshgrid(ys, xs, indexing='ij')   # (H, W) each

        n   = int(bristle_count)
        rng = getattr(self, '_rng', _np.random.RandomState(42))
        # Bristle track spacing in pixels — scale with canvas size
        spacing = max(2.5, min(w, h) * 0.006)

        separation_mask = _np.zeros((h, w), dtype=_np.float32)
        for i in range(n):
            # Fan angle for this bristle: evenly spaced within jitter range
            fan_frac  = (i / max(n - 1, 1)) - 0.5   # -0.5 … +0.5
            bristle_a = smooth_angle + fan_frac * float(bristle_angle_jitter)

            # Project each pixel onto the bristle direction — varies with position
            proj = xx * _np.cos(bristle_a) + yy * _np.sin(bristle_a)

            # Cosine oscillation across bristle spacing
            wave = _np.cos(2.0 * _np.pi * proj / spacing)
            separation_mask += wave

        separation_mask /= float(n)   # average — range ≈ [-1, +1]

        # ── Gate by gradient magnitude — no effect in flat/uniform areas ───────
        if gmag.max() > 1e-9:
            edge_gate = _np.clip(gmag / gmag.max() * 5.0, 0.0, 1.0)
        else:
            edge_gate = _np.zeros_like(gmag)
        edge_gate = _ndi.gaussian_filter(edge_gate, sigma=2.0).astype(_np.float32)

        strength = float(separation_strength) * edge_gate

        # Peaks (+1): bristle track centres — apply highlight boost
        hi  = _np.clip(separation_mask, 0.0, 1.0) * strength * float(highlight_boost)
        # Troughs (-1): gaps between bristles — apply shadow deepen
        shd = _np.clip(-separation_mask, 0.0, 1.0) * strength * float(shadow_deepen)

        delta = hi - shd   # net luminance delta per pixel, range ≈ [-strength*shadow, +strength*hi]

        r_adj = _np.clip(r0 + delta, 0.0, 1.0)
        g_adj = _np.clip(g0 + delta, 0.0, 1.0)
        b_adj = _np.clip(b0 + delta, 0.0, 1.0)

        # ── Composite ─────────────────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r_adj * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g_adj * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b_adj * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Bristle Separation Texture pass complete.")

    def vallotton_hard_edge_flat_pass(
        self,
        *,
        n_tones: int = 5,
        bilateral_iters: int = 3,
        edge_sharpen: float = 0.60,
        contour_weight: float = 0.25,
        contour_thickness: float = 1.2,
        opacity: float = 0.82,
    ) -> None:
        """
        Vallotton Hard-Edge Flat — ONE HUNDRED AND THIRTY-SECOND distinct mode.
        Session 221: Félix Vallotton (1865–1925).

        Five-stage algorithm implementing Vallotton's anti-impressionist flatness:
        iterated bilateral flattening eliminates within-zone colour variation while
        preserving zone boundaries; posterization forces discrete tonal commitment;
        edge sharpening brings zone contours to hard precision; an optional thin
        woodcut-style contour overlay references Vallotton's celebrated printmaking.

        Novelty (vs. cloisonne_pass and existing passes):
        cloisonne_pass fills zones with *loaded-brush strokes* and draws thick
        organic contours — it is a stroke-simulation pass.  This pass works
        entirely in image-space: bilateral filtering + posterization + unsharp
        edge gate.  The algorithm does not paint; it flattens and sharpens what
        is already on the canvas, replicating how Vallotton's method compresses
        impressionist complexity into hard-edged graphic form.  The contour here
        is thin and precise (woodcut influence), not the broad cloisonné lead of
        Gauguin.  Distinct also from chromatic_zoning_pass (which boosts midtone
        saturation without flattening zones) and watercolor_wash_pass (which adds
        soft, wet spreading).

        n_tones            : Posterization steps per channel.  3 = very graphic,
                             5 = typical Vallotton, 8 = subtle.  Default 5.
        bilateral_iters    : Number of bilateral-filter rounds to flatten within-zone
                             colour.  Each pass reduces micro-texture while preserving
                             inter-zone edges.  Default 3; range 1–6.
        edge_sharpen       : Unsharp-mask strength applied exclusively at zone
                             boundaries.  0 = no sharpening, 1 = maximum crispness.
                             Default 0.60.
        contour_weight     : Opacity of the thin woodcut-style dark contour overlay.
                             0 = no contour, 0.25 = subtle reference to printmaking.
                             Default 0.25.
        contour_thickness  : Gaussian sigma (pixels) used to grow the contour mask.
                             Lower values = thinner, sharper woodcut lines.  Default 1.2.
        opacity            : Final composite blend with original canvas.  Default 0.82.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Vallotton Hard-Edge Flat pass (132nd mode)…")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()

        # ── Stage 1 — Zone Flattening (bilateral-equivalent cascade) ──────────
        # True bilateral filtering requires cv2 or skimage; we replicate it via
        # a Gaussian cascade: large-sigma Gaussian weights neighbouring pixels
        # by spatial proximity and colour similarity through iterative application.
        # Each iteration: compute local mean via Gaussian blur, then pull each
        # channel toward the mean proportionally to how close the local colour
        # is to the pixel's own colour (colour-similarity gate).
        sigma_s = max(2.0, min(w, h) * 0.012)   # spatial sigma — scale with canvas
        sigma_c = 0.18                            # colour similarity threshold
        n_iters = max(1, int(bilateral_iters))
        for _ in range(n_iters):
            # Smooth the colour channels spatially
            br = _ndi.gaussian_filter(r, sigma=sigma_s).astype(_np.float32)
            bg = _ndi.gaussian_filter(g, sigma=sigma_s).astype(_np.float32)
            bb = _ndi.gaussian_filter(b, sigma=sigma_s).astype(_np.float32)
            # Colour-similarity gate: how close is each pixel to its local mean?
            # Pixels far from their local mean (edges) receive less pull.
            diff_sq = (r - br) ** 2 + (g - bg) ** 2 + (b - bb) ** 2
            sim     = _np.exp(-diff_sq / (2.0 * sigma_c ** 2))
            # Blend toward smoothed version only where colour is similar
            r = _np.clip(r * (1.0 - sim) + br * sim, 0.0, 1.0)
            g = _np.clip(g * (1.0 - sim) + bg * sim, 0.0, 1.0)
            b = _np.clip(b * (1.0 - sim) + bb * sim, 0.0, 1.0)

        # ── Stage 2 — Posterization ────────────────────────────────────────────
        # Quantize each channel to n_tones discrete steps.
        # Vallotton's zones are committed — no gradient survives.
        n = max(2, int(n_tones))
        step = 1.0 / float(n - 1)
        r = _np.round(r / step) * step
        g = _np.round(g / step) * step
        b = _np.round(b / step) * step
        r = _np.clip(r, 0.0, 1.0)
        g = _np.clip(g, 0.0, 1.0)
        b = _np.clip(b, 0.0, 1.0)

        # ── Stage 3 — Edge Sharpening at Zone Boundaries ──────────────────────
        # Detect zone boundaries from the posterized image (luminance).
        lum_post = 0.299 * r + 0.587 * g + 0.114 * b
        gx  = _ndi.sobel(lum_post, axis=1).astype(_np.float32)
        gy  = _ndi.sobel(lum_post, axis=0).astype(_np.float32)
        gmag = _np.sqrt(gx ** 2 + gy ** 2)
        if gmag.max() > 1e-9:
            gmag = gmag / gmag.max()

        # Unsharp-mask signal from a light Gaussian blur of the posterized image
        blur_r = _ndi.gaussian_filter(r, sigma=1.5).astype(_np.float32)
        blur_g = _ndi.gaussian_filter(g, sigma=1.5).astype(_np.float32)
        blur_b = _ndi.gaussian_filter(b, sigma=1.5).astype(_np.float32)
        sharp  = float(edge_sharpen)
        # Gate the sharpening to edge zones only — flat interior zones untouched
        gate   = _np.clip(gmag * 4.0, 0.0, 1.0)   # binary-ish mask of edge regions
        r = _np.clip(r + sharp * gate * (r - blur_r), 0.0, 1.0)
        g = _np.clip(g + sharp * gate * (g - blur_g), 0.0, 1.0)
        b = _np.clip(b + sharp * gate * (b - blur_b), 0.0, 1.0)

        # ── Stage 4 — Thin Woodcut Contour Overlay ────────────────────────────
        cw = float(contour_weight)
        if cw > 0.01:
            # Re-detect edges on the sharpened result for the final contour mask
            lum_sharp = 0.299 * r + 0.587 * g + 0.114 * b
            ex = _ndi.sobel(lum_sharp, axis=1).astype(_np.float32)
            ey = _ndi.sobel(lum_sharp, axis=0).astype(_np.float32)
            emag = _np.sqrt(ex ** 2 + ey ** 2)
            if emag.max() > 1e-9:
                emag = emag / emag.max()
            # Grow the contour mask slightly — woodcut lines have finite width
            ct_sigma = max(0.5, float(contour_thickness))
            contour_mask = _ndi.gaussian_filter(emag, sigma=ct_sigma).astype(_np.float32)
            # Threshold to a thin hard line
            threshold    = _np.percentile(contour_mask, 80)
            contour_mask = _np.clip((contour_mask - threshold) / max(threshold, 1e-9),
                                     0.0, 1.0)
            # Vallotton's woodcut lines: near-black, not Gauguin's blue-black
            c_dark = 0.08
            r = _np.clip(r * (1.0 - contour_mask * cw) + c_dark * contour_mask * cw,
                          0.0, 1.0)
            g = _np.clip(g * (1.0 - contour_mask * cw) + c_dark * contour_mask * cw,
                          0.0, 1.0)
            b = _np.clip(b * (1.0 - contour_mask * cw) + c_dark * contour_mask * cw,
                          0.0, 1.0)

        # ── Stage 5 — Composite ───────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Vallotton Hard-Edge Flat pass complete.")

    def bonnard_chromatic_intimism_pass(
        self,
        *,
        saturation_boost: float = 0.55,
        violet_shadow: float = 0.40,
        gold_highlight: float = 0.30,
        dapple_strength: float = 0.08,
        contour_soften: float = 0.35,
        opacity: float = 0.85,
    ) -> None:
        """
        Bonnard Chromatic Intimism -- ONE HUNDRED AND THIRTY-THIRD distinct mode.
        Session 222: Pierre Bonnard (1867-1947).

        Six-stage algorithm implementing Bonnard's memory-heightened chromatic
        intensification: saturation is boosted beyond observation, shadow zones
        shift to warm violet-rose, highlights lift to cream gold, mid-tones receive
        a seeded dappled luminance scatter (light through curtains/foliage), and
        contours are softened so forms dissolve into their surrounding colour fields.

        Novelty (vs. chromatic_zoning_pass and existing passes):
        chromatic_zoning_pass shadows are cool blue-grey (0.22, 0.38, 0.52).
        Bonnard's shadows are warm violet-rose (0.55, 0.32, 0.65) -- a different
        chromatic perception.  The dappled scatter stage (seeded Gaussian noise
        gated to mid-tones) is new to the pipeline.  The contour-softening stage
        blends the blurred image at edge zones -- distinct from all existing passes.
        Global saturation expansion ch = lum + (ch-lum)*(1+boost) differs from
        chromatic_zoning_pass's neutral-level midtone expansion.

        saturation_boost : Expand each channel away from luminance.  Default 0.55.
        violet_shadow    : Shadow blend toward violet-rose (0.55,0.32,0.65).  Default 0.40.
        gold_highlight   : Highlight blend toward cream-gold (0.96,0.90,0.72).  Default 0.30.
        dapple_strength  : Mid-tone seeded noise amplitude.  Default 0.08.
        contour_soften   : Edge-zone Gaussian blend to dissolve contours.  Default 0.35.
        opacity          : Final composite opacity.  Default 0.85.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Bonnard Chromatic Intimism pass (133rd mode)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r = orig[:, :, 2].astype(_np.float32) / 255.0
        g = orig[:, :, 1].astype(_np.float32) / 255.0
        b = orig[:, :, 0].astype(_np.float32) / 255.0
        r0, g0, b0 = r.copy(), g.copy(), b.copy()

        lum = (0.299 * r + 0.587 * g + 0.114 * b).astype(_np.float32)

        # -- Stage 1 -- Chromatic Saturation Boost --------------------------------
        boost = float(saturation_boost)
        r = _np.clip(lum + (r - lum) * (1.0 + boost), 0.0, 1.0)
        g = _np.clip(lum + (g - lum) * (1.0 + boost), 0.0, 1.0)
        b = _np.clip(lum + (b - lum) * (1.0 + boost), 0.0, 1.0)

        lum = (0.299 * r + 0.587 * g + 0.114 * b).astype(_np.float32)

        # -- Stage 2 -- Violet-Rose Shadow Toning ---------------------------------
        vs_weight = _np.clip((0.45 - lum) / 0.30, 0.0, 1.0)
        vs = float(violet_shadow)
        r = _np.clip(r * (1.0 - vs * vs_weight) + 0.55 * vs * vs_weight, 0.0, 1.0)
        g = _np.clip(g * (1.0 - vs * vs_weight) + 0.32 * vs * vs_weight, 0.0, 1.0)
        b = _np.clip(b * (1.0 - vs * vs_weight) + 0.65 * vs * vs_weight, 0.0, 1.0)

        # -- Stage 3 -- Warm Gold Highlight Gilding --------------------------------
        gh_weight = _np.clip((lum - 0.70) / 0.20, 0.0, 1.0)
        gh = float(gold_highlight)
        r = _np.clip(r * (1.0 - gh * gh_weight) + 0.96 * gh * gh_weight, 0.0, 1.0)
        g = _np.clip(g * (1.0 - gh * gh_weight) + 0.90 * gh * gh_weight, 0.0, 1.0)
        b = _np.clip(b * (1.0 - gh * gh_weight) + 0.72 * gh * gh_weight, 0.0, 1.0)

        # -- Stage 4 -- Dappled Luminance Scatter ----------------------------------
        ds = float(dapple_strength)
        if ds > 1e-6:
            rng       = _np.random.RandomState(222)
            raw_noise = rng.randn(h, w).astype(_np.float32)
            noise     = _ndi.gaussian_filter(raw_noise, sigma=3.0).astype(_np.float32)
            if noise.std() > 1e-9:
                noise = noise / noise.std()
            mid_gate = _np.clip(
                _np.minimum(lum - 0.35, 0.75 - lum) / 0.20, 0.0, 1.0
            )
            dapple = ds * noise * mid_gate
            r = _np.clip(r + dapple, 0.0, 1.0)
            g = _np.clip(g + dapple, 0.0, 1.0)
            b = _np.clip(b + dapple, 0.0, 1.0)

        # -- Stage 5 -- Contour Softening ------------------------------------------
        cs = float(contour_soften)
        if cs > 1e-6:
            lum_cur = (0.299 * r + 0.587 * g + 0.114 * b).astype(_np.float32)
            gx      = _ndi.sobel(lum_cur, axis=1).astype(_np.float32)
            gy      = _ndi.sobel(lum_cur, axis=0).astype(_np.float32)
            gmag    = _np.sqrt(gx ** 2 + gy ** 2)
            if gmag.max() > 1e-9:
                edge_gate = _np.clip(gmag / gmag.max() * 3.0, 0.0, 1.0)
            else:
                edge_gate = _np.zeros_like(gmag)
            edge_gate = _ndi.gaussian_filter(edge_gate, sigma=1.5).astype(_np.float32)

            blur_r = _ndi.gaussian_filter(r, sigma=2.0).astype(_np.float32)
            blur_g = _ndi.gaussian_filter(g, sigma=2.0).astype(_np.float32)
            blur_b = _ndi.gaussian_filter(b, sigma=2.0).astype(_np.float32)
            blend  = cs * edge_gate
            r = _np.clip(r * (1.0 - blend) + blur_r * blend, 0.0, 1.0)
            g = _np.clip(g * (1.0 - blend) + blur_g * blend, 0.0, 1.0)
            b = _np.clip(b * (1.0 - blend) + blur_b * blend, 0.0, 1.0)

        # -- Stage 6 -- Composite --------------------------------------------------
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Bonnard Chromatic Intimism pass complete.")

    def edge_quality_variation_pass(
        self,
        *,
        lost_soften: float = 0.60,
        soft_blur: float = 0.30,
        firm_sharpen: float = 0.40,
        hard_sharpen: float = 0.80,
        opacity: float = 0.75,
    ) -> None:
        """
        Edge Quality Variation -- session 222 artistic improvement.

        Classical painting edge theory distinguishes four edge types by local contrast:
          Lost   -- adjacent values so close the boundary disappears
          Soft   -- gradual transition; areas remain distinct
          Firm   -- clear boundary with moderate contrast
          Hard   -- high contrast transition; eye immediately drawn

        This pass classifies each pixel's region by Sobel edge magnitude percentile
        and applies zone-appropriate processing:
          Lost  (lowest 30%): Gaussian blend to merge near-invisible boundaries
          Soft  (30-60%):     mild Gaussian spread
          Firm  (60-85%):     moderate unsharp-mask sharpening
          Hard  (top 15%):    strong unsharp-mask sharpening

        Novelty: first pass to implement differential edge processing based on the
        four-category classical painting framework. vallotton_hard_edge_flat_pass
        sharpens all zone edges uniformly; this pass applies a spectrum -- losing
        some, softening some, firming some, hardening others.

        lost_soften   : Gaussian blend weight at lost-edge zones.  Default 0.60.
        soft_blur     : Gaussian blend weight at soft-edge zones.  Default 0.30.
        firm_sharpen  : Unsharp-mask strength at firm-edge zones.  Default 0.40.
        hard_sharpen  : Unsharp-mask strength at hard-edge zones.  Default 0.80.
        opacity       : Final composite opacity.  Default 0.75.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Edge Quality Variation pass (session 222 improvement)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        r, g, b = r0.copy(), g0.copy(), b0.copy()

        # -- Compute edge magnitude map --------------------------------------------
        lum  = (0.299 * r + 0.587 * g + 0.114 * b).astype(_np.float32)
        gx   = _ndi.sobel(lum, axis=1).astype(_np.float32)
        gy   = _ndi.sobel(lum, axis=0).astype(_np.float32)
        gmag = _np.sqrt(gx ** 2 + gy ** 2)
        if gmag.max() > 1e-9:
            gmag = gmag / gmag.max()

        # -- Gaussian-blur reference for soft/sharp operations --------------------
        blur_sigma = max(1.2, min(self.canvas.w, self.canvas.h) * 0.004)
        blur_r = _ndi.gaussian_filter(r, sigma=blur_sigma).astype(_np.float32)
        blur_g = _ndi.gaussian_filter(g, sigma=blur_sigma).astype(_np.float32)
        blur_b = _ndi.gaussian_filter(b, sigma=blur_sigma).astype(_np.float32)

        # -- Four zone percentile thresholds --------------------------------------
        flat = gmag.ravel()
        t30  = float(_np.percentile(flat, 30))
        t60  = float(_np.percentile(flat, 60))
        t85  = float(_np.percentile(flat, 85))

        # -- Zone weights (smooth transitions) ------------------------------------
        w_lost = _np.clip((t30 - gmag) / max(t30, 1e-9), 0.0, 1.0)
        w_soft = _np.clip(
            _np.minimum((gmag - t30) / max(t60 - t30, 1e-9),
                        (t60 - gmag) / max(t60 - t30, 1e-9)) * 2.0,
            0.0, 1.0
        )
        w_firm = _np.clip(
            _np.minimum((gmag - t60) / max(t85 - t60, 1e-9),
                        (t85 - gmag) / max(t85 - t60, 1e-9)) * 2.0,
            0.0, 1.0
        )
        w_hard = _np.clip((gmag - t85) / max(1.0 - t85, 1e-9), 0.0, 1.0)

        ls = float(lost_soften)
        sb = float(soft_blur)
        fs = float(firm_sharpen)
        hs = float(hard_sharpen)

        # -- Apply zone-specific processing ----------------------------------------
        # Lost: merge near-invisible boundaries.
        r = _np.clip(r - w_lost * ls * (r - blur_r), 0.0, 1.0)
        g = _np.clip(g - w_lost * ls * (g - blur_g), 0.0, 1.0)
        b = _np.clip(b - w_lost * ls * (b - blur_b), 0.0, 1.0)

        # Soft: mild Gaussian pull.
        r = _np.clip(r - w_soft * sb * (r - blur_r), 0.0, 1.0)
        g = _np.clip(g - w_soft * sb * (g - blur_g), 0.0, 1.0)
        b = _np.clip(b - w_soft * sb * (b - blur_b), 0.0, 1.0)

        # Firm: moderate unsharp-mask.
        r = _np.clip(r + w_firm * fs * (r - blur_r), 0.0, 1.0)
        g = _np.clip(g + w_firm * fs * (g - blur_g), 0.0, 1.0)
        b = _np.clip(b + w_firm * fs * (b - blur_b), 0.0, 1.0)

        # Hard: strong unsharp-mask.
        r = _np.clip(r + w_hard * hs * (r - blur_r), 0.0, 1.0)
        g = _np.clip(g + w_hard * hs * (g - blur_g), 0.0, 1.0)
        b = _np.clip(b + w_hard * hs * (b - blur_b), 0.0, 1.0)

        # -- Composite -------------------------------------------------------------
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Edge Quality Variation pass complete.")

    def schjerfbeck_sparse_portrait_pass(
        self,
        *,
        dissolution_radius:   float = 0.40,
        dissolution_strength: float = 0.70,
        flatten_sigma:        float = 3.0,
        flatten_strength:     float = 0.45,
        cool_shift:           float = 0.12,
        veil_opacity:         float = 0.08,
        opacity:              float = 0.78,
    ) -> None:
        """
        Schjerfbeck Sparse Portrait — ONE HUNDRED AND THIRTY-FOURTH distinct mode.
        Session 223: Helene Schjerfbeck (1862–1946).

        Five-stage algorithm implementing Schjerfbeck's radical late simplification:
        peripheral dissolution softens the background outward from a central anchor;
        tonal flattening compresses gradients into soft form-planes; a Nordic cool
        wash pulls the palette toward bleached chalk-white; a final thin veil
        simulates extreme paint dilution over a pale linen ground.

        Novelty vs. existing passes:
        Distinct from tuymans_pale_wash_pass (total desaturation, no radial structure),
        vallotton_hard_edge_flat_pass (image-space posterisation/sharpening, no
        dissolution), bonnard_chromatic_intimism_pass (saturation boost and warm violet
        shadows), and atmospheric_depth_pass (depth-axis haze, not radial centre/
        periphery logic).  The radial peripheral blur with a hard centre-preserve zone
        is unique to this pass — it models how Schjerfbeck's late portraits dissolve
        everything except the face into near-nothingness.

        dissolution_radius   : Normalised radius (0–1) within which the canvas is
                               preserved sharp.  0.40 centres on roughly the face
                               region for a head-cropped portrait.
        dissolution_strength : Maximum blur intensity applied at canvas extremes.
                               Higher = more complete background dissolution.
        flatten_sigma        : Gaussian sigma for tonal form-plane flattening.
                               Applied most strongly in the centre (inverse of
                               dissolution weight).
        flatten_strength     : Blend fraction toward flattened planes in the centre.
        cool_shift           : Strength of the Nordic cool bone-white tonal shift,
                               gated to mid-bright luminance zones.
        veil_opacity         : Opacity of the final thin pale veil overlay.
        opacity              : Final composite blend with original canvas.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Schjerfbeck Sparse Portrait pass (134th mode)…")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()

        # ── Radial weight map (normalised distance from canvas centre) ─────────
        cy, cx   = h / 2.0, w / 2.0
        ys       = (_np.arange(h) - cy) / max(cy, 1e-6)
        xs       = (_np.arange(w) - cx) / max(cx, 1e-6)
        YY, XX   = _np.meshgrid(ys, xs, indexing='ij')
        dist_n   = _np.sqrt(YY ** 2 + XX ** 2) / _np.sqrt(2.0)   # 0 at centre, ~1 at corners

        rr        = float(dissolution_radius)
        periph_wt = _np.clip(
            (dist_n - rr) / max(1.0 - rr, 1e-6), 0.0, 1.0
        ).astype(_np.float32) ** 1.5

        # ── Stage 1 — Peripheral Dissolution ─────────────────────────────────
        ds        = float(dissolution_strength)
        max_sigma = ds * min(h, w) * 0.03
        if max_sigma > 0.5:
            blur_sigma = max_sigma * 0.7   # single representative sigma for efficiency
            br = _ndi.gaussian_filter(r, sigma=blur_sigma).astype(_np.float32)
            bg = _ndi.gaussian_filter(g, sigma=blur_sigma).astype(_np.float32)
            bb = _ndi.gaussian_filter(b, sigma=blur_sigma).astype(_np.float32)
            blend_wt = _np.clip(periph_wt * ds, 0.0, 1.0)
            r = r * (1.0 - blend_wt) + br * blend_wt
            g = g * (1.0 - blend_wt) + bg * blend_wt
            b = b * (1.0 - blend_wt) + bb * blend_wt

        # ── Stage 2 — Tonal Flattening (form-plane simplification) ───────────
        fs = max(0.5, float(flatten_sigma))
        fr = _ndi.gaussian_filter(r, sigma=fs).astype(_np.float32)
        fg = _ndi.gaussian_filter(g, sigma=fs).astype(_np.float32)
        fb = _ndi.gaussian_filter(b, sigma=fs).astype(_np.float32)
        # Flatten more in the centre (interior of form-planes), less at edges
        centre_wt = _np.clip(1.0 - periph_wt, 0.0, 1.0)
        fw        = _np.clip(float(flatten_strength) * centre_wt, 0.0, 1.0)
        r = _np.clip(r * (1.0 - fw) + fr * fw, 0.0, 1.0)
        g = _np.clip(g * (1.0 - fw) + fg * fw, 0.0, 1.0)
        b = _np.clip(b * (1.0 - fw) + fb * fw, 0.0, 1.0)

        # ── Stage 3 — Nordic Cool Wash ────────────────────────────────────────
        lum       = 0.299 * r + 0.587 * g + 0.114 * b
        cool_gate = _np.clip((lum - 0.28) / 0.45, 0.0, 1.0)   # mid-to-bright only
        cs        = float(cool_shift)
        # Cool bone-white target — Schjerfbeck's bleached Nordic surface
        r = _np.clip(r + cool_gate * cs * (0.92 - r), 0.0, 1.0)
        g = _np.clip(g + cool_gate * cs * (0.92 - g), 0.0, 1.0)
        b = _np.clip(b + cool_gate * cs * (0.95 - b), 0.0, 1.0)

        # ── Stage 4 — Thin Veil ───────────────────────────────────────────────
        vo = float(veil_opacity)
        if vo > 0.001:
            r = _np.clip(r + vo * (0.94 - r), 0.0, 1.0)
            g = _np.clip(g + vo * (0.90 - g), 0.0, 1.0)
            b = _np.clip(b + vo * (0.84 - b), 0.0, 1.0)

        # ── Stage 5 — Composite ───────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Schjerfbeck Sparse Portrait pass complete.")

    def halation_glow_pass(
        self,
        *,
        threshold:       float = 0.75,
        bloom_sigma:     float = 0.04,
        bloom_intensity: float = 0.35,
        glow_warm_r:     float = 1.00,
        glow_warm_g:     float = 0.95,
        glow_warm_b:     float = 0.80,
        opacity:         float = 0.65,
    ) -> None:
        """
        Halation Glow — session 223 artistic improvement.

        Models optical light blooming (halation): bright highlight areas spread
        their luminosity into surrounding pixels, creating a luminous aura.  This
        replicates the optical spreading seen in Turner, the Impressionists, and
        Symbolist painters where bright light sources appear to radiate beyond
        their physical boundaries.

        Novelty vs. existing passes:
        All prior passes treat luminosity zones as fixed regions (even
        chiaroscuro_focus_pass only applies a static falloff mask).  Halation
        spreads luminosity *outward* from individual bright pixels via Gaussian
        convolution — a forward-scatter rather than a zonal remap.  The bloom is
        warm-tinted to simulate incandescence (candle, sun, electric arc).  The
        composite adds the glow only to the *surrounding* mid-tones, not back into
        the already-bright source pixels, which would blow them out.

        threshold       : Luminance threshold above which pixels seed the bloom.
                          0.70–0.80 for highlights only; 0.60 for broader glow.
        bloom_sigma     : Gaussian spread as a fraction of min(canvas w, h).
                          0.03–0.05 = tight glow; 0.08–0.12 = broad soft halo.
        bloom_intensity : Peak bloom brightness added to surrounding pixels.
                          0.20 = subtle; 0.50 = dramatic.
        glow_warm_r/g/b : RGB tint of the bloom.  Default warm amber-gold
                          (1.0, 0.95, 0.80) simulates incandescent light.
        opacity         : Final composite blend.  0.50–0.70 is naturalistic.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Halation Glow pass (session 223 improvement)…")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # ── Build highlight seed mask ──────────────────────────────────────────
        thr  = float(threshold)
        seed = _np.clip((lum - thr) / max(1.0 - thr, 1e-6), 0.0, 1.0)

        # ── Gaussian spread of the bloom (forward scatter) ─────────────────────
        sigma_px = float(bloom_sigma) * min(h, w)
        sigma_px = max(1.0, sigma_px)
        bloom    = _ndi.gaussian_filter(seed, sigma=sigma_px).astype(_np.float32)
        # Normalise so peak bloom equals bloom_intensity
        bmax = bloom.max()
        if bmax > 1e-9:
            bloom = bloom / bmax * float(bloom_intensity)

        # ── Warm tint the bloom ────────────────────────────────────────────────
        bloom_r = bloom * float(glow_warm_r)
        bloom_g = bloom * float(glow_warm_g)
        bloom_b = bloom * float(glow_warm_b)

        # ── Apply to surrounding mid-tones (gate out the bright source itself) ─
        mid_gate = _np.clip(1.0 - seed * 2.0, 0.0, 1.0)

        r_glow = _np.clip(r0 + bloom_r * mid_gate, 0.0, 1.0)
        g_glow = _np.clip(g0 + bloom_g * mid_gate, 0.0, 1.0)
        b_glow = _np.clip(b0 + bloom_b * mid_gate, 0.0, 1.0)

        # ── Composite ─────────────────────────────────────────────────────────
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r_glow * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g_glow * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b_glow * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_seeds = int((seed > 0.01).sum())
        print(f"    Halation Glow pass complete  (bloom_sigma={sigma_px:.1f}px  "
              f"seeds={n_seeds}px  intensity={bloom_intensity:.2f})")

    def serov_sunlit_portrait_pass(
        self,
        *,
        warm_shift:         float = 0.22,
        cool_shift:         float = 0.18,
        highlight_thresh:   float = 0.65,
        shadow_thresh:      float = 0.40,
        luminosity_lift:    float = 0.06,
        vibration_strength: float = 0.04,
        opacity:            float = 0.80,
    ) -> None:
        """
        Serov Sunlit Portrait -- ONE HUNDRED AND THIRTY-FIFTH distinct mode.
        Session 224: Valentin Serov (1865-1911).

        Five-stage algorithm implementing Serov's plein-air warm-cool observation:
        warm sunlight tints highlights toward peach-amber; reflected sky cools shadow
        passages toward blue-violet; a luminosity lift brightens the whole surface to
        outdoor levels; and chromatic mid-tone vibration introduces the optical
        freshness of Russian Impressionism.

        Novelty vs. existing passes:
        Unlike schjerfbeck_sparse_portrait_pass (uniform Nordic cool wash, radial
        peripheral dissolution), bonnard_chromatic_intimism_pass (global saturation
        boost with violet shadows), and halation_glow_pass (highlight bloom spread),
        this pass applies opposite warm/cool temperature shifts to different luminance
        zones simultaneously -- warm to highlights, cool to shadows -- which no existing
        pass combines.  The luminosity_lift simulates plein-air ambient brightness
        absent from all studio-based modes.

        warm_shift          : Warm peach-amber blend strength in highlight zones.
        cool_shift          : Cool blue-violet blend strength in shadow zones.
        highlight_thresh    : Luminance above which highlights are warmed.
        shadow_thresh       : Luminance below which shadows are cooled.
        luminosity_lift     : Additive brightness increase across the whole canvas.
        vibration_strength  : Chromatic noise amplitude in mid-tone zone.
        opacity             : Final composite blend with original canvas.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Serov Sunlit Portrait pass (135th mode)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()
        lum = 0.299 * r + 0.587 * g + 0.114 * b

        ht = float(highlight_thresh)
        st = float(shadow_thresh)

        # Stage 1: Warm Highlight Shift -- direct sunlight on flesh: peach-amber (0.96, 0.82, 0.64)
        hi_gate = _np.clip((lum - ht) / max(1.0 - ht, 1e-6), 0.0, 1.0)
        ws      = float(warm_shift)
        r = _np.clip(r + hi_gate * ws * (0.96 - r), 0.0, 1.0)
        g = _np.clip(g + hi_gate * ws * (0.82 - g), 0.0, 1.0)
        b = _np.clip(b + hi_gate * ws * (0.64 - b), 0.0, 1.0)

        # Stage 2: Cool Shadow Shift -- reflected sky in shadow: blue-violet (0.55, 0.55, 0.78)
        sh_gate = _np.clip((st - lum) / max(st, 1e-6), 0.0, 1.0)
        cs      = float(cool_shift)
        r = _np.clip(r + sh_gate * cs * (0.55 - r), 0.0, 1.0)
        g = _np.clip(g + sh_gate * cs * (0.55 - g), 0.0, 1.0)
        b = _np.clip(b + sh_gate * cs * (0.78 - b), 0.0, 1.0)

        # Stage 3: Plein-Air Luminosity Lift
        ll = float(luminosity_lift)
        if ll > 0.001:
            r = _np.clip(r + ll, 0.0, 1.0)
            g = _np.clip(g + ll, 0.0, 1.0)
            b = _np.clip(b + ll, 0.0, 1.0)

        # Stage 4: Chromatic Mid-Tone Vibration
        vib = float(vibration_strength)
        if vib > 0.001:
            band     = max(ht - st, 1e-6)
            mid_gate = _np.clip(
                _np.minimum((lum - st) / band, (ht - lum) / band) * 2.0,
                0.0, 1.0,
            )
            rng     = _np.random.RandomState(224)
            noise_r = _ndi.gaussian_filter(rng.randn(h, w).astype(_np.float32), sigma=0.8)
            noise_g = _ndi.gaussian_filter(rng.randn(h, w).astype(_np.float32), sigma=0.8)
            noise_b = _ndi.gaussian_filter(rng.randn(h, w).astype(_np.float32), sigma=0.8)
            r = _np.clip(r + mid_gate * vib * noise_r, 0.0, 1.0)
            g = _np.clip(g + mid_gate * vib * noise_g, 0.0, 1.0)
            b = _np.clip(b + mid_gate * vib * noise_b, 0.0, 1.0)

        # Stage 5: Composite
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Serov Sunlit Portrait pass complete.")

    def color_temperature_oscillation_pass(
        self,
        *,
        warm_highlight_r: float = 1.00,
        warm_highlight_g: float = 0.96,
        warm_highlight_b: float = 0.82,
        cool_midtone_r:   float = 0.82,
        cool_midtone_g:   float = 0.90,
        cool_midtone_b:   float = 1.00,
        warm_shadow_r:    float = 0.45,
        warm_shadow_g:    float = 0.28,
        warm_shadow_b:    float = 0.12,
        highlight_gate:   float = 0.72,
        shadow_gate:      float = 0.35,
        strength:         float = 0.18,
        opacity:          float = 0.75,
    ) -> None:
        """
        Color Temperature Oscillation -- session 224 artistic improvement.

        Models the warm/cool oscillation used by Sorolla, Sargent, Zorn, and Serov:
        highlights shift warm (golden-amber-white), light-to-shadow transitions cool
        (blue-green), and shadow depths warm again (umber-brown).  Creates the
        vibrating chromatic quality of great oil painting.

        Novelty vs. existing passes:
        Prior passes apply single-direction tonal colour shifts: bonnard applies global
        saturation boost; schjerfbeck applies a uniform Nordic cool wash; glazing applies
        a uniform warm tint.  This pass applies opposite temperature shifts at different
        luminance zones simultaneously -- warm at both extremes (highlights and shadows),
        cool in the midtone transition -- creating an oscillation unreachable by any
        single-zone pass.

        warm_highlight_r/g/b : Warm target colour for the brightest highlight pixels.
        cool_midtone_r/g/b   : Cool target colour for the mid-tone transition zone.
        warm_shadow_r/g/b    : Warm umber target for the deepest shadow pixels.
        highlight_gate       : Luminance above which highlight warming begins.
        shadow_gate          : Luminance below which shadow warming begins.
        strength             : Scale factor on all oscillation blend weights.
        opacity              : Final composite opacity.
        """
        import numpy as _np

        print("    Color Temperature Oscillation pass (session 224 improvement)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()
        lum = 0.299 * r + 0.587 * g + 0.114 * b

        sg  = float(shadow_gate)
        hg  = float(highlight_gate)
        mid = (sg + hg) * 0.5
        st  = float(strength)

        shadow_w = _np.clip((sg - lum) / max(sg, 1e-6), 0.0, 1.0) ** 1.5
        hi_w     = _np.clip((lum - hg) / max(1.0 - hg, 1e-6), 0.0, 1.0) ** 1.5
        mid_band = max(mid - sg, 1e-6)
        mid_w    = _np.clip(
            1.0 - _np.abs(lum - mid) / mid_band, 0.0, 1.0
        ) * _np.clip(1.0 - shadow_w - hi_w, 0.0, 1.0)

        hw = _np.clip(hi_w * st, 0.0, 1.0)
        r  = r + hw * (float(warm_highlight_r) - r)
        g  = g + hw * (float(warm_highlight_g) - g)
        b  = b + hw * (float(warm_highlight_b) - b)

        mw = _np.clip(mid_w * st, 0.0, 1.0)
        r  = r + mw * (float(cool_midtone_r) - r)
        g  = g + mw * (float(cool_midtone_g) - g)
        b  = b + mw * (float(cool_midtone_b) - b)

        sw = _np.clip(shadow_w * st, 0.0, 1.0)
        r  = r + sw * (float(warm_shadow_r) - r)
        g  = g + sw * (float(warm_shadow_g) - g)
        b  = b + sw * (float(warm_shadow_b) - b)

        r = _np.clip(r, 0.0, 1.0)
        g = _np.clip(g, 0.0, 1.0)
        b = _np.clip(b, 0.0, 1.0)

        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Color Temperature Oscillation pass complete.")

    def segantini_stitch_weave_pass(
        self,
        *,
        stitch_density:  float = 12.0,
        weave_strength:  float = 0.14,
        warm_target_r:   float = 0.84,
        warm_target_g:   float = 0.70,
        warm_target_b:   float = 0.32,
        cool_target_r:   float = 0.52,
        cool_target_g:   float = 0.72,
        cool_target_b:   float = 0.90,
        saturation_boost: float = 0.10,
        opacity:         float = 0.78,
    ) -> None:
        """
        Segantini Stitch Weave -- ONE HUNDRED AND THIRTY-SIXTH distinct mode.
        Session 225: Giovanni Segantini (1858-1899).

        Five-stage algorithm implementing Segantini's 'pennellate a virgola' (comma-stroke)
        Divisionist technique: the local gradient direction of the luminance field is
        computed; a sinusoidal stitch mask oscillates perpendicular to the local contour;
        warm and cool oscillations simulate the alternating discrete strokes on a white
        ground; a saturation lift replicates high-altitude alpine UV-rich chroma.

        Novelty vs. existing passes:
        All prior warm/cool oscillation passes (serov_sunlit_portrait_pass,
        color_temperature_oscillation_pass) operate on global luminance zones (highlights,
        shadows, mid-tones) regardless of local form direction.  This pass derives the
        oscillation *axis* from the local image gradient -- stripes run perpendicular to
        the local contour, following the form the way Segantini's actual brushstrokes did.
        The sinusoidal stitch pattern creates visible discrete marks at the pixel scale,
        something no prior pass produces.  The saturation_boost is also unique to this
        pass: prior luminosity lifts (serov, halation) modify value/brightness, not chroma
        independently.

        stitch_density   : Number of stitch cycles per 100 pixels of canvas.
                           8 = coarse weave; 12 = standard; 20 = fine hatching.
        weave_strength   : Amplitude of warm/cool colour blend at stitch peaks/troughs.
                           0.08 = subtle; 0.14 = standard; 0.25 = dramatic.
        warm_target_r/g/b: Warm pole colour (default: golden ochre).
        cool_target_r/g/b: Cool pole colour (default: alpine sky blue).
        saturation_boost : Fractional saturation increase (0.10 = 10% more vivid).
        opacity          : Final composite blend with original canvas.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Segantini Stitch Weave pass (136th mode)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()
        lum = 0.299 * r + 0.587 * g + 0.114 * b

        # Stage 1: Gradient direction via Sobel; fall back to diagonal on flat regions
        kx = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        ky = _np.array([[-1, -2, -1], [0, 0, 0], [1, 2, 1]], dtype=_np.float32)
        grad_x = _ndi.convolve(lum, kx)
        grad_y = _ndi.convolve(lum, ky)
        # Perpendicular direction (rotate 90 degrees)
        perp_cos = -grad_y
        perp_sin =  grad_x
        raw_mag = _np.sqrt(perp_cos ** 2 + perp_sin ** 2)
        # In flat/uniform regions the gradient is near-zero; fall back to 45-degree stitch
        flat = raw_mag < 0.01
        perp_cos = _np.where(flat,  0.7071068, perp_cos)
        perp_sin = _np.where(flat,  0.7071068, perp_sin)
        raw_mag  = _np.where(flat,  1.0,       raw_mag)
        perp_cos = perp_cos / (raw_mag + 1e-9)
        perp_sin = perp_sin / (raw_mag + 1e-9)

        # Stage 2: Stitch mask — sinusoidal oscillation perpendicular to gradient
        ys_idx = _np.arange(h, dtype=_np.float32)[:, None] * _np.ones((1, w), dtype=_np.float32)
        xs_idx = _np.ones((h, 1), dtype=_np.float32) * _np.arange(w, dtype=_np.float32)[None, :]
        density = float(stitch_density)
        phase   = (xs_idx * perp_cos + ys_idx * perp_sin) * (density / 100.0)
        stitch  = _np.sin(phase * 2.0 * _np.pi).astype(_np.float32)  # -1..+1

        # Stage 3: Warm/cool oscillation at stitch peaks and troughs
        pos_mask = _np.clip( stitch, 0.0, 1.0)
        neg_mask = _np.clip(-stitch, 0.0, 1.0)
        ws = float(weave_strength)
        wr = float(warm_target_r)
        wg = float(warm_target_g)
        wb = float(warm_target_b)
        cr = float(cool_target_r)
        cg = float(cool_target_g)
        cb = float(cool_target_b)
        r  = _np.clip(r + pos_mask * ws * (wr - r) + neg_mask * ws * (cr - r), 0.0, 1.0)
        g  = _np.clip(g + pos_mask * ws * (wg - g) + neg_mask * ws * (cg - g), 0.0, 1.0)
        b  = _np.clip(b + pos_mask * ws * (wb - b) + neg_mask * ws * (cb - b), 0.0, 1.0)

        # Stage 4: Alpine saturation boost — scale each channel's deviation from luma
        sb = float(saturation_boost)
        if sb > 0.001:
            lum2 = 0.299 * r + 0.587 * g + 0.114 * b
            r  = _np.clip(lum2 + (r - lum2) * (1.0 + sb), 0.0, 1.0)
            g  = _np.clip(lum2 + (g - lum2) * (1.0 + sb), 0.0, 1.0)
            b  = _np.clip(lum2 + (b - lum2) * (1.0 + sb), 0.0, 1.0)

        # Stage 5: Composite
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print("    Segantini Stitch Weave pass complete.")

    def alpine_luminance_intensification_pass(
        self,
        *,
        shadow_violet_r: float = 0.62,
        shadow_violet_g: float = 0.52,
        shadow_violet_b: float = 0.88,
        shadow_thresh:   float = 0.32,
        highlight_boost: float = 0.07,
        highlight_thresh: float = 0.75,
        chroma_scale:    float = 1.18,
        opacity:         float = 0.72,
    ) -> None:
        """
        Alpine Luminance Intensification -- session 225 artistic improvement.

        Models the optical properties of high-altitude alpine light that Segantini
        pioneered: (1) snow and deep shadows shift toward vivid violet-blue (the cold
        sky dome reflects intensely with no atmospheric buffer); (2) highlights push
        toward pure overexposed white (UV-rich irradiation saturates local colour);
        (3) overall chroma is elevated via a non-uniform saturation scale (thin air
        passes full-spectrum light, making all colours more vivid).

        Novelty vs. existing passes:
        Unlike serov_sunlit_portrait_pass which applies warm/cool zonal shifts to model
        plein-air light, and unlike halation_glow_pass which models optical bloom from
        bright sources, this pass models the *atmospheric physics of altitude*: the
        shadow-to-violet shift uses a steeper transfer curve than any prior pass; the
        highlight boost targets only the uppermost luminance range (above
        highlight_thresh) rather than the full highlight zone; and the chroma_scale
        applies a multiplicative saturation increase across the entire canvas -- the
        first global chroma scale in the pipeline distinct from Bonnard's additive
        saturation boost approach.

        shadow_violet_r/g/b : Target violet-blue colour for deepest shadow passages.
        shadow_thresh       : Luminance below which shadow violeting begins.
        highlight_boost     : Additive brightness push for near-white highlights.
        highlight_thresh    : Luminance above which highlight boost applies.
        chroma_scale        : Multiplicative saturation factor (1.0 = no change).
        opacity             : Final composite opacity.
        """
        import numpy as _np

        print("    Alpine Luminance Intensification pass (session 225 improvement)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()
        lum = 0.299 * r + 0.587 * g + 0.114 * b

        # Stage 1: Shadow violet shift (sky-reflected blue in unlit snow and shadow)
        st  = float(shadow_thresh)
        svr = float(shadow_violet_r)
        svg = float(shadow_violet_g)
        svb = float(shadow_violet_b)
        sh_gate = _np.clip((st - lum) / max(st, 1e-6), 0.0, 1.0) ** 1.8
        r = _np.clip(r + sh_gate * (svr - r), 0.0, 1.0)
        g = _np.clip(g + sh_gate * (svg - g), 0.0, 1.0)
        b = _np.clip(b + sh_gate * (svb - b), 0.0, 1.0)

        # Stage 2: Highlight push toward pure white (UV overexposure on snow)
        ht  = float(highlight_thresh)
        hb  = float(highlight_boost)
        hi_gate = _np.clip((lum - ht) / max(1.0 - ht, 1e-6), 0.0, 1.0)
        if hb > 0.001:
            r = _np.clip(r + hi_gate * hb, 0.0, 1.0)
            g = _np.clip(g + hi_gate * hb, 0.0, 1.0)
            b = _np.clip(b + hi_gate * hb, 0.0, 1.0)

        # Stage 3: Global chroma scale (thin alpine air — multiplicative saturation)
        cs = float(chroma_scale)
        if cs > 1.001:
            c_max = _np.maximum(_np.maximum(r, g), b)
            r  = _np.clip(c_max + (r - c_max) * cs, 0.0, 1.0)
            g  = _np.clip(c_max + (g - c_max) * cs, 0.0, 1.0)
            b  = _np.clip(c_max + (b - c_max) * cs, 0.0, 1.0)

        # Stage 4: Composite
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_shadow = int((lum < st).sum())
        n_hi     = int((lum > ht).sum())
        print(f"    Alpine Luminance Intensification pass complete  "
              f"(shadow_px={n_shadow}  highlight_px={n_hi}  chroma_scale={cs:.2f})")

    def sorolla_mediterranean_light_pass(
        self,
        *,
        bleach_thresh:      float = 0.82,
        bleach_strength:    float = 0.55,
        azure_shadow_r:     float = 0.28,
        azure_shadow_g:     float = 0.58,
        azure_shadow_b:     float = 0.86,
        shadow_thresh:      float = 0.38,
        scatter_density:    float = 0.004,
        scatter_brightness: float = 0.55,
        warm_boost:         float = 0.08,
        opacity:            float = 0.80,
        seed:               int   = 226,
    ) -> None:
        """
        Sorolla Mediterranean Light -- ONE HUNDRED AND THIRTY-SEVENTH distinct mode.
        Session 226: Joaquín Sorolla (1863–1923).

        Five-stage algorithm implementing Sorolla's luminous Mediterranean technique.

        Novelty vs. existing passes:
        alpine_luminance_intensification_pass models altitude physics (UV chroma scale,
        cold violet from sky dome).  This pass models Mediterranean surface optics:
        (1) extreme specular bleaching toward pure white (steeper than alpine's additive
        highlight push, using a 0.6-power gate); (2) transparent azure shadow shift warmer
        and less purple than alpine violet — Mediterranean sea/sky reflected hue;
        (3) stochastic scatter of specular micro-highlights — no existing pass applies
        Bernoulli-mask scatter, this is the first; (4) warm-zone mid-tone saturation boost
        confined to a bell gate around lum=0.62 (distinct from Bonnard's global additive
        boost and alpine's multiplicative global scale).

        bleach_thresh      : Luminance above which highlight bleaching begins.
        bleach_strength    : Push-toward-white amplitude. 0.30=subtle, 0.55=standard, 0.80=extreme.
        azure_shadow_r/g/b : Mediterranean azure reflection colour for shadow passages.
        shadow_thresh      : Luminance below which azure shadow shift begins.
        scatter_density    : Fraction of pixels receiving stochastic specular scatter [0, 0.02].
        scatter_brightness : Additive brightness of each scatter flash [0, 1].
        warm_boost         : Warm saturation scale boost in sun-lit mid-tone zone [0, 0.30].
        opacity            : Final composite opacity.
        seed               : RNG seed for reproducible specular scatter.
        """
        import numpy as _np

        print("    Sorolla Mediterranean Light pass (137th mode)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()
        lum = 0.299 * r + 0.587 * g + 0.114 * b

        # Stage 1: Highlight bleaching — specular overexposure on white fabric/foam
        bt  = float(bleach_thresh)
        bs  = float(bleach_strength)
        hi_gate = _np.clip((lum - bt) / max(1.0 - bt, 1e-6), 0.0, 1.0) ** 0.6
        r = _np.clip(r + hi_gate * bs * (1.0 - r), 0.0, 1.0)
        g = _np.clip(g + hi_gate * bs * (1.0 - g), 0.0, 1.0)
        b = _np.clip(b + hi_gate * bs * (1.0 - b), 0.0, 1.0)

        # Stage 2: Azure shadow shift — Mediterranean sea/sky reflected into shadow passages
        st  = float(shadow_thresh)
        asr = float(azure_shadow_r)
        asg = float(azure_shadow_g)
        asb = float(azure_shadow_b)
        sh_gate = _np.clip((st - lum) / max(st, 1e-6), 0.0, 1.0) ** 0.8
        r = _np.clip(r + sh_gate * (asr - r), 0.0, 1.0)
        g = _np.clip(g + sh_gate * (asg - g), 0.0, 1.0)
        b = _np.clip(b + sh_gate * (asb - b), 0.0, 1.0)

        # Stage 3: Stochastic specular scatter — sun micro-reflections on wet surfaces
        rng  = _np.random.RandomState(int(seed))
        mask = rng.random_sample((h, w)).astype(_np.float32) < float(scatter_density)
        if mask.any():
            flash = rng.uniform(0.6, 1.0, (h, w)).astype(_np.float32)
            sb2   = float(scatter_brightness)
            r = _np.clip(r + mask * flash * sb2, 0.0, 1.0)
            g = _np.clip(g + mask * flash * sb2, 0.0, 1.0)
            b = _np.clip(b + mask * flash * sb2, 0.0, 1.0)

        # Stage 4: Warm mid-tone saturation boost (bell gate around lum=0.62)
        wb = float(warm_boost)
        if wb > 0.001:
            mid_gate = _np.clip(1.0 - _np.abs(lum - 0.62) / 0.24, 0.0, 1.0)
            lum3 = 0.299 * r + 0.587 * g + 0.114 * b
            scale = 1.0 + wb * mid_gate
            r  = _np.clip(lum3 + (r - lum3) * scale, 0.0, 1.0)
            g  = _np.clip(lum3 + (g - lum3) * scale, 0.0, 1.0)
            b  = _np.clip(lum3 + (b - lum3) * scale, 0.0, 1.0)

        # Stage 5: Composite
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_bleached = int((lum > bt).sum())
        n_shadowed = int((lum < st).sum())
        n_scatter  = int(mask.sum())
        print(f"    Sorolla Mediterranean Light pass complete  "
              f"(bleached_px={n_bleached}  shadow_px={n_shadowed}  scatter_px={n_scatter})")

    def diffuse_boundary_pass(
        self,
        *,
        low_grad:  float = 0.04,
        high_grad: float = 0.22,
        sigma:     float = 1.2,
        strength:  float = 0.55,
        opacity:   float = 0.65,
    ) -> None:
        """
        Diffuse Boundary -- session 226 artistic improvement.

        Models wet-into-wet paint diffusion at colour zone boundaries: adjacent
        passages of freshly-laid oil or watercolour bleed into each other at their
        shared edges, producing natural soft gradients between colour masses while
        leaving hard-edged details and flat interior zones intact.

        Novelty vs. existing passes:
        sfumato_pass applies a global Gaussian blur, softening the entire canvas
        uniformly.  edge_quality_variation_pass varies edge sharpness based on a
        focal-distance mask.  This pass operates differently: it computes local
        gradient magnitude, identifies moderate-gradient boundary zones (low_grad <
        mag < high_grad), applies a controlled isotropic blur only in those zones,
        and uses a linear gate to weight the blend.  Hard edges (mag >= high_grad)
        and flat interiors (mag <= low_grad) receive no diffusion — only the
        intermediate colour-zone boundaries are softened, simulating physical
        wet-paint interpenetration without destroying the structure.

        low_grad  : Gradient magnitude below which no diffusion is applied (flat interior).
        high_grad : Gradient magnitude above which no diffusion is applied (hard edge).
        sigma     : Gaussian blur radius applied to the boundary zone [pixels].
        strength  : Blend factor between original and blurred pixels in boundary zone [0, 1].
        opacity   : Final composite opacity.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Diffuse Boundary pass (session 226 improvement)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # Compute gradient magnitude via Sobel
        kx = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        ky = _np.array([[-1, -2, -1], [0, 0, 0], [1, 2, 1]], dtype=_np.float32)
        gx = _ndi.convolve(lum, kx)
        gy = _ndi.convolve(lum, ky)
        mag = _np.sqrt(gx * gx + gy * gy)

        # Gate: 1.0 in moderate-gradient boundary zones, 0 outside
        lo = float(low_grad)
        hi = float(high_grad)
        gate = _np.clip((mag - lo) / max(hi - lo, 1e-6), 0.0, 1.0) * \
               _np.clip((hi - mag) / max(hi - lo, 1e-6), 0.0, 1.0) * 4.0
        gate = _np.clip(gate, 0.0, 1.0)

        # Gaussian blur of each channel
        sig = float(sigma)
        r_blur = _ndi.gaussian_filter(r0, sigma=sig).astype(_np.float32)
        g_blur = _ndi.gaussian_filter(g0, sigma=sig).astype(_np.float32)
        b_blur = _ndi.gaussian_filter(b0, sigma=sig).astype(_np.float32)

        # Blend blurred into original at gate * strength
        st = float(strength)
        blend = gate * st
        r_mid = _np.clip(r0 * (1.0 - blend) + r_blur * blend, 0.0, 1.0)
        g_mid = _np.clip(g0 * (1.0 - blend) + g_blur * blend, 0.0, 1.0)
        b_mid = _np.clip(b0 * (1.0 - blend) + b_blur * blend, 0.0, 1.0)

        # Composite
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r_mid * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g_mid * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b_mid * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_boundary = int((gate > 0.1).sum())
        print(f"    Diffuse Boundary pass complete  (boundary_px={n_boundary}  sigma={sig:.1f})")

    def vermeer_pearl_light_pass(
        self,
        *,
        light_x:         float = 0.20,
        light_y:         float = 0.12,
        light_reach:     float = 0.55,
        warm_strength:   float = 0.10,
        cool_strength:   float = 0.10,
        light_thresh:    float = 0.60,
        shadow_thresh:   float = 0.38,
        pearl_thresh:    float = 0.72,
        pearl_density:   float = 0.006,
        pearl_radius:    float = 1.4,
        pearl_r:         float = 0.97,
        pearl_g:         float = 0.95,
        pearl_b:         float = 0.88,
        shadow_sigma:    float = 1.0,
        shadow_blur_str: float = 0.35,
        opacity:         float = 0.75,
        seed:            int   = 227,
    ) -> None:
        """
        Vermeer Pearl Light -- ONE HUNDRED AND THIRTY-EIGHTH distinct mode.
        Session 227: Johannes Vermeer (1632–1675).

        Four-stage algorithm implementing Vermeer's singular optical vocabulary.

        Novelty vs. existing passes:
        sorolla_mediterranean_light_pass models outdoor specular bleaching and azure sea
        reflections.  This pass models interior north-window light: (1) a radial gradient
        from a single window source brightening the light side of the canvas while cooling
        the shadow side — no existing pass applies a spatial window-position gradient;
        (2) a warm/cool temperature split gated separately on luminance (warm = R push in
        highlights, cool = B push in shadows) — distinct from color_temperature_oscillation_pass
        which cycles periodically across the canvas; (3) "Vermeer pearls" — cream-tinted
        pointillé dots placed stochastically only on pixels that are BOTH above the
        luminance pearl threshold AND on gradient edges (high gradient magnitude), modelling
        the specular sparkle on pearls, satin, and glazed pottery that appears in Vermeer's
        foreground objects; (4) shadow-zone Gaussian softening with luminance gate —
        diffuse_boundary_pass gates on gradient magnitude; this gate on luminance value,
        which softens only the dark shadow recession while leaving lit passages crisp,
        reproducing the peripheral softness associated with Vermeer's use of a camera obscura.

        light_x/light_y   : Normalised [0, 1] canvas position of the window light source.
        light_reach        : Radial falloff distance (fraction of canvas diagonal) [0.2, 1.0].
        warm_strength      : Warm push amplitude in lit passages (R+, B−).
        cool_strength      : Cool push amplitude in shadow passages (B+, R−).
        light_thresh       : Luminance gate above which warm temperature shift is applied.
        shadow_thresh      : Luminance gate below which cool shadow shift is applied.
        pearl_thresh       : Minimum luminance for a pixel to receive pearl sparkle.
        pearl_density      : Fraction of qualifying pixels receiving a pearl [0, 0.02].
        pearl_radius       : Gaussian spread of each pearl dot in pixels [0.5, 3.0].
        pearl_r/g/b        : Pearl colour (warm cream-white by default).
        shadow_sigma       : Gaussian blur radius for shadow softening [0.5, 2.5].
        shadow_blur_str    : Blend weight of blurred image in shadow zone [0, 0.6].
        opacity            : Final composite opacity.
        seed               : RNG seed for reproducible pearl placement.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Vermeer Pearl Light pass (138th mode)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        r, g, b = r0.copy(), g0.copy(), b0.copy()
        lum = 0.299 * r + 0.587 * g + 0.114 * b

        # Stage 1: Window light radial gradient — brighten pixels near the light source,
        # deepen pixels far from it.  Models the fall-off of a single north-facing window.
        ys = (_np.arange(h, dtype=_np.float32) / max(h - 1, 1)).reshape(h, 1)
        xs = (_np.arange(w, dtype=_np.float32) / max(w - 1, 1)).reshape(1, w)
        diag = (h * h + w * w) ** 0.5
        dx   = xs - float(light_x)
        dy   = ys - float(light_y)
        dist = _np.sqrt(dx * dx + dy * dy + 1e-9) * max(h, w) / diag
        reach = float(light_reach)
        # Proximity: 1.0 at window, 0.0 at reach distance
        prox = _np.clip(1.0 - dist / reach, 0.0, 1.0).astype(_np.float32)
        # Subtle luminance boost near light, subtle darkening far away
        lift = prox * 0.08
        r = _np.clip(r + lift, 0.0, 1.0)
        g = _np.clip(g + lift, 0.0, 1.0)
        b = _np.clip(b + lift, 0.0, 1.0)
        # Recompute luminance after lift
        lum = 0.299 * r + 0.587 * g + 0.114 * b

        # Stage 2: Warm-light / cool-shadow temperature split
        lt  = float(light_thresh)
        st  = float(shadow_thresh)
        ws  = float(warm_strength)
        cs  = float(cool_strength)

        # Warm gate: smooth ramp above light_thresh
        warm_gate = _np.clip((lum - lt) / max(1.0 - lt, 1e-6), 0.0, 1.0)
        r = _np.clip(r + warm_gate * ws,        0.0, 1.0)
        b = _np.clip(b - warm_gate * ws * 0.60, 0.0, 1.0)

        # Cool gate: smooth ramp below shadow_thresh
        cool_gate = _np.clip((st - lum) / max(st, 1e-6), 0.0, 1.0)
        b = _np.clip(b + cool_gate * cs,        0.0, 1.0)
        r = _np.clip(r - cool_gate * cs * 0.50, 0.0, 1.0)

        # Stage 3: Vermeer pearl sparkle — pointillé cream dots on specular edge highlights.
        # Gate: pixel must be above pearl_thresh AND on a gradient edge.
        kx = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        ky = kx.T
        gx  = _ndi.convolve(lum, kx)
        gy  = _ndi.convolve(lum, ky)
        gmag = _np.sqrt(gx * gx + gy * gy)
        # Qualify: bright AND on a local edge (gradient not flat)
        pt   = float(pearl_thresh)
        qual = (lum > pt) & (gmag > 0.02)
        rng  = _np.random.RandomState(int(seed))
        rand = rng.random_sample((h, w)).astype(_np.float32)
        pearl_mask = qual & (rand < float(pearl_density))
        if pearl_mask.any():
            # Grow each pearl dot with a Gaussian envelope
            pr = float(pearl_radius)
            pk = _ndi.gaussian_filter(
                pearl_mask.astype(_np.float32), sigma=pr)
            pk = _np.clip(pk / max(pk.max(), 1e-6), 0.0, 1.0)
            pr_col, pg_col, pb_col = float(pearl_r), float(pearl_g), float(pearl_b)
            r = _np.clip(r + pk * (pr_col - r), 0.0, 1.0)
            g = _np.clip(g + pk * (pg_col - g), 0.0, 1.0)
            b = _np.clip(b + pk * (pb_col - b), 0.0, 1.0)

        # Stage 4: Shadow-zone softening — camera-obscura peripheral diffusion.
        # Blur only shadow pixels; crisp lit areas remain sharp.
        sig  = float(shadow_sigma)
        sbs  = float(shadow_blur_str)
        if sbs > 0.001:
            # Shadow gate: 1.0 in deep shadow, fades to 0 at shadow_thresh + 0.12
            sh_gate = _np.clip(
                (st + 0.12 - lum) / max(st + 0.12, 1e-6), 0.0, 1.0)
            r_blur = _ndi.gaussian_filter(r, sigma=sig).astype(_np.float32)
            g_blur = _ndi.gaussian_filter(g, sigma=sig).astype(_np.float32)
            b_blur = _ndi.gaussian_filter(b, sigma=sig).astype(_np.float32)
            blend  = sh_gate * sbs
            r = _np.clip(r * (1.0 - blend) + r_blur * blend, 0.0, 1.0)
            g = _np.clip(g * (1.0 - blend) + g_blur * blend, 0.0, 1.0)
            b = _np.clip(b * (1.0 - blend) + b_blur * blend, 0.0, 1.0)

        # Stage 5: Composite with opacity
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_pearls = int(pearl_mask.sum()) if pearl_mask.any() else 0
        n_lit    = int((lum > lt).sum())
        n_shadow = int((lum < st).sum())
        print(f"    Vermeer Pearl Light pass complete  "
              f"(pearls={n_pearls}  lit_px={n_lit}  shadow_px={n_shadow})")

    def boccioni_futurist_motion_pass(
        self,
        *,
        contour_thresh: float = 0.035,
        force_strength: float = 0.28,
        smear_distance: int   = 6,
        sat_boost:      float = 0.22,
        velocity_blur:  float = 1.8,
        opacity:        float = 0.78,
    ) -> None:
        """
        Boccioni Futurist Motion -- ONE HUNDRED AND THIRTY-NINTH distinct mode.
        Session 228: Umberto Boccioni (1882–1916).

        Four-stage algorithm implementing Boccioni's Futurist force-line technique.

        Novelty vs. existing passes:
        chromatic_zoning_pass splits channels by hue zone globally.
        boldini_belle_epoque_swirl_pass uses rotational distortion.
        This pass operates differently: (a) per-pixel directional sampling via
        map_coordinates — first pass using a geometric warp based on the local
        gradient vector rather than global blur or tonal shift; (b) complementary
        warm-forward / cool-back channel split aligned to each pixel's own force
        direction; (c) combined force-line fringe + saturation burst + velocity
        blur trail in a single physically-motivated Futurist force-field model.

        contour_thresh : Gradient magnitude threshold for force-line activation.
        force_strength : Chromatic fringe blend amplitude in motion zones [0, 1].
        smear_distance : Pixel displacement for forward/back channel shift.
        sat_boost      : Saturation scale boost in high-gradient zones [0, 0.50].
        velocity_blur  : Sigma for soft velocity-blur overlay on luma [pixels].
        opacity        : Final composite opacity.
        """
        import numpy as _np
        from scipy import ndimage as _ndi

        print("    Boccioni Futurist Motion pass (139th mode)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        lum = 0.299 * r0 + 0.587 * g0 + 0.114 * b0

        # Stage 1: Gradient field — magnitude M, unit direction (ux, uy)
        kx  = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        ky  = kx.T
        gx  = _ndi.convolve(lum, kx)
        gy  = _ndi.convolve(lum, ky)
        mag = _np.sqrt(gx * gx + gy * gy + 1e-12).astype(_np.float32)
        ux  = (gx / mag).astype(_np.float32)
        uy  = (gy / mag).astype(_np.float32)

        ct = float(contour_thresh)
        # Force gate: smooth ramp above contour_thresh, shaped with 0.7 power curve
        force_gate = _np.clip((mag - ct) / max(0.18, 1e-6), 0.0, 1.0) ** 0.7

        # Stage 2: Directional chromatic fringe via per-pixel map_coordinates shift
        # R channel shifts in +gradient direction (warm leading edge)
        # B channel shifts in -gradient direction (cool trailing edge)
        sd = float(smear_distance)
        ys = _np.arange(h, dtype=_np.float32)[:, None].repeat(w, axis=1)
        xs = _np.arange(w, dtype=_np.float32)[None, :].repeat(h, axis=0)

        fs = float(force_strength)
        # Shift magnitude per pixel: gate * smear_distance, capped at smear_distance
        shift_mag = force_gate * sd

        coords_r_y = _np.clip(ys + uy * shift_mag, 0.0, h - 1.0).ravel()
        coords_r_x = _np.clip(xs + ux * shift_mag, 0.0, w - 1.0).ravel()
        r_shifted  = _ndi.map_coordinates(
            r0, [coords_r_y, coords_r_x], order=1, mode='nearest'
        ).reshape(h, w).astype(_np.float32)

        coords_b_y = _np.clip(ys - uy * shift_mag, 0.0, h - 1.0).ravel()
        coords_b_x = _np.clip(xs - ux * shift_mag, 0.0, w - 1.0).ravel()
        b_shifted  = _ndi.map_coordinates(
            b0, [coords_b_y, coords_b_x], order=1, mode='nearest'
        ).reshape(h, w).astype(_np.float32)

        blend = force_gate * fs
        r = _np.clip(r0 * (1.0 - blend) + r_shifted * blend, 0.0, 1.0)
        g = g0.copy()
        b = _np.clip(b0 * (1.0 - blend) + b_shifted * blend, 0.0, 1.0)

        # Stage 3: Saturation burst in motion zones
        sb = float(sat_boost)
        if sb > 0.001:
            lum3  = 0.299 * r + 0.587 * g + 0.114 * b
            scale = 1.0 + sb * force_gate
            r = _np.clip(lum3 + (r - lum3) * scale, 0.0, 1.0)
            g = _np.clip(lum3 + (g - lum3) * scale, 0.0, 1.0)
            b = _np.clip(lum3 + (b - lum3) * scale, 0.0, 1.0)

        # Stage 4: Velocity blur layer — soft horizontal luma trail at motion zones
        vb = float(velocity_blur)
        if vb > 0.1:
            lum_blurred = _ndi.gaussian_filter(lum, sigma=[0.5, vb]).astype(_np.float32)
            # Overlay luma trail at gate * 0.18 strength
            trail_str = force_gate * 0.18
            r = _np.clip(r + (lum_blurred - lum) * trail_str, 0.0, 1.0)
            g = _np.clip(g + (lum_blurred - lum) * trail_str, 0.0, 1.0)
            b = _np.clip(b + (lum_blurred - lum) * trail_str, 0.0, 1.0)

        # Stage 5: Composite with opacity
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_active = int((force_gate > 0.1).sum())
        print(f"    Boccioni Futurist Motion pass complete  "
              f"(active_px={n_active}  smear_dist={smear_distance})")

    def chromatic_focal_pull_pass(
        self,
        *,
        focal_x:    float = 0.50,
        focal_y:    float = 0.42,
        reach:      float = 0.55,
        warm_pull:  float = 0.08,
        cool_push:  float = 0.06,
        opacity:    float = 0.70,
    ) -> None:
        """
        Chromatic Focal Pull -- session 228 artistic improvement.

        Directs the viewer's eye toward a focal point using opposing chromatic
        and saturation gradients: the near-focal zone gains saturation and a
        subtle warm temperature bias; the peripheral zone loses saturation and
        gains a subtle cool bias.  Unlike vignette() which darkens the periphery,
        this pass operates only in hue/saturation space — values are preserved.
        Unlike edge_quality_variation_pass which varies edge sharpness by focus
        distance, this pass shifts chromaticity to create compositional energy
        flow without blurring or altering tonal values.

        Novelty vs. existing passes:
        vignette() darkens borders uniformly (no focal control, no chroma).
        atmospheric_depth_pass shifts value AND colour based on depth layers.
        This pass has no blurring, no value change, and is driven by a single
        user-defined focal point — pure hue/saturation compositional pull.

        focal_x    : Focal point horizontal position [0, 1] (0=left, 1=right).
        focal_y    : Focal point vertical position [0, 1] (0=top, 1=bottom).
        reach      : Normalised distance at which warm-pull fades to zero and
                     cool-push peaks [0, 1].
        warm_pull  : Saturation + warm-bias boost at the focal centre [0, 0.30].
        cool_push  : Saturation reduction + cool-bias at the periphery [0, 0.20].
        opacity    : Final composite opacity.
        """
        import numpy as _np

        print("    Chromatic Focal Pull pass (session 228 improvement)...")

        surface = self.canvas.surface
        orig    = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
                      (self.canvas.h, self.canvas.w, 4)).copy()
        h, w    = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        # Normalised distance from focal point
        ys = (_np.arange(h, dtype=_np.float32) / max(h - 1, 1)).reshape(h, 1)
        xs = (_np.arange(w, dtype=_np.float32) / max(w - 1, 1)).reshape(1, w)
        fx = float(focal_x)
        fy = float(focal_y)
        dist = _np.sqrt((xs - fx) ** 2 + (ys - fy) ** 2).astype(_np.float32)
        # Normalise so that a dist of `reach` maps to 1.0
        r_reach = float(reach) * (2.0 ** 0.5)  # max possible dist is sqrt(2)
        dist_n  = _np.clip(dist / max(r_reach, 1e-6), 0.0, 1.0)

        # Near-focal gate: 1 at centre, 0 at reach
        near_gate = _np.clip(1.0 - dist_n, 0.0, 1.0) ** 1.4
        # Far-focal gate: 0 at centre, 1 at periphery
        far_gate  = _np.clip(dist_n, 0.0, 1.0) ** 1.2

        lum3 = 0.299 * r0 + 0.587 * g0 + 0.114 * b0
        r, g, b = r0.copy(), g0.copy(), b0.copy()

        # Near-focal: boost saturation + subtle warm bias (lift R slightly)
        wp = float(warm_pull)
        if wp > 0.001:
            sat_scale_near = 1.0 + wp * near_gate
            r = _np.clip(lum3 + (r - lum3) * sat_scale_near, 0.0, 1.0)
            g = _np.clip(lum3 + (g - lum3) * sat_scale_near, 0.0, 1.0)
            b = _np.clip(lum3 + (b - lum3) * sat_scale_near, 0.0, 1.0)
            # Warm bias: very slight R lift, B dip
            r = _np.clip(r + near_gate * wp * 0.25, 0.0, 1.0)
            b = _np.clip(b - near_gate * wp * 0.15, 0.0, 1.0)

        # Far-focal: reduce saturation + subtle cool bias (lift B slightly)
        cp = float(cool_push)
        if cp > 0.001:
            lum3b = 0.299 * r + 0.587 * g + 0.114 * b
            sat_scale_far = 1.0 - cp * far_gate
            r = _np.clip(lum3b + (r - lum3b) * sat_scale_far, 0.0, 1.0)
            g = _np.clip(lum3b + (g - lum3b) * sat_scale_far, 0.0, 1.0)
            b = _np.clip(lum3b + (b - lum3b) * sat_scale_far, 0.0, 1.0)
            # Cool bias: slight B lift, R dip
            b = _np.clip(b + far_gate * cp * 0.22, 0.0, 1.0)
            r = _np.clip(r - far_gate * cp * 0.12, 0.0, 1.0)

        # Composite
        op    = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b * op, 0.0, 1.0)

        buf          = orig.copy()
        buf[:, :, 2] = (new_r * 255).astype(_np.uint8)
        buf[:, :, 1] = (new_g * 255).astype(_np.uint8)
        buf[:, :, 0] = (new_b * 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_near = int((near_gate > 0.3).sum())
        n_far  = int((far_gate > 0.3).sum())
        print(f"    Chromatic Focal Pull pass complete  "
              f"(near_px={n_near}  far_px={n_far})")

    def redon_luminous_reverie_pass(
        self,
        shadow_thresh:  float = 0.30,
        violet_lift:    float = 0.06,
        phosphor_boost: float = 0.35,
        dream_sigma:    float = 1.8,
        shimmer_thresh: float = 0.82,
        shimmer_str:    float = 0.08,
        opacity:        float = 0.75,
    ) -> None:
        """
        Redon Luminous Reverie -- session 229: ONE HUNDRED AND FORTIETH distinct mode.

        Implements Odilon Redon (1840-1916) Symbolist phosphorescent luminosity.
        Four stages unified by one shared luminance map:

        Stage 1 VIOLET SHADOW LIFT: gate=clip((shadow_thresh-lum)/shadow_thresh,0,1)^1.2
        R-=gate*violet_lift*0.55; B+=gate*violet_lift; G-=gate*violet_lift*0.18.
        Shifts shadows toward spectral indigo of Redon noirs.

        Stage 2 PHOSPHORESCENT MIDTONE BLOOM: bell=exp(-0.5*((lum-0.50)/0.28)^2);
        sat_scale=1+phosphor_boost*bell; ch=lum3+(ch-lum3)*sat_scale.
        Bell-curve peak at lum=0.50 creates glowing-from-within midtone quality.

        Stage 3 DREAM-HAZE SHADOW SOFTENING: Gaussian blur at dream_sigma;
        blend blurred into result weighted by shadow_gate*0.50 -- highlights unaffected.

        Stage 4 HIGHLIGHT SHIMMER BLOOM: shimmer_gate=clip((lum-shimmer_thresh)/
        (1-shimmer_thresh),0,1); tiny Gaussian bloom sigma=0.9; additive at shimmer_str.

        NOVEL vs. existing passes:
        (a) Bell-curve luminance gate for saturation (first mid-luma peak saturation pass).
        (b) Violet-indigo directional hue shift in shadow zones (not darkening/cool push).
        (c) Shadow-zone Gaussian softening + highlight shimmer in single unified model.
        (d) All four operations share one luminance computation.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Redon Luminous Reverie pass (session 229 -- 140th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Violet Shadow Lift
        st = float(shadow_thresh)
        shadow_gate = _np.clip((st - lum) / (st + 1e-6), 0.0, 1.0) ** 1.2
        vl = float(violet_lift)
        r1 = _np.clip(r0 - shadow_gate * vl * 0.55, 0.0, 1.0)
        g1 = _np.clip(g0 - shadow_gate * vl * 0.18, 0.0, 1.0)
        b1 = _np.clip(b0 + shadow_gate * vl,         0.0, 1.0)

        # Stage 2: Phosphorescent Midtone Bloom (bell-curve saturation)
        bell = _np.exp(-0.5 * ((lum - 0.50) / 0.28) ** 2).astype(_np.float32)
        pb = float(phosphor_boost)
        sat_scale = 1.0 + pb * bell
        lum3 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        r2 = _np.clip(lum3 + (r1 - lum3) * sat_scale, 0.0, 1.0)
        g2 = _np.clip(lum3 + (g1 - lum3) * sat_scale, 0.0, 1.0)
        b2 = _np.clip(lum3 + (b1 - lum3) * sat_scale, 0.0, 1.0)

        # Stage 3: Dream-Haze Shadow Softening
        ds = float(dream_sigma)
        r_blur = _gf(r2, ds).astype(_np.float32)
        g_blur = _gf(g2, ds).astype(_np.float32)
        b_blur = _gf(b2, ds).astype(_np.float32)
        haze_gate = shadow_gate * 0.50
        r3 = r2 * (1.0 - haze_gate) + r_blur * haze_gate
        g3 = g2 * (1.0 - haze_gate) + g_blur * haze_gate
        b3 = b2 * (1.0 - haze_gate) + b_blur * haze_gate

        # Stage 4: Highlight Shimmer Bloom
        sth = float(shimmer_thresh)
        shimmer_gate = _np.clip((lum - sth) / (1.0 - sth + 1e-6), 0.0, 1.0)
        r_sh = _gf(r3, 0.9).astype(_np.float32)
        g_sh = _gf(g3, 0.9).astype(_np.float32)
        b_sh = _gf(b3, 0.9).astype(_np.float32)
        ss = float(shimmer_str)
        r4 = _np.clip(r3 + shimmer_gate * ss * (r_sh - r3), 0.0, 1.0)
        g4 = _np.clip(g3 + shimmer_gate * ss * (g_sh - g3), 0.0, 1.0)
        b4 = _np.clip(b3 + shimmer_gate * ss * (b_sh - b3), 0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r4 * op
        new_g = g0 * (1.0 - op) + g4 * op
        new_b = b0 * (1.0 - op) + b4 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_violet  = int((shadow_gate > 0.2).sum())
        n_bloom   = int((bell > 0.5).sum())
        n_shimmer = int((shimmer_gate > 0.1).sum())
        print(f"    Redon Luminous Reverie complete "
              f"(violet_px={n_violet} bloom_px={n_bloom} shimmer_px={n_shimmer})")

    def impasto_relief_pass(
        self,
        light_angle:    float = 2.36,
        relief_scale:   float = 0.12,
        thickness_gate: float = 0.30,
        relief_sigma:   float = 1.2,
        opacity:        float = 0.55,
    ) -> None:
        """
        Impasto Relief -- session 229 artistic improvement.

        Models the 3D surface of thick oil paint under directional raking light.
        Oil paint physically builds up in ridges; a raking light from above-left
        reveals the micro-topography: bright highlights on ridge faces toward the
        light, dark shadows on faces pointing away.

        Mechanism: treat smoothed luminance as a paint-height proxy. Compute a
        directional Sobel derivative along light_angle. Positive gradient (surface
        slopes toward light) gets brightness addition; negative gradient subtraction.
        Gated by luminance threshold so only moderately thick paint shows the relief.

        NOVEL vs. existing passes:
        - canvas_tooth_texture_pass models the canvas BELOW the paint (periodic
          woven structure), not the paint surface itself.
        - edge_definition_pass sharpens edges uniformly with no directional light.
        - This pass simulates PAINT SURFACE TOPOGRAPHY under a user-defined raking
          light -- first pass using directional Sobel on luminance-as-height-proxy
          to derive paint surface normals for 3D relief lighting.

        light_angle    : Direction of raking light in radians (default ~135 deg NW).
        relief_scale   : Amplitude of relief brightness modulation [0, 0.30].
        thickness_gate : Luminance threshold -- relief only where lum > this.
        relief_sigma   : Gaussian sigma for smoothing the height-proxy.
        opacity        : Final composite opacity.
        """
        import numpy as _np
        import math as _math
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        print("    Impasto Relief pass (session 229 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Paint height proxy: smoothed luminance
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        height = _gf(lum, float(relief_sigma)).astype(_np.float32)

        # Directional derivative along light_angle
        la = float(light_angle)
        dx = _sobel(height, axis=1).astype(_np.float32)
        dy = _sobel(height, axis=0).astype(_np.float32)
        relief = (dx * _math.cos(la) + dy * _math.sin(la)).astype(_np.float32)

        # Normalise relief to [-1, 1]
        r_max = _np.abs(relief).max()
        if r_max > 1e-6:
            relief = relief / r_max

        # Thickness gate: relief only where paint is thick enough
        tg = float(thickness_gate)
        thick_gate = _np.clip((lum - tg) / (1.0 - tg + 1e-6), 0.0, 1.0) ** 0.8

        rs = float(relief_scale)
        delta = relief * rs * thick_gate

        r1 = _np.clip(r0 + delta,        0.0, 1.0)
        g1 = _np.clip(g0 + delta * 0.95, 0.0, 1.0)
        b1 = _np.clip(b0 + delta * 0.88, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_lit  = int((delta > 0.005).sum())
        n_dark = int((delta < -0.005).sum())
        print(f"    Impasto Relief pass complete (lit_px={n_lit} dark_px={n_dark})")

    def hammershoi_grey_interior_pass(
        self,
        grey_veil:       float = 0.55,
        window_lift:     float = 0.09,
        window_cool:     float = 0.06,
        stillness_sigma: float = 1.6,
        stillness_str:   float = 0.40,
        opacity:         float = 0.70,
    ) -> None:
        """
        Hammershøi Grey Interior -- session 230: ONE HUNDRED AND FORTY-FIRST distinct mode.

        Implements Vilhelm Hammershøi (1864-1916) Danish Intimist silvery interior quality.
        Three stages unified by one shared luminance map:

        Stage 1 MIDTONE GREY VEIL: bell=exp(-0.5*((lum-0.55)/0.30)^2) peaks at lum=0.55.
        Desaturate toward grey: grey=lum (per-channel); ch=ch*(1-bell*grey_veil)+grey*bell*grey_veil.
        Preserve warmth in highlights (lum>0.75: tiny warm lift +0.012 R) and coolness in
        shadows (lum<0.30: tiny cool lift +0.010 B).

        Stage 2 UNIDIRECTIONAL LEFT-WINDOW GRADIENT: x_norm in [0,1] left-to-right.
        window_gate=clip(1-x_norm/0.55, 0, 1)^1.5 — soft left-column brightening.
        R+=window_gate*window_lift; G+=window_gate*window_lift*0.90; B+=window_gate*window_lift*0.82.
        Far side: cool_gate=clip((x_norm-0.65)/0.35, 0, 1); B+=cool_gate*window_cool;
        R-=cool_gate*window_cool*0.55 — cool blue cast in the shadow-right zone.

        Stage 3 STILLNESS HAZE: midtone bell_s=exp(-0.5*((lum-0.55)/0.28)^2).
        Gaussian blur at stillness_sigma; blend at bell_s*stillness_str — blurs
        interior contours at midtones while leaving the lit window zone and deep
        corner shadows crisp.

        NOVEL vs. existing passes:
        (a) Midtone-peaking bell-curve for desaturation (strongest at grey mid-tones,
            tapering off at both highlights and shadows) — no prior pass uses this.
        (b) Unidirectional horizontal left-right window gradient (not radial like
            vermeer_pearl_light_pass, not distance-based like atmospheric_depth_pass).
        (c) Midtone-gated stillness haze (bell at lum=0.55) vs. shadow-gated
            (redon stage 3) or edge-gated (diffuse_boundary_pass).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Hammershøi Grey Interior pass (session 230 -- 141st mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Midtone Grey Veil
        bell = _np.exp(-0.5 * ((lum - 0.55) / 0.30) ** 2).astype(_np.float32)
        gv = float(grey_veil)
        veil_w = bell * gv
        r1 = r0 * (1.0 - veil_w) + lum * veil_w
        g1 = g0 * (1.0 - veil_w) + lum * veil_w
        b1 = b0 * (1.0 - veil_w) + lum * veil_w

        # Preserve warmth in highlights
        hi_gate = _np.clip((lum - 0.75) / 0.25, 0.0, 1.0)
        r1 = _np.clip(r1 + hi_gate * 0.012, 0.0, 1.0)

        # Preserve cool cast in shadows
        sh_gate = _np.clip((0.30 - lum) / 0.30, 0.0, 1.0)
        b1 = _np.clip(b1 + sh_gate * 0.010, 0.0, 1.0)

        # Stage 2: Unidirectional Left-Window Gradient
        x_norm = _np.linspace(0.0, 1.0, w, dtype=_np.float32)[_np.newaxis, :]
        window_gate = _np.clip(1.0 - x_norm / 0.55, 0.0, 1.0) ** 1.5
        wl = float(window_lift)
        r2 = _np.clip(r1 + window_gate * wl,        0.0, 1.0)
        g2 = _np.clip(g1 + window_gate * wl * 0.90, 0.0, 1.0)
        b2 = _np.clip(b1 + window_gate * wl * 0.82, 0.0, 1.0)

        cool_gate = _np.clip((x_norm - 0.65) / 0.35, 0.0, 1.0)
        wc = float(window_cool)
        r2 = _np.clip(r2 - cool_gate * wc * 0.55, 0.0, 1.0)
        b2 = _np.clip(b2 + cool_gate * wc,         0.0, 1.0)

        # Stage 3: Stillness Haze (midtone-gated)
        ss = float(stillness_sigma)
        r_blur = _gf(r2, ss).astype(_np.float32)
        g_blur = _gf(g2, ss).astype(_np.float32)
        b_blur = _gf(b2, ss).astype(_np.float32)
        bell_s = _np.exp(-0.5 * ((lum - 0.55) / 0.28) ** 2).astype(_np.float32)
        haze_w = bell_s * float(stillness_str)
        r3 = r2 * (1.0 - haze_w) + r_blur * haze_w
        g3 = g2 * (1.0 - haze_w) + g_blur * haze_w
        b3 = b2 * (1.0 - haze_w) + b_blur * haze_w

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_veiled  = int((bell > 0.5).sum())
        n_window  = int((window_gate > 0.2).sum())
        n_haze    = int((bell_s > 0.5).sum())
        print(f"    Hammershøi Grey Interior complete "
              f"(veiled_px={n_veiled} window_px={n_window} haze_px={n_haze})")

    def chromatic_memory_pass(
        self,
        memory_radius:  int   = 9,
        memory_pull:    float = 0.22,
        sat_threshold:  float = 0.18,
        opacity:        float = 0.60,
    ) -> None:
        """
        Chromatic Memory -- session 230 artistic improvement.

        Models the painter's unconscious colour harmony: in low-saturation zones,
        neighbouring hues gently pull each pixel toward the local average colour,
        creating soft chromatic cohesion without touching saturated focal areas.

        Artists working in muted palettes (Hammershøi, Morandi, Tuymans) achieve
        a subtle harmony where low-saturation greys and near-neutrals carry a faint
        shared tint — the whole interior breathes the same colour memory.  This pass
        replicates that effect computationally.

        Mechanism:
        1. Compute saturation map (HSV S channel).
        2. For pixels where saturation < sat_threshold: compute local-average RGB
           within a box of radius memory_radius via uniform_filter.
        3. Pull each low-saturation pixel memory_pull of the way toward its local
           neighbourhood average — creating soft harmonic cohesion among near-greys.
        4. High-saturation pixels are unaffected (gate = 0 above threshold).

        NOVEL vs. existing passes:
        - chromatic_zoning_pass: splits by absolute hue zone (warm vs. cool), not by
          saturation level; it shifts hue, not toward local average.
        - chromatic_focal_pull_pass: pulls toward/away from focal zone by distance,
          not toward neighbourhood average.
        - palette_proximity_pull_pass: pulls toward a fixed artist palette, not toward
          spatially-local neighbours.
        - wet_blend: a stroke-level simulation during painting; this is a post-pass.
        - This pass: spatial colour memory via local-average pull gated by saturation —
          first pass in pipeline using per-pixel neighbourhood-average as the target.

        memory_radius  : Half-width of neighbourhood box for local average (pixels).
        memory_pull    : Blend fraction toward local average [0, 1].
        sat_threshold  : Only pixels with HSV saturation below this are affected.
        opacity        : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import uniform_filter as _uf

        print("    Chromatic Memory pass (session 230 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Saturation from RGB: sat = (max-min)/max  (HSV S approximation)
        cmax = _np.maximum(_np.maximum(r0, g0), b0)
        cmin = _np.minimum(_np.minimum(r0, g0), b0)
        sat  = _np.where(cmax > 1e-6, (cmax - cmin) / (cmax + 1e-6), 0.0).astype(_np.float32)

        # Gate: active only below sat_threshold
        st = float(sat_threshold)
        gate = _np.clip(1.0 - sat / (st + 1e-6), 0.0, 1.0)

        # Local neighbourhood average
        ksize = 2 * int(memory_radius) + 1
        r_avg = _uf(r0, ksize).astype(_np.float32)
        g_avg = _uf(g0, ksize).astype(_np.float32)
        b_avg = _uf(b0, ksize).astype(_np.float32)

        # Pull toward local average, scaled by gate and memory_pull
        mp = float(memory_pull)
        r1 = r0 + gate * mp * (r_avg - r0)
        g1 = g0 + gate * mp * (g_avg - g0)
        b1 = b0 + gate * mp * (b_avg - b0)

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_active = int((gate > 0.2).sum())
        print(f"    Chromatic Memory pass complete (active_px={n_active})")

    def vrubel_crystal_facet_pass(
        self,
        facet_sigma:   float = 4.5,
        edge_thresh:   float = 0.18,
        grout_depth:   float = 0.45,
        jewel_boost:   float = 0.30,
        opacity:       float = 0.80,
    ) -> None:
        """
        Vrubel Crystal Facet -- session 231: ONE HUNDRED AND FORTY-SECOND distinct mode.

        Implements Mikhail Vrubel (1856-1910) mosaic-crystalline surface technique.
        Vrubel built forms from angular, facet-like brushstrokes separated by dark
        edges -- like a shattered stained-glass window reassembled on canvas.  The
        surface reads as a field of crystalline colour planes, not a continuous tonal
        gradation.

        Mechanism: detect region-level luminance gradient boundaries from a
        pre-smoothed field (so we find macro-scale "tile" edges, not pixel noise);
        darken at those boundaries to simulate dark grout lines between mosaic tiles;
        boost saturation in the low-gradient interior of each facet for the jewel-like
        iridescent quality.

        Stage 1 FACET EDGE DETECTION:
          lum_smooth = gaussian_filter(lum, facet_sigma);
          dx = sobel(lum_smooth, axis=1); dy = sobel(lum_smooth, axis=0);
          grad = sqrt(dx^2+dy^2); normalise to [0,1];
          edge_gate = clip(grad/edge_thresh, 0, 1)^0.7.

        Stage 2 GROUT DARKENING:
          grout_factor = 1 - edge_gate * grout_depth;
          r1 = r*grout_factor, g1 = g*grout_factor, b1 = b*grout_factor.

        Stage 3 FACET INTERIOR JEWEL BOOST:
          facet_int = 1 - edge_gate;  (high in flat interiors, zero at edges)
          sat_scale = 1 + jewel_boost * facet_int;
          lum1 = weighted-luminance(r1,g1,b1);
          r2 = clip(lum1 + (r1-lum1)*sat_scale, 0,1) etc.

        NOVEL vs. existing passes:
        (a) Pre-smoothed Sobel gradient at macro scale (facet_sigma~4-5px) targets
            region-level colour plane boundaries -- distinct from edge_definition_pass
            which operates at pixel scale with an unsharp mask;
        (b) Dual-zone treatment: grout-darkening at detected edges + jewel-saturation
            boost in flat interiors -- no prior pass does this paired treatment;
        (c) impasto_relief_pass uses directional Sobel on luminance-as-height for 3D
            raking light; this pass uses isotropic gradient magnitude for 2D mosaic
            segmentation -- orthogonal operations.

        facet_sigma  : Gaussian pre-smooth radius; larger = bigger facets.
        edge_thresh  : Normalised gradient at which grout darkening reaches full.
        grout_depth  : Strength of edge darkening (1.0 = full black grout).
        jewel_boost  : Saturation multiplier in facet interiors.
        opacity      : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, sobel as _sobel

        print("    Vrubel Crystal Facet pass (session 231 -- 142nd mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Facet edge detection from pre-smoothed luminance
        fs = float(facet_sigma)
        lum_smooth = _gf(lum, fs).astype(_np.float32)
        dx = _sobel(lum_smooth, axis=1).astype(_np.float32)
        dy = _sobel(lum_smooth, axis=0).astype(_np.float32)
        grad = _np.sqrt(dx ** 2 + dy ** 2).astype(_np.float32)
        g_max = grad.max()
        if g_max > 1e-6:
            grad = grad / g_max

        et = float(edge_thresh)
        edge_gate = _np.clip(grad / (et + 1e-6), 0.0, 1.0) ** 0.7

        # Stage 2: Grout darkening at facet edges
        gd = float(grout_depth)
        grout_factor = 1.0 - edge_gate * gd
        r1 = _np.clip(r0 * grout_factor, 0.0, 1.0)
        g1 = _np.clip(g0 * grout_factor, 0.0, 1.0)
        b1 = _np.clip(b0 * grout_factor, 0.0, 1.0)

        # Stage 3: Facet interior jewel-saturation boost
        facet_int = 1.0 - edge_gate
        jb = float(jewel_boost)
        sat_scale = 1.0 + jb * facet_int
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        r2 = _np.clip(lum1 + (r1 - lum1) * sat_scale, 0.0, 1.0)
        g2 = _np.clip(lum1 + (g1 - lum1) * sat_scale, 0.0, 1.0)
        b2 = _np.clip(lum1 + (b1 - lum1) * sat_scale, 0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_edge = int((edge_gate > 0.5).sum())
        n_facet = int((facet_int > 0.5).sum())
        print(f"    Vrubel Crystal Facet complete "
              f"(edge_px={n_edge} facet_px={n_facet})")

    def midtone_clarity_pass(
        self,
        clarity_center: float = 0.50,
        clarity_width:  float = 0.22,
        sharpness:      float = 0.55,
        blur_sigma:     float = 1.4,
        opacity:        float = 0.65,
    ) -> None:
        """
        Midtone Clarity -- session 231 artistic improvement.

        Applies a luminance-selective unsharp mask: sharpening is strongest in the
        mid-tone zone (default lum=0.50) and fades to zero in deep shadows and bright
        highlights.  This preserves the painterly softness of those extremes while
        giving the mid-tone forms (where the eye reads structural detail) crisp,
        readable definition -- a technique closely related to the Ansel Adams zone
        approach and the classical painter technique of rendering form most precisely
        in the half-lights.

        Mechanism:
          clarity_gate = exp(-0.5*((lum-clarity_center)/clarity_width)^2)  [bell-curve]
          unsharp_delta = lum - gaussian_blur(lum, blur_sigma)
          luminance delta applied: delta = clarity_gate * sharpness * unsharp_delta
          Each channel: ch += delta (luminance shift, preserves hue)

        NOVEL vs. existing passes:
        - edge_definition_pass: uniform unsharp mask applied to all pixels regardless
          of luminance (no bell-curve gate).
        - edge_quality_variation_pass: varies edge softness spatially by zone, not by
          per-pixel luminance level.
        - impasto_relief_pass: directional Sobel gradient to simulate 3D paint surface
          (R/G/B weighted differently -- no luminance gate).
        - hammershoi_grey_interior_pass: stillness haze is a SOFTENING (blur) gated
          by midtone bell; this is its complement -- midtone SHARPENING with same gate.
        - Novel: (a) luminance bell-curve gate at configurable mid-tone centre; (b)
          sharpening complement to midtone-gated blurring (no prior pass combines
          these into a single perceptual clarity tool); (c) only channel-uniform
          luminance delta applied (no colour fringing).

        clarity_center : Luminance at which sharpening is strongest (0=black, 1=white).
        clarity_width  : Bell-curve half-width; larger = broader zone of sharpening.
        sharpness      : Unsharp mask amplitude.
        blur_sigma     : Gaussian sigma for the low-pass component.
        opacity        : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Midtone Clarity pass (session 231 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Bell-curve gate: strongest sharpening at clarity_center
        cc = float(clarity_center)
        cw = float(clarity_width)
        clarity_gate = _np.exp(-0.5 * ((lum - cc) / (cw + 1e-6)) ** 2).astype(_np.float32)

        # Unsharp mask delta (luminance channel)
        bs = float(blur_sigma)
        lum_blur = _gf(lum, bs).astype(_np.float32)
        unsharp_delta = (lum - lum_blur).astype(_np.float32)

        # Gated sharpening delta
        sh = float(sharpness)
        delta = clarity_gate * sh * unsharp_delta

        # Apply luminance delta uniformly to all channels
        r1 = _np.clip(r0 + delta,        0.0, 1.0)
        g1 = _np.clip(g0 + delta,        0.0, 1.0)
        b1 = _np.clip(b0 + delta * 0.95, 0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_active = int((clarity_gate > 0.5).sum())
        n_sharp  = int((delta > 0.003).sum())
        print(f"    Midtone Clarity pass complete (active_px={n_active} sharpened_px={n_sharp})")

    def moreau_jeweled_ornament_pass(
        self,
        grain_strength:  float = 0.06,
        grain_sigma:     float = 0.55,
        grain_center:    float = 0.60,
        grain_width:     float = 0.22,
        lum_lift:        float = 0.055,
        glow_center:     float = 0.58,
        glow_width:      float = 0.24,
        gold_r_shift:    float = 0.040,
        gold_g_shift:    float = 0.018,
        gold_b_shift:    float = 0.032,
        gold_threshold:  float = 0.52,
        opacity:         float = 0.82,
    ) -> None:
        """
        Moreau Jeweled Ornament -- session 232: ONE HUNDRED AND FORTY-THIRD distinct mode.

        Implements Gustave Moreau (1826-1898) encrusted mythological surface technique.
        Moreau built his paintings like illuminated manuscripts -- every surface dense
        with ornamental grain, every lit zone glowing with an inner jewel luminosity,
        every highlight cast in warm burnished gold.  The effect is a surface that
        reads as simultaneously flat (decorative pattern) and deep (translucent glazing).

        Three-stage mechanism:

        Stage 1 ORNAMENTAL GRAIN:
          noise = gaussian_filter(random_field, grain_sigma) -- spatially coherent fine grain
          norm to [-0.5, 0.5];
          grain_gate = exp(-0.5*((lum-grain_center)/grain_width)^2)  [bell, peaks at 0.60]
          ch += grain_gate * grain_strength * noise

        Stage 2 JEWEL LUMINOSITY LIFT:
          glow_gate = exp(-0.5*((lum-glow_center)/glow_width)^2)  [bell, peaks at 0.58]
          delta_lum = glow_gate * lum_lift
          ch += delta_lum  (uniform channel lift -- preserves hue, brightens mid zone)

        Stage 3 WARM GILDING TINT:
          gold_gate = clip((lum - gold_threshold) / 0.20, 0, 1)  [ramp in bright zone]
          R += gold_gate * gold_r_shift
          G += gold_gate * gold_g_shift
          B -= gold_gate * gold_b_shift

        NOVEL vs. existing passes:
        (a) Spatially-coherent ornamental grain gated by luminance bell (grain_sigma ~0.5px
            produces fine, smooth texture clusters, not sharp pixel noise) -- no prior pass
            adds gated grain as a primary mechanism;
        (b) Separate luminosity lift in the mid-bright zone (lum 0.40-0.75) to simulate
            Moreau's translucent glaze glow from beneath the surface -- distinct from
            midtone_clarity_pass which sharpens detail rather than lifting brightness;
        (c) Warm gilding tint ramp in highlights (R+, G+, B-) -- models burnished gold
            light on illuminated surfaces -- no prior pass implements highlight-zone
            colour temperature shift as a standalone operation;
        (d) All three stages operate on different luminance zones and accumulate without
            cancelling each other: grain peaks at lum=0.60, glow peaks at lum=0.58,
            gold ramp activates above lum=0.52.

        grain_strength : Amplitude of ornamental grain texture.
        grain_sigma    : Gaussian sigma for coherent grain; smaller = finer ornament.
        grain_center   : Luminance at which grain is strongest (bell-curve peak).
        grain_width    : Bell half-width for grain gate.
        lum_lift       : Brightness lift in the jewel-glow zone.
        glow_center    : Luminance at which glow lift is strongest.
        glow_width     : Bell half-width for glow gate.
        gold_r_shift   : Red channel shift in warm gilding highlights.
        gold_g_shift   : Green channel shift in warm gilding highlights.
        gold_b_shift   : Blue channel reduction in warm gilding highlights.
        gold_threshold : Luminance above which warm gilding ramp begins.
        opacity        : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Moreau Jeweled Ornament pass (session 232 -- 143rd mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Ornamental grain -- coherent fine texture gated by luminance bell
        rng = _np.random.RandomState(2320)
        raw_noise = rng.uniform(-0.5, 0.5, size=(self.canvas.h, self.canvas.w)).astype(_np.float32)
        coherent_noise = _gf(raw_noise, float(grain_sigma)).astype(_np.float32)
        gc = float(grain_center)
        gw = float(grain_width)
        grain_gate = _np.exp(-0.5 * ((lum - gc) / (gw + 1e-6)) ** 2).astype(_np.float32)
        gs = float(grain_strength)
        grain_delta = grain_gate * gs * coherent_noise
        r1 = _np.clip(r0 + grain_delta, 0.0, 1.0)
        g1 = _np.clip(g0 + grain_delta, 0.0, 1.0)
        b1 = _np.clip(b0 + grain_delta, 0.0, 1.0)

        # Stage 2: Jewel luminosity lift in mid-bright zone
        glc = float(glow_center)
        glw = float(glow_width)
        glow_gate = _np.exp(-0.5 * ((lum - glc) / (glw + 1e-6)) ** 2).astype(_np.float32)
        ll = float(lum_lift)
        delta_lum = glow_gate * ll
        r2 = _np.clip(r1 + delta_lum, 0.0, 1.0)
        g2 = _np.clip(g1 + delta_lum, 0.0, 1.0)
        b2 = _np.clip(b1 + delta_lum, 0.0, 1.0)

        # Stage 3: Warm gilding tint in highlights
        gt = float(gold_threshold)
        gold_gate = _np.clip((lum - gt) / 0.20, 0.0, 1.0).astype(_np.float32)
        r3 = _np.clip(r2 + gold_gate * float(gold_r_shift), 0.0, 1.0)
        g3 = _np.clip(g2 + gold_gate * float(gold_g_shift), 0.0, 1.0)
        b3 = _np.clip(b2 - gold_gate * float(gold_b_shift), 0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_grain  = int((grain_gate > 0.5).sum())
        n_glow   = int((glow_gate > 0.5).sum())
        n_gilded = int((gold_gate > 0.2).sum())
        print(f"    Moreau Jeweled Ornament complete "
              f"(grain_px={n_grain} glow_px={n_glow} gilded_px={n_gilded})")

    def warm_cool_zone_pass(
        self,
        warm_threshold: float = 0.52,
        warm_ramp:      float = 0.20,
        warm_r_lift:    float = 0.045,
        warm_b_drop:    float = 0.030,
        cool_threshold: float = 0.34,
        cool_ramp:      float = 0.18,
        cool_b_lift:    float = 0.040,
        cool_r_drop:    float = 0.022,
        cool_g_drop:    float = 0.008,
        opacity:        float = 0.70,
    ) -> None:
        """
        Warm-Cool Zone -- session 232 artistic improvement.

        Applies the classical academic painter's principle of warm light / cool shadow:
        highlights are pushed toward warm (R+, B-) and deep shadows are shifted toward
        cool (B+, R-, slight G-).  This replicates the atmospheric colour temperature
        separation used by Moreau, Bouguereau, Cabanel, and the entire Academic tradition
        -- warm light sources (sun, candle, gold) cast warm highlights; the shadow
        zones, unilluminated by direct light, pick up the cool ambient sky or air.

        Both gates are smooth linear ramps to avoid banding:
          warm_gate = clip((lum - warm_threshold) / warm_ramp, 0, 1)
            -- zero below warm_threshold, linearly rises to 1 at warm_threshold+warm_ramp
          cool_gate = clip((cool_threshold - lum) / cool_ramp, 0, 1)
            -- zero above cool_threshold, linearly rises to 1 at cool_threshold-cool_ramp

        Warm highlights:
          R += warm_gate * warm_r_lift
          B -= warm_gate * warm_b_drop

        Cool shadows:
          B += cool_gate * cool_b_lift
          R -= cool_gate * cool_r_drop
          G -= cool_gate * cool_g_drop

        NOVEL vs. existing passes:
        - hammershoi_grey_interior_pass: specific warm/cool lifts (hi_gate, sh_gate) are
          minor secondary adjustments tied to its dominant grey-veil mechanism and
          unidirectional window gradient.  This pass makes warm/cool temperature
          separation the primary, standalone operation.
        - chromatic_memory_pass: pulls toward local spatial colour average -- no warm/cool
          logic, no luminance-gated temperature model.
        - midtone_clarity_pass: luminance-gated unsharp mask -- sharpening, not colour
          temperature.  Different goal.
        - No prior pass implements warm-light / cool-shadow as a configurable, standalone
          atmospheric separation tool.
        - Novel: (a) dual independent ramp gates (warm and cool) on separate luminance
          zones with no overlap at mid-tones; (b) the mid-tone zone [cool_threshold,
          warm_threshold] is intentionally untouched -- mid-tones stay neutral, enforcing
          the classical tonality model; (c) configurable thresholds and ramp widths allow
          calibration from subtle Academic polish to bold Expressionist contrast.

        warm_threshold : Luminance at which warm shift begins to activate.
        warm_ramp      : Ramp width over which warm gate rises from 0 to 1.
        warm_r_lift    : Red channel gain in warm highlight zone.
        warm_b_drop    : Blue channel reduction in warm highlight zone.
        cool_threshold : Luminance at which cool shift begins to activate.
        cool_ramp      : Ramp width over which cool gate rises from 0 to 1.
        cool_b_lift    : Blue channel gain in cool shadow zone.
        cool_r_drop    : Red channel reduction in cool shadow zone.
        cool_g_drop    : Green channel reduction in cool shadow zone.
        opacity        : Final composite opacity.
        """
        import numpy as _np

        print("    Warm-Cool Zone pass (session 232 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Warm gate: smooth ramp from 0 at warm_threshold to 1 at warm_threshold+warm_ramp
        wt = float(warm_threshold)
        wr = float(warm_ramp)
        warm_gate = _np.clip((lum - wt) / (wr + 1e-6), 0.0, 1.0).astype(_np.float32)

        # Cool gate: smooth ramp from 0 at cool_threshold to 1 at cool_threshold-cool_ramp
        ct = float(cool_threshold)
        cr = float(cool_ramp)
        cool_gate = _np.clip((ct - lum) / (cr + 1e-6), 0.0, 1.0).astype(_np.float32)

        # Warm highlight adjustment
        r1 = _np.clip(r0 + warm_gate * float(warm_r_lift), 0.0, 1.0)
        b1 = _np.clip(b0 - warm_gate * float(warm_b_drop), 0.0, 1.0)

        # Cool shadow adjustment (applied to the already warm-adjusted channels)
        r2 = _np.clip(r1 - cool_gate * float(cool_r_drop), 0.0, 1.0)
        g2 = _np.clip(g0 - cool_gate * float(cool_g_drop), 0.0, 1.0)
        b2 = _np.clip(b1 + cool_gate * float(cool_b_lift), 0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_warm = int((warm_gate > 0.2).sum())
        n_cool = int((cool_gate > 0.2).sum())
        print(f"    Warm-Cool Zone pass complete (warm_px={n_warm} cool_px={n_cool})")

    def khnopff_frozen_reverie_pass(
        self,
        desat_str:       float = 0.55,
        cool_shift:      float = 0.055,
        reverie_sigma:   float = 1.80,
        mist_str:        float = 0.50,
        bright_start:    float = 0.58,
        bright_range:    float = 0.25,
        pearl_b_boost:   float = 0.030,
        pearl_start:     float = 0.70,
        opacity:         float = 0.80,
    ) -> None:
        """
        Khnopff Frozen Reverie -- session 232: ONE HUNDRED AND FORTY-THIRD distinct mode.

        Implements Fernand Khnopff (1858-1921) Belgian Symbolist atmosphere:
        everything muted toward cool silver-grey, forms dissolved into atmospheric
        mist in shadows and midtones, while highlights remain crisp and pearl-cool.
        The effect: a remembered vision seen through fine Belgian mist, emotionally
        suspended between waking and dreaming.

        Three-stage mechanism:

        Stage 1 COOL SILVER VEIL (desaturation toward cool grey):
          ch_desat = lum + (ch - lum) * (1 - desat_str)  [pull toward grey]
          cool_gate = clip(1 - lum/0.65, 0, 1)  [strongest in shadow, zero at lum=0.65]
          B_desat += cool_shift * cool_gate
          R_desat -= cool_shift * 0.45 * cool_gate
          [Shadows become cool blue-grey; mid-tones cool slightly; highlights left warmer]

        Stage 2 REVERIE MIST BLUR (atmospheric dissolution in non-highlights):
          blur_r,g,b = gaussian_filter(ch_desat, reverie_sigma)
          bright_gate = clip((lum - bright_start) / bright_range, 0, 1)  [0→shadow, 1→highlight]
          mist_blend = mist_str * (1 - bright_gate)
          ch_mist = ch_blur * mist_blend + ch_desat * (1 - mist_blend)
          [Highlights crisp; shadows and midtones dissolved into atmospheric softness]

        Stage 3 PEARL HIGHLIGHT COOL TINT:
          pearl_gate = clip((lum - pearl_start) / 0.20, 0, 1)  [activates in bright zone]
          B_out += pearl_gate * pearl_b_boost
          [Adds characteristic cool-white pearl quality to brightest highlights;
           distinct from Moreau's warm gold -- Khnopff highlights are pearl, not gold]

        NOVEL vs. existing passes:
        (a) Simultaneous global cool desaturation (pulling toward blue-grey, not neutral
            grey) + luminance-gated atmospheric mist blur -- no prior pass combines both;
            hammershoi_grey_interior_pass uses a midtone bell grey veil + unidirectional
            window gradient (very different spatial logic);
        (b) Mist blur that preserves crisp highlights via bright_gate: the blur amount
            is 0 in bright zones, maximum in shadows -- inverse of midtone_clarity_pass
            which sharpens midtones; no prior pass applies selective blur by luminance;
        (c) Cool pearl tint in highlights (B+ at lum>pearl_start): opposite of
            moreau_jeweled_ornament_pass warm gilding; models the Belgian grey-light
            highlight quality (north European light, not Mediterranean gold);
        (d) The cool_gate for desaturation is strongest in shadows (inversely luminance-
            gated): shadows are coolest, mid-tones slightly cool, highlights neutral --
            the opposite of most prior passes which work from neutral darkness outward.

        desat_str     : Desaturation strength (0=no change, 1=fully grey).
        cool_shift    : Blue channel boost in shadow/mid zones; R reduced proportionally.
        reverie_sigma : Gaussian sigma for atmospheric mist blur.
        mist_str      : Maximum mist blend fraction (in darkest zones).
        bright_start  : Luminance at which mist blur begins to fade (highlight preservation).
        bright_range  : Luminance range over which mist fades from mist_str to 0.
        pearl_b_boost : Blue channel boost in brightest highlights (cool pearl quality).
        pearl_start   : Luminance at which pearl cool tint activates.
        opacity       : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Khnopff Frozen Reverie pass (session 232 -- 143rd mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Cool silver veil -- desaturation + cool push in shadow/mid zones
        ds = float(desat_str)
        r1 = _np.clip(lum + (r0 - lum) * (1.0 - ds), 0.0, 1.0)
        g1 = _np.clip(lum + (g0 - lum) * (1.0 - ds), 0.0, 1.0)
        b1 = _np.clip(lum + (b0 - lum) * (1.0 - ds), 0.0, 1.0)

        cool_gate = _np.clip(1.0 - lum / (0.65 + 1e-6), 0.0, 1.0).astype(_np.float32)
        cs = float(cool_shift)
        r1 = _np.clip(r1 - cs * 0.45 * cool_gate, 0.0, 1.0)
        b1 = _np.clip(b1 + cs * cool_gate, 0.0, 1.0)

        # Stage 2: Reverie mist blur -- atmospheric dissolution gated away from highlights
        rs = float(reverie_sigma)
        r_blur = _gf(r1, rs).astype(_np.float32)
        g_blur = _gf(g1, rs).astype(_np.float32)
        b_blur = _gf(b1, rs).astype(_np.float32)

        bs_val = float(bright_start)
        br_val = float(bright_range)
        bright_gate = _np.clip((lum - bs_val) / (br_val + 1e-6), 0.0, 1.0).astype(_np.float32)
        ms = float(mist_str)
        mist_blend = ms * (1.0 - bright_gate)

        r2 = r_blur * mist_blend + r1 * (1.0 - mist_blend)
        g2 = g_blur * mist_blend + g1 * (1.0 - mist_blend)
        b2 = b_blur * mist_blend + b1 * (1.0 - mist_blend)

        # Stage 3: Pearl highlight cool tint -- B+ in brightest zones
        ps = float(pearl_start)
        pearl_gate = _np.clip((lum - ps) / (0.20 + 1e-6), 0.0, 1.0).astype(_np.float32)
        pb = float(pearl_b_boost)
        b3 = _np.clip(b2 + pearl_gate * pb, 0.0, 1.0)
        r3 = r2
        g3 = g2

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_mist   = int((mist_blend > 0.3).sum())
        n_crisp  = int((bright_gate > 0.5).sum())
        n_pearl  = int((pearl_gate > 0.2).sum())
        print(f"    Khnopff Frozen Reverie complete "
              f"(mist_px={n_mist} crisp_px={n_crisp} pearl_px={n_pearl})")

    def kuindzhi_moonlit_radiance_pass(
        self,
        halo_sigma:        float = 14.0,
        halo_strength:     float = 0.18,
        velvet_power:      float = 2.20,
        velvet_threshold:  float = 0.28,
        moon_cold_b_shift: float = 0.10,
        moon_cold_r_drop:  float = 0.06,
        moon_threshold:    float = 0.68,
        shadow_b_push:     float = 0.06,
        shadow_threshold:  float = 0.22,
        streak_width:      float = 0.06,
        streak_strength:   float = 0.14,
        opacity:           float = 0.88,
    ) -> None:
        """
        Kuindzhi Moonlit Radiance -- session 233: ONE HUNDRED AND FORTY-FOURTH distinct mode.

        Implements Arkhip Kuindzhi (1842-1910) theatrical moonlight technique.
        Kuindzhi's "Moonlit Night on the Dnieper" (1880) stunned contemporaries with
        its impossibly incandescent moon -- crowds queued for hours, some suspecting
        a hidden light behind the canvas.  His method: near-black velvet shadows pushed
        to absolute darkness, a luminous cold-white moon surrounded by a radiating halo
        of pale light, and a vertical reflection streak on still water below.

        Four-stage mechanism, all sharing one luminance map:

        Stage 1 LUMINOUS HALO CORONA:
          bright_mask = clip((lum - moon_threshold) / (1-moon_threshold), 0, 1)
          halo_expanded = gaussian_filter(bright_mask, halo_sigma)
          corona = halo_expanded * (1 - bright_mask)   -- ring outside the source
          R,G,B += corona * halo_strength               -- pale cold ring

        Stage 2 SHADOW VELVETING:
          dark_mask = clip((velvet_threshold - lum) / velvet_threshold, 0, 1)
          velvet_gate = dark_mask ** velvet_power        -- power-curve in shadows
          R,G,B *= (1 - velvet_gate * 0.45)            -- crush to near-black

        Stage 3 CHROMATIC MOONLIGHT SHIFT:
          High zone (lum > moon_threshold): B += moon_cold_b_shift * bright_mask
                                            R -= moon_cold_r_drop * bright_mask
          Low zone (lum < shadow_threshold): B += shadow_b_push * dark_mask
          Models cold blue-white moonlight in highlights, indigo push in deep shadows.

        Stage 4 LUNAR REFLECTION STREAK:
          x_norm in [0, 1]; dist_from_centre = |x_norm - 0.5|
          streak_gate = clip(1 - dist_from_centre / streak_width, 0, 1)^1.5
          lum_streak = uniform_filter(lum, size=1) along vertical axis
          streak_lum = lum * streak_gate              -- vertical bar on water zone
          R,G,B += streak_lum * streak_strength * streak_gate
          Simulates the vertical shimmer of moonlight reflected on still water.

        NOVEL vs. existing passes:
        (a) Halo corona: Gaussian-expanded mask minus the source mask creates a ring of
            light AROUND the bright zone -- no prior pass models a light source corona;
        (b) Power-curve shadow velveting: dark^power crushes shadow gradients to near-black
            without touching mid-tones -- distinct from warm_cool_zone_pass which shifts
            colour temperature, not tonal depth;
        (c) Chromatic moonlight shift: cold blue-white in bright zone (B+, R-) combined
            with indigo push in deep shadows (B+) models the dual-temperature moonlit palette;
        (d) Vertical reflection streak: spatial distance from x-centre creates a narrow
            luminous column simulating moon-on-water -- first pass using horizontal
            distance to modulate a vertical luminance feature.

        halo_sigma        : Gaussian radius for expanding the bright zone corona.
        halo_strength     : Brightness of the halo ring additive boost.
        velvet_power      : Power exponent for shadow velveting (higher = more crushing).
        velvet_threshold  : Luminance below which velveting applies.
        moon_cold_b_shift : Blue channel boost in highlight zone (moonlight coldness).
        moon_cold_r_drop  : Red channel reduction in highlight zone.
        moon_threshold    : Luminance above which moonlight tint applies.
        shadow_b_push     : Blue channel push in deep shadow zone (indigo darkness).
        shadow_threshold  : Luminance below which indigo shadow push applies.
        streak_width      : Half-width of the vertical reflection streak (0-0.5).
        streak_strength   : Amplitude of the reflection streak additive.
        opacity           : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Kuindzhi Moonlit Radiance pass (session 233 -- 144th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Luminous Halo Corona
        mt = float(moon_threshold)
        bright_mask = _np.clip((lum - mt) / (1.0 - mt + 1e-6), 0.0, 1.0)
        halo_expanded = _gf(bright_mask, float(halo_sigma)).astype(_np.float32)
        corona = _np.clip(halo_expanded - bright_mask * 0.5, 0.0, 1.0)
        hs = float(halo_strength)
        r1 = _np.clip(r0 + corona * hs * 0.85, 0.0, 1.0)
        g1 = _np.clip(g0 + corona * hs * 0.90, 0.0, 1.0)
        b1 = _np.clip(b0 + corona * hs,        0.0, 1.0)

        # Stage 2: Shadow Velveting
        vt = float(velvet_threshold)
        dark_mask = _np.clip((vt - lum) / (vt + 1e-6), 0.0, 1.0)
        vp = float(velvet_power)
        velvet_gate = dark_mask ** vp
        crush = 1.0 - velvet_gate * 0.45
        r2 = _np.clip(r1 * crush, 0.0, 1.0)
        g2 = _np.clip(g1 * crush, 0.0, 1.0)
        b2 = _np.clip(b1 * crush, 0.0, 1.0)

        # Stage 3: Chromatic Moonlight Shift
        cb = float(moon_cold_b_shift)
        cr = float(moon_cold_r_drop)
        sb = float(shadow_b_push)
        st_low = float(shadow_threshold)
        shadow_gate = _np.clip((st_low - lum) / (st_low + 1e-6), 0.0, 1.0)
        r3 = _np.clip(r2 - bright_mask * cr, 0.0, 1.0)
        g3 = g2
        b3 = _np.clip(b2 + bright_mask * cb + shadow_gate * sb, 0.0, 1.0)

        # Stage 4: Lunar Reflection Streak
        sw = float(streak_width)
        ss = float(streak_strength)
        x_idx = _np.arange(w, dtype=_np.float32) / (w - 1)
        dist_from_centre = _np.abs(x_idx - 0.5)
        streak_gate_1d = _np.clip(1.0 - dist_from_centre / (sw + 1e-6), 0.0, 1.0) ** 1.5
        streak_gate = _np.broadcast_to(streak_gate_1d[None, :], (h, w)).copy()
        streak_lum = lum * streak_gate * ss
        r4 = _np.clip(r3 + streak_lum * 0.85, 0.0, 1.0)
        g4 = _np.clip(g3 + streak_lum * 0.90, 0.0, 1.0)
        b4 = _np.clip(b3 + streak_lum,        0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r4 * op
        new_g = g0 * (1.0 - op) + g4 * op
        new_b = b0 * (1.0 - op) + b4 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_halo    = int((corona > 0.05).sum())
        n_velvet  = int((velvet_gate > 0.20).sum())
        n_moon    = int((bright_mask > 0.10).sum())
        n_streak  = int((streak_gate > 0.20).sum())
        print(f"    Kuindzhi Moonlit Radiance complete "
              f"(halo_px={n_halo} velvet_px={n_velvet} "
              f"moon_px={n_moon} streak_px={n_streak})")

    def paint_gravity_drift_pass(
        self,
        drift_sigma_down:  float = 3.5,
        drift_sigma_up:    float = 0.6,
        thick_threshold:   float = 0.35,
        thick_power:       float = 1.40,
        drift_strength:    float = 0.55,
        opacity:           float = 0.60,
    ) -> None:
        """
        Paint Gravity Drift -- session 233 artistic improvement.

        Models the subtle physical sag of wet oil paint under gravity: thick paint
        (modelled by high luminance as a paint-height proxy) slowly spreads downward,
        softening the lower edge of each mark while leaving the upper edge crisp.
        This creates the characteristically organic quality of freshly applied impasto —
        a living surface whose forms drift fractionally under their own weight.

        Mechanism: asymmetric 1-D Gaussian blur in the vertical axis.
        A downward kernel (length = drift_sigma_down * 4, normalized) is applied
        to each column independently.  The effect is then blended back in proportion
        to a paint-thickness gate derived from luminance.

        Implementation via 1D uniform convolution approximation:
          kernel_down: 1D array of length K; values = exp(-0.5*(i/sigma_down)^2)
                       for i in [0, K) -- causal (forward/downward only)
          kernel_up  : 1D array of length K; values = exp(-0.5*(i/sigma_up)^2)
                       for i in [0, K) -- causal upward
          Both normalized to sum=1.
          Per-column, convolve each channel with (kernel_down - kernel_up) to get
          the net downward drift delta, scaled by drift_strength.

          thick_gate = clip((lum - thick_threshold) / (1 - thick_threshold), 0, 1)
                        ^ thick_power
          ch_out = ch_orig + drift_delta * thick_gate * drift_strength

        NOVEL vs. existing passes:
        (a) Asymmetric kernel (down >> up): prior anisotropic passes (batoni_silk_sheen)
            use symmetric elongated kernels along a direction; this pass uses a
            non-symmetric causal kernel that has NO symmetry -- downward spread is
            much longer than upward, producing a physically grounded asymmetric effect.
        (b) Thickness gate from luminance: only thick paint (bright zones) sags --
            thin paint and shadows stay crisp.  impasto_relief_pass models topography
            under raking light; this pass models the MOTION of thick paint over time.
        (c) Column-wise 1D convolution (axis=0, scipy.ndimage.convolve1d) rather than
            isotropic Gaussian -- first pass to use a directional 1D causal kernel.

        drift_sigma_down : Downward spread sigma in pixels.
        drift_sigma_up   : Upward counter-drift (smaller = more one-sided).
        thick_threshold  : Luminance below which paint is too thin to drift.
        thick_power      : Power shaping of thickness gate (higher = steeper).
        drift_strength   : Amplitude of the drift blend.
        opacity          : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import convolve1d as _c1d

        print("    Paint Gravity Drift pass (session 233 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Build asymmetric downward kernel
        sd = float(drift_sigma_down)
        su = float(drift_sigma_up)
        K = max(5, int(sd * 5) | 1)  # odd length
        i = _np.arange(K, dtype=_np.float32)
        k_down = _np.exp(-0.5 * (i / (sd + 1e-6)) ** 2)
        k_down /= k_down.sum()
        k_up   = _np.exp(-0.5 * (i / (su + 1e-6)) ** 2)
        k_up  /= k_up.sum()
        # Net drift = downward spread minus upward spread
        k_net = k_down - k_up  # causal positive = downward

        # Apply per-channel column-wise 1D convolution (axis=0 = vertical)
        r_drift = _c1d(r0, k_net, axis=0, mode='reflect').astype(_np.float32)
        g_drift = _c1d(g0, k_net, axis=0, mode='reflect').astype(_np.float32)
        b_drift = _c1d(b0, k_net, axis=0, mode='reflect').astype(_np.float32)

        # Thickness gate: only thick/bright paint drifts
        tt = float(thick_threshold)
        tp = float(thick_power)
        thick_gate = _np.clip(
            (lum - tt) / (1.0 - tt + 1e-6), 0.0, 1.0) ** tp

        ds = float(drift_strength)
        r1 = _np.clip(r0 + (r_drift - r0) * thick_gate * ds, 0.0, 1.0)
        g1 = _np.clip(g0 + (g_drift - g0) * thick_gate * ds, 0.0, 1.0)
        b1 = _np.clip(b0 + (b_drift - b0) * thick_gate * ds, 0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_thick  = int((thick_gate > 0.15).sum())
        n_active = int((_np.abs(r_drift - r0) > 0.002).sum())
        print(f"    Paint Gravity Drift pass complete (thick_px={n_thick} active_px={n_active})")

    def ryder_moonlit_sea_pass(
        self,
        dark_thresh:         float = 0.32,
        dark_power:          float = 1.80,
        dark_crush:          float = 0.40,
        light_thresh:        float = 0.64,
        light_power:         float = 1.50,
        light_lift:          float = 0.30,
        amber_center:        float = 0.40,
        amber_width:         float = 0.26,
        amber_r:             float = 0.14,
        amber_g:             float = 0.06,
        amber_b:             float = 0.10,
        amber_str:           float = 0.72,
        dissolution_sigma:   float = 2.20,
        dissolution_blend:   float = 0.22,
        opacity:             float = 0.85,
    ) -> None:
        """
        Ryder Moonlit Sea -- session 234: ONE HUNDRED AND FORTY-FIFTH distinct mode.

        Implements Albert Pinkham Ryder (1847-1910) visionary Tonalism technique.
        Ryder reduced sea and sky to bare elemental masses -- near-black water,
        pale luminous sky, a small incandescent moon -- and built his canvases up
        over years with thick paint and resinous varnish glazes, creating a dreaming,
        dissolving quality unlike any of his contemporaries.  His "Moonlit Cove"
        (c.1880-90) reduces the world to three tonal zones and a ghostly luminous
        presence.  His "Death on a Pale Horse" and "Jonah" push further into
        visionary hallucination.  Ryder's method: obsessive reworking with asphaltum
        and other bituminous mediums, causing his surfaces to craze and amber over
        time.  The hallmark: simplified masses, amber-ochre mid-tone tint from aged
        medium, and softened contours where forms dissolve into each other like shapes
        in a half-remembered dream.

        Three-stage mechanism:

        Stage 1 TONAL MASSING (zone-selective luminance pull):
          dark_gate  = clip((dark_thresh  - lum) / (dark_thresh  + 1e-6), 0, 1)^dark_power
          light_gate = clip((lum - light_thresh) / (1-light_thresh+1e-6), 0, 1)^light_power
          Shadows: R,G,B *= (1 - dark_gate * dark_crush)   -- pull darks to near-black
          Lights:  R,G,B += (1-ch) * light_gate * light_lift -- lift lights toward white

        Stage 2 AMBER OCHRE GLAZE (aged medium simulation):
          amber_gate = exp(-0.5 * ((lum - amber_center) / amber_width)^2)
          R += amber_r * amber_gate * amber_str
          G += amber_g * amber_gate * amber_str
          B -= amber_b * amber_gate * amber_str
          Bell curve centered at lum=0.40 (shadow-mid boundary).  Models the yellow-
          orange cast of Ryder's lead white and resinous medium as it aged over decades.

        Stage 3 VISIONARY DISSOLUTION (global form softening):
          R_blur, G_blur, B_blur = gaussian_filter(R, dissolution_sigma), etc.
          ch_out = ch_blur * dissolution_blend + ch_in * (1 - dissolution_blend)
          Isotropic low-pass blur blended back to dissolve hard contours globally,
          producing the dream-like, boundary-erasing quality of his later work.

        NOVEL vs. existing passes:
        (a) Zone-selective dual tonal pull: dark zones crushed independently of light zones
            being lifted -- not a global S-curve (distinct from tonal_compression_pass
            which applies a flat compression factor); first pass using separate power
            gates for dark-crush and light-lift simultaneously as two independent
            luminance-zone operations;
        (b) Bell-curve amber glaze at lum=0.40 (shadow-mid boundary): different from
            moreau_gilded_pass (bell at lum=0.60 for gold in mid-brights) and
            moreau_jeweled_ornament_pass (bell at lum=0.60 for grain) -- Ryder's
            amber was strongest at the transition from mid-tone to shadow, not in
            the upper mid-tones; B subtracted (not just R+G added) for ochre shift;
        (c) Global dissolution blur: first pass applying a uniform isotropic Gaussian
            blur composited at a low blend ratio for form dissolution;
            sfumato_veil_pass is edge-masked (blurs only at detected edges),
            hammershoi_grey_interior_pass applies blur within narrow luminance bands;
            this pass blurs the entire surface uniformly, creating Ryder's indistinct
            dream-like form merging.

        dark_thresh       : Luminance below which tonal crushing begins.
        dark_power        : Power exponent for shadow gate (higher = sharper boundary).
        dark_crush        : Fractional darkening multiplier in shadow zone (0-1).
        light_thresh      : Luminance above which tonal lifting begins.
        light_power       : Power exponent for highlight gate.
        light_lift        : Push-toward-white amplitude in highlight zone.
        amber_center      : Bell-curve centre luminance for amber glaze.
        amber_width       : Bell-curve sigma for amber glaze.
        amber_r/g/b       : R+, G+ and B- shift amounts for amber tint.
        amber_str         : Overall amplitude of amber glaze.
        dissolution_sigma : Gaussian sigma for form dissolution blur (pixels).
        dissolution_blend : Blend ratio of blurred-to-original (0=no blur, 1=full blur).
        opacity           : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Ryder Moonlit Sea pass (session 234 -- 145th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Tonal Massing — zone-selective dual luminance pull
        dt = float(dark_thresh)
        dp = float(dark_power)
        dc = float(dark_crush)
        dark_gate = _np.clip((dt - lum) / (dt + 1e-6), 0.0, 1.0) ** dp
        crush = 1.0 - dark_gate * dc
        r1 = _np.clip(r0 * crush, 0.0, 1.0)
        g1 = _np.clip(g0 * crush, 0.0, 1.0)
        b1 = _np.clip(b0 * crush, 0.0, 1.0)

        lt = float(light_thresh)
        lp = float(light_power)
        ll = float(light_lift)
        light_gate = _np.clip((lum - lt) / (1.0 - lt + 1e-6), 0.0, 1.0) ** lp
        r1 = _np.clip(r1 + (1.0 - r1) * light_gate * ll, 0.0, 1.0)
        g1 = _np.clip(g1 + (1.0 - g1) * light_gate * ll, 0.0, 1.0)
        b1 = _np.clip(b1 + (1.0 - b1) * light_gate * ll, 0.0, 1.0)

        # Stage 2: Amber Ochre Glaze — aged medium simulation (bell at lum=0.40)
        ac = float(amber_center)
        aw = float(amber_width)
        astr = float(amber_str)
        amber_gate = _np.exp(-0.5 * ((lum - ac) / (aw + 1e-6)) ** 2).astype(_np.float32)
        r2 = _np.clip(r1 + float(amber_r) * amber_gate * astr, 0.0, 1.0)
        g2 = _np.clip(g1 + float(amber_g) * amber_gate * astr, 0.0, 1.0)
        b2 = _np.clip(b1 - float(amber_b) * amber_gate * astr, 0.0, 1.0)

        # Stage 3: Visionary Dissolution — global form softening
        ds = float(dissolution_sigma)
        db = float(dissolution_blend)
        if ds > 0.1 and db > 0.01:
            r_blur = _gf(r2, ds).astype(_np.float32)
            g_blur = _gf(g2, ds).astype(_np.float32)
            b_blur = _gf(b2, ds).astype(_np.float32)
            r3 = r_blur * db + r2 * (1.0 - db)
            g3 = g_blur * db + g2 * (1.0 - db)
            b3 = b_blur * db + b2 * (1.0 - db)
        else:
            r3, g3, b3 = r2, g2, b2

        # Composite at opacity
        op = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r3 * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g3 * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b3 * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_dark   = int((dark_gate  > 0.15).sum())
        n_light  = int((light_gate > 0.10).sum())
        n_amber  = int((amber_gate > 0.20).sum())
        print(f"    Ryder Moonlit Sea complete "
              f"(dark_px={n_dark} light_px={n_light} amber_px={n_amber})")

    def paint_varnish_depth_pass(
        self,
        sat_center:       float = 0.45,
        sat_width:        float = 0.28,
        sat_boost:        float = 0.35,
        sheen_thresh:     float = 0.72,
        sheen_sigma:      float = 3.50,
        sheen_strength:   float = 0.06,
        opacity:          float = 0.70,
        seed:             int   = 234,
    ) -> None:
        """
        Paint Varnish Depth -- session 234 artistic improvement.

        Models the optical depth added by layers of picture varnish on a finished
        oil painting.  A well-varnished surface produces three observable effects:
        (1) dry mid-tone pigments are 'wetted', recovering their saturated chroma
        (varnish fills the micro-gaps that scatter light from dry paint, restoring
        the optically smooth surface that shows full colour); (2) the very brightest
        zones acquire a faint specular micro-sheen — coherent reflected light from
        the smooth resin surface; (3) the overall surface reads as slightly deeper
        and more unified, as surface scatter is reduced.

        Two-stage mechanism:

        Stage 1 SATURATION ENRICHMENT (dry pigment wetted by varnish):
          sat_gate = exp(-0.5 * ((lum - sat_center) / sat_width)^2)  -- bell at 0.45
          lum3 = 0.299*R + 0.587*G + 0.114*B
          sat_scale = 1 + sat_boost * sat_gate
          R_sat = clip(lum3 + (R - lum3) * sat_scale, 0, 1)
          Saturates the mid-tone zone (peaked at 0.45) while leaving shadows and
          highlights nearly unchanged -- matching the photometric reality that dry
          paint loses chroma most visibly in mid-tones.

        Stage 2 SPECULAR MICRO-SHEEN (glossy resin surface):
          noise_raw = gaussian_filter(standard_normal(h, w), sheen_sigma) -- smooth noise
          noise_norm = (noise_raw - noise_raw.min()) / (noise_raw.ptp() + 1e-6) * 2 - 1
          sheen_gate = clip((lum - sheen_thresh) / (1 - sheen_thresh + 1e-6), 0, 1)^2
          R,G,B += noise_norm * sheen_strength * sheen_gate
          Adds coherent Gaussian-smoothed noise micro-texture only in the near-white
          zone (lum > sheen_thresh), simulating the slight micro-unevenness of a
          varnish surface catching directional light.

        NOVEL vs. existing passes:
        (a) Bell-curve sat boost peaked at lum=0.45 (shadow-mid boundary):
            Explicitly models varnish's property of wetting dry pigment. Distinct from
            sorolla_mediterranean_light_pass warm_boost (bell at 0.62, models sunlit
            mid-tone zone), and from bonnard_chromatic_intimism_pass (global additive
            saturation scale, no luminance gating).  The 0.45 center targets the
            specific zone where dry-paint scatter is strongest;
        (b) Coherent Gaussian-noise sheen gated to near-white only (lum > 0.72):
            Distinct from moreau_jeweled_ornament_pass (grain bell at lum=0.60),
            dry_granulation_pass (grain in shadow zone lum < 0.45),
            bristle_separation_texture_pass (directional texture across all zones).
            This is the first pass applying smooth coherent noise exclusively in
            the near-white highlight zone to simulate glossy surface micro-texture.

        sat_center     : Bell-curve centre luminance for saturation wetness peak.
        sat_width      : Bell-curve sigma (spread) for saturation gate.
        sat_boost      : Maximum saturation scale boost at peak (0=none, 0.35=standard).
        sheen_thresh   : Luminance above which specular sheen applies.
        sheen_sigma    : Gaussian sigma for coherent noise generation (pixels).
        sheen_strength : Amplitude of sheen noise additive.
        opacity        : Final composite opacity.
        seed           : RNG seed for reproducible noise.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Paint Varnish Depth pass (session 234 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Saturation enrichment — varnish wets dry mid-tone pigment
        sc = float(sat_center)
        sw = float(sat_width)
        sb = float(sat_boost)
        sat_gate = _np.exp(-0.5 * ((lum - sc) / (sw + 1e-6)) ** 2).astype(_np.float32)
        lum3 = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        sat_scale = 1.0 + sb * sat_gate
        r1 = _np.clip(lum3 + (r0 - lum3) * sat_scale, 0.0, 1.0)
        g1 = _np.clip(lum3 + (g0 - lum3) * sat_scale, 0.0, 1.0)
        b1 = _np.clip(lum3 + (b0 - lum3) * sat_scale, 0.0, 1.0)

        # Stage 2: Specular micro-sheen — coherent Gaussian noise in near-white zones
        rng = _np.random.RandomState(int(seed))
        noise_raw = _gf(
            rng.standard_normal((h, w)).astype(_np.float32),
            float(sheen_sigma)
        ).astype(_np.float32)
        p_min, p_max = float(noise_raw.min()), float(noise_raw.max())
        if p_max - p_min > 1e-6:
            noise_norm = (noise_raw - p_min) / (p_max - p_min) * 2.0 - 1.0
        else:
            noise_norm = noise_raw * 0.0
        noise_norm = noise_norm.astype(_np.float32)

        st = float(sheen_thresh)
        ss = float(sheen_strength)
        sheen_gate = _np.clip(
            (lum - st) / (1.0 - st + 1e-6), 0.0, 1.0) ** 2
        r2 = _np.clip(r1 + noise_norm * ss * sheen_gate, 0.0, 1.0)
        g2 = _np.clip(g1 + noise_norm * ss * sheen_gate, 0.0, 1.0)
        b2 = _np.clip(b1 + noise_norm * ss * sheen_gate, 0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = _np.clip(r0 * (1.0 - op) + r2 * op, 0.0, 1.0)
        new_g = _np.clip(g0 * (1.0 - op) + g2 * op, 0.0, 1.0)
        new_b = _np.clip(b0 * (1.0 - op) + b2 * op, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_sat   = int((sat_gate  > 0.20).sum())
        n_sheen = int((sheen_gate > 0.10).sum())
        print(f"    Paint Varnish Depth pass complete (sat_px={n_sat} sheen_px={n_sheen})")

    def nolde_incandescent_surge_pass(
        self,
        shadow_ceil:       float = 0.30,
        shadow_power:      float = 1.80,
        shadow_r_push:     float = 0.10,
        shadow_b_drop:     float = 0.07,
        mid_center:        float = 0.50,
        mid_width:         float = 0.20,
        surge_boost:       float = 0.70,
        bloom_chroma_min:  float = 0.22,
        bloom_lum_min:     float = 0.38,
        bloom_sigma:       float = 3.50,
        bloom_warm_r:      float = 0.06,
        bloom_warm_g:      float = 0.03,
        bloom_warm_b:      float = 0.01,
        opacity:           float = 0.84,
    ) -> None:
        """
        Nolde Incandescent Surge -- session 235: ONE HUNDRED AND FORTY-SIXTH distinct mode.

        Implements Emil Nolde (1867-1956) incandescent colour-expressionism technique.
        Nolde, the great colourist of German Expressionism, painted with primordial colour
        force: his shadows glow warm (orange-red) against near-black voids, his mid-tones
        surge to full spectral intensity, and intense saturated zones radiate a luminous
        halo of warm light.  Crucially, Nolde INVERTS the academic warm-light / cool-shadow
        convention: his shadows are warm (fire and earth), his lights are often cooler or
        neutral.  He paints northern sea storms, florals of savage colour intensity, and
        barbaric figurative subjects with an almost spiritual chromatic violence.

        Three-stage mechanism, sharing one luminance and chroma map:

        Stage 1  SHADOW WARMTH INVERSION (inverted from academic convention):
          dark_gate = clip((shadow_ceil - lum) / shadow_ceil, 0, 1) ^ shadow_power
          R += dark_gate * shadow_r_push   [warm red push into shadows]
          B -= dark_gate * shadow_b_drop   [pull cool blue from shadow zones]
          Creates Nolde's characteristic warm-red ground in dark recesses --
          the OPPOSITE of academic painting where shadows are cool.
          Differs from warm_cool_zone_pass (which warms LIGHTS, cools SHADOWS).

        Stage 2  MID-TONE CHROMATIC SURGE (bell-curve at lum=0.50):
          mid_gate = exp(-0.5 * ((lum - mid_center) / mid_width)^2)
          ch_dev = ch - lum
          R,G,B = clip(lum + ch_dev * (1 + surge_boost * mid_gate), 0, 1)
          Bell-curve centred at lum=0.50 saturates mid-tone colours toward their
          most intense spectral expression -- Nolde's mid-tones are maximum-chroma,
          never grey.  Peak at lum=0.50 is distinct from Moreau's penumbra bell
          at lum=0.28 (s232) and from Chagall's chroma-gate approach (s234).

        Stage 3  VIVID BLOOM HALATION (dual chroma+lum gate):
          vivid_mask = clip((chroma - bloom_chroma_min) / 0.30, 0, 1)
                     * clip((lum_post - bloom_lum_min) / 0.30, 0, 1)
          bloom_halo = gaussian_filter(vivid_mask, bloom_sigma)
          R,G,B += bloom_halo * bloom_warm_r/g/b
          Intense saturated AND luminous zones radiate a warm halation into
          surrounding areas -- models Nolde's incandescent glow quality where
          vivid colour zones seem to emit warm light.  Requires BOTH high chroma
          AND sufficient luminance (dual gate), preventing bloom in vivid-but-dark
          zones (e.g. deep saturated shadows).

        NOVEL vs. existing passes:
        (a) Shadow warmth inversion: dark zones pushed WARM (R+, B-) while lights
            stay cool/neutral -- the OPPOSITE of warm_cool_zone_pass which follows
            academic convention; no prior pass inverts the warm/cool temperature
            relationship between lights and shadows;
        (b) Mid-tone bell-curve chromatic surge at lum=0.50: chroma gate targets
            lum=0.50 (true mid-tones) -- distinct from chagall_lyrical_dream_pass
            (s234) which uses max-min chroma as gate (not luminance) and from
            chromatic_chiaroscuro_pass (s234) which uses lum=0.28 (penumbra);
        (c) Dual chroma+lum gated bloom halation: requires BOTH high chroma AND
            sufficient luminance -- no prior bloom/corona pass uses this dual gate
            (kuindzhi_moonlit_radiance s233 gates corona on lum alone; warm_highlight_
            bloom and radiance_bloom also gate on lum alone).

        shadow_ceil      : Luminance ceiling for shadow warmth inversion.
        shadow_power     : Power exponent for shadow gate (higher = steeper falloff).
        shadow_r_push    : Red channel boost in shadow zones (warmth).
        shadow_b_drop    : Blue channel reduction in shadow zones (warmth).
        mid_center       : Luminance centre of mid-tone chromatic surge bell.
        mid_width        : Standard deviation (sigma) of the surge bell-curve.
        surge_boost      : Peak saturation multiplier in the surge zone.
        bloom_chroma_min : Minimum chroma for vivid bloom trigger.
        bloom_lum_min    : Minimum luminance for vivid bloom trigger.
        bloom_sigma      : Gaussian blur sigma for bloom halation spread.
        bloom_warm_r     : Red channel component of bloom warm tint.
        bloom_warm_g     : Green channel component of bloom warm tint.
        bloom_warm_b     : Blue channel component of bloom warm tint.
        opacity          : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Nolde Incandescent Surge pass (session 235 -- 146th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Shadow Warmth Inversion
        sc  = float(shadow_ceil)
        sp  = float(shadow_power)
        srp = float(shadow_r_push)
        sbd = float(shadow_b_drop)
        dark_gate = _np.clip((sc - lum) / (sc + 1e-6), 0.0, 1.0) ** sp
        r1 = _np.clip(r0 + dark_gate * srp, 0.0, 1.0)
        g1 = g0
        b1 = _np.clip(b0 - dark_gate * sbd, 0.0, 1.0)

        # Stage 2: Mid-tone Chromatic Surge (bell-curve at mid_center)
        mc  = float(mid_center)
        mw  = float(mid_width)
        sb  = float(surge_boost)
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        mid_gate = _np.exp(-0.5 * ((lum1 - mc) / (mw + 1e-6)) ** 2).astype(_np.float32)
        scale = 1.0 + sb * mid_gate
        r2 = _np.clip(lum1 + (r1 - lum1) * scale, 0.0, 1.0)
        g2 = _np.clip(lum1 + (g1 - lum1) * scale, 0.0, 1.0)
        b2 = _np.clip(lum1 + (b1 - lum1) * scale, 0.0, 1.0)

        # Stage 3: Vivid Bloom Halation (dual chroma + lum gate)
        bcm  = float(bloom_chroma_min)
        blm  = float(bloom_lum_min)
        bsig = float(bloom_sigma)
        bwr  = float(bloom_warm_r)
        bwg  = float(bloom_warm_g)
        bwb  = float(bloom_warm_b)
        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        chroma2 = (_np.maximum(_np.maximum(r2, g2), b2)
                   - _np.minimum(_np.minimum(r2, g2), b2)).astype(_np.float32)
        chroma_gate = _np.clip((chroma2 - bcm) / (0.30 + 1e-6), 0.0, 1.0)
        lum_gate    = _np.clip((lum2 - blm)   / (0.30 + 1e-6), 0.0, 1.0)
        vivid_mask  = (chroma_gate * lum_gate).astype(_np.float32)
        bloom_halo  = _gf(vivid_mask, bsig).astype(_np.float32)
        r3 = _np.clip(r2 + bloom_halo * bwr, 0.0, 1.0)
        g3 = _np.clip(g2 + bloom_halo * bwg, 0.0, 1.0)
        b3 = _np.clip(b2 + bloom_halo * bwb, 0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_dark   = int((dark_gate > 0.20).sum())
        n_mid    = int((mid_gate > 0.30).sum())
        n_bloom  = int((bloom_halo > 0.05).sum())
        print(f"    Nolde Incandescent Surge complete "
              f"(dark_px={n_dark} mid_px={n_mid} bloom_px={n_bloom})")

    def paint_pigment_granulation_pass(
        self,
        coarse_sigma:   float = 6.00,
        fine_sigma:     float = 1.20,
        coarse_weight:  float = 0.60,
        fine_weight:    float = 0.40,
        chroma_min:     float = 0.10,
        granule_depth:  float = 0.08,
        valley_r_push:  float = 0.025,
        valley_g_push:  float = 0.012,
        opacity:        float = 0.55,
    ) -> None:
        """
        Pigment Granulation -- session 235 artistic improvement.

        Simulates the characteristic granulation of mineral pigments in wet watercolour
        technique.  Certain heavy-particle pigments (French Ultramarine, Burnt Sienna,
        Manganese Blue, Raw Umber) granulate as they dry: heavy pigment particles settle
        into the paper's micro-valleys while the liquid medium carries finer particles
        to surface peaks, creating a distinctive stippled/mottled clumping texture within
        colour washes.  This pass models the physical settling process:

        Stage 1  MULTI-SCALE GRANULATION TEXTURE:
          coarse_field = gaussian_filter(uniform_noise, coarse_sigma)
          fine_field   = gaussian_filter(uniform_noise_2, fine_sigma)
          granulation  = coarse_weight * coarse_field + fine_weight * fine_field
          [both fields normalised to [-1, 1] before weighting]
          Two independent noise fields at different scales are blended to model the
          two-level structure of granulation: coarse pigment clusters (coarse_sigma)
          within a finer random distribution (fine_sigma).  Multi-scale composition
          is physically motivated -- mineral pigments form clusters of varying sizes.

        Stage 2  CHROMA GATING (more pigment = more granulation):
          chroma = max(R,G,B) - min(R,G,B)
          chroma_gate = clip((chroma - chroma_min) / (1 - chroma_min), 0, 1)
          [low-chroma/neutral areas granulate less: less mineral pigment present]
          Granulation is gated by local chroma -- heavily pigmented (saturated)
          areas granulate more intensely than neutral washes.  Physically correct:
          granulation arises from heavy pigment particles, so neutral near-grey
          areas (low chroma) are mostly binder/gum with little heavy pigment.

        Stage 3  PEAK/VALLEY VALUE VARIATION + VALLEY WARM TINT:
          grain_gated = granulation * chroma_gate
          [peaks: grain_gated > 0 -- slightly lighter (pigment on paper surface)]
          [valleys: grain_gated < 0 -- slightly darker + warm push]
          peak_mask   = clip(grain_gated, 0, 1)
          valley_mask = clip(-grain_gated, 0, 1)
          R,G,B += peak_mask * granule_depth          [lighter peaks]
          R,G,B -= valley_mask * granule_depth        [darker valleys]
          R += valley_mask * valley_r_push            [warm orange-brown valley tint]
          G += valley_mask * valley_g_push            [warm green-earth valley tint]
          Valley tint models the specific property of granulating earth pigments:
          Burnt Sienna and Raw Umber valley-clumps have a characteristic warm
          orange-brown colour distinct from the overall wash hue.

        NOVEL vs. existing passes:
        (a) Dual-frequency coherent noise (coarse_sigma=6 px clusters + fine_sigma=1.2 px
            granules): first pass to use two independent Gaussian-filtered noise fields
            at different scales composed additively; canvas_grain_pass uses a single
            Gaussian-filtered noise; film_grain_overlay_pass uses a single Gaussian noise
            with uniform distribution; no prior pass uses multi-scale noise composition;
        (b) Chroma gating for granulation texture (higher chroma = more grain): physically
            motivated by pigment particle density; prior texture passes (canvas_grain_pass,
            film_grain_overlay_pass) gate on luminance or apply uniformly, not on chroma;
        (c) Directional valley warm tint: valley zones (dark granulation clumps) receive
            a separate warm push (valley_r_push, valley_g_push) modelling the specific
            hue of mineral pigment clumps distinct from the host wash -- no prior texture
            pass applies a hue-shifted tint selectively to the dark granulation zones.

        coarse_sigma   : Gaussian sigma for coarse-scale pigment cluster noise.
        fine_sigma     : Gaussian sigma for fine-scale individual-granule noise.
        coarse_weight  : Blend weight of the coarse field (0-1).
        fine_weight    : Blend weight of the fine field (0-1).
        chroma_min     : Minimum chroma threshold below which granulation is suppressed.
        granule_depth  : Amplitude of the light/dark value variation (0-1).
        valley_r_push  : Red channel boost in dark valley granulation zones.
        valley_g_push  : Green channel boost in dark valley granulation zones.
        opacity        : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Pigment Granulation pass (session 235 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        rng = _np.random.default_rng(seed=137)

        # Stage 1: Multi-scale granulation texture
        cs = float(coarse_sigma)
        fs = float(fine_sigma)
        cw = float(coarse_weight)
        fw = float(fine_weight)
        noise_c_raw = rng.uniform(0.0, 1.0, (h, w)).astype(_np.float32)
        noise_f_raw = rng.uniform(0.0, 1.0, (h, w)).astype(_np.float32)
        coarse_field = _gf(noise_c_raw, cs)
        fine_field   = _gf(noise_f_raw, fs)
        # Normalise each to [-1, 1]
        def _norm(field):
            mn, mx = field.min(), field.max()
            span = mx - mn + 1e-8
            return (field - mn) / span * 2.0 - 1.0
        coarse_norm = _norm(coarse_field)
        fine_norm   = _norm(fine_field)
        granulation = (cw * coarse_norm + fw * fine_norm).astype(_np.float32)
        # Re-normalise combined field to [-1, 1]
        granulation = _norm(granulation)

        # Stage 2: Chroma gating
        cm_min = float(chroma_min)
        chroma = (_np.maximum(_np.maximum(r0, g0), b0)
                  - _np.minimum(_np.minimum(r0, g0), b0)).astype(_np.float32)
        chroma_gate = _np.clip((chroma - cm_min) / (1.0 - cm_min + 1e-6), 0.0, 1.0)
        grain_gated = granulation * chroma_gate

        # Stage 3: Peak/valley variation + valley warm tint
        gd  = float(granule_depth)
        vrp = float(valley_r_push)
        vgp = float(valley_g_push)
        peak_mask   = _np.clip(grain_gated,  0.0, 1.0)
        valley_mask = _np.clip(-grain_gated, 0.0, 1.0)
        r1 = _np.clip(r0 + peak_mask * gd - valley_mask * gd + valley_mask * vrp,
                      0.0, 1.0)
        g1 = _np.clip(g0 + peak_mask * gd - valley_mask * gd + valley_mask * vgp,
                      0.0, 1.0)
        b1 = _np.clip(b0 + peak_mask * gd - valley_mask * gd, 0.0, 1.0)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_peak   = int((peak_mask > 0.10).sum())
        n_valley = int((valley_mask > 0.10).sum())
        n_chroma = int((chroma_gate > 0.20).sum())
        print(f"    Pigment Granulation complete "
              f"(peak_px={n_peak} valley_px={n_valley} chroma_px={n_chroma})")

    def kupka_orphic_fugue_pass(
        self,
        *,
        hue_amplitude:   float = 0.12,
        hue_period_frac: float = 0.28,
        hue_phase:       float = 0.0,
        centroid_thresh: float = 0.55,
        chroma_boost:    float = 0.28,
        mid_lum_center:  float = 0.52,
        mid_lum_width:   float = 0.22,
        opacity:         float = 0.82,
    ) -> None:
        """
        Kupka Orphic Fugue -- session 236: ONE HUNDRED AND FORTY-SEVENTH distinct mode.

        Implements Frantisek Kupka (1871-1957), Czech-French pioneer of pure
        abstraction and originator of Orphism.  Kupka's 'Amorpha: Fugue in Two
        Colors' (1912) and 'Vertical Planes in Blue and Red' (1913) use repeating
        colour themes radiating from a luminous focus -- a 'colour fugue' where
        hue rotates periodically outward from the compositional centre, like
        concentric rings of a musical canon.  Unlike Delaunay's multi-disk
        complementary pairs, Kupka's fugue is a SINGLE RADIAL OSCILLATION of
        hue across the whole canvas, creating chromatic rhythm from one focal point.

        TWO-STAGE mechanism operating entirely in HSV colour space:

        Stage 1  RADIAL HUE FUGUE (concentric hue oscillation):
          (a) Luminance centroid: cx, cy = sum(x * lum^2) / sum(lum^2) -- the
              weighted centre of luminous pixels anchors the fugue focus.
          (b) Radial distance field: r_norm = sqrt((x-cx)^2 + (y-cy)^2) / min(w,h)
          (c) Hue rotation field: delta_H = hue_amplitude * sin(2pi * r_norm /
              hue_period_frac + hue_phase) -- sinusoidal oscillation of hue
              around its original value, period set as fraction of image width.
          (d) Apply to HSV hue channel: H_out = (H_in + delta_H) mod 1.0
          Warm hues (reds, oranges) cycle through cool (blues, greens) and back,
          creating Kupka's characteristic concentric colour-ring fugue structure.

        Stage 2  CHROMATIC INTENSITY SURGE (mid-tone saturation amplification):
          bell = exp(-0.5 * ((V - mid_lum_center) / mid_lum_width)^2)
          S_out = clip(S_in * (1 + chroma_boost * bell), 0, 1)
          Bell centred at V=0.52 (true mid-value zone) drives mid-tone colours
          toward their most intense expression -- Kupka's 'colour without
          compromise' aesthetic; pure hues at maximum saturation, no neutrals.

        NOVEL vs. all existing passes:
        (a) FIRST pass to operate in HSV colour space and apply HUE ROTATION as
            its primary operation.  All prior chromatic passes (Nolde shadow
            warmth inversion, Delaunay ring fields, Delacroix complementary
            vibration, warm_cool_zone_pass, chagall_lyrical_dream, etc.) add or
            subtract fixed RGB offsets or scale RGB channel deviations -- none
            rotates the hue wheel.  HSV hue rotation is fundamentally different:
            it shifts ALL saturated pixels along the colour wheel simultaneously,
            preserving their value and saturation while cycling their hue.
        (b) LUMINANCE-CENTROID radial field: the radial origin is the luminosity-
            weighted compositional focus (centroid of lum^2), NOT the geometric
            centre or a fixed point.  This makes the fugue naturally orbit the
            most luminous element (light source, bright face, etc.).  Delaunay's
            orphist_disk_pass uses a golden-angle spiral of MULTIPLE independent
            centres each with separate complementary pairs; this pass uses ONE
            centroid with a continuous sinusoidal rotation.
        (c) Hue rotation PERIOD as fraction of image diagonal, making the fugue
            scale correctly with image dimensions.

        hue_amplitude   : Max hue rotation (0-1 hue-wheel scale; 0.12 ~ 43 deg).
        hue_period_frac : Spatial period of hue oscillation as fraction of
                          min(W,H) -- smaller = more concentric rings.
        hue_phase       : Phase offset for the sinusoidal cycle (radians).
        centroid_thresh : Luminance threshold used to weight the centroid.
        chroma_boost    : Maximum saturation scale-up at the bell peak.
        mid_lum_center  : Value (luminance) at the centre of the saturation bell.
        mid_lum_width   : Width (sigma) of the saturation bell in value units.
        opacity         : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        import math as _math

        print("    Kupka Orphic Fugue pass (session 236 -- 147th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        # Cairo stores BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Radial hue fugue ────────────────────────────────────────
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Luminance-weighted centroid (centroid of bright pixels)
        ct = float(centroid_thresh)
        weight = _np.clip((lum - ct) / (1.0 - ct + 1e-7), 0.0, 1.0) ** 2
        w_sum = float(weight.sum()) + 1e-12
        yy, xx = _np.mgrid[0:h, 0:w]
        cx = float((xx * weight).sum()) / w_sum
        cy = float((yy * weight).sum()) / w_sum

        # Radial distance field normalised by min(w, h)
        r_norm = _np.sqrt(((xx - cx) / min(w, h)) ** 2
                          + ((yy - cy) / min(w, h)) ** 2).astype(_np.float32)

        # Hue rotation field: sinusoidal wave outward from centroid
        tp = float(hue_period_frac)
        phase = float(hue_phase)
        delta_H = (float(hue_amplitude)
                   * _np.sin(2.0 * _math.pi * r_norm / tp + phase)
                   ).astype(_np.float32)

        # RGB → HSV (vectorised)
        Cmax = _np.maximum(_np.maximum(r0, g0), b0)
        Cmin = _np.minimum(_np.minimum(r0, g0), b0)
        delta_c = Cmax - Cmin

        V = Cmax
        S = _np.where(Cmax > 1e-7, delta_c / _np.maximum(Cmax, 1e-7),
                      0.0).astype(_np.float32)

        safe_d = _np.maximum(delta_c, 1e-7)
        H_r = ((g0 - b0) / safe_d) % 6.0
        H_g = (b0 - r0) / safe_d + 2.0
        H_b = (r0 - g0) / safe_d + 4.0
        is_r = (Cmax == r0)
        is_g = (~is_r) & (Cmax == g0)
        H_raw = _np.where(is_r, H_r, _np.where(is_g, H_g, H_b)) / 6.0
        H = _np.where(delta_c > 1e-7, H_raw % 1.0, 0.0).astype(_np.float32)

        # Apply hue rotation (stays in [0, 1))
        H_out = (H + delta_H) % 1.0

        # ── Stage 2: Chromatic intensity surge (bell saturation boost) ───────
        bell = _np.exp(-0.5 * ((V - float(mid_lum_center))
                               / float(mid_lum_width)) ** 2).astype(_np.float32)
        S_out = _np.clip(S * (1.0 + float(chroma_boost) * bell), 0.0, 1.0)

        # HSV → RGB (vectorised)
        H6 = H_out * 6.0
        I = _np.floor(H6).astype(_np.int32) % 6
        f = (H6 - _np.floor(H6)).astype(_np.float32)
        p = (V * (1.0 - S_out)).astype(_np.float32)
        q = (V * (1.0 - f * S_out)).astype(_np.float32)
        t = (V * (1.0 - (1.0 - f) * S_out)).astype(_np.float32)

        r1 = _np.where(I==0, V, _np.where(I==1, q, _np.where(I==2, p,
             _np.where(I==3, p, _np.where(I==4, t, V))))).astype(_np.float32)
        g1 = _np.where(I==0, t, _np.where(I==1, V, _np.where(I==2, V,
             _np.where(I==3, q, _np.where(I==4, p, p))))).astype(_np.float32)
        b1 = _np.where(I==0, p, _np.where(I==1, p, _np.where(I==2, t,
             _np.where(I==3, V, _np.where(I==4, V, q))))).astype(_np.float32)

        # Composite at opacity
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_rotated = int(((_np.abs(delta_H) > 0.04) & (S > 0.08)).sum())
        n_boosted = int((bell > 0.5).sum())
        print(f"    Kupka Orphic Fugue complete "
              f"(rotated_px={n_rotated} boosted_px={n_boosted} "
              f"centroid=({cx:.1f},{cy:.1f}))")

    def paint_medium_pooling_pass(
        self,
        *,
        pool_size:     int   = 5,
        pool_depth:    float = 0.045,
        pool_sat_lift: float = 0.14,
        pool_thresh:   float = 0.035,
        pool_power:    float = 0.75,
        opacity:       float = 0.62,
    ) -> None:
        """
        Paint Medium Pooling -- session 236 artistic improvement.

        Models the physical pooling of drying oil medium (linseed, stand oil) in
        the valleys between impasto brush strokes.  Oil medium flows by gravity
        and surface tension into the low points of the paint topography as it
        dries over hours.  In these 'pools' the paint is:
          (a) Slightly DARKER -- medium pooling deepens apparent colour depth.
          (b) More SATURATED -- wet pooled medium refracts more light, restoring
              the vivid colour that dry unpooled pigment loses.
        This effect is clearly visible in close examination of old master oil
        surfaces -- the low points between strokes retain a glossy, darker,
        more saturated appearance compared to the adjacent dry ridges.

        THREE-STAGE MORPHOLOGICAL MODEL:

        Stage 1  VALLEY DETECTION via morphological erosion:
          eroded = grey_erosion(lum, size=pool_size)  [local minimum field]
          valley_depth = lum - eroded                 [distance above local min]
          valley_gate = clip(1 - valley_depth/pool_thresh, 0, 1)^pool_power
          Pixels where valley_depth is SMALL (near the local minimum) are the
          actual paint valleys -- where medium pools.  Note: we are looking for
          pixels that ARE near the floor, not far above it.

        Stage 2  VALLEY DARKENING:
          R,G,B *= (1 - pool_depth * valley_gate)
          Attenuates all channels equally -- pooled medium does not shift hue,
          only darkens by increasing optical path through the medium layer.

        Stage 3  VALLEY SATURATION ENRICHMENT:
          lum3 = 0.299R + 0.587G + 0.114B (after darkening)
          R,G,B = clip(lum3 + (R,G,B - lum3) * (1 + pool_sat_lift * valley_gate))
          Boosts chroma in valleys -- refracting medium 'brings back' the
          saturation lost to dry pigment scatter, exactly as wetting a dry
          pigment cake reveals its true colour.

        NOVEL vs. existing improvement passes:
        (a) MORPHOLOGICAL EROSION (grey_erosion) -- FIRST improvement pass using
            a morphological operator.  All prior passes use Gaussian smoothing,
            Sobel edges, or additive noise.  grey_erosion provides a local-minimum
            field that is mathematically distinct from any filter used so far.
        (b) VALLEY-GATE METRIC: we detect pixels by their PROXIMITY TO LOCAL
            MINIMUM (valley_depth small), not by gradient magnitude (Sobel) or
            luminance threshold.  A pixel can be dark AND a valley, or mid-tone
            AND a valley, so this is orthogonal to luminance gating.
        (c) CO-LOCATED DARKENING + SATURATION BOOST in the valley zone models
            the two simultaneous effects of pooled medium (depth darkening and
            saturation restoration) as a single physically motivated pass.
            impasto_relief_pass applies directional Sobel relief independently.
            paint_varnish_depth_pass applies saturation at mid-lum without valley
            detection.  paint_pigment_granulation_pass uses chroma (not valley)
            for gating.  None of these capture the valley-specific dual effect.

        pool_size     : Morphological erosion kernel size (pixels; larger = wider
                        valleys detected).
        pool_depth    : Maximum luminance attenuation in valley zones [0, 0.15].
        pool_sat_lift : Maximum saturation boost in valley zones [0, 0.35].
        pool_thresh   : Valley depth threshold -- larger means less of the image
                        qualifies as 'in a valley'.
        pool_power    : Power exponent on the valley gate (higher = sharper cutoff).
        opacity       : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import grey_erosion as _erode

        print("    Paint Medium Pooling pass (session 236 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Valley detection via morphological erosion
        ps = int(pool_size)
        eroded = _erode(lum, size=ps).astype(_np.float32)
        valley_depth = (lum - eroded).astype(_np.float32)
        pt = float(pool_thresh)
        valley_gate = _np.clip(
            1.0 - valley_depth / (pt + 1e-7), 0.0, 1.0
        ) ** float(pool_power)

        # Stage 2: Valley darkening
        pd = float(pool_depth)
        r1 = _np.clip(r0 * (1.0 - pd * valley_gate), 0.0, 1.0)
        g1 = _np.clip(g0 * (1.0 - pd * valley_gate), 0.0, 1.0)
        b1 = _np.clip(b0 * (1.0 - pd * valley_gate), 0.0, 1.0)

        # Stage 3: Valley saturation enrichment
        ps2 = float(pool_sat_lift)
        lum3 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        lum3_3 = lum3[:, :, _np.newaxis]
        sat_scale = 1.0 + ps2 * valley_gate
        r2 = _np.clip(lum3 + (r1 - lum3) * sat_scale, 0.0, 1.0)
        g2 = _np.clip(lum3 + (g1 - lum3) * sat_scale, 0.0, 1.0)
        b2 = _np.clip(lum3 + (b1 - lum3) * sat_scale, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_valley = int((valley_gate > 0.2).sum())
        n_dark   = int((valley_gate > 0.5).sum())
        print(f"    Paint Medium Pooling complete "
              f"(valley_px={n_valley} deep_valley_px={n_dark})")
    def rouault_stained_glass_pass(
        self,
        contour_thresh: float = 0.18,
        contour_depth:  float = 0.72,
        contour_power:  float = 1.8,
        lead_cool:      float = 0.08,
        jewel_boost:    float = 0.55,
        opacity:        float = 0.82,
    ) -> None:
        r"""
        Rouault Stained Glass -- session 237: ONE HUNDRED AND FORTY-EIGHTH distinct mode.

        Implements Georges Rouault (1871-1958) Expressionist stained-glass aesthetic.
        Three stages unified by a single Sobel gradient magnitude map:

        Stage 1 CONTOUR DETECTION via Sobel derivative:
        sx = sobel(lum, axis=1); sy = sobel(lum, axis=0);
        grad = sqrt(sx^2 + sy^2); grad_norm = clip(grad/contour_thresh, 0, 1);
        contour_gate = grad_norm^contour_power.
        FIRST pass in project to use a spatial derivative (Sobel operator) as
        its primary tool -- all prior passes use luminance thresholds, chroma
        gates, bell-curve functions, or morphological operators.

        Stage 2 CONTOUR DARKENING + LEAD-LINE COOL TINT:
        R,G,B *= (1 - contour_depth * contour_gate).
        Then shift boundary toward blue-grey of raw lead came:
        R -= contour_gate * lead_cool * 0.60;
        G -= contour_gate * lead_cool * 0.30;
        B += contour_gate * lead_cool.
        No prior pass darkens by gradient magnitude.

        Stage 3 INTERIOR JEWEL SATURATION (inverse gradient gate):
        interior_gate = clip(1 - grad_norm, 0, 1);
        sat_scale = 1 + jewel_boost * interior_gate;
        ch = lum + (ch - lum) * sat_scale.
        INVERSE GRADIENT GATE: contour zones darkened, interior zones saturated.

        NOVEL vs. existing passes:
        (a) SOBEL GRADIENT as primary spatial operator (first derivative-based pass).
        (b) CONTOUR DARKENING by gradient magnitude (no prior pass does this).
        (c) INVERSE GRADIENT GATE for interior saturation (complementary dual).
        (d) LEAD-LINE COOL TINT at contour peaks (blue-grey shift of lead came).

        contour_thresh : Gradient magnitude at which contour_gate saturates.
        contour_depth  : Maximum darkening factor in contour zones [0, 1].
        contour_power  : Power exponent on contour gate (higher = sharper lines).
        lead_cool      : Blue-grey cool shift at maximum contour [0, 0.12].
        jewel_boost    : Saturation multiplier in interior zones [0, 0.8].
        opacity        : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel

        print("    Rouault Stained Glass pass (session 237 -- 148th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Sobel gradient magnitude
        sx = _sobel(lum, axis=1).astype(_np.float32)
        sy = _sobel(lum, axis=0).astype(_np.float32)
        grad = _np.sqrt(sx ** 2 + sy ** 2)
        ct = float(contour_thresh)
        grad_norm = _np.clip(grad / (ct + 1e-7), 0.0, 1.0)
        cp = float(contour_power)
        contour_gate = grad_norm ** cp

        # Stage 2: Contour darkening + lead-line cool tint
        cd = float(contour_depth)
        r1 = _np.clip(r0 * (1.0 - cd * contour_gate), 0.0, 1.0)
        g1 = _np.clip(g0 * (1.0 - cd * contour_gate), 0.0, 1.0)
        b1 = _np.clip(b0 * (1.0 - cd * contour_gate), 0.0, 1.0)
        lc = float(lead_cool)
        r2 = _np.clip(r1 - contour_gate * lc * 0.60, 0.0, 1.0)
        g2 = _np.clip(g1 - contour_gate * lc * 0.30, 0.0, 1.0)
        b2 = _np.clip(b1 + contour_gate * lc,         0.0, 1.0)

        # Stage 3: Interior jewel saturation
        interior_gate = _np.clip(1.0 - grad_norm, 0.0, 1.0)
        jb = float(jewel_boost)
        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        sat_scale = 1.0 + jb * interior_gate
        r3 = _np.clip(lum2 + (r2 - lum2) * sat_scale, 0.0, 1.0)
        g3 = _np.clip(lum2 + (g2 - lum2) * sat_scale, 0.0, 1.0)
        b3 = _np.clip(lum2 + (b2 - lum2) * sat_scale, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_contour  = int((contour_gate > 0.3).sum())
        n_interior = int((interior_gate > 0.7).sum())
        print(f"    Rouault Stained Glass complete "
              f"(contour_px={n_contour} interior_px={n_interior})")

    def paint_scumble_pass(
        self,
        bristle_sigma:  float = 0.75,
        bristle_thresh: float = 0.60,
        scumble_lift:   float = 0.13,
        cool_tint:      float = 0.055,
        lum_gate_low:   float = 0.25,
        lum_gate_high:  float = 0.85,
        opacity:        float = 0.46,
        seed:           int   = 237,
    ) -> None:
        r"""
        Paint Scumble -- session 237 improvement.

        Scumbling: a nearly-dry brush loaded with semi-opaque lighter paint is
        dragged roughly over a darker underpainting, catching on canvas texture
        peaks and skipping valleys, revealing the underlayer in a broken pattern.

        THREE-STAGE SCUMBLE SIMULATION:

        Stage 1 SPARSE BRISTLE MASK: uniform noise smoothed at bristle_sigma,
        normalised to [0,1], then thresholded at bristle_thresh to produce a
        near-binary sparse mask of bristle contact zones.  FIRST in project to
        use a thresholded binary noise mask -- all prior noise passes use
        continuous noise (film_grain, pigment_granulation).

        Stage 2 LUMINANCE GATE: scumbling concentrates in mid-to-upper luminance
        zones (shadows are too dark to lift significantly).
        lum_gate = clip((lum - lum_gate_low)/(lum_gate_high - lum_gate_low), 0, 1).
        combined_gate = bristle_mask * lum_gate.

        Stage 3 SCUMBLE DEPOSIT: cool asymmetric channel lift in gate zones:
        R += gate * scumble_lift * 0.82;
        G += gate * scumble_lift * 0.92;
        B += gate * (scumble_lift + cool_tint).
        Models thin cool dry-paint deposit catching on texture peaks.

        NOVEL vs. existing passes:
        (a) SPARSE THRESHOLDED NOISE bristle pattern (binary vs. continuous).
        (b) LUMINANCE-GATED POSITIVE LIFT (distinct from impasto, varnish, granulation).
        (c) COOL ASYMMETRIC CHANNEL LIFT via sparse binary gate.

        bristle_sigma  : Gaussian blur sigma for noise smoothing.
        bristle_thresh : Threshold for binarising the noise [0.5-0.7 typical].
        scumble_lift   : Maximum luminance lift in bristle zones [0, 0.20].
        cool_tint      : Additional blue lift over scumble_lift [0, 0.10].
        lum_gate_low   : Luminance below which scumbling has no effect.
        lum_gate_high  : Luminance above which scumbling is at full effect.
        opacity        : Final composite opacity.
        seed           : RNG seed for reproducibility.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Paint Scumble pass (session 237 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Sparse bristle mask via thresholded noise
        rng = _np.random.RandomState(int(seed))
        noise = rng.uniform(0.0, 1.0, (h, w)).astype(_np.float32)
        smoothed = _gf(noise, float(bristle_sigma))
        sn_min = float(smoothed.min())
        sn_max = float(smoothed.max())
        smoothed = (smoothed - sn_min) / (sn_max - sn_min + 1e-7)
        bristle_mask = (smoothed > float(bristle_thresh)).astype(_np.float32)

        # Stage 2: Luminance gate
        low  = float(lum_gate_low)
        high = float(lum_gate_high)
        lum_gate = _np.clip((lum - low) / (high - low + 1e-7), 0.0, 1.0)
        gate = bristle_mask * lum_gate

        # Stage 3: Scumble deposit (cool asymmetric channel lift)
        sl = float(scumble_lift)
        ct = float(cool_tint)
        r1 = _np.clip(r0 + gate * sl * 0.82, 0.0, 1.0)
        g1 = _np.clip(g0 + gate * sl * 0.92, 0.0, 1.0)
        b1 = _np.clip(b0 + gate * (sl + ct), 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_bristle = int((bristle_mask > 0.5).sum())
        n_active  = int((gate > 0.2).sum())
        print(f"    Paint Scumble complete "
              f"(bristle_px={n_bristle} active_px={n_active})")
    def feininger_crystalline_prism_pass(
        self,
        facet_sigma:   float = 8.0,
        prism_cycles:  float = 3.0,
        chroma_tilt:   float = 0.10,
        lum_facet:     float = 0.06,
        opacity:       float = 0.72,
    ) -> None:
        r"""
        Feininger Crystalline Prism -- session 238: ONE HUNDRED AND FORTY-NINTH distinct mode.

        Implements Lyonel Feininger (1871-1956) Cubist-Expressionist crystalline
        aesthetic.  Feininger organised his canvases as interlocking angular planes
        of subtly differentiated atmospheric colour, each planar zone catching light
        from a slightly different directional angle -- the structural logic of a
        crystal face illuminated by directional light.

        TWO-STAGE CRYSTALLINE FACET SIMULATION unified by gradient direction angle:

        Stage 1 COHERENT ANGLE MAP via circular Gaussian averaging:
        sx = sobel(lum, axis=1); sy = sobel(lum, axis=0);
        angle = atan2(sy, sx) in [-pi, pi].
        Circular averaging (correct for angle arithmetic -- not affected by
        the 2*pi wraparound discontinuity):
        z_cos = gaussian(cos(angle), facet_sigma);
        z_sin = gaussian(sin(angle), facet_sigma);
        coherent_angle = atan2(z_sin, z_cos).
        FIRST pass in project to use spatial gradient DIRECTION (atan2) as its
        primary variable -- all prior Sobel-based passes (e.g. rouault_stained_glass)
        use gradient MAGNITUDE only.  FIRST use of circular/angular Gaussian
        blurring via complex-exponential decomposition.

        Stage 2 PRISMATIC WARM/COOL CHROMATIC MAPPING:
        warm_cool = cos(coherent_angle * prism_cycles) in [-1, 1].
        lum_mod   = sin(coherent_angle * prism_cycles + pi/6) * lum_facet.
        Channel adjustments:
        R += warm_cool * ct * 0.78 + lum_mod;
        G += warm_cool * ct * 0.28 + lum_mod * 0.80;
        B -= warm_cool * ct * 0.92 - lum_mod * 0.60.
        Positive warm_cool: R+, G+slightly, B- (amber/warm crystal face).
        Negative warm_cool: R-, G-slightly, B+ (cobalt/cool crystal face).
        FIRST cyclic periodic warm/cool mapping governed by local gradient
        DIRECTION -- prior periodic passes (e.g. kupka_orphic_fugue) derive
        oscillation from spatial POSITION (radial distance from centroid),
        not from local gradient orientation angle.

        NOVEL vs. existing passes:
        (a) CIRCULAR ANGLE AVERAGING via cos/sin decomposition -- first
            directional spatial average; prior Sobel passes use only magnitude.
        (b) GRADIENT DIRECTION (atan2) as primary mapping variable, not magnitude.
        (c) CYCLIC DIRECTION-ANGLE chromatic modulation -- first pass where
            warm/cool oscillation is governed by local gradient orientation.

        facet_sigma  : Gaussian blur radius for coherent angle region formation.
        prism_cycles : Number of warm/cool oscillation cycles per 2*pi angle sweep.
        chroma_tilt  : Maximum chromatic deviation in warm or cool direction [0, 0.20].
        lum_facet    : Luminance modulation amplitude across facet planes [0, 0.12].
        opacity      : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel, gaussian_filter as _gf

        print("    Feininger Crystalline Prism pass (session 238: 149th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Coherent angle map via circular Gaussian averaging
        sx = _sobel(lum, axis=1).astype(_np.float32)
        sy = _sobel(lum, axis=0).astype(_np.float32)
        angle = _np.arctan2(sy, sx).astype(_np.float32)

        sigma = float(facet_sigma)
        z_cos = _gf(_np.cos(angle).astype(_np.float32), sigma)
        z_sin = _gf(_np.sin(angle).astype(_np.float32), sigma)
        coherent_angle = _np.arctan2(z_sin, z_cos).astype(_np.float32)

        # Stage 2: Prismatic warm/cool chromatic mapping
        pc = float(prism_cycles)
        warm_cool = _np.cos(coherent_angle * pc).astype(_np.float32)
        lum_mod   = (_np.sin(coherent_angle * pc + _np.pi / 6.0)
                     * float(lum_facet)).astype(_np.float32)

        ct = float(chroma_tilt)
        r1 = _np.clip(r0 + warm_cool * ct * 0.78 + lum_mod, 0.0, 1.0)
        g1 = _np.clip(g0 + warm_cool * ct * 0.28 + lum_mod * 0.80, 0.0, 1.0)
        b1 = _np.clip(b0 - warm_cool * ct * 0.92 + lum_mod * 0.60, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_warm = int((warm_cool > 0.5).sum())
        n_cool = int((warm_cool < -0.5).sum())
        print(f"    Feininger Crystalline Prism complete "
              f"(warm_px={n_warm} cool_px={n_cool})")

    def paint_split_toning_pass(
        self,
        shadow_cool:      float = 0.065,
        highlight_warm:   float = 0.055,
        shadow_pivot:     float = 0.30,
        highlight_pivot:  float = 0.72,
        transition_width: float = 0.18,
        opacity:          float = 0.52,
    ) -> None:
        r"""
        Paint Split Toning -- session 238 improvement.

        Split toning is a photographic darkroom technique in which shadow and
        highlight regions receive distinct, opposing colour tints while midtones
        remain near-neutral.  Classic split toning pushes shadows toward cool
        blue-teal and highlights toward warm amber-gold, reinforcing the natural
        temperature contrast between ambient (cool sky fill) and direct (warm sun)
        light sources.

        TWO-STAGE SPLIT TONING:

        Stage 1 LUMINANCE ZONE GATES with smooth linear transitions:
        shadow_gate    = clip((shadow_pivot - lum) / transition_width, 0, 1).
        highlight_gate = clip((lum - highlight_pivot) / transition_width, 0, 1).
        Both gates ramp from 0 to 1 over a transition_width luminance band.
        Midtone region (luminances between the two pivots) receives zero tinting.

        Stage 2 OPPOSING DUAL-ZONE TINTING:
        Shadow (cool): R -= shadow_gate * shadow_cool * 0.50;
                       G -= shadow_gate * shadow_cool * 0.15;
                       B += shadow_gate * shadow_cool * 0.90.
        Highlight (warm): R += highlight_gate * highlight_warm * 0.88;
                          G += highlight_gate * highlight_warm * 0.48;
                          B -= highlight_gate * highlight_warm * 0.65.
        Both adjustments are summed before opacity composite.

        NOVEL vs. existing passes:
        (a) SIMULTANEOUS OPPOSING DUAL-ZONE TINTING: shadows driven cool (B+,R-)
            and highlights driven warm (R+,B-) in a single pass -- no prior pass
            applies two opposing colour shifts to two distinct luminance zones
            simultaneously.
        (b) THREE-ZONE LUMINANCE SEGMENTATION (shadow/midtone/highlight) with
            independent smooth linear gates -- prior lum-gated passes (scumble,
            varnish, granulation) operate on a single zone or one-sided ramp.

        shadow_cool      : Max cool tint in dark zones [0, 0.15].
        highlight_warm   : Max warm tint in bright zones [0, 0.12].
        shadow_pivot     : Luminance below which shadow tint is at full strength.
        highlight_pivot  : Luminance above which highlight tint begins to ramp.
        transition_width : Luminance width of each tint ramp zone.
        opacity          : Final composite opacity.
        """
        import numpy as _np

        print("    Paint Split Toning pass (session 238 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Luminance zone gates
        tw = float(transition_width)
        sp = float(shadow_pivot)
        hp = float(highlight_pivot)
        shadow_gate    = _np.clip((sp - lum) / (tw + 1e-7), 0.0, 1.0)
        highlight_gate = _np.clip((lum - hp) / (tw + 1e-7), 0.0, 1.0)

        # Stage 2: Opposing dual-zone tinting
        sc = float(shadow_cool)
        hw = float(highlight_warm)
        r_adj = -shadow_gate * sc * 0.50 + highlight_gate * hw * 0.88
        g_adj = -shadow_gate * sc * 0.15 + highlight_gate * hw * 0.48
        b_adj = +shadow_gate * sc * 0.90 - highlight_gate * hw * 0.65

        r1 = _np.clip(r0 + r_adj, 0.0, 1.0)
        g1 = _np.clip(g0 + g_adj, 0.0, 1.0)
        b1 = _np.clip(b0 + b_adj, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_shadow    = int((shadow_gate    > 0.5).sum())
        n_highlight = int((highlight_gate > 0.5).sum())
        print(f"    Paint Split Toning complete "
              f"(shadow_px={n_shadow} highlight_px={n_highlight})")



    def dix_neue_sachlichkeit_pass(
        self,
        compress_strength: float = 0.45,
        midtone_gamma:     float = 1.8,
        surge_lo:          float = 0.28,
        surge_hi:          float = 0.68,
        saturation_surge:  float = 0.38,
        hi_thresh:         float = 0.78,
        hi_power:          float = 1.5,
        hi_crispness:      float = 0.55,
        opacity:           float = 0.80,
    ) -> None:
        r"""
        Dix Neue Sachlichkeit -- session 239: ONE HUNDRED AND FIFTIETH distinct mode.

        Implements Otto Dix (1891-1969) New Objectivity (Neue Sachlichkeit) tonal
        technique.  Dix\'s defining visual language: surgical midtone compression
        that collapses ambiguous grey tones toward definite light or shadow,
        heightened saturation at shadow-to-highlight transition boundaries, and
        forensic crisping of the topmost highlights to near-white -- producing the
        hard, enamel-like surface quality of his Weimar-era portraits and war paintings.

        THREE-STAGE NEW OBJECTIVITY SIMULATION:

        Stage 1 MIDTONE TONAL COMPRESSION:
        t = abs(lum - 0.5) / 0.5  (distance from neutral mid-grey, in [0,1])
        compress_gate = t ** midtone_gamma
        target = 1.0 if lum >= 0.5 else 0.0
        lum_new = lum + (target - lum) * compress_gate * compress_strength
        Each channel shifted proportionally: ch_new = ch + (ch_new/lum) * (lum_new-lum)
        Luminances close to 0.5 (compress_gate near 0) are almost unaffected;
        luminances further from 0.5 are pushed harder toward their nearest extreme.
        FIRST pass in project to use luminance-distance-from-neutral as a gate:
        (a) unlike shadow-gate passes that operate from lum=0 upward, this gate
            peaks at lum=0 AND lum=1, with minimum at lum=0.5 -- inverting the
            usual gate curve; (b) first pass where the direction of the shift
            reverses sign depending on which side of midgrey the pixel falls.

        Stage 2 BOUNDARY SATURATION SURGE:
        edge_gate = sobel_magnitude normalised to [0,1]
        zone_gate = bell on [surge_lo, surge_hi]: triangular peak at centre,
                    zero outside -- isolates the transition zone between shadow
                    and highlight (Dix\'s most characteristic region of colour).
        combined = edge_gate * zone_gate
        sat_scale = 1 + saturation_surge * combined
        lum3 = luminance of Stage 1 result; ch_sat = lum3 + (ch-lum3)*sat_scale.
        Saturation boost is strongest where there is BOTH an edge AND a mid-tone
        pixel -- exactly at shadow-to-light transitions.
        FIRST pass to boost saturation specifically at mid-tone EDGE BOUNDARIES
        (joint gate: high gradient AND transition luminance zone).  Prior
        saturation passes boost globally or in a single luminance zone.

        Stage 3 FORENSIC HIGHLIGHT CRISPING:
        hi_gate = clip((lum - hi_thresh) / (1 - hi_thresh), 0, 1) ** hi_power
        R,G,B += hi_gate * hi_crispness * (1 - channel)  -- pushes toward white.
        Simulates the enamel-hard white highlights characteristic of Dix\'s
        oil-over-tempera technique, where the topmost impasto catches light
        with surgical precision.

        NOVEL vs. existing passes:
        (a) LUMINANCE-DISTANCE-FROM-NEUTRAL COMPRESSION GATE (t=|lum-0.5|/0.5)
            with sign-reversing shift direction -- first pass where the tonal
            shift inverts sign at lum=0.5; all prior lum-gated passes use
            monotone gates (shadow or highlight only).
        (b) JOINT EDGE-AND-ZONE SATURATION GATE (sobel_mag * zone_bell) --
            first pass to boost saturation only where high gradient AND mid-tone
            luminance coincide simultaneously.
        (c) THREE-STAGE UNIFIED MODEL: midtone compression + boundary saturation
            surge + highlight crisping in one pass -- no prior pass combines
            tonal redistribution with a joint spatial-luminance saturation boost.

        compress_strength : Fraction of midtone pushed toward nearest extreme [0,1].
        midtone_gamma     : Power curve for compression gate (>1: faster at extremes).
        surge_lo/hi       : Luminance band for the saturation surge zone.
        saturation_surge  : Max saturation multiplier increase [0, 1.0].
        hi_thresh         : Luminance above which highlight crisping begins.
        hi_power          : Sharpness of highlight gate transition.
        hi_crispness      : Max push toward white in highlight zone [0, 1].
        opacity           : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel

        print("    Dix Neue Sachlichkeit pass (session 239: 150th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Midtone tonal compression
        t = (_np.abs(lum - 0.5) / 0.5).astype(_np.float32)
        compress_gate = (t ** float(midtone_gamma)).astype(_np.float32)
        target = (lum >= 0.5).astype(_np.float32)  # 1.0 for light, 0.0 for dark
        cs = float(compress_strength)
        lum_new = lum + (target - lum) * compress_gate * cs
        # Preserve chroma by shifting channels proportionally
        scale = _np.where(_np.abs(lum) > 1e-6, lum_new / (lum + 1e-6), 1.0).astype(_np.float32)
        r1 = _np.clip(r0 * scale, 0.0, 1.0)
        g1 = _np.clip(g0 * scale, 0.0, 1.0)
        b1 = _np.clip(b0 * scale, 0.0, 1.0)

        # Stage 2: Boundary saturation surge
        sx = _sobel(lum, axis=1).astype(_np.float32)
        sy = _sobel(lum, axis=0).astype(_np.float32)
        mag = _np.sqrt(sx ** 2 + sy ** 2).astype(_np.float32)
        mag_norm = mag / (mag.max() + 1e-7)

        sl, sh = float(surge_lo), float(surge_hi)
        zone_mid  = (sl + sh) * 0.5
        zone_half = (sh - sl) * 0.5 + 1e-7
        zone_gate = _np.clip(1.0 - _np.abs(lum - zone_mid) / zone_half, 0.0, 1.0).astype(_np.float32)

        combined  = (mag_norm * zone_gate).astype(_np.float32)
        ss = float(saturation_surge)
        sat_scale = (1.0 + ss * combined).astype(_np.float32)

        lum3 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        r2 = _np.clip(lum3 + (r1 - lum3) * sat_scale, 0.0, 1.0)
        g2 = _np.clip(lum3 + (g1 - lum3) * sat_scale, 0.0, 1.0)
        b2 = _np.clip(lum3 + (b1 - lum3) * sat_scale, 0.0, 1.0)

        # Stage 3: Forensic highlight crisping
        ht = float(hi_thresh)
        hp = float(hi_power)
        hc = float(hi_crispness)
        hi_gate = _np.clip((lum - ht) / (1.0 - ht + 1e-7), 0.0, 1.0) ** hp
        r3 = _np.clip(r2 + hi_gate * hc * (1.0 - r2), 0.0, 1.0)
        g3 = _np.clip(g2 + hi_gate * hc * (1.0 - g2), 0.0, 1.0)
        b3 = _np.clip(b2 + hi_gate * hc * (1.0 - b2), 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_compressed = int((compress_gate > 0.4).sum())
        n_surged     = int((combined       > 0.2).sum())
        n_crisped    = int((hi_gate        > 0.2).sum())
        print(f"    Dix Neue Sachlichkeit complete "
              f"(compressed_px={n_compressed} surged_px={n_surged} crisped_px={n_crisped})")

    def paint_glaze_gradient_pass(
        self,
        color:         tuple = (0.58, 0.32, 0.08),
        axis:          str   = 'y',
        opacity_near:  float = 0.0,
        opacity_far:   float = 0.10,
        gamma:         float = 1.5,
        reverse:       bool  = False,
        blend_mode:    str   = 'multiply',
    ) -> None:
        r"""
        Paint Glaze Gradient -- session 239 artistic improvement.

        Traditional oil painting glazing applies a thin transparent layer of pure,
        highly diluted colour over dried paint.  A GRADIENT GLAZE varies the
        concentration of the wash along a single axis -- the artist loads a broad
        flat brush and progressively thins or thickens the wash as they work across
        the canvas.  Turner used descending warm golden glazes; Vermeer applied
        selective cool blue-grey glazes over warm imprimatura in his skies.

        AXIAL GRADIENT TRANSPARENT GLAZE:
        t = linspace(0, 1, canvas_height_or_width) along chosen axis.
        t_curved = t ** gamma  (non-linear power-curve build).
        If reverse: t_curved = (1-t) ** gamma.
        alpha(pixel) = opacity_near + (opacity_far - opacity_near) * t_curved.
        Two blend modes:
        'multiply': result = original * (1 - alpha*(1 - glaze_col))
            Deepens and tints colour; appropriate for glazes over mid/light values.
        'screen':   result = 1 - (1-original)*(1 - alpha*glaze_col)
            Lightens and adds luminosity; appropriate for glazes over darks.

        NOVEL vs. existing passes:
        (a) SPATIALLY VARYING (AXIAL GRADIENT) GLAZE OPACITY -- the existing
            glaze() method applies a single uniform opacity over the entire canvas;
            this pass creates a smooth directional build from opacity_near to
            opacity_far, modelling the physical technique of a gradient wash.
            No prior pass applies a spatially varying transparent overlay along
            a chosen axis.
        (b) GAMMA-CURVED GRADIENT RAMP -- non-linear power curve allows the glaze
            to build slowly at first then accelerate, matching natural variation
            in brush load as paint thins during the stroke.
        (c) DUAL BLEND MODES (multiply / screen) -- selects between two physically
            distinct glaze interaction models based on blend_mode parameter.

        color        : RGB glaze colour as normalised floats.
        axis         : 'y' (top-to-bottom) or 'x' (left-to-right).
        opacity_near : Glaze opacity at the near end of the gradient (t=0).
        opacity_far  : Glaze opacity at the far end of the gradient (t=1).
        gamma        : Power curve for gradient build (>1 slow start / fast end).
        reverse      : Swap near and far ends of the gradient.
        blend_mode   : 'multiply' or 'screen'.
        """
        import numpy as _np

        print("    Paint Glaze Gradient pass (session 239 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Build 1-D ramp along chosen axis
        n = h if axis == 'y' else w
        t = _np.linspace(0.0, 1.0, n, dtype=_np.float32)
        if reverse:
            t = 1.0 - t
        t_curved = t ** float(gamma)
        on = float(opacity_near)
        of = float(opacity_far)
        alpha_1d = (on + (of - on) * t_curved).astype(_np.float32)

        if axis == 'y':
            alpha = alpha_1d[:, _np.newaxis]
        else:
            alpha = alpha_1d[_np.newaxis, :]

        gr = _np.float32(float(color[0]))
        gg = _np.float32(float(color[1]))
        gb = _np.float32(float(color[2]))

        if blend_mode == 'screen':
            r1 = _np.clip(1.0 - (1.0 - r0) * (1.0 - alpha * gr), 0.0, 1.0)
            g1 = _np.clip(1.0 - (1.0 - g0) * (1.0 - alpha * gg), 0.0, 1.0)
            b1 = _np.clip(1.0 - (1.0 - b0) * (1.0 - alpha * gb), 0.0, 1.0)
        else:  # multiply
            r1 = _np.clip(r0 * (1.0 - alpha * (1.0 - gr)), 0.0, 1.0)
            g1 = _np.clip(g0 * (1.0 - alpha * (1.0 - gg)), 0.0, 1.0)
            b1 = _np.clip(b0 * (1.0 - alpha * (1.0 - gb)), 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(r1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(g1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(b1 * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        alpha_mean = float(alpha_1d.mean())
        alpha_max  = float(alpha_1d.max())
        print(f"    Paint Glaze Gradient complete "
              f"(axis={axis} blend={blend_mode} "
              f"alpha_mean={alpha_mean:.3f} alpha_max={alpha_max:.3f})")

    def dufy_chromatic_dissociation_pass(
        self,
        outline_sigma:      float = 1.2,
        outline_threshold:  float = 0.18,
        outline_darkness:   float = 0.72,
        chroma_dx:          int   = 9,
        chroma_dy:          int   = 6,
        saturation_lift:    float = 0.28,
        opacity:            float = 0.82,
    ) -> None:
        r"""
        Dufy Chromatic Dissociation -- session 240: ONE HUNDRED AND FIFTY-FIRST distinct mode.

        Implements Raoul Dufy (1877-1953) signature technique of deliberate
        chromatic dissociation: rapid ink or watercolour outline strokes are
        laid separately from broad, luminous colour washes, the two layers
        intentionally misregistered so that colour \"escapes\" beyond and around
        the drawn contours.  The result is an image that reads simultaneously as
        drawing AND painting, neither fully containing the other -- the very
        quality that gives Dufy\'s festive regatta, racetrack, and Riviera scenes
        their buoyant, light-filled energy.

        THREE-STAGE CHROMATIC DISSOCIATION SIMULATION:

        Stage 1 OUTLINE EXTRACTION AND DARKENING:
        Compute Sobel magnitude on luminance channel.
        Smooth the magnitude map with Gaussian sigma=outline_sigma to soften
        the edge indicator into a broad brushed-line zone.
        edge_gate = clip(mag_norm / (outline_threshold + eps), 0, 1) ** 0.6
        Darken the canvas within the edge zone:
        ch_outlined = ch * (1 - edge_gate * outline_darkness)
        This pushes high-gradient pixels toward near-black, simulating the
        rapid loaded-brush ink outline that Dufy drew over dried colour washes.
        FIRST pass in project to model ink-outline occlusion: pixels near edges
        are darkened toward near-black (not merely contrast-sharpened); all prior
        edge-aware passes boost contrast or saturation at edges but never push
        the edge zone itself toward black independently of surrounding values.

        Stage 2 CHROMINANCE SPATIAL DISSOCIATION:
        Decompose each channel into luminance and chrominance deviation:
            cb_ch = ch - lum   (signed chroma deviation from grey)
        Translate cb_ch arrays by (chroma_dx, chroma_dy) pixels using np.roll:
            cb_ch_shifted = roll(cb_ch, shift=(dy, dx), axis=(0, 1))
        Recompose with the ORIGINAL (unshifted) luminance:
            ch_dissociated = clip(lum + cb_ch_shifted, 0, 1)
        Because luminance stays fixed while chrominance is offset, the colour
        regions spatially drift relative to the tonal structure -- the exact
        mis-registration seen in Dufy\'s paintings where his blue washes lap past
        his ink-drawn sails and his yellow bleeds into his sky outlines.
        NOVEL: (a) CHROMINANCE SPATIAL DISPLACEMENT -- first pass to apply
        different spatial translations to the chrominance deviation (cb_ch) and
        the luminance, intentionally producing colour-line mis-registration;
        no prior pass translates any image component independently of another.
        np.roll is used so the operation is cheap, deterministic, and
        parameter-controlled (dx, dy pixels); the wrap-around artifact at
        canvas borders is masked out by the composite opacity.

        Stage 3 FAUVIST SATURATION LIFT:
        Compute luminance of the dissociated result.
        sat_scale = 1 + saturation_lift
        ch_vivid = lum_d + (ch_d - lum_d) * sat_scale
        Boosting saturation uniformly across the canvas re-creates Dufy\'s
        luminous, transparent watercolour-on-white quality where every hue
        reads at near-full chroma.

        NOVEL vs. existing passes:
        (a) CHROMINANCE SPATIAL DISPLACEMENT (np.roll on chroma deviation, not
            full channel) -- first pass to separate chroma from luma and
            translate each independently, producing intentional colour-line
            mis-registration; prior chromatic passes shift hue or saturation
            but never spatially translate colour relative to form.
        (b) EDGE-SELECTIVE NEAR-BLACK DARKENING (stage 1 outline gate) --
            first pass to push the edge zone itself toward near-black as an
            ink-outline model; existing edge passes boost contrast, crispness,
            or saturation at edges but do not independently darken the edge zone.
        (c) UNIFIED THREE-STAGE: outline darkening + chroma displacement +
            saturation vivification -- models both strands of Dufy\'s working
            method (drawn line + colour wash) in one consolidated pass.

        outline_sigma     : Gaussian smoothing sigma for edge indicator.
        outline_threshold : Normalised edge magnitude above which darkening begins.
        outline_darkness  : Max fraction of channel pushed toward black at edge.
        chroma_dx         : Horizontal pixel offset for chrominance shift.
        chroma_dy         : Vertical pixel offset for chrominance shift.
        saturation_lift   : Added saturation multiplier (0 = no change, 0.3 = 30% boost).
        opacity           : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel, gaussian_filter as _gauss

        print("    Dufy Chromatic Dissociation pass (session 240: 151st mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Outline extraction and darkening
        sx = _sobel(lum, axis=1).astype(_np.float32)
        sy = _sobel(lum, axis=0).astype(_np.float32)
        mag = _np.sqrt(sx * sx + sy * sy).astype(_np.float32)
        mag_smooth = _gauss(mag, sigma=float(outline_sigma)).astype(_np.float32)
        mag_norm = mag_smooth / (mag_smooth.max() + 1e-7)

        ot = float(outline_threshold)
        od = float(outline_darkness)
        edge_gate = _np.clip(mag_norm / (ot + 1e-7), 0.0, 1.0) ** 0.6
        r1 = _np.clip(r0 * (1.0 - edge_gate * od), 0.0, 1.0)
        g1 = _np.clip(g0 * (1.0 - edge_gate * od), 0.0, 1.0)
        b1 = _np.clip(b0 * (1.0 - edge_gate * od), 0.0, 1.0)

        # Stage 2: Chrominance spatial dissociation
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        cb_r = (r1 - lum1).astype(_np.float32)
        cb_g = (g1 - lum1).astype(_np.float32)
        cb_b = (b1 - lum1).astype(_np.float32)

        dx, dy = int(chroma_dx), int(chroma_dy)
        cb_r_s = _np.roll(_np.roll(cb_r, dy, axis=0), dx, axis=1)
        cb_g_s = _np.roll(_np.roll(cb_g, dy, axis=0), dx, axis=1)
        cb_b_s = _np.roll(_np.roll(cb_b, dy, axis=0), dx, axis=1)

        r2 = _np.clip(lum1 + cb_r_s, 0.0, 1.0)
        g2 = _np.clip(lum1 + cb_g_s, 0.0, 1.0)
        b2 = _np.clip(lum1 + cb_b_s, 0.0, 1.0)

        # Stage 3: Fauvist saturation lift
        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        sat_scale = 1.0 + float(saturation_lift)
        r3 = _np.clip(lum2 + (r2 - lum2) * sat_scale, 0.0, 1.0)
        g3 = _np.clip(lum2 + (g2 - lum2) * sat_scale, 0.0, 1.0)
        b3 = _np.clip(lum2 + (b2 - lum2) * sat_scale, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_outlined = int((edge_gate > 0.3).sum())
        chroma_mag = float(_np.abs(cb_r).mean() + _np.abs(cb_g).mean() + _np.abs(cb_b).mean())
        print(f"    Dufy Chromatic Dissociation complete "
              f"(outlined_px={n_outlined} chroma_shift=({dx},{dy}) "
              f"chroma_mag={chroma_mag:.4f})")

    def paint_sfumato_focus_pass(
        self,
        cx:            float = 0.5,
        cy:            float = 0.5,
        focus_radius:  float = 0.22,
        max_sigma:     float = 4.0,
        sat_falloff:   float = 0.30,
        transition_k:  float = 6.0,
        opacity:       float = 0.72,
    ) -> None:
        r"""
        Paint Sfumato Focus -- session 240 artistic improvement.

        Leonardo da Vinci\'s sfumato (Italian: \"evaporated\") is the technique of
        softening edges and forms by blending tones imperceptibly into one another,
        without lines or sharp borders.  Leonardo applied sfumato most heavily in
        the periphery of his compositions, preserving maximum sharpness only in
        the primary focal zone -- the famous \"smoke without fire\" aerial softness
        that gives the Mona Lisa and Virgin of the Rocks their atmospheric depth.

        RADIAL PROGRESSIVE BLUR WITH SATURATION FALLOFF:

        1. RADIAL DISTANCE MAP:
           dist(x, y) = sqrt(((x/W) - cx)^2 + ((y/H) - cy)^2)
           normalised so the image diagonal = 1.0.
           r_norm = clip(dist / diag, 0, 1) where diag = sqrt(cx^2 + cy^2 + ...).

        2. FOCUS GATE (sigmoid):
           t = r_norm (normalised radius; focus_radius is the sharp zone)
           gate = sigmoid((t - focus_radius) * transition_k)
              = 1 / (1 + exp(-transition_k * (t - focus_radius)))
           gate = 0 inside focus zone, rises smoothly to 1 in the periphery.

        3. SPATIALLY VARYING GAUSSIAN BLUR:
           For each pixel, blur sigma = max_sigma * gate(pixel).
           Implementation: pre-compute blurred version at max_sigma, then
           composite pixel-by-pixel: result = sharp * (1 - gate) + blurred * gate.
           This is equivalent to a spatially varying Gaussian to first order and
           is computationally tractable without a full spatial-variant convolution.

        4. PERIPHERAL SATURATION FALLOFF:
           lum_blend = luminance of blended result.
           sat_gate = gate * sat_falloff
           ch_faded = lum_blend + (ch_blend - lum_blend) * (1 - sat_gate)
           Colours in the periphery desaturate toward grey, reinforcing the
           sense of atmospheric recession away from the focal centre.

        NOVEL vs. existing passes:
        (a) RADIAL PROGRESSIVE BLUR -- first pass to apply spatially varying
            Gaussian blur with strength increasing continuously from a focal
            centre point; no prior pass applies blur that varies by distance
            from a specified (cx, cy) focal coordinate.  The existing
            diffuse_boundary_pass() blurs near detected edges; this pass blurs
            by RADIAL DISTANCE FROM A FOCAL CENTRE, an entirely different model.
        (b) SIMULTANEOUS RADIAL FOCUS AND SATURATION FALLOFF -- first pass to
            combine a spatial blur gradient with a saturation gradient from the
            same focal centre; prior passes that modulate saturation do so
            globally or by luminance zone, never by radial distance.
        (c) SIGMOID TRANSITION GATE (not linear or Gaussian) -- the focus
            boundary transitions via a smooth logistic curve parameterised by
            transition_k; sharper k gives a harder focus edge, lower k gives
            the true imperceptible sfumato gradation.

        cx, cy        : Focus centre as fractions of canvas width/height [0, 1].
        focus_radius  : Radius of sharp zone as fraction of image diagonal.
        max_sigma     : Maximum Gaussian blur sigma applied at maximum radius.
        sat_falloff   : Maximum saturation reduction in the far periphery [0, 1].
        transition_k  : Sigmoid steepness (higher = harder focus edge).
        opacity       : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss

        print("    Paint Sfumato Focus pass (session 240 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Build radial distance map
        xs = _np.linspace(0.0, 1.0, w, dtype=_np.float32)
        ys = _np.linspace(0.0, 1.0, h, dtype=_np.float32)
        xg, yg = _np.meshgrid(xs, ys)
        dist = _np.sqrt((xg - float(cx)) ** 2 + (yg - float(cy)) ** 2).astype(_np.float32)
        diag = float(_np.sqrt(2.0) * 0.5)
        r_norm = _np.clip(dist / (diag + 1e-7), 0.0, 1.0).astype(_np.float32)

        # Sigmoid gate: 0 inside focus, 1 at periphery
        fr = float(focus_radius)
        tk = float(transition_k)
        gate = (1.0 / (1.0 + _np.exp(-tk * (r_norm - fr)))).astype(_np.float32)

        # Spatially varying blur: blend sharp and fully blurred by gate
        ms = float(max_sigma)
        r_blurred = _gauss(r0, sigma=ms).astype(_np.float32)
        g_blurred = _gauss(g0, sigma=ms).astype(_np.float32)
        b_blurred = _gauss(b0, sigma=ms).astype(_np.float32)

        r1 = (r0 * (1.0 - gate) + r_blurred * gate).astype(_np.float32)
        g1 = (g0 * (1.0 - gate) + g_blurred * gate).astype(_np.float32)
        b1 = (b0 * (1.0 - gate) + b_blurred * gate).astype(_np.float32)

        # Peripheral saturation falloff
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        sf = float(sat_falloff)
        sat_gate = gate * sf
        r2 = _np.clip(lum1 + (r1 - lum1) * (1.0 - sat_gate), 0.0, 1.0)
        g2 = _np.clip(lum1 + (g1 - lum1) * (1.0 - sat_gate), 0.0, 1.0)
        b2 = _np.clip(lum1 + (b1 - lum1) * (1.0 - sat_gate), 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        gate_mean = float(gate.mean())
        gate_max  = float(gate.max())
        print(f"    Paint Sfumato Focus complete "
              f"(focus=({cx:.2f},{cy:.2f}) r={focus_radius:.2f} "
              f"sigma={max_sigma:.1f} gate_mean={gate_mean:.3f} gate_max={gate_max:.3f})")

    def frankenthaler_soak_stain_pass(
        self,
        n_stains:         int   = 4,
        sigma_large:      float = 40.0,
        sigma_small:      float = 12.0,
        stain_alpha:      float = 0.40,
        absorption:       float = 0.65,
        cap_sigma:        float = 3.0,
        cap_threshold:    float = 0.06,
        seed:             int   = 7,
        opacity:          float = 0.78,
    ) -> None:
        r"""
        Frankenthaler Soak-Stain -- session 241: ONE HUNDRED AND FIFTY-SECOND distinct mode.

        Implements Helen Frankenthaler (1928-2011) soak-stain technique, invented in
        1952 with her seminal painting Mountains and Sea.  Working on raw, unprimed
        canvas laid flat on the studio floor, Frankenthaler poured turpentine-thinned
        paint directly from cans, guiding the flowing pools by tilting the canvas.
        Because the canvas is unprimed, the paint soaks INTO the weave of the cotton
        duck rather than sitting on top as a film: no impasto, no surface texture --
        only luminous, transparent colour that has become one with the fabric.

        THREE-STAGE SOAK-STAIN SIMULATION:

        Stage 1 ORGANIC STAIN REGION GENERATION:
        For each of n_stains stain regions, generate a random float plane, then
        compose a multi-scale noise field:
            stain_field_i = clip(
                0.65 * blur(noise_i, sigma=sigma_large)
                + 0.35 * blur(noise_i * 0.6 + noise_i_2 * 0.4, sigma=sigma_small),
                0, 1)
        Two Gaussian sigmas model different physical scales of paint flow: large-sigma
        simulates the broad swept pool from a tilted canvas pour; small-sigma simulates
        finer wicking detail within the pool as paint migrates along individual canvas
        fibres.  A luminance-bias step then weights the stain mask toward mid-luminance
        regions of the underlying canvas (where unprimed canvas would absorb most):
            lum_bias = 1.0 - |lum - 0.50| * 2.0   (peaks at lum=0.5, zero at 0 and 1)
            stain_mask_i = stain_field_i * (1.0 + lum_bias * 0.40)
            stain_mask_i = clip(stain_mask_i / stain_mask_i.max(), 0, 1)
        NOVEL: (a) MULTI-SCALE NOISE COMPOSITION -- first pass to build stain region
        masks by summing two independently Gaussian-blurred random planes at different
        sigmas (sigma_large for gross flow, sigma_small for capillary detail); no prior
        pass constructs organic region masks by this two-sigma composition method;
        (b) LUMINANCE-BIASED STAIN PLACEMENT -- first pass to scale the stain mask by
        a mid-luminance preference weight, reflecting the physical reality that unprimed
        canvas absorbs most pigment in mid-tone areas where surface energy is neutral.

        Stage 2 PAINT ABSORPTION SIMULATION:
        For each stain region, sample the average canvas colour within the stain footprint
        to obtain a locally representative hue for that pool:
            stain_color_i = mean(ch * stain_mask_i) over the stain region
        Then compose the absorbed stain:
            ch_stained = ch + stain_mask_i * stain_alpha
                         * (stain_color_i * (1.0 - absorption) + ch * absorption - ch)
            = ch + stain_mask_i * stain_alpha * (stain_color_i * (1-absorption) - ch*(1-absorption))
            = ch + stain_mask_i * stain_alpha * (1-absorption) * (stain_color_i - ch)
        The absorption coefficient (0..1) controls how much of the stain colour is
        neutralised by the canvas ground: high absorption (0.7+) means the stain shifts
        the canvas colour only gently, as pigment is mostly absorbed into fibres; low
        absorption (0.2-0.3) means more pigment sits at the surface.  The effective
        shift per stain is:  delta = stain_alpha * (1 - absorption) * (stain_color - ch).
        NOVEL: (b) PAINT ABSORPTION COEFFICIENT -- first pass to model paint as partially
        absorbed INTO the canvas substrate via an explicit absorption fraction blended
        toward the canvas ground; all prior passes model paint as sitting ON the surface
        at a given opacity; this pass separates surface opacity (stain_alpha) from
        substrate absorption fraction (absorption), creating the transparent, filmless
        quality of soak-stain work distinct from any glazing or wash technique.

        Stage 3 CAPILLARY EDGE DIFFUSION:
        At the boundary of each stain region, paint wicks outward along canvas fibres
        beyond the main pool edge -- the capillary fringe.  To simulate this:
            grad_mask = |nabla stain_mask| (magnitude of gradient of the stain mask)
            boundary = (grad_mask > cap_threshold).astype(float)
            boundary_smooth = gaussian_blur(boundary, sigma=1.0)
            ch_cap = gaussian_blur(ch_stained, sigma=cap_sigma)
            ch_final = ch_stained * (1.0 - boundary_smooth) + ch_cap * boundary_smooth
        The extra blur applied only at the stain perimeter creates a soft, diffuse halo
        that extends the stain colour slightly beyond the pool boundary, matching the
        capillary fringe visible in Frankenthaler's actual paintings.
        NOVEL: (c) BOUNDARY-LOCALISED CAPILLARY BLUR -- first pass to apply Gaussian
        blur selectively AT stain boundary zones (|nabla mask| > threshold) to simulate
        capillary migration of paint along canvas fibres at the pool edge; no prior
        pass applies spatially gated extra blurring at the gradient-detected boundary
        of a generated region mask.

        n_stains      : Number of independent stain pools to pour.
        sigma_large   : Gaussian sigma for broad flow component of stain shape.
        sigma_small   : Gaussian sigma for fine capillary detail component.
        stain_alpha   : Maximum colour shift per stain pool (paint volume).
        absorption    : Fraction absorbed into canvas (reduces surface colour shift).
        cap_sigma     : Gaussian sigma for capillary edge diffusion blur.
        cap_threshold : |nabla mask| threshold above which capillary blur is applied.
        seed          : Random seed for reproducible stain placement.
        opacity       : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss

        print("    Frankenthaler Soak-Stain pass (session 241: 152nd mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        rng = _np.random.RandomState(int(seed))

        r_out = r0.copy()
        g_out = g0.copy()
        b_out = b0.copy()

        sl = float(sigma_large)
        ss = float(sigma_small)
        sa = float(stain_alpha)
        ab = float(absorption)

        for _ in range(int(n_stains)):
            noise_a = rng.rand(h, w).astype(_np.float32)
            noise_b = rng.rand(h, w).astype(_np.float32)

            # Multi-scale composition: broad pour + fine capillary detail
            large_field = _gauss(noise_a, sigma=sl).astype(_np.float32)
            small_field = _gauss(noise_a * 0.6 + noise_b * 0.4, sigma=ss).astype(_np.float32)

            # Normalise each field to [0,1] then compose
            large_norm = large_field / (large_field.max() + 1e-7)
            small_norm = small_field / (small_field.max() + 1e-7)
            stain_raw = (0.65 * large_norm + 0.35 * small_norm).astype(_np.float32)
            stain_raw = _np.clip(stain_raw, 0.0, 1.0)

            # Luminance bias: stain stronger in mid-luminance areas
            lum_bias = (1.0 - _np.abs(lum - 0.50) * 2.0).astype(_np.float32)
            lum_bias = _np.clip(lum_bias, 0.0, 1.0)
            stain_mask = stain_raw * (1.0 + lum_bias * 0.40)
            mx = stain_mask.max()
            if mx > 1e-7:
                stain_mask = _np.clip(stain_mask / mx, 0.0, 1.0)
            stain_mask = stain_mask.astype(_np.float32)

            # Sample stain colour: luminance-weighted mean of current canvas within stain
            weight_sum = stain_mask.sum() + 1e-7
            sc_r = float((r_out * stain_mask).sum() / weight_sum)
            sc_g = float((g_out * stain_mask).sum() / weight_sum)
            sc_b = float((b_out * stain_mask).sum() / weight_sum)

            # Absorption-modulated stain application
            delta_r = stain_mask * sa * (1.0 - ab) * (sc_r - r_out)
            delta_g = stain_mask * sa * (1.0 - ab) * (sc_g - g_out)
            delta_b = stain_mask * sa * (1.0 - ab) * (sc_b - b_out)

            r_stained = _np.clip(r_out + delta_r, 0.0, 1.0).astype(_np.float32)
            g_stained = _np.clip(g_out + delta_g, 0.0, 1.0).astype(_np.float32)
            b_stained = _np.clip(b_out + delta_b, 0.0, 1.0).astype(_np.float32)

            # Capillary edge diffusion: extra blur at stain perimeter
            cs = float(cap_sigma)
            ct = float(cap_threshold)

            # Gradient magnitude of stain mask
            sm_gy = _np.abs(_np.gradient(stain_mask, axis=0)).astype(_np.float32)
            sm_gx = _np.abs(_np.gradient(stain_mask, axis=1)).astype(_np.float32)
            grad_mag = _np.sqrt(sm_gx * sm_gx + sm_gy * sm_gy).astype(_np.float32)

            boundary = (grad_mag > ct).astype(_np.float32)
            boundary_smooth = _gauss(boundary, sigma=1.0).astype(_np.float32)
            boundary_smooth = _np.clip(boundary_smooth, 0.0, 1.0)

            r_cap = _gauss(r_stained, sigma=cs).astype(_np.float32)
            g_cap = _gauss(g_stained, sigma=cs).astype(_np.float32)
            b_cap = _gauss(b_stained, sigma=cs).astype(_np.float32)

            r_out = r_stained * (1.0 - boundary_smooth) + r_cap * boundary_smooth
            g_out = g_stained * (1.0 - boundary_smooth) + g_cap * boundary_smooth
            b_out = b_stained * (1.0 - boundary_smooth) + b_cap * boundary_smooth

            r_out = _np.clip(r_out, 0.0, 1.0).astype(_np.float32)
            g_out = _np.clip(g_out, 0.0, 1.0).astype(_np.float32)
            b_out = _np.clip(b_out, 0.0, 1.0).astype(_np.float32)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r_out * op
        new_g = g0 * (1.0 - op) + g_out * op
        new_b = b0 * (1.0 - op) + b_out * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        mean_shift = float(_np.abs(r_out - r0).mean() + _np.abs(g_out - g0).mean() + _np.abs(b_out - b0).mean())
        print(f"    Frankenthaler Soak-Stain complete "
              f"(n_stains={n_stains} sigma=({sl},{ss}) "
              f"absorption={absorption:.2f} mean_shift={mean_shift:.4f})")

    def paint_lost_found_edges_pass(
        self,
        found_sharpness:  float = 1.60,
        found_radius:     float = 1.0,
        lost_sigma:       float = 2.2,
        importance_k:     float = 5.0,
        cx:               float = 0.5,
        cy:               float = 0.5,
        focal_weight:     float = 0.45,
        opacity:          float = 0.68,
    ) -> None:
        r"""
        Paint Lost-and-Found Edges -- session 241 artistic improvement.

        The "lost and found" edge doctrine is a cornerstone of classical oil painting
        as practised by Rembrandt, Velazquez, Sargent, and Zorn.  A "found" (hard)
        edge occurs at the boundary of the primary subject, in areas of maximum
        contrast or maximum light-dark transition, and wherever the painter wants
        the eye to stop and look.  A "lost" (soft) edge occurs in the periphery,
        where forms turn away from the light, where one dark mass meets another, or
        where the painter wants the eye to pass through without stopping.  The
        principle is that differential edge quality creates a visual hierarchy:
        found edges lead; lost edges recede.  A painting with every edge equally
        sharp is as loud as one with every note fortissimo.

        DIFFERENTIAL EDGE TREATMENT -- FOUND EDGES SHARPENED, LOST EDGES SOFTENED:

        1. EDGE STRENGTH MAP:
           Compute Sobel magnitude on luminance channel.
           edge_mag = sqrt(sobel_x^2 + sobel_y^2), normalised to [0,1].

        2. LOCAL CONTRAST MAP:
           Compute local standard deviation of luminance in a 9x9 neighbourhood:
           local_std = sqrt(blur(lum^2, sigma=3) - blur(lum, sigma=3)^2)
           Normalise: local_std_norm = local_std / local_std.max().

        3. FOCAL PROXIMITY WEIGHT:
           Radial distance from (cx, cy): dist_norm as fraction of image diagonal.
           proximity = 1.0 / (1.0 + exp(importance_k * (dist_norm - 0.45)))
           (High near centre, low at periphery -- sigmoid fall-off.)

        4. IMPORTANCE SCORE:
           importance = (1 - focal_weight) * (edge_mag * local_std_norm)
                        + focal_weight * proximity
           Combined score balances local edge strength (contrast) against spatial
           proximity to the designated focal centre.

        5. FOUND EDGE SHARPENING:
           Unsharp mask: blurred = gaussian_blur(ch, sigma=found_radius)
                          sharp = ch + found_sharpness * (ch - blurred)
           found_gate = clip(importance, 0, 1)^0.7
           ch_found = ch * (1 - found_gate) + sharp * found_gate

        6. LOST EDGE SOFTENING:
           soft = gaussian_blur(ch, sigma=lost_sigma)
           lost_gate = clip(1.0 - importance, 0, 1)^0.7
           ch_lost = ch_found * (1 - lost_gate) + soft * lost_gate

        NOVEL vs. existing passes:
        (a) DIFFERENTIAL EDGE TREATMENT -- first pass to simultaneously SHARPEN
            high-importance (found) edges via unsharp mask AND SOFTEN low-importance
            (lost) edges via Gaussian blur in a single unified pass governed by the
            same importance metric; no prior pass combines both selective sharpening
            and selective softening; existing edge-aware passes either only boost
            contrast/sharpness or only blur, never both directions at once.
        (b) COMBINED IMPORTANCE METRIC -- first pass to fuse local-contrast-at-edge
            (edge_mag * local_std_norm) with radial focal proximity (sigmoid centred
            at cx, cy) into a single importance score that classifies each pixel on
            the found-to-lost spectrum; prior focal passes (sfumato_focus_pass) blur
            radially but do not also sharpen the focal zone, and prior contrast passes
            sharpen globally without softening peripheral edges.
        (c) CONTINUOUS FOUND/LOST SPECTRUM -- gate functions with 0.7 exponent create
            a continuous spectrum from fully found (sharp) to fully lost (soft) rather
            than a binary threshold; this matches how skilled painters modulate edge
            quality along a continuum rather than a step function.

        found_sharpness : Unsharp-mask amplification factor for found edges.
        found_radius    : Gaussian sigma for unsharp-mask base blur.
        lost_sigma      : Gaussian sigma for lost-edge softening.
        importance_k    : Sigmoid steepness for focal-proximity falloff.
        cx, cy          : Focal centre as fractions of canvas width/height.
        focal_weight    : Blend weight between local-contrast and proximity (0=contrast only, 1=proximity only).
        opacity         : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss

        print("    Paint Lost-Found Edges pass (session 241 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # 1. Edge strength: Sobel magnitude on luminance
        from scipy.ndimage import sobel as _sobel
        sx = _sobel(lum, axis=1).astype(_np.float32)
        sy = _sobel(lum, axis=0).astype(_np.float32)
        edge_mag = _np.sqrt(sx * sx + sy * sy).astype(_np.float32)
        edge_norm = edge_mag / (edge_mag.max() + 1e-7)

        # 2. Local contrast: local std in neighbourhood
        lum_sq = lum * lum
        local_mean = _gauss(lum, sigma=3.0).astype(_np.float32)
        local_mean_sq = _gauss(lum_sq, sigma=3.0).astype(_np.float32)
        local_var = _np.clip(local_mean_sq - local_mean * local_mean, 0.0, None)
        local_std = _np.sqrt(local_var).astype(_np.float32)
        std_norm = local_std / (local_std.max() + 1e-7)

        # 3. Focal proximity
        xs = _np.linspace(0.0, 1.0, w, dtype=_np.float32)
        ys = _np.linspace(0.0, 1.0, h, dtype=_np.float32)
        xg, yg = _np.meshgrid(xs, ys)
        dist = _np.sqrt((xg - float(cx)) ** 2 + (yg - float(cy)) ** 2).astype(_np.float32)
        diag = float(_np.sqrt(2.0) * 0.5)
        dist_norm = _np.clip(dist / (diag + 1e-7), 0.0, 1.0).astype(_np.float32)
        ik = float(importance_k)
        proximity = (1.0 / (1.0 + _np.exp(ik * (dist_norm - 0.45)))).astype(_np.float32)

        # 4. Importance score
        fw = float(focal_weight)
        contrast_score = (edge_norm * std_norm).astype(_np.float32)
        cs_norm = contrast_score / (contrast_score.max() + 1e-7)
        importance = ((1.0 - fw) * cs_norm + fw * proximity).astype(_np.float32)
        importance = importance / (importance.max() + 1e-7)

        # 5. Found edge sharpening (unsharp mask)
        fr = float(found_radius)
        fs = float(found_sharpness)
        r_blur_f = _gauss(r0, sigma=fr).astype(_np.float32)
        g_blur_f = _gauss(g0, sigma=fr).astype(_np.float32)
        b_blur_f = _gauss(b0, sigma=fr).astype(_np.float32)

        r_sharp = _np.clip(r0 + fs * (r0 - r_blur_f), 0.0, 1.0).astype(_np.float32)
        g_sharp = _np.clip(g0 + fs * (g0 - g_blur_f), 0.0, 1.0).astype(_np.float32)
        b_sharp = _np.clip(b0 + fs * (b0 - b_blur_f), 0.0, 1.0).astype(_np.float32)

        found_gate = _np.clip(importance, 0.0, 1.0) ** 0.7
        r_found = r0 * (1.0 - found_gate) + r_sharp * found_gate
        g_found = g0 * (1.0 - found_gate) + g_sharp * found_gate
        b_found = b0 * (1.0 - found_gate) + b_sharp * found_gate

        # 6. Lost edge softening
        ls = float(lost_sigma)
        r_soft = _gauss(r_found, sigma=ls).astype(_np.float32)
        g_soft = _gauss(g_found, sigma=ls).astype(_np.float32)
        b_soft = _gauss(b_found, sigma=ls).astype(_np.float32)

        lost_gate = _np.clip(1.0 - importance, 0.0, 1.0) ** 0.7
        r1 = _np.clip(r_found * (1.0 - lost_gate) + r_soft * lost_gate, 0.0, 1.0)
        g1 = _np.clip(g_found * (1.0 - lost_gate) + g_soft * lost_gate, 0.0, 1.0)
        b1 = _np.clip(b_found * (1.0 - lost_gate) + b_soft * lost_gate, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        found_mean = float(found_gate.mean())
        lost_mean  = float(lost_gate.mean())
        print(f"    Paint Lost-Found Edges complete "
              f"(focus=({cx:.2f},{cy:.2f}) found_mean={found_mean:.3f} "
              f"lost_mean={lost_mean:.3f})")

    def signac_divisionist_mosaic_pass(
        self,
        patch_size:  int   = 6,
        comp_mix:    float = 0.35,
        sat_boost:   float = 0.22,
        hue_thresh:  float = 80.0,
        blend_sigma: float = 0.8,
        opacity:     float = 0.72,
    ) -> None:
        r"""
        Signac Divisionist Mosaic -- session 242: ONE HUNDRED AND FIFTY-THIRD distinct mode.

        Implements Paul Signac (1863-1935) Divisionist technique.  A passionate
        sailor and devoted theorist, Signac extended Seurat's pointillism into a
        more muscular, directional practice: where Seurat used tiny circular dots of
        uniform size arranged in a dense, isotropic field, Signac evolved toward
        larger rectangular or square mosaic-like brushstrokes -- each a flat patch of
        pure, unmixed colour whose visual effect depended on optical mixing at distance.
        He grounded his method in three bodies of colour science:

          - Michel-Eugene Chevreul's law of simultaneous contrast: two complementary
            colours placed adjacent will each appear more vivid than either would in
            isolation (orange appears more orange next to blue; blue more intensely
            blue next to orange).
          - Ogden Rood's Modern Chromatics (1879): a scientific model of chromatic
            mixing describing how pigments and coloured lights mix differently, and
            providing the first rigorous colour circle with accurate complementary pairs.
          - Charles Henry's harmonic and aesthetic theories: directional lines carry
            emotional weight; colour intervals mirror musical intervals.

        The result: a canvas that from close range reads as a shimmering mosaic of
        discrete coloured patches, but at gallery distance resolves into luminous,
        vibrating passages of pure optical light.

        THREE-STAGE DIVISIONIST MOSAIC SIMULATION:

        Stage 1 PATCH QUANTIZATION:
        The canvas is subdivided into patch_size x patch_size rectangular tiles.
        For each tile, the mean RGB colour is computed by vectorised block-reshape
        mean pooling (no per-pixel Python loops):
            r_tile = mean(r_ch[tile]) over all pixels in the tile
        The mean is broadcast back to the full tile, producing flat-colour mosaic
        patches -- each representing one of Signac's rectangular brushstrokes.
        NOVEL: (a) VECTORISED RECTANGULAR PATCH QUANTIZATION -- first pass to apply
        divisionist colour quantization via numpy block-reshape mean pooling, producing
        a rectangular-patch mosaic; pointillist_pass applies circular dots at random
        positions; fauvist_mosaic_pass uses Voronoi / random zone assignment; neither
        uses rectangular block-mean quantization with numpy reshape.

        Stage 2 COMPLEMENTARY INTERLEAVING:
        Within each patch, a tile-level checkerboard mask -- (patch_row + patch_col) % 2 --
        assigns even tiles to the primary (mean) colour and odd tiles to the complementary
        colour (hue rotated 180 degrees on the colour wheel, same saturation and value):
            comp_hue = (patch_hue + 180.0) % 360.0
            comp_rgb = hsv_to_rgb(comp_hue, patch_sat, patch_val)
            mosaic_pixel = primary  if (patch_row + patch_col) % 2 == 0
                         = primary * (1 - comp_mix) + complement * comp_mix  otherwise
        This implements Chevreul's simultaneous contrast at the intra-patch level:
        each tile contains both the dominant hue and its complement, maximising the
        optical vibrancy of the mosaic at close range.
        NOVEL: (b) TILE-LEVEL COMPLEMENTARY CHECKERBOARD -- first pass to interleave
        the primary colour and its 180-degree hue complement within the same quantized
        patch using a tile-index (not single-pixel) checkerboard; chromatic_split_pass
        shifts RGB channels laterally; pointillist_pass places random complementary
        dots offset by a fixed distance; neither interleaves hue-opposite tiles within
        the same quantized block.

        Stage 3 SIMULTANEOUS CONTRAST BOUNDARY BOOST:
        At boundaries between adjacent patches, Chevreul's simultaneous contrast
        effect intensifies: opposing-hue colours at a shared edge appear more vivid
        than identical patches surrounded by neutral neighbours.  To simulate this:
            hdiff = min(|hue_A - hue_B|, 360 - |hue_A - hue_B|)  (wrap-around distance)
            boost = sat_boost * clip((hdiff - hue_thresh) / (180 - hue_thresh), 0, 1)
            sat_boosted = clip(patch_sat + boost * is_boundary_pixel, 0, 1)
        Applied only to pixels on the boundary rows/columns of each patch.
        NOVEL: (c) SIMULTANEOUS CONTRAST SATURATION BOOST AT OPPOSING-HUE BOUNDARIES
        -- first pass to detect adjacent patches with large hue differences (> hue_thresh)
        and boost saturation specifically at those inter-patch boundaries proportionally
        to how far the adjacent hues are apart on the colour wheel; no prior pass applies
        Chevreul simultaneous contrast as a boundary-localised, hue-distance-weighted
        saturation boost.

        patch_size  : Width/height of each rectangular mosaic patch in pixels.
        comp_mix    : Fraction of complementary colour blended into odd-tile patches (0..1).
        sat_boost   : Maximum saturation boost at high-hue-contrast patch boundaries.
        hue_thresh  : Minimum hue difference (degrees) before boundary boost activates.
        blend_sigma : Light Gaussian sigma for post-mosaic integration blur.
        opacity     : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss

        print("    Signac Divisionist Mosaic pass (session 242: 153rd mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        ps = max(2, int(patch_size))

        # ── Stage 1: Patch quantization via block-reshape mean pooling ────────
        ph = ((h - 1) // ps + 1) * ps
        pw = ((w - 1) // ps + 1) * ps

        def _pad(a):
            return _np.pad(a, ((0, ph - h), (0, pw - w)), mode='edge').astype(_np.float32)

        rp, gp, bp_ch = _pad(r0), _pad(g0), _pad(b0)
        n_ph, n_pw = ph // ps, pw // ps

        rr = rp.reshape(n_ph, ps, n_pw, ps).mean(axis=(1, 3)).astype(_np.float32)
        gg = gp.reshape(n_ph, ps, n_pw, ps).mean(axis=(1, 3)).astype(_np.float32)
        bb = bp_ch.reshape(n_ph, ps, n_pw, ps).mean(axis=(1, 3)).astype(_np.float32)

        patch_r = _np.repeat(_np.repeat(rr, ps, axis=0), ps, axis=1)[:h, :w].astype(_np.float32)
        patch_g = _np.repeat(_np.repeat(gg, ps, axis=0), ps, axis=1)[:h, :w].astype(_np.float32)
        patch_b = _np.repeat(_np.repeat(bb, ps, axis=0), ps, axis=1)[:h, :w].astype(_np.float32)

        # ── RGB <-> HSV helpers (fully vectorised) ────────────────────────────
        def _rgb_to_hsv(r, g, b):
            maxc = _np.maximum(r, _np.maximum(g, b)).astype(_np.float32)
            minc = _np.minimum(r, _np.minimum(g, b)).astype(_np.float32)
            v    = maxc
            diff = (maxc - minc).astype(_np.float32)
            s    = _np.where(maxc > 1e-7, diff / (maxc + 1e-7), 0.0).astype(_np.float32)
            eps  = 1e-7
            h_deg = _np.zeros_like(r, dtype=_np.float32)
            mr = (maxc == r) & (diff > eps)
            mg = (maxc == g) & ~mr & (diff > eps)
            mb = (maxc == b) & ~mr & ~mg & (diff > eps)
            h_deg[mr] = (60.0 * ((g[mr] - b[mr]) / (diff[mr] + eps))) % 360.0
            h_deg[mg] = (60.0 * ((b[mg] - r[mg]) / (diff[mg] + eps))) + 120.0
            h_deg[mb] = (60.0 * ((r[mb] - g[mb]) / (diff[mb] + eps))) + 240.0
            h_deg = h_deg % 360.0
            return h_deg, s, v

        def _hsv_to_rgb(h_deg, s, v):
            h6 = (h_deg / 60.0).astype(_np.float32)
            i  = _np.floor(h6).astype(_np.int32) % 6
            f  = (h6 - _np.floor(h6)).astype(_np.float32)
            p  = (v * (1.0 - s)).astype(_np.float32)
            q  = (v * (1.0 - f * s)).astype(_np.float32)
            t  = (v * (1.0 - (1.0 - f) * s)).astype(_np.float32)
            r_ = _np.select([i == 0, i == 1, i == 2, i == 3, i == 4], [v, q, p, p, t], default=v)
            g_ = _np.select([i == 0, i == 1, i == 2, i == 3, i == 4], [t, v, v, q, p], default=p)
            b_ = _np.select([i == 0, i == 1, i == 2, i == 3, i == 4], [p, p, t, v, v], default=q)
            return r_.astype(_np.float32), g_.astype(_np.float32), b_.astype(_np.float32)

        ph_map, ps_map, pv_map = _rgb_to_hsv(patch_r, patch_g, patch_b)

        # ── Stage 2: Complementary interleaving ──────────────────────────────
        # Tile-level checkerboard by patch row/col index
        iy = _np.arange(h)[:, None] // ps   # patch row index
        ix = _np.arange(w)[None, :] // ps   # patch col index
        tile_check = ((iy + ix) % 2).astype(_np.float32)  # 0=primary, 1=complement

        comp_h = (ph_map + 180.0) % 360.0
        comp_r, comp_g, comp_b_ch = _hsv_to_rgb(comp_h, ps_map, pv_map)

        cm = float(comp_mix)
        r_mosaic = _np.where(tile_check > 0.5, patch_r * (1.0 - cm) + comp_r * cm, patch_r).astype(_np.float32)
        g_mosaic = _np.where(tile_check > 0.5, patch_g * (1.0 - cm) + comp_g * cm, patch_g).astype(_np.float32)
        b_mosaic = _np.where(tile_check > 0.5, patch_b * (1.0 - cm) + comp_b_ch * cm, patch_b).astype(_np.float32)

        # ── Stage 3: Simultaneous contrast boundary saturation boost ─────────
        ht = float(hue_thresh)
        sb = float(sat_boost)

        # Hue-difference map: compare each patch hue with rightward and downward neighbor
        hue_r_shift = _np.roll(ph_map, -1, axis=1)
        hue_d_shift = _np.roll(ph_map, -1, axis=0)
        hdiff_h = _np.abs(ph_map - hue_r_shift)
        hdiff_h = _np.minimum(hdiff_h, 360.0 - hdiff_h)
        hdiff_v = _np.abs(ph_map - hue_d_shift)
        hdiff_v = _np.minimum(hdiff_v, 360.0 - hdiff_v)
        hdiff   = _np.maximum(hdiff_h, hdiff_v).astype(_np.float32)

        # Boundary mask: pixels on edge rows/cols of each patch
        prow = _np.arange(h)[:, None] % ps
        pcol = _np.arange(w)[None, :] % ps
        is_boundary = ((prow == 0) | (prow == ps - 1) |
                       (pcol == 0) | (pcol == ps - 1)).astype(_np.float32)

        boost = _np.clip((hdiff - ht) / (180.0 - ht + 1e-7), 0.0, 1.0) * sb * is_boundary
        boost = boost.astype(_np.float32)

        hm, sm, vm = _rgb_to_hsv(r_mosaic, g_mosaic, b_mosaic)
        sm_boosted = _np.clip(sm + boost, 0.0, 1.0).astype(_np.float32)
        r_out, g_out, b_out = _hsv_to_rgb(hm, sm_boosted, vm)

        # Light integration blur
        if float(blend_sigma) > 0.05:
            bs = float(blend_sigma)
            r_out = _gauss(r_out, sigma=bs).astype(_np.float32)
            g_out = _gauss(g_out, sigma=bs).astype(_np.float32)
            b_out = _gauss(b_out, sigma=bs).astype(_np.float32)

        r_out = _np.clip(r_out, 0.0, 1.0)
        g_out = _np.clip(g_out, 0.0, 1.0)
        b_out = _np.clip(b_out, 0.0, 1.0)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r_out * op
        new_g = g0 * (1.0 - op) + g_out * op
        new_b = b0 * (1.0 - op) + b_out * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        mean_sat = float(sm.mean())
        mean_boost = float(boost.mean())
        print(f"    Signac Divisionist Mosaic complete "
              f"(patch_size={ps} comp_mix={cm:.2f} "
              f"mean_sat={mean_sat:.3f} mean_boundary_boost={mean_boost:.4f})")


    def kirchner_brucke_expressionist_pass(
        self,
        hue_pull_str:    float = 0.55,
        contour_thresh:  float = 0.08,
        contour_dark:    float = 0.32,
        polarize_radius: int   = 7,
        polarize_str:    float = 0.28,
        opacity:         float = 0.80,
    ) -> None:
        r"""Kirchner Die Brucke Expressionist -- session 243: ONE HUNDRED AND FIFTY-FOURTH distinct mode.

        THREE-STAGE DIE BRUECKE EXPRESSIONIST SIMULATION:
        Stage 1 CHROMATIC DISSONANCE AMPLIFICATION: Five Kirchner hue poles (0, 50, 110, 225, 300 deg).
        Per-pixel hue rotated toward nearest pole; rot_mag=hue_pull_str*(1-dist/90), zero at pole.
        Saturation boosted by 0.5*rot_mag. NOVEL: (a) MULTI-POLE HUE ATTRACTION -- first pass
        to pull each pixel hue toward its nearest entry in an artist-specific pole vocabulary
        using per-pixel angular-distance weighting; prior passes use single warm/cool target.
        Stage 2 WOODCUT CONTOUR DARKENING: Sobel gradient normalised to 99th percentile.
        dark_factor=1-(1-contour_dark)*clip((grad-thresh)/(1-thresh),0,1). Multiplicative
        darkening drives high-gradient pixels toward pure black, simulating woodblock contour.
        NOVEL: (b) GRADIENT-MAGNITUDE-WEIGHTED MULTIPLICATIVE CONTOUR DARKENING -- first pass
        to apply gradient-proportional multiplicative darkness at form boundaries toward black.
        Stage 3 FLAT PLANE VALUE POLARIZATION: local luminance mean via uniform_filter(radius).
        above-mean pushed brighter, below-mean pushed darker by polarize_str*(lum-local_mean).
        NOVEL: (c) LOCAL-MEAN-RELATIVE LUMINANCE POLARIZATION -- first pass to apply
        bidirectional value push relative to sliding luminance mean, creating Kirchner hard
        tonal jumps between slab-like colour planes.

        hue_pull_str    : Chromatic pull strength toward Kirchner palette poles.
        contour_thresh  : Normalised gradient threshold for contour darkening.
        contour_dark    : Minimum value multiplier at strongest edges (0=black, 1=no effect).
        polarize_radius : Half-width of box-filter window for local luminance mean.
        polarize_str    : Bidirectional value push magnitude.
        opacity         : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import uniform_filter as _ufilt, sobel as _sobel

        print("    Kirchner Die Brucke Expressionist pass (session 243: 154th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        def _rgb_to_hsv(r, g, b):
            maxc = _np.maximum(r, _np.maximum(g, b)).astype(_np.float32)
            minc = _np.minimum(r, _np.minimum(g, b)).astype(_np.float32)
            v    = maxc
            diff = (maxc - minc).astype(_np.float32)
            s    = _np.where(maxc > 1e-7, diff / (maxc + 1e-7), 0.0).astype(_np.float32)
            eps  = 1e-7
            h_deg = _np.zeros_like(r, dtype=_np.float32)
            mr = (maxc == r) & (diff > eps)
            mg = (maxc == g) & ~mr & (diff > eps)
            mb = (maxc == b) & ~mr & ~mg & (diff > eps)
            h_deg[mr] = (60.0 * ((g[mr] - b[mr]) / (diff[mr] + eps))) % 360.0
            h_deg[mg] = (60.0 * ((b[mg] - r[mg]) / (diff[mg] + eps))) + 120.0
            h_deg[mb] = (60.0 * ((r[mb] - g[mb]) / (diff[mb] + eps))) + 240.0
            h_deg = h_deg % 360.0
            return h_deg, s, v

        def _hsv_to_rgb(h_deg, s, v):
            h6 = (h_deg / 60.0).astype(_np.float32)
            i  = _np.floor(h6).astype(_np.int32) % 6
            f  = (h6 - _np.floor(h6)).astype(_np.float32)
            p  = (v * (1.0 - s)).astype(_np.float32)
            q  = (v * (1.0 - f * s)).astype(_np.float32)
            t  = (v * (1.0 - (1.0 - f) * s)).astype(_np.float32)
            r_ = _np.select([i==0,i==1,i==2,i==3,i==4],[v,q,p,p,t], default=v)
            g_ = _np.select([i==0,i==1,i==2,i==3,i==4],[t,v,v,q,p], default=p)
            b_ = _np.select([i==0,i==1,i==2,i==3,i==4],[p,p,t,v,v], default=q)
            return r_.astype(_np.float32), g_.astype(_np.float32), b_.astype(_np.float32)

        hue, sat, val = _rgb_to_hsv(r0, g0, b0)

        # Stage 1: Chromatic dissonance amplification
        poles = _np.array([0.0, 50.0, 110.0, 225.0, 300.0], dtype=_np.float32)
        pull  = float(hue_pull_str)
        h_exp = hue[:, :, _np.newaxis]
        raw   = _np.abs(h_exp - poles[_np.newaxis, _np.newaxis, :])
        dist  = _np.minimum(raw, 360.0 - raw).astype(_np.float32)
        nearest_idx  = _np.argmin(dist, axis=2).astype(_np.int32)
        nearest_hue  = poles[nearest_idx].astype(_np.float32)
        nearest_dist = dist[_np.arange(h)[:, None], _np.arange(w)[None, :], nearest_idx]
        rot_mag  = _np.clip(1.0 - nearest_dist / 90.0, 0.0, 1.0).astype(_np.float32) * pull
        raw_diff = nearest_hue - hue
        rot_dir  = _np.where(raw_diff > 180.0, raw_diff - 360.0,
                   _np.where(raw_diff < -180.0, raw_diff + 360.0, raw_diff))
        rot_dir  = _np.sign(rot_dir).astype(_np.float32)
        hue_rot    = (hue + rot_dir * rot_mag * 45.0) % 360.0
        sat_pulled = _np.clip(sat + 0.5 * rot_mag, 0.0, 1.0).astype(_np.float32)
        r1, g1, b1 = _hsv_to_rgb(hue_rot, sat_pulled, val)

        # Stage 2: Woodcut contour darkening
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        gx = _sobel(lum1, axis=1).astype(_np.float32)
        gy = _sobel(lum1, axis=0).astype(_np.float32)
        grad_mag  = _np.hypot(gx, gy).astype(_np.float32)
        p99 = max(float(_np.percentile(grad_mag, 99)), 1e-7)
        grad_norm = _np.clip(grad_mag / p99, 0.0, 1.0).astype(_np.float32)
        ct  = float(contour_thresh)
        cd  = float(contour_dark)
        dark_factor = 1.0 - _np.clip((grad_norm - ct)/(1.0-ct+1e-7), 0.0, 1.0)*(1.0-cd)
        hue2, sat2, val2 = _rgb_to_hsv(r1, g1, b1)
        val2_dark = _np.clip(val2 * dark_factor, 0.0, 1.0).astype(_np.float32)
        r2, g2, b2 = _hsv_to_rgb(hue2, sat2, val2_dark)

        # Stage 3: Flat plane value polarization
        pr = max(1, int(polarize_radius))
        ps = float(polarize_str)
        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        local_mean = _ufilt(lum2, size=2*pr+1, mode='reflect').astype(_np.float32)
        polar_push = ps * (lum2 - local_mean)
        hue3, sat3, val3 = _rgb_to_hsv(r2, g2, b2)
        val3_polar = _np.clip(val3 + polar_push, 0.0, 1.0).astype(_np.float32)
        r_out, g_out, b_out = _hsv_to_rgb(hue3, sat3, val3_polar)
        r_out = _np.clip(r_out, 0.0, 1.0)
        g_out = _np.clip(g_out, 0.0, 1.0)
        b_out = _np.clip(b_out, 0.0, 1.0)
        op    = float(opacity)
        new_r = r0*(1.0-op) + r_out*op
        new_g = g0*(1.0-op) + g_out*op
        new_b = b0*(1.0-op) + b_out*op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r*255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g*255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b*255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print(f"    Kirchner Die Brucke Expressionist complete (hue_pull={pull:.2f} "
              f"mean_rot={float(rot_mag.mean()):.3f} mean_grad={float(grad_norm.mean()):.3f} "
              f"mean_polar={float(_np.abs(polar_push).mean()):.4f})")

    def paint_imprimatura_warmth_pass(
        self,
        warmth_gate:   float = 0.35,
        warmth_str:    float = 0.22,
        imprimatura_r: float = 0.68,
        imprimatura_g: float = 0.42,
        imprimatura_b: float = 0.18,
        edge_warmth:   float = 0.12,
        edge_sigma:    float = 1.2,
        opacity:       float = 0.60,
    ) -> None:
        r"""Paint Imprimatura Warmth -- session 243 artistic improvement.

        Simulates the warm oil ground (imprimatura) glowing through thin paint in
        shadow zones and at brushstroke edges. THREE-STAGE LUMINANCE-GATED:
        Stage 1: warmth_mask=clip((warmth_gate-L)/warmth_gate,0,1) -- luminance-gated mask.
        Stage 2: imprimatura colour blend: ch=ch*(1-str*mask)+imp_ch*str*mask.
        Stage 3: Sobel edge fringe -- warm colour bled at high-gradient stroke perimeters.
        NOVEL: (a) luminance-gated imprimatura blend; (b) configurable ground colour
        per-pixel blend with luminance-inverse weight; (c) gradient-detected edge warmth
        fringe. All three novel over prior passes (warm_cool_zone_pass applies spatial zones).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss, sobel as _sobel

        print("    Paint Imprimatura Warmth pass (session 243 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        lum = (0.299*r0 + 0.587*g0 + 0.114*b0).astype(_np.float32)
        wg = float(warmth_gate); ws = float(warmth_str)
        imp_r = float(imprimatura_r); imp_g = float(imprimatura_g); imp_b = float(imprimatura_b)

        warmth_mask = _np.clip((wg - lum)/(wg + 1e-7), 0.0, 1.0).astype(_np.float32)
        blend = ws * warmth_mask
        r1 = _np.clip(r0*(1.0-blend) + imp_r*blend, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0*(1.0-blend) + imp_g*blend, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0*(1.0-blend) + imp_b*blend, 0.0, 1.0).astype(_np.float32)

        gx = _sobel(lum, axis=1).astype(_np.float32)
        gy = _sobel(lum, axis=0).astype(_np.float32)
        grad_mag  = _np.hypot(gx, gy).astype(_np.float32)
        p99 = max(float(_np.percentile(grad_mag, 99)), 1e-7)
        grad_norm = _np.clip(grad_mag/p99, 0.0, 1.0).astype(_np.float32)
        edge_mask = _gauss(grad_norm, sigma=float(edge_sigma)).astype(_np.float32)
        ew = float(edge_warmth)
        r_out = _np.clip(r1 + ew*edge_mask*(imp_r-r1), 0.0, 1.0).astype(_np.float32)
        g_out = _np.clip(g1 + ew*edge_mask*(imp_g-g1), 0.0, 1.0).astype(_np.float32)
        b_out = _np.clip(b1 + ew*edge_mask*(imp_b-b1), 0.0, 1.0).astype(_np.float32)

        op    = float(opacity)
        new_r = r0*(1.0-op) + r_out*op
        new_g = g0*(1.0-op) + g_out*op
        new_b = b0*(1.0-op) + b_out*op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r*255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g*255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b*255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print(f"    Paint Imprimatura Warmth complete (gate={wg:.2f} str={ws:.2f} "
              f"mean_mask={float(warmth_mask.mean()):.3f} mean_edge={float(edge_mask.mean()):.3f})")

    def paint_color_bloom_pass(
        self,
        bloom_threshold: float = 0.52,
        bloom_sigma:     float = 3.0,
        bloom_strength:  float = 0.28,
        chroma_shift:    float = 0.015,
        opacity:         float = 0.65,
    ) -> None:
        r"""
        Paint Color Bloom -- session 242 artistic improvement.

        In any physical painting made with oil or egg-tempera pigments, highly
        saturated colours exhibit a phenomenon painters call "irradiation" or colour
        bloom: vivid reds, blues, and yellows appear to glow or spread slightly beyond
        their physical paint boundary, halating into neighbouring, less-saturated areas.
        This is partly perceptual (the eye's over-response to intense chroma) and partly
        optical: highly saturated pigments absorb and re-emit light with a very selective
        spectral response, producing slight chromatic scattering at their physical edge.
        The blue channel scatters more than red (shorter wavelength, higher diffraction
        index), producing a faint chromatic fringe -- blue bleeding slightly further than
        red -- at the boundary of any intensely saturated region.

        THREE-STAGE SATURATION-GATED COLOUR BLOOM:

        Stage 1 SATURATION-GATED BLOOM MASK:
        For each pixel, compute saturation S = (max_rgb - min_rgb) / max_rgb.
        Create a graduated bloom mask weighted by excess saturation above threshold:
            bloom_mask = clip((S - bloom_threshold) / (1.0 - bloom_threshold), 0, 1)
        Only pixels with S > bloom_threshold contribute to the bloom source.
        The graduated weighting means more saturated pixels create a stronger bloom.
        NOVEL: (a) SATURATION-THRESHOLD-GATED BLOOM SOURCE -- first pass to apply
        colour irradiation specifically and only to pixels exceeding a per-pixel
        saturation threshold, with the bloom mask weighted proportionally to the
        excess saturation; all prior passes apply effects uniformly or gated by
        luminance (not saturation); the saturation gate is physically correct because
        irradiation is a property of spectral purity (chroma), not brightness (value).

        Stage 2 GAUSSIAN COLOUR BLEEDING:
        The bloom mask is spread outward by Gaussian diffusion to model the halo of
        irradiation in adjacent, less-saturated pixels:
            bloom_spread = gaussian_blur(bloom_mask, sigma=bloom_sigma)
            effective_strength = bloom_spread * bloom_strength
            ch_bloomed = ch_original * (1 - effective_strength) + ch_blurred * effective_strength
        where ch_blurred = gaussian_blur(ch_original, sigma=bloom_sigma).
        The blurred channel carries the saturated source colour outward; the bloom_spread
        mask controls where that colour bleeds and by how much.
        NOVEL: (b) SATURATION-PROPORTIONAL BLOOM SPREAD -- first pass where the
        intensity of colour bleeding into adjacent pixels is proportional to how much
        the source pixel's saturation exceeds the threshold; the spread is not just
        the Gaussian blur of the image but the Gaussian spread of the SATURATION EXCESS
        MASK, so the bloom extends further from more deeply saturated sources and
        barely at all from borderline-saturated ones.

        Stage 3 CHROMATIC FRINGE:
        Blue light (shorter wavelength, higher refractive index) diffracts slightly
        more at colour boundaries than red light, creating a faint blue-biased fringe
        at the outer edge of highly saturated colour zones:
            b_extra = gaussian_blur(b_channel, sigma=bloom_sigma * (1 + 2*chroma_shift))
            fringe_mask = clip(blur(bloom_mask, sigma=bloom_sigma*(1+chroma_shift))
                               - bloom_mask, 0, 1)
            b_final = b_bloomed + fringe_mask * chroma_shift * b_extra
        The fringe_mask isolates the OUTER ANNULAR ZONE of the bloom halo -- the region
        where the spread exceeds the source but is still elevated -- and adds a small
        blue bias there.
        NOVEL: (c) SATURATION-GATED DIFFERENTIAL CHROMATIC FRINGE -- first pass to
        apply a blue-biased chromatic spread specifically at the outer annular zone of
        high-saturation colour halos; the existing chromatic_split_pass applies a
        uniform lateral channel offset across the entire canvas; this pass targets
        only the outer fringe of saturation-gated bloom regions, and only boosts blue
        (not all channels), matching the physical optics of short-wavelength diffraction.

        bloom_threshold : Minimum saturation (0..1) for a pixel to be a bloom source.
        bloom_sigma     : Gaussian sigma for colour spread and fringe calculation.
        bloom_strength  : Maximum blend fraction of bloomed vs original colour in adjacent pixels.
        chroma_shift    : Magnitude of blue-channel extra spread (as fraction of bloom_sigma).
        opacity         : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss

        print("    Paint Color Bloom pass (session 242 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Saturation-gated bloom mask ─────────────────────────────
        maxc = _np.maximum(r0, _np.maximum(g0, b0)).astype(_np.float32)
        minc = _np.minimum(r0, _np.minimum(g0, b0)).astype(_np.float32)
        sat  = _np.where(maxc > 1e-7, (maxc - minc) / (maxc + 1e-7), 0.0).astype(_np.float32)

        bt = float(bloom_threshold)
        bloom_mask = _np.clip((sat - bt) / (1.0 - bt + 1e-7), 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Gaussian colour bleeding ────────────────────────────────
        bs  = float(bloom_sigma)
        bst = float(bloom_strength)
        cs  = float(chroma_shift)

        r_blur = _gauss(r0, sigma=bs).astype(_np.float32)
        g_blur = _gauss(g0, sigma=bs).astype(_np.float32)
        b_blur = _gauss(b0, sigma=bs).astype(_np.float32)   # base blur for bleeding

        bloom_spread = _gauss(bloom_mask, sigma=bs).astype(_np.float32)
        bloom_spread = _np.clip(bloom_spread, 0.0, 1.0)

        eff = bloom_spread * bst
        r_bloomed = _np.clip(r0 * (1.0 - eff) + r_blur * eff, 0.0, 1.0).astype(_np.float32)
        g_bloomed = _np.clip(g0 * (1.0 - eff) + g_blur * eff, 0.0, 1.0).astype(_np.float32)
        b_bloomed = _np.clip(b0 * (1.0 - eff) + b_blur * eff, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Chromatic fringe (blue bleeds further) ──────────────────
        b_extra    = _gauss(b0, sigma=bs * (1.0 + 2.0 * cs)).astype(_np.float32)
        fringe_spread = _gauss(bloom_mask, sigma=bs * (1.0 + cs)).astype(_np.float32)
        fringe_mask   = _np.clip(fringe_spread - bloom_mask, 0.0, 1.0).astype(_np.float32)

        b_final = _np.clip(b_bloomed + fringe_mask * cs * b_extra, 0.0, 1.0).astype(_np.float32)

        r_out = r_bloomed
        g_out = g_bloomed
        b_out = b_final

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r_out * op
        new_g = g0 * (1.0 - op) + g_out * op
        new_b = b0 * (1.0 - op) + b_out * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        mean_bloom_coverage = float(bloom_spread.mean())
        mean_sat = float(sat.mean())
        print(f"    Paint Color Bloom complete "
              f"(threshold={bt:.2f} sigma={bs:.1f} "
              f"mean_sat={mean_sat:.3f} bloom_coverage={mean_bloom_coverage:.3f})")

    def beckmann_black_armature_pass(
        self,
        armature_thresh:   float = 0.12,
        armature_snap:     float = 0.82,
        compress_str:      float = 0.18,
        compress_mid:      float = 0.48,
        palette_str:       float = 0.40,
        palette_radius:    float = 55.0,
        opacity:           float = 0.82,
    ) -> None:
        r"""Beckmann Black Armature -- session 244: ONE HUNDRED AND FIFTY-FIFTH distinct mode.

        THREE-STAGE BLACK ARMATURE EXPRESSIONIST SIMULATION (Max Beckmann):

        Stage 1 GRADIENT-THRESHOLD SATURATION-STRIPPING SNAP TO BLACK: Compute Sobel
        gradient magnitude of luminance; normalise to 99th percentile. Where grad_norm
        exceeds armature_thresh, strip saturation and snap value toward black with
        strength proportional to (grad_norm - thresh)/(1-thresh)*armature_snap.
        This hard, erasure-like snap -- not Kirchner's gradual multiplicative darkening
        -- produces the decisive drawn-black armature bounding Beckmann's forms.
        NOVEL: (a) SATURATION-STRIPPED BLACK SNAP AT GRADIENT BOUNDARIES -- first pass
        to simultaneously zero saturation and snap value to black at high-gradient edges
        with a hard threshold gate; prior contour passes (kirchner) darken multiplicatively
        without saturation removal; this simulates Beckmann's drawn contour lines which
        are fully desaturated black, not darkened-colour outlines.

        Stage 2 BIDIRECTIONAL VALUE RANGE COMPRESSION TOWARD MIDTONE: Compute per-pixel
        value V; apply compression function V' = compress_mid + (V - compress_mid) *
        (1 - compress_str). Pixels above mid are pulled down; pixels below mid are pulled
        up. This symmetrically contracts the tonal range toward the mid-grey anchor,
        creating the airless, claustrophobic tonal flatness of Beckmann's interiors.
        NOVEL: (b) SYMMETRIC TONAL COMPRESSION TOWARD CONFIGURABLE MID-ANCHOR -- first
        pass to apply a symmetric linear contraction of the entire tonal range toward a
        single midpoint; prior passes push values apart (kirchner polarize), boost shadows
        (imprimatura warmth), or add glaze shift; none compress both extremes simultaneously
        toward a neutral anchor point.

        Stage 3 BECKMANN PALETTE ATTRACTION WITH HARD ANGULAR SNAP: Five Beckmann hue
        poles (salmon-orange 15, acid yellow-green 80, cold blue-violet 220, brick red
        350, deep teal 175 deg). Per-pixel hue pulled toward nearest pole if within
        palette_radius degrees; snap strength = palette_str * (1 - dist/palette_radius).
        Unlike Kirchner's soft rotation (rot_dir * rot_mag * 45), this applies a
        proportional angular fraction of the full rotation, landing harder at the pole.
        NOVEL: (c) PROPORTIONAL ANGULAR FRACTION HALO SNAP -- first pass to apply a
        proportional-distance snap where the hue jumps palette_str fraction of the
        remaining angular gap to the pole (rather than a fixed rotation magnitude);
        creates the sudden non-naturalistic hue jumps characteristic of Beckmann's palette.

        armature_thresh : Normalised gradient threshold for black armature activation.
        armature_snap   : Maximum snap strength toward black at strongest edges.
        compress_str    : Tonal compression strength (0=none, 1=all pixels to mid).
        compress_mid    : Mid-grey anchor for tonal compression (default 0.48).
        palette_str     : Fraction of angular gap to close toward each palette pole.
        palette_radius  : Angular search radius (degrees) for palette pole attraction.
        opacity         : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import uniform_filter as _ufilt, sobel as _sobel

        print("    Beckmann Black Armature pass (session 244: 155th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        def _rgb_to_hsv(r, g, b):
            maxc = _np.maximum(r, _np.maximum(g, b)).astype(_np.float32)
            minc = _np.minimum(r, _np.minimum(g, b)).astype(_np.float32)
            v    = maxc
            diff = (maxc - minc).astype(_np.float32)
            s    = _np.where(maxc > 1e-7, diff / (maxc + 1e-7), 0.0).astype(_np.float32)
            eps  = 1e-7
            h_deg = _np.zeros_like(r, dtype=_np.float32)
            mr = (maxc == r) & (diff > eps)
            mg = (maxc == g) & ~mr & (diff > eps)
            mb = (maxc == b) & ~mr & ~mg & (diff > eps)
            h_deg[mr] = (60.0 * ((g[mr] - b[mr]) / (diff[mr] + eps))) % 360.0
            h_deg[mg] = (60.0 * ((b[mg] - r[mg]) / (diff[mg] + eps))) + 120.0
            h_deg[mb] = (60.0 * ((r[mb] - g[mb]) / (diff[mb] + eps))) + 240.0
            h_deg = h_deg % 360.0
            return h_deg, s, v

        def _hsv_to_rgb(h_deg, s, v):
            h6 = (h_deg / 60.0).astype(_np.float32)
            i  = _np.floor(h6).astype(_np.int32) % 6
            f  = (h6 - _np.floor(h6)).astype(_np.float32)
            p  = (v * (1.0 - s)).astype(_np.float32)
            q  = (v * (1.0 - f * s)).astype(_np.float32)
            t  = (v * (1.0 - (1.0 - f) * s)).astype(_np.float32)
            r_ = _np.select([i==0,i==1,i==2,i==3,i==4],[v,q,p,p,t], default=v)
            g_ = _np.select([i==0,i==1,i==2,i==3,i==4],[t,v,v,q,p], default=p)
            b_ = _np.select([i==0,i==1,i==2,i==3,i==4],[p,p,t,v,v], default=q)
            return r_.astype(_np.float32), g_.astype(_np.float32), b_.astype(_np.float32)

        hue, sat, val = _rgb_to_hsv(r0, g0, b0)

        # Stage 1: Gradient-threshold saturation-stripping snap to black
        lum0 = (0.299*r0 + 0.587*g0 + 0.114*b0).astype(_np.float32)
        gx = _sobel(lum0, axis=1).astype(_np.float32)
        gy = _sobel(lum0, axis=0).astype(_np.float32)
        grad_mag  = _np.hypot(gx, gy).astype(_np.float32)
        p99 = max(float(_np.percentile(grad_mag, 99)), 1e-7)
        grad_norm = _np.clip(grad_mag / p99, 0.0, 1.0).astype(_np.float32)
        at  = float(armature_thresh)
        asnap = float(armature_snap)
        snap_weight = _np.clip((grad_norm - at) / (1.0 - at + 1e-7), 0.0, 1.0) * asnap
        val1 = _np.clip(val * (1.0 - snap_weight), 0.0, 1.0).astype(_np.float32)
        sat1 = _np.clip(sat * (1.0 - snap_weight), 0.0, 1.0).astype(_np.float32)
        r1, g1, b1 = _hsv_to_rgb(hue, sat1, val1)

        # Stage 2: Bidirectional value range compression toward midtone
        cs   = float(compress_str)
        cmid = float(compress_mid)
        hue2, sat2, val2 = _rgb_to_hsv(r1, g1, b1)
        val2_comp = _np.clip(cmid + (val2 - cmid) * (1.0 - cs), 0.0, 1.0).astype(_np.float32)
        r2, g2, b2 = _hsv_to_rgb(hue2, sat2, val2_comp)

        # Stage 3: Beckmann palette attraction with proportional angular snap
        poles = _np.array([15.0, 80.0, 175.0, 220.0, 350.0], dtype=_np.float32)
        pr    = float(palette_radius)
        ps    = float(palette_str)
        hue3, sat3, val3 = _rgb_to_hsv(r2, g2, b2)
        h_exp = hue3[:, :, _np.newaxis]
        raw   = _np.abs(h_exp - poles[_np.newaxis, _np.newaxis, :])
        dist  = _np.minimum(raw, 360.0 - raw).astype(_np.float32)
        nearest_idx  = _np.argmin(dist, axis=2).astype(_np.int32)
        nearest_hue  = poles[nearest_idx].astype(_np.float32)
        nearest_dist = dist[_np.arange(h)[:, None], _np.arange(w)[None, :], nearest_idx]
        in_radius = (nearest_dist < pr).astype(_np.float32)
        frac = _np.clip(1.0 - nearest_dist / (pr + 1e-7), 0.0, 1.0) * ps * in_radius
        raw_diff  = nearest_hue - hue3
        rot_dir   = _np.where(raw_diff > 180.0, raw_diff - 360.0,
                    _np.where(raw_diff < -180.0, raw_diff + 360.0, raw_diff))
        hue_out   = (hue3 + rot_dir * frac) % 360.0
        r_out, g_out, b_out = _hsv_to_rgb(hue_out, sat3, val3)
        r_out = _np.clip(r_out, 0.0, 1.0)
        g_out = _np.clip(g_out, 0.0, 1.0)
        b_out = _np.clip(b_out, 0.0, 1.0)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r_out * op
        new_g = g0 * (1.0 - op) + g_out * op
        new_b = b0 * (1.0 - op) + b_out * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print(f"    Beckmann Black Armature complete (snap={asnap:.2f} "
              f"compress={cs:.2f} palette_str={ps:.2f} "
              f"mean_snap={float(snap_weight.mean()):.3f} "
              f"mean_in_radius={float(in_radius.mean()):.3f})")

    def paint_aerial_perspective_pass(
        self,
        fine_sigma:    float = 1.2,
        coarse_sigma:  float = 12.0,
        depth_str:     float = 0.45,
        haze_r:        float = 0.80,
        haze_g:        float = 0.82,
        haze_b:        float = 0.90,
        haze_strength: float = 0.28,
        desat_str:     float = 0.30,
        opacity:       float = 0.70,
    ) -> None:
        r"""Paint Aerial Perspective -- session 244 artistic improvement.

        Atmospheric (aerial) perspective is the phenomenon whereby objects farther from
        the viewer appear lighter, bluer, and less saturated than objects in the
        foreground -- a consequence of light scattering in the intervening column of
        atmosphere.  Leonardo noted it as "perspective of disappearance"; Turner,
        Corot, Constable, and later Cézanne exploited it systematically.  In a
        traditional oil painting, distant passages are worked with thin, cool, pale
        washes; foreground passages are thick, warm, and saturated.

        This pass estimates scene depth non-geometrically using spatial frequency
        analysis: regions of low spatial frequency (large smooth areas) statistically
        correspond to distance/sky, while high-frequency (fine detail) areas correspond
        to foreground.  The Difference-of-Gaussians (DoG) map isolates this distinction
        and drives per-pixel desaturation and warm-to-cool haze blending.

        THREE-STAGE SPATIAL-FREQUENCY AERIAL PERSPECTIVE:

        Stage 1 DIFFERENCE-OF-GAUSSIANS DEPTH ESTIMATION: Compute luma channel; apply
        two Gaussian blurs at different scales (fine_sigma, coarse_sigma); DoG =
        |gaussian(luma, fine_sigma) - gaussian(luma, coarse_sigma)|; normalise to [0,1];
        depth_map = 1 - clip(DoG / 95th_percentile, 0, 1) -- high DoG = foreground
        (detail-rich), low DoG = background (smooth/distant). Normalise to [0,1].
        NOVEL: (a) DIFFERENCE-OF-GAUSSIANS INVERSE-FREQUENCY DEPTH MAP -- first pass to
        estimate foreground/background depth from spatial-frequency content using a DoG
        operator; all prior passes are frequency-agnostic or use gradient magnitude for
        edge detection, not for global depth estimation; the DoG map is a well-known
        scale-space operator repurposed here as a non-geometric depth proxy.

        Stage 2 DEPTH-WEIGHTED ATMOSPHERIC DESATURATION: Compute saturation S; apply
        per-pixel desaturation: S' = S * (1 - desat_str * depth_map). Pixels in smooth
        /background regions lose saturation proportionally to their estimated depth.
        NOVEL: (b) SPATIAL-FREQUENCY-GATED SELECTIVE DESATURATION -- first pass to apply
        saturation reduction gated by the DoG depth map rather than by luminance, gradient,
        or spatial zone; desat_str controls atmosphere density; the depth_map ensures
        that only statistically distant pixels are desaturated.

        Stage 3 DEPTH-WEIGHTED COOL HAZE BLEND: Blend each pixel toward the haze colour
        (default cool blue-grey) proportionally to depth_map * haze_strength. Lighter,
        cooler haze tint applied to background zones simulates the spectral shift caused
        by Rayleigh scattering of blue light in the atmosphere.
        NOVEL: (c) SPATIAL-FREQUENCY-GATED ATMOSPHERIC HAZE TINT -- first pass to apply
        a configurable haze colour blend weighted by DoG depth map; prior passes apply
        warm tints (imprimatura warmth, glaze gradient) or cool shifts (sfumato focus)
        but none use spatial frequency to gate a configurable atmospheric haze tint.

        fine_sigma    : Gaussian sigma for the fine-scale (foreground detail) blur.
        coarse_sigma  : Gaussian sigma for the coarse-scale (background smooth) blur.
        depth_str     : Scale applied to depth_map before downstream stages.
        haze_r/g/b    : RGB components of the atmospheric haze colour (default cool grey).
        haze_strength : Maximum fraction of haze colour blended at furthest depth.
        desat_str     : Maximum saturation reduction fraction at furthest depth.
        opacity       : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss

        print("    Paint Aerial Perspective pass (session 244 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        lum = (0.299*r0 + 0.587*g0 + 0.114*b0).astype(_np.float32)

        # Stage 1: DoG depth estimation
        fs = float(fine_sigma)
        cs_ = float(coarse_sigma)
        fine_blur   = _gauss(lum, sigma=fs).astype(_np.float32)
        coarse_blur = _gauss(lum, sigma=cs_).astype(_np.float32)
        dog = _np.abs(fine_blur - coarse_blur).astype(_np.float32)
        p95 = max(float(_np.percentile(dog, 95)), 1e-7)
        dog_norm  = _np.clip(dog / p95, 0.0, 1.0).astype(_np.float32)
        depth_map = _np.clip((1.0 - dog_norm) * float(depth_str), 0.0, 1.0).astype(_np.float32)

        # Stage 2: Depth-weighted atmospheric desaturation
        maxc = _np.maximum(r0, _np.maximum(g0, b0)).astype(_np.float32)
        minc = _np.minimum(r0, _np.minimum(g0, b0)).astype(_np.float32)
        diff = (maxc - minc).astype(_np.float32)
        sat  = _np.where(maxc > 1e-7, diff / (maxc + 1e-7), 0.0).astype(_np.float32)
        ds = float(desat_str)
        new_sat = _np.clip(sat * (1.0 - ds * depth_map), 0.0, 1.0).astype(_np.float32)
        desat_ratio = _np.where(sat > 1e-7, new_sat / (sat + 1e-7), 1.0).astype(_np.float32)
        r1 = lum + (r0 - lum) * desat_ratio
        g1 = lum + (g0 - lum) * desat_ratio
        b1 = lum + (b0 - lum) * desat_ratio
        r1 = _np.clip(r1, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g1, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b1, 0.0, 1.0).astype(_np.float32)

        # Stage 3: Depth-weighted cool haze blend
        hr = float(haze_r); hg = float(haze_g); hb_ = float(haze_b)
        hs = float(haze_strength)
        haze_blend = depth_map * hs
        r_out = _np.clip(r1 * (1.0 - haze_blend) + hr * haze_blend, 0.0, 1.0).astype(_np.float32)
        g_out = _np.clip(g1 * (1.0 - haze_blend) + hg * haze_blend, 0.0, 1.0).astype(_np.float32)
        b_out = _np.clip(b1 * (1.0 - haze_blend) + hb_ * haze_blend, 0.0, 1.0).astype(_np.float32)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r_out * op
        new_g = g0 * (1.0 - op) + g_out * op
        new_b = b0 * (1.0 - op) + b_out * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        mean_depth = float(depth_map.mean())
        mean_desat = float((1.0 - desat_ratio).mean())
        print(f"    Paint Aerial Perspective complete (fine_sigma={fs:.1f} "
              f"coarse_sigma={cs_:.1f} mean_depth={mean_depth:.3f} "
              f"mean_desat={mean_desat:.3f} haze_str={hs:.2f})")

    def jawlensky_abstract_head_pass(
        self,
        inner_radius:  float = 0.35,
        outer_radius:  float = 0.55,
        warm_hue:      float = 35.0,
        cool_hue:      float = 230.0,
        warmth_str:    float = 0.50,
        cool_str:      float = 0.45,
        cool_sat_lift: float = 0.12,
        cool_val_lift: float = 0.06,
        edge_thresh:   float = 0.10,
        edge_blue_r:   float = 0.08,
        edge_blue_g:   float = 0.10,
        edge_blue_b:   float = 0.38,
        edge_snap:     float = 0.72,
        opacity:       float = 0.80,
    ) -> None:
        r"""Jawlensky Abstract Head -- session 245: ONE HUNDRED AND FIFTY-SIXTH distinct mode.

        THREE-STAGE ICONIC RADIAL WARMTH SIMULATION (Alexej von Jawlensky):

        Stage 1 RADIAL WARMTH GRADIENT: Compute the normalised radial distance of each
        pixel from the image centroid. Pixels within inner_radius (fraction of half-diagonal)
        receive a hue attraction toward warm_hue (amber/saffron ~35 deg) with strength
        (1 - dist/inner_radius) * warmth_str. This encodes Jawlensky radial inner warmth.
        NOVEL: (a) RADIAL CENTRE-TO-PERIPHERY WARMTH MAP -- first pass to apply
        inward-warm/outward-cool hue shift weighted by normalised radial distance from
        image centroid; prior passes apply uniform warm tints (imprimatura), directional
        DoG-gated tints (aerial perspective), or edge-based snaps (Beckmann armature).

        Stage 2 COOL PERIPHERAL PUSH: Pixels beyond outer_radius receive a complementary
        hue attraction toward cool_hue (blue-violet ~230 deg) with strength proportional
        to (dist-outer_radius)/(1-outer_radius+eps)*cool_str. Simultaneously, saturation
        is boosted by cool_sat_lift and value is lifted by cool_val_lift in the outer zone.
        NOVEL: (b) COMPLEMENTARY COOL OUTER PUSH -- first pass to simultaneously apply
        cool hue shift + saturation boost + value lift in the image periphery only, weighted
        by radial distance from centroid.

        Stage 3 ULTRAMARINE EDGE TINT: Detect high-gradient boundaries via normalised
        Sobel magnitude. Blend edge pixels toward ultramarine-dark (edge_blue_r/g/b)
        rather than pure black. Unlike Beckmann (strips saturation + snaps to achromatic
        black) or Kirchner (multiplicative darkening), this blends toward a chromatically
        blue dark, producing Jawlensky blue-tinted contour lines.
        NOVEL: (c) CHROMATIC BLUE EDGE BLEND -- first pass to blend gradient-detected
        edge pixels toward a configurable blue-dark rather than achromatic black.

        inner_radius  : Radial fraction of half-diagonal for warm inner zone.
        outer_radius  : Radial fraction for start of cool outer zone.
        warm_hue      : Target hue (degrees) for inner warmth attraction (~35 amber).
        cool_hue      : Target hue (degrees) for outer cool attraction (~230 blue-violet).
        warmth_str    : Maximum warm hue attraction strength at centroid.
        cool_str      : Maximum cool hue attraction strength at periphery.
        cool_sat_lift : Saturation boost in outer zone.
        cool_val_lift : Value (brightness) lift in outer zone.
        edge_thresh   : Normalised gradient threshold for blue edge activation.
        edge_blue_r/g/b : RGB components of the ultramarine edge colour.
        edge_snap     : Maximum blend strength toward edge colour at strongest edges.
        opacity       : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel

        print("    Jawlensky Abstract Head pass (session 245: 156th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        def _rgb_to_hsv(r, g, b):
            maxc = _np.maximum(r, _np.maximum(g, b)).astype(_np.float32)
            minc = _np.minimum(r, _np.minimum(g, b)).astype(_np.float32)
            v    = maxc
            diff = (maxc - minc).astype(_np.float32)
            s    = _np.where(maxc > 1e-7, diff / (maxc + 1e-7), 0.0).astype(_np.float32)
            eps  = 1e-7
            h_deg = _np.zeros_like(r, dtype=_np.float32)
            mr = (maxc == r) & (diff > eps)
            mg = (maxc == g) & ~mr & (diff > eps)
            mb = (maxc == b) & ~mr & ~mg & (diff > eps)
            h_deg[mr] = (60.0 * ((g[mr] - b[mr]) / (diff[mr] + eps))) % 360.0
            h_deg[mg] = (60.0 * ((b[mg] - r[mg]) / (diff[mg] + eps))) + 120.0
            h_deg[mb] = (60.0 * ((r[mb] - g[mb]) / (diff[mb] + eps))) + 240.0
            h_deg = h_deg % 360.0
            return h_deg, s, v

        def _hsv_to_rgb(h_deg, s, v):
            h6 = (h_deg / 60.0).astype(_np.float32)
            i  = _np.floor(h6).astype(_np.int32) % 6
            f  = (h6 - _np.floor(h6)).astype(_np.float32)
            p  = (v * (1.0 - s)).astype(_np.float32)
            q  = (v * (1.0 - f * s)).astype(_np.float32)
            t_ = (v * (1.0 - (1.0 - f) * s)).astype(_np.float32)
            r_ = _np.select([i==0,i==1,i==2,i==3,i==4],[v,q,p,p,t_], default=v)
            g_ = _np.select([i==0,i==1,i==2,i==3,i==4],[t_,v,v,q,p], default=p)
            b_ = _np.select([i==0,i==1,i==2,i==3,i==4],[p,p,t_,v,v], default=q)
            return r_.astype(_np.float32), g_.astype(_np.float32), b_.astype(_np.float32)

        # Radial distance map normalised to half-diagonal
        cy_c = (h - 1) / 2.0
        cx_c = (w - 1) / 2.0
        half_diag = _np.hypot(cy_c, cx_c)
        ys = _np.arange(h, dtype=_np.float32)
        xs = _np.arange(w, dtype=_np.float32)
        yy, xx = _np.meshgrid(ys, xs, indexing="ij")
        dist_map = _np.hypot(yy - cy_c, xx - cx_c).astype(_np.float32)
        dist_norm = _np.clip(dist_map / (half_diag + 1e-7), 0.0, 1.0).astype(_np.float32)

        hue, sat, val = _rgb_to_hsv(r0, g0, b0)

        # Stage 1: Radial warmth gradient
        ir = float(inner_radius)
        wh = float(warm_hue)
        ws = float(warmth_str)
        warm_weight = _np.clip((1.0 - dist_norm / (ir + 1e-7)), 0.0, 1.0).astype(_np.float32)
        warm_weight = _np.where(dist_norm < ir, warm_weight, 0.0).astype(_np.float32)
        raw_diff_w = wh - hue
        rot_w = _np.where(raw_diff_w > 180.0, raw_diff_w - 360.0,
                _np.where(raw_diff_w < -180.0, raw_diff_w + 360.0, raw_diff_w))
        hue1 = (hue + rot_w * warm_weight * ws) % 360.0
        r1, g1, b1 = _hsv_to_rgb(hue1, sat, val)

        # Stage 2: Cool peripheral push
        orr = float(outer_radius)
        ch_ = float(cool_hue)
        cs_ = float(cool_str)
        csl = float(cool_sat_lift)
        cvl = float(cool_val_lift)
        cool_weight = _np.clip((dist_norm - orr) / (1.0 - orr + 1e-7), 0.0, 1.0).astype(_np.float32)
        cool_weight = _np.where(dist_norm > orr, cool_weight, 0.0).astype(_np.float32)
        hue2, sat2, val2 = _rgb_to_hsv(r1, g1, b1)
        raw_diff_c = ch_ - hue2
        rot_c = _np.where(raw_diff_c > 180.0, raw_diff_c - 360.0,
                _np.where(raw_diff_c < -180.0, raw_diff_c + 360.0, raw_diff_c))
        hue2_out = (hue2 + rot_c * cool_weight * cs_) % 360.0
        sat2_out = _np.clip(sat2 + cool_weight * csl, 0.0, 1.0).astype(_np.float32)
        val2_out = _np.clip(val2 + cool_weight * cvl, 0.0, 1.0).astype(_np.float32)
        r2, g2, b2 = _hsv_to_rgb(hue2_out, sat2_out, val2_out)

        # Stage 3: Ultramarine edge tint
        lum2 = (0.299*r2 + 0.587*g2 + 0.114*b2).astype(_np.float32)
        gx = _sobel(lum2, axis=1).astype(_np.float32)
        gy = _sobel(lum2, axis=0).astype(_np.float32)
        grad_mag  = _np.hypot(gx, gy).astype(_np.float32)
        p99 = max(float(_np.percentile(grad_mag, 99)), 1e-7)
        grad_norm = _np.clip(grad_mag / p99, 0.0, 1.0).astype(_np.float32)
        et = float(edge_thresh)
        es = float(edge_snap)
        er = float(edge_blue_r)
        eg = float(edge_blue_g)
        eb = float(edge_blue_b)
        edge_weight = _np.clip((grad_norm - et) / (1.0 - et + 1e-7), 0.0, 1.0) * es
        r_out = _np.clip(r2 * (1.0 - edge_weight) + er * edge_weight, 0.0, 1.0).astype(_np.float32)
        g_out = _np.clip(g2 * (1.0 - edge_weight) + eg * edge_weight, 0.0, 1.0).astype(_np.float32)
        b_out = _np.clip(b2 * (1.0 - edge_weight) + eb * edge_weight, 0.0, 1.0).astype(_np.float32)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r_out * op
        new_g = g0 * (1.0 - op) + g_out * op
        new_b = b0 * (1.0 - op) + b_out * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print(f"    Jawlensky Abstract Head complete (warmth_str={ws:.2f} "
              f"cool_str={cs_:.2f} edge_snap={es:.2f} "
              f"mean_warm={float(warm_weight.mean()):.3f} "
              f"mean_cool={float(cool_weight.mean()):.3f})")

    def paint_optical_vibration_pass(
        self,
        boundary_sigma: float = 8.0,
        diverge_str:    float = 0.35,
        vibration_str:  float = 0.28,
        warm_anchor:    float = 30.0,
        cool_anchor:    float = 210.0,
        opacity:        float = 0.72,
    ) -> None:
        r"""Paint Optical Vibration -- session 245 artistic improvement.

        Simultaneous contrast is the perceptual phenomenon theorised by Josef Albers
        in Interaction of Color (1963): colours appear to change their perceived hue
        depending on surrounding colours. The effect is strongest at warm-cool chromatic
        boundaries. Expressionists such as Jawlensky and Kirchner deliberately placed
        warm-cool pairs adjacent to maximise the optical oscillation.

        THREE-STAGE SIMULTANEOUS CONTRAST VIBRATION:

        Stage 1 WARM-COOL FIELD GRADIENT BOUNDARY DETECTION: Classify each pixel as
        warm (hue in [320,360] union [0,90] degrees) or cool (hue in [90,270] degrees).
        Apply Gaussian blur to produce a smooth warm-density field. Compute gradient
        magnitude of this field to identify warm-cool boundary zones.
        NOVEL: (a) WARM-COOL FIELD GRADIENT BOUNDARY MAP -- first pass to classify
        pixels into warm/cool chromatic fields and use the gradient of the blurred
        classification field to identify chromatic transition zones.

        Stage 2 COMPLEMENTARY HUE DIVERGENCE: At boundary zones, push warm pixels toward
        warm_anchor and cool pixels toward cool_anchor. Push = boundary_map * diverge_str.
        NOVEL: (b) BOUNDARY-GATED COMPLEMENTARY DIVERGENCE -- first pass to push warm and
        cool pixels in opposite hue directions exclusively at chromatic boundary zones.

        Stage 3 BOUNDARY SATURATION VIBRATION: Boost saturation proportionally to
        boundary_map * vibration_str at boundary zones, creating optical oscillation.
        NOVEL: (c) TRANSITION-ZONE SATURATION BOOST -- first pass to boost saturation
        specifically at warm-cool chromatic interfaces rather than globally or radially.

        boundary_sigma : Gaussian blur sigma for warm-cool field smoothing.
        diverge_str    : Hue divergence strength at boundary zones.
        vibration_str  : Saturation boost strength at boundary zones.
        warm_anchor    : Hue target for warm-side divergence (~30 deg, orange).
        cool_anchor    : Hue target for cool-side divergence (~210 deg, blue-green).
        opacity        : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss, sobel as _sobel

        print("    Paint Optical Vibration pass (session 245 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        def _rgb_to_hsv(r, g, b):
            maxc = _np.maximum(r, _np.maximum(g, b)).astype(_np.float32)
            minc = _np.minimum(r, _np.minimum(g, b)).astype(_np.float32)
            v    = maxc
            diff = (maxc - minc).astype(_np.float32)
            s    = _np.where(maxc > 1e-7, diff / (maxc + 1e-7), 0.0).astype(_np.float32)
            eps  = 1e-7
            hd   = _np.zeros_like(r, dtype=_np.float32)
            mr = (maxc == r) & (diff > eps)
            mg = (maxc == g) & ~mr & (diff > eps)
            mb = (maxc == b) & ~mr & ~mg & (diff > eps)
            hd[mr] = (60.0 * ((g[mr] - b[mr]) / (diff[mr] + eps))) % 360.0
            hd[mg] = (60.0 * ((b[mg] - r[mg]) / (diff[mg] + eps))) + 120.0
            hd[mb] = (60.0 * ((r[mb] - g[mb]) / (diff[mb] + eps))) + 240.0
            hd = hd % 360.0
            return hd, s, v

        def _hsv_to_rgb(hd, s, v):
            h6 = (hd / 60.0).astype(_np.float32)
            i  = _np.floor(h6).astype(_np.int32) % 6
            f  = (h6 - _np.floor(h6)).astype(_np.float32)
            p  = (v * (1.0 - s)).astype(_np.float32)
            q  = (v * (1.0 - f * s)).astype(_np.float32)
            t_ = (v * (1.0 - (1.0 - f) * s)).astype(_np.float32)
            r_ = _np.select([i==0,i==1,i==2,i==3,i==4],[v,q,p,p,t_], default=v)
            g_ = _np.select([i==0,i==1,i==2,i==3,i==4],[t_,v,v,q,p], default=p)
            b_ = _np.select([i==0,i==1,i==2,i==3,i==4],[p,p,t_,v,v], default=q)
            return r_.astype(_np.float32), g_.astype(_np.float32), b_.astype(_np.float32)

        hue, sat, val = _rgb_to_hsv(r0, g0, b0)

        # Stage 1: Warm-cool field gradient boundary detection
        is_warm = ((hue <= 90.0) | (hue >= 320.0)).astype(_np.float32)
        bs = float(boundary_sigma)
        warm_field = _gauss(is_warm, sigma=bs).astype(_np.float32)
        gx = _sobel(warm_field, axis=1).astype(_np.float32)
        gy = _sobel(warm_field, axis=0).astype(_np.float32)
        boundary_raw = _np.hypot(gx, gy).astype(_np.float32)
        p99 = max(float(_np.percentile(boundary_raw, 99)), 1e-7)
        boundary_map = _np.clip(boundary_raw / p99, 0.0, 1.0).astype(_np.float32)

        # Stage 2: Complementary hue divergence at boundaries
        wa = float(warm_anchor)
        ca = float(cool_anchor)
        ds = float(diverge_str)
        raw_diff_warm = wa - hue
        rot_warm = _np.where(raw_diff_warm > 180.0, raw_diff_warm - 360.0,
                   _np.where(raw_diff_warm < -180.0, raw_diff_warm + 360.0, raw_diff_warm))
        raw_diff_cool = ca - hue
        rot_cool = _np.where(raw_diff_cool > 180.0, raw_diff_cool - 360.0,
                   _np.where(raw_diff_cool < -180.0, raw_diff_cool + 360.0, raw_diff_cool))
        rot_dir = _np.where(is_warm > 0.5, rot_warm, rot_cool).astype(_np.float32)
        hue_out = (hue + rot_dir * boundary_map * ds) % 360.0

        # Stage 3: Boundary saturation vibration
        vs = float(vibration_str)
        sat_out = _np.clip(sat + boundary_map * vs, 0.0, 1.0).astype(_np.float32)

        r_out, g_out, b_out = _hsv_to_rgb(hue_out, sat_out, val)
        r_out = _np.clip(r_out, 0.0, 1.0)
        g_out = _np.clip(g_out, 0.0, 1.0)
        b_out = _np.clip(b_out, 0.0, 1.0)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r_out * op
        new_g = g0 * (1.0 - op) + g_out * op
        new_b = b0 * (1.0 - op) + b_out * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        mean_boundary = float(boundary_map.mean())
        mean_warm = float(is_warm.mean())
        print(f"    Paint Optical Vibration complete (sigma={bs:.1f} "
              f"diverge={ds:.2f} vibration={vs:.2f} "
              f"mean_boundary={mean_boundary:.3f} "
              f"mean_warm_frac={mean_warm:.3f})")


    def macke_luminous_planes_pass(
        self,
        n_hue_zones:     int   = 8,
        sat_target:      float = 0.82,
        sat_lift_str:    float = 0.65,
        hue_jump_bright: float = 0.20,
        hue_jump_thresh: float = 0.10,
        warm_r:          float = 0.96,
        warm_g:          float = 0.84,
        warm_b:          float = 0.42,
        veil_strength:   float = 0.20,
        opacity:         float = 0.80,
    ) -> None:
        r"""Macke Luminous Planes -- session 246: ONE HUNDRED AND FIFTY-SEVENTH distinct mode.

        THREE-STAGE LUMINOUS COLOUR PLANE SIMULATION (August Macke):

        Stage 1 HUE-ZONE SATURATION NORMALISATION: Divide the hue wheel into n_hue_zones
        equal sectors (width = 360/n_hue_zones degrees). For each sector, compute the 80th-
        percentile saturation of pixels belonging to that sector. If p80 < sat_target and
        p80 > 0.01, compute a per-sector scale factor = sat_target / p80, clamped to [1, 2.5].
        Lift each pixel in the sector: s_new = clip(s * (1 + (scale - 1) * sat_lift_str), 0, 1).
        Sectors already at or above sat_target are left unchanged.
        NOVEL: (a) PER-HUE-SECTOR PERCENTILE-REFERENCED SATURATION LIFT -- first pass to
        independently normalise each hue sector's saturation toward a uniform target using
        that sector's own 80th-percentile as the reference; prior passes boost saturation
        globally (color_bloom), at warm-cool boundaries (optical_vibration), in periphery only
        (jawlensky), or not at all -- none apply per-hue-sector percentile-normalised lift.

        Stage 2 CIRCULAR HUE GRADIENT BOUNDARY BRIGHTENING: Decompose the hue angle into
        sin(hue_rad) and cos(hue_rad). Apply Sobel gradient to each component to produce
        hue_gx and hue_gy. Combine: circular_grad = sqrt(sin_gx^2 + sin_gy^2 + cos_gx^2 +
        cos_gy^2). Normalise by 99th percentile. Pixels above hue_jump_thresh are brightened:
        v_new = clip(v + boundary_map * hue_jump_bright, 0, 1).
        NOVEL: (b) CIRCULAR HUE GRADIENT BRIGHTENING AT COLOUR-PLANE BOUNDARIES -- first pass
        to (i) detect boundaries via the CIRCULAR HUE GRADIENT (sin/cos Sobel, not luminance
        Sobel) and (ii) apply BRIGHTENING rather than darkening at those boundaries; jawlensky,
        beckmann, kirchner all use luminance-gradient Sobel for edge detection and darken or
        blend toward dark at edges; none brighten at hue-jump boundaries.

        Stage 3 LUMINANCE-PROPORTIONAL WARM GOLDEN VEIL: Compute luminance lum = 0.299r +
        0.587g + 0.114b. Blend each pixel toward the warm golden colour (warm_r, warm_g,
        warm_b) with weight = lum * veil_strength. Brighter pixels absorb more of the warm
        veil, simulating Macke's golden-tan ground showing through thinner paint in lit zones.
        NOVEL: (c) LUMINANCE-WEIGHTED WARM VEIL BLEND -- first pass to blend toward a warm
        colour with weight directly proportional to existing pixel luminance; imprimatura_warmth
        applies the same warm blend uniformly; aerial_perspective uses DoG-gated tinting;
        jawlensky uses radial distance from centre; none scale the warm blend by current lum.

        n_hue_zones     : Number of equal hue sectors for saturation normalisation.
        sat_target      : Saturation target for sector lifting.
        sat_lift_str    : Interpolation strength toward scale-corrected saturation.
        hue_jump_bright : Maximum brightness lift at colour-plane boundaries.
        hue_jump_thresh : Normalised circular-gradient threshold for boundary activation.
        warm_r/g/b      : RGB components of the warm golden veil colour.
        veil_strength   : Maximum warm veil blend weight (at luminance = 1.0).
        opacity         : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import sobel as _sobel

        print("    Macke Luminous Planes pass (session 246: 157th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        def _rgb_to_hsv(r, g, b):
            maxc = _np.maximum(r, _np.maximum(g, b)).astype(_np.float32)
            minc = _np.minimum(r, _np.minimum(g, b)).astype(_np.float32)
            v    = maxc
            diff = (maxc - minc).astype(_np.float32)
            s    = _np.where(maxc > 1e-7, diff / (maxc + 1e-7), 0.0).astype(_np.float32)
            eps  = 1e-7
            hd   = _np.zeros_like(r, dtype=_np.float32)
            mr = (maxc == r) & (diff > eps)
            mg = (maxc == g) & ~mr & (diff > eps)
            mb = (maxc == b) & ~mr & ~mg & (diff > eps)
            hd[mr] = (60.0 * ((g[mr] - b[mr]) / (diff[mr] + eps))) % 360.0
            hd[mg] = (60.0 * ((b[mg] - r[mg]) / (diff[mg] + eps))) + 120.0
            hd[mb] = (60.0 * ((r[mb] - g[mb]) / (diff[mb] + eps))) + 240.0
            hd = hd % 360.0
            return hd, s, v

        def _hsv_to_rgb(hd, s, v):
            h6 = (hd / 60.0).astype(_np.float32)
            i  = _np.floor(h6).astype(_np.int32) % 6
            f  = (h6 - _np.floor(h6)).astype(_np.float32)
            p  = (v * (1.0 - s)).astype(_np.float32)
            q  = (v * (1.0 - f * s)).astype(_np.float32)
            t_ = (v * (1.0 - (1.0 - f) * s)).astype(_np.float32)
            r_ = _np.select([i==0,i==1,i==2,i==3,i==4],[v,q,p,p,t_], default=v)
            g_ = _np.select([i==0,i==1,i==2,i==3,i==4],[t_,v,v,q,p], default=p)
            b_ = _np.select([i==0,i==1,i==2,i==3,i==4],[p,p,t_,v,v], default=q)
            return r_.astype(_np.float32), g_.astype(_np.float32), b_.astype(_np.float32)

        hue, sat, val = _rgb_to_hsv(r0, g0, b0)

        # Stage 1: Per-hue-zone saturation normalisation
        st_float  = float(sat_target)
        sl_float  = float(sat_lift_str)
        nz        = int(n_hue_zones)
        zone_w    = 360.0 / nz
        sat_new   = sat.copy()
        for z in range(nz):
            lo = z * zone_w
            hi = (z + 1) * zone_w
            mask = (hue >= lo) & (hue < hi)
            n_px = int(mask.sum())
            if n_px < 5:
                continue
            p80 = float(_np.percentile(sat[mask], 80))
            if p80 < st_float and p80 > 0.01:
                scale = min(st_float / p80, 2.5)
                sat_zone = sat[mask] * (1.0 + (scale - 1.0) * sl_float)
                sat_new[mask] = _np.clip(sat_zone, 0.0, 1.0).astype(_np.float32)
        sat_new = _np.clip(sat_new, 0.0, 1.0).astype(_np.float32)
        r1, g1, b1 = _hsv_to_rgb(hue, sat_new, val)

        # Stage 2: Circular hue gradient boundary brightening
        hue_rad  = _np.deg2rad(hue).astype(_np.float32)
        sin_h    = _np.sin(hue_rad).astype(_np.float32)
        cos_h    = _np.cos(hue_rad).astype(_np.float32)
        sin_gx   = _sobel(sin_h, axis=1).astype(_np.float32)
        sin_gy   = _sobel(sin_h, axis=0).astype(_np.float32)
        cos_gx   = _sobel(cos_h, axis=1).astype(_np.float32)
        cos_gy   = _sobel(cos_h, axis=0).astype(_np.float32)
        circ_grad = _np.sqrt(sin_gx**2 + sin_gy**2 + cos_gx**2 + cos_gy**2).astype(_np.float32)
        p99  = max(float(_np.percentile(circ_grad, 99)), 1e-7)
        circ_norm = _np.clip(circ_grad / p99, 0.0, 1.0).astype(_np.float32)
        jt   = float(hue_jump_thresh)
        jb   = float(hue_jump_bright)
        boundary_map = _np.clip((circ_norm - jt) / (1.0 - jt + 1e-7), 0.0, 1.0)
        hue2, sat2, val2 = _rgb_to_hsv(r1, g1, b1)
        val2_out = _np.clip(val2 + boundary_map * jb, 0.0, 1.0).astype(_np.float32)
        r2, g2, b2 = _hsv_to_rgb(hue2, sat2, val2_out)

        # Stage 3: Luminance-proportional warm golden veil
        wr   = float(warm_r)
        wg   = float(warm_g)
        wb   = float(warm_b)
        vs   = float(veil_strength)
        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        veil_w = _np.clip(lum2 * vs, 0.0, 1.0).astype(_np.float32)
        r3 = _np.clip(r2 * (1.0 - veil_w) + wr * veil_w, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 * (1.0 - veil_w) + wg * veil_w, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 * (1.0 - veil_w) + wb * veil_w, 0.0, 1.0).astype(_np.float32)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        print(f"    Macke Luminous Planes complete (n_zones={nz} sat_target={st_float:.2f} "
              f"boundary_mean={float(boundary_map.mean()):.3f} "
              f"veil_str={vs:.2f})")

    def paint_golden_ground_pass(
        self,
        ground_r:         float = 0.72,
        ground_g:         float = 0.52,
        ground_b:         float = 0.22,
        midtone_str:      float = 0.28,
        shadow_thresh:    float = 0.32,
        shadow_ground_r:  float = 0.48,
        shadow_ground_g:  float = 0.28,
        shadow_ground_b:  float = 0.10,
        shadow_str:       float = 0.22,
        highlight_thresh: float = 0.76,
        highlight_r:      float = 0.98,
        highlight_g:      float = 0.92,
        highlight_b:      float = 0.72,
        highlight_str:    float = 0.14,
        opacity:          float = 0.72,
    ) -> None:
        r"""Paint Golden Ground -- session 246 artistic improvement.

        Simulates the technique of painting over a warm, coloured ground in three
        value zones: the mid-tones echo the ground colour most strongly; the shadows
        are anchored to a deeper, richer version of the ground; the highlights receive
        a subtle warm golden kiss. Together these three zones unify the palette with
        a common warm undertone, the way a warm-ochre imprimatura unifies an oil painting.

        THREE-STAGE GOLDEN GROUND ECHO:

        Stage 1 MIDTONE GROUND ECHO: Compute midtone proximity for each pixel as
        proximity = max(0, 1 - 2 * |lum - 0.5|) where lum is pixel luminance. Blend the
        pixel toward the ground colour (ground_r/g/b) with weight = proximity * midtone_str.
        Pixels near 50% luminance are pulled most strongly toward the ground; pixels at
        full light or full dark are barely affected.
        NOVEL: (a) MIDTONE-PROXIMITY-WEIGHTED GROUND BLEND -- first pass to use
        max(0, 1-2|lum-0.5|) as the blend weight toward a ground colour; no prior pass uses
        proximity-to-midpoint-luminance as its primary blend driver; imprimatura_warmth
        applies uniformly; beckmann uses edge proximity; jawlensky uses radial centroid
        distance; aerial perspective uses DoG frequency gates.

        Stage 2 SHADOW WARMTH ANCHOR: In shadow zones (lum < shadow_thresh), apply an
        additional blend toward a deeper, richer ground tone (shadow_ground_r/g/b) with
        weight = (shadow_thresh - lum) / shadow_thresh * shadow_str. Darker pixels receive
        stronger shadow anchoring.
        NOVEL: (b) SHADOW-GATED DEEP GROUND ANCHOR -- first pass to apply a distinct
        deeper-tone ground blend exclusively to shadow-value pixels using a value threshold
        gate; no prior pass applies a second, darker ground-tone blend with its own value-
        gated weight formula specifically in the shadow zone.

        Stage 3 GOLDEN HIGHLIGHT KISS: In highlight zones (lum > highlight_thresh), blend
        toward a warm near-white golden colour (highlight_r/g/b) with weight =
        (lum - highlight_thresh) / (1 - highlight_thresh) * highlight_str. Brighter
        highlights receive a stronger warm golden tint, simulating warm impasto catching
        ambient golden light.
        NOVEL: (c) HIGHLIGHT-GATED GOLDEN WARM TINT -- first pass to apply a warm near-white
        tint exclusively to pixels above an upper luminance threshold with a third, distinct
        value-gated weight formula; no prior pass handles midtone/shadow/highlight as three
        separate value zones each with their own ground-colour target and blend strength.

        ground_r/g/b      : RGB of the mid-tone ground echo colour (warm ochre default).
        midtone_str       : Blend strength for midtone ground echo.
        shadow_thresh     : Upper luminance boundary for shadow zone.
        shadow_ground_r/g/b : Darker, richer ground colour for shadow anchoring.
        shadow_str        : Blend strength for shadow zone anchor.
        highlight_thresh  : Lower luminance boundary for highlight zone.
        highlight_r/g/b   : Warm near-white golden colour for highlight kiss.
        highlight_str     : Maximum blend strength for highlight kiss.
        opacity           : Final composite opacity.
        """
        import numpy as _np

        print("    Paint Golden Ground pass (session 246 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Midtone ground echo
        gr  = float(ground_r)
        gg  = float(ground_g)
        gb  = float(ground_b)
        mts = float(midtone_str)
        proximity  = _np.clip(1.0 - 2.0 * _np.abs(lum - 0.5), 0.0, 1.0).astype(_np.float32)
        mid_w      = proximity * mts
        r1 = _np.clip(r0 + (gr - r0) * mid_w, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 + (gg - g0) * mid_w, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 + (gb - b0) * mid_w, 0.0, 1.0).astype(_np.float32)

        # Stage 2: Shadow warmth anchor
        sgr = float(shadow_ground_r)
        sgg = float(shadow_ground_g)
        sgb = float(shadow_ground_b)
        sth = float(shadow_thresh)
        sst = float(shadow_str)
        shadow_w = _np.clip(
            _np.where(lum < sth, (sth - lum) / (sth + 1e-7) * sst, 0.0),
            0.0, 1.0).astype(_np.float32)
        r2 = _np.clip(r1 + (sgr - r1) * shadow_w, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 + (sgg - g1) * shadow_w, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 + (sgb - b1) * shadow_w, 0.0, 1.0).astype(_np.float32)

        # Stage 3: Golden highlight kiss
        htr = float(highlight_r)
        htg = float(highlight_g)
        htb = float(highlight_b)
        hth = float(highlight_thresh)
        hts = float(highlight_str)
        highlight_w = _np.clip(
            _np.where(lum > hth, (lum - hth) / (1.0 - hth + 1e-7) * hts, 0.0),
            0.0, 1.0).astype(_np.float32)
        r3 = _np.clip(r2 + (htr - r2) * highlight_w, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 + (htg - g2) * highlight_w, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 + (htb - b2) * highlight_w, 0.0, 1.0).astype(_np.float32)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        mean_mid = float(mid_w.mean())
        mean_shd = float(shadow_w.mean())
        mean_hlt = float(highlight_w.mean())
        print(f"    Paint Golden Ground complete (midtone_str={mts:.2f} "
              f"shadow_str={sst:.2f} highlight_str={hts:.2f} "
              f"mean_mid_w={mean_mid:.3f} mean_shd_w={mean_shd:.3f} "
              f"mean_hlt_w={mean_hlt:.3f})")

    def kollwitz_charcoal_etching_pass(
        self,
        desat_str:        float = 0.85,
        warm_r:           float = 0.95,
        warm_g:           float = 0.90,
        warm_b:           float = 0.80,
        dark_r:           float = 0.14,
        dark_g:           float = 0.10,
        dark_b:           float = 0.07,
        sigmoid_k:        float = 7.0,
        shadow_thresh:    float = 0.38,
        grain_angle_deg:  float = 45.0,
        grain_strength:   float = 0.12,
        grain_kernel_len: int   = 9,
        opacity:          float = 0.88,
    ) -> None:
        r"""Kollwitz Charcoal Etching -- session 247: ONE HUNDRED AND FIFTY-EIGHTH distinct mode.

        THREE-STAGE WARM MONOCHROME SOCIAL REALISM (Käthe Kollwitz):

        Stage 1 WARM CHARCOAL MONOCHROME CONVERSION: Compute per-pixel luminance lum =
        0.299r + 0.587g + 0.114b. Build the two-endpoint warm charcoal ramp: for each
        pixel, charcoal_r = lum * warm_r + (1 - lum) * dark_r (and likewise for g, b),
        mapping lum=0 to (dark_r, dark_g, dark_b) — a deep warm black — and lum=1 to
        (warm_r, warm_g, warm_b) — a warm paper white. Blend each pixel from its original
        colour toward this charcoal image with weight = desat_str. The result is a
        desaturated near-monochrome image that retains organic warmth: shadows fall into
        sepia-dark, highlights glow with paper-white warmth.
        NOVEL: (a) DUAL-ENDPOINT WARM CHARCOAL RAMP AS DESATURATION TARGET -- first pass
        to parameterise the desaturation target as a two-colour charcoal ramp (separate
        endpoints for shadow and highlight zones) rather than achromatic grey; prior
        desaturation operations in this codebase blend toward a single neutral grey or
        toward a single warm colour (imprimatura_warmth, golden_ground); none parameterise
        separate warm endpoints for the shadow zone and the highlight zone and interpolate
        by luminance between them.

        Stage 2 SIGMOID TONAL CONTRAST EXPANSION: Recompute luminance of the post-
        desaturation image lum1. Apply the symmetric sigmoid: lum2 = 1 / (1 + exp(-k *
        (lum1 - 0.5))), with k = sigmoid_k (default 7.0). Scale all three channels by the
        contrast ratio: r_out = r_in * (lum2 / max(lum1, eps)). This expands the tonal
        range: dark pixels grow darker; bright pixels grow brighter; the overall effect
        simulates the extreme tonal contrast of Kollwitz's charcoal drawings and etching
        plates, where the deepest blacks are absolute and the highlights approach pure paper.
        NOVEL: (b) PARAMETRIC SYMMETRIC SIGMOID TONE CURVE -- first pass to apply a
        symmetric logistic sigmoid as a standalone tonal contrast stage; prior passes use
        Sobel-based edge maps, DoG-gated frequency bands, percentile-anchored linear
        stretches, or luminance-threshold gates for tonal adjustment -- none apply a smooth
        parametric sigmoid that is differentiable everywhere and symmetric around the mid-
        tone.

        Stage 3 DIRECTIONAL SHADOW GRAIN (Lithographic Mark Texture): Build a 1D
        directional kernel of length grain_kernel_len at angle grain_angle_deg using
        sub-pixel bilinear accumulation along the parametric line. Convolve the post-
        sigmoid luminance channel with this kernel to produce a blurred-along-direction
        version. Subtract the blurred version from the original luminance to obtain a
        high-frequency directional residual (the grain). In shadow pixels (lum2 <
        shadow_thresh), blend this residual grain back into each channel with weight =
        grain_strength * ((shadow_thresh - lum2) / shadow_thresh). The result is a
        visible directional mark texture in dark zones, simulating the hatched strokes of
        Kollwitz's charcoal and etching work.
        NOVEL: (c) PARAMETRIC-ANGLE DIRECTIONAL GRAIN IN SHADOW ZONE -- first pass to (i)
        construct a directional 1D convolution kernel at a user-specified angle using sub-
        pixel sampling, (ii) extract the high-frequency residual by subtracting the
        directional blur, and (iii) add this oriented texture exclusively to pixels below a
        shadow luminance threshold with luminance-proportional blending weight; no prior pass
        applies direction-specific convolutional texture gated by a shadow luminance
        threshold.

        desat_str        : Overall desaturation blend strength (0=no change, 1=full charcoal).
        warm_r/g/b       : Warm paper-white endpoint colour at luminance = 1.
        dark_r/g/b       : Warm deep-black endpoint colour at luminance = 0.
        sigmoid_k        : Steepness of sigmoid tonal contrast curve (higher = more contrast).
        shadow_thresh    : Luminance threshold below which shadow grain is applied.
        grain_angle_deg  : Angle in degrees of the directional grain kernel.
        grain_strength   : Maximum grain blend weight in the deepest shadow pixels.
        grain_kernel_len : Length of the 1D directional grain kernel (odd preferred).
        opacity          : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import convolve as _convolve

        print("    Kollwitz Charcoal Etching pass (session 247: 158th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum0 = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Warm charcoal monochrome conversion
        wr = float(warm_r); wg = float(warm_g); wb = float(warm_b)
        dr = float(dark_r); dg = float(dark_g); db = float(dark_b)
        ds = float(desat_str)
        charcoal_r = (lum0 * wr + (1.0 - lum0) * dr).astype(_np.float32)
        charcoal_g = (lum0 * wg + (1.0 - lum0) * dg).astype(_np.float32)
        charcoal_b = (lum0 * wb + (1.0 - lum0) * db).astype(_np.float32)
        r1 = _np.clip(r0 * (1.0 - ds) + charcoal_r * ds, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * (1.0 - ds) + charcoal_g * ds, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * (1.0 - ds) + charcoal_b * ds, 0.0, 1.0).astype(_np.float32)

        # Stage 2: Sigmoid tonal contrast expansion
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        k    = float(sigmoid_k)
        lum2 = (1.0 / (1.0 + _np.exp(-k * (lum1 - 0.5)))).astype(_np.float32)
        ratio = (lum2 / (lum1 + 1e-7)).astype(_np.float32)
        r2 = _np.clip(r1 * ratio, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 * ratio, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 * ratio, 0.0, 1.0).astype(_np.float32)

        # Stage 3: Directional shadow grain
        klen    = max(3, int(grain_kernel_len))
        ang_rad = _np.deg2rad(float(grain_angle_deg))
        dx      = _np.cos(ang_rad)
        dy      = _np.sin(ang_rad)
        # Build 1D kernel by sampling along parametric line with sub-pixel weights
        half    = klen // 2
        kernel_2d = _np.zeros((klen, klen), dtype=_np.float32)
        for i in range(klen):
            t  = float(i - half)
            px = t * dx
            py = t * dy
            ix = int(_np.floor(px))
            iy = int(_np.floor(py))
            fx = px - ix
            fy = py - iy
            for (row_off, col_off, w_val) in [
                (iy,     ix,     (1 - fy) * (1 - fx)),
                (iy,     ix + 1, (1 - fy) * fx),
                (iy + 1, ix,     fy * (1 - fx)),
                (iy + 1, ix + 1, fy * fx),
            ]:
                r_idx = row_off + half
                c_idx = col_off + half
                if 0 <= r_idx < klen and 0 <= c_idx < klen:
                    kernel_2d[r_idx, c_idx] += w_val
        k_sum = kernel_2d.sum()
        if k_sum > 1e-7:
            kernel_2d /= k_sum

        lum2_for_grain = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        blurred_lum    = _convolve(lum2_for_grain, kernel_2d, mode='reflect').astype(_np.float32)
        grain_residual = (lum2_for_grain - blurred_lum).astype(_np.float32)

        st        = float(shadow_thresh)
        gs        = float(grain_strength)
        shadow_mask = (lum2_for_grain < st).astype(_np.float32)
        grain_w     = _np.clip(
            shadow_mask * ((st - lum2_for_grain) / (st + 1e-7)) * gs,
            0.0, 0.5).astype(_np.float32)
        r3 = _np.clip(r2 + grain_residual * grain_w, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 + grain_residual * grain_w, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 + grain_residual * grain_w, 0.0, 1.0).astype(_np.float32)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        mean_grain = float(_np.abs(grain_residual).mean())
        print(f"    Kollwitz Charcoal Etching complete (desat={ds:.2f} sigmoid_k={k:.1f} "
              f"angle={float(grain_angle_deg):.0f}deg shadow_thresh={st:.2f} "
              f"mean_grain={mean_grain:.4f})")

    def paint_luminance_stretch_pass(
        self,
        lo_pct:  float = 2.0,
        hi_pct:  float = 98.0,
        opacity: float = 0.80,
    ) -> None:
        r"""Paint Luminance Stretch -- session 247 artistic improvement.

        PERCENTILE-ANCHORED TONAL NORMALISATION: Compute the lo_pct and hi_pct
        percentiles of the canvas luminance (lum = 0.299r + 0.587g + 0.114b).
        Map the luminance range [p_lo, p_hi] linearly to [0, 1] by computing a scale
        factor and offset. Apply the same linear transform proportionally to all three
        channels: channel_out = clip((channel - p_lo * channel/lum) * scale, 0, 1).
        Pixels at or below the p_lo luminance percentile are driven toward black; pixels
        at or above the p_hi percentile are driven toward their maximum saturation-
        corrected value. The transform is applied per-pixel using the global percentile
        anchors, not per-channel, so hue is preserved -- only the tonal range changes.

        THREE-STAGE TONAL NORMALISATION:

        Stage 1 LUMINANCE PERCENTILE ANCHORING: Compute lum = 0.299r + 0.587g + 0.114b
        for every pixel. Find p_lo = np.percentile(lum, lo_pct) and p_hi =
        np.percentile(lum, hi_pct). If p_hi - p_lo < 0.05 (very flat image), the pass
        still runs but has minimal visible effect.

        Stage 2 LUMINANCE-PROPORTIONAL CHANNEL SCALING: Compute scale = 1.0 / (p_hi -
        p_lo + eps). For each pixel, compute the normalised luminance lum_n = clip((lum -
        p_lo) * scale, 0, 1). Scale each channel by (lum_n / max(lum, eps)): this
        brightens dark pixels (lum < p_lo → drives toward 0) and brightens bright pixels
        (lum near p_hi → drives toward maximum) while preserving their hue angle.
        NOVEL: (a) LUMINANCE-PROPORTIONAL PERCENTILE STRETCH WITH HUE PRESERVATION --
        first improvement pass to apply a percentile-anchored linear luminance stretch
        that scales all three channels together proportionally so hue is preserved; no
        prior improvement pass applies a tonal range normalisation using luminance
        percentiles; paint_color_bloom_pass expands saturation; paint_optical_vibration_
        pass adds warm-cool boundary flicker; paint_aerial_perspective_pass uses DoG
        frequency gating; paint_imprimatura_warmth_pass, paint_golden_ground_pass warm
        the palette; paint_lost_found_edges_pass refines edge contrast; none normalise
        the full tonal range via percentile anchors.

        Stage 3 OPACITY COMPOSITE: Blend result with original canvas at opacity.

        lo_pct   : Lower percentile for tonal anchor (pixels below → towards black).
        hi_pct   : Upper percentile for tonal anchor (pixels above → towards max).
        opacity  : Final composite opacity.
        """
        import numpy as _np

        print("    Paint Luminance Stretch pass (session 247 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Stage 1: Compute luminance percentile anchors
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        p_lo = float(_np.percentile(lum, float(lo_pct)))
        p_hi = float(_np.percentile(lum, float(hi_pct)))
        span = p_hi - p_lo
        scale = 1.0 / max(span, 1e-6)

        # Stage 2: Luminance-proportional channel scaling (hue-preserving)
        lum_n = _np.clip((lum - p_lo) * scale, 0.0, 1.0).astype(_np.float32)
        ratio = (lum_n / (lum + 1e-7)).astype(_np.float32)
        r1 = _np.clip(r0 * ratio, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * ratio, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * ratio, 0.0, 1.0).astype(_np.float32)

        # Stage 3: Opacity composite
        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        lum_out = (0.299 * new_r + 0.587 * new_g + 0.114 * new_b)
        print(f"    Paint Luminance Stretch complete (p_lo={p_lo:.3f} p_hi={p_hi:.3f} "
              f"span={span:.3f} lum_out_mean={float(lum_out.mean()):.3f})")

    def de_stael_palette_knife_mosaic_pass(
        self,
        tile_h:           int   = 24,
        tile_w:           int   = 32,
        knife_angle_deg:  float = 12.0,
        knife_texture_str: float = 0.06,
        boundary_width:   int   = 2,
        boundary_strength: float = 0.18,
        opacity:          float = 0.85,
    ) -> None:
        r"""Nicolas de Stael Palette Knife Mosaic -- session 248: ONE HUNDRED AND FIFTY-NINTH distinct mode.

        THREE-STAGE PALETTE KNIFE MOSAIC (Nicolas de Stael):

        Stage 1 RECTANGULAR TILE MEAN QUANTIZATION: Divide the canvas into a
        grid of non-overlapping rectangular tiles of size (tile_h x tile_w)
        pixels, with edge tiles cropped to the canvas boundary. For each tile,
        compute the arithmetic mean of the R, G, and B channels across all pixels
        within the tile. Replace every pixel in the tile with this mean colour.
        The result is a mosaic of flat rectangular colour planes, each carrying
        the average hue and luminance of the original region it covers.
        NOVEL: (a) RECTANGULAR TILE MEAN QUANTIZATION AS PRIMARY COLOUR STAGE --
        first pass to divide the canvas into a rectangular grid and replace each
        tile with its mean colour (spatial mean pooling over rectangular blocks)
        as a primary image-processing operation; prior passes use Gaussian blurs
        (spatially-continuous weighted averaging), Sobel operators (edge
        detection from adjacent pixel differences), frequency decompositions
        (DoG bandpass), or percentile operations -- none replace pixel values
        with the mean of a rectangular tile grid.

        Stage 2 INTRA-TILE DIRECTIONAL KNIFE GRADIENT: Build a (tile_h x tile_w)
        directional gradient template by computing, at each local pixel position
        (dy, dx) within the tile (centred, normalised to [-1, +1]),
        t = dx * cos(a) + dy * sin(a), where a = knife_angle_deg in radians.
        Tile this template across the full canvas (cropping edge tiles to canvas
        bounds). Multiply the template by knife_texture_str to obtain per-pixel
        luminance adjustments. Add these adjustments to all three channels of the
        quantized result. The effect is a slight directional luminance gradient
        within each colour block, simulating the way a palette knife dragged
        across a thick paint deposit deposits slightly more pigment at one edge
        than the other.
        NOVEL: (b) INTRA-TILE DIRECTIONAL LUMINANCE GRADIENT -- first pass to
        add a parametric directional luminance ramp within each quantized tile
        using a shared gradient template that is tiled across the canvas; the
        gradient direction is controlled by knife_angle_deg and is the same for
        all tiles, reproducing the consistent stroke direction of a single palette-
        knife passage across a composition; prior directional passes (kollwitz
        grain, diffuse_boundary) apply convolutional kernels to the full canvas,
        not a per-tile spatial ramp.

        Stage 3 TILE BOUNDARY GAP DARKENING: For each pixel, compute its
        distance to the nearest horizontal or vertical tile boundary: dist_row =
        min(row % tile_h, tile_h - 1 - row % tile_h) and similarly for
        dist_col; take min_dist = min(dist_row, dist_col). Apply a darkening
        weight = clip((boundary_width - min_dist) / boundary_width, 0, 1) *
        boundary_strength. Subtract this weight from all three channels. The
        result is a thin darkened zone along every tile boundary, simulating the
        slight trough or gap where a palette knife lifts between adjacent paint
        deposits.
        NOVEL: (c) TILE BOUNDARY GAP DARKENING -- first pass to compute per-
        pixel proximity to quantized tile boundaries and apply a proportional
        darkening in that proximity zone; the trough geometry is derived directly
        from the tile grid parameters (tile_h, tile_w) and applies identically
        at every tile edge throughout the canvas; no prior pass darkens pixels
        specifically based on their distance to a spatial quantization boundary.

        tile_h           : Height of each rectangular tile in pixels.
        tile_w           : Width of each rectangular tile in pixels.
        knife_angle_deg  : Angle (degrees) of the intra-tile knife gradient.
        knife_texture_str: Max luminance adjustment amplitude within each tile.
        boundary_width   : Width in pixels of the boundary darkening zone.
        boundary_strength: Maximum darkening applied at the tile boundary edge.
        opacity          : Final composite opacity.
        """
        import numpy as _np

        print("    de Stael Palette Knife Mosaic pass (session 248: 159th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        th = int(max(1, tile_h))
        tw = int(max(1, tile_w))

        # Stage 1: Rectangular tile mean quantization (vectorised via padding)
        pad_h = (th - (h % th)) % th
        pad_w = (tw - (w % tw)) % tw
        def _tile_mean(ch):
            padded = _np.pad(ch, ((0, pad_h), (0, pad_w)), mode='edge')
            Hp, Wp = padded.shape
            ntr = Hp // th
            ntc = Wp // tw
            blocked = padded.reshape(ntr, th, ntc, tw)
            means   = blocked.mean(axis=(1, 3))        # (ntr, ntc)
            expanded = _np.repeat(_np.repeat(means, th, axis=0), tw, axis=1)
            return expanded[:h, :w].astype(_np.float32)

        r1 = _tile_mean(r0)
        g1 = _tile_mean(g0)
        b1 = _tile_mean(b0)

        # Stage 2: Intra-tile directional knife gradient (tiled template)
        ang_rad = _np.deg2rad(float(knife_angle_deg))
        cos_a   = float(_np.cos(ang_rad))
        sin_a   = float(_np.sin(ang_rad))
        tile_ys = _np.linspace(-1.0, 1.0, th).astype(_np.float32)[:, None]
        tile_xs = _np.linspace(-1.0, 1.0, tw).astype(_np.float32)[None, :]
        tile_grad = (tile_xs * cos_a + tile_ys * sin_a) * float(knife_texture_str)

        pad_h2  = (th - (h % th)) % th
        pad_w2  = (tw - (w % tw)) % tw
        ntr2    = (h + pad_h2) // th
        ntc2    = (w + pad_w2) // tw
        tiled   = _np.tile(tile_grad, (ntr2, ntc2))[:h, :w].astype(_np.float32)
        r1 = _np.clip(r1 + tiled, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g1 + tiled, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b1 + tiled, 0.0, 1.0).astype(_np.float32)

        # Stage 3: Tile boundary gap darkening
        row_idx    = _np.arange(h).astype(_np.int32)
        col_idx    = _np.arange(w).astype(_np.int32)
        row_offset = row_idx % th
        col_offset = col_idx % tw
        dist_row   = _np.minimum(row_offset, th - 1 - row_offset).astype(_np.float32)[:, None]
        dist_col   = _np.minimum(col_offset, tw - 1 - col_offset).astype(_np.float32)[None, :]
        min_dist   = _np.minimum(dist_row, dist_col)
        bw         = float(max(1, boundary_width))
        bs         = float(boundary_strength)
        bw_weight  = _np.clip((bw - min_dist) / bw, 0.0, 1.0) * bs
        r2 = _np.clip(r1 - bw_weight, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 - bw_weight, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 - bw_weight, 0.0, 1.0).astype(_np.float32)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        n_tiles = ((h + th - 1) // th) * ((w + tw - 1) // tw)
        print(f"    de Stael Palette Knife Mosaic complete (tile={th}x{tw} "
              f"n_tiles={n_tiles} knife_angle={float(knife_angle_deg):.1f}deg "
              f"boundary_w={int(boundary_width)} boundary_str={bs:.3f})")

    def paint_halation_pass(
        self,
        halation_thresh:  float = 0.76,
        halation_sigma:   float = 16.0,
        tint_r:           float = 1.00,
        tint_g:           float = 0.68,
        tint_b:           float = 0.30,
        bloom_strength:   float = 0.28,
        opacity:          float = 0.55,
    ) -> None:
        r"""Paint Halation -- session 248 artistic improvement.

        BRIGHTNESS-GATED WARM GAUSSIAN BLOOM: Extract pixels whose luminance
        exceeds halation_thresh. Expand those bright areas with a wide Gaussian
        bloom at halation_sigma. Tint the bloom with (tint_r, tint_g, tint_b)
        -- default warm orange, simulating the warm halation glow of dusk light
        or incandescent sources bleeding into surrounding areas. Add the tinted
        bloom back into the canvas at bloom_strength, then composite with the
        original at opacity.

        THREE-STAGE HALATION:

        Stage 1 LUMINANCE-THRESHOLDED BRIGHT-PIXEL MASK: Compute per-pixel
        luminance lum = 0.299r + 0.587g + 0.114b. Compute a soft bright mask:
        bright = clip((lum - halation_thresh) / max(1 - halation_thresh, 0.01),
        0, 1). This gives a continuous mask whose value rises from 0 at the
        threshold to 1 at full brightness.
        NOVEL: (a) LUMINANCE-THRESHOLD-GATED HALATION BLOOM -- first improvement
        pass to extract a brightness-based continuous pixel mask for bloom
        generation; prior improvement passes that gate on luminance use it for
        other purposes: aerial_perspective_pass gates DoG frequency selection,
        kollwitz_charcoal_etching_pass gates shadow grain -- none compute a
        continuous bright-zone mask specifically for bloom generation.

        Stage 2 GAUSSIAN BLOOM WITH RGB TINT: Apply a 2D Gaussian filter at
        sigma=halation_sigma to the bright mask to produce a soft radial bloom
        field. Multiply by (tint_r, tint_g, tint_b) * bloom_strength to obtain
        per-channel bloom contributions. Add these contributions directly to the
        original channel values and clip.
        NOVEL: (b) TINTED BRIGHTNESS-GATED GAUSSIAN BLOOM -- first improvement
        pass to (i) compute a brightness-gated luminance mask, (ii) expand it
        via wide Gaussian blurring to create a soft radial glow field, (iii)
        apply a user-specified RGB tint to the glow, and (iv) additively blend
        the result; prior improvement passes: color_bloom_pass (saturation-based
        expansion, not brightness-gated), optical_vibration_pass (warm-cool
        boundary oscillation, not bloom), golden_ground_pass (uniform warm
        overlay, not spatially varying), imprimatura_warmth_pass (uniform warm
        blend), luminance_stretch_pass (tonal normalisation) -- none create a
        brightness-gated, tinted, spatially-soft Gaussian glow.

        Stage 3 OPACITY COMPOSITE: Blend the bloomed result with the original
        canvas at opacity.

        halation_thresh  : Luminance threshold above which pixels contribute to bloom.
        halation_sigma   : Gaussian sigma for bloom expansion (larger = wider glow).
        tint_r/g/b       : RGB colour tint applied to the bloom (default warm orange).
        bloom_strength   : Amplitude of the additive bloom contribution.
        opacity          : Final composite opacity (0=no change, 1=full effect).
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Paint Halation pass (session 248 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Stage 1: Luminance-thresholded bright-pixel mask
        lum   = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        ht    = float(halation_thresh)
        denom = max(1.0 - ht, 0.01)
        bright = _np.clip((lum - ht) / denom, 0.0, 1.0).astype(_np.float32)

        # Stage 2: Gaussian bloom with RGB tint
        sig = float(halation_sigma)
        bs  = float(bloom_strength)
        bloom_field = _gf(bright, sigma=sig).astype(_np.float32)
        bloom_r = bloom_field * float(tint_r) * bs
        bloom_g = bloom_field * float(tint_g) * bs
        bloom_b = bloom_field * float(tint_b) * bs
        r1 = _np.clip(r0 + bloom_r, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 + bloom_g, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 + bloom_b, 0.0, 1.0).astype(_np.float32)

        # Stage 3: Opacity composite
        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        bloom_mean = float(bloom_field.mean())
        bright_frac = float((bright > 0.01).mean())
        print(f"    Paint Halation complete (thresh={ht:.2f} sigma={sig:.1f} "
              f"bloom_strength={bs:.2f} bright_frac={bright_frac:.3f} "
              f"bloom_mean={bloom_mean:.4f})")
    def basquiat_neo_expressionist_scrawl_pass(
        self,
        n_levels:        int   = 6,
        n_marks:         int   = 180,
        mark_length:     int   = 18,
        mark_width:      float = 2.0,
        mark_strength:   float = 0.22,
        dark_mark_frac:  float = 0.65,
        mid_lo:          float = 0.22,
        mid_hi:          float = 0.72,
        sat_boost:       float = 0.40,
        opacity:         float = 0.82,
        seed:            int   = 249,
    ) -> None:
        r"""Jean-Michel Basquiat Neo-Expressionist Scrawl -- session 249: ONE HUNDRED AND SIXTIETH distinct mode.

        THREE-STAGE NEO-EXPRESSIONIST SCRAWL (Jean-Michel Basquiat):

        Stage 1 PER-PIXEL CHANNEL DISCRETE POSTERIZATION: For each pixel,
        independently quantize each R, G, B channel to n_levels discrete steps
        using: quantized = floor(channel * n_levels) / n_levels. This flattens
        continuous tonal gradients into discrete flat colour fields, reproducing
        the graphic sign-painter directness of Basquiat flat primary-colour zones
        -- cadmium red, chrome yellow, near-white, near-black -- where colour is
        applied as a single flat decision rather than a modulated tonal field.
        NOVEL: (a) GLOBAL PER-PIXEL PER-CHANNEL DISCRETE POSTERIZATION AS PRIMARY
        COLOUR STAGE -- first pass to apply global per-pixel per-channel discrete
        level quantization (floor rounding) as its primary colour operation;
        de Stael tile mean quantization (session 248) averages all pixels within
        a spatial tile region before replacing them -- a spatial average; this
        pass operates independently on each pixel by channel without any spatial
        averaging; no prior pass applies floor-rounding to discrete channel levels
        as its primary colour stage.

        Stage 2 RANDOM DIRECTIONAL CRUDE MARK OVERLAY: Generate n_marks random
        oriented marks using rng with seed. For each mark: random centre (cx, cy)
        in [0, W) x [0, H); random angle theta in [0, pi); polarity = -1 (dark)
        with probability dark_mark_frac else +1 (light). Compute a local bounding
        box around the centre. Within that box, compute per-pixel distance to the
        line segment at angle theta clamped to half_length. Pixels within
        mark_width/2 of the segment receive +/- mark_strength.
        NOVEL: (b) RANDOM DIRECTIONAL LINE-SEGMENT RASTER MARK FIELD -- first
        pass to generate a parametric random field of short oriented line-segment
        raster marks; each mark is defined by a random position, angle, and
        polarity, rasterized by per-pixel distance to the clamped segment; prior
        directional passes apply convolutional kernels uniformly to the full
        canvas -- none generate individually positioned and oriented segment marks.

        Stage 3 MIDTONE SATURATION AMPLIFICATION: Compute per-pixel luminance
        lum = 0.299r + 0.587g + 0.114b. Build a midtone mask with smooth ramps.
        Within the masked region, push each channel away from the pixel luminance
        value by factor (1 + sat_boost): ch_boosted = lum + (ch - lum) * (1 + sat_boost).
        NOVEL: (c) MIDTONE-WINDOW SATURATION AMPLIFICATION -- first pass to
        selectively amplify saturation within a bounded midtone luminance window
        [mid_lo, mid_hi] while leaving very dark shadows and very bright highlights
        at their natural saturation; no prior pass applies saturation amplification
        gated by a two-sided luminance threshold window.

        n_levels       : Number of discrete levels per channel for posterization.
        n_marks        : Total number of crude marks scattered across the canvas.
        mark_length    : Half-length of each mark segment in pixels.
        mark_width     : Perpendicular width of each mark in pixels.
        mark_strength  : Luminance shift amplitude per mark (+/- applied to RGB).
        dark_mark_frac : Fraction of marks that darken (polarity = -1).
        mid_lo         : Lower luminance bound of the midtone saturation window.
        mid_hi         : Upper luminance bound of the midtone saturation window.
        sat_boost      : Saturation amplification factor within the midtone window.
        opacity        : Final composite opacity (0=no change, 1=full effect).
        seed           : RNG seed for reproducibility of mark positions.
        """
        import numpy as _np

        print("    Basquiat Neo-Expressionist Scrawl pass (session 249: 160th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Stage 1: Per-pixel channel discrete posterization
        nl = int(max(2, n_levels))
        r1 = (_np.floor(r0 * nl) / nl).astype(_np.float32)
        g1 = (_np.floor(g0 * nl) / nl).astype(_np.float32)
        b1 = (_np.floor(b0 * nl) / nl).astype(_np.float32)

        # Stage 2: Random directional crude mark overlay
        rng = _np.random.default_rng(int(seed))
        mark_buf = _np.zeros((h, w), dtype=_np.float32)
        half_l  = float(mark_length) / 2.0
        mw_half = float(mark_width) / 2.0
        ms  = float(mark_strength)
        dmf = float(dark_mark_frac)

        for _ in range(int(n_marks)):
            cx    = float(rng.integers(0, w))
            cy    = float(rng.integers(0, h))
            theta = float(rng.uniform(0.0, _np.pi))
            pol   = -1.0 if rng.random() < dmf else 1.0
            cos_t = float(_np.cos(theta))
            sin_t = float(_np.sin(theta))

            xl = max(0, int(cx - abs(cos_t) * half_l - mw_half - 1))
            xr = min(w, int(cx + abs(cos_t) * half_l + mw_half + 2))
            yt = max(0, int(cy - abs(sin_t) * half_l - mw_half - 1))
            yb = min(h, int(cy + abs(sin_t) * half_l + mw_half + 2))
            if xl >= xr or yt >= yb:
                continue

            cols = _np.arange(xl, xr, dtype=_np.float32) - cx
            rows = _np.arange(yt, yb, dtype=_np.float32) - cy
            cc, rr = _np.meshgrid(cols, rows)

            t   = _np.clip(cc * cos_t + rr * sin_t, -half_l, half_l)
            px  = cc - t * cos_t
            py  = rr - t * sin_t
            dist = _np.sqrt(px * px + py * py)

            seg_mask = (dist <= mw_half).astype(_np.float32)
            mark_buf[yt:yb, xl:xr] += seg_mask * pol * ms

        mark_buf = _np.clip(mark_buf, -0.5, 0.5)
        r2 = _np.clip(r1 + mark_buf, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 + mark_buf, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 + mark_buf, 0.0, 1.0).astype(_np.float32)

        # Stage 3: Midtone saturation amplification
        lum   = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        ml    = float(mid_lo)
        mh    = float(mid_hi)
        ramp  = 0.05
        lo_ramp = _np.clip((lum - ml) / max(ramp, 1e-6), 0.0, 1.0)
        hi_ramp = _np.clip((mh - lum) / max(ramp, 1e-6), 0.0, 1.0)
        mid_mask = (lo_ramp * hi_ramp).astype(_np.float32)

        sb = float(sat_boost)
        def _boost(ch, _lum, _mask):
            boosted = _lum + (ch - _lum) * (1.0 + sb)
            return (ch * (1.0 - _mask) + _np.clip(boosted, 0.0, 1.0) * _mask).astype(_np.float32)

        r3 = _boost(r2, lum, mid_mask)
        g3 = _boost(g2, lum, mid_mask)
        b3 = _boost(b2, lum, mid_mask)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        mark_mean = float(_np.abs(mark_buf).mean())
        sat_area  = float((mid_mask > 0.5).mean())
        print(f"    Basquiat Scrawl complete (n_levels={nl} n_marks={int(n_marks)} "
              f"mark_mean={mark_mean:.4f} sat_boost={sb:.2f} sat_area={sat_area:.3f})")
    def paint_chroma_focus_pass(
        self,
        focus_x:              float = 0.50,
        focus_y:              float = 0.40,
        focus_radius:         float = 0.38,
        center_sat_boost:     float = 0.32,
        periphery_sat_reduce: float = 0.22,
        opacity:              float = 0.55,
    ) -> None:
        r"""Paint Chroma Focus -- session 249 artistic improvement.

        RADIALLY-VARYING SATURATION DIFFERENTIAL: Build a smooth radial weight
        map from a configurable focus point. Within the focus radius, boost
        saturation. Beyond the focus radius, gently reduce saturation toward grey.
        The result guides the viewer to the focal area through chromatic contrast.

        THREE-STAGE CHROMA FOCUS:

        Stage 1 RADIAL DISTANCE MAP: For each pixel (row r, col c), compute
        Euclidean distance d_px to the focus point (focus_x * W, focus_y * H).
        Normalise by focus_radius * min(H, W) to obtain dimensionless radial
        distance d. Center weight cw = clip(1 - d, 0, 1). Periphery weight
        pw = clip(d - 1, 0, 1).
        NOVEL: (a) SMOOTH RADIAL CENTRE-PERIPHERY WEIGHT MAP -- first improvement
        pass to build a per-pixel radial distance field from a configurable focus
        point yielding separate centre and periphery weight arrays; prior
        improvement passes use luminance thresholds, frequency bands, or uniform
        overlays -- none compute a geometric radial distance from a focal point.

        Stage 2 DIFFERENTIAL SATURATION: At each pixel, compute luminance
        lum = 0.299r + 0.587g + 0.114b. In the focus zone: boost saturation by
        pushing channels away from lum by (1 + center_sat_boost * cw). In the
        periphery: reduce saturation by pulling channels toward lum by
        (1 - periphery_sat_reduce * pw).
        NOVEL: (b) RADIAL DIFFERENTIAL SATURATION -- first improvement pass to
        simultaneously boost saturation in a central zone and reduce it in the
        peripheral zone; no prior improvement pass applies a geometric
        centre-boost / periphery-reduce saturation differential.

        Stage 3 OPACITY COMPOSITE: Blend adjusted result with original at opacity.

        focus_x              : Horizontal focus centre as canvas fraction [0,1].
        focus_y              : Vertical focus centre as canvas fraction [0,1].
        focus_radius         : Focus zone radius as fraction of min(H, W).
        center_sat_boost     : Saturation boost factor at focus centre.
        periphery_sat_reduce : Saturation reduction factor at canvas edge.
        opacity              : Final composite opacity.
        """
        import numpy as _np

        print("    Paint Chroma Focus pass (session 249 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Stage 1: Radial distance map
        fx = float(focus_x) * float(w)
        fy = float(focus_y) * float(h)
        fr = max(float(focus_radius) * float(min(h, w)), 1.0)

        rows = _np.arange(h, dtype=_np.float32)[:, None]
        cols = _np.arange(w, dtype=_np.float32)[None, :]
        d_px = _np.sqrt((cols - fx) ** 2 + (rows - fy) ** 2)
        d    = (d_px / fr).astype(_np.float32)

        cw = _np.clip(1.0 - d, 0.0, 1.0).astype(_np.float32)
        pw = _np.clip(d - 1.0, 0.0, 1.0).astype(_np.float32)

        # Stage 2: Differential saturation
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        csb = float(center_sat_boost)
        psr = float(periphery_sat_reduce)

        def _adjust(ch):
            centre_adj    = lum + (ch - lum) * (1.0 + csb * cw)
            periphery_adj = lum + (ch - lum) * (1.0 - psr * pw)
            in_centre  = (cw > 0).astype(_np.float32)
            in_periph  = (pw > 0).astype(_np.float32)
            at_boundary = ((cw == 0) & (pw == 0)).astype(_np.float32)
            result = (
                _np.clip(centre_adj,    0.0, 1.0) * in_centre +
                _np.clip(periphery_adj, 0.0, 1.0) * in_periph * (1.0 - in_centre) +
                ch * at_boundary
            )
            return result.astype(_np.float32)

        r1 = _adjust(r0)
        g1 = _adjust(g0)
        b1 = _adjust(b0)

        # Stage 3: Opacity composite
        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        centre_area    = float((cw > 0.1).mean())
        periphery_area = float((pw > 0.1).mean())
        print(f"    Paint Chroma Focus complete (focus=({float(focus_x):.2f},{float(focus_y):.2f}) "
              f"radius={float(focus_radius):.2f} centre_boost={csb:.2f} "
              f"periphery_reduce={psr:.2f} centre_area={centre_area:.3f})")
    def mitchell_gestural_arc_pass(
        self,
        n_arcs:           int   = 28,
        arc_radius_lo:    float = 0.18,
        arc_radius_hi:    float = 0.55,
        arc_span_lo:      float = 0.55,
        arc_span_hi:      float = 2.20,
        mark_width:       float = 4.5,
        brightness_shift: float = 0.20,
        dark_frac:        float = 0.35,
        wet_sat_thresh:   float = 0.28,
        wet_sigma_lo:     float = 1.4,
        wet_sigma_hi:     float = 3.0,
        wet_strength:     float = 0.32,
        density_boost:    float = 0.26,
        density_reduce:   float = 0.14,
        opacity:          float = 0.80,
        seed:             int   = 250,
    ) -> None:
        r"""Joan Mitchell Gestural Arc -- session 250: ONE HUNDRED AND SIXTY-FIRST distinct mode.

        THREE-STAGE GESTURAL LYRIC ARC (Joan Mitchell):

        Stage 1 LARGE CIRCULAR ARC GESTURAL MARKS: Generate n_arcs arc marks,
        each defined by a random centre point (cx * W, cy * H), a radius r in
        [arc_radius_lo, arc_radius_hi] * min(H, W), a random start_angle in
        [0, 2*pi), and a random arc_span in [arc_span_lo, arc_span_hi] radians.
        For each pixel (row, col), compute the vector from the arc centre to the
        pixel; compute the pixel's angular distance to the nearest arc point
        (clamped to the arc span); compute Euclidean distance from the pixel to
        that nearest arc point. Pixels within mark_width/2 of the nearest arc
        point receive brightness_shift (dark_frac fraction of arcs darken,
        remainder brighten). Accumulate all arc contributions into a delta field.
        NOVEL: (a) CIRCULAR ARC SEGMENT GESTURAL RASTER MARKS -- first pass to
        rasterize gestural overlay marks as curved circular arc segments defined
        by centre, radius, start angle, and arc span; Basquiat (s249) uses
        straight line-segment rasters; Franz Kline (s119) uses calligraphic
        mega-strokes derived from luminance gradient orientation along straight
        paths; no prior pass parameterizes marks as curved circular arc segments.

        Stage 2 WET-SPREAD DIRECTIONAL COLOUR BLEED: Identify high-saturation
        pixels (pixels with per-pixel HSV saturation > wet_sat_thresh) as
        saturated paint marks. For each channel, apply an anisotropic Gaussian
        blur: along the horizontal axis with sigma=wet_sigma_hi and along the
        vertical axis with sigma=wet_sigma_lo (approximating lateral spread of
        arm-direction paint). Blend the spread result with the original via the
        saturation mask (more spread where saturation is highest) at wet_strength.
        NOVEL: (b) SATURATION-GATED ANISOTROPIC COLOUR BLEED -- first pass to
        identify high-saturation pixels as saturated paint marks and apply
        anisotropic Gaussian blending weighted by per-pixel saturation; prior
        wet-blend passes apply uniform or luminance-driven blending; no prior
        pass gates the anisotropic bleed by the per-pixel saturation value.

        Stage 3 MARK DENSITY SATURATION RHYTHM: Using the arc density field D
        accumulated in Stage 1 (counting how many arcs pass within mark_width
        of each pixel), normalise D to [0, 1]. In high-density zones (D > 0.5),
        boost saturation by density_boost * (D - 0.5) * 2. In low-density zones
        (D < 0.5), reduce saturation by density_reduce * (0.5 - D) * 2. This
        creates the dense-sparse rhythmic alternation of all-over composition.
        NOVEL: (c) MARK-DENSITY-GATED SATURATION RHYTHM -- first pass to
        modulate saturation by a spatially derived arc mark density field,
        creating rhythmic chromatic alternation that matches gestural mark
        density; chroma_focus (s249) uses a geometric radial field; Basquiat
        midtone sat (s249) uses a luminance threshold; no prior pass gates
        saturation by a computed mark-density spatial map.

        n_arcs           : Number of circular arc gestural marks.
        arc_radius_lo/hi : Arc radius range as fraction of min(H, W).
        arc_span_lo/hi   : Arc angular span range in radians.
        mark_width       : Width of each arc mark in pixels.
        brightness_shift : Luminance change applied within mark width.
        dark_frac        : Fraction of arcs that darken (polarity = -1).
        wet_sat_thresh   : Saturation threshold above which bleed applies.
        wet_sigma_lo/hi  : Anisotropic Gaussian sigmas (lo = narrow, hi = wide).
        wet_strength     : Opacity of wet-spread blend onto original.
        density_boost    : Saturation boost in high-density arc zones.
        density_reduce   : Saturation reduction in low-density arc zones.
        opacity          : Final composite opacity.
        seed             : RNG seed for arc position reproducibility.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss

        print("    Mitchell Gestural Arc pass (session 250: 161st mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        rng = _np.random.default_rng(int(seed))
        rows_f = _np.arange(h, dtype=_np.float32)[:, None]
        cols_f = _np.arange(w, dtype=_np.float32)[None, :]

        # ── Stage 1: Large circular arc gestural marks ─────────────────────
        delta_arc   = _np.zeros((h, w), dtype=_np.float32)
        density_map = _np.zeros((h, w), dtype=_np.float32)
        mw_half = float(mark_width) / 2.0
        min_dim = float(min(h, w))
        bs = float(brightness_shift)
        df = float(dark_frac)

        for _ in range(int(n_arcs)):
            cx     = float(rng.uniform(0.1, 0.9)) * w
            cy     = float(rng.uniform(0.1, 0.9)) * h
            r_norm = float(rng.uniform(float(arc_radius_lo), float(arc_radius_hi)))
            radius = r_norm * min_dim
            start  = float(rng.uniform(0.0, 2.0 * _np.pi))
            span   = float(rng.uniform(float(arc_span_lo), float(arc_span_hi)))
            pol    = -1.0 if rng.random() < df else 1.0

            # Per-pixel angle relative to arc centre
            dy_pix = rows_f - cy
            dx_pix = cols_f - cx
            ang    = _np.arctan2(dy_pix, dx_pix).astype(_np.float32)

            # Clamp angle to arc span (modular arithmetic)
            dang = ((ang - start + _np.pi) % (2.0 * _np.pi) - _np.pi).astype(_np.float32)
            clamped = _np.clip(dang, 0.0, float(span))
            # Nearest arc point: point at (cx + radius*cos(start+clamped), ...)
            nearest_ang = start + clamped
            nx = cx + radius * _np.cos(nearest_ang).astype(_np.float32)
            ny = cy + radius * _np.sin(nearest_ang).astype(_np.float32)

            dist = _np.sqrt((cols_f - nx) ** 2 + (rows_f - ny) ** 2).astype(_np.float32)
            inside = (dist <= mw_half).astype(_np.float32)
            delta_arc   += inside * (pol * bs)
            density_map += inside

        delta_arc   = _np.clip(delta_arc, -0.6, 0.6)
        r1 = _np.clip(r0 + delta_arc, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 + delta_arc, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 + delta_arc, 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Wet-spread directional colour bleed ────────────────────
        maxc  = _np.maximum(_np.maximum(r1, g1), b1)
        minc  = _np.minimum(_np.minimum(r1, g1), b1)
        sat   = _np.where(maxc > 1e-8, (maxc - minc) / (maxc + 1e-8), 0.0).astype(_np.float32)
        sat_w = _np.clip((sat - float(wet_sat_thresh)) / max(1.0 - float(wet_sat_thresh), 0.01),
                         0.0, 1.0).astype(_np.float32)

        sl, sh = float(wet_sigma_lo), float(wet_sigma_hi)
        def _aniso_blur(ch):
            bl_h = _gauss(ch, sigma=[sl, sh])   # narrow vertical, wide horizontal
            bl_v = _gauss(ch, sigma=[sh, sl])   # wide vertical, narrow horizontal
            return ((bl_h + bl_v) * 0.5).astype(_np.float32)

        ws = float(wet_strength)
        r2 = _np.clip(r1 * (1.0 - sat_w * ws) + _aniso_blur(r1) * sat_w * ws, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 * (1.0 - sat_w * ws) + _aniso_blur(g1) * sat_w * ws, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 * (1.0 - sat_w * ws) + _aniso_blur(b1) * sat_w * ws, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Mark density saturation rhythm ─────────────────────────
        d_max = float(density_map.max())
        if d_max > 0:
            d_norm = (density_map / d_max).astype(_np.float32)
        else:
            d_norm = density_map.astype(_np.float32)

        maxc2 = _np.maximum(_np.maximum(r2, g2), b2)
        minc2 = _np.minimum(_np.minimum(r2, g2), b2)
        lum2  = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)

        hi_dens = _np.clip(d_norm - 0.5, 0.0, 0.5) * 2.0   # 0->1 for dense zones
        lo_dens = _np.clip(0.5 - d_norm, 0.0, 0.5) * 2.0   # 0->1 for sparse zones

        db = float(density_boost)
        dr = float(density_reduce)

        def _mod_sat(ch, _lum, boost_w, reduce_w):
            boosted  = _lum + (ch - _lum) * (1.0 + db * boost_w)
            reduced  = _lum + (ch - _lum) * (1.0 - dr * reduce_w)
            return _np.clip(boosted * boost_w + reduced * reduce_w + ch * (1.0 - boost_w - reduce_w),
                            0.0, 1.0).astype(_np.float32)

        bw = _np.clip(hi_dens, 0.0, 1.0)
        rw = _np.clip(lo_dens * (1.0 - bw), 0.0, 1.0)
        r3 = _mod_sat(r2, lum2, bw, rw)
        g3 = _mod_sat(g2, lum2, bw, rw)
        b3 = _mod_sat(b2, lum2, bw, rw)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op
        buf   = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        arc_cov   = float((density_map > 0).mean())
        dense_cov = float((d_norm > 0.5).mean())
        print(f"    Mitchell Gestural Arc complete (n_arcs={int(n_arcs)} "
              f"arc_coverage={arc_cov:.3f} dense_zones={dense_cov:.3f})")

    def paint_chromatic_underdark_pass(
        self,
        shadow_thresh:  float = 0.32,
        shadow_fade:    float = 0.12,
        dark_hue:       float = 0.72,
        dark_strength:  float = 0.40,
        clarity_sigma:  float = 1.6,
        clarity_amount: float = 0.22,
        opacity:        float = 0.50,
    ) -> None:
        r"""Paint Chromatic Underdark -- session 250 artistic improvement.

        THREE-STAGE SHADOW CHROMATIC ENRICHMENT:

        Stage 1 SHADOW MASK CONSTRUCTION: Compute per-pixel luminance
        lum = 0.299r + 0.587g + 0.114b. Build a smooth shadow mask with a
        soft ramp: shadow_mask = clip((shadow_thresh - lum) / shadow_fade, 0, 1).
        Pixels with lum << shadow_thresh receive mask=1.0 (full shadow); pixels
        with lum slightly below shadow_thresh receive a partial mask; pixels
        with lum >= shadow_thresh receive mask=0.0 (no effect). This produces
        a spatially smooth shadow zone without hard boundaries.
        NOVEL: (a) CONFIGURABLE HUE ANCHOR SHADOW ENRICHMENT -- first improvement
        pass to rotate shadow-zone pixel hues in HSV space toward a configurable
        deep chromatic anchor hue (dark_hue), weighted by per-pixel saturation
        and shadow_mask; prior improvement passes (chroma_focus: radial boost/
        reduce; halation: bright bloom; golden_ground: warm tone overlay;
        aerial_perspective: luminance gradient; luminance_stretch: range expand;
        optical_vibration: hue-shift by gradient magnitude) do not apply a
        configurable deep hue target specifically in shadow zones via HSV rotation.

        Stage 2 HUE-BIASED SHADOW ENRICHMENT: Convert RGB to HSV per pixel.
        In shadow zones, rotate the hue toward dark_hue by angular interpolation:
        hue_new = hue + shadow_mask * sat * dark_strength * delta_hue, where
        delta_hue is the shortest angular path from hue to dark_hue (mod 1.0).
        Convert back to RGB. The result: coloured shadows pick up a deep violet-
        indigo (or configurable) cast, adding chromatic richness to what would
        otherwise be flat dark areas, a technique of the great colorists from
        Velazquez to Bonnard.
        NOVEL: (b) SATURATION-WEIGHTED HSV HUE ROTATION TOWARD DEEP ANCHOR IN
        SHADOW ZONE -- the hue rotation is scaled by the pixel's existing
        saturation (s), so achromatic pixels are unaffected while chromatic
        shadow pixels gain a hue bias; no prior improvement pass applies a
        saturation-modulated, anchor-targeted hue rotation within a luminance-
        defined shadow zone.

        Stage 3 SHADOW CLARITY LIFT: Apply an unsharp mask within the shadow
        zone: blurred = Gaussian(r2, sigma=clarity_sigma); clarity_delta =
        (r2 - blurred) * clarity_amount * shadow_mask. Add clarity_delta to
        each channel. This lifts local contrast in the shadow zone, preventing
        dark areas from becoming undifferentiated flat black and preserving the
        textural information that lies in dark passages.
        NOVEL: (c) SHADOW-ZONE UNSHARP MASK CLARITY -- first improvement pass
        to apply unsharp mask (local contrast lift) specifically within the
        shadow-zone mask; prior improvement passes do not target local contrast
        enhancement to shadow regions; edge passes (edge_definition, edge_lost_
        and_found) apply sharpening globally or by focal zone, not shadow-masked.

        shadow_thresh  : Luminance below which the shadow mask begins.
        shadow_fade    : Width of the smooth transition band above shadow_thresh.
        dark_hue       : Target deep hue for shadow enrichment (0=red, 0.72=blue-violet).
        dark_strength  : Maximum hue rotation strength within shadow zone.
        clarity_sigma  : Gaussian sigma for the unsharp mask blur.
        clarity_amount : Unsharp mask strength within shadow zone.
        opacity        : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gauss

        print("    Paint Chromatic Underdark pass (session 250 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Shadow mask ────────────────────────────────────────────
        lum  = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        fade = max(float(shadow_fade), 1e-6)
        sh_mask = _np.clip((float(shadow_thresh) - lum) / fade, 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Hue-biased shadow enrichment ──────────────────────────
        maxc  = _np.maximum(_np.maximum(r0, g0), b0)
        minc  = _np.minimum(_np.minimum(r0, g0), b0)
        delta = maxc - minc
        d_safe = _np.where(delta > 1e-8, delta, 1.0).astype(_np.float32)

        is_r  = (maxc == r0) & (delta > 1e-8)
        is_g  = (~is_r) & (maxc == g0) & (delta > 1e-8)
        is_b  = (~is_r) & (~is_g) & (maxc == b0) & (delta > 1e-8)
        hue_raw = _np.where(is_r, (g0 - b0) / d_safe, 0.0)
        hue_raw = _np.where(is_g, 2.0 + (b0 - r0) / d_safe, hue_raw)
        hue_raw = _np.where(is_b, 4.0 + (r0 - g0) / d_safe, hue_raw)
        hue     = (hue_raw / 6.0 % 1.0).astype(_np.float32)
        sat     = _np.where(maxc > 1e-8, delta / (maxc + 1e-8), 0.0).astype(_np.float32)
        val     = maxc.astype(_np.float32)

        dh   = float(dark_hue)
        diff = ((dh - hue + 0.5) % 1.0 - 0.5).astype(_np.float32)  # shortest path
        ds   = float(dark_strength)
        hue1 = (hue + sh_mask * sat * ds * diff) % 1.0

        # HSV → RGB
        h6 = hue1 * 6.0
        i  = _np.floor(h6).astype(_np.int32) % 6
        f  = (h6 - _np.floor(h6)).astype(_np.float32)
        p  = (val * (1.0 - sat)).astype(_np.float32)
        q  = (val * (1.0 - sat * f)).astype(_np.float32)
        t_ = (val * (1.0 - sat * (1.0 - f))).astype(_np.float32)
        r1 = _np.where(i == 0, val, _np.where(i == 1, q, _np.where(i == 2, p,
             _np.where(i == 3, p, _np.where(i == 4, t_, val))))).astype(_np.float32)
        g1 = _np.where(i == 0, t_, _np.where(i == 1, val, _np.where(i == 2, val,
             _np.where(i == 3, q, _np.where(i == 4, p, p))))).astype(_np.float32)
        b1 = _np.where(i == 0, p, _np.where(i == 1, p, _np.where(i == 2, t_,
             _np.where(i == 3, val, _np.where(i == 4, val, q))))).astype(_np.float32)
        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        # ── Stage 3: Shadow clarity lift ───────────────────────────────────
        ca = float(clarity_amount)
        cs = max(float(clarity_sigma), 0.5)

        def _clarity(ch):
            blurred = _gauss(ch, sigma=cs)
            return _np.clip(ch + (ch - blurred) * ca * sh_mask, 0.0, 1.0).astype(_np.float32)

        r2 = _clarity(r1)
        g2 = _clarity(g1)
        b2 = _clarity(b1)

        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op
        buf   = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        shadow_area = float((sh_mask > 0.1).mean())
        sat_mean    = float(sat[sh_mask > 0.3].mean()) if (sh_mask > 0.3).any() else 0.0
        print(f"    Chromatic Underdark complete (shadow_area={shadow_area:.3f} "
              f"sat_mean_in_shadow={sat_mean:.3f} dark_hue={float(dark_hue):.2f})")

    def bacon_isolated_figure_pass(
        self,
        focal_x:          float = 0.50,
        focal_y:          float = 0.50,
        rx:               float = 0.38,
        ry:               float = 0.46,
        transition_width: float = 0.08,
        exterior_strength: float = 0.72,
        smear_angle:      float = 25.0,
        smear_length:     int   = 14,
        mid_luminance:    float = 0.48,
        smear_bandwidth:  float = 0.30,
        smear_opacity:    float = 0.70,
        flat_hue:         float = 0.06,
        flat_sat:         float = 0.72,
        exterior_blend:   float = 0.58,
        opacity:          float = 0.85,
    ) -> None:
        r"""Bacon Isolated Figure -- session 251, 162nd distinct painting mode.

        THREE-STAGE ISOLATED FIGURE SMEAR:

        Stage 1 ELLIPTICAL ISOLATION VIGNETTE: Build per-pixel elliptical
        distance map from (focal_x * w, focal_y * h) with semi-axes
        (rx * min_dim, ry * min_dim). Normalise so ellipse boundary = 1.0.
        Build exterior weight: ext_w = clip((d_norm - 1.0) / transition_width,
        0, 1) smoothed by cosine curve (1 - cos(pi * t)) / 2.
        Darken exterior: r_ext = r * (1 - exterior_strength * ext_w).
        NOVEL: (a) ELLIPTICAL ISOLATION VIGNETTE -- first pass to use a
        configurable elliptical (not circular, not corner-based) spatial zone
        as primary spatial structure; vignette_pass uses corner-based quartic
        falloff; chroma_focus uses circular radial field for saturation (not
        darkening); no prior pass uses explicit ellipse with configurable
        aspect ratio (rx != ry) as primary spatial mask.

        Stage 2 DIRECTIONAL LINEAR SMEAR: Compute interior mask int_w = 1 -
        ext_w. Per-pixel luminance lum; smear weight sw = clip(1 - |lum -
        mid_luminance| / smear_bandwidth, 0, 1): smear is strongest in mid-
        tone pixels (flesh), weakest at bright highlights and deep shadows.
        Apply discrete linear motion-blur kernel of smear_length pixels at
        smear_angle degrees. NOVEL: (b) DISCRETE LINEAR MOTION-BLUR KERNEL
        WEIGHTED BY MID-TONE LUMINANCE PROXIMITY -- first pass to apply a
        directional line-averaging kernel (not Gaussian) to simulate Bacon
        rag-scrub smear technique; prior blur passes use isotropic Gaussian
        forms or structure-guided filtering.

        Stage 3 FLAT BACKGROUND TONE FIELD: In exterior zone (ext_w > 0),
        blend pixel hue toward flat_hue and saturation toward flat_sat by
        exterior_blend * ext_w. Unifies background to flat tone field --
        Bacon characteristic raw sienna, cobalt, or viridian ground.
        NOVEL: (c) HUE AND SATURATION FIELD UNIFICATION IN EXTERIOR ELLIPSE
        ZONE -- first pass to apply coordinated hue + saturation target
        blending in the exterior isolation zone.

        focal_x, focal_y   : Ellipse centre as fraction of width/height.
        rx, ry             : Ellipse semi-axes as fraction of min(w,h).
        transition_width   : Smooth transition band width (ellipse normalised).
        exterior_strength  : Darkening in exterior zone (0=none, 1=black).
        smear_angle        : Direction of motion blur in degrees (0=horizontal).
        smear_length       : Number of pixels in linear smear kernel.
        mid_luminance      : Luminance around which smear is strongest.
        smear_bandwidth    : Halfwidth of smear weight around mid_luminance.
        smear_opacity      : Smear blend strength.
        flat_hue           : Target hue for background field (0=red, 0.06=sienna).
        flat_sat           : Target saturation for background field.
        exterior_blend     : Hue/sat blend strength toward flat field.
        opacity            : Final composite opacity.
        """
        import numpy as _np

        print("    Bacon Isolated Figure pass (session 251, 162nd mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Stage 1: Elliptical isolation vignette
        min_dim = float(min(w, h))
        cx = float(focal_x) * w
        cy = float(focal_y) * h
        axr = max(float(rx) * min_dim, 1.0)
        axc = max(float(ry) * min_dim, 1.0)
        ys = _np.arange(h, dtype=_np.float32)
        xs = _np.arange(w, dtype=_np.float32)
        yy, xx = _np.meshgrid(ys, xs, indexing='ij')
        d_norm = _np.sqrt(((xx - cx) / axr) ** 2 + ((yy - cy) / axc) ** 2).astype(_np.float32)
        tw = max(float(transition_width), 1e-3)
        t_raw = _np.clip((d_norm - 1.0) / tw, 0.0, 1.0).astype(_np.float32)
        ext_w = ((1.0 - _np.cos(_np.pi * t_raw)) / 2.0).astype(_np.float32)
        int_w = (1.0 - ext_w).astype(_np.float32)

        es = float(exterior_strength)
        r1 = (r0 * (1.0 - es * ext_w)).astype(_np.float32)
        g1 = (g0 * (1.0 - es * ext_w)).astype(_np.float32)
        b1 = (b0 * (1.0 - es * ext_w)).astype(_np.float32)

        # Stage 2: Directional linear smear in interior
        ang_rad = float(smear_angle) * _np.pi / 180.0
        dy = float(_np.sin(ang_rad))
        dx = float(_np.cos(ang_rad))
        sl = max(int(smear_length), 1)
        half = sl // 2

        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        ml = float(mid_luminance)
        sb = max(float(smear_bandwidth), 1e-3)
        sw = _np.clip(1.0 - _np.abs(lum1 - ml) / sb, 0.0, 1.0).astype(_np.float32)

        offsets = _np.arange(-half, sl - half, dtype=_np.float32)
        off_y = offsets * dy
        off_x = offsets * dx

        acc_r = _np.zeros_like(r1)
        acc_g = _np.zeros_like(g1)
        acc_b = _np.zeros_like(b1)

        for k in range(sl):
            sy = _np.clip(_np.round(yy + off_y[k]).astype(_np.int32), 0, h - 1)
            sx = _np.clip(_np.round(xx + off_x[k]).astype(_np.int32), 0, w - 1)
            acc_r += r1[sy, sx]
            acc_g += g1[sy, sx]
            acc_b += b1[sy, sx]

        smear_r = (acc_r / sl).astype(_np.float32)
        smear_g = (acc_g / sl).astype(_np.float32)
        smear_b = (acc_b / sl).astype(_np.float32)

        so = float(smear_opacity)
        blend = so * int_w * sw
        r2 = (r1 + blend * (smear_r - r1)).astype(_np.float32)
        g2 = (g1 + blend * (smear_g - g1)).astype(_np.float32)
        b2 = (b1 + blend * (smear_b - b1)).astype(_np.float32)

        # Stage 3: Flat background tone field
        maxc  = _np.maximum(_np.maximum(r2, g2), b2)
        minc  = _np.minimum(_np.minimum(r2, g2), b2)
        delta = maxc - minc
        d_safe = _np.where(delta > 1e-8, delta, 1.0).astype(_np.float32)

        is_r  = (maxc == r2) & (delta > 1e-8)
        is_g  = (~is_r) & (maxc == g2) & (delta > 1e-8)
        is_b  = (~is_r) & (~is_g) & (maxc == b2) & (delta > 1e-8)
        hue_raw = _np.where(is_r, (g2 - b2) / d_safe, 0.0)
        hue_raw = _np.where(is_g, 2.0 + (b2 - r2) / d_safe, hue_raw)
        hue_raw = _np.where(is_b, 4.0 + (r2 - g2) / d_safe, hue_raw)
        hue = (hue_raw / 6.0 % 1.0).astype(_np.float32)
        sat = _np.where(maxc > 1e-8, delta / (maxc + 1e-8), 0.0).astype(_np.float32)
        val = maxc.astype(_np.float32)

        fh = float(flat_hue)
        fs = float(flat_sat)
        eb = float(exterior_blend)
        diff_h = ((fh - hue + 0.5) % 1.0 - 0.5).astype(_np.float32)
        blend_ext = (ext_w * eb).astype(_np.float32)
        hue3 = (hue + blend_ext * diff_h) % 1.0
        sat3 = _np.clip(sat + blend_ext * (fs - sat), 0.0, 1.0).astype(_np.float32)
        val3 = val

        h6 = hue3 * 6.0
        i  = _np.floor(h6).astype(_np.int32) % 6
        f_ = (h6 - _np.floor(h6)).astype(_np.float32)
        p_ = (val3 * (1.0 - sat3)).astype(_np.float32)
        q_ = (val3 * (1.0 - sat3 * f_)).astype(_np.float32)
        t_ = (val3 * (1.0 - sat3 * (1.0 - f_))).astype(_np.float32)
        r3 = _np.where(i == 0, val3, _np.where(i == 1, q_, _np.where(i == 2, p_,
             _np.where(i == 3, p_, _np.where(i == 4, t_, val3))))).astype(_np.float32)
        g3 = _np.where(i == 0, t_, _np.where(i == 1, val3, _np.where(i == 2, val3,
             _np.where(i == 3, q_, _np.where(i == 4, p_, p_))))).astype(_np.float32)
        b3 = _np.where(i == 0, p_, _np.where(i == 1, p_, _np.where(i == 2, t_,
             _np.where(i == 3, val3, _np.where(i == 4, val3, q_))))).astype(_np.float32)
        r3 = _np.clip(r3, 0.0, 1.0)
        g3 = _np.clip(g3, 0.0, 1.0)
        b3 = _np.clip(b3, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        int_coverage = float(int_w.mean())
        smear_active = float((blend * sw > 0.05).mean())
        ext_hue_shift = float((_np.abs(diff_h) * blend_ext).mean())
        print(f"    Bacon Isolated Figure complete (int_coverage={int_coverage:.3f} "
              f"smear_active={smear_active:.3f} ext_hue_shift={ext_hue_shift:.4f})")

    def paint_warm_cool_separation_pass(
        self,
        warm_boost:     float = 0.28,
        cool_boost:     float = 0.24,
        warm_lum_shift: float = 0.04,
        cool_lum_shift: float = 0.03,
        opacity:        float = 0.55,
    ) -> None:
        r"""Paint Warm-Cool Separation -- session 251 artistic improvement.

        THREE-STAGE TEMPERATURE CHROMATIC PUSH:

        Stage 1 WARM-COOL HUE ZONE CLASSIFICATION: Compute per-pixel hue in
        HSV. Build warm weight warm_w as cosine proximity centred on
        warm_hue_centre=0.07 (red-orange-yellow, [0,0.16] + [0.9,1.0] wrap).
        Build cool weight cool_w as cosine proximity centred on
        cool_hue_centre=0.62 (blue-violet, [0.50,0.75]). Both weights
        modulated by saturation so achromatic pixels are unaffected.
        NOVEL: (a) DUAL HUE-ZONE WARM-COOL CLASSIFICATION -- first improvement
        pass to explicitly build separate warm-zone and cool-zone cosine
        proximity weight maps modulated by saturation; prior saturation passes
        (chroma_focus: radial; chromatic_underdark: shadow-luminance-gated;
        basquiat midtone: luminance-range) do not classify by warm/cool hue.

        Stage 2 INDEPENDENT WARM AND COOL SATURATION PUSH: Apply separate
        saturation amplifications: warm zones receive +warm_boost * warm_w,
        cool zones receive +cool_boost * cool_w. Strongly warm or cool pixels
        receive a larger saturation boost than neutral pixels, causing
        temperature poles to pull further apart in colour space.
        NOVEL: (b) DUAL INDEPENDENT TEMPERATURE-ZONE SATURATION AMPLIFICATION
        -- first improvement pass to simultaneously boost warm-zone and cool-
        zone saturation via independent per-pixel weights.

        Stage 3 TEMPERATURE-DEPENDENT LUMINOSITY ADJUSTMENT: lum_shift =
        warm_lum_shift * warm_w - cool_lum_shift * cool_w; val_new = clip(val
        + lum_shift, 0, 1). Follows perceptual temperature rule: warm colours
        appear lighter, cool colours appear heavier (used by Rubens, Delacroix,
        Venetian colorists).
        NOVEL: (c) TEMPERATURE-DEPENDENT LUMINOSITY ADJUSTMENT -- first
        improvement pass to adjust per-pixel luminosity (HSV value) based on
        warm/cool hue classification; prior passes apply luminosity changes
        based on brightness thresholds, radial position, or shadow masks.

        warm_boost     : Saturation amplification in warm hue zones.
        cool_boost     : Saturation amplification in cool hue zones.
        warm_lum_shift : Luminosity lift applied in warm zones.
        cool_lum_shift : Luminosity drop applied in cool zones.
        opacity        : Final composite opacity.
        """
        import numpy as _np

        print("    Paint Warm-Cool Separation pass (session 251 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Compute HSV
        maxc  = _np.maximum(_np.maximum(r0, g0), b0)
        minc  = _np.minimum(_np.minimum(r0, g0), b0)
        delta = maxc - minc
        d_safe = _np.where(delta > 1e-8, delta, 1.0).astype(_np.float32)

        is_r  = (maxc == r0) & (delta > 1e-8)
        is_g  = (~is_r) & (maxc == g0) & (delta > 1e-8)
        is_b  = (~is_r) & (~is_g) & (maxc == b0) & (delta > 1e-8)
        hue_raw = _np.where(is_r, (g0 - b0) / d_safe, 0.0)
        hue_raw = _np.where(is_g, 2.0 + (b0 - r0) / d_safe, hue_raw)
        hue_raw = _np.where(is_b, 4.0 + (r0 - g0) / d_safe, hue_raw)
        hue = (hue_raw / 6.0 % 1.0).astype(_np.float32)
        sat = _np.where(maxc > 1e-8, delta / (maxc + 1e-8), 0.0).astype(_np.float32)
        val = maxc.astype(_np.float32)

        # Stage 1: Warm-cool zone classification
        warm_center = 0.07
        warm_radius = 0.20
        dw = _np.minimum(_np.abs(hue - warm_center),
                         1.0 - _np.abs(hue - warm_center)).astype(_np.float32)
        warm_w = _np.clip(
            (_np.cos(_np.pi * _np.clip(dw / warm_radius, 0.0, 1.0)) * 0.5 + 0.5) * sat,
            0.0, 1.0
        ).astype(_np.float32)

        cool_center = 0.62
        cool_radius = 0.22
        dc = _np.abs(hue - cool_center).astype(_np.float32)
        cool_w = _np.clip(
            (_np.cos(_np.pi * _np.clip(dc / cool_radius, 0.0, 1.0)) * 0.5 + 0.5) * sat,
            0.0, 1.0
        ).astype(_np.float32)

        # Stage 2: Independent saturation push
        wb = float(warm_boost)
        cb = float(cool_boost)
        sat2 = _np.clip(sat + wb * warm_w + cb * cool_w, 0.0, 1.0).astype(_np.float32)

        # Stage 3: Temperature luminosity adjustment
        wls = float(warm_lum_shift)
        cls_ = float(cool_lum_shift)
        lum_shift = wls * warm_w - cls_ * cool_w
        val2 = _np.clip(val + lum_shift, 0.0, 1.0).astype(_np.float32)

        # HSV -> RGB
        h6 = hue * 6.0
        i  = _np.floor(h6).astype(_np.int32) % 6
        f_ = (h6 - _np.floor(h6)).astype(_np.float32)
        p_ = (val2 * (1.0 - sat2)).astype(_np.float32)
        q_ = (val2 * (1.0 - sat2 * f_)).astype(_np.float32)
        t_ = (val2 * (1.0 - sat2 * (1.0 - f_))).astype(_np.float32)
        r2 = _np.where(i == 0, val2, _np.where(i == 1, q_, _np.where(i == 2, p_,
             _np.where(i == 3, p_, _np.where(i == 4, t_, val2))))).astype(_np.float32)
        g2 = _np.where(i == 0, t_, _np.where(i == 1, val2, _np.where(i == 2, val2,
             _np.where(i == 3, q_, _np.where(i == 4, p_, p_))))).astype(_np.float32)
        b2 = _np.where(i == 0, p_, _np.where(i == 1, p_, _np.where(i == 2, t_,
             _np.where(i == 3, val2, _np.where(i == 4, val2, q_))))).astype(_np.float32)
        r2 = _np.clip(r2, 0.0, 1.0)
        g2 = _np.clip(g2, 0.0, 1.0)
        b2 = _np.clip(b2, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op
        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        warm_area = float((warm_w > 0.1).mean())
        cool_area = float((cool_w > 0.1).mean())
        print(f"    Warm-Cool Separation complete (warm_area={warm_area:.3f} "
              f"cool_area={cool_area:.3f})")

    def richter_squeegee_drag_pass(
        self,
        n_bands:        int   = 22,
        band_min:       int   = 28,
        band_max:       int   = 90,
        drag_fraction:  float = 0.62,
        drag_offset:    int   = 8,
        sat_threshold:  float = 0.28,
        trail_length:   int   = 48,
        trail_strength: float = 0.55,
        residue_amp:    float = 0.055,
        opacity:        float = 0.80,
        seed:           int   = 252,
    ) -> None:
        r"""Gerhard Richter Squeegee Drag -- session 252, 163rd distinct painting mode.

        THREE-STAGE SQUEEGEE DRAG:

        Stage 1 HORIZONTAL DRAG BAND DECOMPOSITION: Divide the canvas into
        n_bands horizontal strips of randomly varied height, each between
        band_min and band_max pixels (RNG seeded with seed). For each band,
        simulate a lateral squeegee drag by blending pixel colours toward the
        mean colour of rows at +/- drag_offset above and below the band centre,
        scaled by drag_fraction. The blended result reproduces the squeegee
        picking up paint from adjacent zones and mixing it as it travels across.
        Accumulate a per-pixel drag weight map (1.0 within band interiors,
        tapering to 0 at boundaries via cosine ramp of width 6px).
        NOVEL: (a) SPATIALLY PARTITIONED HORIZONTAL DRAG BAND AVERAGING --
        first pass to mix pixel colours via explicit band decomposition with
        adjacent-row sampling (drag_offset rows above/below); all prior
        directional blur passes (bacon smear, mitchell arc spread, kollwitz
        charcoal) apply either global convolution kernels or mark-local
        operations -- none decompose the canvas into random-height horizontal
        drag bands with cross-band colour averaging as the primary colour
        stage.

        Stage 2 LATERAL PIGMENT CHANNEL TRAILS: At each inter-band boundary
        (transition rows between adjacent bands), detect pixels whose HSV
        saturation exceeds sat_threshold. For each such pixel, apply a 1-D
        horizontal mean-filter of width trail_length centred on that pixel,
        then blend trail_strength of this filtered value back over the current
        pixel colour. This creates the concentrated pigment channel ridges left
        by the squeegee blade edge -- the colour rivers that are the most
        recognisable visual signature of Richter's abstract paintings.
        NOVEL: (b) SATURATION-GATED DIRECTIONAL TRAIL BLUR AT DRAG BOUNDARIES
        -- first pass to detect pigment concentration at drag-band boundary
        rows and apply a directional horizontal trail blur exclusively at those
        boundaries as a distinct secondary stage; basquiat marks (s249) apply
        a random directional segment raster; bacon (s251) applies a directional
        linear smear modulated by mid-tone luminance -- neither gates the trail
        operation on band boundary position combined with per-pixel saturation.

        Stage 3 DRAG RESIDUE LUMINANCE MODULATION: Within each drag band,
        apply a sinusoidal luminance modulation with frequency 1 cycle per
        band-height and amplitude residue_amp. The modulation phase is set so
        that the leading edge of each band (top row) receives a positive
        luminance shift (paint thinned by the blade advancing) and the
        trailing edge (bottom row) receives a negative shift (paint
        accumulated ahead of the blade). The effect is a subtle periodic
        brightening-darkening rhythm across band boundaries.
        NOVEL: (c) BAND-COORDINATED SINUSOIDAL LUMINANCE MODULATION -- first
        pass to apply a per-band sinusoidal brightness variation parameterised
        by fractional position within the band (0=leading edge, 1=trailing
        edge) to simulate squeegee paint thickness variation; no prior pass
        applies luminance variation coordinated to explicitly defined band
        positions; paint_aerial_perspective uses gradient falloff by global
        y-coordinate; this pass uses per-band local phase position.

        n_bands        : Number of horizontal drag bands.
        band_min       : Minimum band height in pixels.
        band_max       : Maximum band height in pixels.
        drag_fraction  : Blend fraction toward adjacent-row mean (0=no drag, 1=full).
        drag_offset    : Y-distance (rows) to sample for adjacent colour mixing.
        sat_threshold  : HSV saturation threshold for pigment trail detection.
        trail_length   : Width of horizontal trail blur in pixels.
        trail_strength : Blend fraction for trail blur (0=none, 1=full trail).
        residue_amp    : Amplitude of sinusoidal luminance modulation (0–0.15).
        opacity        : Final composite opacity (0=no change, 1=full effect).
        seed           : RNG seed for reproducible band layout.
        """
        import numpy as _np

        print("    Richter Squeegee Drag pass (session 252, 163rd mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        rng = _np.random.default_rng(int(seed))

        # Build random band layout
        bmin = max(int(band_min), 4)
        bmax = max(int(band_max), bmin + 4)
        band_heights = rng.integers(bmin, bmax + 1, size=int(n_bands)).tolist()
        # Fill remaining canvas rows with the last band height
        bands = []
        y = 0
        for bh in band_heights:
            if y >= h:
                break
            end = min(y + bh, h)
            bands.append((y, end))
            y = end
        if y < h:
            bands.append((y, h))

        # Stage 1: Horizontal drag band decomposition
        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()
        drag_weight = _np.zeros((h, w), dtype=_np.float32)
        off = max(int(drag_offset), 1)
        df = float(drag_fraction)
        taper = 6

        for (y0, y1) in bands:
            bh = max(y1 - y0, 1)
            # Rows to sample for adjacent colour
            sample_lo = max(y0 - off, 0)
            sample_hi = min(y1 + off, h)
            mean_r = r0[sample_lo:sample_hi, :].mean(axis=0)
            mean_g = g0[sample_lo:sample_hi, :].mean(axis=0)
            mean_b = b0[sample_lo:sample_hi, :].mean(axis=0)

            # Interior drag weight with cosine taper at band edges
            for row in range(y0, y1):
                local_pos = row - y0
                # Cosine taper from band top and bottom
                t_top = min(local_pos, taper) / float(taper)
                t_bot = min((y1 - 1 - row), taper) / float(taper)
                w_factor = (
                    (1.0 - _np.cos(_np.pi * t_top)) / 2.0 *
                    (1.0 - _np.cos(_np.pi * t_bot)) / 2.0
                )
                drag_weight[row, :] = float(w_factor)
                r1[row, :] = r0[row, :] * (1.0 - df * w_factor) + mean_r * df * w_factor
                g1[row, :] = g0[row, :] * (1.0 - df * w_factor) + mean_g * df * w_factor
                b1[row, :] = b0[row, :] * (1.0 - df * w_factor) + mean_b * df * w_factor

        # Stage 2: Lateral pigment channel trails at band boundaries
        r2 = r1.copy()
        g2 = g1.copy()
        b2 = b1.copy()

        sat_thr = float(sat_threshold)
        tl = max(int(trail_length), 1)
        ts = float(trail_strength)

        # Compute HSV saturation of dragged result
        max_c = _np.maximum(_np.maximum(r1, g1), b1)
        min_c = _np.minimum(_np.minimum(r1, g1), b1)
        sat_1 = _np.where(max_c > 1e-8, (max_c - min_c) / (max_c + 1e-8), 0.0).astype(_np.float32)

        # Boundary rows: rows that are within 2 pixels of a band edge
        boundary_mask = _np.zeros(h, dtype=bool)
        for (y0, y1) in bands:
            for dy in range(min(3, y1 - y0)):
                if y0 + dy < h:
                    boundary_mask[y0 + dy] = True
                if y1 - 1 - dy >= 0:
                    boundary_mask[y1 - 1 - dy] = True

        half_t = tl // 2
        pad = _np.zeros(w + 2 * half_t, dtype=_np.float32)

        for row in range(h):
            if not boundary_mask[row]:
                continue
            sat_row = sat_1[row, :]
            high_sat = (sat_row > sat_thr)
            if not high_sat.any():
                continue

            # Horizontal mean filter for trail blur
            def _htrail(ch_row):
                padded = _np.pad(ch_row, half_t, mode='edge')
                cs = _np.cumsum(padded)
                sums = cs[tl:] - cs[:-tl]
                return (sums / tl).astype(_np.float32)

            trail_r = _htrail(r1[row, :])
            trail_g = _htrail(g1[row, :])
            trail_b = _htrail(b1[row, :])

            blend = (high_sat * ts).astype(_np.float32)
            r2[row, :] = r1[row, :] * (1.0 - blend) + trail_r * blend
            g2[row, :] = g1[row, :] * (1.0 - blend) + trail_g * blend
            b2[row, :] = b1[row, :] * (1.0 - blend) + trail_b * blend

        # Stage 3: Drag residue sinusoidal luminance modulation
        r3 = r2.copy()
        g3 = g2.copy()
        b3 = b2.copy()
        amp = float(residue_amp)

        for (y0, y1) in bands:
            bh = float(max(y1 - y0, 1))
            for row in range(y0, y1):
                t = (row - y0) / bh   # 0 at leading edge, 1 at trailing
                # Positive at leading (paint thinned), negative at trailing
                lum_mod = amp * _np.cos(_np.pi * t)
                r3[row, :] = _np.clip(r2[row, :] + lum_mod, 0.0, 1.0)
                g3[row, :] = _np.clip(g2[row, :] + lum_mod, 0.0, 1.0)
                b3[row, :] = _np.clip(b2[row, :] + lum_mod, 0.0, 1.0)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        n_boundary = int(boundary_mask.sum())
        print(f"    Squeegee Drag complete ({len(bands)} bands, {n_boundary} boundary rows)")






    def hilma_af_klint_biomorphic_pass(
        self,
        ring_count:       float = 5.0,
        ring_amplitude:   float = 0.35,
        warm_push:        float = 0.08,
        cool_push:        float = 0.08,
        haze_sigma:       float = 18.0,
        haze_strength:    float = 0.10,
        opacity:          float = 0.78,
    ) -> None:
        r"""Hilma af Klint Biomorphic Abstraction -- session 257, 168th distinct mode.

        THREE-STAGE BIOMORPHIC ABSTRACTION INSPIRED BY AF KLINT'S
        "THE PAINTINGS FOR THE TEMPLE" (1906-1915):

        Hilma af Klint (1862-1944) was a Swedish artist who produced large-scale
        abstract paintings of extraordinary originality, keeping them private
        until after her death. Working in Stockholm from 1906, she painted
        nearly two hundred major canvases in "The Paintings for the Temple"
        series -- biomorphic forms, concentric ovals and spirals, interlocking
        warm and cool colour zones -- before Kandinsky exhibited his first
        abstract works. Her technical signatures: concentric oval/circular
        forms suggesting growth and cosmic cycles; warm amber/orange zones
        (symbolising earthly/masculine energy) opposed by cool blue/violet
        (cosmic/feminine energy); soft transitions where forms bleed into
        each other; luminous halos along form boundaries. The present pass
        derives three stages from these observations.

        Stage 1 CONCENTRIC RADIAL GROWTH RING FIELD: Compute the luminance-
        weighted centroid of the canvas (the visual centre of gravity):
          lum = 0.299R + 0.587G + 0.114B
          cy = sum(y * lum) / sum(lum),  cx = sum(x * lum) / sum(lum)
        From (cy, cx), compute the radial distance field r(y,x). Normalise by
        the mean distance to the four canvas corners so r_norm in [0, ~1].
        Apply a sine wave: ring_field = 0.5 * (1 + sin(2*pi * r_norm *
        ring_count)). This produces concentric growth rings at ring_count
        intervals between 0 and 1, peaking (1.0) at the ring centres and
        troughing (0.0) at the ring midpoints. Scale by ring_amplitude so
        the effect is proportional to the user parameter.
        NOVEL: (a) LUMINANCE-WEIGHTED CENTROID AS RADIAL RING ORIGIN WITH
        SINE-WAVE FREQUENCY RING FIELD -- first pass to derive the centroid
        of the image from the luminance distribution and use it as the origin
        of a sine-frequency radial ring field; no prior pass generates
        concentric sine-wave rings from a computed centroid; paint_warm_cool
        _separation_pass (s251) uses quadrant splits; no prior pass applies
        sin(2*pi*r_norm*freq) growth rings from a luminance-centroid origin.

        Stage 2 BIOMORPHIC ZONE COLOUR RESONANCE: Apply a chromatic warm/cool
        push to each ring zone. For each pixel, compute the ring_field value
        from Stage 1. Inner-ring pixels (ring_field > 0.5) receive a warm push:
          dR = +warm_push * (ring_field - 0.5) * 2
          dB = -warm_push * (ring_field - 0.5) * 2
        Outer-ring pixels (ring_field <= 0.5) receive a cool push:
          dR = -cool_push * (0.5 - ring_field) * 2
          dB = +cool_push * (0.5 - ring_field) * 2
        The push strength is proportional to distance from the 0.5 transition,
        so it is zero at ring boundaries and maximum at ring centres. This
        simulates af Klint's deliberate warm-inner / cool-outer zone pairing
        in her temple paintings.
        NOVEL: (b) RADIAL RING-FIELD DISTANCE-WEIGHTED CHROMATIC WARM/COOL ZONE
        RESONANCE -- first pass to apply chromatic warm/cool colour push with
        strength proportional to the ring_field value's distance from the
        midpoint (0.5), creating alternating warm/cool zones at sine-wave ring
        radii from the luminance centroid; paint_edge_temperature_pass (s256)
        uses hue-distance masks at warm/cool boundaries; no prior pass uses a
        radial sine-wave ring distance as the weight for a chromatic zone push.

        Stage 3 LUMINOUS BOUNDARY HAZE: Compute the absolute value of the
        gradient of the ring_field using central differences:
          gy = ring_field[2:,:] - ring_field[:-2,:]  (padded)
          gx = ring_field[:,2:] - ring_field[:,:-2]  (padded)
          ring_grad = sqrt(gy^2 + gx^2)
        The gradient magnitude is maximum exactly at the ring transition points
        (where sine crosses zero -- the 0.5 value line). Apply a wide Gaussian
        blur with sigma=haze_sigma to spread the gradient into a broad luminous
        zone. Normalise to [0, 1]. Apply as a multiplicative luminosity boost:
          scale = 1 + haze_strength * haze_field
          R *= scale, G *= scale, B *= scale  (clipped to [0,1])
        This simulates the characteristic af Klint boundary luminosity: a soft
        glow at each zone transition, as if the transition line itself radiates
        outward into both the warm and cool zones it separates.
        NOVEL: (c) GRADIENT MAGNITUDE OF RADIAL SINE-WAVE RING FIELD BLURRED
        INTO A WIDE LUMINOSITY HAZE AT RING ZONE TRANSITIONS -- first pass to
        compute the spatial gradient of a ring_field, apply wide Gaussian to
        spread the gradient into a broad glow zone, and use it as a
        multiplicative luminosity scale; no prior pass extracts ring boundary
        gradients and blurs them into a luminous haze; paint_edge_temperature
        _pass (s256) uses gradient of a hue-membership difference map for a
        channel push, not a luminosity scale; no prior pass uses ring boundary
        gradient as a multiplicative brightness field.

        ring_count     : Number of concentric rings (sine periods over r_norm).
        ring_amplitude : Amplitude of the ring field (0=flat, 1=full sine).
        warm_push      : Max warm channel push at ring peak (inner zone).
        cool_push      : Max cool channel push at ring trough (outer zone).
        haze_sigma     : Gaussian sigma for luminous boundary haze spread.
        haze_strength  : Multiplicative luminosity boost at ring boundaries.
        opacity        : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Hilma af Klint Biomorphic pass (session 257, 168th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        # Cairo BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Stage 1: Luminance-weighted centroid + radial ring field
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        lum_sum = float(lum.sum()) + 1e-8

        ys = _np.arange(h, dtype=_np.float32).reshape(-1, 1)
        xs = _np.arange(w, dtype=_np.float32).reshape(1, -1)

        cy = float((ys * lum).sum()) / lum_sum
        cx = float((xs * lum).sum()) / lum_sum

        # Radial distance field
        dy = ys - cy
        dx = xs - cx
        r_field = _np.sqrt(dy ** 2 + dx ** 2).astype(_np.float32)

        # Normalise by mean distance to canvas corners
        corners = [
            _np.sqrt(cy ** 2 + cx ** 2),
            _np.sqrt(cy ** 2 + (w - cx) ** 2),
            _np.sqrt((h - cy) ** 2 + cx ** 2),
            _np.sqrt((h - cy) ** 2 + (w - cx) ** 2),
        ]
        mean_corner_dist = float(_np.mean(corners)) + 1e-8
        r_norm = (r_field / mean_corner_dist).astype(_np.float32)

        # Sine-wave ring field in [0, 1]
        rc = float(ring_count)
        ring_field = (0.5 * (1.0 + _np.sin(2.0 * _np.pi * r_norm * rc))).astype(_np.float32)
        ring_amp = float(ring_amplitude)

        # Stage 2: Biomorphic zone colour resonance
        wp = float(warm_push)
        cp = float(cool_push)

        # Inner-ring zones (ring_field > 0.5): warm push proportional to excess above 0.5
        inner_weight = _np.clip((ring_field - 0.5) * 2.0, 0.0, 1.0).astype(_np.float32)
        # Outer-ring zones (ring_field <= 0.5): cool push proportional to deficit below 0.5
        outer_weight = _np.clip((0.5 - ring_field) * 2.0, 0.0, 1.0).astype(_np.float32)

        dR = (ring_amp * wp * inner_weight - ring_amp * cp * outer_weight).astype(_np.float32)
        dB = (-ring_amp * wp * inner_weight + ring_amp * cp * outer_weight).astype(_np.float32)

        r1 = _np.clip(r0 + dR, 0.0, 1.0).astype(_np.float32)
        g1 = g0.copy()
        b1 = _np.clip(b0 + dB, 0.0, 1.0).astype(_np.float32)

        # Stage 3: Luminous boundary haze at ring transition zones
        # Gradient of ring_field (maximum at sine zero-crossings -- transition points)
        gy = _np.pad(ring_field[2:, :] - ring_field[:-2, :], ((1, 1), (0, 0)), mode='edge')
        gx = _np.pad(ring_field[:, 2:] - ring_field[:, :-2], ((0, 0), (1, 1)), mode='edge')
        ring_grad = _np.sqrt(gy ** 2 + gx ** 2).astype(_np.float32)

        haze_field = _gf(ring_grad, sigma=float(haze_sigma)).astype(_np.float32)
        hm = haze_field.max()
        if hm > 1e-8:
            haze_field /= hm

        scale = (1.0 + float(haze_strength) * haze_field).astype(_np.float32)
        r2 = _np.clip(r1 * scale, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 * scale, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 * scale, 0.0, 1.0).astype(_np.float32)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        print(f"    af Klint Biomorphic complete "
              f"(centroid=({cx:.0f},{cy:.0f}), rings={ring_count:.1f}, "
              f"haze_sigma={haze_sigma:.1f})")

    def kollwitz_charcoal_compression_pass(
        self,
        dark_power:         float = 1.55,
        smear_angle_deg:    float = 38.0,
        smear_sigma_along:  float = 5.0,
        smear_sigma_across: float = 0.6,
        smear_strength:     float = 0.55,
        lift_density:       float = 0.014,
        lift_radius:        float = 2.5,
        lift_strength:      float = 0.22,
        opacity:            float = 0.82,
        seed:               int   = 256,
    ) -> None:
        r"""Käthe Kollwitz Charcoal Compression -- session 256, 167th distinct mode.

        THREE-STAGE CHARCOAL MEDIUM SIMULATION INSPIRED BY KOLLWITZ:

        Stage 1 DARK TONAL COMPRESSION: Apply a power-law luminance
        compression that pushes the tonal range toward the dark half of the
        scale, simulating charcoal's inability to produce luminance above the
        raw paper value. Compute per-pixel luminance:
        lum = 0.299R + 0.587G + 0.114B. Apply power-law: new_lum =
        lum ** dark_power. When dark_power > 1 the midtones and lights
        collapse toward the dark end (0.5 ** 1.55 ≈ 0.34). Compute per-channel
        luminance scale: scale = new_lum / (lum + 1e-6), clamped to [0.05, 4.0].
        Apply to all channels. This makes the few pale passages read with
        heightened contrast against the surrounding compressed dark mass.
        NOVEL: (a) POWER-LAW LUMINANCE COMPRESSION TOWARD THE DARK HALF OF THE
        TONAL SCALE AS A CHARCOAL MEDIUM SIMULATION -- first pass to apply a
        power-law exponent > 1 to the luminance field to push the tonal
        distribution toward darkness, simulating charcoal's fundamental
        constraint that the paper surface provides the ceiling; no prior pass
        applies a direct luminance power-law for dark-range compression;
        paint_tonal_key_pass (s255) applies sigmoid remapping; no prior pass
        uses power-law lum ** dark_power for directional dark compression.

        Stage 2 DIRECTIONAL CHARCOAL SMEAR: Simulate the broad lateral sweep
        of the charcoal stick or the side of the hand along the gesture axis.
        Rotate the Stage 1 image by -smear_angle_deg degrees (scipy.ndimage
        .rotate, reshape=False, mode='reflect'). Apply an anisotropic Gaussian
        blur with sigma=(smear_sigma_along, smear_sigma_across): long sigma
        along the y-axis (which, in the rotated frame, aligns with the smear
        direction) and short sigma across the x-axis to preserve detail
        perpendicular to the stroke. Rotate back by +smear_angle_deg degrees.
        Blend with Stage 1 at smear_strength: result = (1 - smear_strength) *
        stage1 + smear_strength * smeared. The directionality creates the
        gestural sweep quality in Kollwitz's broad mid-tone marks.
        NOVEL: (b) ANGLE-PARAMETERISED ANISOTROPIC SMEAR VIA PAIRED IMAGE
        ROTATION WITH ASYMMETRIC GAUSSIAN -- first pass to implement a
        directional smear by rotating the canvas to align the smear axis with
        the filter's long axis (sigma_along >> sigma_across), applying the
        blur, then rotating back; no prior pass uses paired forward/back image
        rotation to achieve anisotropic directional smear at an arbitrary
        angle; wyeth_tempera_drybrush_pass (s255) uses asymmetric sigma in a
        fixed orientation without rotation.

        Stage 3 CHARCOAL HIGHLIGHT LIFT: In charcoal the brightest passages
        are produced by erasing, not by applying a light pigment. Simulate
        kneaded-eraser lifting at sparse random locations in the upper tonal
        zone. Using seeded RNG, generate a uniform random field; threshold at
        1 - lift_density to activate lift_density fraction of pixels.
        Apply Gaussian blur with sigma=lift_radius to create soft lift zones
        (the eraser removes charcoal from a small area, softening the boundary
        of the lifted spot). Weight the lift by how dark the pixel currently
        is: lift_amount = lift_strength * lift_field * (1 - new_lum), where
        new_lum is the current luminance from Stage 2; this ensures the lift
        is strongest where the charcoal is darkest and produces the smallest
        brightening where the paper is already near-white (no charcoal to
        remove). Add lift_amount to all channels.
        NOVEL: (c) SPARSE ERASER-LIFT ZONES WEIGHTED BY LOCAL DARKNESS AS
        CHARCOAL HIGHLIGHT SIMULATION -- first pass to generate sparse lifted-
        highlight zones (Gaussian-blurred sparse binary field) where the lift
        brightness is inversely proportional to the current luminance,
        simulating kneaded-eraser charcoal removal; no prior pass models the
        erasure process (darkness-weighted additive brightening from a sparse
        Gaussian-blurred field); wyeth_tempera_drybrush_pass (s255) stage 3
        uses a sparse field additively but in a tonal-transition zone for
        fiber traces, not as an eraser-lift simulation, and does not weight by
        (1 - lum); no prior pass simulates charcoal removal with a
        darkness-weighted sparse lift field.

        dark_power         : Power-law exponent (> 1 = compress toward dark).
        smear_angle_deg    : Smear direction in degrees (0 = horizontal).
        smear_sigma_along  : Gaussian sigma along smear axis (long blur).
        smear_sigma_across : Gaussian sigma across smear axis (short blur).
        smear_strength     : Blend fraction of smeared image (0=no smear).
        lift_density       : Fraction of pixels activated as lift zones.
        lift_radius        : Gaussian blur radius for lift zone softening.
        lift_strength      : Peak brightness added at lift zones.
        opacity            : Final composite opacity.
        seed               : RNG seed for reproducibility.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from scipy.ndimage import rotate as _rot

        print("    Kollwitz Charcoal Compression pass (session 256, 167th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        # Cairo BGRA order
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Stage 1: Dark tonal compression via power-law
        lum0 = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        new_lum1 = _np.power(_np.clip(lum0, 0.0, 1.0), float(dark_power)).astype(_np.float32)
        scale1 = _np.clip(new_lum1 / (lum0 + 1e-6), 0.05, 4.0).astype(_np.float32)
        r1 = _np.clip(r0 * scale1, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * scale1, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * scale1, 0.0, 1.0).astype(_np.float32)

        # Stage 2: Directional charcoal smear via rotation + asymmetric Gaussian
        ang = float(smear_angle_deg)
        sa  = float(smear_sigma_along)
        sc  = float(smear_sigma_across)

        def _smear_channel(ch):
            rotated  = _rot(ch, angle=-ang, reshape=False, mode='reflect',
                            order=1).astype(_np.float32)
            blurred  = _gf(rotated, sigma=(sa, sc)).astype(_np.float32)
            unrotated = _rot(blurred, angle=ang, reshape=False, mode='reflect',
                             order=1).astype(_np.float32)
            return _np.clip(unrotated, 0.0, 1.0)

        sm = float(smear_strength)
        r2 = _np.clip((1.0 - sm) * r1 + sm * _smear_channel(r1), 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip((1.0 - sm) * g1 + sm * _smear_channel(g1), 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip((1.0 - sm) * b1 + sm * _smear_channel(b1), 0.0, 1.0).astype(_np.float32)

        # Stage 3: Sparse eraser-lift zones weighted by local darkness
        rng = _np.random.default_rng(int(seed))
        sparse = (rng.uniform(0.0, 1.0, size=(h, w)) > (1.0 - float(lift_density))).astype(_np.float32)
        lift_field = _gf(sparse, sigma=float(lift_radius)).astype(_np.float32)
        if lift_field.max() > 1e-8:
            lift_field /= lift_field.max()

        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        lift_amount = float(lift_strength) * lift_field * (1.0 - lum2)
        r3 = _np.clip(r2 + lift_amount, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 + lift_amount, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 + lift_amount, 0.0, 1.0).astype(_np.float32)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        lifted_px = int((lift_field > 0.05).sum())
        print(f"    Kollwitz Charcoal complete (dark_power={dark_power:.2f}, "
              f"smear_angle={smear_angle_deg:.0f}°, "
              f"lift_zones={lifted_px}px)")

    def wyeth_tempera_drybrush_pass(
        self,
        chalk_amplitude:  float = 0.018,
        midtone_low:      float = 0.22,
        midtone_high:     float = 0.78,
        contrast_strength: float = 0.40,
        fiber_low_lum:    float = 0.15,
        fiber_high_lum:   float = 0.42,
        fiber_density:    float = 0.04,
        fiber_brightness: float = 0.08,
        opacity:          float = 0.78,
        seed:             int   = 255,
    ) -> None:
        r"""Andrew Wyeth Tempera Dry-Brush -- session 255, 166th distinct painting mode.

        THREE-STAGE EGG-TEMPERA DRY-SURFACE SIMULATION INSPIRED BY WYETH:

        Stage 1 DRY CHALK SURFACE: Generate seeded random noise with an
        asymmetric Gaussian blur applied to create a horizontally-biased grain
        direction. The noise is generated via numpy.random.default_rng(seed)
        .standard_normal((h, w)), then blurred with scipy.ndimage.gaussian_filter
        using sigma=(3.0, 0.5) -- a tall vertical sigma of 3.0 and narrow
        horizontal sigma of 0.5. This strongly elongates the noise in the
        vertical direction, creating horizontal grain that simulates the
        characteristic horizontal-stroke mark of egg tempera applied with a
        small flat brush across a gessoed panel. The noise is normalised to
        [-1, 1] and then added uniformly to all three channels at chalk_amplitude.
        Adding the same value to R, G, and B preserves the per-pixel hue while
        adding a luminance-domain grain. Values are clamped to [0, 1].
        NOVEL: (a) HORIZONTALLY-BIASED ASYMMETRIC GAUSSIAN NOISE IN THE
        LUMINANCE DOMAIN FOR EGG-TEMPERA CHALK SURFACE SIMULATION -- first
        pass to apply a seeded standard-normal noise field blurred with an
        asymmetric (tall-vertical) Gaussian to create horizontal grain
        direction, applied uniformly to all channels to preserve hue; no
        prior pass generates directional grain noise using asymmetric blur
        sigma for tempera surface simulation; paint_surface_tooth_pass (s252)
        uses a different surface texture mechanism; no prior pass applies
        horizontally-biased noise to simulate the directional chalky grain
        of egg tempera on gessoed panel.

        Stage 2 MIDTONE PRECISION BAND CONTRAST: Compute the luminance of the
        Stage 1 result. Compute a blurred luminance reference via
        gaussian_filter(lum, sigma=8.0). Compute the local contrast signal
        as the unsharp-mask residual: local_contrast = lum - lum_blurred.
        Compute a soft luminance band mask for the midtone region [midtone_low,
        midtone_high]: the mask ramps from 0 to 1 over the lower 0.15 lum
        above midtone_low, stays 1 in the interior, and ramps back from 1 to
        0 over the upper 0.15 lum below midtone_high. Apply the local contrast
        enhancement within the band: new_channel = channel + local_contrast *
        contrast_strength * band_mask. Values are clamped to [0, 1].
        This simulates Wyeth's extraordinary differentiation within midtone
        values, achieved through the discipline of egg tempera (which cannot
        be blended and requires each value to be mixed and placed precisely).
        NOVEL: (b) LUMINANCE-BAND-GATED UNSHARP-MASK LOCAL CONTRAST
        ENHANCEMENT TARGETING ONLY THE MIDTONE ZONE -- first pass to apply
        an unsharp-mask contrast residual (canvas - Gaussian_blur) gated by a
        soft luminance band mask that restricts enhancement to the midtone
        range [midtone_low, midtone_high]; meso_detail_pass and
        micro_detail_pass apply spatial detail enhancement globally; no prior
        pass uses a smooth luminance-band mask to confine local contrast
        enhancement to the midtone zone for simulating tempera tonal precision.

        Stage 3 DRY-BRUSH FIBER TRACES AT TONAL TRANSITIONS: Compute the
        luminance of the Stage 2 result. Identify tonal transition pixels
        in the dark-to-mid zone [fiber_low_lum, fiber_high_lum] using a soft
        tent mask (ramps over 0.10 lum at each edge). Generate a sparse binary
        noise field: random uniform values with threshold (1 - fiber_density)
        activate only fiber_density fraction of pixels. Apply a horizontal-only
        Gaussian blur with sigma=(0.0, 1.5) to the sparse field, creating
        horizontal fiber-like runs where isolated activated pixels smear into
        short horizontal traces. Apply this field at fiber_brightness as an
        additive brightness offset, masked by the tonal transition zone mask.
        This simulates the dry-brush watercolour technique: a near-pigment-
        starved brush dragged across rough cold-press paper catches only on the
        grain peaks, leaving bare paper visible between fibres. The effect is
        most visible at dark-to-mid tonal transitions where the brush lifts
        before completing its stroke.
        NOVEL: (c) HORIZONTALLY-BLURRED SPARSE NOISE FIELD APPLIED AS ADDITIVE
        FIBER-TRACE BRIGHTNESS IN TONAL TRANSITION ZONES -- first pass to
        generate a sparse activation field (fiber_density fraction active),
        blur it horizontally-only (sigma=(0, 1.5)) to create fiber-like runs,
        and apply it as an additive brightening within the dark-to-mid tonal
        transition zone [fiber_low_lum, fiber_high_lum]; no prior pass
        generates a sparse-then-horizontal-blur noise field for fiber-trace
        simulation; paint_scumble_pass deposits dry marks on texture peaks
        globally; no prior pass creates directional fiber traces restricted
        to tonal transition zones as a dry-brush paper-grain simulation.

        chalk_amplitude  : Amplitude of horizontal-grain noise (luminance domain).
        midtone_low      : Lower luminance bound of midtone precision band.
        midtone_high     : Upper luminance bound of midtone precision band.
        contrast_strength: Unsharp-mask contrast strength within the midtone band.
        fiber_low_lum    : Lower lum bound of tonal transition zone for fibers.
        fiber_high_lum   : Upper lum bound of tonal transition zone for fibers.
        fiber_density    : Fraction of pixels activated in sparse fiber field.
        fiber_brightness : Additive brightness amplitude of fiber traces.
        opacity          : Final composite opacity.
        seed             : RNG seed for reproducibility.
        """
        import numpy as _np

        print("    Wyeth Tempera Dry-Brush pass (session 255, 166th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        # Working in float32 [0,1] -- cairo BGRA order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        from scipy.ndimage import gaussian_filter as _gf

        # ── Stage 1: Dry chalk surface (horizontal-grain noise) ───────────
        rng = _np.random.default_rng(int(seed))
        noise = rng.standard_normal((h, w)).astype(_np.float32)
        # Asymmetric blur: sigma_y=3.0 elongates vertically -> horizontal grain
        noise_directional = _gf(noise, sigma=(3.0, 0.5)).astype(_np.float32)
        noise_max = float(_np.abs(noise_directional).max())
        if noise_max > 1e-6:
            noise_directional /= noise_max

        ca = float(chalk_amplitude)
        r1 = _np.clip(r0 + noise_directional * ca, 0.0, 1.0)
        g1 = _np.clip(g0 + noise_directional * ca, 0.0, 1.0)
        b1 = _np.clip(b0 + noise_directional * ca, 0.0, 1.0)

        # ── Stage 2: Midtone precision band contrast ───────────────────────
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        lum_blur = _gf(lum1, sigma=8.0).astype(_np.float32)
        local_contrast = (lum1 - lum_blur).astype(_np.float32)

        ml = float(midtone_low)
        mh = float(midtone_high)
        ramp = 0.15
        # Lower ramp: 0->1 from ml to ml+ramp
        lower_ramp = _np.clip((lum1 - ml) / (ramp + 1e-6), 0.0, 1.0)
        # Upper ramp: 1->0 from mh-ramp to mh
        upper_ramp = _np.clip((mh - lum1) / (ramp + 1e-6), 0.0, 1.0)
        band_mask = (lower_ramp * upper_ramp).astype(_np.float32)

        cs = float(contrast_strength)
        r2 = _np.clip(r1 + local_contrast * cs * band_mask, 0.0, 1.0)
        g2 = _np.clip(g1 + local_contrast * cs * band_mask, 0.0, 1.0)
        b2 = _np.clip(b1 + local_contrast * cs * band_mask, 0.0, 1.0)

        # ── Stage 3: Dry-brush fiber traces at tonal transitions ───────────
        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)

        fl = float(fiber_low_lum)
        fh = float(fiber_high_lum)
        fiber_ramp = 0.10
        fib_lower = _np.clip((lum2 - fl) / (fiber_ramp + 1e-6), 0.0, 1.0)
        fib_upper = _np.clip((fh - lum2) / (fiber_ramp + 1e-6), 0.0, 1.0)
        fiber_zone = (fib_lower * fib_upper).astype(_np.float32)

        # Sparse activation field with horizontal blur for fiber-like runs
        rng2 = _np.random.default_rng(int(seed) + 1)
        sparse = (rng2.uniform(0.0, 1.0, (h, w)) >
                  (1.0 - float(fiber_density))).astype(_np.float32)
        fiber_blurred = _gf(sparse, sigma=(0.0, 1.5)).astype(_np.float32)
        fib_max = float(fiber_blurred.max())
        if fib_max > 1e-6:
            fiber_blurred /= fib_max

        fb = float(fiber_brightness)
        fiber_add = fiber_blurred * fiber_zone * fb
        r3 = _np.clip(r2 + fiber_add, 0.0, 1.0)
        g3 = _np.clip(g2 + fiber_add, 0.0, 1.0)
        b3 = _np.clip(b2 + fiber_add, 0.0, 1.0)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        n_fiber = int((fiber_zone * fiber_blurred > 0.1).sum())
        print(f"    Wyeth Tempera Dry-Brush complete (fiber_pixels={n_fiber})")

    def paint_tonal_key_pass(
        self,
        target_key:       float = 0.50,
        key_strength:     float = 4.0,
        dither_amplitude: float = 0.006,
        opacity:          float = 0.65,
    ) -> None:
        r"""Tonal Key Correction with Micro-Dithering -- session 255 improvement pass.

        THREE-STAGE TONAL KEY MANAGEMENT INSPIRED BY THE PAINTER'S CONCEPT
        OF KEY (HIGH-KEY, MID-KEY, LOW-KEY):

        Addresses the fundamental painting concept of tonal key: whether a
        work is high-key (luminous, light-filled), low-key (somber, dark), or
        mid-key (balanced). Artists deliberately work in a key to create a
        unified emotional tone. The pipeline can drift toward arbitrary tonal
        distributions; this pass analyses the actual tonal distribution and
        applies a sigmoid remapping to correct or set the key, then adds
        micro-tonal dithering to prevent posterisation in compressed zones.

        Stage 1 LUMINANCE MEDIAN ANALYSIS: Compute the per-pixel luminance:
        lum = 0.299R + 0.587G + 0.114B. Compute the median luminance value
        (50th percentile across all h*w pixels) using numpy.median(lum). The
        median is the robust tonal center of mass of the painting -- where the
        bulk of pixels live tonally. Unlike the mean, the median is not dragged
        by extreme darks (a small black vignette) or extreme lights (a single
        bright highlight).
        NOVEL: (a) LUMINANCE MEDIAN ANALYSIS AS TONAL CENTER OF MASS FOR
        KEY CORRECTION -- first pass to compute the luminance median as the
        painting's tonal center of mass in order to drive a subsequent
        key correction; no prior pass computes a full-image luminance
        statistical measure to inform a tonal remapping; paint_glazing_pass
        applies a fixed-colour glaze; no prior pass measures the painting's
        current key and applies a targeted correction based on the measured
        tonal distribution.

        Stage 2 SIGMOID KEY CORRECTION: Compute per-pixel luminance deviation
        from the median: dev = lum - median_lum. Apply sigmoid key remapping:
        sigmoid_input = dev * key_strength + (target_key - 0.5) * key_strength;
        new_lum = 1 / (1 + exp(-sigmoid_input)); this maps the tonal
        distribution through a sigmoid function centred at target_key,
        compressing darks or lights depending on the target direction.
        Apply per-channel luminance scaling: scale = new_lum / (lum + 1e-6),
        clamped to [0.05, 20.0] to prevent extreme rescaling; final_channel =
        channel * scale clamped to [0, 1].
        NOVEL: (b) SIGMOID LUMINANCE REMAPPING DRIVEN BY MEASURED TONAL MEDIAN
        TO PUSH THE DISTRIBUTION TOWARD A USER-SPECIFIED KEY -- first pass to
        apply a sigmoid function to per-pixel luminance deviations from the
        computed median to correct the tonal key; no prior pass applies a
        sigmoid luminance remapping; paint_vignette_pass darkens edges;
        no prior pass uses a sigmoid of (dev * key_strength + key_offset) to
        push the tonal distribution toward a specified key value.

        Stage 3 MICRO-TONAL DITHERING WITH 4x4 BAYER MATRIX: Apply ordered
        dithering using a 4x4 Bayer threshold matrix to prevent posterisation
        artifacts in compressed tonal zones. The matrix values [0..15] are
        normalised to [-0.5, 0.5] and scaled by dither_amplitude. The matrix
        is tiled to canvas dimensions via numpy.tile. The same offset is added
        to all three channels (luminance-domain dithering), preserving hue
        while adding the micro-tonal variation needed to break banding in
        compressed tonal areas. dither_amplitude of 0.006 adds approximately
        ±1.5/255 tonal variation -- invisible in normal viewing but sufficient
        to break banding.
        NOVEL: (c) 4x4 BAYER MATRIX ORDERED DITHERING IN THE LUMINANCE DOMAIN
        AS A TONAL ANTI-POSTERISATION STEP -- first pass to apply a Bayer
        threshold matrix as ordered dithering to the canvas; no prior pass
        uses an ordered-dither pattern; paint_chromatic_aberration_pass
        introduces RGB channel displacement fringing; no prior pass applies
        a Bayer matrix to prevent banding in compressed tonal zones.

        target_key        : Target tonal key (0=low-key, 0.5=mid, 1.0=high-key).
        key_strength      : Sigmoid steepness controlling correction aggressiveness.
        dither_amplitude  : Peak amplitude of Bayer dither offset (0.006 = subtle).
        opacity           : Final composite opacity.
        """
        import numpy as _np

        print("    Tonal Key pass (session 255 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        # Stage 1: Luminance median analysis
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        median_lum = float(_np.median(lum))

        # Stage 2: Sigmoid key correction
        dev = (lum - median_lum).astype(_np.float64)
        tgt = float(target_key)
        ks  = float(key_strength)
        sigmoid_input = dev * ks + (tgt - 0.5) * ks
        new_lum = (1.0 / (1.0 + _np.exp(-sigmoid_input))).astype(_np.float32)

        eps = 1e-6
        scale = _np.clip(new_lum / (lum + eps), 0.05, 20.0).astype(_np.float32)
        r1 = _np.clip(r0 * scale, 0.0, 1.0)
        g1 = _np.clip(g0 * scale, 0.0, 1.0)
        b1 = _np.clip(b0 * scale, 0.0, 1.0)

        # Stage 3: Micro-tonal dithering with 4x4 Bayer matrix
        bayer4 = _np.array([
            [ 0,  8,  2, 10],
            [12,  4, 14,  6],
            [ 3, 11,  1,  9],
            [15,  7, 13,  5],
        ], dtype=_np.float32) / 16.0 - 0.5   # normalised to [-0.5, 0.5]

        tiles_y = h // 4 + 1
        tiles_x = w // 4 + 1
        bayer_full = _np.tile(bayer4, (tiles_y, tiles_x))[:h, :w]
        dither = bayer_full * float(dither_amplitude)

        r2 = _np.clip(r1 + dither, 0.0, 1.0)
        g2 = _np.clip(g1 + dither, 0.0, 1.0)
        b2 = _np.clip(b1 + dither, 0.0, 1.0)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        print(f"    Tonal Key complete (median_lum={median_lum:.3f}, "
              f"target_key={target_key:.2f})")

    def rego_flat_figure_pass(
        self,
        n_levels:         int   = 6,
        zone_blend:       float = 0.72,
        contour_threshold: float = 0.08,
        contour_strength: float = 0.58,
        contour_px:       int   = 2,
        outline_tone:     tuple = (0.16, 0.10, 0.08),
        tension_warm:     tuple = (0.72, 0.52, 0.32),
        tension_cool:     tuple = (0.44, 0.52, 0.66),
        tension_strength: float = 0.12,
        opacity:          float = 0.85,
        seed:             int   = 254,
    ) -> None:
        r"""Paula Rego Flat Figure -- session 254, 165th distinct painting mode.

        THREE-STAGE FLAT FIGURE POSTERISATION WITH CONTOUR WEIGHT:

        Stage 1 TONAL ZONE POSTERISATION: Quantise the canvas RGB colours into
        n_levels discrete tonal steps per channel using uniform quantisation:
        q = round(v * (n_levels - 1)) / (n_levels - 1). This produces the
        flat, posterised zones of colour characteristic of Rego's pastel work
        -- large areas of a single unmodulated tone. Then apply local zone-mean
        smoothing: for each quantised level, identify all pixels in that zone
        and replace each pixel with a blend of its original value and the zone
        mean colour at zone_blend fraction. This softens the hard digital
        posterisation toward the organic flatness of hand-applied pastel.
        NOVEL: (a) ZONE-MEAN-SMOOTHED POSTERISATION FOR FIGURATIVE FLATNESS --
        first pass to combine per-channel uniform quantisation with per-zone
        local mean blending as a two-step figurative colour flattening; the
        existing paint_posterize or split_toning passes apply global tone
        operations; no prior pass performs quantised zone identification
        followed by zone-mean colour replacement weighted by zone_blend.

        Stage 2 WARM CONTOUR OUTLINING: Compute the luminance image of the
        Stage 1 result. Apply finite-difference gradient magnitude to find
        edges. Pixels with gradient magnitude > contour_threshold are
        edge pixels. Dilate the edge mask by contour_px pixels (expand the
        contour band outward). Blend each edge pixel toward outline_tone at
        contour_strength. outline_tone is a warm dark (near-black brown) that
        gives Rego's figures their characteristic heavy, slightly warm boundary.
        NOVEL: (b) WARM-TONED DARKENING OF FIGURE CONTOURS WITH DILATION --
        first pass to apply warm-toned dark blending specifically at dilated
        gradient-edge pixels as a figurative contour simulation; distinct from
        paint_contour_weight_pass (s254 improvement, below) which applies
        variable-weight thickness scaling; no prior artist pass applies a
        warm-shifted dark tone to dilated edge pixels for contour darkening.

        Stage 3 CHROMATIC ZONE TENSION: Divide the canvas into four spatial
        quadrants. Assign each quadrant a role alternating figure/ground:
        upper-left=ground, upper-right=figure, lower-left=figure,
        lower-right=ground (Rego's typical compositional diagonal). Apply a
        slight warm push (blend tension_strength toward tension_warm) to
        figure-quadrant pixels, and a slight cool push (blend tension_strength
        toward tension_cool) to ground-quadrant pixels. This creates the
        specific warm-figure / cool-ground chromatic tension of Rego's
        compositions without global colour shifting.
        NOVEL: (c) QUADRANT-INDEXED WARM/COOL CHROMATIC TENSION AS SPATIAL
        FIGURE-GROUND SEPARATION -- first pass to apply alternating warm/cool
        chromatic pushes indexed by spatial quadrant position as a figurative
        composition technique; paint_warm_cool_separation_pass (s251) applies
        a global luminance-threshold warm/cool split; no prior pass assigns
        warm/cool roles by spatial quadrant index as a compositional device.

        n_levels          : Number of discrete tonal levels per channel.
        zone_blend        : Blend fraction toward zone mean colour (flatness).
        contour_threshold : Gradient magnitude threshold for contour detection.
        contour_strength  : Blend fraction toward outline_tone at contours.
        contour_px        : Dilation radius for contour band in pixels.
        outline_tone      : Warm dark RGB for contour darkening.
        tension_warm      : RGB target for figure-zone chromatic warmth.
        tension_cool      : RGB target for ground-zone chromatic coolness.
        tension_strength  : Blend fraction for warm/cool zone tension.
        opacity           : Final composite opacity.
        seed              : RNG seed (reserved for future stochastic stages).
        """
        import numpy as _np

        print("    Rego Flat Figure pass (session 254, 165th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        # Working in float32 [0,1] -- cairo BGRA order
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0

        # ── Stage 1: Tonal zone posterisation with zone-mean smoothing ─────
        nl = float(n_levels - 1) if n_levels > 1 else 1.0

        # Per-channel quantisation
        r_q = _np.round(r0 * nl) / nl
        g_q = _np.round(g0 * nl) / nl
        b_q = _np.round(b0 * nl) / nl

        # Zone-mean smoothing: for each quantised level, average original
        # colours of all pixels in that level and blend toward the mean
        r1 = r_q.copy()
        g1 = g_q.copy()
        b1 = b_q.copy()

        for li in range(int(n_levels)):
            lv = float(li) / nl
            # Tolerance window for level membership
            tol = 0.5 / nl + 1e-6
            mask = (_np.abs(r_q - lv) < tol) | (_np.abs(g_q - lv) < tol) |                    (_np.abs(b_q - lv) < tol)
            if mask.sum() == 0:
                continue
            # Zone mean of original colours
            mr = float(r0[mask].mean())
            mg = float(g0[mask].mean())
            mb = float(b0[mask].mean())
            zb = float(zone_blend)
            r1[mask] = r_q[mask] * (1.0 - zb) + mr * zb
            g1[mask] = g_q[mask] * (1.0 - zb) + mg * zb
            b1[mask] = b_q[mask] * (1.0 - zb) + mb * zb

        # ── Stage 2: Warm contour outlining ───────────────────────────────
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1)

        # Gradient magnitude
        gx = _np.zeros_like(lum1)
        gx[:, 1:-1] = lum1[:, 2:] - lum1[:, :-2]
        gx[:, 0] = lum1[:, 1] - lum1[:, 0]
        gx[:, -1] = lum1[:, -1] - lum1[:, -2]
        gy = _np.zeros_like(lum1)
        gy[1:-1, :] = lum1[2:, :] - lum1[:-2, :]
        gy[0, :] = lum1[1, :] - lum1[0, :]
        gy[-1, :] = lum1[-1, :] - lum1[-2, :]
        grad = _np.sqrt(gx ** 2 + gy ** 2).astype(_np.float32)

        edge_mask = (grad > float(contour_threshold)).astype(_np.float32)

        # Dilate edge mask by contour_px pixels using max-pooling
        if int(contour_px) > 0:
            from scipy.ndimage import maximum_filter as _maxf
            size = 2 * int(contour_px) + 1
            edge_mask = _maxf(edge_mask, size=size).astype(_np.float32)

        ot_r, ot_g, ot_b = float(outline_tone[0]), float(outline_tone[1]), float(outline_tone[2])
        cs = float(contour_strength)

        r2 = r1 * (1.0 - edge_mask * cs) + ot_r * (edge_mask * cs)
        g2 = g1 * (1.0 - edge_mask * cs) + ot_g * (edge_mask * cs)
        b2 = b1 * (1.0 - edge_mask * cs) + ot_b * (edge_mask * cs)

        # ── Stage 3: Chromatic zone tension ───────────────────────────────
        # Quadrant map: figure=(upper-right, lower-left), ground=(upper-left, lower-right)
        cy, cx = h // 2, w // 2
        figure_mask = _np.zeros((h, w), dtype=_np.float32)
        figure_mask[:cy, cx:] = 1.0   # upper-right = figure
        figure_mask[cy:, :cx] = 1.0   # lower-left  = figure
        ground_mask = 1.0 - figure_mask

        tw_r, tw_g, tw_b = float(tension_warm[0]), float(tension_warm[1]), float(tension_warm[2])
        tc_r, tc_g, tc_b = float(tension_cool[0]), float(tension_cool[1]), float(tension_cool[2])
        ts = float(tension_strength)

        # Warm push on figure zones
        r3 = r2 + figure_mask * ts * (tw_r - r2)
        g3 = g2 + figure_mask * ts * (tw_g - g2)
        b3 = b2 + figure_mask * ts * (tw_b - b2)
        # Cool push on ground zones
        r3 = r3 + ground_mask * ts * (tc_r - r3)
        g3 = g3 + ground_mask * ts * (tc_g - g3)
        b3 = b3 + ground_mask * ts * (tc_b - b3)

        r3 = _np.clip(r3, 0.0, 1.0)
        g3 = _np.clip(g3, 0.0, 1.0)
        b3 = _np.clip(b3, 0.0, 1.0)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        contour_px_count = int((edge_mask > 0.5).sum())
        print(f"    Rego Flat Figure complete (contour_pixels={contour_px_count})")

    def paint_contour_weight_pass(
        self,
        contour_threshold: float = 0.06,
        max_weight:       float = 0.55,
        weight_exponent:  float = 1.4,
        outline_tone:     tuple = (0.12, 0.08, 0.06),
        junction_boost:   float = 0.22,
        taper_strength:   float = 0.38,
        opacity:          float = 0.72,
    ) -> None:
        r"""Variable-Weight Contour Drawing -- session 254 improvement pass.

        THREE-STAGE CONTOUR WEIGHTING INSPIRED BY FIGURATIVE DRAWING:

        Simulates the variable-weight contour line used by figurative draughts-
        persons: lines are heaviest at junctions and corners (where directions
        change most), and taper toward their ends. Applies the contour to the
        existing painted surface as a darkening layer.

        Stage 1 EDGE GRADIENT FIELD: Compute the luminance image. Apply
        finite-difference horizontal (Gx) and vertical (Gy) gradients. Compute
        gradient magnitude M = sqrt(Gx^2 + Gy^2) and gradient direction
        theta = atan2(Gy, Gx). Threshold M at contour_threshold to produce
        a binary edge map. Scale the sub-threshold edge values to [0, 1]
        representing local edge strength.
        NOVEL: (a) GRADIENT FIELD WITH DIRECTION MAP FOR VARIABLE-WEIGHT
        CONTOUR -- first pass to compute both magnitude AND direction of the
        gradient field simultaneously, retaining both for use in junction
        detection and taper computation; paint_lost_found_edges_pass modifies
        edge softness from a magnitude image only; no prior pass retains the
        gradient direction to inform the weight at each contour pixel.

        Stage 2 JUNCTION DETECTION AND WEIGHT BOOST: For each edge pixel,
        compute the local variation in gradient direction over a 3x3 window
        (angular variance). High angular variance indicates a corner or
        junction (where multiple edges meet). Apply a junction_boost additive
        to the edge weight at these high-variance pixels, clamped to 1.0.
        This gives the characteristic heaviness at corners and junctions of
        a skilled draughtsman's contour line.
        NOVEL: (b) ANGULAR VARIANCE JUNCTION DETECTION FOR CONTOUR WEIGHTING
        -- first pass to compute local angular variance of gradient direction
        as a junction/corner detector, and to use the resulting junction map
        additively on the contour weight; no prior pass uses gradient direction
        angular variance to detect corners for the purpose of modulating
        contour darkness.

        Stage 3 TAPER TOWARD ENDPOINTS AND DARKENING APPLICATION: Apply the
        final contour weight as a power-law scaling: final_weight = edge_weight
        ^ weight_exponent * max_weight. Blend each edge pixel toward
        outline_tone at final_weight (multiplicative darkening plus warm tone
        shift). taper_strength reduces the contour weight at pixels with
        low local edge connectivity (isolated edge pixels = endpoints): compute
        the number of edge neighbours in a 3x3 window; pixels with fewer than
        2 neighbours are endpoints and receive weight multiplied by
        (1 - taper_strength). This produces tapered stroke ends.
        NOVEL: (c) POWER-LAW CONTOUR WEIGHT WITH NEIGHBOUR-COUNT TAPER --
        first pass to apply power-law darkening weight to contour pixels and
        to reduce contour weight at low-connectivity endpoint pixels using a
        3x3 neighbour count; no prior pass combines gradient-magnitude-derived
        contour weight with endpoint taper suppression for variable-thickness
        figurative contour simulation.

        contour_threshold : Gradient magnitude threshold for edge detection.
        max_weight        : Maximum blend fraction toward outline_tone.
        weight_exponent   : Power-law exponent for contour weight scaling.
        outline_tone      : Dark warm RGB for contour darkening.
        junction_boost    : Additive weight increase at junction pixels.
        taper_strength    : Weight reduction at endpoint/isolated edge pixels.
        opacity           : Final composite opacity (0=no change, 1=full).
        """
        import numpy as _np

        print("    Contour Weight pass (session 254 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0)

        # Stage 1: Gradient field (magnitude + direction)
        gx = _np.zeros_like(lum)
        gx[:, 1:-1] = lum[:, 2:] - lum[:, :-2]
        gx[:, 0] = lum[:, 1] - lum[:, 0]
        gx[:, -1] = lum[:, -1] - lum[:, -2]
        gy = _np.zeros_like(lum)
        gy[1:-1, :] = lum[2:, :] - lum[:-2, :]
        gy[0, :] = lum[1, :] - lum[0, :]
        gy[-1, :] = lum[-1, :] - lum[-2, :]

        grad_mag = _np.sqrt(gx ** 2 + gy ** 2).astype(_np.float32)
        grad_dir = _np.arctan2(gy, gx).astype(_np.float32)   # [-pi, pi]

        thresh = float(contour_threshold)
        # Edge weight in [0, 1] above threshold.
        # Use max(max-thresh, 0)+eps to avoid negative denominator on flat canvases.
        _denom = float(_np.maximum(grad_mag.max() - thresh, 0.0)) + 1e-6
        edge_weight = _np.clip((grad_mag - thresh) / _denom, 0.0, 1.0)
        edge_mask = (grad_mag > thresh).astype(_np.float32)

        # Stage 2: Junction detection via local angular variance
        # Compute local circular variance of gradient direction in 3x3 window
        sin_dir = _np.sin(grad_dir)
        cos_dir = _np.cos(grad_dir)
        # Local mean direction components via box filter
        from scipy.ndimage import uniform_filter as _uf
        sin_mean = _uf(sin_dir, size=3)
        cos_mean = _uf(cos_dir, size=3)
        # Circular variance in [0, 1]: 0=uniform direction, 1=highly variable
        circ_var = 1.0 - _np.sqrt(sin_mean ** 2 + cos_mean ** 2).astype(_np.float32)
        # Junction pixels: high direction variance on edges
        junction_map = (circ_var * edge_mask).astype(_np.float32)
        # Add junction boost to edge weight
        edge_weight = _np.clip(edge_weight + junction_map * float(junction_boost),
                               0.0, 1.0)

        # Stage 3: Taper at endpoints and apply darkening
        # Count edge neighbours in 3x3 window
        neighbour_sum = _uf(edge_mask, size=3) * 9.0 - edge_mask
        # Endpoint: fewer than 2 neighbours
        endpoint_mask = ((neighbour_sum < 2.0) & (edge_mask > 0.5)).astype(_np.float32)
        edge_weight = edge_weight * (1.0 - endpoint_mask * float(taper_strength))

        # Apply power-law weight scaling
        exp = float(weight_exponent)
        mw = float(max_weight)
        final_w = _np.clip(edge_weight ** exp * mw, 0.0, 1.0)

        # Darken toward outline_tone
        ot_r, ot_g, ot_b = float(outline_tone[0]), float(outline_tone[1]), float(outline_tone[2])
        r1 = r0 * (1.0 - final_w) + ot_r * final_w
        g1 = g0 * (1.0 - final_w) + ot_g * final_w
        b1 = b0 * (1.0 - final_w) + ot_b * final_w

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        n_edge = int((edge_mask > 0.5).sum())
        n_junction = int((junction_map > 0.3).sum())
        print(f"    Contour Weight complete (edge_pixels={n_edge}, "
              f"junction_pixels={n_junction})")

    def kiefer_scorched_earth_pass(
        self,
        n_zones:        int   = 8,
        ash_tone:       tuple = (0.28, 0.26, 0.24),
        max_ash_blend:  float = 0.68,
        dark_push:      float = 0.14,
        n_cracks:       int   = 18,
        crack_width:    int   = 3,
        crack_depth:    float = 0.38,
        crack_tone:     tuple = (0.14, 0.12, 0.10),
        lum_ceiling:    float = 0.60,
        straw_angle:    float = 15.0,
        straw_period:   int   = 9,
        fiber_strength: float = 0.38,
        straw_lo:       float = 0.30,
        straw_hi:       float = 0.65,
        straw_color:    tuple = (0.76, 0.68, 0.28),
        opacity:        float = 0.82,
        seed:           int   = 253,
    ) -> None:
        r"""Anselm Kiefer Scorched Earth -- session 253, 164th distinct painting mode.

        THREE-STAGE SCORCHED FIELD WITH STRAW AND LEAD:

        Stage 1 ASHEN FIELD DESATURATION GRADIENT: Divide the canvas into
        n_zones equal horizontal depth strips (foreground=bottom to
        background=top). For each zone compute a fractional blend weight
        zone_frac = (zone_index / n_zones) * max_ash_blend, representing the
        increasing ashen haze toward the horizon. Convert each pixel to HSV;
        blend the pixel colour toward ash_tone at zone_frac. Additionally gate
        the blend by pixel luminance: dark pixels (lum < 0.35) receive an extra
        darkening push of dark_push toward near-black (charred zone); mid-tone
        pixels (0.35 ≤ lum < 0.65) receive full ash blend (scorched field);
        light pixels (lum ≥ 0.65) receive half blend (unburned edge glint).
        NOVEL: (a) ZONE-PARTITIONED LUMINANCE-GATED SIMULTANEOUS DESATURATION
        AND DARKENING IN DEPTH GRADIENT -- first pass to apply zone-indexed
        horizontal strip desaturation that simultaneously pushes dark pixels
        toward charcoal and mid-tones toward ash while preserving light-pixel
        chroma, parameterised by depth position (foreground to horizon); no
        prior depth-gradient pass (paint_aerial_perspective_pass uses colour
        shift by global y-coordinate without luminance gating; paint_glaze_
        gradient_pass applies a unitary glaze colour without zone partitioning
        or luminance-gated differential treatment).

        Stage 2 LEAD SHEET CRACK VEINING: Generate n_cracks sinusoidal crack
        trajectories. Each crack: amplitude A = rng.uniform(4, 28) pixels,
        frequency f = rng.uniform(0.005, 0.020) cycles/pixel, phase phi =
        rng.uniform(0, 2π), origin y_origin = rng.uniform(0.1, 0.9) * h.
        For each x in [0, w): crack_y = y_origin + A * sin(2π * f * x + phi).
        For pixels within crack_width of crack_y AND with pixel lum < lum_ceiling,
        blend the pixel colour toward crack_tone at crack_depth.
        NOVEL: (b) SINUSOIDAL DIRECTIONAL VEIN NETWORK WITH LUMINANCE-GATED
        DISCONTINUITY -- first pass to generate crack-path veinings as
        composites of sinusoidal directional trajectories with per-pixel
        luminance gating (cracks only appear on dark/mid-tone surfaces, not
        on light areas); the crackle pass in ArtStyle uses a boolean crackle
        flag applied elsewhere as isotropic Voronoi noise; no prior stroke_engine
        pass draws structured sinusoidal directional vein paths with luminance-
        threshold discontinuity.

        Stage 3 STRAW FIBER WARM OVERLAY: Compute a tilted sinusoidal fiber
        texture oriented at straw_angle degrees from horizontal (representing
        Kiefer's embedded straw at the characteristic ~15° ploughed-furrow
        angle). For each pixel (x, y): compute the fiber coordinate along
        the rotated axis: u = x * cos(θ) + y * sin(θ), where θ = straw_angle
        in radians. fiber = 0.5 + 0.5 * sin(2π * u / straw_period). Gate the
        overlay on pixel luminance: apply only where straw_lo ≤ lum ≤ straw_hi
        (Kiefer's straw rests on mid-tone surfaces, not in deep shadow or
        highlight). Blend fiber_strength of straw_color into the mid-lum pixels
        at each fiber peak (fiber > 0.55).
        NOVEL: (c) ROTATED SINGLE-DIRECTION CHROMATIC SINUSOIDAL FIBER TEXTURE
        GATED ON MID-LUMINANCE -- first pass to apply a tilted (non-orthogonal)
        single-direction sinusoidal fiber grid with warm chromatic coloring
        (straw gold) exclusively at mid-luminance pixels; paint_surface_tooth_pass
        (s252) uses an orthogonal H×V product for achromatic canvas texture;
        no prior pass applies a rotated single-axis sinusoidal fiber with
        chromatic hue blending gated on a mid-luminance band.

        n_zones        : Number of horizontal depth zones for ash gradient.
        ash_tone       : Target RGB colour for ashen blending (charcoal grey).
        max_ash_blend  : Maximum blend fraction at the topmost (horizon) zone.
        dark_push      : Extra luminance reduction for dark pixels in each zone.
        n_cracks       : Number of sinusoidal lead-crack trajectories.
        crack_width    : Pixel half-width of each crack vein.
        crack_depth    : Blend fraction toward crack_tone at crack centres.
        crack_tone     : Target RGB colour for crack darkening (near-black).
        lum_ceiling    : Luminance threshold above which cracks are suppressed.
        straw_angle    : Fiber direction in degrees from horizontal (0=horiz).
        straw_period   : Fiber repeat period in pixels.
        fiber_strength : Blend fraction of straw_color at fiber peaks.
        straw_lo       : Lower luminance bound for straw overlay zone.
        straw_hi       : Upper luminance bound for straw overlay zone.
        straw_color    : Warm straw-gold RGB for fiber overlay.
        opacity        : Final composite opacity.
        seed           : RNG seed for reproducible crack layout.
        """
        import numpy as _np

        print("    Kiefer Scorched Earth pass (session 253, 164th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        rng = _np.random.default_rng(seed)

        # Working in float32 [0,1]
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        lum0 = (0.299 * r0 + 0.587 * g0 + 0.114 * b0)

        # Stage 1: Ashen field desaturation gradient
        ar, ag, ab = float(ash_tone[0]), float(ash_tone[1]), float(ash_tone[2])
        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()

        zone_h = h / float(n_zones)
        for zi in range(n_zones):
            # Zone 0 = bottom (foreground), zone n_zones-1 = top (horizon)
            # Flip so horizon gets max blend: high zi = higher y? No:
            # y=0 is top (sky/horizon), y=h-1 is bottom (foreground).
            # We want top zones (small y) to be more ashen.
            y_top = int(zi * zone_h)
            y_bot = int((zi + 1) * zone_h)
            y_bot = min(y_bot, h)
            # Zone fraction: 0 at bottom (foreground), 1 at top (horizon)
            denom = float(max(n_zones - 1, 1))
            zone_frac = (float(n_zones - 1 - zi) / denom) * float(max_ash_blend)

            lum_z = lum0[y_top:y_bot, :]
            r_z = r0[y_top:y_bot, :]
            g_z = g0[y_top:y_bot, :]
            b_z = b0[y_top:y_bot, :]

            # Luminance-gated blend weights
            dark_mask   = (lum_z < 0.35).astype(_np.float32)
            mid_mask    = ((lum_z >= 0.35) & (lum_z < 0.65)).astype(_np.float32)
            light_mask  = (lum_z >= 0.65).astype(_np.float32)

            w_dark  = zone_frac * dark_mask
            w_mid   = zone_frac * mid_mask
            w_light = zone_frac * 0.5 * light_mask

            blend = w_dark + w_mid + w_light

            # Blend toward ash
            r1[y_top:y_bot, :] = r_z * (1.0 - blend) + ar * blend
            g1[y_top:y_bot, :] = g_z * (1.0 - blend) + ag * blend
            b1[y_top:y_bot, :] = b_z * (1.0 - blend) + ab * blend

            # Extra dark push for dark pixels
            dp = float(dark_push) * dark_mask * zone_frac
            r1[y_top:y_bot, :] = _np.clip(r1[y_top:y_bot, :] - dp, 0.0, 1.0)
            g1[y_top:y_bot, :] = _np.clip(g1[y_top:y_bot, :] - dp, 0.0, 1.0)
            b1[y_top:y_bot, :] = _np.clip(b1[y_top:y_bot, :] - dp, 0.0, 1.0)

        # Stage 2: Lead sheet crack veining
        r2 = r1.copy()
        g2 = g1.copy()
        b2 = b1.copy()
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1)
        cr, cg, cb = float(crack_tone[0]), float(crack_tone[1]), float(crack_tone[2])
        cd = float(crack_depth)
        lc = float(lum_ceiling)
        cw = int(crack_width)

        xs = _np.arange(w, dtype=_np.float32)

        for _ in range(int(n_cracks)):
            amp   = float(rng.uniform(4.0, 28.0))
            freq  = float(rng.uniform(0.005, 0.020))
            phase = float(rng.uniform(0.0, 2.0 * _np.pi))
            y_orig = float(rng.uniform(0.1, 0.9)) * h

            # Crack y-coordinate per x
            crack_ys = y_orig + amp * _np.sin(2.0 * _np.pi * freq * xs + phase)
            crack_ys = _np.clip(_np.round(crack_ys).astype(_np.int32), 0, h - 1)

            for dy in range(-cw, cw + 1):
                ys_idx = _np.clip(crack_ys + dy, 0, h - 1)
                # Luminance gate: only darken dark/mid pixels
                lum_vals = lum1[ys_idx, xs.astype(_np.int32)]
                mask = (lum_vals < lc).astype(_np.float32)

                # Blend strength falls off with distance from crack centre
                dist_frac = 1.0 - abs(dy) / float(cw + 1)
                blend_c = cd * dist_frac * mask

                cols = xs.astype(_np.int32)
                r2[ys_idx, cols] = r2[ys_idx, cols] * (1.0 - blend_c) + cr * blend_c
                g2[ys_idx, cols] = g2[ys_idx, cols] * (1.0 - blend_c) + cg * blend_c
                b2[ys_idx, cols] = b2[ys_idx, cols] * (1.0 - blend_c) + cb * blend_c

        # Stage 3: Straw fiber warm overlay
        r3 = r2.copy()
        g3 = g2.copy()
        b3 = b2.copy()
        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2)

        theta = float(straw_angle) * _np.pi / 180.0
        cos_t = float(_np.cos(theta))
        sin_t = float(_np.sin(theta))
        sp = float(straw_period)
        fs = float(fiber_strength)
        sr, sg, sb = float(straw_color[0]), float(straw_color[1]), float(straw_color[2])
        s_lo, s_hi = float(straw_lo), float(straw_hi)

        # Coordinate grids
        ys_grid, xs_grid = _np.mgrid[0:h, 0:w]
        u = xs_grid * cos_t + ys_grid * sin_t
        fiber = (0.5 + 0.5 * _np.sin(2.0 * _np.pi * u / sp)).astype(_np.float32)

        # Mask: mid-luminance AND fiber peak
        mid_lum_mask = ((lum2 >= s_lo) & (lum2 <= s_hi)).astype(_np.float32)
        fiber_peak   = (fiber > 0.55).astype(_np.float32)
        straw_mask   = mid_lum_mask * fiber_peak * fs

        r3 = _np.clip(r2 * (1.0 - straw_mask) + sr * straw_mask, 0.0, 1.0)
        g3 = _np.clip(g2 * (1.0 - straw_mask) + sg * straw_mask, 0.0, 1.0)
        b3 = _np.clip(b2 * (1.0 - straw_mask) + sb * straw_mask, 0.0, 1.0)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        straw_pixels = int((straw_mask > 0).sum())
        crack_coverage = float((r3 < r2 - 0.01).mean())
        print(f"    Scorched Earth complete (straw_pixels={straw_pixels}, "
              f"crack_coverage={crack_coverage:.4f})")

    def paint_impasto_ridge_cast_pass(
        self,
        edge_sensitivity: float = 0.55,
        shadow_offset:    int   = 4,
        shadow_strength:  float = 0.28,
        highlight_strength: float = 0.12,
        light_angle:      float = 135.0,
        ridge_threshold:  float = 0.08,
        opacity:          float = 0.75,
    ) -> None:
        r"""Impasto Ridge Cast Shadows -- session 253 improvement pass.

        THREE-STAGE IMPASTO DEPTH SIMULATION:

        Simulates the three-dimensional quality of thick impasto paint by
        detecting luminance-gradient ridge edges (where paint has been applied
        thickly) and synthesizing cast micro-shadows and catch-light highlights
        from those ridges based on a configurable light direction.

        Stage 1 RIDGE DETECTION: Compute the luminance image and apply a
        Sobel-like edge detection using horizontal and vertical finite
        differences. Compute gradient magnitude = sqrt(Gx^2 + Gy^2).
        Threshold at ridge_threshold * edge_sensitivity to isolate strong
        ridges that represent thick impasto edges. Scale ridge map to [0,1].
        NOVEL: (a) SOBEL-MAGNITUDE RIDGE MAP FOR IMPASTO DEPTH -- first pass
        to compute a Sobel-derived gradient magnitude map for the explicit
        purpose of identifying thick impasto ridges; no prior pass uses a
        gradient magnitude image as the source map for shadow and highlight
        synthesis (paint_lost_found_edges_pass modifies edge softness but does
        not synthesise 3D cast shadows from those edges; paint_aerial_perspective
        uses global-y luminance shifts rather than local edge topology).

        Stage 2 SHADOW CASTING: Compute the anti-light direction from
        light_angle (degrees from top, clockwise): shadow_dx = sin(angle),
        shadow_dy = cos(angle) (downward in image coords). For each pixel
        with ridge_map > ridge_threshold: write a darkening offset at
        (x + shadow_dx * shadow_offset, y + shadow_dy * shadow_offset),
        proportional to ridge_map * shadow_strength. Accumulate shadow
        contributions across all ridge pixels into a shadow buffer; apply
        shadow buffer as multiplicative darkening: pixel *= (1 - shadow_buf).
        NOVEL: (b) DIRECTIONAL SHADOW CAST FROM RIDGE TOPOLOGY -- first pass
        to compute directional cast-shadow displacement from a ridge map
        (pushing shadow pixels in the anti-light direction by shadow_offset
        pixels with ridge-proportional intensity); paint_sfumato_focus_pass
        and paint_split_toning apply global or region luminance shifts -- none
        displace a shadow specifically from detected ridge positions.

        Stage 3 HIGHLIGHT LEADING EDGE: Compute the light-facing direction
        opposite to the shadow: highlight_dx = -shadow_dx, highlight_dy =
        -shadow_dy. For each ridge pixel, write a brightening at
        (x + highlight_dx, y + highlight_dy) proportional to
        ridge_map * highlight_strength. Apply as additive luminance boost
        (clamped to 1.0). This creates the catch-light that makes impasto
        physically three-dimensional -- the bright edge where the paint ridge
        faces the light source.
        NOVEL: (c) CATCH-LIGHT HIGHLIGHT ON LIGHT-FACING RIDGE EDGE --
        first pass to apply an additive luminance highlight displaced in the
        light-facing direction from each ridge pixel; the highlight is paired
        with the shadow displacement as a complete light-source simulation from
        physical surface topology; paint_glaze_gradient_pass and paint_halation
        apply global luminance increases -- none compute per-ridge catch-lights
        at positions offset by the ridge-normal vs. light-direction projection.

        edge_sensitivity  : Multiplier for gradient threshold (higher = fewer ridges).
        shadow_offset     : Pixel distance of shadow cast in anti-light direction.
        shadow_strength   : Darkening magnitude at shadow centre (0–1).
        highlight_strength: Brightening magnitude at catch-light (0–1).
        light_angle       : Light source angle in degrees, clockwise from top.
        ridge_threshold   : Gradient magnitude threshold for ridge detection.
        opacity           : Final composite opacity (0=no change, 1=full effect).
        """
        import numpy as _np

        print("    Impasto Ridge Cast pass (session 253 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        r0 = orig[:, :, 2].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0)

        # Stage 1: Ridge detection via finite-difference gradient magnitude
        # Horizontal gradient
        gx = _np.zeros_like(lum)
        gx[:, 1:-1] = lum[:, 2:] - lum[:, :-2]
        gx[:, 0] = lum[:, 1] - lum[:, 0]
        gx[:, -1] = lum[:, -1] - lum[:, -2]
        # Vertical gradient
        gy = _np.zeros_like(lum)
        gy[1:-1, :] = lum[2:, :] - lum[:-2, :]
        gy[0, :] = lum[1, :] - lum[0, :]
        gy[-1, :] = lum[-1, :] - lum[-2, :]

        grad_mag = _np.sqrt(gx ** 2 + gy ** 2).astype(_np.float32)
        thresh = float(ridge_threshold) * float(edge_sensitivity)
        ridge_map = _np.clip((grad_mag - thresh) / (1.0 - thresh + 1e-6), 0.0, 1.0)

        # Stage 2: Shadow casting
        ang_rad = float(light_angle) * _np.pi / 180.0
        # Anti-light direction (shadow falls away from light)
        sdx = int(round(float(_np.sin(ang_rad)) * float(shadow_offset)))
        sdy = int(round(float(_np.cos(ang_rad)) * float(shadow_offset)))

        shadow_buf = _np.zeros((h, w), dtype=_np.float32)
        src_y, src_x = _np.mgrid[0:h, 0:w]
        dst_y = _np.clip(src_y + sdy, 0, h - 1)
        dst_x = _np.clip(src_x + sdx, 0, w - 1)
        _np.add.at(shadow_buf, (dst_y, dst_x), ridge_map * float(shadow_strength))
        shadow_buf = _np.clip(shadow_buf, 0.0, 1.0)

        r1 = _np.clip(r0 * (1.0 - shadow_buf), 0.0, 1.0)
        g1 = _np.clip(g0 * (1.0 - shadow_buf), 0.0, 1.0)
        b1 = _np.clip(b0 * (1.0 - shadow_buf), 0.0, 1.0)

        # Stage 3: Highlight on light-facing ridge edge
        hdx = -sdx
        hdy = -sdy
        hl_buf = _np.zeros((h, w), dtype=_np.float32)
        dst_hy = _np.clip(src_y + hdy, 0, h - 1)
        dst_hx = _np.clip(src_x + hdx, 0, w - 1)
        _np.add.at(hl_buf, (dst_hy, dst_hx), ridge_map * float(highlight_strength))
        hl_buf = _np.clip(hl_buf, 0.0, 1.0)

        r2 = _np.clip(r1 + hl_buf, 0.0, 1.0)
        g2 = _np.clip(g1 + hl_buf, 0.0, 1.0)
        b2 = _np.clip(b1 + hl_buf, 0.0, 1.0)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        n_ridge = int((ridge_map > 0.05).sum())
        shadow_cov = float((shadow_buf > 0.01).mean())
        print(f"    Impasto Ridge Cast complete (ridge_pixels={n_ridge}, "
              f"shadow_coverage={shadow_cov:.4f})")

    def paint_surface_tooth_pass(
        self,
        grain_size:        int   = 12,
        fiber_amplitude:   float = 0.030,
        cross_boost:       float = 0.018,
        light_angle:       float = 42.0,
        ridge_strength:    float = 0.025,
        opacity:           float = 0.72,
        seed:              int   = 4252,
    ) -> None:
        r"""Canvas Surface Tooth -- session 252 improvement pass.

        THREE-STAGE CANVAS SURFACE TOOTH:

        Simulates the physical texture of a woven linen or cotton canvas --
        the raised warp-and-weft fiber grid that gives painted surfaces their
        characteristic tactile quality.

        Stage 1 WOVEN FIBER PATTERN: Generate a dual-direction periodic
        fiber texture using two sinusoidal grids:
          H_fiber(x, y) = sin(2π * y / grain_size + noise_y[x,y])
          V_fiber(x, y) = sin(2π * x / grain_size + noise_x[x,y])
        Combine: fiber_map = H_fiber * V_fiber (product gives crossing peaks)
        Add fiber_amplitude * fiber_map to luminance channel.
        NOVEL: (a) DUAL-DIRECTION WARP-AND-WEFT SINUSOIDAL FIBER PRODUCT --
        first pass to generate a simulated woven fiber texture using the
        product of two orthogonal sinusoidal grids (H × V) to produce peaks
        at fiber crossings and valleys along fiber runs; prior texture passes
        (make_linen_texture, make_cold_press_texture) generate isotropic or
        Gaussian noise textures -- none compute a structured periodic fiber
        grid with directional warp/weft periodicity and crossing peaks.

        Stage 2 FIBER CROSSING MICRO-CONTRAST: At fiber crossing points
        (where fiber_map > 0.6, i.e., both H and V are in phase), apply a
        per-pixel local micro-contrast boost: darken dark values, lighten
        light values by cross_boost in the [0.2, 0.8] luminance range.
        This simulates paint accumulating at raised fiber crossings (where
        the weave peak catches and holds paint).
        NOVEL: (b) PEAK-GATED LOCAL MICRO-CONTRAST AT FIBER INTERSECTIONS --
        first pass to apply luminance-dependent micro-contrast boost
        exclusively at fiber crossing peak locations; paint_optical_vibration
        applies contrast amplification globally; all prior contrast passes
        operate on full-canvas luminance criteria -- none gate contrast
        adjustment on a structured spatial peak-detection grid.

        Stage 3 DIRECTIONAL RIDGE CATCH-LIGHT: Along horizontal fiber
        ridges (H_fiber > 0.5), apply a directional luminance highlight based
        on the dot product of each ridge normal with the light direction
        (light_angle degrees from horizontal). Ridge normals point upward from
        the weave surface; ridges facing the light source receive a luminance
        boost of ridge_strength, those facing away receive a subtle dimming.
        NOVEL: (c) ANISOTROPIC DIRECTIONAL HIGHLIGHT DERIVED FROM SURFACE
        RELIEF ORIENTATION -- first pass to compute ridge normals from a
        periodic surface relief map and apply a directional diffuse-light
        highlight based on the ridge-normal vs. light-vector dot product;
        no prior pass applies directional lighting derived from simulated
        surface topology.

        grain_size      : Fiber period in pixels (warp/weft spacing).
        fiber_amplitude : Brightness modulation amplitude from fiber grid.
        cross_boost     : Micro-contrast amplification at fiber crossings.
        light_angle     : Light source direction in degrees (0=from right,
                          90=from below, 42=upper-right typical studio).
        ridge_strength  : Luminance boost/dim amplitude for ridge catch-light.
        opacity         : Final composite opacity (0=no change, 1=full effect).
        seed            : RNG seed for fiber phase noise.
        """
        import numpy as _np

        print("    Surface Tooth pass (session 252 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        rng = _np.random.default_rng(int(seed))
        gs = max(int(grain_size), 2)

        # Stage 1: Woven fiber pattern
        ys = _np.arange(h, dtype=_np.float32)
        xs = _np.arange(w, dtype=_np.float32)
        yy, xx = _np.meshgrid(ys, xs, indexing='ij')

        # Small random phase noise per-pixel to break periodicity
        noise_y = rng.uniform(-0.3, 0.3, size=(h, w)).astype(_np.float32)
        noise_x = rng.uniform(-0.3, 0.3, size=(h, w)).astype(_np.float32)

        H_fiber = _np.sin(2.0 * _np.pi * (yy / gs) + noise_y).astype(_np.float32)
        V_fiber = _np.sin(2.0 * _np.pi * (xx / gs) + noise_x).astype(_np.float32)
        fiber_map = (H_fiber * V_fiber).astype(_np.float32)   # [-1, 1]

        fa = float(fiber_amplitude)
        lum0 = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        lum1 = _np.clip(lum0 + fa * fiber_map, 0.0, 1.0).astype(_np.float32)

        # Apply luminance change proportionally to RGB channels
        scale = _np.where(lum0 > 1e-5, lum1 / (lum0 + 1e-5), 1.0).astype(_np.float32)
        scale = _np.clip(scale, 0.0, 2.0)
        r1 = _np.clip(r0 * scale, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * scale, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * scale, 0.0, 1.0).astype(_np.float32)

        # Stage 2: Fiber crossing micro-contrast
        crossing_mask = (fiber_map > 0.60).astype(_np.float32)
        cb = float(cross_boost)
        lum2 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        # Micro-contrast: push away from 0.5 for mid-tones
        mid_weight = _np.where(
            (lum2 > 0.20) & (lum2 < 0.80),
            2.0 * _np.abs(lum2 - 0.5) * crossing_mask,
            0.0
        ).astype(_np.float32)
        micro_shift = cb * _np.sign(lum2 - 0.5) * mid_weight
        r2 = _np.clip(r1 + micro_shift, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 + micro_shift, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 + micro_shift, 0.0, 1.0).astype(_np.float32)

        # Stage 3: Directional ridge catch-light
        ang_rad = float(light_angle) * _np.pi / 180.0
        # Light direction vector (in image plane)
        lx = float(_np.cos(ang_rad))
        ly = -float(_np.sin(ang_rad))   # y increases downward
        # Ridge normals from H_fiber gradient (horizontal ridges)
        ridge_mask = (H_fiber > 0.50).astype(_np.float32)
        # Normal points upward (negative y in image coords)
        # Dot with light direction: lx * 0 + ly * (-1) = -ly = sin(angle)
        dot = float(-ly)   # constant for horizontal ridges
        rs = float(ridge_strength)
        light_mod = rs * dot * ridge_mask
        r3 = _np.clip(r2 + light_mod, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 + light_mod, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 + light_mod, 0.0, 1.0).astype(_np.float32)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()
        fiber_coverage = float((fiber_map > 0.6).mean())
        print(f"    Surface Tooth complete (grain_size={grain_size}, "
              f"fiber_coverage={fiber_coverage:.3f})")
    def paint_edge_temperature_pass(
        self,
        warm_hue_center:   float = 0.05,
        warm_hue_width:    float = 0.18,
        cool_hue_center:   float = 0.60,
        cool_hue_width:    float = 0.20,
        gradient_zone_px:  float = 3.5,
        contrast_strength: float = 0.14,
        opacity:           float = 0.72,
    ) -> None:
        r"""Edge Temperature Contrast -- session 256 improvement pass.

        THREE-STAGE SIMULTANEOUS TEMPERATURE CONTRAST AT WARM/COOL BOUNDARIES:

        Addresses the fundamental painting observation that warm and cool
        colour zones, when adjacent, each appear more extreme at their shared
        boundary than they do in isolation -- a phenomenon called simultaneous
        colour contrast. Painters (Chevreul, Albers, Itten) have used this
        deliberately: warm-lit areas appear warmer when their shadow edge
        abuts a cool-toned zone, and cool shadows appear cooler when they
        meet warm light. This pass detects the spatial boundaries between warm-
        and cool-hued regions and applies a bidirectional temperature push
        that intensifies both sides of each boundary.

        Stage 1 WARM/COOL HSV HUE MEMBERSHIP MASKS: Convert each RGB pixel to
        HSV. Compute a soft warm-hue membership mask using a Gaussian bell over
        hue distance from warm_hue_center (wrapping around the hue circle):
          dist_w = min(|H - warm_hue_center|, 1 - |H - warm_hue_center|)
          warm_mask = exp(-(dist_w / warm_hue_width) ** 2)
        Compute cool_mask identically for cool_hue_center and cool_hue_width.
        Both masks are in [0, 1]; saturated pixels contribute more weight
        (multiply by S) so achromatic pixels do not trigger false boundaries.
        NOVEL: (a) SATURATION-WEIGHTED SOFT HSV HUE-MEMBERSHIP MASKS FOR
        SIMULTANEOUS WARM/COOL TEMPERATURE CONTRAST -- first pass to compute
        per-pixel warm and cool hue membership via wrapped Gaussian bell over
        hue distance, weighted by HSV saturation; no prior pass builds dual
        hue-membership masks from HSV hue-angle distance for warm/cool
        temperature operations; paint_warm_cool_separation_pass (s251) applies
        a global spatial warm/cool push without per-pixel hue membership
        detection; no prior pass uses saturation-weighted Gaussian hue-distance
        masks to localise a temperature operation to genuinely chromatic pixels.

        Stage 2 TEMPERATURE BOUNDARY GRADIENT ZONE: Compute the finite-
        difference gradient magnitude of (warm_mask - cool_mask):
          diff = warm_mask - cool_mask  (in [-1, 1])
          gy = diff[2:, :] - diff[:-2, :]  (central difference, rows)
          gx = diff[:, 2:] - diff[:, :-2]  (central difference, cols)
          grad_mag = sqrt(gy_padded^2 + gx_padded^2)
        Apply Gaussian blur with sigma=gradient_zone_px to spread the detected
        boundary into a smooth zone of influence. Normalise to [0, 1].
        NOVEL: (b) GRADIENT MAGNITUDE OF THE WARM-COOL MEMBERSHIP DIFFERENCE
        MAP SMOOTHED INTO A TEMPERATURE BOUNDARY ZONE -- first pass to detect
        spatial boundaries between warm and cool hue regions via the gradient
        of the signed membership difference (warm_mask - cool_mask), then
        spread the boundary into a smooth zone via Gaussian blur; no prior pass
        computes the gradient of a hue-membership difference map to locate
        warm/cool boundaries; paint_lost_found_edges_pass detects luminance
        edges; no prior pass uses hue-space gradient detection.

        Stage 3 BIDIRECTIONAL SIMULTANEOUS TEMPERATURE CONTRAST: At each
        pixel, compute a signed temperature signal:
          temp_signal = contrast_strength * boundary_zone *
                        (warm_mask - cool_mask)
        Apply as a bidirectional red-blue push:
          R += temp_signal * 0.12
          B -= temp_signal * 0.08
        When temp_signal > 0 (warm-zone boundary pixel) this pushes R up and
        B down (warmer). When temp_signal < 0 (cool-zone boundary pixel) R
        goes down and B goes up (cooler). Pixels far from any warm/cool
        boundary (boundary_zone ≈ 0) receive no push, preserving the interior
        of zones unchanged.
        NOVEL: (c) BIDIRECTIONAL SIMULTANEOUS TEMPERATURE CONTRAST PUSH DRIVEN
        BY SIGNED HUE-MEMBERSHIP DIFFERENCE WEIGHTED BY SMOOTH BOUNDARY ZONE
        -- first pass to apply a single signed R/B push derived from
        (warm_mask - cool_mask) * boundary_zone, pushing warm-side pixels
        warmer and cool-side pixels cooler simultaneously in one operation;
        paint_warm_cool_separation_pass (s251) applies a global spatial push
        indexed by image quadrant; no prior pass applies bidirectional
        simultaneous temperature contrast at per-pixel hue boundaries using
        a smooth boundary-zone weighting.

        warm_hue_center   : Center of warm hue range in HSV [0, 1] (~orange).
        warm_hue_width     : Gaussian half-width of warm hue range.
        cool_hue_center    : Center of cool hue range in HSV [0, 1] (~blue).
        cool_hue_width     : Gaussian half-width of cool hue range.
        gradient_zone_px   : Gaussian sigma for boundary zone spread (pixels).
        contrast_strength  : Temperature push amplitude at boundaries.
        opacity            : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        import colorsys as _cs

        print("    Edge Temperature pass (session 256 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        # Cairo BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # Stage 1: Warm/cool hue membership masks (vectorised HSV)
        # Convert RGB -> HSV without looping using colorsys-equivalent formulae
        maxc = _np.maximum(_np.maximum(r0, g0), b0).astype(_np.float32)
        minc = _np.minimum(_np.minimum(r0, g0), b0).astype(_np.float32)
        saturation = _np.where(maxc > 1e-6, (maxc - minc) / (maxc + 1e-6), 0.0).astype(_np.float32)

        delta = (maxc - minc + 1e-9).astype(_np.float32)
        # Hue computation (vectorised)
        hue = _np.zeros((h, w), dtype=_np.float32)
        # Red is max
        mask_r = (maxc == r0) & (maxc > minc)
        hue[mask_r] = ((g0[mask_r] - b0[mask_r]) / delta[mask_r]) % 6.0
        # Green is max
        mask_g = (maxc == g0) & (maxc > minc) & ~mask_r
        hue[mask_g] = (b0[mask_g] - r0[mask_g]) / delta[mask_g] + 2.0
        # Blue is max
        mask_b = (maxc == b0) & (maxc > minc) & ~mask_r & ~mask_g
        hue[mask_b] = (r0[mask_b] - g0[mask_b]) / delta[mask_b] + 4.0
        hue = (hue / 6.0) % 1.0   # normalise to [0, 1]

        def _soft_hue_mask(hue_arr, center, width):
            # Gaussian bell over wrapped hue distance, weighted by saturation
            dist = _np.abs(hue_arr - center)
            dist = _np.minimum(dist, 1.0 - dist)   # wrap-around
            return _np.exp(-(dist / (float(width) + 1e-8)) ** 2).astype(_np.float32) * saturation

        wm = _soft_hue_mask(hue, float(warm_hue_center), float(warm_hue_width))
        cm = _soft_hue_mask(hue, float(cool_hue_center), float(cool_hue_width))

        # Stage 2: Gradient of (warm - cool) difference map -> boundary zone
        diff = (wm - cm).astype(_np.float32)   # in [-1, 1]

        # Central-difference gradient (pad to preserve shape)
        gy = _np.pad(diff[2:, :] - diff[:-2, :], ((1, 1), (0, 0)), mode='edge')
        gx = _np.pad(diff[:, 2:] - diff[:, :-2], ((0, 0), (1, 1)), mode='edge')
        grad_mag = _np.sqrt(gy ** 2 + gx ** 2).astype(_np.float32)

        boundary_zone = _gf(grad_mag, sigma=float(gradient_zone_px)).astype(_np.float32)
        bz_max = boundary_zone.max()
        if bz_max > 1e-8:
            boundary_zone /= bz_max

        # Stage 3: Bidirectional simultaneous temperature contrast push
        cs = float(contrast_strength)
        temp_signal = (cs * boundary_zone * diff).astype(_np.float32)

        r1 = _np.clip(r0 + temp_signal * 0.12, 0.0, 1.0).astype(_np.float32)
        g1 = g0.copy()
        b1 = _np.clip(b0 - temp_signal * 0.08, 0.0, 1.0).astype(_np.float32)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        boundary_px = int((boundary_zone > 0.1).sum())
        print(f"    Edge Temperature complete "
              f"(boundary_px={boundary_px}, "
              f"contrast_strength={contrast_strength:.3f})")
    def paint_shadow_bleed_pass(
        self,
        shadow_threshold:  float = 0.35,
        bright_threshold:  float = 0.72,
        bleed_sigma:       float = 8.0,
        reflect_strength:  float = 0.14,
        warm_r:            float = 0.85,
        warm_g:            float = 0.60,
        warm_b:            float = 0.30,
        opacity:           float = 0.75,
    ) -> None:
        r"""Shadow Bleed -- Reflected Warm Light in Shadows -- session 257 improvement.

        THREE-STAGE REFLECTED SECONDARY ILLUMINATION IN SHADOW ZONES:

        Reflected light (or bounced light) is a fundamental principle in
        traditional oil painting: bright surfaces in the scene act as secondary
        light sources, casting diffuse light back into the shadow sides of
        adjacent objects. This effect is responsible for the characteristic
        warmth found deep in the shadows of Old Master paintings -- a warm
        amber glow visible on the underside of a chin or at the shaded edge of
        an arm, where the warm ground plane bounces light back. Without
        reflected light, shadows are flat, cold, and dead. With it, the dark
        areas are alive and connected to the light. This pass synthesises that
        effect by detecting the spatial relationship between bright and shadow
        regions and injecting a warm tint into the shadow boundary zone.

        Stage 1 SHADOW BOUNDARY PROXIMITY FIELD: Compute per-pixel luminance
        lum = 0.299R + 0.587G + 0.114B. Create a binary shadow mask:
          shadow_mask = (lum < shadow_threshold)  [0=lit, 1=shadow]
        Apply Gaussian blur with sigma=bleed_sigma to create a smooth shadow-
        boundary field that transitions from 1 inside deep shadows to 0
        outside, with a gradient falloff zone proportional to bleed_sigma.
        This field represents the proximity of each pixel to the shadow interior
        weighted by its depth within the shadow.
        NOVEL: (a) SMOOTH SHADOW BOUNDARY PROXIMITY FIELD FROM GAUSSIAN-BLURRED
        BINARY LUMINANCE-THRESHOLD SHADOW MASK -- first pass to derive a smooth
        shadow boundary proximity map by Gaussian-blurring a per-pixel binary
        shadow mask (not an edge-detection gradient), producing a continuous
        scalar field encoding depth-within-shadow proximity; paint_lost_found_
        edges_pass applies gradient-of-luminance for edge softening -- it does
        not threshold into binary shadow zones; no prior pass produces a smooth
        binary-mask-derived shadow proximity field.

        Stage 2 BRIGHT REGION PROXIMITY FIELD: Create a binary bright mask:
          bright_mask = (lum > bright_threshold)
        Apply identical Gaussian blur at bleed_sigma to create a smooth bright-
        source proximity field: each pixel's value encodes how near it is to a
        bright region (the secondary light source). The two fields independently
        capture the shadow interior and the bright source; their product in
        Stage 3 will identify only the zone where both are simultaneously true.
        NOVEL: (b) BRIGHT SOURCE PROXIMITY FIELD FROM GAUSSIAN-BLURRED BINARY
        LUMINANCE-THRESHOLD MASK AS SECONDARY LIGHT SOURCE INDICATOR -- first
        pass to independently derive a bright-source proximity field from a
        blurred binary luminance-threshold mask; the physical model is that any
        bright area acts as a secondary diffuse source; no prior pass derives
        a separate bright-source proximity field for use in a reflected-light
        injection; paint_halation_pass (s?) concentrates on a single bright
        point, not a spatial field of all bright areas.

        Stage 3 REFLECTED WARM LIGHT INJECTION AT SHADOW-BRIGHT INTERSECTION:
        Compute the reflected light injection field:
          reflect_field = shadow_proximity * bright_proximity
        This field is nonzero only in the zone that is simultaneously inside a
        shadow and near a bright surface -- the exact physical location where
        reflected secondary illumination occurs. Apply a warm tint:
          R += reflect_strength * reflect_field * (warm_r - r)
          G += reflect_strength * reflect_field * (warm_g - g)
          B += reflect_strength * reflect_field * (warm_b - b)
        This moves pixels in the reflected zone toward the warm colour
        (warm_r, warm_g, warm_b) at a rate proportional to reflect_field and
        reflect_strength. The warm default (0.85, 0.60, 0.30) simulates diffuse
        warm environmental light bouncing from a sunlit ground or warm wall.
        NOVEL: (c) REFLECTED WARM TINT INJECTION DRIVEN BY SHADOW-BRIGHT
        PROXIMITY PRODUCT AS REFLECTED SECONDARY LIGHT SIMULATION -- first pass
        to derive the reflected light injection zone as the PRODUCT of shadow
        and bright proximity fields and apply a directional colour nudge
        (toward warm_r/g/b) proportional to the product; no prior pass
        synthesises a spatial reflected-light zone from the product of two
        proximity fields; paint_warm_cool_separation_pass (s251) applies a
        global spatial push by quadrant; paint_edge_temperature_pass (s256)
        applies temperature contrast at hue-zone boundaries -- neither computes
        a proximity-product zone; this is the first pass to model secondary
        diffuse reflected illumination from bright surfaces into adjacent
        shadow zones.

        shadow_threshold : Luminance ceiling for shadow zone (0-1).
        bright_threshold : Luminance floor for bright (source) zone (0-1).
        bleed_sigma      : Gaussian sigma for proximity field smoothing.
        reflect_strength : Amplitude of warm tint injection at peak.
        warm_r/g/b       : RGB target colour of the reflected secondary light.
        opacity          : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Shadow Bleed pass (session 257 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        # Cairo BGRA
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # Stage 1: Shadow proximity field (blurred binary shadow mask)
        shadow_mask = (lum < float(shadow_threshold)).astype(_np.float32)
        shadow_prox = _gf(shadow_mask, sigma=float(bleed_sigma)).astype(_np.float32)
        sp_max = shadow_prox.max()
        if sp_max > 1e-8:
            shadow_prox /= sp_max

        # Stage 2: Bright-source proximity field (blurred binary bright mask)
        bright_mask = (lum > float(bright_threshold)).astype(_np.float32)
        bright_prox = _gf(bright_mask, sigma=float(bleed_sigma)).astype(_np.float32)
        bp_max = bright_prox.max()
        if bp_max > 1e-8:
            bright_prox /= bp_max

        # Stage 3: Product zone = reflected light injection field
        reflect_field = (shadow_prox * bright_prox).astype(_np.float32)
        rf_max = reflect_field.max()
        if rf_max > 1e-8:
            reflect_field /= rf_max

        rs = float(reflect_strength)
        wr = float(warm_r)
        wg = float(warm_g)
        wb = float(warm_b)

        r1 = _np.clip(r0 + rs * reflect_field * (wr - r0), 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 + rs * reflect_field * (wg - g0), 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 + rs * reflect_field * (wb - b0), 0.0, 1.0).astype(_np.float32)

        # Final composite
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        shadow_px = int(shadow_mask.sum())
        reflect_px = int((reflect_field > 0.1).sum())
        print(f"    Shadow Bleed complete (shadow_px={shadow_px}, "
              f"reflect_zone_px={reflect_px}, "
              f"reflect_strength={reflect_strength:.3f})")

    def morandi_dusty_vessel_pass(
        self,
        dust_veil:         float = 0.55,
        compress_strength: float = 0.40,
        target_mid:        float = 0.52,
        reveal_threshold:  float = 0.72,
        reveal_strength:   float = 0.25,
        ochre_r:           float = 0.86,
        ochre_g:           float = 0.80,
        ochre_b:           float = 0.56,
        opacity:           float = 0.80,
    ) -> None:
        r"""Giorgio Morandi Dusty Still-Life -- session 258, 169th distinct mode.

        THREE-STAGE DUSTY VESSEL EFFECT INSPIRED BY MORANDI'S
        "STILL LIFE" PAINTINGS (1916-1964):

        Giorgio Morandi (1890-1964) spent almost his entire life in Bologna,
        painting the same small group of bottles, jars, and boxes with obsessive
        variation.  His technical signatures: an almost matte, powder-dry paint
        surface built from thin, re-worked layers of earth pigments over a warm
        ground; colour differences so subtle they hover at the threshold of
        perception -- warm grey against cool grey, ochre against sand; tonal
        range compressed to roughly a third of the available scale; the highest
        lights barely reach a creamy vellum; the deepest shadows rarely go below
        a warm ash grey; and a characteristic warm-ochre glow in the very
        lightest passages where the ground colour bleeds through thin paint.
        The three stages below derive from these observations.

        Stage 1 DUSTY DESATURATION VEIL: Convert each pixel from RGB to HSV
        (hue h, saturation s, value v).  Apply a luminance-weighted saturation
        reduction:
          lum = 0.299*R + 0.587*G + 0.114*B
          s_new = s * max(0, 1 - dust_veil * (1 - lum))
        Shadow pixels (low lum) lose the most saturation; light pixels retain
        slightly more colour.  The intent is Morandi's characteristic loss of
        chromatic identity in the shadows -- every colour in shadow becomes a
        version of warm grey.  Set s_new back into HSV and convert to RGB.
        NOVEL: (a) LUMINANCE-WEIGHTED SATURATION REDUCTION AS DUSTY SHADOW
        DESATURATION VEIL -- first pass to derive the saturation suppression
        factor from (1 - lum), so darker pixels are de-saturated more
        aggressively; paint_shadow_bleed_pass (s257) adds warm tint in the
        shadow zone but does not modify saturation; no prior pass applies a
        luminance-weighted saturation clamp as a dust/atmospheric effect.

        Stage 2 TONAL COMPRESSION: In luminance space, push all pixel values
        toward a target mid-tone:
          lum_new = lum + compress_strength * (target_mid - lum)
          scale = lum_new / (lum + 1e-6)  (protect against zero)
          R *= scale,  G *= scale,  B *= scale
        With target_mid ~0.52 and compress_strength ~0.40, the tonal range
        contracts toward the mid-grey: very dark pixels brighten slightly
        (ashes in Morandi never go truly black) and very light pixels are
        pulled back from stark white (Morandi's brightest lights are cream,
        not white).  The result is the narrow, velvety tonal window that
        distinguishes Morandi from all other still-life painters.
        NOVEL: (b) LUMINANCE-PUSH-TOWARD-MIDTONE TONAL COMPRESSION WITHOUT
        GAMMA CORRECTION -- first pass to compress tonal range by shifting
        individual pixel luminance toward a defined mid target via lerp and
        then scaling RGB proportionally; paint_tonal_key_pass (s255) shifts
        the overall key by a global histogram percentile adjustment; no prior
        pass applies a pixel-wise lerp of luminance toward a user-defined
        mid-tone value as its sole purpose.

        Stage 3 OCHRE GROUND REVEAL: In the lightest pixels (lum > reveal_threshold),
        blend the RGB values toward the warm ochre ground colour (ochre_r, ochre_g,
        ochre_b) at a rate proportional to how far above the threshold the pixel is:
          t = min(1, (lum - reveal_threshold) / (1 - reveal_threshold))
          reveal = reveal_strength * t
          R = R*(1-reveal) + ochre_r*reveal
          G = G*(1-reveal) + ochre_g*reveal
          B = B*(1-reveal) + ochre_b*reveal
        This simulates the glowing warm quality Morandi's paintings show in their
        brightest passages -- a consequence of thin paint over a warm ochre
        imprimatura: the ground bleeds through and tints the pale highlight.
        NOVEL: (c) LUMINANCE-GATED GROUND COLOUR BLEED IN NEAR-HIGHLIGHT PIXELS
        AS A THIN-PAINT IMPRIMATURA REVEAL -- first pass to identify pixels above
        a luminance reveal_threshold and blend them toward a user-specified warm
        ground colour proportional to their excess luminance; paint_shadow_bleed_pass
        (s257) blends toward a warm colour in shadow zones based on proximity to
        bright pixels; this stage applies the inverse: blending near-highlight
        pixels toward the ground colour as a luminance-gated glaze reveal,
        distinct from shadow zone proximity logic.

        dust_veil         : Saturation reduction amplitude (0=no dust, 1=greyscale
                            in the darkest shadows).
        compress_strength : Fraction of distance toward target_mid to move (0-1).
        target_mid        : Luminance target for compression (0-1; ~0.52 = cream).
        reveal_threshold  : Luminance above which ground colour begins to show.
        reveal_strength   : Max blend fraction toward ochre at the lightest pixels.
        ochre_r/g/b       : RGB of the warm ground colour to reveal.
        opacity           : Final composite opacity.
        """
        import numpy as _np
        import colorsys as _cs

        print("    Morandi Dusty Vessel pass (session 258, 169th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        # Cairo BGRA ordering
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Dusty Desaturation Veil (HSV saturation reduction) ──────
        # Vectorised HSV round-trip using per-channel operations
        # max/min per pixel for value and saturation
        cmax = _np.maximum(_np.maximum(r0, g0), b0)
        cmin = _np.minimum(_np.minimum(r0, g0), b0)
        delta = (cmax - cmin).astype(_np.float32)

        # Value = cmax
        v = cmax.copy()

        # Saturation = delta / (cmax + 1e-8)
        s = _np.where(cmax > 1e-6, delta / (cmax + 1e-8), 0.0).astype(_np.float32)

        # Hue in [0, 1]
        eps = 1e-8
        hue = _np.zeros((h, w), dtype=_np.float32)
        m_r = (cmax == r0) & (delta > eps)
        m_g = (cmax == g0) & (delta > eps)
        m_b = (cmax == b0) & (delta > eps)

        hue[m_r] = (((g0[m_r] - b0[m_r]) / (delta[m_r] + eps)) % 6.0) / 6.0
        hue[m_g] = (((b0[m_g] - r0[m_g]) / (delta[m_g] + eps)) + 2.0) / 6.0
        hue[m_b] = (((r0[m_b] - g0[m_b]) / (delta[m_b] + eps)) + 4.0) / 6.0
        hue = _np.clip(hue, 0.0, 1.0)

        # Luminance-weighted saturation suppression
        dv = float(dust_veil)
        reduction = _np.maximum(0.0, 1.0 - dv * (1.0 - lum)).astype(_np.float32)
        s1 = (s * reduction).astype(_np.float32)

        # Back to RGB from HSV (s1, v)
        h6 = hue * 6.0
        i = _np.floor(h6).astype(_np.int32) % 6
        f = (h6 - _np.floor(h6)).astype(_np.float32)
        p = (v * (1.0 - s1)).astype(_np.float32)
        q = (v * (1.0 - s1 * f)).astype(_np.float32)
        t2 = (v * (1.0 - s1 * (1.0 - f))).astype(_np.float32)

        r1 = _np.select(
            [i == 0, i == 1, i == 2, i == 3, i == 4, i == 5],
            [v, q, p, p, t2, v], default=v).astype(_np.float32)
        g1 = _np.select(
            [i == 0, i == 1, i == 2, i == 3, i == 4, i == 5],
            [t2, v, v, q, p, p], default=v).astype(_np.float32)
        b1 = _np.select(
            [i == 0, i == 1, i == 2, i == 3, i == 4, i == 5],
            [p, p, t2, v, v, q], default=v).astype(_np.float32)

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        # ── Stage 2: Tonal Compression ─────────────────────────────────────────
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        cs = float(compress_strength)
        tm = float(target_mid)
        lum2 = (lum1 + cs * (tm - lum1)).astype(_np.float32)
        scale = (lum2 / _np.maximum(lum1, 1e-6)).astype(_np.float32)
        r2 = _np.clip(r1 * scale, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 * scale, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 * scale, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Ochre Ground Reveal in near-highlights ────────────────────
        rt = float(reveal_threshold)
        rs_f = float(reveal_strength)
        or_ = float(ochre_r)
        og_ = float(ochre_g)
        ob_ = float(ochre_b)

        lum2_full = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        range_hi = max(1.0 - rt, 1e-6)
        t_reveal = _np.clip((lum2_full - rt) / range_hi, 0.0, 1.0).astype(_np.float32)
        reveal = (rs_f * t_reveal).astype(_np.float32)

        r3 = _np.clip(r2 * (1.0 - reveal) + or_ * reveal, 0.0, 1.0)
        g3 = _np.clip(g2 * (1.0 - reveal) + og_ * reveal, 0.0, 1.0)
        b3 = _np.clip(b2 * (1.0 - reveal) + ob_ * reveal, 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        reveal_px = int((t_reveal > 0.01).sum())
        print(f"    Morandi Dusty Vessel complete "
              f"(dust_veil={dust_veil:.2f}, compress={compress_strength:.2f}, "
              f"reveal_px={reveal_px})")


    def paint_granulation_pass(
        self,
        granule_sigma:   float = 2.0,
        granule_scale:   float = 0.06,
        warm_shift:      float = 0.04,
        cool_shift:      float = 0.04,
        edge_sharpen:    float = 0.35,
        noise_seed:      int   = 42,
        opacity:         float = 0.70,
    ) -> None:
        r"""Paint Granulation -- session 258 improvement.

        THREE-STAGE PIGMENT GRANULATION SIMULATION:

        Traditional oil and watercolour painters observe that pigment particles
        of differing density settle differently on a textured surface: heavier
        particles collect in the tooth valleys (producing dark, warm particle
        concentrations) while lighter pigments stay at the peaks (producing
        cool, bright highlights in the granule structure).  This pass models
        that behaviour procedurally.

        Stage 1 TEXTURE FREQUENCY DECOMPOSITION: Separate the canvas luminance
        into a low-frequency base layer (Gaussian-blurred at granule_sigma) and
        a high-frequency residual (the difference -- the texture/detail component):
          lum_smooth = gaussian_filter(lum, sigma=granule_sigma)
          lum_detail = lum - lum_smooth
        The detail layer captures existing paint edges, brush marks, and
        impasto ridges.  The smooth layer is the large tonal mass.
        NOVEL: (a) GAUSSIAN LOW/HIGH FREQUENCY DECOMPOSITION OF CANVAS LUMINANCE
        AS A GRANULATION STRUCTURE FIELD -- first pass to use the Laplacian-of-
        Gaussian residual (lum - blur) as the spatial granule distribution field;
        paint_impasto_ridge_cast_pass uses Sobel edge of a smoothed luminance as
        an impasto relief field; no prior pass uses the absolute difference between
        luminance and its Gaussian blur as the granulation particle placement map.

        Stage 2 CHROMATIC GRANULATION: Use the detail layer (lum_detail) as
        a signed particle field: positive values = paint ridges (peaks);
        negative values = valleys.  Apply a chromatic push:
          At peaks (lum_detail > 0):  nudge toward cool (B up, R down)
            scale = granule_scale * lum_detail (normalised to max)
            R -= warm_shift * scale
            B += cool_shift * scale
          In valleys (lum_detail < 0): nudge toward warm (R up, B down)
            scale = granule_scale * abs(lum_detail) (normalised to max)
            R += warm_shift * scale
            B -= cool_shift * scale
        This is the physical inversion of naive intuition: pigment VALLEYS are
        where warm, heavy particles concentrate (the paint is thick there);
        PEAKS are exposed -- the surface reflects coolly with less pigment.
        NOVEL: (b) SIGNED DETAIL-LAYER-DRIVEN CHROMATIC PUSH WITH WARM-IN-VALLEY
        / COOL-ON-PEAK GRANULATION POLARITY -- first pass to apply opposing warm
        and cool chromatic nudges at the PEAKS and VALLEYS of a Gaussian residual
        field; paint_surface_tooth_pass (s252) adds luminance modulation based on
        a noise field for surface texture; no prior pass splits a Gaussian residual
        into signed peak/valley regions and applies opposing warm/cool channel
        pushes to each region independently.

        Stage 3 EDGE CLARITY ENHANCEMENT: To counteract the slight softening
        from the granulation process, apply an unsharp mask to the detail layer:
          lum_sharp = lum + edge_sharpen * lum_detail
        Reconstruct RGB by scaling each channel proportionally:
          scale = lum_sharp / (lum + 1e-6)
          R *= scale,  G *= scale,  B *= scale
        This restores edge definition at brush stroke boundaries and object
        contours, giving the granulated surface a crisp, resolved quality
        at high frequencies while retaining the granule texture at mid-frequency.
        NOVEL: (c) UNSHARP MASK APPLIED TO THE SAME GAUSSIAN RESIDUAL FIELD
        USED FOR GRANULATION, AS A PAIRED SHARPENING STAGE -- first pass to
        recombine the granulation residual as an unsharp mask to restore edge
        contrast after the chromatic granulation; paint_surface_tooth_pass adds
        noise-modulated luminance; no prior pass uses the same Laplacian residual
        both for chromatic granulation and as an unsharp mask in two paired stages.

        granule_sigma : Gaussian sigma for the frequency decomposition.
        granule_scale : Amplitude scaling for the chromatic granulation push.
        warm_shift    : Max warm (R+/B-) push amplitude in valley pixels.
        cool_shift    : Max cool (B+/R-) push amplitude at ridge pixels.
        edge_sharpen  : Unsharp mask strength (0=none, 1=full residual add).
        noise_seed    : RNG seed for any stochastic noise component (unused for
                        determinism; reserved for future per-channel noise).
        opacity       : Final composite opacity.
        """
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        print("    Paint Granulation pass (session 258 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Frequency decomposition ──────────────────────────────────
        sig = max(float(granule_sigma), 0.5)
        lum_smooth = _gf(lum, sigma=sig).astype(_np.float32)
        lum_detail = (lum - lum_smooth).astype(_np.float32)

        detail_max = _np.abs(lum_detail).max()
        if detail_max < 1e-8:
            # Flat canvas -- nothing to granulate; just composite identity
            detail_norm = lum_detail
        else:
            detail_norm = (lum_detail / detail_max).astype(_np.float32)  # in [-1, 1]

        # ── Stage 2: Chromatic granulation ────────────────────────────────────
        gs = float(granule_scale)
        ws = float(warm_shift)
        cs_f = float(cool_shift)

        # Peaks: lum_detail > 0  → cool push (B up, R down)
        peak_mask = (detail_norm > 0).astype(_np.float32)
        valley_mask = (detail_norm < 0).astype(_np.float32)

        peak_strength  = detail_norm * peak_mask   * gs   # >= 0
        valley_strength = -detail_norm * valley_mask * gs   # >= 0

        r1 = _np.clip(r0 - peak_strength * ws + valley_strength * ws, 0.0, 1.0).astype(_np.float32)
        g1 = g0.copy()   # G channel largely unaffected (warm/cool is R-B axis)
        b1 = _np.clip(b0 + peak_strength * cs_f - valley_strength * cs_f, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Edge clarity unsharp mask ────────────────────────────────
        es = float(edge_sharpen)
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        lum1_sharp = _np.clip(lum1 + es * lum_detail, 0.0, 1.0).astype(_np.float32)

        scale = (lum1_sharp / _np.maximum(lum1, 1e-6)).astype(_np.float32)
        r2 = _np.clip(r1 * scale, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 * scale, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 * scale, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        peak_px   = int(peak_mask.sum())
        valley_px = int(valley_mask.sum())
        print(f"    Paint Granulation complete "
              f"(peaks={peak_px}, valleys={valley_px}, "
              f"edge_sharpen={edge_sharpen:.2f})")

    def rysselberghe_chromatic_dot_field_pass(
        self,
        spectral_boost:       float = 0.35,
        luminosity_gain:      float = 0.18,
        luminosity_threshold: float = 0.42,
        dot_spacing:          int   = 8,
        dot_jitter:           float = 0.30,
        dot_sigma:            float = 1.8,
        dot_amplitude:        float = 0.04,
        noise_seed:           int   = 259,
        opacity:              float = 0.72,
    ) -> None:
        r"""Théo van Rysselberghe Chromatic Dot Field -- session 259, 170th distinct mode.

        THREE-STAGE NEO-IMPRESSIONIST POINTILLIST CHROMATIC FIELD EFFECT
        INSPIRED BY VAN RYSSELBERGHE'S DIVISIONIST TECHNIQUE (1890-1926):

        Théo van Rysselberghe (1862-1926) was the leading Belgian practitioner of
        Neo-Impressionist Divisionism.  His method: apply pigment as discrete units
        of near-pure spectral colour, trusting the eye to mix them optically at
        viewing distance.  Optical mixture yields higher apparent luminosity than
        physical mixing because subtractive pigment mixing absorbs light while
        adjacent pure-hue dots combine additively in the eye.  The systematic dot
        application creates a fine all-over surface vibration and a chromatic
        intensity no blended technique can achieve.  The three stages below model
        the perceptual and physical phenomena of this approach.

        Stage 1 SPECTRAL HUE SATURATION BOOST: Convert each pixel to HSV.  For each
        pixel's hue angle h (0-1 representing 0-360°), compute its angular distance
        to the nearest spectral primary:
          primaries = [0.0, 1/6, 2/6, 3/6, 4/6, 5/6]  (red, yellow, green, cyan, blue, violet)
          d = min over primaries: | h - p | (angular, wrap-around)
          boost_s = spectral_boost * (1 - 2*d/primary_spacing)  (zero at mid-point between primaries)
          s_new = clip(s + boost_s, 0, 1)
        This sharpens the chromatic identity of each pixel by pushing its hue toward
        the nearest pure spectral primary -- modelling the pointillist practice of
        selecting pure unmixed pigment for each dot rather than blending toward an
        intermediate hue.
        NOVEL: (a) HUE-ANGLE-DEPENDENT SATURATION PUSH TOWARD NEAREST SPECTRAL PRIMARY
        AS A MODEL OF PURE-PIGMENT DOT COLOUR SELECTION -- first pass to compute
        angular proximity to spectral primaries and scale saturation boost proportionally;
        paint_granulation_pass (s258) adjusts saturation indirectly via luminance scaling;
        no prior pass uses each pixel's angular distance to the nearest spectral primary
        to drive a proportional saturation amplification.

        Stage 2 OPTICAL LUMINOSITY ENHANCEMENT: Neo-Impressionist optical colour
        mixing produces a glow not achievable through physical pigment blending.
        Simulate this with a saturation-gated luminance lift:
          sat_excess = max(0, s_new - luminosity_threshold)
          lum_lift = luminosity_gain * sat_excess / (1 - luminosity_threshold + 1e-6)
          lum_new = clip(lum + lum_lift, 0, 1)
          scale = lum_new / (lum + 1e-6)
          R *= scale, G *= scale, B *= scale
        Highly saturated pixels (pure chromatic dots) are brightened; near-grey
        pixels are unaffected.  This approximates the luminous shimmer of pure-pigment
        dot fields in Mediterranean sunlight.
        NOVEL: (b) SATURATION-GATED LUMINANCE LIFT AS A MODEL OF OPTICAL COLOUR
        MIXING LUMINOSITY GAIN IN NEO-IMPRESSIONISM -- first pass to use each pixel's
        own saturation (after the hue boost) as the gate for a luminance enhancement
        operation; paint_tonal_key_pass (s255) shifts overall key via histogram
        percentile; no prior pass uses per-pixel saturation as the explicit gate
        and scaling input for a luminance boost modelling Neo-Impressionist optical mixing.

        Stage 3 DOT FIELD TEXTURE: Generate a perturbed regular grid of dot centres
        (spacing = dot_spacing pixels, each centre jittered by ±dot_jitter * dot_spacing
        in x and y using the noise_seed RNG).  At each dot centre (cx, cy) stamp a
        2D Gaussian luminance bump of amplitude ±dot_amplitude (alternating sign
        on a checkerboard pattern: sign = (-1)^(i+j) where i,j are grid indices,
        so adjacent dots are light and dark, giving the micro-contrast of discrete
        paint marks on a textured ground):
          bump[row, col] = dot_amplitude * sign * exp(-((row-cy)^2 + (col-cx)^2)
                           / (2 * dot_sigma^2))
        Apply as luminance modulation: lum_dot = lum_prev + bump_field; scale RGB.
        NOVEL: (c) SPATIALLY-PERIODIC JITTERED GRID OF GAUSSIAN-PROFILE LUMINANCE
        BUMPS WITH ALTERNATING SIGN CHECKERBOARD AS A PAINT-MARK DISCRETISATION
        TEXTURE -- first pass to stamp a fresh spatial dot grid (with alternating
        light/dark bumps) onto the canvas as luminance micro-modulation independently
        of the existing paint texture; paint_granulation_pass (s258) decomposes the
        existing canvas texture via frequency decomposition; no prior pass generates
        a new spatial dot grid and stamps Gaussian-profile bumps with alternating
        checkerboard sign pattern as an independent texture layer.

        spectral_boost       : Max saturation increase toward nearest spectral primary (0-1).
        luminosity_gain      : Max luminance lift for fully saturated pixels (0-1).
        luminosity_threshold : Saturation threshold below which no luminance boost (0-1).
        dot_spacing          : Grid spacing in pixels for dot centres.
        dot_jitter           : Fraction of dot_spacing for random centre displacement (0-1).
        dot_sigma            : Gaussian sigma for each dot bump in pixels.
        dot_amplitude        : Max luminance delta per dot bump (± this value).
        noise_seed           : RNG seed for dot centre jitter.
        opacity              : Final composite opacity.
        """
        import numpy as _np

        print("    Rysselberghe Chromatic Dot Field pass (session 259, 170th mode)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        # Cairo BGRA ordering
        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Spectral Hue Saturation Boost (HSV-space) ────────────────
        cmax = _np.maximum(_np.maximum(r0, g0), b0)
        cmin = _np.minimum(_np.minimum(r0, g0), b0)
        delta = (cmax - cmin).astype(_np.float32)
        v = cmax.copy()
        s = _np.where(cmax > 1e-6, delta / (cmax + 1e-8), 0.0).astype(_np.float32)

        eps = 1e-8
        hue = _np.zeros((h, w), dtype=_np.float32)
        m_r = (cmax == r0) & (delta > eps)
        m_g = (cmax == g0) & (delta > eps)
        m_b = (cmax == b0) & (delta > eps)
        hue[m_r] = (((g0[m_r] - b0[m_r]) / (delta[m_r] + eps)) % 6.0) / 6.0
        hue[m_g] = (((b0[m_g] - r0[m_g]) / (delta[m_g] + eps)) + 2.0) / 6.0
        hue[m_b] = (((r0[m_b] - g0[m_b]) / (delta[m_b] + eps)) + 4.0) / 6.0
        hue = _np.clip(hue, 0.0, 1.0)

        # Six spectral primaries evenly spaced in [0, 1) hue circle
        primaries = _np.array([0.0, 1.0/6, 2.0/6, 3.0/6, 4.0/6, 5.0/6],
                               dtype=_np.float32)
        primary_spacing = 1.0 / 6.0  # 60° gap between primaries

        # Minimum circular angular distance to nearest primary
        hue_exp = hue[:, :, _np.newaxis]          # (H, W, 1)
        prim_exp = primaries[_np.newaxis, _np.newaxis, :]  # (1, 1, 6)
        raw_diff = _np.abs(hue_exp - prim_exp)
        angular_dist = _np.minimum(raw_diff, 1.0 - raw_diff)  # wrap
        min_dist = angular_dist.min(axis=2).astype(_np.float32)

        # Boost = max at primary centre, zero at mid-point between two primaries
        boost_factor = _np.clip(
            1.0 - min_dist / (primary_spacing * 0.5),
            0.0, 1.0
        ).astype(_np.float32)
        boost_s = (float(spectral_boost) * boost_factor).astype(_np.float32)
        s1 = _np.clip(s + boost_s, 0.0, 1.0).astype(_np.float32)

        # Rebuild RGB from (hue, s1, v)
        h6 = hue * 6.0
        i = _np.floor(h6).astype(_np.int32) % 6
        f = (h6 - _np.floor(h6)).astype(_np.float32)
        p_v = (v * (1.0 - s1)).astype(_np.float32)
        q_v = (v * (1.0 - s1 * f)).astype(_np.float32)
        t_v = (v * (1.0 - s1 * (1.0 - f))).astype(_np.float32)

        r1 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5],
                        [v, q_v, p_v, p_v, t_v, v], default=v).astype(_np.float32)
        g1 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5],
                        [t_v, v, v, q_v, p_v, p_v], default=v).astype(_np.float32)
        b1 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5],
                        [p_v, p_v, t_v, v, v, q_v], default=v).astype(_np.float32)

        r1 = _np.clip(r1, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g1, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b1, 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Optical Luminosity Enhancement ───────────────────────────
        lg = float(luminosity_gain)
        lt = float(luminosity_threshold)
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        sat_excess = _np.maximum(0.0, s1 - lt).astype(_np.float32)
        sat_range  = max(1.0 - lt, 1e-6)
        lum_lift   = (lg * sat_excess / sat_range).astype(_np.float32)
        lum2       = _np.clip(lum1 + lum_lift, 0.0, 1.0).astype(_np.float32)
        scale2     = (lum2 / _np.maximum(lum1, 1e-6)).astype(_np.float32)
        r2 = _np.clip(r1 * scale2, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 * scale2, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 * scale2, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Dot Field Texture ────────────────────────────────────────
        rng = _np.random.default_rng(int(noise_seed))
        sp  = max(1, int(dot_spacing))
        jit = float(dot_jitter) * sp
        sig = max(0.5, float(dot_sigma))
        amp = float(dot_amplitude)

        bump_field = _np.zeros((h, w), dtype=_np.float32)

        ys = _np.arange(sp // 2, h + sp, sp)
        xs = _np.arange(sp // 2, w + sp, sp)
        for gi, cy_base in enumerate(ys):
            for gj, cx_base in enumerate(xs):
                cy = int(round(cy_base + rng.uniform(-jit, jit)))
                cx = int(round(cx_base + rng.uniform(-jit, jit)))
                # Checkerboard sign
                sign = 1.0 if (gi + gj) % 2 == 0 else -1.0

                # Bounding box for the Gaussian (3 sigma)
                r_min = max(0, cy - int(3 * sig) - 1)
                r_max = min(h, cy + int(3 * sig) + 2)
                c_min = max(0, cx - int(3 * sig) - 1)
                c_max = min(w, cx + int(3 * sig) + 2)
                if r_max <= r_min or c_max <= c_min:
                    continue

                rows = _np.arange(r_min, r_max, dtype=_np.float32)
                cols = _np.arange(c_min, c_max, dtype=_np.float32)
                dr = (rows - cy)[:, _np.newaxis]
                dc = (cols - cx)[_np.newaxis, :]
                gauss = sign * amp * _np.exp(-(dr**2 + dc**2) / (2.0 * sig**2))
                bump_field[r_min:r_max, c_min:c_max] += gauss.astype(_np.float32)

        lum2_full = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        lum3 = _np.clip(lum2_full + bump_field, 0.0, 1.0).astype(_np.float32)
        scale3 = (lum3 / _np.maximum(lum2_full, 1e-6)).astype(_np.float32)
        r3 = _np.clip(r2 * scale3, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 * scale3, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 * scale3, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        boosted_px = int((boost_s > 0.01).sum())
        lifted_px  = int((lum_lift > 0.001).sum())
        print(f"    Rysselberghe Chromatic Dot Field complete "
              f"(spectral_boost={spectral_boost:.2f}, "
              f"boosted_px={boosted_px}, "
              f"lifted_px={lifted_px})")


    def paint_atmospheric_recession_pass(
        self,
        recession_direction: str   = "top",
        haze_lift:           float = 0.08,
        desaturation:        float = 0.30,
        cool_shift_r:        float = 0.04,
        cool_shift_g:        float = 0.01,
        cool_shift_b:        float = 0.08,
        near_fraction:       float = 0.25,
        far_fraction:        float = 0.85,
        opacity:             float = 0.65,
    ) -> None:
        r"""Paint Atmospheric Recession -- session 259 improvement.

        THREE-STAGE AERIAL PERSPECTIVE SIMULATION:

        Aerial perspective (atmospheric perspective) is the optical phenomenon
        first described systematically by Leonardo da Vinci: objects at greater
        distances appear lighter, more desaturated, and shifted toward blue-grey
        relative to near objects, as the air column between viewer and subject
        scatters light.  The three physical mechanisms -- (1) luminance lift from
        forward-scattered light filling in shadows, (2) saturation loss from
        atmospheric grey averaging, and (3) cool Rayleigh scattering shifting
        distant hues toward blue -- are modelled in three independent stages.

        The pass defines a linear depth-weight field across the canvas in a
        chosen recession direction:
          weight(row, col) in [0, 1]  (0=near, 1=far)
        All three effects are applied proportional to this weight, interpolated
        between near_fraction (the weight at the nominally near edge of the
        canvas) and far_fraction (the weight at the far edge).

        Stage 1 DISTANCE HAZE LIFT: Push pixel luminance up proportionally to
        depth weight.  The physical mechanism is forward light scatter that adds
        a luminous haze to distant surfaces, reducing apparent shadow depth:
          lum_lift = haze_lift * w
          lum_new = clip(lum + lum_lift, 0, 1)
          scale = lum_new / (lum + 1e-6)
          R *= scale, G *= scale, B *= scale
        NOVEL: (a) DISTANCE-WEIGHT-PROPORTIONAL LUMINANCE LIFT AS A MODEL OF
        ATMOSPHERIC FORWARD-SCATTER HAZE -- first pass to apply a spatially-
        varying luminance increase driven purely by a linear distance-weight
        field; paint_tonal_key_pass (s255) shifts the global key via histogram
        percentile without any spatial gradient; no prior pass applies a
        linearly-weighted per-pixel luminance boost along a spatial depth axis.

        Stage 2 ATMOSPHERIC DESATURATION: Reduce saturation proportional to
        depth weight.  Distant atmospheric averaging dilutes chromatic contrast:
          HSV: s_new = s * (1 - desaturation * w)
        Reconstruct RGB from modified saturation.
        NOVEL: (b) DEPTH-WEIGHT-PROPORTIONAL SATURATION REDUCTION ALONG A
        SPATIAL RECESSION AXIS AS ATMOSPHERIC GREY AVERAGING -- first pass
        to reduce HSV saturation in proportion to a spatial depth weight field;
        morandi_dusty_vessel_pass (s258) applies luminance-weighted saturation
        reduction as a dust veil; no prior pass applies saturation reduction
        as a function of position along a user-defined spatial recession axis.

        Stage 3 COOL AERIAL SHIFT: Blend pixel RGB toward a pale cool aerial
        grey (modelling Rayleigh scattering bias toward shorter wavelengths)
        in proportion to depth weight:
          aerial = (R + cool_shift_r * w, G + cool_shift_g * w, B + cool_shift_b * w)
          Out = blend(In, aerial, cool_weight = w * opacity_local)
        Effectively: R nudged down slightly (warm reduced at distance), B nudged
        up (cool increased at distance), producing the characteristic blue-grey
        haze of distant landscape planes.
        NOVEL: (c) SPATIALLY-VARYING RGB COOL-SHIFT ALONG A DEPTH-AXIS WEIGHT
        FIELD AS RAYLEIGH-SCATTER CHROMATIC RECESSION -- first pass to apply a
        distance-proportional per-channel RGB shift (R down, B up) along a
        user-defined recession axis to simulate atmospheric chromatic cooling;
        paint_shadow_bleed_pass (s257) blends shadow-zone pixels toward a warm
        bounce colour based on proximity to bright pixels; no prior pass applies
        a spatially-varying cool RGB shift proportional to a linear depth-weight
        gradient.

        recession_direction : "top" (top=far), "bottom" (bottom=far),
                              "left" (left=far), "right" (right=far).
        haze_lift           : Max luminance increase at far edge (0-1).
        desaturation        : Max saturation reduction fraction at far edge (0-1).
        cool_shift_r/g/b    : Per-channel max shift at far edge (positive = add).
        near_fraction       : Depth weight at the near canvas edge (0-1).
        far_fraction        : Depth weight at the far canvas edge (0-1).
        opacity             : Final composite opacity.
        """
        import numpy as _np

        print("    Paint Atmospheric Recession pass (session 259 improvement)...")

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Build depth-weight field ───────────────────────────────────────────
        nf = float(near_fraction)
        ff = float(far_fraction)
        d = str(recession_direction).lower()

        if d in ("top", "up"):
            # top = far; row 0 = far weight
            row_t = _np.linspace(ff, nf, h, dtype=_np.float32)
            weight = _np.broadcast_to(row_t[:, _np.newaxis], (h, w)).copy()
        elif d in ("bottom", "down"):
            row_t = _np.linspace(nf, ff, h, dtype=_np.float32)
            weight = _np.broadcast_to(row_t[:, _np.newaxis], (h, w)).copy()
        elif d == "left":
            col_t = _np.linspace(ff, nf, w, dtype=_np.float32)
            weight = _np.broadcast_to(col_t[_np.newaxis, :], (h, w)).copy()
        else:  # right
            col_t = _np.linspace(nf, ff, w, dtype=_np.float32)
            weight = _np.broadcast_to(col_t[_np.newaxis, :], (h, w)).copy()

        weight = weight.astype(_np.float32)

        # ── Stage 1: Distance Haze Lift ────────────────────────────────────────
        hl = float(haze_lift)
        lum_lift = (hl * weight).astype(_np.float32)
        lum1 = _np.clip(lum + lum_lift, 0.0, 1.0).astype(_np.float32)
        scale1 = (lum1 / _np.maximum(lum, 1e-6)).astype(_np.float32)
        r1 = _np.clip(r0 * scale1, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * scale1, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * scale1, 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Atmospheric Desaturation (HSV) ───────────────────────────
        cmax = _np.maximum(_np.maximum(r1, g1), b1)
        cmin = _np.minimum(_np.minimum(r1, g1), b1)
        delta = (cmax - cmin).astype(_np.float32)
        v = cmax.copy()
        s = _np.where(cmax > 1e-6, delta / (cmax + 1e-8), 0.0).astype(_np.float32)

        eps = 1e-8
        hue = _np.zeros((h, w), dtype=_np.float32)
        m_r = (cmax == r1) & (delta > eps)
        m_g = (cmax == g1) & (delta > eps)
        m_b = (cmax == b1) & (delta > eps)
        hue[m_r] = (((g1[m_r] - b1[m_r]) / (delta[m_r] + eps)) % 6.0) / 6.0
        hue[m_g] = (((b1[m_g] - r1[m_g]) / (delta[m_g] + eps)) + 2.0) / 6.0
        hue[m_b] = (((r1[m_b] - g1[m_b]) / (delta[m_b] + eps)) + 4.0) / 6.0
        hue = _np.clip(hue, 0.0, 1.0)

        ds = float(desaturation)
        s2 = _np.clip(s * (1.0 - ds * weight), 0.0, 1.0).astype(_np.float32)

        # Rebuild RGB from (hue, s2, v)
        h6 = hue * 6.0
        i = _np.floor(h6).astype(_np.int32) % 6
        f = (h6 - _np.floor(h6)).astype(_np.float32)
        p_v = (v * (1.0 - s2)).astype(_np.float32)
        q_v = (v * (1.0 - s2 * f)).astype(_np.float32)
        t_v = (v * (1.0 - s2 * (1.0 - f))).astype(_np.float32)

        r2 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5],
                        [v, q_v, p_v, p_v, t_v, v], default=v).astype(_np.float32)
        g2 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5],
                        [t_v, v, v, q_v, p_v, p_v], default=v).astype(_np.float32)
        b2 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5],
                        [p_v, p_v, t_v, v, v, q_v], default=v).astype(_np.float32)

        r2 = _np.clip(r2, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g2, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b2, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Cool Aerial Shift ────────────────────────────────────────
        csr = float(cool_shift_r)
        csg = float(cool_shift_g)
        csb = float(cool_shift_b)
        r3 = _np.clip(r2 - csr * weight, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 - csg * weight, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 + csb * weight, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        far_px = int((weight > 0.6).sum())
        print(f"    Atmospheric Recession complete "
              f"(direction={recession_direction}, "
              f"haze_lift={haze_lift:.2f}, "
              f"far_px={far_px})")

    def foujita_milky_ground_contour_pass(
        self,
        ivory_r:            float = 0.97,
        ivory_g:            float = 0.95,
        ivory_b:            float = 0.88,
        ivory_threshold:    float = 0.70,
        ivory_strength:     float = 0.55,
        contour_threshold:  float = 0.06,
        contour_width:      int   = 1,
        contour_darkness:   float = 0.72,
        hatch_spacing:      int   = 4,
        hatch_amplitude:    float = 0.035,
        hatch_sigma:        float = 0.8,
        noise_seed:         int   = 260,
        opacity:            float = 0.78,
    ) -> None:
        r"""Tsuguharu Foujita Milky Ground Contour -- session 260, 171st distinct mode.

        THREE-STAGE JAPANESE-FRENCH MILKY IVORY TECHNIQUE INSPIRED BY
        FOUJITA'S OIL PAINTINGS (1918-1960):

        Tsuguharu Foujita (1886-1968) was the Japanese painter of the Ecole de
        Paris celebrated for a unique oil technique combining Japanese ink-drawing
        precision with Western oil paint.  His most famous innovation was a
        luminous milky-white ground achieved by repeated fine sanding of ivory-
        tinted titanium-white grounds and glazing with creamy, almost dry paint.
        This gave his nudes, cats, and figures a porcelain glow distinct from all
        Western painting.  He applied contour lines not with charcoal but with a
        very fine sable brush in oil paint -- thin, unwavering Japanese-ink lines
        that defined volumes without chiaroscuro shading.  Across pale surfaces
        he built fine directional micro-texture marks (like cat-fur hatching) using
        individual tiny brushmarks aligned to surface contour and hair direction.
        The three stages below model these three phenomena.

        Stage 1 MILKY IVORY GROUND LIFT: Foujita's prepared grounds glowed with
        a warm ivory luminosity from within the paint film.  Model this by lifting
        highlight regions toward the target ivory color (ivory_r, ivory_g, ivory_b).
        For each pixel, compute:
          lum = 0.299*R + 0.587*G + 0.114*B
          If lum > ivory_threshold:
            weight = ivory_strength * (lum - ivory_threshold) / (1 - ivory_threshold + 1e-6)
            R_new = R * (1 - weight) + ivory_r * weight
            G_new = G * (1 - weight) + ivory_g * weight
            B_new = B * (1 - weight) + ivory_b * weight
          Else: pass through unchanged
        This concentrates the ivory warmth in the luminous highlight passages,
        precisely where Foujita's prepared ground showed through the thin paint.
        NOVEL: (a) HIGHLIGHT-TARGETED WARM IVORY TONE DRIFT PROPORTIONAL TO
        LUMINANCE ABOVE A THRESHOLD -- first pass to blend highlights specifically
        toward a target ivory color with per-pixel weight proportional to how far
        each pixel's luminance exceeds the threshold; paint_tonal_key_pass (s255)
        shifts whole histogram; no prior pass isolates above-threshold pixels and
        blends them toward a specific warm ivory target color.

        Stage 2 JAPANESE INK CONTOUR TRACING: Foujita's sable-brush ink lines
        are the structural skeleton of his images -- placed precisely at tonal
        boundaries where dark meets light.  Model this by computing a Sobel-based
        gradient magnitude of the current luminance channel, normalising it, and
        darkening pixels where the normalised gradient exceeds contour_threshold:
          gx = Sobel(lum, axis=1)    (horizontal derivative)
          gy = Sobel(lum, axis=0)    (vertical derivative)
          grad = sqrt(gx^2 + gy^2)
          grad_norm = grad / (grad.max() + 1e-6)  (in [0,1])
          contour_mask = (grad_norm > contour_threshold).astype(float)
          if contour_width > 1: dilate mask by contour_width pixels (binary dilation)
          darkness_weight = contour_darkness * contour_mask
          R_new = R * (1 - darkness_weight)   (darkening toward black)
          G_new = G * (1 - darkness_weight)
          B_new = B * (1 - darkness_weight)
        This produces hair-thin dark contours at all significant tonal transitions,
        exactly replicating the structural role of Foujita's sable-brush oil lines.
        NOVEL: (b) SOBEL-GRADIENT CONTOUR MAP DARKENED AS JAPANESE-INK SABLE LINE
        SIMULATION -- first pass to use normalised Sobel gradient magnitude to
        construct a binary contour mask and apply multiplicative darkening along
        that mask to simulate Japanese-ink precision line drawing in oil;
        weyden_angular_shadow_pass (s246) uses directional lighting to build
        edge shadows; no prior pass uses a normalised Sobel edge map as an
        explicit contour-line darkening mask emulating Japanese ink-brush lines.

        Stage 3 DIRECTIONAL MICRO-TEXTURE HATCHING: Foujita built fine
        directional marks across pale zones -- fur, skin, and fabric surfaces
        show individual hairline marks aligned to the local surface normal and
        direction of hair/fibre growth.  Model this by computing local gradient
        orientation from the luminance image, then generating a sinusoidal
        hatching pattern oriented perpendicular to the local gradient (i.e.,
        along contours, not across them) and modulated by a pale-zone mask:
          pale_mask = clip(1 - 4*(lum - 0.75)^2, 0, 1)  (bell centred on lum=0.75)
          angle = atan2(gy, gx + 1e-6)   (local orientation angle)
          For each pixel (y, x):
            hatch_phase = x * cos(angle[y,x]) + y * sin(angle[y,x])
            hatch_val = sin(2*pi * hatch_phase / hatch_spacing)
            luminance_bump = hatch_amplitude * hatch_val * pale_mask[y,x]
          Apply luminance bump: R += bump, G += bump, B += bump (clipped)
        This creates fine parallel micro-texture lines across the bright pale zones
        while leaving shadows and contours unaffected -- exactly Foujita's surface.
        NOVEL: (c) ORIENTATION-ALIGNED SINUSOIDAL HATCHING IN PALE ZONES DERIVED
        FROM LOCAL SOBEL GRADIENT ANGLE -- first pass to use per-pixel atan2(gy, gx)
        as the hatch orientation and a bell-function pale-zone mask centred on a
        mid-high luminance value; paint_granulation_pass (s258) adds chromatic
        frequency-based texture; no prior pass computes per-pixel sine hatch phase
        from local gradient orientation to simulate directional brushmark micro-
        texture in the light zones only.
        """
        print("    Foujita Milky Ground Contour pass (session 260, 171st mode)...")

        import math as _math
        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Milky Ivory Ground Lift ──────────────────────────────────
        ir = float(ivory_r)
        ig = float(ivory_g)
        ib = float(ivory_b)
        thr = float(ivory_threshold)
        iso = float(ivory_strength)

        above = _np.maximum(0.0, lum - thr).astype(_np.float32)
        denom = max(1.0 - thr, 1e-6)
        w_ivory = _np.clip(iso * above / denom, 0.0, 1.0).astype(_np.float32)

        r1 = (r0 * (1.0 - w_ivory) + ir * w_ivory).astype(_np.float32)
        g1 = (g0 * (1.0 - w_ivory) + ig * w_ivory).astype(_np.float32)
        b1 = (b0 * (1.0 - w_ivory) + ib * w_ivory).astype(_np.float32)

        # ── Stage 2: Japanese Ink Contour Tracing ─────────────────────────────
        from scipy.ndimage import sobel as _sobel, binary_dilation as _bdil

        gy_raw = _sobel(lum, axis=0).astype(_np.float32)
        gx_raw = _sobel(lum, axis=1).astype(_np.float32)
        grad = _np.sqrt(gx_raw ** 2 + gy_raw ** 2).astype(_np.float32)
        gmax = float(grad.max())
        grad_norm = (grad / (gmax + 1e-6)).astype(_np.float32)

        ct = float(contour_threshold)
        contour_mask = (grad_norm > ct).astype(_np.float32)

        cw = int(contour_width)
        if cw > 1:
            struct = _np.ones((cw, cw), dtype=bool)
            contour_mask = _bdil(contour_mask > 0, structure=struct).astype(_np.float32)

        cd = float(contour_darkness)
        dark_weight = cd * contour_mask
        r2 = _np.clip(r1 * (1.0 - dark_weight), 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 * (1.0 - dark_weight), 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 * (1.0 - dark_weight), 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Directional Micro-Texture Hatching ───────────────────────
        ha = float(hatch_amplitude)
        hs = int(max(hatch_spacing, 2))
        hsg = float(hatch_sigma)

        # pale_zone bell centred on lum=0.75
        pale_mask = _np.clip(1.0 - 4.0 * (lum - 0.75) ** 2, 0.0, 1.0).astype(_np.float32)
        if hsg > 0.0:
            pale_mask = _gf(pale_mask, sigma=hsg).astype(_np.float32)

        # local gradient orientation (angle of steepest ascent)
        angle = _np.arctan2(gy_raw, gx_raw + 1e-8).astype(_np.float32)

        ys = _np.arange(h, dtype=_np.float32)
        xs = _np.arange(w, dtype=_np.float32)
        xg, yg = _np.meshgrid(xs, ys)

        cos_a = _np.cos(angle).astype(_np.float32)
        sin_a = _np.sin(angle).astype(_np.float32)

        # hatch phase: project (x, y) onto direction perpendicular to gradient
        # (i.e., along iso-luminance contours): direction = (-sin, cos)
        hatch_phase = (-sin_a * xg + cos_a * yg).astype(_np.float32)
        hatch_val = _np.sin(2.0 * _np.float32(_math.pi) * hatch_phase / hs).astype(_np.float32)
        bump = (ha * hatch_val * pale_mask).astype(_np.float32)

        r3 = _np.clip(r2 + bump, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 + bump, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 + bump, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        contour_px = int(contour_mask.sum())
        pale_px    = int((pale_mask > 0.1).sum())
        lifted_px  = int((w_ivory > 0.05).sum())
        print(f"    Foujita Milky Ground Contour complete "
              f"(lifted_px={lifted_px}, contour_px={contour_px}, pale_px={pale_px})")


    def paint_sfumato_contour_dissolution_pass(
        self,
        edge_sigma:        float = 1.2,
        edge_threshold:    float = 0.04,
        blur_sigma:        float = 2.5,
        dissolve_strength: float = 0.70,
        shadow_bias:       float = 0.25,
        noise_seed:        int   = 260,
        opacity:           float = 0.65,
    ) -> None:
        r"""Sfumato Contour Dissolution -- session 260 improvement.

        THREE-STAGE EDGE-TARGETED SFUMATO SOFTENING INSPIRED BY LEONARDO DA
        VINCI'S SMOKELESS BLENDING TECHNIQUE (c.1490-1517):

        Leonardo da Vinci described sfumato (Italian: smoke) as a technique in
        which contours are dissolved rather than drawn: colours blend at their
        edges without hard lines, transitions disappear gradually like smoke,
        and forms emerge from shadow rather than being bounded by outline.
        Technically, Leonardo achieved this by dozens of near-invisible thin
        glaze strokes at boundary zones, each fractionally shifting tone and
        hue without ever asserting a hard edge.  The result is that forms appear
        to emerge from or dissolve into their backgrounds -- edges are alive and
        ambiguous rather than fixed.  No prior pass specifically targets DETECTED
        EDGE ZONES for selective softening; broad blur passes affect the whole
        image uniformly.  This pass implements sfumato as an edge-aware,
        spatially-selective blur that dissolves ONLY the boundary zones while
        leaving interior textured areas and fully dark shadows intact.

        Stage 1 EDGE DETECTION AND ZONE MAP: Compute a Gaussian-smoothed
        luminance gradient using a fine-scale Sobel after Gaussian pre-smoothing:
          lum_smooth = gaussian_filter(lum, sigma=edge_sigma)
          gx = Sobel(lum_smooth, axis=1)
          gy = Sobel(lum_smooth, axis=0)
          edge_map = sqrt(gx^2 + gy^2)
          edge_map_norm = edge_map / (edge_map.max() + 1e-6)  (in [0,1])
          sfumato_zone = clip(edge_map_norm / (edge_threshold + 1e-6), 0, 1)
        This isolates the boundary-transition zone around every tonal edge.
        NOVEL: (a) GAUSSIAN-PRE-SMOOTHED SOBEL EDGE MAP AS A SPATIALLY-SELECTIVE
        BLUR MASK TARGETING SFUMATO DISSOLUTION ZONES -- first pass to combine
        a scale-controlled Gaussian pre-smooth with Sobel to produce a soft
        sfumato-zone mask; paint_granulation_pass (s258) uses frequency
        decomposition for texture; no prior pass uses a Gaussian-smoothed Sobel
        to define a per-pixel zone mask that drives a spatially-selective blur
        rather than a global one.

        Stage 2 EDGE-TARGETED GAUSSIAN BLUR: Apply a Gaussian blur to the full
        RGB image (sigma = blur_sigma) and blend it with the original using the
        sfumato_zone mask as the blend weight:
          blurred_R, G, B = gaussian_filter(R, G, B, sigma=blur_sigma)
          sfumato_blend = sfumato_zone * dissolve_strength
          R_soft = R * (1 - sfumato_blend) + blurred_R * sfumato_blend
          G_soft = G * (1 - sfumato_blend) + blurred_G * sfumato_blend
          B_soft = B * (1 - sfumato_blend) + blurred_B * sfumato_blend
        Interior zones (low edge response) receive no blur; boundary zones receive
        blur weighted by how strongly they read as transitions.  This produces
        locally soft edges while preserving interior textural clarity.
        NOVEL: (b) PER-PIXEL SPATIALLY-VARYING GAUSSIAN BLUR WEIGHTED BY EDGE-
        ZONE MAP FOR SFUMATO EDGE DISSOLUTION -- first pass to use a continuous
        edge-response field (rather than binary mask or global param) to
        interpolate between original and blurred versions at each pixel;
        wet_on_wet_bleeding_pass applies diffusion globally; no prior pass uses
        per-pixel edge-response magnitude as a continuous blend weight for a
        spatially-selective Gaussian softening operation at detected boundaries.

        Stage 3 SHADOW-BIAS TONAL DEEPENING: In Leonardo's sfumato the
        shadow sides of forms dissolve most strongly -- they go darker as well
        as softer, deepening the illusion of recession.  Model this by applying
        a luminance-dependent multiplicative darkening within the sfumato zone:
          shadow_weight = sfumato_zone * shadow_bias * (1 - lum)
          R_final = R_soft * (1 - shadow_weight)
          G_final = G_soft * (1 - shadow_weight)
          B_final = B_soft * (1 - shadow_weight)
        High sfumato_zone + low luminance (dark edge region) receives most
        darkening; bright edge zones (rim lights) receive much less.
        NOVEL: (c) SFUMATO-ZONE-GATED LUMINANCE-INVERSE SHADOW DEEPENING --
        first pass to multiply the sfumato_zone mask by (1 - lum) to produce a
        shadow-deepening weight that is strongest at dark sfumato boundary zones;
        warm_shadow_lift_pass lifts shadows globally; no prior pass uses the
        product of a per-pixel sfumato-zone weight and (1-luminance) as the
        driving input for a multiplicative darkening of shadow-edge boundary pixels.
        """
        print("    Sfumato Contour Dissolution pass (session 260 improvement)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from scipy.ndimage import sobel as _sobel
        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Edge Detection and Zone Map ──────────────────────────────
        es = max(float(edge_sigma), 0.3)
        lum_smooth = _gf(lum, sigma=es).astype(_np.float32)

        gy_raw = _sobel(lum_smooth, axis=0).astype(_np.float32)
        gx_raw = _sobel(lum_smooth, axis=1).astype(_np.float32)
        edge_map = _np.sqrt(gx_raw ** 2 + gy_raw ** 2).astype(_np.float32)
        emax = float(edge_map.max())
        edge_norm = (edge_map / (emax + 1e-6)).astype(_np.float32)

        et = max(float(edge_threshold), 1e-6)
        sfumato_zone = _np.clip(edge_norm / et, 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Edge-Targeted Gaussian Blur ──────────────────────────────
        bs = max(float(blur_sigma), 0.5)
        r_blur = _gf(r0, sigma=bs).astype(_np.float32)
        g_blur = _gf(g0, sigma=bs).astype(_np.float32)
        b_blur = _gf(b0, sigma=bs).astype(_np.float32)

        ds = float(dissolve_strength)
        sfumato_blend = (sfumato_zone * ds).astype(_np.float32)

        r1 = _np.clip(r0 * (1.0 - sfumato_blend) + r_blur * sfumato_blend, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * (1.0 - sfumato_blend) + g_blur * sfumato_blend, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * (1.0 - sfumato_blend) + b_blur * sfumato_blend, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Shadow-Bias Tonal Deepening ──────────────────────────────
        sb = float(shadow_bias)
        shadow_weight = _np.clip(sfumato_zone * sb * (1.0 - lum), 0.0, 1.0).astype(_np.float32)

        r2 = _np.clip(r1 * (1.0 - shadow_weight), 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 * (1.0 - shadow_weight), 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 * (1.0 - shadow_weight), 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        edge_px = int((sfumato_zone > 0.5).sum())
        deep_px = int((shadow_weight > 0.1).sum())
        print(f"    Sfumato Contour Dissolution complete "
              f"(edge_zone_px={edge_px}, deepened_px={deep_px}, "
              f"blur_sigma={blur_sigma:.1f}, dissolve={dissolve_strength:.2f})")


    def paint_triple_zone_glaze_pass(
        self,
        shadow_pivot:     float = 0.28,
        highlight_pivot:  float = 0.68,
        zone_feather:     float = 0.12,
        shadow_r:         float = 0.25,
        shadow_g:         float = 0.28,
        shadow_b:         float = 0.48,
        shadow_opacity:   float = 0.12,
        mid_r:            float = 0.72,
        mid_g:            float = 0.68,
        mid_b:            float = 0.52,
        mid_opacity:      float = 0.08,
        highlight_r:      float = 0.92,
        highlight_g:      float = 0.88,
        highlight_b:      float = 0.78,
        highlight_opacity: float = 0.10,
        feather_sigma:    float = 8.0,
        noise_seed:       int   = 261,
        opacity:          float = 0.72,
    ) -> None:
        r"""Triple Zone Glaze -- session 261 artistic improvement.

        THREE-STAGE INDEPENDENT ZONE GLAZING INSPIRED BY OLD MASTER OIL
        GLAZING PRACTICE (Titian, Rubens, Rembrandt, c.1500-1700):

        Traditional oil glazing applies thin transparent colour layers over
        dried paint to modify colour relationships within specific tonal zones.
        Titian would apply a warm amber glaze selectively in the midtone flesh
        passages; Rembrandt would deepen shadow zones with a cool brown-black
        transparent scumble while leaving highlights untouched; Vermeer applied
        a cool blue-grey glaze in shadow zones while warming highlight passages
        with a cream veil.  In each case the glaze colours for shadow, midtone,
        and highlight zones were INDEPENDENT colour choices reflecting the
        painter's reading of the specific light quality -- not mechanically
        opposite warm/cool.  No prior pass implements three independently
        configurable zone glazes with Gaussian-feathered zone boundary masks.

        Stage 1 THREE-ZONE LUMINANCE SEGMENTATION WITH GAUSSIAN FEATHERING:
        Compute three smooth zone masks with Gaussian-feathered boundaries:
          raw_shadow    = clip((shadow_pivot - lum) / zone_feather, 0, 1)
          raw_highlight = clip((lum - highlight_pivot) / zone_feather, 0, 1)
          raw_mid       = clip(1 - raw_shadow - raw_highlight, 0, 1)
          shadow_mask    = gaussian_filter(raw_shadow,    sigma=feather_sigma)
          highlight_mask = gaussian_filter(raw_highlight, sigma=feather_sigma)
          mid_mask       = gaussian_filter(raw_mid,       sigma=feather_sigma)
          (Each mask is renormalized to [0, 1] after Gaussian smoothing.)
        Gaussian feathering prevents hard zone boundaries and ensures smooth
        transitions between independently glazed tonal zones.
        NOVEL: (a) GAUSSIAN-FEATHERED THREE-ZONE LUMINANCE SEGMENTATION WITH
        INDEPENDENT MASK PER ZONE -- first pass to apply Gaussian blur to raw
        luminance-threshold zone masks before using them as glaze opacity weights,
        creating smooth zone boundary transitions; paint_split_toning uses linear
        ramp transitions without Gaussian smoothing; no prior pass Gaussian-blurs
        the zone membership masks themselves to create spatially-smoothed zone
        boundaries before compositing.

        Stage 2 INDEPENDENT ZONE GLAZE APPLICATION:
        Apply a distinct transparent glaze colour to each zone:
          glaze_R = R + shadow_mask*shadow_opacity*(shadow_r - R)
                    + mid_mask*mid_opacity*(mid_r - R)
                    + highlight_mask*highlight_opacity*(highlight_r - R)
          (same formula for G, B channels)
        Each zone glaze is a transparent screen toward its target colour, with
        its own opacity.  Additive zone contributions are summed per channel.
        NOVEL: (b) THREE INDEPENDENT TARGET-COLOR TRANSPARENT GLAZES APPLIED
        SIMULTANEOUSLY TO THREE LUMINANCE ZONES -- first pass to apply three
        separate color-targeted glazes (each with its own (R,G,B) target and
        opacity) to three independently-segmented luminance zones in a single
        pass; paint_split_toning applies opposing incremental offsets to two
        zones; paint_glaze_gradient applies ONE color over a spatial gradient;
        no prior pass applies THREE distinct target colors to three independently
        controlled tonal zones simultaneously.

        Stage 3 ZONE-BOUNDARY ANTI-CONTAMINATION FEATHERING:
        At pixels where two zone masks are both significant (both > 0.15),
        reduce glaze opacity proportionally at the blend zone to prevent
        colour fringing from zone overlap:
          blend_conflict = shadow_mask * highlight_mask
                         + shadow_mask * mid_mask * 0.5
                         + mid_mask * highlight_mask * 0.5
          feather_gate   = clip(1 - blend_conflict * 2.5, 0.3, 1.0)
          final_RGB = original_RGB * (1 - feather_gate) + glaze_RGB * feather_gate
        This prevents midtone-to-highlight boundaries from showing colour
        fringing where two glaze colours partially overlap.
        NOVEL: (c) MULTI-ZONE OVERLAP CONFLICT DETECTION AND OPACITY REDUCTION --
        first pass to compute a zone-overlap conflict weight (product of two or
        more zone masks) and use it to attenuate glaze opacity at zone boundaries,
        preventing colour fringing from simultaneous zone membership; no prior
        pass detects or manages the case where a pixel contributes to multiple
        zone glazes simultaneously and reduces composite strength accordingly.
        """
        print("    Triple Zone Glaze pass (session 261 improvement)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Three-Zone Segmentation with Gaussian Feathering ─────────
        sp  = float(shadow_pivot)
        hp  = float(highlight_pivot)
        zf  = max(float(zone_feather), 1e-4)
        fsg = max(float(feather_sigma), 0.5)

        raw_shadow    = _np.clip((sp - lum) / zf, 0.0, 1.0).astype(_np.float32)
        raw_highlight = _np.clip((lum - hp) / zf, 0.0, 1.0).astype(_np.float32)
        raw_mid       = _np.clip(1.0 - raw_shadow - raw_highlight, 0.0, 1.0).astype(_np.float32)

        shadow_mask    = _gf(raw_shadow,    sigma=fsg).astype(_np.float32)
        highlight_mask = _gf(raw_highlight, sigma=fsg).astype(_np.float32)
        mid_mask       = _gf(raw_mid,       sigma=fsg).astype(_np.float32)

        # Renormalize each mask to [0, 1] after blurring
        shadow_mask    = _np.clip(shadow_mask    / (shadow_mask.max()    + 1e-6), 0.0, 1.0)
        highlight_mask = _np.clip(highlight_mask / (highlight_mask.max() + 1e-6), 0.0, 1.0)
        mid_mask       = _np.clip(mid_mask       / (mid_mask.max()       + 1e-6), 0.0, 1.0)

        # ── Stage 2: Independent Zone Glaze Application ───────────────────────
        sr = float(shadow_r);  sg_c = float(shadow_g); sb = float(shadow_b)
        so = float(shadow_opacity)
        mr = float(mid_r);     mg = float(mid_g);      mb = float(mid_b)
        mo = float(mid_opacity)
        hr = float(highlight_r); hg = float(highlight_g); hb = float(highlight_b)
        ho = float(highlight_opacity)

        glaze_r = (r0
                   + shadow_mask    * so * (sr - r0)
                   + mid_mask       * mo * (mr - r0)
                   + highlight_mask * ho * (hr - r0))
        glaze_g = (g0
                   + shadow_mask    * so * (sg_c - g0)
                   + mid_mask       * mo * (mg - g0)
                   + highlight_mask * ho * (hg - g0))
        glaze_b = (b0
                   + shadow_mask    * so * (sb - b0)
                   + mid_mask       * mo * (mb - b0)
                   + highlight_mask * ho * (hb - b0))

        glaze_r = _np.clip(glaze_r, 0.0, 1.0).astype(_np.float32)
        glaze_g = _np.clip(glaze_g, 0.0, 1.0).astype(_np.float32)
        glaze_b = _np.clip(glaze_b, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Zone-Boundary Anti-Contamination Feathering ──────────────
        blend_conflict = (shadow_mask * highlight_mask
                          + shadow_mask * mid_mask * 0.5
                          + mid_mask * highlight_mask * 0.5).astype(_np.float32)
        feather_gate = _np.clip(1.0 - blend_conflict * 2.5, 0.3, 1.0).astype(_np.float32)

        r1 = _np.clip(r0 * (1.0 - feather_gate) + glaze_r * feather_gate, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * (1.0 - feather_gate) + glaze_g * feather_gate, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * (1.0 - feather_gate) + glaze_b * feather_gate, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        shadow_px    = int((shadow_mask > 0.1).sum())
        mid_px       = int((mid_mask > 0.1).sum())
        highlight_px = int((highlight_mask > 0.1).sum())
        conflict_px  = int((blend_conflict > 0.1).sum())
        print(f"    Triple Zone Glaze complete "
              f"(shadow_px={shadow_px}, mid_px={mid_px}, "
              f"highlight_px={highlight_px}, conflict_feathered_px={conflict_px})")

    def sisley_silver_veil_pass(
        self,
        sky_fraction:       float = 0.42,
        sky_r:              float = 0.84,
        sky_g:              float = 0.85,
        sky_b:              float = 0.88,
        sky_strength:       float = 0.38,
        haze_center:        float = 0.56,
        haze_band:          float = 0.18,
        haze_r:             float = 0.78,
        haze_g:             float = 0.78,
        haze_b:             float = 0.81,
        haze_strength:      float = 0.32,
        sky_blur_sigma:     float = 6.0,
        sky_blur_opacity:   float = 0.48,
        noise_seed:         int   = 261,
        opacity:            float = 0.78,
    ) -> None:
        r"""Alfred Sisley Silver Veil -- session 261, 172nd distinct mode.

        THREE-STAGE SILVERY IMPRESSIONIST LANDSCAPE TECHNIQUE INSPIRED BY
        ALFRED SISLEY'S ATMOSPHERIC PAINTING (c.1870-1899):

        Alfred Sisley (1839-1899), the most consistently atmospheric of the
        Impressionists, painted the same reaches of the Seine and Loing rivers
        for thirty years, developing three defining painterly qualities: a
        characteristic cool silver sky that sets the tonal key of the whole
        picture, a neutral silver mist at middle distances that softens and
        desaturates the midground without introducing warm or cool bias, and
        predominantly horizontal stroke direction in sky and water that gives
        his paintings the quality of wind-driven cloud movement.

        Stage 1 SILVER SKY BAND: Sisley devoted more canvas to sky than any
        other Impressionist, treating it as a cool silver-grey field with an
        occasional warm horizon accent.  Model this by applying a cool silver
        tint (sky_r, sky_g, sky_b) to the upper sky_fraction of the image with
        a linear vertical weight that is strongest at the top and zero at the
        sky boundary:
          sky_weight(y) = clip(1 - y / (sky_fraction * H), 0, 1) * sky_strength
          R_new = R * (1 - sky_weight) + sky_r * sky_weight
          G_new = G * (1 - sky_weight) + sky_g * sky_weight
          B_new = B * (1 - sky_weight) + sky_b * sky_weight
        NOVEL: (a) VERTICAL-ZONE-BOUNDED ADDITIVE SILVER TINT IN UPPER HEIGHT
        FRACTION -- first pass to apply a spatially-bounded tint limited to a
        configurable upper height fraction (sky_fraction) with a linear vertical
        weight gradient strongest at the top edge and zero at the zone boundary;
        paint_glaze_gradient_pass applies a multiplicative glaze over the FULL
        CANVAS along an axis; paint_atmospheric_recession_pass shifts color
        temperature from far to near; no prior pass applies an additive blend
        toward a specific silver target limited to a configurable TOP FRACTION
        of the canvas height with linear weight decay to zero at the fraction
        boundary.

        Stage 2 MIDGROUND SILVER ATMOSPHERIC HAZE: At middle distances, Sisley
        applied a thin neutral-grey veil that softens midground colours toward
        a cool silver -- neither warm nor cool, simply neutral and atmospheric.
        Model this via a Gaussian bell-curve weight centered on the midtone
        luminance (haze_center), blending pixels in that luminance band toward
        the silver target (haze_r, haze_g, haze_b):
          bell_weight = exp(-0.5 * ((lum - haze_center) / haze_band)^2) * haze_strength
          R_new = R * (1 - bell_weight) + haze_r * bell_weight
          G_new = G * (1 - bell_weight) + haze_g * bell_weight
          B_new = B * (1 - bell_weight) + haze_b * bell_weight
        NOVEL: (b) GAUSSIAN BELL LUMINANCE WINDOW BLENDING TOWARD A NEUTRAL
        COOL SILVER TARGET AT THE MID-LUMINANCE BAND -- first pass to use a
        Gaussian bell centered at lum=0.56 (mid-luminance) to drive a blend
        toward a specific cool-neutral silver (near-grey with slight blue bias),
        modelling Sisley's atmospheric silver mist; chirico Stage 2 uses a
        similar bell formula but drives toward warm sienna; foujita Stage 1 uses
        a one-sided above-threshold ramp; no prior pass uses a Gaussian bell
        centered on mid-luminance to blend toward a cool neutral silver as
        opposed to a warm or strongly hued target.

        Stage 3 HORIZONTAL SKY MOTION BLUR: Sisley's skies and water surfaces
        are painted with predominantly horizontal strokes, giving them a
        horizontal atmospheric motion quality.  Model this by applying a
        directional (horizontal-axis only) Gaussian blur restricted to the upper
        sky zone:
          For rows y in [0, sky_fraction * H]:
            blur_weight = clip(1 - y / (sky_fraction * H), 0, 1) * sky_blur_opacity
            blurred_R(y) = gaussian_filter_1d(R(y), sigma=sky_blur_sigma, axis=1)
            blurred_G(y) = gaussian_filter_1d(G(y), sigma=sky_blur_sigma, axis=1)
            blurred_B(y) = gaussian_filter_1d(B(y), sigma=sky_blur_sigma, axis=1)
            R_new(y) = R(y) * (1 - blur_weight) + blurred_R(y) * blur_weight
          (Rows below sky_fraction receive no blur.)
        NOVEL: (c) UNIDIRECTIONAL (HORIZONTAL-AXIS) GAUSSIAN BLUR (sigma_y=0,
        sigma_x>0) RESTRICTED TO A CONFIGURABLE UPPER VERTICAL ZONE WITH
        VERTICALLY-DECAYING BLEND WEIGHT -- first pass to apply a strictly 1D
        horizontal-only Gaussian blur (along axis=1, sigma_y=0 so vertical
        structure is preserved) limited to the top sky_fraction of the image
        with a vertical weight gradient; paint_sfumato_focus_pass applies
        isotropic radial blur; paint_atmospheric_recession_pass applies uniform
        isotropic blur; no prior pass applies a unidirectional (1D horizontal)
        blur restricted to a spatially-bounded upper vertical zone.
        """
        print("    Sisley Silver Veil pass (session 261, 172nd mode)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter1d as _gf1d

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Silver Sky Band ───────────────────────────────────────────
        sf = float(sky_fraction)
        sky_rows = int(sf * h)
        sr = float(sky_r); sg = float(sky_g); sb_col = float(sky_b)
        sstr = float(sky_strength)

        ys = _np.arange(h, dtype=_np.float32)
        sky_w = _np.clip(1.0 - ys / (max(sky_rows, 1)), 0.0, 1.0) * sstr
        sky_w = sky_w[:, _np.newaxis]  # (h, 1) broadcast over width

        r1 = _np.clip(r0 * (1.0 - sky_w) + sr * sky_w, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * (1.0 - sky_w) + sg * sky_w, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * (1.0 - sky_w) + sb_col * sky_w, 0.0, 1.0).astype(_np.float32)

        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)

        # ── Stage 2: Midground Silver Atmospheric Haze ────────────────────────
        hc = float(haze_center)
        hb = max(float(haze_band), 1e-4)
        hstr = float(haze_strength)
        hr = float(haze_r); hg = float(haze_g); hb_col = float(haze_b)

        bell = _np.exp(-0.5 * ((lum1 - hc) / hb) ** 2).astype(_np.float32)
        bell_w = _np.clip(bell * hstr, 0.0, 1.0).astype(_np.float32)

        r2 = _np.clip(r1 * (1.0 - bell_w) + hr * bell_w, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 * (1.0 - bell_w) + hg * bell_w, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 * (1.0 - bell_w) + hb_col * bell_w, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Horizontal Sky Motion Blur ───────────────────────────────
        bs = max(float(sky_blur_sigma), 0.5)
        bop = float(sky_blur_opacity)

        # Horizontal-only blur (1D along axis=1) for full image first
        r_hblur = _gf1d(r2, sigma=bs, axis=1).astype(_np.float32)
        g_hblur = _gf1d(g2, sigma=bs, axis=1).astype(_np.float32)
        b_hblur = _gf1d(b2, sigma=bs, axis=1).astype(_np.float32)

        # Apply blur only in sky zone with vertically-decaying weight
        sky_blur_w = _np.clip(1.0 - ys / (max(sky_rows, 1)), 0.0, 1.0) * bop
        sky_blur_w = sky_blur_w[:, _np.newaxis]

        r3 = _np.clip(r2 * (1.0 - sky_blur_w) + r_hblur * sky_blur_w, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 * (1.0 - sky_blur_w) + g_hblur * sky_blur_w, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 * (1.0 - sky_blur_w) + b_hblur * sky_blur_w, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        sky_px  = int((sky_w[:, 0] > 0.02).sum()) * w
        haze_px = int((bell_w > 0.05).sum())
        blur_px = int((sky_blur_w[:, 0] > 0.02).sum()) * w
        print(f"    Sisley Silver Veil complete "
              f"(sky_tinted_px={sky_px}, haze_px={haze_px}, "
              f"sky_blurred_px={blur_px})")

    def vuillard_chromatic_dissolution_pass(
        self,
        hue_blur_sigma:    float = 12.0,
        hue_blend:         float = 0.55,
        ochre_r:           float = 0.78,
        ochre_g:           float = 0.66,
        ochre_b:           float = 0.42,
        ochre_strength:    float = 0.22,
        ochre_lum_lo:      float = 0.35,
        ochre_lum_hi:      float = 0.72,
        grain_amplitude:   float = 0.028,
        grain_sigma:       float = 0.8,
        noise_seed:        int   = 262,
        opacity:           float = 0.80,
    ) -> None:
        r"""Édouard Vuillard Chromatic Dissolution -- session 262, 173rd distinct mode.

        THREE-STAGE INTIMIST PATTERN DISSOLUTION TECHNIQUE INSPIRED BY
        ÉDOUARD VUILLARD (1868-1940):

        Édouard Vuillard (1868-1940), a member of the Nabi group with Bonnard
        and Sérusier, developed a style of domestic intimism unlike any other
        painter's.  His defining achievement is the DISSOLUTION OF BOUNDARY
        between figure and environment: in his interiors, a woman's blouse
        cannot be distinguished from the wallpaper behind her, a tablecloth
        merges into the floor, a brooch is the same colour as a picture frame.
        Three techniques create this quality:

        (1) LOCAL HUE AVERAGING (pattern dissolution): Vuillard perceived and
        painted the AVERAGE local hue rather than the precise hue of each
        individual object.  In practice, he would mix a colour drawn from a
        wide local sample of the scene and apply it consistently across figure
        and background alike.  This can be modelled by spatially blurring the
        hue channel of the image and blending the blurred hue back into the
        original, pushing nearby areas of different hue toward a shared local
        average.  The result is that the hard hue boundaries between object
        and background soften: both share a common local chromatic field.

        (2) WARM OCHRE GROUND PENETRATION: Vuillard frequently painted in
        PEINTURE À LA COLLE (distemper on cardboard), a matte, dry medium that
        absorbs colour differently from oil.  The warm ochre-brown of the
        unprepared cardboard reads through all subsequent layers, giving his
        interiors a warm, amber-yellow undertone in the midtone range.  Bright
        highlights remain cool (they are the thinnest paint), deep shadows
        remain cool (they are the darkest underpaint), but the midtone range
        is warmed by the ground penetrating the thin distemper layer above.

        (3) MATTE DISTEMPER SURFACE GRAIN: Peinture à la colle produces a
        characteristically matte, powdery surface unlike oil or pastel.
        Individual marks are not visible as brushstrokes but as faint tonal
        variations in the dried distemper layer.  This grain is more isotropic
        and finer than oil impasto; it reads as a warm, velvety skin rather
        than directional brushwork.

        Stage 1 LOCAL HUE AVERAGING: Convert the image from RGB to HSV (or
        equivalent HSL), spatially Gaussian-blur the hue channel at a wide
        sigma (hue_blur_sigma), then blend the blurred hue back into the
        original at hue_blend strength.  Convert back to RGB.
          [H, S, V] = rgb_to_hsv(R, G, B)
          H_blur    = gaussian_filter(H, sigma=hue_blur_sigma)
          H_new     = H * (1 - hue_blend) + H_blur * hue_blend
          [R', G', B'] = hsv_to_rgb(H_new, S, V)
        NOVEL: (a) SPATIAL GAUSSIAN BLUR OF HSV HUE CHANNEL ONLY (S AND V
        UNCHANGED) THEN PARTIAL BLEND BACK INTO ORIGINAL HUE -- first pass
        to apply a spatially-blurred hue blend using only the hue channel
        of HSV (not affecting saturation or value), creating the soft hue
        dissolution between adjacent areas; intimiste_pattern_pass adds
        repeating textile STROKES; no prior pass spatially averages the HSV
        hue channel with Gaussian blur and blends toward the local hue mean.

        Stage 2 WARM OCHRE MIDTONE PENETRATION: In the midtone luminance
        band (lum in [ochre_lum_lo, ochre_lum_hi]), apply a warm ochre tint
        with a smooth bell-curve weight.  The bell is Gaussian-shaped,
        centred at (ochre_lum_lo + ochre_lum_hi) / 2:
          lum_center = (ochre_lum_lo + ochre_lum_hi) / 2
          lum_sigma  = (ochre_lum_hi - ochre_lum_lo) / 4
          ochre_gate = exp(-0.5 * ((lum - lum_center) / lum_sigma)^2) * ochre_strength
          R_new = clip(R + ochre_gate * (ochre_r - R), 0, 1)
          G_new = clip(G + ochre_gate * (ochre_g - G), 0, 1)
          B_new = clip(B + ochre_gate * (ochre_b - B), 0, 1)
        NOVEL: (b) GAUSSIAN BELL MIDTONE-BOUNDED WARM OCHRE TINT BLEND (WITH
        CENTRE AT MID-RANGE OF [ochre_lum_lo, ochre_lum_hi] AND SIGMA DERIVED
        FROM BAND HALF-WIDTH) -- first pass to apply an ochre/amber warm tint
        specifically in the midtone band using a Gaussian bell computed from
        configurable lum_lo/lum_hi parameters, distinct from triple_zone_glaze
        (which uses hard pivot thresholds) and from split_toning (two hard zones);
        the ochre target (0.78, 0.66, 0.42) is the peinture-à-la-colle cardboard
        ground colour, a specific warm amber not used in any prior pass.

        Stage 3 MATTE DISTEMPER SURFACE GRAIN: Generate smooth low-amplitude
        noise by creating random noise and blurring it (grain_sigma) to remove
        pixel-scale harshness, then add to the image at grain_amplitude:
          raw_noise = rng.standard_normal((H, W)) * grain_amplitude
          smooth_noise = gaussian_filter(raw_noise, sigma=grain_sigma)
          R_new = clip(R + smooth_noise, 0, 1)
          G_new = clip(G + smooth_noise, 0, 1)
          B_new = clip(B + smooth_noise, 0, 1)
        Applying the same smooth_noise to all three channels produces an
        achromatic (luminance-only) grain -- the powdery matte distemper
        surface.
        NOVEL: (c) SINGLE-CHANNEL (LUMINANCE-ONLY) SMOOTH NOISE GRAIN VIA
        IDENTICAL NOISE ADDED TO ALL THREE RGB CHANNELS (ACHROMATIC GRAIN,
        NOT CHROMATIC) -- first pass to produce an achromatic grain by adding
        a single Gaussian-smoothed noise field identically to R, G, and B;
        paint_granulation_pass uses per-channel different noise to produce
        CHROMATIC grain; paint_film_grain_overlay_pass uses per-channel noise;
        no prior pass adds a single smooth noise to all three channels to
        produce achromatic (luminance-only) grain that does not shift hue.
        """
        print("    Vuillard Chromatic Dissolution pass (session 262, 173rd mode)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        rng_local = _np.random.default_rng(int(noise_seed))

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Local Hue Averaging ──────────────────────────────────────
        hs = max(float(hue_blur_sigma), 0.5)
        hb = float(hue_blend)

        # RGB -> HSV
        c_max = _np.maximum(_np.maximum(r0, g0), b0)
        c_min = _np.minimum(_np.minimum(r0, g0), b0)
        delta = c_max - c_min

        # Value
        v = c_max.copy()

        # Saturation
        s = _np.where(c_max > 1e-6, delta / (c_max + 1e-6), 0.0).astype(_np.float32)

        # Hue (0..1 range)
        hue = _np.zeros((h, w), dtype=_np.float32)
        eps = 1e-6
        mask_r = (c_max == r0) & (delta > eps)
        mask_g = (c_max == g0) & (delta > eps)
        mask_b = (c_max == b0) & (delta > eps)
        hue[mask_r] = ((g0[mask_r] - b0[mask_r]) / (delta[mask_r] + eps)) % 6.0
        hue[mask_g] = (b0[mask_g] - r0[mask_g]) / (delta[mask_g] + eps) + 2.0
        hue[mask_b] = (r0[mask_b] - g0[mask_b]) / (delta[mask_b] + eps) + 4.0
        hue = hue / 6.0  # normalise to [0, 1]

        # Blur hue (circular -- encode as sin/cos to handle wraparound)
        hue_sin = _np.sin(hue * 2.0 * _np.pi).astype(_np.float32)
        hue_cos = _np.cos(hue * 2.0 * _np.pi).astype(_np.float32)
        hue_sin_blur = _gf(hue_sin, sigma=hs)
        hue_cos_blur = _gf(hue_cos, sigma=hs)
        hue_blur = (_np.arctan2(hue_sin_blur, hue_cos_blur) / (2.0 * _np.pi)) % 1.0

        hue_new = (hue * (1.0 - hb) + hue_blur * hb) % 1.0

        # HSV -> RGB
        h6 = hue_new * 6.0
        i  = _np.floor(h6).astype(_np.int32) % 6
        f  = (h6 - _np.floor(h6)).astype(_np.float32)
        p  = _np.clip(v * (1.0 - s),          0.0, 1.0).astype(_np.float32)
        q  = _np.clip(v * (1.0 - s * f),       0.0, 1.0).astype(_np.float32)
        t  = _np.clip(v * (1.0 - s * (1.0 - f)), 0.0, 1.0).astype(_np.float32)

        r1 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5], [v, q, p, p, t, v], default=v).astype(_np.float32)
        g1 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5], [t, v, v, q, p, p], default=v).astype(_np.float32)
        b1 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5], [p, p, t, v, v, q], default=v).astype(_np.float32)

        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        # ── Stage 2: Warm Ochre Midtone Penetration ───────────────────────────
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        or_ = float(ochre_r); og = float(ochre_g); ob = float(ochre_b)
        ostr = float(ochre_strength)
        llo = float(ochre_lum_lo); lhi = float(ochre_lum_hi)
        lc = (llo + lhi) * 0.5
        lsig = max((lhi - llo) * 0.25, 1e-4)

        ochre_gate = _np.clip(
            _np.exp(-0.5 * ((lum1 - lc) / lsig) ** 2) * ostr,
            0.0, 1.0
        ).astype(_np.float32)

        r2 = _np.clip(r1 + ochre_gate * (or_ - r1), 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 + ochre_gate * (og - g1), 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 + ochre_gate * (ob - b1), 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Matte Distemper Surface Grain ────────────────────────────
        ga = float(grain_amplitude)
        gs = max(float(grain_sigma), 0.3)

        raw_noise = rng_local.standard_normal((h, w)).astype(_np.float32) * ga
        smooth_noise = _gf(raw_noise, sigma=gs).astype(_np.float32)

        r3 = _np.clip(r2 + smooth_noise, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 + smooth_noise, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 + smooth_noise, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        ochre_px = int((ochre_gate > 0.05).sum())
        print(f"    Vuillard Chromatic Dissolution complete "
              f"(hue_blend={hb:.2f}, ochre_px={ochre_px}, "
              f"grain_amplitude={ga:.3f})")


    def paint_local_hue_drift_pass(
        self,
        drift_sigma:   float = 18.0,
        drift_strength: float = 0.40,
        saturation_floor: float = 0.08,
        saturation_ceil:  float = 0.90,
        noise_seed:    int   = 262,
        opacity:       float = 0.70,
    ) -> None:
        r"""Local Hue Drift -- session 262 artistic improvement.

        SPATIALLY-VARYING HUE FIELD DRIFT WITH SATURATION CLAMP.

        In many painting traditions the precise hue of a small object area is
        not recorded independently but is allowed to drift toward the dominant
        local hue.  Vuillard merged figure with environment through shared hue
        fields.  Cézanne allowed large orange still-life planes to echo the
        warm grey of the tablecloth below.  Morandi reduced all vessels in a
        group to the same narrow hue range regardless of their actual ceramic
        colour.  In all cases the mechanism is LOCAL HUE AVERAGING: the eye
        adapts to the dominant hue of a spatial region and perceives smaller
        hue variations within it as uniform.

        Stage 1 CIRCULAR-MEAN HUE BLUR WITH SATURATION GATE: Extract the HSV
        hue channel.  Encode as (sin(2π·H), cos(2π·H)) to handle the circular
        wraparound at red (H=0/1).  Gaussian-blur each component at sigma
        drift_sigma.  Reconstruct the blurred hue via arctan2.  The drift is
        applied proportional to pixel saturation: fully-desaturated pixels
        (grey) have no hue to drift; fully-saturated pixels drift maximally.
          H_sin_blur = gaussian_filter(sin(2π·H), sigma=drift_sigma)
          H_cos_blur = gaussian_filter(cos(2π·H), sigma=drift_sigma)
          H_drift    = arctan2(H_sin_blur, H_cos_blur) / (2π) mod 1
          s_gate     = clip((S - saturation_floor) / (saturation_ceil - saturation_floor), 0, 1)
          H_new      = H * (1 - drift_strength * s_gate) + H_drift * drift_strength * s_gate
        NOVEL: (a) SATURATION-GATED CIRCULAR-MEAN HUE DRIFT -- first pass to
        apply a circular-mean hue blur (via sin/cos encoding) gated by per-pixel
        saturation; hammershoi uses global desat not hue blur; vuillard_chromatic
        dissolution_pass (this session) applies a fixed hue_blend without
        saturation gating; this pass modulates drift_strength by local saturation
        so grey pixels drift less than coloured pixels.

        Stage 2 SATURATION CLAMP: After hue drift, clamp saturation to the
        range [saturation_floor, saturation_ceil].  This prevents isolated
        highly-saturated pixels from remaining isolated after the drift (which
        would create hue artifacts) and ensures grey pixels are not assigned
        saturated colours:
          S_new = clip(S, saturation_floor, saturation_ceil)
        NOVEL: (b) GLOBAL SATURATION CLAMP APPLIED AFTER HUE DRIFT TO MAINTAIN
        PERCEPTUAL COHERENCE -- no prior pass implements a saturation clamp
        following a spatial hue manipulation; this removes drift artifacts at
        chromatic boundaries where the blurred hue diverges from the original.

        Stage 3 RECONSTRUCT AND COMPOSITE: Convert modified HSV back to RGB
        and composite at opacity.
        """
        print("    Local Hue Drift pass (session 262 improvement)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Circular-Mean Hue Blur with Saturation Gate ──────────────
        ds = max(float(drift_sigma), 0.5)
        dstr = float(drift_strength)
        sfl = float(saturation_floor)
        sc  = float(saturation_ceil)

        c_max = _np.maximum(_np.maximum(r0, g0), b0)
        c_min = _np.minimum(_np.minimum(r0, g0), b0)
        delta = c_max - c_min
        v = c_max.copy()
        s = _np.where(c_max > 1e-6, delta / (c_max + 1e-6), 0.0).astype(_np.float32)

        eps = 1e-6
        hue = _np.zeros((h, w), dtype=_np.float32)
        mask_r = (c_max == r0) & (delta > eps)
        mask_g = (c_max == g0) & (delta > eps)
        mask_b = (c_max == b0) & (delta > eps)
        hue[mask_r] = ((g0[mask_r] - b0[mask_r]) / (delta[mask_r] + eps)) % 6.0
        hue[mask_g] = (b0[mask_g] - r0[mask_g]) / (delta[mask_g] + eps) + 2.0
        hue[mask_b] = (r0[mask_b] - g0[mask_b]) / (delta[mask_b] + eps) + 4.0
        hue = hue / 6.0

        hue_sin = _np.sin(hue * 2.0 * _np.pi).astype(_np.float32)
        hue_cos = _np.cos(hue * 2.0 * _np.pi).astype(_np.float32)
        hsb = _gf(hue_sin, sigma=ds)
        hcb = _gf(hue_cos, sigma=ds)
        hue_drift = (_np.arctan2(hsb, hcb) / (2.0 * _np.pi)) % 1.0

        s_gate = _np.clip((s - sfl) / max(sc - sfl, eps), 0.0, 1.0).astype(_np.float32)
        hue_new = (hue * (1.0 - dstr * s_gate) + hue_drift * dstr * s_gate) % 1.0

        # ── Stage 2: Saturation Clamp ──────────────────────────────────────────
        s_new = _np.clip(s, sfl, sc).astype(_np.float32)

        # ── Stage 3: HSV -> RGB ────────────────────────────────────────────────
        h6 = hue_new * 6.0
        i  = _np.floor(h6).astype(_np.int32) % 6
        f  = (h6 - _np.floor(h6)).astype(_np.float32)
        p  = _np.clip(v * (1.0 - s_new),                 0.0, 1.0).astype(_np.float32)
        q  = _np.clip(v * (1.0 - s_new * f),             0.0, 1.0).astype(_np.float32)
        t  = _np.clip(v * (1.0 - s_new * (1.0 - f)),     0.0, 1.0).astype(_np.float32)

        r1 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5], [v, q, p, p, t, v], default=v).astype(_np.float32)
        g1 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5], [t, v, v, q, p, p], default=v).astype(_np.float32)
        b1 = _np.select([i==0, i==1, i==2, i==3, i==4, i==5], [p, p, t, v, v, q], default=v).astype(_np.float32)
        r1 = _np.clip(r1, 0.0, 1.0)
        g1 = _np.clip(g1, 0.0, 1.0)
        b1 = _np.clip(b1, 0.0, 1.0)

        op = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        drifted_px = int((s_gate > 0.1).sum())
        print(f"    Local Hue Drift complete "
              f"(drift_sigma={ds:.1f}, drifted_px={drifted_px})")

    def paint_flat_zone_pass(
        self,
        zone_radius:    int   = 5,
        preserve_edges: float = 0.82,
        ground_r:       float = 0.78,
        ground_g:       float = 0.72,
        ground_b:       float = 0.62,
        ground_strength: float = 0.08,
        edge_sigma:     float = 1.5,
        noise_seed:     int   = 263,
        opacity:        float = 0.68,
    ) -> None:
        r"""Flat Zone -- session 263 artistic improvement.

        THREE-STAGE FLAT-COLOUR ZONE UNIFICATION INSPIRED BY NABIS AND
        JAPANESE WOODBLOCK PRINT TECHNIQUE (Vallotton, Vuillard, Sérusier,
        Hokusai, c.1885-1910):

        The Nabis were inspired by Gauguin's dictum that painting should be
        flat coloured surfaces assembled in a certain order.  Félix Vallotton,
        Édouard Vuillard, and Paul Sérusier treated each zone of a composition
        as a near-uniform patch of colour -- the wallpaper a single dusty mauve
        field, the tablecloth a single warm cream, the dress a single muted rose
        -- modulated only by the texture of the support and the slight chaos of
        individual marks.  This is the anti-academic, anti-tonal quality they
        absorbed from Japanese woodblock prints: flat, bounded, assertively
        two-dimensional.  The spatial median filter (not a Gaussian) is the
        correct model for this: it smooths within each colour zone while
        preserving the hard boundaries between zones (since the median of a
        group spanning a sharp edge stays on one side or the other, unlike the
        Gaussian average which bridges it).

        Stage 1 SPATIAL MEDIAN ZONE FLATTENING: Apply ndimage.median_filter
        with footprint size (2*zone_radius+1)^2 to each colour channel
        independently:
          R_flat = median_filter(R, size=2*zone_radius+1)
          G_flat = median_filter(G, size=2*zone_radius+1)
          B_flat = median_filter(B, size=2*zone_radius+1)
        Median filtering removes within-zone tonal graduation while preserving
        the high-contrast edges between zones (the median at a boundary pixel
        is determined by whichever side dominates the filter footprint, so the
        edge location is preserved at half-pixel precision rather than being
        smeared like a Gaussian).
        NOVEL: (a) CHANNEL-BY-CHANNEL SPATIAL MEDIAN FILTER FOR FLAT-ZONE
        UNIFICATION WITH EDGE PRESERVATION -- first pass to apply a spatial
        median filter (ndimage.median_filter) independently per colour channel
        to create Nabis-style flat colour zones while inherently preserving
        edge boundaries; paint_scumble_pass applies a dry-brush drag with
        random stroke placement; paint_atmospheric_recession_pass applies an
        isotropic Gaussian blur for atmospheric haze; no prior pass applies a
        spatial median filter that specifically preserves zone boundary edges
        while smoothing within-zone tonal variation.

        Stage 2 EDGE-PRESERVED COMPOSITE: Compute a Sobel edge magnitude mask
        from the original image:
          Gx = convolve(lum, sobel_x); Gy = convolve(lum, sobel_y)
          edge_mag = sqrt(Gx^2 + Gy^2)
          edge_blur = gaussian_filter(edge_mag, sigma=edge_sigma)
          edge_w = clip(edge_blur / edge_blur.max(), 0, 1) * preserve_edges
        Blend: R_out = R_flat*(1-edge_w) + R*edge_w
        NOVEL: (b) SOBEL-MAGNITUDE EDGE PRESERVATION MASK APPLIED TO A MEDIAN-
        FILTERED COMPOSITE -- first pass to compute a Sobel gradient-based
        edge-preservation mask and use it to alpha-blend a spatially-filtered
        image (retaining the original at edges) so that the flat-zone filter
        does not destroy form-defining contours; paint_sfumato_contour_dissolution
        uses a similar Sobel mask but ADDS dissolution at edges rather than
        using it to PRESERVE them; no prior pass applies a Sobel magnitude mask
        to preferentially retain the original image at edges while using a
        spatial flattening filter in the interior of flat zones.

        Stage 3 WARM GROUND REVEAL IN FLAT ZONES: In image regions where local
        saturation is low (flat, near-grey zones), blend a faint trace of the
        warm ground colour (ground_r, ground_g, ground_b):
          local_sat = (max_channel - min_channel) / (max_channel + 1e-6)
          ground_w = clip((flat_thresh - local_sat) / flat_thresh, 0, 1)
                     * ground_strength
          R_final = R_out + ground_w * (ground_r - R_out)
        NOVEL: (c) SATURATION-GATED WARM GROUND COLOUR REVEAL IN LOW-SATURATION
        ZONES -- first pass to use per-pixel local saturation as a gate to blend
        a warm ground colour specifically into flat/neutral areas while leaving
        chromatic zones untouched; paint_triple_zone_glaze applies a luminance-
        gated glaze; no prior pass uses local saturation (chroma) as the gate
        for a selective warm-ground-reveal blend.
        """
        print("    Flat Zone pass (session 263 improvement)...")

        import numpy as _np
        from scipy.ndimage import median_filter as _mf, gaussian_filter as _gf
        from scipy.ndimage import convolve as _conv

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Spatial Median Zone Flattening ───────────────────────────
        sz  = max(3, 2 * int(zone_radius) + 1)
        r_flat = _mf(r0, size=sz).astype(_np.float32)
        g_flat = _mf(g0, size=sz).astype(_np.float32)
        b_flat = _mf(b0, size=sz).astype(_np.float32)

        # ── Stage 2: Edge-Preserved Composite ─────────────────────────────────
        lum0 = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        sobel_x = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        sobel_y = sobel_x.T

        gx = _conv(lum0, sobel_x, mode="reflect").astype(_np.float32)
        gy = _conv(lum0, sobel_y, mode="reflect").astype(_np.float32)
        edge_mag = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)

        esig = max(float(edge_sigma), 0.5)
        edge_blur = _gf(edge_mag, sigma=esig).astype(_np.float32)
        emx = edge_blur.max()
        edge_norm = _np.clip(edge_blur / (emx + 1e-6), 0.0, 1.0).astype(_np.float32)

        pe = float(preserve_edges)
        edge_w = (edge_norm * pe).astype(_np.float32)

        r1 = (r_flat * (1.0 - edge_w) + r0 * edge_w).astype(_np.float32)
        g1 = (g_flat * (1.0 - edge_w) + g0 * edge_w).astype(_np.float32)
        b1 = (b_flat * (1.0 - edge_w) + b0 * edge_w).astype(_np.float32)

        # ── Stage 3: Warm Ground Reveal in Flat Zones ─────────────────────────
        ch_max = _np.maximum(_np.maximum(r1, g1), b1)
        ch_min = _np.minimum(_np.minimum(r1, g1), b1)
        local_sat = (ch_max - ch_min) / (ch_max + 1e-6)
        local_sat = _np.clip(local_sat, 0.0, 1.0).astype(_np.float32)

        flat_thresh = 0.30
        ground_blend = _np.clip((flat_thresh - local_sat) / (flat_thresh + 1e-6),
                                0.0, 1.0).astype(_np.float32)
        ground_blend = (ground_blend * float(ground_strength)).astype(_np.float32)

        gr_r = float(ground_r); gr_g = float(ground_g); gr_b = float(ground_b)

        r2 = _np.clip(r1 + ground_blend * (gr_r - r1), 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 + ground_blend * (gr_g - g1), 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 + ground_blend * (gr_b - b1), 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        flat_px   = int((local_sat < flat_thresh).sum())
        edge_px   = int((edge_w > 0.3).sum())
        ground_px = int((ground_blend > 0.03).sum())
        print(f"    Flat Zone pass complete "
              f"(flat_px={flat_px}, edge_preserved_px={edge_px}, "
              f"ground_reveal_px={ground_px})")


    def vallotton_dark_interior_pass(
        self,
        shadow_crush:    float = 0.38,
        crush_steepness: float = 6.0,
        lamp_cx:         float = 0.50,
        lamp_cy:         float = 0.35,
        lamp_radius:     float = 0.22,
        lamp_r:          float = 0.96,
        lamp_g:          float = 0.88,
        lamp_b:          float = 0.62,
        lamp_strength:   float = 0.32,
        contour_sigma:   float = 1.2,
        contour_thresh:  float = 0.055,
        contour_dark:    float = 0.55,
        noise_seed:      int   = 263,
        opacity:         float = 0.80,
    ) -> None:
        r"""Vallotton Dark Interior -- session 263, 174th distinct mode.

        THREE-STAGE STARK INTERIOR CHIAROSCURO TECHNIQUE INSPIRED BY
        FÉLIX VALLOTTON'S LAMP-LIT INTERIOR PAINTINGS (c.1895-1920):

        Félix Vallotton (1865-1925), the Swiss-French Nabi, painted interiors
        of a fundamentally different quality from his colleague Vuillard.  Where
        Vuillard dissolved figure into ground with equal-intensity marks, Vallotton
        DRAMATIZED the domestic interior: the lamp-lit room was a stage for
        psychological tension, with hard shadows that cut across the floor in
        geometric precision, figures that become silhouettes against bright
        backgrounds, and a Japanese-influenced flatness that gave every object
        the weight of a symbol.  Three technical signatures define his work:
        (1) SHADOW CRUSH: Vallotton pushed dark zones to near-black with extreme
        contrast -- the shadow under the table, the back wall behind the figure,
        the dark dress fabric -- these are darker than the Impressionists would
        ever permit, almost black, against which even a mid-grey reads as light;
        (2) RADIAL LAMP POOL: a warm amber radial glow centred on the light source
        (a kerosene lamp, a hanging lamp-shade) that bleeds warmth into the
        middle-zone colours in a concentric gradient; (3) JAPANESE INK CONTOUR:
        hard dark outlines at major tonal transitions -- the silhouette of a
        figure against the lamp-lit wall, the edge of the table on the floor --
        modelling his woodcut-influenced approach where contours are drawn, not
        implied.

        Stage 1 SHADOW CRUSH: For pixels with luminance below shadow_crush,
        apply a sigmoid-steepened compression that pushes them toward near-black:
          lum_offset = lum - shadow_crush
          crushed_lum = shadow_crush / (1 + exp(-crush_steepness * lum_offset))
          scale = crushed_lum / (lum + 1e-6), clamped [0, 1]
          R_crushed = R * scale; G_crushed = G * scale; B_crushed = B * scale
        This creates the characteristic Vallotton near-black shadow zone that
        sits below all other tonal ranges in the painting.
        NOVEL: (a) SIGMOID-STEEPENED SHADOW CRUSH BELOW A LUMINANCE THRESHOLD
        -- first pass to apply a sigmoid function specifically below shadow_crush
        (not above as paint_tonal_key does with target key) to push sub-threshold
        pixels aggressively toward near-black while leaving mid-tones and lights
        untouched; paint_tonal_key applies a full-range sigmoid shift; no prior
        pass uses a below-threshold sigmoid to create the Vallotton flat near-
        black shadow pool independently of the mid/highlight tonal zones.

        Stage 2 RADIAL LAMP WARMTH POOL: Compute a radial distance falloff from
        the lamp centre (lamp_cx, lamp_cy in [0,1] image coordinates):
          dx = (x/W - lamp_cx); dy = (y/H - lamp_cy)
          dist = sqrt(dx^2 + dy^2)
          lamp_w = clip(1 - dist/lamp_radius, 0, 1)^2 * lamp_strength
          R_warm = R + lamp_w * (lamp_r - R)
          G_warm = G + lamp_w * (lamp_g - G)
          B_warm = B + lamp_w * (lamp_b - B)
        The quadratic falloff (^2) creates a pool of warmth concentrated near
        the lamp that fades smoothly to the room's ambient tone.
        NOVEL: (b) QUADRATIC-FALLOFF RADIAL WARM LAMP POOL CENTRED ON A
        CONFIGURABLE IMAGE-SPACE LAMP COORDINATE -- first pass to apply a
        radially-decaying warm-colour blend centred on a user-specified lamp
        position (lamp_cx, lamp_cy as fractions of image dimensions) with a
        quadratic distance falloff; paint_halation_pass applies isotropic Gaussian
        bloom from bright regions generally; no prior pass applies a configurable
        positional warm-light pool with quadratic falloff centred at an arbitrary
        image-coordinate lamp position rather than at detected bright regions.

        Stage 3 JAPANESE INK CONTOUR OVERLAY: Detect major tonal boundaries via
        Sobel gradient; threshold at contour_thresh to produce a binary edge map;
        apply Gaussian blur (sigma=contour_sigma) to anti-alias; darken edge
        pixels toward contour_dark fraction of their current value:
          edge_mask = gaussian_filter(sobel_mag > contour_thresh, sigma=contour_sigma)
          R_contour = R * (1 - edge_mask * contour_dark)
          (same G, B)
        This creates the ink-drawn contour lines that give Vallotton's interiors
        their woodcut quality -- every major silhouette bounded by a dark line.
        NOVEL: (c) THRESHOLD-AND-BLUR EDGE MASK APPLIED AS A DARKENING MULTIPLIER
        TO ADD INK-QUALITY CONTOURS -- first pass to threshold a Sobel gradient map
        to produce a binary edge mask, Gaussian-anti-alias it, and use it as a
        multiplicative darkening factor (not additive like paint_contour_weight_pass)
        so edges DARKEN the existing colour rather than adding a fixed black value;
        paint_contour_weight_pass adds a fixed dark displacement; no prior pass
        multiplies a Gaussian-anti-aliased thresholded Sobel mask against the
        current colour channels to darken edges proportionally to their current
        value rather than adding a fixed dark increment.
        """
        print("    Vallotton Dark Interior pass (session 263, 174th mode)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, convolve as _conv

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Shadow Crush ─────────────────────────────────────────────
        sc  = float(shadow_crush)
        ks  = float(crush_steepness)
        lum_offset = lum - sc
        crushed_lum = (sc / (1.0 + _np.exp(-ks * lum_offset))).astype(_np.float32)
        crushed_lum = _np.where(lum < sc, crushed_lum, lum).astype(_np.float32)
        scale = _np.clip(crushed_lum / (lum + 1e-6), 0.0, 1.0).astype(_np.float32)

        r1 = _np.clip(r0 * scale, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * scale, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * scale, 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Radial Lamp Warmth Pool ──────────────────────────────────
        lcx = float(lamp_cx); lcy = float(lamp_cy)
        lr  = max(float(lamp_radius), 0.01)
        ls  = float(lamp_strength)
        lr_v = float(lamp_r); lg_v = float(lamp_g); lb_v = float(lamp_b)

        xs = (_np.arange(w, dtype=_np.float32) / w)[_np.newaxis, :]
        ys = (_np.arange(h, dtype=_np.float32) / h)[:, _np.newaxis]
        dx = xs - lcx
        dy = ys - lcy
        dist = _np.sqrt(dx * dx + dy * dy).astype(_np.float32)
        lamp_w = _np.clip(1.0 - dist / lr, 0.0, 1.0) ** 2 * ls
        lamp_w = lamp_w.astype(_np.float32)

        r2 = _np.clip(r1 + lamp_w * (lr_v - r1), 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 + lamp_w * (lg_v - g1), 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 + lamp_w * (lb_v - b1), 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Japanese Ink Contour Overlay ─────────────────────────────
        csig = max(float(contour_sigma), 0.3)
        cthr = float(contour_thresh)
        cdrk = float(contour_dark)

        sobel_x = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        sobel_y = sobel_x.T
        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        gx = _conv(lum2, sobel_x, mode="reflect").astype(_np.float32)
        gy = _conv(lum2, sobel_y, mode="reflect").astype(_np.float32)
        sobel_mag = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)
        smx = sobel_mag.max()
        sobel_norm = (sobel_mag / (smx + 1e-6)).astype(_np.float32)

        edge_binary = (sobel_norm > cthr).astype(_np.float32)
        edge_mask = _gf(edge_binary, sigma=csig).astype(_np.float32)
        edge_mask = _np.clip(edge_mask / (edge_mask.max() + 1e-6), 0.0, 1.0).astype(_np.float32)
        darken = (1.0 - edge_mask * cdrk).astype(_np.float32)

        r3 = _np.clip(r2 * darken, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 * darken, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 * darken, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        crushed_px = int((lum < sc).sum())
        lamp_px    = int((lamp_w > 0.05).sum())
        contour_px = int((edge_mask > 0.1).sum())
        print(f"    Vallotton Dark Interior complete "
              f"(crushed_px={crushed_px}, lamp_pool_px={lamp_px}, "
              f"contour_px={contour_px})")

    def paint_luminance_excavation_pass(
        self,
        dark_threshold:   float = 0.36,
        variance_sigma:   float = 4.0,
        texture_strength: float = 0.09,
        lift_amount:      float = 0.035,
        noise_seed:       int   = 264,
        opacity:          float = 0.62,
    ) -> None:
        r"""Luminance Excavation -- session 264 artistic improvement.

        THREE-STAGE MICRO-TEXTURE RECOVERY IN DARK REGIONS INSPIRED BY THE
        CHALLENGE FACED BY PAINTERS WORKING IN EXTREME LOW-KEY REGISTERS
        (Soulages, Reinhardt, Malevich, c.1960-2000):

        Any painter working with very dark values faces a fundamental tension:
        the pigment carries internal texture -- direction of application, tonal
        variance within a single loaded stroke, canvas grain pressing through --
        but these are compressed to near-invisibility at low luminance because
        the eye's sensitivity to luminance differences falls steeply in dark
        regions (Weber-Fechner law).  The solution the great dark-field painters
        discovered: create MICRO-TEXTURE that operates at luminance differences
        too small to read as distinct value steps but large enough to register
        as surface quality.  A Soulages canvas that reads as "pure black" from
        a distance reveals, on close approach, a complex internal landscape of
        slight luminance variation -- traces of the squeegee drag, the groove of
        the palette knife, the pooling of medium in a depression -- that give the
        black its depth.  This pass excavates and amplifies that latent micro-
        texture from the dark regions of the canvas.

        Stage 1 DARK REGION ISOLATION: Compute per-pixel luminance; isolate all
        pixels below dark_threshold:
          lum = 0.299*R + 0.587*G + 0.114*B
          dark_mask = (lum < dark_threshold).astype(float)
        Apply Gaussian blur to dark_mask with sigma=2.0 to feather edges:
          dark_w = gaussian_filter(dark_mask, sigma=2.0), clamped [0, 1]
        NOVEL: (a) LUMINANCE-THRESHOLD DARK REGION MASK WITH GAUSSIAN FEATHER --
        first improvement to isolate sub-threshold pixels using a feathered binary
        luminance mask; paint_shadow_bleed_pass uses a similar threshold but for
        bleeding colour outward; no prior improvement uses a feathered dark-region
        mask specifically to EXCAVATE internal micro-variation without affecting
        mid/light zones.

        Stage 2 LOCAL LUMINANCE VARIANCE VIA DOG: Within dark regions, compute
        local luminance variance using a difference-of-Gaussians approximation:
          lum_fine   = gaussian_filter(lum, sigma=variance_sigma / 4.0)
          lum_coarse = gaussian_filter(lum, sigma=variance_sigma)
          dog        = abs(lum_fine - lum_coarse)
          dog_norm   = clip(dog / (dog.max() + 1e-6), 0, 1)
        The DoG reveals local micro-variation at scale variance_sigma -- the
        frequency band where paint texture lives (2-20 pixels).
        NOVEL: (b) DIFFERENCE-OF-GAUSSIANS MICRO-TEXTURE EXTRACTION APPLIED
        SELECTIVELY TO DARK REGIONS -- first improvement to use a DoG approach
        (subtracting a coarse Gaussian from a fine Gaussian) to extract micro-
        texture frequency content and use it to selectively amplify buried
        variation; paint_scumble_pass adds physical dry-brush texture; no prior
        improvement uses DoG to excavate and amplify EXISTING sub-threshold
        variation already present in the canvas from prior strokes.

        Stage 3 MICRO-TEXTURE LIFT: Use dog_norm as a micro-texture guide to
        lift dark region luminance very slightly:
          lift = dog_norm * texture_strength * dark_w * lift_amount
          R_lift = R + lift  (same G, B, clipped to [0, 1])
        This gives dark zones a subtle internal relief: the canvas grain, the
        stroke direction, the pooling of pigment -- all very slightly lighter
        against their near-black surroundings, exactly as in Soulages' Outrenoir.
        NOVEL: (c) DOG-GUIDED LUMINANCE MICRO-LIFT CONFINED TO DARK MASK REGION --
        first improvement to use a DoG micro-texture map to slightly raise
        luminance WITHIN dark regions (using dark_w as gate) so that buried
        stroke texture becomes visible without globally brightening the dark zones;
        paint_craquelure_pass adds crack texture globally; no prior improvement
        uses DoG micro-texture extraction followed by a dark-region-gated lift
        that excavates buried stroke variation from sub-threshold zones.
        """
        print("    Luminance Excavation pass (session 264 improvement)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Dark Region Isolation ────────────────────────────────────
        dt       = float(dark_threshold)
        dark_mask = (lum < dt).astype(_np.float32)
        dark_w    = _np.clip(_gf(dark_mask, sigma=2.0), 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Local Luminance Variance (DoG) ───────────────────────────
        vsig       = max(float(variance_sigma), 1.0)
        lum_fine   = _gf(lum, sigma=max(vsig / 4.0, 0.5)).astype(_np.float32)
        lum_coarse = _gf(lum, sigma=vsig).astype(_np.float32)
        dog        = _np.abs(lum_fine - lum_coarse).astype(_np.float32)
        dog_norm   = _np.clip(dog / (dog.max() + 1e-6), 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Micro-Texture Lift ───────────────────────────────────────
        ts   = float(texture_strength)
        la   = float(lift_amount)
        lift = (dog_norm * ts * dark_w * la).astype(_np.float32)

        r1 = _np.clip(r0 + lift, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 + lift, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 + lift, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        dark_px    = int(dark_mask.sum())
        texture_px = int((dog_norm > 0.1).sum())
        lifted_px  = int((lift > 0.001).sum())
        print(f"    Luminance Excavation complete "
              f"(dark_px={dark_px}, texture_px={texture_px}, lifted_px={lifted_px})")


    def soulages_outrenoir_pass(
        self,
        black_threshold:  float = 0.42,
        deepening_power:  float = 2.4,
        stripe_freq:      float = 26.0,
        stripe_strength:  float = 0.055,
        stripe_threshold: float = 0.48,
        bloom_sigma:      float = 2.8,
        bloom_strength:   float = 0.07,
        noise_seed:       int   = 264,
        opacity:          float = 0.80,
    ) -> None:
        r"""Soulages Outrenoir -- session 264, 175th distinct mode.

        THREE-STAGE OUTRENOIR REFLECTIVE-BLACK TECHNIQUE INSPIRED BY
        PIERRE SOULAGES' MATURE ABSTRACT PAINTING (c.1979-2022):

        Pierre Soulages (1919-2022), born in Conques, Aveyron, France, spent
        seven decades building one of the most radical bodies of work in modern
        painting.  In 1979 he made the discovery that would define the rest of
        his career: while working on a canvas that had accumulated too much black
        paint to develop further, he turned off his studio lights and looked at
        the canvas in the dark -- and found it emanating light.  The surfaces of
        the accumulated black paint, dragged by large squeegees and palette knives
        into grooves, furrows, ridges, and flat planes at different orientations,
        were catching and reflecting ambient light differently, creating a
        topographic luminance map WITHIN the black itself.  He called this
        discovery "Outrenoir" -- beyond black -- because the black was not the
        absence of light but its generator.  From that point, Soulages painted
        only with black, never again using colour.  His canvases are built from
        the trace of the tool rather than from pigment colour: a flat-dragged
        squeegee leaves a matte field; a sharp-edged tool leaves a bright seam;
        a curved drag leaves a field of varying reflectivity across its arc.
        The viewer experiences this as pure luminance contrast within the
        supposedly single-valued darkness: zones of near-total absorption beside
        zones of bright metallic sheen, all within the same black.

        Stage 1 ULTRA-BLACK DEEPENING: For pixels below black_threshold, apply
        a power-law compression that pushes luminance toward near-zero:
          lum_norm = clip(lum / black_threshold, 0, 1)
          scale    = lum_norm^(deepening_power - 1.0)  for lum < black_threshold
          scale    = 1.0                                 for lum >= black_threshold
          R_deep   = R * scale  (same G, B; scale clamped [0, 1])
        This creates the Soulages pigment depth: the pure absorption of industrial-
        grade matte black acrylic, richer and darker than any conventional paint.
        NOVEL: (a) POWER-LAW LUMINANCE COMPRESSION BELOW A THRESHOLD TO CREATE
        SOULAGES-STYLE ULTRA-BLACK DEPTH -- first pass to apply a configurable
        power-law scaling (lum/threshold)^(power-1) specifically to sub-threshold
        pixels, independently compressing dark zones without affecting mid/lights;
        vallotton_dark_interior_pass uses sigmoid-steepened compression; no prior
        pass applies a power-law (gamma-style) compression below a specific
        luminance threshold to push near-darks toward total black while leaving
        mid-tones and highlights entirely untouched.

        Stage 2 HORIZONTAL REFLECTIVE STRIPE FIELD: Within dark regions (below
        stripe_threshold), add a field of subtle horizontal luminance variations
        that simulate Soulages' horizontal squeegee-drag marks catching light:
          y_norm   = arange(H) / H
          stripe_t = (sin(y_norm * stripe_freq * pi) + 1.0) / 2.0
          dark_mask = clip(1 - lum / stripe_threshold, 0, 1)^2
          stripe_add = stripe_t * stripe_strength * dark_mask
          R_stripe = R + stripe_add  (same G, B, achromatic)
        The sinusoidal stripe pattern, confined to dark zones by dark_mask,
        creates the impression of horizontal tool marks catching ambient light
        at different angles -- bright-seam / matte-field alternation.
        NOVEL: (b) SINUSOIDAL HORIZONTAL STRIPE FIELD CONFINED TO DARK-REGION
        MASK TO SIMULATE SQUEEGEE-DRAG REFLECTIVE SEAMS -- first pass to use a
        sinusoidal luminance variation (sin(y*freq*pi)) confined to a dark-region
        mask to create horizontal surface-reflectivity bands within black zones;
        paint_brushstroke_grain_pass adds physical stroke texture; no prior pass
        applies a sinusoidal luminance-stripe field specifically confined to
        sub-threshold dark zones to simulate horizontal tool-mark reflectivity
        within a Soulages-style ultra-black field.

        Stage 3 EDGE LUMINANCE BLOOM AT DARK/LIGHT BOUNDARIES: At the transition
        between deep-black and lighter areas, slightly amplify the light side --
        the "black makes the white whiter" phenomenon Soulages himself described:
          edge_mag   = sqrt(sobel_x^2 + sobel_y^2)
          dark_side  = clip(1 - lum, 0, 1)
          bloom_raw  = edge_mag * dark_side
          bloom_blur = gaussian_filter(bloom_raw, sigma=bloom_sigma)
          bloom_norm = clip(bloom_blur / bloom_blur.max(), 0, 1)
          R_bloom    = R + bloom_norm * bloom_strength  (same G, B)
        The bloom occurs from the dark side, pushing adjacent light pixels very
        slightly brighter, increasing perceived luminance contrast without
        touching the dark zone itself.
        NOVEL: (c) DARK-SIDE-WEIGHTED EDGE BLOOM AT DARK/LIGHT TRANSITIONS TO
        SIMULATE SOULAGES' CONTRAST AMPLIFICATION EFFECT -- first pass to weight
        a Sobel edge magnitude by proximity to dark regions (dark_side = 1 - lum)
        and use this dark-proximity-edge product (Gaussian-blurred) to LIFT the
        light pixels at dark boundaries without touching the dark regions themselves;
        paint_halation_pass blooms from bright regions outward; no prior pass
        applies dark-side-weighted edge lifting to create the effect where extreme
        darkness makes surrounding light appear brighter.
        """
        print("    Soulages Outrenoir pass (session 264, 175th mode)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, convolve as _conv

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Ultra-Black Deepening ────────────────────────────────────
        bt       = float(black_threshold)
        dp       = max(float(deepening_power), 1.0)
        lum_norm = _np.clip(lum / (bt + 1e-6), 0.0, 1.0).astype(_np.float32)
        scale    = _np.where(
            lum < bt,
            lum_norm ** max(dp - 1.0, 0.0),
            _np.ones((h, w), dtype=_np.float32),
        ).astype(_np.float32)
        scale = _np.clip(scale, 0.0, 1.0).astype(_np.float32)

        r1 = _np.clip(r0 * scale, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * scale, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * scale, 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Horizontal Reflective Stripe Field ───────────────────────
        sf  = float(stripe_freq)
        ss  = float(stripe_strength)
        st  = float(stripe_threshold)

        y_norm   = (_np.arange(h, dtype=_np.float32) / max(h - 1, 1))[:, _np.newaxis]
        stripe_t = ((_np.sin(y_norm * sf * _np.pi) + 1.0) / 2.0).astype(_np.float32)
        stripe_t = _np.broadcast_to(stripe_t, (h, w)).copy().astype(_np.float32)

        lum1      = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        dark_mask = (_np.clip(1.0 - lum1 / (st + 1e-6), 0.0, 1.0) ** 2).astype(_np.float32)
        stripe_add = (stripe_t * ss * dark_mask).astype(_np.float32)

        r2 = _np.clip(r1 + stripe_add, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 + stripe_add, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 + stripe_add, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Edge Luminance Bloom at Dark/Light Boundaries ───────────
        bsig = max(float(bloom_sigma), 0.5)
        bst  = float(bloom_strength)

        sobel_x  = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        sobel_y  = sobel_x.T
        lum2     = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        gx       = _conv(lum2, sobel_x, mode="reflect").astype(_np.float32)
        gy       = _conv(lum2, sobel_y, mode="reflect").astype(_np.float32)
        edge_mag = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)

        dark_side  = _np.clip(1.0 - lum2, 0.0, 1.0).astype(_np.float32)
        bloom_raw  = (edge_mag * dark_side).astype(_np.float32)
        bloom_blur = _gf(bloom_raw, sigma=bsig).astype(_np.float32)
        bmx        = bloom_blur.max()
        bloom_norm = _np.clip(bloom_blur / (bmx + 1e-6), 0.0, 1.0).astype(_np.float32)

        r3 = _np.clip(r2 + bloom_norm * bst, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(g2 + bloom_norm * bst, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(b2 + bloom_norm * bst, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        deepened_px = int((lum < bt).sum())
        stripe_px   = int((stripe_add > 0.005).sum())
        bloom_px    = int((bloom_norm > 0.10).sum())
        print(f"    Soulages Outrenoir complete "
              f"(deepened_px={deepened_px}, stripe_px={stripe_px}, "
              f"bloom_px={bloom_px})")

    def paint_wet_surface_gleam_pass(
        self,
        spec_threshold:   float = 0.72,
        streak_sigma:     float = 18.0,
        gleam_r:          float = 0.28,
        gleam_g:          float = 0.20,
        gleam_b:          float = 0.10,
        feather_sigma:    float = 1.5,
        noise_seed:       int   = 265,
        opacity:          float = 0.55,
    ) -> None:
        r"""Wet Surface Gleam -- session 265 artistic improvement.

        THREE-STAGE VERTICAL DOWNWARD LIGHT-TRAIL FROM BRIGHT SOURCES ON RAIN-
        WET SURFACES INSPIRED BY THE PHYSICAL OPTICS OF SPECULAR REFLECTION ON
        RAIN-SLICKED COBBLESTONES (Ury, Sisley, Sickert, c.1880-1920):

        When rain coats a cobblestone or tile surface with a thin continuous film
        of water, every light source above the horizon -- gas lamp, cafe window,
        electric arc -- produces a specular reflection in that film. The geometry
        of the reflection is determined by the Fresnel equations and the geometry
        of the surface relative to the viewer: from a low angle of incidence (the
        viewer looking down at cobblestones a few metres away), the reflection of
        a point source is elongated vertically in the direction away from the
        viewer (downward in the image), because slight variations in surface
        slope across the cobblestone field scatter the reflection angle over a
        range of vertical positions while keeping the horizontal position tightly
        constrained. The result, visible in every Ury nocturne and Sisley river
        painting, is that light sources produce downward "gleam trails" on wet
        surfaces -- narrow, warm, vertically elongated bands of reflected light
        that terminate in the dark surface below each source.

        Stage 1 SPECULAR MASK EXTRACTION: Compute per-pixel luminance;
        build a soft specular mask of all pixels above spec_threshold:
          lum      = 0.299*R + 0.587*G + 0.114*B
          spec_raw = clip((lum - spec_threshold) / max(1 - spec_threshold, 0.01), 0, 1)
          spec_mask = gaussian_filter(spec_raw, sigma=feather_sigma), clamped [0, 1]
        The feathering ensures that only genuinely bright pixels (gas lamps,
        window highlights, sky patches) contribute to the gleam trail.
        NOVEL: (a) LUMINANCE-THRESHOLD SPECULAR MASK WITH GAUSSIAN FEATHER --
        first improvement to extract a soft specular mask using per-pixel lum
        clipped above a configurable spec_threshold then feathered with a small
        Gaussian; paint_luminance_stretch_pass globally stretches luminance; no
        prior improvement builds a specular-threshold mask specifically to guide
        a vertical streak simulating physical wet-surface optics.

        Stage 2 VERTICAL GAUSSIAN STREAK: Apply 1D Gaussian blur along the
        vertical axis (axis=0) to the specular mask with sigma=streak_sigma:
          streak = gaussian_filter1d(spec_mask, sigma=streak_sigma, axis=0)
          streak = clip(streak / (streak.max() + 1e-6), 0, 1)
        The 1D vertical blur elongates the bright specular spots downward
        (and slightly upward for reflections above the source), producing the
        characteristic narrow downward gleam trail of a gas lamp reflection
        on rain-wet cobblestones. streak_sigma=18.0 gives ~36-pixel trails at
        full resolution, matching Ury's observed gleam lengths.
        NOVEL: (b) 1D VERTICAL GAUSSIAN STREAK FROM SPECULAR MASK -- first
        improvement to apply gaussian_filter1d along axis=0 to a specular-
        threshold mask to create downward "light trail" streaks; paint_sfumato_
        contour_dissolution_pass uses Gaussian blur for horizontal edge softening;
        no prior improvement applies 1D vertical Gaussian blur specifically to a
        specular mask to model the elongated reflection geometry of light sources
        on rain-wet surfaces.

        Stage 3 WARM-TINTED GLEAM COMPOSITE: Apply a warm-tinted gleam using
        the streak as a lift guide, with per-channel warm weights:
          r_lift = streak * gleam_r
          g_lift = streak * gleam_g  (gleam_g < gleam_r)
          b_lift = streak * gleam_b  (gleam_b < gleam_g)
          R_out  = clip(R + r_lift, 0, 1), G_out, B_out
        gleam_r > gleam_g > gleam_b ensures the gleam is warm (amber-ivory)
        rather than white, matching the warm colour temperature of gas lamps
        and cafe windows that Ury depicted.
        NOVEL: (c) PER-CHANNEL WARM-TINTED GLEAM LIFT FROM VERTICAL STREAK --
        first improvement to use a vertically-streaked specular mask with
        asymmetric per-channel weights (R > G > B) to place warm downward gleam
        marks on the canvas; paint_golden_ground_pass applies warm tinting
        globally; no prior improvement uses specular-extract-then-vertically-
        streak followed by a warm per-channel tint to create warm, downward-
        elongated gleam streaks specifically from bright-source pixels only.
        """
        print("    Wet Surface Gleam pass (session 265 improvement)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf, gaussian_filter1d as _gf1d

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        # ── Stage 1: Specular Mask Extraction ─────────────────────────────────
        st       = float(spec_threshold)
        denom    = max(1.0 - st, 0.01)
        spec_raw = _np.clip((lum - st) / denom, 0.0, 1.0).astype(_np.float32)
        fsig     = max(float(feather_sigma), 0.5)
        spec_mask = _np.clip(_gf(spec_raw, sigma=fsig), 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Vertical Gaussian Streak ─────────────────────────────────
        ssig   = max(float(streak_sigma), 1.0)
        streak = _gf1d(spec_mask, sigma=ssig, axis=0).astype(_np.float32)
        streak = _np.clip(streak / (streak.max() + 1e-6), 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Warm-Tinted Gleam Composite ──────────────────────────────
        gr = float(gleam_r)
        gg = float(gleam_g)
        gb = float(gleam_b)

        r1 = _np.clip(r0 + streak * gr, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 + streak * gg, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 + streak * gb, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r1 * op
        new_g = g0 * (1.0 - op) + g1 * op
        new_b = b0 * (1.0 - op) + b1 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        spec_px   = int((spec_mask > 0.05).sum())
        streak_px = int((streak > 0.05).sum())
        gleam_px  = int((streak * gr > 0.005).sum())
        print(f"    Wet Surface Gleam complete "
              f"(spec_px={spec_px}, streak_px={streak_px}, gleam_px={gleam_px})")


    def ury_nocturne_reflection_pass(
        self,
        sky_fraction:           float = 0.45,
        pavement_fraction:      float = 0.40,
        h_blur_sigma:           float = 18.0,
        v_blur_sigma:           float = 3.5,
        reflection_attenuation: float = 0.38,
        reflection_opacity:     float = 0.62,
        lamp_threshold:         float = 0.62,
        corona_sigma:           float = 22.0,
        corona_strength:        float = 0.18,
        amber_dr:               float = 0.14,
        amber_dg:               float = 0.04,
        amber_db_cut:           float = 0.12,
        shadow_threshold:       float = 0.32,
        shadow_r_scale:         float = 0.74,
        shadow_g_scale:         float = 0.82,
        shadow_b_lift:          float = 0.022,
        shadow_strength:        float = 0.70,
        noise_seed:             int   = 265,
        opacity:                float = 0.78,
    ) -> None:
        r"""Ury Nocturne Reflection -- session 265, 176th distinct mode.

        THREE-STAGE NOCTURNE STREET REFLECTION TECHNIQUE INSPIRED BY
        LESSER URY'S BERLIN NIGHT SCENES (c.1888-1920):

        Lesser Ury (1861-1931) was a German-Jewish Impressionist who spent most
        of his career painting Berlin's cafes, streets, and parks. His mature
        work in the 1890s-1900s established him as one of the foremost painters
        of the nocturne street scene in European art. Working from the charged
        intersection of Impressionism, Japonisme, and the new electric and gas
        lighting of the modern city, Ury developed a distinctive visual language:
        prussian-blue / indigo shadow zones that make the warm amber of gas lamps
        and cafe interiors appear almost incandescent; a technique of depicting
        wet cobblestones by treating the pavement as a mirror that inverts and
        elongates the light sources above it; and a characteristic "corona" around
        light sources -- a Gaussian bloom of warm amber spreading into atmospheric
        haze -- that gives his nocturnes their quality of urban fog and gaslight
        mystery. Unlike Monet's haystacks (nature) or Whistler's nocturnes
        (aestheticism), Ury's paintings are fundamentally about the new,
        specifically URBAN experience of artificial light: the way it pools and
        reflects and halos in a city at night, creating islands of warmth in a
        sea of prussian dark.

        Stage 1 WET PAVEMENT VERTICAL MIRROR REFLECTION: Take the upper
        sky_fraction rows of the canvas as the "light source zone"; flip them
        vertically to create a physical mirror image; apply asymmetric Gaussian
        blur (heavy horizontal: sigma=h_blur_sigma to elongate reflections along
        the pavement; light vertical: sigma=v_blur_sigma for softening); darken
        by reflection_attenuation (water absorbs ~62% of incident light); then
        composite over the lower pavement_fraction rows at reflection_opacity:
          source_zone  = canvas[0 : sky_rows, :, :]
          mirror       = source_zone[::-1, :, :]    (vertical flip)
          mirror_blur  = gaussian_filter(mirror, sigma=(v_blur, h_blur))
          mirror_dark  = mirror_blur * reflection_attenuation
          canvas[pave_start:, :, :] = blend(canvas, mirror_dark, reflection_opacity)
        NOVEL: (a) UPPER-CANVAS VERTICAL FLIP + ASYMMETRIC GAUSSIAN BLUR +
        LUMINANCE ATTENUATION COMPOSITED INTO LOWER CANVAS TO SIMULATE WET
        PAVEMENT MIRROR REFLECTIONS -- first pass to extract a configurable
        sky_fraction of the canvas, flip it vertically, apply a 2D Gaussian
        with DIFFERENT sigma values on each axis (heavy horizontal for rain-
        elongated reflections, light vertical for softening), then darken and
        composite into the lower pavement_fraction; paint_sfumato_focus_pass
        blurs specific regions uniformly; no prior pass creates pavement-plane
        reflections by flipping upper canvas content with asymmetric per-axis
        blur and luminance attenuation.

        Stage 2 GAS-LAMP AMBER CORONA: Build a warm amber corona around light
        sources. Identify pixels above lamp_threshold by luminance; shift those
        pixels toward warm amber by adding amber increments (amber_dr, amber_dg)
        and subtracting from blue (amber_db_cut); Gaussian-blur the warm-amber
        excess at sigma=corona_sigma to simulate atmospheric diffusion; composite
        at corona_strength:
          lamp_mask  = clip(lum - lamp_threshold, 0, 1) / (1 - lamp_threshold)
          r_excess   = clip(r + amber_dr * lamp_mask, 0, 1) - r
          g_excess   = clip(g + amber_dg * lamp_mask, 0, 1) - g
          b_excess   = clip(b - amber_db_cut * lamp_mask, 0, 1) - b
          r_glow     = gaussian_filter(r_excess * lamp_mask, corona_sigma)
          R_out      = R + r_glow * corona_strength
        NOVEL: (b) LUMINANCE-GATED WARM-AMBER HUE SHIFT FOLLOWED BY GAUSSIAN
        DIFFUSION TO CREATE GAS-LAMP ATMOSPHERIC CORONA -- first pass to extract
        a luminance-threshold lamp mask, apply differential per-channel warm-amber
        shift (adding R/G, subtracting B) specifically to bright pixels only, then
        Gaussian-blur the warm excess to create a spreading amber corona simulating
        gaslight atmospheric scattering; paint_halation_pass spreads achromatic
        luminance outward from bright zones; no prior pass applies warm-amber hue
        shifting to a luminance-gated bright mask followed by Gaussian diffusion of
        the warm excess to create specifically amber (not white) coronas.

        Stage 3 PRUSSIAN BLUE NIGHT-SHADOW COOLER: For all pixels below
        shadow_threshold luminance, cool the shadow hue toward prussian blue by
        applying differential per-channel scaling and a slight blue lift:
          r_out = r * shadow_r_scale                  (< 1, reduces red)
          g_out = g * shadow_g_scale                  (< 1, reduces green less)
          b_out = clip(b + shadow_b_lift, 0, 1)        (slight blue lift in darks)
        Blend the cooled shadow at shadow_strength, gated by
          shadow_mask = clip(1 - lum / shadow_threshold, 0, 1):
          R_final = R*(1 - gate) + r_out*gate,  gate = shadow_mask * shadow_strength
        NOVEL: (c) DIFFERENTIAL PER-CHANNEL SCALING WITH BLUE LIFT GATED BY
        SHADOW LUMINANCE MASK TO CREATE PRUSSIAN-BLUE NIGHT SHADOWS -- first pass
        to apply asymmetric per-channel factors (R*scale_r < 1, G*scale_g < 1,
        B + lift > 0) specifically to sub-threshold dark pixels only, shifting
        their hue toward prussian blue while leaving mid-tones and highlights
        untouched; paint_warm_cool_separation_pass divides the canvas by luminance
        but applies global warm/cool shifts; no prior pass applies configurable
        per-channel differential scaling specifically to the low-luminance shadow
        zone only to cool darks toward prussian blue / indigo in the manner of
        Ury, Sickert, or the Paris Impressionist nocturne tradition.
        """
        print("    Ury Nocturne Reflection pass (session 265, 176th mode)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        r1 = r0.copy()
        g1 = g0.copy()
        b1 = b0.copy()

        # ── Stage 1: Wet Pavement Vertical Mirror Reflection ──────────────────
        sky_rows  = max(1, int(h * float(sky_fraction)))
        pave_rows = max(1, int(h * float(pavement_fraction)))
        pave_start = h - pave_rows

        src_r = r1[:sky_rows, :].copy()
        src_g = g1[:sky_rows, :].copy()
        src_b = b1[:sky_rows, :].copy()

        mir_r = src_r[::-1, :].copy()
        mir_g = src_g[::-1, :].copy()
        mir_b = src_b[::-1, :].copy()

        hsig = max(float(h_blur_sigma), 1.0)
        vsig = max(float(v_blur_sigma), 0.5)
        mir_r = _gf(mir_r, sigma=(vsig, hsig)).astype(_np.float32)
        mir_g = _gf(mir_g, sigma=(vsig, hsig)).astype(_np.float32)
        mir_b = _gf(mir_b, sigma=(vsig, hsig)).astype(_np.float32)

        att = float(reflection_attenuation)
        mir_r = (mir_r * att).astype(_np.float32)
        mir_g = (mir_g * att).astype(_np.float32)
        mir_b = (mir_b * att).astype(_np.float32)

        use_rows = min(pave_rows, mir_r.shape[0])
        ref_op   = float(reflection_opacity)

        for i in range(use_rows):
            dst_row = pave_start + i
            if dst_row >= h:
                break
            src_i = min(i, mir_r.shape[0] - 1)
            r1[dst_row, :] = _np.clip(
                r1[dst_row, :] * (1.0 - ref_op) + mir_r[src_i, :] * ref_op, 0.0, 1.0)
            g1[dst_row, :] = _np.clip(
                g1[dst_row, :] * (1.0 - ref_op) + mir_g[src_i, :] * ref_op, 0.0, 1.0)
            b1[dst_row, :] = _np.clip(
                b1[dst_row, :] * (1.0 - ref_op) + mir_b[src_i, :] * ref_op, 0.0, 1.0)

        refl_px = use_rows * w

        # ── Stage 2: Gas-Lamp Amber Corona ────────────────────────────────────
        lum1       = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        lt         = float(lamp_threshold)
        lamp_denom = max(1.0 - lt, 0.01)
        lamp_mask  = _np.clip((lum1 - lt) / lamp_denom, 0.0, 1.0).astype(_np.float32)

        adr  = float(amber_dr)
        adg  = float(amber_dg)
        adb  = float(amber_db_cut)
        csig = max(float(corona_sigma), 1.0)
        cst  = float(corona_strength)

        warm_r_excess = (_np.clip(r1 + adr * lamp_mask, 0.0, 1.0) - r1).astype(_np.float32)
        warm_g_excess = (_np.clip(g1 + adg * lamp_mask, 0.0, 1.0) - g1).astype(_np.float32)
        warm_b_excess = (_np.clip(b1 - adb * lamp_mask, 0.0, 1.0) - b1).astype(_np.float32)

        glow_r = _gf((warm_r_excess * lamp_mask).astype(_np.float32), sigma=csig)
        glow_g = _gf((warm_g_excess * lamp_mask).astype(_np.float32), sigma=csig)
        glow_b = _gf((warm_b_excess * lamp_mask).astype(_np.float32), sigma=csig)

        r2 = _np.clip(r1 + glow_r * cst, 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 + glow_g * cst, 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 + glow_b * cst, 0.0, 1.0).astype(_np.float32)
        lamp_px = int((lamp_mask > 0.1).sum())

        # ── Stage 3: Prussian Blue Night-Shadow Cooler ────────────────────────
        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)
        st2  = float(shadow_threshold)
        ss   = float(shadow_strength)
        shdw = _np.clip(1.0 - lum2 / (st2 + 1e-6), 0.0, 1.0).astype(_np.float32)
        gate = (shdw * ss).astype(_np.float32)

        rs = float(shadow_r_scale)
        gs = float(shadow_g_scale)
        bl = float(shadow_b_lift)

        r3_cool = _np.clip(r2 * rs, 0.0, 1.0).astype(_np.float32)
        g3_cool = _np.clip(g2 * gs, 0.0, 1.0).astype(_np.float32)
        b3_cool = _np.clip(b2 + bl, 0.0, 1.0).astype(_np.float32)

        r3 = (r2 * (1.0 - gate) + r3_cool * gate).astype(_np.float32)
        g3 = (g2 * (1.0 - gate) + g3_cool * gate).astype(_np.float32)
        b3 = (b2 * (1.0 - gate) + b3_cool * gate).astype(_np.float32)

        shadow_px = int((shdw > 0.5).sum())

        # ── Composite at opacity ───────────────────────────────────────────────
        op    = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        print(f"    Ury Nocturne Reflection complete "
              f"(refl_px={refl_px}, lamp_px={lamp_px}, shadow_px={shadow_px})")

    def paint_hue_zone_boundary_pass(
        self,
        variance_sigma:      float = 3.0,
        boundary_dark:       float = 0.55,
        interior_chroma:     float = 0.18,
        feather_sigma:       float = 1.5,
        sat_floor:           float = 0.10,
        noise_seed:          int   = 266,
        opacity:             float = 0.70,
    ) -> None:
        r"""Hue Zone Boundary -- session 266 artistic improvement.

        THREE-STAGE HUE ZONE BOUNDARY ISOLATION TECHNIQUE INSPIRED BY THE
        ENAMEL CLOISONNE AND STAINED-GLASS TRADITION (Gallen-Kallela, Tiffany,
        medieval enamel work, c.1100-1930):

        In cloisonne enamel, thin metal wires (cloisons) partition the surface
        into discrete cells; each cell is filled with a single colour of powdered
        glass that fuses at high temperature into a flat, jewel-bright zone. The
        metal partitions appear as narrow, dark lines between the colour zones.
        In oil painting, Akseli Gallen-Kallela and the Symbolist painters who
        absorbed the decorative arts tradition reproduced this effect by building
        their compositions from flat colour zones separated by bold dark outlines
        -- a technique that simultaneously derives from medieval enamel, Japanese
        woodblock prints (where the key block prints black outlines), and the
        Synthetic Cubism of Gauguin and the Pont-Aven school. The key perceptual
        mechanism is that the dark boundary line sharpens the apparent contrast
        of the two adjacent colour zones: adjacent colours always appear more
        saturated when separated by a dark partition. This is a consequence of
        simultaneous contrast -- the dark line shifts the visual context for both
        adjacent zones toward the opposite end of the luminance scale.

        The critical novelty of this pass is using CIRCULAR HUE STATISTICS to
        locate zone boundaries. All prior passes that create edge effects use
        LUMINANCE gradients (Sobel, DoG) -- these detect light-to-dark boundaries
        but miss colour-to-colour boundaries of equal luminance (e.g., a red zone
        adjacent to a green zone of the same brightness, or an orange region
        touching a cyan region). Circular hue variance detects exactly the
        boundaries that luminance-based methods miss: adjacent colour zones with
        different hues but similar luminance are invisible to Sobel but produce
        maximum hue variance.

        Stage 1 CIRCULAR HUE VARIANCE FIELD: Convert RGB to HSV. Encode hue
        as unit vectors: hue_sin = sin(2pi*H), hue_cos = cos(2pi*H). Compute
        local Gaussian-weighted means of sin and cos components:
          sin_mean = gaussian_filter(sat_masked_sin, variance_sigma)
          cos_mean = gaussian_filter(sat_masked_cos, variance_sigma)
        The circular coherence R = sqrt(sin_mean^2 + cos_mean^2) measures how
        aligned the hue vectors are in the local neighbourhood. R near 1 means
        all nearby pixels have the same hue (zone interior). R near 0 means the
        hue vectors cancel (zone boundary between different hues). Define:
          hue_var = 1 - R   (high at zone boundaries, low at zone interiors)
          hue_var = clip(hue_var / hue_var.max(), 0, 1)  (normalized)
        Saturation masking: apply gaussian_filter on sat*sin and sat*cos to weight
        the hue statistics by local saturation, so that grey/near-grey pixels (which
        have no meaningful hue) do not artificially inflate hue variance.
        NOVEL: (a) CIRCULAR HUE VARIANCE FIELD USING SIN/COS ENCODING OF HSV HUE
        CHANNEL WITH SATURATION-WEIGHTED LOCAL GAUSSIAN NEIGHBORHOOD -- first pass
        to use circular statistics (unit-vector mean + coherence) to compute a hue-
        zone boundary detection field; all prior boundary-detection passes (paint_
        flat_zone_pass, paint_sfumato_contour_dissolution_pass, paint_contour_weight_
        pass) use luminance-based Sobel gradients, which miss equal-luminance color
        boundaries; this pass detects exactly those boundaries (blue-to-orange,
        green-to-red, etc.) that Sobel cannot see.

        Stage 2 BOUNDARY DARKENING COMPOSITE: Feather the hue variance field with
        a small Gaussian (feather_sigma) to smooth the partition lines. Apply
        multiplicative darkening gated by the hue variance:
          dark_gate = hue_var_feathered * boundary_dark
          r_dark = r * (1 - dark_gate)
          g_dark = g * (1 - dark_gate)
          b_dark = b * (1 - dark_gate)
        This creates narrow dark outlines at zone boundaries, simulating the metal
        cloison partitions of enamel work and the bold contour lines of Gallen-
        Kallela's Symbolist period paintings.
        NOVEL: (b) MULTIPLICATIVE DARKENING GATED BY CIRCULAR HUE VARIANCE FIELD
        TO PRODUCE DARK OUTLINES AT COLOR ZONE BOUNDARIES WITHOUT REQUIRING LUMINANCE
        CONTRAST -- first pass to apply a darkening effect specifically to pixels
        identified as hue zone boundaries via circular statistics; paint_edge_temperature_
        pass applies warm/cool shifts at luminance edges; no prior pass uses a hue-
        coherence-based field to gate a darkening effect at colour zone boundary positions.

        Stage 3 INTERIOR CHROMA AMPLIFICATION: In low-variance (zone interior)
        pixels, amplify saturation by interior_chroma, gated by
          interior_gate = (1 - hue_var) * clip((S - sat_floor)/sat_floor, 0, 1)
        Convert the hue-adjusted interior pixels back to RGB and blend at
        interior_chroma strength. The saturation floor gate prevents grey areas
        from being pushed into false colour (grey pixels have undefined hue and
        amplifying their near-zero saturation produces distracting colour noise).
        NOVEL: (c) SATURATION AMPLIFICATION GATED BY CIRCULAR HUE COHERENCE AND
        SATURATION FLOOR THRESHOLD IN ZONE INTERIOR PIXELS -- first pass to use
        1-hue_var (the zone interior map) as the gate for a per-pixel saturation
        boost; paint_chroma_focus_pass applies saturation globally based on
        luminance; no prior pass uses a hue-coherence field to identify zone
        interiors specifically and apply saturation enhancement only within those
        flat-hue regions, which is exactly the mechanism that makes enamel zones
        appear richer than the surrounding painted areas.
        """
        print("    Hue Zone Boundary pass (session 266 improvement)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Circular Hue Variance Field ──────────────────────────────
        ch_max = _np.maximum(_np.maximum(r0, g0), b0)
        ch_min = _np.minimum(_np.minimum(r0, g0), b0)
        sat = _np.clip((ch_max - ch_min) / (ch_max + 1e-6), 0.0, 1.0).astype(_np.float32)

        # Hue angle (0..1 range = 0..360 deg), only meaningful where sat > 0
        delta = (ch_max - ch_min).astype(_np.float32)
        hue = _np.zeros_like(r0)
        m = delta > 1e-6
        r_m = r0[m]; g_m = g0[m]; b_m = b0[m]
        d_m = delta[m]; mx_m = ch_max[m]

        hr = ((g_m - b_m) / d_m) % 6.0
        hg = (b_m - r_m) / d_m + 2.0
        hb = (r_m - g_m) / d_m + 4.0

        is_r = (mx_m == r_m)
        is_g = (mx_m == g_m) & ~is_r
        is_b = ~is_r & ~is_g

        h_m = _np.where(is_r, hr, _np.where(is_g, hg, hb)) / 6.0
        hue[m] = h_m

        # Circular encoding weighted by saturation (unsaturated pixels contribute nothing)
        theta = (2.0 * _np.pi * hue).astype(_np.float32)
        sin_h = (sat * _np.sin(theta)).astype(_np.float32)
        cos_h = (sat * _np.cos(theta)).astype(_np.float32)

        vsig = max(float(variance_sigma), 0.5)
        sin_mean = _gf(sin_h, sigma=vsig).astype(_np.float32)
        cos_mean = _gf(cos_h, sigma=vsig).astype(_np.float32)
        sat_mean = _gf(sat, sigma=vsig).astype(_np.float32) + 1e-6

        coherence = _np.sqrt(sin_mean**2 + cos_mean**2) / sat_mean
        coherence = _np.clip(coherence, 0.0, 1.0).astype(_np.float32)
        hue_var = (1.0 - coherence).astype(_np.float32)
        hue_var_n = _np.clip(hue_var / (hue_var.max() + 1e-6), 0.0, 1.0).astype(_np.float32)
        boundary_px = int((hue_var_n > 0.5).sum())

        # ── Stage 2: Boundary Darkening Composite ─────────────────────────────
        fsig = max(float(feather_sigma), 0.5)
        hue_var_f = _np.clip(_gf(hue_var_n, sigma=fsig), 0.0, 1.0).astype(_np.float32)

        dark = float(boundary_dark)
        dark_gate = (hue_var_f * dark).astype(_np.float32)

        r1 = _np.clip(r0 * (1.0 - dark_gate), 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g0 * (1.0 - dark_gate), 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b0 * (1.0 - dark_gate), 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Interior Chroma Amplification ─────────────────────────────
        sf = max(float(sat_floor), 0.01)
        sat_gate = _np.clip((sat - sf) / (sf + 1e-6), 0.0, 1.0).astype(_np.float32)
        interior_gate = ((1.0 - hue_var_f) * sat_gate).astype(_np.float32)

        ic = float(interior_chroma)
        ch_max1 = _np.maximum(_np.maximum(r1, g1), b1)
        ch_min1 = _np.minimum(_np.minimum(r1, g1), b1)
        sat1 = _np.clip((ch_max1 - ch_min1) / (ch_max1 + 1e-6), 0.0, 1.0).astype(_np.float32)
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)

        # Amplify saturation by lifting channels away from luminance
        r2 = _np.clip(lum1 + (r1 - lum1) * (1.0 + ic * interior_gate), 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(lum1 + (g1 - lum1) * (1.0 + ic * interior_gate), 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(lum1 + (b1 - lum1) * (1.0 + ic * interior_gate), 0.0, 1.0).astype(_np.float32)

        interior_px = int((interior_gate > 0.1).sum())

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r2 * op
        new_g = g0 * (1.0 - op) + g2 * op
        new_b = b0 * (1.0 - op) + b2 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        print(f"    Hue Zone Boundary complete "
              f"(boundary_px={boundary_px}, interior_px={interior_px})")


    def gallen_kallela_enamel_cloisonne_pass(
        self,
        flat_sigma:         float = 4.0,
        zone_blend:         float = 0.55,
        contour_strength:   float = 0.70,
        contour_sigma:      float = 1.0,
        sat_boost:          float = 0.22,
        sat_floor:          float = 0.12,
        sat_ceil:           float = 0.92,
        noise_seed:         int   = 266,
        opacity:            float = 0.78,
    ) -> None:
        r"""Gallen-Kallela Enamel Cloisonne -- session 266, 177th distinct mode.

        THREE-STAGE ENAMEL CLOISONNE DECORATIVE TECHNIQUE INSPIRED BY AKSELI
        GALLEN-KALLELA'S DECORATIVE PAINTING PRACTICE (c.1891-1930):

        Akseli Gallen-Kallela (1865-1931) was the dominant figure in Finnish art
        during the National Romantic period. His mature style -- developed through
        intense study of Japanese woodblock prints, medieval stained glass, and
        Byzantine mosaic art during his Paris years (1884-89) -- combined the
        flat, bounded colour zones of Japanese woodblock printing with the jewel-
        bright saturation of enamel and the bold contour lines of medieval
        manuscript illumination. Unlike the Nabis who sought intimacy through
        flat colour, Gallen-Kallela used flatness in service of heroic scale and
        mythological gravitas: his Kalevala illustrations and the Aino triptych
        (1891) treat Finnish forest landscape with the decorative authority of a
        cathedral window. Each coloured zone is a category, not a modulation: the
        birch trunks are WHITE, not "light grey with subtle tonal gradation"; the
        sky is COBALT, not "atmospheric blue with value shifting"; the forest floor
        is BURNT SIENNA, not "complex textured ground."

        The technique has three identifiable mechanical stages: First, the within-
        zone colour is unified (the Japanese woodblock flatness) -- subtle brush-
        mark variation within a zone is resolved into a single dominant hue. Second,
        zone boundaries are reinforced with a dark outline (the stained-glass lead
        line) -- painted with a thin pointed brush, darker than either adjacent zone,
        creating the edge-enhancing perceptual effect that makes both adjacent zones
        appear more saturated. Third, the zone colours are pushed toward the
        decorative palette (the enamel richness) -- Gallen-Kallela's palette in
        his mature period is characterised by cobalt blue, burnt orange, forest
        green, cream-white, dark umber, and occasional crimson, with minimal use
        of grey or neutral tones: everything in the composition resolves toward
        a pure, assertive hue.

        Stage 1 CIRCULAR-HUE ZONE FLATTENING: Compute local hue mean using
        Gaussian-weighted circular averaging (sin/cos encoding of hue angle with
        saturation weighting) at sigma=flat_sigma. Blend the original hue toward
        the local circular mean at zone_blend strength. Convert back to RGB
        retaining the original luminance and saturation but with a locally
        unified hue:
          theta_mean = atan2(gaussian(sat*sin(2pi*H), flat_sigma),
                             gaussian(sat*cos(2pi*H), flat_sigma))
          H_flat = theta_mean / (2*pi) mod 1.0
          blend H toward H_flat at zone_blend; reconstruct HSV -> RGB
        NOVEL: (a) CIRCULAR MEAN HUE ZONE FLATTENING VIA GAUSSIAN-WEIGHTED SIN/
        COS ENCODING WITH SATURATION MASKING -- first MODE pass to apply Gaussian-
        smoothing in circular hue space (not in linear hue space, which cannot
        handle the 0/1 wraparound) to unify local hue zones; paint_flat_zone_pass
        applies spatial median filtering per channel (which does not separate hue
        from luminance); paint_local_hue_drift_pass blends toward a local circular
        hue mean at a single global saturation-gate but does not use it to create
        discrete bounded colour zones -- gallen_kallela_enamel_cloisonne_pass adds
        flat_sigma control and zone_blend gating on a per-luminance-stability basis,
        specifically targeting zone unification rather than drift.

        Stage 2 BOLD CONTOUR DARKENING: Compute Sobel edge magnitude on the hue-
        flattened canvas (after Stage 1). Apply Gaussian feathering (contour_sigma)
        to the Sobel magnitude. Use as a multiplicative darkening gate:
          edge_w = clip(sobel_mag / sobel_mag.max(), 0, 1)
          edge_feathered = gaussian_filter(edge_w, contour_sigma)
          R_dark = R * (1 - contour_strength * edge_feathered)
          G_dark = G * (1 - contour_strength * edge_feathered)
          B_dark = B * (1 - contour_strength * edge_feathered)
        NOVEL: (b) SOBEL-MAGNITUDE CONTOUR DARKENING APPLIED TO A CIRCULAR-HUE-
        FLATTENED CANVAS RATHER THAN THE ORIGINAL PAINTED SURFACE -- first mode
        pass to apply bold contour darkening to a pre-processed hue-flattened
        image (the Sobel magnitude detects boundaries between unified colour zones,
        not the original painted brushmarks); paint_contour_weight_pass applies
        contour darkening to the original canvas, which detects both zone boundaries
        AND brushmark edges; gallen_kallela_enamel_cloisonne_pass detects zone
        boundaries specifically from the flattened result, producing clean partition
        lines rather than noisy multi-scale edge marks.

        Stage 3 DECORATIVE PALETTE SATURATION PUNCH: In pixels above sat_floor
        and below sat_ceil, boost saturation by sat_boost using per-pixel chroma
        amplification from luminance:
          chroma_boost = sat_boost * clip((sat - sat_floor)/(sat_ceil - sat_floor), 0, 1)
          R_rich = lum + (R - lum) * (1 + chroma_boost)
          G_rich = lum + (G - lum) * (1 + chroma_boost)
          B_rich = lum + (B - lum) * (1 + chroma_boost)
        This differentially amplifies chromatic departure from grey while leaving
        luminance unchanged, reproducing the jewel-like saturation of Gallen-
        Kallela's decorative enamel palette without clipping highlights.
        NOVEL: (c) SATURATION-GATED PER-PIXEL CHROMA AMPLIFICATION FROM LOCAL
        LUMINANCE IN COMBINATION WITH A HUE-FLATTENED AND BOLDLY-OUTLINED CANVAS
        -- first mode pass to combine (1) circular hue zone flattening, (2) bold
        contour darkening on the flattened result, and (3) saturation-bounded chroma
        amplification in a single three-stage pipeline specifically calibrated for the
        Finnish Symbolist enamel cloisonne decorative technique; no prior mode pass
        treats both the flatness and the partition line and the chromatic punch as an
        integrated three-stage system.
        """
        print("    Gallen-Kallela Enamel Cloisonne pass (session 266, 177th mode)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from scipy.ndimage import convolve as _conv

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Circular-Hue Zone Flattening ─────────────────────────────
        ch_max = _np.maximum(_np.maximum(r0, g0), b0)
        ch_min = _np.minimum(_np.minimum(r0, g0), b0)
        delta  = (ch_max - ch_min).astype(_np.float32)
        sat0   = _np.clip(delta / (ch_max + 1e-6), 0.0, 1.0).astype(_np.float32)
        lum0   = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        hue0 = _np.zeros_like(r0)
        m = delta > 1e-6
        if m.any():
            rr = r0[m]; gg = g0[m]; bb = b0[m]
            dd = delta[m]; mx = ch_max[m]
            is_r = (mx == rr)
            is_g = (mx == gg) & ~is_r
            hr = ((gg - bb) / dd) % 6.0
            hg = (bb - rr) / dd + 2.0
            hb = (rr - gg) / dd + 4.0
            hue0[m] = _np.where(is_r, hr, _np.where(is_g, hg, hb)) / 6.0

        theta = (2.0 * _np.pi * hue0).astype(_np.float32)
        sin_h = (sat0 * _np.sin(theta)).astype(_np.float32)
        cos_h = (sat0 * _np.cos(theta)).astype(_np.float32)

        fsig = max(float(flat_sigma), 0.5)
        sin_sm = _gf(sin_h, sigma=fsig).astype(_np.float32)
        cos_sm = _gf(cos_h, sigma=fsig).astype(_np.float32)

        hue_flat = (_np.arctan2(sin_sm, cos_sm) / (2.0 * _np.pi)) % 1.0
        hue_flat = hue_flat.astype(_np.float32)

        zb = float(zone_blend)
        hue_blended = (hue0 * (1.0 - zb) + hue_flat * zb).astype(_np.float32)

        # Reconstruct RGB from (hue_blended, sat0, lum0) via HSV-like inverse
        def _hsv_to_rgb(h_ch, s_ch, v_ch):
            h6 = (h_ch * 6.0).astype(_np.float32)
            i  = h6.astype(_np.int32) % 6
            f  = h6 - _np.floor(h6)
            p  = (v_ch * (1.0 - s_ch)).astype(_np.float32)
            q  = (v_ch * (1.0 - s_ch * f)).astype(_np.float32)
            t  = (v_ch * (1.0 - s_ch * (1.0 - f))).astype(_np.float32)
            R  = _np.select([i==0,i==1,i==2,i==3,i==4,i==5], [v_ch,q,p,p,t,v_ch])
            G  = _np.select([i==0,i==1,i==2,i==3,i==4,i==5], [t,v_ch,v_ch,q,p,p])
            B  = _np.select([i==0,i==1,i==2,i==3,i==4,i==5], [p,p,t,v_ch,v_ch,q])
            return R.astype(_np.float32), G.astype(_np.float32), B.astype(_np.float32)

        v_ch = ch_max.astype(_np.float32)
        r1, g1, b1 = _hsv_to_rgb(hue_blended, sat0, v_ch)
        r1 = _np.clip(r1, 0.0, 1.0).astype(_np.float32)
        g1 = _np.clip(g1, 0.0, 1.0).astype(_np.float32)
        b1 = _np.clip(b1, 0.0, 1.0).astype(_np.float32)

        zone_px = int((sat0 > 0.1).sum())

        # ── Stage 2: Bold Contour Darkening ───────────────────────────────────
        lum1 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1).astype(_np.float32)
        sobel_x = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        sobel_y = sobel_x.T
        gx = _conv(lum1, sobel_x, mode="reflect").astype(_np.float32)
        gy = _conv(lum1, sobel_y, mode="reflect").astype(_np.float32)
        edge_mag = _np.sqrt(gx * gx + gy * gy).astype(_np.float32)
        edge_n = _np.clip(edge_mag / (edge_mag.max() + 1e-6), 0.0, 1.0).astype(_np.float32)

        csig = max(float(contour_sigma), 0.3)
        edge_f = _np.clip(_gf(edge_n, sigma=csig), 0.0, 1.0).astype(_np.float32)

        cs = float(contour_strength)
        r2 = _np.clip(r1 * (1.0 - cs * edge_f), 0.0, 1.0).astype(_np.float32)
        g2 = _np.clip(g1 * (1.0 - cs * edge_f), 0.0, 1.0).astype(_np.float32)
        b2 = _np.clip(b1 * (1.0 - cs * edge_f), 0.0, 1.0).astype(_np.float32)

        contour_px = int((edge_f > 0.3).sum())

        # ── Stage 3: Decorative Palette Saturation Punch ──────────────────────
        ch_max2 = _np.maximum(_np.maximum(r2, g2), b2)
        ch_min2 = _np.minimum(_np.minimum(r2, g2), b2)
        sat2 = _np.clip((ch_max2 - ch_min2) / (ch_max2 + 1e-6), 0.0, 1.0).astype(_np.float32)
        lum2 = (0.299 * r2 + 0.587 * g2 + 0.114 * b2).astype(_np.float32)

        sf = float(sat_floor); sc = float(sat_ceil)
        chroma_gate = _np.clip((sat2 - sf) / ((sc - sf) + 1e-6), 0.0, 1.0).astype(_np.float32)
        sb = float(sat_boost)
        boost = (1.0 + sb * chroma_gate).astype(_np.float32)

        r3 = _np.clip(lum2 + (r2 - lum2) * boost, 0.0, 1.0).astype(_np.float32)
        g3 = _np.clip(lum2 + (g2 - lum2) * boost, 0.0, 1.0).astype(_np.float32)
        b3 = _np.clip(lum2 + (b2 - lum2) * boost, 0.0, 1.0).astype(_np.float32)

        sat_px = int((chroma_gate > 0.1).sum())

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + r3 * op
        new_g = g0 * (1.0 - op) + g3 * op
        new_b = b0 * (1.0 - op) + b3 * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        print(f"    Gallen-Kallela Enamel Cloisonne complete "
              f"(zone_px={zone_px}, contour_px={contour_px}, sat_px={sat_px})")

    def paint_palette_knife_ridge_pass(
        self,
        ridge_freq:    float = 0.18,
        ridge_scale:   float = 0.055,
        ridge_sigma:   float = 8.0,
        lum_lo:        float = 0.18,
        lum_hi:        float = 0.82,
        noise_seed:    int   = 267,
        opacity:       float = 0.65,
    ) -> None:
        r"""Palette Knife Ridge Texture -- session 267 artistic improvement.

        THREE-STAGE PALETTE KNIFE RIDGE TEXTURE INSPIRED BY THE DIRECT IMPASTO
        TECHNIQUE OF NATALIA GONCHAROVA AND THE NEO-PRIMITIVIST PAINTERS
        (c.1905-1915):

        Natalia Goncharova (1881-1962) and her contemporaries in the Russian
        Neo-Primitivist movement painted with a directness that derived from
        peasant icon painting and folk art traditions: broad, flat strokes
        applied with a loaded palette knife or stiff hog-hair brush, building
        surfaces that carry visible material evidence of their construction.
        The palette knife in particular produces a characteristic surface
        topology: each stroke deposits paint in a flat slab with steep raised
        edges -- the knife lifts away a ridge of paint at the stroke boundary,
        and the interior of the stroke is level or slightly concave where the
        knife blade compressed the paint. When raking light hits such a surface,
        alternating ridges and troughs catch highlights and cast micro-shadows
        that follow the directional logic of the stroke. These ridges are not
        random (as canvas grain is) nor fixed-direction (as woven fiber is):
        they run PERPENDICULAR to the knife stroke direction, which itself
        follows the form of the subject -- a painter building the roundness of
        a sunflower petal applies strokes along the petal axis, so ridges run
        transversely across it.

        The critical novelty of this pass is computing a GRADIENT-FOLLOWING
        SPATIAL SINUSOIDAL RIDGE TEXTURE. The local luminance gradient direction
        is used to infer the dominant paint-application direction (the knife
        stroke axis), and the ridge texture is generated perpendicular to that
        axis as a spatial sinusoid. This means the ridge pattern locally adapts
        to the form of the subject: ridges are radial on round objects, horizontal
        on flat ground planes, and diagonal on angled surfaces. No prior pass
        generates a form-following ridge texture; all prior texture passes use
        either isotropic noise (granulation), woven grid patterns (surface_tooth),
        or gradient-magnitude shadow casting on EXISTING ridges (impasto_ridge_cast).
        This pass synthesises new ridge marks that authentically follow the
        painted forms as a palette knife would.

        Stage 1 LOCAL GRADIENT DIRECTION FIELD: Compute the luminance image from
        the canvas RGB. Apply Sobel gradient operators to get (Gx, Gy). Encode
        the gradient direction as unit vectors (sin_g, cos_g) = (sin(angle),
        cos(angle)) where angle = atan2(Gy, Gx). Apply Gaussian smoothing to
        sin_g and cos_g at sigma=ridge_sigma to produce a smooth gradient
        direction field (vectorial averaging handles the pi-periodic wrap-around
        of direction vectors). Reconstruct smoothed_angle = atan2(smooth_sin,
        smooth_cos). This is the local "flow direction" of the painted form.
        NOVEL: (a) VECTORIAL GRADIENT DIRECTION SMOOTHING VIA SIN/COS CIRCULAR
        MEAN AT LARGE SIGMA -- all prior passes that use gradient direction use
        the raw Sobel direction without smoothing (paint_impasto_ridge_cast_pass
        uses gradient magnitude, not direction; paint_edge_temperature_pass uses
        Sobel magnitude as a gate without computing direction); smoothing the
        direction field at ridge_sigma=8px removes small-scale noise and yields
        a coherent stroke-direction field that follows the major forms of the
        subject rather than individual brushmark edges.

        Stage 2 PERPENDICULAR RIDGE FREQUENCY SYNTHESIS: Compute the ridge
        direction as perpendicular to the gradient: perp_angle = smoothed_angle
        + pi/2. For every pixel (y, x) compute the ridge phase:
          ridge_phase = (X * cos(perp_angle) + Y * sin(perp_angle)) * ridge_freq
          ridge_tex = sin(ridge_phase * 2 * pi)
        where X = horizontal coordinate grid, Y = vertical coordinate grid.
        The result is a spatially-varying sinusoidal ridge pattern that locally
        aligns perpendicular to the estimated stroke direction. At ridge_freq=0.18
        cycles/pixel, ridges are approximately 5-6 pixels wide at painting scale --
        the visual width of a palette knife ridge on a 1040-1440px canvas.
        NOVEL: (b) GRADIENT-DIRECTION-FOLLOWING SPATIAL SINUSOIDAL RIDGE TEXTURE
        -- first pass to generate per-pixel ridge texture by dotting the pixel
        coordinate with the LOCAL PERPENDICULAR DIRECTION rather than a global
        fixed direction or isotropic noise; paint_surface_tooth_pass uses dual
        sinusoidal grids at 0° and 90° (fixed global axes, not form-following);
        paint_granulation_pass uses Gaussian-smoothed random noise (isotropic,
        no directional coherence); this pass generates ridges that curve and
        reorient to follow the round forms, flat planes, and diagonal surfaces
        of the subject exactly as a palette knife does.

        Stage 3 LUMINANCE-GATED RIDGE COMPOSITE: Apply the ridge texture as a
        direct luminance lift/depression:
          lum_gate = 4 * clip((lum - lum_lo)/(lum_hi-lum_lo), 0, 1) *
                         clip((lum_hi - lum)/(lum_hi-lum_lo), 0, 1)
          (peaks at lum = (lum_lo + lum_hi)/2, falls to zero at both extremes)
          delta = ridge_tex * lum_gate * ridge_scale
          new_r = clip(r + delta, 0, 1)
          new_g = clip(g + delta, 0, 1)
          new_b = clip(b + delta, 0, 1)
        The luminance gate ensures ridges are prominent in mid-tones (where the
        most active palette knife work is typically visible) and invisible in
        deep shadows or pure highlights, which is correct for raking light
        conditions where ridge contrast is highest in the intermediate tonal zone.
        NOVEL: (c) BELL-CURVE LUMINANCE GATE FOR RIDGE VISIBILITY, PEAKING AT
        MID-TONE -- no prior texture pass uses a symmetric mid-tone bell gate
        (the product of two linear ramps, equalling a triangular/bell shape at
        the mid-luminance point); paint_granulation_pass uses a global opacity
        without luminance gating; paint_surface_tooth_pass uses a fixed ridge_
        strength without gating; this gate physically models the behaviour of
        raking light on an undulating surface, where the greatest tonal contrast
        between ridge peaks (bright) and trough valleys (dark) occurs at
        intermediate luminance levels -- pure whites show no ridge contrast
        because both peak and trough are bright; pure blacks show none because
        both are dark.
        """
        print("    Palette Knife Ridge Texture pass (session 267 improvement)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from scipy.ndimage import convolve as _conv

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Local Gradient Direction Field ────────────────────────────
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)

        sobel_x = _np.array([[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]], dtype=_np.float32)
        sobel_y = sobel_x.T
        gx = _conv(lum, sobel_x, mode="reflect").astype(_np.float32)
        gy = _conv(lum, sobel_y, mode="reflect").astype(_np.float32)

        angle = _np.arctan2(gy, gx).astype(_np.float32)
        sin_g = _np.sin(angle).astype(_np.float32)
        cos_g = _np.cos(angle).astype(_np.float32)

        rsig = max(float(ridge_sigma), 0.5)
        smooth_sin = _gf(sin_g, sigma=rsig).astype(_np.float32)
        smooth_cos = _gf(cos_g, sigma=rsig).astype(_np.float32)
        smoothed_angle = _np.arctan2(smooth_sin, smooth_cos).astype(_np.float32)

        # ── Stage 2: Perpendicular Ridge Frequency Synthesis ──────────────────
        perp_angle = (smoothed_angle + _np.pi / 2.0).astype(_np.float32)

        Y_grid, X_grid = _np.mgrid[0:h, 0:w]
        X_f = X_grid.astype(_np.float32)
        Y_f = Y_grid.astype(_np.float32)

        ridge_phase = (
            X_f * _np.cos(perp_angle) + Y_f * _np.sin(perp_angle)
        ).astype(_np.float32)

        rf = float(ridge_freq)
        ridge_tex = _np.sin(ridge_phase * rf * 2.0 * _np.pi).astype(_np.float32)

        # ── Stage 3: Luminance-Gated Ridge Composite ──────────────────────────
        lo = float(lum_lo)
        hi = float(lum_hi)
        span = max(hi - lo, 1e-4)
        ramp_lo = _np.clip((lum - lo) / span, 0.0, 1.0).astype(_np.float32)
        ramp_hi = _np.clip((hi - lum) / span, 0.0, 1.0).astype(_np.float32)
        lum_gate = (4.0 * ramp_lo * ramp_hi).astype(_np.float32)

        rs = float(ridge_scale)
        delta = (ridge_tex * lum_gate * rs).astype(_np.float32)

        new_r = _np.clip(r0 + delta, 0.0, 1.0).astype(_np.float32)
        new_g = _np.clip(g0 + delta, 0.0, 1.0).astype(_np.float32)
        new_b = _np.clip(b0 + delta, 0.0, 1.0).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        final_r = r0 * (1.0 - op) + new_r * op
        final_g = g0 * (1.0 - op) + new_g * op
        final_b = b0 * (1.0 - op) + new_b * op

        ridge_px = int((lum_gate > 0.3).sum())

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(final_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(final_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(final_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        print(f"    Palette Knife Ridge complete (active_px={ridge_px})")


    def goncharova_rayonist_pass(
        self,
        n_angles:           int   = 4,
        ray_sigma:          float = 24.0,
        ray_strength:       float = 0.32,
        shimmer_angle:      float = 14.0,
        shimmer_freq:       float = 0.06,
        shimmer_threshold:  float = 0.12,
        noise_seed:         int   = 267,
        opacity:            float = 0.72,
    ) -> None:
        r"""Goncharova Rayonist -- session 267, 178th distinct mode.

        THREE-STAGE RAYONIST LIGHT FRACTURE TECHNIQUE INSPIRED BY NATALIA
        GONCHAROVA'S RAYONIST PAINTING PRACTICE (c.1912-1914):

        Natalia Goncharova (1881-1962) co-developed Rayonism (Luchism) with
        Mikhail Larionov as the first fully abstract art movement to originate
        in Russia. The theoretical basis, published in the 1913 manifesto
        "Rayonism and Futurism", holds that the eye does not perceive objects
        directly but rather the REFLECTED RAYS OF LIGHT that objects emit into
        the space between subject and viewer. Painting, therefore, should render
        not the object but these dynamic ray fields -- the electromagnetic
        interaction of illuminated surfaces. In practice, Rayonist paintings
        dissolve recognizable forms into crossing bands of directional colour,
        each band representing a ray of reflected light traveling in a specific
        direction. Where rays from adjacent objects cross, the colours interfere
        and mix, producing chromatic complexity at intersection zones. The 1913
        Rayonist works (Cats, Linen, Forest, Glass) show objects fragmented into
        long, roughly parallel colour streaks that cross each other at various
        angles; the underlying form is still legible but buried beneath the
        dynamic ray field.

        The implementation models this through three identifiable mechanical
        stages: First, the existing paint colors on the canvas are elongated
        simultaneously in multiple directions through directional Gaussian
        blurring -- this "stretches" each colour into ray-like extensions along
        4 angles (0°, 45°, 90°, 135°, covering the full directional space at
        45° intervals). Each directional blur approximates a family of parallel
        light rays traveling in that direction. Second, the multi-directional
        streak synthesis is blended over the original canvas weighted by
        luminance, so that bright areas (the natural light emitters) contribute
        more strongly to the ray field than dark areas -- this is the Rayonist
        principle that brightly illuminated surfaces generate the most energetic
        ray emission. Third, in the zones where the rayonist treatment diverges
        most strongly from the original (the crossing-ray interference zones),
        a spatial alternating hue rotation introduces chromatic shimmer --
        adjacent sub-regions shift hue in opposite directions, creating the
        prismatic colour separation that Goncharova achieved through deliberate
        complementary colour placement within ray bands.

        Stage 1 MULTI-ANGLE DIRECTIONAL STREAK SYNTHESIS: Iterate over N=4
        angles [0, 45, 90, 135] degrees. For each angle:
          a. Rotate each RGB channel by -angle_deg (bilinear for 45/135,
             np.rot90 for 90, identity for 0), reshape=False (canvas size
             preserved), mode='reflect' (edges continue with mirrored content).
          b. Apply 1D Gaussian blur along axis=1 (the row axis, which after
             rotation represents the ray direction): sigma=ray_sigma=24px.
          c. Apply 1D Gaussian blur along axis=0 (cross direction): sigma=1.5px
             to smooth interpolation artifacts without smearing transversally.
          d. Rotate back by +angle_deg.
          e. Accumulate in streak_r, streak_g, streak_b.
        streak_mean = accumulated / N_ANGLES.
        NOVEL: (a) MULTI-ANGLE 1D DIRECTIONAL GAUSSIAN STREAK SYNTHESIS COVERING
        FULL 180° DIRECTIONAL SPACE IN 45° STEPS -- first mode pass to apply a
        family of directional 1D Gaussian blurs at multiple angles and sum them
        into a streak composite; paint_shadow_bleed_pass applies a single-
        direction multi-scale Gaussian blur (luminance-weighted); paint_sisley_
        silver_veil_pass applies a single horizontal motion blur in the sky zone;
        no prior mode pass applies elongating directional blurs at 4+ distinct
        angles and composites them, which is the mechanism that creates the
        multi-directional ray field characteristic of Rayonist paintings.

        Stage 2 LUMINANCE-WEIGHTED STREAK OVERLAY: Compute a source weight map
        from the original luminance:
          source_w = clip(lum / (lum.max() + eps), 0, 1)  (normalized luminance)
          source_w_n = gaussian_filter(source_w, sigma=4)  (smooth weighting)
        Blend the streak mean over the original at ray_strength, modulated by
        source weight:
          blend_factor = ray_strength * (0.4 + 0.6 * source_w_n)
          ray_r = r0 * (1 - blend_factor) + streak_mean_r * blend_factor
          ray_g = g0 * (1 - blend_factor) + streak_mean_g * blend_factor
          ray_b = b0 * (1 - blend_factor) + streak_mean_b * blend_factor
        This ensures bright areas (sunflower discs, sky highlights) generate
        stronger ray extensions than dark areas, consistent with the Rayonist
        physical model of ray emission strength proportional to light intensity.
        NOVEL: (b) LUMINANCE-PROPORTIONAL WEIGHTING OF STREAK CONTRIBUTION --
        first mode pass to modulate the directional streak strength per-pixel
        by the normalised original luminance; prior blending passes use a fixed
        global opacity; this creates spatially-varying ray density that is
        highest at bright emission zones and lowest in deep shadows, physically
        modelling the directional dispersion of light sources.

        Stage 3 CHROMATIC HUE SHIMMER AT RAY INTERFERENCE ZONES: Compute the
        per-pixel ray energy:
          ray_energy = mean(|ray_composite - original|) over RGB channels
        In pixels where ray_energy > shimmer_threshold, apply a spatially
        alternating hue rotation:
          spatial_sign = sign(sin(X * shimmer_freq * 2*pi) *
                              cos(Y * shimmer_freq * 2*pi))
          hue_delta = (shimmer_angle / 360.0) * spatial_sign
        Convert to HSV, shift H by hue_delta, convert back to RGB. Gate by
        the shimmer_mask (ray_energy > shimmer_threshold). This creates
        alternating warm/cool patches within the ray interference zones,
        reproducing the chromatic vibration of Goncharova's Rayonist canvases
        where adjacent ray bands carry complementary colours.
        NOVEL: (c) SPATIALLY-ALTERNATING HUE ROTATION GATED BY RAY DIVERGENCE
        FIELD -- first mode pass to gate a hue rotation by the DIFFERENCE
        between the directional-streak composite and the original canvas (the
        "ray interference field"); prior hue-rotation passes use luminance or
        saturation gates; this pass identifies specifically the zones where ray
        mixing creates new chromatic conditions and applies the complementary
        shimmer only there, which is the mechanism behind Goncharova's
        prismatic colour placement along crossing ray paths.
        """
        print("    Goncharova Rayonist pass (session 267, 178th mode)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter1d as _gf1d
        from scipy.ndimage import gaussian_filter as _gf
        from scipy.ndimage import rotate as _rot_fn

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Multi-Angle Directional Streak Synthesis ─────────────────
        def _rotate_ch(ch, ang_deg):
            """Rotate 2D float32 array by ang_deg CCW; exact for 0/90."""
            if ang_deg == 0:
                return ch.copy()
            if ang_deg == 90:
                return _np.rot90(ch, k=1).astype(_np.float32)
            return _rot_fn(ch, angle=float(ang_deg), reshape=False,
                           order=1, mode="reflect").astype(_np.float32)

        def _unrotate_ch(ch, ang_deg):
            """Inverse rotation."""
            if ang_deg == 0:
                return ch
            if ang_deg == 90:
                return _np.rot90(ch, k=3).astype(_np.float32)
            return _rot_fn(ch, angle=-float(ang_deg), reshape=False,
                           order=1, mode="reflect").astype(_np.float32)

        rs = float(ray_sigma)
        angles = [0, 45, 90, 135]
        n_ang = len(angles)

        streak_r = _np.zeros((h, w), dtype=_np.float32)
        streak_g = _np.zeros((h, w), dtype=_np.float32)
        streak_b = _np.zeros((h, w), dtype=_np.float32)

        for ang in angles:
            rr = _rotate_ch(r0, ang)
            rg = _rotate_ch(g0, ang)
            rb = _rotate_ch(b0, ang)

            rr_h = rr.shape[0]; rr_w = rr.shape[1]

            br = _gf1d(_gf1d(rr, sigma=rs, axis=1), sigma=1.5, axis=0)
            bg = _gf1d(_gf1d(rg, sigma=rs, axis=1), sigma=1.5, axis=0)
            bb = _gf1d(_gf1d(rb, sigma=rs, axis=1), sigma=1.5, axis=0)

            ur = _unrotate_ch(br, ang)
            ug = _unrotate_ch(bg, ang)
            ub = _unrotate_ch(bb, ang)

            # After un-rotation, shape may differ for 90° on non-square images.
            # Crop or pad to (h, w) to ensure consistent accumulation.
            ur = ur[:h, :w]
            ug = ug[:h, :w]
            ub = ub[:h, :w]

            streak_r += ur
            streak_g += ug
            streak_b += ub

        streak_r /= float(n_ang)
        streak_g /= float(n_ang)
        streak_b /= float(n_ang)

        # ── Stage 2: Luminance-Weighted Streak Overlay ─────────────────────────
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        source_w = _np.clip(lum / (lum.max() + 1e-6), 0.0, 1.0).astype(_np.float32)
        source_w_n = _gf(source_w, sigma=4.0).astype(_np.float32)

        ray_str = float(ray_strength)
        blend_f = (ray_str * (0.4 + 0.6 * source_w_n)).astype(_np.float32)
        blend_f = _np.clip(blend_f, 0.0, 1.0).astype(_np.float32)

        ray_r = (r0 * (1.0 - blend_f) + streak_r * blend_f).astype(_np.float32)
        ray_g = (g0 * (1.0 - blend_f) + streak_g * blend_f).astype(_np.float32)
        ray_b = (b0 * (1.0 - blend_f) + streak_b * blend_f).astype(_np.float32)

        ray_r = _np.clip(ray_r, 0.0, 1.0).astype(_np.float32)
        ray_g = _np.clip(ray_g, 0.0, 1.0).astype(_np.float32)
        ray_b = _np.clip(ray_b, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Chromatic Hue Shimmer at Ray Interference Zones ──────────
        ray_energy = (
            _np.abs(ray_r - r0) + _np.abs(ray_g - g0) + _np.abs(ray_b - b0)
        ) / 3.0
        ray_energy = ray_energy.astype(_np.float32)

        shimmer_mask = (ray_energy > float(shimmer_threshold)).astype(_np.float32)
        shimmer_count = int(shimmer_mask.sum())

        if shimmer_count > 0:
            Y_grid, X_grid = _np.mgrid[0:h, 0:w]
            sf = float(shimmer_freq)
            spatial_sign = _np.sign(
                _np.sin(X_grid.astype(_np.float32) * sf * 2.0 * _np.pi) *
                _np.cos(Y_grid.astype(_np.float32) * sf * 2.0 * _np.pi)
            ).astype(_np.float32)
            hue_delta = (float(shimmer_angle) / 360.0 * spatial_sign).astype(_np.float32)

            # HSV hue rotation for shimmer pixels
            ch_max = _np.maximum(_np.maximum(ray_r, ray_g), ray_b)
            ch_min = _np.minimum(_np.minimum(ray_r, ray_g), ray_b)
            delta   = (ch_max - ch_min).astype(_np.float32)
            sat_v   = _np.clip(delta / (ch_max + 1e-6), 0.0, 1.0).astype(_np.float32)
            val_v   = ch_max.astype(_np.float32)

            hue_v = _np.zeros_like(ray_r)
            m = delta > 1e-6
            if m.any():
                rr2 = ray_r[m]; gg2 = ray_g[m]; bb2 = ray_b[m]
                dd2 = delta[m]; mx2 = ch_max[m]
                is_r = (mx2 == rr2)
                is_g = (mx2 == gg2) & ~is_r
                hr2 = ((gg2 - bb2) / dd2) % 6.0
                hg2 = (bb2 - rr2) / dd2 + 2.0
                hb2 = (rr2 - gg2) / dd2 + 4.0
                hue_v[m] = _np.where(is_r, hr2, _np.where(is_g, hg2, hb2)) / 6.0

            new_h = (hue_v + hue_delta) % 1.0

            # HSV → RGB
            h6  = (new_h * 6.0).astype(_np.float32)
            i_a = h6.astype(_np.int32) % 6
            f_a = (h6 - _np.floor(h6)).astype(_np.float32)
            p_a = (val_v * (1.0 - sat_v)).astype(_np.float32)
            q_a = (val_v * (1.0 - sat_v * f_a)).astype(_np.float32)
            t_a = (val_v * (1.0 - sat_v * (1.0 - f_a))).astype(_np.float32)

            sh_r = _np.select([i_a==0,i_a==1,i_a==2,i_a==3,i_a==4,i_a==5],
                              [val_v,q_a,p_a,p_a,t_a,val_v]).astype(_np.float32)
            sh_g = _np.select([i_a==0,i_a==1,i_a==2,i_a==3,i_a==4,i_a==5],
                              [t_a,val_v,val_v,q_a,p_a,p_a]).astype(_np.float32)
            sh_b = _np.select([i_a==0,i_a==1,i_a==2,i_a==3,i_a==4,i_a==5],
                              [p_a,p_a,t_a,val_v,val_v,q_a]).astype(_np.float32)

            sh_r = _np.clip(sh_r, 0.0, 1.0).astype(_np.float32)
            sh_g = _np.clip(sh_g, 0.0, 1.0).astype(_np.float32)
            sh_b = _np.clip(sh_b, 0.0, 1.0).astype(_np.float32)

            ray_r = (ray_r * (1.0 - shimmer_mask) + sh_r * shimmer_mask).astype(_np.float32)
            ray_g = (ray_g * (1.0 - shimmer_mask) + sh_g * shimmer_mask).astype(_np.float32)
            ray_b = (ray_b * (1.0 - shimmer_mask) + sh_b * shimmer_mask).astype(_np.float32)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        new_r = r0 * (1.0 - op) + ray_r * op
        new_g = g0 * (1.0 - op) + ray_g * op
        new_b = b0 * (1.0 - op) + ray_b * op

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(new_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(new_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(new_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        print(f"    Goncharova Rayonist complete "
              f"(shimmer_px={shimmer_count})")

    def paint_depth_atmosphere_pass(
        self,
        haze_color:       tuple = (0.76, 0.82, 0.92),
        depth_sigma:      float = 40.0,
        max_haze:         float = 0.35,
        vertical_weight:  float = 0.60,
        contrast_weight:  float = 0.40,
        contrast_radius:  float = 8.0,
        noise_seed:       int   = 268,
        opacity:          float = 0.75,
    ) -> None:
        r"""Depth Atmosphere (Aerial Perspective) -- session 268 improvement.

        AERIAL PERSPECTIVE SIMULATION INSPIRED BY THE CLASSICAL OIL PAINTING
        PRINCIPLE CODIFIED BY LEONARDO DA VINCI (c. 1490s) AND CENTRAL TO
        WESTERN LANDSCAPE PAINTING FROM CLAUDE LORRAIN TO J.M.W. TURNER:

        Aerial perspective (also called atmospheric perspective) is the optical
        phenomenon by which distant objects appear lighter, cooler in hue
        (shifted toward blue-grey), lower in contrast, and softer in edge
        definition as a result of the scattering of light by the intervening
        atmosphere. Leonardo described it in the Treatise on Painting: objects
        at a distance lose their warm colours and their sharp edges, taking on
        the blue of the air between them and the eye. Turner's late paintings
        exploit this principle to dissolve distant forms into luminous haze
        while keeping foreground elements vivid and warm. Corot systematically
        greys and lightens his backgrounds as they recede. Chinese ink painting
        uses kongyun (empty cloud) to represent distant mountain peaks dissolved
        into white mist -- atmospheric perspective has been a cross-cultural
        universal of landscape painting for millennia.

        The implementation estimates a SPATIAL DEPTH MAP from two independent
        signals: (1) the vertical position in the canvas (higher in the picture
        plane conventionally indicates greater distance in landscape convention),
        and (2) the local contrast at each pixel (low local contrast indicates
        smooth, textureless distant passages; high local contrast indicates
        detailed, close-range material). These are linearly combined into a
        composite depth estimate, smoothed with a large Gaussian to avoid harsh
        boundaries, and used to linearly blend each pixel toward a cool haze
        color. The result simulates the cumulative blue scattering of
        atmospheric depth without requiring a geometric 3D model.

        Stage 1 VERTICAL DEPTH SIGNAL: Build a vertical gradient y_depth[y, x]
        = y / (H-1) that increases linearly from 0.0 at the bottom (near
        foreground) to 1.0 at the top (far background). This encodes the
        landscape convention that higher pixels represent greater distance.
        NOVEL: (a) VERTICAL POSITION AS DEPTH PROXY -- no prior pass uses
        canvas vertical position as a spatial depth signal; paint_atmospheric_
        recession_pass (s237) applies a fixed vertical gradient desaturation
        based on canvas-height fractions with hard threshold zones, not a
        smooth blended depth map computed from multiple cues; this pass
        constructs a continuous gradient, not a zonally-thresholded function,
        and combines it with a second independent signal (local contrast).

        Stage 2 LOCAL CONTRAST DEPTH SIGNAL: Compute the luminance image L.
        For each pixel, compute the local mean luminance using a Gaussian blur
        at sigma=contrast_radius, and the local standard deviation from
        sqrt(gaussian(L^2) - gaussian(L)^2). Normalise: low local std = distant
        (depth signal = 1), high local std = close (depth signal = 0). This
        contrast_depth signal detects smooth distant sky and mist passages
        versus textured close-range grass, bark, or stone.
        NOVEL: (b) LOCAL CONTRAST AS A DISTANCE SIGNAL FUSED WITH VERTICAL
        POSITION -- no prior pass computes per-pixel local standard deviation
        to estimate scene depth; this is a signal-processing approach to
        scene depth estimation without any 3D model; local std falls naturally
        in aerial-hazed distant regions because atmospheric blurring removes
        fine-scale texture detail, making the depth signal self-consistent with
        the optical physics of aerial perspective.

        Stage 3 COMPOSITE DEPTH MAP: Blend the two signals:
          depth = vertical_weight * y_depth + contrast_weight * contrast_depth
        Apply Gaussian smoothing at sigma=depth_sigma to suppress edges and
        produce a spatially-smooth transition. Clamp to [0, 1].

        Stage 4 ATMOSPHERIC HAZE BLEND: For each pixel:
          haze_amount = depth * max_haze
          new_r = r * (1 - haze_amount) + haze_r * haze_amount
          new_g = g * (1 - haze_amount) + haze_g * haze_amount
          new_b = b * (1 - haze_amount) + haze_b * haze_amount
        where (haze_r, haze_g, haze_b) is the haze_color (default: cool
        blue-grey 0.76/0.82/0.92, approximating clear-sky atmospheric blue).
        This shift simultaneously lightens dark distant passages, cools warm
        colours, and reduces saturation -- the three perceptual signatures of
        aerial perspective.
        NOVEL: (c) PER-PIXEL MULTI-CUE DEPTH-WEIGHTED LINEAR HAZE BLEND --
        all prior passes that affect distant regions do so with fixed vertical
        zones (atmospheric_recession_pass: three fixed bands at canvas thirds)
        or global operators (sfumato_contour_dissolution: edge softening via
        gradient-magnitude gate, no distance cue). This pass is the first to
        compute a continuous per-pixel depth field from two spatial signals
        (vertical position + local contrast), smooth it to a coherent depth map,
        and use it to control a linear haze blend per pixel -- producing a
        smooth, form-following aerial recession that adapts to any composition.
        """
        print("    Depth Atmosphere (Aerial Perspective) pass (session 268 improvement)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        # ── Stage 1: Vertical Depth Signal ────────────────────────────────────
        y_idx = _np.arange(h, dtype=_np.float32)
        y_norm = y_idx / max(float(h - 1), 1.0)
        # y=0 is the TOP (far/sky); depth increases toward top, so invert y_norm
        y_depth = _np.tile((1.0 - y_norm)[:, _np.newaxis], (1, w)).astype(_np.float32)

        # ── Stage 2: Local Contrast Depth Signal ──────────────────────────────
        lum = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        cr = max(float(contrast_radius), 0.5)
        lum_mean = _gf(lum, sigma=cr).astype(_np.float32)
        lum2_mean = _gf(lum ** 2, sigma=cr).astype(_np.float32)
        local_var = _np.maximum(lum2_mean - lum_mean ** 2, 0.0).astype(_np.float32)
        local_std = _np.sqrt(local_var).astype(_np.float32)
        std_max = float(local_std.max()) + 1e-6
        contrast_depth = _np.clip(1.0 - local_std / std_max, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Composite Depth Map ──────────────────────────────────────
        vw = float(vertical_weight)
        cw = float(contrast_weight)
        depth = (vw * y_depth + cw * contrast_depth).astype(_np.float32)
        ds = max(float(depth_sigma), 0.5)
        depth = _gf(depth, sigma=ds).astype(_np.float32)
        depth = _np.clip(depth, 0.0, 1.0).astype(_np.float32)

        # ── Stage 4: Atmospheric Haze Blend ───────────────────────────────────
        hr, hg, hb = float(haze_color[0]), float(haze_color[1]), float(haze_color[2])
        mh = float(max_haze)
        haze_amt = (depth * mh).astype(_np.float32)

        new_r = (r0 * (1.0 - haze_amt) + hr * haze_amt).astype(_np.float32)
        new_g = (g0 * (1.0 - haze_amt) + hg * haze_amt).astype(_np.float32)
        new_b = (b0 * (1.0 - haze_amt) + hb * haze_amt).astype(_np.float32)

        new_r = _np.clip(new_r, 0.0, 1.0)
        new_g = _np.clip(new_g, 0.0, 1.0)
        new_b = _np.clip(new_b, 0.0, 1.0)

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        final_r = r0 * (1.0 - op) + new_r * op
        final_g = g0 * (1.0 - op) + new_g * op
        final_b = b0 * (1.0 - op) + new_b * op

        hazed_px = int((haze_amt > 0.05).sum())

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(final_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(final_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(final_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        print(f"    Depth Atmosphere complete (hazed_px={hazed_px})")


    def zao_wou_ki_ink_atmosphere_pass(
        self,
        glow_sigma:         float = 0.18,
        glow_strength:      float = 0.26,
        vignette_strength:  float = 0.40,
        vignette_color:     tuple = (0.04, 0.06, 0.14),
        warm_boost:         float = 0.16,
        cool_shift:         float = 0.14,
        ink_n_strokes:      int   = 28,
        ink_length_frac:    float = 0.22,
        ink_width:          float = 2.8,
        ink_opacity:        float = 0.55,
        noise_seed:         int   = 268,
        opacity:            float = 0.82,
    ) -> None:
        r"""Zao Wou-Ki Ink Atmosphere -- session 268, 179th distinct mode.

        FOUR-STAGE LYRICAL ABSTRACTION TECHNIQUE INSPIRED BY ZAO WOU-KI'S
        PAINTING PRACTICE (c.1954-2013):

        Zao Wou-Ki (Zhao Wuji, 1920-2013) was a Chinese-French painter who
        synthesised the spatial philosophy of Song Dynasty ink painting
        (shanshui -- mountain-water landscape) with the chromatic ambition of
        Western Abstract Expressionism, developing a distinctive pictorial
        language that has no direct precedent in either tradition. Born in
        Beijing into an educated family with access to classical Chinese art,
        he trained at the Hangzhou Academy under Lin Fengmian, absorbing the
        ink painting tradition's treatment of empty space (xu -- the void) as
        an active pictorial element. He arrived in Paris in 1948 and absorbed
        Cézanne, Klee, Matisse, and later de Kooning -- but his essential
        innovation was not to synthesise these influences but to find that the
        fundamental concern of Chinese ink painting (the energy-relationship
        between mark and void) was identical to the fundamental concern of
        American Abstract Expressionism (the gestural field and its atmospheric
        ground). This identity, not synthesis, is the source of his originality.

        His mature paintings (from the mid-1950s onward) are organised around a
        single structural principle: a LUMINOUS CENTER surrounded by dark,
        calligraphically-marked peripheral zones. The center is not simply
        bright -- it is a zone of warm, golden, almost blinding light, as though
        a furnace or sun or spiritual presence radiates from the interior of the
        canvas. The periphery is not simply dark -- it is a zone of deep blue-
        black or indigo where ink-like gestural marks (jottings, curves, sweeping
        arcs) carry the calligraphic energy of the hand while remaining
        fundamentally abstract. Between center and edge, colour temperature
        shifts are extreme: warm orange-gold in the luminous core, cool blue-
        violet in the outer dark zone, with a narrow transitional band where
        warm and cool clash and create chromatic complexity.

        The composition has no horizon, no named forms, no narrative -- yet the
        eye reads it immediately as a landscape: the luminous center as sky or
        sun or distant valley light, the dark marks as mountain, rock, forest,
        or storm. This landscape reading arises entirely from the structural
        logic of the luminous-center / dark-periphery architecture, not from
        any depicted form. Zao called his paintings "windows onto the imaginary"
        -- the frame opens onto a felt rather than depicted space.

        Stage 1 LUMINOUS CENTER DETECTION AND RADIAL GLOW AMPLIFICATION:
        Compute the luminance L of the canvas. Smooth L with a wide Gaussian at
        sigma = glow_sigma * min(H, W) (expressed as a fraction of canvas size).
        Find the peak location (cy_peak, cx_peak) of the smoothed luminance --
        this is the detected luminous center. Build a radial proximity map:
          center_dist[y, x] = sqrt(((y-cy_peak)/H)^2 + ((x-cx_peak)/W)^2)
          radial_glow = exp(-center_dist^2 / (glow_sigma^2 * 2))
        Apply the glow as a luminance lift:
          glow_lift = radial_glow * glow_strength
          r_glow = clip(r0 + glow_lift * (1 - r0), 0, 1)  (lifts toward white)
          g_glow = clip(g0 + glow_lift * (1 - g0), 0, 1)
          b_glow = clip(b0 + glow_lift * (1 - b0), 0, 1)  (cools less than warm)
        NOVEL: (a) CANVAS-WIDE LUMINOUS CENTER DETECTION VIA SMOOTHED LUMINANCE
        PEAK, FOLLOWED BY CONTENT-ALIGNED RADIAL BRIGHTENING -- first pass to
        locate the brightest region of the PAINTED CANVAS (not a fixed point)
        and amplify it with a content-aligned radial field; prior passes with
        radial operators use fixed centers (canvas center, fixed fraction of
        canvas size); this pass reads the actual painted luminance distribution
        and reinforces the existing compositional light source, making the glow
        a signal-amplifying operation rather than an imposed geometry.

        Stage 2 DARK PERIPHERAL VIGNETTE:
        Using the same center_dist map:
          vignette_weight = center_dist^1.5 (non-linear: rapid darkening past midfield)
          vignette_weight = clip(vignette_weight / vignette_weight.max(), 0, 1)
          new_r = r_glow * (1 - vignette_strength * vignette_weight) + vc_r * vignette_strength * vignette_weight
          (similarly for g, b, using vignette_color = deep blue-black (0.04/0.06/0.14))
        NOVEL: (b) CONTENT-ALIGNED NON-LINEAR PERIPHERAL VIGNETTE TOWARD DEEP
        BLUE-BLACK, CENTERED ON THE DETECTED LUMINOUS PEAK -- all prior vignette
        operators in the engine use the CANVAS CENTER as the vignette center and
        apply a fixed power-law or Gaussian falloff; this pass centers the
        vignette on the DETECTED LUMINOUS PEAK (which may be anywhere in the
        canvas), creating an asymmetric vignette that reinforces the existing
        spatial asymmetry of the composition; the blue-black target color models
        Zao's peripheral indigo-black zones, not generic dark grey.

        Stage 3 DUAL THERMAL COLOR FIELD (WARM CENTER, COOL PERIPHERY):
        Compute final luminance L_post from stage-2 result.
        In bright regions (L_post > 0.55): shift hue toward warm gold:
          hue_delta_warm = +warm_boost * (L_post - 0.55) / 0.45  (scaled by excess lum)
        In dark regions (L_post < 0.35): shift hue toward cool blue-indigo:
          hue_delta_cool = -cool_shift * (0.35 - L_post) / 0.35  (scaled by depth)
        Apply HSV hue rotation at those zones only.
        NOVEL: (c) LUMINANCE-ZONED DUAL THERMAL HUE SHIFT WITH VARIABLE
        MAGNITUDE -- first pass to apply OPPOSITE hue rotations to bright and
        dark zones in the same operation, with the rotation magnitude scaled
        continuously by how bright or dark the pixel is (not a binary gate);
        paint_edge_temperature_pass applies a single warm/cool split at edges
        (not at luminance zones, not dual-direction, not scaled by luminance
        depth); paint_warm_cool_separation_pass applies fixed warm/cool shifts
        in fixed screen halves (not luminance-guided, not scaled by tonal depth);
        this pass creates the characteristic Zao Wou-Ki THERMAL FIELD where
        the color temperature gradient runs from warm gold at the luminous center
        through neutral mid-tones to deep blue-indigo at the dark periphery.

        Stage 4 INK CALLIGRAPHIC STREAK SYNTHESIS:
        Generate ink_n_strokes gestural ink marks in the outer zone of the
        canvas (distance from center_peak > 0.20 * min(H, W)). Each mark:
          a. Random anchor point in the peripheral zone
          b. Direction approximately tangential to the radial field from center
             (angle = atan2(anchor_y - cy_peak, anchor_x - cx_peak) + pi/2 + noise)
             with angular noise ~ Uniform(-35°, +35°)
          c. Length = ink_length_frac * min(H, W) * Uniform(0.5, 1.4)
          d. Rendered as a Gaussian-blurred line (sigma=ink_width/2) with dark
             blue-black ink color, blended at ink_opacity
        This creates the calligraphic peripheral marks that carry the gestural
        energy of Zao's ink-painting heritage in the outer dark zone.
        NOVEL: (d) CONTENT-ALIGNED TANGENTIAL INK STROKE PLACEMENT IN THE
        PERIPHERAL ZONE -- all prior calligraphic/gestural passes (twombly_
        calligraphic_scrawl_pass: random clusters across whole canvas; mitchell_
        gestural_arc_pass: content-detected arcs at edge boundaries; kline_
        gestural_slash_pass: large diagonal slashes at detected major axis)
        place marks based on content edges or randomly; this pass places marks
        specifically in the PERIPHERAL ZONE (beyond a radial threshold from the
        luminous center) and orients them TANGENTIALLY to the radial field,
        generating the circling, orbiting quality of Zao's peripheral
        calligraphic marks that spiral around the luminous interior.
        """
        print("    Zao Wou-Ki Ink Atmosphere pass (session 268, 179th mode)...")

        import numpy as _np
        from scipy.ndimage import gaussian_filter as _gf
        from PIL import Image as _Image, ImageDraw as _ImageDraw

        surface = self.canvas.surface
        orig = _np.frombuffer(surface.get_data(), dtype=_np.uint8).reshape(
            (self.canvas.h, self.canvas.w, 4)).copy()
        h, w = orig.shape[:2]

        b0 = orig[:, :, 0].astype(_np.float32) / 255.0
        g0 = orig[:, :, 1].astype(_np.float32) / 255.0
        r0 = orig[:, :, 2].astype(_np.float32) / 255.0

        rng = _np.random.default_rng(int(noise_seed))

        # ── Stage 1: Luminous Center Detection and Radial Glow ────────────────
        lum0 = (0.299 * r0 + 0.587 * g0 + 0.114 * b0).astype(_np.float32)
        glow_sigma_px = max(float(glow_sigma) * float(min(h, w)), 4.0)
        lum_smooth = _gf(lum0, sigma=glow_sigma_px).astype(_np.float32)

        peak_idx = int(_np.argmax(lum_smooth))
        cy_peak = float(peak_idx // w)
        cx_peak = float(peak_idx % w)

        Y_grid, X_grid = _np.mgrid[0:h, 0:w]
        cy_n = cy_peak / float(max(h - 1, 1))
        cx_n = cx_peak / float(max(w - 1, 1))
        y_n = Y_grid.astype(_np.float32) / float(max(h - 1, 1))
        x_n = X_grid.astype(_np.float32) / float(max(w - 1, 1))
        center_dist = _np.sqrt((y_n - cy_n) ** 2 + (x_n - cx_n) ** 2).astype(_np.float32)

        gs = float(glow_sigma)
        radial_glow = _np.exp(-center_dist ** 2 / (2.0 * gs ** 2)).astype(_np.float32)
        glow_lift = (radial_glow * float(glow_strength)).astype(_np.float32)

        r_g = _np.clip(r0 + glow_lift * (1.0 - r0), 0.0, 1.0).astype(_np.float32)
        g_g = _np.clip(g0 + glow_lift * (1.0 - g0), 0.0, 1.0).astype(_np.float32)
        b_g = _np.clip(b0 + glow_lift * (1.0 - b0) * 0.7, 0.0, 1.0).astype(_np.float32)

        # ── Stage 2: Dark Peripheral Vignette ─────────────────────────────────
        vc_r, vc_g, vc_b = (float(vignette_color[0]),
                             float(vignette_color[1]),
                             float(vignette_color[2]))
        cd_max = float(center_dist.max()) + 1e-6
        vw = _np.clip((center_dist ** 1.5) / (cd_max ** 1.5), 0.0, 1.0).astype(_np.float32)
        vs = float(vignette_strength)

        r_v = (r_g * (1.0 - vs * vw) + vc_r * vs * vw).astype(_np.float32)
        g_v = (g_g * (1.0 - vs * vw) + vc_g * vs * vw).astype(_np.float32)
        b_v = (b_g * (1.0 - vs * vw) + vc_b * vs * vw).astype(_np.float32)
        r_v = _np.clip(r_v, 0.0, 1.0).astype(_np.float32)
        g_v = _np.clip(g_v, 0.0, 1.0).astype(_np.float32)
        b_v = _np.clip(b_v, 0.0, 1.0).astype(_np.float32)

        # ── Stage 3: Dual Thermal Color Field ─────────────────────────────────
        lum1 = (0.299 * r_v + 0.587 * g_v + 0.114 * b_v).astype(_np.float32)

        # HSV decomposition helper
        def _rgb_to_hsv(r, g, b):
            mx = _np.maximum(_np.maximum(r, g), b)
            mn = _np.minimum(_np.minimum(r, g), b)
            delta = mx - mn
            val = mx.copy()
            sat = _np.where(mx > 1e-6, delta / (mx + 1e-6), 0.0).astype(_np.float32)
            hue = _np.zeros_like(r)
            m = delta > 1e-6
            if m.any():
                rr2 = r[m]; gg2 = g[m]; bb2 = b[m]
                dd2 = delta[m]; mx2 = mx[m]
                is_r = (mx2 == rr2)
                is_g = (mx2 == gg2) & ~is_r
                hr2 = ((gg2 - bb2) / dd2) % 6.0
                hg2 = (bb2 - rr2) / dd2 + 2.0
                hb2 = (rr2 - gg2) / dd2 + 4.0
                hue[m] = _np.where(is_r, hr2, _np.where(is_g, hg2, hb2)) / 6.0
            return hue, sat, val

        def _hsv_to_rgb(hue, sat, val):
            h6 = (hue * 6.0).astype(_np.float32)
            i_a = h6.astype(_np.int32) % 6
            f_a = (h6 - _np.floor(h6)).astype(_np.float32)
            p_a = (val * (1.0 - sat)).astype(_np.float32)
            q_a = (val * (1.0 - sat * f_a)).astype(_np.float32)
            t_a = (val * (1.0 - sat * (1.0 - f_a))).astype(_np.float32)
            out_r = _np.select([i_a==0,i_a==1,i_a==2,i_a==3,i_a==4,i_a==5],
                               [val,q_a,p_a,p_a,t_a,val]).astype(_np.float32)
            out_g = _np.select([i_a==0,i_a==1,i_a==2,i_a==3,i_a==4,i_a==5],
                               [t_a,val,val,q_a,p_a,p_a]).astype(_np.float32)
            out_b = _np.select([i_a==0,i_a==1,i_a==2,i_a==3,i_a==4,i_a==5],
                               [p_a,p_a,t_a,val,val,q_a]).astype(_np.float32)
            return (
                _np.clip(out_r, 0.0, 1.0),
                _np.clip(out_g, 0.0, 1.0),
                _np.clip(out_b, 0.0, 1.0),
            )

        hue_v, sat_v, val_v = _rgb_to_hsv(r_v, g_v, b_v)

        # Warm zone (bright): hue shift toward gold (hue ~0.10)
        warm_thr = 0.55
        warm_mask = lum1 > warm_thr
        warm_mag = (_np.clip((lum1 - warm_thr) / max(1.0 - warm_thr, 1e-4),
                             0.0, 1.0) * float(warm_boost)).astype(_np.float32)
        # Shift hue toward ~0.10 (gold/orange)
        gold_target = 0.10
        hue_warm_delta = ((gold_target - hue_v) * warm_mag * warm_mask.astype(_np.float32))

        # Cool zone (dark): hue shift toward blue-indigo (hue ~0.67)
        cool_thr = 0.35
        cool_mask = lum1 < cool_thr
        cool_mag = (_np.clip((cool_thr - lum1) / max(cool_thr, 1e-4),
                             0.0, 1.0) * float(cool_shift)).astype(_np.float32)
        indigo_target = 0.67
        hue_cool_delta = ((indigo_target - hue_v) * cool_mag * cool_mask.astype(_np.float32))

        new_hue = _np.clip(hue_v + hue_warm_delta + hue_cool_delta, 0.0, 1.0).astype(_np.float32)
        r_t, g_t, b_t = _hsv_to_rgb(new_hue, sat_v, val_v)

        # ── Stage 4: Ink Calligraphic Streak Synthesis ────────────────────────
        # Render ink strokes onto a float32 RGBA accumulator
        ink_acc_r = r_t.copy()
        ink_acc_g = g_t.copy()
        ink_acc_b = b_t.copy()

        ink_r_val, ink_g_val, ink_b_val = 0.04, 0.06, 0.14  # deep blue-black ink
        ink_op = float(ink_opacity)
        peripheral_radius = 0.20
        min_dim = float(min(h, w))
        length_base = float(ink_length_frac) * min_dim
        iw = max(float(ink_width), 0.5)
        sigma_line = iw / 2.0

        for _ in range(int(ink_n_strokes)):
            # Sample anchor in peripheral zone
            for _attempt in range(80):
                ay = int(rng.integers(0, h))
                ax = int(rng.integers(0, w))
                d = center_dist[ay, ax]
                if d > peripheral_radius:
                    break
            # Direction: tangential to radial field + noise
            base_angle = _np.arctan2(float(ay) - cy_peak, float(ax) - cx_peak) + _np.pi / 2.0
            noise_angle = rng.uniform(-35.0, 35.0) * _np.pi / 180.0
            angle = base_angle + noise_angle
            length = length_base * float(rng.uniform(0.5, 1.4))

            x0_f = ax - _np.cos(angle) * length / 2.0
            y0_f = ay - _np.sin(angle) * length / 2.0
            x1_f = ax + _np.cos(angle) * length / 2.0
            y1_f = ay + _np.sin(angle) * length / 2.0

            # Rasterise as anti-aliased line via distance-to-segment
            # Clip bounding box
            bx0 = max(0, int(min(x0_f, x1_f) - iw * 3))
            bx1 = min(w, int(max(x0_f, x1_f) + iw * 3) + 1)
            by0 = max(0, int(min(y0_f, y1_f) - iw * 3))
            by1 = min(h, int(max(y0_f, y1_f) + iw * 3) + 1)
            if bx1 <= bx0 or by1 <= by0:
                continue

            patch_Y, patch_X = _np.mgrid[by0:by1, bx0:bx1]
            pY = patch_Y.astype(_np.float32)
            pX = patch_X.astype(_np.float32)

            dx = float(x1_f - x0_f); dy = float(y1_f - y0_f)
            seg_len2 = dx * dx + dy * dy
            if seg_len2 < 1.0:
                continue
            t = _np.clip(
                ((pX - x0_f) * dx + (pY - y0_f) * dy) / seg_len2,
                0.0, 1.0
            )
            proj_x = x0_f + t * dx
            proj_y = y0_f + t * dy
            dist2 = (pX - proj_x) ** 2 + (pY - proj_y) ** 2
            line_alpha = _np.exp(-dist2 / (2.0 * sigma_line ** 2)) * ink_op

            ink_acc_r[by0:by1, bx0:bx1] = _np.clip(
                ink_acc_r[by0:by1, bx0:bx1] * (1.0 - line_alpha) + ink_r_val * line_alpha,
                0.0, 1.0
            )
            ink_acc_g[by0:by1, bx0:bx1] = _np.clip(
                ink_acc_g[by0:by1, bx0:bx1] * (1.0 - line_alpha) + ink_g_val * line_alpha,
                0.0, 1.0
            )
            ink_acc_b[by0:by1, bx0:bx1] = _np.clip(
                ink_acc_b[by0:by1, bx0:bx1] * (1.0 - line_alpha) + ink_b_val * line_alpha,
                0.0, 1.0
            )

        # ── Composite at opacity ───────────────────────────────────────────────
        op = float(opacity)
        final_r = (r0 * (1.0 - op) + ink_acc_r * op).astype(_np.float32)
        final_g = (g0 * (1.0 - op) + ink_acc_g * op).astype(_np.float32)
        final_b = (b0 * (1.0 - op) + ink_acc_b * op).astype(_np.float32)
        final_r = _np.clip(final_r, 0.0, 1.0)
        final_g = _np.clip(final_g, 0.0, 1.0)
        final_b = _np.clip(final_b, 0.0, 1.0)

        buf = orig.copy()
        buf[:, :, 2] = _np.clip(final_r * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 1] = _np.clip(final_g * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 0] = _np.clip(final_b * 255, 0, 255).astype(_np.uint8)
        buf[:, :, 3] = orig[:, :, 3]
        surface.get_data()[:] = buf.tobytes()
        surface.mark_dirty()

        print(f"    Zao Wou-Ki Ink Atmosphere complete "
              f"(center=({int(cx_peak)},{int(cy_peak)}), "
              f"strokes={int(ink_n_strokes)})")

